window.CARD_DATA={"schemaVersion":1,"cards":[{"title":"德国兴登堡计划","level":"B","type":"制度/文本卡","tags":["经济与社会","战争与外交"],"mainTag":"经济与社会","subTag":"战争与外交","timeText":"1916年提出并推进","place":"德国","summary":"德国兴登堡计划试图把德国经济更彻底转向军需生产，体现一战后期总体战对社会和工业的全面压榨。","fields":[{"label":"标题","value":"德国兴登堡计划"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1916年提出并推进"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国兴登堡计划试图把德国经济更彻底转向军需生产，体现一战后期总体战对社会和工业的全面压榨。"},{"label":"制定方/签署方","value":"兴登堡、鲁登道夫主导的第三最高陆军统帅部及德国政府。"},{"label":"主要内容","value":"大幅提高武器和弹药产量，集中资源于军需工业，加强劳动力配置和国家干预。"},{"label":"它试图解决什么问题","value":"凡尔登和索姆河等消耗战使德国面临弹药、劳动力和工业产能压力，军方要求以更强国家管制支撑战争。"},{"label":"为什么重要","value":"它标志德国战争经济进一步军事化，也显示军方在帝国内政中的权力上升。"},{"label":"争议/局限","value":"计划目标过高，挤压民用经济和劳动力，未能解决粮食短缺和社会疲惫。"},{"label":"造成的影响","value":"强化“一战总动员社会”；加剧后方物资短缺；第三最高陆军统帅部权力扩张。"},{"label":"出处","value":"1914-1918 Online: Hindenburg Program；German History Documents and Images相关资料；Deutsches Historisches Museum/LeMO相关资料。"}],"relationItems":["← 前因：一战总动员社会","← 前因：凡尔登战役","→ 后果：德国“芜菁冬天”","↔ 相关：兴登堡和鲁登道夫崛起"],"relations":[{"text":"← 前因：一战总动员社会","id":"extra653"},{"text":"← 前因：凡尔登战役","id":"extra654"},{"text":"→ 后果：德国“芜菁冬天”","id":"extra657"},{"text":"↔ 相关：兴登堡和鲁登道夫崛起","id":"extra938"}],"source":"history","id":"card1"},{"title":"《凡尔赛和约》战争责任条款","level":"B","type":"制度/文本卡","tags":["战争与外交","文化与思想"],"mainTag":"战争与外交","subTag":"文化与思想","timeText":"1919年《凡尔赛和约》第231条","place":"一战后巴黎和会与《凡尔赛和约》文本","summary":"《凡尔赛和约》战争责任条款把德国及其盟国列为战争损失责任方，成为赔款法律依据和德国民族主义愤怒的焦点。","fields":[{"label":"标题","value":"《凡尔赛和约》战争责任条款"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1919年《凡尔赛和约》第231条"},{"label":"地点","value":"一战后巴黎和会与《凡尔赛和约》文本"},{"label":"主要国家","value":"德国、法国、英国、美国"},{"label":"一句话概括","value":"《凡尔赛和约》战争责任条款把德国及其盟国列为战争损失责任方，成为赔款法律依据和德国民族主义愤怒的焦点。"},{"label":"制定方/签署方","value":"协约国在《凡尔赛和约》中制定，德国被迫接受。"},{"label":"主要内容","value":"第231条规定德国及其盟国应对协约国因战争遭受的损失和损害承担责任。该条并非直接写出全部赔款数额，但为赔款要求提供法律基础。"},{"label":"它试图解决什么问题","value":"战胜国需要为赔款和战后索赔建立法律理由，同时把战争损害责任制度化。"},{"label":"为什么重要","value":"德国公众普遍把它理解为“德国独自承担战争罪责”，使条约在心理和政治上更难被接受。右翼势力利用该条攻击共和国和签约政治家。"},{"label":"争议/局限","value":"条文的法律功能与公众理解之间存在落差，但政治效果极强。它把复杂的一战起因争论压缩为战败国屈辱感。"},{"label":"造成的影响","value":"强化德国修约主义；加剧“十一月罪人”和“背后一刀”叙事；成为魏玛政治极化的素材。"},{"label":"出处","value":"Avalon Project: Treaty of Versailles Article 231；Encyclopaedia Britannica: Treaty of Versailles；United States Holocaust Memorial Museum相关资料。"}],"relationItems":["← 前因：《凡尔赛和约》","→ 后果：德国“背后一刀”传说","→ 后果：魏玛德国赔款问题"],"relations":[{"text":"← 前因：《凡尔赛和约》","id":"card59"},{"text":"→ 后果：德国“背后一刀”传说","id":"extra623"},{"text":"→ 后果：魏玛德国赔款问题","id":"card3"}],"source":"history","id":"card2"},{"title":"魏玛德国赔款问题","level":"A","type":"概念/思潮卡","tags":["经济与社会","战争与外交"],"mainTag":"经济与社会","subTag":"战争与外交","timeText":"1919年至1932年为核心阶段","place":"德国、法国、英国、美国及国际赔款机制","summary":"魏玛德国赔款问题把战后债务、财政、外交安全和民族主义绑在一起，成为魏玛共和国最持续的危机来源之一。","fields":[{"label":"标题","value":"魏玛德国赔款问题"},{"label":"分级","value":"A"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1919年至1932年为核心阶段"},{"label":"地点","value":"德国、法国、英国、美国及国际赔款机制"},{"label":"主要国家","value":"德国、法国、英国、美国、比利时"},{"label":"一句话概括","value":"魏玛德国赔款问题把战后债务、财政、外交安全和民族主义绑在一起，成为魏玛共和国最持续的危机来源之一。"},{"label":"核心主张/思路","value":"赔款不是单一数字问题，而是战胜国安全和补偿需求、德国支付能力、国际贷款和国内政治合法性的交汇。"},{"label":"提出者/代表人物（可选）","value":"赔款委员会、协约国政府、德国历届魏玛政府；凯恩斯是著名批评者之一。"},{"label":"它从何而来","value":"《凡尔赛和约》和《凡尔赛和约》战争责任条款确立赔款基础，法国和比利时等国要求补偿战争破坏，德国则认为赔款超出能力且具有惩罚性。"},{"label":"典型表现","value":"伦敦支付方案、鲁尔占领、恶性通胀、德国赔款《道威斯计划》、德国赔款《杨格计划》、胡佛暂停偿付和洛桑会议。"},{"label":"为什么重要","value":"赔款问题把魏玛经济周期和国际政治紧密连接。德国既需要履约或谈判缓和外部压力，又要面对国内反凡尔赛情绪。"},{"label":"争议/局限","value":"赔款确实给德国财政和外汇造成压力，但魏玛经济崩溃不能只归因于赔款，还涉及战争债务、货币政策、国际贷款和大萧条。"},{"label":"出处","value":"Encyclopaedia Britannica: reparations and Treaty of Versailles；1914-1918 Online: Reparations；Gerald Feldman, The Great Disorder。"}],"relationItems":["← 前因：《凡尔赛和约》","← 前因：《凡尔赛和约》战争责任条款","→ 后果：鲁尔占领与德国消极抵抗","→ 后果：德国赔款《道威斯计划》","→ 后果：德国赔款《杨格计划》"],"relations":[{"text":"← 前因：《凡尔赛和约》","id":"card59"},{"text":"← 前因：《凡尔赛和约》战争责任条款","id":"card2"},{"text":"→ 后果：鲁尔占领与德国消极抵抗","id":"card62"},{"text":"→ 后果：德国赔款《道威斯计划》","id":"card92"},{"text":"→ 后果：德国赔款《杨格计划》","id":"card93"}],"source":"history","id":"card3"},{"title":"一战后国际联盟","level":"A","type":"组织/机构卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1920年成立；1946年正式解散","place":"总部设于日内瓦","summary":"一战后国际联盟是一战后建立的集体安全组织，试图用国际合作防止战争，但因缺乏强制力和大国支持不足而失败。","fields":[{"label":"标题","value":"一战后国际联盟"},{"label":"分级","value":"A"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1920年成立；1946年正式解散"},{"label":"地点","value":"总部设于日内瓦"},{"label":"主要国家","value":"英国、法国、日本、意大利及众多成员国；美国未加入"},{"label":"一句话概括","value":"一战后国际联盟是一战后建立的集体安全组织，试图用国际合作防止战争，但因缺乏强制力和大国支持不足而失败。"},{"label":"性质/类型","value":"国际组织、集体安全机制。"},{"label":"成立/解散时间","value":"1920年根据《凡尔赛和约》体系成立；二战后由联合国取代，1946年正式解散。"},{"label":"核心目标/宗旨","value":"维护和平、促进裁军、处理国际争端、管理委任统治地、推动卫生、劳工和难民等跨国合作。"},{"label":"关键人物（可选）","value":"伍德罗·威尔逊是主要倡议者，但美国国会拒绝加入。"},{"label":"关键行动/事件","value":"处理奥兰群岛、上西里西亚等争端；管理一战后国际联盟委任统治体系；面对日本侵占东北、意大利侵略埃塞俄比亚和德国扩张时表现无力。"},{"label":"为什么重要","value":"它是现代国际组织和集体安全思想的重要实验，虽然失败，却为联合国提供制度经验和教训。"},{"label":"争议/局限","value":"缺乏自己的军力，决策依赖成员国意愿；美国缺席、德苏起初被排除、英法自身利益限制行动能力。"},{"label":"出处","value":"Encyclopaedia Britannica: League of Nations；United Nations Geneva: League of Nations；Office of the Historian相关资料。"}],"relationItems":["← 前因：威尔逊十四点原则","← 前因：一战后巴黎和会","→ 后果：一战后国际联盟委任统治体系","→ 后果：联合国","↔ 相关：《凡尔赛和约》"],"relations":[{"text":"← 前因：威尔逊十四点原则","id":"extra661"},{"text":"← 前因：一战后巴黎和会","id":"extra668"},{"text":"→ 后果：一战后国际联盟委任统治体系","id":"card5"},{"text":"↔ 相关：《凡尔赛和约》","id":"card59"}],"source":"history","id":"card4"},{"title":"一战后国际联盟委任统治体系","level":"A","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"一战后由一战后国际联盟体系建立","place":"中东、非洲、太平洋等前德属和前奥斯曼地区","summary":"一战后国际联盟委任统治体系把战败国殖民地和奥斯曼领地交由战胜国管理，以国际监督名义延续帝国控制。","fields":[{"label":"标题","value":"一战后国际联盟委任统治体系"},{"label":"分级","value":"A"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"一战后由一战后国际联盟体系建立"},{"label":"地点","value":"中东、非洲、太平洋等前德属和前奥斯曼地区"},{"label":"主要国家","value":"英国、法国、日本、澳大利亚、新西兰、南非及被统治地区"},{"label":"一句话概括","value":"一战后国际联盟委任统治体系把战败国殖民地和奥斯曼领地交由战胜国管理，以国际监督名义延续帝国控制。"},{"label":"制定方/签署方","value":"一战后巴黎和会和一战后国际联盟框架下形成，由主要战胜国承担委任统治。"},{"label":"主要内容","value":"前德国殖民地和前奥斯曼帝国部分领地不被直接称为战利品，而被分类为A、B、C类委任统治地，由英法日等国家“代管”。"},{"label":"它试图解决什么问题","value":"战胜国需要重新分配殖民地和奥斯曼遗产，同时在威尔逊民族自决话语下避免公开承认传统瓜分殖民地。"},{"label":"为什么重要","value":"它是战后秩序双重性的典型：语言上强调文明责任和国际监督，现实中延续殖民控制，深刻影响中东和非洲边界。"},{"label":"争议/局限","value":"被统治地区人民缺乏真正决定权。民族自决原则主要适用于欧洲部分地区，在殖民地世界执行极不平等。"},{"label":"造成的影响","value":"英法控制中东多个地区；巴勒斯坦、伊拉克、叙利亚等问题长期影响二十世纪国际政治。"},{"label":"出处","value":"Encyclopaedia Britannica: mandate system；League of Nations Covenant Article 22；United Nations资料。"}],"relationItems":["← 前因：一战后国际联盟","← 前因：一战后巴黎和会","→ 后果：中东战后边界问题","↔ 相关：威尔逊十四点原则"],"relations":[{"text":"← 前因：一战后国际联盟","id":"card4"},{"text":"← 前因：一战后巴黎和会","id":"extra668"},{"text":"↔ 相关：威尔逊十四点原则","id":"extra661"}],"source":"history","id":"card5"},{"title":"德国艾伯特-格勒纳协议","level":"B","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1918年11月10日","place":"德国柏林及最高陆军统帅部通信","summary":"德国艾伯特-格勒纳协议让新共和国政府获得军方支持，也使魏玛从开局就依赖旧军队力量维持秩序。","fields":[{"label":"标题","value":"德国艾伯特-格勒纳协议"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1918年11月10日"},{"label":"地点","value":"德国柏林及最高陆军统帅部通信"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国艾伯特-格勒纳协议让新共和国政府获得军方支持，也使魏玛从开局就依赖旧军队力量维持秩序。"},{"label":"参与者","value":"弗里德里希·艾伯特、威廉·格勒纳、德国社会民主党、德国军方。"},{"label":"发生了什么","value":"德国十一月革命爆发后，社会民主党领导人艾伯特接管政府，但面对工兵委员会、左翼革命派和秩序崩溃风险，需要军方合作。11月10日，代表最高陆军统帅部的格勒纳通过电话向艾伯特承诺军队支持新政府维护秩序、反对布尔什维克式革命。作为交换，新政府保留军官团基本结构和军队权威。协议没有公开正式签署，却在实际政治中确立了共和国政府与旧军方的合作。"},{"label":"为什么重要","value":"它解释魏玛共和国的结构性矛盾：共和国由革命产生，却为了稳定依赖并保留了帝国旧军队。"},{"label":"前因","value":"十一月革命后新共和国缺乏稳定武装力量，旧军方也担心士兵委员会和左翼革命会瓦解军队等级秩序，双方因此形成临时互保关系。"},{"label":"后果","value":"协议帮助社民党政府维持短期秩序，却让旧军方在共和国中保留特殊地位，并为镇压左翼起义和自由军团暴力打开空间。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Ebert-Groener-Pakt；German History Documents and Images相关资料；Encyclopaedia Britannica: Friedrich Ebert。"}],"relationItems":["← 前因：德国十一月革命","→ 后果：德国斯巴达克起义","→ 后果：魏玛德国自由军团","↔ 相关：魏玛共和国成立"],"relations":[{"text":"← 前因：德国十一月革命","id":"extra666"},{"text":"→ 后果：德国斯巴达克起义","id":"card8"},{"text":"→ 后果：魏玛德国自由军团","id":"card9"},{"text":"↔ 相关：魏玛共和国成立","id":"card7"}],"source":"history","id":"card6"},{"title":"魏玛共和国成立","level":"A","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1918年至1919年","place":"德国，柏林与魏玛","summary":"魏玛共和国在战败、革命和帝制崩溃中建立，是德国第一次全国性议会民主共和国。","fields":[{"label":"标题","value":"魏玛共和国成立"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1918年至1919年"},{"label":"地点","value":"德国，柏林与魏玛"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"魏玛共和国在战败、革命和帝制崩溃中建立，是德国第一次全国性议会民主共和国。"},{"label":"参与者","value":"社会民主党、独立社民党、工兵委员会、国民议会、艾伯特、谢德曼等。"},{"label":"发生了什么","value":"1918年11月革命推翻帝制后，社会民主党领导人接管政府并宣布共和国。临时政府一方面同军方合作维持秩序，一方面准备选举制宪会议。1919年1月，全国选举产生国民议会，由于柏林局势不稳，会议在魏玛召开。国民议会制定宪法，选举艾伯特为总统，并逐步把革命后的临时政权转化为正式共和国。新国家从诞生起就同时面对战败、凡尔赛条约、左翼革命压力和右翼反共和国敌意。"},{"label":"为什么重要","value":"它是德国政治制度断裂的核心节点，开启1919年至1933年的民主实验。"},{"label":"前因","value":"德国军事失败、停战压力和十一月革命共同摧毁帝制，艾伯特政府需要把革命局势转化为可运作的议会共和国。"},{"label":"后果","value":"共和国从诞生起就同时面对战败、革命恐惧和右翼污名化，魏玛宪法确立制度框架，但背后一刀传说持续削弱其合法性。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Weimarer Republik；Encyclopaedia Britannica: Weimar Republic；German History Documents and Images相关资料。"}],"relationItems":["← 前因：德国十一月革命","← 前因：德国艾伯特-格勒纳协议","→ 后果：德国魏玛国民议会","→ 后果：魏玛宪法"],"relations":[{"text":"← 前因：德国十一月革命","id":"extra666"},{"text":"← 前因：德国艾伯特-格勒纳协议","id":"card6"},{"text":"→ 后果：德国魏玛国民议会","id":"card10"},{"text":"→ 后果：魏玛宪法","id":"card11"}],"source":"history","id":"card7"},{"title":"德国斯巴达克起义","level":"B","type":"事件卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1919年1月","place":"德国柏林","summary":"德国斯巴达克起义是德国革命左翼与社民党政府之间的暴力决裂，镇压后加深魏玛左翼分裂。","fields":[{"label":"标题","value":"德国斯巴达克起义"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1919年1月"},{"label":"地点","value":"德国柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国斯巴达克起义是德国革命左翼与社民党政府之间的暴力决裂，镇压后加深魏玛左翼分裂。"},{"label":"参与者","value":"斯巴达克同盟、德国共产党、柏林工人、社会民主党政府、魏玛德国自由军团、罗莎·卢森堡、卡尔·李卜克内西。"},{"label":"发生了什么","value":"1919年1月，柏林警察总监被免职引发左翼群众抗议，斯巴达克派和部分革命力量试图把抗议推向推翻政府的行动。起义者占领报社等据点，但组织和目标并不统一，也缺乏足够军事准备。艾伯特政府和国防部长诺斯克动用魏玛德国自由军团镇压。数日战斗后起义失败，罗莎·卢森堡和卡尔·李卜克内西被魏玛德国自由军团成员杀害。"},{"label":"为什么重要","value":"它使德国革命失去和平整合左翼的可能，社会民主党与共产党之间的敌意深刻影响魏玛政治。"},{"label":"前因","value":"十一月革命没有走向苏维埃式政权，艾伯特政府同旧军方合作维持秩序，德国共产党和激进工人因此认为革命被温和派背叛。"},{"label":"后果","value":"起义被自由军团镇压后，魏玛左翼分裂加深，右翼准军事暴力获得政治空间，卢森堡和李卜克内西之死成为左翼记忆核心。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Spartakusaufstand；Encyclopaedia Britannica: Spartacist Revolt；German History Documents and Images相关资料。"}],"relationItems":["← 前因：魏玛共和国成立","← 前因：德国艾伯特-格勒纳协议","→ 后果：魏玛德国自由军团","→ 后果：德国共产党成立"],"relations":[{"text":"← 前因：魏玛共和国成立","id":"card7"},{"text":"← 前因：德国艾伯特-格勒纳协议","id":"card6"},{"text":"→ 后果：魏玛德国自由军团","id":"card9"},{"text":"→ 后果：德国共产党成立","id":"extra694"}],"source":"history","id":"card8"},{"title":"魏玛德国自由军团","level":"B","type":"组织/机构卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"主要活跃于1918年至1923年前后","place":"德国及东欧边境地区","summary":"魏玛德国自由军团由退伍军人和民族主义武装组成，参与镇压左翼革命，也为魏玛政治暴力和右翼准军事文化提供土壤。","fields":[{"label":"标题","value":"魏玛德国自由军团"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"主要活跃于1918年至1923年前后"},{"label":"地点","value":"德国及东欧边境地区"},{"label":"主要国家","value":"德国、波兰、波罗的海地区国家"},{"label":"一句话概括","value":"魏玛德国自由军团由退伍军人和民族主义武装组成，参与镇压左翼革命，也为魏玛政治暴力和右翼准军事文化提供土壤。"},{"label":"性质/类型","value":"准军事组织、志愿武装团体。"},{"label":"成立/解散时间","value":"一战结束后大量形成；1920年代初逐步被解散、整编或转入其他右翼组织。"},{"label":"核心目标/宗旨","value":"维护秩序、反对布尔什维克和左翼革命，同时保卫或扩张德国民族主义边界诉求。"},{"label":"关键人物（可选）","value":"古斯塔夫·诺斯克支持动用魏玛德国自由军团；许多后来的右翼和纳粹成员曾有魏玛德国自由军团经历。"},{"label":"关键行动/事件","value":"镇压德国斯巴达克起义、巴伐利亚苏维埃共和国和鲁尔红军；在波罗的海和东部边境参与武装冲突。"},{"label":"为什么重要","value":"魏玛德国自由军团把战场暴力带回国内政治，使魏玛共和国从开端就面临准军事化和右翼反民主力量。"},{"label":"争议/局限","value":"它短期帮助政府镇压革命和恢复秩序，但长期削弱共和国对暴力的垄断，许多成员敌视共和国。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Freikorps；United States Holocaust Memorial Museum相关资料；German History Documents and Images相关资料。"}],"relationItems":["← 前因：德国艾伯特-格勒纳协议","← 前因：德国斯巴达克起义","→ 后果：魏玛德国卡普政变","↔ 相关：魏玛政治街头暴力"],"relations":[{"text":"← 前因：德国艾伯特-格勒纳协议","id":"card6"},{"text":"← 前因：德国斯巴达克起义","id":"card8"},{"text":"→ 后果：魏玛德国卡普政变","id":"card13"},{"text":"↔ 相关：魏玛政治街头暴力","id":"card34"}],"source":"history","id":"card9"},{"title":"德国魏玛国民议会","level":"B","type":"组织/机构卡","tags":["政治与制度","无"],"mainTag":"政治与制度","subTag":"无","timeText":"1919年2月至1920年","place":"德国魏玛","summary":"德国魏玛国民议会是德国革命后产生的制宪机构，负责把临时共和国转化为宪政共和国。","fields":[{"label":"标题","value":"德国魏玛国民议会"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"无"},{"label":"时间","value":"1919年2月至1920年"},{"label":"地点","value":"德国魏玛"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国魏玛国民议会是德国革命后产生的制宪机构，负责把临时共和国转化为宪政共和国。"},{"label":"性质/类型","value":"制宪议会、临时国家权力机构。"},{"label":"成立/解散时间","value":"1919年1月选举产生，2月在魏玛开会；1920年帝国议会选举后结束使命。"},{"label":"核心目标/宗旨","value":"制定共和国宪法，建立合法政府，处理战败与和约压力下的新国家制度。"},{"label":"关键人物（可选）","value":"弗里德里希·艾伯特、菲利普·谢德曼、胡戈·普罗伊斯等。"},{"label":"关键行动/事件","value":"选举艾伯特为总统；组建魏玛联合政府；通过魏玛宪法；在《凡尔赛和约》签署问题上承受巨大压力。"},{"label":"为什么重要","value":"它是魏玛共和国合法性的制度来源，也是德国从革命街头转向议会制宪的关键环节。"},{"label":"争议/局限","value":"国民议会在战败和内乱压力下工作，许多德国人把其同凡尔赛条约屈辱联系起来，削弱了新制度声望。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Nationalversammlung；Encyclopaedia Britannica: Weimar Republic；German History Documents and Images相关资料。"}],"relationItems":["← 前因：魏玛共和国成立","→ 后果：魏玛宪法","↔ 相关：《凡尔赛和约》"],"relations":[{"text":"← 前因：魏玛共和国成立","id":"card7"},{"text":"→ 后果：魏玛宪法","id":"card11"},{"text":"↔ 相关：《凡尔赛和约》","id":"card59"}],"source":"history","id":"card10"},{"title":"魏玛宪法","level":"A","type":"制度/文本卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1919年8月11日签署","place":"德国魏玛与柏林","summary":"魏玛宪法建立议会民主、普选和基本权利体系，同时以总统紧急权等设计留下制度风险。","fields":[{"label":"标题","value":"魏玛宪法"},{"label":"分级","value":"A"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1919年8月11日签署"},{"label":"地点","value":"德国魏玛与柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"魏玛宪法建立议会民主、普选和基本权利体系，同时以总统紧急权等设计留下制度风险。"},{"label":"制定方/签署方","value":"德国魏玛国民议会制定，德国总统艾伯特签署。"},{"label":"主要内容","value":"确立共和制、比例代表制、男女普选、基本权利、联邦结构和总统制因素；总统由民选产生，掌握任命政府、解散议会和根据第48条发布紧急措施等权力。"},{"label":"它试图解决什么问题","value":"革命后德国需要在君主制崩溃、地方邦国传统、群众民主和国家稳定之间建立新宪政框架。"},{"label":"为什么重要","value":"它是德国第一次全国民主共和国的制度基础，也解释魏玛政治为何既高度民主化又容易在危机中转向总统紧急统治。"},{"label":"争议/局限","value":"比例代表制使政党碎片化更明显；第48条本为危机工具，后来被频繁使用，削弱议会责任政治。"},{"label":"造成的影响","value":"为魏玛民主提供法律框架；在大萧条后被魏玛总统内阁和纳粹夺权过程利用。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Weimarer Verfassung；German History Documents and Images: Weimar Constitution；Encyclopaedia Britannica: Weimar Republic。"}],"relationItems":["← 前因：德国魏玛国民议会","→ 后果：总统紧急权","→ 后果：魏玛共和国成立"],"relations":[{"text":"← 前因：德国魏玛国民议会","id":"card10"},{"text":"→ 后果：魏玛共和国成立","id":"card7"}],"source":"history","id":"card11"},{"title":"魏玛宪法第48条","level":"A","type":"制度/文本卡","tags":["政治与制度","无"],"mainTag":"政治与制度","subTag":"无","timeText":"1919年写入魏玛宪法","place":"德国","summary":"魏玛宪法第48条赋予总统紧急权，原为危机治理工具，后来成为绕开议会统治的重要通道。","fields":[{"label":"标题","value":"魏玛宪法第48条"},{"label":"分级","value":"A"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"无"},{"label":"时间","value":"1919年写入魏玛宪法"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"魏玛宪法第48条赋予总统紧急权，原为危机治理工具，后来成为绕开议会统治的重要通道。"},{"label":"制定方/签署方","value":"德国魏玛国民议会制定，作为魏玛宪法条文之一。"},{"label":"主要内容","value":"在公共安全和秩序受到严重扰乱或威胁时，总统可采取必要措施，包括动用武力，并可临时限制部分基本权利。"},{"label":"它试图解决什么问题","value":"新共和国面临革命、政变、地方叛乱和国家崩溃风险，制宪者希望总统能在议会无法及时行动时维护秩序。"},{"label":"为什么重要","value":"第48条是理解魏玛制度脆弱性的核心。它本身不是纳粹夺权的唯一原因，但在魏玛总统内阁时期被用来替代正常议会立法。"},{"label":"争议/局限","value":"条文边界模糊，依赖总统和政府自我约束。危机越严重，越容易把临时权力常态化。"},{"label":"造成的影响","value":"布吕宁、巴本、施莱歇尔等魏玛总统内阁大量依赖紧急法令；希特勒上台后也利用紧急权破坏民主制度。"},{"label":"出处","value":"German History Documents and Images: Weimar Constitution Article 48；Deutsches Historisches Museum/LeMO相关资料；Encyclopaedia Britannica: Weimar Republic。"}],"relationItems":["← 前因：魏玛宪法","→ 后果：布吕宁内阁通缩政策","→ 后果：希特勒出任德国总理"],"relations":[{"text":"← 前因：魏玛宪法","id":"card11"},{"text":"→ 后果：布吕宁内阁通缩政策","id":"card65"},{"text":"→ 后果：希特勒出任德国总理","id":"card71"}],"source":"history","id":"card12"},{"title":"魏玛德国卡普政变","level":"B","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1920年3月13日至17日","place":"德国柏林及全国","summary":"魏玛德国卡普政变是右翼军政力量推翻魏玛政府的尝试，因全国总罢工和行政瘫痪而失败。","fields":[{"label":"标题","value":"魏玛德国卡普政变"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1920年3月13日至17日"},{"label":"地点","value":"德国柏林及全国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"魏玛德国卡普政变是右翼军政力量推翻魏玛政府的尝试，因全国总罢工和行政瘫痪而失败。"},{"label":"参与者","value":"沃尔夫冈·卡普、瓦尔特·冯·吕特维茨、埃尔哈特旅、魏玛政府、工会、社会民主党、军方。"},{"label":"发生了什么","value":"凡尔赛条约要求德国裁军，部分魏玛德国自由军团和军方右翼拒绝解散。1920年3月，吕特维茨率部进入柏林，支持卡普建立反共和国政府。魏玛政府被迫撤离柏林，正规军领导层拒绝为共和国直接开火。政府、工会和社民党号召总罢工，全国交通、行政和公共服务瘫痪，政变政府无法运作。数日后卡普逃亡，政变失败，但随后鲁尔等地左翼武装和政府镇压又引发新冲突。"},{"label":"为什么重要","value":"它暴露魏玛共和国对军队和右翼准军事组织控制不足，也显示工人运动仍有强大保卫共和国能力。"},{"label":"前因","value":"凡尔赛裁军要求威胁自由军团和右翼军官利益，旧军政力量对共和国缺乏忠诚，右翼反共和国情绪因此转化为政变尝试。"},{"label":"后果","value":"全国罢工挫败政变，但政府随后对鲁尔工人武装采取强硬镇压，暴露共和国对右翼和左翼暴力处理不平衡。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Kapp-Lüttwitz-Putsch；Encyclopaedia Britannica: Kapp Putsch；German History Documents and Images相关资料。"}],"relationItems":["← 前因：魏玛德国自由军团","← 前因：《凡尔赛和约》","→ 后果：德国鲁尔红军起义","↔ 相关：魏玛共和国成立"],"relations":[{"text":"← 前因：魏玛德国自由军团","id":"card9"},{"text":"← 前因：《凡尔赛和约》","id":"card59"},{"text":"→ 后果：德国鲁尔红军起义","id":"card14"},{"text":"↔ 相关：魏玛共和国成立","id":"card7"}],"source":"history","id":"card13"},{"title":"德国鲁尔红军起义","level":"B","type":"事件卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1920年3月至4月","place":"德国鲁尔区","summary":"德国鲁尔红军起义是魏玛德国卡普政变后工人武装反击右翼的行动，随后被政府军和魏玛德国自由军团镇压。","fields":[{"label":"标题","value":"德国鲁尔红军起义"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1920年3月至4月"},{"label":"地点","value":"德国鲁尔区"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国鲁尔红军起义是魏玛德国卡普政变后工人武装反击右翼的行动，随后被政府军和魏玛德国自由军团镇压。"},{"label":"参与者","value":"鲁尔区工人、工会、共产党和左翼社会民主派、魏玛政府、国防军、魏玛德国自由军团。"},{"label":"发生了什么","value":"魏玛德国卡普政变爆发后，鲁尔区工人响应总罢工，并组织武装力量对抗右翼政变和地方军警。政变失败后，部分工人武装不愿立即解除，提出社会化和工人权力诉求，形成所谓鲁尔红军。魏玛政府担心左翼革命扩大，派国防军和魏玛德国自由军团进入鲁尔区镇压。战斗造成大量伤亡，工人武装被击败。"},{"label":"为什么重要","value":"它显示魏玛早期政治暴力不是简单的左或右单线问题，而是共和国依赖旧军队和右翼武装镇压左翼，从而加剧合法性危机。"},{"label":"前因","value":"卡普政变激发工人自卫和总罢工，鲁尔区强大的工人组织把反政变行动发展为武装控制地方的革命运动。"},{"label":"后果","value":"共和国调动国防军和自由军团镇压鲁尔工人，进一步损害政府与工人阶级关系，也使右翼武装暴力继续影响政治。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Ruhrkampf 1920；German History Documents and Images相关资料。"}],"relationItems":["← 前因：魏玛德国卡普政变","← 前因：魏玛德国自由军团","↔ 相关：德国社会民主党（SPD）"],"relations":[{"text":"← 前因：魏玛德国卡普政变","id":"card13"},{"text":"← 前因：魏玛德国自由军团","id":"card9"},{"text":"↔ 相关：德国社会民主党（SPD）","id":"extra628"}],"source":"history","id":"card14"},{"title":"上西里西亚公投与分割","level":"B","type":"事件卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1921年公投，1922年前后分割落实","place":"上西里西亚","summary":"上西里西亚公投与分割围绕民族归属和工业资源展开，是凡尔赛体系下边界重划矛盾的典型案例。","fields":[{"label":"标题","value":"上西里西亚公投与分割"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1921年公投，1922年前后分割落实"},{"label":"地点","value":"上西里西亚"},{"label":"主要国家","value":"德国、波兰、法国、英国"},{"label":"一句话概括","value":"上西里西亚公投与分割围绕民族归属和工业资源展开，是凡尔赛体系下边界重划矛盾的典型案例。"},{"label":"参与者","value":"德国居民和组织、波兰居民和组织、协约国监督机构、一战后国际联盟。"},{"label":"发生了什么","value":"《凡尔赛和约》规定上西里西亚通过公投决定归属。当地德波人口、工业利益和民族动员高度交织，投票前后爆发多次起义和武装冲突。1921年公投显示总体上支持德国者较多，但东部工业区有大量波兰支持者。协约国内部对如何划界存在分歧，最终由一战后国际联盟参与提出分割方案，将部分重要工业地区划给波兰，其他地区留给德国。"},{"label":"为什么重要","value":"它说明战后民族自决在多民族、工业化和混居地区很难简单执行。边界划分同时牵涉民族、煤矿、钢铁和国家财政。"},{"label":"前因","value":"凡尔赛体系把民族自决原则用于德波边界，但上西里西亚同时具有混合民族结构和重要工业资源，简单归属难以被各方接受。"},{"label":"后果","value":"分割使德国失去部分工业区并强化修约主义，波兰获得关键资源，一战后国际联盟也被迫承担复杂边界争端的调停角色。"},{"label":"出处","value":"Encyclopaedia Britannica: Upper Silesia；League of Nations资料；German History Documents and Images相关资料。"}],"relationItems":["← 前因：《凡尔赛和约》","← 前因：一战后国际联盟","↔ 相关：一战后国际联盟委任统治体系"],"relations":[{"text":"← 前因：《凡尔赛和约》","id":"card59"},{"text":"← 前因：一战后国际联盟","id":"card4"},{"text":"↔ 相关：一战后国际联盟委任统治体系","id":"card5"}],"source":"history","id":"card15"},{"title":"1922年热那亚会议","level":"C","type":"事件卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1922年4月至5月","place":"意大利热那亚","summary":"1922年热那亚会议试图处理战后欧洲经济重建和苏俄关系，却因债务、赔款和外交互疑难以取得实质突破。","fields":[{"label":"标题","value":"1922年热那亚会议"},{"label":"分级","value":"C"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1922年4月至5月"},{"label":"地点","value":"意大利热那亚"},{"label":"主要国家","value":"英国、法国、德国、苏俄、意大利"},{"label":"一句话概括","value":"1922年热那亚会议试图处理战后欧洲经济重建和苏俄关系，却因债务、赔款和外交互疑难以取得实质突破。"},{"label":"参与者","value":"欧洲多国代表，尤其是英国、法国、德国、意大利和苏俄代表。"},{"label":"发生了什么","value":"一战后欧洲经济混乱、债务和赔款问题交织，列强在热那亚召开会议，希望恢复贸易、稳定金融并讨论同苏俄的经济关系。会议中，西方国家要求苏俄承认旧债和赔偿被没收财产，苏俄则要求赔偿干涉和封锁造成的损失。德国处于凡尔赛体系压力下，希望寻找外交空间。会议未能解决主要矛盾，但为德国和苏俄私下接近创造了机会。"},{"label":"为什么重要","value":"它显示战后欧洲经济秩序无法单靠会议恢复，也为《拉帕洛条约》提供背景。"},{"label":"前因","value":"战后欧洲经济混乱、德国赔款压力和苏俄被孤立，使列强试图在热那亚讨论经济恢复、债务和俄国关系。"},{"label":"后果","value":"会议未能解决主要矛盾，德国和苏俄却借机签署《拉帕洛条约》，改善双边关系并突破部分外交孤立。"},{"label":"出处","value":"Encyclopaedia Britannica: Genoa Conference；Office of the Historian相关资料；German History Documents and Images相关资料。"}],"relationItems":["← 前因：魏玛德国赔款问题","→ 后果：德苏《拉帕洛条约》"],"relations":[{"text":"← 前因：魏玛德国赔款问题","id":"card3"},{"text":"→ 后果：德苏《拉帕洛条约》","id":"card17"}],"source":"history","id":"card16"},{"title":"德苏《拉帕洛条约》","level":"B","type":"制度/文本卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1922年4月16日","place":"意大利拉帕洛","summary":"《拉帕洛条约》使德国和苏俄相互放弃索赔并恢复关系，是两个被孤立国家突破战后秩序的外交合作。","fields":[{"label":"标题","value":"德苏《拉帕洛条约》"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1922年4月16日"},{"label":"地点","value":"意大利拉帕洛"},{"label":"主要国家","value":"德国、苏俄"},{"label":"一句话概括","value":"《拉帕洛条约》使德国和苏俄相互放弃索赔并恢复关系，是两个被孤立国家突破战后秩序的外交合作。"},{"label":"制定方/签署方","value":"魏玛德国和苏维埃俄国。"},{"label":"主要内容","value":"双方恢复外交关系，相互放弃战争和国有化相关索赔，并发展经济合作。后续德苏还在军事合作方面进行秘密接触。"},{"label":"它试图解决什么问题","value":"德国受凡尔赛体系限制，苏俄被西方孤立，双方都需要外交突破、贸易机会和摆脱战胜国压力。"},{"label":"为什么重要","value":"它震动西方列强，显示战后体系无法完全控制被排斥的大国。对德国而言，这是“向东”争取外交空间的重要一步。"},{"label":"争议/局限","value":"条约没有直接推翻凡尔赛体系，但增加了法国等国对德国外交意图的疑虑；秘密军事合作也与裁军条款存在冲突。"},{"label":"造成的影响","value":"德苏关系改善；德国获得部分军事技术和训练回旋空间；战后欧洲外交格局更复杂。"},{"label":"出处","value":"Encyclopaedia Britannica: Treaty of Rapallo；German History Documents and Images: Treaty of Rapallo；Office of the Historian相关资料。"}],"relationItems":["← 前因：1922年热那亚会议","← 前因：《凡尔赛和约》","→ 后果：德苏秘密军事合作","↔ 相关：魏玛德国赔款问题"],"relations":[{"text":"← 前因：1922年热那亚会议","id":"card16"},{"text":"← 前因：《凡尔赛和约》","id":"card59"},{"text":"↔ 相关：魏玛德国赔款问题","id":"card3"}],"source":"history","id":"card17"},{"title":"希特勒啤酒馆政变","level":"B","type":"事件卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1923年11月8日至9日","place":"德国慕尼黑","summary":"希特勒啤酒馆政变是希特勒和纳粹党模仿墨索里尼进军罗马的夺权尝试，失败后反而给希特勒全国曝光。","fields":[{"label":"标题","value":"希特勒啤酒馆政变"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1923年11月8日至9日"},{"label":"地点","value":"德国慕尼黑"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"希特勒啤酒馆政变是希特勒和纳粹党模仿墨索里尼进军罗马的夺权尝试，失败后反而给希特勒全国曝光。"},{"label":"参与者","value":"阿道夫·希特勒、鲁登道夫、纳粹党、纳粹冲锋队、巴伐利亚地方领导人、慕尼黑警察。"},{"label":"发生了什么","value":"1923年德国深陷鲁尔危机和恶性通胀，巴伐利亚右翼势力活跃。希特勒在慕尼黑一座啤酒馆中劫持地方领导人，试图迫使他们支持向柏林进军并推翻共和国。次日，希特勒、鲁登道夫和支持者上街游行，遭到警察阻击，政变迅速失败。希特勒被捕受审，在审判中把自己塑造成民族主义反凡尔赛斗士，并在监禁期间写作《我的奋斗》。"},{"label":"为什么重要","value":"政变失败使纳粹党一度受挫，但也让希特勒认识到需要通过合法选举和群众组织夺权。"},{"label":"前因","value":"鲁尔危机、恶性通胀和共和国威信崩溃给右翼激进派制造机会，希特勒试图仿效墨索里尼进军罗马，用巴伐利亚作为夺权起点。"},{"label":"后果","value":"政变失败后希特勒被审判并入狱，纳粹党转向重组和合法夺权策略，《我的奋斗》也成为纳粹意识形态宣传文本。"},{"label":"出处","value":"United States Holocaust Memorial Museum: Beer Hall Putsch；Encyclopaedia Britannica: Beer Hall Putsch；Deutsches Historisches Museum/LeMO相关资料。"}],"relationItems":["← 前因：纳粹党成立","← 前因：魏玛德国赔款问题","→ 后果：希特勒《我的奋斗》","→ 后果：纳粹党重组"],"relations":[{"text":"← 前因：纳粹党成立","id":"extra92"},{"text":"← 前因：魏玛德国赔款问题","id":"card3"},{"text":"→ 后果：希特勒《我的奋斗》","id":"extra66"}],"source":"history","id":"card18"},{"title":"古斯塔夫·施特雷泽曼","level":"A","type":"人物卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1878年至1929年；魏玛外交核心时期为1923年至1929年","place":"德国","summary":"施特雷泽曼是魏玛中期最重要的外交政治家，通过务实修约和西方合作推动德国重返国际体系。","fields":[{"label":"标题","value":"古斯塔夫·施特雷泽曼"},{"label":"分级","value":"A"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1878年至1929年；魏玛外交核心时期为1923年至1929年"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国、法国、英国、美国"},{"label":"一句话概括","value":"施特雷泽曼是魏玛中期最重要的外交政治家，通过务实修约和西方合作推动德国重返国际体系。"},{"label":"生卒年/活跃年代","value":"1878-1929；魏玛时期担任总理和长期外交部长。"},{"label":"身份/职务","value":"德国人民党政治家，1923年任总理，1923年至1929年任外交部长。"},{"label":"关键贡献/作为","value":"结束鲁尔消极抵抗，推动货币稳定，参与德国赔款《道威斯计划》、欧洲《洛迦诺公约》和德国加入一战后国际联盟。"},{"label":"核心主张/立场","value":"接受现实、通过履约和谈判逐步修正凡尔赛体系，而不是立即军事对抗。"},{"label":"为什么重要","value":"他代表魏玛外交最成功的一条路线：不承认凡尔赛秩序永远合理，但先通过合作恢复德国信用和大国地位。"},{"label":"争议/评价","value":"右翼指责其妥协，左翼和法国部分人士也怀疑其修约目标；他本人兼具民族主义目标和现实主义手段。"},{"label":"关联事件（可选）","value":"欧洲《洛迦诺公约》、德国加入一战后国际联盟、德国赔款《道威斯计划》。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Gustav Stresemann；Encyclopaedia Britannica: Gustav Stresemann；Nobel Prize: Stresemann。"}],"relationItems":["← 前因：魏玛德国赔款问题","→ 后果：欧洲《洛迦诺公约》","→ 后果：德国加入一战后国际联盟","↔ 相关：德国赔款《道威斯计划》"],"relations":[{"text":"← 前因：魏玛德国赔款问题","id":"card3"},{"text":"→ 后果：欧洲《洛迦诺公约》","id":"card20"},{"text":"→ 后果：德国加入一战后国际联盟","id":"card21"},{"text":"↔ 相关：德国赔款《道威斯计划》","id":"card92"}],"source":"history","id":"card19"},{"title":"欧洲《洛迦诺公约》","level":"A","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1925年10月达成，1926年生效","place":"瑞士洛迦诺及欧洲外交体系","summary":"欧洲《洛迦诺公约》确认德国西部边界并引入英意保证，象征魏玛中期欧洲和解与德国重返外交体系。","fields":[{"label":"标题","value":"欧洲《洛迦诺公约》"},{"label":"分级","value":"A"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1925年10月达成，1926年生效"},{"label":"地点","value":"瑞士洛迦诺及欧洲外交体系"},{"label":"主要国家","value":"德国、法国、比利时、英国、意大利、波兰、捷克斯洛伐克"},{"label":"一句话概括","value":"欧洲《洛迦诺公约》确认德国西部边界并引入英意保证，象征魏玛中期欧洲和解与德国重返外交体系。"},{"label":"制定方/签署方","value":"德国、法国、比利时、英国、意大利，并涉及波兰和捷克斯洛伐克相关仲裁安排。"},{"label":"主要内容","value":"德国承认与法国、比利时的西部边界，英意作为保证国；德国与波兰、捷克斯洛伐克签订仲裁条约，但未同样永久确认东部边界。"},{"label":"它试图解决什么问题","value":"法国需要安全保证，德国需要摆脱外交孤立并修复国际信用，英国希望稳定欧洲大陆。"},{"label":"为什么重要","value":"它标志“洛迦诺精神”的出现，使德国在不完全接受东部边界的前提下获得西方承认和外交回归。"},{"label":"争议/局限","value":"西部边界获得保证，东部边界没有同等保障，留下德国未来向东修约的空间和不安。"},{"label":"造成的影响","value":"德国加入一战后国际联盟；法德关系短期缓和；魏玛外交进入相对稳定阶段。"},{"label":"出处","value":"Encyclopaedia Britannica: Locarno Pact；Deutsches Historisches Museum/LeMO: Locarno；Office of the Historian相关资料。"}],"relationItems":["← 前因：古斯塔夫·施特雷泽曼","→ 后果：德国加入一战后国际联盟","↔ 相关：德国赔款《道威斯计划》"],"relations":[{"text":"← 前因：古斯塔夫·施特雷泽曼","id":"card19"},{"text":"→ 后果：德国加入一战后国际联盟","id":"card21"},{"text":"↔ 相关：德国赔款《道威斯计划》","id":"card92"}],"source":"history","id":"card20"},{"title":"德国加入一战后国际联盟","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1926年9月","place":"日内瓦","summary":"德国加入一战后国际联盟并成为常任理事国，标志魏玛德国从战败孤立中部分重返大国外交。","fields":[{"label":"标题","value":"德国加入一战后国际联盟"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1926年9月"},{"label":"地点","value":"日内瓦"},{"label":"主要国家","value":"德国、法国、英国、一战后国际联盟成员国"},{"label":"一句话概括","value":"德国加入一战后国际联盟并成为常任理事国，标志魏玛德国从战败孤立中部分重返大国外交。"},{"label":"参与者","value":"魏玛德国、一战后国际联盟、施特雷泽曼、法国和英国等成员国。"},{"label":"发生了什么","value":"欧洲《洛迦诺公约》达成后，德国获得加入一战后国际联盟的外交条件。1926年，德国正式加入一战后国际联盟，并取得常任理事国席位。施特雷泽曼在日内瓦发表讲话，强调德国愿意通过国际合作恢复地位。加入一战后国际联盟并不意味着德国放弃修约诉求，但它把修约路线转入谈判、仲裁和多边外交框架。"},{"label":"为什么重要","value":"它是魏玛外交的高点之一，显示战败国德国被重新纳入欧洲大国协商机制。"},{"label":"前因","value":"欧洲《洛迦诺公约》和施特雷泽曼外交缓和了德国同西方的关系，德国赔款《道威斯计划》稳定经济也让德国重新进入国际体系成为可能。"},{"label":"后果","value":"德国获得大国外交承认并进入魏玛外交稳定期，但右翼仍把洛迦诺和国际合作视为对凡尔赛体系的妥协。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Völkerbund；Encyclopaedia Britannica: League of Nations；Nobel Prize: Stresemann/Briand。"}],"relationItems":["← 前因：欧洲《洛迦诺公约》","← 前因：古斯塔夫·施特雷泽曼","↔ 相关：一战后国际联盟"],"relations":[{"text":"← 前因：欧洲《洛迦诺公约》","id":"card20"},{"text":"← 前因：古斯塔夫·施特雷泽曼","id":"card19"},{"text":"↔ 相关：一战后国际联盟","id":"card4"}],"source":"history","id":"card21"},{"title":"《凯洛格-白里安公约》","level":"B","type":"制度/文本卡","tags":["战争与外交","文化与思想"],"mainTag":"战争与外交","subTag":"文化与思想","timeText":"1928年签署","place":"巴黎","summary":"《凯洛格-白里安公约》以国际条约形式宣布放弃战争作为国家政策工具，体现一战后和平主义外交想象。","fields":[{"label":"标题","value":"《凯洛格-白里安公约》"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1928年签署"},{"label":"地点","value":"巴黎"},{"label":"主要国家","value":"美国、法国、德国、英国、日本等"},{"label":"一句话概括","value":"《凯洛格-白里安公约》以国际条约形式宣布放弃战争作为国家政策工具，体现一战后和平主义外交想象。"},{"label":"制定方/签署方","value":"美国国务卿凯洛格、法国外交部长白里安推动，多国签署。"},{"label":"主要内容","value":"签约国谴责以战争解决国际争端，并承诺放弃战争作为国家政策工具。"},{"label":"它试图解决什么问题","value":"一战后国际社会希望通过法律和道德承诺限制战争，法国也希望把美国牵入欧洲安全结构。"},{"label":"为什么重要","value":"它体现二十年代国际和平主义高潮，也为后来“侵略战争非法”观念提供法律资源。"},{"label":"争议/局限","value":"公约缺乏有效执行机制，无法阻止日本、意大利和德国后来的侵略行为。"},{"label":"造成的影响","value":"成为战间期国际法重要文本；纽伦堡审判中“侵略战争”概念与其有历史关联。"},{"label":"出处","value":"Encyclopaedia Britannica: Kellogg-Briand Pact；Office of the Historian: Kellogg-Briand Pact；Avalon Project文本。"}],"relationItems":["← 前因：一战后国际联盟","↔ 相关：欧洲《洛迦诺公约》","→ 后果：纳粹战犯纽伦堡审判"],"relations":[{"text":"← 前因：一战后国际联盟","id":"card4"},{"text":"↔ 相关：欧洲《洛迦诺公约》","id":"card20"},{"text":"→ 后果：纳粹战犯纽伦堡审判","id":"extra6"}],"source":"history","id":"card22"},{"title":"魏玛联合政府","level":"B","type":"概念/思潮卡","tags":["政治与制度","无"],"mainTag":"政治与制度","subTag":"无","timeText":"1919年至1920年最典型，魏玛时期多次以联合组阁形式出现","place":"德国","summary":"魏玛联合政府指依靠多党妥协维持议会多数的组阁模式，反映魏玛民主既多元又脆弱的政治结构。","fields":[{"label":"标题","value":"魏玛联合政府"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"无"},{"label":"时间","value":"1919年至1920年最典型，魏玛时期多次以联合组阁形式出现"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"魏玛联合政府指依靠多党妥协维持议会多数的组阁模式，反映魏玛民主既多元又脆弱的政治结构。"},{"label":"核心主张/思路","value":"在比例代表制和政党分裂条件下，政府必须由多个政党联合组成，通过政策妥协维持议会支持。"},{"label":"提出者/代表人物（可选）","value":"社会民主党、中央党、德国民主党是早期“魏玛联盟”核心。"},{"label":"它从何而来","value":"魏玛宪法采用比例代表制，德国社会阶层、宗教和意识形态分裂明显，单一政党难以获得多数。"},{"label":"典型表现","value":"社会民主党、中央党和德国民主党早期合作；后期政府更频繁依赖脆弱联盟或总统任命。"},{"label":"为什么重要","value":"它解释魏玛不是没有民主程序，而是政党体系高度碎片化、反共和国党派强大，使稳定多数难以维持。"},{"label":"争议/局限","value":"联合政府可以代表多元社会，但在经济危机和极端化压力下容易被指责为低效和妥协。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Weimarer Koalition；Encyclopaedia Britannica: Weimar Republic；German History Documents and Images相关资料。"}],"relationItems":["← 前因：魏玛宪法","↔ 相关：德国社会民主党（SPD）","↔ 相关：德国中央党","→ 后果：布吕宁内阁通缩政策"],"relations":[{"text":"← 前因：魏玛宪法","id":"card11"},{"text":"↔ 相关：德国社会民主党（SPD）","id":"extra628"},{"text":"↔ 相关：德国中央党","id":"extra673"},{"text":"→ 后果：布吕宁内阁通缩政策","id":"card65"}],"source":"history","id":"card23"},{"title":"德国民主党","level":"C","type":"组织/机构卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1918年成立，魏玛时期活跃","place":"德国","summary":"德国民主党是魏玛早期自由民主派政党，支持共和国、法治和议会民主，但社会基础逐渐萎缩。","fields":[{"label":"标题","value":"德国民主党"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1918年成立，魏玛时期活跃"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国民主党是魏玛早期自由民主派政党，支持共和国、法治和议会民主，但社会基础逐渐萎缩。"},{"label":"性质/类型","value":"自由主义、共和主义政党。"},{"label":"成立/解散时间","value":"1918年成立；魏玛后期影响下降并改组。"},{"label":"核心目标/宗旨","value":"支持民主共和国、法治、个人自由、教育改革和中产阶级自由主义政治。"},{"label":"关键人物（可选）","value":"瓦尔特·拉特瑙、胡戈·普罗伊斯等与其相关。"},{"label":"关键行动/事件","value":"参与魏玛联盟和早期共和国建构；支持魏玛宪法。"},{"label":"为什么重要","value":"它代表魏玛共和国的自由民主核心，但其衰落说明中产自由主义在危机政治中难以抵挡左右极端动员。"},{"label":"争议/局限","value":"党内社会基础偏城市中产、知识界和自由职业者，难以稳定吸纳大众阶层。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Deutsche Demokratische Partei；German History Documents and Images相关资料。"}],"relationItems":["← 前因：魏玛共和国成立","↔ 相关：魏玛联合政府","↔ 相关：魏玛宪法"],"relations":[{"text":"← 前因：魏玛共和国成立","id":"card7"},{"text":"↔ 相关：魏玛联合政府","id":"card23"},{"text":"↔ 相关：魏玛宪法","id":"card11"}],"source":"history","id":"card24"},{"title":"德国人民党","level":"C","type":"组织/机构卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1918年至1933年","place":"德国","summary":"德国人民党代表民族自由主义和工商资产阶级利益，因施特雷泽曼而成为魏玛中期务实外交的重要支点。","fields":[{"label":"标题","value":"德国人民党"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1918年至1933年"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国人民党代表民族自由主义和工商资产阶级利益，因施特雷泽曼而成为魏玛中期务实外交的重要支点。"},{"label":"性质/类型","value":"民族自由主义、资产阶级政党。"},{"label":"成立/解散时间","value":"1918年成立，1933年纳粹掌权后解散。"},{"label":"核心目标/宗旨","value":"维护私有财产和企业利益，主张民族修约，同时在施特雷泽曼领导下逐步参与共和国治理。"},{"label":"关键人物（可选）","value":"古斯塔夫·施特雷泽曼。"},{"label":"关键行动/事件","value":"参与多届魏玛政府；支持施特雷泽曼外交路线。"},{"label":"为什么重要","value":"它说明魏玛中期稳定不只靠左中派，也需要部分民族自由派接受共和国现实并参与治理。"},{"label":"争议/局限","value":"党内不少成员对共和国认同有限，施特雷泽曼去世后党更难维持务实中间路线。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Deutsche Volkspartei；German History Documents and Images相关资料；Encyclopaedia Britannica: Gustav Stresemann。"}],"relationItems":["↔ 相关：古斯塔夫·施特雷泽曼","↔ 相关：欧洲《洛迦诺公约》","→ 后果：魏玛联合政府"],"relations":[{"text":"↔ 相关：古斯塔夫·施特雷泽曼","id":"card19"},{"text":"↔ 相关：欧洲《洛迦诺公约》","id":"card20"},{"text":"→ 后果：魏玛联合政府","id":"card23"}],"source":"history","id":"card25"},{"title":"德国国家人民党","level":"B","type":"组织/机构卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1918年至1933年","place":"德国","summary":"德国国家人民党是魏玛右翼民族保守政党，长期反对凡尔赛体系和共和国民主。","fields":[{"label":"标题","value":"德国国家人民党"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1918年至1933年"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国国家人民党是魏玛右翼民族保守政党，长期反对凡尔赛体系和共和国民主。"},{"label":"性质/类型","value":"民族保守、右翼政党。"},{"label":"成立/解散时间","value":"1918年成立；1933年后被纳粹体制吸收和解散。"},{"label":"核心目标/宗旨","value":"反对凡尔赛条约，维护民族主义、保守社会秩序、君主主义或威权主义倾向，代表地主、工业和保守中产等部分利益。"},{"label":"关键人物（可选）","value":"阿尔弗雷德·胡根贝格等。"},{"label":"关键行动/事件","value":"反对共和国“履约”外交；参与反德国赔款《杨格计划》运动；后期与纳粹合作削弱魏玛民主。"},{"label":"为什么重要","value":"它是理解魏玛右翼合法政治如何与反民主力量相互接近的关键组织。"},{"label":"争议/局限","value":"党内从传统保守到激进民族主义差异较大，但总体上削弱共和国合法性。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: DNVP；German History Documents and Images相关资料；Encyclopaedia Britannica相关资料。"}],"relationItems":["← 前因：德国“背后一刀”传说","↔ 相关：魏玛德国赔款问题","→ 后果：反德国赔款《杨格计划》运动","→ 后果：希特勒出任德国总理"],"relations":[{"text":"← 前因：德国“背后一刀”传说","id":"extra623"},{"text":"↔ 相关：魏玛德国赔款问题","id":"card3"},{"text":"→ 后果：反德国赔款《杨格计划》运动","id":"card51"},{"text":"→ 后果：希特勒出任德国总理","id":"card71"}],"source":"history","id":"card26"},{"title":"瓦尔特·拉特瑙遇刺","level":"B","type":"事件卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1922年6月24日","place":"德国柏林","summary":"外交部长拉特瑙被右翼恐怖分子刺杀，暴露魏玛共和国早期反犹主义和反共和国暴力的危险。","fields":[{"label":"标题","value":"瓦尔特·拉特瑙遇刺"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1922年6月24日"},{"label":"地点","value":"德国柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"外交部长拉特瑙被右翼恐怖分子刺杀，暴露魏玛共和国早期反犹主义和反共和国暴力的危险。"},{"label":"参与者","value":"瓦尔特·拉特瑙、德国组织“领事”、右翼极端分子、魏玛政府和公众。"},{"label":"发生了什么","value":"拉特瑙是犹太裔工业家、德国民主党政治家和魏玛外交部长，参与《拉帕洛条约》等外交事务。右翼极端分子把他视为“履约政治”、共和国和所谓“犹太影响”的象征。1922年6月24日，刺客在柏林街头驾车接近拉特瑙，向其开枪并投掷手榴弹，拉特瑙身亡。遇刺引发全国震动和大规模悼念，政府通过保卫共和国相关措施打击极右翼组织，但右翼政治暴力并未根除。"},{"label":"为什么重要","value":"它说明魏玛共和国的敌人不只在议会中，也在准军事和恐怖网络中。反犹主义、民族主义和反共和国叙事已经能转化为政治谋杀。"},{"label":"前因","value":"反犹主义、背后一刀传说和反共和国仇恨在右翼网络中扩散，拉特瑙作为犹太裔外长和《拉帕洛条约》签署者成为攻击目标。"},{"label":"后果","value":"共和国通过保卫共和国法打击右翼恐怖，但未能根除反犹主义和准军事网络，政治暗杀继续侵蚀魏玛安全感。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Rathenau-Mord；Encyclopaedia Britannica: Walther Rathenau；United States Holocaust Memorial Museum相关资料。"}],"relationItems":["← 前因：德苏《拉帕洛条约》","← 前因：反犹主义政治运动","→ 后果：德国保卫共和国法","↔ 相关：德国民主党"],"relations":[{"text":"← 前因：德苏《拉帕洛条约》","id":"card17"},{"text":"← 前因：反犹主义政治运动","id":"extra686"},{"text":"→ 后果：德国保卫共和国法","id":"card29"},{"text":"↔ 相关：德国民主党","id":"card24"}],"source":"history","id":"card27"},{"title":"德国组织“领事”","level":"C","type":"组织/机构卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1920年代初活跃","place":"德国","summary":"德国组织“领事”是魏玛早期右翼秘密恐怖组织，参与政治暗杀，体现魏玛德国自由军团网络向地下暴力转化。","fields":[{"label":"标题","value":"德国组织“领事”"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1920年代初活跃"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国组织“领事”是魏玛早期右翼秘密恐怖组织，参与政治暗杀，体现魏玛德国自由军团网络向地下暴力转化。"},{"label":"性质/类型","value":"右翼秘密组织、恐怖组织。"},{"label":"成立/解散时间","value":"魏玛德国卡普政变失败后由埃尔哈特旅相关网络发展；1922年拉特瑙遇刺后遭取缔。"},{"label":"核心目标/宗旨","value":"推翻魏玛共和国，打击共和国政治家、左翼和被右翼视为“卖国”的人物。"},{"label":"关键人物（可选）","value":"赫尔曼·埃尔哈特相关网络。"},{"label":"关键行动/事件","value":"参与暗杀马蒂亚斯·埃茨贝格、瓦尔特·拉特瑙等政治谋杀。"},{"label":"为什么重要","value":"它说明魏玛右翼暴力不是零散个人行为，而有组织网络和准军事前史。"},{"label":"争议/局限","value":"组织被取缔后，成员和网络并未完全消失，部分转入其他右翼团体。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Organisation Consul；German History Documents and Images相关资料；United States Holocaust Memorial Museum相关资料。"}],"relationItems":["← 前因：魏玛德国自由军团","→ 后果：瓦尔特·拉特瑙遇刺","↔ 相关：德国“背后一刀”传说"],"relations":[{"text":"← 前因：魏玛德国自由军团","id":"card9"},{"text":"→ 后果：瓦尔特·拉特瑙遇刺","id":"card27"},{"text":"↔ 相关：德国“背后一刀”传说","id":"extra623"}],"source":"history","id":"card28"},{"title":"德国保卫共和国法","level":"C","type":"制度/文本卡","tags":["政治与制度","无"],"mainTag":"政治与制度","subTag":"无","timeText":"1922年通过","place":"德国","summary":"德国保卫共和国法在拉特瑙遇刺后出台，试图用法律手段打击反共和国暴力和极端组织。","fields":[{"label":"标题","value":"德国保卫共和国法"},{"label":"分级","value":"C"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"无"},{"label":"时间","value":"1922年通过"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国保卫共和国法在拉特瑙遇刺后出台，试图用法律手段打击反共和国暴力和极端组织。"},{"label":"制定方/签署方","value":"魏玛共和国政府和帝国议会。"},{"label":"主要内容","value":"加强对反共和国组织、政治谋杀和煽动暴力活动的惩处，设立或强化保护共和国的司法和行政工具。"},{"label":"它试图解决什么问题","value":"魏玛早期右翼暗杀和恐怖活动威胁共和国政治人物和制度稳定，政府需要公开回应。"},{"label":"为什么重要","value":"它反映魏玛民主并非完全被动，也尝试用法治手段自卫。"},{"label":"争议/局限","value":"司法系统中保守和反共和国倾向仍然存在，法律执行不均衡，难以彻底清除右翼暴力网络。"},{"label":"造成的影响","value":"德国组织“领事”等受到打击；共和国自卫问题成为长期争议。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Republikschutzgesetz；German History Documents and Images相关资料。"}],"relationItems":["← 前因：瓦尔特·拉特瑙遇刺","← 前因：德国组织“领事”","↔ 相关：魏玛共和国成立"],"relations":[{"text":"← 前因：瓦尔特·拉特瑙遇刺","id":"card27"},{"text":"← 前因：德国组织“领事”","id":"card28"},{"text":"↔ 相关：魏玛共和国成立","id":"card7"}],"source":"history","id":"card29"},{"title":"德国包豪斯","level":"B","type":"组织/机构卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1919年至1933年","place":"魏玛、德绍、柏林","summary":"德国包豪斯把艺术、工艺、建筑和工业设计结合起来，成为现代主义设计和建筑史的核心机构。","fields":[{"label":"标题","value":"德国包豪斯"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1919年至1933年"},{"label":"地点","value":"魏玛、德绍、柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国包豪斯把艺术、工艺、建筑和工业设计结合起来，成为现代主义设计和建筑史的核心机构。"},{"label":"性质/类型","value":"艺术、设计与建筑学校。"},{"label":"成立/解散时间","value":"1919年由格罗皮乌斯在魏玛创立，后迁至德绍和柏林，1933年在纳粹压力下关闭。"},{"label":"核心目标/宗旨","value":"打破艺术与工艺、设计与工业之间的隔阂，为现代工业社会创造新的形式语言。"},{"label":"关键人物（可选）","value":"瓦尔特·格罗皮乌斯、保罗·克利、瓦西里·康定斯基、密斯·凡德罗等。"},{"label":"关键行动/事件","value":"发展基础课程、工作坊教学、现代建筑和家具设计；德绍校舍成为现代主义建筑代表。"},{"label":"为什么重要","value":"德国包豪斯是魏玛文化国际影响最大的成果之一，其设计理念深刻影响二十世纪建筑、平面设计、家具和艺术教育。"},{"label":"争议/局限","value":"它在魏玛时期持续遭到保守派和民族主义者攻击，被指责为“非德国”“左翼”或“堕落”。"},{"label":"出处","value":"Bauhaus Dessau Foundation；Deutsches Historisches Museum/LeMO: Bauhaus；Encyclopaedia Britannica: Bauhaus。"}],"relationItems":["← 前因：魏玛共和国成立","↔ 相关：德国新客观主义","↔ 相关：魏玛文化","→ 后果：纳粹文化清洗"],"relations":[{"text":"← 前因：魏玛共和国成立","id":"card7"},{"text":"↔ 相关：德国新客观主义","id":"card31"},{"text":"↔ 相关：魏玛文化","id":"card197"}],"source":"history","id":"card30"},{"title":"德国新客观主义","level":"B","type":"概念/思潮卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1920年代魏玛共和国时期","place":"德国","summary":"德国新客观主义以冷静、尖锐和现实观察回应战后社会，成为魏玛艺术、文学和摄影的重要风格。","fields":[{"label":"标题","value":"德国新客观主义"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1920年代魏玛共和国时期"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国新客观主义以冷静、尖锐和现实观察回应战后社会，成为魏玛艺术、文学和摄影的重要风格。"},{"label":"核心主张/思路","value":"拒绝表现主义的主观激情，转向清醒、讽刺、现实、都市和社会剖析。"},{"label":"提出者/代表人物（可选）","value":"奥托·迪克斯、乔治·格罗兹、克里斯蒂安·沙德等。"},{"label":"它从何而来","value":"一战创伤、通胀、都市消费文化、政治极化和现代传媒共同塑造了更冷峻的现实感。"},{"label":"典型表现","value":"残疾退伍军人、都市夜生活、资产阶级伪善、性别变化、政治暴力和社会不平等。"},{"label":"为什么重要","value":"它是理解魏玛文化的关键入口，把共和国的现代性和病灶都以视觉和文学形式呈现出来。"},{"label":"争议/局限","value":"德国新客观主义不是统一组织，而是后人用来概括多种相近风格的标签。"},{"label":"出处","value":"Tate: New Objectivity；Deutsches Historisches Museum/LeMO: Neue Sachlichkeit；MoMA相关资料。"}],"relationItems":["↔ 相关：德国包豪斯","↔ 相关：弗里茨·朗电影《大都会》","↔ 相关：魏玛文化"],"relations":[{"text":"↔ 相关：德国包豪斯","id":"card30"},{"text":"↔ 相关：弗里茨·朗电影《大都会》","id":"extra65"},{"text":"↔ 相关：魏玛文化","id":"card197"}],"source":"history","id":"card31"},{"title":"魏玛“新女性”","level":"B","type":"概念/思潮卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1920年代魏玛共和国时期","place":"德国城市，尤其柏林","summary":"魏玛“新女性”是魏玛都市文化中独立、就业、消费和性别角色变化的象征形象。","fields":[{"label":"标题","value":"魏玛“新女性”"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1920年代魏玛共和国时期"},{"label":"地点","value":"德国城市，尤其柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"魏玛“新女性”是魏玛都市文化中独立、就业、消费和性别角色变化的象征形象。"},{"label":"核心主张/思路","value":"女性可以接受教育、进入办公室和服务业、追求消费、恋爱自主和公共生活，不再完全被家庭角色定义。"},{"label":"提出者/代表人物（可选）","value":"不是单一人物提出，而是媒体、广告、电影、杂志和城市生活共同塑造的文化形象。"},{"label":"它从何而来","value":"一战后女性劳动经验、魏玛宪法赋予女性选举权、城市白领岗位增加和大众消费文化发展。"},{"label":"典型表现","value":"短发、现代服饰、办公室女职员、电影院和咖啡馆、运动和都市娱乐。"},{"label":"为什么重要","value":"它显示魏玛现代性进入日常生活和身体形象，也引发保守派对性别秩序瓦解的焦虑。"},{"label":"争议/局限","value":"魏玛“新女性”更多是城市中产和白领文化形象，不代表所有德国女性真实处境。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Neue Frau；German History Documents and Images相关资料；Weimar Culture相关研究。"}],"relationItems":["← 前因：德国妇女运动","↔ 相关：魏玛文化","↔ 相关：魏玛柏林现代性"],"relations":[{"text":"← 前因：德国妇女运动","id":"extra684"},{"text":"↔ 相关：魏玛文化","id":"card197"},{"text":"↔ 相关：魏玛柏林现代性","id":"card33"}],"source":"history","id":"card32"},{"title":"魏玛柏林现代性","level":"B","type":"概念/思潮卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"十九世纪末至魏玛时期，1920年代最突出","place":"德国柏林","summary":"魏玛柏林现代性指柏林作为大都市在交通、电影、夜生活、政治冲突和大众文化中呈现的现代经验。","fields":[{"label":"标题","value":"魏玛柏林现代性"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"十九世纪末至魏玛时期，1920年代最突出"},{"label":"地点","value":"德国柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"魏玛柏林现代性指柏林作为大都市在交通、电影、夜生活、政治冲突和大众文化中呈现的现代经验。"},{"label":"核心主张/思路","value":"这不是单一思想，而是一种城市经验：速度、消费、匿名性、阶级混杂、性别变化和政治街头化。"},{"label":"提出者/代表人物（可选）","value":"无单一提出者；艺术家、记者、电影人和社会观察者共同塑造其形象。"},{"label":"它从何而来","value":"帝国时期人口爆炸、工业化、电气化和魏玛时期文化开放共同推动柏林成为欧洲现代都市。"},{"label":"典型表现","value":"地铁、电车、百货公司、电影院、夜总会、政治游行、街头暴力和租住营房。"},{"label":"为什么重要","value":"柏林是魏玛共和国最鲜明的窗口：它同时代表自由、实验、消费、贫困和极端政治。"},{"label":"争议/局限","value":"柏林经验不能代表整个德国，保守乡村和小城对柏林常抱有强烈反感。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Berlin in der Weimarer Republik；Peter Gay, Weimar Culture；German History Documents and Images相关资料。"}],"relationItems":["← 前因：德意志帝国柏林租住营房","↔ 相关：魏玛“新女性”","↔ 相关：弗里茨·朗电影《大都会》","↔ 相关：魏玛广播文化"],"relations":[{"text":"← 前因：德意志帝国柏林租住营房","id":"extra683"},{"text":"↔ 相关：魏玛“新女性”","id":"card32"},{"text":"↔ 相关：弗里茨·朗电影《大都会》","id":"extra65"},{"text":"↔ 相关：魏玛广播文化","id":"card80"}],"source":"history","id":"card33"},{"title":"魏玛政治街头暴力","level":"B","type":"概念/思潮卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1918年至1933年，1929年后尤为严重","place":"德国城市街头","summary":"魏玛政治街头暴力是政党准军事组织、失业青年和意识形态仇恨在公共空间中的持续冲突。","fields":[{"label":"标题","value":"魏玛政治街头暴力"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1918年至1933年，1929年后尤为严重"},{"label":"地点","value":"德国城市街头"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"魏玛政治街头暴力是政党准军事组织、失业青年和意识形态仇恨在公共空间中的持续冲突。"},{"label":"核心主张/思路","value":"这不是思想，而是一种政治实践：通过游行、制服、集会保护、挑衅和斗殴来争夺街头控制权和群众心理。"},{"label":"提出者/代表人物（可选）","value":"纳粹冲锋队、德国红色阵线战士联盟、德国钢盔团等组织都参与其中。"},{"label":"它从何而来","value":"战败后武器和退伍军人流入社会，革命与反革命暴力延续，经济危机又扩大了可动员人群。"},{"label":"典型表现","value":"集会冲突、酒馆斗殴、暗杀、准军事游行、街区争夺和警察镇压。"},{"label":"为什么重要","value":"魏玛民主不是只在议会中失败，也在街头被持续消耗。暴力让极端政党显示力量，并削弱普通人对共和国秩序的信任。"},{"label":"争议/局限","value":"不同组织的暴力目标和社会基础不完全相同，不能把所有街头冲突简单等同。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Politische Gewalt；United States Holocaust Memorial Museum相关资料；German History Documents and Images相关资料。"}],"relationItems":["← 前因：魏玛德国自由军团","→ 后果：纳粹冲锋队","→ 后果：希特勒出任德国总理","↔ 相关：德国共产党成立"],"relations":[{"text":"← 前因：魏玛德国自由军团","id":"card9"},{"text":"→ 后果：纳粹冲锋队","id":"extra93"},{"text":"→ 后果：希特勒出任德国总理","id":"card71"},{"text":"↔ 相关：德国共产党成立","id":"extra694"}],"source":"history","id":"card34"},{"title":"德国钢盔团","level":"B","type":"组织/机构卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1918年后成立，魏玛时期活跃","place":"德国","summary":"德国钢盔团是一战退伍军人右翼组织，代表魏玛时期民族主义、反共和国和准军事文化的重要力量。","fields":[{"label":"标题","value":"德国钢盔团"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1918年后成立，魏玛时期活跃"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国钢盔团是一战退伍军人右翼组织，代表魏玛时期民族主义、反共和国和准军事文化的重要力量。"},{"label":"性质/类型","value":"退伍军人组织、右翼准军事团体。"},{"label":"成立/解散时间","value":"1918年后成立；纳粹掌权后逐步被吸收和改组。"},{"label":"核心目标/宗旨","value":"维护前线军人荣誉，反对凡尔赛体系和魏玛共和国，支持民族主义和威权政治。"},{"label":"关键人物（可选）","value":"弗朗茨·泽尔特等。"},{"label":"关键行动/事件","value":"参与右翼政治动员、反共和集会，与德国国家人民党和其他保守民族主义力量关系密切。"},{"label":"为什么重要","value":"它说明魏玛右翼不只有纳粹党，还有更广泛的退伍军人和民族保守组织网络。"},{"label":"争议/局限","value":"德国钢盔团与纳粹既合作又竞争，最终在纳粹体制中失去独立性。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Stahlhelm；German History Documents and Images相关资料；United States Holocaust Memorial Museum相关资料。"}],"relationItems":["← 前因：第一次世界大战德国战败","↔ 相关：德国“背后一刀”传说","↔ 相关：魏玛政治街头暴力"],"relations":[{"text":"← 前因：第一次世界大战德国战败","id":"extra926"},{"text":"↔ 相关：德国“背后一刀”传说","id":"extra623"},{"text":"↔ 相关：魏玛政治街头暴力","id":"card34"}],"source":"history","id":"card35"},{"title":"德国红色阵线战士联盟","level":"C","type":"组织/机构卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1924年至1929年被禁","place":"德国","summary":"德国红色阵线战士联盟是德国共产党周边准军事组织，在魏玛街头政治中与右翼组织和警察频繁冲突。","fields":[{"label":"标题","value":"德国红色阵线战士联盟"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1924年至1929年被禁"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国红色阵线战士联盟是德国共产党周边准军事组织，在魏玛街头政治中与右翼组织和警察频繁冲突。"},{"label":"性质/类型","value":"共产党关联准军事和群众组织。"},{"label":"成立/解散时间","value":"1924年成立；1929年在普鲁士等地被禁止。"},{"label":"核心目标/宗旨","value":"保护共产党集会，动员工人和退伍军人，展示革命左翼街头力量。"},{"label":"关键人物（可选）","value":"恩斯特·台尔曼与其政治形象密切相关。"},{"label":"关键行动/事件","value":"参与游行、集会保护和街头冲突；与纳粹冲锋队、德国钢盔团和警察发生对抗。"},{"label":"为什么重要","value":"它说明魏玛街头暴力具有左右多方参与，国家秩序在极化政治中不断被削弱。"},{"label":"争议/局限","value":"其活动被政府视为威胁公共秩序，但禁止也加深共产党对共和国的敌意。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Roter Frontkämpferbund；German History Documents and Images相关资料。"}],"relationItems":["← 前因：德国共产党成立","↔ 相关：魏玛政治街头暴力","↔ 相关：纳粹冲锋队"],"relations":[{"text":"← 前因：德国共产党成立","id":"extra694"},{"text":"↔ 相关：魏玛政治街头暴力","id":"card34"},{"text":"↔ 相关：纳粹冲锋队","id":"extra93"}],"source":"history","id":"card36"},{"title":"保罗·冯·兴登堡","level":"B","type":"人物卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1847年至1934年；1925年至1934年任德国总统","place":"德国","summary":"兴登堡从一战名将变成魏玛总统，其威望帮助共和国维持表面稳定，也在魏玛总统内阁和希特勒任命中发挥决定作用。","fields":[{"label":"标题","value":"保罗·冯·兴登堡"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1847年至1934年；1925年至1934年任德国总统"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"兴登堡从一战名将变成魏玛总统，其威望帮助共和国维持表面稳定，也在魏玛总统内阁和希特勒任命中发挥决定作用。"},{"label":"生卒年/活跃年代","value":"1847-1934；一战期间任德军最高统帅之一，1925年起任总统。"},{"label":"身份/职务","value":"德意志帝国陆军元帅，魏玛共和国总统。"},{"label":"关键贡献/作为","value":"1914年后成为德国战争神话中的英雄；1925年当选总统；1930年后依靠紧急法令支持魏玛总统内阁；1933年任命希特勒为总理。"},{"label":"核心主张/立场","value":"保守民族主义、君主制情感和对议会民主的有限认同并存。"},{"label":"为什么重要","value":"兴登堡的个人声望使魏玛宪法第48条和总统权力获得政治合法性。他不是纳粹，但其任命决定打开了纳粹合法掌权通道。"},{"label":"争议/评价","value":"常被视为魏玛后期保守精英误判的关键人物；其年老、顾问圈和反议会倾向放大了制度危机。"},{"label":"关联事件（可选）","value":"1925年德国总统选举、1932年德国总统选举、希特勒出任德国总理。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Paul von Hindenburg；Encyclopaedia Britannica: Paul von Hindenburg；United States Holocaust Memorial Museum相关资料。"}],"relationItems":["← 前因：一战东线坦能堡战役","→ 后果：魏玛总统内阁","→ 后果：希特勒出任德国总理","↔ 相关：魏玛宪法第48条"],"relations":[{"text":"← 前因：一战东线坦能堡战役","id":"extra649"},{"text":"→ 后果：魏玛总统内阁","id":"card39"},{"text":"→ 后果：希特勒出任德国总理","id":"card71"},{"text":"↔ 相关：魏玛宪法第48条","id":"card12"}],"source":"history","id":"card37"},{"title":"1925年德国总统选举","level":"B","type":"事件卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1925年3月至4月","place":"德国","summary":"1925年总统选举使保守民族主义象征兴登堡进入共和国最高职位，改变魏玛政治平衡。","fields":[{"label":"标题","value":"1925年德国总统选举"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1925年3月至4月"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1925年总统选举使保守民族主义象征兴登堡进入共和国最高职位，改变魏玛政治平衡。"},{"label":"参与者","value":"保罗·冯·兴登堡、威廉·马克思、恩斯特·台尔曼、德国选民、右翼和中间派政党。"},{"label":"发生了什么","value":"魏玛首任总统艾伯特去世后，德国举行首次总统直选。第一轮没有候选人获得绝对多数，第二轮中，右翼阵营推举一战元帅兴登堡参选，中间派支持中央党人威廉·马克思，共产党仍推出台尔曼。兴登堡凭借战争英雄形象、保守选民支持和反共和国情绪获胜。虽然他宣誓遵守宪法，但共和国最高职位由一个旧帝国象征人物担任，显示魏玛民主的社会认同基础并不稳固。"},{"label":"为什么重要","value":"它使总统职位从共和国缔造者艾伯特转入保守军人手中，为后来的魏玛总统内阁政治埋下前提。"},{"label":"前因","value":"艾伯特去世后共和国需要选出新总统，魏玛宪法赋予总统较大权力，保守派把兴登堡作为能够超越党派、恢复旧秩序象征的人物。"},{"label":"后果","value":"兴登堡当选使总统职位带有强烈保守和军人色彩，后来总统内阁政治更容易以他的权威绕开议会。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Reichspräsidentenwahl 1925；German History Documents and Images相关资料；Encyclopaedia Britannica: Hindenburg。"}],"relationItems":["← 前因：保罗·冯·兴登堡","→ 后果：魏玛总统内阁","↔ 相关：魏玛宪法第48条"],"relations":[{"text":"← 前因：保罗·冯·兴登堡","id":"card37"},{"text":"→ 后果：魏玛总统内阁","id":"card39"},{"text":"↔ 相关：魏玛宪法第48条","id":"card12"}],"source":"history","id":"card38"},{"title":"魏玛总统内阁","level":"A","type":"概念/思潮卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1930年至1933年","place":"德国","summary":"魏玛总统内阁指魏玛后期政府不再依赖稳定议会多数，而依靠总统任命和紧急法令治理。","fields":[{"label":"标题","value":"魏玛总统内阁"},{"label":"分级","value":"A"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1930年至1933年"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"魏玛总统内阁指魏玛后期政府不再依赖稳定议会多数，而依靠总统任命和紧急法令治理。"},{"label":"核心主张/思路","value":"在议会多数难以形成时，总统任命总理，并用第48条紧急法令绕开或压制议会。"},{"label":"提出者/代表人物（可选）","value":"兴登堡、布吕宁、巴本、施莱歇尔及总统顾问圈。"},{"label":"它从何而来","value":"大萧条冲击、政党碎片化、议会多数崩溃和总统权力设计共同推动魏玛总统内阁出现。"},{"label":"典型表现","value":"政府预算和经济政策通过紧急法令实施；议会反对时可被解散重新选举。"},{"label":"为什么重要","value":"魏玛总统内阁是魏玛民主死亡前的过渡机制。它没有立即建立纳粹独裁，却先把议会民主掏空，使威权治理常态化。"},{"label":"争议/局限","value":"支持者认为它是危机治理，批评者认为它破坏议会责任政治并为希特勒开路。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Präsidialkabinette；Encyclopaedia Britannica: Weimar Republic；German History Documents and Images相关资料。"}],"relationItems":["← 前因：魏玛宪法第48条","← 前因：1925年德国总统选举","→ 后果：巴本内阁","→ 后果：魏玛施莱歇尔内阁","→ 后果：希特勒出任德国总理"],"relations":[{"text":"← 前因：魏玛宪法第48条","id":"card12"},{"text":"← 前因：1925年德国总统选举","id":"card38"},{"text":"→ 后果：魏玛施莱歇尔内阁","id":"card43"},{"text":"→ 后果：希特勒出任德国总理","id":"card71"}],"source":"history","id":"card39"},{"title":"弗朗茨·冯·巴本","level":"B","type":"人物卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1879年至1969年；1932年至1933年为关键政治活动期","place":"德国","summary":"巴本是魏玛末期保守精英政治的代表，试图利用纳粹群众力量摧毁议会民主，最终帮助希特勒上台。","fields":[{"label":"标题","value":"弗朗茨·冯·巴本"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1879年至1969年；1932年至1933年为关键政治活动期"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"巴本是魏玛末期保守精英政治的代表，试图利用纳粹群众力量摧毁议会民主，最终帮助希特勒上台。"},{"label":"生卒年/活跃年代","value":"1879-1969；1932年任总理，1933年任希特勒内阁副总理。"},{"label":"身份/职务","value":"保守派政治家、德国总理、后任副总理。"},{"label":"关键贡献/作为","value":"1932年出任魏玛总统内阁总理，发动1932年普鲁士政变，推动同纳粹交易，并说服兴登堡任命希特勒。"},{"label":"核心主张/立场","value":"反议会民主，倾向威权保守国家，希望借纳粹力量重组右翼统治。"},{"label":"为什么重要","value":"巴本不是纳粹党人，但他是保守精英误判纳粹、拆毁共和国制度防线的关键人物。"},{"label":"争议/评价","value":"其“控制希特勒”的设想被证明彻底失败，是魏玛崩溃中最典型的精英误判。"},{"label":"关联事件（可选）","value":"1932年普鲁士政变、巴本税收抵用券与降薪法令、希特勒出任德国总理。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Franz von Papen；Encyclopaedia Britannica: Franz von Papen；United States Holocaust Memorial Museum相关资料。"}],"relationItems":["← 前因：魏玛总统内阁","→ 后果：1932年普鲁士政变","→ 后果：希特勒出任德国总理","↔ 相关：巴本税收抵用券与降薪法令"],"relations":[{"text":"← 前因：魏玛总统内阁","id":"card39"},{"text":"→ 后果：1932年普鲁士政变","id":"card41"},{"text":"→ 后果：希特勒出任德国总理","id":"card71"},{"text":"↔ 相关：巴本税收抵用券与降薪法令","id":"card70"}],"source":"history","id":"card40"},{"title":"1932年普鲁士政变","level":"B","type":"事件卡","tags":["政治与制度","无"],"mainTag":"政治与制度","subTag":"无","timeText":"1932年7月20日","place":"德国普鲁士邦，柏林","summary":"1932年普鲁士政变中巴本政府解除普鲁士社民党政府，摧毁魏玛民主最重要的地方堡垒。","fields":[{"label":"标题","value":"1932年普鲁士政变"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"无"},{"label":"时间","value":"1932年7月20日"},{"label":"地点","value":"德国普鲁士邦，柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1932年普鲁士政变中巴本政府解除普鲁士社民党政府，摧毁魏玛民主最重要的地方堡垒。"},{"label":"参与者","value":"巴本内阁、兴登堡、普鲁士邦政府、奥托·布劳恩、卡尔·泽韦林、国防军和警察。"},{"label":"发生了什么","value":"1932年普鲁士州议会选举后，民主政党失去稳定多数，但社民党领导的普鲁士政府仍以看守政府维持行政。巴本借口1932年阿尔托纳血腥星期日等街头暴力和公共秩序危机，请求兴登堡发布紧急法令，任命自己为普鲁士专员。中央政府解除普鲁士政府职务，接管警察和行政权。普鲁士政府选择法律抗议而非武装抵抗，国家法院后来只作有限裁决，无法恢复其实际权力。"},{"label":"为什么重要","value":"普鲁士掌握德国最大邦和重要警察系统。政变使共和国失去关键制度防线，后来纳粹接收国家机器更容易。"},{"label":"前因","value":"巴本内阁缺乏议会多数，魏玛街头暴力升级给中央政府提供干预借口；普鲁士社民党政府控制的警察体系是共和国最后的重要制度堡垒之一。"},{"label":"后果","value":"政变削弱联邦制和民主防线，中央政府控制普鲁士警察与行政机器，使希特勒上台后更容易掌握国家强制力量。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Preußenschlag；German History Documents and Images相关资料；Encyclopaedia Britannica: Franz von Papen。"}],"relationItems":["← 前因：弗朗茨·冯·巴本","← 前因：魏玛总统内阁","→ 后果：希特勒出任德国总理","↔ 相关：魏玛宪法第48条"],"relations":[{"text":"← 前因：弗朗茨·冯·巴本","id":"card40"},{"text":"← 前因：魏玛总统内阁","id":"card39"},{"text":"→ 后果：希特勒出任德国总理","id":"card71"},{"text":"↔ 相关：魏玛宪法第48条","id":"card12"}],"source":"history","id":"card41"},{"title":"库尔特·冯·施莱歇尔","level":"B","type":"人物卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1882年至1934年；1932年至1933年任总理","place":"德国","summary":"施莱歇尔是魏玛最后一任非纳粹总理，试图分裂纳粹并建立跨阶层联盟但失败。","fields":[{"label":"标题","value":"库尔特·冯·施莱歇尔"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1882年至1934年；1932年至1933年任总理"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"施莱歇尔是魏玛最后一任非纳粹总理，试图分裂纳粹并建立跨阶层联盟但失败。"},{"label":"生卒年/活跃年代","value":"1882-1934；1932年12月至1933年1月任总理。"},{"label":"身份/职务","value":"德国将军、政治操盘者、魏玛末任非纳粹总理。"},{"label":"关键贡献/作为","value":"长期在国防军和总统政治中活动；推动魏玛总统内阁；试图拉拢工会和纳粹左翼格雷戈尔·施特拉asser，形成“横向阵线”。"},{"label":"核心主张/立场","value":"威权保守而非议会民主派，希望通过军方和社会政策组合稳定国家。"},{"label":"为什么重要","value":"他的失败说明魏玛总统内阁已没有稳定社会基础，也说明保守军政精英无法在不交权给希特勒的情况下控制危机。"},{"label":"争议/评价","value":"施莱歇尔既是魏玛议会民主的破坏者之一，也是纳粹上台前最后一个试图阻止希特勒的保守政治家。"},{"label":"关联事件（可选）","value":"魏玛施莱歇尔内阁、希特勒出任德国总理、纳粹长刀之夜。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Kurt von Schleicher；Encyclopaedia Britannica: Kurt von Schleicher；United States Holocaust Memorial Museum相关资料。"}],"relationItems":["← 前因：魏玛总统内阁","→ 后果：希特勒出任德国总理","→ 后果：纳粹长刀之夜"],"relations":[{"text":"← 前因：魏玛总统内阁","id":"card39"},{"text":"→ 后果：希特勒出任德国总理","id":"card71"},{"text":"→ 后果：纳粹长刀之夜","id":"extra108"}],"source":"history","id":"card42"},{"title":"魏玛施莱歇尔内阁","level":"B","type":"事件卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1932年12月至1933年1月","place":"德国","summary":"魏玛施莱歇尔内阁是魏玛最后一个非纳粹政府，试图用“横向阵线”稳定局势但迅速失败。","fields":[{"label":"标题","value":"魏玛施莱歇尔内阁"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1932年12月至1933年1月"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"魏玛施莱歇尔内阁是魏玛最后一个非纳粹政府，试图用“横向阵线”稳定局势但迅速失败。"},{"label":"参与者","value":"库尔特·冯·施莱歇尔、兴登堡、工会、格雷戈尔·施特拉asser、纳粹党、保守精英。"},{"label":"发生了什么","value":"巴本内阁失去可操作基础后，兴登堡任命施莱歇尔为总理。施莱歇尔试图同时争取工会、部分社会政策支持者和纳粹党内较左的施特拉asser派，形成跨阶层支持，削弱希特勒对纳粹的控制。但希特勒压制党内分裂，工会和社民党也不愿信任军方保守总理。施莱歇尔无法取得议会多数，也无法说服兴登堡授权长期紧急统治。巴本则在幕后同希特勒接近，最终施莱歇尔辞职。"},{"label":"为什么重要","value":"它是魏玛制度崩溃的最后阶段，说明非纳粹保守威权方案已经耗尽。"},{"label":"前因","value":"巴本内阁无法获得议会支持，施莱歇尔试图通过分化纳粹和争取工会支持建立“横向阵线”，但缺乏稳定政治基础。"},{"label":"后果","value":"施莱歇尔失败后，保守派转向同希特勒交易，兴登堡最终任命希特勒为总理，魏玛总统内阁道路走到尽头。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Präsidialkabinette/Schleicher；Encyclopaedia Britannica: Kurt von Schleicher；German History Documents and Images相关资料。"}],"relationItems":["← 前因：库尔特·冯·施莱歇尔","← 前因：魏玛总统内阁","→ 后果：希特勒出任德国总理"],"relations":[{"text":"← 前因：库尔特·冯·施莱歇尔","id":"card42"},{"text":"← 前因：魏玛总统内阁","id":"card39"},{"text":"→ 后果：希特勒出任德国总理","id":"card71"}],"source":"history","id":"card43"},{"title":"1930年德国国会选举","level":"A","type":"事件卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1930年9月14日","place":"德国","summary":"1930年国会选举中纳粹党跃升为第二大党，标志大萧条开始摧毁魏玛政党格局。","fields":[{"label":"标题","value":"1930年德国国会选举"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1930年9月14日"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1930年国会选举中纳粹党跃升为第二大党，标志大萧条开始摧毁魏玛政党格局。"},{"label":"参与者","value":"纳粹党、社会民主党、共产党、中央党、德国国家人民党、德国选民。"},{"label":"发生了什么","value":"大萧条冲击德国后，失业和社会焦虑急剧上升。布吕宁政府依靠紧急法令推行紧缩，并在议会受阻后解散国会重新选举。1930年9月选举中，纳粹党得票率和席位暴增，从边缘党变成国会第二大党；共产党也有所增长，中间和传统资产阶级政党受挤压。新国会更难形成稳定多数，魏玛总统内阁对紧急法令的依赖进一步加深。"},{"label":"为什么重要","value":"它是纳粹从地方极端运动跃升为全国政治核心力量的转折点。"},{"label":"前因","value":"大萧条冲击德国信贷和就业，布吕宁通缩政策加剧社会痛苦，选民对传统执政党和议会妥协失去信心。"},{"label":"后果","value":"纳粹党和共产党得票大增，议会多数更加破碎，总统紧急法令治理成为常态，魏玛民主进入最后危机。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Reichstagswahl 1930；United States Holocaust Memorial Museum相关资料；German History Documents and Images相关资料。"}],"relationItems":["← 前因：布吕宁内阁通缩政策","← 前因：华尔街“黑色星期四”","→ 后果：1932年7月德国国会选举","↔ 相关：纳粹党成立"],"relations":[{"text":"← 前因：布吕宁内阁通缩政策","id":"card65"},{"text":"← 前因：华尔街“黑色星期四”","id":"card64"},{"text":"→ 后果：1932年7月德国国会选举","id":"card46"},{"text":"↔ 相关：纳粹党成立","id":"extra92"}],"source":"history","id":"card44"},{"title":"1932年德国总统选举","level":"B","type":"事件卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1932年3月至4月","place":"德国","summary":"1932年总统选举中兴登堡击败希特勒连任，但选举显示纳粹已成为全国性群众力量。","fields":[{"label":"标题","value":"1932年德国总统选举"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1932年3月至4月"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1932年总统选举中兴登堡击败希特勒连任，但选举显示纳粹已成为全国性群众力量。"},{"label":"参与者","value":"保罗·冯·兴登堡、阿道夫·希特勒、恩斯特·台尔曼、德国选民、各主要政党。"},{"label":"发生了什么","value":"兴登堡任期届满时，德国已深陷经济和政治危机。希特勒以纳粹党领袖身份参选，试图通过总统选举证明自己拥有全国合法性。第一轮无人获得绝对多数，第二轮中，许多支持共和国的选民被迫支持保守的兴登堡，以阻止希特勒。兴登堡最终连任，但希特勒获得巨大票数，纳粹宣传机器把失败包装为群众力量展示。选举没有稳定共和国，反而暴露传统权威只能暂时挡住纳粹。"},{"label":"为什么重要","value":"它显示希特勒尚未掌权时已经能动员数千万选民，魏玛政治中心被极端力量挤压。"},{"label":"前因","value":"经济危机和失业使政治极化加深，兴登堡虽代表保守权威，却成为阻止希特勒直接赢得总统职位的共和国临时屏障。"},{"label":"后果","value":"希特勒虽败选却证明纳粹群众动员能力，随后的国会选举和保守派宫廷政治把他继续推向总理职位。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Reichspräsidentenwahl 1932；United States Holocaust Memorial Museum相关资料；German History Documents and Images相关资料。"}],"relationItems":["← 前因：保罗·冯·兴登堡","← 前因：1930年德国国会选举","→ 后果：1932年7月德国国会选举"],"relations":[{"text":"← 前因：保罗·冯·兴登堡","id":"card37"},{"text":"← 前因：1930年德国国会选举","id":"card44"},{"text":"→ 后果：1932年7月德国国会选举","id":"card46"}],"source":"history","id":"card45"},{"title":"1932年7月德国国会选举","level":"A","type":"事件卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1932年7月31日","place":"德国","summary":"1932年7月国会选举使纳粹党成为最大党，但未能获得多数，德国议会政治进一步瘫痪。","fields":[{"label":"标题","value":"1932年7月德国国会选举"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1932年7月31日"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1932年7月国会选举使纳粹党成为最大党，但未能获得多数，德国议会政治进一步瘫痪。"},{"label":"参与者","value":"纳粹党、社会民主党、共产党、中央党、德国国家人民党、德国选民。"},{"label":"发生了什么","value":"巴本内阁缺乏议会基础，在经济危机和街头暴力加剧的背景下解散国会并举行选举。纳粹党利用失业、反凡尔赛、反共产党和反体制宣传大规模动员，成为国会第一大党。共产党也增长，传统中间政党继续萎缩。虽然纳粹成为最大党，但没有绝对多数，希特勒要求总理职位遭兴登堡拒绝。新国会无法形成稳定政府，巴本继续依靠总统权力。"},{"label":"为什么重要","value":"它让纳粹获得“最大党”地位，显著提升希特勒索取政权的谈判筹码。"},{"label":"前因","value":"失业危机、街头暴力和巴本政变削弱共和国秩序，纳粹利用反凡尔赛、反马克思主义和就业承诺吸引大批选民。"},{"label":"后果","value":"纳粹成为国会第一大党但无法单独执政，政治僵局继续恶化，11月再次选举和施莱歇尔内阁很快接续出现。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Reichstagswahl Juli 1932；United States Holocaust Memorial Museum相关资料；German History Documents and Images相关资料。"}],"relationItems":["← 前因：1932年德国总统选举","← 前因：1932年普鲁士政变","→ 后果：1932年11月德国国会选举"],"relations":[{"text":"← 前因：1932年德国总统选举","id":"card45"},{"text":"← 前因：1932年普鲁士政变","id":"card41"},{"text":"→ 后果：1932年11月德国国会选举","id":"card47"}],"source":"history","id":"card46"},{"title":"1932年11月德国国会选举","level":"B","type":"事件卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1932年11月6日","place":"德国","summary":"1932年11月选举中纳粹票数下降，却没有恢复议会多数，反而加速保守精英寻找同希特勒交易。","fields":[{"label":"标题","value":"1932年11月德国国会选举"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1932年11月6日"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1932年11月选举中纳粹票数下降，却没有恢复议会多数，反而加速保守精英寻找同希特勒交易。"},{"label":"参与者","value":"纳粹党、共产党、社会民主党、中央党、德国国家人民党、德国选民。"},{"label":"发生了什么","value":"7月选举后国会无法支持巴本政府，政治僵局继续。11月再次选举时，纳粹党得票和席位有所下降，显示其动员也有上限和疲劳。共产党继续增长，中间政党依旧薄弱，国会仍没有可行多数。纳粹内部财政和士气承压，但保守精英也看不到稳定替代方案。巴本和希特勒阵营开始更认真谈判权力安排，施莱歇尔短暂上台后仍无法建立多数。"},{"label":"为什么重要","value":"它说明纳粹并非线性上升，但魏玛制度已无法把纳粹的相对退潮转化为民主恢复。"},{"label":"前因","value":"7月选举后纳粹拒绝支持稳定政府，巴本和兴登堡也无法获得议会多数，只能再次诉诸选举。"},{"label":"后果","value":"纳粹票数虽下降但仍是最大党，施莱歇尔短暂组阁失败后，保守派认为可以把希特勒纳入并控制在内。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Reichstagswahl November 1932；United States Holocaust Memorial Museum相关资料；German History Documents and Images相关资料。"}],"relationItems":["← 前因：1932年7月德国国会选举","→ 后果：魏玛施莱歇尔内阁","→ 后果：希特勒出任德国总理"],"relations":[{"text":"← 前因：1932年7月德国国会选举","id":"card46"},{"text":"→ 后果：魏玛施莱歇尔内阁","id":"card43"},{"text":"→ 后果：希特勒出任德国总理","id":"card71"}],"source":"history","id":"card47"},{"title":"德国哈尔茨堡阵线","level":"B","type":"事件卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1931年10月","place":"德国巴特哈尔茨堡","summary":"德国哈尔茨堡阵线把纳粹、国家人民党、德国钢盔团和保守民族主义力量聚集在一起，展示反魏玛右翼联盟。","fields":[{"label":"标题","value":"德国哈尔茨堡阵线"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1931年10月"},{"label":"地点","value":"德国巴特哈尔茨堡"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国哈尔茨堡阵线把纳粹、国家人民党、德国钢盔团和保守民族主义力量聚集在一起，展示反魏玛右翼联盟。"},{"label":"参与者","value":"纳粹党、德国国家人民党、德国钢盔团、阿尔弗雷德·胡根贝格、希特勒及其他右翼代表。"},{"label":"发生了什么","value":"1931年，面对布吕宁政府、经济危机和共和国制度，德国右翼力量在巴特哈尔茨堡集会。纳粹党、国家人民党、德国钢盔团和部分保守精英试图展示共同反对魏玛共和国、凡尔赛体系和马克思主义的阵线。表面上这是右翼统一，实际上希特勒和胡根贝格等人互不信任，纳粹也不愿长期做保守派附庸。集会强化了右翼合作氛围，也让纳粹进一步进入保守精英视野。"},{"label":"为什么重要","value":"它是保守民族主义与纳粹相互接近的重要场景，显示魏玛右翼反民主共识扩大。"},{"label":"前因","value":"国家人民党、钢盔团和纳粹都反对魏玛共和国和布吕宁政府，右翼力量试图通过共同集会展示反共和国阵营的规模。"},{"label":"后果","value":"阵线没有形成稳定统一组织，却让保守民族主义者和纳粹的合作关系公开化，为后来的保守派与纳粹交易提供政治背景。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Harzburger Front；United States Holocaust Memorial Museum相关资料；German History Documents and Images相关资料。"}],"relationItems":["← 前因：德国国家人民党","← 前因：德国钢盔团","→ 后果：希特勒出任德国总理","↔ 相关：纳粹冲锋队"],"relations":[{"text":"← 前因：德国国家人民党","id":"card26"},{"text":"← 前因：德国钢盔团","id":"card35"},{"text":"→ 后果：希特勒出任德国总理","id":"card71"},{"text":"↔ 相关：纳粹冲锋队","id":"extra93"}],"source":"history","id":"card48"},{"title":"约瑟夫·戈培尔","level":"B","type":"人物卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1897年至1945年；1926年后在纳粹宣传中重要","place":"德国","summary":"戈培尔是纳粹宣传的核心组织者，把现代媒体、群众情绪和领袖崇拜结合成政治动员工具。","fields":[{"label":"标题","value":"约瑟夫·戈培尔"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1897年至1945年；1926年后在纳粹宣传中重要"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"戈培尔是纳粹宣传的核心组织者，把现代媒体、群众情绪和领袖崇拜结合成政治动员工具。"},{"label":"生卒年/活跃年代","value":"1897-1945；1926年任纳粹柏林大区负责人，1933年后任宣传部长。"},{"label":"身份/职务","value":"纳粹政治家、宣传家。"},{"label":"关键贡献/作为","value":"组织柏林纳粹宣传和街头政治；塑造希特勒领袖形象；掌控纳粹德国宣传、广播、电影和文化管制。"},{"label":"核心主张/立场","value":"极端反犹主义、反马克思主义、领袖崇拜和群众动员政治。"},{"label":"为什么重要","value":"戈培尔说明现代传媒技术可以服务极权政治，把危机社会的焦虑转化为仇恨、忠诚和服从。"},{"label":"争议/评价","value":"他不是单纯“宣传天才”，而是系统制造谎言、仇恨和灭绝政策正当化的政治罪犯。"},{"label":"关联事件（可选）","value":"纳粹宣传机器、水晶之夜、总体战演说。"},{"label":"出处","value":"United States Holocaust Memorial Museum: Joseph Goebbels；Encyclopaedia Britannica: Joseph Goebbels；Deutsches Historisches Museum/LeMO相关资料。"}],"relationItems":["← 前因：纳粹宣传机器","→ 后果：纳粹宣传部","↔ 相关：希特勒出任德国总理"],"relations":[{"text":"← 前因：纳粹宣传机器","id":"extra94"},{"text":"↔ 相关：希特勒出任德国总理","id":"card71"}],"source":"history","id":"card49"},{"title":"阿尔弗雷德·胡根贝格","level":"B","type":"人物卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1865年至1951年；魏玛后期影响突出","place":"德国","summary":"胡根贝格是右翼媒体大亨和国家人民党领袖，帮助把保守民族主义舆论与纳粹动员连接起来。","fields":[{"label":"标题","value":"阿尔弗雷德·胡根贝格"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1865年至1951年；魏玛后期影响突出"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"胡根贝格是右翼媒体大亨和国家人民党领袖，帮助把保守民族主义舆论与纳粹动员连接起来。"},{"label":"生卒年/活跃年代","value":"1865-1951；1920年代后期至1933年政治影响突出。"},{"label":"身份/职务","value":"媒体企业家、德国国家人民党领袖、保守民族主义政治家。"},{"label":"关键贡献/作为","value":"控制报刊和电影新闻资源；领导反德国赔款《杨格计划》运动；参与德国哈尔茨堡阵线；1933年进入希特勒内阁。"},{"label":"核心主张/立场","value":"反凡尔赛、反共和国、民族保守主义，试图利用纳粹群众力量服务保守右翼目标。"},{"label":"为什么重要","value":"胡根贝格展示传媒资本、右翼政党和纳粹运动如何在魏玛后期相互利用。"},{"label":"争议/评价","value":"他以为能借纳粹摧毁共和国并维持保守控制，最终被纳粹边缘化。"},{"label":"关联事件（可选）","value":"德国哈尔茨堡阵线、反德国赔款《杨格计划》运动、希特勒出任德国总理。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Alfred Hugenberg；Encyclopaedia Britannica相关资料；German History Documents and Images相关资料。"}],"relationItems":["← 前因：德国国家人民党","→ 后果：德国哈尔茨堡阵线","→ 后果：希特勒出任德国总理"],"relations":[{"text":"← 前因：德国国家人民党","id":"card26"},{"text":"→ 后果：德国哈尔茨堡阵线","id":"card48"},{"text":"→ 后果：希特勒出任德国总理","id":"card71"}],"source":"history","id":"card50"},{"title":"反德国赔款《杨格计划》运动","level":"B","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1929年至1930年","place":"德国","summary":"反德国赔款《杨格计划》运动把国家人民党、纳粹和右翼媒体联合起来反对赔款妥协，显著提升希特勒全国曝光。","fields":[{"label":"标题","value":"反德国赔款《杨格计划》运动"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1929年至1930年"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"反德国赔款《杨格计划》运动把国家人民党、纳粹和右翼媒体联合起来反对赔款妥协，显著提升希特勒全国曝光。"},{"label":"参与者","value":"德国国家人民党、阿尔弗雷德·胡根贝格、纳粹党、希特勒、德国钢盔团及右翼团体。"},{"label":"发生了什么","value":"德国赔款《杨格计划》试图重新安排魏玛德国赔款问题，魏玛政府把它视为减轻外部压力的谈判成果。右翼民族主义者则攻击其延长德国“奴役”，胡根贝格利用媒体资源推动全民公投运动，纳粹党也加入宣传。虽然反对运动在正式投票中失败，但希特勒借此与传统右翼和媒体网络建立联系，纳粹获得远超原本规模的全国曝光。"},{"label":"为什么重要","value":"它是纳粹从边缘极端党进入全国右翼政治联盟的重要跳板。"},{"label":"前因","value":"德国赔款《杨格计划》试图重组赔款问题，但民族主义右翼把任何赔款安排都描绘为延续凡尔赛屈辱，胡根贝格借此整合媒体和右翼资源。"},{"label":"后果","value":"运动让纳粹获得全国宣传平台和保守派资源，虽然公投失败，却推动纳粹从边缘党进入群众政治中心。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Youngplan/Volksbegehren；United States Holocaust Memorial Museum相关资料；German History Documents and Images相关资料。"}],"relationItems":["← 前因：德国赔款《杨格计划》","← 前因：德国国家人民党","→ 后果：1930年德国国会选举","↔ 相关：纳粹宣传机器"],"relations":[{"text":"← 前因：德国赔款《杨格计划》","id":"card93"},{"text":"← 前因：德国国家人民党","id":"card26"},{"text":"→ 后果：1930年德国国会选举","id":"card44"},{"text":"↔ 相关：纳粹宣传机器","id":"extra94"}],"source":"history","id":"card51"},{"title":"恩斯特·台尔曼","level":"B","type":"人物卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1886年至1944年；魏玛后期为德国共产党领袖","place":"德国","summary":"台尔曼是魏玛后期德国共产党领袖，代表共产国际影响下反社民党、反法西斯但难以联合的路线。","fields":[{"label":"标题","value":"恩斯特·台尔曼"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1886年至1944年；魏玛后期为德国共产党领袖"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国、苏联"},{"label":"一句话概括","value":"台尔曼是魏玛后期德国共产党领袖，代表共产国际影响下反社民党、反法西斯但难以联合的路线。"},{"label":"生卒年/活跃年代","value":"1886-1944；1920年代中后期起领导德国共产党。"},{"label":"身份/职务","value":"德国共产党主席、共产国际路线在德国的重要执行者。"},{"label":"关键贡献/作为","value":"领导共产党参与选举和街头政治；推动德国红色阵线战士联盟；1932年参加总统选举。"},{"label":"核心主张/立场","value":"革命共产主义，强烈反对资本主义、纳粹和社会民主党领导层。"},{"label":"为什么重要","value":"台尔曼说明魏玛左翼反纳粹力量为何难以联合。共产党把社民党视为主要敌人之一，削弱了共同保卫共和国的可能。"},{"label":"争议/评价","value":"其路线受莫斯科影响很大，反法西斯立场明确，但“社会法西斯”策略造成严重政治后果。"},{"label":"关联事件（可选）","value":"1932年德国总统选举、德国红色阵线战士联盟。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Ernst Thälmann；German History Documents and Images相关资料；Encyclopaedia Britannica相关资料。"}],"relationItems":["← 前因：德国共产党成立","↔ 相关：德国红色阵线战士联盟","↔ 相关：1932年德国总统选举"],"relations":[{"text":"← 前因：德国共产党成立","id":"extra694"},{"text":"↔ 相关：德国红色阵线战士联盟","id":"card36"},{"text":"↔ 相关：1932年德国总统选举","id":"card45"}],"source":"history","id":"card52"},{"title":"共产国际“社会法西斯”论","level":"B","type":"概念/思潮卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1928年至1934年前后影响突出","place":"共产国际及德国共产党政治语境","summary":"共产国际“社会法西斯”论把社会民主党视为法西斯的变体，严重阻碍德国左翼在纳粹崛起时形成统一战线。","fields":[{"label":"标题","value":"共产国际“社会法西斯”论"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1928年至1934年前后影响突出"},{"label":"地点","value":"共产国际及德国共产党政治语境"},{"label":"主要国家","value":"苏联、德国"},{"label":"一句话概括","value":"共产国际“社会法西斯”论把社会民主党视为法西斯的变体，严重阻碍德国左翼在纳粹崛起时形成统一战线。"},{"label":"核心主张/思路","value":"共产国际“第三时期”路线认为社会民主党维护资本主义秩序，实质上是法西斯主义的另一种支柱。"},{"label":"提出者/代表人物（可选）","value":"共产国际路线，德国共产党在台尔曼领导下执行。"},{"label":"它从何而来","value":"苏联和共产国际对资本主义危机的判断、对社会民主党镇压革命记忆的敌意、以及革命高潮预期共同形成。"},{"label":"典型表现","value":"德国共产党把社民党称为“社会法西斯”，优先攻击社民党领导层，而不是与其建立反纳粹统一阵线。"},{"label":"为什么重要","value":"它是魏玛末期反纳粹失败的重要因素之一。纳粹增长时，左翼最大两党互不信任，无法形成稳定防线。"},{"label":"争议/局限","value":"社民党和共产党之间的敌意不只由该理论造成，也与1918-1919年镇压记忆、苏联影响和阶级政治竞争有关。"},{"label":"出处","value":"German History Documents and Images相关资料；Deutsches Historisches Museum/LeMO相关资料；共产国际史研究资料。"}],"relationItems":["← 前因：德国共产党成立","↔ 相关：恩斯特·台尔曼","↔ 相关：德国社会民主党（SPD）","→ 后果：希特勒出任德国总理"],"relations":[{"text":"← 前因：德国共产党成立","id":"extra694"},{"text":"↔ 相关：恩斯特·台尔曼","id":"card52"},{"text":"↔ 相关：德国社会民主党（SPD）","id":"extra628"},{"text":"→ 后果：希特勒出任德国总理","id":"card71"}],"source":"history","id":"card53"},{"title":"德国铁阵线","level":"B","type":"组织/机构卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1931年成立","place":"德国","summary":"德国铁阵线是社民党和工会阵营建立的共和国防卫组织，试图同时抵抗纳粹、共产党和君主主义右翼。","fields":[{"label":"标题","value":"德国铁阵线"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1931年成立"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国铁阵线是社民党和工会阵营建立的共和国防卫组织，试图同时抵抗纳粹、共产党和君主主义右翼。"},{"label":"性质/类型","value":"共和派群众防卫联盟。"},{"label":"成立/解散时间","value":"1931年成立，1933年纳粹掌权后被摧毁。"},{"label":"核心目标/宗旨","value":"保卫魏玛共和国和民主制度，反对纳粹、共产党和反共和国右翼。"},{"label":"关键人物（可选）","value":"社会民主党、自由工会和德国国旗团等组织参与。"},{"label":"关键行动/事件","value":"组织集会、宣传和防卫活动，使用三箭标志反击三类反共和国敌人。"},{"label":"为什么重要","value":"它说明共和国支持者并非完全没有自卫意识，但在经济危机、国家机器右转和左翼分裂中力量不足。"},{"label":"争议/局限","value":"德国铁阵线主要依托社民党阵营，难以整合共产党，也无法控制警察和军队等关键权力。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Eiserne Front；German History Documents and Images相关资料。"}],"relationItems":["← 前因：魏玛政治街头暴力","↔ 相关：德国社会民主党（SPD）","↔ 相关：纳粹冲锋队","→ 后果：希特勒出任德国总理"],"relations":[{"text":"← 前因：魏玛政治街头暴力","id":"card34"},{"text":"↔ 相关：德国社会民主党（SPD）","id":"extra628"},{"text":"↔ 相关：纳粹冲锋队","id":"extra93"},{"text":"→ 后果：希特勒出任德国总理","id":"card71"}],"source":"history","id":"card54"},{"title":"德国国旗团","level":"C","type":"组织/机构卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1924年成立","place":"德国","summary":"德国国旗团是保卫魏玛共和国的共和派退伍军人和群众组织，以德国黑红金旗帜反击右翼和左翼准军事压力。","fields":[{"label":"标题","value":"德国国旗团"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1924年成立"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国国旗团是保卫魏玛共和国的共和派退伍军人和群众组织，以德国黑红金旗帜反击右翼和左翼准军事压力。"},{"label":"性质/类型","value":"共和派防卫组织、群众组织。"},{"label":"成立/解散时间","value":"1924年成立，1933年纳粹掌权后被禁止。"},{"label":"核心目标/宗旨","value":"维护共和国宪法和黑红金民主传统，对抗君主主义、极右翼和共产主义威胁。"},{"label":"关键人物（可选）","value":"社会民主党、中央党和民主党支持者参与。"},{"label":"关键行动/事件","value":"组织集会、游行和共和国纪念活动；后来参与德国铁阵线。"},{"label":"为什么重要","value":"它说明魏玛共和国有自己的象征政治和街头组织，只是力量和国家支持不足以抵挡极端化。"},{"label":"争议/局限","value":"德国国旗团虽然有群众基础，但在准军事冲突和国家权力争夺中能力有限。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Reichsbanner Schwarz-Rot-Gold；German History Documents and Images相关资料。"}],"relationItems":["← 前因：魏玛共和国成立","→ 后果：德国铁阵线","↔ 相关：德国汉巴赫节"],"relations":[{"text":"← 前因：魏玛共和国成立","id":"card7"},{"text":"→ 后果：德国铁阵线","id":"card54"},{"text":"↔ 相关：德国汉巴赫节","id":"extra489"}],"source":"history","id":"card55"},{"title":"1932年阿尔托纳血腥星期日","level":"B","type":"事件卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1932年7月17日","place":"德国阿尔托纳","summary":"1932年阿尔托纳血腥星期日是纳粹游行引发的街头暴力事件，被巴本政府用作1932年普鲁士政变的秩序借口。","fields":[{"label":"标题","value":"1932年阿尔托纳血腥星期日"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1932年7月17日"},{"label":"地点","value":"德国阿尔托纳"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1932年阿尔托纳血腥星期日是纳粹游行引发的街头暴力事件，被巴本政府用作1932年普鲁士政变的秩序借口。"},{"label":"参与者","value":"纳粹冲锋队、共产党支持者、阿尔托纳居民、警察、巴本政府。"},{"label":"发生了什么","value":"1932年7月，纳粹冲锋队在工人阶级和共产党影响较强的阿尔托纳举行游行，现场紧张迅速升级为枪击和混乱。警察开火，造成多人死亡。事件具体责任复杂，但巴本政府将其作为普鲁士政府无法维持秩序的证据。三天后，中央政府发动1932年普鲁士政变，解除普鲁士社民党政府并接管警察。街头暴力因此被转化为中央集权和威权干预的政治理由。"},{"label":"为什么重要","value":"它是魏玛街头暴力如何被魏玛总统内阁利用来拆除民主制度防线的典型案例。"},{"label":"前因","value":"魏玛末期街头政治高度暴力化，纳粹冲锋队、共产党组织和警察在工人区的对峙很容易升级为流血冲突。"},{"label":"后果","value":"事件被巴本政府用作干预普鲁士的借口，普鲁士政变随后削弱了共和国最重要的民主州政府。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Altonaer Blutsonntag；German History Documents and Images相关资料。"}],"relationItems":["← 前因：魏玛政治街头暴力","← 前因：纳粹冲锋队","→ 后果：1932年普鲁士政变"],"relations":[{"text":"← 前因：魏玛政治街头暴力","id":"card34"},{"text":"← 前因：纳粹冲锋队","id":"extra93"},{"text":"→ 后果：1932年普鲁士政变","id":"card41"}],"source":"history","id":"card56"},{"title":"1933年3月德国国会选举","level":"B","type":"事件卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1933年3月5日","place":"德国","summary":"1933年3月国会选举在恐怖和镇压环境中举行，纳粹未获绝对多数，却足以推动独裁合法化。","fields":[{"label":"标题","value":"1933年3月德国国会选举"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1933年3月5日"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1933年3月国会选举在恐怖和镇压环境中举行，纳粹未获绝对多数，却足以推动独裁合法化。"},{"label":"参与者","value":"纳粹党、德国国家人民党、社会民主党、中央党、共产党、德国选民。"},{"label":"发生了什么","value":"希特勒上台后很快解散国会，试图通过选举获得更强授权。德国国会纵火案后，政府逮捕共产党人并压制左翼媒体和组织，冲锋队、纳粹党卫队和警察制造恐怖气氛。选举中纳粹党成为最大党，但没有单独获得绝对多数；它依靠德国国家人民党等右翼盟友掌控议会多数。共产党议席实际被剥夺，反对派行动空间被压缩。随后纳粹推动纳粹德国授权法，把临时选举优势转化为独裁权力。"},{"label":"为什么重要","value":"它说明纳粹夺权不是通过一次“正常民主选举”完成，而是在国家暴力和法律操纵下完成。"},{"label":"前因","value":"希特勒已任总理，国会纵火案和紧急法令使纳粹能够在恐怖、宣传和国家资源支持下进行选举。"},{"label":"后果","value":"纳粹仍未获得绝对多数，但借助保守盟友和镇压共产党推动授权法，德国很快转入一党独裁。"},{"label":"出处","value":"DHM/LeMO: Reichstagswahl März 1933；USHMM相关资料；German History Documents and Images相关资料。"}],"relationItems":["← 前因：德国国会纵火法令","→ 后果：纳粹德国授权法","↔ 相关：纳粹宣传机器"],"relations":[{"text":"← 前因：德国国会纵火法令","id":"extra98"},{"text":"→ 后果：纳粹德国授权法","id":"extra99"},{"text":"↔ 相关：纳粹宣传机器","id":"extra94"}],"source":"history","id":"card57"},{"title":"德国《施廷内斯—莱吉恩协议》","level":"B","type":"制度/文本卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1918年11月15日","place":"德国","summary":"1918年战败后，德国重工业代表与工会签订的劳资协议，确立了八小时工作制和工会地位，奠定了魏玛初期劳资妥协格局。","fields":[{"label":"标题","value":"德国《施廷内斯—莱吉恩协议》"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1918年11月15日"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1918年战败后，德国重工业代表与工会签订的劳资协议，确立了八小时工作制和工会地位，奠定了魏玛初期劳资妥协格局。"},{"label":"制定方/签署方","value":"胡戈·施廷内斯（代表大工业家/雇主协会）与卡尔·莱吉恩（代表自由工会）。"},{"label":"主要内容","value":"协议促成了“雇主协会与工会中央工作组”的成立。雇主方做出重大让步：承认工会拥有薪资谈判权，与反对工会的经济协会脱钩，并承诺实行八小时工作制。作为回报，基督教工会和自由工会同意在复员问题上进行友好合作。"},{"label":"它试图解决什么问题","value":"一战战败后，德国面临数百万士兵复员以及潜在的革命动荡。企业家预计战后经济需求会反弹，为了将企业决策权从国家的监管下解放出来，并避免遭到彻底的“社会化”（国有化），资方主动选择与工会结盟。"},{"label":"为什么重要","value":"它是魏玛初期工业劳动关系体系的重大突破，确立了建国初期的阶级经济妥协，为魏玛共和国早期的社会福利制度奠定了基石。"},{"label":"争议/局限","value":"协议在很大程度上使企业家获益，他们获得了定价、出口和分配国家补贴的极大自主权；而工会希望借此参与国家宏观经济决策的诉求，后来被证明是一厢情愿的幻想。"},{"label":"造成的影响","value":"形成了魏玛初期的劳资共治局面，但鲁尔区的重工业企业对此颇有微词，埋下了后期重工业企业要求废除八小时工作制的隐患。"},{"label":"出处","value":"《魏玛共和国的兴亡》第一章。"}],"relationItems":["↔ 同时期参考：《凡尔赛和约》","✗ 对立/冲突：布吕宁内阁通缩政策"],"relations":[{"text":"↔ 同时期参考：《凡尔赛和约》","id":"card59"},{"text":"✗ 对立/冲突：布吕宁内阁通缩政策","id":"card65"}],"source":"history","id":"card58"},{"title":"《凡尔赛和约》","level":"S","type":"制度/文本卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1919年6月28日","place":"法国凡尔赛宫镜厅","summary":"一战战胜国与德国签订的和平条约，以战争罪责条款为依据强加巨额赔款并割让大量工业资源。","fields":[{"label":"标题","value":"《凡尔赛和约》"},{"label":"分级","value":"S"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1919年6月28日"},{"label":"地点","value":"法国凡尔赛宫镜厅"},{"label":"主要国家","value":"德国；法国；英国；美国；意大利；日本"},{"label":"一句话概括","value":"一战战胜国与德国签订的和平条约，以战争罪责条款为依据强加巨额赔款并割让大量工业资源。"},{"label":"制定方/签署方","value":"协约国代表与德国和平代表团（赫尔曼·米勒、约翰内斯·贝尔）。"},{"label":"主要内容","value":"在领土和资源上，德国失去了75%的铁矿、68%的锌矿、26%的煤炭产能、44%的生铁产能和38%的钢材产能（如割让上西里西亚工业区给波兰，萨尔矿区交由法国）。在赔款上，基于第231条战争罪责条款，要求德国先行支付200亿金马克（包含实物与现金），且未设定最终赔款总额。"},{"label":"它试图解决什么问题","value":"战胜国（尤其是法国）希望通过巨额索赔和削弱德国重工业潜力，弥补自身的战争损失，并长期压制德国在欧洲大陆的竞争力和军事复苏可能。"},{"label":"为什么重要","value":"它是魏玛共和国整个存续期间经济与外交危机的绝对源头。巨额赔款和资源丧失直接摧毁了德国的外贸平衡，使国家深陷外汇短缺的泥潭。"},{"label":"争议/局限","value":"经济学家约翰·梅纳德·凯恩斯严厉批评其经济政策存在先天缺陷，指出“未来的危险不在于边界，而在于粮食、煤炭和运输”。德国国内则几乎一致认为其违背法理，将其视为“惩罚性和平”。"},{"label":"造成的影响","value":"导致德国极度缺乏原材料，贸易赤字飙升；同时“战争罪责”条款在德国国内激起了狂热的民族主义情绪，使随后的每一届政府都面临着巨大的右翼反扑压力。"},{"label":"出处","value":"《魏玛共和国的兴亡》第二章。"}],"relationItems":["→ 后果：魏玛德国赔款履约政策","→ 后果：鲁尔占领与德国消极抵抗"],"relations":[{"text":"→ 后果：魏玛德国赔款履约政策","id":"card60"},{"text":"→ 后果：鲁尔占领与德国消极抵抗","id":"card62"}],"source":"history","id":"card59"},{"title":"魏玛德国赔款履约政策","level":"B","type":"概念/思潮卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1921年5月10日（通过赔款方案）","place":"德国","summary":"德国政府试图通过尽最大努力支付战争赔款，向协约国证明赔款方案\n超出了德国的实际经济能力，以此换取国际让步。","fields":[{"label":"标题","value":"魏玛德国赔款履约政策"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1921年5月10日（通过赔款方案）"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国；法国；英国；美国；比利时"},{"label":"一句话概括","value":"德国政府试图通过尽最大努力支付战争赔款，向协约国证明赔款方案\n超出了德国的实际经济能力，以此换取国际让步。"},{"label":"核心特征","value":"魏玛德国赔款履约政策是左翼中间派总理约瑟夫·维尔特面对协约国制裁威胁时采取的策略。其核心逻辑是：接受付款计划并尽最大努力履行赔款义务，通过将国家财政逼向极限的实际行动，暴露出赔款方案的经济不合理性，从而为潜在的赔款妥协创造条件。"},{"label":"为什么形成","value":"1921年5月，协约国下达了来自伦敦的最后通牒，要求德国承担1320亿金马克的总赔款，并威胁若不接受将在6天内占领鲁尔区。面对迫在眉睫的军事占领和祖国分裂的危险，维尔特内阁在议会多数支持下，决定面对现实接受条件。"},{"label":"代表案例","value":"维尔特内阁在1921年5月10日推动议会接受伦敦支付方案；随后外交部长瓦尔特·拉特瑙与法国签订《威斯巴登协议》，试图用德国的物资和劳动力直接推动法国重建来替代外汇支付，但最终失败。"},{"label":"它影响了什么","value":"这种绥靖政策招致了国内右派的猛烈谩骂（称其为魏玛德国赔款履约政策并指责其卖国）。最终，由于德国外汇严重短缺和经济现状的制约，政府在年底便无法筹集到足够资金，被迫向赔款委员会请求暂停支付，加剧了后来的鲁尔危机和通货膨胀。"},{"label":"出处","value":"《魏玛共和国的兴亡》第三章。"}],"relationItems":["← 前因：《凡尔赛和约》","→ 后果：鲁尔占领与德国消极抵抗","↔ 相关：施廷内斯法德重工业协议尝试"],"relations":[{"text":"← 前因：《凡尔赛和约》","id":"card59"},{"text":"→ 后果：鲁尔占领与德国消极抵抗","id":"card62"},{"text":"↔ 相关：施廷内斯法德重工业协议尝试","id":"card61"}],"source":"history","id":"card60"},{"title":"施廷内斯法德重工业协议尝试","level":"C","type":"事件卡","tags":["经济与社会","无"],"mainTag":"经济与社会","subTag":"无","timeText":"1922年9月14日","place":"德法之间","summary":"1922年德国重工业巨头施廷内斯绕过政府，私下与法国工业界签订货物供应协议，试图以资本合作替代国家赔款外交。","fields":[{"label":"标题","value":"施廷内斯法德重工业协议尝试"},{"label":"分级","value":"C"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"无"},{"label":"时间","value":"1922年9月14日"},{"label":"地点","value":"德法之间"},{"label":"主要国家","value":"德国；法国"},{"label":"一句话概括","value":"1922年德国重工业巨头施廷内斯绕过政府，私下与法国工业界签订货物供应协议，试图以资本合作替代国家赔款外交。"},{"label":"参与者","value":"胡戈·施廷内斯（德国重工业代表）、吕贝萨克侯爵（法国方代表）。"},{"label":"发生了什么","value":"在魏玛政府层面的魏玛德国赔款履约政策及《威斯巴登协议》陷入困境时，德国重工业巨头胡戈·施廷内斯尝试直接与法国达成谅解。1922年9月14日，施廷内斯与法国的吕贝萨克侯爵签署了一项货物供应协议。施廷内斯的宏大计划是：通过交换德国和法国企业的股权，为法德重工业的合并奠定基础（此举也明显针对英国）。"},{"label":"为什么重要","value":"揭示了魏玛时期大资本家拥有庞大的“国中之国”权力，能够平行甚至凌驾于政府的官方外交政策之上进行跨国经济博弈。反映了除了国家层面的政治索赔外，德法之间还存在着重工业资本如何瓜分欧洲大陆主导权的隐秘较量。"},{"label":"前因","value":"鲁尔占领和赔款危机使德国工业界寻找绕开国家对抗的经济解决方案，法国部分重工业利益也希望通过合作获得煤钢供应。\n政府主导的《威斯巴登协议》因法国工业界抵制和英国的警惕而失败。\n魏玛政府的魏玛德国赔款履约政策遭遇严重的外汇筹集困难。"},{"label":"后果","value":"协议尝试未能真正解决赔款和占领问题，但显示经济精英在国家外交僵局之外寻找交易空间，也暴露鲁尔危机的经济压力。\n这种资本层面的妥协尝试并未能阻止两国政治矛盾的恶化。\n随着德国在赔款交付上的违约，法国最终选择直接出兵占领鲁尔区。"},{"label":"出处","value":"《魏玛共和国的兴亡》第三章、第五章（图注）。"}],"relationItems":["← 前因：魏玛德国赔款履约政策","↔ 相关：德国《施廷内斯—莱吉恩协议》","↔ 相关：鲁尔占领与德国消极抵抗"],"relations":[{"text":"← 前因：魏玛德国赔款履约政策","id":"card60"},{"text":"↔ 相关：德国《施廷内斯—莱吉恩协议》","id":"card58"},{"text":"↔ 相关：鲁尔占领与德国消极抵抗","id":"card62"}],"source":"history","id":"card61"},{"title":"鲁尔占领与德国消极抵抗","level":"A","type":"事件卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1923年1月","place":"德国鲁尔区","summary":"1923年法比因德国拖欠赔款，出兵占领鲁尔工业区，德国政府号召全境罢工抵抗，成为引爆恶性通胀的直接导火索。","fields":[{"label":"标题","value":"鲁尔占领与德国消极抵抗"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1923年1月"},{"label":"地点","value":"德国鲁尔区"},{"label":"主要国家","value":"法国；比利时；德国"},{"label":"一句话概括","value":"1923年法比因德国拖欠赔款，出兵占领鲁尔工业区，德国政府号召全境罢工抵抗，成为引爆恶性通胀的直接导火索。"},{"label":"参与者","value":"法国与比利时军队、德国政府、鲁尔区工人和企业家"},{"label":"发生了什么","value":"1923年1月，法国和比利时以德国逃避煤炭和木材等物资赔款为由，悍然出兵占领了集中德国大量煤矿、钢厂的重工业区——鲁尔区。作为回应，德国政府宣布实施“消极抵抗”政策，要求该地区的所有工人、职员放下工具罢工，拒绝与占领军进行任何形式的合作。"},{"label":"为什么重要","value":"沉重打击了德国的工业生产，导致煤炭等关键经济物资严重短缺。\n德国政府为了支付罢工工人和公职人员的工资，只能无节制地开动印钞机，导致通货膨胀彻底失控，演变为灾难性的恶性通胀。"},{"label":"前因","value":"德国赔款履约困难引发法国和比利时强硬回应，魏玛政府缺乏军事反抗能力，只能以罢工、停工和行政不合作来反制占领。\n德国无法满足《凡尔赛和约》及伦敦支付方案中规定的巨额赔款要求。"},{"label":"后果","value":"政府为维持消极抵抗大量发钞和补贴，财政失控加速恶性通胀；停止抵抗后，魏玛转向货币稳定和德国赔款《道威斯计划》。\n1923年马克汇率彻底崩溃，引发了席卷全国的经济和社会生存危机。国家财政濒临破产，政府于1923年9月被迫放弃了消极抵抗政策。"},{"label":"出处","value":"《魏玛德国——希望与悲剧》第103、138、139页；《魏玛共和国》第57页。 资料备注：关于法比占领鲁尔的具体日期，提供资料中仅明确到“1923年1月”，故不主观添加具体日期。"}],"relationItems":["← 前因：魏玛德国赔款履约政策","→ 后果：魏玛恶性通货膨胀","↔ 相关：《凡尔赛和约》"],"relations":[{"text":"← 前因：魏玛德国赔款履约政策","id":"card60"},{"text":"→ 后果：魏玛恶性通货膨胀","id":"card90"},{"text":"↔ 相关：《凡尔赛和约》","id":"card59"}],"source":"history","id":"card62"},{"title":"魏玛工业合理化改革","level":"B","type":"概念/思潮卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"1924—1929年","place":"德国","summary":"1924—1929年德国企业借美国贷款大规模引入流水线和泰罗制，生产效率大幅提升，但同时造成结构性失业。","fields":[{"label":"标题","value":"魏玛工业合理化改革"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1924—1929年"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1924—1929年德国企业借美国贷款大规模引入流水线和泰罗制，生产效率大幅提升，但同时造成结构性失业。"},{"label":"核心特征","value":"企业呈现大规模集中化趋势（如联合企业的建立），并在生产线上广泛应用美国的“福特制”（流水线）和“泰罗制”（动作与时间心理学研究）。用高精度的机器和严密的控制替代人工。"},{"label":"为什么形成","value":"在德国赔款《道威斯计划》带来巨额美国资金后，德国企业为了提高生产效率、降低劳动力成本，以偿还债务并在国际市场上重新获得竞争力，开始疯狂投资新技术并革新管理模式。"},{"label":"代表案例","value":"在鲁尔区，矿井广泛采用长壁开采法和电动新机器，导致采矿增加18%的同时工人反而大幅减少；在生活领域，“新法兰克福“法兰克福厨房””将工厂流水线的空间利用理念直接引入了家庭主妇的烹饪空间。"},{"label":"它影响了什么","value":"大幅提高了德国的工业生产率（如金属加工提高25%），但也导致了工作节奏飞快、劳动强度陡增、工伤事故更加严重。更致命的是，它造成了20世纪20年代中后期居高不下的结构性失业。"},{"label":"出处","value":"《魏玛德国——希望与悲剧》第134、151-157、182页。"}],"relationItems":["← 前因：德国赔款《道威斯计划》","↔ 相关：德国《施廷内斯—莱吉恩协议》"],"relations":[{"text":"← 前因：德国赔款《道威斯计划》","id":"card92"},{"text":"↔ 相关：德国《施廷内斯—莱吉恩协议》","id":"card58"}],"source":"history","id":"card63"},{"title":"华尔街“黑色星期四”","level":"S","type":"事件卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1929年10月","place":"美国纽约 / 德国","summary":"1929年10月美国股市崩盘引发了全球经济危机\n，美国资本迅速撤出德国，依赖外资的魏玛经济资金链断裂，触发了全面经济危机。","fields":[{"label":"标题","value":"华尔街“黑色星期四”"},{"label":"分级","value":"S"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1929年10月"},{"label":"地点","value":"美国纽约 / 德国"},{"label":"主要国家","value":"美国；德国；英国；法国"},{"label":"一句话概括","value":"1929年10月美国股市崩盘引发了全球经济危机\n，美国资本迅速撤出德国，依赖外资的魏玛经济资金链断裂，触发了全面经济危机。"},{"label":"参与者","value":"美国金融界、外国投资者、德国企业与劳工。"},{"label":"发生了什么","value":"1929年10月下旬，美国华尔街股市发生灾难性崩盘，大萧条席卷全球。由于德国此前的经济繁荣高度依赖美国贷款，随着美国债权人拒绝续期并大量收回短期贷款，德国经济的资金链直接断裂。随之而来的是德国外贸出口萎缩、企业大面积破产、国家税收锐减。"},{"label":"为什么重要","value":"切断了魏玛共和国“黄金时代”的外部资金输血，从根本上摧毁了魏玛脆弱的经济复苏基础。经济危机迅速转化为政治危机的催化剂，极端的社会苦难使得纳粹党等激进势力获得了庞大的选民支持。"},{"label":"前因","value":"1920年代美国信贷扩张和投机推高股价，经济结构性问题和市场信心逆转最终触发股票抛售。\n德国赔款《道威斯计划》实施后，德国经济高度依赖美国的短期贷款流入。"},{"label":"后果","value":"美国资本回流和国际信贷收缩冲击依赖外资的德国经济，大萧条失业危机和魏玛政治极化随之加深。\n德国国内爆发了规模空前的企业破产潮和失业潮。\n迫使接下来的德国政府为了平衡预算而采取严酷的通货紧缩政策。"},{"label":"出处","value":"《Weimar Culture》第一章；《魏玛德国——希望与悲剧》第124页。"}],"relationItems":["← 前因：德国赔款《道威斯计划》","→ 后果：布吕宁内阁通缩政策","→ 后果：1932年德国失业人数突破600万"],"relations":[{"text":"← 前因：德国赔款《道威斯计划》","id":"card92"},{"text":"→ 后果：布吕宁内阁通缩政策","id":"card65"},{"text":"→ 后果：1932年德国失业人数突破600万","id":"card69"}],"source":"history","id":"card64"},{"title":"布吕宁内阁通缩政策","level":"A","type":"事件卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1930年3月底","place":"德国","summary":"1930年海因里希·布吕宁就任总理后，为摆脱战争赔款负担，利用总统紧急法令绕开议会推行严厉通缩，试图通过经济极限承压向协约国证明赔款不可行，将德国推入经济枯竭的深渊。","fields":[{"label":"标题","value":"布吕宁内阁通缩政策"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1930年3月底"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1930年海因里希·布吕宁就任总理后，为摆脱战争赔款负担，利用总统紧急法令绕开议会推行严厉通缩，试图通过经济极限承压向协约国证明赔款不可行，将德国推入经济枯竭的深渊。"},{"label":"参与者","value":"海因里希·布吕宁、兴登堡总统、德国政府、国会、失业者、公务员、企业界。"},{"label":"发生了什么","value":"1930年3月，布吕宁出任德国总理后，在大萧条冲击和失业保险财政危机的背景下，推行了以削减财政支出、压低物价和工资、减少社会福利为核心的通缩政策。他希望通过让德国经济承受极限压力，向协约国证明德国已无力继续承担赔款。由于国会对其财政方案多有反对，布吕宁频繁依靠《魏玛宪法》第48条，通过总统紧急法令绕开议会实施政策。这使经济进一步恶化，也加剧了魏玛议会政治的失能。"},{"label":"为什么重要","value":"它使经济危机进一步深化，把大萧条转化为更严重的社会与政治危机。\n它强化了总统内阁和紧急法令政治，削弱了魏玛民主制度本身。"},{"label":"前因","value":"大萧条使德国财政、外债和赔款问题同时恶化，布吕宁希望通过削减开支和压低工资价格证明德国无力继续赔款。\n华尔街“黑色星期四”\n德国赔款《杨格计划》带来的赔款压力与财政困境"},{"label":"后果","value":"通缩政策加重失业和社会痛苦，削弱议会民主支持基础，极端政党在1930年后迅速扩大影响。\n德国达纳特银行倒闭\n失业继续上升，社会进一步激进化"},{"label":"出处","value":"《魏玛共和国的兴亡》第222-226页、第245-247页；《Weimar Culture》第一章。"}],"relationItems":["← 前因：华尔街“黑色星期四”","← 前因：德国赔款《杨格计划》","→ 后果：德国达纳特银行倒闭","✗ 对立/冲突：魏玛WTB就业创造计划"],"relations":[{"text":"← 前因：华尔街“黑色星期四”","id":"card64"},{"text":"← 前因：德国赔款《杨格计划》","id":"card93"},{"text":"→ 后果：德国达纳特银行倒闭","id":"card67"},{"text":"✗ 对立/冲突：魏玛WTB就业创造计划","id":"card68"}],"source":"history","id":"card65"},{"title":"魏玛《东部援助》法案","level":"C","type":"制度/文本卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1931年2月至11月","place":"德国（尤其是易北河以东地区）","summary":"1931年布吕宁政府推出的农业补贴法案，将巨额国家资金倾斜给易北河以东大地主，是魏玛末期资源错配与利益绑架的典型案例。","fields":[{"label":"标题","value":"魏玛《东部援助》法案"},{"label":"分级","value":"C"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1931年2月至11月"},{"label":"地点","value":"德国（尤其是易北河以东地区）"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1931年布吕宁政府推出的农业补贴法案，将巨额国家资金倾斜给易北河以东大地主，是魏玛末期资源错配与利益绑架的典型案例。"},{"label":"制定方/签署方","value":"布吕宁内阁、总统兴登堡及相关农业利益集团。"},{"label":"主要内容","value":"政府通过提供极高的国家担保、普遍降低利率、债务重组，以及直接划拨工业税收和国家贷款等方式，向易北河以东的农业企业（主要是大型庄园主）提供巨额的财政补贴。"},{"label":"它试图解决什么问题","value":"试图挽救因国际农产品价格暴跌和过度负债而面临大面积破产的东部大农业，并迎合大农场主阶层提出的“防卫东部边境不受斯拉夫化影响”的政治诉求。"},{"label":"为什么重要","value":"它揭示了魏玛晚期大农业利益集团如何利用其政治影响力（尤其是与兴登堡总统的密切关系）绑架国家财政。在全国底层民众承受通货紧缩和削减福利痛苦的同时，国家资源却被用于维持不合理的特权阶层。"},{"label":"争议/局限","value":"该法案在实施中极度不公，约300万小型农场被排除在外，而少数大型农场享受了绝大部分补贴。甚至有大农场主利用国家贷款支付自己奢侈的生活费用。这引发了工业界和劳工阶层的强烈抗议，原本可用于创造就业的巨额资金被挥霍。"},{"label":"造成的影响","value":"未能从根本上挽救东部农业的衰退，其补贴分配过程中的贪腐丑闻反而进一步摧毁了公众对政府的信任，并成为后来几届内阁倒台的政治导火索。"},{"label":"出处","value":"《魏玛共和国的兴亡》第264-267页。"}],"relationItems":["↔ 同时期参考：布吕宁内阁通缩政策","✗ 对立/冲突：魏玛WTB就业创造计划","↔ 相关：德国达纳特银行倒闭"],"relations":[{"text":"↔ 同时期参考：布吕宁内阁通缩政策","id":"card65"},{"text":"✗ 对立/冲突：魏玛WTB就业创造计划","id":"card68"},{"text":"↔ 相关：德国达纳特银行倒闭","id":"card67"}],"source":"history","id":"card66"},{"title":"德国达纳特银行倒闭","level":"A","type":"事件卡","tags":["经济与社会","无"],"mainTag":"经济与社会","subTag":"无","timeText":"1931年7月13日","place":"德国","summary":"受北德毛纺公司破产和外国资本撤离的叠加影响，1931年7月德国第四大银行德国达纳特银行倒闭，引发全国性挤兑，国家被迫接管私人信贷体系，魏玛金融体系实质性崩溃。","fields":[{"label":"标题","value":"德国达纳特银行倒闭"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"无"},{"label":"时间","value":"1931年7月13日"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"受北德毛纺公司破产和外国资本撤离的叠加影响，1931年7月德国第四大银行德国达纳特银行倒闭，引发全国性挤兑，国家被迫接管私人信贷体系，魏玛金融体系实质性崩溃。"},{"label":"参与者","value":"达姆施塔特与国民银行（Danat-Bank）、德国政府、国家银行、国内外债权人"},{"label":"发生了什么","value":"1931年6月，北德毛纺公司因轻率投机而破产，其主要债权人达姆施塔特与国民银行（简称达纳特银行）因此陷入严重的流动性危机。由于布吕宁政府带有政治施压意图的“纳贡呼吁”极大地破坏了国际金融界的信心，外国短期贷款自7月起加速撤离德国。7月13日，流动性枯竭的达纳特银行被迫宣布停止支付交易。全国范围内的储户和国内债权人随即蜂拥至各家银行提款，引发了灾难性的金融雪崩。紧接着，德国第二大信贷机构德累斯顿银行也宣告破产。政府被迫宣布7月14日和15日为银行假日，并通过紧急法规成立承兑和担保银行，国家由此实质上接管了主要的私人信贷机构。"},{"label":"为什么重要","value":"\n它标志着由美国股市崩盘引发的外部危机，正式演变为破坏性极强的德国本土金融和信用体系总崩溃。\n银行系统的瘫痪导致企业资金链断裂，破产数量激增，直接导致了下半年失业率的进一步失控。"},{"label":"前因","value":"大萧条导致德国企业破产和资本外逃，奥地利信贷危机扩散后，德国银行体系承受挤兑和流动性枯竭压力。\n华尔街“黑色星期四”导致外国短期贷款成为魏玛经济极度依赖却又极其脆弱的软肋。\n布吕宁政府试图利用经济危机要求免除赔款的外交表态，摧毁了外国投资者的信任。"},{"label":"后果","value":"银行倒闭引发金融恐慌和银行假日，信贷紧缩进一步打击经济，魏玛政府对危机的控制能力受到严重质疑。\n德国被迫实行严格的外汇管制，正常的市场经济与通货紧缩政策失去现实基础。\n市镇储蓄银行失去流动性，导致地方社会福利救济系统面临枯竭。"},{"label":"出处","value":"《魏玛共和国的兴亡》第八章。"}],"relationItems":["← 前因：华尔街“黑色星期四”","← 前因：布吕宁内阁通缩政策","→ 后果：1932年德国失业人数突破600万","↔ 同时期参考：魏玛《东部援助》法案"],"relations":[{"text":"← 前因：华尔街“黑色星期四”","id":"card64"},{"text":"← 前因：布吕宁内阁通缩政策","id":"card65"},{"text":"→ 后果：1932年德国失业人数突破600万","id":"card69"},{"text":"↔ 同时期参考：魏玛《东部援助》法案","id":"card66"}],"source":"history","id":"card67"},{"title":"魏玛WTB就业创造计划","level":"B","type":"制度/文本卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1931年底至1932年初","place":"德国","summary":"1931—1932年德国工会总联合会提出的就业刺激方案，主张通过国家信贷创造100万岗位，是魏玛末期最具代表性的\"反通缩替代路径\"，但最终遭到政府和正统经济学家的拒绝。","fields":[{"label":"标题","value":"魏玛WTB就业创造计划"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1931年底至1932年初"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1931—1932年德国工会总联合会提出的就业刺激方案，主张通过国家信贷创造100万岗位，是魏玛末期最具代表性的\"反通缩替代路径\"，但最终遭到政府和正统经济学家的拒绝。"},{"label":"制定方/签署方","value":"德国工会总联合会（由弗拉迪米尔·沃伊廷斯基、弗里茨·塔尔诺、弗里茨·巴德起草）。"},{"label":"主要内容","value":"计划要求摆脱单纯被动的、顺应通货紧缩的经济政策，主张通过人为广泛创造信贷的方式为公共工程项目提供资金，从而在短期内为100万名失业者提供就业机会。该计划的核心理念是利用国家信贷扩大公众购买力，通过消费方面的刺激来克服经济危机。"},{"label":"它试图解决什么问题","value":"试图应对大萧条下失业人数激增、购买力暴跌与企业产能闲置相互叠加的恶性循环，希望通过政府主动投资来打破紧缩政策带来的经济瘫痪。"},{"label":"为什么重要","value":"它是魏玛共和国晚期少数几个旨在主动干预并化解经济大崩溃的系统性替代方案，代表了工会试图承担国民经济全面责任的一次重要思想转变。"},{"label":"争议/局限","value":"在当时的主流经济理论看来，人为创造信贷无异于重演1923年的恶性通货膨胀。该计划不仅遭到了重工业界和国家银行总裁路德的坚决反对，就连社会民主党内部的正统经济学家（如希尔费丁）也因担忧通胀后果而对其持高度怀疑态度，布吕宁内阁更是不愿意用它来妨碍自己停止战争赔款的外交大计。"},{"label":"造成的影响","value":"由于缺乏足够的政治和学术支持，该计划未能付诸实施。政府依旧坚持紧缩政策，使得魏玛共和国错失了从内部阻断经济危机的潜在机会，广大失业工人的绝望感进一步加深。"},{"label":"出处","value":"《魏玛共和国的兴亡》第九章、第十章。"}],"relationItems":["← 前因：德国达纳特银行倒闭","✗ 对立/冲突：布吕宁内阁通缩政策"],"relations":[{"text":"← 前因：德国达纳特银行倒闭","id":"card67"},{"text":"✗ 对立/冲突：布吕宁内阁通缩政策","id":"card65"}],"source":"history","id":"card68"},{"title":"1932年德国失业人数突破600万","level":"B","type":"事件卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1932年2月","place":"德国全境","summary":"1932年初德国登记失业人数达到610万、占劳动人口三分之一以上，成为推动选民转向极端政党的最大社会推力。","fields":[{"label":"标题","value":"1932年德国失业人数突破600万"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1932年2月"},{"label":"地点","value":"德国全境"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1932年初德国登记失业人数达到610万、占劳动人口三分之一以上，成为推动选民转向极端政党的最大社会推力。"},{"label":"参与者","value":"德国失业者、工人、白领、青年群体、地方政府、福利机构、极端政党。"},{"label":"发生了什么","value":"到1932年2月，德国官方登记失业人数达到610万，超过劳动人口的三分之一。大量工人、白领、青年和中下层市民同时陷入失业状态，地方政府和社会救济系统不堪重负，许多家庭面临取暖、住房和基本食物都难以维持的困境。失业不再只是经济数字，而成为一种覆盖整个社会的普遍生活经验，并迅速转化为对现有政治秩序的普遍绝望。"},{"label":"为什么重要","value":"它把经济危机变成了大众性的社会崩溃体验。它为纳粹等极端政党提供了最广泛的愤怒选民基础。"},{"label":"前因","value":"全球大萧条、德国对美国贷款依赖和布吕宁通缩政策叠加，使工业生产下降并把大批工人推向长期失业。\n华尔街“黑色星期四”\n布吕宁内阁通缩政策"},{"label":"后果","value":"大规模失业摧毁中下层对共和国的信任，纳粹和共产党得以用反体制承诺吸引选民，1932年政治危机全面加深。\n希特勒出任德国总理\n议会民主进一步失去社会支持"},{"label":"出处","value":"《魏玛共和国的兴亡》第八章。"}],"relationItems":["← 前因：华尔街“黑色星期四”","← 前因：布吕宁内阁通缩政策","→ 后果：希特勒出任德国总理","↔ 相关：魏玛德国失业保险法"],"relations":[{"text":"← 前因：华尔街“黑色星期四”","id":"card64"},{"text":"← 前因：布吕宁内阁通缩政策","id":"card65"},{"text":"→ 后果：希特勒出任德国总理","id":"card71"},{"text":"↔ 相关：魏玛德国失业保险法","id":"card81"}],"source":"history","id":"card69"},{"title":"巴本税收抵用券与降薪法令","level":"B","type":"制度/文本卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1932年9月4日","place":"德国","summary":"巴本内阁试图通过向企业发放税收抵用券和放宽集体降薪限制来刺激雇佣，但因严重偏袒大资本并剥削工人而激化了社会矛盾。","fields":[{"label":"标题","value":"巴本税收抵用券与降薪法令"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1932年9月4日"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"巴本内阁试图通过向企业发放税收抵用券和放宽集体降薪限制来刺激雇佣，但因严重偏袒大资本并剥削工人而激化了社会矛盾。"},{"label":"制定方/签署方","value":"弗朗茨·冯·巴本内阁"},{"label":"主要内容","value":"作为“促进经济复苏的紧急法令”的核心，规定企业可根据缴纳税款的比例获得税收抵用券（实际上是一种人为创造的信贷），用于偿还未来的税收债务。随后的配套条例进一步规定，如果企业增加雇佣人数，就有权打破现有的集体薪资协议，将第31至第40小时的工资降低5%至25%；经济困难的企业也被允许将工资标准降低不超过20%。"},{"label":"它试图解决什么问题","value":"巴本政府希望改变布吕宁时期的单纯节流政策，通过大幅降低劳动力成本并为私人企业提供税收优惠与信贷支持，从企业端刺激经济复苏并创造新的就业岗位。"},{"label":"为什么重要","value":"这是魏玛末期政府试图主动干预经济的尝试，但其将经济复苏的成本单方面转嫁给工人阶级的做法，标志着建国初期奠定的劳资妥协原则与福利国家共识遭到了彻底破坏。"},{"label":"争议/局限","value":"该计划由于将税收优惠与大幅削减工人工资直接挂钩，实质上严重偏袒了大企业，不仅遭到了自由工会、基督教工会的强烈反对，甚至重工业界也担心此举引发的骚乱难以控制。"},{"label":"造成的影响","value":"由于法令实施耗时较长，且企业在订单匮乏的情况下并不愿意为了降低工资而盲目招人，该计划在1932年并未能迅速缓解失业问题。相反，对现行薪资协议的粗暴干预引发了多起激烈的自发罢工（如柏林公交公司罢工），使政府在政治上变得极其孤立。"},{"label":"出处","value":"《魏玛共和国的兴亡》第十二章。"}],"relationItems":["← 前因：1932年德国失业人数突破600万","✗ 对立/冲突：魏玛WTB就业创造计划"],"relations":[{"text":"← 前因：1932年德国失业人数突破600万","id":"card69"},{"text":"✗ 对立/冲突：魏玛WTB就业创造计划","id":"card68"}],"source":"history","id":"card70"},{"title":"希特勒出任德国总理","level":"S","type":"事件卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1933年1月30日","place":"柏林","summary":"1933年1月30日，兴登堡在保守派精英劝说下任命希特勒为总理，魏玛共和国就此终结，德国走向纳粹独裁。","fields":[{"label":"标题","value":"希特勒出任德国总理"},{"label":"分级","value":"S"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1933年1月30日"},{"label":"地点","value":"柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1933年1月30日，兴登堡在保守派精英劝说下任命希特勒为总理，魏玛共和国就此终结，德国走向纳粹独裁。"},{"label":"参与者","value":"阿道夫·希特勒、保罗·冯·兴登堡（国家总统）、以巴本和胡根贝格为首的保守派政治家、大工业家与农业利益集团代表。"},{"label":"发生了什么","value":"在经历了布吕宁、巴本、施莱歇尔几届总统内阁均无法解决经济大萧条与议会僵局后，传统的保守派右翼在选举中彻底失去了多数支持。为了防止议会民主制的复辟，同时打压社会民主党和工会力量，前总理巴本、德国国家人民党领袖胡根贝格以及大工业和农业集团的代表在幕后达成妥协。他们说服了年迈的兴登堡总统，于1933年1月30日任命希特勒为国家总理，组建了由纳粹党和德国国家人民党共同参与的联合政府。"},{"label":"为什么重要","value":"它是魏玛共和国经济彻底崩溃引发的社会怨念转化为极权政治的最终结局。标志着德国民主宪政体制的正式死亡和纳粹独裁暴政的开端，将德国乃至整个世界推向了深渊。"},{"label":"前因","value":"魏玛议会政治瘫痪，保守精英希望借纳粹群众基础重建权威政府，兴登堡在巴本等人劝说下接受了任命安排。\n经济危机导致的超600万大失业为纳粹党提供了庞大且狂热的激进选民基本盘。\n重工业界和大农业利益集团渴望利用纳粹党的暴力和群众基础，彻底粉碎魏玛的工会力量和福利制度。"},{"label":"后果","value":"希特勒利用总理职位、紧急法令和国家暴力迅速摧毁共和国，国会纵火案和授权法把合法任命转化为独裁政权。\n德国迅速沦为法西斯独裁国家，一切工人运动和异见声音被残酷镇压。\n魏玛时期试图依靠民主和妥协来维持的经济秩序被纳粹的备战经济与统制经济完全取代。"},{"label":"出处","value":"《魏玛共和国的兴亡》第十一章、第十二章与结语。"}],"relationItems":["← 前因：1932年德国失业人数突破600万","← 前因：布吕宁内阁通缩政策","← 前因：华尔街“黑色星期四”"],"relations":[{"text":"← 前因：1932年德国失业人数突破600万","id":"card69"},{"text":"← 前因：布吕宁内阁通缩政策","id":"card65"},{"text":"← 前因：华尔街“黑色星期四”","id":"card64"}],"source":"history","id":"card71"},{"title":"马格努斯·赫希菲尔德性科学研究所","level":"B","type":"组织/机构卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1919年成立，1933年被纳粹摧毁","place":"德国柏林","summary":"性科学研究所是魏玛柏林性改革和性少数权利运动的核心机构，1933年被纳粹暴力摧毁。","fields":[{"label":"标题","value":"马格努斯·赫希菲尔德性科学研究所"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1919年成立，1933年被纳粹摧毁"},{"label":"地点","value":"德国柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"性科学研究所是魏玛柏林性改革和性少数权利运动的核心机构，1933年被纳粹暴力摧毁。"},{"label":"性质/类型","value":"医学、性科学、咨询和改革倡议机构。"},{"label":"成立/解散时间","value":"1919年成立；1933年纳粹上台后被冲击、查封和掠夺。"},{"label":"核心目标/宗旨","value":"研究性、性别和婚姻问题，提供咨询，推动废除第175条等性法律改革。"},{"label":"关键人物（可选）","value":"马格努斯·赫希菲尔德。"},{"label":"关键行动/事件","value":"开展性教育、医学咨询、资料收藏和法律改革倡议；其藏书和档案在纳粹德国焚书运动中被毁。"},{"label":"为什么重要","value":"它说明魏玛文化不是单纯“堕落”标签，而包含现代医学、权利倡议和社会改革实验。"},{"label":"争议/局限","value":"研究所面对保守派、民族主义者和纳粹的持续攻击，其改革诉求未能改变魏玛政治脆弱性。"},{"label":"出处","value":"United States Holocaust Memorial Museum，Magnus Hirschfeld and Institute materials；Queer as German Folk，Goethe-Institut materials。"}],"relationItems":["← 前因：德国刑法典第175条","← 前因：德国裸体文化运动","→ 后果：纳粹德国焚书运动","→ 后果：纳粹同性恋迫害","↔ 相关：魏玛“新女性”","↔ 相关：魏玛柏林现代性","✗ 对立/冲突：魏玛德国性改革运动","✗ 对立/冲突：保守道德政治","↔ 同时期参考：德国表现主义电影"],"relations":[{"text":"← 前因：德国刑法典第175条","id":"extra721"},{"text":"← 前因：德国裸体文化运动","id":"extra727"},{"text":"→ 后果：纳粹德国焚书运动","id":"extra284"},{"text":"→ 后果：纳粹同性恋迫害","id":"extra857"},{"text":"↔ 相关：魏玛“新女性”","id":"card32"},{"text":"↔ 相关：魏玛柏林现代性","id":"card33"},{"text":"✗ 对立/冲突：魏玛德国性改革运动","id":"card85"},{"text":"✗ 对立/冲突：保守道德政治","id":"card207"},{"text":"↔ 同时期参考：德国表现主义电影","id":"card78"}],"source":"history","id":"card72"},{"title":"魏玛《全国青少年福利法》","level":"B","type":"制度/文本卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1922年通过，1924年生效","place":"魏玛共和国","summary":"魏玛《全国青少年福利法》把儿童和青少年保护纳入国家社会政策，是德国福利国家发展的重要环节。","fields":[{"label":"标题","value":"魏玛《全国青少年福利法》"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1922年通过，1924年生效"},{"label":"地点","value":"魏玛共和国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"魏玛《全国青少年福利法》把儿童和青少年保护纳入国家社会政策，是德国福利国家发展的重要环节。"},{"label":"制定方/签署方","value":"魏玛共和国国会和政府。"},{"label":"主要内容","value":"建立地方青少年福利办公室，规定儿童照护、监护、救助和青少年保护职责。"},{"label":"它试图解决什么问题","value":"战争遗孤、贫困儿童、城市贫民家庭和青少年失范问题使国家需要更系统的儿童福利制度。"},{"label":"为什么重要","value":"它把社会问题从慈善救济推向公共治理，显示魏玛共和国虽政治脆弱但在社会政策上具有制度创新。"},{"label":"争议/局限","value":"财政危机和地方执行能力限制了法律效果；福利保护也可能带有管教和社会控制色彩。"},{"label":"造成的影响","value":"奠定德国现代青少年福利行政基础，并影响后来儿童保护和家庭政策。"},{"label":"出处","value":"German History in Documents and Images，Weimar social policy materials；Bundeszentrale für politische Bildung，youth welfare history materials。"}],"relationItems":["← 前因：一战总动员社会","← 前因：德国“芜菁冬天”","→ 后果：魏玛福利国家","→ 后果：纳粹青年管制政策","↔ 相关：德国妇女运动","↔ 相关：魏玛“新女性”","✗ 对立/冲突：儿童权利保护","✗ 对立/冲突：国家社会管教","↔ 同时期参考：魏玛广播文化"],"relations":[{"text":"← 前因：一战总动员社会","id":"extra653"},{"text":"← 前因：德国“芜菁冬天”","id":"extra657"},{"text":"↔ 相关：德国妇女运动","id":"extra684"},{"text":"↔ 相关：魏玛“新女性”","id":"card32"},{"text":"↔ 同时期参考：魏玛广播文化","id":"card80"}],"source":"history","id":"card73"},{"title":"魏玛柏林“戒指会”犯罪网络","level":"C","type":"组织/机构卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"十九世纪末形成，魏玛时期活跃","place":"德国柏林","summary":"柏林“戒指会”是魏玛时期城市犯罪亚文化的代表，连接黑市、保护伞、夜生活和警方治理难题。","fields":[{"label":"标题","value":"魏玛柏林“戒指会”犯罪网络"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"十九世纪末形成，魏玛时期活跃"},{"label":"地点","value":"德国柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"柏林“戒指会”是魏玛时期城市犯罪亚文化的代表，连接黑市、保护伞、夜生活和警方治理难题。"},{"label":"性质/类型","value":"松散的犯罪互助组织和地下网络。"},{"label":"成立/解散时间","value":"十九世纪末逐渐出现，魏玛时期扩张；纳粹上台后被强力打击。"},{"label":"核心目标/宗旨","value":"为职业罪犯提供互助、身份掩护、赃物渠道、酒馆社交和法律援助网络。"},{"label":"关键人物（可选）","value":"多为地方犯罪头目和夜生活场所经营者，组织结构并不等同现代集中黑帮。"},{"label":"关键行动/事件","value":"参与盗窃、赃物交易、敲诈、地下酒馆和夜生活保护网络。"},{"label":"为什么重要","value":"它把魏玛柏林的现代都市经验从电影、舞厅和先锋艺术扩展到犯罪、贫困和警务治理。"},{"label":"争议/局限","value":"许多叙述来自警方、新闻和流行文化，容易把复杂城市贫困问题戏剧化。"},{"label":"出处","value":"German History in Documents and Images，Weimar crime and urban life materials；Weimar Berlin historical crime studies。"}],"relationItems":["← 前因：德意志帝国柏林租住营房","← 前因：德国战后通货膨胀","→ 后果：纳粹治安国家","→ 后果：盖世太保与刑警系统","↔ 相关：魏玛柏林现代性","↔ 相关：魏玛政治街头暴力","✗ 对立/冲突：都市地下经济","✗ 对立/冲突：现代警察治理","↔ 同时期参考：哈曼连环杀人案","↔ 同时期参考：彼得·库尔滕连环杀人案"],"relations":[{"text":"← 前因：德意志帝国柏林租住营房","id":"extra683"},{"text":"→ 后果：纳粹治安国家","id":"extra858"},{"text":"↔ 相关：魏玛柏林现代性","id":"card33"},{"text":"↔ 相关：魏玛政治街头暴力","id":"card34"},{"text":"↔ 同时期参考：哈曼连环杀人案","id":"card75"},{"text":"↔ 同时期参考：彼得·库尔滕连环杀人案","id":"card76"}],"source":"history","id":"card74"},{"title":"哈曼连环杀人案","level":"C","type":"事件卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"主要发生于1918年—1924年，1924年被捕","place":"德国汉诺威","summary":"哈曼连环杀人案把魏玛社会的贫困、失踪青年、警方漏洞和大众犯罪恐惧集中暴露出来。","fields":[{"label":"标题","value":"哈曼连环杀人案"},{"label":"分级","value":"C"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"主要发生于1918年—1924年，1924年被捕"},{"label":"地点","value":"德国汉诺威"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"哈曼连环杀人案把魏玛社会的贫困、失踪青年、警方漏洞和大众犯罪恐惧集中暴露出来。"},{"label":"参与者","value":"弗里茨·哈曼；多名年轻男性受害者；汉诺威警方和法院。"},{"label":"发生了什么","value":"战后汉诺威出现多名青年失踪，弗里茨·哈曼利用贫困、流动人口和火车站周边社会缝隙接近受害者。1924年警方调查后发现其长期杀害多名年轻男性，案件审判引发全国轰动。哈曼于1925年被处决。"},{"label":"为什么重要","value":"它不只是猎奇案件，而是魏玛社会失序、都市流动人口、警方失职和媒体犯罪消费共同作用的窗口。"},{"label":"前因","value":"一战后汉诺威存在流浪青年、黑市和社会救助不足等问题，警务系统对边缘人群失踪和暴力风险反应迟缓。"},{"label":"后果","value":"案件刺激魏玛时期犯罪新闻和公共恐慌，也引发对警察侦查、青少年保护和城市贫困治理的讨论。"},{"label":"出处","value":"Encyclopaedia Britannica，Fritz Haarmann materials；German criminal history sources on Weimar serial murder。"}],"relationItems":["← 前因：魏玛《全国青少年福利法》","← 前因：魏玛柏林现代性","→ 后果：魏玛犯罪恐惧","→ 后果：弗里茨·朗电影《M》","↔ 相关：魏玛柏林“戒指会”犯罪网络","↔ 相关：彼得·库尔滕连环杀人案","✗ 对立/冲突：现代都市匿名性","✗ 对立/冲突：社会保护能力","↔ 同时期参考：魏玛广播文化"],"relations":[{"text":"← 前因：魏玛《全国青少年福利法》","id":"card73"},{"text":"← 前因：魏玛柏林现代性","id":"card33"},{"text":"→ 后果：弗里茨·朗电影《M》","id":"extra70"},{"text":"↔ 相关：魏玛柏林“戒指会”犯罪网络","id":"card74"},{"text":"↔ 相关：彼得·库尔滕连环杀人案","id":"card76"},{"text":"↔ 同时期参考：魏玛广播文化","id":"card80"}],"source":"history","id":"card75"},{"title":"彼得·库尔滕连环杀人案","level":"C","type":"事件卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"1929年—1931年","place":"德国杜塞尔多夫","summary":"彼得·库尔滕案制造了魏玛末期的都市恐慌，也影响了德国犯罪电影和现代侦查想象。","fields":[{"label":"标题","value":"彼得·库尔滕连环杀人案"},{"label":"分级","value":"C"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1929年—1931年"},{"label":"地点","value":"德国杜塞尔多夫"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"彼得·库尔滕案制造了魏玛末期的都市恐慌，也影响了德国犯罪电影和现代侦查想象。"},{"label":"参与者","value":"彼得·库尔滕；杜塞尔多夫受害者；警方、法庭和新闻媒体。"},{"label":"发生了什么","value":"1929年前后，杜塞尔多夫发生多起袭击和杀人案件，媒体称凶手为“杜塞尔多夫吸血鬼”。警方在公众恐慌和新闻压力下展开大规模侦查，库尔滕被捕后受审，并于1931年被处决。案件与当时连环杀人、心理异常和现代警务的讨论紧密相连。"},{"label":"为什么重要","value":"它体现魏玛后期大众媒体、犯罪心理学和都市恐惧如何相互强化，并常被视为《M》等犯罪叙事的重要背景。"},{"label":"前因","value":"魏玛城市大众报刊扩大了犯罪恐惧传播，杜塞尔多夫连续暴力案件又正好击中社会对匿名都市危险的想象。"},{"label":"后果","value":"案件推动犯罪心理学和司法精神鉴定讨论，也为弗里茨·朗电影《M》的城市恐惧氛围提供现实背景。"},{"label":"出处","value":"Encyclopaedia Britannica，Peter Kürten materials；German film and crime history studies。"}],"relationItems":["← 前因：魏玛柏林“戒指会”犯罪网络","← 前因：哈曼连环杀人案","→ 后果：弗里茨·朗电影《M》","→ 后果：纳粹治安国家","↔ 相关：德国表现主义电影","↔ 相关：魏玛柏林现代性","✗ 对立/冲突：新闻轰动效应","✗ 对立/冲突：现代警务理性","↔ 同时期参考：1930年德国国会选举"],"relations":[{"text":"← 前因：魏玛柏林“戒指会”犯罪网络","id":"card74"},{"text":"← 前因：哈曼连环杀人案","id":"card75"},{"text":"→ 后果：弗里茨·朗电影《M》","id":"extra70"},{"text":"→ 后果：纳粹治安国家","id":"extra858"},{"text":"↔ 相关：德国表现主义电影","id":"card78"},{"text":"↔ 相关：魏玛柏林现代性","id":"card33"},{"text":"↔ 同时期参考：1930年德国国会选举","id":"card44"}],"source":"history","id":"card76"},{"title":"德国乌发电影公司","level":"B","type":"组织/机构卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1917年成立","place":"德国柏林及巴伯尔斯贝格片厂","summary":"乌发电影公司从一战宣传机构发展为魏玛电影工业核心，塑造德国现代电影的国际影响力。","fields":[{"label":"标题","value":"德国乌发电影公司"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1917年成立"},{"label":"地点","value":"德国柏林及巴伯尔斯贝格片厂"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"乌发电影公司从一战宣传机构发展为魏玛电影工业核心，塑造德国现代电影的国际影响力。"},{"label":"性质/类型","value":"电影制片和发行公司。"},{"label":"成立/解散时间","value":"1917年成立；魏玛时期商业化发展，纳粹时期被纳入宣传体系。"},{"label":"核心目标/宗旨","value":"最初服务战争宣传和国家影像竞争，战后转向商业电影、艺术电影和国际发行。"},{"label":"关键人物（可选）","value":"埃里希·波默、弗里茨·朗、F.W.茂瑙、约瑟夫·冯·斯登堡等与其作品相关。"},{"label":"关键行动/事件","value":"出品或发行《卡里加里博士的小屋》《大都会》《蓝天使》等重要电影，建设大型片厂体系。"},{"label":"为什么重要","value":"它把电影从娱乐业提升为现代大众文化、技术工业和国际软实力的综合载体。"},{"label":"争议/局限","value":"公司从国家宣传起家，后又被纳粹控制，显示电影工业很容易被政治权力吸纳。"},{"label":"出处","value":"Encyclopaedia Britannica，UFA materials；Deutsche Kinemathek，UFA history materials。"}],"relationItems":["← 前因：一战总动员社会","← 前因：魏玛广播文化","→ 后果：纳粹宣传机器","→ 后果：纳粹文化控制","↔ 相关：弗里茨·朗电影《大都会》","↔ 相关：德国电影《蓝天使》","↔ 相关：德国表现主义电影","✗ 对立/冲突：电影艺术实验","✗ 对立/冲突：国家宣传功能","↔ 同时期参考：魏玛柏林达达运动"],"relations":[{"text":"← 前因：一战总动员社会","id":"extra653"},{"text":"← 前因：魏玛广播文化","id":"card80"},{"text":"→ 后果：纳粹宣传机器","id":"extra94"},{"text":"→ 后果：纳粹文化控制","id":"extra113"},{"text":"↔ 相关：弗里茨·朗电影《大都会》","id":"extra65"},{"text":"↔ 相关：德国电影《蓝天使》","id":"extra68"},{"text":"↔ 相关：德国表现主义电影","id":"card78"},{"text":"↔ 同时期参考：魏玛柏林达达运动","id":"card79"}],"source":"history","id":"card77"},{"title":"德国表现主义电影","level":"B","type":"概念/思潮卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"约1919年—1920年代中期","place":"魏玛共和国电影工业中心，尤其柏林和巴伯尔斯贝格","summary":"德国表现主义电影以扭曲布景、强烈光影和心理化叙事表现战后焦虑，深刻影响世界电影语言。","fields":[{"label":"标题","value":"德国表现主义电影"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"约1919年—1920年代中期"},{"label":"地点","value":"魏玛共和国电影工业中心，尤其柏林和巴伯尔斯贝格"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国表现主义电影以扭曲布景、强烈光影和心理化叙事表现战后焦虑，深刻影响世界电影语言。"},{"label":"核心主张/思路","value":"电影不必自然主义再现现实，而可以用夸张造型、阴影、空间扭曲和心理氛围呈现内在恐惧。"},{"label":"提出者/代表人物（可选）","value":"罗伯特·维内、F.W.茂瑙、弗里茨·朗等。"},{"label":"它从何而来","value":"战后社会创伤、舞台表现主义、美术设计实验和魏玛电影工业条件。"},{"label":"典型表现","value":"《卡里加里博士的小屋》《诺斯费拉图》《大都会》《M》等作品中的阴影、都市焦虑和权威恐惧。"},{"label":"为什么重要","value":"它为恐怖片、黑色电影和现代心理电影提供视觉语法，也让魏玛文化成为世界电影史中心之一。"},{"label":"争议/局限","value":"并非所有魏玛电影都属于表现主义，过度使用该标签会遮蔽通俗片、喜剧和现实主义电影。"},{"label":"出处","value":"Encyclopaedia Britannica，“German Expressionism”；British Film Institute，Weimar cinema materials。"}],"relationItems":["← 前因：德国乌发电影公司","← 前因：魏玛柏林现代性","→ 后果：弗里茨·朗电影《M》","→ 后果：电影黑色传统","↔ 相关：弗里茨·朗电影《大都会》","↔ 相关：德国电影《蓝天使》","↔ 相关：德国新客观主义","✗ 对立/冲突：自然主义再现","✗ 对立/冲突：心理化视觉风格","↔ 同时期参考：魏玛柏林达达运动"],"relations":[{"text":"← 前因：德国乌发电影公司","id":"card77"},{"text":"← 前因：魏玛柏林现代性","id":"card33"},{"text":"→ 后果：弗里茨·朗电影《M》","id":"extra70"},{"text":"→ 后果：电影黑色传统","id":"card199"},{"text":"↔ 相关：弗里茨·朗电影《大都会》","id":"extra65"},{"text":"↔ 相关：德国电影《蓝天使》","id":"extra68"},{"text":"↔ 相关：德国新客观主义","id":"card31"},{"text":"↔ 同时期参考：魏玛柏林达达运动","id":"card79"}],"source":"history","id":"card78"},{"title":"魏玛柏林达达运动","level":"C","type":"概念/思潮卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"约1918年—1923年","place":"德国柏林","summary":"柏林达达运动用拼贴、讽刺和反艺术姿态攻击战争、资产阶级秩序和魏玛政治虚伪。","fields":[{"label":"标题","value":"魏玛柏林达达运动"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"约1918年—1923年"},{"label":"地点","value":"德国柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"柏林达达运动用拼贴、讽刺和反艺术姿态攻击战争、资产阶级秩序和魏玛政治虚伪。"},{"label":"核心主张/思路","value":"反对传统艺术神圣性，用荒诞、拼贴、照片蒙太奇和政治讽刺揭露现代社会的暴力与虚假。"},{"label":"提出者/代表人物（可选）","value":"汉娜·赫希、乔治·格罗兹、约翰·哈特菲尔德、劳尔·豪斯曼等。"},{"label":"它从何而来","value":"一战创伤、反军国主义情绪、左翼政治文化和欧洲达达主义传播。"},{"label":"典型表现","value":"照片蒙太奇、讽刺画、杂志、展览和对军官、资本家、民族主义者的攻击性图像。"},{"label":"为什么重要","value":"它把先锋艺术从形式实验推进到大众媒体和政治讽刺，影响后来的平面设计、摄影拼贴和反战艺术。"},{"label":"争议/局限","value":"达达的反艺术策略有时依赖小圈子冲击效果，政治立场也并不完全统一。"},{"label":"出处","value":"Museum of Modern Art，Dada materials；Tate，Berlin Dada materials。"}],"relationItems":["← 前因：一战总动员社会","← 前因：德国十一月革命","→ 后果：德国新客观主义","→ 后果：纳粹德国“退化艺术”展","↔ 相关：魏玛柏林现代性","↔ 相关：魏玛政治街头暴力","✗ 对立/冲突：资产阶级艺术制度","✗ 对立/冲突：反艺术政治讽刺","↔ 同时期参考：德国表现主义电影"],"relations":[{"text":"← 前因：一战总动员社会","id":"extra653"},{"text":"← 前因：德国十一月革命","id":"extra666"},{"text":"→ 后果：德国新客观主义","id":"card31"},{"text":"→ 后果：纳粹德国“退化艺术”展","id":"extra126"},{"text":"↔ 相关：魏玛柏林现代性","id":"card33"},{"text":"↔ 相关：魏玛政治街头暴力","id":"card34"},{"text":"↔ 同时期参考：德国表现主义电影","id":"card78"}],"source":"history","id":"card79"},{"title":"魏玛广播文化","level":"C","type":"概念/思潮卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1923年以后","place":"魏玛共和国","summary":"魏玛广播文化把新闻、音乐、教育和家庭娱乐带入日常生活，也预示大众传媒政治动员的力量。","fields":[{"label":"标题","value":"魏玛广播文化"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1923年以后"},{"label":"地点","value":"魏玛共和国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"魏玛广播文化把新闻、音乐、教育和家庭娱乐带入日常生活，也预示大众传媒政治动员的力量。"},{"label":"核心主张/思路","value":"广播使声音跨越空间进入家庭，形成新的公共文化和同步收听经验。"},{"label":"提出者/代表人物（可选）","value":"由广播公司、邮政管理机构、文化教育界和节目制作人共同推动。"},{"label":"它从何而来","value":"无线电技术、一战通信经验、城市娱乐市场和国家对频谱管理的需要。"},{"label":"典型表现","value":"音乐会转播、新闻、广播剧、教育节目、家庭收音机和收听许可证制度。"},{"label":"为什么重要","value":"它让魏玛大众文化不仅属于电影院和报刊，也属于家庭客厅；同时为纳粹后来的广播宣传提供媒介基础。"},{"label":"争议/局限","value":"广播从一开始就受到国家许可和监管，公共教育理想与政治控制可能并存。"},{"label":"出处","value":"German History in Documents and Images，radio in Weimar Germany materials；Deutsches Rundfunkarchiv，German radio history materials。"}],"relationItems":["← 前因：魏玛广播文化","← 前因：德国乌发电影公司","→ 后果：纳粹宣传机器","→ 后果：纳粹德国人民收音机","↔ 相关：魏玛柏林现代性","↔ 相关：德国新客观主义","✗ 对立/冲突：公共教育媒介","✗ 对立/冲突：政治宣传媒介","↔ 同时期参考：德国表现主义电影"],"relations":[{"text":"← 前因：魏玛广播文化","id":"card80"},{"text":"← 前因：德国乌发电影公司","id":"card77"},{"text":"→ 后果：纳粹宣传机器","id":"extra94"},{"text":"→ 后果：纳粹德国人民收音机","id":"extra285"},{"text":"↔ 相关：魏玛柏林现代性","id":"card33"},{"text":"↔ 相关：德国新客观主义","id":"card31"},{"text":"↔ 同时期参考：德国表现主义电影","id":"card78"}],"source":"history","id":"card80"},{"title":"魏玛德国失业保险法","level":"B","type":"制度/文本卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1927年","place":"魏玛共和国","summary":"魏玛德国失业保险法把失业风险纳入全国社会保险体系，是德国福利国家扩张的重要一步。","fields":[{"label":"标题","value":"魏玛德国失业保险法"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1927年"},{"label":"地点","value":"魏玛共和国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"魏玛德国失业保险法把失业风险纳入全国社会保险体系，是德国福利国家扩张的重要一步。"},{"label":"制定方/签署方","value":"魏玛共和国国会和政府。"},{"label":"主要内容","value":"建立全国性失业保险和就业介绍制度，由雇主、雇员和公共机构共同承担相关责任。"},{"label":"它试图解决什么问题","value":"战后经济波动、复员、结构性失业和工人家庭收入不稳定，使国家需要制度化应对失业。"},{"label":"为什么重要","value":"它体现魏玛共和国的社会国家理想，也解释大萧条到来时福利财政为何迅速承压。"},{"label":"争议/局限","value":"制度建立时间较晚，资金基础脆弱；1929年后大规模失业使保险体系难以承受。"},{"label":"造成的影响","value":"成为魏玛福利国家成就与危机的双重象征。"},{"label":"出处","value":"German History in Documents and Images，Weimar welfare state materials；Bundeszentrale für politische Bildung，German unemployment insurance history materials。"}],"relationItems":["← 前因：德国俾斯麦社会保险立法","← 前因：魏玛共和国成立","→ 后果：大萧条下德国失业危机","→ 后果：魏玛总统内阁","↔ 相关：魏玛《全国青少年福利法》","↔ 相关：德国消费合作社运动","✗ 对立/冲突：社会保障权利","✗ 对立/冲突：财政承受能力","↔ 同时期参考：魏玛德国大众消费文化"],"relations":[{"text":"← 前因：德国俾斯麦社会保险立法","id":"extra629"},{"text":"← 前因：魏玛共和国成立","id":"card7"},{"text":"→ 后果：魏玛总统内阁","id":"card39"},{"text":"↔ 相关：魏玛《全国青少年福利法》","id":"card73"},{"text":"↔ 相关：德国消费合作社运动","id":"extra728"},{"text":"↔ 同时期参考：魏玛德国大众消费文化","id":"card87"}],"source":"history","id":"card81"},{"title":"新法兰克福住房项目","level":"B","type":"事件卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"1925年—1930年","place":"德国法兰克福","summary":"新法兰克福住房项目用现代主义规划和标准化住宅回应住房短缺，是魏玛社会改革与设计实验的代表。","fields":[{"label":"标题","value":"新法兰克福住房项目"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1925年—1930年"},{"label":"地点","value":"德国法兰克福"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"新法兰克福住房项目用现代主义规划和标准化住宅回应住房短缺，是魏玛社会改革与设计实验的代表。"},{"label":"参与者","value":"法兰克福市政府；建筑师恩斯特·迈；现代主义建筑师、设计师和市政住房机构。"},{"label":"发生了什么","value":"法兰克福在市政支持下展开大规模住宅建设，采用标准化构件、现代平面、采光通风原则和社区设施规划。项目不仅建房，也同步设计厨房、家具、交通、绿地和公共服务，试图用可复制的现代住宅改善工人及中下层家庭生活。它把建筑师、设计师、市政官员和社会改革者组织到同一套住房实验中。"},{"label":"为什么重要","value":"它说明魏玛现代主义不是纯艺术风格，而是与住房、卫生、女性家务劳动和市政福利直接相关。"},{"label":"前因","value":"一战后城市住房短缺严重，公共卫生和社会改革理念推动市政当局把住宅建设视为现代城市治理任务。"},{"label":"后果","value":"项目成为现代社会住宅和功能主义设计的重要范式，但纳粹上台后现代主义建筑与相关社会改革网络受到压制。"},{"label":"出处","value":"Museum Angewandte Kunst Frankfurt，New Frankfurt materials；MoMA，Ernst May and New Frankfurt materials。"}],"relationItems":["← 前因：德意志帝国柏林租住营房","← 前因：德国城市公共卫生运动","→ 后果：新法兰克福“法兰克福厨房”","→ 后果：现代社会住宅","↔ 相关：德国包豪斯","↔ 相关：魏玛《全国青少年福利法》","✗ 对立/冲突：投机性租房市场","✗ 对立/冲突：市政住宅改革","↔ 同时期参考：柏林现代主义住宅区"],"relations":[{"text":"← 前因：德意志帝国柏林租住营房","id":"extra683"},{"text":"← 前因：德国城市公共卫生运动","id":"extra733"},{"text":"→ 后果：新法兰克福“法兰克福厨房”","id":"card84"},{"text":"→ 后果：现代社会住宅","id":"card201"},{"text":"↔ 相关：德国包豪斯","id":"card30"},{"text":"↔ 相关：魏玛《全国青少年福利法》","id":"card73"},{"text":"↔ 同时期参考：柏林现代主义住宅区","id":"card83"}],"source":"history","id":"card82"},{"title":"柏林现代主义住宅区","level":"B","type":"事件卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"1920年代，2008年列入世界遗产","place":"德国柏林","summary":"柏林现代主义住宅区用光线、绿地和功能平面回应工人住房问题，是魏玛住房改革的世界级遗产。","fields":[{"label":"标题","value":"柏林现代主义住宅区"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1920年代，2008年列入世界遗产"},{"label":"地点","value":"德国柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"柏林现代主义住宅区用光线、绿地和功能平面回应工人住房问题，是魏玛住房改革的世界级遗产。"},{"label":"参与者","value":"柏林市政住房机构；布鲁诺·陶特、马丁·瓦格纳等建筑师。"},{"label":"发生了什么","value":"魏玛时期柏林通过公共和合作住房建设，发展出一批现代主义住宅区。它们强调低密度、采光、绿化、卫生设施和可负担性，与十九世纪拥挤租住营房形成对比。联合国教科文组织后来将六处相关住宅区列为世界遗产。"},{"label":"为什么重要","value":"它把社会政策、建筑现代主义和日常居住质量结合起来，是理解魏玛改革能力的重要非政治入口。"},{"label":"前因","value":"柏林租住营房问题和战后住房短缺迫使市政当局寻找低成本、卫生、光照和绿地条件更好的公共住宅方案。"},{"label":"后果","value":"这些住宅区建立了现代社会住宅传统，也使魏玛现代主义建筑在纳粹时期成为被攻击和压制的对象。"},{"label":"出处","value":"UNESCO World Heritage Centre，“Berlin Modernism Housing Estates”；Bauhaus Kooperation，modernist housing materials。"}],"relationItems":["← 前因：德意志帝国柏林租住营房","← 前因：德国城市公共卫生运动","→ 后果：现代社会住宅","↔ 相关：新法兰克福住房项目","↔ 相关：德国包豪斯","✗ 对立/冲突：拥挤租住营房","✗ 对立/冲突：现代健康住宅","↔ 同时期参考：魏玛德国失业保险法"],"relations":[{"text":"← 前因：德意志帝国柏林租住营房","id":"extra683"},{"text":"← 前因：德国城市公共卫生运动","id":"extra733"},{"text":"→ 后果：现代社会住宅","id":"card201"},{"text":"↔ 相关：新法兰克福住房项目","id":"card82"},{"text":"↔ 相关：德国包豪斯","id":"card30"},{"text":"↔ 同时期参考：魏玛德国失业保险法","id":"card81"}],"source":"history","id":"card83"},{"title":"新法兰克福“法兰克福厨房”","level":"C","type":"作品卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1926年设计并推广","place":"德国法兰克福","summary":"新法兰克福“法兰克福厨房”把家务劳动当作可被科学组织的工作，是现代厨房设计和女性日常生活史的重要节点。","fields":[{"label":"标题","value":"新法兰克福“法兰克福厨房”"},{"label":"分级","value":"C"},{"label":"类型","value":"作品卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1926年设计并推广"},{"label":"地点","value":"德国法兰克福"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"新法兰克福“法兰克福厨房”把家务劳动当作可被科学组织的工作，是现代厨房设计和女性日常生活史的重要节点。"},{"label":"作者/创作者","value":"玛格丽特·舒特-利霍茨基。"},{"label":"媒介/体裁","value":"住宅室内设计、标准化厨房系统。"},{"label":"主要内容/讲了什么","value":"它通过紧凑平面、固定柜体、储物系统、工作台高度和动线设计，提高小住宅中烹饪与家务效率。"},{"label":"核心主张/表达","value":"现代设计应介入日常劳动，减少家务耗时，并把家庭空间纳入科学管理。"},{"label":"它出现在什么背景下","value":"新法兰克福住房项目、大规模社会住宅建设和女性家务劳动负担讨论。"},{"label":"为什么重要","value":"它是现代整体厨房的早期原型之一，也揭示现代主义设计如何改变家庭内部劳动。"},{"label":"接受与影响","value":"被广泛视为现代厨房设计经典，影响二十世纪住宅标准化。"},{"label":"争议/局限","value":"它提高效率，但没有根本改变家务主要由女性承担的性别结构。"},{"label":"出处","value":"Museum Angewandte Kunst Frankfurt，Frankfurt Kitchen materials；MoMA，Margarete Schütte-Lihotzky materials。"}],"relationItems":["← 前因：新法兰克福住房项目","← 前因：魏玛“新女性”","→ 后果：现代整体厨房","↔ 相关：德国包豪斯","↔ 相关：魏玛德国大众消费文化","✗ 对立/冲突：传统家庭空间","✗ 对立/冲突：科学化家务劳动","↔ 同时期参考：柏林现代主义住宅区"],"relations":[{"text":"← 前因：新法兰克福住房项目","id":"card82"},{"text":"← 前因：魏玛“新女性”","id":"card32"},{"text":"↔ 相关：德国包豪斯","id":"card30"},{"text":"↔ 相关：魏玛德国大众消费文化","id":"card87"},{"text":"↔ 同时期参考：柏林现代主义住宅区","id":"card83"}],"source":"history","id":"card84"},{"title":"魏玛德国性改革运动","level":"B","type":"概念/思潮卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1919年—1933年","place":"魏玛共和国，尤其柏林","summary":"魏玛德国性改革运动围绕避孕、婚姻、同性恋除罪和性教育展开，是现代身体政治的重要实验。","fields":[{"label":"标题","value":"魏玛德国性改革运动"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1919年—1933年"},{"label":"地点","value":"魏玛共和国，尤其柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"魏玛德国性改革运动围绕避孕、婚姻、同性恋除罪和性教育展开，是现代身体政治的重要实验。"},{"label":"核心主张/思路","value":"性和婚姻问题应由科学、教育、权利和公共卫生讨论，而不只由教会道德或刑法支配。"},{"label":"提出者/代表人物（可选）","value":"马格努斯·赫希菲尔德、海伦娜·施特克尔等性改革者和医生。"},{"label":"它从何而来","value":"第175条争议、妇女运动、城市大众文化、医学性科学和战后社会重组。"},{"label":"典型表现","value":"性咨询中心、避孕宣传、婚姻改革讨论、同性恋权利倡议和性科学出版物。"},{"label":"为什么重要","value":"它解释魏玛文化为什么既被视为解放，也被保守派描绘成道德危机。"},{"label":"争议/局限","value":"改革运动主要集中在城市知识界和部分工人组织中，且很快遭纳粹暴力摧毁。"},{"label":"出处","value":"United States Holocaust Memorial Museum，Magnus Hirschfeld materials；German History in Documents and Images，Weimar sexuality materials。"}],"relationItems":["← 前因：德国刑法典第175条","← 前因：德国妇女运动","→ 后果：纳粹德国焚书运动","→ 后果：纳粹家庭政策","↔ 相关：马格努斯·赫希菲尔德性科学研究所","↔ 相关：魏玛“新女性”","✗ 对立/冲突：保守性道德","✗ 对立/冲突：性科学改革","↔ 同时期参考：魏玛广播文化"],"relations":[{"text":"← 前因：德国刑法典第175条","id":"extra721"},{"text":"← 前因：德国妇女运动","id":"extra684"},{"text":"→ 后果：纳粹德国焚书运动","id":"extra284"},{"text":"→ 后果：纳粹家庭政策","id":"extra117"},{"text":"↔ 相关：马格努斯·赫希菲尔德性科学研究所","id":"card72"},{"text":"↔ 相关：魏玛“新女性”","id":"card32"},{"text":"↔ 同时期参考：魏玛广播文化","id":"card80"}],"source":"history","id":"card85"},{"title":"魏玛德国大众体育文化","level":"C","type":"概念/思潮卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1920年代—1933年","place":"魏玛共和国","summary":"魏玛德国大众体育文化让拳击、足球、自行车赛和体操成为城市娱乐、阶级身份和身体理想的一部分。","fields":[{"label":"标题","value":"魏玛德国大众体育文化"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1920年代—1933年"},{"label":"地点","value":"魏玛共和国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"魏玛德国大众体育文化让拳击、足球、自行车赛和体操成为城市娱乐、阶级身份和身体理想的一部分。"},{"label":"核心主张/思路","value":"体育既是健康训练，也是大众传媒、商业娱乐、工人社团和民族身体想象的交叉空间。"},{"label":"提出者/代表人物（可选）","value":"由体育协会、工人体育组织、俱乐部、报刊和明星运动员共同塑造。"},{"label":"它从何而来","value":"帝德体操传统、城市休闲市场、报刊广播扩张和战后身体重建需求。"},{"label":"典型表现","value":"足球俱乐部、拳击明星、六日自行车赛、工人体育节、女性运动和体育新闻。"},{"label":"为什么重要","value":"它把魏玛现代性从夜总会和电影扩展到身体、竞技和大众休闲。"},{"label":"争议/局限","value":"体育文化既能推动身体自由，也可能被民族主义和性别规范重新编码。"},{"label":"出处","value":"German History in Documents and Images，sports in Weimar Germany materials；Bundeszentrale für politische Bildung，German sports history materials。"}],"relationItems":["← 前因：德国体操运动","← 前因：德国裸体文化运动","→ 后果：1936年柏林奥运会","↔ 相关：魏玛广播文化","↔ 相关：魏玛“新女性”","✗ 对立/冲突：身体商业娱乐","✗ 对立/冲突：身体政治规训","↔ 同时期参考：魏玛德国大众消费文化"],"relations":[{"text":"← 前因：德国体操运动","id":"extra517"},{"text":"← 前因：德国裸体文化运动","id":"extra727"},{"text":"→ 后果：1936年柏林奥运会","id":"extra129"},{"text":"↔ 相关：魏玛广播文化","id":"card80"},{"text":"↔ 相关：魏玛“新女性”","id":"card32"},{"text":"↔ 同时期参考：魏玛德国大众消费文化","id":"card87"}],"source":"history","id":"card86"},{"title":"魏玛德国大众消费文化","level":"C","type":"概念/思潮卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"1920年代","place":"魏玛共和国城市社会","summary":"魏玛德国大众消费文化以广告、百货商店、电影、杂志和新式家用品塑造现代城市欲望。","fields":[{"label":"标题","value":"魏玛德国大众消费文化"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1920年代"},{"label":"地点","value":"魏玛共和国城市社会"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"魏玛德国大众消费文化以广告、百货商店、电影、杂志和新式家用品塑造现代城市欲望。"},{"label":"核心主张/思路","value":"消费不只是购买商品，也是在广告、橱窗、明星和生活方式中想象现代自我。"},{"label":"提出者/代表人物（可选）","value":"由百货商店、广告公司、电影工业、杂志出版和制造业共同推动。"},{"label":"它从何而来","value":"帝德百货商店、战后稳定期经济复苏、美国化影响和城市传媒扩张。"},{"label":"典型表现","value":"橱窗购物、分期付款、电影明星、女性杂志、家电、化妆品和品牌广告。"},{"label":"为什么重要","value":"它解释魏玛文化中“新女性”、电影、住房设计和保守道德恐慌之间的联系。"},{"label":"争议/局限","value":"消费文化主要集中于城市和相对有购买力群体，失业和贫困使许多人只能旁观这种现代生活。"},{"label":"出处","value":"German History in Documents and Images，Weimar consumer culture materials；Deutsches Historisches Museum/LeMO，Weimar everyday life materials。"}],"relationItems":["← 前因：德国百货商店兴起","← 前因：德国乌发电影公司","→ 后果：纳粹德国“力量来自欢乐”组织","↔ 相关：魏玛“新女性”","↔ 相关：新法兰克福“法兰克福厨房”","✗ 对立/冲突：消费现代性","✗ 对立/冲突：经济不平等","↔ 同时期参考：魏玛德国失业保险法"],"relations":[{"text":"← 前因：德国百货商店兴起","id":"extra730"},{"text":"← 前因：德国乌发电影公司","id":"card77"},{"text":"→ 后果：纳粹德国“力量来自欢乐”组织","id":"extra104"},{"text":"↔ 相关：魏玛“新女性”","id":"card32"},{"text":"↔ 相关：新法兰克福“法兰克福厨房”","id":"card84"},{"text":"↔ 同时期参考：魏玛德国失业保险法","id":"card81"}],"source":"history","id":"card87"},{"title":"汉娜·赫希","level":"C","type":"人物卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1889年—1978年","place":"德国柏林","summary":"汉娜·赫希以照片蒙太奇批判性别、媒体和政治权力，是柏林达达运动中最重要的女性艺术家之一。","fields":[{"label":"标题","value":"汉娜·赫希"},{"label":"分级","value":"C"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1889年—1978年"},{"label":"地点","value":"德国柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"汉娜·赫希以照片蒙太奇批判性别、媒体和政治权力，是柏林达达运动中最重要的女性艺术家之一。"},{"label":"生卒年/活跃年代","value":"1889年生，1978年卒；魏玛时期尤其活跃。"},{"label":"身份/职务","value":"艺术家、达达主义者、照片蒙太奇实践者。"},{"label":"关键贡献/作为","value":"用报刊图像、广告和政治人物照片拼贴出讽刺性作品，挑战男性艺术圈和大众媒体性别形象。"},{"label":"核心主张/立场","value":"通过拼贴拆解现代媒体制造的身体、性别和权力图像。"},{"label":"为什么重要","value":"她让魏玛先锋艺术不只是男性政治讽刺，也包含女性视角下的传媒和性别批判。"},{"label":"争议/评价","value":"她在男性主导的达达圈内长期被边缘化，战后研究才更充分确认其地位。"},{"label":"关联事件（可选）","value":"柏林达达运动；纳粹“退化艺术”展。"},{"label":"出处","value":"Tate，“Hannah Höch”；Museum of Modern Art，Hannah Höch materials。"}],"relationItems":["← 前因：魏玛柏林达达运动","← 前因：魏玛“新女性”","→ 后果：现代照片蒙太奇艺术","↔ 相关：德国新客观主义","↔ 相关：魏玛德国大众消费文化","✗ 对立/冲突：男性先锋艺术圈","✗ 对立/冲突：女性艺术主体性","↔ 同时期参考：德布林《柏林亚历山大广场》"],"relations":[{"text":"← 前因：魏玛柏林达达运动","id":"card79"},{"text":"← 前因：魏玛“新女性”","id":"card32"},{"text":"↔ 相关：德国新客观主义","id":"card31"},{"text":"↔ 相关：魏玛德国大众消费文化","id":"card87"},{"text":"↔ 同时期参考：德布林《柏林亚历山大广场》","id":"extra69"}],"source":"history","id":"card88"},{"title":"德国人权联盟","level":"C","type":"组织/机构卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1922年成立，纳粹上台后被取缔","place":"魏玛共和国","summary":"德国人权联盟是魏玛时期反军国主义、共和防卫和公民权利倡议的重要组织。","fields":[{"label":"标题","value":"德国人权联盟"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1922年成立，纳粹上台后被取缔"},{"label":"地点","value":"魏玛共和国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国人权联盟是魏玛时期反军国主义、共和防卫和公民权利倡议的重要组织。"},{"label":"性质/类型","value":"公民权利和和平主义组织。"},{"label":"成立/解散时间","value":"1922年成立；1933年后被纳粹压制。"},{"label":"核心目标/宗旨","value":"维护共和法治、反对政治暴力、支持和平主义和人权观念。"},{"label":"关键人物（可选）","value":"卡尔·冯·奥西茨基等和平主义者和左翼自由派人士与其相关。"},{"label":"关键行动/事件","value":"发表声明、参与反军国主义活动、支持政治受害者和公共舆论倡议。"},{"label":"为什么重要","value":"它提醒魏玛并非只有极端主义街头政治，也存在试图用权利语言守护共和国的公民社会。"},{"label":"争议/局限","value":"组织影响力无法抵消右翼民族主义、政治暴力和司法偏向带来的压力。"},{"label":"出处","value":"German History in Documents and Images，Weimar civil liberties materials；Bundeszentrale für politische Bildung，Weimar pacifism materials。"}],"relationItems":["← 前因：德国保卫共和国法","← 前因：魏玛政治街头暴力","→ 后果：纳粹一体化政策","↔ 相关：瓦尔特·拉特瑙遇刺","↔ 相关：德国铁阵线","✗ 对立/冲突：共和公民权利","✗ 对立/冲突：反共和暴力政治","↔ 同时期参考：魏玛德国性改革运动"],"relations":[{"text":"← 前因：德国保卫共和国法","id":"card29"},{"text":"← 前因：魏玛政治街头暴力","id":"card34"},{"text":"→ 后果：纳粹一体化政策","id":"extra100"},{"text":"↔ 相关：瓦尔特·拉特瑙遇刺","id":"card27"},{"text":"↔ 相关：德国铁阵线","id":"card54"},{"text":"↔ 同时期参考：魏玛德国性改革运动","id":"card85"}],"source":"history","id":"card89"},{"title":"魏玛恶性通货膨胀","level":"A","type":"事件卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1921年—1923年，1923年达到高峰","place":"魏玛共和国","summary":"魏玛恶性通货膨胀摧毁货币信任和中产储蓄，是理解魏玛政治激化与社会创伤的关键节点。","fields":[{"label":"标题","value":"魏玛恶性通货膨胀"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1921年—1923年，1923年达到高峰"},{"label":"地点","value":"魏玛共和国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"魏玛恶性通货膨胀摧毁货币信任和中产储蓄，是理解魏玛政治激化与社会创伤的关键节点。"},{"label":"参与者","value":"魏玛政府、德国央行、企业、工人、中产储户、赔款债权国。"},{"label":"发生了什么","value":"战后德国财政、赔款压力和政治危机叠加，政府以发行货币应对开支。1923年鲁尔被占领后，消极抵抗进一步扩大财政缺口，马克急剧贬值。工资和物价以天、小时计变化，储蓄和固定收入被摧毁，日常交易、租金和工资支付陷入混乱。"},{"label":"为什么重要","value":"它深刻破坏共和国合法性，塑造中产阶层对魏玛的怨恨记忆，也推动货币稳定政策和外债依赖。"},{"label":"前因","value":"战争债务、赔款压力、财政赤字和鲁尔消极抵抗的发钞补贴共同摧毁纸马克信用。"},{"label":"后果","value":"恶性通胀洗劫储蓄并破坏社会信任，伦滕马克和德国赔款《道威斯计划》虽恢复稳定，却让通胀创伤长期留在德国政治记忆中。"},{"label":"出处","value":"Encyclopaedia Britannica，Weimar hyperinflation materials；German History in Documents and Images，hyperinflation materials。"}],"relationItems":["← 前因：魏玛德国赔款问题","← 前因：鲁尔占领与德国消极抵抗","→ 后果：魏玛德国伦滕马克","→ 后果：德国赔款《道威斯计划》","↔ 相关：魏玛德国大众消费文化","↔ 相关：德国国家人民党","✗ 对立/冲突：货币信用","✗ 对立/冲突：财政崩溃","↔ 同时期参考：魏玛德国失业保险法"],"relations":[{"text":"← 前因：魏玛德国赔款问题","id":"card3"},{"text":"← 前因：鲁尔占领与德国消极抵抗","id":"card62"},{"text":"→ 后果：魏玛德国伦滕马克","id":"card91"},{"text":"→ 后果：德国赔款《道威斯计划》","id":"card92"},{"text":"↔ 相关：魏玛德国大众消费文化","id":"card87"},{"text":"↔ 相关：德国国家人民党","id":"card26"},{"text":"↔ 同时期参考：魏玛德国失业保险法","id":"card81"}],"source":"history","id":"card90"},{"title":"魏玛德国伦滕马克","level":"B","type":"制度/文本卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1923年11月推出","place":"魏玛共和国","summary":"伦滕马克通过限制发行和资产背书恢复货币信任，帮助结束魏玛恶性通货膨胀。","fields":[{"label":"标题","value":"魏玛德国伦滕马克"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1923年11月推出"},{"label":"地点","value":"魏玛共和国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"伦滕马克通过限制发行和资产背书恢复货币信任，帮助结束魏玛恶性通货膨胀。"},{"label":"制定方/签署方","value":"魏玛政府、德国央行体系和货币改革机构。"},{"label":"主要内容","value":"以伦滕马克替代崩溃的纸马克，并通过发行限制和土地、工业资产背书重建信用。"},{"label":"它试图解决什么问题","value":"1923年恶性通货膨胀使马克失去交易和储值功能，经济生活需要可信的新货币单位。"},{"label":"为什么重要","value":"它为魏玛“相对稳定期”奠定货币基础，也显示货币信用是一种制度和心理秩序。"},{"label":"争议/局限","value":"伦滕马克稳定了币值，但没有解决赔款、财政和外债依赖等深层问题。"},{"label":"造成的影响","value":"通货膨胀迅速受控，随后德国进入依赖美国资本和德国赔款《道威斯计划》的稳定阶段。"},{"label":"出处","value":"Encyclopaedia Britannica，Rentenmark materials；Bundeszentrale für politische Bildung，Weimar currency stabilization materials。"}],"relationItems":["← 前因：魏玛恶性通货膨胀","← 前因：魏玛德国赔款问题","→ 后果：德国赔款《道威斯计划》","→ 后果：魏玛德国相对稳定期","↔ 相关：古斯塔夫·施特雷泽曼","↔ 相关：德国央行","✗ 对立/冲突：纸马克崩溃","✗ 对立/冲突：新货币信用","↔ 同时期参考：希特勒啤酒馆政变"],"relations":[{"text":"← 前因：魏玛恶性通货膨胀","id":"card90"},{"text":"← 前因：魏玛德国赔款问题","id":"card3"},{"text":"→ 后果：德国赔款《道威斯计划》","id":"card92"},{"text":"→ 后果：魏玛德国相对稳定期","id":"card134"},{"text":"↔ 相关：古斯塔夫·施特雷泽曼","id":"card19"},{"text":"↔ 同时期参考：希特勒啤酒馆政变","id":"card18"}],"source":"history","id":"card91"},{"title":"德国赔款《道威斯计划》","level":"B","type":"制度/文本卡","tags":["经济与社会","战争与外交"],"mainTag":"经济与社会","subTag":"战争与外交","timeText":"1924年","place":"德国、法国、英国、美国等相关国家","summary":"德国赔款《道威斯计划》重排德国赔款支付并引入美国贷款，使魏玛进入相对稳定但外债依赖的阶段。","fields":[{"label":"标题","value":"德国赔款《道威斯计划》"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1924年"},{"label":"地点","value":"德国、法国、英国、美国等相关国家"},{"label":"主要国家","value":"德国、美国、法国、英国"},{"label":"一句话概括","value":"德国赔款《道威斯计划》重排德国赔款支付并引入美国贷款，使魏玛进入相对稳定但外债依赖的阶段。"},{"label":"制定方/签署方","value":"由查尔斯·道威斯主持的国际专家委员会提出，协约国和德国接受。"},{"label":"主要内容","value":"调整德国年度赔款支付节奏，稳定德国财政和货币，并通过国际贷款帮助德国经济恢复。"},{"label":"它试图解决什么问题","value":"鲁尔危机和恶性通胀显示原有赔款安排难以执行，欧洲经济稳定需要新的支付机制。"},{"label":"为什么重要","value":"它短期稳定魏玛经济和欧洲外交，但也使德国复苏高度依赖美国资本流入。"},{"label":"争议/局限","value":"计划没有取消赔款，只是重新安排；1929年美国金融危机后其脆弱性暴露。"},{"label":"造成的影响","value":"推动魏玛相对稳定期、洛迦诺外交和德国重新进入国际体系。"},{"label":"出处","value":"Encyclopaedia Britannica，“Dawes Plan”；German History in Documents and Images，Dawes Plan materials。"}],"relationItems":["← 前因：魏玛恶性通货膨胀","← 前因：魏玛德国伦滕马克","→ 后果：欧洲《洛迦诺公约》","→ 后果：德国赔款《杨格计划》","↔ 相关：古斯塔夫·施特雷泽曼","↔ 相关：魏玛德国赔款问题","✗ 对立/冲突：赔款惩罚逻辑","✗ 对立/冲突：国际金融稳定逻辑","↔ 同时期参考：德国包豪斯"],"relations":[{"text":"← 前因：魏玛恶性通货膨胀","id":"card90"},{"text":"← 前因：魏玛德国伦滕马克","id":"card91"},{"text":"→ 后果：欧洲《洛迦诺公约》","id":"card20"},{"text":"→ 后果：德国赔款《杨格计划》","id":"card93"},{"text":"↔ 相关：古斯塔夫·施特雷泽曼","id":"card19"},{"text":"↔ 相关：魏玛德国赔款问题","id":"card3"},{"text":"↔ 同时期参考：德国包豪斯","id":"card30"}],"source":"history","id":"card92"},{"title":"德国赔款《杨格计划》","level":"B","type":"制度/文本卡","tags":["经济与社会","战争与外交"],"mainTag":"经济与社会","subTag":"战争与外交","timeText":"1929年达成","place":"德国及相关债权国","summary":"德国赔款《杨格计划》再次调整德国赔款并延长支付安排，却在大萧条前夕引发右翼反赔款动员。","fields":[{"label":"标题","value":"德国赔款《杨格计划》"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1929年达成"},{"label":"地点","value":"德国及相关债权国"},{"label":"主要国家","value":"德国、美国、法国、英国"},{"label":"一句话概括","value":"德国赔款《杨格计划》再次调整德国赔款并延长支付安排，却在大萧条前夕引发右翼反赔款动员。"},{"label":"制定方/签署方","value":"由欧文·杨主持的国际委员会提出，德国和债权国协商接受。"},{"label":"主要内容","value":"降低并长期化德国赔款总额和年度负担，配合结束莱茵兰占领等安排。"},{"label":"它试图解决什么问题","value":"德国赔款《道威斯计划》只是临时安排，德国和债权国都需要更长期、明确的赔款机制。"},{"label":"为什么重要","value":"它连接魏玛外交正常化、国际金融秩序和国内民族主义反弹，是1929年前后政治激化的关键背景。"},{"label":"争议/局限","value":"右翼认为它延续凡尔赛枷锁；左翼和部分经济界也担心长期债务负担。"},{"label":"造成的影响","value":"引发反德国赔款《杨格计划》运动，帮助纳粹与传统右翼扩大合作和曝光。"},{"label":"出处","value":"Encyclopaedia Britannica，“Young Plan”；German History in Documents and Images，Young Plan materials。"}],"relationItems":["← 前因：德国赔款《道威斯计划》","← 前因：魏玛德国赔款问题","→ 后果：反德国赔款《杨格计划》运动","→ 后果：德国哈尔茨堡阵线","↔ 相关：阿尔弗雷德·胡根贝格","↔ 相关：约瑟夫·戈培尔","✗ 对立/冲突：国际债务妥协","✗ 对立/冲突：民族主义拒付政治","↔ 同时期参考：魏玛德国失业保险法"],"relations":[{"text":"← 前因：德国赔款《道威斯计划》","id":"card92"},{"text":"← 前因：魏玛德国赔款问题","id":"card3"},{"text":"→ 后果：反德国赔款《杨格计划》运动","id":"card51"},{"text":"→ 后果：德国哈尔茨堡阵线","id":"card48"},{"text":"↔ 相关：阿尔弗雷德·胡根贝格","id":"card50"},{"text":"↔ 相关：约瑟夫·戈培尔","id":"card49"},{"text":"↔ 同时期参考：魏玛德国失业保险法","id":"card81"}],"source":"history","id":"card93"},{"title":"法兰克福社会研究所","level":"B","type":"组织/机构卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1923年成立","place":"德国法兰克福","summary":"法兰克福社会研究所孕育了法兰克福学派，把马克思主义、社会学、心理学和文化批判结合起来。","fields":[{"label":"标题","value":"法兰克福社会研究所"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1923年成立"},{"label":"地点","value":"德国法兰克福"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"法兰克福社会研究所孕育了法兰克福学派，把马克思主义、社会学、心理学和文化批判结合起来。"},{"label":"性质/类型","value":"社会科学研究机构。"},{"label":"成立/解散时间","value":"1923年成立；纳粹上台后成员流亡，战后重建。"},{"label":"核心目标/宗旨","value":"研究资本主义社会、阶级关系、文化工业、权威人格和现代性问题。"},{"label":"关键人物（可选）","value":"马克斯·霍克海默、特奥多尔·阿多诺、弗里德里希·波洛克、赫伯特·马尔库塞等。"},{"label":"关键行动/事件","value":"形成批判理论传统，纳粹上台后迁往海外并影响战后思想界。"},{"label":"为什么重要","value":"它使魏玛德国成为现代社会理论的重要发源地，也把经济危机、文化大众化和权威政治联系起来。"},{"label":"争议/局限","value":"理论高度抽象，常被批评与实际工人政治距离较远。"},{"label":"出处","value":"Institute for Social Research Frankfurt，history；Stanford Encyclopedia of Philosophy，Critical Theory materials。"}],"relationItems":["← 前因：德国历史学派经济学","← 前因：德国共产党成立","→ 后果：批判理论","→ 后果：战后西方马克思主义","↔ 相关：《新教伦理与资本主义精神》","↔ 相关：魏玛德国大众消费文化","✗ 对立/冲突：实证社会科学","✗ 对立/冲突：批判社会理论","↔ 同时期参考：德国包豪斯"],"relations":[{"text":"← 前因：德国历史学派经济学","id":"extra734"},{"text":"← 前因：德国共产党成立","id":"extra694"},{"text":"↔ 相关：《新教伦理与资本主义精神》","id":"extra71"},{"text":"↔ 相关：魏玛德国大众消费文化","id":"card87"},{"text":"↔ 同时期参考：德国包豪斯","id":"card30"}],"source":"history","id":"card94"},{"title":"德国自由工会总联盟","level":"B","type":"组织/机构卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1919年成立，1933年被纳粹摧毁","place":"魏玛共和国","summary":"德国自由工会总联盟是魏玛最大工会联合体，代表工人谈判、社会政策和共和国劳工秩序。","fields":[{"label":"标题","value":"德国自由工会总联盟"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1919年成立，1933年被纳粹摧毁"},{"label":"地点","value":"魏玛共和国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国自由工会总联盟是魏玛最大工会联合体，代表工人谈判、社会政策和共和国劳工秩序。"},{"label":"性质/类型","value":"全国性工会联合组织。"},{"label":"成立/解散时间","value":"1919年成立；1933年5月被纳粹取缔和接管。"},{"label":"核心目标/宗旨","value":"维护工人集体谈判、工资、工时、社会保险和劳动权利，并支持共和劳工制度。"},{"label":"关键人物（可选）","value":"卡尔·莱金、特奥多尔·莱帕特等。"},{"label":"关键行动/事件","value":"参与八小时工作制、社会政策讨论、罢工协调和反纳粹防卫。"},{"label":"为什么重要","value":"它是魏玛社会民主主义劳工秩序的核心支柱，说明共和国的基础也存在于工厂和工会办公室。"},{"label":"争议/局限","value":"大萧条后失业削弱工会力量，且工会在面对纳粹夺权时行动受限。"},{"label":"出处","value":"Friedrich Ebert Stiftung，ADGB history；German History in Documents and Images，Weimar labour movement materials。"}],"relationItems":["← 前因：德国自由工会总委员会","← 前因：德国十一月革命","→ 后果：纳粹取缔德国工会","→ 后果：纳粹德国劳工阵线","↔ 相关：魏玛德国失业保险法","↔ 相关：德国社会民主党（SPD）","✗ 对立/冲突：自由工会自治","✗ 对立/冲突：纳粹劳工控制","↔ 同时期参考：德国人权联盟"],"relations":[{"text":"← 前因：德国自由工会总委员会","id":"extra739"},{"text":"← 前因：德国十一月革命","id":"extra666"},{"text":"→ 后果：纳粹取缔德国工会","id":"extra102"},{"text":"→ 后果：纳粹德国劳工阵线","id":"extra103"},{"text":"↔ 相关：魏玛德国失业保险法","id":"card81"},{"text":"↔ 相关：德国社会民主党（SPD）","id":"extra628"},{"text":"↔ 同时期参考：德国人权联盟","id":"card89"}],"source":"history","id":"card95"},{"title":"魏玛第218条堕胎争议","level":"C","type":"概念/思潮卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1919年—1933年","place":"魏玛共和国","summary":"魏玛第218条堕胎争议围绕女性身体、贫困、医疗和刑法展开，是性改革与社会政策交叉点。","fields":[{"label":"标题","value":"魏玛第218条堕胎争议"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1919年—1933年"},{"label":"地点","value":"魏玛共和国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"魏玛第218条堕胎争议围绕女性身体、贫困、医疗和刑法展开，是性改革与社会政策交叉点。"},{"label":"核心主张/思路","value":"支持改革者认为堕胎刑罚加重贫困女性风险，反对者则以宗教、道德和人口政策维护刑法禁令。"},{"label":"提出者/代表人物（可选）","value":"妇女运动、医生、性改革者、左翼政党和教会保守派均参与争论。"},{"label":"它从何而来","value":"德国刑法第218条、战后贫困、住房拥挤、避孕知识传播和女性就业变化。"},{"label":"典型表现","value":"公开演讲、医生审判、性咨询、左翼剧场和废除或放宽刑罚的政治倡议。"},{"label":"为什么重要","value":"它把魏玛现代性落到女性身体和阶级不平等层面，不能只理解为夜生活或艺术自由。"},{"label":"争议/局限","value":"争论高度政治化，纳粹上台后女性身体被重新纳入种族生育政策。"},{"label":"出处","value":"German History in Documents and Images，Paragraph 218 and Weimar sexuality materials；Bundeszentrale für politische Bildung，abortion law history materials。"}],"relationItems":["← 前因：德国刑法典第175条","← 前因：魏玛德国性改革运动","→ 后果：纳粹家庭政策","→ 后果：纳粹母亲十字勋章","↔ 相关：魏玛“新女性”","↔ 相关：马格努斯·赫希菲尔德性科学研究所","✗ 对立/冲突：女性身体自主","✗ 对立/冲突：刑法与人口政治","↔ 同时期参考：魏玛《全国青少年福利法》"],"relations":[{"text":"← 前因：德国刑法典第175条","id":"extra721"},{"text":"← 前因：魏玛德国性改革运动","id":"card85"},{"text":"→ 后果：纳粹家庭政策","id":"extra117"},{"text":"→ 后果：纳粹母亲十字勋章","id":"extra131"},{"text":"↔ 相关：魏玛“新女性”","id":"card32"},{"text":"↔ 相关：马格努斯·赫希菲尔德性科学研究所","id":"card72"},{"text":"↔ 同时期参考：魏玛《全国青少年福利法》","id":"card73"}],"source":"history","id":"card96"},{"title":"德国卡特尔条例","level":"C","type":"制度/文本卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1923年","place":"魏玛共和国","summary":"德国卡特尔条例试图监管企业卡特尔，反映魏玛国家面对高度组织化资本主义的治理难题。","fields":[{"label":"标题","value":"德国卡特尔条例"},{"label":"分级","value":"C"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1923年"},{"label":"地点","value":"魏玛共和国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国卡特尔条例试图监管企业卡特尔，反映魏玛国家面对高度组织化资本主义的治理难题。"},{"label":"制定方/签署方","value":"魏玛共和国政府。"},{"label":"主要内容","value":"要求卡特尔协议接受一定登记、审查或国家干预，试图限制明显损害公共利益的企业联合。"},{"label":"它试图解决什么问题","value":"德国工业中卡特尔和行业联盟普遍存在，价格控制和市场分割可能损害消费者与小企业。"},{"label":"为什么重要","value":"它说明魏玛经济不是纯自由市场，而是国家、银行、企业集团和行业组织交错的“有组织资本主义”。"},{"label":"争议/局限","value":"条例并未根本拆解卡特尔结构，国家监管能力也受经济危机和政治压力限制。"},{"label":"造成的影响","value":"为后续德国反垄断和竞争政策争论提供早期经验。"},{"label":"出处","value":"German History in Documents and Images，cartels and organized capitalism materials；economic history studies of Weimar cartel policy。"}],"relationItems":["← 前因：德意志帝国保护关税政策","← 前因：德国鲁尔工业区","→ 后果：德国IG法本公司成立","↔ 相关：德国化学工业","↔ 相关：德国历史学派经济学","✗ 对立/冲突：企业联合效率","✗ 对立/冲突：市场竞争秩序","↔ 同时期参考：魏玛德国伦滕马克"],"relations":[{"text":"← 前因：德意志帝国保护关税政策","id":"extra630"},{"text":"← 前因：德国鲁尔工业区","id":"extra679"},{"text":"→ 后果：德国IG法本公司成立","id":"card98"},{"text":"↔ 相关：德国化学工业","id":"extra680"},{"text":"↔ 相关：德国历史学派经济学","id":"extra734"},{"text":"↔ 同时期参考：魏玛德国伦滕马克","id":"card91"}],"source":"history","id":"card97"},{"title":"德国IG法本公司成立","level":"B","type":"事件卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1925年","place":"魏玛共和国","summary":"IG法本公司整合德国大型化学企业，成为魏玛和纳粹时期最重要的工业集团之一。","fields":[{"label":"标题","value":"德国IG法本公司成立"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1925年"},{"label":"地点","value":"魏玛共和国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"IG法本公司整合德国大型化学企业，成为魏玛和纳粹时期最重要的工业集团之一。"},{"label":"参与者","value":"巴斯夫、拜耳、赫希斯特等德国化学企业及银行、管理层。"},{"label":"发生了什么","value":"1925年，多家德国大型化学企业合并组成IG法本公司，集中染料、药品、合成材料和化工研发生产能力。它继承德国化学工业的技术优势，并通过资本、专利、研发和国际市场扩张成为全球化工巨头。纳粹时期公司又深度卷入战争经济和强迫劳动。"},{"label":"为什么重要","value":"它把德国科学、资本集中、全球市场和后来纳粹战争经济连接起来，是企业史不能回避的节点。"},{"label":"前因","value":"德国化学工业高度发达但竞争激烈，企业希望通过合并整合专利、市场和资本力量，应对战后经济和国际竞争压力。"},{"label":"后果","value":"IG法本成为魏玛和纳粹时期德国最重要的化工联合体之一，后来深度卷入四年计划、战争经济和战后审判。"},{"label":"出处","value":"Encyclopaedia Britannica，“IG Farben”；United States Holocaust Memorial Museum，IG Farben materials。"}],"relationItems":["← 前因：德国化学工业","← 前因：德国卡特尔条例","→ 后果：纳粹德国四年计划","→ 后果：战后IG法本审判","↔ 相关：合成氨哈伯-博施法","↔ 相关：德国拜耳推出阿司匹林","✗ 对立/冲突：工业创新","✗ 对立/冲突：企业战争责任","↔ 同时期参考：法兰克福社会研究所"],"relations":[{"text":"← 前因：德国化学工业","id":"extra680"},{"text":"← 前因：德国卡特尔条例","id":"card97"},{"text":"→ 后果：纳粹德国四年计划","id":"extra122"},{"text":"↔ 相关：合成氨哈伯-博施法","id":"extra681"},{"text":"↔ 相关：德国拜耳推出阿司匹林","id":"extra738"},{"text":"↔ 同时期参考：法兰克福社会研究所","id":"card94"}],"source":"history","id":"card98"},{"title":"德国大萧条失业危机","level":"A","type":"事件卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1929年—1933年","place":"魏玛共和国","summary":"大萧条使德国失业暴增并压垮魏玛福利财政，是纳粹崛起最关键的社会经济背景之一。","fields":[{"label":"标题","value":"德国大萧条失业危机"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1929年—1933年"},{"label":"地点","value":"魏玛共和国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"大萧条使德国失业暴增并压垮魏玛福利财政，是纳粹崛起最关键的社会经济背景之一。"},{"label":"参与者","value":"失业工人、魏玛政府、雇主、工会、政党、地方救济机构。"},{"label":"发生了什么","value":"1929年后，国际金融危机切断美国资本流入，德国出口、信贷和工业生产急剧收缩。企业裁员、工资下降和财政紧缩相互强化，数百万人失业。失业保险和地方救济体系迅速承压，街头政治、住房困境、家庭压力和极端政党支持同步扩大。"},{"label":"为什么重要","value":"它把魏玛共和国的经济脆弱、福利财政危机和政治极化连成一条主因果链。"},{"label":"前因","value":"德国1920年代复苏依赖美国贷款，道威斯体系脆弱；美国股市崩盘和信贷收缩后，企业倒闭和财政紧缩迅速扩大失业。"},{"label":"后果","value":"失业危机摧毁魏玛社会妥协，1930年后纳粹和共产党得票飙升，总统内阁和反议会政治成为主导趋势。"},{"label":"出处","value":"Encyclopaedia Britannica，Great Depression in Germany materials；German History in Documents and Images，unemployment in Weimar Germany materials。"}],"relationItems":["← 前因：德国赔款《道威斯计划》","← 前因：魏玛德国失业保险法","→ 后果：1930年德国国会选举","→ 后果：魏玛总统内阁","↔ 相关：德国自由工会总联盟","↔ 相关：魏玛德国大众消费文化","✗ 对立/冲突：福利国家承诺","✗ 对立/冲突：经济危机财政现实","↔ 同时期参考：反德国赔款《杨格计划》运动"],"relations":[{"text":"← 前因：德国赔款《道威斯计划》","id":"card92"},{"text":"← 前因：魏玛德国失业保险法","id":"card81"},{"text":"→ 后果：1930年德国国会选举","id":"card44"},{"text":"→ 后果：魏玛总统内阁","id":"card39"},{"text":"↔ 相关：德国自由工会总联盟","id":"card95"},{"text":"↔ 相关：魏玛德国大众消费文化","id":"card87"},{"text":"↔ 同时期参考：反德国赔款《杨格计划》运动","id":"card51"}],"source":"history","id":"card99"},{"title":"魏玛德国鸦片法","level":"B","type":"制度/文本卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1920年后逐步建立，1929年形成更系统的鸦片法框架","place":"魏玛共和国","summary":"魏玛德国鸦片法把吗啡、海洛因、可卡因等纳入国家监管，标志德国毒品管制制度化。","fields":[{"label":"标题","value":"魏玛德国鸦片法"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1920年后逐步建立，1929年形成更系统的鸦片法框架"},{"label":"地点","value":"魏玛共和国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"魏玛德国鸦片法把吗啡、海洛因、可卡因等纳入国家监管，标志德国毒品管制制度化。"},{"label":"制定方/签署方","value":"魏玛共和国政府和国会。"},{"label":"主要内容","value":"依据国际毒品管制义务，对鸦片、吗啡、海洛因、可卡因等药物的生产、销售、进出口和处方使用进行限制。"},{"label":"它试图解决什么问题","value":"战后药物流通、成瘾问题、国际条约义务和城市消费文化使国家需要更明确的毒品监管。"},{"label":"为什么重要","value":"它说明毒品问题从单纯医学或商业问题转为法律、警务、公共卫生和国际秩序共同治理对象。"},{"label":"争议/局限","value":"法律管制并不等于消除成瘾，过度刑事化也可能把公共卫生问题推向地下市场。"},{"label":"造成的影响","value":"为后来德国毒品监管体系提供基础，也影响警方和医学界对成瘾者的分类。"},{"label":"出处","value":"United Nations Office on Drugs and Crime，drug control history；German legal history materials on the Opiumgesetz；League of Nations drug control materials。"}],"relationItems":["← 前因：海牙《国际鸦片公约》","← 前因：拜耳海洛因商品化","→ 后果：纳粹德国药物管制","↔ 相关：魏玛德国性改革运动","↔ 相关：魏玛柏林“戒指会”犯罪网络","✗ 对立/冲突：医疗用药","✗ 对立/冲突：刑法与警务管制","↔ 同时期参考：魏玛第218条堕胎争议"],"relations":[{"text":"← 前因：海牙《国际鸦片公约》","id":"extra744"},{"text":"← 前因：拜耳海洛因商品化","id":"extra743"},{"text":"↔ 相关：魏玛德国性改革运动","id":"card85"},{"text":"↔ 相关：魏玛柏林“戒指会”犯罪网络","id":"card74"},{"text":"↔ 同时期参考：魏玛第218条堕胎争议","id":"card96"}],"source":"history","id":"card100"},{"title":"魏玛德国毒品消费文化","level":"C","type":"概念/思潮卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1920年代—1933年","place":"魏玛共和国大城市，尤其柏林","summary":"魏玛德国毒品消费文化把可卡因、吗啡和夜生活想象联系起来，也引发医学、警务和道德恐慌。","fields":[{"label":"标题","value":"魏玛德国毒品消费文化"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1920年代—1933年"},{"label":"地点","value":"魏玛共和国大城市，尤其柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"魏玛德国毒品消费文化把可卡因、吗啡和夜生活想象联系起来，也引发医学、警务和道德恐慌。"},{"label":"核心主张/思路","value":"毒品在魏玛城市中既是真实的药物滥用问题，也是报刊、文学和保守舆论塑造“堕落大都市”的符号。"},{"label":"提出者/代表人物（可选）","value":"不是单一思想家提出，而是由医生、警方、报刊、夜生活场所和文学影视共同塑造。"},{"label":"它从何而来","value":"战后创伤、退伍军人用药、城市夜生活、药品市场、国际毒品流通和现代大众传媒。"},{"label":"典型表现","value":"关于可卡因、吗啡、夜总会、艺术家、性少数空间和犯罪网络的报道与传闻。"},{"label":"为什么重要","value":"它帮助理解魏玛现代性为什么会被同时描述为自由、刺激、成瘾、犯罪和道德危机。"},{"label":"争议/局限","value":"许多材料带有夸张和道德恐慌色彩，不能把魏玛社会简单等同于普遍吸毒。"},{"label":"出处","value":"German History in Documents and Images，Weimar urban culture materials；historical studies of Weimar narcotics and urban nightlife；UNODC drug control history materials。"}],"relationItems":["← 前因：魏玛德国鸦片法","← 前因：魏玛柏林现代性","→ 后果：纳粹文化控制","↔ 相关：魏玛柏林“戒指会”犯罪网络","↔ 相关：德布林《柏林亚历山大广场》","✗ 对立/冲突：都市自由想象","✗ 对立/冲突：成瘾与道德恐慌","↔ 同时期参考：魏玛德国大众消费文化"],"relations":[{"text":"← 前因：魏玛德国鸦片法","id":"card100"},{"text":"← 前因：魏玛柏林现代性","id":"card33"},{"text":"→ 后果：纳粹文化控制","id":"extra113"},{"text":"↔ 相关：魏玛柏林“戒指会”犯罪网络","id":"card74"},{"text":"↔ 相关：德布林《柏林亚历山大广场》","id":"extra69"},{"text":"✗ 对立/冲突：都市自由想象","id":"card202"},{"text":"↔ 同时期参考：魏玛德国大众消费文化","id":"card87"}],"source":"history","id":"card101"},{"title":"德国革命人民代表委员会","level":"B","type":"组织/机构卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1918年11月10日—1919年2月13日","place":"德国；柏林","summary":"人民代表委员会是十一月革命后的临时政府，在共和国建立、停战执行和国民议会选举之间维持国家运转。","fields":[{"label":"标题","value":"德国革命人民代表委员会"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1918年11月10日—1919年2月13日"},{"label":"地点","value":"德国；柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"人民代表委员会是十一月革命后的临时政府，在共和国建立、停战执行和国民议会选举之间维持国家运转。"},{"label":"性质/类型","value":"革命后的临时中央政府，由多数社民党和独立社民党代表组成。"},{"label":"成立/解散时间","value":"1918年11月10日成立；1919年2月魏玛国民议会选出正式政府后结束。"},{"label":"核心目标/宗旨","value":"结束战争、维持秩序、组织制宪国民议会选举，并在议会共和国与委员会共和国之间控制革命方向。"},{"label":"关键人物（可选）","value":"弗里德里希·艾伯特、菲利普·谢德曼、奥托·兰茨贝格、胡戈·哈泽、威廉·迪特曼、埃米尔·巴特。"},{"label":"关键行动/事件","value":"发布政府纲领，确认若干民主和社会权利，推动1919年1月国民议会选举；同时同军方合作镇压激进左翼。"},{"label":"为什么重要","value":"它是帝制和魏玛共和国之间的过渡政府。魏玛共和国的制度方向、左翼分裂和国家暴力问题，都在这个临时政府时期已经形成。"},{"label":"争议/局限","value":"委员会名义上来自革命，但多数社民党主导下选择尽快召开国民议会，而不是把权力交给工人士兵委员会体系。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Rat der Volksbeauftragten；German History in Documents and Images: The First Council of People’s Representatives；Bundestag historical exhibition on November Revolution。"}],"relationItems":["← 前因：德国十一月革命","← 前因：德国工人士兵委员会","→ 后果：德国魏玛国民议会","→ 后果：德国艾伯特-格勒纳协议","↔ 相关：弗里德里希·艾伯特"],"relations":[{"text":"← 前因：德国十一月革命","id":"extra666"},{"text":"← 前因：德国工人士兵委员会","id":"extra807"},{"text":"→ 后果：德国魏玛国民议会","id":"card10"},{"text":"→ 后果：德国艾伯特-格勒纳协议","id":"card6"},{"text":"↔ 相关：弗里德里希·艾伯特","id":"card103"}],"source":"history","id":"card102"},{"title":"弗里德里希·艾伯特","level":"A","type":"人物卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1871—1925年；1918—1925年主导魏玛共和国早期政治","place":"德国；柏林、魏玛","summary":"艾伯特是魏玛共和国第一任总统，用议会共和国和秩序优先路线稳定国家，也加深左翼裂痕。","fields":[{"label":"标题","value":"弗里德里希·艾伯特"},{"label":"分级","value":"A"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1871—1925年；1918—1925年主导魏玛共和国早期政治"},{"label":"地点","value":"德国；柏林、魏玛"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"艾伯特是魏玛共和国第一任总统，用议会共和国和秩序优先路线稳定国家，也加深左翼裂痕。"},{"label":"生卒年/活跃年代","value":"1871年2月4日—1925年2月28日；1913年起任SPD主席之一，1919—1925年任德国总统。"},{"label":"身份/职务","value":"德国社会民主党政治家、人民代表委员会核心人物、魏玛共和国第一任总统。"},{"label":"关键贡献/作为","value":"在1918年革命中接掌政府，推动国民议会选举和魏玛宪法；同军方达成艾伯特-格勒纳协议；多次使用第48条应对危机。"},{"label":"核心主张/立场","value":"主张通过议会民主和社会民主党领导的渐进改革建立共和国，优先维护国家秩序，反对苏维埃式革命。"},{"label":"为什么重要","value":"他是魏玛共和国能否活下来的关键人物。没有艾伯特，共和国早期可能更快陷入内战；但他的秩序路线也让旧军方和右翼暴力保留了空间。"},{"label":"争议/评价","value":"支持者认为他保住了民主共和国，批评者认为他过度依赖旧军队和自由军团，造成左翼分裂和共和国合法性伤口。"},{"label":"关联事件（可选）","value":"德国革命人民代表委员会；德国艾伯特-格勒纳协议；魏玛共和国成立；德国斯巴达克起义；魏玛德国卡普政变。"},{"label":"出处","value":"Encyclopaedia Britannica: Friedrich Ebert；Friedrich-Ebert-Stiftung: Friedrich Ebert and the Weimar Republic；Deutsches Historisches Museum/LeMO: Friedrich Ebert。"}],"relationItems":["← 前因：德国社会民主党（SPD）","→ 后果：魏玛共和国成立","→ 后果：魏玛宪法","↔ 相关：德国革命人民代表委员会","↔ 相关：保罗·冯·兴登堡"],"relations":[{"text":"← 前因：德国社会民主党（SPD）","id":"extra628"},{"text":"→ 后果：魏玛共和国成立","id":"card7"},{"text":"→ 后果：魏玛宪法","id":"card11"},{"text":"↔ 相关：德国革命人民代表委员会","id":"card102"},{"text":"↔ 相关：保罗·冯·兴登堡","id":"card37"}],"source":"history","id":"card103"},{"title":"德国全国工人士兵委员会代表大会","level":"B","type":"事件卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1918年12月16日—21日","place":"德国柏林，普鲁士众议院大楼","summary":"全国工人士兵委员会代表大会决定支持国民议会选举，使德国革命转向议会共和国而非委员会共和国。","fields":[{"label":"标题","value":"德国全国工人士兵委员会代表大会"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1918年12月16日—21日"},{"label":"地点","value":"德国柏林，普鲁士众议院大楼"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"全国工人士兵委员会代表大会决定支持国民议会选举，使德国革命转向议会共和国而非委员会共和国。"},{"label":"参与者","value":"德国各地工人和士兵委员会代表、SPD、USPD、革命工长、人民代表委员会。"},{"label":"发生了什么","value":"1918年12月，德国各地工人士兵委员会代表在柏林召开全国代表大会，讨论国家权力归属、军队改革和是否召开国民议会。大会多数支持尽快举行制宪国民议会选举，并选出中央委员会监督临时政府。这一决定削弱了把委员会制度作为国家权力基础的可能。"},{"label":"为什么重要","value":"它是德国革命道路的关键分岔点。德国没有走向苏维埃式委员会共和国，而是把合法性重心转向普选产生的国民议会。"},{"label":"前因","value":"十一月革命后，工人士兵委员会实际掌握许多地方权力，但人民代表委员会和多数社民党希望用全国选举稳定国家秩序。"},{"label":"后果","value":"1919年1月国民议会选举获得革命合法性支持，激进左翼对议会道路更加不满，斯巴达克起义和左翼分裂随之加深。"},{"label":"出处","value":"Bundesarchiv: Reichsrätekongress 1918；Deutsches Historisches Museum/LeMO: Reichsrätekongress 1918；German History in Documents and Images: The Spread of the 1918 Revolution。"}],"relationItems":["← 前因：德国工人士兵委员会","← 前因：德国革命人民代表委员会","→ 后果：德国魏玛国民议会","→ 后果：德国斯巴达克起义","↔ 相关：弗里德里希·艾伯特"],"relations":[{"text":"← 前因：德国工人士兵委员会","id":"extra807"},{"text":"← 前因：德国革命人民代表委员会","id":"card102"},{"text":"→ 后果：德国魏玛国民议会","id":"card10"},{"text":"→ 后果：德国斯巴达克起义","id":"card8"},{"text":"↔ 相关：弗里德里希·艾伯特","id":"card103"}],"source":"history","id":"card104"},{"title":"罗莎·卢森堡","level":"B","type":"人物卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1871—1919年；一战和德国革命时期影响突出","place":"波兰、德国；柏林","summary":"罗莎·卢森堡是革命马克思主义理论家和斯巴达克派领袖，其遇害成为魏玛左翼创伤的核心记忆。","fields":[{"label":"标题","value":"罗莎·卢森堡"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1871—1919年；一战和德国革命时期影响突出"},{"label":"地点","value":"波兰、德国；柏林"},{"label":"主要国家","value":"德国、波兰、俄罗斯帝国"},{"label":"一句话概括","value":"罗莎·卢森堡是革命马克思主义理论家和斯巴达克派领袖，其遇害成为魏玛左翼创伤的核心记忆。"},{"label":"生卒年/活跃年代","value":"1871年3月5日—1919年1月15日。"},{"label":"身份/职务","value":"马克思主义理论家、社会民主党左翼、斯巴达克派和德国共产党创始人物之一。"},{"label":"关键贡献/作为","value":"批判修正主义，反对一战，参与创建斯巴达克同盟和德国共产党；在十一月革命后主张社会主义革命和群众民主。"},{"label":"核心主张/立场","value":"强调群众罢工、国际主义和社会主义民主，反对帝国主义战争，也批判布尔什维克式限制民主的倾向。"},{"label":"为什么重要","value":"她让魏玛左翼问题不只是组织斗争，也成为民主、革命和暴力边界的思想问题。她的遇害加深了社民党和共产党之间的历史裂痕。"},{"label":"争议/评价","value":"她支持革命方向，但对1919年1月起义本身并非简单冒进派。后世常把她神圣化或妖魔化，都容易忽视其思想复杂性。"},{"label":"关联事件（可选）","value":"德国斯巴达克起义；德国共产党成立；魏玛德国自由军团。"},{"label":"出处","value":"Encyclopaedia Britannica: Rosa Luxemburg；Encyclopaedia Britannica: Spartacus League；Deutsches Historisches Museum/LeMO: Rosa Luxemburg。"}],"relationItems":["← 前因：德国独立社会民主党","→ 后果：德国斯巴达克起义","→ 后果：魏玛左翼分裂","↔ 相关：卡尔·李卜克内西","↔ 相关：德国共产党成立"],"relations":[{"text":"← 前因：德国独立社会民主党","id":"extra693"},{"text":"→ 后果：德国斯巴达克起义","id":"card8"},{"text":"↔ 相关：卡尔·李卜克内西","id":"card106"},{"text":"↔ 相关：德国共产党成立","id":"extra694"}],"source":"history","id":"card105"},{"title":"卡尔·李卜克内西","level":"B","type":"人物卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1871—1919年；一战反战和德国革命时期影响突出","place":"德国；柏林","summary":"李卜克内西是一战中最著名的德国反战社会主义者之一，也是斯巴达克派和德国共产党早期象征人物。","fields":[{"label":"标题","value":"卡尔·李卜克内西"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1871—1919年；一战反战和德国革命时期影响突出"},{"label":"地点","value":"德国；柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"李卜克内西是一战中最著名的德国反战社会主义者之一，也是斯巴达克派和德国共产党早期象征人物。"},{"label":"生卒年/活跃年代","value":"1871年8月13日—1919年1月15日。"},{"label":"身份/职务","value":"社会民主党左翼政治家、国会议员、反战活动家、斯巴达克派和德国共产党创始人物之一。"},{"label":"关键贡献/作为","value":"一战中反对战争贷款并公开反战；参与斯巴达克同盟和德国共产党；1918年11月9日宣布“自由社会主义共和国”。"},{"label":"核心主张/立场","value":"反对帝国主义战争，主张无产阶级革命和社会主义共和国，支持工人士兵委员会式政治动员。"},{"label":"为什么重要","value":"他把反战社会主义从议会少数意见变成群众政治象征。其遇害让魏玛共和国从一开始就背负镇压革命左翼的血债记忆。"},{"label":"争议/评价","value":"他具有强烈动员能力，但政治策略常被认为比卢森堡更冒进；其象征意义往往大于实际组织控制力。"},{"label":"关联事件（可选）","value":"德国1914年战争贷款表决；德国斯巴达克起义；德国共产党成立。"},{"label":"出处","value":"Encyclopaedia Britannica: Karl Liebknecht；Encyclopaedia Britannica: Spartacus League；German History in Documents and Images: Spartacist materials。"}],"relationItems":["← 前因：德国1914年战争贷款表决","→ 后果：德国斯巴达克起义","↔ 相关：罗莎·卢森堡","↔ 相关：德国共产党成立","↔ 相关：德国“背后一刀”传说"],"relations":[{"text":"← 前因：德国1914年战争贷款表决","id":"extra691"},{"text":"→ 后果：德国斯巴达克起义","id":"card8"},{"text":"↔ 相关：罗莎·卢森堡","id":"card105"},{"text":"↔ 相关：德国共产党成立","id":"extra694"},{"text":"↔ 相关：德国“背后一刀”传说","id":"extra623"}],"source":"history","id":"card106"},{"title":"古斯塔夫·诺斯克","level":"C","type":"人物卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1868—1946年；1918—1920年影响突出","place":"德国；基尔、柏林","summary":"诺斯克是魏玛早期社民党强硬派，依靠军队和自由军团镇压左翼起义，成为共和国秩序暴力的象征。","fields":[{"label":"标题","value":"古斯塔夫·诺斯克"},{"label":"分级","value":"C"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1868—1946年；1918—1920年影响突出"},{"label":"地点","value":"德国；基尔、柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"诺斯克是魏玛早期社民党强硬派，依靠军队和自由军团镇压左翼起义，成为共和国秩序暴力的象征。"},{"label":"生卒年/活跃年代","value":"1868年7月9日—1946年11月30日；1919—1920年任国防部长。"},{"label":"身份/职务","value":"德国社会民主党政治家、人民代表委员会成员、魏玛共和国首任国防部长。"},{"label":"关键贡献/作为","value":"1918年到基尔处理水兵起义；1919年负责调动军队和自由军团镇压斯巴达克起义及其他左翼运动。"},{"label":"核心主张/立场","value":"认为共和国必须先恢复秩序并保住国家机器，即使需要同旧军官和自由军团合作。"},{"label":"为什么重要","value":"他集中体现魏玛共和国早期的根本悖论：民主政府为了生存，依赖许多并不忠于民主的武装力量。"},{"label":"争议/评价","value":"支持者认为他阻止了内战和布尔什维克式革命，批评者认为他纵容右翼准军事暴力，破坏共和国同工人阶级的关系。"},{"label":"关联事件（可选）","value":"德国基尔水兵起义；德国斯巴达克起义；魏玛德国自由军团；魏玛德国卡普政变。"},{"label":"出处","value":"Encyclopaedia Britannica: Gustav Noske；Deutsches Historisches Museum/LeMO: Gustav Noske；Encyclopaedia Britannica: German Revolution 1918-1919。"}],"relationItems":["← 前因：德国革命人民代表委员会","→ 后果：德国斯巴达克起义","→ 后果：魏玛德国自由军团","↔ 相关：弗里德里希·艾伯特","↔ 相关：魏玛德国国防军"],"relations":[{"text":"← 前因：德国革命人民代表委员会","id":"card102"},{"text":"→ 后果：德国斯巴达克起义","id":"card8"},{"text":"→ 后果：魏玛德国自由军团","id":"card9"},{"text":"↔ 相关：弗里德里希·艾伯特","id":"card103"},{"text":"↔ 相关：魏玛德国国防军","id":"card109"}],"source":"history","id":"card107"},{"title":"德国巴伐利亚苏维埃共和国","level":"B","type":"事件卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1919年4月—5月","place":"德国巴伐利亚；慕尼黑","summary":"巴伐利亚苏维埃共和国是德国革命中短暂的委员会共和国实验，被国防军和自由军团血腥镇压。","fields":[{"label":"标题","value":"德国巴伐利亚苏维埃共和国"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1919年4月—5月"},{"label":"地点","value":"德国巴伐利亚；慕尼黑"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"巴伐利亚苏维埃共和国是德国革命中短暂的委员会共和国实验，被国防军和自由军团血腥镇压。"},{"label":"参与者","value":"巴伐利亚左翼革命者、USPD、共产党人、无政府主义者、巴伐利亚政府、国防军、自由军团。"},{"label":"发生了什么","value":"1918年11月巴伐利亚王朝垮台后，库尔特·艾斯纳建立巴伐利亚自由邦。1919年2月艾斯纳遇刺后，慕尼黑局势激化。4月，左翼力量宣布建立巴伐利亚苏维埃共和国，试图以委员会制度和社会主义政策重组地方政权。5月，政府军和自由军团攻入慕尼黑，苏维埃共和国被镇压，随后发生严厉报复。"},{"label":"为什么重要","value":"它让魏玛早期“革命恐惧”在南德具体化，也帮助解释为什么巴伐利亚后来成为右翼、反共和国和纳粹活动的重要庇护地。"},{"label":"前因","value":"德国十一月革命瓦解王朝秩序，巴伐利亚政治在艾斯纳遇刺后失去稳定中心，俄国革命和委员会运动又提供了激进左翼想象。"},{"label":"后果","value":"镇压造成左翼创伤和右翼复仇政治，巴伐利亚转向更保守和反柏林的政治环境，为后来的希特勒啤酒馆政变提供地方背景。"},{"label":"出处","value":"Encyclopaedia Britannica: Bavaria, History；Deutsches Historisches Museum/LeMO: Jahreschronik 1919；bavarikon: Formation of the Councils。"}],"relationItems":["← 前因：德国十一月革命","← 前因：德国工人士兵委员会","→ 后果：希特勒啤酒馆政变","↔ 相关：魏玛德国自由军团","↔ 同时期参考：德国斯巴达克起义"],"relations":[{"text":"← 前因：德国十一月革命","id":"extra666"},{"text":"← 前因：德国工人士兵委员会","id":"extra807"},{"text":"→ 后果：希特勒啤酒馆政变","id":"card18"},{"text":"↔ 相关：魏玛德国自由军团","id":"card9"},{"text":"↔ 同时期参考：德国斯巴达克起义","id":"card8"}],"source":"history","id":"card108"},{"title":"魏玛德国国防军","level":"B","type":"组织/机构卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1919—1935年","place":"德国","summary":"魏玛德国国防军是在凡尔赛限制下建立的十万人职业军，名义服从共和国，实际保持高度自主。","fields":[{"label":"标题","value":"魏玛德国国防军"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1919—1935年"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"魏玛德国国防军是在凡尔赛限制下建立的十万人职业军，名义服从共和国，实际保持高度自主。"},{"label":"性质/类型","value":"魏玛共和国武装力量，包含陆军和海军，受凡尔赛条约严格限制。"},{"label":"成立/解散时间","value":"1919年临时国防军逐步形成；1921年后按凡尔赛限制稳定为十万人陆军和小规模海军；1935年被纳粹改组为国防军。"},{"label":"核心目标/宗旨","value":"维护国家安全和内部秩序，同时在凡尔赛限制下保存专业军官团、训练体系和未来扩军潜力。"},{"label":"关键人物（可选）","value":"汉斯·冯·塞克特、古斯塔夫·诺斯克、威廉·格勒纳等。"},{"label":"关键行动/事件","value":"在卡普政变、共和国危机和秘密再军备问题中保持特殊地位；通过部队办公室等方式保存总参谋部传统。"},{"label":"为什么重要","value":"国防军是魏玛共和国最重要的“国家中之国家”之一。它既能保护共和国免于部分极端力量冲击，也长期拒绝真正民主化。"},{"label":"争议/局限","value":"国防军自称非政治化，但这种非政治化常意味着远离议会控制、保留保守军官文化，并对共和国忠诚有限。"},{"label":"出处","value":"Encyclopaedia Britannica: Hans von Seeckt；Deutsches Historisches Museum/LeMO: Wehrmacht/Reichswehr background；Britannica: Treaty of Versailles military limitations。"}],"relationItems":["← 前因：《凡尔赛和约》","← 前因：德国艾伯特-格勒纳协议","→ 后果：纳粹德国再武装","↔ 相关：汉斯·冯·塞克特","↔ 相关：魏玛德国卡普政变"],"relations":[{"text":"← 前因：《凡尔赛和约》","id":"card59"},{"text":"← 前因：德国艾伯特-格勒纳协议","id":"card6"},{"text":"→ 后果：纳粹德国再武装","id":"extra119"},{"text":"↔ 相关：汉斯·冯·塞克特","id":"card110"},{"text":"↔ 相关：魏玛德国卡普政变","id":"card13"}],"source":"history","id":"card109"},{"title":"汉斯·冯·塞克特","level":"B","type":"人物卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1866—1936年；1920—1926年主导魏玛国防军","place":"德国；柏林","summary":"塞克特是魏玛国防军的核心塑造者，把凡尔赛限制下的小军队改造成保守、专业、等待扩军的骨干。","fields":[{"label":"标题","value":"汉斯·冯·塞克特"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1866—1936年；1920—1926年主导魏玛国防军"},{"label":"地点","value":"德国；柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"塞克特是魏玛国防军的核心塑造者，把凡尔赛限制下的小军队改造成保守、专业、等待扩军的骨干。"},{"label":"生卒年/活跃年代","value":"1866年4月22日—1936年12月27日；1920—1926年任陆军统帅。"},{"label":"身份/职务","value":"德国将领、魏玛国防军陆军统帅。"},{"label":"关键贡献/作为","value":"在凡尔赛限制下重建十万人职业军，强调专业训练、军官团连续性和远离党派政治；同时保存未来扩军和现代战术能力。"},{"label":"核心主张/立场","value":"主张军队高于党派、保持职业独立，并把国防军视为国家连续性的核心，而不是议会民主的附属机构。"},{"label":"为什么重要","value":"他影响了魏玛军队的制度性格。后来的纳粹德国再武装和国防军专业传统，部分建立在塞克特时期保存和改造的基础上。"},{"label":"争议/评价","value":"他被称为国防军重建者，但其“非政治军队”实际上削弱了共和国对军队的民主控制。"},{"label":"关联事件（可选）","value":"魏玛德国国防军；魏玛德国卡普政变；《拉帕洛条约》。"},{"label":"出处","value":"Encyclopaedia Britannica: Hans von Seeckt；1914-1918 Online: Seeckt, Hans von；German History in Documents and Images: Reichswehr materials。"}],"relationItems":["← 前因：《凡尔赛和约》","→ 后果：魏玛德国国防军","→ 后果：纳粹德国再武装","↔ 相关：保罗·冯·兴登堡","↔ 相关：德国艾伯特-格勒纳协议"],"relations":[{"text":"← 前因：《凡尔赛和约》","id":"card59"},{"text":"→ 后果：魏玛德国国防军","id":"card109"},{"text":"→ 后果：纳粹德国再武装","id":"extra119"},{"text":"↔ 相关：保罗·冯·兴登堡","id":"card37"},{"text":"↔ 相关：德国艾伯特-格勒纳协议","id":"card6"}],"source":"history","id":"card110"},{"title":"魏玛普鲁士自由邦","level":"B","type":"组织/机构卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1918—1932年作为民主州政府尤其重要；形式上延续至纳粹时期","place":"德国；普鲁士各省、柏林","summary":"普鲁士自由邦是魏玛共和国最大邦，长期由共和派联盟治理，被视为共和国最重要的民主堡垒。","fields":[{"label":"标题","value":"魏玛普鲁士自由邦"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1918—1932年作为民主州政府尤其重要；形式上延续至纳粹时期"},{"label":"地点","value":"德国；普鲁士各省、柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"普鲁士自由邦是魏玛共和国最大邦，长期由共和派联盟治理，被视为共和国最重要的民主堡垒。"},{"label":"性质/类型","value":"魏玛共和国成员邦，前普鲁士王国转型而成的共和邦。"},{"label":"成立/解散时间","value":"1918年革命后由普鲁士王国转为自由邦；1932年普鲁士政变后实际失去自治，1947年被盟国正式废除普鲁士。"},{"label":"核心目标/宗旨","value":"在联邦共和国框架内治理德国最大邦，管理警察、教育、行政和经济事务。"},{"label":"关键人物（可选）","value":"奥托·布劳恩、卡尔·塞韦林等社会民主党政治家。"},{"label":"关键行动/事件","value":"长期维持社民党、中央党和民主党等共和派合作；改革普鲁士警察和行政；1932年被巴本中央政府夺权。"},{"label":"为什么重要","value":"魏玛不是只有中央政府。普鲁士占德国人口和地域很大比例，普鲁士自由邦的稳定支撑了共和国，1932年普鲁士政变则是共和国防线崩塌的重要节点。"},{"label":"争议/局限","value":"普鲁士虽较稳定，但仍继承庞大官僚和地区差异；民主改革没有完全清除旧精英影响。"},{"label":"出处","value":"Encyclopaedia Britannica: Prussia；Deutsches Historisches Museum/LeMO: Otto Braun；Britannica: Weimar Republic, The end of the Weimar Republic。"}],"relationItems":["← 前因：德国十一月革命","→ 后果：1932年普鲁士政变","↔ 相关：魏玛共和国成立","↔ 相关：德国铁阵线","↔ 相关：弗朗茨·冯·巴本"],"relations":[{"text":"← 前因：德国十一月革命","id":"extra666"},{"text":"→ 后果：1932年普鲁士政变","id":"card41"},{"text":"↔ 相关：魏玛共和国成立","id":"card7"},{"text":"↔ 相关：德国铁阵线","id":"card54"},{"text":"↔ 相关：弗朗茨·冯·巴本","id":"card40"}],"source":"history","id":"card111"},{"title":"魏玛共和国比例代表制","level":"C","type":"制度/文本卡","tags":["政治与制度","无"],"mainTag":"政治与制度","subTag":"无","timeText":"1919—1933年","place":"德国","summary":"魏玛比例代表制让选票较公平转化为席位，却也使国会高度碎片化，加剧组阁困难。","fields":[{"label":"标题","value":"魏玛共和国比例代表制"},{"label":"分级","value":"C"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"无"},{"label":"时间","value":"1919—1933年"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"魏玛比例代表制让选票较公平转化为席位，却也使国会高度碎片化，加剧组阁困难。"},{"label":"制定方/签署方","value":"魏玛制宪者和共和国选举制度立法者。"},{"label":"主要内容","value":"帝国议会选举采用比例代表制，政党按照得票比例获得席位，降低小党进入国会的门槛。"},{"label":"它试图解决什么问题","value":"新共和国希望用更民主、更平等的选举制度替代帝国时期不均衡和邦国差异明显的政治代表结构。"},{"label":"为什么重要","value":"它是魏玛民主的制度基础之一，也解释为什么共和国政府常常依赖多党联合。"},{"label":"争议/局限","value":"比例代表制本身不是魏玛崩溃的唯一原因，但在社会极化和反共和国政党壮大时，它使议会更难形成稳定多数。"},{"label":"造成的影响","value":"魏玛联合政府频繁更替，总统和紧急法令在后期更容易取代议会协商。"},{"label":"出处","value":"Encyclopaedia Britannica: Weimar Republic；German History in Documents and Images: The Weimar Constitution；Dieter Nohlen electoral system research references。"}],"relationItems":["← 前因：魏玛宪法","→ 后果：魏玛联合政府","→ 后果：魏玛总统内阁","↔ 相关：1930年德国国会选举","↔ 相关：德国1912年国会选举"],"relations":[{"text":"← 前因：魏玛宪法","id":"card11"},{"text":"→ 后果：魏玛联合政府","id":"card23"},{"text":"→ 后果：魏玛总统内阁","id":"card39"},{"text":"↔ 相关：1930年德国国会选举","id":"card44"},{"text":"↔ 相关：德国1912年国会选举","id":"extra789"}],"source":"history","id":"card112"},{"title":"德国埃尔茨贝格财政改革","level":"B","type":"制度/文本卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1919—1920年","place":"德国","summary":"埃尔茨贝格财政改革把税收权力集中到中央，奠定魏玛财政国家基础，也让改革者成为右翼仇恨目标。","fields":[{"label":"标题","value":"德国埃尔茨贝格财政改革"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1919—1920年"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"埃尔茨贝格财政改革把税收权力集中到中央，奠定魏玛财政国家基础，也让改革者成为右翼仇恨目标。"},{"label":"制定方/签署方","value":"魏玛政府、财政部长马蒂亚斯·埃尔茨贝格、魏玛国民议会和帝国议会。"},{"label":"主要内容","value":"改革重组中央和邦国财政关系，扩大帝国直接税和统一税收能力，建立更集中化的财政行政，以应对战争债务、赔款和社会支出压力。"},{"label":"它试图解决什么问题","value":"帝国时期中央财政长期依赖间接税和邦国缴款，战后共和国面对巨额债务和赔款，必须建立更有力的现代税收国家。"},{"label":"为什么重要","value":"它是魏玛共和国最重要的制度建设之一。共和国不只是换了宪法，也在财政能力上从联邦分散走向中央集权。"},{"label":"争议/局限","value":"改革增强国家能力，却触动邦国、财产阶层和右翼民族主义者利益；财政集中无法单独解决通胀和赔款危机。"},{"label":"造成的影响","value":"魏玛中央财政能力提高，埃尔茨贝格也被右翼塑造成“停战、赔款和税收压迫”的象征敌人。"},{"label":"出处","value":"German History in Documents and Images: Matthias Erzberger on the Need for Tax Reform；Universität Münster: Erzbergersche Finanzreform；Gabler Wirtschaftslexikon: Erzbergersche Finanzreform。"}],"relationItems":["← 前因：德国一战债务融资政策","← 前因：《凡尔赛和约》","→ 后果：马蒂亚斯·埃尔茨贝格遇刺","↔ 相关：魏玛德国赔款问题","↔ 相关：魏玛恶性通货膨胀"],"relations":[{"text":"← 前因：德国一战债务融资政策","id":"extra699"},{"text":"← 前因：《凡尔赛和约》","id":"card59"},{"text":"→ 后果：马蒂亚斯·埃尔茨贝格遇刺","id":"card118"},{"text":"↔ 相关：魏玛德国赔款问题","id":"card3"},{"text":"↔ 相关：魏玛恶性通货膨胀","id":"card90"}],"source":"history","id":"card113"},{"title":"马蒂亚斯·埃尔茨贝格","level":"B","type":"人物卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1875—1921年；一战末期和魏玛早期影响突出","place":"德国；柏林、贡比涅、巴登","summary":"埃尔茨贝格签署一战停战协定并推动财政改革，成为右翼把战败和共和国联系起来攻击的核心对象。","fields":[{"label":"标题","value":"马蒂亚斯·埃尔茨贝格"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1875—1921年；一战末期和魏玛早期影响突出"},{"label":"地点","value":"德国；柏林、贡比涅、巴登"},{"label":"主要国家","value":"德国、法国"},{"label":"一句话概括","value":"埃尔茨贝格签署一战停战协定并推动财政改革，成为右翼把战败和共和国联系起来攻击的核心对象。"},{"label":"生卒年/活跃年代","value":"1875年9月20日—1921年8月26日。"},{"label":"身份/职务","value":"德国中央党政治家、停战代表团成员、魏玛财政部长。"},{"label":"关键贡献/作为","value":"1917年推动和平决议；1918年代表德国签署停战协定；1919—1920年任财政部长，推动埃尔茨贝格财政改革。"},{"label":"核心主张/立场","value":"从战时支持转向寻求和平和履约现实主义，认为共和国需要通过财政重建和外交履约争取生存空间。"},{"label":"为什么重要","value":"他是魏玛“履约政策”和共和国责任政治的早期代表。右翼仇恨他，正说明共和国政治家被迫承担军方和帝国留下的失败遗产。"},{"label":"争议/评价","value":"右翼把他称为“十一月罪人”，但他签署停战是在军事失败已成事实后承担政治任务。"},{"label":"关联事件（可选）","value":"一战停战；德国帝国议会和平决议；德国埃尔茨贝格财政改革；马蒂亚斯·埃尔茨贝格遇刺。"},{"label":"出处","value":"Encyclopaedia Britannica: Matthias Erzberger；1914-1918 Online: Erzberger, Matthias；German History in Documents and Images: Matthias Erzberger on Tax Reform。"}],"relationItems":["← 前因：德国帝国议会和平决议","→ 后果：德国埃尔茨贝格财政改革","→ 后果：马蒂亚斯·埃尔茨贝格遇刺","↔ 相关：德国“背后一刀”传说","↔ 相关：德国中央党"],"relations":[{"text":"← 前因：德国帝国议会和平决议","id":"extra800"},{"text":"→ 后果：德国埃尔茨贝格财政改革","id":"card113"},{"text":"→ 后果：马蒂亚斯·埃尔茨贝格遇刺","id":"card118"},{"text":"↔ 相关：德国“背后一刀”传说","id":"extra623"},{"text":"↔ 相关：德国中央党","id":"extra673"}],"source":"history","id":"card114"},{"title":"德国1920年企业委员会法","level":"C","type":"制度/文本卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1920年2月4日","place":"德国","summary":"1920年企业委员会法把工厂层面的工人代表制度化，是魏玛劳资关系和协商民主的重要早期尝试。","fields":[{"label":"标题","value":"德国1920年企业委员会法"},{"label":"分级","value":"C"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1920年2月4日"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1920年企业委员会法把工厂层面的工人代表制度化，是魏玛劳资关系和协商民主的重要早期尝试。"},{"label":"制定方/签署方","value":"魏玛国民议会和魏玛政府。"},{"label":"主要内容","value":"法律规定一定规模以上企业设立企业委员会，让工人代表在劳动规则、福利、纠纷和部分企业事务中拥有咨询和参与权。"},{"label":"它试图解决什么问题","value":"十一月革命后的工人委员会要求社会化和经济民主，政府需要把革命性的委员会诉求转化为可控的劳动法制度。"},{"label":"为什么重要","value":"它是德国共同决定传统的早期制度来源之一，也显示魏玛共和国试图把阶级冲突纳入法律和协商框架。"},{"label":"争议/局限","value":"激进工人认为它削弱真正的委员会权力，雇主则担心工厂管理权受限；法律提供的是有限参与，而不是工人控制企业。"},{"label":"造成的影响","value":"企业委员会进入德国劳动制度传统，后来西德企业宪制和共同决定制度也能追溯到魏玛经验。"},{"label":"出处","value":"1000 Schlüsseldokumente: Betriebsrätegesetz；Encyclopaedia Britannica: Weimar Republic；Max Planck Institute for Legal History: Works Councils in the Weimar Republic。"}],"relationItems":["← 前因：德国工人士兵委员会","← 前因：德国《施廷内斯—莱吉恩协议》","→ 后果：德国自由工会总联盟","↔ 相关：魏玛共和国成立","↔ 相关：德国1920年国会选举"],"relations":[{"text":"← 前因：德国工人士兵委员会","id":"extra807"},{"text":"← 前因：德国《施廷内斯—莱吉恩协议》","id":"card58"},{"text":"→ 后果：德国自由工会总联盟","id":"card95"},{"text":"↔ 相关：魏玛共和国成立","id":"card7"},{"text":"↔ 相关：德国1920年国会选举","id":"card116"}],"source":"history","id":"card115"},{"title":"德国1920年国会选举","level":"B","type":"事件卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1920年6月6日","place":"德国","summary":"1920年国会选举中魏玛联盟大幅失势，显示共和国刚建立就迅速失去中间多数。","fields":[{"label":"标题","value":"德国1920年国会选举"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1920年6月6日"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1920年国会选举中魏玛联盟大幅失势，显示共和国刚建立就迅速失去中间多数。"},{"label":"参与者","value":"德国选民、SPD、中央党、德国民主党、德国人民党、德国国家人民党、USPD、KPD等。"},{"label":"发生了什么","value":"1920年6月，魏玛共和国举行第一届正式帝国议会选举。与1919年国民议会选举相比，支持共和国的魏玛联盟政党席位明显减少，独立社民党、人民党和国家人民党等左右两翼及保守力量扩大影响。新国会更碎片化，组阁更困难。"},{"label":"为什么重要","value":"它说明魏玛共和国的民主合法性从一开始就不稳。制宪时期的共和多数没有延续为长期稳定的执政多数。"},{"label":"前因","value":"凡尔赛和约、经济困难、卡普政变、鲁尔红军起义和社会秩序焦虑共同削弱选民对制宪时期执政党信任。"},{"label":"后果","value":"魏玛联合政府更加脆弱，议会政治需要更复杂的中间和右派合作，反共和国力量在国会中的影响扩大。"},{"label":"出处","value":"Encyclopaedia Britannica: Weimar Republic, Years of crisis 1920-23；German History in Documents and Images: Reichstag election results；Bundeswahlleiter historical election data。"}],"relationItems":["← 前因：魏玛德国卡普政变","← 前因：《凡尔赛和约》","→ 后果：魏玛联合政府","→ 后果：德国人民党","↔ 相关：魏玛共和国比例代表制"],"relations":[{"text":"← 前因：魏玛德国卡普政变","id":"card13"},{"text":"← 前因：《凡尔赛和约》","id":"card59"},{"text":"→ 后果：魏玛联合政府","id":"card23"},{"text":"→ 后果：德国人民党","id":"card25"},{"text":"↔ 相关：魏玛共和国比例代表制","id":"card112"}],"source":"history","id":"card116"},{"title":"1921年伦敦最后通牒","level":"B","type":"制度/文本卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1921年5月5日—12日","place":"伦敦、柏林；德国赔款外交","summary":"伦敦最后通牒要求德国接受1320亿金马克赔款计划，否则面临鲁尔占领威胁。","fields":[{"label":"标题","value":"1921年伦敦最后通牒"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1921年5月5日—12日"},{"label":"地点","value":"伦敦、柏林；德国赔款外交"},{"label":"主要国家","value":"德国、英国、法国、比利时、意大利、日本"},{"label":"一句话概括","value":"伦敦最后通牒要求德国接受1320亿金马克赔款计划，否则面临鲁尔占领威胁。"},{"label":"制定方/签署方","value":"协约国最高委员会和赔款委员会；德国政府被迫接受。"},{"label":"主要内容","value":"协约国向德国提出赔款支付计划，总额定为1320亿金马克，并要求德国履行裁军、审判战犯等义务；若德国拒绝，协约国威胁占领鲁尔。"},{"label":"它试图解决什么问题","value":"凡尔赛和约没有立即确定最终赔款总额，战胜国需要把赔款义务具体化，同时迫使德国承认履行机制。"},{"label":"为什么重要","value":"它把抽象的赔款问题变成具体数字和期限，直接加剧魏玛政府的财政、外交和国内政治压力。"},{"label":"争议/局限","value":"德国视其为强制性羞辱，法国则担心没有强制措施德国不会支付。赔款总额和支付能力问题长期争论不休。"},{"label":"造成的影响","value":"德国接受最后通牒后，“履约政策”成为国内政治攻击焦点；赔款压力和货币危机继续发展，最终导向鲁尔占领和恶性通胀。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Londoner Ultimatum；Bundesarchiv: Londoner Ultimatum；Encyclopaedia Britannica: Reparations。"}],"relationItems":["← 前因：魏玛德国赔款问题","← 前因：《凡尔赛和约》战争责任条款","→ 后果：魏玛德国赔款履约政策","→ 后果：鲁尔占领与德国消极抵抗","↔ 相关：马蒂亚斯·埃尔茨贝格"],"relations":[{"text":"← 前因：魏玛德国赔款问题","id":"card3"},{"text":"← 前因：《凡尔赛和约》战争责任条款","id":"card2"},{"text":"→ 后果：魏玛德国赔款履约政策","id":"card60"},{"text":"→ 后果：鲁尔占领与德国消极抵抗","id":"card62"},{"text":"↔ 相关：马蒂亚斯·埃尔茨贝格","id":"card114"}],"source":"history","id":"card117"},{"title":"马蒂亚斯·埃尔茨贝格遇刺","level":"C","type":"事件卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1921年8月26日","place":"德国巴登，黑森林巴特格里斯巴赫附近","summary":"埃尔茨贝格被右翼恐怖分子刺杀，显示魏玛共和国早期政治暴力集中攻击“履约”和共和国代表人物。","fields":[{"label":"标题","value":"马蒂亚斯·埃尔茨贝格遇刺"},{"label":"分级","value":"C"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1921年8月26日"},{"label":"地点","value":"德国巴登，黑森林巴特格里斯巴赫附近"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"埃尔茨贝格被右翼恐怖分子刺杀，显示魏玛共和国早期政治暴力集中攻击“履约”和共和国代表人物。"},{"label":"参与者","value":"马蒂亚斯·埃尔茨贝格、右翼极端分子、组织“领事”相关网络、魏玛共和国政府。"},{"label":"发生了什么","value":"1921年8月26日，前财政部长、中央党政治家埃尔茨贝格在黑森林休养期间被两名右翼极端分子枪杀。刺杀者来自反共和国、民族主义和前军人网络。埃尔茨贝格因签署停战协定、支持履约和推动税制改革，长期遭受右翼宣传攻击。"},{"label":"为什么重要","value":"它是魏玛右翼恐怖的代表事件之一。政治暗杀把“十一月罪人”叙事从宣传变成致命暴力。"},{"label":"前因","value":"停战、凡尔赛和约、赔款履约和财政改革使埃尔茨贝格成为右翼仇恨对象，背后一刀传说又把共和国政治家塑造成卖国者。"},{"label":"后果","value":"共和国震动并加强反右翼恐怖讨论，但司法和警务系统对右翼暴力的处理仍显软弱，拉特瑙遇刺很快再次暴露问题。"},{"label":"出处","value":"Bundesarchiv: Mord an Matthias Erzberger；Encyclopaedia Britannica: Organisation Konsul；Encyclopaedia Britannica: Matthias Erzberger。"}],"relationItems":["← 前因：马蒂亚斯·埃尔茨贝格","← 前因：德国“背后一刀”传说","→ 后果：瓦尔特·拉特瑙遇刺","↔ 相关：德国组织“领事”","↔ 相关：德国保卫共和国法"],"relations":[{"text":"← 前因：马蒂亚斯·埃尔茨贝格","id":"card114"},{"text":"← 前因：德国“背后一刀”传说","id":"extra623"},{"text":"→ 后果：瓦尔特·拉特瑙遇刺","id":"card27"},{"text":"↔ 相关：德国组织“领事”","id":"card28"},{"text":"↔ 相关：德国保卫共和国法","id":"card29"}],"source":"history","id":"card118"},{"title":"约瑟夫·维尔特","level":"B","type":"人物卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1879—1956年；1921—1922年任德国总理","place":"德国；柏林、弗赖堡","summary":"维尔特是魏玛履约政策的重要总理，试图通过执行赔款证明凡尔赛要求不可承受。","fields":[{"label":"标题","value":"约瑟夫·维尔特"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1879—1956年；1921—1922年任德国总理"},{"label":"地点","value":"德国；柏林、弗赖堡"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"维尔特是魏玛履约政策的重要总理，试图通过执行赔款证明凡尔赛要求不可承受。"},{"label":"生卒年/活跃年代","value":"1879年9月6日—1956年1月3日；1921—1922年任魏玛共和国总理。"},{"label":"身份/职务","value":"德国中央党政治家、魏玛共和国总理。"},{"label":"关键贡献/作为","value":"在伦敦最后通牒后组阁，推行履约政策；拉帕洛条约和拉特瑙遇刺都发生在其政府时期；拉特瑙遇刺后推动《保卫共和国法》。"},{"label":"核心主张/立场","value":"主张共和国必须在极端压力下争取外交回旋空间，通过履行或尝试履行赔款来证明要求过高。"},{"label":"为什么重要","value":"他体现魏玛早期现实主义外交的困境：不履约会被制裁，履约又会被国内右翼骂成卖国。"},{"label":"争议/评价","value":"右翼把履约政策视为屈服，支持者则认为这是弱国在战败秩序下争取修约的策略。维尔特政府最终因履约政策和政治暴力压力而难以维持。"},{"label":"关联事件（可选）","value":"1921年伦敦最后通牒；魏玛德国赔款履约政策；《拉帕洛条约》；德国保卫共和国法。"},{"label":"出处","value":"Encyclopaedia Britannica: Joseph Wirth；Deutsches Historisches Museum/LeMO: Joseph Wirth；Akten der Reichskanzlei: Erfüllungspolitik。"}],"relationItems":["← 前因：1921年伦敦最后通牒","→ 后果：魏玛德国赔款履约政策","→ 后果：德国保卫共和国法","↔ 相关：瓦尔特·拉特瑙","↔ 相关：德国中央党"],"relations":[{"text":"← 前因：1921年伦敦最后通牒","id":"card117"},{"text":"→ 后果：魏玛德国赔款履约政策","id":"card60"},{"text":"→ 后果：德国保卫共和国法","id":"card29"},{"text":"↔ 相关：瓦尔特·拉特瑙","id":"card120"},{"text":"↔ 相关：德国中央党","id":"extra673"}],"source":"history","id":"card119"},{"title":"瓦尔特·拉特瑙","level":"B","type":"人物卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1867—1922年；一战和魏玛早期影响突出","place":"德国；柏林、拉帕洛","summary":"拉特瑙从战争经济组织者转为魏玛外长，推动履约政策和拉帕洛条约，最终被右翼恐怖分子刺杀。","fields":[{"label":"标题","value":"瓦尔特·拉特瑙"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1867—1922年；一战和魏玛早期影响突出"},{"label":"地点","value":"德国；柏林、拉帕洛"},{"label":"主要国家","value":"德国、苏俄"},{"label":"一句话概括","value":"拉特瑙从战争经济组织者转为魏玛外长，推动履约政策和拉帕洛条约，最终被右翼恐怖分子刺杀。"},{"label":"生卒年/活跃年代","value":"1867年9月29日—1922年6月24日。"},{"label":"身份/职务","value":"德国犹太裔工业家、作家、AEG领导人、战时经济组织者、魏玛重建部长和外交部长。"},{"label":"关键贡献/作为","value":"一战中推动战争原料部；魏玛时期参与履约政策，1922年任外交部长，并同苏俄签署《拉帕洛条约》。"},{"label":"核心主张/立场","value":"在战败秩序下寻求现实主义外交和经济重建，试图同时与西方协约国和苏俄打开空间。"},{"label":"为什么重要","value":"他把帝国战争经济、魏玛赔款外交和德国国际孤立问题连接起来。其遇刺也暴露共和国面对反犹主义和右翼恐怖的脆弱。"},{"label":"争议/评价","value":"右翼把他作为“犹太共和国”和履约政策的象征敌人；事实上他试图在极不利条件下扩大德国外交选择。"},{"label":"关联事件（可选）","value":"德国战争原料部；魏玛德国赔款履约政策；《拉帕洛条约》；瓦尔特·拉特瑙遇刺。"},{"label":"出处","value":"Encyclopaedia Britannica: Walther Rathenau；Deutsches Historisches Museum/LeMO: Walther Rathenau；Bundesarchiv: Walther Rathenau wird Außenminister。"}],"relationItems":["← 前因：德国战争原料部","→ 后果：德苏《拉帕洛条约》","→ 后果：瓦尔特·拉特瑙遇刺","↔ 相关：约瑟夫·维尔特","↔ 相关：德国组织“领事”"],"relations":[{"text":"← 前因：德国战争原料部","id":"extra795"},{"text":"→ 后果：德苏《拉帕洛条约》","id":"card17"},{"text":"→ 后果：瓦尔特·拉特瑙遇刺","id":"card27"},{"text":"↔ 相关：约瑟夫·维尔特","id":"card119"},{"text":"↔ 相关：德国组织“领事”","id":"card28"}],"source":"history","id":"card120"},{"title":"魏玛威廉·库诺内阁","level":"B","type":"组织/机构卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1922年11月22日—1923年8月12日","place":"德国；柏林、鲁尔区","summary":"库诺内阁在鲁尔占领中推行消极抵抗，短期凝聚民族抗议，却把德国财政和货币推向崩溃。","fields":[{"label":"标题","value":"魏玛威廉·库诺内阁"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1922年11月22日—1923年8月12日"},{"label":"地点","value":"德国；柏林、鲁尔区"},{"label":"主要国家","value":"德国、法国、比利时"},{"label":"一句话概括","value":"库诺内阁在鲁尔占领中推行消极抵抗，短期凝聚民族抗议，却把德国财政和货币推向崩溃。"},{"label":"性质/类型","value":"魏玛共和国中央政府，常被视为无党派或资产阶级专家内阁。"},{"label":"成立/解散时间","value":"1922年11月成立；1923年8月在鲁尔危机和通胀失控中倒台。"},{"label":"核心目标/宗旨","value":"处理赔款僵局、争取外交援助，并在法国和比利时占领鲁尔后组织全国性消极抵抗。"},{"label":"关键人物（可选）","value":"威廉·库诺，来自汉堡-美洲航运公司背景。"},{"label":"关键行动/事件","value":"呼吁鲁尔工人和企业不合作，由政府补贴停工者和受影响企业；向美国寻求调停未果。"},{"label":"为什么重要","value":"库诺内阁是1923年危机的政府载体。它证明民族抵抗可以短期获得支持，但若无财政基础，会迅速转化为恶性通胀和政府崩溃。"},{"label":"争议/局限","value":"消极抵抗在政治上有象征意义，却经济代价极高；库诺缺乏稳定议会基础，也缺乏结束危机的方案。"},{"label":"出处","value":"Encyclopaedia Britannica: Wilhelm Cuno；Deutsches Historisches Museum/LeMO: Wilhelm Cuno；Encyclopaedia Britannica: Ruhr occupation。"}],"relationItems":["← 前因：鲁尔占领与德国消极抵抗","← 前因：魏玛德国赔款履约政策","→ 后果：魏玛恶性通货膨胀","→ 后果：古斯塔夫·施特雷泽曼内阁","↔ 相关：魏玛德国伦滕马克"],"relations":[{"text":"← 前因：鲁尔占领与德国消极抵抗","id":"card62"},{"text":"← 前因：魏玛德国赔款履约政策","id":"card60"},{"text":"→ 后果：魏玛恶性通货膨胀","id":"card90"},{"text":"→ 后果：古斯塔夫·施特雷泽曼内阁","id":"card122"},{"text":"↔ 相关：魏玛德国伦滕马克","id":"card91"}],"source":"history","id":"card121"},{"title":"古斯塔夫·施特雷泽曼内阁","level":"B","type":"组织/机构卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1923年8月13日—11月30日","place":"德国；柏林、鲁尔区、萨克森、巴伐利亚","summary":"施特雷泽曼短暂组阁期间结束鲁尔消极抵抗、推动货币稳定，并同时面对左右两翼和地方叛乱。","fields":[{"label":"标题","value":"古斯塔夫·施特雷泽曼内阁"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1923年8月13日—11月30日"},{"label":"地点","value":"德国；柏林、鲁尔区、萨克森、巴伐利亚"},{"label":"主要国家","value":"德国、法国、比利时"},{"label":"一句话概括","value":"施特雷泽曼短暂组阁期间结束鲁尔消极抵抗、推动货币稳定，并同时面对左右两翼和地方叛乱。"},{"label":"性质/类型","value":"魏玛共和国危机内阁，大联合政府。"},{"label":"成立/解散时间","value":"1923年8月13日成立；同年11月30日结束，施特雷泽曼此后继续任外交部长。"},{"label":"核心目标/宗旨","value":"结束鲁尔危机、稳定货币、维护国家统一，并阻止共产党起义、巴伐利亚右翼挑战和莱茵分离主义。"},{"label":"关键人物（可选）","value":"古斯塔夫·施特雷泽曼、财政和货币改革官员、国防军领导层。"},{"label":"关键行动/事件","value":"宣布结束消极抵抗；推动伦滕马克改革；处理“德意志十月”、萨克森帝国执行和希特勒啤酒馆政变。"},{"label":"为什么重要","value":"这是魏玛共和国从1923年濒临崩溃转向相对稳定的关键政府。它的成就和代价都很大：稳定国家，同时强化紧急权力和军队政治作用。"},{"label":"争议/局限","value":"结束消极抵抗被右翼斥为屈服，对萨克森和巴伐利亚采取不同强度的措施也引发政治争议。"},{"label":"出处","value":"Encyclopaedia Britannica: Gustav Stresemann；Deutsches Historisches Museum/LeMO: Chronik 1923；Bundesarchiv: Sturz des Kabinetts Stresemann。"}],"relationItems":["← 前因：魏玛威廉·库诺内阁","← 前因：魏玛恶性通货膨胀","→ 后果：魏玛德国伦滕马克","→ 后果：德国赔款《道威斯计划》","↔ 相关：古斯塔夫·施特雷泽曼"],"relations":[{"text":"← 前因：魏玛威廉·库诺内阁","id":"card121"},{"text":"← 前因：魏玛恶性通货膨胀","id":"card90"},{"text":"→ 后果：魏玛德国伦滕马克","id":"card91"},{"text":"→ 后果：德国赔款《道威斯计划》","id":"card92"},{"text":"↔ 相关：古斯塔夫·施特雷泽曼","id":"card19"}],"source":"history","id":"card122"},{"title":"魏玛黑色国防军","level":"C","type":"组织/机构卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"约1921—1923年","place":"德国；尤其是东部边境和军事训练网络","summary":"黑色国防军是魏玛时期绕开凡尔赛军备限制的秘密准军事网络，显示国防军与右翼地下力量的灰色关系。","fields":[{"label":"标题","value":"魏玛黑色国防军"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"约1921—1923年"},{"label":"地点","value":"德国；尤其是东部边境和军事训练网络"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"黑色国防军是魏玛时期绕开凡尔赛军备限制的秘密准军事网络，显示国防军与右翼地下力量的灰色关系。"},{"label":"性质/类型","value":"非法或半非法准军事组织、秘密军事预备网络。"},{"label":"成立/解散时间","value":"约1921年后形成；1923年库斯特林政变后被进一步清理。"},{"label":"核心目标/宗旨","value":"在凡尔赛限制下保存额外军事人力和武器，作为国防军之外的秘密后备力量。"},{"label":"关键人物（可选）","value":"汉斯·冯·塞克特体系下的部分军官；布鲁诺·布赫鲁克等右翼军人。"},{"label":"关键行动/事件","value":"以劳动队等名义组织训练和武器储备，部分成员卷入费默谋杀和库斯特林政变。"},{"label":"为什么重要","value":"它说明魏玛共和国的军队问题并不只是十万人限制，而是国家军队、右翼准军事组织和秘密再武装之间的复杂勾连。"},{"label":"争议/局限","value":"黑色国防军规模和控制关系在史料中有争议；不能把所有国防军成员都等同于非法右翼武装，但军方默许和利用这些网络确实削弱共和国法治。"},{"label":"出处","value":"Bundesarchiv: Akten der Reichskanzlei, Schwarze Reichswehr materials；Die Weimarer Republik: Reichswehr/Militär；Encyclopaedia Britannica: Hans von Seeckt。"}],"relationItems":["← 前因：魏玛德国国防军","← 前因：《凡尔赛和约》","→ 后果：魏玛费默谋杀","↔ 相关：汉斯·冯·塞克特","↔ 相关：魏玛德国自由军团"],"relations":[{"text":"← 前因：魏玛德国国防军","id":"card109"},{"text":"← 前因：《凡尔赛和约》","id":"card59"},{"text":"→ 后果：魏玛费默谋杀","id":"card124"},{"text":"↔ 相关：汉斯·冯·塞克特","id":"card110"},{"text":"↔ 相关：魏玛德国自由军团","id":"card9"}],"source":"history","id":"card123"},{"title":"魏玛费默谋杀","level":"C","type":"概念/思潮卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1919—1920年代中期，1923年前后尤为突出","place":"德国；巴伐利亚、东普鲁士、勃兰登堡等地","summary":"费默谋杀指右翼地下组织以“惩罚叛徒”为名实施的秘密杀人，暴露魏玛早期准军事暴力和司法软弱。","fields":[{"label":"标题","value":"魏玛费默谋杀"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1919—1920年代中期，1923年前后尤为突出"},{"label":"地点","value":"德国；巴伐利亚、东普鲁士、勃兰登堡等地"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"费默谋杀指右翼地下组织以“惩罚叛徒”为名实施的秘密杀人，暴露魏玛早期准军事暴力和司法软弱。"},{"label":"核心主张/思路","value":"右翼秘密组织把泄密者、被怀疑告发武器藏匿者、共和国支持者或内部“不忠者”视为可私刑处决的叛徒。"},{"label":"提出者/代表人物（可选）","value":"不是单一人物提出的概念，常与自由军团、黑色国防军和组织“领事”等右翼网络相关。"},{"label":"它从何而来","value":"战败、解除武装、凡尔赛限制和反共和国仇恨使准军事组织形成地下纪律；国家司法又常对右翼暴力处理宽纵。"},{"label":"典型表现","value":"秘密审判、绑架、枪杀或掩埋尸体；案件常以“民族荣誉”和“反叛徒”语言正当化。"},{"label":"为什么重要","value":"它让魏玛政治暴力从公开街斗延伸到地下恐怖。共和国面对的不是普通犯罪，而是带有政治忠诚、军事纪律和反民主意识形态的私刑系统。"},{"label":"争议/局限","value":"费默谋杀数量和组织归属因案件隐蔽而难以精确统计，不能把所有政治谋杀都归入同一组织模式。"},{"label":"出处","value":"Bundesarchiv: Weimar political violence materials；Encyclopaedia Britannica: Weimar Republic, Years of crisis；History.com: Political assassinations in Weimar Germany。"}],"relationItems":["← 前因：魏玛黑色国防军","← 前因：德国组织“领事”","→ 后果：德国保卫共和国法","↔ 相关：马蒂亚斯·埃尔茨贝格遇刺","↔ 相关：瓦尔特·拉特瑙遇刺"],"relations":[{"text":"← 前因：魏玛黑色国防军","id":"card123"},{"text":"← 前因：德国组织“领事”","id":"card28"},{"text":"→ 后果：德国保卫共和国法","id":"card29"},{"text":"↔ 相关：马蒂亚斯·埃尔茨贝格遇刺","id":"card118"},{"text":"↔ 相关：瓦尔特·拉特瑙遇刺","id":"card27"}],"source":"history","id":"card124"},{"title":"德国1923年“德意志十月”","level":"B","type":"事件卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1923年10月","place":"德国；萨克森、图林根、汉堡等地","summary":"1923年“德意志十月”是共产党试图借危机推动革命的失败尝试，最终只在汉堡爆发孤立起义。","fields":[{"label":"标题","value":"德国1923年“德意志十月”"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1923年10月"},{"label":"地点","value":"德国；萨克森、图林根、汉堡等地"},{"label":"主要国家","value":"德国、苏联"},{"label":"一句话概括","value":"1923年“德意志十月”是共产党试图借危机推动革命的失败尝试，最终只在汉堡爆发孤立起义。"},{"label":"参与者","value":"德国共产党、共产国际、萨克森和图林根的SPD-KPD联合政府、魏玛中央政府、国防军。"},{"label":"发生了什么","value":"1923年德国同时遭遇鲁尔危机、恶性通胀、地方分离和右翼挑战，共产国际和德国共产党判断德国可能进入革命时机。KPD进入萨克森和图林根州政府，试图通过“无产阶级百人队”等方式准备武装动员。但在关键会议和工人支持不足的情况下，中央起义计划被取消，只有汉堡地方组织发动起义。魏玛政府随后出兵萨克森，左翼政府被清除。"},{"label":"为什么重要","value":"它是魏玛左翼革命道路的重大失败。此后KPD内部路线斗争加剧，德国共产党逐渐更深地受共产国际和苏联路线影响。"},{"label":"前因","value":"鲁尔占领、通胀和政府危机使德国社会极度动荡，俄国革命经验又让共产国际相信德国可能成为欧洲革命突破口。"},{"label":"后果","value":"革命计划失败削弱KPD领导层，汉堡起义成为孤立流血事件；魏玛政府通过国防军干预萨克森，显示中央会对左翼州政府采取强硬手段。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Deutscher Oktober 1923；Encyclopaedia Britannica: Weimar Republic, The Ruhr and inflation；Weimarer Republik Portal: October 1923。"}],"relationItems":["← 前因：魏玛恶性通货膨胀","← 前因：鲁尔占领与德国消极抵抗","→ 后果：德国汉堡起义","→ 后果：魏玛政府出兵萨克森","↔ 相关：恩斯特·台尔曼"],"relations":[{"text":"← 前因：魏玛恶性通货膨胀","id":"card90"},{"text":"← 前因：鲁尔占领与德国消极抵抗","id":"card62"},{"text":"→ 后果：德国汉堡起义","id":"card126"},{"text":"→ 后果：魏玛政府出兵萨克森","id":"card127"},{"text":"↔ 相关：恩斯特·台尔曼","id":"card52"}],"source":"history","id":"card125"},{"title":"德国汉堡起义","level":"C","type":"事件卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1923年10月23日—25日","place":"德国汉堡","summary":"1923年汉堡起义是“德意志十月”中唯一真正爆发的共产党武装行动，很快被镇压。","fields":[{"label":"标题","value":"德国汉堡起义"},{"label":"分级","value":"C"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1923年10月23日—25日"},{"label":"地点","value":"德国汉堡"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1923年汉堡起义是“德意志十月”中唯一真正爆发的共产党武装行动，很快被镇压。"},{"label":"参与者","value":"德国共产党汉堡组织、恩斯特·台尔曼相关地方力量、汉堡警察、魏玛政府。"},{"label":"发生了什么","value":"1923年10月23日，汉堡共产党人袭击多个警察局并设置街垒，试图以地方起义带动更广泛革命。但全国起义计划已被取消，汉堡行动缺乏外部响应。经过数日冲突后，警察和政府力量镇压起义，参与者被捕，事件造成多人死亡。"},{"label":"为什么重要","value":"它显示德国共产党对1923年革命形势判断严重失误。汉堡起义后来在KPD内部记忆中被塑造成英雄传统，也帮助台尔曼提升党内地位。"},{"label":"前因","value":"“德意志十月”计划使KPD部分地方组织准备武装行动，汉堡的贫困、粮食骚乱和工人激进化又提供了行动基础。"},{"label":"后果","value":"起义孤立失败后，KPD面临路线清算，台尔曼等地方领导人的革命资历反而被后来的党内政治利用。"},{"label":"出处","value":"Encyclopaedia Britannica: Hamburg uprising；Deutsches Historisches Museum: Der Hamburger Aufstand Oktober 1923；Hamburg History Book: 1923 Staat und Gesellschaft in Aufruhr。"}],"relationItems":["← 前因：德国1923年“德意志十月”","→ 后果：恩斯特·台尔曼","↔ 相关：德国共产党成立","↔ 相关：共产国际“社会法西斯”论","↔ 同时期参考：希特勒啤酒馆政变"],"relations":[{"text":"← 前因：德国1923年“德意志十月”","id":"card125"},{"text":"→ 后果：恩斯特·台尔曼","id":"card52"},{"text":"↔ 相关：德国共产党成立","id":"extra694"},{"text":"↔ 相关：共产国际“社会法西斯”论","id":"card53"},{"text":"↔ 同时期参考：希特勒啤酒馆政变","id":"card18"}],"source":"history","id":"card126"},{"title":"魏玛政府出兵萨克森","level":"C","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1923年10月","place":"德国萨克森；德累斯顿等地","summary":"1923年魏玛中央政府以“帝国执行”名义出兵萨克森，解除SPD-KPD州政府中的共产党力量。","fields":[{"label":"标题","value":"魏玛政府出兵萨克森"},{"label":"分级","value":"C"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1923年10月"},{"label":"地点","value":"德国萨克森；德累斯顿等地"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1923年魏玛中央政府以“帝国执行”名义出兵萨克森，解除SPD-KPD州政府中的共产党力量。"},{"label":"参与者","value":"施特雷泽曼政府、艾伯特总统、国防军、萨克森州政府、SPD、KPD。"},{"label":"发生了什么","value":"1923年10月，KPD进入萨克森和图林根州政府，被中央政府和国防军视为共产党革命的跳板。魏玛中央政府依据宪法紧急权力和“帝国执行”机制派国防军进入萨克森，迫使州政府中共产党部长下台，并重组地方政治秩序。"},{"label":"为什么重要","value":"它显示魏玛中央政府在1923年会动用军事力量打击左翼州政府，同时对巴伐利亚右翼挑战采取更谨慎态度，这种不对称处理引发长期争议。"},{"label":"前因","value":"德意志十月计划和KPD进入萨克森政府使中央担心地方政府成为武装起义基地，恶性通胀和鲁尔危机又使国家统一处于危险状态。"},{"label":"后果","value":"KPD革命计划失败，萨克森左翼政府被削弱；SPD内部对中央政府和国防军使用方式产生不满。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Deutscher Oktober 1923；Bundestag Wissenschaftliche Dienste: Reichsexekution in der Weimarer Republik；Encyclopaedia Britannica: Weimar Republic, The Ruhr and inflation。"}],"relationItems":["← 前因：德国1923年“德意志十月”","→ 后果：德国汉堡起义","↔ 相关：魏玛宪法第48条","↔ 相关：古斯塔夫·施特雷泽曼内阁","↔ 同时期参考：魏玛巴伐利亚右翼“秩序细胞”"],"relations":[{"text":"← 前因：德国1923年“德意志十月”","id":"card125"},{"text":"→ 后果：德国汉堡起义","id":"card126"},{"text":"↔ 相关：魏玛宪法第48条","id":"card12"},{"text":"↔ 相关：古斯塔夫·施特雷泽曼内阁","id":"card122"},{"text":"↔ 同时期参考：魏玛巴伐利亚右翼“秩序细胞”","id":"card129"}],"source":"history","id":"card127"},{"title":"魏玛莱茵分离主义危机","level":"C","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1923年10—11月","place":"德国莱茵兰；亚琛、科布伦茨等地","summary":"1923年莱茵分离主义者短暂宣布“莱茵共和国”，但缺乏群众基础，很快失败。","fields":[{"label":"标题","value":"魏玛莱茵分离主义危机"},{"label":"分级","value":"C"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1923年10—11月"},{"label":"地点","value":"德国莱茵兰；亚琛、科布伦茨等地"},{"label":"主要国家","value":"德国、法国、比利时"},{"label":"一句话概括","value":"1923年莱茵分离主义者短暂宣布“莱茵共和国”，但缺乏群众基础，很快失败。"},{"label":"参与者","value":"莱茵分离主义组织、法国和比利时占领当局、当地德国居民、魏玛政府。"},{"label":"发生了什么","value":"鲁尔占领和恶性通胀期间，莱茵地区出现试图脱离或高度自治的分离主义活动。1923年10月，分离主义者在亚琛等地宣布“莱茵共和国”，并寻求占领当局支持。但运动缺乏广泛民众支持，在地方抵抗、政治混乱和国际压力下很快瓦解。"},{"label":"为什么重要","value":"它说明1923年危机威胁的不只是中央政府更替，而是德国国家完整性。法国对莱茵问题的态度也加深德国民族主义反感。"},{"label":"前因","value":"鲁尔占领削弱中央权威，莱茵地区长期处在盟军占领和法国安全政策影响下，恶性通胀又让地方政治更不稳定。"},{"label":"后果","value":"分离主义失败后，德国民族主义者把莱茵危机作为反法和反凡尔赛宣传材料；斯特雷泽曼政府更重视通过西方外交解决莱茵和安全问题。"},{"label":"出处","value":"Encyclopaedia Britannica: Rhineland；Deutsches Historisches Museum/LeMO: Chronik 1923；Sage Journals: Stresemann, the Ruhr Crisis, and Rhenish Separatism。"}],"relationItems":["← 前因：鲁尔占领与德国消极抵抗","← 前因：魏玛恶性通货膨胀","→ 后果：欧洲《洛迦诺公约》","↔ 相关：古斯塔夫·施特雷泽曼内阁","↔ 同时期参考：德国1923年“德意志十月”"],"relations":[{"text":"← 前因：鲁尔占领与德国消极抵抗","id":"card62"},{"text":"← 前因：魏玛恶性通货膨胀","id":"card90"},{"text":"→ 后果：欧洲《洛迦诺公约》","id":"card20"},{"text":"↔ 相关：古斯塔夫·施特雷泽曼内阁","id":"card122"},{"text":"↔ 同时期参考：德国1923年“德意志十月”","id":"card125"}],"source":"history","id":"card128"},{"title":"魏玛巴伐利亚右翼“秩序细胞”","level":"B","type":"概念/思潮卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1920—1923年尤为突出","place":"德国巴伐利亚；慕尼黑","summary":"巴伐利亚“秩序细胞”把自己塑造成反马克思主义、反柏林共和国的右翼堡垒，为纳粹早期成长提供环境。","fields":[{"label":"标题","value":"魏玛巴伐利亚右翼“秩序细胞”"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1920—1923年尤为突出"},{"label":"地点","value":"德国巴伐利亚；慕尼黑"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"巴伐利亚“秩序细胞”把自己塑造成反马克思主义、反柏林共和国的右翼堡垒，为纳粹早期成长提供环境。"},{"label":"核心主张/思路","value":"巴伐利亚被描绘为维护传统、天主教保守秩序和民族主义的堡垒，对抗被右翼称为“马克思主义”和“犹太化”的柏林共和国。"},{"label":"提出者/代表人物（可选）","value":"古斯塔夫·冯·卡尔及巴伐利亚保守、民族主义和右翼准军事网络。"},{"label":"它从何而来","value":"巴伐利亚苏维埃共和国被镇压后，反左翼恐惧和地方主义强化；柏林中央政府的共和民主路线被巴伐利亚右翼视为软弱和非法。"},{"label":"典型表现","value":"容忍或庇护右翼组织；拒绝严格执行共和国保护法；在1923年任命卡尔为总国家专员并同中央政府公开冲突。"},{"label":"为什么重要","value":"它解释纳粹为什么能在慕尼黑获得早期发展空间。纳粹不是在政治真空中成长，而是在巴伐利亚右翼地方保护伞下扩张。"},{"label":"争议/局限","value":"巴伐利亚不是整体等同于纳粹；当地保守派和纳粹之间既合作又竞争，希特勒啤酒馆政变时卡尔最终镇压了希特勒。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Ordnungszelle Bayern；Encyclopaedia Britannica: Beer Hall Putsch；Deutsches Historisches Museum/LeMO: Gustav Ritter von Kahr。"}],"relationItems":["← 前因：德国巴伐利亚苏维埃共和国","→ 后果：希特勒啤酒馆政变","↔ 相关：古斯塔夫·冯·卡尔","↔ 相关：纳粹党成立","↔ 相关：纳粹冲锋队"],"relations":[{"text":"← 前因：德国巴伐利亚苏维埃共和国","id":"card108"},{"text":"→ 后果：希特勒啤酒馆政变","id":"card18"},{"text":"↔ 相关：古斯塔夫·冯·卡尔","id":"card130"},{"text":"↔ 相关：纳粹党成立","id":"extra92"},{"text":"↔ 相关：纳粹冲锋队","id":"extra93"}],"source":"history","id":"card129"},{"title":"古斯塔夫·冯·卡尔","level":"C","type":"人物卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1862—1934年；1920—1924年影响突出","place":"德国巴伐利亚；慕尼黑","summary":"卡尔是巴伐利亚右翼保守政治的代表人物，1923年既挑战柏林政府，也镇压了希特勒的希特勒啤酒馆政变。","fields":[{"label":"标题","value":"古斯塔夫·冯·卡尔"},{"label":"分级","value":"C"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1862—1934年；1920—1924年影响突出"},{"label":"地点","value":"德国巴伐利亚；慕尼黑"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"卡尔是巴伐利亚右翼保守政治的代表人物，1923年既挑战柏林政府，也镇压了希特勒的希特勒啤酒馆政变。"},{"label":"生卒年/活跃年代","value":"1862年11月29日—1934年6月30日；1920年任巴伐利亚总理，1923年任总国家专员。"},{"label":"身份/职务","value":"巴伐利亚保守政治家、巴伐利亚总理、总国家专员。"},{"label":"关键贡献/作为","value":"把巴伐利亚经营成右翼“秩序细胞”；1923年获独裁性紧急权力，拒绝执行部分中央命令；在希特勒啤酒馆政变中被希特勒胁迫后转而镇压政变。"},{"label":"核心主张/立场","value":"反马克思主义、反柏林共和国，倾向保守威权和巴伐利亚特殊地位。"},{"label":"为什么重要","value":"他说明魏玛右翼并非铁板一块。保守威权派可以庇护纳粹成长，但在权力竞争中也会与纳粹冲突。"},{"label":"争议/评价","value":"卡尔既是共和国敌人，也是希特勒1923年失败的重要阻力；1934年长刀之夜中他被纳粹杀害，显示纳粹后来清算旧右翼竞争者。"},{"label":"关联事件（可选）","value":"魏玛巴伐利亚右翼“秩序细胞”；希特勒啤酒馆政变；纳粹长刀之夜。"},{"label":"出处","value":"Encyclopaedia Britannica: Gustav Ritter von Kahr；Deutsches Historisches Museum/LeMO: Gustav Ritter von Kahr；LMU München: Generalstaatskommissar Gustav von Kahr und der Hitler-Ludendorff-Putsch。"}],"relationItems":["← 前因：魏玛巴伐利亚右翼“秩序细胞”","→ 后果：希特勒啤酒馆政变","→ 后果：纳粹长刀之夜","↔ 相关：纳粹党成立","↔ 相关：古斯塔夫·施特雷泽曼内阁"],"relations":[{"text":"← 前因：魏玛巴伐利亚右翼“秩序细胞”","id":"card129"},{"text":"→ 后果：希特勒啤酒馆政变","id":"card18"},{"text":"→ 后果：纳粹长刀之夜","id":"extra108"},{"text":"↔ 相关：纳粹党成立","id":"extra92"},{"text":"↔ 相关：古斯塔夫·施特雷泽曼内阁","id":"card122"}],"source":"history","id":"card130"},{"title":"啤酒馆政变后希特勒审判","level":"B","type":"事件卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1924年2月26日—4月1日","place":"德国巴伐利亚；慕尼黑、兰茨贝格监狱","summary":"希特勒啤酒馆政变后，希特勒在审判中把叛国案变成宣传舞台，并获得相对宽大的判决。","fields":[{"label":"标题","value":"啤酒馆政变后希特勒审判"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1924年2月26日—4月1日"},{"label":"地点","value":"德国巴伐利亚；慕尼黑、兰茨贝格监狱"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"希特勒啤酒馆政变后，希特勒在审判中把叛国案变成宣传舞台，并获得相对宽大的判决。"},{"label":"参与者","value":"阿道夫·希特勒、埃里希·鲁登道夫、巴伐利亚司法机关、纳粹党人、德国和国际媒体。"},{"label":"发生了什么","value":"希特勒啤酒馆政变失败后，希特勒等人因叛国受审。审判本应追究其推翻共和国的责任，但法庭允许希特勒长篇陈述政治观点，他借机把自己塑造成民族主义救世者。1924年4月，希特勒被判五年监禁，但实际在兰茨贝格服刑不足一年便获释。"},{"label":"为什么重要","value":"这是纳粹从失败政变中恢复的重要节点。审判让希特勒获得全国知名度，也使他认识到公开宣传和合法夺权路线的重要性。"},{"label":"前因","value":"希特勒啤酒馆政变试图借巴伐利亚右翼危机发动“向柏林进军”，但卡尔和巴伐利亚警方最终镇压政变，希特勒被捕。"},{"label":"后果","value":"希特勒在狱中写作《我的奋斗》，纳粹运动随后重组并逐渐从暴力政变转向利用选举和合法程序夺权。"},{"label":"出处","value":"Encyclopaedia Britannica: Beer Hall Putsch；German History in Documents and Images: Putsch Participants in Landsberg Prison；History.com: Beer Hall Putsch。"}],"relationItems":["← 前因：希特勒啤酒馆政变","→ 后果：希特勒《我的奋斗》","→ 后果：纳粹党禁令与重建","↔ 相关：古斯塔夫·冯·卡尔","↔ 相关：埃里希·鲁登道夫"],"relations":[{"text":"← 前因：希特勒啤酒馆政变","id":"card18"},{"text":"→ 后果：希特勒《我的奋斗》","id":"extra66"},{"text":"→ 后果：纳粹党禁令与重建","id":"card132"},{"text":"↔ 相关：古斯塔夫·冯·卡尔","id":"card130"},{"text":"↔ 相关：埃里希·鲁登道夫","id":"extra798"}],"source":"history","id":"card131"},{"title":"纳粹党禁令与重建","level":"B","type":"事件卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1923年11月—1925年2月","place":"德国；巴伐利亚、慕尼黑","summary":"希特勒啤酒馆政变后纳粹党被禁，希特勒获释后重建党组织，并明确转向合法夺权策略。","fields":[{"label":"标题","value":"纳粹党禁令与重建"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1923年11月—1925年2月"},{"label":"地点","value":"德国；巴伐利亚、慕尼黑"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"希特勒啤酒馆政变后纳粹党被禁，希特勒获释后重建党组织，并明确转向合法夺权策略。"},{"label":"参与者","value":"阿道夫·希特勒、纳粹党、巴伐利亚政府、魏玛共和国司法和警察机关。"},{"label":"发生了什么","value":"1923年希特勒啤酒馆政变失败后，纳粹党及其相关组织被禁止，党报也受到限制。希特勒在审判和狱中保留政治影响力，1924年底获释后争取巴伐利亚允许重新活动。1925年2月，纳粹党重新建立，希特勒在党内强化领袖权威，并把夺权策略从直接政变转向通过宣传、选举和组织扩张进入国家权力。"},{"label":"为什么重要","value":"它解释纳粹为什么没有因1923年失败而消失。政变失败反而促成组织重建、领袖原则强化和合法夺权路线。"},{"label":"前因","value":"希特勒啤酒馆政变失败使纳粹运动遭受打击，但希特勒审判和宽大服刑保留了其公众影响力。"},{"label":"后果","value":"重建后的纳粹党发展出更稳定的全国组织、宣传体系和附属组织，为大萧条后的群众化扩张奠定基础。"},{"label":"出处","value":"Encyclopaedia Britannica: Adolf Hitler, Rise to power；United States Holocaust Memorial Museum: Nazi Party；Encyclopaedia Britannica: Nazi Party。"}],"relationItems":["← 前因：啤酒馆政变后希特勒审判","← 前因：希特勒啤酒馆政变","→ 后果：纳粹宣传机器","→ 后果：纳粹冲锋队","↔ 相关：希特勒《我的奋斗》"],"relations":[{"text":"← 前因：啤酒馆政变后希特勒审判","id":"card131"},{"text":"← 前因：希特勒啤酒馆政变","id":"card18"},{"text":"→ 后果：纳粹宣传机器","id":"extra94"},{"text":"→ 后果：纳粹冲锋队","id":"extra93"},{"text":"↔ 相关：希特勒《我的奋斗》","id":"extra66"}],"source":"history","id":"card132"},{"title":"德国1924年两次国会选举","level":"B","type":"事件卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1924年5月4日、1924年12月7日","place":"德国","summary":"1924年两次国会选举从危机投票走向相对稳定，显示恶性通胀后的政治重组和极端派短期回落。","fields":[{"label":"标题","value":"德国1924年两次国会选举"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1924年5月4日、1924年12月7日"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1924年两次国会选举从危机投票走向相对稳定，显示恶性通胀后的政治重组和极端派短期回落。"},{"label":"参与者","value":"德国选民、SPD、中央党、德国人民党、德国民主党、德国国家人民党、共产党、纳粹相关替代名单。"},{"label":"发生了什么","value":"1924年5月，德国在鲁尔危机、恶性通胀和希特勒啤酒馆政变余波后举行国会选举，反共和国和极端力量得票明显扩大，国家人民党、共产党以及纳粹被禁后的替代组织表现突出。德国赔款《道威斯计划》和货币稳定推进后，12月再次举行国会选举，极端左右力量相对回落，中间和温和政党恢复部分支持，但共和国仍需要脆弱联合政府。"},{"label":"为什么重要","value":"这两次选举像一张政治温度计：5月显示1923危机造成的愤怒和不信任，12月显示稳定化政策开始产生效果，但魏玛中间多数并没有真正恢复到1919年的水平。"},{"label":"前因","value":"1923年国家危机、恶性通胀、鲁尔占领和希特勒啤酒馆政变严重冲击共和国信任；施特雷泽曼稳定政策和德国赔款《道威斯计划》又在1924年逐步改变社会预期。"},{"label":"后果","value":"12月选举后魏玛进入相对稳定期，但德国国家人民党仍很强，纳粹虽短期受挫却保留组织重建空间，议会联合政府仍然脆弱。"},{"label":"出处","value":"Bundestag: Elections in the Weimar Republic；Encyclopaedia Britannica: Weimar Republic, Toward stabilization；Deutsches Historisches Museum/LeMO: Reichstagswahl 7. Dezember 1924。"}],"relationItems":["← 前因：魏玛恶性通货膨胀","← 前因：德国赔款《道威斯计划》","← 前因：啤酒馆政变后希特勒审判","→ 后果：欧洲《洛迦诺公约》","→ 后果：纳粹党禁令与重建","↔ 相关：魏玛共和国比例代表制"],"relations":[{"text":"← 前因：魏玛恶性通货膨胀","id":"card90"},{"text":"← 前因：德国赔款《道威斯计划》","id":"card92"},{"text":"← 前因：啤酒馆政变后希特勒审判","id":"card131"},{"text":"→ 后果：欧洲《洛迦诺公约》","id":"card20"},{"text":"→ 后果：纳粹党禁令与重建","id":"card132"},{"text":"↔ 相关：魏玛共和国比例代表制","id":"card112"}],"source":"history","id":"card133"},{"title":"魏玛德国相对稳定期","level":"B","type":"概念/思潮卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1924—1929年","place":"德国；欧洲外交和美国资本市场之间","summary":"1924至1929年魏玛共和国进入相对稳定期，经济、外交和文化短暂复苏，但基础高度依赖外债和脆弱联合政府。","fields":[{"label":"标题","value":"魏玛德国相对稳定期"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1924—1929年"},{"label":"地点","value":"德国；欧洲外交和美国资本市场之间"},{"label":"主要国家","value":"德国、美国、法国、英国"},{"label":"一句话概括","value":"1924至1929年魏玛共和国进入相对稳定期，经济、外交和文化短暂复苏，但基础高度依赖外债和脆弱联合政府。"},{"label":"核心主张/思路","value":"所谓“相对稳定”不是共和国真正稳固，而是货币稳定、德国赔款《道威斯计划》、美国贷款、洛迦诺外交和文化繁荣共同造成的阶段性缓和。"},{"label":"提出者/代表人物（可选）","value":"历史叙述中常以施特雷泽曼外交、沙赫特货币稳定和1920年代柏林文化作为代表。"},{"label":"它从何而来","value":"1923年鲁尔危机、恶性通胀和政治暴力几乎摧毁共和国，随后伦滕马克、德国赔款《道威斯计划》和鲁尔撤军把危机暂时压下。"},{"label":"典型表现","value":"德国重返国际外交，加入一战后国际联盟；美国资本大量流入；城市消费和现代文化繁荣；极端政党一度在选举中退潮。"},{"label":"为什么重要","value":"它解释魏玛共和国为什么看似恢复，又为什么在1929年后迅速崩溃。稳定来自外部资本和政治妥协，而不是深层社会共识。"},{"label":"争议/局限","value":"“黄金二十年代”主要描述城市文化和部分中产消费经验，不能掩盖农村困境、失业风险、住房短缺和反共和国力量的持续存在。"},{"label":"出处","value":"Encyclopaedia Britannica: Weimar Republic, Toward stabilization；Bundeszentrale für politische Bildung: Zwischen Festigung und Gefährdung 1924-1929；Deutsches Historisches Museum/LeMO: Goldene Zwanziger。"}],"relationItems":["← 前因：德国1924年两次国会选举","← 前因：德国赔款《道威斯计划》","→ 后果：华尔街“黑色星期四”","→ 后果：德国大萧条失业危机","↔ 相关：魏玛柏林现代性"],"relations":[{"text":"← 前因：德国1924年两次国会选举","id":"card133"},{"text":"← 前因：德国赔款《道威斯计划》","id":"card92"},{"text":"→ 后果：华尔街“黑色星期四”","id":"card64"},{"text":"→ 后果：德国大萧条失业危机","id":"card99"},{"text":"↔ 相关：魏玛柏林现代性","id":"card33"}],"source":"history","id":"card134"},{"title":"威廉·马克思","level":"B","type":"人物卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1863—1946年；1923—1925年、1926—1928年任德国总理","place":"德国；柏林、波恩","summary":"威廉·马克思是魏玛相对稳定期的重要中央党总理，推动德国赔款《道威斯计划》并维持中间派政府。","fields":[{"label":"标题","value":"威廉·马克思"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1863—1946年；1923—1925年、1926—1928年任德国总理"},{"label":"地点","value":"德国；柏林、波恩"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"威廉·马克思是魏玛相对稳定期的重要中央党总理，推动德国赔款《道威斯计划》并维持中间派政府。"},{"label":"生卒年/活跃年代","value":"1863年1月15日—1946年8月5日；1923—1925年和1926—1928年两度任总理。"},{"label":"身份/职务","value":"中央党政治家、法官、魏玛共和国总理、1925年总统候选人。"},{"label":"关键贡献/作为","value":"1923年后接替施特雷泽曼组阁，推动德国赔款《道威斯计划》立法和稳定化；1925年代表共和派竞选总统但败给兴登堡；1926年后再次组阁。"},{"label":"核心主张/立场","value":"代表中央党温和务实路线，倾向通过议会联合、履约外交和制度稳定维持共和国。"},{"label":"为什么重要","value":"他说明魏玛稳定期并不只由施特雷泽曼塑造，中央党和中间派政府在德国赔款《道威斯计划》通过、财政稳定和外交正常化中也很关键。"},{"label":"争议/评价","value":"马克思的温和和妥协能力帮助共和国渡过危机，但他缺乏强烈群众号召力，也无法阻止中间政党长期萎缩。"},{"label":"关联事件（可选）","value":"德国赔款《道威斯计划》；1925年德国总统选举；德国1924年两次国会选举。"},{"label":"出处","value":"Encyclopaedia Britannica: Wilhelm Marx；Encyclopaedia Britannica: Weimar Republic, Toward stabilization；Weimarer Republik Portal: Wilhelm Marx。"}],"relationItems":["← 前因：古斯塔夫·施特雷泽曼内阁","→ 后果：德国赔款《道威斯计划》","→ 后果：1925年德国总统选举","↔ 相关：德国中央党","↔ 相关：威廉·马克思"],"relations":[{"text":"← 前因：古斯塔夫·施特雷泽曼内阁","id":"card122"},{"text":"→ 后果：德国赔款《道威斯计划》","id":"card92"},{"text":"→ 后果：1925年德国总统选举","id":"card38"},{"text":"↔ 相关：德国中央党","id":"extra673"},{"text":"↔ 相关：威廉·马克思","id":"card135"}],"source":"history","id":"card135"},{"title":"汉斯·路德","level":"C","type":"人物卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1879—1962年；1923—1926年和1930—1933年影响突出","place":"德国；柏林","summary":"汉斯·路德参与货币稳定，后任魏玛总理和帝国银行总裁，是共和国技术官僚政治的代表。","fields":[{"label":"标题","value":"汉斯·路德"},{"label":"分级","value":"C"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1879—1962年；1923—1926年和1930—1933年影响突出"},{"label":"地点","value":"德国；柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"汉斯·路德参与货币稳定，后任魏玛总理和帝国银行总裁，是共和国技术官僚政治的代表。"},{"label":"生卒年/活跃年代","value":"1879年3月10日—1962年5月11日；1923年任财政部长，1925—1926年任总理，1930—1933年任帝国银行总裁。"},{"label":"身份/职务","value":"财政部长、魏玛共和国总理、帝国银行总裁、外交官。"},{"label":"关键贡献/作为","value":"作为财政部长参与伦滕马克稳定政策；任总理期间参与洛迦诺外交；后继沙赫特出任帝国银行总裁。"},{"label":"核心主张/立场","value":"倾向财政和货币稳定、行政技术治理和中间派协商，政治上不属于强党派型领袖。"},{"label":"为什么重要","value":"他代表魏玛共和国在危机后依赖专家、财政纪律和中间派内阁维持稳定的治理方式。"},{"label":"争议/评价","value":"路德的技术官僚风格有利于稳定，但也显示魏玛政党政治难以产生强多数，政府常依赖非党派专家和总统信任。"},{"label":"关联事件（可选）","value":"魏玛德国伦滕马克；欧洲《洛迦诺公约》；魏玛帝国银行独立化。"},{"label":"出处","value":"Encyclopaedia Britannica: Hans Luther；Deutsches Historisches Museum/LeMO: Hans Luther；Das Parlament: Sie führten die Rentenmark zum Erfolg。"}],"relationItems":["← 前因：魏玛恶性通货膨胀","→ 后果：魏玛德国伦滕马克","↔ 相关：雅尔马·沙赫特","↔ 相关：欧洲《洛迦诺公约》","↔ 相关：魏玛总统内阁"],"relations":[{"text":"← 前因：魏玛恶性通货膨胀","id":"card90"},{"text":"→ 后果：魏玛德国伦滕马克","id":"card91"},{"text":"↔ 相关：雅尔马·沙赫特","id":"card137"},{"text":"↔ 相关：欧洲《洛迦诺公约》","id":"card20"},{"text":"↔ 相关：魏玛总统内阁","id":"card39"}],"source":"history","id":"card136"},{"title":"雅尔马·沙赫特","level":"B","type":"人物卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1877—1970年；1923—1930年、1933—1939年影响突出","place":"德国；柏林","summary":"沙赫特先帮助魏玛稳定货币，后又成为纳粹经济和再军备融资的重要人物，横跨两个德国政权。","fields":[{"label":"标题","value":"雅尔马·沙赫特"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1877—1970年；1923—1930年、1933—1939年影响突出"},{"label":"地点","value":"德国；柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"沙赫特先帮助魏玛稳定货币，后又成为纳粹经济和再军备融资的重要人物，横跨两个德国政权。"},{"label":"生卒年/活跃年代","value":"1877年1月22日—1970年6月3日；1923年任货币专员，1923—1930年任帝国银行总裁。"},{"label":"身份/职务","value":"银行家、货币专员、帝国银行总裁、后来的纳粹经济部长。"},{"label":"关键贡献/作为","value":"参与推出伦滕马克并稳定货币；作为帝国银行总裁执行紧缩和稳定政策；1929年参与德国赔款《杨格计划》谈判后因不满而辞职，后与右翼和纳粹靠近。"},{"label":"核心主张/立场","value":"强调货币纪律、财政稳定和中央银行权威；政治上逐渐从魏玛稳定派转向支持右翼威权解决方案。"},{"label":"为什么重要","value":"他说明技术官僚并不必然等于民主派。沙赫特能稳定魏玛货币，也能服务纳粹再军备。"},{"label":"争议/评价","value":"沙赫特常被称为“金融魔术师”，但他的政治选择极具争议；战后纽伦堡审判中被判无罪仍长期引发讨论。"},{"label":"关联事件（可选）","value":"魏玛德国伦滕马克；魏玛帝国银行独立化；德国赔款《杨格计划》；纳粹德国四年计划。"},{"label":"出处","value":"Encyclopaedia Britannica: Hjalmar Schacht；Deutsches Historisches Museum/LeMO: Hjalmar Schacht；German History in Documents and Images: Hjalmar Schacht on Stabilization。"}],"relationItems":["← 前因：魏玛恶性通货膨胀","→ 后果：魏玛帝国银行独立化","→ 后果：纳粹德国四年计划","↔ 相关：汉斯·路德","↔ 相关：德国哈尔茨堡阵线"],"relations":[{"text":"← 前因：魏玛恶性通货膨胀","id":"card90"},{"text":"→ 后果：魏玛帝国银行独立化","id":"card138"},{"text":"→ 后果：纳粹德国四年计划","id":"extra122"},{"text":"↔ 相关：汉斯·路德","id":"card136"},{"text":"↔ 相关：德国哈尔茨堡阵线","id":"card48"}],"source":"history","id":"card137"},{"title":"魏玛帝国银行独立化","level":"B","type":"制度/文本卡","tags":["经济与社会","战争与外交"],"mainTag":"经济与社会","subTag":"战争与外交","timeText":"1924年8月30日","place":"德国；柏林","summary":"1924年帝国银行改革增强中央银行独立性，是德国赔款《道威斯计划》下稳定货币和恢复外资信任的关键条件。","fields":[{"label":"标题","value":"魏玛帝国银行独立化"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1924年8月30日"},{"label":"地点","value":"德国；柏林"},{"label":"主要国家","value":"德国、美国、英国、法国"},{"label":"一句话概括","value":"1924年帝国银行改革增强中央银行独立性，是德国赔款《道威斯计划》下稳定货币和恢复外资信任的关键条件。"},{"label":"制定方/签署方","value":"魏玛政府、帝国议会、帝国银行和赔款相关国际监督机制。"},{"label":"主要内容","value":"根据德国赔款《道威斯计划》框架，帝国银行被重组并增强独立地位，发行和信贷政策受到更严格限制，并与国际贷款、赔款转移和货币稳定联系起来。"},{"label":"它试图解决什么问题","value":"恶性通胀暴露政府通过中央银行融资的危险，德国需要向国内外证明纸币发行不会再被财政赤字吞没。"},{"label":"为什么重要","value":"货币稳定不只靠发行新货币，还靠制度约束。帝国银行独立化让魏玛经济能重新接入国际资本市场。"},{"label":"争议/局限","value":"独立化提高货币信用，但也限制政府在危机中使用货币政策的空间；它还把德国金融主权部分置于赔款和国际监督框架内。"},{"label":"造成的影响","value":"帝国银行成为魏玛稳定期核心金融机构，也让沙赫特等中央银行家获得巨大政策影响。"},{"label":"出处","value":"German History in Documents and Images: The Dawes Plan；Encyclopaedia Britannica: Dawes Plan；German History in Documents and Images: Report of the Commissioner of the Reichsbank。"}],"relationItems":["← 前因：德国赔款《道威斯计划》","← 前因：魏玛德国伦滕马克","→ 后果：道威斯贷款与美国资本流入","↔ 相关：雅尔马·沙赫特","↔ 相关：德意志帝国银行"],"relations":[{"text":"← 前因：德国赔款《道威斯计划》","id":"card92"},{"text":"← 前因：魏玛德国伦滕马克","id":"card91"},{"text":"→ 后果：道威斯贷款与美国资本流入","id":"card140"},{"text":"↔ 相关：雅尔马·沙赫特","id":"card137"},{"text":"↔ 相关：德意志帝国银行","id":"extra747"}],"source":"history","id":"card138"},{"title":"魏玛德意志国铁路公司","level":"C","type":"组织/机构卡","tags":["经济与社会","战争与外交"],"mainTag":"经济与社会","subTag":"战争与外交","timeText":"1924—1937年作为公司化形态运作","place":"德国全国铁路网络","summary":"魏玛德意志国铁路公司在德国赔款《道威斯计划》下被改组为赔款担保对象，把铁路经营、国家财政和国际赔款绑在一起。","fields":[{"label":"标题","value":"魏玛德意志国铁路公司"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1924—1937年作为公司化形态运作"},{"label":"地点","value":"德国全国铁路网络"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"魏玛德意志国铁路公司在德国赔款《道威斯计划》下被改组为赔款担保对象，把铁路经营、国家财政和国际赔款绑在一起。"},{"label":"性质/类型","value":"国有但公司化经营的全国铁路企业。"},{"label":"成立/解散时间","value":"德国国有铁路统一始于1920年；1924年按德国赔款《道威斯计划》改组为 Deutsche Reichsbahn-Gesellschaft；1937年纳粹时期重新更直接纳入国家。"},{"label":"核心目标/宗旨","value":"统一经营全国铁路，提高收益，并用铁路收入为赔款支付提供担保。"},{"label":"关键人物（可选）","value":"铁路管理官员和国际监督董事会成员。"},{"label":"关键行动/事件","value":"1924年改革后，国铁路从普通行政机构转为更独立的经营公司，收益部分服务赔款安排。"},{"label":"为什么重要","value":"它显示德国赔款《道威斯计划》不是抽象赔款数字，而是深入德国基础设施和国家企业治理。铁路成为战败秩序中的财政资产。"},{"label":"争议/局限","value":"铁路公司化有利于经营和信用，却被右翼视为外国控制德国经济命脉；工人和地方利益也受到经营效率压力影响。"},{"label":"出处","value":"Deutsche Bahn: Im Dienst von Demokratie und Diktatur；Bundesarchiv Akten der Reichskanzlei: Deutsche Reichsbahn-Gesellschaft；Business History Review: The German National Railway Company, 1924-1932。"}],"relationItems":["← 前因：德国赔款《道威斯计划》","← 前因：德国铁路建设","→ 后果：道威斯贷款与美国资本流入","↔ 相关：魏玛德国赔款问题","↔ 相关：魏玛帝国银行独立化"],"relations":[{"text":"← 前因：德国赔款《道威斯计划》","id":"card92"},{"text":"← 前因：德国铁路建设","id":"extra507"},{"text":"→ 后果：道威斯贷款与美国资本流入","id":"card140"},{"text":"↔ 相关：魏玛德国赔款问题","id":"card3"},{"text":"↔ 相关：魏玛帝国银行独立化","id":"card138"}],"source":"history","id":"card139"},{"title":"道威斯贷款与美国资本流入","level":"B","type":"概念/思潮卡","tags":["经济与社会","战争与外交"],"mainTag":"经济与社会","subTag":"战争与外交","timeText":"1924—1929年","place":"德国、美国、伦敦和纽约资本市场","summary":"德国赔款《道威斯计划》后美国贷款大量流入德国，支撑魏玛复苏，也让德国经济高度依赖短期外资。","fields":[{"label":"标题","value":"道威斯贷款与美国资本流入"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1924—1929年"},{"label":"地点","value":"德国、美国、伦敦和纽约资本市场"},{"label":"主要国家","value":"德国、美国、英国、法国"},{"label":"一句话概括","value":"德国赔款《道威斯计划》后美国贷款大量流入德国，支撑魏玛复苏，也让德国经济高度依赖短期外资。"},{"label":"核心主张/思路","value":"德国通过国际贷款获得资本，恢复工业、地方财政和赔款支付；美国资本则通过德国赔款和协约国债务形成跨大西洋资金循环。"},{"label":"提出者/代表人物（可选）","value":"查尔斯·道威斯、国际银行团、德国政府和企业借款者。"},{"label":"它从何而来","value":"1923年危机后德国资本枯竭，协约国也希望德国有能力支付赔款；美国金融市场在1920年代具备大量可贷资本。"},{"label":"典型表现","value":"1924年道威斯贷款；德国企业和地方政府在美国市场发债；德国用经济复苏和出口收入维持赔款体系。"},{"label":"为什么重要","value":"它是魏玛稳定期的经济发动机，也是最大隐患。一旦美国资本撤回，德国金融、企业和就业会迅速承压。"},{"label":"争议/局限","value":"外资流入提高投资和消费，却可能掩盖德国财政和产业结构问题；短期借款用于长期项目使风险更大。"},{"label":"出处","value":"Encyclopaedia Britannica: Dawes Plan；Deutsches Historisches Museum/LeMO: Auslandsanleihen 1924-1933；Bundeszentrale für politische Bildung: Zwischen Festigung und Gefährdung 1924-1929。"}],"relationItems":["← 前因：德国赔款《道威斯计划》","← 前因：魏玛帝国银行独立化","→ 后果：华尔街“黑色星期四”","→ 后果：德国大萧条失业危机","↔ 相关：魏玛德意志国铁路公司"],"relations":[{"text":"← 前因：德国赔款《道威斯计划》","id":"card92"},{"text":"← 前因：魏玛帝国银行独立化","id":"card138"},{"text":"→ 后果：华尔街“黑色星期四”","id":"card64"},{"text":"→ 后果：德国大萧条失业危机","id":"card99"},{"text":"↔ 相关：魏玛德意志国铁路公司","id":"card139"}],"source":"history","id":"card140"},{"title":"德苏《柏林条约》","level":"B","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1926年4月24日","place":"德国柏林","summary":"1926年德苏《柏林条约》延续拉帕洛关系，保证一方遭第三国攻击时另一方保持中立。","fields":[{"label":"标题","value":"德苏《柏林条约》"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1926年4月24日"},{"label":"地点","value":"德国柏林"},{"label":"主要国家","value":"德国、苏联"},{"label":"一句话概括","value":"1926年德苏《柏林条约》延续拉帕洛关系，保证一方遭第三国攻击时另一方保持中立。"},{"label":"制定方/签署方","value":"德意志国与苏维埃社会主义共和国联盟。"},{"label":"主要内容","value":"双方确认友好关系，并约定如果一方与第三国发生战争，另一方保持中立；条约有效期五年。"},{"label":"它试图解决什么问题","value":"德国加入西方外交体系后，苏联担心德国倒向反苏阵营；德国则希望在洛迦诺和加入一战后国际联盟之外保留东方外交选项。"},{"label":"为什么重要","value":"它显示施特雷泽曼外交不是单纯“向西方靠拢”，而是东西平衡。德国既通过洛迦诺改善西方关系，也保留同苏联合作的空间。"},{"label":"争议/局限","value":"条约维持灵活性，但也使德国外交被右翼和左翼各自解读为工具；它不能消除德国在西方和苏联之间的长期战略矛盾。"},{"label":"造成的影响","value":"德苏关系在1920年代继续保持军事和经济合作空间，后来也成为理解1939年德苏互不侵犯条约前史的远背景。"},{"label":"出处","value":"Encyclopaedia Britannica: Treaty of Berlin；Deutsches Historisches Museum/LeMO: Chronik 1926；German History in Documents and Images: Treaty of Berlin between the Soviet Union and Germany。"}],"relationItems":["← 前因：德苏《拉帕洛条约》","← 前因：欧洲《洛迦诺公约》","→ 后果：德国加入一战后国际联盟","↔ 相关：古斯塔夫·施特雷泽曼","↔ 同时期参考：苏联外交孤立"],"relations":[{"text":"← 前因：德苏《拉帕洛条约》","id":"card17"},{"text":"← 前因：欧洲《洛迦诺公约》","id":"card20"},{"text":"→ 后果：德国加入一战后国际联盟","id":"card21"},{"text":"↔ 相关：古斯塔夫·施特雷泽曼","id":"card19"}],"source":"history","id":"card141"},{"title":"德国王公财产征收公投","level":"B","type":"事件卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1926年6月20日","place":"德国","summary":"1926年王公财产征收公投试图无偿没收旧王公财产，虽获大量支持但未达通过门槛。","fields":[{"label":"标题","value":"德国王公财产征收公投"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1926年6月20日"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1926年王公财产征收公投试图无偿没收旧王公财产，虽获大量支持但未达通过门槛。"},{"label":"参与者","value":"德国共产党、社会民主党、德国人权联盟、旧王公家族、保守派、中央党、选民。"},{"label":"发生了什么","value":"十一月革命后，旧王公家族财产归属长期争议。1926年，KPD推动无偿征收王公财产，SPD后来加入支持，形成大规模公民投票运动。6月20日公投中，赞成票数量巨大，但因未达到宪法要求的法定选民比例，提案失败。"},{"label":"为什么重要","value":"它是魏玛直接民主最重要的案例之一，也显示左翼在社会正义议题上曾有联合动员能力。"},{"label":"前因","value":"帝制崩溃后旧王室和各邦围绕财产补偿争议不断，通胀创伤和贫困又让普通民众更反感旧王公获得巨额财产。"},{"label":"后果","value":"公投失败后，旧精英财产问题没有彻底解决；左翼合作未能稳定延续，右翼则进一步动员保护财产权和反共产主义。"},{"label":"出处","value":"Bundesarchiv: Volksentscheid zur Fürstenenteignung；Deutsches Historisches Museum/LeMO: Chronik 1926；American Political Science Review: The German Referendum on the Princes’ Property。"}],"relationItems":["← 前因：德国十一月革命","← 前因：魏玛恶性通货膨胀","→ 后果：共产国际“社会法西斯”论","↔ 相关：德国人权联盟","↔ 相关：魏玛共和国比例代表制"],"relations":[{"text":"← 前因：德国十一月革命","id":"extra666"},{"text":"← 前因：魏玛恶性通货膨胀","id":"card90"},{"text":"→ 后果：共产国际“社会法西斯”论","id":"card53"},{"text":"↔ 相关：德国人权联盟","id":"card89"},{"text":"↔ 相关：魏玛共和国比例代表制","id":"card112"}],"source":"history","id":"card142"},{"title":"施特雷泽曼-白里安和解外交","level":"B","type":"概念/思潮卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1925—1929年","place":"德国、法国、洛迦诺、日内瓦","summary":"施特雷泽曼和白里安以安全保障、修约和外交承认为基础，推动德法关系短暂缓和。","fields":[{"label":"标题","value":"施特雷泽曼-白里安和解外交"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1925—1929年"},{"label":"地点","value":"德国、法国、洛迦诺、日内瓦"},{"label":"主要国家","value":"德国、法国"},{"label":"一句话概括","value":"施特雷泽曼和白里安以安全保障、修约和外交承认为基础，推动德法关系短暂缓和。"},{"label":"核心主张/思路","value":"德国通过承认西部边界、履约和国际合作换取外交平等、赔款调整和占领结束；法国通过安全保障和国际机制减少对德国复仇的恐惧。"},{"label":"提出者/代表人物（可选）","value":"德国外长古斯塔夫·施特雷泽曼、法国外长阿里斯蒂德·白里安。"},{"label":"它从何而来","value":"鲁尔危机证明强制占领代价高昂，德国也需要摆脱国际孤立，英美则推动欧洲金融和安全稳定。"},{"label":"典型表现","value":"欧洲《洛迦诺公约》、德国加入一战后国际联盟、凯洛格-白里安公约、德国赔款《杨格计划》前后的谈判氛围。"},{"label":"为什么重要","value":"它是魏玛外交的最高点。它没有消灭凡尔赛矛盾，但创造了德国以谈判而非战争重返欧洲大国政治的可能。"},{"label":"争议/局限","value":"和解主要集中在西部边界，德国并未同样承认东部边界；法国国内安全焦虑和德国右翼修约主义都限制了和解深度。"},{"label":"出处","value":"Encyclopaedia Britannica: Aristide Briand；Encyclopaedia Britannica: Gustav Stresemann；Encyclopaedia Britannica: Locarno Pact。"}],"relationItems":["← 前因：欧洲《洛迦诺公约》","→ 后果：德国加入一战后国际联盟","→ 后果：德国赔款《杨格计划》","↔ 相关：古斯塔夫·施特雷泽曼","↔ 相关：《凯洛格-白里安公约》"],"relations":[{"text":"← 前因：欧洲《洛迦诺公约》","id":"card20"},{"text":"→ 后果：德国加入一战后国际联盟","id":"card21"},{"text":"→ 后果：德国赔款《杨格计划》","id":"card93"},{"text":"↔ 相关：古斯塔夫·施特雷泽曼","id":"card19"},{"text":"↔ 相关：《凯洛格-白里安公约》","id":"card22"}],"source":"history","id":"card143"},{"title":"德国1928年国会选举","level":"B","type":"事件卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1928年5月20日","place":"德国","summary":"1928年国会选举中SPD成为最大党，纳粹得票很低，表面上显示魏玛民主进入相对稳定阶段。","fields":[{"label":"标题","value":"德国1928年国会选举"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1928年5月20日"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1928年国会选举中SPD成为最大党，纳粹得票很低，表面上显示魏玛民主进入相对稳定阶段。"},{"label":"参与者","value":"德国选民、SPD、中央党、DVP、DDP、DNVP、KPD、NSDAP等政党。"},{"label":"发生了什么","value":"1928年5月德国举行国会选举。SPD明显获胜并成为最大党，DNVP受挫，纳粹党只获得很小比例选票。选举后，赫尔曼·穆勒组成包括SPD、中央党、DVP、DDP和BVP的大联合政府。"},{"label":"为什么重要","value":"这是魏玛共和国最后一次相对正常和稳定的全国选举。它显示纳粹在经济危机前仍属边缘力量，也显示民主政党仍可能组成多数政府。"},{"label":"前因","value":"德国赔款《道威斯计划》、货币稳定和外交缓和改善了社会预期，1924—1929年的相对稳定让极端反共和国动员短期退潮。"},{"label":"后果","value":"第二次穆勒内阁成立，但大联合政府内部在军费、社会政策和失业保险上矛盾深重，最终在大萧条冲击下瓦解。"},{"label":"出处","value":"Bundesarchiv: Die Reichstagswahl vom 20. Mai 1928；Deutsches Historisches Museum/LeMO: Reichstagswahl 20. Mai 1928；German Bundestag: The Weimar Republic。"}],"relationItems":["← 前因：魏玛德国相对稳定期","→ 后果：赫尔曼·穆勒第二内阁","→ 后果：魏玛失业保险财政争议","↔ 相关：纳粹党禁令与重建","↔ 相关：德国1924年两次国会选举"],"relations":[{"text":"← 前因：魏玛德国相对稳定期","id":"card134"},{"text":"→ 后果：赫尔曼·穆勒第二内阁","id":"card145"},{"text":"→ 后果：魏玛失业保险财政争议","id":"card148"},{"text":"↔ 相关：纳粹党禁令与重建","id":"card132"},{"text":"↔ 相关：德国1924年两次国会选举","id":"card133"}],"source":"history","id":"card144"},{"title":"赫尔曼·穆勒第二内阁","level":"B","type":"组织/机构卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1928年6月28日—1930年3月27日","place":"德国；柏林","summary":"穆勒第二内阁是魏玛最后一个有议会多数基础的大联合政府，最终因大萧条和失业保险争议崩溃。","fields":[{"label":"标题","value":"赫尔曼·穆勒第二内阁"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1928年6月28日—1930年3月27日"},{"label":"地点","value":"德国；柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"穆勒第二内阁是魏玛最后一个有议会多数基础的大联合政府，最终因大萧条和失业保险争议崩溃。"},{"label":"性质/类型","value":"魏玛共和国中央政府，大联合内阁。"},{"label":"成立/解散时间","value":"1928年6月成立；1930年3月辞职。"},{"label":"核心目标/宗旨","value":"维持议会多数，处理德国赔款《杨格计划》、军备争议、社会政策和经济放缓。"},{"label":"关键人物（可选）","value":"赫尔曼·穆勒、古斯塔夫·施特雷泽曼、鲁道夫·希法亭、威廉·格勒纳。"},{"label":"关键行动/事件","value":"推动德国赔款《杨格计划》谈判和批准；处理装甲巡洋舰A争议；在失业保险财政问题上无法维持联合。"},{"label":"为什么重要","value":"它是魏玛议会政府的最后一道主防线。其倒台后，德国进入总统内阁阶段，议会民主开始被系统绕开。"},{"label":"争议/局限","value":"大联合政府成员从SPD到DVP分歧巨大，很多议题只能暂时妥协。经济危机一来，社会政策和财政纪律之间的矛盾迅速爆发。"},{"label":"出处","value":"German History in Documents and Images: The Second Müller Cabinet；Bundesarchiv: Rücktritt des Kabinetts Müller；Encyclopaedia Britannica: Hermann Müller。"}],"relationItems":["← 前因：德国1928年国会选举","→ 后果：魏玛失业保险财政争议","→ 后果：魏玛总统内阁","↔ 相关：德国赔款《杨格计划》","↔ 相关：德国装甲巡洋舰A争议"],"relations":[{"text":"← 前因：德国1928年国会选举","id":"card144"},{"text":"→ 后果：魏玛失业保险财政争议","id":"card148"},{"text":"→ 后果：魏玛总统内阁","id":"card39"},{"text":"↔ 相关：德国赔款《杨格计划》","id":"card93"},{"text":"↔ 相关：德国装甲巡洋舰A争议","id":"card146"}],"source":"history","id":"card145"},{"title":"德国装甲巡洋舰A争议","level":"C","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1928年","place":"德国；帝国议会和选举舆论场","summary":"装甲巡洋舰A争议让SPD在反军费口号和联合执政责任之间陷入矛盾，暴露魏玛军政问题。","fields":[{"label":"标题","value":"德国装甲巡洋舰A争议"},{"label":"分级","value":"C"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1928年"},{"label":"地点","value":"德国；帝国议会和选举舆论场"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"装甲巡洋舰A争议让SPD在反军费口号和联合执政责任之间陷入矛盾，暴露魏玛军政问题。"},{"label":"参与者","value":"SPD、赫尔曼·穆勒内阁、国防军、帝国议会、选民和反军国主义舆论。"},{"label":"发生了什么","value":"1928年选举中，SPD用“儿童餐而非装甲巡洋舰”批评右派和中间派支持建造昂贵军舰。选后SPD进入大联合政府，却在内阁中为了维持联合而接受建舰预算，引发党内和支持者不满。随后SPD国会党团又试图反对拨款，造成政府和党团之间的尴尬冲突。"},{"label":"为什么重要","value":"它不是军事技术小事，而是魏玛议会政治的缩影：民主政党既要反军国主义，又要同保守军方和中间党派共同执政。"},{"label":"前因","value":"凡尔赛条约限制德国海军规模，但国防军和保守派仍希望通过新舰维持远洋作战能力和大国象征；1928年选举又把社会福利、儿童救济和军费优先级推到舆论中心。"},{"label":"后果","value":"SPD公信力受损，穆勒内阁内部裂痕加深；军费和福利支出的冲突预示失业保险财政争议会进一步撕裂大联合政府。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Streit um den Panzerkreuzerbau 1928；Bundeszentrale für politische Bildung: Zwischen Festigung und Gefährdung 1924-1929；Zeit: Panzerkreuzer A。"}],"relationItems":["← 前因：德国1928年国会选举","→ 后果：赫尔曼·穆勒第二内阁","↔ 相关：魏玛德国国防军","↔ 相关：魏玛失业保险财政争议","↔ 相关：德国社会民主党（SPD）"],"relations":[{"text":"← 前因：德国1928年国会选举","id":"card144"},{"text":"→ 后果：赫尔曼·穆勒第二内阁","id":"card145"},{"text":"↔ 相关：魏玛德国国防军","id":"card109"},{"text":"↔ 相关：魏玛失业保险财政争议","id":"card148"},{"text":"↔ 相关：德国社会民主党（SPD）","id":"extra628"}],"source":"history","id":"card146"},{"title":"魏玛柏林“血腥五月”","level":"B","type":"事件卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1929年5月1日—3日","place":"德国柏林；婚礼区、诺伊克ölln等工人区","summary":"1929年魏玛柏林“血腥五月”中警察镇压共产党五一示威，严重加深SPD与KPD之间的敌意。","fields":[{"label":"标题","value":"魏玛柏林“血腥五月”"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1929年5月1日—3日"},{"label":"地点","value":"德国柏林；婚礼区、诺伊克ölln等工人区"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1929年魏玛柏林“血腥五月”中警察镇压共产党五一示威，严重加深SPD与KPD之间的敌意。"},{"label":"参与者","value":"柏林警察、警察局长卡尔·策吉贝尔、德国共产党、工人示威者、旁观平民、普鲁士和柏林社民党政府。"},{"label":"发生了什么","value":"1929年五一前，柏林警察禁止露天政治集会。KPD仍号召工人示威，警察在婚礼区和诺伊克ölln等地强力驱散，冲突持续数日，造成数十人死亡和大量伤者。许多死伤者并非武装起义者，而是示威者或居民。"},{"label":"为什么重要","value":"它把魏玛左翼分裂推向更深处。KPD把SPD描绘为“社会法西斯”的叙事因此更容易传播，反纳粹共同阵线更难形成。"},{"label":"前因","value":"魏玛末期工人区政治高度紧张，SPD掌控的普鲁士和柏林警察坚持秩序优先，KPD则把五一示威视为阶级动员和挑战国家权力的机会。"},{"label":"后果","value":"KPD与SPD之间的互信进一步崩溃，红色阵线战士联盟不久被禁，左翼无法合作成为共和国末期反纳粹失败的重要背景。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Blutmai 1929；The Historical Journal: Blutmai 1929；Bundesarchiv: Blutmai 1929 image materials。"}],"relationItems":["← 前因：德国红色阵线战士联盟","← 前因：德国1928年国会选举","→ 后果：共产国际“社会法西斯”论","↔ 相关：魏玛政治街头暴力","↔ 相关：德国铁阵线"],"relations":[{"text":"← 前因：德国红色阵线战士联盟","id":"card36"},{"text":"← 前因：德国1928年国会选举","id":"card144"},{"text":"→ 后果：共产国际“社会法西斯”论","id":"card53"},{"text":"↔ 相关：魏玛政治街头暴力","id":"card34"},{"text":"↔ 相关：德国铁阵线","id":"card54"}],"source":"history","id":"card147"},{"title":"魏玛失业保险财政争议","level":"B","type":"事件卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1928—1930年，1930年3月达到高潮","place":"德国；柏林政府和帝国议会","summary":"失业保险财政争议撕裂穆勒大联合政府，成为魏玛从议会内阁转入总统内阁的直接导火索。","fields":[{"label":"标题","value":"魏玛失业保险财政争议"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1928—1930年，1930年3月达到高潮"},{"label":"地点","value":"德国；柏林政府和帝国议会"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"失业保险财政争议撕裂穆勒大联合政府，成为魏玛从议会内阁转入总统内阁的直接导火索。"},{"label":"参与者","value":"赫尔曼·穆勒内阁、SPD、DVP、中央党、企业界、工会、失业保险机构、兴登堡总统。"},{"label":"发生了什么","value":"1927年失业保险制度建立后，经济放缓和失业上升很快让基金承压。穆勒内阁内部围绕提高缴费、削减福利还是用财政补贴填补缺口发生争执。SPD拒绝削弱失业者保障，DVP等中右力量反对增加雇主负担。1930年3月，妥协失败，穆勒内阁辞职。"},{"label":"为什么重要","value":"它把福利国家财政问题变成政体转折点。魏玛民主不是突然被街头暴力击倒，而是在失业、预算和联盟政治无法协调时失去议会治理能力。"},{"label":"前因","value":"魏玛失业保险法建立了现代保障承诺，但1928年后经济放缓和失业上升使保险基金收入不足，企业和工会对负担分配意见相反。"},{"label":"后果","value":"穆勒内阁倒台后，兴登堡任命布吕宁组阁，政府越来越依赖总统任命和紧急法令绕开国会；福利财政危机因此成为魏玛议会民主瓦解的制度转折点之一。"},{"label":"出处","value":"Bundesarchiv: Rücktritt des Kabinetts Müller；Encyclopaedia Britannica: Weimar Republic, The end of the Weimar Republic；Encyclopaedia Britannica: Hermann Müller。"}],"relationItems":["← 前因：魏玛德国失业保险法","← 前因：赫尔曼·穆勒第二内阁","→ 后果：魏玛总统内阁","→ 后果：布吕宁内阁通缩政策","↔ 相关：德国大萧条失业危机"],"relations":[{"text":"← 前因：魏玛德国失业保险法","id":"card81"},{"text":"← 前因：赫尔曼·穆勒第二内阁","id":"card145"},{"text":"→ 后果：魏玛总统内阁","id":"card39"},{"text":"→ 后果：布吕宁内阁通缩政策","id":"card65"},{"text":"↔ 相关：德国大萧条失业危机","id":"card99"}],"source":"history","id":"card148"},{"title":"魏玛《普鲁士协约》","level":"C","type":"制度/文本卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1929年6月14日","place":"德国普鲁士自由邦；罗马教廷","summary":"1929年《普鲁士协约》调整普鲁士与天主教会关系，显示魏玛州邦层面仍在处理国家与教会秩序。","fields":[{"label":"标题","value":"魏玛《普鲁士协约》"},{"label":"分级","value":"C"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1929年6月14日"},{"label":"地点","value":"德国普鲁士自由邦；罗马教廷"},{"label":"主要国家","value":"德国、梵蒂冈"},{"label":"一句话概括","value":"1929年《普鲁士协约》调整普鲁士与天主教会关系，显示魏玛州邦层面仍在处理国家与教会秩序。"},{"label":"制定方/签署方","value":"普鲁士自由邦政府与罗马教廷。"},{"label":"主要内容","value":"协约规定教区组织、主教任命、神学教育和教会事务等安排，以适应帝制崩溃和魏玛宪法后的新国家教会关系。"},{"label":"它试图解决什么问题","value":"1918年后旧王朝国家教会关系失效，普鲁士需要在共和宪制下重新确定天主教会的法律地位。"},{"label":"为什么重要","value":"它提醒我们魏玛政治不只是国会和街头暴力，也包括宗教、教育和州邦治理的制度化谈判。"},{"label":"争议/局限","value":"协约主要规范天主教会制度权利，没有解决全部学校和文化政治争议；1933年全国性《政教协定》又在纳粹背景下改变问题性质。"},{"label":"造成的影响","value":"普鲁士协约为魏玛时期国家教会关系提供州邦层面的稳定框架，也成为后来1933年帝国协约的制度背景之一。"},{"label":"出处","value":"Kulturstiftung: Das Preussenkonkordat；verfassungen.de: Preußisches Konkordat 1929；Konrad-Adenauer-Stiftung research on Preußenkonkordat。"}],"relationItems":["← 前因：魏玛普鲁士自由邦","← 前因：德国中央党","→ 后果：纳粹德国《政教协定》（1933）","↔ 相关：德意志帝国文化斗争","↔ 相关：纳粹一体化政策"],"relations":[{"text":"← 前因：魏玛普鲁士自由邦","id":"card111"},{"text":"← 前因：德国中央党","id":"extra673"},{"text":"↔ 相关：德意志帝国文化斗争","id":"extra626"},{"text":"↔ 相关：纳粹一体化政策","id":"extra100"}],"source":"history","id":"card149"},{"title":"海因里希·布吕宁","level":"B","type":"人物卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1885—1970年；担任德国总理为1930—1932年","place":"德国；柏林","summary":"布吕宁是魏玛第一个总统内阁总理，他用紧急法令和通缩政策应对危机，却加速削弱议会民主。","fields":[{"label":"标题","value":"海因里希·布吕宁"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1885—1970年；担任德国总理为1930—1932年"},{"label":"地点","value":"德国；柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"布吕宁是魏玛第一个总统内阁总理，他用紧急法令和通缩政策应对危机，却加速削弱议会民主。"},{"label":"生卒年/活跃年代","value":"1885年出生，1970年去世；魏玛政治高峰在1930—1932年。"},{"label":"身份/职务","value":"中央党政治家，1930年3月至1932年5月任德国总理。"},{"label":"关键贡献/作为","value":"在大萧条中实行削减支出、压低工资、增税和紧缩预算；依靠兴登堡总统和宪法第48条治理；推动德国证明赔款不可持续。"},{"label":"核心主张/立场","value":"倾向财政正统、国家权威和对凡尔赛体系的修正，希望通过忍受短期痛苦换取赔款问题的外交突破。"},{"label":"为什么重要","value":"他把魏玛从议会内阁带入总统内阁阶段，是理解1930年后民主制度失灵的关键人物。"},{"label":"争议/评价","value":"布吕宁是否有意用经济痛苦来结束赔款仍有争议；但他的通缩政策和紧急法令治理明显扩大了社会痛苦和反民主政治空间。"},{"label":"关联事件","value":"魏玛失业保险财政争议；布吕宁总统内阁；布吕宁内阁通缩政策；洛桑赔款会议。"},{"label":"出处","value":"Encyclopaedia Britannica: Heinrich Brüning；German History in Documents and Images: The Brüning Cabinet, March 30, 1930；Bundesarchiv: Akten der Reichskanzlei, Kabinett Brüning。"}],"relationItems":["← 前因：赫尔曼·穆勒第二内阁","↔ 相关：德国中央党","↔ 相关：魏玛总统内阁","↔ 相关：布吕宁内阁通缩政策","→ 后果：布吕宁内阁倒台"],"relations":[{"text":"← 前因：赫尔曼·穆勒第二内阁","id":"card145"},{"text":"↔ 相关：德国中央党","id":"extra673"},{"text":"↔ 相关：魏玛总统内阁","id":"card39"},{"text":"↔ 相关：布吕宁内阁通缩政策","id":"card65"},{"text":"→ 后果：布吕宁内阁倒台","id":"card158"}],"source":"history","id":"card150"},{"title":"布吕宁总统内阁","level":"B","type":"组织/机构卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1930年3月—1932年5月","place":"德国；柏林","summary":"布吕宁总统内阁是魏玛议会内阁向总统任命、紧急法令治理过渡的第一个长期样本。","fields":[{"label":"标题","value":"布吕宁总统内阁"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1930年3月—1932年5月"},{"label":"地点","value":"德国；柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"布吕宁总统内阁是魏玛议会内阁向总统任命、紧急法令治理过渡的第一个长期样本。"},{"label":"性质/类型","value":"由兴登堡总统任命、缺乏稳定国会多数的少数派政府。"},{"label":"成立/解散时间","value":"1930年3月30日成立，1932年5月30日辞职。"},{"label":"核心目标/宗旨","value":"恢复财政平衡、压低公共开支、处理失业保险赤字，并在外交上推动赔款减免。"},{"label":"关键人物","value":"海因里希·布吕宁、保罗·冯·兴登堡、威廉·格勒纳、约瑟夫·维尔特、汉斯·施朗格-舍宁根等。"},{"label":"关键行动/事件","value":"通过紧急财政法令执政；在国会受阻后解散国会；实行通缩政策；推动赔款暂停和洛桑谈判。"},{"label":"为什么重要","value":"它不是普通换届政府，而是魏玛权力结构改变的信号：内阁越来越依赖总统而不是议会。"},{"label":"争议/局限","value":"内阁既没有群众基础，也没有稳定议会多数，只能用紧急法令维持运转，削弱了共和制度的正常责任链。"},{"label":"出处","value":"German History in Documents and Images: The Brüning Cabinet, March 30, 1930；Encyclopaedia Britannica: Weimar Republic, The end of the Weimar Republic；Bundesarchiv: Akten der Reichskanzlei, Kabinett Brüning。"}],"relationItems":["← 前因：魏玛失业保险财政争议","↔ 相关：海因里希·布吕宁","↔ 相关：魏玛总统内阁","↔ 相关：魏玛宪法第48条","→ 后果：德国1930年紧急财政法令危机"],"relations":[{"text":"← 前因：魏玛失业保险财政争议","id":"card148"},{"text":"↔ 相关：海因里希·布吕宁","id":"card150"},{"text":"↔ 相关：魏玛总统内阁","id":"card39"},{"text":"↔ 相关：魏玛宪法第48条","id":"card12"},{"text":"→ 后果：德国1930年紧急财政法令危机","id":"card153"}],"source":"history","id":"card151"},{"title":"德国SPD对布吕宁政府的“容忍政策”","level":"C","type":"概念/思潮卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1930—1932年","place":"德国；帝国议会和SPD党内政治","summary":"SPD容忍布吕宁政府，是为了阻挡更右翼政府和纳粹上台，却让自身背上支持紧缩的政治代价。","fields":[{"label":"标题","value":"德国SPD对布吕宁政府的“容忍政策”"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1930—1932年"},{"label":"地点","value":"德国；帝国议会和SPD党内政治"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"SPD容忍布吕宁政府，是为了阻挡更右翼政府和纳粹上台，却让自身背上支持紧缩的政治代价。"},{"label":"核心主张/思路","value":"不加入布吕宁内阁，也不轻易推翻它；在极端右翼压力下，把总统内阁视为较小危险。"},{"label":"提出者/代表人物（可选）","value":"SPD国会党团和党内领导层，背景人物包括奥托·韦尔斯等。"},{"label":"它从何而来","value":"1930年选举后国会碎片化，纳粹和共产党席位上升，SPD担心倒阁只会带来更右翼的政府或新的纳粹增长。"},{"label":"典型表现","value":"SPD反对布吕宁的许多紧缩措施，但在关键不信任案和废除紧急法令的表决上采取克制。"},{"label":"为什么重要","value":"它显示民主政党在极端化环境中的困境：为了保护共和国而容忍削弱共和国议会机制的政府。"},{"label":"争议/局限","value":"这一策略没有阻止威权化，反而使SPD与工人选民之间的距离扩大，也让KPD更容易攻击SPD“背叛工人”。"},{"label":"出处","value":"Encyclopaedia Britannica: Weimar Republic, The end of the Weimar Republic；Bundestag historical exhibition materials on Weimar emergency government；German History in Documents and Images: Weimar Germany, 1930–1933。"}],"relationItems":["← 前因：1930年德国国会选举","↔ 相关：德国社会民主党（SPD）","↔ 相关：布吕宁总统内阁","↔ 相关：共产国际“社会法西斯”论","→ 后果：德国铁阵线"],"relations":[{"text":"← 前因：1930年德国国会选举","id":"card44"},{"text":"↔ 相关：德国社会民主党（SPD）","id":"extra628"},{"text":"↔ 相关：布吕宁总统内阁","id":"card151"},{"text":"↔ 相关：共产国际“社会法西斯”论","id":"card53"},{"text":"→ 后果：德国铁阵线","id":"card54"}],"source":"history","id":"card152"},{"title":"德国1930年紧急财政法令危机","level":"B","type":"事件卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1930年7月","place":"德国；柏林帝国议会","summary":"1930年紧急财政法令危机让布吕宁绕开国会执政，并直接导致国会解散和纳粹选票暴涨。","fields":[{"label":"标题","value":"德国1930年紧急财政法令危机"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1930年7月"},{"label":"地点","value":"德国；柏林帝国议会"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1930年紧急财政法令危机让布吕宁绕开国会执政，并直接导致国会解散和纳粹选票暴涨。"},{"label":"参与者","value":"海因里希·布吕宁、兴登堡总统、帝国议会、SPD、DNVP、NSDAP、KPD等。"},{"label":"发生了什么","value":"布吕宁政府提出财政紧缩和增税方案以应对预算赤字。国会多数反对后，布吕宁请求兴登堡根据宪法第48条以紧急法令形式颁布。国会又试图废除该法令，布吕宁随即促成解散国会并重新选举。1930年9月选举后，纳粹党成为第二大党。"},{"label":"为什么重要","value":"这是总统内阁从例外手段变成日常治理工具的关键节点，也把经济政策冲突转化成制度危机。"},{"label":"前因","value":"穆勒内阁因失业保险财政争议倒台后，布吕宁缺乏稳定议会多数，却仍试图用紧缩预算恢复财政信用。"},{"label":"后果","value":"1930年国会选举极大扩大纳粹和共产党席位，布吕宁虽继续执政，但魏玛议会多数变得更难形成。"},{"label":"出处","value":"Weimarer Republik portal: July 1930 timeline；Encyclopaedia Britannica: Weimar Republic, The end of the Weimar Republic；German History in Documents and Images: The Brüning Cabinet。"}],"relationItems":["← 前因：魏玛失业保险财政争议","← 前因：布吕宁总统内阁","→ 后果：1930年德国国会选举","↔ 相关：魏玛宪法第48条","↔ 相关：布吕宁内阁通缩政策"],"relations":[{"text":"← 前因：魏玛失业保险财政争议","id":"card148"},{"text":"← 前因：布吕宁总统内阁","id":"card151"},{"text":"→ 后果：1930年德国国会选举","id":"card44"},{"text":"↔ 相关：魏玛宪法第48条","id":"card12"},{"text":"↔ 相关：布吕宁内阁通缩政策","id":"card65"}],"source":"history","id":"card153"},{"title":"胡佛暂停债务与赔款偿付倡议","level":"B","type":"制度/文本卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1931年6月提出，1931—1932年实施","place":"美国、德国、英国、法国及其他债权国","summary":"胡佛暂停债务与赔款令试图冻结一战债务链条，为德国和欧洲金融危机争取喘息时间。","fields":[{"label":"标题","value":"胡佛暂停债务与赔款偿付倡议"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1931年6月提出，1931—1932年实施"},{"label":"地点","value":"美国、德国、英国、法国及其他债权国"},{"label":"主要国家","value":"美国；德国；英国；法国"},{"label":"一句话概括","value":"胡佛暂停债务与赔款令试图冻结一战债务链条，为德国和欧洲金融危机争取喘息时间。"},{"label":"制定方/签署方","value":"美国总统赫伯特·胡佛提出，涉及德国赔款和协约国对美国战债。"},{"label":"主要内容","value":"暂停一年政府间债务支付，包括德国赔款和盟国战债；目标是避免金融恐慌继续扩散。"},{"label":"它试图解决什么问题","value":"德国银行危机、资本外逃和赔款压力相互叠加，欧洲各国又依赖德国赔款偿还美国战债。"},{"label":"为什么重要","value":"它承认了赔款体系和战债体系在大萧条中已难以维持，是从道威斯、德国赔款《杨格计划》走向洛桑收尾的过渡。"},{"label":"争议/局限","value":"暂停来得太晚，且只是临时措施，无法修复德国银行系统和世界贸易萎缩造成的深层危机。"},{"label":"造成的影响","value":"为1932年洛桑会议处理赔款问题铺路，但没有阻止德国国内政治继续极端化。"},{"label":"出处","value":"Encyclopaedia Britannica: United States, The Great Depression；Encyclopaedia Britannica: 20th-century international relations, origins of World War II；The American Presidency Project: Hoover statement on intergovernmental debts and reparations。"}],"relationItems":["← 前因：德国赔款《杨格计划》","↔ 相关：德国1931年银行危机","↔ 相关：华尔街“黑色星期四”","→ 后果：德国赔款洛桑会议"],"relations":[{"text":"← 前因：德国赔款《杨格计划》","id":"card93"},{"text":"↔ 相关：德国1931年银行危机","id":"card155"},{"text":"↔ 相关：华尔街“黑色星期四”","id":"card64"},{"text":"→ 后果：德国赔款洛桑会议","id":"card159"}],"source":"history","id":"card154"},{"title":"德国1931年银行危机","level":"B","type":"事件卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1931年夏季，7月达到高潮","place":"德国；柏林和全国银行体系","summary":"德国1931年银行危机把外债、资本外逃和国内萧条合成系统性恐慌，重创魏玛经济信任。","fields":[{"label":"标题","value":"德国1931年银行危机"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1931年夏季，7月达到高潮"},{"label":"地点","value":"德国；柏林和全国银行体系"},{"label":"主要国家","value":"德国；美国；奥地利；英国；法国"},{"label":"一句话概括","value":"德国1931年银行危机把外债、资本外逃和国内萧条合成系统性恐慌，重创魏玛经济信任。"},{"label":"参与者","value":"德国帝国银行、达纳特银行、德累斯顿银行、德国政府、外国债权人、存款人和企业。"},{"label":"发生了什么","value":"奥地利信用安施塔特危机后，国际金融市场对中欧银行信心下降。德国短期外资撤出，帝国银行黄金和外汇储备流失。达纳特银行因企业贷款风险和挤兑而崩溃，政府被迫宣布银行假日、限制提款并干预银行体系。"},{"label":"为什么重要","value":"危机表明魏玛稳定期依赖美国短期资本的结构极其脆弱，也让布吕宁紧缩政策面临更大社会代价。"},{"label":"前因","value":"道威斯贷款和美国资本流入支撑了1920年代德国复苏，但大萧条后美国资金回流，欧洲金融体系连锁承压。"},{"label":"后果","value":"银行停业、信用紧缩和企业倒闭加深失业，德国进一步转向外汇管制和国家干预，也推动赔款暂停与洛桑谈判。"},{"label":"出处","value":"Encyclopaedia Britannica: History of Europe, The impact of the slump；Encyclopaedia Britannica: United States, The Great Depression；Bundesarchiv/Weimar materials on economic crisis。"}],"relationItems":["← 前因：道威斯贷款与美国资本流入","← 前因：华尔街“黑色星期四”","↔ 相关：德国达纳特银行倒闭","↔ 相关：胡佛暂停债务与赔款偿付倡议","→ 后果：德国赔款洛桑会议"],"relations":[{"text":"← 前因：道威斯贷款与美国资本流入","id":"card140"},{"text":"← 前因：华尔街“黑色星期四”","id":"card64"},{"text":"↔ 相关：德国达纳特银行倒闭","id":"card67"},{"text":"↔ 相关：胡佛暂停债务与赔款偿付倡议","id":"card154"},{"text":"→ 后果：德国赔款洛桑会议","id":"card159"}],"source":"history","id":"card155"},{"title":"德奥关税同盟计划","level":"C","type":"事件卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1931年3月公布，1931年9月受挫","place":"德国、奥地利、海牙国际法院和欧洲外交场域","summary":"德奥关税同盟计划以经济合作名义触动凡尔赛体系，遭法国等国抵制后失败。","fields":[{"label":"标题","value":"德奥关税同盟计划"},{"label":"分级","value":"C"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1931年3月公布，1931年9月受挫"},{"label":"地点","value":"德国、奥地利、海牙国际法院和欧洲外交场域"},{"label":"主要国家","value":"德国；奥地利；法国；英国；意大利"},{"label":"一句话概括","value":"德奥关税同盟计划以经济合作名义触动凡尔赛体系，遭法国等国抵制后失败。"},{"label":"参与者","value":"德国政府、奥地利政府、法国政府、一战后国际联盟相关机构、常设国际法院。"},{"label":"发生了什么","value":"德国和奥地利宣布计划建立关税同盟，试图取消两国间关税壁垒。法国认为这会绕开凡尔赛和圣日耳曼体系中禁止德奥合并的安排，并以金融和外交压力反对。海牙常设国际法院也对计划合法性作出不利判断，计划最终搁置。"},{"label":"为什么重要","value":"它显示德国修约并不只发生在军事领域，经济一体化同样会被视为改变中欧权力格局的手段。"},{"label":"前因","value":"大萧条削弱奥地利经济，德国也希望扩大中欧经济影响力；施特雷泽曼去世后，德国外交更急于取得修约成果。"},{"label":"后果","value":"计划失败加深德国对凡尔赛限制的怨气，也暴露法国仍能用金融和外交手段阻止中欧格局变化；德国之后更强调“平等权利”和修约诉求，军备平等问题逐渐压过经济合作议题。"},{"label":"出处","value":"Encyclopaedia Britannica: Weimar Republic, The end of the Weimar Republic；European History Quarterly materials on the Austro-German customs union；League of Nations and PCIJ references on the 1931 customs union dispute。"}],"relationItems":["← 前因：欧洲《洛迦诺公约》","↔ 相关：德国1931年银行危机","↔ 相关：奥地利信用安施塔特银行危机","→ 后果：1932年日内瓦裁军会议德国平权争议"],"relations":[{"text":"← 前因：欧洲《洛迦诺公约》","id":"card20"},{"text":"↔ 相关：德国1931年银行危机","id":"card155"},{"text":"→ 后果：1932年日内瓦裁军会议德国平权争议","id":"card166"}],"source":"history","id":"card156"},{"title":"德国东部垦殖计划争议","level":"C","type":"事件卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1932年春","place":"德国；东易北农业区和柏林总统府","summary":"德国东部垦殖计划争议让布吕宁失去兴登堡信任，成为他下台的直接诱因之一。","fields":[{"label":"标题","value":"德国东部垦殖计划争议"},{"label":"分级","value":"C"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1932年春"},{"label":"地点","value":"德国；东易北农业区和柏林总统府"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国东部垦殖计划争议让布吕宁失去兴登堡信任，成为他下台的直接诱因之一。"},{"label":"参与者","value":"海因里希·布吕宁、兴登堡、东易北容克地主、汉斯·施朗格-舍宁根、失业者和农业利益集团。"},{"label":"发生了什么","value":"布吕宁政府试图把部分濒临破产的大地产转为安置失业者的小农垦殖用地，并调整东部农业救助方式。东易北地主和保守派把这一政策攻击为侵犯财产权甚至“农业布尔什维主义”。作为东部地主的兴登堡对计划反感，拒绝继续给予布吕宁发布紧急法令的政治支持。"},{"label":"为什么重要","value":"它说明布吕宁倒台不只是经济失败，也来自总统府、军方顾问和保守土地利益集团的政治合围。"},{"label":"前因","value":"东部农业长期依赖国家救助，大萧条使地主债务、财政紧缩和失业安置同时恶化；布吕宁希望把救助从无条件补贴转向土地重组，因此触动东易北大地产利益。"},{"label":"后果","value":"兴登堡撤回信任后，布吕宁内阁辞职，巴本得以组建更保守、更少议会基础的总统内阁；总统府和保守精英从此更直接地推动威权改造。"},{"label":"出处","value":"Encyclopaedia Britannica: Heinrich Brüning；Weimarer Republik portal: May 1932 timeline；Landesbildungsserver Baden-Württemberg: Präsidialkabinett Brüning。"}],"relationItems":["← 前因：魏玛《东部援助》法案","↔ 相关：海因里希·布吕宁","↔ 相关：布吕宁总统内阁","→ 后果：布吕宁内阁倒台"],"relations":[{"text":"← 前因：魏玛《东部援助》法案","id":"card66"},{"text":"↔ 相关：海因里希·布吕宁","id":"card150"},{"text":"↔ 相关：布吕宁总统内阁","id":"card151"},{"text":"→ 后果：布吕宁内阁倒台","id":"card158"}],"source":"history","id":"card157"},{"title":"布吕宁内阁倒台","level":"B","type":"事件卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1932年5月30日","place":"德国；柏林","summary":"布吕宁内阁倒台标志着魏玛最后一层中间派总统治理被更右翼的总统政治取代。","fields":[{"label":"标题","value":"布吕宁内阁倒台"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1932年5月30日"},{"label":"地点","value":"德国；柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"布吕宁内阁倒台标志着魏玛最后一层中间派总统治理被更右翼的总统政治取代。"},{"label":"参与者","value":"海因里希·布吕宁、保罗·冯·兴登堡、库尔特·冯·施莱歇尔、弗朗茨·冯·巴本、东部农业利益集团。"},{"label":"发生了什么","value":"1932年总统选举后，布吕宁虽然帮助兴登堡连任，却因紧缩政策、SA禁令、东部垦殖计划和总统府权力斗争逐渐失去支持。兴登堡拒绝继续为布吕宁签署关键紧急法令，布吕宁被迫辞职。随后巴本在施莱歇尔支持下组建新内阁。"},{"label":"为什么重要","value":"它把魏玛危机从“中间派用总统权力维持秩序”推进到“保守派主动拆除共和防线”的阶段。"},{"label":"前因","value":"布吕宁长期依靠紧急法令和SPD容忍政策执政，经济恶化、农业利益集团反弹和总统府阴谋共同削弱了他的地位。"},{"label":"后果","value":"巴本“男爵内阁”上台，解除SA禁令并发动普鲁士政变，把中央总统权力用于拆除普鲁士民主防线；魏玛共和国的制度防线进一步崩塌。"},{"label":"出处","value":"Encyclopaedia Britannica: Heinrich Brüning；Encyclopaedia Britannica: Franz von Papen；Weimarer Republik portal: May 1932 timeline。"}],"relationItems":["← 前因：德国东部垦殖计划争议","← 前因：布吕宁总统内阁","→ 后果：德国巴本“男爵内阁”","→ 后果：1932年普鲁士政变","↔ 相关：库尔特·冯·施莱歇尔"],"relations":[{"text":"← 前因：德国东部垦殖计划争议","id":"card157"},{"text":"← 前因：布吕宁总统内阁","id":"card151"},{"text":"→ 后果：德国巴本“男爵内阁”","id":"card162"},{"text":"→ 后果：1932年普鲁士政变","id":"card41"},{"text":"↔ 相关：库尔特·冯·施莱歇尔","id":"card42"}],"source":"history","id":"card158"},{"title":"德国赔款洛桑会议","level":"B","type":"事件卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1932年6月16日—7月9日","place":"瑞士洛桑","summary":"洛桑赔款会议事实上结束了德国一战赔款体系，但来得太晚，未能挽救魏玛共和国。","fields":[{"label":"标题","value":"德国赔款洛桑会议"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1932年6月16日—7月9日"},{"label":"地点","value":"瑞士洛桑"},{"label":"主要国家","value":"德国；英国；法国；意大利；比利时；日本"},{"label":"一句话概括","value":"洛桑赔款会议事实上结束了德国一战赔款体系，但来得太晚，未能挽救魏玛共和国。"},{"label":"参与者","value":"德国代表团，英国、法国、意大利、比利时、日本等债权国代表。"},{"label":"发生了什么","value":"各国在大萧条和胡佛暂停令背景下讨论魏玛德国赔款问题。会议同意继续要求德国大额赔款已不现实，提出以较低的最终付款结束赔款体系。由于美国战债问题未解决，相关安排没有完整按原设想落实，但实际赔款支付已基本终止。"},{"label":"为什么重要","value":"这是凡尔赛赔款体系的收尾节点，说明德国长期外交目标在1932年接近实现，却未能转化为国内民主稳定。"},{"label":"前因","value":"德国赔款《杨格计划》仍保留赔款义务，1931年银行危机和胡佛暂停令表明德国及欧洲债务链条已经难以维持。"},{"label":"后果","value":"赔款问题不再是德国财政的现实核心，但国内失业、总统内阁和纳粹动员已经把政治危机推向不可逆阶段。"},{"label":"出处","value":"Encyclopaedia Britannica: Lausanne Conference；Encyclopaedia Britannica: Reparations；Encyclopaedia Britannica: 20th-century international relations, origins of World War II。"}],"relationItems":["← 前因：德国赔款《杨格计划》","← 前因：胡佛暂停债务与赔款偿付倡议","↔ 相关：魏玛德国赔款问题","↔ 相关：布吕宁内阁通缩政策","→ 后果：纳粹德国废弃凡尔赛体系"],"relations":[{"text":"← 前因：德国赔款《杨格计划》","id":"card93"},{"text":"← 前因：胡佛暂停债务与赔款偿付倡议","id":"card154"},{"text":"↔ 相关：魏玛德国赔款问题","id":"card3"},{"text":"↔ 相关：布吕宁内阁通缩政策","id":"card65"}],"source":"history","id":"card159"},{"title":"奥托·布劳恩","level":"B","type":"人物卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1872—1955年；普鲁士总理任期主要为1920—1932年","place":"德国；普鲁士自由邦和柏林","summary":"奥托·布劳恩长期领导普鲁士自由邦，使普鲁士成为魏玛民主最重要的州级支柱。","fields":[{"label":"标题","value":"奥托·布劳恩"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1872—1955年；普鲁士总理任期主要为1920—1932年"},{"label":"地点","value":"德国；普鲁士自由邦和柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"奥托·布劳恩长期领导普鲁士自由邦，使普鲁士成为魏玛民主最重要的州级支柱。"},{"label":"生卒年/活跃年代","value":"1872年出生，1955年去世；魏玛政治核心期为1919—1932年。"},{"label":"身份/职务","value":"SPD政治家，长期任普鲁士自由邦总理。"},{"label":"关键贡献/作为","value":"维持SPD、中央党和自由派在普鲁士的稳定联盟；推动行政、警察和教育体系相对共和化；在魏玛中央政府频繁更替时保持州级稳定。"},{"label":"核心主张/立场","value":"支持议会民主、共和秩序和务实改革，重视用普鲁士州政府抵抗极端主义。"},{"label":"为什么重要","value":"普鲁士面积和人口占德国多数，布劳恩政府的稳定性让魏玛共和国在地方层面仍有一条重要民主防线。"},{"label":"争议/评价","value":"普鲁士政府虽比中央稳定，但对官僚、司法和军警系统的改造仍不彻底，1932年面对中央接管时抵抗有限。"},{"label":"关联事件","value":"魏玛普鲁士自由邦；1932年普鲁士政变。"},{"label":"出处","value":"Encyclopaedia Britannica: Otto Braun；DHM/LeMO and Weimar Republic references on Prussia；Bundesarchiv: Akten der Reichskanzlei。"}],"relationItems":["← 前因：魏玛普鲁士自由邦","↔ 相关：卡尔·塞韦林","↔ 相关：德国社会民主党（SPD）","→ 后果：1932年普鲁士政变"],"relations":[{"text":"← 前因：魏玛普鲁士自由邦","id":"card111"},{"text":"↔ 相关：卡尔·塞韦林","id":"card161"},{"text":"↔ 相关：德国社会民主党（SPD）","id":"extra628"},{"text":"→ 后果：1932年普鲁士政变","id":"card41"}],"source":"history","id":"card160"},{"title":"卡尔·塞韦林","level":"C","type":"人物卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1875—1952年；魏玛时期活跃于1919—1932年","place":"德国；普鲁士和柏林","summary":"卡尔·塞韦林是魏玛社民党治安改革的代表，试图把普鲁士警察变成共和秩序工具。","fields":[{"label":"标题","value":"卡尔·塞韦林"},{"label":"分级","value":"C"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1875—1952年；魏玛时期活跃于1919—1932年"},{"label":"地点","value":"德国；普鲁士和柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"卡尔·塞韦林是魏玛社民党治安改革的代表，试图把普鲁士警察变成共和秩序工具。"},{"label":"生卒年/活跃年代","value":"1875年出生，1952年去世；魏玛关键任职在1920年代至1932年。"},{"label":"身份/职务","value":"SPD政治家，曾任普鲁士内政部长和德国中央政府内政部长。"},{"label":"关键贡献/作为","value":"推动普鲁士警察和内政系统改革，压制政治暴力，维护共和国秩序；在普鲁士政变时是被中央政府解除权力的核心人物之一。"},{"label":"核心主张/立场","value":"主张共和法治和强有力的民主国家机器，反对极右翼与极左翼街头暴力。"},{"label":"为什么重要","value":"他体现魏玛民主并非没有国家防卫意识，而是州级共和力量最终被总统政府和保守派中央权力压倒。"},{"label":"争议/评价","value":"塞韦林对共产主义和右翼暴力都采取强硬手段，因此既被右派仇视，也被KPD视为镇压工人的社民党官僚。"},{"label":"关联事件","value":"魏玛柏林“血腥五月”；1932年普鲁士政变。"},{"label":"出处","value":"Friedrich-Ebert-Stiftung: Carl Severing；Bundesarchiv: Akten der Reichskanzlei, Severing；Zeit historical profile: Carl Severing。"}],"relationItems":["← 前因：魏玛普鲁士自由邦","↔ 相关：奥托·布劳恩","↔ 相关：魏玛柏林“血腥五月”","→ 后果：1932年普鲁士政变"],"relations":[{"text":"← 前因：魏玛普鲁士自由邦","id":"card111"},{"text":"↔ 相关：奥托·布劳恩","id":"card160"},{"text":"↔ 相关：魏玛柏林“血腥五月”","id":"card147"},{"text":"→ 后果：1932年普鲁士政变","id":"card41"}],"source":"history","id":"card161"},{"title":"德国巴本“男爵内阁”","level":"B","type":"组织/机构卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1932年6月—1932年12月","place":"德国；柏林","summary":"巴本“男爵内阁”是保守精英脱离议会基础直接执政的实验，进一步打开希特勒上台道路。","fields":[{"label":"标题","value":"德国巴本“男爵内阁”"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1932年6月—1932年12月"},{"label":"地点","value":"德国；柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"巴本“男爵内阁”是保守精英脱离议会基础直接执政的实验，进一步打开希特勒上台道路。"},{"label":"性质/类型","value":"由兴登堡任命、缺乏国会多数的保守总统内阁，成员多来自贵族、官僚和保守精英。"},{"label":"成立/解散时间","value":"1932年6月1日组建，1932年12月被施莱歇尔内阁取代。"},{"label":"核心目标/宗旨","value":"削弱议会民主和普鲁士社民党防线，争取利用纳粹群众力量支持保守威权重建。"},{"label":"关键人物","value":"弗朗茨·冯·巴本、库尔特·冯·施莱歇尔、兴登堡、威廉·冯·盖尔等。"},{"label":"关键行动/事件","value":"解除SA禁令，解散国会，推动1932年7月国会选举，发动普鲁士政变，并试图以总统权力维持统治。"},{"label":"为什么重要","value":"它标志着保守派不再只是防守共和秩序，而是主动拆解共和制度，以为能控制纳粹。"},{"label":"争议/局限","value":"内阁几乎没有社会基础，既无法控制国会，也无法真正控制纳粹，最终被施莱歇尔和希特勒-巴本交易取代。"},{"label":"出处","value":"Encyclopaedia Britannica: Weimar Republic, Papen and Schleicher；Encyclopaedia Britannica: Franz von Papen；German History in Documents and Images: The Papen Cabinet, June 3, 1932。"}],"relationItems":["← 前因：布吕宁内阁倒台","↔ 相关：弗朗茨·冯·巴本","↔ 相关：1932年纳粹冲锋队禁令与解除","→ 后果：1932年普鲁士政变","→ 后果：1932年7月德国国会选举"],"relations":[{"text":"← 前因：布吕宁内阁倒台","id":"card158"},{"text":"↔ 相关：弗朗茨·冯·巴本","id":"card40"},{"text":"↔ 相关：1932年纳粹冲锋队禁令与解除","id":"extra96"},{"text":"→ 后果：1932年普鲁士政变","id":"card41"},{"text":"→ 后果：1932年7月德国国会选举","id":"card46"}],"source":"history","id":"card162"},{"title":"格雷戈尔·施特拉塞","level":"C","type":"人物卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1892—1934年；纳粹党内高峰在1920年代末至1932年","place":"德国；纳粹党全国组织网络","summary":"格雷戈尔·施特拉塞是纳粹党早期组织扩张核心人物，也是1932年党内潜在分裂的中心。","fields":[{"label":"标题","value":"格雷戈尔·施特拉塞"},{"label":"分级","value":"C"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1892—1934年；纳粹党内高峰在1920年代末至1932年"},{"label":"地点","value":"德国；纳粹党全国组织网络"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"格雷戈尔·施特拉塞是纳粹党早期组织扩张核心人物，也是1932年党内潜在分裂的中心。"},{"label":"生卒年/活跃年代","value":"1892年出生，1934年在长刀之夜被杀。"},{"label":"身份/职务","value":"纳粹党高级干部和组织者，曾负责党组织建设，在1930年代初影响力仅次于希特勒集团核心。"},{"label":"关键贡献/作为","value":"推动纳粹党在北德和全国范围扩张，强化党组织和宣传网络；1932年与施莱歇尔接触，引发党内权力危机。"},{"label":"核心主张/立场","value":"强调纳粹运动中的反资本主义和社会民粹色彩，但仍服从民族主义和反犹政治框架。"},{"label":"为什么重要","value":"他说明纳粹党并非天然铁板一块；希特勒在1932年能压服施特拉塞，是纳粹夺权前内部权威确立的重要一步。"},{"label":"争议/评价","value":"施特拉塞常被误读为“左翼纳粹”，但他的政治并非民主社会主义，而是民族主义、反自由主义和种族主义框架内的社会激进动员。"},{"label":"关联事件","value":"施莱歇尔-施特拉塞分裂尝试；纳粹长刀之夜。"},{"label":"出处","value":"Encyclopaedia Britannica: Gregor Strasser；Encyclopaedia Britannica: Were the Nazis Socialists?；Nazi Party historical references on party organization。"}],"relationItems":["← 前因：纳粹党禁令与重建","↔ 相关：纳粹党成立","↔ 相关：德国施莱歇尔“横向阵线”计划","→ 后果：施莱歇尔-施特拉塞分裂尝试"],"relations":[{"text":"← 前因：纳粹党禁令与重建","id":"card132"},{"text":"↔ 相关：纳粹党成立","id":"extra92"},{"text":"↔ 相关：德国施莱歇尔“横向阵线”计划","id":"card164"},{"text":"→ 后果：施莱歇尔-施特拉塞分裂尝试","id":"card165"}],"source":"history","id":"card163"},{"title":"德国施莱歇尔“横向阵线”计划","level":"C","type":"概念/思潮卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1932年，施莱歇尔内阁期间达到高潮","place":"德国；柏林总统府、国防军和政党谈判场域","summary":"施莱歇尔“横向阵线”计划试图绕过传统党派，把工会、军方和纳粹温和派拼成总统政府基础。","fields":[{"label":"标题","value":"德国施莱歇尔“横向阵线”计划"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1932年，施莱歇尔内阁期间达到高潮"},{"label":"地点","value":"德国；柏林总统府、国防军和政党谈判场域"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"施莱歇尔“横向阵线”计划试图绕过传统党派，把工会、军方和纳粹温和派拼成总统政府基础。"},{"label":"核心主张/思路","value":"通过吸纳ADGB工会、基督教工会、农业利益和格雷戈尔·施特拉塞派纳粹，建立跨左右的社会支持。"},{"label":"提出者/代表人物（可选）","value":"库尔特·冯·施莱歇尔。"},{"label":"它从何而来","value":"巴本政府缺乏国会基础，纳粹又拒绝只做辅助力量，施莱歇尔希望拆分纳粹并给总统政府找到新的群众支撑。"},{"label":"典型表现","value":"与工会和施特拉塞接触，暗示就业创造和社会政策让步，同时保留总统内阁和国防军影响。"},{"label":"为什么重要","value":"它是魏玛最后阶段阻止希特勒的一次保守技术性方案，但方案本身仍不是真正恢复议会民主。"},{"label":"争议/局限","value":"计划过分依赖幕后谈判和分裂对手，既得不到兴登堡充分信任，也未能真正拆开纳粹党。"},{"label":"出处","value":"Landesbildungsserver Baden-Württemberg: Kabinett Kurt von Schleicher；Encyclopaedia Britannica: Weimar Republic, Papen and Schleicher；Encyclopaedia Britannica: Gregor Strasser。"}],"relationItems":["← 前因：德国巴本“男爵内阁”","↔ 相关：库尔特·冯·施莱歇尔","↔ 相关：格雷戈尔·施特拉塞","↔ 相关：德国自由工会总联盟","→ 后果：施莱歇尔-施特拉塞分裂尝试"],"relations":[{"text":"← 前因：德国巴本“男爵内阁”","id":"card162"},{"text":"↔ 相关：库尔特·冯·施莱歇尔","id":"card42"},{"text":"↔ 相关：格雷戈尔·施特拉塞","id":"card163"},{"text":"↔ 相关：德国自由工会总联盟","id":"card95"},{"text":"→ 后果：施莱歇尔-施特拉塞分裂尝试","id":"card165"}],"source":"history","id":"card164"},{"title":"施莱歇尔-施特拉塞分裂尝试","level":"C","type":"事件卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1932年12月","place":"德国；柏林和纳粹党领导层","summary":"施莱歇尔拉拢施特拉塞失败，使纳粹党没有在夺权前分裂，希特勒的谈判地位反而巩固。","fields":[{"label":"标题","value":"施莱歇尔-施特拉塞分裂尝试"},{"label":"分级","value":"C"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1932年12月"},{"label":"地点","value":"德国；柏林和纳粹党领导层"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"施莱歇尔拉拢施特拉塞失败，使纳粹党没有在夺权前分裂，希特勒的谈判地位反而巩固。"},{"label":"参与者","value":"库尔特·冯·施莱歇尔、格雷戈尔·施特拉塞、阿道夫·希特勒、纳粹党国会党团和总统府圈子。"},{"label":"发生了什么","value":"施莱歇尔试图让施特拉塞进入政府或带走一部分纳粹力量，以瓦解希特勒对总理职位的强硬要求。希特勒迅速压制党内动摇者，迫使施特拉塞辞去党内职务。纳粹党没有形成足以支撑施莱歇尔的分裂派。"},{"label":"为什么重要","value":"它显示希特勒在1932年底仍面临真实党内危机，但也证明他的个人控制力已足以压过组织派挑战。"},{"label":"前因","value":"巴本政府失败后，施莱歇尔需要在不任命希特勒为总理的前提下为总统内阁寻找群众基础；纳粹党在选举和财政压力下也出现过组织路线分歧。"},{"label":"后果","value":"施莱歇尔失去分裂纳粹的机会，巴本随后与希特勒重新接触，促成1933年1月的保守派-纳粹组阁交易。"},{"label":"出处","value":"Encyclopaedia Britannica: Gregor Strasser；Landesbildungsserver Baden-Württemberg: Kabinett Kurt von Schleicher；Encyclopaedia Britannica: Weimar Republic, Papen and Schleicher。"}],"relationItems":["← 前因：德国施莱歇尔“横向阵线”计划","↔ 相关：格雷戈尔·施特拉塞","↔ 相关：魏玛施莱歇尔内阁","→ 后果：希特勒出任德国总理"],"relations":[{"text":"← 前因：德国施莱歇尔“横向阵线”计划","id":"card164"},{"text":"↔ 相关：格雷戈尔·施特拉塞","id":"card163"},{"text":"↔ 相关：魏玛施莱歇尔内阁","id":"card43"},{"text":"→ 后果：希特勒出任德国总理","id":"card71"}],"source":"history","id":"card165"},{"title":"1932年日内瓦裁军会议德国平权争议","level":"C","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1932年2月—12月","place":"瑞士日内瓦","summary":"1932年日内瓦裁军会议中，德国以“平等权利”挑战凡尔赛军备限制，成为修约外交的核心议题。","fields":[{"label":"标题","value":"1932年日内瓦裁军会议德国平权争议"},{"label":"分级","value":"C"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1932年2月—12月"},{"label":"地点","value":"瑞士日内瓦"},{"label":"主要国家","value":"德国；英国；法国；意大利；美国"},{"label":"一句话概括","value":"1932年日内瓦裁军会议中，德国以“平等权利”挑战凡尔赛军备限制，成为修约外交的核心议题。"},{"label":"参与者","value":"德国代表团，英国、法国、意大利、美国等国代表，一战后国际联盟裁军会议机制。"},{"label":"发生了什么","value":"世界裁军会议召开后，德国要求在军备问题上获得与其他大国同等地位，实质上要求解除凡尔赛条约对德国单方面限制。法国强调安全保障，英国和美国则试图推动妥协。德国因要求未获满足一度退出谈判，12月五国声明原则上承认德国及其他被条约裁军国家在安全体系中的平等权利。"},{"label":"为什么重要","value":"这说明魏玛末期德国修约目标已经从赔款转向军备平等，为纳粹上台后公开扩军提供了外交前奏。"},{"label":"前因","value":"德国通过洛迦诺和一战后国际联盟重返大国外交后，仍受凡尔赛军事条款限制；大萧条又削弱各国维持旧秩序的意愿。"},{"label":"后果","value":"平权原则未能形成稳定裁军协议，希特勒上台后德国在1933年退出裁军会议和一战后国际联盟，转向公开重整军备。"},{"label":"出处","value":"Encyclopaedia Britannica: World Disarmament Conference；Office of the Historian, FRUS 1932: Five Power Declaration；Library of Congress: Disarmament Conference, Geneva。"}],"relationItems":["← 前因：《凡尔赛和约》","↔ 相关：德国赔款洛桑会议","↔ 相关：纳粹德国再武装","→ 后果：纳粹德国退出一战后国际联盟"],"relations":[{"text":"← 前因：《凡尔赛和约》","id":"card59"},{"text":"↔ 相关：德国赔款洛桑会议","id":"card159"},{"text":"↔ 相关：纳粹德国再武装","id":"extra119"},{"text":"→ 后果：纳粹德国退出一战后国际联盟","id":"extra155"}],"source":"history","id":"card166"},{"title":"魏玛《少年法院法》","level":"C","type":"制度/文本卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1923年2月16日","place":"德国","summary":"魏玛《少年法院法》建立独立少年刑事司法框架，把未成年人犯罪纳入教育和保护逻辑。","fields":[{"label":"标题","value":"魏玛《少年法院法》"},{"label":"分级","value":"C"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1923年2月16日"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"魏玛《少年法院法》建立独立少年刑事司法框架，把未成年人犯罪纳入教育和保护逻辑。"},{"label":"制定方/签署方","value":"魏玛共和国立法机关和司法行政系统。"},{"label":"主要内容","value":"将少年刑事案件与成人刑事司法区分开，强调教育、保护和专门少年法院程序。"},{"label":"它试图解决什么问题","value":"战后贫困、家庭破裂和城市青少年问题突出，传统刑罚难以处理未成年人犯罪和社会风险。"},{"label":"为什么重要","value":"它是德国现代少年司法的重要起点，也连接魏玛福利国家和司法改革。"},{"label":"争议/局限","value":"魏玛财政和行政能力有限，少年司法改革的实际落实受地方资源和政治动荡影响。"},{"label":"造成的影响","value":"少年司法的教育理念长期影响德国法制，纳粹时期则对其进行更威权化改造。"},{"label":"出处","value":"Hessische Landeszentrale für politische Bildung: 100 Jahre Jugendgerichtsgesetz；Institut für Zeitgeschichte: Jugendgerichtsgesetz vom 16. Februar 1923；Nomos: Die Praxis des Jugendstrafrechts in der Weimarer Republik。"}],"relationItems":["← 前因：魏玛《全国青少年福利法》","↔ 相关：魏玛柏林“戒指会”犯罪网络","→ 后果：纳粹特别法院"],"relations":[{"text":"← 前因：魏玛《全国青少年福利法》","id":"card73"},{"text":"↔ 相关：魏玛柏林“戒指会”犯罪网络","id":"card74"},{"text":"→ 后果：纳粹特别法院","id":"extra140"}],"source":"history","id":"card167"},{"title":"魏玛《劳动法院法》","level":"C","type":"制度/文本卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1926年通过，1927年7月1日生效","place":"德国","summary":"魏玛《劳动法院法》建立统一劳动法院体系，使劳资争议进入专门司法渠道。","fields":[{"label":"标题","value":"魏玛《劳动法院法》"},{"label":"分级","value":"C"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1926年通过，1927年7月1日生效"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"魏玛《劳动法院法》建立统一劳动法院体系，使劳资争议进入专门司法渠道。"},{"label":"制定方/签署方","value":"魏玛共和国立法机关。"},{"label":"主要内容","value":"建立分级劳动法院体系，处理雇佣、集体劳动关系和劳资争议等案件。"},{"label":"它试图解决什么问题","value":"工业社会中的劳动合同、工会、雇主和罢工争议需要比普通民事法院更专业的处理机制。"},{"label":"为什么重要","value":"它是魏玛社会国家和法治国家结合的节点，让劳资冲突不只在街头、罢工和政治斗争中解决。"},{"label":"争议/局限","value":"劳动法院无法消除经济危机和阶级冲突，只能在制度上提供争议处理框架。"},{"label":"造成的影响","value":"德国劳动司法传统得到制度化，战后西德劳动法院体系也继承了这一专业化方向。"},{"label":"出处","value":"NRW Justiz: Geschichte der Arbeitsgerichtsbarkeit；Hessen Arbeitsgerichtsbarkeit: Geschichte der deutschen Arbeitsgerichtsbarkeit；Bundesarbeitsgericht historical brochure。"}],"relationItems":["← 前因：德国1920年企业委员会法","↔ 相关：德国自由工会总联盟","↔ 相关：魏玛失业保险财政争议"],"relations":[{"text":"← 前因：德国1920年企业委员会法","id":"card115"},{"text":"↔ 相关：德国自由工会总联盟","id":"card95"},{"text":"↔ 相关：魏玛失业保险财政争议","id":"card148"}],"source":"history","id":"card168"},{"title":"恩斯特·根纳特","level":"C","type":"人物卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1880—1939年；魏玛时期为职业高峰","place":"德国柏林","summary":"恩斯特·根纳特是柏林刑警和凶杀侦查现代化代表，把犯罪调查变成更专业化的警务实践。","fields":[{"label":"标题","value":"恩斯特·根纳特"},{"label":"分级","value":"C"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1880—1939年；魏玛时期为职业高峰"},{"label":"地点","value":"德国柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"恩斯特·根纳特是柏林刑警和凶杀侦查现代化代表，把犯罪调查变成更专业化的警务实践。"},{"label":"生卒年/活跃年代","value":"1880年出生，1939年去世；1920年代在柏林刑事警察中影响突出。"},{"label":"身份/职务","value":"柏林刑事警察官员，凶杀侦查专家。"},{"label":"关键贡献/作为","value":"改革柏林凶杀侦查流程，重视案发现场、档案、统计、快速出警和专业分工。"},{"label":"核心主张/立场","value":"以专业调查、经验积累和组织化流程提高破案能力。"},{"label":"为什么重要","value":"他体现魏玛时期犯罪现代性的一面：城市犯罪增加的同时，刑侦技术和警察组织也在现代化。"},{"label":"争议/评价","value":"警察专业化可以提高侦查效率，但魏玛警察也处在政治暴力、社会偏见和后来纳粹接管的阴影下。"},{"label":"关联事件","value":"魏玛柏林凶杀科改革。"},{"label":"出处","value":"Berlin Polizei: Geschichte der Berliner Polizei in der Weimarer Republik；Rheinpfalz: Ernst Gennat und moderne Polizeiarbeit；Humboldt University dissertation on Berliner Kriminalpolizei。"}],"relationItems":["← 前因：魏玛柏林“戒指会”犯罪网络","→ 后果：魏玛柏林凶杀科改革","↔ 相关：彼得·库尔滕连环杀人案"],"relations":[{"text":"← 前因：魏玛柏林“戒指会”犯罪网络","id":"card74"},{"text":"→ 后果：魏玛柏林凶杀科改革","id":"card170"},{"text":"↔ 相关：彼得·库尔滕连环杀人案","id":"card76"}],"source":"history","id":"card169"},{"title":"魏玛柏林凶杀科改革","level":"C","type":"概念/思潮卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1920年代，1926年后影响突出","place":"德国柏林","summary":"魏玛柏林凶杀科改革把凶杀案侦查专业化，形成现代都市刑警的典型形象。","fields":[{"label":"标题","value":"魏玛柏林凶杀科改革"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1920年代，1926年后影响突出"},{"label":"地点","value":"德国柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"魏玛柏林凶杀科改革把凶杀案侦查专业化，形成现代都市刑警的典型形象。"},{"label":"核心主张/思路","value":"凶杀侦查需要专门团队、案发现场保护、档案管理、快速机动和跨案比较，而不是临时拼凑。"},{"label":"提出者/代表人物（可选）","value":"恩斯特·根纳特。"},{"label":"它从何而来","value":"魏玛大都市犯罪、媒体关注和连环杀人案增加，迫使警察改进调查方法。"},{"label":"典型表现","value":"专门凶杀侦查部门、案件卡片、现场流程、机动侦查车辆和更系统的嫌疑人分析。"},{"label":"为什么重要","value":"它让犯罪专题不只停留在猎奇案件，而能看到现代国家如何用技术和组织回应城市风险。"},{"label":"争议/局限","value":"刑侦现代化并不等于警察民主化，警察组织后来也可被纳粹国家吸收和重组。"},{"label":"出处","value":"Berlin Polizei: Weimarer Republik；Rheinpfalz: Der Mann, der die moderne Polizeiarbeit erfand；Humboldt University: Die Berliner Kriminalpolizei in Republik und Nationalsozialismus。"}],"relationItems":["← 前因：恩斯特·根纳特","↔ 相关：哈曼连环杀人案","↔ 相关：彼得·库尔滕连环杀人案","→ 后果：纳粹德国帝国刑事警察局"],"relations":[{"text":"← 前因：恩斯特·根纳特","id":"card169"},{"text":"↔ 相关：哈曼连环杀人案","id":"card75"},{"text":"↔ 相关：彼得·库尔滕连环杀人案","id":"card76"},{"text":"→ 后果：纳粹德国帝国刑事警察局","id":"extra281"}],"source":"history","id":"card170"},{"title":"魏玛德国《帝国小学法》","level":"B","type":"制度/文本卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1920年","place":"魏玛共和国","summary":"1920年《帝国小学法》确立共同四年小学，削弱阶层隔离式预备学校，是魏玛教育改革的核心成果之一。","fields":[{"label":"标题","value":"魏玛德国《帝国小学法》"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1920年"},{"label":"地点","value":"魏玛共和国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1920年《帝国小学法》确立共同四年小学，削弱阶层隔离式预备学校，是魏玛教育改革的核心成果之一。"},{"label":"制定方/签署方","value":"魏玛共和国中央立法机关与教育行政体系。"},{"label":"主要内容","value":"法律推动设立所有儿童共同就读的四年制基础小学，取代上层家庭子女绕开普通小学、直接进入中学预备轨道的旧安排。"},{"label":"它试图解决什么问题","value":"帝国时期教育体系把阶层差异过早转化为学校轨道差异，魏玛改革者希望用共同基础学校延缓分流，提升教育公平和共和公民意识。"},{"label":"为什么重要","value":"它是魏玛社会改革中少数真正制度化的教育成果，把民主共和国的平等理念写入儿童教育结构。"},{"label":"争议/局限","value":"四年共同小学之后仍然存在中学分流，宗教学校、地方教育权和阶层资源差异继续限制改革效果。"},{"label":"造成的影响","value":"共同小学成为德国教育体系的重要基础，但也保留了后续分轨结构，形成“平等开端”和“早期分流”并存的魏玛教育格局。"},{"label":"出处","value":"German History in Documents and Images, Volksschule Enrollment (1911-1941)；Bundesarchiv, Akten der Reichskanzlei: Grundschulgesetz。"}],"relationItems":["← 前因：魏玛宪法","→ 后果：魏玛德国学校改革运动","↔ 相关：德意志帝国古典文理中学","↔ 相关：德意志帝国实科中学","↔ 同时期参考：欧洲战后教育改革"],"relations":[{"text":"← 前因：魏玛宪法","id":"card11"},{"text":"→ 后果：魏玛德国学校改革运动","id":"card172"},{"text":"↔ 相关：德意志帝国古典文理中学","id":"extra818"},{"text":"↔ 相关：德意志帝国实科中学","id":"extra819"}],"source":"history","id":"card171"},{"title":"魏玛德国学校改革运动","level":"C","type":"概念/思潮卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"1919—1933年","place":"魏玛共和国","summary":"魏玛学校改革运动试图把共和国、公民教育和教育公平带进学校，但受地方权力、宗教争议和政治分裂限制。","fields":[{"label":"标题","value":"魏玛德国学校改革运动"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1919—1933年"},{"label":"地点","value":"魏玛共和国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"魏玛学校改革运动试图把共和国、公民教育和教育公平带进学校，但受地方权力、宗教争议和政治分裂限制。"},{"label":"核心主张/思路","value":"学校应减少阶层隔离，培养共和国公民，而不是只复制帝国时期的等级、服从和古典精英文化。"},{"label":"提出者/代表人物（可选）","value":"社会民主党教育改革者、进步教育家、地方教育行政人员和教师组织。"},{"label":"它从何而来","value":"1918年革命和魏玛宪法带来民主化期待，教育被视为塑造共和政治文化、弥合阶层差距和摆脱帝国权威主义的重要工具。"},{"label":"典型表现","value":"共同小学、活动学校和劳动学校理念、公民教育、教师培训改革、地方实验学校，以及围绕宗教学校和统一学校的激烈争论。"},{"label":"为什么重要","value":"它揭示魏玛共和国的问题不只是政党和经济危机，也包括共和国能否培养支持自身制度的下一代。"},{"label":"争议/局限","value":"教育权主要仍在各邦和地方，中央改革空间有限；保守派、教会和中产阶层担心统一学校削弱家庭与宗教控制，改革推进并不彻底。"},{"label":"出处","value":"German History in Documents and Images, Volksschule Enrollment (1911-1941)；Britannica, Education: Nazi Germany and modern German education context。"}],"relationItems":["← 前因：魏玛德国《帝国小学法》","→ 后果：纳粹德国学校课程纳粹化","↔ 相关：魏玛宪法","↔ 相关：魏玛德国青少年福利法","↔ 同时期参考：杜威教育思想"],"relations":[{"text":"← 前因：魏玛德国《帝国小学法》","id":"card171"},{"text":"→ 后果：纳粹德国学校课程纳粹化","id":"extra286"},{"text":"↔ 相关：魏玛宪法","id":"card11"}],"source":"history","id":"card172"},{"title":"魏玛德国帝国广播公司","level":"B","type":"组织/机构卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1925—1945年","place":"柏林及德国各地区广播公司","summary":"帝国广播公司把魏玛地方广播纳入全国网络，后来被纳粹接管为国家宣传体系的一部分。","fields":[{"label":"标题","value":"魏玛德国帝国广播公司"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1925—1945年"},{"label":"地点","value":"柏林及德国各地区广播公司"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"帝国广播公司把魏玛地方广播纳入全国网络，后来被纳粹接管为国家宣传体系的一部分。"},{"label":"性质/类型","value":"全国性广播网络和控股/协调机构。"},{"label":"成立/解散时间","value":"1925年在柏林成立；纳粹时期继续存在并被宣传部控制，战后清算。"},{"label":"核心目标/宗旨","value":"协调各地区广播公司、技术标准、节目交换和全国广播管理，使广播从地方实验转向全国媒介。"},{"label":"关键人物（可选）","value":"汉斯·布雷多等广播行政人物；1933年后与戈培尔宣传体系相关。"},{"label":"关键行动/事件","value":"整合魏玛各地区广播台；1933年后纳入纳粹宣传部影响，广播从文化和信息媒介进一步转变为政治动员工具。"},{"label":"为什么重要","value":"它是理解广播如何从新技术变成国家政治工具的关键机构，连接魏玛广播文化、纳粹宣传和战后德国广播重建。"},{"label":"争议/局限","value":"魏玛时期广播 already 受国家邮政、电信和政治监管影响，公共性有限；纳粹接管后更直接服务一党宣传。"},{"label":"出处","value":"Deutsches Rundfunkarchiv, Organisation: Weimarer Rundfunk；Reichs-Rundfunk-Gesellschaft m.b.H. (RRG) archival material。"}],"relationItems":["← 前因：魏玛广播文化","→ 后果：纳粹德国人民收音机","↔ 相关：纳粹德国帝国宣传部","↔ 相关：纳粹宣传机器","↔ 同时期参考：英国BBC"],"relations":[{"text":"← 前因：魏玛广播文化","id":"card80"},{"text":"→ 后果：纳粹德国人民收音机","id":"extra285"},{"text":"↔ 相关：纳粹德国帝国宣传部","id":"extra146"},{"text":"↔ 相关：纳粹宣传机器","id":"extra94"}],"source":"history","id":"card173"},{"title":"魏玛德国乌尔施泰因出版社","level":"C","type":"组织/机构卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1877年创立；魏玛时期达到重要影响","place":"柏林","summary":"乌尔施泰因出版社是魏玛柏林大众出版和报刊商业化的代表，连接报纸、杂志、小说和现代都市消费文化。","fields":[{"label":"标题","value":"魏玛德国乌尔施泰因出版社"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1877年创立；魏玛时期达到重要影响"},{"label":"地点","value":"柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"乌尔施泰因出版社是魏玛柏林大众出版和报刊商业化的代表，连接报纸、杂志、小说和现代都市消费文化。"},{"label":"性质/类型","value":"大型报刊与图书出版集团。"},{"label":"成立/解散时间","value":"1877年由利奥波德·乌尔施泰因创立；1903年扩展图书出版，魏玛时期影响巨大；1930年代遭纳粹压力和“雅利安化”。"},{"label":"核心目标/宗旨","value":"通过报纸、杂志、图书和通俗出版满足城市大众读者、商业广告和现代文化消费需求。"},{"label":"关键人物（可选）","value":"利奥波德·乌尔施泰因及乌尔施泰因家族；编辑和出版经营团队。"},{"label":"关键行动/事件","value":"经营《柏林画报》等大众媒体；出版现代文学、纪实和通俗读物；魏玛晚期因犹太背景和自由派形象成为纳粹攻击对象。"},{"label":"为什么重要","value":"它说明魏玛文化不是只由先锋艺术构成，也由大规模商业出版、广告、摄影和读者市场塑造。"},{"label":"争议/局限","value":"商业出版容易被批评为迎合大众趣味；纳粹上台后，出版社所有权和编辑路线受到政治暴力与种族政策冲击。"},{"label":"出处","value":"Ullstein Verlag, Verlagsgeschichte；Utrecht University, The ‘Ullstein Spirit’。"}],"relationItems":["← 前因：德意志帝国《帝国报刊法》","→ 后果：纳粹德国《报刊编辑法》","↔ 相关：魏玛德国插图新闻杂志文化","↔ 相关：魏玛“新女性”","↔ 同时期参考：美国大众杂志业"],"relations":[{"text":"← 前因：德意志帝国《帝国报刊法》","id":"extra816"},{"text":"→ 后果：纳粹德国《报刊编辑法》","id":"extra151"},{"text":"↔ 相关：魏玛德国插图新闻杂志文化","id":"card175"},{"text":"↔ 相关：魏玛“新女性”","id":"card32"}],"source":"history","id":"card174"},{"title":"魏玛德国插图新闻杂志文化","level":"C","type":"概念/思潮卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1919—1933年","place":"柏林及德国大城市","summary":"魏玛插图新闻杂志用照片、广告和都市报道塑造大众视觉经验，是现代媒体文化的重要组成部分。","fields":[{"label":"标题","value":"魏玛德国插图新闻杂志文化"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1919—1933年"},{"label":"地点","value":"柏林及德国大城市"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"魏玛插图新闻杂志用照片、广告和都市报道塑造大众视觉经验，是现代媒体文化的重要组成部分。"},{"label":"核心主张/思路","value":"新闻不只靠文字传递，也靠照片、版面、广告和连续视觉叙事吸引大众读者。"},{"label":"提出者/代表人物（可选）","value":"乌尔施泰因等出版集团、摄影记者、编辑和视觉设计者共同推动。"},{"label":"它从何而来","value":"战后城市读者扩大、印刷技术进步、摄影传播成本下降和大众消费文化兴起，使插图杂志成为高影响力媒介。"},{"label":"典型表现","value":"《柏林画报》等刊物报道政治、体育、明星、旅行、科学、战争记忆和都市生活；照片与广告共同形成“看见现代性”的日常经验。"},{"label":"为什么重要","value":"它让普通读者通过图像理解共和国、消费、性别角色和国际新闻，也为后来的政治宣传和视觉动员提供技术与审美基础。"},{"label":"争议/局限","value":"图像新闻可能制造猎奇和消费幻觉，也可能把复杂政治简化为视觉冲击；纳粹上台后，插图杂志被纳入更强政治控制。"},{"label":"出处","value":"arthistoricum.net, Illustrated Magazines of the Weimar Republic；MoMA Object:Photo, Berliner Illustrirte Zeitung。"}],"relationItems":["← 前因：魏玛德国乌尔施泰因出版社","→ 后果：纳粹宣传机器","↔ 相关：德国表现主义电影","↔ 相关：魏玛广播文化","↔ 同时期参考：美国《生活》杂志"],"relations":[{"text":"← 前因：魏玛德国乌尔施泰因出版社","id":"card174"},{"text":"→ 后果：纳粹宣传机器","id":"extra94"},{"text":"↔ 相关：德国表现主义电影","id":"card78"},{"text":"↔ 相关：魏玛广播文化","id":"card80"}],"source":"history","id":"card175"},{"title":"魏玛包豪斯迁往德绍","level":"B","type":"事件卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1925年","place":"魏玛、德绍","summary":"1925年包豪斯因图林根保守政治压力离开魏玛、迁往德绍，进入其最具国际影响力的发展阶段。","fields":[{"label":"标题","value":"魏玛包豪斯迁往德绍"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1925年"},{"label":"地点","value":"魏玛、德绍"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1925年包豪斯因图林根保守政治压力离开魏玛、迁往德绍，进入其最具国际影响力的发展阶段。"},{"label":"参与者","value":"瓦尔特·格罗皮乌斯、包豪斯师生、图林根州政府、德绍市政府。"},{"label":"发生了什么","value":"包豪斯在魏玛创立后长期受到保守派和民族主义者攻击，被指责为激进、左翼和“非传统”的艺术学校。1924—1925年图林根政治格局变化后，学校经费和政治支持遭削弱，格罗皮乌斯等人决定离开魏玛。德绍市接纳学校，并委托建设新校舍和教师住宅，使包豪斯从地方争议中的艺术学校转入更系统的设计、建筑和工业合作阶段。"},{"label":"为什么重要","value":"迁校使包豪斯的教育理念、建筑空间和工业设计实践结合得更紧密，德绍阶段成为现代主义建筑和设计史中的关键节点。"},{"label":"前因","value":"包豪斯在魏玛时期已经形成现代设计和工艺结合的理念，但它依赖地方政府财政支持；魏玛共和国地方政治右转后，保守派把学校视为文化激进主义象征，削弱其继续存在的条件。"},{"label":"后果","value":"德绍阶段产生包豪斯校舍、教师住宅和更成熟的设计课程；但它也继续遭遇右翼政治压力，1932年又迁往柏林，1933年最终被迫关闭。"},{"label":"出处","value":"Stiftung Bauhaus Dessau, Chronologie；DHM LeMO, Bauhaus。"}],"relationItems":["← 前因：魏玛德国学校改革运动","→ 后果：纳粹德国焚书运动","↔ 相关：德国表现主义电影","↔ 相关：新法兰克福住房项目","↔ 同时期参考：欧洲现代主义建筑"],"relations":[{"text":"← 前因：魏玛德国学校改革运动","id":"card172"},{"text":"→ 后果：纳粹德国焚书运动","id":"extra284"},{"text":"↔ 相关：德国表现主义电影","id":"card78"},{"text":"↔ 相关：新法兰克福住房项目","id":"card82"}],"source":"history","id":"card176"},{"title":"魏玛德国女性高等教育扩张","level":"C","type":"概念/思潮卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"1919—1933年","place":"魏玛共和国大学城市","summary":"魏玛时期女性进入大学和专业教育更常见，但教育机会仍受到阶层、职业壁垒和性别角色期待限制。","fields":[{"label":"标题","value":"魏玛德国女性高等教育扩张"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1919—1933年"},{"label":"地点","value":"魏玛共和国大学城市"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"魏玛时期女性进入大学和专业教育更常见，但教育机会仍受到阶层、职业壁垒和性别角色期待限制。"},{"label":"核心主张/思路","value":"女性不应只被限定在家庭和辅助职业中，也可以通过高等教育进入医学、法律、教育、学术和公共文化领域。"},{"label":"提出者/代表人物（可选）","value":"女性教育运动者、职业女性组织、大学中的女性学生群体。"},{"label":"它从何而来","value":"帝国晚期各邦逐步开放女性大学注册，1918年后女性获得政治权利，魏玛共和国的城市文化和职业结构扩大了女性受教育空间。"},{"label":"典型表现","value":"更多女性进入大学和专业学校，成为医生、教师、律师助理、记者和学术研究者；“新女性”形象与受教育、就业和城市消费相互重叠。"},{"label":"为什么重要","value":"它把魏玛性别史从服装和娱乐扩展到制度层面，说明女性现代性依赖教育资格、职业市场和公民权利共同支撑。"},{"label":"争议/局限","value":"女性高等教育并不等于平等就业。许多专业岗位仍存在性别歧视，经济危机时女性就业还常被批评为挤占男性岗位。"},{"label":"出处","value":"German History in Documents and Images, Female University Students (1908)；The Weimar Republic Sourcebook, University of California Press overview。"}],"relationItems":["← 前因：德意志帝国女性大学入学开放","→ 后果：纳粹德国学校课程纳粹化","↔ 相关：魏玛“新女性”","↔ 相关：魏玛德国学校改革运动","↔ 同时期参考：英国女性参政权运动"],"relations":[{"text":"← 前因：德意志帝国女性大学入学开放","id":"extra823"},{"text":"→ 后果：纳粹德国学校课程纳粹化","id":"extra286"},{"text":"↔ 相关：魏玛“新女性”","id":"card32"},{"text":"↔ 相关：魏玛德国学校改革运动","id":"card172"}],"source":"history","id":"card177"},{"title":"魏玛德国宗教教育妥协","level":"C","type":"制度/文本卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1919年起","place":"魏玛共和国","summary":"魏玛宪法在学校问题上保留宗教教育，同时保障良心自由，形成共和国与教会之间的折中安排。","fields":[{"label":"标题","value":"魏玛德国宗教教育妥协"},{"label":"分级","value":"C"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1919年起"},{"label":"地点","value":"魏玛共和国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"魏玛宪法在学校问题上保留宗教教育，同时保障良心自由，形成共和国与教会之间的折中安排。"},{"label":"制定方/签署方","value":"魏玛国民议会；魏玛共和国宪法体系。"},{"label":"主要内容","value":"宪法保障宗教自由，规定不得设立国教，同时在公立学校中保留宗教课安排，并把学生参与宗教教育与家长或本人意愿联系起来。"},{"label":"它试图解决什么问题","value":"共和国需要在社会民主派的世俗化诉求、天主教和新教社群的教育权诉求、各邦传统学校制度之间寻找妥协。"},{"label":"为什么重要","value":"它说明魏玛民主不是简单地把国家和宗教完全切开，而是在教派社会中用宪法妥协维持政治联盟和学校秩序。"},{"label":"争议/局限","value":"这种妥协保留了宗教学校和教派教育争议，左翼认为世俗化不彻底，教会和保守派又担心共和教育削弱宗教家庭影响。"},{"label":"造成的影响","value":"学校改革推进受限，宗教教育问题持续成为魏玛政党和地方政治中的争议点，并影响战后德国基本法中的宗教课安排。"},{"label":"出处","value":"Weimar Constitution, Articles on Religion and Education；Hans-Peter Retter, The Compromise on Religious Instruction in Elementary Schools in the Weimar Constitution。"}],"relationItems":["← 前因：魏玛宪法","→ 后果：魏玛德国学校改革运动","↔ 相关：魏玛德国《帝国小学法》","↔ 相关：德国中央党","↔ 同时期参考：法国政教分离法"],"relations":[{"text":"← 前因：魏玛宪法","id":"card11"},{"text":"→ 后果：魏玛德国学校改革运动","id":"card172"},{"text":"↔ 相关：魏玛德国《帝国小学法》","id":"card171"},{"text":"↔ 相关：德国中央党","id":"extra673"}],"source":"history","id":"card178"},{"title":"魏玛德国《帝国电影法》","level":"C","type":"制度/文本卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1920年5月12日","place":"魏玛共和国","summary":"1920年《帝国电影法》建立全国电影审查制度，使魏玛一边保障言论自由，一边对电影实行特殊监管。","fields":[{"label":"标题","value":"魏玛德国《帝国电影法》"},{"label":"分级","value":"C"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1920年5月12日"},{"label":"地点","value":"魏玛共和国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1920年《帝国电影法》建立全国电影审查制度，使魏玛一边保障言论自由，一边对电影实行特殊监管。"},{"label":"制定方/签署方","value":"魏玛共和国国民议会及相关行政机构。"},{"label":"主要内容","value":"法律要求公开放映的电影接受国家审查，设立电影审查机关，可因公共秩序、国家利益、青少年保护或道德理由限制、删改或禁止影片。"},{"label":"它试图解决什么问题","value":"电影作为新兴大众媒介传播快、影响广，政府和社会保守力量担心暴力、性、政治煽动和青少年影响，因而要求建立统一监管机制。"},{"label":"为什么重要","value":"它揭示魏玛自由主义的复杂性：宪法反对普遍审查，但电影因媒介性质被单独纳入审查体系，为纳粹后来的电影控制提供制度连续性。"},{"label":"争议/局限","value":"电影审查容易把道德保护和政治压制混在一起，艺术家和电影业则认为它限制表达与商业发行。"},{"label":"造成的影响","value":"魏玛电影在创新与审查之间发展；1934年纳粹电影法进一步集中审查权，把电影更直接纳入宣传部控制。"},{"label":"出处","value":"filmportal.de, Banning, Censoring, and Rating；Deutsche Digitale Bibliothek, Reichslichtspielgesetz vom 12. Mai 1920。"}],"relationItems":["← 前因：德国乌发电影公司","→ 后果：纳粹德国电影法（1934）","↔ 相关：德国表现主义电影","↔ 相关：魏玛德国插图新闻杂志文化","↔ 同时期参考：美国电影审查与海斯法典"],"relations":[{"text":"← 前因：德国乌发电影公司","id":"card77"},{"text":"↔ 相关：德国表现主义电影","id":"card78"},{"text":"↔ 相关：魏玛德国插图新闻杂志文化","id":"card175"}],"source":"history","id":"card179"},{"title":"魏玛德国《保护青少年免受低俗作品法》","level":"C","type":"制度/文本卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1926年12月18日生效","place":"魏玛共和国","summary":"1926年法律以保护青少年为名限制“低俗”和“污秽”出版物，暴露魏玛文化自由与道德保护之间的紧张。","fields":[{"label":"标题","value":"魏玛德国《保护青少年免受低俗作品法》"},{"label":"分级","value":"C"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1926年12月18日生效"},{"label":"地点","value":"魏玛共和国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1926年法律以保护青少年为名限制“低俗”和“污秽”出版物，暴露魏玛文化自由与道德保护之间的紧张。"},{"label":"制定方/签署方","value":"魏玛共和国国会与政府。"},{"label":"主要内容","value":"法律设立审查和登记机制，把被认定为“低俗”或“污秽”的出版物列入限制名单，限制其对青少年传播和销售。"},{"label":"它试图解决什么问题","value":"教会、保守团体和部分家长组织担心大众读物、色情材料、犯罪小说和廉价出版物腐蚀青少年，要求国家介入文化消费。"},{"label":"为什么重要","value":"这张卡说明魏玛文化争议并不只是左翼先锋艺术和右翼反现代之间的冲突，也包括民主国家内部对儿童、市场和道德边界的管理。"},{"label":"争议/局限","value":"“低俗”和“污秽”的定义高度主观，容易成为文化保守主义压制通俗文学、性表达和社会批判的工具。"},{"label":"造成的影响","value":"法律加剧围绕文化现代性、青少年保护和审查边界的争论；战后西德也重新出现类似青少年媒介保护制度。"},{"label":"出处","value":"Cambridge Core, The 1926 German Law to Protect Youth against Trash and Dirt；German Museum of Books and Writing, Censorship: When literature offends。"}],"relationItems":["← 前因：魏玛德国插图新闻杂志文化","→ 后果：纳粹德国焚书运动","↔ 相关：魏玛德国《帝国电影法》","↔ 相关：魏玛第218条堕胎争议","↔ 同时期参考：美国反淫秽出版运动"],"relations":[{"text":"← 前因：魏玛德国插图新闻杂志文化","id":"card175"},{"text":"→ 后果：纳粹德国焚书运动","id":"extra284"},{"text":"↔ 相关：魏玛德国《帝国电影法》","id":"card179"},{"text":"↔ 相关：魏玛第218条堕胎争议","id":"card96"}],"source":"history","id":"card180"},{"title":"魏玛德国工人体育联盟","level":"C","type":"组织/机构卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1919—1933年","place":"魏玛共和国","summary":"魏玛工人体育联盟把体操、足球、田径和社团教育组织起来，是德国劳工文化中规模巨大的群众体育机构。","fields":[{"label":"标题","value":"魏玛德国工人体育联盟"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1919—1933年"},{"label":"地点","value":"魏玛共和国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"魏玛工人体育联盟把体操、足球、田径和社团教育组织起来，是德国劳工文化中规模巨大的群众体育机构。"},{"label":"性质/类型","value":"工人体育联合组织。"},{"label":"成立/解散时间","value":"前身工人体操联盟成立于1893年；1919年改组为工人体育联盟；1933年被纳粹取缔。"},{"label":"核心目标/宗旨","value":"通过体育活动提升工人健康、组织能力和阶级团结，并与资产阶级体育、民族主义体育保持区分。"},{"label":"关键人物（可选）","value":"地方工人体育社团、社会民主党和工会周边组织者。"},{"label":"关键行动/事件","value":"组织体操、足球、田径、水上运动和体育节，出版报刊，培养体育教师和干部；魏玛后期受社民党与共产党分裂影响。"},{"label":"为什么重要","value":"它是理解魏玛社会生活的重要入口：政治并不只在议会和街头，也在球场、体育馆、俱乐部和周末活动中组织群众。"},{"label":"争议/局限","value":"与资产阶级体育组织和共产主义体育组织存在竞争；纳粹上台后独立工人体育空间被迅速摧毁。"},{"label":"出处","value":"bpb, 150 Jahre SPD - 150 Jahre Arbeiterturn- und Sportbewegung；Deutsche Digitale Bibliothek, Arbeiter-Turn- und Sportbund。"}],"relationItems":["← 前因：德意志帝国工人体育运动","→ 后果：纳粹德国“力量来自欢乐”组织","↔ 相关：魏玛德国大众体育文化","↔ 相关：魏玛德国足球职业化争议","↔ 同时期参考：欧洲工人奥林匹克运动"],"relations":[{"text":"← 前因：德意志帝国工人体育运动","id":"extra827"},{"text":"→ 后果：纳粹德国“力量来自欢乐”组织","id":"extra104"},{"text":"↔ 相关：魏玛德国大众体育文化","id":"card86"},{"text":"↔ 相关：魏玛德国足球职业化争议","id":"card182"}],"source":"history","id":"card181"},{"title":"魏玛德国足球职业化争议","level":"C","type":"概念/思潮卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"1920年代—1933年","place":"魏玛共和国足球俱乐部与足协体系","summary":"魏玛足球迅速大众化和商业化，但德国足协长期坚持业余主义，使职业化成为体育道德、阶层和市场的争议焦点。","fields":[{"label":"标题","value":"魏玛德国足球职业化争议"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1920年代—1933年"},{"label":"地点","value":"魏玛共和国足球俱乐部与足协体系"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"魏玛足球迅速大众化和商业化，但德国足协长期坚持业余主义，使职业化成为体育道德、阶层和市场的争议焦点。"},{"label":"核心主张/思路","value":"足球是否应允许球员以踢球谋生，关系到体育是“纯粹业余锻炼”、群众娱乐，还是可商业运营的现代职业产业。"},{"label":"提出者/代表人物（可选）","value":"德国足球协会、地方俱乐部、体育记者、试图推动职业化的俱乐部经营者和球员。"},{"label":"它从何而来","value":"一战后足球观众和俱乐部规模扩大，门票、媒体和城市群众娱乐提高了足球商业价值；但德国体育传统仍强调业余身份和身体教育。"},{"label":"典型表现","value":"俱乐部暗中补贴球员、职业联赛设想、足协处罚“假业余”现象，以及1930年前后围绕沙尔克等俱乐部的争议。"},{"label":"为什么重要","value":"它说明魏玛大众文化不只是电影、夜生活和报刊，也包括足球这种后来极其重要的群众娱乐产业。"},{"label":"争议/局限","value":"职业化在1933年前未能制度化完成，德国全国性职业联赛要到1963年 Bundesliga 成立后才真正实现。"},{"label":"出处","value":"Britannica, Football: Professionalism；Das Parlament, Wie der Fußball nach Deutschland kam；Deutschlandfunk Kultur, Fußball in der Weimarer Republik。"}],"relationItems":["← 前因：德国足球协会成立","→ 后果：1936年柏林奥运会","↔ 相关：魏玛德国大众体育文化","↔ 相关：魏玛德国工人体育联盟","↔ 同时期参考：英格兰职业足球"],"relations":[{"text":"← 前因：德国足球协会成立","id":"extra826"},{"text":"→ 后果：1936年柏林奥运会","id":"extra129"},{"text":"↔ 相关：魏玛德国大众体育文化","id":"card86"},{"text":"↔ 相关：魏玛德国工人体育联盟","id":"card181"}],"source":"history","id":"card182"},{"title":"魏玛柏林卡巴莱文化","level":"C","type":"概念/思潮卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1919—1933年","place":"柏林；德国大城市","summary":"魏玛柏林卡巴莱把政治讽刺、性别表演、音乐和夜生活结合起来，成为共和国都市现代性的高辨识度符号。","fields":[{"label":"标题","value":"魏玛柏林卡巴莱文化"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1919—1933年"},{"label":"地点","value":"柏林；德国大城市"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"魏玛柏林卡巴莱把政治讽刺、性别表演、音乐和夜生活结合起来，成为共和国都市现代性的高辨识度符号。"},{"label":"核心主张/思路","value":"舞台可以用歌曲、段子、讽刺和身体表演评论政治、战争创伤、性别角色和都市生活。"},{"label":"提出者/代表人物（可选）","value":"柏林卡巴莱艺人、作曲家、剧场经营者和都市观众；与布莱希特、魏尔等戏剧音乐传统相关。"},{"label":"它从何而来","value":"帝国末期已有文学咖啡馆和小剧场传统；战后审查松动、城市消费文化扩大、政治危机频繁，使讽刺娱乐和夜生活迅速发展。"},{"label":"典型表现","value":"小剧场政治讽刺、歌舞表演、变装和性别越界形象、爵士和流行曲、面向本地人和外国游客的夜间娱乐场所。"},{"label":"为什么重要","value":"它解释为什么魏玛常被世界文化记忆成“现代、危险、开放又不稳定”的城市舞台，也说明文化自由与社会危机常常共存。"},{"label":"争议/局限","value":"后世容易把魏玛卡巴莱神话化为单纯“堕落夜生活”，忽略其政治讽刺、商业机制和地区差异。"},{"label":"出处","value":"Weimar Culture historical overviews；Staging Decadence, The Mythical Decadence of Weimar Cabaret；Peter Jelavich, Berlin Cabaret: Studies in Cultural History。"}],"relationItems":["← 前因：德国表现主义电影","→ 后果：纳粹德国《保护德国血统和荣誉法》（1935）","↔ 相关：魏玛“新女性”","↔ 相关：魏玛德国爵士文化","↔ 同时期参考：巴黎爵士时代夜生活"],"relations":[{"text":"← 前因：德国表现主义电影","id":"card78"},{"text":"↔ 相关：魏玛“新女性”","id":"card32"},{"text":"↔ 相关：魏玛德国爵士文化","id":"card184"}],"source":"history","id":"card183"},{"title":"魏玛德国爵士文化","level":"C","type":"概念/思潮卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1920年代—1933年","place":"柏林、汉堡等德国大城市","summary":"魏玛爵士文化把美国音乐、舞厅消费、种族想象和现代都市节奏带入德国，引发迷恋与道德恐慌并存的反应。","fields":[{"label":"标题","value":"魏玛德国爵士文化"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1920年代—1933年"},{"label":"地点","value":"柏林、汉堡等德国大城市"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"魏玛爵士文化把美国音乐、舞厅消费、种族想象和现代都市节奏带入德国，引发迷恋与道德恐慌并存的反应。"},{"label":"核心主张/思路","value":"爵士象征美国化、节奏感、身体自由和现代娱乐，也被反现代、种族主义和民族主义者攻击为“外来”“低俗”或“黑人化”。"},{"label":"提出者/代表人物（可选）","value":"舞厅乐队、唱片公司、广播节目、都市青年和跨国表演者。"},{"label":"它从何而来","value":"一战后美国文化影响扩大，唱片、广播、电影和舞厅产业把爵士及其衍生舞曲带入德国城市消费空间。"},{"label":"典型表现","value":"舞厅、咖啡馆、唱片、广播和电影配乐中出现爵士元素；约瑟芬·贝克等国际表演者在德国城市文化中引起关注。"},{"label":"为什么重要","value":"它把魏玛的文化现代性与全球流行文化联系起来，也为纳粹时期对爵士和摇摆的打压，以及摇摆青年反抗提供背景。"},{"label":"争议/局限","value":"魏玛爵士并不等于真正理解非裔美国音乐文化，德国接受常夹杂异国情调、种族刻板印象和商业包装。"},{"label":"出处","value":"The Jazz Republic: Music, Race, and American Culture in Weimar Germany；DW, Swing Youth in Nazi Germany, jazz was an act of defiance。"}],"relationItems":["← 前因：魏玛广播文化","→ 后果：纳粹德国摇摆青年","↔ 相关：魏玛柏林卡巴莱文化","↔ 相关：魏玛德国插图新闻杂志文化","↔ 同时期参考：美国爵士时代"],"relations":[{"text":"← 前因：魏玛广播文化","id":"card80"},{"text":"→ 后果：纳粹德国摇摆青年","id":"extra291"},{"text":"↔ 相关：魏玛柏林卡巴莱文化","id":"card183"},{"text":"↔ 相关：魏玛德国插图新闻杂志文化","id":"card175"}],"source":"history","id":"card184"},{"title":"魏玛德国白领雇员阶层","level":"B","type":"概念/思潮卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"1919—1933年","place":"魏玛共和国城市办公、商业和服务部门","summary":"魏玛白领雇员夹在工人与资产阶级之间，既代表现代办公室社会，也承受失业、身份焦虑和政治摇摆。","fields":[{"label":"标题","value":"魏玛德国白领雇员阶层"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1919—1933年"},{"label":"地点","value":"魏玛共和国城市办公、商业和服务部门"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"魏玛白领雇员夹在工人与资产阶级之间，既代表现代办公室社会，也承受失业、身份焦虑和政治摇摆。"},{"label":"核心主张/思路","value":"白领雇员包括店员、银行职员、办公室文员、保险职员、技术员和销售人员，他们依靠工资生活，却常把自己同工人区分开。"},{"label":"提出者/代表人物（可选）","value":"不是思想流派，而是现代服务业、商业和办公组织扩张形成的社会阶层。"},{"label":"它从何而来","value":"帝国后期企业规模扩大、行政和商业部门扩张，一战后通货膨胀和大萧条又冲击了白领安全感。"},{"label":"典型表现","value":"办公室、打字机、百货公司、银行柜台、职业服装、雇员协会和关于“新中产”的社会讨论。"},{"label":"为什么重要","value":"它解释魏玛社会结构为什么不能只看工人和资本家。白领阶层的焦虑、消费欲望和地位恐惧是政治文化的重要背景。"},{"label":"争议/局限","value":"白领并非天然支持某一政治阵营，不同收入、性别和行业差异很大；把他们简单等同于纳粹选民并不准确。"},{"label":"出处","value":"Siegfried Kracauer, Die Angestellten historical references；German History in Documents and Images, white-collar employees and Weimar society materials。"}],"relationItems":["← 前因：德意志帝国白领雇员形成","→ 后果：大萧条冲击德国社会","↔ 相关：魏玛“新女性”","↔ 相关：魏玛德国大众消费文化","↔ 同时期参考：美国办公室白领阶层"],"relations":[{"text":"→ 后果：大萧条冲击德国社会","id":"card198"},{"text":"↔ 相关：魏玛“新女性”","id":"card32"},{"text":"↔ 相关：魏玛德国大众消费文化","id":"card87"}],"source":"history","id":"card185"},{"title":"魏玛德国广告专业化","level":"C","type":"概念/思潮卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1919—1933年","place":"魏玛共和国大城市，尤其柏林","summary":"魏玛广告把海报、摄影、品牌、橱窗和市场研究结合起来，使消费社会获得更现代的视觉语言。","fields":[{"label":"标题","value":"魏玛德国广告专业化"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1919—1933年"},{"label":"地点","value":"魏玛共和国大城市，尤其柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"魏玛广告把海报、摄影、品牌、橱窗和市场研究结合起来，使消费社会获得更现代的视觉语言。"},{"label":"核心主张/思路","value":"广告不只是告知商品存在，而是用图像、字体、心理暗示和城市展示制造现代生活方式。"},{"label":"提出者/代表人物（可选）","value":"广告公司、百货公司、设计师、摄影师、报刊出版商和消费品企业。"},{"label":"它从何而来","value":"帝国时期广告和百货商店已兴起，魏玛时期大众消费、摄影、电影和现代设计进一步推动广告专业化。"},{"label":"典型表现","value":"新字体、摄影广告、橱窗设计、品牌标识、杂志广告、海报竞赛和市场细分。"},{"label":"为什么重要","value":"它把魏玛文化从先锋艺术扩展到商业视觉环境，解释普通人如何在街道、报纸和商店中接触现代性。"},{"label":"争议/局限","value":"广告也被批评为操纵欲望、美国化和商业肤浅化；经济危机下，消费承诺与现实贫困形成反差。"},{"label":"出处","value":"Routledge histories of German advertising；Bauhaus and New Typography advertising references；German History in Documents and Images, Weimar consumer culture materials。"}],"relationItems":["← 前因：德意志帝国广告业兴起","→ 后果：魏玛德国大众消费文化","↔ 相关：魏玛德国插图新闻杂志文化","↔ 相关：新法兰克福“法兰克福厨房”","↔ 同时期参考：美国麦迪逊大道广告业"],"relations":[{"text":"← 前因：德意志帝国广告业兴起","id":"extra834"},{"text":"→ 后果：魏玛德国大众消费文化","id":"card87"},{"text":"↔ 相关：魏玛德国插图新闻杂志文化","id":"card175"},{"text":"↔ 相关：新法兰克福“法兰克福厨房”","id":"card84"}],"source":"history","id":"card186"},{"title":"魏玛德国电影院日常","level":"C","type":"概念/思潮卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"1919—1933年","place":"魏玛共和国城市和小城镇","summary":"电影院是魏玛最重要的大众娱乐场所之一，把工人、白领、青年和中产观众带进共同的现代影像空间。","fields":[{"label":"标题","value":"魏玛德国电影院日常"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1919—1933年"},{"label":"地点","value":"魏玛共和国城市和小城镇"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"电影院是魏玛最重要的大众娱乐场所之一，把工人、白领、青年和中产观众带进共同的现代影像空间。"},{"label":"核心主张/思路","value":"电影不是只由经典作品构成，也是一种日常消费、约会、避寒、休闲和新闻获取方式。"},{"label":"提出者/代表人物（可选）","value":"影院经营者、电影公司、观众、审查机关和城市娱乐业共同构成。"},{"label":"它从何而来","value":"一战前电影业已发展，魏玛时期乌发电影公司、城市娱乐区、票价层级和电影审查共同塑造影院制度。"},{"label":"典型表现","value":"大型电影宫、小型街区影院、连续放映、新闻短片、明星广告、乐队伴奏和有声电影转型。"},{"label":"为什么重要","value":"它让“魏玛文化”不再只属于知识分子和先锋艺术，而成为普通城市居民每周都可能体验的娱乐。"},{"label":"争议/局限","value":"电影院被保守派批评为道德危险和青少年问题来源，也受到《帝国电影法》的审查限制。"},{"label":"出处","value":"filmportal.de, Weimar cinema and film culture materials；German History in Documents and Images, Cinema in Weimar Germany references。"}],"relationItems":["← 前因：德国乌发电影公司","→ 后果：弗里茨·朗电影《M》","↔ 相关：魏玛德国《帝国电影法》","↔ 相关：德国表现主义电影","↔ 同时期参考：好莱坞电影宫文化"],"relations":[{"text":"← 前因：德国乌发电影公司","id":"card77"},{"text":"→ 后果：弗里茨·朗电影《M》","id":"extra70"},{"text":"↔ 相关：魏玛德国《帝国电影法》","id":"card179"},{"text":"↔ 相关：德国表现主义电影","id":"card78"}],"source":"history","id":"card187"},{"title":"魏玛德国新客观摄影","level":"C","type":"概念/思潮卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1920年代—1933年","place":"魏玛共和国大城市","summary":"新客观摄影用清晰、冷静和物质细节观察现代世界，体现魏玛视觉文化从表现主义情绪转向客观表面的趋势。","fields":[{"label":"标题","value":"魏玛德国新客观摄影"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1920年代—1933年"},{"label":"地点","value":"魏玛共和国大城市"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"新客观摄影用清晰、冷静和物质细节观察现代世界，体现魏玛视觉文化从表现主义情绪转向客观表面的趋势。"},{"label":"核心主张/思路","value":"摄影应以精确、锐利和非感伤方式呈现物体、城市、面孔、工业产品和社会类型。"},{"label":"提出者/代表人物（可选）","value":"奥古斯特·桑德、阿尔伯特·伦格尔-帕奇、新视觉摄影师群体等。"},{"label":"它从何而来","value":"一战后表现主义的情绪爆发逐渐退潮，技术媒介、新闻摄影、广告和现代设计推动更冷静的视觉方式。"},{"label":"典型表现","value":"社会类型肖像、工业物件特写、建筑和机械摄影、杂志图片和摄影书。"},{"label":"为什么重要","value":"它让用户看到魏玛文化不只有夜生活和电影，也有一种用镜头整理现代社会的视觉方法。"},{"label":"争议/局限","value":"“客观”并不等于中立，拍摄对象、分类方式和版面语境仍会制造社会判断。"},{"label":"出处","value":"Tate, Neue Sachlichkeit photography；MoMA, August Sander and New Objectivity resources；Metropolitan Museum of Art, New Objectivity photography。"}],"relationItems":["← 前因：德国新客观主义","→ 后果：魏玛德国新闻摄影","↔ 相关：魏玛德国插图新闻杂志文化","↔ 相关：魏玛德国广告专业化","↔ 同时期参考：苏联构成主义摄影"],"relations":[{"text":"← 前因：德国新客观主义","id":"card31"},{"text":"→ 后果：魏玛德国新闻摄影","id":"card190"},{"text":"↔ 相关：魏玛德国插图新闻杂志文化","id":"card175"},{"text":"↔ 相关：魏玛德国广告专业化","id":"card186"}],"source":"history","id":"card188"},{"title":"魏玛德国山岳电影","level":"C","type":"概念/思潮卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1920年代—1930年代初","place":"德国、奥地利阿尔卑斯影像空间；魏玛电影市场","summary":"山岳电影用雪山、登山和自然崇高制造逃离城市现代性的视觉幻想，也孕育了后来纳粹审美中的身体与自然主题。","fields":[{"label":"标题","value":"魏玛德国山岳电影"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1920年代—1930年代初"},{"label":"地点","value":"德国、奥地利阿尔卑斯影像空间；魏玛电影市场"},{"label":"主要国家","value":"德国；奥地利"},{"label":"一句话概括","value":"山岳电影用雪山、登山和自然崇高制造逃离城市现代性的视觉幻想，也孕育了后来纳粹审美中的身体与自然主题。"},{"label":"核心主张/思路","value":"通过高山、冰雪、身体挑战和自然危险，把现代城市疲惫转化为纯净、勇气和超越的影像体验。"},{"label":"提出者/代表人物（可选）","value":"阿诺德·范克、路易斯·特伦克尔、莱妮·里芬施塔尔等。"},{"label":"它从何而来","value":"魏玛都市文化、体育身体热、自然崇拜和电影技术进步共同推动山地外景电影流行。"},{"label":"典型表现","value":"登山、滑雪、雪崩、云海、冰川、强健身体和自然景观长镜头。"},{"label":"为什么重要","value":"它说明魏玛电影不只有城市、犯罪和表现主义，也有一种向山地和自然逃离的现代审美。"},{"label":"争议/局限","value":"山岳电影常被后世讨论为法西斯审美前史，但不能简单把所有山岳电影等同于纳粹宣传。"},{"label":"出处","value":"BFI, Mountain film / Bergfilm references；Senses of Cinema, Arnold Fanck and the mountain film；Routledge German cinema histories。"}],"relationItems":["← 前因：魏玛德国大众体育文化","→ 后果：莱妮·里芬施塔尔《意志的胜利》","↔ 相关：德国表现主义电影","↔ 相关：纳粹德国人民收音机","↔ 同时期参考：欧洲自然主义体育文化"],"relations":[{"text":"← 前因：魏玛德国大众体育文化","id":"card86"},{"text":"→ 后果：莱妮·里芬施塔尔《意志的胜利》","id":"extra88"},{"text":"↔ 相关：德国表现主义电影","id":"card78"},{"text":"↔ 相关：纳粹德国人民收音机","id":"extra285"}],"source":"history","id":"card189"},{"title":"魏玛德国新闻摄影","level":"C","type":"概念/思潮卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1920年代—1933年","place":"柏林及德国大城市","summary":"魏玛新闻摄影把政治、明星、灾难、体育和城市日常变成可快速消费的图像新闻。","fields":[{"label":"标题","value":"魏玛德国新闻摄影"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1920年代—1933年"},{"label":"地点","value":"柏林及德国大城市"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"魏玛新闻摄影把政治、明星、灾难、体育和城市日常变成可快速消费的图像新闻。"},{"label":"核心主张/思路","value":"现代读者不仅阅读新闻，也“观看”新闻；照片可以制造现场感、情绪和公共记忆。"},{"label":"提出者/代表人物（可选）","value":"摄影记者、图片编辑、插图杂志和报业集团。"},{"label":"它从何而来","value":"小型相机、印刷技术、插图杂志和城市新闻竞争推动摄影成为新闻核心材料。"},{"label":"典型表现","value":"政治人物抓拍、街头生活、体育赛事、犯罪现场、明星照片和图片版面叙事。"},{"label":"为什么重要","value":"它连接魏玛媒体商业化和现代公众经验，说明政治社会的许多“记忆瞬间”是通过照片形成的。"},{"label":"争议/局限","value":"照片能增强真实感，也能通过裁剪、标题和版面制造误导；新闻摄影很快也被政治宣传吸收。"},{"label":"出处","value":"MoMA, Object:Photo and Weimar illustrated press resources；arthistoricum.net, Illustrated Magazines of the Weimar Republic；Getty, Weimar photography resources。"}],"relationItems":["← 前因：魏玛德国插图新闻杂志文化","→ 后果：纳粹宣传机器","↔ 相关：魏玛德国新客观摄影","↔ 相关：魏玛德国乌尔施泰因出版社","↔ 同时期参考：美国新闻摄影兴起"],"relations":[{"text":"← 前因：魏玛德国插图新闻杂志文化","id":"card175"},{"text":"→ 后果：纳粹宣传机器","id":"extra94"},{"text":"↔ 相关：魏玛德国新客观摄影","id":"card188"},{"text":"↔ 相关：魏玛德国乌尔施泰因出版社","id":"card174"}],"source":"history","id":"card190"},{"title":"魏玛德国住房利息税","level":"C","type":"制度/文本卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1924年后在多地实施","place":"魏玛共和国城市","summary":"住房利息税把通胀后旧房东的收益转化为公共资金，用于支持魏玛时期新住房建设。","fields":[{"label":"标题","value":"魏玛德国住房利息税"},{"label":"分级","value":"C"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1924年后在多地实施"},{"label":"地点","value":"魏玛共和国城市"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"住房利息税把通胀后旧房东的收益转化为公共资金，用于支持魏玛时期新住房建设。"},{"label":"制定方/签署方","value":"魏玛共和国及各州、市住房财政体系。"},{"label":"主要内容","value":"对因通货膨胀减轻债务负担的旧房产征税，把收入用于公共住房、新住宅区和城市建设项目。"},{"label":"它试图解决什么问题","value":"一战和通胀后德国城市住房严重短缺，私人市场难以提供足够、可负担的新住宅，政府需要新的住房财政来源。"},{"label":"为什么重要","value":"它解释新法兰克福、柏林现代主义住宅区等项目背后的财政机制，说明魏玛住房改革不是只靠设计理念。"},{"label":"争议/局限","value":"税收引发房产业主反对，住房建设仍无法完全解决贫困和拥挤问题；经济危机后财政能力下降。"},{"label":"造成的影响","value":"推动魏玛中期社会住房建设，使城市现代主义建筑和福利政策有了更现实的财政基础。"},{"label":"出处","value":"German History in Documents and Images, Weimar housing reform materials; architectural histories of Hauszinssteuer and social housing。"}],"relationItems":["← 前因：战后德国住房短缺","→ 后果：新法兰克福住房项目","↔ 相关：柏林现代主义住宅区","↔ 相关：新法兰克福“法兰克福厨房”","↔ 同时期参考：维也纳红色市政住房"],"relations":[{"text":"→ 后果：新法兰克福住房项目","id":"card82"},{"text":"↔ 相关：柏林现代主义住宅区","id":"card83"},{"text":"↔ 相关：新法兰克福“法兰克福厨房”","id":"card84"}],"source":"history","id":"card191"},{"title":"魏玛柏林咖啡馆文化","level":"C","type":"概念/思潮卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1919—1933年","place":"柏林","summary":"魏玛柏林咖啡馆是作家、记者、艺术家和政治人物交换消息、写作和表演都市身份的重要空间。","fields":[{"label":"标题","value":"魏玛柏林咖啡馆文化"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1919—1933年"},{"label":"地点","value":"柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"魏玛柏林咖啡馆是作家、记者、艺术家和政治人物交换消息、写作和表演都市身份的重要空间。"},{"label":"核心主张/思路","value":"咖啡馆不仅是消费场所，也是半公共文化空间，人在其中阅读报纸、写作、谈政治、看人和被看。"},{"label":"提出者/代表人物（可选）","value":"柏林作家、记者、艺术家、编辑和城市知识分子群体。"},{"label":"它从何而来","value":"帝国末期城市报刊和文学圈已发展，战后柏林文化产业、政治危机和夜生活进一步强化咖啡馆公共性。"},{"label":"典型表现","value":"作家固定座位、报纸架、烟雾、讨论、讽刺、编辑约稿和跨阶层观察。"},{"label":"为什么重要","value":"它让魏玛文化有了日常空间，不只是书本和舞台，而是人在城市里如何相遇、争论和生产文化。"},{"label":"争议/局限","value":"咖啡馆文化常被浪漫化，实际参与者多为有时间和文化资本的都市群体，难以代表全部社会。"},{"label":"出处","value":"Weimar Berlin cultural histories; German History in Documents and Images, Berlin urban culture materials; Peter Jelavich, Berlin Cabaret references。"}],"relationItems":["← 前因：德意志帝国广告业兴起","→ 后果：魏玛柏林卡巴莱文化","↔ 相关：魏玛德国插图新闻杂志文化","↔ 相关：德布林《柏林亚历山大广场》","↔ 同时期参考：维也纳咖啡馆文化"],"relations":[{"text":"← 前因：德意志帝国广告业兴起","id":"extra834"},{"text":"→ 后果：魏玛柏林卡巴莱文化","id":"card183"},{"text":"↔ 相关：魏玛德国插图新闻杂志文化","id":"card175"},{"text":"↔ 相关：德布林《柏林亚历山大广场》","id":"extra69"}],"source":"history","id":"card192"},{"title":"魏玛德国政治漫画","level":"C","type":"概念/思潮卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1919—1933年","place":"魏玛共和国报刊和杂志市场","summary":"魏玛政治漫画用夸张人物、讽刺场景和视觉隐喻处理通胀、政党斗争、军国主义和纳粹崛起。","fields":[{"label":"标题","value":"魏玛德国政治漫画"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1919—1933年"},{"label":"地点","value":"魏玛共和国报刊和杂志市场"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"魏玛政治漫画用夸张人物、讽刺场景和视觉隐喻处理通胀、政党斗争、军国主义和纳粹崛起。"},{"label":"核心主张/思路","value":"漫画以快速、尖锐和可视化方式表达政治判断，比长篇社论更容易进入大众阅读和街头讨论。"},{"label":"提出者/代表人物（可选）","value":"乔治·格罗茨、约翰·哈特菲尔德、托马斯·海内等艺术家和讽刺杂志作者。"},{"label":"它从何而来","value":"帝国时期讽刺杂志传统、魏玛新闻自由、政治极化和大众报刊市场共同推动政治漫画繁荣。"},{"label":"典型表现","value":"资本家、军官、政客、纳粹、通胀受害者和战争残疾人被画成具有强烈象征性的形象。"},{"label":"为什么重要","value":"它让用户看到魏玛政治不仅通过议会和街头斗争表达，也通过图像讽刺和视觉攻击传播。"},{"label":"争议/局限","value":"漫画可以揭露权力，也可能强化刻板印象和极端仇恨；魏玛后期政治图像越来越激烈。"},{"label":"出处","value":"MoMA, John Heartfield and political photomontage; Tate, George Grosz; German History in Documents and Images, Weimar political cartoons。"}],"relationItems":["← 前因：魏玛德国插图新闻杂志文化","→ 后果：纳粹德国《报刊编辑法》","↔ 相关：魏玛柏林达达运动","↔ 相关：魏玛德国新闻摄影","↔ 同时期参考：法国《鸭鸣报》讽刺传统"],"relations":[{"text":"← 前因：魏玛德国插图新闻杂志文化","id":"card175"},{"text":"→ 后果：纳粹德国《报刊编辑法》","id":"extra151"},{"text":"↔ 相关：魏玛柏林达达运动","id":"card79"},{"text":"↔ 相关：魏玛德国新闻摄影","id":"card190"}],"source":"history","id":"card193"},{"title":"魏玛德国大众舞厅文化","level":"C","type":"概念/思潮卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"1920年代—1933年","place":"柏林、汉堡等德国城市","summary":"魏玛大众舞厅把音乐、身体、性别关系和消费连接起来，是城市青年体验现代生活的重要场所。","fields":[{"label":"标题","value":"魏玛德国大众舞厅文化"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1920年代—1933年"},{"label":"地点","value":"柏林、汉堡等德国城市"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"魏玛大众舞厅把音乐、身体、性别关系和消费连接起来，是城市青年体验现代生活的重要场所。"},{"label":"核心主张/思路","value":"跳舞不只是娱乐，也是一种身体自由、社交选择、消费身份和代际冲突的表达。"},{"label":"提出者/代表人物（可选）","value":"舞厅经营者、乐队、都市青年、白领和工人消费者。"},{"label":"它从何而来","value":"战后娱乐需求、爵士和舞曲输入、城市夜生活扩张、女性就业和新消费空间共同推动舞厅流行。"},{"label":"典型表现","value":"狐步舞、探戈、查尔斯顿、爵士乐队、舞票、夜间娱乐和男女公共社交。"},{"label":"为什么重要","value":"它补足魏玛文化的身体层面，让“现代性”不只是观念和电影，而是人们如何跳舞、约会和消费夜晚。"},{"label":"争议/局限","value":"保守派批评舞厅败坏道德、美国化和性放纵；经济危机也压缩娱乐消费。"},{"label":"出处","value":"Weimar dance hall culture studies; DW and cultural histories of jazz and dance in Weimar Germany; German History in Documents and Images, modern youth culture materials。"}],"relationItems":["← 前因：魏玛德国爵士文化","→ 后果：纳粹德国摇摆青年","↔ 相关：魏玛柏林卡巴莱文化","↔ 相关：魏玛“新女性”","↔ 同时期参考：美国爵士时代舞厅"],"relations":[{"text":"← 前因：魏玛德国爵士文化","id":"card184"},{"text":"→ 后果：纳粹德国摇摆青年","id":"extra291"},{"text":"↔ 相关：魏玛柏林卡巴莱文化","id":"card183"},{"text":"↔ 相关：魏玛“新女性”","id":"card32"}],"source":"history","id":"card194"},{"title":"魏玛德国女性职员文化","level":"C","type":"概念/思潮卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"1919—1933年","place":"魏玛共和国城市办公室、商店和服务业","summary":"魏玛女性职员把打字机、办公室、百货公司和都市时尚连接起来，是“新女性”形象的现实基础之一。","fields":[{"label":"标题","value":"魏玛德国女性职员文化"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1919—1933年"},{"label":"地点","value":"魏玛共和国城市办公室、商店和服务业"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"魏玛女性职员把打字机、办公室、百货公司和都市时尚连接起来，是“新女性”形象的现实基础之一。"},{"label":"核心主张/思路","value":"受教育年轻女性进入办公室、商店、电话交换台和服务行业，以工资劳动换取一定经济独立和城市生活机会。"},{"label":"提出者/代表人物（可选）","value":"不是思想流派，而是白领劳动市场、商业部门和女性教育扩张共同形成的社会群体。"},{"label":"它从何而来","value":"帝国晚期女性教育和商业岗位扩大，一战后女性就业经验、城市消费文化和白领部门扩张使女性职员更可见。"},{"label":"典型表现","value":"打字员、售货员、电话接线员、办公室女职员、短发、职业服装、午休消费和恋爱/婚姻压力。"},{"label":"为什么重要","value":"它把“新女性”从杂志图像落到工资、通勤、职业技能和性别歧视的现实处境中。"},{"label":"争议/局限","value":"女性职员收入低、升迁有限，常被要求年轻、整洁和可替代；经济危机时又被批评抢走男性岗位。"},{"label":"出处","value":"German History in Documents and Images, Women in office and white-collar work materials; Weimar Republic Sourcebook selections on women employees。"}],"relationItems":["← 前因：德意志帝国女性大学入学开放","→ 后果：魏玛“新女性”","↔ 相关：魏玛德国白领雇员阶层","↔ 相关：魏玛德国大众消费文化","↔ 同时期参考：美国“办公室女郎”文化"],"relations":[{"text":"← 前因：德意志帝国女性大学入学开放","id":"extra823"},{"text":"→ 后果：魏玛“新女性”","id":"card32"},{"text":"↔ 相关：魏玛德国白领雇员阶层","id":"card185"},{"text":"↔ 相关：魏玛德国大众消费文化","id":"card87"}],"source":"history","id":"card195"},{"title":"魏玛德国周末休闲文化","level":"C","type":"概念/思潮卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"1920年代—1933年","place":"魏玛共和国城市及郊外","summary":"魏玛周末休闲把郊游、湖边、体育、电影和消费连接起来，显示劳动时间缩短后城市生活节奏变化。","fields":[{"label":"标题","value":"魏玛德国周末休闲文化"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1920年代—1933年"},{"label":"地点","value":"魏玛共和国城市及郊外"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"魏玛周末休闲把郊游、湖边、体育、电影和消费连接起来，显示劳动时间缩短后城市生活节奏变化。"},{"label":"核心主张/思路","value":"休闲不再只是精英度假，工人、白领和青年也通过周末出行、体育和娱乐体验现代城市生活。"},{"label":"提出者/代表人物（可选）","value":"工会、体育组织、交通公司、电影业、旅游和娱乐企业共同塑造。"},{"label":"它从何而来","value":"工时缩短、公共交通扩展、体育组织和城市娱乐业发展，使普通居民获得更多可规划的闲暇时间。"},{"label":"典型表现","value":"湖边游泳、郊外徒步、工人体育、电影院、舞厅、咖啡馆和短途火车旅行。"},{"label":"为什么重要","value":"它说明社会现代化不仅是生产效率提高，也包括“如何不工作”的新制度和新欲望。"},{"label":"争议/局限","value":"失业者的“闲暇”常是贫困和焦虑，不能与有工资者的休闲消费等同；阶层差异仍然明显。"},{"label":"出处","value":"German History in Documents and Images, Weimar leisure culture materials; Shelley Baranowski, Strength Through Joy background on Weimar leisure。"}],"relationItems":["← 前因：魏玛德国大众体育文化","→ 后果：纳粹德国“力量来自欢乐”组织","↔ 相关：魏玛德国大众舞厅文化","↔ 相关：魏玛德国电影院日常","↔ 同时期参考：英国海滨度假文化"],"relations":[{"text":"← 前因：魏玛德国大众体育文化","id":"card86"},{"text":"→ 后果：纳粹德国“力量来自欢乐”组织","id":"extra104"},{"text":"↔ 相关：魏玛德国大众舞厅文化","id":"card194"},{"text":"↔ 相关：魏玛德国电影院日常","id":"card187"}],"source":"history","id":"card196"},{"title":"魏玛文化","level":"B","type":"概念/思潮卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1919—1933年","place":"德国，尤其柏林、德绍、法兰克福、慕尼黑等城市","summary":"魏玛文化是战后危机、都市现代性、大众媒介和艺术实验交织出的德国现代文化高峰。","fields":[{"label":"标题","value":"魏玛文化"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1919—1933年"},{"label":"地点","value":"德国，尤其柏林、德绍、法兰克福、慕尼黑等城市"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"魏玛文化是战后危机、都市现代性、大众媒介和艺术实验交织出的德国现代文化高峰。"},{"label":"核心主张/思路","value":"在共和国政治不稳定和社会快速变动中，电影、建筑、戏剧、摄影、卡巴莱、新闻和性别文化都出现强烈实验性。"},{"label":"提出者/代表人物（可选）","value":"包豪斯艺术家、布莱希特、格罗皮乌斯、弗里茨·朗、德布林、汉娜·赫希、新闻和电影行业从业者。"},{"label":"它从何而来","value":"帝国晚期城市现代性、一战创伤、革命后自由空间、通货膨胀和相对稳定期的消费文化共同塑造魏玛文化。"},{"label":"典型表现","value":"德国包豪斯、德国表现主义电影、德国新客观主义、魏玛柏林卡巴莱文化、魏玛“新女性”、大众舞厅和插图杂志。"},{"label":"为什么重要","value":"魏玛文化影响现代主义艺术、电影语言、设计和都市文化想象，也是理解纳粹文化清洗和“堕落艺术”话语的前提。"},{"label":"争议/局限","value":"魏玛文化常被浪漫化为自由黄金时代，但它只覆盖部分城市和阶层，并与失业、贫困、政治暴力同时存在。"},{"label":"出处","value":"Peter Gay, Weimar Culture；German History in Documents and Images: Weimar culture；DHM/LeMO: Weimarer Republik Kultur。"}],"relationItems":["← 前因：德意志帝国城市现代性","↔ 相关：德国包豪斯","↔ 相关：德国表现主义电影","↔ 相关：魏玛“新女性”","→ 后果：纳粹文化控制"],"relations":[{"text":"← 前因：德意志帝国城市现代性","id":"extra944"},{"text":"↔ 相关：德国包豪斯","id":"card30"},{"text":"↔ 相关：德国表现主义电影","id":"card78"},{"text":"↔ 相关：魏玛“新女性”","id":"card32"},{"text":"→ 后果：纳粹文化控制","id":"extra113"}],"source":"history","id":"card197"},{"title":"大萧条冲击德国社会","level":"B","type":"事件卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1929—1933年","place":"德国、全球资本主义经济体系","summary":"大萧条使德国失业、财政和银行体系急剧恶化，削弱魏玛共和国社会基础。","fields":[{"label":"标题","value":"大萧条冲击德国社会"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1929—1933年"},{"label":"地点","value":"德国、全球资本主义经济体系"},{"label":"主要国家","value":"德国；美国；英国；法国"},{"label":"一句话概括","value":"大萧条使德国失业、财政和银行体系急剧恶化，削弱魏玛共和国社会基础。"},{"label":"参与者","value":"德国失业工人、企业、银行、布吕宁政府、美国债权人、政党和工会。"},{"label":"发生了什么","value":"华尔街崩盘后，美国资本回流和贷款收缩冲击德国经济。企业倒闭、银行危机、出口下降和财政收入减少相互强化。布吕宁政府采取通缩政策和紧急法令，失业人数飙升，社会救济压力扩大。"},{"label":"为什么重要","value":"经济灾难使魏玛民主的妥协空间收窄，推动总统内阁、街头政治和极端政党支持上升。纳粹崛起不能只用经济解释，但大萧条是关键背景。"},{"label":"前因","value":"道威斯贷款与美国资本流入使德国复苏高度依赖外部金融；世界经济在1929年后急剧收缩。"},{"label":"后果","value":"德国大萧条失业危机加重，布吕宁总统内阁依赖紧急法令，纳粹党和共产党选票上升。"},{"label":"出处","value":"German History in Documents and Images: Great Depression in Germany；DHM/LeMO: Weltwirtschaftskrise；Encyclopaedia Britannica: Great Depression。"}],"relationItems":["← 前因：华尔街“黑色星期四”","← 前因：道威斯贷款与美国资本流入","→ 后果：德国大萧条失业危机","→ 后果：布吕宁内阁通缩政策","→ 后果：纳粹夺权","↔ 相关：魏玛德国失业保险法"],"relations":[{"text":"← 前因：华尔街“黑色星期四”","id":"card64"},{"text":"← 前因：道威斯贷款与美国资本流入","id":"card140"},{"text":"→ 后果：德国大萧条失业危机","id":"card99"},{"text":"→ 后果：布吕宁内阁通缩政策","id":"card65"},{"text":"→ 后果：纳粹夺权","id":"extra852"},{"text":"↔ 相关：魏玛德国失业保险法","id":"card81"}],"source":"history","id":"card198"},{"title":"电影黑色传统","level":"C","type":"概念/思潮卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1920年代—1940年代形成，后来持续发展","place":"德国、美国、跨大西洋电影工业","summary":"电影黑色传统把都市犯罪、阴影视觉和道德暧昧叙事结合起来，部分源自魏玛电影经验。","fields":[{"label":"标题","value":"电影黑色传统"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1920年代—1940年代形成，后来持续发展"},{"label":"地点","value":"德国、美国、跨大西洋电影工业"},{"label":"主要国家","value":"德国；美国"},{"label":"一句话概括","value":"电影黑色传统把都市犯罪、阴影视觉和道德暧昧叙事结合起来，部分源自魏玛电影经验。"},{"label":"核心主张/思路","value":"通过低调照明、扭曲空间、犯罪心理、都市焦虑和反英雄人物，表现现代城市中的不安、欲望与控制。"},{"label":"提出者/代表人物（可选）","value":"弗里茨·朗、魏玛电影从业者、流亡美国的欧洲导演、好莱坞犯罪片制作者。"},{"label":"它从何而来","value":"德国表现主义电影、魏玛犯罪文化、都市现代性和移民导演进入好莱坞后的视觉与叙事转化。"},{"label":"典型表现","value":"《M》、德国表现主义电影、美国1940年代黑色电影、城市夜景与阴影构图。"},{"label":"为什么重要","value":"它说明魏玛文化不只影响德国本土，也通过流亡和电影工业进入世界电影史。"},{"label":"争议/局限","value":"“电影黑色”作为概念多由后来批评家命名，不能把所有阴暗风格电影都简单归入同一传统。"},{"label":"出处","value":"British Film Institute: Film noir；German History in Documents and Images: Weimar cinema；Siegfried Kracauer, From Caligari to Hitler。"}],"relationItems":["← 前因：德国表现主义电影","↔ 相关：弗里茨·朗电影《M》","↔ 相关：魏玛柏林“戒指会”犯罪网络","→ 后果：美国黑色电影","↔ 相关：魏玛文化"],"relations":[{"text":"← 前因：德国表现主义电影","id":"card78"},{"text":"↔ 相关：弗里茨·朗电影《M》","id":"extra70"},{"text":"↔ 相关：魏玛柏林“戒指会”犯罪网络","id":"card74"},{"text":"↔ 相关：魏玛文化","id":"card197"}],"source":"history","id":"card199"},{"title":"现代主义艺术","level":"B","type":"概念/思潮卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"19世纪末—20世纪中期","place":"欧洲、美国及全球艺术网络","summary":"现代主义艺术以形式实验、反传统和都市经验为核心，回应工业化、战争和现代生活断裂。","fields":[{"label":"标题","value":"现代主义艺术"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"19世纪末—20世纪中期"},{"label":"地点","value":"欧洲、美国及全球艺术网络"},{"label":"主要国家","value":"法国；德国；奥地利；俄罗斯；美国"},{"label":"一句话概括","value":"现代主义艺术以形式实验、反传统和都市经验为核心，回应工业化、战争和现代生活断裂。"},{"label":"核心主张/思路","value":"艺术不再以再现古典秩序为唯一目标，而是通过抽象、拼贴、变形、功能主义和媒介实验表达现代经验。"},{"label":"提出者/代表人物（可选）","value":"毕加索、康定斯基、克利、格罗皮乌斯、达达艺术家、表现主义和包豪斯艺术家。"},{"label":"它从何而来","value":"工业化城市、摄影和电影冲击、世界大战创伤、前卫团体和艺术市场变化。"},{"label":"典型表现","value":"表现主义、达达主义、包豪斯、新客观主义、抽象艺术、现代建筑和设计。"},{"label":"为什么重要","value":"魏玛文化和纳粹“退化艺术”展都离不开现代主义艺术背景。它也是20世纪全球视觉文化的重要转折。"},{"label":"争议/局限","value":"现代主义常被赞为解放性实验，也被批评为精英化、疏离大众或被国家与市场重新吸收。"},{"label":"出处","value":"Tate: Modernism；MoMA: Modern art；German History in Documents and Images: Weimar art。"}],"relationItems":["↔ 相关：德国表现主义电影","↔ 相关：德国包豪斯","↔ 相关：魏玛柏林达达运动","→ 后果：纳粹德国“退化艺术”展","↔ 相关：魏玛文化"],"relations":[{"text":"↔ 相关：德国表现主义电影","id":"card78"},{"text":"↔ 相关：德国包豪斯","id":"card30"},{"text":"↔ 相关：魏玛柏林达达运动","id":"card79"},{"text":"→ 后果：纳粹德国“退化艺术”展","id":"extra126"},{"text":"↔ 相关：魏玛文化","id":"card197"}],"source":"history","id":"card200"},{"title":"现代社会住宅","level":"C","type":"概念/思潮卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"1920年代—1930年代","place":"德国、奥地利、荷兰等欧洲城市","summary":"现代社会住宅用规划、标准化和公共政策回应工业城市住房危机。","fields":[{"label":"标题","value":"现代社会住宅"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1920年代—1930年代"},{"label":"地点","value":"德国、奥地利、荷兰等欧洲城市"},{"label":"主要国家","value":"德国；奥地利；荷兰"},{"label":"一句话概括","value":"现代社会住宅用规划、标准化和公共政策回应工业城市住房危机。"},{"label":"核心主张/思路","value":"住房不只是私人商品，也应被视为公共健康、家庭生活和社会稳定的基础设施。"},{"label":"提出者/代表人物（可选）","value":"恩斯特·迈、布鲁诺·陶特、格罗皮乌斯、维也纳市政社会主义规划者。"},{"label":"它从何而来","value":"工业化城市拥挤、战后住房短缺、公共卫生运动、现代建筑和地方政府社会政策。"},{"label":"典型表现","value":"新法兰克福住房项目、柏林现代主义住宅区、法兰克福厨房、维也纳红色城市住宅。"},{"label":"为什么重要","value":"它把建筑现代主义与福利政治连接起来。魏玛德国的住宅实验影响后来城市规划和公共住房讨论。"},{"label":"争议/局限","value":"标准化住宅提高效率，但也可能被批评为生活方式规训或忽视居民差异。"},{"label":"出处","value":"German History in Documents and Images: Housing reform；MoMA: Modern architecture；DHM/LeMO: Neues Bauen。"}],"relationItems":["← 前因：工业化时代的德国城市社会","↔ 相关：新法兰克福住房项目","↔ 相关：柏林现代主义住宅区","↔ 相关：新法兰克福“法兰克福厨房”","→ 后果：战后德国住房重建"],"relations":[{"text":"← 前因：工业化时代的德国城市社会","id":"extra934"},{"text":"↔ 相关：新法兰克福住房项目","id":"card82"},{"text":"↔ 相关：柏林现代主义住宅区","id":"card83"},{"text":"↔ 相关：新法兰克福“法兰克福厨房”","id":"card84"},{"text":"→ 后果：战后德国住房重建","id":"extra850"}],"source":"history","id":"card201"},{"title":"都市自由想象","level":"C","type":"概念/思潮卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1920年代尤为突出","place":"柏林、巴黎、纽约等现代都市","summary":"都市自由想象把大城市看作摆脱传统约束、体验消费、性别流动和匿名生活的空间。","fields":[{"label":"标题","value":"都市自由想象"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1920年代尤为突出"},{"label":"地点","value":"柏林、巴黎、纽约等现代都市"},{"label":"主要国家","value":"德国；法国；美国"},{"label":"一句话概括","value":"都市自由想象把大城市看作摆脱传统约束、体验消费、性别流动和匿名生活的空间。"},{"label":"核心主张/思路","value":"现代都市提供夜生活、咖啡馆、舞厅、电影、同性亚文化、职业女性和陌生人社会，让人想象新的生活可能。"},{"label":"提出者/代表人物（可选）","value":"城市作家、电影导演、新闻记者、卡巴莱表演者、青年和白领群体。"},{"label":"它从何而来","value":"工业城市扩张、大众消费、交通和传媒发展，以及战后社会规范松动。"},{"label":"典型表现","value":"魏玛柏林卡巴莱文化、魏玛德国大众舞厅文化、魏玛“新女性”、德布林《柏林亚历山大广场》。"},{"label":"为什么重要","value":"它解释魏玛文化为什么被后人想象为“自由都市”的象征，也解释保守派和纳粹为何把城市现代性视为道德危机。"},{"label":"争议/局限","value":"都市自由并不普遍，阶级、性别、警务和贫困仍限制许多人的实际生活。"},{"label":"出处","value":"Peter Gay, Weimar Culture；German History in Documents and Images: Weimar urban culture；DHM/LeMO: Weimar Berlin。"}],"relationItems":["← 前因：魏玛柏林现代性","↔ 相关：魏玛柏林卡巴莱文化","↔ 相关：魏玛“新女性”","↔ 相关：德布林《柏林亚历山大广场》","✗ 对立/冲突：保守道德政治"],"relations":[{"text":"← 前因：魏玛柏林现代性","id":"card33"},{"text":"↔ 相关：魏玛柏林卡巴莱文化","id":"card183"},{"text":"↔ 相关：魏玛“新女性”","id":"card32"},{"text":"↔ 相关：德布林《柏林亚历山大广场》","id":"extra69"},{"text":"✗ 对立/冲突：保守道德政治","id":"card207"}],"source":"history","id":"card202"},{"title":"1919年爱丁顿日食观测","level":"B","type":"事件卡","tags":["文化与思想","战争与外交"],"mainTag":"文化与思想","subTag":"战争与外交","timeText":"1919年5月29日观测；1919年11月公布结果","place":"普林西比岛、巴西索布拉尔、英国伦敦","summary":"1919年爱丁顿日食观测验证广义相对论的光线偏折预言，使爱因斯坦成为世界性科学名人。","fields":[{"label":"标题","value":"1919年爱丁顿日食观测"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1919年5月29日观测；1919年11月公布结果"},{"label":"地点","value":"普林西比岛、巴西索布拉尔、英国伦敦"},{"label":"主要国家","value":"英国；巴西；葡萄牙；德国"},{"label":"一句话概括","value":"1919年爱丁顿日食观测验证广义相对论的光线偏折预言，使爱因斯坦成为世界性科学名人。"},{"label":"参与者","value":"亚瑟·爱丁顿、弗兰克·戴森、查尔斯·戴维森、安德鲁·克罗姆林和阿尔伯特·爱因斯坦。"},{"label":"发生了什么","value":"英国天文学团队分别前往普林西比岛和巴西索布拉尔，利用日全食时太阳被遮挡的机会拍摄太阳附近恒星位置。观测数据用于检验太阳引力是否会使星光发生偏折。1919年11月，英国皇家学会和皇家天文学会会议公布结果，认为数据支持爱因斯坦广义相对论。"},{"label":"为什么重要","value":"它让德国科学家爱因斯坦在一战后获得跨国声望，也成为现代科学、媒体和国际合作关系的标志性事件。"},{"label":"前因","value":"爱因斯坦1915年提出广义相对论，并预言太阳引力会使经过太阳附近的光线偏折。"},{"label":"后果","value":"广义相对论获得更广泛承认，爱因斯坦成为公众人物，科学新闻进入大众媒体。"},{"label":"出处","value":"Royal Society: 1919 eclipse and general relativity；NASA: Einstein and Eddington；Lemos et al., Einstein and Eddington and the consequences of general relativity。"}],"relationItems":["← 前因：爱因斯坦广义相对论","→ 后果：现代物理学革命","↔ 相关：一战后国际科学合作"],"relations":[{"text":"← 前因：爱因斯坦广义相对论","id":"extra723"}],"source":"history","id":"card203"},{"title":"德国“十一月罪人”政治污名","level":"B","type":"概念/思潮卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1919年后，1920年代—1930年代初持续使用","place":"德国","summary":"“十一月罪人”是德国右翼攻击共和国政治家的污名话语，把战败、革命和凡尔赛责任转嫁给民主派。","fields":[{"label":"标题","value":"德国“十一月罪人”政治污名"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1919年后，1920年代—1930年代初持续使用"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"“十一月罪人”是德国右翼攻击共和国政治家的污名话语，把战败、革命和凡尔赛责任转嫁给民主派。"},{"label":"核心主张/思路","value":"把1918年十一月革命、停战签署、共和国建立和凡尔赛条约说成少数政客对前线军队和民族的背叛。"},{"label":"提出者/代表人物（可选）","value":"德国民族人民党、民族主义媒体、纳粹党和反共和国右翼团体。"},{"label":"它从何而来","value":"德国“背后一刀”传说、战败责任逃避、反社会主义情绪、反犹主义和对凡尔赛条约的愤怒相互叠加。"},{"label":"典型表现","value":"把埃尔茨贝格、谢德曼、社会民主党、中央党和其他共和国支持者称为“Novemberverbrecher”。"},{"label":"为什么重要","value":"它削弱魏玛共和国合法性，给右翼暴力、政治暗杀和纳粹反共和国宣传提供语言武器。"},{"label":"争议/局限","value":"这个污名掩盖德国军事失败和最高陆军指挥部责任，把复杂的战败原因简化成内部背叛阴谋。"},{"label":"出处","value":"DHM/LeMO: Dolchstoßlegende；Encyclopaedia Britannica: Weimar Republic；Richard J. Evans, The Coming of the Third Reich。"}],"relationItems":["← 前因：德国“背后一刀”传说","↔ 相关：凡尔赛条约","↔ 相关：魏玛共和国成立","→ 后果：纳粹宣传机器"],"relations":[{"text":"← 前因：德国“背后一刀”传说","id":"extra623"},{"text":"↔ 相关：魏玛共和国成立","id":"card7"},{"text":"→ 后果：纳粹宣传机器","id":"extra94"}],"source":"history","id":"card204"},{"title":"五四运动","level":"A","type":"事件卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1919年5月4日起","place":"中国北京，后扩展到上海等城市","summary":"五四运动由巴黎和会山东问题引爆，推动中国民族主义、新文化运动和现代政治动员。","fields":[{"label":"标题","value":"五四运动"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1919年5月4日起"},{"label":"地点","value":"中国北京，后扩展到上海等城市"},{"label":"主要国家","value":"中国；日本；英国；法国；美国；德国"},{"label":"一句话概括","value":"五四运动由巴黎和会山东问题引爆，推动中国民族主义、新文化运动和现代政治动员。"},{"label":"参与者","value":"北京学生、知识分子、商人、工人、北洋政府、巴黎和会中国代表团和各地市民。"},{"label":"发生了什么","value":"巴黎和会决定把德国在山东的权益转交日本后，北京学生在天安门前集会抗议，要求拒签和约、惩办亲日官员。运动遭镇压后扩展到罢课、罢工、罢市和全国舆论动员。中国代表最终拒绝在《凡尔赛条约》上签字。"},{"label":"为什么重要","value":"它把国际外交失败转化为中国现代民族主义和群众政治的节点，也推动马克思主义传播和中国共产党成立背景。"},{"label":"前因","value":"日本“二十一条”、德国强租胶州湾、一战日英攻占青岛战役和巴黎和会山东问题共同积累不满。"},{"label":"后果","value":"新文化运动政治化，中国外交和民族运动进入新阶段，青年学生成为现代政治动员的重要力量。"},{"label":"出处","value":"Encyclopaedia Britannica: May Fourth Movement；Jonathan Spence, The Search for Modern China；Rana Mitter, A Bitter Revolution。"}],"relationItems":["← 前因：巴黎和会山东问题","← 前因：一战日英攻占青岛战役","↔ 相关：新文化运动","→ 后果：中国共产党成立"],"relations":[{"text":"← 前因：巴黎和会山东问题","id":"card206"},{"text":"← 前因：一战日英攻占青岛战役","id":"extra703"}],"source":"history","id":"card205"},{"title":"巴黎和会山东问题","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1919年","place":"法国巴黎；中国山东","summary":"巴黎和会山东问题围绕德国在山东权益是否归还中国展开，最终引发五四运动。","fields":[{"label":"标题","value":"巴黎和会山东问题"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1919年"},{"label":"地点","value":"法国巴黎；中国山东"},{"label":"主要国家","value":"中国；日本；德国；英国；法国；美国"},{"label":"一句话概括","value":"巴黎和会山东问题围绕德国在山东权益是否归还中国展开，最终引发五四运动。"},{"label":"参与者","value":"巴黎和会中国代表团、日本代表团、英法美主要战胜国、北洋政府和中国公众舆论。"},{"label":"发生了什么","value":"中国作为战胜国要求收回德国在胶州湾和山东的权益，但日本依据对德作战占领、此前列强承诺和对中国压力，坚持继承德国权益。和会最终倾向日本，导致中国代表拒签《凡尔赛条约》，国内爆发五四运动。"},{"label":"为什么重要","value":"它说明战后民族自决原则在列强利益面前高度有限，也把中国现代民族主义推向新阶段。"},{"label":"前因","value":"德国强租胶州湾、一战日英攻占青岛战役、日本对华“二十一条”和协约国战时秘密承诺共同塑造争议。"},{"label":"后果","value":"五四运动爆发，中国拒签《凡尔赛条约》，山东问题后来在华盛顿会议中重新处理。"},{"label":"出处","value":"Encyclopaedia Britannica: Treaty of Versailles；Jonathan Spence, The Search for Modern China；Erez Manela, The Wilsonian Moment。"}],"relationItems":["← 前因：德国强租胶州湾","← 前因：一战日英攻占青岛战役","↔ 相关：一战后巴黎和会","→ 后果：五四运动"],"relations":[{"text":"← 前因：德国强租胶州湾","id":"extra773"},{"text":"← 前因：一战日英攻占青岛战役","id":"extra703"},{"text":"↔ 相关：一战后巴黎和会","id":"extra668"},{"text":"→ 后果：五四运动","id":"card205"}],"source":"history","id":"card206"},{"title":"保守道德政治","level":"C","type":"概念/思潮卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"19世纪末—20世纪上半叶，魏玛时期冲突突出","place":"欧洲和北美城市社会","summary":"保守道德政治把性、家庭、宗教和公共秩序视为政治斗争对象，反对自由化和都市现代性。","fields":[{"label":"标题","value":"保守道德政治"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"19世纪末—20世纪上半叶，魏玛时期冲突突出"},{"label":"地点","value":"欧洲和北美城市社会"},{"label":"主要国家","value":"德国；英国；美国；法国"},{"label":"一句话概括","value":"保守道德政治把性、家庭、宗教和公共秩序视为政治斗争对象，反对自由化和都市现代性。"},{"label":"核心主张/思路","value":"国家和社会应维护传统家庭、性别秩序、宗教伦理和公共风俗，对色情、同性恋、堕胎、夜生活和“颓废艺术”进行限制。"},{"label":"提出者/代表人物（可选）","value":"教会团体、保守政党、道德改革协会、民族主义者和部分医学、司法专家。"},{"label":"它从何而来","value":"城市化、女性就业、性改革、娱乐产业和青年文化被保守派视为社会秩序瓦解的信号。"},{"label":"典型表现","value":"反色情审查、反堕胎动员、反同性恋政治、攻击卡巴莱和夜生活、批判魏玛柏林现代性。"},{"label":"为什么重要","value":"它解释魏玛自由文化为何会遭到强烈反扑，也解释纳粹后来如何把道德净化、民族共同体和国家暴力连接起来。"},{"label":"争议/局限","value":"保守道德政治有时以保护家庭和儿童为名，但也可能压制个人权利、少数群体和文化实验。"},{"label":"出处","value":"Peter Gay, Weimar Culture；Cornelie Usborne, The Politics of the Body in Weimar Germany；DHM/LeMO: Weimar culture。"}],"relationItems":["✗ 对立/冲突：魏玛德国性改革运动","✗ 对立/冲突：都市自由想象","↔ 相关：魏玛第218条堕胎争议","→ 后果：纳粹文化控制"],"relations":[{"text":"✗ 对立/冲突：魏玛德国性改革运动","id":"card85"},{"text":"✗ 对立/冲突：都市自由想象","id":"card202"},{"text":"↔ 相关：魏玛第218条堕胎争议","id":"card96"},{"text":"→ 后果：纳粹文化控制","id":"extra113"}],"source":"history","id":"card207"}],"extraHistoryCards":[{"title":"纳粹德国无条件投降","level":"A","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1945年5月7日至8日签署，欧洲战事于5月8日结束","place":"法国兰斯、德国柏林卡尔斯霍斯特","summary":"纳粹德国无条件投降结束欧洲战场，也使德国国家主权被盟国接管，战后重组由此开始。","fields":[{"label":"标题","value":"纳粹德国无条件投降"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1945年5月7日至8日签署，欧洲战事于5月8日结束"},{"label":"地点","value":"法国兰斯、德国柏林卡尔斯霍斯特"},{"label":"主要国家","value":"德国、苏联、美国、英国、法国"},{"label":"一句话概括","value":"纳粹德国无条件投降结束欧洲战场，也使德国国家主权被盟国接管，战后重组由此开始。"},{"label":"参与者","value":"德国国防军代表、盟军最高司令部、苏联红军、英美法盟军。"},{"label":"发生了什么","value":"1945年春，苏军攻入柏林，希特勒自杀，纳粹政权军事和政治体系崩溃。德国代表先在兰斯向西方盟军签署投降文件，随后又在柏林卡尔斯霍斯特向苏联及盟国正式确认无条件投降。投降不是一次普通停战，而是德国国家军事抵抗和纳粹政权合法性的彻底终结。盟国随后以占领权接管德国最高权力。"},{"label":"为什么重要","value":"它是战后重组时期的起点。德国不只是战败，而是失去中央政府和完整主权，必须在盟国占领、非纳粹化、赔偿、难民和制度重建中重新定义国家。"},{"label":"前因","value":"1945年春盟军从东西两线攻入德国，柏林战役和希特勒自杀使纳粹政权失去继续指挥战争的能力，德国军政体系已无条件谈判空间。"},{"label":"后果","value":"德国不是以主权国家身份签订普通和平条约，而是由盟国接管最高权力，随后进入分区占领、波茨坦安排、去纳粹化和制度重建阶段。"},{"label":"出处","value":"United States Holocaust Memorial Museum: German surrender；Deutsches Historisches Museum/LeMO: Kriegsende 1945；Encyclopaedia Britannica相关资料。"},{"label":"资料备注","value":"西欧通常以1945年5月8日为欧洲胜利日；苏联及部分东欧纪念日因时区和政治传统常为5月9日。"}],"relationItems":["← 前因：柏林战役","← 前因：柏林地堡希特勒自杀","→ 后果：盟国占领德国","→ 后果：盟国《波茨坦协定》","↔ 相关：纳粹德国崩溃"],"relations":[{"text":"← 前因：柏林战役","id":"extra276"},{"text":"← 前因：柏林地堡希特勒自杀","id":"extra277"},{"text":"→ 后果：盟国占领德国","id":"extra2"},{"text":"→ 后果：盟国《波茨坦协定》","id":"extra3"}],"source":"history","id":"extra1"},{"title":"盟国占领德国","level":"A","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1945年至1949年为核心阶段","place":"德国及柏林","summary":"盟国占领德国把战败德国分为四个占领区，既是去纳粹化和重建的框架，也埋下德国分裂的制度基础。","fields":[{"label":"标题","value":"盟国占领德国"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1945年至1949年为核心阶段"},{"label":"地点","value":"德国及柏林"},{"label":"主要国家","value":"美国、英国、法国、苏联、德国"},{"label":"一句话概括","value":"盟国占领德国把战败德国分为四个占领区，既是去纳粹化和重建的框架，也埋下德国分裂的制度基础。"},{"label":"参与者","value":"美国、英国、法国、苏联四个占领当局，德国地方政府和居民。"},{"label":"发生了什么","value":"纳粹德国战败后，美国、英国、法国和苏联分别管理德国四个占领区，柏林虽位于苏占区内，也被分为四个占领扇区。盟国名义上共同治理德国，目标包括非军事化、去纳粹化、民主化和赔偿安排。但各占领国的安全利益、意识形态和经济政策差异很快扩大，西部占领区逐渐合作，苏占区则按苏联模式改造。"},{"label":"为什么重要","value":"占领体制决定了德国战后重建不是德国人单独完成的国家恢复，而是在冷战开始的国际权力结构中被重塑。"},{"label":"前因","value":"德国无条件投降后缺乏可继续承担国家主权的中央政府，盟国此前已在战时会议中规划分区占领和共同管制框架。"},{"label":"后果","value":"四国占领本来试图共同管理德国，但各占领国的安全利益和意识形态差异逐渐扩大，西部占领区合作与苏占区改造最终把德国推向两个国家。"},{"label":"出处","value":"Office of the Historian: Occupation and reconstruction of Germany；DHM/LeMO: Besatzungszonen；Encyclopaedia Britannica: Allied occupation of Germany。"}],"relationItems":["← 前因：纳粹德国无条件投降","→ 后果：盟国管制委员会","→ 后果：西占区双占区和三占区","→ 后果：德意志联邦共和国成立","→ 后果：德意志民主共和国成立"],"relations":[{"text":"← 前因：纳粹德国无条件投降","id":"extra1"},{"text":"→ 后果：盟国管制委员会","id":"extra4"},{"text":"→ 后果：西占区双占区和三占区","id":"extra12"},{"text":"→ 后果：德意志联邦共和国成立","id":"extra16"},{"text":"→ 后果：德意志民主共和国成立","id":"extra19"}],"source":"history","id":"extra2"},{"title":"盟国《波茨坦协定》","level":"A","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1945年7月至8月波茨坦会议后形成","place":"德国波茨坦","summary":"波茨坦协定确立战后德国占领和改造原则，用“四个D”框定德国重建，也把赔偿、边界和驱逐问题制度化。","fields":[{"label":"标题","value":"盟国《波茨坦协定》"},{"label":"分级","value":"A"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1945年7月至8月波茨坦会议后形成"},{"label":"地点","value":"德国波茨坦"},{"label":"主要国家","value":"美国、英国、苏联、法国、德国、波兰"},{"label":"一句话概括","value":"波茨坦协定确立战后德国占领和改造原则，用“四个D”框定德国重建，也把赔偿、边界和驱逐问题制度化。"},{"label":"制定方/签署方","value":"美国、英国、苏联三国首脑在波茨坦会议上达成；法国随后参与执行占领安排但未参加会议。"},{"label":"主要内容","value":"确认德国非军事化、去纳粹化、民主化和分散化的方向；规定盟国共同管理德国；安排赔偿和工业限制；承认奥得河—尼斯河线以东地区由波兰和苏联管理；提出对德国人口转移应有秩序地进行。"},{"label":"它试图解决什么问题","value":"战胜国需要在纳粹德国崩溃后处理安全、防止德国再发动战争、赔偿战争损失、管理边界和重建政治秩序。"},{"label":"为什么重要","value":"它是战后德国重组的基本蓝图。后来很多冲突，如赔偿、占领区经济政策、东部边界和难民驱逐，都可以追溯到波茨坦框架。"},{"label":"争议/局限","value":"协议留下许多模糊空间。西方与苏联对民主化、赔偿和德国经济统一的理解不同，导致共同占领机制很快失灵。"},{"label":"造成的影响","value":"盟国占领政策获得正式原则；德国东部领土和人口转移问题进入战后秩序；德国统一经济管理目标逐渐被冷战分裂取代。"},{"label":"出处","value":"Avalon Project: Berlin (Potsdam) Conference Protocol；Office of the Historian: Potsdam Conference；DHM/LeMO: Potsdamer Abkommen。"}],"relationItems":["← 前因：盟国占领德国","← 前因：雅尔塔会议","→ 后果：德国去纳粹化","→ 后果：德国战后赔偿与拆迁","→ 后果：德国东部领土丧失与被驱逐者","↔ 相关：盟国管制委员会"],"relations":[{"text":"← 前因：盟国占领德国","id":"extra2"},{"text":"← 前因：雅尔塔会议","id":"extra265"},{"text":"→ 后果：德国去纳粹化","id":"extra5"},{"text":"→ 后果：德国战后赔偿与拆迁","id":"extra10"},{"text":"→ 后果：德国东部领土丧失与被驱逐者","id":"extra7"},{"text":"↔ 相关：盟国管制委员会","id":"extra4"}],"source":"history","id":"extra3"},{"title":"盟国管制委员会","level":"B","type":"组织/机构卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1945年成立；1948年后基本瘫痪","place":"德国柏林","summary":"盟国管制委员会名义上共同治理德国，但大国分歧使其难以维持德国整体管理，最终反映占领合作破裂。","fields":[{"label":"标题","value":"盟国管制委员会"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1945年成立；1948年后基本瘫痪"},{"label":"地点","value":"德国柏林"},{"label":"主要国家","value":"美国、英国、法国、苏联、德国"},{"label":"一句话概括","value":"盟国管制委员会名义上共同治理德国，但大国分歧使其难以维持德国整体管理，最终反映占领合作破裂。"},{"label":"性质/类型","value":"四大占领国共同治理德国的最高占领机构。"},{"label":"成立/解散时间","value":"1945年根据盟国占领安排建立；1948年苏联退出后基本停止作为共同治理机构运作。"},{"label":"核心目标/宗旨","value":"以四国一致原则处理德国整体事务，执行占领政策、非军事化、去纳粹化、经济管理和行政重建。"},{"label":"关键人物（可选）","value":"四国驻德军事总督和占领当局代表。"},{"label":"关键行动/事件","value":"发布占领法令，管理跨区政策，推动德国非军事化和行政重建；在赔偿、经济统一和政治方向问题上不断受阻。"},{"label":"为什么重要","value":"它显示战后德国最初并非必然分裂，盟国曾试图维持共同治理。但一致决策机制在冷战分歧下无法运作。"},{"label":"争议/局限","value":"四国一致原则使任何重大分歧都能阻塞治理。苏联和西方对德国经济复兴、赔偿、政党制度和安全缓冲的目标逐渐冲突。"},{"label":"出处","value":"DHM/LeMO: Alliierter Kontrollrat；Office of the Historian相关资料；German History Documents and Images相关资料。"}],"relationItems":["← 前因：盟国占领德国","← 前因：盟国《波茨坦协定》","→ 后果：西占区双占区和三占区","→ 后果：冷战初期柏林封锁与空运","↔ 相关：德国去纳粹化"],"relations":[{"text":"← 前因：盟国占领德国","id":"extra2"},{"text":"← 前因：盟国《波茨坦协定》","id":"extra3"},{"text":"→ 后果：西占区双占区和三占区","id":"extra12"},{"text":"→ 后果：冷战初期柏林封锁与空运","id":"extra14"},{"text":"↔ 相关：德国去纳粹化","id":"extra5"}],"source":"history","id":"extra4"},{"title":"德国去纳粹化","level":"B","type":"制度/文本卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1945年后启动，1940年代后期逐渐弱化","place":"德国四个占领区","summary":"德国去纳粹化试图清除纳粹人员、组织和思想影响，但在冷战、行政需要和社会自我辩护中逐渐变得有限。","fields":[{"label":"标题","value":"德国去纳粹化"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1945年后启动，1940年代后期逐渐弱化"},{"label":"地点","value":"德国四个占领区"},{"label":"主要国家","value":"德国、美国、英国、法国、苏联"},{"label":"一句话概括","value":"德国去纳粹化试图清除纳粹人员、组织和思想影响，但在冷战、行政需要和社会自我辩护中逐渐变得有限。"},{"label":"制定方/签署方","value":"盟国占领当局根据波茨坦原则和各占领区政策推动。"},{"label":"主要内容","value":"取缔纳粹党及其组织，清除政府、司法、教育和媒体中的纳粹骨干，审查个人政治责任，改造教材和公共文化，追究战争罪和反人类罪。"},{"label":"它试图解决什么问题","value":"战胜国认为德国若要重建，必须拆除纳粹政治机器和意识形态基础，防止军国主义和法西斯主义复活。"},{"label":"为什么重要","value":"它是战后德国政治重建的道德和制度前提。后来联邦德国和民主德国都以不同方式把“反纳粹”作为合法性资源。"},{"label":"争议/局限","value":"实际执行差异很大。西占区很快面临行政人才短缺和冷战压力，许多普通党员被重新纳入社会；苏占区则把去纳粹化同社会主义改造和清除政治对手结合。"},{"label":"造成的影响","value":"纳粹组织被解散；大规模审查和分类程序展开；德国社会形成长期的责任、沉默和记忆政治问题。"},{"label":"出处","value":"USHMM: Denazification；DHM/LeMO: Entnazifizierung；German History Documents and Images相关资料。"}],"relationItems":["← 前因：盟国《波茨坦协定》","← 前因：纳粹德国无条件投降","→ 后果：纳粹战犯纽伦堡审判","→ 后果：德国战后民主重建","↔ 相关：战后德国“零点时刻”"],"relations":[{"text":"← 前因：盟国《波茨坦协定》","id":"extra3"},{"text":"← 前因：纳粹德国无条件投降","id":"extra1"},{"text":"→ 后果：纳粹战犯纽伦堡审判","id":"extra6"},{"text":"↔ 相关：战后德国“零点时刻”","id":"extra9"}],"source":"history","id":"extra5"},{"title":"纳粹战犯纽伦堡审判","level":"A","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1945年11月至1946年10月为主要国际军事法庭审判","place":"德国纽伦堡","summary":"纽伦堡审判以国际法庭审判纳粹主要战犯，把侵略战争、战争罪和反人类罪转化为可追责的法律问题。","fields":[{"label":"标题","value":"纳粹战犯纽伦堡审判"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1945年11月至1946年10月为主要国际军事法庭审判"},{"label":"地点","value":"德国纽伦堡"},{"label":"主要国家","value":"美国、英国、苏联、法国、德国"},{"label":"一句话概括","value":"纽伦堡审判以国际法庭审判纳粹主要战犯，把侵略战争、战争罪和反人类罪转化为可追责的法律问题。"},{"label":"参与者","value":"国际军事法庭、盟国检察方、纳粹主要领导人和组织代表。"},{"label":"发生了什么","value":"战后盟国在纽伦堡设立国际军事法庭，审判戈林、里宾特洛甫、凯特尔等纳粹主要领导人。法庭指控包括破坏和平罪、战争罪和反人类罪，并审查纳粹组织的犯罪性质。审判以大量文件、影像和证人材料揭示纳粹侵略、纳粹犹太人大屠杀和占领暴行。此后美国还在纽伦堡继续组织后续审判，审理医生、法官、工业家和军官等群体。"},{"label":"为什么重要","value":"它既是战后清算纳粹罪行的核心事件，也是现代国际刑事法的重要起点之一。"},{"label":"前因","value":"纳粹德国战败后，盟国需要处理纳粹领导层、侵略战争、纳粹犹太人大屠杀和战争罪行的责任问题，并为去纳粹化建立具有示范意义的司法框架。"},{"label":"后果","value":"审判确立了追究个人战争责任和反人类罪责任的国际法先例，也迫使战后德国社会面对纳粹罪行和政治责任问题。"},{"label":"出处","value":"USHMM: International Military Tribunal at Nuremberg；DHM/LeMO: Nürnberger Prozesse；Encyclopaedia Britannica: Nuremberg trials。"}],"relationItems":["← 前因：德国去纳粹化","← 前因：纳粹犹太人大屠杀","→ 后果：德国战后责任讨论","↔ 相关：纳粹优生政策","↔ 相关：纳粹战争罪行"],"relations":[{"text":"← 前因：德国去纳粹化","id":"extra5"},{"text":"← 前因：纳粹犹太人大屠杀","id":"extra218"},{"text":"↔ 相关：纳粹优生政策","id":"extra118"}],"source":"history","id":"extra6"},{"title":"德国东部领土丧失与被驱逐者","level":"B","type":"事件卡","tags":["经济与社会","战争与外交"],"mainTag":"经济与社会","subTag":"战争与外交","timeText":"1945年前后至1940年代后期","place":"奥得河—尼斯河线以东地区、捷克斯洛伐克、波兰、德国各占领区","summary":"德国战败后失去东部大片领土，数百万德意志人逃亡或被驱逐，深刻改变战后德国社会结构和记忆政治。","fields":[{"label":"标题","value":"德国东部领土丧失与被驱逐者"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1945年前后至1940年代后期"},{"label":"地点","value":"奥得河—尼斯河线以东地区、捷克斯洛伐克、波兰、德国各占领区"},{"label":"主要国家","value":"德国、波兰、捷克斯洛伐克、苏联、盟国"},{"label":"一句话概括","value":"德国战败后失去东部大片领土，数百万德意志人逃亡或被驱逐，深刻改变战后德国社会结构和记忆政治。"},{"label":"参与者","value":"德国平民、波兰和捷克斯洛伐克等国政府、苏联及盟国占领当局。"},{"label":"发生了什么","value":"随着苏军推进和战后边界重划，奥得河—尼斯河线以东的德国地区转由波兰和苏联管理，苏台德等地德意志人也被大规模驱逐。许多人在战争末期逃亡，另一些人在战后被强制迁移到德国占领区。波茨坦协定承认人口转移应以“有秩序和人道”方式进行，但现实中伴随暴力、财产剥夺、饥饿、疾病和大量死亡。"},{"label":"为什么重要","value":"这使战后德国面对巨大难民吸收压力，也让“家园丧失”成为西德政治和社会记忆中的长期议题。"},{"label":"前因","value":"纳粹德国在东欧发动侵略和种族战争，战败后苏联和波兰边界西移，波茨坦框架又把德国东部领土和德意志人口转移问题纳入战后安排。"},{"label":"后果","value":"数百万被驱逐者进入各占领区，显著加重住房、粮食和社会整合压力，也使奥得河—尼斯河边界和被驱逐者记忆长期影响西德政治。"},{"label":"出处","value":"DHM/LeMO: Flucht und Vertreibung；German History Documents and Images相关资料；Encyclopaedia Britannica相关资料。"}],"relationItems":["← 前因：盟国《波茨坦协定》","← 前因：纳粹德国东欧侵略","→ 后果：战后德国饥饿与住房危机","→ 后果：西德被驱逐者政治","↔ 相关：盟国占领德国"],"relations":[{"text":"← 前因：盟国《波茨坦协定》","id":"extra3"},{"text":"→ 后果：战后德国饥饿与住房危机","id":"extra8"},{"text":"↔ 相关：盟国占领德国","id":"extra2"}],"source":"history","id":"extra7"},{"title":"战后德国饥饿与住房危机","level":"C","type":"概念/思潮卡","tags":["经济与社会","战争与外交"],"mainTag":"经济与社会","subTag":"战争与外交","timeText":"1945年至1948年前后尤为突出","place":"德国各占领区，城市地区尤其严重","summary":"战后德国饥饿与住房危机让重建首先成为生存问题，解释了黑市、配给、难民安置和货币改革的紧迫性。","fields":[{"label":"标题","value":"战后德国饥饿与住房危机"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1945年至1948年前后尤为突出"},{"label":"地点","value":"德国各占领区，城市地区尤其严重"},{"label":"主要国家","value":"德国、盟国占领国"},{"label":"一句话概括","value":"战后德国饥饿与住房危机让重建首先成为生存问题，解释了黑市、配给、难民安置和货币改革的紧迫性。"},{"label":"核心主张/思路","value":"战后德国社会不是直接进入民主繁荣，而是在废墟、粮食短缺、燃料不足、住房毁坏和难民涌入中恢复基本生活。"},{"label":"提出者/代表人物（可选）","value":"无单一提出者，主要是战后社会现实和占领政策共同塑造的经验。"},{"label":"它从何而来","value":"盟军轰炸、交通和工业体系崩溃、农业供应不足、占领区分割、人口流动和寒冬共同造成民生危机。"},{"label":"典型表现","value":"粮食配给、黑市交易、城市居民到乡村换食物、燃料短缺、废墟清理、多人挤住同一住宅、难民营和临时安置。"},{"label":"为什么重要","value":"它提醒战后重建不是抽象制度设计。普通德国人的政治态度、对稳定的渴望和对经济改革的接受，都与日常生存压力有关。"},{"label":"争议/局限","value":"德国平民苦难不能掩盖纳粹战争和纳粹犹太人大屠杀造成的更大灾难，也不能把德国社会简单塑造成纯粹受害者。"},{"label":"出处","value":"DHM/LeMO: Nachkriegsalltag；German History Documents and Images相关资料；Tony Judt, Postwar相关论述。"}],"relationItems":["← 前因：纳粹德国无条件投降","← 前因：德国东部领土丧失与被驱逐者","→ 后果：1948年西占区货币改革","↔ 相关：战后德国“零点时刻”"],"relations":[{"text":"← 前因：纳粹德国无条件投降","id":"extra1"},{"text":"← 前因：德国东部领土丧失与被驱逐者","id":"extra7"},{"text":"→ 后果：1948年西占区货币改革","id":"extra13"},{"text":"↔ 相关：战后德国“零点时刻”","id":"extra9"}],"source":"history","id":"extra8"},{"title":"战后德国“零点时刻”","level":"C","type":"概念/思潮卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1945年后形成并流行","place":"德国","summary":"“零点时刻”把1945年说成德国重新开始的起点，既表达废墟后的断裂感，也容易淡化纳粹延续和责任问题。","fields":[{"label":"标题","value":"战后德国“零点时刻”"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1945年后形成并流行"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"“零点时刻”把1945年说成德国重新开始的起点，既表达废墟后的断裂感，也容易淡化纳粹延续和责任问题。"},{"label":"核心主张/思路","value":"把1945年德国战败、废墟经验和制度重建理解为历史归零，强调旧时代结束和重新开始。"},{"label":"提出者/代表人物（可选）","value":"不是单一人物提出，而是战后公共语言、媒体叙事、政治讲话和历史解释共同塑造的说法。"},{"label":"它从何而来","value":"纳粹国家崩溃、城市废墟、盟国占领、去纳粹化和普通人希望摆脱战争责任与生存困境的心理。"},{"label":"典型表现","value":"德语“Stunde Null”常被用来描述1945年后的断裂感、废墟中的重建和制度重新开始。"},{"label":"为什么重要","value":"它解释战后德国社会如何理解断裂和重建，也提示战后叙事中“重新开始”与“承担责任”之间的张力。"},{"label":"争议/局限","value":"“零点”容易制造完全清零的错觉，淡化纳粹时期人员延续、社会自我辩护和受害者记忆。"},{"label":"出处","value":"DHM/LeMO关于1945年“Stunde Null”与战后社会资料；German History Documents and Images相关资料。"},{"label":"资料备注","value":"德语原文为 Stunde Null。该说法有解释力，但不能把1945年理解为人员、观念和社会结构的完全清零。"}],"relationItems":["← 前因：纳粹德国无条件投降","↔ 相关：德国去纳粹化","↔ 相关：战后德国饥饿与住房危机","✗ 对立/冲突：纳粹连续性与战后责任讨论"],"relations":[{"text":"← 前因：纳粹德国无条件投降","id":"extra1"},{"text":"↔ 相关：德国去纳粹化","id":"extra5"},{"text":"↔ 相关：战后德国饥饿与住房危机","id":"extra8"}],"source":"history","id":"extra9"},{"title":"德国战后赔偿与拆迁","level":"B","type":"制度/文本卡","tags":["经济与社会","战争与外交"],"mainTag":"经济与社会","subTag":"战争与外交","timeText":"1945年后，1940年代后期仍持续","place":"德国各占领区","summary":"德国战后赔偿与拆迁把战争责任转化为物资、工业设备和劳动力补偿，也加剧东西占领区经济政策分歧。","fields":[{"label":"标题","value":"德国战后赔偿与拆迁"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1945年后，1940年代后期仍持续"},{"label":"地点","value":"德国各占领区"},{"label":"主要国家","value":"德国、苏联、美国、英国、法国及受害国"},{"label":"一句话概括","value":"德国战后赔偿与拆迁把战争责任转化为物资、工业设备和劳动力补偿，也加剧东西占领区经济政策分歧。"},{"label":"制定方/签署方","value":"盟国通过波茨坦框架和各占领区政策执行。"},{"label":"主要内容","value":"拆除或限制德国军事和重工业设施，将工厂设备、物资和专利等作为赔偿转移；苏联在东部占领区尤其重视以拆迁、征收和苏联股份公司形式取得补偿。"},{"label":"它试图解决什么问题","value":"纳粹德国造成巨大破坏，受害国尤其苏联要求德国承担赔偿，同时盟国希望削弱德国再发动战争的工业能力。"},{"label":"为什么重要","value":"赔偿政策直接影响德国经济恢复速度，也推动西方从“限制德国”逐渐转向“复兴德国以稳定欧洲”。"},{"label":"争议/局限","value":"过度拆迁会削弱德国民生和欧洲复苏。西方担心德国长期贫困会制造政治不稳定，苏联则强调自身战争损失和安全补偿。"},{"label":"造成的影响","value":"东占区工业损失严重；西方占领政策逐步从惩罚转向重建；冷战经济分裂加深。"},{"label":"出处","value":"Office of the Historian相关资料；DHM/LeMO: Demontagen；German History Documents and Images相关资料。"}],"relationItems":["← 前因：盟国《波茨坦协定》","→ 后果：马歇尔计划与西德重建","→ 后果：西占区双占区和三占区","↔ 相关：盟国占领德国"],"relations":[{"text":"← 前因：盟国《波茨坦协定》","id":"extra3"},{"text":"→ 后果：马歇尔计划与西德重建","id":"extra11"},{"text":"→ 后果：西占区双占区和三占区","id":"extra12"},{"text":"↔ 相关：盟国占领德国","id":"extra2"}],"source":"history","id":"extra10"},{"title":"马歇尔计划与西德重建","level":"B","type":"制度/文本卡","tags":["经济与社会","战争与外交"],"mainTag":"经济与社会","subTag":"战争与外交","timeText":"1947年提出，1948年后执行","place":"西欧与德国西部占领区","summary":"马歇尔计划把西部德国纳入西欧复兴和美国冷战战略，推动西德经济恢复，也加深德国东西分裂。","fields":[{"label":"标题","value":"马歇尔计划与西德重建"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1947年提出，1948年后执行"},{"label":"地点","value":"西欧与德国西部占领区"},{"label":"主要国家","value":"美国、英国、法国、德国及西欧国家"},{"label":"一句话概括","value":"马歇尔计划把西部德国纳入西欧复兴和美国冷战战略，推动西德经济恢复，也加深德国东西分裂。"},{"label":"制定方/签署方","value":"美国政府提出欧洲复兴计划，西欧国家和西部占领区参与执行；苏联及东欧国家拒绝或被迫退出。"},{"label":"主要内容","value":"美国向欧洲提供援助、贷款、物资和技术支持，要求受援方协调经济政策并提高生产能力。西部德国通过相关机制获得物资、资金和制度支持。"},{"label":"它试图解决什么问题","value":"美国希望防止欧洲经济崩溃、遏制共产主义扩张、恢复贸易体系，并让德国西部成为稳定西欧秩序的一部分。"},{"label":"为什么重要","value":"它改变了对德国的政策方向：西德不再只是被控制的战败国，而逐渐成为西方阵营中需要恢复的经济核心。"},{"label":"争议/局限","value":"援助不是单纯慈善，而是冷战战略和市场重建工程。苏联认为它会把西欧纳入美国影响范围，因此加速东欧和东德的阵营化。"},{"label":"造成的影响","value":"西部德国经济恢复获得外部支撑；欧洲经济合作加强；东西占领区差异扩大。"},{"label":"出处","value":"Office of the Historian: Marshall Plan；DHM/LeMO: Marshallplan；Encyclopaedia Britannica: Marshall Plan。"}],"relationItems":["← 前因：德国战后赔偿与拆迁","← 前因：战后德国饥饿与住房危机","→ 后果：西占区双占区和三占区","→ 后果：西德社会市场经济","↔ 相关：冷战形成"],"relations":[{"text":"← 前因：德国战后赔偿与拆迁","id":"extra10"},{"text":"← 前因：战后德国饥饿与住房危机","id":"extra8"},{"text":"→ 后果：西占区双占区和三占区","id":"extra12"},{"text":"→ 后果：西德社会市场经济","id":"extra17"},{"text":"↔ 相关：冷战形成","id":"extra849"}],"source":"history","id":"extra11"},{"title":"西占区双占区和三占区","level":"B","type":"组织/机构卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"双占区1947年1月形成；法国占领区1949年4月并入三占区经济框架","place":"德国西部占领区","summary":"双占区和三占区把西部占领区从合作管理推向准国家结构，为德意志联邦共和国成立铺路。","fields":[{"label":"标题","value":"西占区双占区和三占区"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"双占区1947年1月形成；法国占领区1949年4月并入三占区经济框架"},{"label":"地点","value":"德国西部占领区"},{"label":"主要国家","value":"美国、英国、法国、德国"},{"label":"一句话概括","value":"双占区和三占区把西部占领区从合作管理推向准国家结构，为德意志联邦共和国成立铺路。"},{"label":"性质/类型","value":"西部占领区经济和行政合并机制。"},{"label":"成立/解散时间","value":"美国和英国占领区于1947年合并为双占区；法国占领区随后逐渐并入，形成三占区框架。"},{"label":"核心目标/宗旨","value":"统一西部占领区经济管理，降低占领成本，恢复生产和财政秩序，并为西部德国政治重建创造行政基础。"},{"label":"关键人物（可选）","value":"美英法占领当局，西部德国州级政治家。"},{"label":"关键行动/事件","value":"建立共同经济管理机构，推动经济委员会和行政机关，配合马歇尔计划和货币改革，逐渐形成西部德国政治经济核心。"},{"label":"为什么重要","value":"它说明德国分裂不是一天发生的，而是在占领区合作失败后，通过经济合并、行政整合和货币改革逐步制度化。"},{"label":"争议/局限","value":"西方认为这是恢复秩序和经济效率的必要步骤，苏联则把它视为破坏德国统一管理和建立西方德国国家的前奏。"},{"label":"出处","value":"DHM/LeMO: Bizone；Office of the Historian相关资料；German History Documents and Images相关资料。"}],"relationItems":["← 前因：盟国管制委员会","← 前因：马歇尔计划与西德重建","→ 后果：1948年西占区货币改革","→ 后果：德意志联邦共和国成立","✗ 对立/冲突：苏联占领区社会主义改造"],"relations":[{"text":"← 前因：盟国管制委员会","id":"extra4"},{"text":"← 前因：马歇尔计划与西德重建","id":"extra11"},{"text":"→ 后果：1948年西占区货币改革","id":"extra13"},{"text":"→ 后果：德意志联邦共和国成立","id":"extra16"},{"text":"✗ 对立/冲突：苏联占领区社会主义改造","id":"extra18"}],"source":"history","id":"extra12"},{"title":"1948年西占区货币改革","level":"A","type":"事件卡","tags":["经济与社会","战争与外交"],"mainTag":"经济与社会","subTag":"战争与外交","timeText":"1948年6月20日，西柏林随后实施","place":"德国西部占领区和西柏林","summary":"1948年西占区货币改革以德国马克取代旧帝国马克，恢复市场和财政秩序，也直接触发柏林封锁。","fields":[{"label":"标题","value":"1948年西占区货币改革"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1948年6月20日，西柏林随后实施"},{"label":"地点","value":"德国西部占领区和西柏林"},{"label":"主要国家","value":"美国、英国、法国、德国、苏联"},{"label":"一句话概括","value":"1948年西占区货币改革以德国马克取代旧帝国马克，恢复市场和财政秩序，也直接触发柏林封锁。"},{"label":"参与者","value":"美英法占领当局、西部德国行政机构、路德维希·艾哈德、苏联占领当局。"},{"label":"发生了什么","value":"战后旧货币失去信用，配给和黑市普遍存在。1948年6月，西方占领区推出新货币德国马克，限制旧币兑换并配合价格和经济政策调整。货币改革迅速改善市场流通，商店商品重新出现。西方随后把改革扩展到西柏林，苏联认为这是破坏四国共同管理柏林和德国经济统一，随即升级交通封锁。"},{"label":"为什么重要","value":"它是西部德国经济重建的关键转折，也是德国分裂从行政和经济差异走向公开冷战危机的节点。"},{"label":"前因","value":"旧帝国马克在战后黑市和配给经济中基本失去信用，西部占领区经济整合和马歇尔计划执行也需要稳定货币和价格体系。"},{"label":"后果","value":"货币改革恢复了西部市场秩序，却被苏联视为破坏四国共同管理德国和柏林的单边行动，直接引发柏林封锁，并推动西德国家建设加速。"},{"label":"出处","value":"DHM/LeMO: Währungsreform 1948；Bundesbank historical materials；Office of the Historian相关资料。"}],"relationItems":["← 前因：西占区双占区和三占区","← 前因：马歇尔计划与西德重建","→ 后果：冷战初期柏林封锁与空运","→ 后果：西德社会市场经济"],"relations":[{"text":"← 前因：西占区双占区和三占区","id":"extra12"},{"text":"← 前因：马歇尔计划与西德重建","id":"extra11"},{"text":"→ 后果：冷战初期柏林封锁与空运","id":"extra14"},{"text":"→ 后果：西德社会市场经济","id":"extra17"}],"source":"history","id":"extra13"},{"title":"冷战初期柏林封锁与空运","level":"A","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1948年6月至1949年5月","place":"德国柏林","summary":"冷战初期柏林封锁与空运是冷战早期最重要危机之一，西方以空运维持西柏林，使德国分裂和阵营对峙公开化。","fields":[{"label":"标题","value":"冷战初期柏林封锁与空运"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1948年6月至1949年5月"},{"label":"地点","value":"德国柏林"},{"label":"主要国家","value":"苏联、美国、英国、法国、德国"},{"label":"一句话概括","value":"冷战初期柏林封锁与空运是冷战早期最重要危机之一，西方以空运维持西柏林，使德国分裂和阵营对峙公开化。"},{"label":"参与者","value":"苏联占领当局、美国和英国空军、法国占领当局、西柏林居民、柏林市政当局。"},{"label":"发生了什么","value":"西方在西占区及西柏林推进货币改革后，苏联切断西方通往西柏林的陆路和水路交通，试图迫使西方放弃西柏林或撤回政策。美国和英国组织大规模空运，持续向西柏林运送食品、煤炭和生活物资。空运持续近一年，苏联未能迫使西方撤出，1949年5月解除封锁。"},{"label":"为什么重要","value":"它把德国问题变成冷战前线。西柏林从占领飞地变成西方抵抗苏联压力的象征，也推动西方加速建立西德国家。"},{"label":"前因","value":"西部占领区货币改革和西方国家推动西德建国，使苏联认为其在德国和柏林的安全利益受到威胁。此时盟国管制机制已经难以调和双方冲突。"},{"label":"后果","value":"西方空运维持了西柏林，也把德国问题公开变成冷战前线。危机结束后，西德和东德相继成立，德国分裂制度化。"},{"label":"出处","value":"Office of the Historian: Berlin Airlift；DHM/LeMO: Berlin-Blockade；Encyclopaedia Britannica: Berlin blockade。"}],"relationItems":["← 前因：1948年西占区货币改革","← 前因：盟国管制委员会","→ 后果：德意志联邦共和国成立","→ 后果：德意志民主共和国成立","↔ 相关：冷战形成"],"relations":[{"text":"← 前因：1948年西占区货币改革","id":"extra13"},{"text":"← 前因：盟国管制委员会","id":"extra4"},{"text":"→ 后果：德意志联邦共和国成立","id":"extra16"},{"text":"→ 后果：德意志民主共和国成立","id":"extra19"},{"text":"↔ 相关：冷战形成","id":"extra849"}],"source":"history","id":"extra14"},{"title":"西德《基本法》","level":"A","type":"制度/文本卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1949年5月23日生效","place":"德国波恩及西部占领区","summary":"西德《基本法》以临时宪法形式建立联邦民主制度，吸取魏玛失败经验，并把西德国家建立在西方占领框架内。","fields":[{"label":"标题","value":"西德《基本法》"},{"label":"分级","value":"A"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1949年5月23日生效"},{"label":"地点","value":"德国波恩及西部占领区"},{"label":"主要国家","value":"德国、美国、英国、法国"},{"label":"一句话概括","value":"西德《基本法》以临时宪法形式建立联邦民主制度，吸取魏玛失败经验，并把西德国家建立在西方占领框架内。"},{"label":"制定方/签署方","value":"西部各州代表组成的议会委员会起草，西方占领当局批准，1949年5月23日公布生效。"},{"label":"主要内容","value":"确立人的尊严和基本权利，建立联邦制、议会制、联邦宪法法院和建设性不信任案等制度；强调该法具有临时性质，保留德国统一愿望。"},{"label":"它试图解决什么问题","value":"西部德国需要建立稳定民主政府，同时避免魏玛时期总统紧急权、议会碎片化和反民主力量合法摧毁制度的风险。"},{"label":"为什么重要","value":"它是联邦德国政治秩序的核心文本。它把战后德国民主重建从占领管理推进为宪政国家，同时体现德国分裂尚被视为临时状态。"},{"label":"争议/局限","value":"它不是由全德国人民统一制宪产生，而是在西方占领和德国分裂加深的条件下形成；“临时性”与实际建国功能之间存在张力。"},{"label":"造成的影响","value":"德意志联邦共和国成立；西德议会民主和联邦制确立；德国统一问题以宪法语言保留下来。"},{"label":"出处","value":"Bundestag: Basic Law；DHM/LeMO: Grundgesetz；German History Documents and Images相关文本。"}],"relationItems":["← 前因：冷战初期柏林封锁与空运","← 前因：西占区双占区和三占区","→ 后果：德意志联邦共和国成立","↔ 相关：魏玛宪法","✗ 对立/冲突：德意志民主共和国成立"],"relations":[{"text":"← 前因：冷战初期柏林封锁与空运","id":"extra14"},{"text":"← 前因：西占区双占区和三占区","id":"extra12"},{"text":"→ 后果：德意志联邦共和国成立","id":"extra16"},{"text":"↔ 相关：魏玛宪法","id":"card11"},{"text":"✗ 对立/冲突：德意志民主共和国成立","id":"extra19"}],"source":"history","id":"extra15"},{"title":"德意志联邦共和国成立","level":"A","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1949年5月23日《基本法》生效，1949年9月组建首届联邦政府","place":"德国西部占领区，政府所在地波恩","summary":"德意志联邦共和国在西方占领区基础上成立，使西部德国成为议会民主国家和西方阵营成员。","fields":[{"label":"标题","value":"德意志联邦共和国成立"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1949年5月23日《基本法》生效，1949年9月组建首届联邦政府"},{"label":"地点","value":"德国西部占领区，政府所在地波恩"},{"label":"主要国家","value":"德国、美国、英国、法国"},{"label":"一句话概括","value":"德意志联邦共和国在西方占领区基础上成立，使西部德国成为议会民主国家和西方阵营成员。"},{"label":"参与者","value":"西部德国各州、议会委员会、西方占领当局、康拉德·阿登纳、德国政党。"},{"label":"发生了什么","value":"在西方占领区经济和行政整合、货币改革和柏林危机之后，西部各州代表制定《基本法》。1949年5月，《基本法》生效，德意志联邦共和国成立。随后举行联邦议院选举，康拉德·阿登纳成为首任联邦总理。新国家仍受占领法规限制，但已拥有自己的议会、政府和联邦制度。"},{"label":"为什么重要","value":"它标志德国分裂的西部国家形态正式形成，也开启西德民主巩固、经济复兴和西方一体化道路。"},{"label":"前因","value":"西部占领区在经济、货币和行政上逐步合并，柏林封锁进一步强化西方阵营内部合作，《基本法》则为西部德国建立联邦民主制度提供宪制基础。"},{"label":"后果","value":"西德建国使德国分裂进入国家层面，并为社会市场经济和西方一体化奠定制度基础。苏占区随后建立德意志民主共和国作为回应。"},{"label":"出处","value":"DHM/LeMO: Gründung der Bundesrepublik；Bundestag相关资料；Office of the Historian相关资料。"}],"relationItems":["← 前因：西德《基本法》","← 前因：1948年西占区货币改革","→ 后果：西德社会市场经济","→ 后果：德意志民主共和国成立","✗ 对立/冲突：德意志民主共和国成立"],"relations":[{"text":"← 前因：西德《基本法》","id":"extra15"},{"text":"← 前因：1948年西占区货币改革","id":"extra13"},{"text":"→ 后果：西德社会市场经济","id":"extra17"},{"text":"→ 后果：德意志民主共和国成立","id":"extra19"},{"text":"✗ 对立/冲突：德意志民主共和国成立","id":"extra19"}],"source":"history","id":"extra16"},{"title":"西德社会市场经济","level":"B","type":"概念/思潮卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1948年货币改革后成形，1949年后成为西德核心经济理念","place":"德意志联邦共和国","summary":"西德社会市场经济把市场竞争、货币稳定和社会保障结合起来，为西德战后复兴提供核心经济叙事。","fields":[{"label":"标题","value":"西德社会市场经济"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1948年货币改革后成形，1949年后成为西德核心经济理念"},{"label":"地点","value":"德意志联邦共和国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"西德社会市场经济把市场竞争、货币稳定和社会保障结合起来，为西德战后复兴提供核心经济叙事。"},{"label":"核心主张/思路","value":"经济应以竞争市场为基础，但国家要维护竞争秩序、货币稳定和基本社会保障，避免自由放任和计划经济两种极端。"},{"label":"提出者/代表人物（可选）","value":"路德维希·艾哈德、阿尔弗雷德·米勒-阿尔马克、秩序自由主义经济学者。"},{"label":"它从何而来","value":"魏玛经济危机、纳粹统制经济和战后黑市经验使西德改革者强调稳定货币、开放价格和制度秩序；同时战后社会也要求安全和福利补偿。"},{"label":"典型表现","value":"1948年货币改革后的价格放开和经济管理调整，反卡特尔和竞争秩序理念，社会保险和劳资协商制度逐步结合。"},{"label":"为什么重要","value":"它成为西德“经济奇迹”的解释框架之一，也帮助新共和国获得社会合法性。"},{"label":"争议/局限","value":"经济复兴不能只归功于一种理念，还包括马歇尔计划、战后低起点、工业基础、国际市场和劳动力等因素。"},{"label":"出处","value":"DHM/LeMO: Soziale Marktwirtschaft；Bundeszentrale für politische Bildung相关资料；Encyclopaedia Britannica: Ludwig Erhard。"}],"relationItems":["← 前因：1948年西占区货币改革","← 前因：马歇尔计划与西德重建","→ 后果：西德经济奇迹","↔ 相关：德意志联邦共和国成立"],"relations":[{"text":"← 前因：1948年西占区货币改革","id":"extra13"},{"text":"← 前因：马歇尔计划与西德重建","id":"extra11"},{"text":"↔ 相关：德意志联邦共和国成立","id":"extra16"}],"source":"history","id":"extra17"},{"title":"苏联占领区社会主义改造","level":"B","type":"事件卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1945年至1949年","place":"德国苏联占领区","summary":"苏联占领区通过土地改革、工业国有化和政党合并走向社会主义体制，为德意志民主共和国成立奠定基础。","fields":[{"label":"标题","value":"苏联占领区社会主义改造"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1945年至1949年"},{"label":"地点","value":"德国苏联占领区"},{"label":"主要国家","value":"苏联、德国"},{"label":"一句话概括","value":"苏联占领区通过土地改革、工业国有化和政党合并走向社会主义体制，为德意志民主共和国成立奠定基础。"},{"label":"参与者","value":"苏联军事管理当局、德国共产党、德国社会民主党东部组织、德国统一社会党、地方行政机构。"},{"label":"发生了什么","value":"苏联占领区在战后迅速推行土地改革，没收大地主和纳粹相关财产，重组地方行政和警察体系。1946年，在苏联压力和共产党推动下，东部德国共产党与社会民主党合并为德国统一社会党。工业企业被没收、国有化或转入苏联股份公司体系，教育和媒体也按反法西斯民主与社会主义方向改造。"},{"label":"为什么重要","value":"它说明东德不是1949年突然出现，而是在苏占区制度改造中逐步形成。政治多元空间被压缩，社会主义国家结构提前成型。"},{"label":"前因","value":"苏联在自己的占领区拥有实际最高权力，并把反法西斯改造、赔偿需求和安全缓冲区建设结合起来推进制度重塑。"},{"label":"后果","value":"土地改革、企业国有化和政党合并逐步形成苏式政治经济结构，为1949年德意志民主共和国成立和后来的计划经济奠定基础。"},{"label":"出处","value":"DHM/LeMO: SBZ；German History Documents and Images相关资料；Encyclopaedia Britannica: German Democratic Republic。"}],"relationItems":["← 前因：盟国占领德国","← 前因：德国去纳粹化","→ 后果：德意志民主共和国成立","✗ 对立/冲突：西占区双占区和三占区"],"relations":[{"text":"← 前因：盟国占领德国","id":"extra2"},{"text":"← 前因：德国去纳粹化","id":"extra5"},{"text":"→ 后果：德意志民主共和国成立","id":"extra19"},{"text":"✗ 对立/冲突：西占区双占区和三占区","id":"extra12"}],"source":"history","id":"extra18"},{"title":"德意志民主共和国成立","level":"A","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1949年10月7日","place":"德国苏联占领区，政治中心东柏林","summary":"德意志民主共和国在苏联占领区成立，是对西德建国的回应，也使德国分裂正式国家化。","fields":[{"label":"标题","value":"德意志民主共和国成立"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1949年10月7日"},{"label":"地点","value":"德国苏联占领区，政治中心东柏林"},{"label":"主要国家","value":"德国、苏联"},{"label":"一句话概括","value":"德意志民主共和国在苏联占领区成立，是对西德建国的回应，也使德国分裂正式国家化。"},{"label":"参与者","value":"苏联占领当局、德国统一社会党、德国人民委员会和人民议会、威廉·皮克、奥托·格罗提渥。"},{"label":"发生了什么","value":"西德成立后，苏联占领区加快建立东部德国国家。1949年10月7日，德国人民议会宣布德意志民主共和国成立，威廉·皮克成为总统，奥托·格罗提渥任总理。新国家表面保留多党和统一阵线结构，实际由德国统一社会党在苏联支持下掌握核心权力。"},{"label":"为什么重要","value":"它完成了1945年以来德国分裂的制度化。德国问题从战败国治理问题变成冷战两大阵营对峙中的双重国家问题。"},{"label":"前因","value":"苏联占领区已经完成政党、土地和工业结构改造。西德成立后，苏联和德国统一社会党推动建立东部德国国家，以回应西部建国并巩固本阵营控制。"},{"label":"后果","value":"东德成立使德国分裂正式国家化，德国问题由占领管理转为两个制度和两个阵营之间的长期对立。"},{"label":"出处","value":"DHM/LeMO: Gründung der DDR；Encyclopaedia Britannica: German Democratic Republic；German History Documents and Images相关资料。"}],"relationItems":["← 前因：苏联占领区社会主义改造","← 前因：德意志联邦共和国成立","→ 后果：德国长期分裂","✗ 对立/冲突：德意志联邦共和国成立","↔ 相关：冷战初期柏林封锁与空运"],"relations":[{"text":"← 前因：苏联占领区社会主义改造","id":"extra18"},{"text":"← 前因：德意志联邦共和国成立","id":"extra16"},{"text":"✗ 对立/冲突：德意志联邦共和国成立","id":"extra16"},{"text":"↔ 相关：冷战初期柏林封锁与空运","id":"extra14"}],"source":"history","id":"extra19"},{"title":"盟国《柏林宣言》","level":"B","type":"制度/文本卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1945年6月5日","place":"德国柏林","summary":"《柏林宣言》确认盟国接管德国最高权力，为四国占领和盟国管制委员会提供法律基础。","fields":[{"label":"标题","value":"盟国《柏林宣言》"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1945年6月5日"},{"label":"地点","value":"德国柏林"},{"label":"主要国家","value":"美国；英国；苏联；法国；德国"},{"label":"一句话概括","value":"《柏林宣言》确认盟国接管德国最高权力，为四国占领和盟国管制委员会提供法律基础。"},{"label":"制定方/签署方","value":"美国、英国、苏联和法国代表。"},{"label":"主要内容","value":"宣布德国战败后不再拥有有效中央政府，盟国承担德国最高权力，并按占领区和四国共同机制治理德国。"},{"label":"它试图解决什么问题","value":"德国无条件投降后，需要明确谁拥有国家最高权力、如何管理德国整体事务和占领区事务。"},{"label":"为什么重要","value":"它把军事投降转化为占领治理秩序，是战后德国国家主权中断和四国管制的关键文本。"},{"label":"争议/局限","value":"四国共同治理在文本上成立，但美英法苏对德国未来的目标差异很快削弱了共同管制。"},{"label":"造成的影响","value":"盟国管制委员会开始运作，德国进入分区占领和共同治理并存的阶段。"},{"label":"出处","value":"German History in Documents and Images: Establishment of the Allied Control Council, June 5, 1945；CVCE: Berlin Declaration, June 5, 1945；Encyclopaedia Britannica: Potsdam Conference。"}],"relationItems":["← 前因：纳粹德国无条件投降","→ 后果：盟国管制委员会","↔ 相关：盟国占领德国"],"relations":[{"text":"← 前因：纳粹德国无条件投降","id":"extra1"},{"text":"→ 后果：盟国管制委员会","id":"extra4"},{"text":"↔ 相关：盟国占领德国","id":"extra2"}],"source":"history","id":"extra20"},{"title":"美国对德摩根索计划","level":"C","type":"概念/思潮卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1944年提出，1945年后影响盟国早期对德政策讨论","place":"美国政策圈；盟国对德处置讨论","summary":"摩根索计划主张大幅削弱德国工业能力，体现盟国早期防止德国再军事化的严厉方案。","fields":[{"label":"标题","value":"美国对德摩根索计划"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1944年提出，1945年后影响盟国早期对德政策讨论"},{"label":"地点","value":"美国政策圈；盟国对德处置讨论"},{"label":"主要国家","value":"美国；德国；英国"},{"label":"一句话概括","value":"摩根索计划主张大幅削弱德国工业能力，体现盟国早期防止德国再军事化的严厉方案。"},{"label":"核心主张/思路","value":"通过拆分、去工业化和限制重工业，把德国转变为难以再次发动战争的国家。"},{"label":"提出者/代表人物（可选）","value":"美国财政部长亨利·摩根索。"},{"label":"它从何而来","value":"两次世界大战都由德国扩张引发，盟国内部有人认为必须从经济结构上消除德国战争能力。"},{"label":"典型表现","value":"关于鲁尔、重工业、拆迁和农业化的政策构想，以及战后早期较严厉的占领指令氛围。"},{"label":"为什么重要","value":"它不是最终完整实施的政策，却代表了战后对德政策从惩罚到重建转向前的一个极端选项。"},{"label":"争议/局限","value":"计划被批评会造成经济灾难，并不利于欧洲重建；后来西方政策逐步转向恢复西德经济。"},{"label":"出处","value":"bpb: Morgenthau-Plan；Encyclopaedia Britannica: World War II, Germany and the Morgenthau Plan；German History in Documents and Images: Allied occupation policy documents。"}],"relationItems":["← 前因：纳粹德国无条件投降","↔ 相关：德国战后赔偿与拆迁","→ 后果：马歇尔计划与西德重建"],"relations":[{"text":"← 前因：纳粹德国无条件投降","id":"extra1"},{"text":"↔ 相关：德国战后赔偿与拆迁","id":"extra10"},{"text":"→ 后果：马歇尔计划与西德重建","id":"extra11"}],"source":"history","id":"extra21"},{"title":"美国对德占领指令JCS 1067","level":"C","type":"制度/文本卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1945年4月批准，1945—1947年影响美国占领区政策","place":"美国政府；德国美国占领区","summary":"JCS 1067是美国早期占领德国的指令，强调非军事化和限制德国经济复兴。","fields":[{"label":"标题","value":"美国对德占领指令JCS 1067"},{"label":"分级","value":"C"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1945年4月批准，1945—1947年影响美国占领区政策"},{"label":"地点","value":"美国政府；德国美国占领区"},{"label":"主要国家","value":"美国；德国"},{"label":"一句话概括","value":"JCS 1067是美国早期占领德国的指令，强调非军事化和限制德国经济复兴。"},{"label":"制定方/签署方","value":"美国参谋长联席会议和美国政府。"},{"label":"主要内容","value":"要求美国占领当局避免把德国经济恢复作为目标，优先执行非军事化、去纳粹化、去集中化和控制工业。"},{"label":"它试图解决什么问题","value":"美国希望防止德国再次成为军事威胁，并在战争刚结束时避免过早扶持德国复兴。"},{"label":"为什么重要","value":"它说明美国对德政策不是一开始就支持“西德经济奇迹”，而是经历了从惩罚控制到重建扶持的转向。"},{"label":"争议/局限","value":"随着欧洲经济困难和冷战加剧，JCS 1067被认为不利于西欧恢复，后被更强调重建的政策取代。"},{"label":"造成的影响","value":"美国占领区初期政策偏谨慎和限制，后来马歇尔计划、双占区和货币改革显示政策方向改变。"},{"label":"出处","value":"German History in Documents and Images: Directive JCS 1067；U.S. Department of State historical materials on occupation policy；bpb: Besatzungspolitik in Deutschland。"}],"relationItems":["← 前因：美国对德摩根索计划","↔ 相关：德国去纳粹化","↔ 相关：德国战后赔偿与拆迁","→ 后果：马歇尔计划与西德重建"],"relations":[{"text":"← 前因：美国对德摩根索计划","id":"extra21"},{"text":"↔ 相关：德国去纳粹化","id":"extra5"},{"text":"↔ 相关：德国战后赔偿与拆迁","id":"extra10"},{"text":"→ 后果：马歇尔计划与西德重建","id":"extra11"}],"source":"history","id":"extra22"},{"title":"德国-波兰奥得-尼斯线","level":"B","type":"概念/思潮卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1945年后成为德国-波兰边界问题核心","place":"奥得河、卢萨蒂亚尼斯河一线；德国和波兰之间","summary":"奥得-尼斯线把德国东部大片地区置于波兰管理之下，成为战后德国边界和驱逐问题核心。","fields":[{"label":"标题","value":"德国-波兰奥得-尼斯线"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1945年后成为德国-波兰边界问题核心"},{"label":"地点","value":"奥得河、卢萨蒂亚尼斯河一线；德国和波兰之间"},{"label":"主要国家","value":"德国；波兰；苏联；英国；美国"},{"label":"一句话概括","value":"奥得-尼斯线把德国东部大片地区置于波兰管理之下，成为战后德国边界和驱逐问题核心。"},{"label":"核心主张/思路","value":"以奥得河和尼斯河为波兰西部边界，使波兰向西移动，以补偿苏联吞并波兰东部领土。"},{"label":"提出者/代表人物（可选）","value":"苏联推动，波茨坦会议中得到战后临时安排性质的确认。"},{"label":"它从何而来","value":"战争结束时苏联已控制东欧，波兰边界问题与苏联安全、德国惩罚和人口迁移纠缠在一起。"},{"label":"典型表现","value":"西里西亚、波美拉尼亚、东勃兰登堡等德国原有地区转入波兰管理，大量德国居民被驱逐或逃亡。"},{"label":"为什么重要","value":"它把德国战败、波兰重建和东欧冷战秩序连接起来，是战后德国国家边界最重要变化。"},{"label":"争议/局限","value":"西德长期不愿完全承认该线为最终边界，直到冷战后德国统一前后才最终解决。"},{"label":"出处","value":"Encyclopaedia Britannica: Oder-Neisse Line；Encyclopaedia Britannica: Potsdam Conference；bpb: Oder-Neiße-Grenze。"}],"relationItems":["← 前因：盟国《波茨坦协定》","↔ 相关：德国东部领土丧失与被驱逐者","→ 后果：德波边界承认问题"],"relations":[{"text":"← 前因：盟国《波茨坦协定》","id":"extra3"},{"text":"↔ 相关：德国东部领土丧失与被驱逐者","id":"extra7"}],"source":"history","id":"extra23"},{"title":"战后德国被迫迁徙者营地","level":"C","type":"组织/机构卡","tags":["经济与社会","战争与外交"],"mainTag":"经济与社会","subTag":"战争与外交","timeText":"1945年后，1940年代后半期尤为重要","place":"德国各占领区；尤其西部占领区","summary":"战后德国被迫迁徙者营地收容幸存者、强迫劳工、难民和无家可归者，是战后人道危机的节点。","fields":[{"label":"标题","value":"战后德国被迫迁徙者营地"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1945年后，1940年代后半期尤为重要"},{"label":"地点","value":"德国各占领区；尤其西部占领区"},{"label":"主要国家","value":"德国；美国；英国；苏联；欧洲多国"},{"label":"一句话概括","value":"战后德国被迫迁徙者营地收容幸存者、强迫劳工、难民和无家可归者，是战后人道危机的节点。"},{"label":"性质/类型","value":"盟国和救援机构管理的临时收容、登记和安置设施。"},{"label":"成立/解散时间","value":"1945年后大量设立，随着遣返、移民和安置逐渐减少。"},{"label":"核心目标/宗旨","value":"收容战争结束后无法立即回家的 displaced persons，包括集中营幸存者、强迫劳工、战俘、难民和无国籍者。"},{"label":"关键人物（可选）","value":"盟军占领当局、联合国善后救济总署、国际难民组织、犹太救援组织等。"},{"label":"关键行动/事件","value":"身份登记、遣返安排、食品和医疗救助、移民申请、犹太幸存者社群重建。"},{"label":"为什么重要","value":"它说明1945年不是秩序立即恢复，而是数百万人身份、国籍和归属需要重新安排。"},{"label":"争议/局限","value":"有些人不愿回到苏联或东欧新政权控制区，遣返政策和难民身份引发复杂政治问题。"},{"label":"出处","value":"Encyclopaedia Britannica: 20th-century international relations, Wasteland after 1945；USHMM Holocaust Encyclopedia: Displaced Persons；German History in Documents and Images: Displaced Persons in Postwar Germany。"}],"relationItems":["← 前因：纳粹死亡行军","↔ 相关：战后德国饥饿与住房危机","↔ 相关：德国东部领土丧失与被驱逐者","→ 后果：战后欧洲难民安置"],"relations":[{"text":"← 前因：纳粹死亡行军","id":"extra269"},{"text":"↔ 相关：战后德国饥饿与住房危机","id":"extra8"},{"text":"↔ 相关：德国东部领土丧失与被驱逐者","id":"extra7"}],"source":"history","id":"extra24"},{"title":"战后德国黑市经济","level":"C","type":"概念/思潮卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1945—1948年尤为突出","place":"德国各占领区；城市和农村交换网络","summary":"战后德国黑市经济源于货币失灵和物资短缺，成为普通人维持生活的重要灰色渠道。","fields":[{"label":"标题","value":"战后德国黑市经济"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1945—1948年尤为突出"},{"label":"地点","value":"德国各占领区；城市和农村交换网络"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"战后德国黑市经济源于货币失灵和物资短缺，成为普通人维持生活的重要灰色渠道。"},{"label":"核心主张/思路","value":"在配给不足、价格管制和帝国马克失去信任时，香烟、食物、煤炭和实物交换比官方货币更有用。"},{"label":"提出者/代表人物（可选）","value":"不是一项政策，而是战后社会自发形成的生存机制。"},{"label":"它从何而来","value":"战争破坏、交通瘫痪、住房和食品短缺、占领管制与货币过剩共同造成官方市场无法满足需求。"},{"label":"典型表现","value":"香烟货币、城市居民去农村换粮、物资走私、以物易物和占领军物资流入黑市。"},{"label":"为什么重要","value":"它解释为什么1948年货币改革对西占区如此关键：改革不是单纯换钱，而是恢复市场信任。"},{"label":"争议/局限","value":"黑市既是生存渠道，也加剧不平等、腐败和占领当局治理难题。"},{"label":"出处","value":"German History in Documents and Images: Black Market in Berlin；Deutsche Bundesbank: Währungsreform 1948；DHM/LeMO: Nachkriegsalltag。"}],"relationItems":["← 前因：战后德国饥饿与住房危机","↔ 相关：1948年西占区货币改革","→ 后果：西德社会市场经济"],"relations":[{"text":"← 前因：战后德国饥饿与住房危机","id":"extra8"},{"text":"↔ 相关：1948年西占区货币改革","id":"extra13"},{"text":"→ 后果：西德社会市场经济","id":"extra17"}],"source":"history","id":"extra25"},{"title":"德国基督教民主联盟成立","level":"B","type":"组织/机构卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1945年后在各占领区形成，1940年代后半期整合","place":"德国西部和柏林等地","summary":"德国基督教民主联盟试图把天主教和新教保守中间派合并为战后新的跨宗派人民党。","fields":[{"label":"标题","value":"德国基督教民主联盟成立"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1945年后在各占领区形成，1940年代后半期整合"},{"label":"地点","value":"德国西部和柏林等地"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国基督教民主联盟试图把天主教和新教保守中间派合并为战后新的跨宗派人民党。"},{"label":"性质/类型","value":"战后德国中右政党和基督教民主主义政党。"},{"label":"成立/解散时间","value":"1945年后在多个地区成立，后来成为西德主要执政党之一。"},{"label":"核心目标/宗旨","value":"以基督教伦理、议会民主、反极权和社会市场经济为基础，取代魏玛时期宗派分裂的中间派政治。"},{"label":"关键人物（可选）","value":"康拉德·阿登纳、雅各布·凯泽等。"},{"label":"关键行动/事件","value":"参与西占区和联邦共和国政治建设，在1949年成为西德组阁核心力量。"},{"label":"为什么重要","value":"它是战后西德政党体系重建的核心组织，体现从魏玛多党碎片化转向人民党政治。"},{"label":"争议/局限","value":"CDU内部既有社会改革派，也有保守和反共力量，路线整合需要在占领和冷战压力下完成。"},{"label":"出处","value":"Konrad-Adenauer-Stiftung: Geschichte der CDU；Encyclopaedia Britannica: Christian Democratic Union；German History in Documents and Images: Founding of postwar parties。"}],"relationItems":["← 前因：德国中央党","↔ 相关：西德《基本法》","→ 后果：1949年西德首次联邦议院选举","↔ 相关：康拉德·阿登纳"],"relations":[{"text":"← 前因：德国中央党","id":"extra673"},{"text":"↔ 相关：西德《基本法》","id":"extra15"},{"text":"→ 后果：1949年西德首次联邦议院选举","id":"extra33"},{"text":"↔ 相关：康拉德·阿登纳","id":"extra29"}],"source":"history","id":"extra26"},{"title":"德国社会统一党成立","level":"B","type":"组织/机构卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1946年4月","place":"苏联占领区和柏林","summary":"德国社会统一党由苏占区共产党和社民党合并而成，成为东德一党统治核心。","fields":[{"label":"标题","value":"德国社会统一党成立"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1946年4月"},{"label":"地点","value":"苏联占领区和柏林"},{"label":"主要国家","value":"德国；苏联"},{"label":"一句话概括","value":"德国社会统一党由苏占区共产党和社民党合并而成，成为东德一党统治核心。"},{"label":"性质/类型","value":"苏联占领区社会主义政党，后为东德执政党。"},{"label":"成立/解散时间","value":"1946年由KPD和SPD在苏占区合并成立，1989年后改组。"},{"label":"核心目标/宗旨","value":"在苏联支持下统一工人运动，推动苏占区社会主义改造和国家政权建设。"},{"label":"关键人物（可选）","value":"瓦尔特·乌布利希、奥托·格罗 Grotewohl、威廉·皮克等。"},{"label":"关键行动/事件","value":"合并KPD与SPD，控制苏占区政治机构，后来成为德意志民主共和国的执政党。"},{"label":"为什么重要","value":"它是战后德国分裂的政党制度基础之一，东德不是简单“苏占区”，而是有自己的党国结构。"},{"label":"争议/局限","value":"合并在苏占区压力下进行，许多社民党人并非自由选择，西方占领区SPD拒绝合并。"},{"label":"出处","value":"bpb: Gründung der SED；DHM/LeMO: SED-Gründung；German History in Documents and Images: Forced merger of KPD and SPD。"}],"relationItems":["← 前因：苏联占领区社会主义改造","↔ 相关：德国社会民主党（SPD）","→ 后果：德意志民主共和国成立","↔ 相关：瓦尔特·乌布利希"],"relations":[{"text":"← 前因：苏联占领区社会主义改造","id":"extra18"},{"text":"↔ 相关：德国社会民主党（SPD）","id":"extra628"},{"text":"→ 后果：德意志民主共和国成立","id":"extra19"},{"text":"↔ 相关：瓦尔特·乌布利希","id":"extra28"}],"source":"history","id":"extra27"},{"title":"瓦尔特·乌布利希","level":"B","type":"人物卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1893—1973年；战后德国政治核心期为1945年后","place":"苏联占领区；东德","summary":"乌布利希是苏占区和东德早期社会主义体制建设的核心组织者。","fields":[{"label":"标题","value":"瓦尔特·乌布利希"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1893—1973年；战后德国政治核心期为1945年后"},{"label":"地点","value":"苏联占领区；东德"},{"label":"主要国家","value":"德国；苏联"},{"label":"一句话概括","value":"乌布利希是苏占区和东德早期社会主义体制建设的核心组织者。"},{"label":"生卒年/活跃年代","value":"1893年出生，1973年去世；魏玛和流亡时期为共产党干部，战后成为东德领导核心。"},{"label":"身份/职务","value":"德国共产党和后来的SED领导人，东德党国体制核心人物。"},{"label":"关键贡献/作为","value":"1945年随苏联支持返回德国，参与重建共产党组织、推动KPD/SPD合并、建设苏占区行政和东德国家体制。"},{"label":"核心主张/立场","value":"亲苏马克思列宁主义路线，主张通过党组织和国家计划重塑社会。"},{"label":"为什么重要","value":"他是理解东德如何从占领区转为社会主义党国的关键人物。"},{"label":"争议/评价","value":"乌布利希代表东德体制的组织能力，也代表政治控制、党内整肃和对社会自主空间的压缩。"},{"label":"关联事件","value":"德国社会统一党成立；德意志民主共和国成立。"},{"label":"出处","value":"Encyclopaedia Britannica: Walter Ulbricht；DHM/LeMO: Walter Ulbricht；bpb: Walter Ulbricht。"}],"relationItems":["← 前因：苏联占领区社会主义改造","↔ 相关：德国社会统一党成立","→ 后果：德意志民主共和国成立"],"relations":[{"text":"← 前因：苏联占领区社会主义改造","id":"extra18"},{"text":"↔ 相关：德国社会统一党成立","id":"extra27"},{"text":"→ 后果：德意志民主共和国成立","id":"extra19"}],"source":"history","id":"extra28"},{"title":"康拉德·阿登纳","level":"A","type":"人物卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1876—1967年；西德总理任期为1949—1963年","place":"德国；科隆、波恩和西德政治场域","summary":"阿登纳是西德首任总理，主导联邦共和国早期建国、亲西方路线和议会民主巩固。","fields":[{"label":"标题","value":"康拉德·阿登纳"},{"label":"分级","value":"A"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1876—1967年；西德总理任期为1949—1963年"},{"label":"地点","value":"德国；科隆、波恩和西德政治场域"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"阿登纳是西德首任总理，主导联邦共和国早期建国、亲西方路线和议会民主巩固。"},{"label":"生卒年/活跃年代","value":"1876年出生，1967年去世；战后核心政治期为1945年后。"},{"label":"身份/职务","value":"CDU政治家，科隆前市长，西德首任联邦总理。"},{"label":"关键贡献/作为","value":"参与CDU和西德国家建设，1949年出任总理，推动西德融入西方阵营并稳定议会民主。"},{"label":"核心主张/立场","value":"亲西方、反共产主义、联邦主义和基督教民主路线，强调先恢复西德国家能力和国际信任。"},{"label":"为什么重要","value":"阿登纳让战后德国主线从占领和瓦解转向西德国家建构，是1949年之后西德道路的核心人物。"},{"label":"争议/评价","value":"其“西方绑定”强化西德稳定，但也被批评加深德国分裂并降低短期统一可能。"},{"label":"关联事件","value":"德意志联邦共和国成立；1949年西德首次联邦议院选举。"},{"label":"出处","value":"Encyclopaedia Britannica: Konrad Adenauer；Konrad-Adenauer-Stiftung: Konrad Adenauer；German History in Documents and Images: Adenauer and the Federal Republic。"}],"relationItems":["← 前因：德国基督教民主联盟成立","↔ 相关：西德《基本法》","→ 后果：德意志联邦共和国成立"],"relations":[{"text":"← 前因：德国基督教民主联盟成立","id":"extra26"},{"text":"↔ 相关：西德《基本法》","id":"extra15"},{"text":"→ 后果：德意志联邦共和国成立","id":"extra16"}],"source":"history","id":"extra29"},{"title":"路德维希·艾哈德","level":"B","type":"人物卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1897—1977年；战后经济核心期为1948年后","place":"德国；西占区和西德","summary":"艾哈德是西德社会市场经济和货币改革后经济政策的代表人物。","fields":[{"label":"标题","value":"路德维希·艾哈德"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1897—1977年；战后经济核心期为1948年后"},{"label":"地点","value":"德国；西占区和西德"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"艾哈德是西德社会市场经济和货币改革后经济政策的代表人物。"},{"label":"生卒年/活跃年代","value":"1897年出生，1977年去世；1948年后成为西德经济政策核心人物。"},{"label":"身份/职务","value":"经济学者和政治家，双占区经济管理机构负责人，后任西德经济部长和总理。"},{"label":"关键贡献/作为","value":"参与1948年货币改革后的经济政策，推动放松价格管制和社会市场经济路线。"},{"label":"核心主张/立场","value":"强调市场机制、稳定货币、竞争秩序和社会保障之间的平衡。"},{"label":"为什么重要","value":"他把西占区货币改革和西德经济复苏联系起来，是“经济奇迹”叙事中最重要的人物之一。"},{"label":"争议/评价","value":"艾哈德常被塑造成经济奇迹缔造者，但西德复苏也依赖马歇尔计划、劳动力、全球市场和既有工业基础。"},{"label":"关联事件","value":"1948年西占区货币改革；西德社会市场经济。"},{"label":"出处","value":"Encyclopaedia Britannica: Ludwig Erhard；Deutsche Bundesbank: Währungsreform 1948；bpb: Soziale Marktwirtschaft。"}],"relationItems":["← 前因：1948年西占区货币改革","↔ 相关：西德社会市场经济","→ 后果：马歇尔计划与西德重建"],"relations":[{"text":"← 前因：1948年西占区货币改革","id":"extra13"},{"text":"↔ 相关：西德社会市场经济","id":"extra17"},{"text":"→ 后果：马歇尔计划与西德重建","id":"extra11"}],"source":"history","id":"extra30"},{"title":"西德建国《法兰克福文件》","level":"B","type":"制度/文本卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1948年7月1日","place":"德国法兰克福","summary":"法兰克福文件要求西德各州启动制宪程序，是联邦共和国建国的直接制度起点。","fields":[{"label":"标题","value":"西德建国《法兰克福文件》"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1948年7月1日"},{"label":"地点","value":"德国法兰克福"},{"label":"主要国家","value":"美国；英国；法国；德国"},{"label":"一句话概括","value":"法兰克福文件要求西德各州启动制宪程序，是联邦共和国建国的直接制度起点。"},{"label":"制定方/签署方","value":"美国、英国、法国三国军事长官提交给西部各州州长。"},{"label":"主要内容","value":"要求西部各州召开制宪会议，制定联邦制、民主和权利保障框架，并处理州界和占领权问题。"},{"label":"它试图解决什么问题","value":"西方盟国决定把西占区整合为新的德国国家结构，需要德国方面以州为基础起草宪法性文件。"},{"label":"为什么重要","value":"它把占领区行政整合推进到国家建构，是基本法和联邦共和国成立的直接前奏。"},{"label":"争议/局限","value":"德国州长担心正式制宪会固化分裂，因此后来用“基本法”而非“宪法”强调临时性。"},{"label":"造成的影响","value":"议会委员会成立，西德基本法起草进程启动。"},{"label":"出处","value":"German History in Documents and Images: Frankfurt Documents, July 1, 1948；Haus der Geschichte: Frankfurter Dokumente；bpb: Frankfurter Dokumente。"}],"relationItems":["← 前因：西占区双占区和三占区","↔ 相关：西德《基本法》","→ 后果：西德制宪议会委员会"],"relations":[{"text":"← 前因：西占区双占区和三占区","id":"extra12"},{"text":"↔ 相关：西德《基本法》","id":"extra15"},{"text":"→ 后果：西德制宪议会委员会","id":"extra32"}],"source":"history","id":"extra31"},{"title":"西德制宪议会委员会","level":"B","type":"组织/机构卡","tags":["政治与制度"],"mainTag":"政治与制度","subTag":"","timeText":"1948年9月—1949年5月","place":"德国波恩","summary":"议会委员会负责起草西德《基本法》，把战后西占区整合为联邦共和国制度框架。","fields":[{"label":"标题","value":"西德制宪议会委员会"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"时间","value":"1948年9月—1949年5月"},{"label":"地点","value":"德国波恩"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"议会委员会负责起草西德《基本法》，把战后西占区整合为联邦共和国制度框架。"},{"label":"性质/类型","value":"西部各州代表组成的制宪性议事机构。"},{"label":"成立/解散时间","value":"1948年9月召开，1949年完成基本法后结束历史使命。"},{"label":"核心目标/宗旨","value":"在西方盟国授权下起草一部民主、联邦和权利保障明确的基本法。"},{"label":"关键人物（可选）","value":"康拉德·阿登纳担任主席，卡洛·施密德等参与重要讨论。"},{"label":"关键行动/事件","value":"讨论联邦制、基本权利、议会政府、宪法法院和德国统一临时性问题。"},{"label":"为什么重要","value":"它是西德制度设计的实际工作场所，解释基本法不是凭空出现，而是战后德国政治精英和占领现实协商的结果。"},{"label":"争议/局限","value":"它不是全民直选制宪大会，而是在占领条件和德国分裂压力下形成的间接制宪机制。"},{"label":"出处","value":"Deutscher Bundestag: Parlamentarischer Rat；Haus der Geschichte: Parlamentarischer Rat；German History in Documents and Images: Parliamentary Council materials。"}],"relationItems":["← 前因：西德建国《法兰克福文件》","↔ 相关：康拉德·阿登纳","→ 后果：西德《基本法》"],"relations":[{"text":"← 前因：西德建国《法兰克福文件》","id":"extra31"},{"text":"↔ 相关：康拉德·阿登纳","id":"extra29"},{"text":"→ 后果：西德《基本法》","id":"extra15"}],"source":"history","id":"extra32"},{"title":"1949年西德首次联邦议院选举","level":"B","type":"事件卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1949年8月14日","place":"德意志联邦共和国；西德各州","summary":"1949年西德首次联邦议院选举确立战后西德议会政治起点，并促成阿登纳组阁。","fields":[{"label":"标题","value":"1949年西德首次联邦议院选举"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1949年8月14日"},{"label":"地点","value":"德意志联邦共和国；西德各州"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1949年西德首次联邦议院选举确立战后西德议会政治起点，并促成阿登纳组阁。"},{"label":"参与者","value":"CDU/CSU、SPD、FDP等政党，西德选民，康拉德·阿登纳、库尔特·舒马赫等。"},{"label":"发生了什么","value":"基本法生效后，西德举行首次联邦议院选举。CDU/CSU成为最大党但优势有限，SPD位居其后，FDP等小党成为组阁关键。选举后，阿登纳以微弱多数当选首任联邦总理，西德议会制度开始运转。"},{"label":"为什么重要","value":"它把联邦共和国从制度文本推进到实际政党竞争和政府组成。"},{"label":"前因","value":"基本法确立了西德议会民主框架，CDU/CSU、SPD和FDP等战后政党完成初步组织；西占区从占领行政转向联邦国家运作。"},{"label":"后果","value":"阿登纳政府成立，西德开始在亲西方路线、社会市场经济和联邦议会制度下运作；战后西德政治秩序由此进入常态化竞争。"},{"label":"出处","value":"Bundeswahlleiter: Bundestagswahl 1949；Deutscher Bundestag: Erste Bundestagswahl 1949；Encyclopaedia Britannica: Formation of the Federal Republic of Germany。"}],"relationItems":["← 前因：西德《基本法》","↔ 相关：德国基督教民主联盟成立","↔ 相关：康拉德·阿登纳","→ 后果：德意志联邦共和国成立"],"relations":[{"text":"← 前因：西德《基本法》","id":"extra15"},{"text":"↔ 相关：德国基督教民主联盟成立","id":"extra26"},{"text":"↔ 相关：康拉德·阿登纳","id":"extra29"},{"text":"→ 后果：德意志联邦共和国成立","id":"extra16"}],"source":"history","id":"extra33"},{"title":"波恩成为西德临时首都","level":"C","type":"事件卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1949年","place":"德国波恩","summary":"波恩成为西德临时首都，体现联邦共和国强调临时性、低姿态和避免柏林问题升级。","fields":[{"label":"标题","value":"波恩成为西德临时首都"},{"label":"分级","value":"C"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1949年"},{"label":"地点","value":"德国波恩"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"波恩成为西德临时首都，体现联邦共和国强调临时性、低姿态和避免柏林问题升级。"},{"label":"参与者","value":"议会委员会、西德各州政治力量、康拉德·阿登纳、法兰克福和波恩等候选城市。"},{"label":"发生了什么","value":"联邦共和国成立前后，西德需要选择政府所在地。柏林因四国地位和封锁危机不适合作为实际首都。波恩最终胜出，成为联邦政府所在地，并长期承担首都功能。选择波恩也带有避免强烈民族国家象征、强调西德临时性的考虑。"},{"label":"为什么重要","value":"它是战后德国分裂政治的细节节点：连首都选择都反映德国问题尚未解决。"},{"label":"前因","value":"柏林处在苏占区内部并经历封锁危机，西德建国必须在西部占领区内寻找可运作的政治中心；同时新国家又不愿放弃德国统一的象征诉求。"},{"label":"后果","value":"波恩成为西德政治中心，联邦政府、议会和外交机构长期在此运转；直到德国统一后，首都和政府所在地问题才重新回到柏林。"},{"label":"出处","value":"Haus der Geschichte: Bonn wird Hauptstadt；Deutscher Bundestag: Bonn as parliamentary seat；Encyclopaedia Britannica: Bonn。"}],"relationItems":["← 前因：冷战初期柏林封锁与空运","↔ 相关：德意志联邦共和国成立","↔ 相关：西德《基本法》"],"relations":[{"text":"← 前因：冷战初期柏林封锁与空运","id":"extra14"},{"text":"↔ 相关：德意志联邦共和国成立","id":"extra16"},{"text":"↔ 相关：西德《基本法》","id":"extra15"}],"source":"history","id":"extra34"},{"title":"盟国管制委员会第2号法令","level":"C","type":"制度/文本卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1945年10月10日","place":"盟国占领下的德国","summary":"第2号法令正式解散纳粹党及其附属组织，把纳粹组织清算纳入盟国占领法框架。","fields":[{"label":"标题","value":"盟国管制委员会第2号法令"},{"label":"分级","value":"C"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1945年10月10日"},{"label":"地点","value":"盟国占领下的德国"},{"label":"主要国家","value":"美国；英国；苏联；法国；德国"},{"label":"一句话概括","value":"第2号法令正式解散纳粹党及其附属组织，把纳粹组织清算纳入盟国占领法框架。"},{"label":"制定方/签署方","value":"盟国管制委员会。"},{"label":"主要内容","value":"法令规定终止和清算纳粹党及相关组织，处理其财产、机构和组织残余，并为占领当局没收、监管和解散纳粹组织提供法律依据。"},{"label":"它试图解决什么问题","value":"德国战败后，盟国需要防止纳粹党组织网络转入地下或借旧机构继续影响社会，同时为去纳粹化提供可执行的组织清算工具。"},{"label":"为什么重要","value":"它把“消灭纳粹主义”从政治口号变成占领法命令，是理解战后德国制度清洗的基础文本之一。"},{"label":"争议/局限","value":"组织解散并不等于社会观念立即改变，许多前纳粹成员仍以个人身份回到地方行政、经济或专业岗位。"},{"label":"造成的影响","value":"纳粹组织财产被接管，公共机构和社团生活开始重组；后续去纳粹化审查、党籍追查和职业排除都在这种法律环境中展开。"},{"label":"出处","value":"Wikisource, Control Council Law No. 2 (10 October 1945)；Allied Control Council official gazette references。"}],"relationItems":["← 前因：纳粹德国无条件投降","→ 后果：德国去纳粹化","↔ 相关：盟国管制委员会","↔ 相关：美国占领区《解放法》","↔ 同时期参考：盟国管制委员会第10号法令"],"relations":[{"text":"← 前因：纳粹德国无条件投降","id":"extra1"},{"text":"→ 后果：德国去纳粹化","id":"extra5"},{"text":"↔ 相关：盟国管制委员会","id":"extra4"},{"text":"↔ 相关：美国占领区《解放法》","id":"extra39"},{"text":"↔ 同时期参考：盟国管制委员会第10号法令","id":"extra36"}],"source":"history","id":"extra35"},{"title":"盟国管制委员会第10号法令","level":"B","type":"制度/文本卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1945年12月20日","place":"盟国占领下的德国","summary":"第10号法令为各占领国在本区审判战犯提供法律基础，使纽伦堡原则从一次审判扩展为占领区司法实践。","fields":[{"label":"标题","value":"盟国管制委员会第10号法令"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1945年12月20日"},{"label":"地点","value":"盟国占领下的德国"},{"label":"主要国家","value":"美国；英国；苏联；法国；德国"},{"label":"一句话概括","value":"第10号法令为各占领国在本区审判战犯提供法律基础，使纽伦堡原则从一次审判扩展为占领区司法实践。"},{"label":"制定方/签署方","value":"盟国管制委员会。"},{"label":"主要内容","value":"法令规定战争罪、反和平罪、反人道罪和犯罪组织成员责任，并授权各占领当局在自己的占领区设立法庭审判相关被告。"},{"label":"它试图解决什么问题","value":"国际军事法庭只能审判少数最高层战犯，盟国还需要处理大量医生、法官、企业家、军官、党卫队成员和行政人员的责任问题。"},{"label":"为什么重要","value":"它是纽伦堡后续审判和各占领区战犯审判的法律基础，把纳粹罪责追究从最高领导人扩展到制度执行者。"},{"label":"争议/局限","value":"各占领区执行力度不一，冷战加剧后西方审判和追责逐渐收缩；许多涉案人员未被充分追究。"},{"label":"造成的影响","value":"纽伦堡后续审判、医生审判、法官审判、工业家审判等得以进行，也影响战后国际刑法和反人道罪概念发展。"},{"label":"出处","value":"Control Council Law No. 10, December 20, 1945；Library of Congress, Trials of War Criminals before the Nuernberg Military Tribunals under Control Council Law No. 10。"}],"relationItems":["← 前因：纳粹战犯纽伦堡审判","→ 后果：纽伦堡后续审判","↔ 相关：盟国管制委员会","↔ 相关：德国去纳粹化","↔ 同时期参考：东京审判"],"relations":[{"text":"← 前因：纳粹战犯纽伦堡审判","id":"extra6"},{"text":"→ 后果：纽伦堡后续审判","id":"extra37"},{"text":"↔ 相关：盟国管制委员会","id":"extra4"},{"text":"↔ 相关：德国去纳粹化","id":"extra5"},{"text":"↔ 同时期参考：东京审判","id":"extra851"}],"source":"history","id":"extra36"},{"title":"纽伦堡后续审判","level":"B","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1946—1949年","place":"德国纽伦堡","summary":"纽伦堡后续审判由美国占领当局审理医生、法官、军官和企业家等群体，追究纳粹制度执行层责任。","fields":[{"label":"标题","value":"纽伦堡后续审判"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1946—1949年"},{"label":"地点","value":"德国纽伦堡"},{"label":"主要国家","value":"美国；德国"},{"label":"一句话概括","value":"纽伦堡后续审判由美国占领当局审理医生、法官、军官和企业家等群体，追究纳粹制度执行层责任。"},{"label":"参与者","value":"美国军事法庭、纳粹医生和法官、工业家、党卫队和军方人员、检方与证人。"},{"label":"发生了什么","value":"国际军事法庭结束后，美国根据盟国管制委员会第10号法令在纽伦堡继续举行一系列审判。被告不再只是希特勒政权最高层，还包括集中营医学实验相关医生、参与种族政策的法官和官员、利用强迫劳动或参与战争经济的企业管理者，以及军方和党卫队人员。"},{"label":"为什么重要","value":"它把纳粹罪行理解从“少数领袖犯罪”推向“专业群体和机构共同参与”，是战后司法清算的重要深化。"},{"label":"前因","value":"纽伦堡主审判确立了反和平罪、战争罪和反人道罪框架，但无法处理大批中高层执行者；盟国管制委员会第10号法令为分区审判提供法律基础。"},{"label":"后果","value":"医生审判推动《纽伦堡法典》形成，法官审判揭示法律职业如何服务恐怖统治，工业审判暴露企业与强迫劳动、战争经济的关系。"},{"label":"出处","value":"Library of Congress, Trials of War Criminals before the Nuernberg Military Tribunals；USHMM Holocaust Encyclopedia, Subsequent Nuremberg Proceedings。"}],"relationItems":["← 前因：盟国管制委员会第10号法令","→ 后果：战后医学伦理与《纽伦堡法典》","↔ 相关：纳粹集中营医学实验","↔ 相关：纳粹战犯纽伦堡审判","↔ 同时期参考：东京审判"],"relations":[{"text":"← 前因：盟国管制委员会第10号法令","id":"extra36"},{"text":"↔ 相关：纳粹集中营医学实验","id":"extra282"},{"text":"↔ 相关：纳粹战犯纽伦堡审判","id":"extra6"},{"text":"↔ 同时期参考：东京审判","id":"extra851"}],"source":"history","id":"extra37"},{"title":"盟国管制委员会第46号法令废除普鲁士","level":"B","type":"制度/文本卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1947年2月25日","place":"盟国占领下的德国","summary":"1947年第46号法令正式废除普鲁士，象征盟国要切断德国军国主义和中央集权传统的制度来源。","fields":[{"label":"标题","value":"盟国管制委员会第46号法令废除普鲁士"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1947年2月25日"},{"label":"地点","value":"盟国占领下的德国"},{"label":"主要国家","value":"美国；英国；苏联；法国；德国"},{"label":"一句话概括","value":"1947年第46号法令正式废除普鲁士，象征盟国要切断德国军国主义和中央集权传统的制度来源。"},{"label":"制定方/签署方","value":"盟国管制委员会。"},{"label":"主要内容","value":"法令宣布普鲁士国家及其中央政府机构废止，原普鲁士领土按占领区和新州结构重新安排。"},{"label":"它试图解决什么问题","value":"盟国认为普鲁士长期与德国军国主义、威权官僚和侵略传统相连，战后重建德国必须拆解这个历史上最强大的德意志国家结构。"},{"label":"为什么重要","value":"它是德国战后联邦化和去普鲁士化的重要节点，把德国历史上持续数百年的政治主体正式划上句号。"},{"label":"争议/局限","value":"把德国军国主义归因于普鲁士有简化风险；普鲁士传统内部也包含改革、法治和行政现代化面向。"},{"label":"造成的影响","value":"德国州结构重组，普鲁士作为国家消失；西德《基本法》的联邦制和东德后来的中央化都在“无普鲁士”的新格局中展开。"},{"label":"出处","value":"Wikisource, Control Council Law No. 46 (25 February 1947) Abolition of Prussia；Kulturstiftung, Kontrollratsgesetz Nr. 46。"}],"relationItems":["← 前因：普鲁士军国主义传统","→ 后果：西德《基本法》","↔ 相关：盟国占领德国","↔ 相关：盟国管制委员会","↔ 同时期参考：德国联邦制重建"],"relations":[{"text":"→ 后果：西德《基本法》","id":"extra15"},{"text":"↔ 相关：盟国占领德国","id":"extra2"},{"text":"↔ 相关：盟国管制委员会","id":"extra4"}],"source":"history","id":"extra38"},{"title":"美国占领区《解放法》","level":"C","type":"制度/文本卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1946年3月5日","place":"美国占领区德国","summary":"1946年《解放法》把去纳粹化审查交给德国地方机构执行，用分类制度处理大量前纳粹成员。","fields":[{"label":"标题","value":"美国占领区《解放法》"},{"label":"分级","value":"C"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1946年3月5日"},{"label":"地点","value":"美国占领区德国"},{"label":"主要国家","value":"美国；德国"},{"label":"一句话概括","value":"1946年《解放法》把去纳粹化审查交给德国地方机构执行，用分类制度处理大量前纳粹成员。"},{"label":"制定方/签署方","value":"美国占领区州议会/州政府在美国军事政府框架下制定。"},{"label":"主要内容","value":"法律要求审查成年人同纳粹主义和军国主义的关系，把被审查者分为主要罪犯、罪犯、较轻罪犯、追随者和无罪者等类别，并配套处罚、限制和复权程序。"},{"label":"它试图解决什么问题","value":"盟国无法长期直接审查数以百万计的德国人，需要把去纳粹化从军事政府命令转化为可由德国机构处理的大规模行政司法程序。"},{"label":"为什么重要","value":"它揭示去纳粹化的现实困境：既要清算过去，又要让社会机器重新运转，因而审查逐渐从严厉排除转向分类、罚款和复归。"},{"label":"争议/局限","value":"大量人通过证明书、人情网络或程序负担减轻责任，许多真正责任人未受到相应惩罚；普通“追随者”类别也淡化了社会共谋问题。"},{"label":"造成的影响","value":"审查法庭和分类制度成为美国占领区去纳粹化的核心机制，也影响德国社会对“责任”“追随”和“重新开始”的理解。"},{"label":"出处","value":"Gesetz Nr. 104 zur Befreiung von Nationalsozialismus und Militarismus (1946), verfassungen.de；Nuremberg.media, Denazification Law Enacted。"}],"relationItems":["← 前因：盟国管制委员会第2号法令","→ 后果：德国去纳粹化","↔ 相关：纽伦堡后续审判","↔ 相关：战后德国“零点时刻”","↔ 同时期参考：日本战后公职追放"],"relations":[{"text":"← 前因：盟国管制委员会第2号法令","id":"extra35"},{"text":"→ 后果：德国去纳粹化","id":"extra5"},{"text":"↔ 相关：纽伦堡后续审判","id":"extra37"},{"text":"↔ 相关：战后德国“零点时刻”","id":"extra9"}],"source":"history","id":"extra39"},{"title":"柏林盟国司令部","level":"B","type":"组织/机构卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1945年7月起；1948年后四方合作破裂","place":"柏林","summary":"柏林盟国司令部是四国共同管理柏林的机构，体现柏林既是城市治理问题，也是冷战前线。","fields":[{"label":"标题","value":"柏林盟国司令部"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1945年7月起；1948年后四方合作破裂"},{"label":"地点","value":"柏林"},{"label":"主要国家","value":"美国；英国；苏联；法国；德国"},{"label":"一句话概括","value":"柏林盟国司令部是四国共同管理柏林的机构，体现柏林既是城市治理问题，也是冷战前线。"},{"label":"性质/类型","value":"四国占领下的大柏林共同治理机构。"},{"label":"成立/解散时间","value":"1945年7月开始实际运作；1948年苏方退出后四方合作基本破裂，但西方三方仍在西柏林延续协调。"},{"label":"核心目标/宗旨","value":"协调四个占领区在柏林的城市行政、治安、交通、公共服务和占领政策，使柏林在四国框架下运行。"},{"label":"关键人物（可选）","value":"四国柏林军事司令及其代表。"},{"label":"关键行动/事件","value":"处理柏林分区治理、公共服务恢复、城市秩序和占领当局协调；1948年柏林封锁前后，四方城市治理机制迅速失效。"},{"label":"为什么重要","value":"它说明柏林的特殊地位不是1948年封锁时才出现，而是从战后四国共同占领安排中就已经埋下冲突结构。"},{"label":"争议/局限","value":"四国对德国未来、赔偿、货币和政治制度的目标不同，城市层面的司令部难以抵消大国战略冲突。"},{"label":"出处","value":"The National Archives, Allied Kommandatura: Directives, Minutes and Papers；Gedenktafeln in Berlin, Alliierte Kommandantur。"}],"relationItems":["← 前因：盟国占领德国","→ 后果：冷战初期柏林封锁与空运","↔ 相关：盟国管制委员会","↔ 相关：盟国《柏林宣言》","↔ 同时期参考：维也纳四国占领"],"relations":[{"text":"← 前因：盟国占领德国","id":"extra2"},{"text":"→ 后果：冷战初期柏林封锁与空运","id":"extra14"},{"text":"↔ 相关：盟国管制委员会","id":"extra4"},{"text":"↔ 相关：盟国《柏林宣言》","id":"extra20"}],"source":"history","id":"extra40"},{"title":"苏联驻德军事管理局","level":"B","type":"组织/机构卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1945—1949年","place":"苏联占领区德国；柏林-卡尔斯霍斯特","summary":"苏联驻德军事管理局直接管理苏占区，推动土地改革、政党重组、经济管制和东德建国准备。","fields":[{"label":"标题","value":"苏联驻德军事管理局"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1945—1949年"},{"label":"地点","value":"苏联占领区德国；柏林-卡尔斯霍斯特"},{"label":"主要国家","value":"苏联；德国"},{"label":"一句话概括","value":"苏联驻德军事管理局直接管理苏占区，推动土地改革、政党重组、经济管制和东德建国准备。"},{"label":"性质/类型","value":"苏联在德国占领区的军事政府机构。"},{"label":"成立/解散时间","value":"1945年6月成立；1949年德意志民主共和国成立后改组为苏联管制委员会。"},{"label":"核心目标/宗旨","value":"在苏占区执行苏联占领政策、赔偿拆迁、行政重建、去纳粹化、经济控制和政治改造。"},{"label":"关键人物（可选）","value":"格奥尔基·朱可夫、瓦西里·索科洛夫斯基等苏军高级将领。"},{"label":"关键行动/事件","value":"推动土地改革，批准政党和群众组织，支持社会民主党与共产党合并为SED，监督德国经济委员会等机构。"},{"label":"为什么重要","value":"它是理解东德形成的关键机构。苏占区不是自然走向社会主义国家，而是在苏联军事管理和德国共产党干部合作下逐步制度化。"},{"label":"争议/局限","value":"苏联管理既包含反纳粹和社会改革目标，也伴随强制征收、赔偿拆迁、政治压制和对反对派空间的压缩。"},{"label":"出处","value":"De Gruyter, Inventar der Befehle des Obersten Chefs der Sowjetischen Militäradministration in Deutschland 1945–1949；German Bundestag, The German Democratic Republic (1949-1990)。"}],"relationItems":["← 前因：盟国占领德国","→ 后果：德意志民主共和国成立","↔ 相关：苏联占领区社会主义改造","↔ 相关：苏占区土地改革","↔ 同时期参考：苏联在东欧的卫星国建设"],"relations":[{"text":"← 前因：盟国占领德国","id":"extra2"},{"text":"→ 后果：德意志民主共和国成立","id":"extra19"},{"text":"↔ 相关：苏联占领区社会主义改造","id":"extra18"},{"text":"↔ 相关：苏占区土地改革","id":"extra42"}],"source":"history","id":"extra41"},{"title":"苏占区土地改革","level":"B","type":"事件卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1945年9月—1948年前后","place":"苏联占领区德国","summary":"苏占区土地改革没收大地产和部分“纳粹及战犯”财产，重新分配土地，为东德社会结构改造奠定基础。","fields":[{"label":"标题","value":"苏占区土地改革"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1945年9月—1948年前后"},{"label":"地点","value":"苏联占领区德国"},{"label":"主要国家","value":"苏联；德国"},{"label":"一句话概括","value":"苏占区土地改革没收大地产和部分“纳粹及战犯”财产，重新分配土地，为东德社会结构改造奠定基础。"},{"label":"参与者","value":"苏联军事管理局、德国共产党/社会统一党干部、地方土地委员会、大地产主、无地农民、难民和新农民。"},{"label":"发生了什么","value":"1945年秋起，苏占区在“容克土地归农民”口号下没收大地产、纳粹相关人员和被定为战犯者的土地，分配给无地农民、农业工人和被驱逐者等群体。改革削弱传统地主阶层，也制造大量缺乏牲畜、工具和资金的新农户。"},{"label":"为什么重要","value":"它是苏占区最重要的社会经济改革之一，改变农村所有权结构，也为后来的农业集体化和东德政治动员提供基础。"},{"label":"前因","value":"纳粹战败后，苏联希望打击被视为军国主义社会基础的容克地主，并通过土地分配获得农村支持、安置难民和重组地方权力。"},{"label":"后果","value":"大地产阶层被瓦解，新农民获得土地但经营困难；1950年代东德农业集体化又把这些小农户纳入新的社会主义农业结构。"},{"label":"出处","value":"German History in Documents and Images, Propaganda Photo: Land Reform in the Soviet Occupation Zone (September 1945)；Chronik der Wende, Land Reform。"}],"relationItems":["← 前因：苏联驻德军事管理局","→ 后果：苏联占领区社会主义改造","↔ 相关：德国东部领土丧失与被驱逐者","↔ 相关：苏占区德国人民代表大会运动","↔ 同时期参考：东欧战后土地改革"],"relations":[{"text":"← 前因：苏联驻德军事管理局","id":"extra41"},{"text":"→ 后果：苏联占领区社会主义改造","id":"extra18"},{"text":"↔ 相关：德国东部领土丧失与被驱逐者","id":"extra7"},{"text":"↔ 相关：苏占区德国人民代表大会运动","id":"extra53"}],"source":"history","id":"extra42"},{"title":"苏占区德国经济委员会","level":"B","type":"组织/机构卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1947—1949年","place":"苏联占领区德国","summary":"德国经济委员会是苏占区中央经济行政机构，逐步从经济协调机关转向东德准政府结构。","fields":[{"label":"标题","value":"苏占区德国经济委员会"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1947—1949年"},{"label":"地点","value":"苏联占领区德国"},{"label":"主要国家","value":"苏联；德国"},{"label":"一句话概括","value":"德国经济委员会是苏占区中央经济行政机构，逐步从经济协调机关转向东德准政府结构。"},{"label":"性质/类型","value":"苏占区中央经济和行政协调机构。"},{"label":"成立/解散时间","value":"1947年由苏联军事管理局设立；1949年东德成立后并入新国家机构。"},{"label":"核心目标/宗旨","value":"协调苏占区工业、农业、贸易、财政和计划事务，执行苏联占领政策和经济重建安排。"},{"label":"关键人物（可选）","value":"与SED干部和苏联军事管理局密切相关。"},{"label":"关键行动/事件","value":"管理经济部门，推动集中化和计划化，承接越来越多跨州行政职能，为东德中央政府形成准备制度基础。"},{"label":"为什么重要","value":"它说明东德国家不是1949年突然出现，而是在苏占区中央机构、党组织和经济管理体系中提前成形。"},{"label":"争议/局限","value":"它名义上是德国机构，实际上深受苏联军事管理局和SED路线支配，政治代表性有限。"},{"label":"出处","value":"German Economic Commission historical summaries；German Bundestag, The German Democratic Republic (1949-1990)。"}],"relationItems":["← 前因：苏联驻德军事管理局","→ 后果：德意志民主共和国成立","↔ 相关：苏联占领区社会主义改造","↔ 相关：德国社会统一党成立","↔ 同时期参考：西占区经济委员会"],"relations":[{"text":"← 前因：苏联驻德军事管理局","id":"extra41"},{"text":"→ 后果：德意志民主共和国成立","id":"extra19"},{"text":"↔ 相关：苏联占领区社会主义改造","id":"extra18"},{"text":"↔ 相关：德国社会统一党成立","id":"extra27"},{"text":"↔ 同时期参考：西占区经济委员会","id":"extra44"}],"source":"history","id":"extra43"},{"title":"西占区经济委员会","level":"B","type":"组织/机构卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1947—1949年","place":"法兰克福；英美双占区及后来的西占区","summary":"西占区经济委员会是双占区的德国经济立法和协调机关，是西德政治经济自我管理的前身之一。","fields":[{"label":"标题","value":"西占区经济委员会"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1947—1949年"},{"label":"地点","value":"法兰克福；英美双占区及后来的西占区"},{"label":"主要国家","value":"美国；英国；德国；法国"},{"label":"一句话概括","value":"西占区经济委员会是双占区的德国经济立法和协调机关，是西德政治经济自我管理的前身之一。"},{"label":"性质/类型","value":"英美双占区经济管理和准议会机构。"},{"label":"成立/解散时间","value":"1947年设立；1949年德意志联邦共和国成立后被联邦机构取代。"},{"label":"核心目标/宗旨","value":"在英美占领当局监督下协调双占区经济、财政、交通、粮食和行政事务，让德国代表参与重建政策。"},{"label":"关键人物（可选）","value":"路德维希·艾哈德等战后经济政策人物与该框架相关。"},{"label":"关键行动/事件","value":"围绕价格、配给、货币改革前后经济秩序和重建政策展开争论；成为西占区政党竞争和经济路线形成的重要舞台。"},{"label":"为什么重要","value":"它让西德并不是从《基本法》才开始政治化，经济委员会已经训练了西占区政党、行政和经济政策的准国家运作。"},{"label":"争议/局限","value":"其权力受占领当局限制，法国占领区一开始也不完全参与；德国代表的民主合法性有限。"},{"label":"出处","value":"German History in Documents and Images, The Economic Council (1949)；bpb, Der Frankfurter Wirtschaftsrat 1947—1949。"}],"relationItems":["← 前因：西占区双占区和三占区","→ 后果：西德社会市场经济","↔ 相关：1948年西占区货币改革","↔ 相关：路德维希·艾哈德","↔ 同时期参考：苏占区德国经济委员会"],"relations":[{"text":"← 前因：西占区双占区和三占区","id":"extra12"},{"text":"→ 后果：西德社会市场经济","id":"extra17"},{"text":"↔ 相关：1948年西占区货币改革","id":"extra13"},{"text":"↔ 相关：路德维希·艾哈德","id":"extra30"},{"text":"↔ 同时期参考：苏占区德国经济委员会","id":"extra43"}],"source":"history","id":"extra44"},{"title":"西德建国伦敦六国会议","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1948年2月—6月","place":"英国伦敦","summary":"伦敦六国会议由西方三占领国和比荷卢讨论西德建国与鲁尔安排，推动德国分裂制度化。","fields":[{"label":"标题","value":"西德建国伦敦六国会议"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1948年2月—6月"},{"label":"地点","value":"英国伦敦"},{"label":"主要国家","value":"美国；英国；法国；比利时；荷兰；卢森堡；德国"},{"label":"一句话概括","value":"伦敦六国会议由西方三占领国和比荷卢讨论西德建国与鲁尔安排，推动德国分裂制度化。"},{"label":"参与者","value":"美国、英国、法国、比利时、荷兰、卢森堡代表；德国代表没有正式参与决策。"},{"label":"发生了什么","value":"在四国合作陷入僵局后，西方三占领国与比荷卢在伦敦讨论西占区未来政治结构、联邦制、占领权、鲁尔控制和西欧安全。会议成果转化为交给西德州长的法兰克福文件，要求西占区准备制定宪法性质文本。"},{"label":"为什么重要","value":"它是西德建国的外交前奏，把德国问题从四国共同管理转向西方阵营内部安排。"},{"label":"前因","value":"盟国管制委员会合作破裂、苏联与西方在赔偿和德国经济统一问题上冲突加深，马歇尔计划和西占区货币改革计划又推动西方重新组织德国。"},{"label":"后果","value":"法兰克福文件出台，议会委员会启动《基本法》制定；苏联方面则更加推动苏占区政治整合，德国分裂加速。"},{"label":"出处","value":"Office of the Historian, FRUS 1948 documents on Germany；Frankfurt Documents historical summaries；CVCE, Six-Power Conference materials。"}],"relationItems":["← 前因：盟国管制委员会","→ 后果：西德建国《法兰克福文件》","↔ 相关：国际鲁尔管理局","↔ 相关：西占区双占区和三占区","↔ 同时期参考：马歇尔计划与西德重建"],"relations":[{"text":"← 前因：盟国管制委员会","id":"extra4"},{"text":"→ 后果：西德建国《法兰克福文件》","id":"extra31"},{"text":"↔ 相关：国际鲁尔管理局","id":"extra46"},{"text":"↔ 相关：西占区双占区和三占区","id":"extra12"},{"text":"↔ 同时期参考：马歇尔计划与西德重建","id":"extra11"}],"source":"history","id":"extra45"},{"title":"国际鲁尔管理局","level":"B","type":"组织/机构卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1948年决定设立；1949年协议生效","place":"鲁尔工业区；伦敦；杜塞尔多夫","summary":"国际鲁尔管理局试图把鲁尔煤钢生产置于国际监督下，防止德国工业力量再次转化为战争能力。","fields":[{"label":"标题","value":"国际鲁尔管理局"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1948年决定设立；1949年协议生效"},{"label":"地点","value":"鲁尔工业区；伦敦；杜塞尔多夫"},{"label":"主要国家","value":"美国；英国；法国；比利时；荷兰；卢森堡；德国"},{"label":"一句话概括","value":"国际鲁尔管理局试图把鲁尔煤钢生产置于国际监督下，防止德国工业力量再次转化为战争能力。"},{"label":"性质/类型","value":"战后西方盟国设立的国际经济监督机构。"},{"label":"成立/解散时间","value":"1948年伦敦会议决定设立，1949年相关协议生效；1950年代欧洲煤钢共同体兴起后作用逐步被取代。"},{"label":"核心目标/宗旨","value":"监督鲁尔煤、焦炭和钢铁的生产、分配和出口，使德国工业复兴服务欧洲重建而非军事再起。"},{"label":"关键人物（可选）","value":"西方六国政府代表；西德政界作为被监管对象和后来参与者。"},{"label":"关键行动/事件","value":"围绕鲁尔煤钢配额、出口和国际控制权展开安排；西德政治家普遍认为该制度限制德国主权。"},{"label":"为什么重要","value":"它说明战后西德重建不是简单“恢复工业”，而是在盟国安全恐惧、法国对鲁尔的担忧和欧洲复兴需求之间寻找平衡。"},{"label":"争议/局限","value":"德国方面认为其削弱经济主权；法国希望更强控制，美国和英国则更重视西欧复兴与冷战整合。"},{"label":"出处","value":"Office of the Historian, Draft Agreement for the Establishment of an International Authority for the Ruhr；CVCE, Final Communiqué of the Six-Power Conference on the International Authority for the Ruhr。"}],"relationItems":["← 前因：西德建国伦敦六国会议","→ 后果：德意志联邦共和国成立","↔ 相关：德国战后赔偿与拆迁","↔ 相关：马歇尔计划与西德重建","↔ 同时期参考：欧洲煤钢共同体"],"relations":[{"text":"← 前因：西德建国伦敦六国会议","id":"extra45"},{"text":"→ 后果：德意志联邦共和国成立","id":"extra16"},{"text":"↔ 相关：德国战后赔偿与拆迁","id":"extra10"},{"text":"↔ 相关：马歇尔计划与西德重建","id":"extra11"}],"source":"history","id":"extra46"},{"title":"战后德国再教育政策","level":"C","type":"概念/思潮卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1945—1949年为核心阶段","place":"盟国占领下的德国","summary":"再教育政策试图通过学校、媒体、电影和文化交流改造德国政治文化，使德国社会脱离纳粹和军国主义。","fields":[{"label":"标题","value":"战后德国再教育政策"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1945—1949年为核心阶段"},{"label":"地点","value":"盟国占领下的德国"},{"label":"主要国家","value":"美国；英国；法国；苏联；德国"},{"label":"一句话概括","value":"再教育政策试图通过学校、媒体、电影和文化交流改造德国政治文化，使德国社会脱离纳粹和军国主义。"},{"label":"核心主张/思路","value":"德国战后重建不能只靠解除武装和审判战犯，还要改变教育、公共舆论、历史理解和公民文化。"},{"label":"提出者/代表人物（可选）","value":"四国占领当局，美国占领区尤其强调 re-education / re-orientation。"},{"label":"它从何而来","value":"盟国认为纳粹统治能够动员社会，与学校、宣传、新闻和社会服从文化有关，因此占领政策必须重塑德国人的价值观和公共信息环境。"},{"label":"典型表现","value":"改编教材，审查教师，重开学校，放映集中营影像，许可新报刊，推动民主教育和文化交流。"},{"label":"为什么重要","value":"它把战后重组从制度层面扩展到社会心理和文化层面，是理解西德民主化和东德意识形态教育分化的关键背景。"},{"label":"争议/局限","value":"德国人常把再教育视为外来训导；各占领国目标不同，冷战后再教育逐渐服务阵营竞争。"},{"label":"出处","value":"Occupation Studies, Re-educational Strategies beyond the Postwar Moment；NCBI Bookshelf, The Perils of Peace: Compromises and Confrontations, 1945–1949。"}],"relationItems":["← 前因：纳粹宣传机器","→ 后果：战后德国许可证报刊","↔ 相关：德国去纳粹化","↔ 相关：战后德国“零点时刻”","↔ 同时期参考：日本战后民主化教育改革"],"relations":[{"text":"← 前因：纳粹宣传机器","id":"extra94"},{"text":"→ 后果：战后德国许可证报刊","id":"extra48"},{"text":"↔ 相关：德国去纳粹化","id":"extra5"},{"text":"↔ 相关：战后德国“零点时刻”","id":"extra9"}],"source":"history","id":"extra47"},{"title":"战后德国许可证报刊","level":"C","type":"概念/思潮卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1945—1949年","place":"盟国占领下的德国","summary":"许可证报刊是在占领当局许可下重新出现的德国报纸，用来重建新闻业并防止纳粹舆论复活。","fields":[{"label":"标题","value":"战后德国许可证报刊"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1945—1949年"},{"label":"地点","value":"盟国占领下的德国"},{"label":"主要国家","value":"美国；英国；法国；苏联；德国"},{"label":"一句话概括","value":"许可证报刊是在占领当局许可下重新出现的德国报纸，用来重建新闻业并防止纳粹舆论复活。"},{"label":"核心主张/思路","value":"新闻自由不能简单恢复到纳粹以前状态，必须先清除纳粹新闻体系，由占领当局筛选可靠出版人并监督新报刊。"},{"label":"提出者/代表人物（可选）","value":"四国军事政府、德国获得许可证的编辑和出版人。"},{"label":"它从何而来","value":"纳粹时期新闻被一体化和宣传部控制，战后盟国关闭旧媒体体系，再通过许可制度逐步允许德国人重新办报。"},{"label":"典型表现","value":"占领区内出现由军事政府批准的日报、周报和杂志；编辑资格、纸张配给和政治方向都受占领当局影响。"},{"label":"为什么重要","value":"它解释战后德国公共舆论如何从纳粹宣传体系过渡到民主新闻或社会主义新闻体系，也解释许多战后大报的制度起点。"},{"label":"争议/局限","value":"许可制度本身限制出版自由，且各占领区目标不同；冷战后，新闻许可也成为阵营宣传竞争的一部分。"},{"label":"出处","value":"DeWiki, Lizenzzeitung；Zeitklicks, Lizenzen zum Drucken；Eprints Glasgow, More than just a business: recasting literary publishing in postwar Germany, 1945-1949。"}],"relationItems":["← 前因：纳粹德国《报刊编辑法》","→ 后果：战后德国再教育政策","↔ 相关：盟国占领德国","↔ 相关：德国去纳粹化","↔ 同时期参考：日本战后新闻审查"],"relations":[{"text":"← 前因：纳粹德国《报刊编辑法》","id":"extra151"},{"text":"→ 后果：战后德国再教育政策","id":"extra47"},{"text":"↔ 相关：盟国占领德国","id":"extra2"},{"text":"↔ 相关：德国去纳粹化","id":"extra5"}],"source":"history","id":"extra48"},{"title":"战后德国“瓦砾妇女”","level":"C","type":"概念/思潮卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"1945年后，1940年代后半期最具象征性","place":"德国被轰炸城市，尤其柏林等大城市","summary":"“瓦砾妇女”指战后参与清理废墟的女性，后来成为德国重建记忆中的重要但被神话化的形象。","fields":[{"label":"标题","value":"战后德国“瓦砾妇女”"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1945年后，1940年代后半期最具象征性"},{"label":"地点","value":"德国被轰炸城市，尤其柏林等大城市"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"“瓦砾妇女”指战后参与清理废墟的女性，后来成为德国重建记忆中的重要但被神话化的形象。"},{"label":"核心主张/思路","value":"女性在男性死亡、被俘或失踪后的城市废墟中承担清理砖石、维持家庭和恢复日常生活的劳动。"},{"label":"提出者/代表人物（可选）","value":"不是单一组织提出，而是战后城市劳动、照片宣传和后来的纪念文化共同塑造。"},{"label":"它从何而来","value":"战争轰炸造成巨大废墟，战后劳动力短缺、住房危机和配给困难使清理废墟成为城市恢复的必要环节。"},{"label":"典型表现","value":"女性敲砖、搬运瓦砾、清理街道和废墟；照片、纪念碑和回忆叙事中常把她们塑造成重建德国的象征。"},{"label":"为什么重要","value":"这张卡能把战后重组从高层外交拉回身体劳动和性别经验，也提醒用户战后“重建神话”本身需要被分析。"},{"label":"争议/局限","value":"近年来研究指出，“瓦砾妇女”形象在不同城市差异很大，女性并非总是清理废墟的主力；后来的纪念政治可能放大了其象征意义。"},{"label":"出处","value":"German History in Documents and Images, Berlin “rubble woman” image；bpb, Mythos Trümmerfrauen；Stadtmuseum Berlin, Anni Mittelstädt / Trümmerfrauen collections。"}],"relationItems":["← 前因：战后德国饥饿与住房危机","→ 后果：战后德国住房重建","↔ 相关：战后德国“零点时刻”","↔ 相关：CARE包裹进入德国","↔ 同时期参考：欧洲战后城市重建"],"relations":[{"text":"← 前因：战后德国饥饿与住房危机","id":"extra8"},{"text":"→ 后果：战后德国住房重建","id":"extra850"},{"text":"↔ 相关：战后德国“零点时刻”","id":"extra9"},{"text":"↔ 相关：CARE包裹进入德国","id":"extra50"}],"source":"history","id":"extra49"},{"title":"CARE包裹进入德国","level":"C","type":"事件卡","tags":["经济与社会","战争与外交"],"mainTag":"经济与社会","subTag":"战争与外交","timeText":"1946年后","place":"德国西占区和柏林等地","summary":"CARE包裹把美国民间援助送入战后德国，成为饥饿年代里物质救助和美德关系重塑的象征。","fields":[{"label":"标题","value":"CARE包裹进入德国"},{"label":"分级","value":"C"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1946年后"},{"label":"地点","value":"德国西占区和柏林等地"},{"label":"主要国家","value":"美国；德国"},{"label":"一句话概括","value":"CARE包裹把美国民间援助送入战后德国，成为饥饿年代里物质救助和美德关系重塑的象征。"},{"label":"参与者","value":"CARE组织、美国捐赠者、战后德国受援家庭、占领当局。"},{"label":"发生了什么","value":"CARE于1945年由美国多个组织联合成立，最初向战后欧洲运送食品和生活必需品。1946年后，包裹逐渐进入德国，常包含食物、衣物、卫生用品、学习用品等，在饥饿、配给和物资短缺环境中具有很强象征意义。柏林封锁期间，CARE包裹也成为西柏林人道援助的一部分。"},{"label":"为什么重要","value":"它说明战后德国重建不只有马歇尔计划这种国家层面援助，也有民间慈善、亲属联系和人道救济对日常生活的影响。"},{"label":"前因","value":"战后德国粮食、住房和燃料短缺严重，早期盟国对德救济政策受惩罚性占领思路限制；随着冷战和人道压力上升，美国对德援助逐渐扩大。"},{"label":"后果","value":"CARE包裹改善部分家庭生活，也强化美国从占领者向援助者、保护者转变的形象，为西德亲美社会心理提供日常层面的经验。"},{"label":"出处","value":"CARE, The Original CARE Package；National WWII Museum, Sending Hope to Europe: The First CARE Packages Arrive in 1946；Stadtmuseum Berlin, CARE-Paket。"}],"relationItems":["← 前因：战后德国饥饿与住房危机","→ 后果：马歇尔计划与西德重建","↔ 相关：冷战初期柏林封锁与空运","↔ 相关：战后德国“瓦砾妇女”","↔ 同时期参考：欧洲战后人道救济"],"relations":[{"text":"← 前因：战后德国饥饿与住房危机","id":"extra8"},{"text":"→ 后果：马歇尔计划与西德重建","id":"extra11"},{"text":"↔ 相关：冷战初期柏林封锁与空运","id":"extra14"},{"text":"↔ 相关：战后德国“瓦砾妇女”","id":"extra49"}],"source":"history","id":"extra50"},{"title":"德国自由民主党成立","level":"C","type":"组织/机构卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1948年12月","place":"西占区德国；黑彭海姆","summary":"自由民主党在西占区整合自由主义地方党派，成为西德建国初期重要的中间派和执政联盟伙伴。","fields":[{"label":"标题","value":"德国自由民主党成立"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1948年12月"},{"label":"地点","value":"西占区德国；黑彭海姆"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"自由民主党在西占区整合自由主义地方党派，成为西德建国初期重要的中间派和执政联盟伙伴。"},{"label":"性质/类型","value":"自由主义政党。"},{"label":"成立/解散时间","value":"1948年12月在黑彭海姆成立；1949年后进入西德政党体系。"},{"label":"核心目标/宗旨","value":"继承德国自由主义传统，强调个人自由、法治、市场经济和反集权政治，在基民盟与社民党之间争取中间选民。"},{"label":"关键人物（可选）","value":"特奥多尔·豪斯等自由主义政治家。"},{"label":"关键行动/事件","value":"整合西占区自由主义州党；1949年参加首届联邦议院选举，并成为阿登纳政府联盟的一部分。"},{"label":"为什么重要","value":"它补足西德建国政党结构。没有FDP，就难以理解1949年后西德议会联盟政治和社会市场经济路线的形成。"},{"label":"争议/局限","value":"早期自由主义阵营内部既有民族自由派、经济自由派，也有较强的地方差异和旧精英延续问题。"},{"label":"出处","value":"Picture Alliance, 80 years ago: the founding of the FDP；ParlGov, Germany FDP party data；FDP historical summaries。"}],"relationItems":["← 前因：德国民主党","→ 后果：1949年西德首次联邦议院选举","↔ 相关：德国基督教民主联盟成立","↔ 相关：康拉德·阿登纳","↔ 同时期参考：战后欧洲自由主义政党重建"],"relations":[{"text":"← 前因：德国民主党","id":"card24"},{"text":"→ 后果：1949年西德首次联邦议院选举","id":"extra33"},{"text":"↔ 相关：德国基督教民主联盟成立","id":"extra26"},{"text":"↔ 相关：康拉德·阿登纳","id":"extra29"}],"source":"history","id":"extra51"},{"title":"库尔特·舒马赫","level":"B","type":"人物卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1895—1952年；战后政治核心期为1945—1952年","place":"德国；西占区；西德","summary":"库尔特·舒马赫重建战后社民党，反对同共产党合并，也成为阿登纳西德路线的主要议会对手。","fields":[{"label":"标题","value":"库尔特·舒马赫"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1895—1952年；战后政治核心期为1945—1952年"},{"label":"地点","value":"德国；西占区；西德"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"库尔特·舒马赫重建战后社民党，反对同共产党合并，也成为阿登纳西德路线的主要议会对手。"},{"label":"生卒年/活跃年代","value":"1895—1952年；1945年后为战后SPD核心领导人。"},{"label":"身份/职务","value":"德国社会民主党政治家，战后SPD主席和西德反对党领袖。"},{"label":"关键贡献/作为","value":"战后在西占区重建SPD，坚决反对社民党与共产党在苏占区合并，主张民主社会主义和德国统一，1949年后领导SPD反对阿登纳政府。"},{"label":"核心主张/立场","value":"反纳粹、反共产主义、民主社会主义，强调社会正义、民族统一和议会民主，但不接受西德过快绑定西方阵营的路线。"},{"label":"为什么重要","value":"他说明战后西德并非只有阿登纳路线。SPD的反对派角色、统一诉求和社会化经济主张，塑造了早期西德民主竞争。"},{"label":"争议/评价","value":"舒马赫政治风格强硬，反对西方一体化的立场在冷战背景下受限；但他维护SPD独立性，避免其被苏占区式统一社会主义吞并。"},{"label":"关联事件（可选）","value":"德国社会统一党成立、1949年西德首次联邦议院选举、德意志联邦共和国成立。"},{"label":"出处","value":"SPD.de, 1945 Für ein besseres Deutschland；NDR, Neuaufbau nach dem Krieg: Schumacher und die SPD；Cambridge Core, Germany's Postwar Socialism: Nationalism and Kurt Schumacher。"}],"relationItems":["← 前因：德国社会民主党（SPD）","→ 后果：1949年西德首次联邦议院选举","↔ 相关：德国社会统一党成立","↔ 相关：康拉德·阿登纳","↔ 同时期参考：克莱门特·艾德礼"],"relations":[{"text":"← 前因：德国社会民主党（SPD）","id":"extra628"},{"text":"→ 后果：1949年西德首次联邦议院选举","id":"extra33"},{"text":"↔ 相关：德国社会统一党成立","id":"extra27"},{"text":"↔ 相关：康拉德·阿登纳","id":"extra29"}],"source":"history","id":"extra52"},{"title":"苏占区德国人民代表大会运动","level":"B","type":"组织/机构卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1947—1949年","place":"苏联占领区；东柏林","summary":"人民代表大会运动由SED主导，以“统一与和平”名义组织东部政治动员，成为东德建国的制度前奏。","fields":[{"label":"标题","value":"苏占区德国人民代表大会运动"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1947—1949年"},{"label":"地点","value":"苏联占领区；东柏林"},{"label":"主要国家","value":"德国；苏联"},{"label":"一句话概括","value":"人民代表大会运动由SED主导，以“统一与和平”名义组织东部政治动员，成为东德建国的制度前奏。"},{"label":"性质/类型","value":"由SED和民主阵营推动的政治大会与准代表机构。"},{"label":"成立/解散时间","value":"1947年首次召开，1949年转化为东德临时人民议院相关结构。"},{"label":"核心目标/宗旨","value":"反对西方单独建国，宣传德国统一、和平条约和反法西斯民主，同时在苏占区建立SED主导的代表性外观。"},{"label":"关键人物（可选）","value":"SED领导层、民主阵营政党和群众组织代表。"},{"label":"关键行动/事件","value":"1947年12月召开第一次人民代表大会；随后组织人民委员会和宪法草案工作；1949年第三次人民代表大会后形成东德临时人民议院基础。"},{"label":"为什么重要","value":"它解释东德建国不是单纯由苏联宣布，而是通过一套群众代表、统一宣传和宪法程序包装出来。"},{"label":"争议/局限","value":"大会由SED主导，政治竞争和代表自由有限；“全德国统一”话语与实际苏占区国家化进程存在张力。"},{"label":"出处","value":"German History in Documents and Images, First German People’s Congress (December 6-7, 1947)；German Bundestag, The German Democratic Republic (1949-1990)。"}],"relationItems":["← 前因：德国社会统一党成立","→ 后果：德意志民主共和国成立","↔ 相关：苏占区德国经济委员会","↔ 相关：苏联占领区社会主义改造","↔ 同时期参考：伦敦六国会议"],"relations":[{"text":"← 前因：德国社会统一党成立","id":"extra27"},{"text":"→ 后果：德意志民主共和国成立","id":"extra19"},{"text":"↔ 相关：苏占区德国经济委员会","id":"extra43"},{"text":"↔ 相关：苏联占领区社会主义改造","id":"extra18"}],"source":"history","id":"extra53"},{"title":"战后德国配给票制度","level":"C","type":"制度/文本卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1945—1948年尤为重要，部分地区延续更久","place":"盟国占领下的德国","summary":"战后配给票制度延续了短缺经济，把食品、衣物和燃料分配变成占领区日常生活的核心秩序。","fields":[{"label":"标题","value":"战后德国配给票制度"},{"label":"分级","value":"C"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1945—1948年尤为重要，部分地区延续更久"},{"label":"地点","value":"盟国占领下的德国"},{"label":"主要国家","value":"德国；美国；英国；法国；苏联"},{"label":"一句话概括","value":"战后配给票制度延续了短缺经济，把食品、衣物和燃料分配变成占领区日常生活的核心秩序。"},{"label":"制定方/签署方","value":"盟国占领当局与德国地方行政机构。"},{"label":"主要内容","value":"居民凭配给票购买面包、脂肪、肉类、衣物和燃料等生活必需品，配给标准受占领区、年龄、职业和供应状况影响。"},{"label":"它试图解决什么问题","value":"德国战败后生产崩溃、交通破坏、难民涌入和粮食短缺严重，占领当局需要用票证维持最低生活和社会秩序。"},{"label":"为什么重要","value":"它让战后重组落到普通人的饭桌和衣柜上，解释为什么黑市、CARE包裹和货币改革会有那么强的社会冲击。"},{"label":"争议/局限","value":"配给标准往往不足以维持体面生活，城市居民依赖黑市、乡村交换和亲友援助；不同占领区供应差异明显。"},{"label":"造成的影响","value":"配给制度与黑市经济长期并存，1948年西占区货币改革后市场供应改善，配给的重要性逐渐下降。"},{"label":"出处","value":"German History in Documents and Images, postwar food rationing materials；Allied occupation economic histories；Haus der Geschichte, ration cards and postwar everyday life collections。"}],"relationItems":["← 前因：纳粹德国配给票制度","→ 后果：1948年西占区货币改革","↔ 相关：战后德国黑市经济","↔ 相关：CARE包裹进入德国","↔ 同时期参考：英国战后配给延续"],"relations":[{"text":"← 前因：纳粹德国配给票制度","id":"extra293"},{"text":"→ 后果：1948年西占区货币改革","id":"extra13"},{"text":"↔ 相关：战后德国黑市经济","id":"extra25"},{"text":"↔ 相关：CARE包裹进入德国","id":"extra50"}],"source":"history","id":"extra54"},{"title":"战后德国返乡战俘","level":"C","type":"事件卡","tags":["经济与社会","战争与外交"],"mainTag":"经济与社会","subTag":"战争与外交","timeText":"1945年后，1940年代后期至1950年代仍持续","place":"德国各占领区；苏联、法国、英国、美国等战俘关押地","summary":"数百万德国战俘在战后陆续返乡，改变家庭、劳动力市场和战争责任记忆。","fields":[{"label":"标题","value":"战后德国返乡战俘"},{"label":"分级","value":"C"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1945年后，1940年代后期至1950年代仍持续"},{"label":"地点","value":"德国各占领区；苏联、法国、英国、美国等战俘关押地"},{"label":"主要国家","value":"德国；苏联；美国；英国；法国"},{"label":"一句话概括","value":"数百万德国战俘在战后陆续返乡，改变家庭、劳动力市场和战争责任记忆。"},{"label":"参与者","value":"德国战俘、盟国关押当局、德国家庭、地方行政和救济机构。"},{"label":"发生了什么","value":"德国投降后，大量士兵仍被盟国作为战俘关押，用于清理、重建、农业或赔偿性劳动。美国、英国和法国较早释放大量战俘，苏联关押时间更长，直到1950年代仍有战俘归来。返乡者面对家庭变故、住房短缺、就业困难和战败记忆。"},{"label":"为什么重要","value":"返乡战俘把战争从前线带回家庭，使战后德国社会必须处理失踪、残疾、心理创伤、男性身份和罪责回避等问题。"},{"label":"前因","value":"德国军队在欧洲各战场投降或被俘，盟国既要防止军队重组，也把战俘劳力用于战后清理和赔偿劳动。"},{"label":"后果","value":"战俘返乡缓解部分劳动力短缺，却也冲击由女性、老人和儿童维持的战后家庭秩序；苏联释放战俘问题成为西德冷战政治议题。"},{"label":"出处","value":"German Historical Institute, German POWs after 1945 references；Bundeszentrale für politische Bildung, Heimkehrer and POW memory materials；USHMM / WWII POW general references。"}],"relationItems":["← 前因：纳粹德国无条件投降","→ 后果：战后德国住房重建","↔ 相关：战后德国“瓦砾妇女”","↔ 相关：德国去纳粹化","↔ 同时期参考：日本战俘返乡"],"relations":[{"text":"← 前因：纳粹德国无条件投降","id":"extra1"},{"text":"→ 后果：战后德国住房重建","id":"extra850"},{"text":"↔ 相关：战后德国“瓦砾妇女”","id":"extra49"},{"text":"↔ 相关：德国去纳粹化","id":"extra5"}],"source":"history","id":"extra55"},{"title":"战后德国大学重开","level":"C","type":"事件卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1945—1949年","place":"盟国占领下的德国大学城市","summary":"战后德国大学在废墟、去纳粹化和占领监管下陆续重开，承担知识重建和政治再教育双重任务。","fields":[{"label":"标题","value":"战后德国大学重开"},{"label":"分级","value":"C"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1945—1949年"},{"label":"地点","value":"盟国占领下的德国大学城市"},{"label":"主要国家","value":"德国；美国；英国；法国；苏联"},{"label":"一句话概括","value":"战后德国大学在废墟、去纳粹化和占领监管下陆续重开，承担知识重建和政治再教育双重任务。"},{"label":"参与者","value":"盟国占领当局、德国大学行政、教授、学生、去纳粹化审查机构。"},{"label":"发生了什么","value":"德国战败后，大学因战争破坏、纳粹化、教授审查和物资短缺而停摆或受限。各占领区在审查教师、改编课程和恢复设施后陆续允许大学重开。许多学生是退伍军人、战俘返乡者或经历战争中断的一代。"},{"label":"为什么重要","value":"大学重开说明战后重建不只是修桥铺路，也包括恢复知识生产、专业训练和公共文化权威。"},{"label":"前因","value":"纳粹德国大学清洗和战争动员严重破坏学术自治，大量学者流亡、死亡或卷入纳粹体制；战败后占领当局必须决定如何处理旧大学。"},{"label":"后果","value":"大学逐步恢复教学，但去纳粹化不彻底、物资匮乏和冷战分裂影响学术环境；东西德高等教育后来走向不同制度。"},{"label":"出处","value":"German History in Documents and Images, postwar university reopening materials；University histories of Heidelberg, Munich, Berlin after 1945；Allied re-education studies。"}],"relationItems":["← 前因：纳粹德国大学清洗","→ 后果：战后德国再教育政策","↔ 相关：德国去纳粹化","↔ 相关：战后德国返乡战俘","↔ 同时期参考：日本大学战后改革"],"relations":[{"text":"← 前因：纳粹德国大学清洗","id":"extra287"},{"text":"→ 后果：战后德国再教育政策","id":"extra47"},{"text":"↔ 相关：德国去纳粹化","id":"extra5"},{"text":"↔ 相关：战后德国返乡战俘","id":"extra55"}],"source":"history","id":"extra56"},{"title":"战后德国废墟文学","level":"B","type":"概念/思潮卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1945—1950年代初","place":"战后德国","summary":"废墟文学用简短、冷静和反修辞的语言描写战败、饥饿、返乡和道德破碎，是战后德国文学重新开始的重要形式。","fields":[{"label":"标题","value":"战后德国废墟文学"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1945—1950年代初"},{"label":"地点","value":"战后德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"废墟文学用简短、冷静和反修辞的语言描写战败、饥饿、返乡和道德破碎，是战后德国文学重新开始的重要形式。"},{"label":"核心主张/思路","value":"在纳粹语言和战争宣传崩溃后，文学应回到具体经验、破碎生活和朴素语言，避免宏大谎言。"},{"label":"提出者/代表人物（可选）","value":"海因里希·伯尔、沃尔夫冈·博歇特、君特·艾希等。"},{"label":"它从何而来","value":"城市废墟、战俘返乡、家庭破裂、饥饿和纳粹语言污染，使战后作家寻找新的低调表达方式。"},{"label":"典型表现","value":"短篇小说、广播剧和诗歌描写瓦砾、寒冷、黑市、失踪者、返乡士兵和日常道德选择。"},{"label":"为什么重要","value":"它把“零点时刻”的文化感受具体化，说明战后德国如何尝试在语言上摆脱纳粹修辞和战争幻觉。"},{"label":"争议/局限","value":"废墟文学常聚焦德国人的苦难，有时较少直接面对德国加害责任和犹太人纳粹犹太人大屠杀。"},{"label":"出处","value":"Britannica, German literature after 1945；Goethe-Institut, Trümmerliteratur; German Studies resources on rubble literature。"}],"relationItems":["← 前因：战后德国“零点时刻”","→ 后果：战后德国罪责讨论","↔ 相关：战后德国“瓦砾妇女”","↔ 相关：战后德国返乡战俘","↔ 同时期参考：日本战后文学"],"relations":[{"text":"← 前因：战后德国“零点时刻”","id":"extra9"},{"text":"↔ 相关：战后德国“瓦砾妇女”","id":"extra49"},{"text":"↔ 相关：战后德国返乡战俘","id":"extra55"}],"source":"history","id":"extra57"},{"title":"DEFA电影制片厂成立","level":"C","type":"组织/机构卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1946年5月17日","place":"苏联占领区；柏林/波茨坦-巴伯尔斯贝格","summary":"DEFA在苏占区成立，承担战后电影重建、反法西斯叙事和后来东德国家电影体系的基础功能。","fields":[{"label":"标题","value":"DEFA电影制片厂成立"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1946年5月17日"},{"label":"地点","value":"苏联占领区；柏林/波茨坦-巴伯尔斯贝格"},{"label":"主要国家","value":"德国；苏联"},{"label":"一句话概括","value":"DEFA在苏占区成立，承担战后电影重建、反法西斯叙事和后来东德国家电影体系的基础功能。"},{"label":"性质/类型","value":"电影制片机构。"},{"label":"成立/解散时间","value":"1946年成立；东德时期成为国家电影制片体系核心。"},{"label":"核心目标/宗旨","value":"重建德国电影生产，制作反法西斯、再教育和社会主义导向的影片，同时恢复专业电影工业。"},{"label":"关键人物（可选）","value":"苏联占领当局、德国电影人、后来东德文化行政人员。"},{"label":"关键行动/事件","value":"制作《凶手就在我们中间》等战后早期影片，利用巴伯尔斯贝格电影传统建立新电影生产。"},{"label":"为什么重要","value":"它说明战后文化重建在东西占领区很快分化，电影成为记忆、再教育和国家认同塑造工具。"},{"label":"争议/局限","value":"DEFA提供重要艺术作品，也长期受党和审查制度影响，艺术自主受到限制。"},{"label":"出处","value":"DEFA Foundation, History; University of Massachusetts DEFA Film Library, DEFA history。"}],"relationItems":["← 前因：战后德国再教育政策","→ 后果：德意志民主共和国成立","↔ 相关：战后德国废墟文学","↔ 相关：苏联驻德军事管理局","↔ 同时期参考：意大利新现实主义电影"],"relations":[{"text":"← 前因：战后德国再教育政策","id":"extra47"},{"text":"→ 后果：德意志民主共和国成立","id":"extra19"},{"text":"↔ 相关：战后德国废墟文学","id":"extra57"},{"text":"↔ 相关：苏联驻德军事管理局","id":"extra41"}],"source":"history","id":"extra58"},{"title":"西北德意志广播电台","level":"C","type":"组织/机构卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1945年后形成；1948年转为德国管理","place":"英国占领区，汉堡、科隆等地","summary":"西北德意志广播电台在英国占领区重建公共广播，成为战后西德广播制度的重要前身。","fields":[{"label":"标题","value":"西北德意志广播电台"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1945年后形成；1948年转为德国管理"},{"label":"地点","value":"英国占领区，汉堡、科隆等地"},{"label":"主要国家","value":"英国；德国"},{"label":"一句话概括","value":"西北德意志广播电台在英国占领区重建公共广播，成为战后西德广播制度的重要前身。"},{"label":"性质/类型","value":"占领区公共广播机构。"},{"label":"成立/解散时间","value":"1945年英国占领当局接管并重组广播，1948年转交德国管理；后分化为NDR、WDR等机构。"},{"label":"核心目标/宗旨","value":"在占领监管下提供新闻、教育、文化和民主化内容，摆脱纳粹广播宣传模式。"},{"label":"关键人物（可选）","value":"英国占领当局、德国广播人、战后文化行政人员。"},{"label":"关键行动/事件","value":"重启广播节目，建立相对公共服务导向的广播结构，为西德联邦式公共广播传统奠定基础。"},{"label":"为什么重要","value":"它说明战后德国媒体重建不只是报刊许可，广播也从宣传机器转向公共服务制度。"},{"label":"争议/局限","value":"早期广播受占领当局监管，政治中立和德国自主性有限；冷战后广播也承担阵营宣传功能。"},{"label":"出处","value":"NDR, Geschichte des NWDR; WDR historical materials; Deutsches Rundfunkarchiv postwar broadcasting references。"}],"relationItems":["← 前因：纳粹德国人民收音机","→ 后果：战后德国再教育政策","↔ 相关：战后德国许可证报刊","↔ 相关：魏玛德国帝国广播公司","↔ 同时期参考：英国BBC公共广播模式"],"relations":[{"text":"← 前因：纳粹德国人民收音机","id":"extra285"},{"text":"→ 后果：战后德国再教育政策","id":"extra47"},{"text":"↔ 相关：战后德国许可证报刊","id":"extra48"},{"text":"↔ 相关：魏玛德国帝国广播公司","id":"card173"}],"source":"history","id":"extra59"},{"title":"大众汽车在英国占领区复产","level":"C","type":"事件卡","tags":["经济与社会","战争与外交"],"mainTag":"经济与社会","subTag":"战争与外交","timeText":"1945—1949年","place":"沃尔夫斯堡，英国占领区","summary":"英国占领当局接管大众汽车工厂并恢复生产，使纳粹“人民汽车”项目转化为战后西德工业复兴资源。","fields":[{"label":"标题","value":"大众汽车在英国占领区复产"},{"label":"分级","value":"C"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1945—1949年"},{"label":"地点","value":"沃尔夫斯堡，英国占领区"},{"label":"主要国家","value":"德国；英国"},{"label":"一句话概括","value":"英国占领当局接管大众汽车工厂并恢复生产，使纳粹“人民汽车”项目转化为战后西德工业复兴资源。"},{"label":"参与者","value":"英国占领当局、伊万·赫斯特、德国工人、大众汽车工厂。"},{"label":"发生了什么","value":"战争结束后，沃尔夫斯堡大众汽车工厂受损并面临拆迁或转用。英国军官伊万·赫斯特等人组织恢复生产，最初为占领当局提供车辆，随后工厂逐步稳定。纳粹时期未兑现给储户的“人民汽车”承诺，在战后被改造成实际汽车工业基础。"},{"label":"为什么重要","value":"它把纳粹消费乌托邦、战争工厂和西德经济奇迹前史连接起来，说明战后复兴常建立在旧工业遗产再利用上。"},{"label":"前因","value":"纳粹大众汽车计划在战前制造了“人民汽车”的消费承诺，战争期间沃尔夫斯堡工厂则主要服务军工生产。1945年后，工厂设备、劳动力和城市空间仍然存在，但它必须在占领监管、物资短缺和去纳粹化环境中重新定位。"},{"label":"后果","value":"复产使沃尔夫斯堡避免彻底拆解，并为西德汽车工业保留重要生产基础。大众汽车后来成为西德最重要工业企业之一，甲壳虫汽车也从纳粹未兑现的承诺转化为战后大众消费和出口成功的象征。"},{"label":"出处","value":"Volkswagen, History; Volkswagen Newsroom, Ivan Hirst and the restart of production; British occupation zone industrial history materials。"}],"relationItems":["← 前因：纳粹大众汽车计划","→ 后果：西德社会市场经济","↔ 相关：纳粹德国“力量来自欢乐”组织","↔ 相关：马歇尔计划与西德重建","↔ 同时期参考：日本丰田战后复兴"],"relations":[{"text":"← 前因：纳粹大众汽车计划","id":"extra124"},{"text":"→ 后果：西德社会市场经济","id":"extra17"},{"text":"↔ 相关：纳粹德国“力量来自欢乐”组织","id":"extra104"},{"text":"↔ 相关：马歇尔计划与西德重建","id":"extra11"}],"source":"history","id":"extra60"},{"title":"冷战形成","level":"A","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1945—1949年为关键形成期","place":"欧洲、德国、柏林、全球权力体系","summary":"冷战形成源于美苏战后秩序分歧、欧洲重建、安全缓冲和德国问题的持续升级。","fields":[{"label":"标题","value":"冷战形成"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1945—1949年为关键形成期"},{"label":"地点","value":"欧洲、德国、柏林、全球权力体系"},{"label":"主要国家","value":"美国；苏联；英国；法国；德国"},{"label":"一句话概括","value":"冷战形成源于美苏战后秩序分歧、欧洲重建、安全缓冲和德国问题的持续升级。"},{"label":"参与者","value":"美国政府、苏联政府、英国和法国、德国占领区政府机构、欧洲各国政党和社会力量。"},{"label":"发生了什么","value":"二战结束后，美苏从战时同盟转向制度和安全竞争。东欧政权重组、马歇尔计划、德国占领区经济合并、货币改革和柏林封锁使分歧公开化。到1949年，北约成立，德意志联邦共和国和德意志民主共和国相继建立，欧洲分裂格局固定下来。"},{"label":"为什么重要","value":"德国战后重组不是孤立国内问题，而是冷战秩序形成的核心现场。柏林、赔偿、货币、政党制度和安全联盟都成为美苏竞争焦点。"},{"label":"前因","value":"纳粹德国无条件投降后，盟国对德国未来、东欧安全、赔偿和经济复兴目标不同。"},{"label":"后果","value":"欧洲分裂为东西两大阵营，西德和东德分别进入不同制度和联盟体系，柏林成为冷战前线。"},{"label":"出处","value":"Office of the Historian: The Cold War 1945-1952；DHM/LeMO: Kalter Krieg；Encyclopaedia Britannica: Cold War。"}],"relationItems":["← 前因：盟国占领德国","← 前因：盟国《波茨坦协定》","↔ 相关：马歇尔计划与西德重建","→ 后果：冷战初期柏林封锁与空运","→ 后果：德意志联邦共和国成立","→ 后果：德意志民主共和国成立"],"relations":[{"text":"← 前因：盟国占领德国","id":"extra2"},{"text":"← 前因：盟国《波茨坦协定》","id":"extra3"},{"text":"↔ 相关：马歇尔计划与西德重建","id":"extra11"},{"text":"→ 后果：冷战初期柏林封锁与空运","id":"extra14"},{"text":"→ 后果：德意志联邦共和国成立","id":"extra16"},{"text":"→ 后果：德意志民主共和国成立","id":"extra19"}],"source":"history","id":"extra849"},{"title":"战后德国住房重建","level":"C","type":"事件卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1945年后，1940年代后期至1950年代尤为关键","place":"德国各大城市和占领区","summary":"战后德国住房重建面对轰炸废墟、难民潮和材料短缺，是社会恢复的基础工程。","fields":[{"label":"标题","value":"战后德国住房重建"},{"label":"分级","value":"C"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1945年后，1940年代后期至1950年代尤为关键"},{"label":"地点","value":"德国各大城市和占领区"},{"label":"主要国家","value":"德国；美国；英国；法国；苏联"},{"label":"一句话概括","value":"战后德国住房重建面对轰炸废墟、难民潮和材料短缺，是社会恢复的基础工程。"},{"label":"参与者","value":"占领当局、德国地方政府、建筑部门、被驱逐者、返乡战俘、城市居民和“瓦砾妇女”。"},{"label":"发生了什么","value":"二战结束后，德国许多城市住房严重损毁，大量被驱逐者和返乡人员进一步加剧短缺。各占领区通过清理废墟、临时安置、配给建筑材料和恢复市政服务逐步重建居住空间。西德后来在社会住房政策和经济恢复中加快建设。"},{"label":"为什么重要","value":"住房重建是战后“正常生活”恢复的前提。没有住房、供暖和市政服务，去纳粹化、经济复兴和政治重建都难以稳定推进。"},{"label":"前因","value":"盟军战略轰炸德国、德国东部领土丧失与被驱逐者、战后德国饥饿与住房危机。"},{"label":"后果","value":"社会住房政策和城市重建展开，也形成关于废墟记忆、现代建筑和战后家庭生活的新讨论。"},{"label":"出处","value":"DHM/LeMO: Nachkriegszeit；German History in Documents and Images: Postwar reconstruction；Jeffry Diefendorf, In the Wake of War。"}],"relationItems":["← 前因：战后德国饥饿与住房危机","← 前因：战后德国“瓦砾妇女”","↔ 相关：现代社会住宅","→ 后果：西德社会市场经济","↔ 相关：战后德国被迫迁徙者营地"],"relations":[{"text":"← 前因：战后德国饥饿与住房危机","id":"extra8"},{"text":"← 前因：战后德国“瓦砾妇女”","id":"extra49"},{"text":"↔ 相关：现代社会住宅","id":"card201"},{"text":"→ 后果：西德社会市场经济","id":"extra17"},{"text":"↔ 相关：战后德国被迫迁徙者营地","id":"extra24"}],"source":"history","id":"extra850"},{"title":"东京审判","level":"B","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1946—1948年","place":"日本东京","summary":"东京审判审理日本甲级战犯，是二战后国际刑事司法体系的重要组成部分。","fields":[{"label":"标题","value":"东京审判"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1946—1948年"},{"label":"地点","value":"日本东京"},{"label":"主要国家","value":"日本；美国；英国；中国；苏联；澳大利亚；荷兰；法国；印度等"},{"label":"一句话概括","value":"东京审判审理日本甲级战犯，是二战后国际刑事司法体系的重要组成部分。"},{"label":"参与者","value":"远东国际军事法庭、盟国检察官、日本被告、道格拉斯·麦克阿瑟主导的盟军占领当局。"},{"label":"发生了什么","value":"盟国在东京设立远东国际军事法庭，审理日本领导层的侵略战争、战争罪和反人道罪责任。审判历时两年多，对东条英机等被告作出判决，并与纽伦堡审判共同构成战后国际刑事司法先例。"},{"label":"为什么重要","value":"它把战后追责从欧洲扩展到亚太，也留下关于胜者审判、天皇责任和殖民暴力纳入范围不足的争议。"},{"label":"前因","value":"日本发动侵略战争、太平洋战争结束和盟军占领日本。"},{"label":"后果","value":"日本战后政治重建、战争责任记忆和国际刑法发展受到长期影响。"},{"label":"出处","value":"United Nations Audiovisual Library of International Law: International Military Tribunal for the Far East；Yuma Totani, The Tokyo War Crimes Trial；Neil Boister and Robert Cryer, The Tokyo International Military Tribunal。"}],"relationItems":["← 前因：第二次世界大战结束","↔ 相关：纽伦堡审判","↔ 相关：盟国管制委员会第10号法令","→ 后果：战后国际刑事司法"],"relations":[{"text":"↔ 相关：盟国管制委员会第10号法令","id":"extra36"}],"source":"history","id":"extra851"},{"title":"纳粹党成立","level":"A","type":"组织/机构卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1920年改名为国家社会主义德国工人党","place":"德国慕尼黑","summary":"纳粹党从战后慕尼黑右翼小党发展而来，把民族主义、反犹主义、反马克思主义和群众动员结合起来。","fields":[{"label":"标题","value":"纳粹党成立"},{"label":"分级","value":"A"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1920年改名为国家社会主义德国工人党"},{"label":"地点","value":"德国慕尼黑"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"纳粹党从战后慕尼黑右翼小党发展而来，把民族主义、反犹主义、反马克思主义和群众动员结合起来。"},{"label":"性质/类型","value":"极右翼政党、群众运动组织。"},{"label":"成立/解散时间","value":"前身德国工人党成立于1919年；1920年改名为国家社会主义德国工人党；1945年纳粹德国战败后被取缔。"},{"label":"核心目标/宗旨","value":"推翻凡尔赛体系和魏玛共和国，建立民族共同体和领袖独裁，排斥犹太人、马克思主义者和其他被定义为敌人的群体。"},{"label":"关键人物（可选）","value":"阿道夫·希特勒、安东·德雷克斯勒、迪特里希·埃卡特等。"},{"label":"关键行动/事件","value":"提出二十五点纲领，建立纳粹冲锋队，利用集会、宣传和街头暴力扩大影响，1923年发动希特勒啤酒馆政变。"},{"label":"为什么重要","value":"纳粹党最初只是战后极右翼生态中的小组织，但它最终成为摧毁魏玛共和国、发动二战和实施纳粹犹太人大屠杀的核心政治机器。"},{"label":"争议/局限","value":"不能用后来的掌权结果反推其早期必然成功。早期纳粹党是在巴伐利亚战后暴力、反共恐惧和凡尔赛怨恨中逐步成长。"},{"label":"出处","value":"United States Holocaust Memorial Museum: Nazi Party；Encyclopaedia Britannica: Nazi Party；Deutsches Historisches Museum/LeMO相关资料。"}],"relationItems":["← 前因：德国“背后一刀”传说","← 前因：《凡尔赛和约》","→ 后果：希特勒啤酒馆政变","→ 后果：希特勒《我的奋斗》"],"relations":[{"text":"← 前因：德国“背后一刀”传说","id":"extra623"},{"text":"← 前因：《凡尔赛和约》","id":"card59"},{"text":"→ 后果：希特勒啤酒馆政变","id":"card18"},{"text":"→ 后果：希特勒《我的奋斗》","id":"extra66"}],"source":"history","id":"extra92"},{"title":"纳粹冲锋队","level":"B","type":"组织/机构卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1921年成立，魏玛后期迅速扩张","place":"德国","summary":"纳粹冲锋队是纳粹党的准军事组织，用街头暴力、制服政治和群众动员帮助纳粹破坏魏玛民主。","fields":[{"label":"标题","value":"纳粹冲锋队"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1921年成立，魏玛后期迅速扩张"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"纳粹冲锋队是纳粹党的准军事组织，用街头暴力、制服政治和群众动员帮助纳粹破坏魏玛民主。"},{"label":"性质/类型","value":"纳粹准军事组织。"},{"label":"成立/解散时间","value":"1921年形成；纳粹掌权后继续存在，1934年纳粹长刀之夜后政治地位被削弱。"},{"label":"核心目标/宗旨","value":"保护纳粹集会，攻击政治对手，制造街头存在感，展示纳粹运动的力量和纪律。"},{"label":"关键人物（可选）","value":"恩斯特·罗姆等。"},{"label":"关键行动/事件","value":"参与街头斗殴、恐吓左翼和犹太人、保护希特勒演讲和纳粹集会。"},{"label":"为什么重要","value":"纳粹党不是只靠选票崛起，也靠纳粹冲锋队把暴力常态化，让政治竞争变成身体威胁。"},{"label":"争议/局限","value":"纳粹冲锋队内部有“第二次革命”等激进诉求，与军方和保守精英发生矛盾，最终被希特勒清洗。"},{"label":"出处","value":"United States Holocaust Memorial Museum: SA；Deutsches Historisches Museum/LeMO: SA；Encyclopaedia Britannica: Sturmabteilung。"}],"relationItems":["← 前因：纳粹党成立","← 前因：魏玛政治街头暴力","→ 后果：纳粹长刀之夜","↔ 相关：希特勒啤酒馆政变"],"relations":[{"text":"← 前因：纳粹党成立","id":"extra92"},{"text":"← 前因：魏玛政治街头暴力","id":"card34"},{"text":"→ 后果：纳粹长刀之夜","id":"extra108"},{"text":"↔ 相关：希特勒啤酒馆政变","id":"card18"}],"source":"history","id":"extra93"},{"title":"纳粹宣传机器","level":"A","type":"概念/思潮卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1920年代至1945年，魏玛后期迅速成熟","place":"德国","summary":"纳粹宣传机器用现代媒体、群众集会和简单敌我叙事，把危机情绪转化为对希特勒和纳粹党的支持。","fields":[{"label":"标题","value":"纳粹宣传机器"},{"label":"分级","value":"A"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1920年代至1945年，魏玛后期迅速成熟"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"纳粹宣传机器用现代媒体、群众集会和简单敌我叙事，把危机情绪转化为对希特勒和纳粹党的支持。"},{"label":"核心主张/思路","value":"政治传播要重复、情绪化、视觉化，把复杂危机解释为民族受辱、内部敌人和领袖拯救。"},{"label":"提出者/代表人物（可选）","value":"约瑟夫·戈培尔是关键组织者，希特勒本人也是核心宣传形象。"},{"label":"它从何而来","value":"魏玛大众传媒、街头政治、战败创伤、经济危机和现代广告技术共同提供条件。"},{"label":"典型表现","value":"海报、报纸、广播、飞机巡回演讲、火炬游行、制服、旗帜、群众大会和电影。"},{"label":"为什么重要","value":"纳粹不是只靠暴力上台，也靠高度现代的政治营销塑造“运动”感和不可阻挡的胜利感。"},{"label":"争议/局限","value":"宣传有效并不等于选民完全被动；它与经济危机、组织网络和精英交易共同作用。"},{"label":"出处","value":"United States Holocaust Memorial Museum: Nazi Propaganda；Deutsches Historisches Museum/LeMO: NS-Propaganda；German History Documents and Images相关资料。"}],"relationItems":["← 前因：魏玛广播文化","← 前因：魏玛政治街头暴力","→ 后果：希特勒出任德国总理","↔ 相关：纳粹冲锋队"],"relations":[{"text":"← 前因：魏玛广播文化","id":"card80"},{"text":"← 前因：魏玛政治街头暴力","id":"card34"},{"text":"→ 后果：希特勒出任德国总理","id":"card71"},{"text":"↔ 相关：纳粹冲锋队","id":"extra93"}],"source":"history","id":"extra94"},{"title":"罗姆与纳粹冲锋队激进化","level":"B","type":"概念/思潮卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1920年代末至1934年","place":"德国","summary":"罗姆领导下的纳粹冲锋队把失业青年、退伍军人和街头暴力组织起来，形成纳粹运动内部激进社会革命压力。","fields":[{"label":"标题","value":"罗姆与纳粹冲锋队激进化"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1920年代末至1934年"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"罗姆领导下的纳粹冲锋队把失业青年、退伍军人和街头暴力组织起来，形成纳粹运动内部激进社会革命压力。"},{"label":"核心主张/思路","value":"纳粹冲锋队不仅要保护纳粹集会，也希望通过暴力和“第二次革命”重塑国家、军队和社会地位。"},{"label":"提出者/代表人物（可选）","value":"恩斯特·罗姆。"},{"label":"它从何而来","value":"战后准军事文化、失业、男性青年失落、右翼暴力和纳粹群众动员结合。"},{"label":"典型表现","value":"街头斗殴、制服游行、攻击共产党和社会民主党人、要求军队吸纳或改造。"},{"label":"为什么重要","value":"纳粹冲锋队帮助纳粹上台，但其规模和激进诉求也威胁传统军方和保守精英，最终引发纳粹长刀之夜。"},{"label":"争议/局限","value":"纳粹冲锋队并非只有社会革命诉求，也包含机会主义、暴力文化和对领袖的个人效忠。"},{"label":"出处","value":"United States Holocaust Memorial Museum: SA；Deutsches Historisches Museum/LeMO: Ernst Röhm；Encyclopaedia Britannica: Ernst Röhm。"}],"relationItems":["← 前因：纳粹冲锋队","→ 后果：纳粹长刀之夜","↔ 相关：魏玛政治街头暴力"],"relations":[{"text":"← 前因：纳粹冲锋队","id":"extra93"},{"text":"→ 后果：纳粹长刀之夜","id":"extra108"},{"text":"↔ 相关：魏玛政治街头暴力","id":"card34"}],"source":"history","id":"extra95"},{"title":"1932年纳粹冲锋队禁令与解除","level":"B","type":"事件卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1932年4月至6月","place":"德国","summary":"1932年纳粹冲锋队一度被禁又被巴本解除禁令，使纳粹街头暴力重新扩张。","fields":[{"label":"标题","value":"1932年纳粹冲锋队禁令与解除"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1932年4月至6月"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1932年纳粹冲锋队一度被禁又被巴本解除禁令，使纳粹街头暴力重新扩张。"},{"label":"参与者","value":"布吕宁政府、巴本政府、纳粹冲锋队、纳粹党、警察和各政党。"},{"label":"发生了什么","value":"1932年春，纳粹冲锋队暴力不断升级，布吕宁政府在总统支持下禁止纳粹冲锋队和纳粹党卫队活动，试图限制纳粹街头力量。布吕宁下台后，巴本为了争取纳粹容忍其内阁并削弱左翼，解除禁令。纳粹冲锋队重新公开活动，选举季街头冲突迅速加剧。禁令解除不但没有稳定局势，反而让纳粹能用暴力和恐吓增强政治存在感。"},{"label":"为什么重要","value":"它显示保守政府为短期议会策略放松对纳粹暴力组织的控制，直接恶化共和国安全环境。"},{"label":"前因","value":"魏玛街头暴力升级后，布吕宁政府试图限制纳粹冲锋队，但总统内阁政治依赖右翼支持，巴本上台后又把解除禁令当作拉拢纳粹的筹码。"},{"label":"后果","value":"禁令解除使冲锋队重新公开动员，街头暴力迅速升级，并直接影响1932年夏季选举和阿尔托纳血腥星期日等危机。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: SA-Verbot 1932；United States Holocaust Memorial Museum相关资料。"}],"relationItems":["← 前因：纳粹冲锋队","→ 后果：1932年阿尔托纳血腥星期日","→ 后果：1932年7月德国国会选举"],"relations":[{"text":"← 前因：纳粹冲锋队","id":"extra93"},{"text":"→ 后果：1932年阿尔托纳血腥星期日","id":"card56"},{"text":"→ 后果：1932年7月德国国会选举","id":"card46"}],"source":"history","id":"extra96"},{"title":"德国国会纵火案","level":"B","type":"事件卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1933年2月27日","place":"德国柏林国会大厦","summary":"德国国会纵火案被纳粹用来制造共产主义暴动恐慌，成为摧毁公民自由和镇压左翼的直接借口。","fields":[{"label":"标题","value":"德国国会纵火案"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1933年2月27日"},{"label":"地点","value":"德国柏林国会大厦"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国国会纵火案被纳粹用来制造共产主义暴动恐慌，成为摧毁公民自由和镇压左翼的直接借口。"},{"label":"参与者","value":"马里inus·范德卢贝、纳粹政府、德国共产党、警察和司法机关。"},{"label":"发生了什么","value":"1933年2月27日晚，柏林国会大厦起火。荷兰共产主义者范德卢贝在现场被捕，纳粹立即宣布这是共产党发动全国暴动的信号。希特勒、戈林等人利用事件推动大规模逮捕共产党人、社会民主党人和其他政治对手。次日，兴登堡签署紧急法令，暂停多项基本权利。纵火案本身的细节长期存在争议，但其政治后果非常明确：纳粹把危机转化为合法镇压。"},{"label":"为什么重要","value":"它是纳粹从联合政府走向恐怖统治的关键转折，帮助纳粹在3月选举前摧毁反对派组织能力。"},{"label":"前因","value":"希特勒刚出任总理但尚未掌握绝对权力，纳粹需要一个把共产党和共和国反对派塑造成国家敌人的紧急契机。"},{"label":"后果","value":"纵火案被用于推动国会纵火法令，共产党和其他反对派遭到镇压，授权法通过的政治条件由此形成。"},{"label":"出处","value":"United States Holocaust Memorial Museum: Reichstag Fire；Deutsches Historisches Museum/LeMO: Reichstagsbrand；Encyclopaedia Britannica相关资料。"}],"relationItems":["← 前因：希特勒出任德国总理","→ 后果：德国国会纵火法令","→ 后果：纳粹德国授权法"],"relations":[{"text":"← 前因：希特勒出任德国总理","id":"card71"},{"text":"→ 后果：德国国会纵火法令","id":"extra98"},{"text":"→ 后果：纳粹德国授权法","id":"extra99"}],"source":"history","id":"extra97"},{"title":"德国国会纵火法令","level":"B","type":"制度/文本卡","tags":["政治与制度","无"],"mainTag":"政治与制度","subTag":"无","timeText":"1933年2月28日","place":"德国","summary":"德国国会纵火法令暂停魏玛宪法基本权利，使纳粹能用国家权力合法化大规模逮捕和镇压。","fields":[{"label":"标题","value":"德国国会纵火法令"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"无"},{"label":"时间","value":"1933年2月28日"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国国会纵火法令暂停魏玛宪法基本权利，使纳粹能用国家权力合法化大规模逮捕和镇压。"},{"label":"制定方/签署方","value":"希特勒政府推动，兴登堡总统根据魏玛宪法第48条签署。"},{"label":"主要内容","value":"暂停人身自由、言论、出版、集会、结社、通信秘密和住宅不可侵犯等权利，并扩大中央政府干预各邦权力。"},{"label":"它试图解决什么问题","value":"纳粹声称德国面临共产主义暴动威胁，需要紧急措施保卫国家。"},{"label":"为什么重要","value":"它把魏玛宪法的紧急权转化为纳粹独裁工具。该法令没有很快撤销，而是成为第三帝国长期恐怖统治的法律基础。"},{"label":"争议/局限","value":"法令表面是应急措施，实质上摧毁宪法自由；它显示合法程序可以被用来取消法治。"},{"label":"造成的影响","value":"共产党和社会民主党组织遭大规模打击；3月选举和纳粹德国授权法表决在恐怖环境中进行。"},{"label":"出处","value":"USHMM: Reichstag Fire Decree；DHM/LeMO: Verordnung zum Schutz von Volk und Staat；German History Documents and Images相关文本。"}],"relationItems":["← 前因：德国国会纵火案","← 前因：魏玛宪法第48条","→ 后果：纳粹德国授权法","→ 后果：纳粹盖世太保"],"relations":[{"text":"← 前因：德国国会纵火案","id":"extra97"},{"text":"← 前因：魏玛宪法第48条","id":"card12"},{"text":"→ 后果：纳粹德国授权法","id":"extra99"},{"text":"→ 后果：纳粹盖世太保","id":"extra106"}],"source":"history","id":"extra98"},{"title":"纳粹德国授权法","level":"A","type":"制度/文本卡","tags":["政治与制度","无"],"mainTag":"政治与制度","subTag":"无","timeText":"1933年3月23日","place":"德国柏林克罗尔歌剧院","summary":"纳粹德国授权法允许希特勒政府绕过国会和宪法立法，是纳粹独裁合法化的核心文件。","fields":[{"label":"标题","value":"纳粹德国授权法"},{"label":"分级","value":"A"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"无"},{"label":"时间","value":"1933年3月23日"},{"label":"地点","value":"德国柏林克罗尔歌剧院"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"纳粹德国授权法允许希特勒政府绕过国会和宪法立法，是纳粹独裁合法化的核心文件。"},{"label":"制定方/签署方","value":"希特勒政府提出，德国国会在恐怖和压力下通过。"},{"label":"主要内容","value":"政府可自行制定法律，包括偏离宪法的法律，不再需要国会正常立法程序。"},{"label":"它试图解决什么问题","value":"纳粹声称国家需要强力政府克服危机，实质上要取消议会制约。"},{"label":"为什么重要","value":"纳粹德国授权法使纳粹从控制政府转向控制国家立法权，是魏玛宪政死亡的核心节点。"},{"label":"争议/局限","value":"表决发生在共产党议员被排除、冲锋队包围、反对派受恐吓的条件下，不能视为自由议会授权。"},{"label":"造成的影响","value":"国会被架空；政党、工会、各邦和社会组织迅速被纳入一体化统治。"},{"label":"出处","value":"USHMM: Enabling Act；DHM/LeMO: Ermächtigungsgesetz；Encyclopaedia Britannica: Enabling Act。"}],"relationItems":["← 前因：1933年3月德国国会选举","← 前因：德国国会纵火法令","→ 后果：纳粹一体化政策","→ 后果：纳粹一党制"],"relations":[{"text":"← 前因：1933年3月德国国会选举","id":"card57"},{"text":"← 前因：德国国会纵火法令","id":"extra98"},{"text":"→ 后果：纳粹一体化政策","id":"extra100"},{"text":"→ 后果：纳粹一党制","id":"extra101"}],"source":"history","id":"extra99"},{"title":"纳粹一体化政策","level":"A","type":"概念/思潮卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1933年至1934年集中推进","place":"德国","summary":"纳粹一体化政策把各邦、政党、工会、文化团体和社会组织纳入纳粹控制，摧毁德国社会多元结构。","fields":[{"label":"标题","value":"纳粹一体化政策"},{"label":"分级","value":"A"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1933年至1934年集中推进"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"纳粹一体化政策把各邦、政党、工会、文化团体和社会组织纳入纳粹控制，摧毁德国社会多元结构。"},{"label":"核心主张/思路","value":"国家、社会和个人都应服从纳粹党和领袖意志，独立组织不能保留自治空间。"},{"label":"提出者/代表人物（可选）","value":"希特勒、纳粹党领导层和各级纳粹组织。"},{"label":"它从何而来","value":"纳粹德国授权法提供法律基础，纳粹暴力组织提供强制力量，保守精英和官僚系统的配合加快执行。"},{"label":"典型表现","value":"解散或合并政党，取缔工会，控制各邦政府，清洗公务员，重组文化、青年、妇女和职业组织。"},{"label":"为什么重要","value":"它解释纳粹如何在短时间内把执政优势变成全社会控制，而不仅是赢得政府职位。"},{"label":"争议/局限","value":"一体化并非完全无阻力，但反对力量被迅速分割、恐吓和制度性消灭。"},{"label":"出处","value":"DHM/LeMO: Gleichschaltung；USHMM相关资料；German History Documents and Images相关资料。"}],"relationItems":["← 前因：纳粹德国授权法","→ 后果：纳粹一党制","→ 后果：纳粹德国劳工阵线","→ 后果：纳粹文化控制"],"relations":[{"text":"← 前因：纳粹德国授权法","id":"extra99"},{"text":"→ 后果：纳粹一党制","id":"extra101"},{"text":"→ 后果：纳粹德国劳工阵线","id":"extra103"},{"text":"→ 后果：纳粹文化控制","id":"extra113"}],"source":"history","id":"extra100"},{"title":"纳粹一党制","level":"A","type":"制度/文本卡","tags":["政治与制度","无"],"mainTag":"政治与制度","subTag":"无","timeText":"1933年7月14日法律确认","place":"德国","summary":"纳粹一党制以法律形式确认纳粹党为德国唯一合法政党，彻底结束魏玛多党政治。","fields":[{"label":"标题","value":"纳粹一党制"},{"label":"分级","value":"A"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"无"},{"label":"时间","value":"1933年7月14日法律确认"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"纳粹一党制以法律形式确认纳粹党为德国唯一合法政党，彻底结束魏玛多党政治。"},{"label":"制定方/签署方","value":"希特勒政府。"},{"label":"主要内容","value":"禁止成立新政党，确认国家社会主义德国工人党为唯一政党，对试图维持或建立其他政党者进行惩罚。"},{"label":"它试图解决什么问题","value":"纳粹要消除议会竞争和政治替代可能，把国家权力与纳粹党组织绑定。"},{"label":"为什么重要","value":"一党制标志德国政治从威权化进入公开独裁，所有合法政治表达被纳粹党垄断。"},{"label":"争议/局限","value":"所谓法律确认发生在其他政党已经被暴力、逮捕、恐吓和自我解散逼入绝境之后。"},{"label":"造成的影响","value":"政党政治消失；党国结构成形；反对派转入流亡、地下或集中营。"},{"label":"出处","value":"DHM/LeMO: Gesetz gegen Neubildung von Parteien；USHMM相关资料；German History Documents and Images相关文本。"}],"relationItems":["← 前因：纳粹一体化政策","← 前因：纳粹德国授权法","→ 后果：纳粹德国党国体制"],"relations":[{"text":"← 前因：纳粹一体化政策","id":"extra100"},{"text":"← 前因：纳粹德国授权法","id":"extra99"},{"text":"→ 后果：纳粹德国党国体制","id":"extra865"}],"source":"history","id":"extra101"},{"title":"纳粹取缔德国工会","level":"B","type":"事件卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1933年5月2日","place":"德国","summary":"纳粹在五一劳动节后突袭并取缔自由工会，摧毁工人阶级独立组织。","fields":[{"label":"标题","value":"纳粹取缔德国工会"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1933年5月2日"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"纳粹在五一劳动节后突袭并取缔自由工会，摧毁工人阶级独立组织。"},{"label":"参与者","value":"纳粹党、冲锋队、纳粹党卫队、自由工会、德国工人和职员。"},{"label":"发生了什么","value":"1933年5月1日，纳粹把国际劳动节改造成“民族劳动日”，用国家仪式吸纳工人象征。次日，冲锋队和纳粹党卫队突袭各地工会办公室，逮捕工会干部，没收财产和档案。自由工会被解散，独立罢工和集体谈判空间被摧毁。随后纳粹建立纳粹德国劳工阵线，把工人和雇主纳入同一党控组织。"},{"label":"为什么重要","value":"它说明纳粹并非真正代表工人自治，而是用民族共同体语言取消阶级组织和劳动权利。"},{"label":"前因","value":"纳粹一体化政策要求消除独立社会组织，工会与社民党、共产党和工人阶级自治传统联系紧密，是独裁统治必须摧毁的力量。"},{"label":"后果","value":"独立工会被纳粹德国劳工阵线取代，罢工权和集体谈判被取消，劳动者被纳入国家和党控制的劳动秩序。"},{"label":"出处","value":"DHM/LeMO: Zerschlagung der Gewerkschaften；USHMM相关资料；German History Documents and Images相关资料。"}],"relationItems":["← 前因：纳粹一体化政策","→ 后果：纳粹德国劳工阵线"],"relations":[{"text":"← 前因：纳粹一体化政策","id":"extra100"},{"text":"→ 后果：纳粹德国劳工阵线","id":"extra103"}],"source":"history","id":"extra102"},{"title":"纳粹德国劳工阵线","level":"B","type":"组织/机构卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1933年至1945年","place":"德国及纳粹控制区","summary":"纳粹德国劳工阵线取代独立工会，把工人与雇主纳入纳粹党控制的劳动共同体。","fields":[{"label":"标题","value":"纳粹德国劳工阵线"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1933年至1945年"},{"label":"地点","value":"德国及纳粹控制区"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"纳粹德国劳工阵线取代独立工会，把工人与雇主纳入纳粹党控制的劳动共同体。"},{"label":"性质/类型","value":"纳粹党控制的劳动组织。"},{"label":"成立/解散时间","value":"1933年建立，1945年纳粹德国战败后解散。"},{"label":"核心目标/宗旨","value":"消除阶级斗争和独立工会，以民族共同体名义控制劳动关系、纪律和福利。"},{"label":"关键人物（可选）","value":"罗伯特·莱伊。"},{"label":"关键行动/事件","value":"接收工会财产，组织纳粹德国“力量来自欢乐”组织等福利娱乐项目，参与劳动纪律和职业组织控制。"},{"label":"为什么重要","value":"它是纳粹社会控制的核心机构之一。工人获得某些福利和象征性尊重，但失去罢工、独立谈判和政治组织权。"},{"label":"争议/局限","value":"它声称调和阶级，实质服务国家、企业和军备经济需求。"},{"label":"出处","value":"DHM/LeMO: Deutsche Arbeitsfront；USHMM相关资料；German History Documents and Images相关资料。"}],"relationItems":["← 前因：纳粹取缔德国工会","→ 后果：纳粹德国“力量来自欢乐”组织","↔ 相关：纳粹德国四年计划"],"relations":[{"text":"← 前因：纳粹取缔德国工会","id":"extra102"},{"text":"→ 后果：纳粹德国“力量来自欢乐”组织","id":"extra104"},{"text":"↔ 相关：纳粹德国四年计划","id":"extra122"}],"source":"history","id":"extra103"},{"title":"纳粹德国“力量来自欢乐”组织","level":"C","type":"组织/机构卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1933年至1945年","place":"德国","summary":"纳粹德国“力量来自欢乐”组织通过旅游、娱乐和消费福利塑造纳粹民族共同体体验。","fields":[{"label":"标题","value":"纳粹德国“力量来自欢乐”组织"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1933年至1945年"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"纳粹德国“力量来自欢乐”组织通过旅游、娱乐和消费福利塑造纳粹民族共同体体验。"},{"label":"性质/类型","value":"纳粹德国劳工阵线下属休闲福利组织。"},{"label":"成立/解散时间","value":"1933年成立，1945年结束。"},{"label":"核心目标/宗旨","value":"组织工人休闲、旅游、体育和文化活动，以提升劳动效率和对政权认同。"},{"label":"关键人物（可选）","value":"纳粹德国劳工阵线领导层。"},{"label":"关键行动/事件","value":"组织廉价旅行、邮轮、音乐会、体育活动和大众消费项目，宣传阶级差异被民族共同体超越。"},{"label":"为什么重要","value":"它说明纳粹统治不只靠恐怖，也通过福利、娱乐和参与感制造认同。"},{"label":"争议/局限","value":"福利承诺和现实享受差异很大，组织也服务于劳动纪律和宣传目标。"},{"label":"出处","value":"DHM/LeMO: Kraft durch Freude；USHMM相关资料；German History Documents and Images相关资料。"}],"relationItems":["← 前因：纳粹德国劳工阵线","↔ 相关：纳粹宣传机器","↔ 相关：纳粹大众汽车计划"],"relations":[{"text":"← 前因：纳粹德国劳工阵线","id":"extra103"},{"text":"↔ 相关：纳粹宣传机器","id":"extra94"},{"text":"↔ 相关：纳粹大众汽车计划","id":"extra124"}],"source":"history","id":"extra104"},{"title":"纳粹达豪集中营建立","level":"A","type":"事件卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1933年3月","place":"德国巴伐利亚达豪","summary":"达豪集中营是纳粹早期集中营体系的关键起点，用来关押政治敌人并训练恐怖统治技术。","fields":[{"label":"标题","value":"纳粹达豪集中营建立"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1933年3月"},{"label":"地点","value":"德国巴伐利亚达豪"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"达豪集中营是纳粹早期集中营体系的关键起点，用来关押政治敌人并训练恐怖统治技术。"},{"label":"参与者","value":"海因里希·希姆莱、纳粹党卫队、巴伐利亚警察、共产党员、社会民主党人和其他政治犯。"},{"label":"发生了什么","value":"希特勒上台后，纳粹需要快速处理大量被捕政治对手。1933年3月，希姆莱宣布在慕尼黑附近达豪建立集中营，最初主要关押共产党人、社会民主党人和其他反纳粹者。纳粹党卫队逐步接管营地管理，发展出严厉纪律、暴力惩罚和去人格化制度。达豪后来成为纳粹党卫队集中营体系的样板，训练看守并输出管理模式。"},{"label":"为什么重要","value":"达豪说明纳粹恐怖不是战时才出现，而是在夺权初期就成为统治工具。"},{"label":"前因","value":"国会纵火法令后纳粹获得镇压政治敌人的法律外衣，党卫队和巴伐利亚纳粹政权需要固定场所关押共产党、社民党人和其他反对者。"},{"label":"后果","value":"达豪成为集中营体系的早期样板，党卫队在其中发展出恐怖统治、强迫劳动和制度化暴力的管理经验。"},{"label":"出处","value":"USHMM: Dachau；DHM/LeMO: Konzentrationslager Dachau；Encyclopaedia Britannica相关资料。"}],"relationItems":["← 前因：德国国会纵火法令","→ 后果：纳粹党卫队","→ 后果：集中营体系"],"relations":[{"text":"← 前因：德国国会纵火法令","id":"extra98"},{"text":"→ 后果：纳粹党卫队","id":"extra107"},{"text":"→ 后果：集中营体系","id":"extra861"}],"source":"history","id":"extra105"},{"title":"纳粹盖世太保","level":"A","type":"组织/机构卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1933年至1945年","place":"德国及纳粹占领区","summary":"纳粹盖世太保是纳粹秘密国家警察，负责监控、镇压和摧毁政权敌人。","fields":[{"label":"标题","value":"纳粹盖世太保"},{"label":"分级","value":"A"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1933年至1945年"},{"label":"地点","value":"德国及纳粹占领区"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"纳粹盖世太保是纳粹秘密国家警察，负责监控、镇压和摧毁政权敌人。"},{"label":"性质/类型","value":"秘密警察机构。"},{"label":"成立/解散时间","value":"1933年在普鲁士建立，后纳入全国警察和纳粹党卫队安全体系，1945年解散。"},{"label":"核心目标/宗旨","value":"发现并镇压政治反对者、犹太人、抵抗者和被政权定义为敌人的群体。"},{"label":"关键人物（可选）","value":"戈林早期创建普鲁士纳粹盖世太保，希姆莱和海德里希后来整合警察权力。"},{"label":"关键行动/事件","value":"监控社会、审讯、保护性拘押、配合集中营和驱逐系统。"},{"label":"为什么重要","value":"纳粹盖世太保把国家警察、恐怖和意识形态敌人概念结合起来，是纳粹统治日常恐惧的核心机构。"},{"label":"争议/局限","value":"纳粹盖世太保人员规模并非无限大，其效率也依赖普通民众告密和地方机构配合。"},{"label":"出处","value":"USHMM: Gestapo；DHM/LeMO: Gestapo；Encyclopaedia Britannica: Gestapo。"}],"relationItems":["← 前因：德国国会纵火法令","↔ 相关：纳粹党卫队","↔ 相关：纳粹达豪集中营建立"],"relations":[{"text":"← 前因：德国国会纵火法令","id":"extra98"},{"text":"↔ 相关：纳粹党卫队","id":"extra107"},{"text":"↔ 相关：纳粹达豪集中营建立","id":"extra105"}],"source":"history","id":"extra106"},{"title":"纳粹党卫队","level":"A","type":"组织/机构卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1925年成立，1930年代成为纳粹核心权力组织","place":"德国及纳粹占领区","summary":"纳粹党卫队从希特勒护卫队发展为纳粹种族国家、警察恐怖和灭绝政策的核心执行组织。","fields":[{"label":"标题","value":"纳粹党卫队"},{"label":"分级","value":"A"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1925年成立，1930年代成为纳粹核心权力组织"},{"label":"地点","value":"德国及纳粹占领区"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"纳粹党卫队从希特勒护卫队发展为纳粹种族国家、警察恐怖和灭绝政策的核心执行组织。"},{"label":"性质/类型","value":"纳粹党准军事和安全组织。"},{"label":"成立/解散时间","value":"1925年成立，1945年随纳粹德国战败被取缔。"},{"label":"核心目标/宗旨","value":"维护希特勒和纳粹政权安全，执行意识形态、警察、集中营和种族政策。"},{"label":"关键人物（可选）","value":"海因里希·希姆莱、莱因哈德·海德里希。"},{"label":"关键行动/事件","value":"接管集中营体系，整合安全警察，参与纳粹长刀之夜，执行占领区屠杀和纳粹犹太人大屠杀。"},{"label":"为什么重要","value":"纳粹党卫队是纳粹国家最关键的暴力机器之一，连接党、警察、种族政策和战争犯罪。"},{"label":"争议/局限","value":"纳粹党卫队内部有普通纳粹党卫队、武装纳粹党卫队、安全机构等不同部分，但共同服务纳粹种族和权力目标。"},{"label":"出处","value":"USHMM: SS；DHM/LeMO: SS；Encyclopaedia Britannica: Schutzstaffel。"}],"relationItems":["← 前因：纳粹冲锋队","→ 后果：纳粹长刀之夜","→ 后果：集中营体系","↔ 相关：纳粹盖世太保"],"relations":[{"text":"← 前因：纳粹冲锋队","id":"extra93"},{"text":"→ 后果：纳粹长刀之夜","id":"extra108"},{"text":"→ 后果：集中营体系","id":"extra861"},{"text":"↔ 相关：纳粹盖世太保","id":"extra106"}],"source":"history","id":"extra107"},{"title":"纳粹长刀之夜","level":"B","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1934年6月30日至7月2日","place":"德国","summary":"纳粹长刀之夜中希特勒清洗冲锋队领导层和其他敌人，换取军方支持并巩固个人独裁。","fields":[{"label":"标题","value":"纳粹长刀之夜"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1934年6月30日至7月2日"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"纳粹长刀之夜中希特勒清洗冲锋队领导层和其他敌人，换取军方支持并巩固个人独裁。"},{"label":"参与者","value":"希特勒、纳粹党卫队、纳粹盖世太保、恩斯特·罗姆、冲锋队领导层、保守派目标人物。"},{"label":"发生了什么","value":"纳粹上台后，冲锋队规模庞大且罗姆提出改造军队和继续“革命”的要求，引发军方和保守精英恐惧。希特勒为争取国防军支持，决定清洗冲锋队领导层。1934年6月底，纳粹党卫队和警察逮捕并处决罗姆及多名冲锋队高层，同时杀害施莱歇尔等其他政治敌人。政权随后以法律追认杀戮为“国家自卫”。军方接受清洗结果，并在兴登堡去世后向希特勒个人宣誓。"},{"label":"为什么重要","value":"它解决纳粹内部暴力权力冲突，使纳粹党卫队崛起并让军方接受希特勒最高统治。"},{"label":"前因","value":"冲锋队要求继续“第二次革命”并威胁军队和保守精英利益，希特勒需要在总统兴登堡去世前争取军方支持并清除党内竞争者。"},{"label":"后果","value":"冲锋队被削弱，党卫队地位上升，军方随后向希特勒个人宣誓，纳粹政权从联盟独裁进一步转向元首独裁。"},{"label":"出处","value":"USHMM: Night of the Long Knives；DHM/LeMO: Röhm-Putsch；Encyclopaedia Britannica相关资料。"}],"relationItems":["← 前因：罗姆与纳粹冲锋队激进化","← 前因：纳粹党卫队","→ 后果：德国国防军向希特勒宣誓"],"relations":[{"text":"← 前因：罗姆与纳粹冲锋队激进化","id":"extra95"},{"text":"← 前因：纳粹党卫队","id":"extra107"},{"text":"→ 后果：德国国防军向希特勒宣誓","id":"extra109"}],"source":"history","id":"extra108"},{"title":"德国国防军向希特勒宣誓","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1934年8月","place":"德国","summary":"兴登堡死后，国防军向希特勒个人宣誓，把军队忠诚从宪法国家转向元首个人。","fields":[{"label":"标题","value":"德国国防军向希特勒宣誓"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1934年8月"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"兴登堡死后，国防军向希特勒个人宣誓，把军队忠诚从宪法国家转向元首个人。"},{"label":"参与者","value":"希特勒、德国国防军、军官团、德国士兵。"},{"label":"发生了什么","value":"1934年8月兴登堡去世后，希特勒把总统和总理职位合并为元首兼总理。德国军队随即采用新的誓词，要求官兵向希特勒个人无条件忠诚，而非向宪法或国家机构宣誓。纳粹长刀之夜刚刚清除了冲锋队对军方的威胁，军官团接受这种安排。个人誓言在后来的战争和政变问题上形成强烈约束，许多军官把反抗希特勒视为违背誓言。"},{"label":"为什么重要","value":"它是纳粹党国与军队关系的关键节点，使希特勒获得直接控制军队的象征和伦理工具。"},{"label":"前因","value":"长刀之夜后希特勒消除了冲锋队对军方的直接威胁，兴登堡去世又使总统和总理权力合并成为可能。"},{"label":"后果","value":"军队忠诚从宪法和国家转向希特勒个人，为再武装和二战中军事服从结构提供了关键政治基础。"},{"label":"出处","value":"DHM/LeMO: Vereidigung der Reichswehr；USHMM相关资料；German History Documents and Images相关资料。"}],"relationItems":["← 前因：纳粹长刀之夜","→ 后果：纳粹德国再武装"],"relations":[{"text":"← 前因：纳粹长刀之夜","id":"extra108"},{"text":"→ 后果：纳粹德国再武装","id":"extra119"}],"source":"history","id":"extra109"},{"title":"纳粹元首国家","level":"A","type":"概念/思潮卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1934年后制度化","place":"德国","summary":"纳粹元首国家把国家、党和社会权力集中到希特勒个人权威之下，是纳粹统治的核心结构。","fields":[{"label":"标题","value":"纳粹元首国家"},{"label":"分级","value":"A"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1934年后制度化"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"纳粹元首国家把国家、党和社会权力集中到希特勒个人权威之下，是纳粹统治的核心结构。"},{"label":"核心主张/思路","value":"领袖意志高于法律、议会和制度，官僚、党组织和社会都应“向元首工作”。"},{"label":"提出者/代表人物（可选）","value":"希特勒和纳粹法学、宣传体系共同塑造。"},{"label":"它从何而来","value":"纳粹德国授权法、纳粹一体化政策、纳粹长刀之夜、兴登堡去世和军队宣誓共同形成。"},{"label":"典型表现","value":"总统和总理合并，个人宣誓，领袖崇拜，法律服从政治意志，多机构竞争取悦希特勒。"},{"label":"为什么重要","value":"纳粹元首国家解释纳粹统治为何既高度个人化又行政混乱：权力中心是希特勒意志，机构之间通过竞争执行和放大其目标。"},{"label":"争议/局限","value":"希特勒并非亲自处理所有事务，许多政策来自下级机构“向元首工作”的主动激进化。"},{"label":"出处","value":"DHM/LeMO: Führerstaat；USHMM相关资料；Ian Kershaw相关研究。"}],"relationItems":["← 前因：纳粹德国授权法","← 前因：德国国防军向希特勒宣誓","→ 后果：纳粹战争决策","↔ 相关：纳粹宣传机器"],"relations":[{"text":"← 前因：纳粹德国授权法","id":"extra99"},{"text":"← 前因：德国国防军向希特勒宣誓","id":"extra109"},{"text":"↔ 相关：纳粹宣传机器","id":"extra94"}],"source":"history","id":"extra110"},{"title":"纳粹1933年抵制犹太商店","level":"B","type":"事件卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1933年4月1日","place":"德国","summary":"纳粹1933年抵制犹太商店是纳粹掌权后首次全国性反犹行动，标志国家支持的排犹政策公开化。","fields":[{"label":"标题","value":"纳粹1933年抵制犹太商店"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1933年4月1日"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"纳粹1933年抵制犹太商店是纳粹掌权后首次全国性反犹行动，标志国家支持的排犹政策公开化。"},{"label":"参与者","value":"纳粹党、冲锋队、犹太商人、德国消费者和公众。"},{"label":"发生了什么","value":"纳粹声称国外批评德国迫害犹太人是“反德宣传”，决定组织全国性抵制。1933年4月1日，冲锋队成员站在犹太商店、医生和律师事务所门口，涂写标语，阻止顾客进入。行动在部分地区执行不一，且因国际反应和经济顾虑只持续一天，但它向社会传递明确信号：犹太人将被国家和党公开排斥。此后排犹政策转向公务员清洗、职业限制和法律剥夺。"},{"label":"为什么重要","value":"它是纳粹反犹从宣传暴力走向国家政策的早期公开节点。"},{"label":"前因","value":"纳粹上台后需要把长期反犹主义转化为国家支持的公共行动，同时回应党内激进分子对犹太人和政治敌人的暴力压力。"},{"label":"后果","value":"抵制行动开启纳粹国家反犹政策的公开阶段，随后职业公务员法和纽伦堡法把歧视进一步制度化。"},{"label":"出处","value":"USHMM: Boycott of Jewish Businesses；DHM/LeMO: Judenboykott；German History Documents and Images相关资料。"}],"relationItems":["← 前因：反犹主义政治运动","→ 后果：纳粹德国职业公务员法","→ 后果：纳粹纽伦堡法"],"relations":[{"text":"← 前因：反犹主义政治运动","id":"extra686"},{"text":"→ 后果：纳粹德国职业公务员法","id":"extra112"},{"text":"→ 后果：纳粹纽伦堡法","id":"extra114"}],"source":"history","id":"extra111"},{"title":"纳粹德国职业公务员法","level":"B","type":"制度/文本卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1933年4月7日","place":"德国","summary":"纳粹德国职业公务员法以“雅利安条款”等规定清洗犹太人和政治异见者，是纳粹种族国家制度化的早期法律。","fields":[{"label":"标题","value":"纳粹德国职业公务员法"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1933年4月7日"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"纳粹德国职业公务员法以“雅利安条款”等规定清洗犹太人和政治异见者，是纳粹种族国家制度化的早期法律。"},{"label":"制定方/签署方","value":"希特勒政府。"},{"label":"主要内容","value":"允许将政治上“不可靠”者和所谓非雅利安人排除出公务员队伍，并影响大学、司法和公共机构。"},{"label":"它试图解决什么问题","value":"纳粹要清除国家机关中的反对者和犹太人，使官僚体系服从新政权和种族原则。"},{"label":"为什么重要","value":"它把反犹主义和政治清洗写入国家人事制度，标志排犹从街头行动转入法律和行政程序。"},{"label":"争议/局限","value":"法律包含一些早期例外，如一战前线老兵等，但这些限制后来被逐步取消或绕过。"},{"label":"造成的影响","value":"犹太公务员、教授、法官和专业人士被排挤；学术和司法系统迅速纳粹化。"},{"label":"出处","value":"USHMM: Law for the Restoration of the Professional Civil Service；DHM/LeMO: Berufsbeamtengesetz；German History Documents and Images文本。"}],"relationItems":["← 前因：纳粹1933年抵制犹太商店","← 前因：纳粹一体化政策","→ 后果：纳粹纽伦堡法"],"relations":[{"text":"← 前因：纳粹1933年抵制犹太商店","id":"extra111"},{"text":"← 前因：纳粹一体化政策","id":"extra100"},{"text":"→ 后果：纳粹纽伦堡法","id":"extra114"}],"source":"history","id":"extra112"},{"title":"纳粹文化控制","level":"B","type":"概念/思潮卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1933年至1945年","place":"德国及占领区","summary":"纳粹文化控制通过审查、组织、展览和宣传定义“德国文化”，清除现代主义、犹太和左翼文化。","fields":[{"label":"标题","value":"纳粹文化控制"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1933年至1945年"},{"label":"地点","value":"德国及占领区"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"纳粹文化控制通过审查、组织、展览和宣传定义“德国文化”，清除现代主义、犹太和左翼文化。"},{"label":"核心主张/思路","value":"艺术和文化必须服务民族共同体、种族意识和领袖国家，不能保持自治。"},{"label":"提出者/代表人物（可选）","value":"戈培尔和宣传部，帝国文化院体系。"},{"label":"它从何而来","value":"纳粹一体化政策和纳粹意识形态需要把文学、电影、音乐、美术、新闻和广播纳入政治控制。"},{"label":"典型表现","value":"焚书、帝国文化院、禁演禁书、清洗犹太和左翼艺术家、“堕落艺术”展。"},{"label":"为什么重要","value":"纳粹统治不只是压制政治反对派，也重塑可见、可听、可阅读的文化世界。"},{"label":"争议/局限","value":"文化控制强大但并非没有缝隙，娱乐、商业和宣传之间仍存在张力。"},{"label":"出处","value":"USHMM: Nazi Propaganda and Censorship；DHM/LeMO: Kultur im Nationalsozialismus；German History Documents and Images相关资料。"}],"relationItems":["← 前因：纳粹德国焚书运动","← 前因：约瑟夫·戈培尔","→ 后果：纳粹德国“退化艺术”展","↔ 相关：德国包豪斯"],"relations":[{"text":"← 前因：纳粹德国焚书运动","id":"extra284"},{"text":"← 前因：约瑟夫·戈培尔","id":"card49"},{"text":"→ 后果：纳粹德国“退化艺术”展","id":"extra126"},{"text":"↔ 相关：德国包豪斯","id":"card30"}],"source":"history","id":"extra113"},{"title":"纳粹纽伦堡法","level":"A","type":"制度/文本卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1935年9月15日","place":"德国纽伦堡党代会","summary":"纳粹纽伦堡法用种族法律剥夺犹太人的公民权和婚姻权，是纳粹反犹政策制度化的核心节点。","fields":[{"label":"标题","value":"纳粹纽伦堡法"},{"label":"分级","value":"A"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1935年9月15日"},{"label":"地点","value":"德国纽伦堡党代会"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"纳粹纽伦堡法用种族法律剥夺犹太人的公民权和婚姻权，是纳粹反犹政策制度化的核心节点。"},{"label":"制定方/签署方","value":"纳粹德国政府和国会。"},{"label":"主要内容","value":"包括《帝国公民法》和《保护德意志血统与荣誉法》，区分“帝国公民”和国家属民，禁止犹太人与“德意志或相关血统”者通婚和性关系。"},{"label":"它试图解决什么问题","value":"纳粹试图用法律定义谁属于民族共同体，并把犹太人排除在公民和社会生活之外。"},{"label":"为什么重要","value":"纳粹纽伦堡法将反犹主义从暴力和行政排斥推进为系统种族法，为后续剥夺、隔离、驱逐和灭绝铺路。"},{"label":"争议/局限","value":"法律中的分类标准需要大量补充规定，显示种族身份并非自然事实，而是国家暴力制造的行政分类。"},{"label":"造成的影响","value":"犹太人失去完整公民权；社会排斥合法化；1938年后迫害进一步升级。"},{"label":"出处","value":"USHMM: Nuremberg Laws；DHM/LeMO: Nürnberger Gesetze；German History Documents and Images文本。"}],"relationItems":["← 前因：纳粹德国职业公务员法","← 前因：纳粹1933年抵制犹太商店","→ 后果：纳粹德国水晶之夜","→ 后果：纳粹犹太人大屠杀"],"relations":[{"text":"← 前因：纳粹德国职业公务员法","id":"extra112"},{"text":"← 前因：纳粹1933年抵制犹太商店","id":"extra111"},{"text":"→ 后果：纳粹德国水晶之夜","id":"extra173"},{"text":"→ 后果：纳粹犹太人大屠杀","id":"extra218"}],"source":"history","id":"extra114"},{"title":"纳粹希特勒青年团","level":"B","type":"组织/机构卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1920年代形成，1936年后成为国家青年组织核心","place":"德国","summary":"纳粹希特勒青年团把德国男孩纳入纳粹意识形态、纪律和准军事训练，是塑造下一代的核心工具。","fields":[{"label":"标题","value":"纳粹希特勒青年团"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1920年代形成，1936年后成为国家青年组织核心"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"纳粹希特勒青年团把德国男孩纳入纳粹意识形态、纪律和准军事训练，是塑造下一代的核心工具。"},{"label":"性质/类型","value":"纳粹青年组织。"},{"label":"成立/解散时间","value":"1920年代形成，1933年后迅速扩张，1936年后制度地位强化，1945年解散。"},{"label":"核心目标/宗旨","value":"用民族主义、种族主义、服从、体能训练和军事准备塑造青少年。"},{"label":"关键人物（可选）","value":"巴尔杜尔·冯·席拉赫等。"},{"label":"关键行动/事件","value":"吸收和取代其他青年组织，组织营地、游行、训练和政治教育。"},{"label":"为什么重要","value":"它说明纳粹统治目标不只是控制成年人政治行为，也要从少年阶段重塑身份和忠诚。"},{"label":"争议/局限","value":"参与既有强制和压力，也有娱乐、集体归属和社会上升吸引力。"},{"label":"出处","value":"USHMM: Hitler Youth；DHM/LeMO: Hitlerjugend；Encyclopaedia Britannica相关资料。"}],"relationItems":["← 前因：德国青年运动","→ 后果：纳粹教育控制","↔ 相关：纳粹德国少女联盟"],"relations":[{"text":"← 前因：德国青年运动","id":"extra685"},{"text":"↔ 相关：纳粹德国少女联盟","id":"extra116"}],"source":"history","id":"extra115"},{"title":"纳粹德国少女联盟","level":"B","type":"组织/机构卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1930年代至1945年","place":"德国","summary":"纳粹德国少女联盟把女孩纳入纳粹性别教育，强调身体、母职、民族共同体和服从。","fields":[{"label":"标题","value":"纳粹德国少女联盟"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1930年代至1945年"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"纳粹德国少女联盟把女孩纳入纳粹性别教育，强调身体、母职、民族共同体和服从。"},{"label":"性质/类型","value":"纳粹女性青少年组织，纳粹希特勒青年团体系的一部分。"},{"label":"成立/解散时间","value":"1930年代扩张，1945年解散。"},{"label":"核心目标/宗旨","value":"培养符合纳粹性别秩序的“民族母亲”和忠诚女性成员。"},{"label":"关键人物（可选）","value":"纳粹青年领导层和女性组织干部。"},{"label":"关键行动/事件","value":"组织体育、营地、家政、意识形态教育和集体活动。"},{"label":"为什么重要","value":"它显示纳粹青年政策有明确性别分工：男孩被训练为战士，女孩被塑造成母亲和民族共同体再生产者。"},{"label":"争议/局限","value":"组织也给一些女孩提供公共活动和同伴空间，但这些活动受严格意识形态框架限制。"},{"label":"出处","value":"USHMM: League of German Girls；DHM/LeMO: Bund Deutscher Mädel；German History Documents and Images相关资料。"}],"relationItems":["← 前因：纳粹希特勒青年团","↔ 相关：德国妇女运动","↔ 相关：纳粹家庭政策"],"relations":[{"text":"← 前因：纳粹希特勒青年团","id":"extra115"},{"text":"↔ 相关：德国妇女运动","id":"extra684"},{"text":"↔ 相关：纳粹家庭政策","id":"extra117"}],"source":"history","id":"extra116"},{"title":"纳粹家庭政策","level":"B","type":"概念/思潮卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"1933年至1945年","place":"德国","summary":"纳粹家庭政策把女性、婚姻和生育纳入种族国家目标，鼓励“合格”德国家庭生育并排除被视为“不合格”的人。","fields":[{"label":"标题","value":"纳粹家庭政策"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1933年至1945年"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"纳粹家庭政策把女性、婚姻和生育纳入种族国家目标，鼓励“合格”德国家庭生育并排除被视为“不合格”的人。"},{"label":"核心主张/思路","value":"家庭不是私人领域，而是民族共同体和种族政策的基础单位。"},{"label":"提出者/代表人物（可选）","value":"纳粹党、妇女组织、卫生和种族政策机构。"},{"label":"它从何而来","value":"纳粹种族主义、反女权、人口政策和对一战后社会变化的保守反弹。"},{"label":"典型表现","value":"母亲十字勋章、婚姻贷款、限制女性职业发展、宣传“三K”角色，同时推行强制绝育和排除政策。"},{"label":"为什么重要","value":"它说明纳粹社会政策同时包含福利诱导和生物政治暴力。"},{"label":"争议/局限","value":"现实中军备经济又需要女性劳动，政策宣传和经济需求存在矛盾。"},{"label":"出处","value":"USHMM: Women in Nazi Germany；DHM/LeMO: Frauen im NS-Staat；German History Documents and Images相关资料。"}],"relationItems":["← 前因：纳粹德国少女联盟","→ 后果：纳粹优生政策","↔ 相关：纳粹纽伦堡法"],"relations":[{"text":"← 前因：纳粹德国少女联盟","id":"extra116"},{"text":"→ 后果：纳粹优生政策","id":"extra118"},{"text":"↔ 相关：纳粹纽伦堡法","id":"extra114"}],"source":"history","id":"extra117"},{"title":"纳粹优生政策","level":"B","type":"制度/文本卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1933年后制度化","place":"德国","summary":"纳粹优生政策用国家暴力定义“遗传健康”，通过强制绝育和医学分类排除被视为“不合格”的人。","fields":[{"label":"标题","value":"纳粹优生政策"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1933年后制度化"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"纳粹优生政策用国家暴力定义“遗传健康”，通过强制绝育和医学分类排除被视为“不合格”的人。"},{"label":"制定方/签署方","value":"纳粹德国政府和卫生、司法机构。"},{"label":"主要内容","value":"1933年《遗传病后代预防法》允许强制绝育被诊断为特定遗传疾病者，建立遗传健康法院。"},{"label":"它试图解决什么问题","value":"纳粹以种族卫生名义试图“改善”民族身体，减少被视为负担或威胁的人口。"},{"label":"为什么重要","value":"优生政策是纳粹种族国家的核心，不只针对犹太人，也针对残疾人、精神病患者和其他被污名化群体。"},{"label":"争议/局限","value":"所谓科学分类建立在伪科学、偏见和国家暴力之上，严重侵犯身体自主和生命权。"},{"label":"造成的影响","value":"数十万人遭强制绝育；为后来的“T4行动”和灭绝政策提供制度与人员经验。"},{"label":"出处","value":"USHMM: Forced Sterilization；DHM/LeMO: Erbgesundheitsgesetz；German History Documents and Images相关资料。"}],"relationItems":["← 前因：纳粹家庭政策","→ 后果：纳粹T4行动","↔ 相关：纳粹纽伦堡法"],"relations":[{"text":"← 前因：纳粹家庭政策","id":"extra117"},{"text":"→ 后果：纳粹T4行动","id":"extra128"},{"text":"↔ 相关：纳粹纽伦堡法","id":"extra114"}],"source":"history","id":"extra118"},{"title":"纳粹德国再武装","level":"A","type":"事件卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1935年公开化，此前已秘密推进","place":"德国","summary":"纳粹德国再武装公开突破凡尔赛裁军限制，标志纳粹外交从隐蔽修约走向公开挑战战后秩序。","fields":[{"label":"标题","value":"纳粹德国再武装"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1935年公开化，此前已秘密推进"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国、法国、英国"},{"label":"一句话概括","value":"纳粹德国再武装公开突破凡尔赛裁军限制，标志纳粹外交从隐蔽修约走向公开挑战战后秩序。"},{"label":"参与者","value":"希特勒政府、国防军、英法政府、一战后国际联盟。"},{"label":"发生了什么","value":"魏玛时期德国已通过秘密合作和规避方式保留部分军事能力。纳粹上台后加速军备扩张，1935年公开宣布恢复征兵并建立空军，将国防军扩编为更大规模军队。英法抗议但缺乏有效制裁，英国随后同德国签订海军协定，在事实上承认德国部分扩军。再武装同时刺激军工生产和就业，强化纳粹政权声望。"},{"label":"为什么重要","value":"它是凡尔赛体系被公开拆解的关键步骤，也为1936年莱茵兰、1938年奥地利和二战做军事准备。"},{"label":"前因","value":"纳粹政权把凡尔赛军备限制视为民族屈辱，军队宣誓和经济动员又给希特勒突破限制提供了政治与组织条件。"},{"label":"后果","value":"德国公开扩军改变欧洲力量平衡，英德海军协定、莱茵兰再军事化和四年计划相继把德国推向战争准备。"},{"label":"出处","value":"DHM/LeMO: Wiederaufrüstung；USHMM相关资料；Encyclopaedia Britannica: Nazi Germany。"}],"relationItems":["← 前因：德国国防军向希特勒宣誓","→ 后果：德国莱茵兰再军事化","→ 后果：纳粹德国四年计划"],"relations":[{"text":"← 前因：德国国防军向希特勒宣誓","id":"extra109"},{"text":"→ 后果：德国莱茵兰再军事化","id":"extra121"},{"text":"→ 后果：纳粹德国四年计划","id":"extra122"}],"source":"history","id":"extra119"},{"title":"纳粹德国《英德海军协定》","level":"B","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1935年6月18日","place":"英国与德国外交关系","summary":"英德海军协定允许德国海军扩张到英国海军一定比例，削弱凡尔赛限制和英法共同阵线。","fields":[{"label":"标题","value":"纳粹德国《英德海军协定》"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1935年6月18日"},{"label":"地点","value":"英国与德国外交关系"},{"label":"主要国家","value":"英国、德国、法国"},{"label":"一句话概括","value":"英德海军协定允许德国海军扩张到英国海军一定比例，削弱凡尔赛限制和英法共同阵线。"},{"label":"制定方/签署方","value":"英国政府和纳粹德国政府。"},{"label":"主要内容","value":"英国同意德国海军总吨位可达到英国皇家海军的35%，潜艇方面也有相关安排。"},{"label":"它试图解决什么问题","value":"英国希望通过双边协议限制德国海军扩张，并避免重演失控海军竞赛。德国则希望获得对其再武装的国际承认。"},{"label":"为什么重要","value":"该协定在没有法国和意大利充分参与的情况下修改凡尔赛限制，鼓励希特勒相信西方愿意让步。"},{"label":"争议/局限","value":"英国认为这是现实主义管控，法国则视其为破坏集体对德政策。"},{"label":"造成的影响","value":"纳粹德国再武装获得外交突破；战后集体安全进一步受损。"},{"label":"出处","value":"DHM/LeMO: Deutsch-Britisches Flottenabkommen；Office of the Historian相关资料；Encyclopaedia Britannica相关资料。"}],"relationItems":["← 前因：纳粹德国再武装","→ 后果：德国莱茵兰再军事化","↔ 相关：德意志帝国英德海军竞赛"],"relations":[{"text":"← 前因：纳粹德国再武装","id":"extra119"},{"text":"→ 后果：德国莱茵兰再军事化","id":"extra121"},{"text":"↔ 相关：德意志帝国英德海军竞赛","id":"extra637"}],"source":"history","id":"extra120"},{"title":"德国莱茵兰再军事化","level":"A","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1936年3月7日","place":"德国莱茵兰","summary":"德国莱茵兰再军事化公开违反凡尔赛和洛迦诺安排，因英法未军事回应而成为希特勒外交冒险成功案例。","fields":[{"label":"标题","value":"德国莱茵兰再军事化"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1936年3月7日"},{"label":"地点","value":"德国莱茵兰"},{"label":"主要国家","value":"德国、法国、英国"},{"label":"一句话概括","value":"德国莱茵兰再军事化公开违反凡尔赛和洛迦诺安排，因英法未军事回应而成为希特勒外交冒险成功案例。"},{"label":"参与者","value":"希特勒政府、德国军队、法国政府、英国政府。"},{"label":"发生了什么","value":"1936年3月，希特勒命令德军进入按条约应保持非军事化的莱茵兰。德军兵力有限，德国将领担心法国若出兵即需撤退。但法国国内政治不稳且不愿单独行动，英国倾向把德国行动视为进入“自家后院”。英法没有采取军事反制，德国成功改变现状。希特勒因此获得巨大国内声望，也更相信西方缺乏阻止其扩张的意志。"},{"label":"为什么重要","value":"这是战间期绥靖和纳粹冒险外交的关键节点，改变法国安全环境并削弱洛迦诺体系。"},{"label":"前因","value":"纳粹德国再武装后，希特勒试探凡尔赛和洛迦诺体系的执行意志，英法国内政治和绥靖倾向降低了军事回应可能。"},{"label":"后果","value":"德国在不战而胜中获得巨大威望和战略纵深，希特勒对外交冒险更有信心，欧洲集体安全体系进一步瓦解。"},{"label":"出处","value":"DHM/LeMO: Rheinlandbesetzung 1936；USHMM相关资料；Encyclopaedia Britannica: Rhineland occupation。"}],"relationItems":["← 前因：纳粹德国再武装","← 前因：欧洲《洛迦诺公约》","→ 后果：罗马-柏林轴心","→ 后果：奥地利合并"],"relations":[{"text":"← 前因：纳粹德国再武装","id":"extra119"},{"text":"← 前因：欧洲《洛迦诺公约》","id":"card20"}],"source":"history","id":"extra121"},{"title":"纳粹德国四年计划","level":"A","type":"制度/文本卡","tags":["经济与社会","战争与外交"],"mainTag":"经济与社会","subTag":"战争与外交","timeText":"1936年启动","place":"德国","summary":"纳粹德国四年计划要求德国在四年内实现战争经济准备和原料自给，标志纳粹经济全面转向备战。","fields":[{"label":"标题","value":"纳粹德国四年计划"},{"label":"分级","value":"A"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1936年启动"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"纳粹德国四年计划要求德国在四年内实现战争经济准备和原料自给，标志纳粹经济全面转向备战。"},{"label":"制定方/签署方","value":"希特勒提出，戈林负责执行。"},{"label":"主要内容","value":"扩大军备生产，发展合成燃料和合成橡胶，控制外汇和进口，推动自给自足和战争准备。"},{"label":"它试图解决什么问题","value":"纳粹担心德国在未来战争中再次遭封锁和原料短缺，需要在军事、工业和资源上提前准备。"},{"label":"为什么重要","value":"纳粹德国四年计划把经济增长、就业和国家干预纳入战争目标，说明纳粹复苏不是普通经济恢复，而是军备驱动。"},{"label":"争议/局限","value":"自给目标成本高、效率低，德国仍依赖部分进口和占领掠夺来支撑战争经济。"},{"label":"造成的影响","value":"戈林权力上升；军备经济加速；对劳动力、原料和外汇控制加强。"},{"label":"出处","value":"DHM/LeMO: Vierjahresplan；Encyclopaedia Britannica: Four-Year Plan；German History Documents and Images相关资料。"}],"relationItems":["← 前因：纳粹德国再武装","→ 后果：纳粹德国战争经济","↔ 相关：纳粹德国劳工阵线"],"relations":[{"text":"← 前因：纳粹德国再武装","id":"extra119"},{"text":"→ 后果：纳粹德国战争经济","id":"extra864"},{"text":"↔ 相关：纳粹德国劳工阵线","id":"extra103"}],"source":"history","id":"extra122"},{"title":"纳粹高速公路宣传","level":"C","type":"概念/思潮卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"1933年后","place":"德国","summary":"纳粹把高速公路建设包装为就业、现代性和民族共同体象征，实际经济效果常被宣传夸大。","fields":[{"label":"标题","value":"纳粹高速公路宣传"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1933年后"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"纳粹把高速公路建设包装为就业、现代性和民族共同体象征，实际经济效果常被宣传夸大。"},{"label":"核心主张/思路","value":"道路建设被塑造成元首带来就业、技术和国家统一的可见成果。"},{"label":"提出者/代表人物（可选）","value":"希特勒政府、宣传部和道路建设机构。"},{"label":"它从何而来","value":"魏玛已有高速道路规划，纳粹上台后将其重新包装为政权工程。"},{"label":"典型表现","value":"开工仪式、劳动者形象、摄影和新闻报道、汽车化未来想象。"},{"label":"为什么重要","value":"它说明纳粹经济合法性很大程度上依赖可视化工程和宣传，而不是单纯经济数据。"},{"label":"争议/局限","value":"高速公路提供的就业数量有限，军事用途也常被后世简化；其宣传价值大于直接经济效果。"},{"label":"出处","value":"DHM/LeMO: Autobahnbau；German History Documents and Images相关资料；相关经济史研究。"}],"relationItems":["← 前因：纳粹宣传机器","↔ 相关：纳粹德国四年计划","↔ 相关：纳粹大众汽车计划"],"relations":[{"text":"← 前因：纳粹宣传机器","id":"extra94"},{"text":"↔ 相关：纳粹德国四年计划","id":"extra122"},{"text":"↔ 相关：纳粹大众汽车计划","id":"extra124"}],"source":"history","id":"extra123"},{"title":"纳粹大众汽车计划","level":"C","type":"事件卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"1930年代后期","place":"德国","summary":"纳粹大众汽车计划承诺让普通德国人拥有汽车，实际更多服务于纳粹消费乌托邦和工业动员宣传。","fields":[{"label":"标题","value":"纳粹大众汽车计划"},{"label":"分级","value":"C"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1930年代后期"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"纳粹大众汽车计划承诺让普通德国人拥有汽车，实际更多服务于纳粹消费乌托邦和工业动员宣传。"},{"label":"参与者","value":"希特勒政府、纳粹德国劳工阵线、纳粹德国“力量来自欢乐”组织、费迪南德·保时捷、德国储户。"},{"label":"发生了什么","value":"纳粹政权宣称要制造价格低廉的“人民汽车”，由劳工阵线和纳粹德国“力量来自欢乐”组织储蓄计划，吸引民众分期缴款。政府建设相关工厂并宣传汽车化未来，把汽车消费同民族共同体和现代生活联系起来。战争爆发后，民用汽车承诺基本落空，工厂转向军需生产，许多储户没有得到汽车。"},{"label":"为什么重要","value":"它显示纳粹统治通过未来消费承诺争取群众认同，同时把工业项目导向战争经济。"},{"label":"前因","value":"纳粹宣传希望用大众消费承诺证明民族共同体能改善普通人生活，汽车工业和高速公路工程也适合展示技术现代性。"},{"label":"后果","value":"计划在战前没有真正实现大规模民用交付，却为战时汽车工业和战后大众汽车企业留下制度与生产基础。"},{"label":"出处","value":"DHM/LeMO: Volkswagen/KdF-Wagen；Volkswagen history资料；German History Documents and Images相关资料。"}],"relationItems":["← 前因：纳粹德国“力量来自欢乐”组织","↔ 相关：纳粹高速公路宣传","↔ 相关：纳粹德国四年计划"],"relations":[{"text":"← 前因：纳粹德国“力量来自欢乐”组织","id":"extra104"},{"text":"↔ 相关：纳粹高速公路宣传","id":"extra123"},{"text":"↔ 相关：纳粹德国四年计划","id":"extra122"}],"source":"history","id":"extra124"},{"title":"纳粹德国帝国文化院","level":"B","type":"组织/机构卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1933年成立","place":"纳粹德国","summary":"纳粹德国帝国文化院把文学、音乐、电影、戏剧、美术、广播和新闻纳入国家审查与职业准入体系。","fields":[{"label":"标题","value":"纳粹德国帝国文化院"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1933年成立"},{"label":"地点","value":"纳粹德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"纳粹德国帝国文化院把文学、音乐、电影、戏剧、美术、广播和新闻纳入国家审查与职业准入体系。"},{"label":"性质/类型","value":"国家文化管制机构。"},{"label":"成立/解散时间","value":"1933年成立；1945年纳粹德国覆灭后结束。"},{"label":"核心目标/宗旨","value":"通过会员资格、职业许可和审查制度控制文化生产，排除犹太人、左翼人士和被视为“不可靠”的艺术家。"},{"label":"关键人物（可选）","value":"约瑟夫·戈培尔。"},{"label":"关键行动/事件","value":"设置电影、音乐、文学、广播、新闻、戏剧和美术等分院，控制艺术家职业资格。"},{"label":"为什么重要","value":"它把纳粹文化控制从暴力事件制度化，说明独裁政权如何通过行业准入改变文化生态。"},{"label":"争议/局限","value":"该机构宣传“民族文化”，实际造成审查、流亡、沉默和文化贫困。"},{"label":"出处","value":"United States Holocaust Memorial Museum，Nazi culture and censorship materials；German History in Documents and Images，Reich Chamber of Culture materials。"}],"relationItems":["← 前因：纳粹文化控制","← 前因：纳粹德国焚书运动","→ 后果：纳粹德国“退化艺术”展","→ 后果：纳粹宣传机器","↔ 相关：约瑟夫·戈培尔","↔ 相关：德国乌发电影公司","✗ 对立/冲突：现代主义艺术","✗ 对立/冲突：纳粹文化控制","↔ 同时期参考：纳粹取缔德国工会"],"relations":[{"text":"← 前因：纳粹文化控制","id":"extra113"},{"text":"← 前因：纳粹德国焚书运动","id":"extra284"},{"text":"→ 后果：纳粹德国“退化艺术”展","id":"extra126"},{"text":"→ 后果：纳粹宣传机器","id":"extra94"},{"text":"↔ 相关：约瑟夫·戈培尔","id":"card49"},{"text":"↔ 相关：德国乌发电影公司","id":"card77"},{"text":"✗ 对立/冲突：现代主义艺术","id":"card200"},{"text":"✗ 对立/冲突：纳粹文化控制","id":"extra113"},{"text":"↔ 同时期参考：纳粹取缔德国工会","id":"extra102"}],"source":"history","id":"extra125"},{"title":"纳粹德国“退化艺术”展","level":"B","type":"事件卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1937年","place":"德国慕尼黑，后巡回展出","summary":"纳粹德国“退化艺术”展以羞辱现代艺术为目标，是纳粹文化清洗和审美政治的集中展示。","fields":[{"label":"标题","value":"纳粹德国“退化艺术”展"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1937年"},{"label":"地点","value":"德国慕尼黑，后巡回展出"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"纳粹德国“退化艺术”展以羞辱现代艺术为目标，是纳粹文化清洗和审美政治的集中展示。"},{"label":"参与者","value":"纳粹宣传部、帝国文化机构、被攻击的现代主义艺术家、参观公众。"},{"label":"发生了什么","value":"纳粹从博物馆没收大量现代艺术作品，并在慕尼黑举办“退化艺术”展，以混乱陈列、嘲讽文字和种族化标签羞辱表现主义、达达、抽象艺术等作品。展览与官方“大德意志艺术展”形成对照，向公众灌输纳粹审美标准。"},{"label":"为什么重要","value":"它展示纳粹如何把艺术判断变成政治忠诚和种族意识问题，也导致现代艺术家被禁、流亡或沉默。"},{"label":"前因","value":"纳粹文化政策把现代主义、犹太艺术和左翼文化都视为民族共同体的敌人，帝国文化院已经建立起审查和排除机制。"},{"label":"后果","value":"大量现代艺术作品被没收、出售或毁坏，艺术家被迫流亡或沉默，战后失落艺术追索也与这场掠夺相连。"},{"label":"出处","value":"Museum of Modern Art，“Degenerate Art”；United States Holocaust Memorial Museum，Degenerate Art materials。"}],"relationItems":["← 前因：魏玛柏林达达运动","← 前因：德国新客观主义","← 前因：纳粹德国帝国文化院","→ 后果：纳粹文化控制","→ 后果：战后艺术追索","↔ 相关：德国表现主义电影","↔ 相关：德国包豪斯","✗ 对立/冲突：现代主义艺术","✗ 对立/冲突：纳粹古典化审美","↔ 同时期参考：1936年柏林奥运会"],"relations":[{"text":"← 前因：魏玛柏林达达运动","id":"card79"},{"text":"← 前因：德国新客观主义","id":"card31"},{"text":"← 前因：纳粹德国帝国文化院","id":"extra125"},{"text":"→ 后果：纳粹文化控制","id":"extra113"},{"text":"↔ 相关：德国表现主义电影","id":"card78"},{"text":"↔ 相关：德国包豪斯","id":"card30"},{"text":"✗ 对立/冲突：现代主义艺术","id":"card200"},{"text":"↔ 同时期参考：1936年柏林奥运会","id":"extra129"}],"source":"history","id":"extra126"},{"title":"纳粹《遗传病后代预防法》","level":"B","type":"制度/文本卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1933年7月14日通过，1934年生效","place":"纳粹德国","summary":"纳粹《遗传病后代预防法》以优生学名义推行强制绝育，是纳粹生物政治的重要制度起点。","fields":[{"label":"标题","value":"纳粹《遗传病后代预防法》"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1933年7月14日通过，1934年生效"},{"label":"地点","value":"纳粹德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"纳粹《遗传病后代预防法》以优生学名义推行强制绝育，是纳粹生物政治的重要制度起点。"},{"label":"制定方/签署方","value":"纳粹德国政府。"},{"label":"主要内容","value":"规定患有被定义为“遗传病”的人可被强制绝育，并设立遗传健康法院处理案件。"},{"label":"它试图解决什么问题","value":"纳粹政权把贫困、残疾、精神疾病和社会边缘化解释为“遗传负担”，试图用国家强制手段塑造所谓“民族共同体”的身体质量。"},{"label":"为什么重要","value":"它把优生思想转化为国家法律实践，连接了医学、法院、福利机构和警察权力。"},{"label":"争议/局限","value":"该法建立在伪科学、歧视和国家暴力基础上，剥夺个人身体自主权并造成长期创伤。"},{"label":"造成的影响","value":"数十万人被强制绝育，并为后来的纳粹T4行动和更广泛的种族政策提供制度经验。"},{"label":"出处","value":"United States Holocaust Memorial Museum，“Law for the Prevention of Offspring with Hereditary Diseases”；German History in Documents and Images，Nazi eugenics materials。"}],"relationItems":["← 前因：纳粹优生政策","← 前因：德意志生命改革运动","→ 后果：纳粹T4行动","→ 后果：纳粹纽伦堡法","↔ 相关：纳粹家庭政策","↔ 相关：纳粹元首国家","✗ 对立/冲突：身体自主权","✗ 对立/冲突：国家优生暴力","↔ 同时期参考：纳粹德国职业公务员法"],"relations":[{"text":"← 前因：纳粹优生政策","id":"extra118"},{"text":"← 前因：德意志生命改革运动","id":"extra726"},{"text":"→ 后果：纳粹T4行动","id":"extra128"},{"text":"→ 后果：纳粹纽伦堡法","id":"extra114"},{"text":"↔ 相关：纳粹家庭政策","id":"extra117"},{"text":"↔ 相关：纳粹元首国家","id":"extra110"},{"text":"✗ 对立/冲突：身体自主权","id":"extra860"},{"text":"↔ 同时期参考：纳粹德国职业公务员法","id":"extra112"}],"source":"history","id":"extra127"},{"title":"纳粹T4行动","level":"A","type":"事件卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1939年开始，1941年官方停止后仍以分散形式延续","place":"纳粹德国及被吞并地区的医疗和杀害机构","summary":"纳粹T4行动以“安乐死”为名系统杀害残障者和精神病患者，是纳粹灭绝政治的关键前史。","fields":[{"label":"标题","value":"纳粹T4行动"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1939年开始，1941年官方停止后仍以分散形式延续"},{"label":"地点","value":"纳粹德国及被吞并地区的医疗和杀害机构"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"纳粹T4行动以“安乐死”为名系统杀害残障者和精神病患者，是纳粹灭绝政治的关键前史。"},{"label":"参与者","value":"希特勒授权的纳粹官僚、医生、护士、福利机构和T4行政人员；受害者为残障者、精神病患者和其他被视为“无价值生命”的人。"},{"label":"发生了什么","value":"纳粹政权以秘密授权启动杀害计划，通过医疗档案筛选、转运和毒气室等方式杀害机构中的残障者和精神病患者。1941年在教会抗议和社会传闻压力下，集中形式的T4行动被宣布停止，但杀害以药物、饥饿和分散机构方式继续。"},{"label":"为什么重要","value":"它说明纳粹犹太人大屠杀并非突然出现，医学化杀害、官僚分类和毒气技术在T4中已经形成。"},{"label":"前因","value":"纳粹优生政策和《遗传病后代预防法》已经把残障者和病人视为国家负担，战争环境又为秘密杀害提供了行政和宣传掩护。"},{"label":"后果","value":"T4行动训练并转移了人员、技术和杀戮经验，后来与灭绝营运作相连，也成为战后医生审判的重要罪行。"},{"label":"出处","value":"United States Holocaust Memorial Museum，“Euthanasia Program”；Yad Vashem，T4 materials。"}],"relationItems":["← 前因：纳粹《遗传病后代预防法》","← 前因：纳粹优生政策","→ 后果：纳粹犹太人大屠杀","→ 后果：纽伦堡医生审判","↔ 相关：纳粹家庭政策","↔ 相关：纳粹元首国家","✗ 对立/冲突：医学伦理","✗ 对立/冲突：国家灭绝政策","↔ 同时期参考：纳粹德国四年计划"],"relations":[{"text":"← 前因：纳粹《遗传病后代预防法》","id":"extra127"},{"text":"← 前因：纳粹优生政策","id":"extra118"},{"text":"→ 后果：纳粹犹太人大屠杀","id":"extra218"},{"text":"→ 后果：纽伦堡医生审判","id":"extra853"},{"text":"↔ 相关：纳粹家庭政策","id":"extra117"},{"text":"↔ 相关：纳粹元首国家","id":"extra110"},{"text":"↔ 同时期参考：纳粹德国四年计划","id":"extra122"}],"source":"history","id":"extra128"},{"title":"1936年柏林奥运会","level":"B","type":"事件卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1936年8月1日—8月16日","place":"德国柏林","summary":"1936年柏林奥运会被纳粹用作国际形象工程，同时也因杰西·欧文斯等表现暴露其种族神话的矛盾。","fields":[{"label":"标题","value":"1936年柏林奥运会"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1936年8月1日—8月16日"},{"label":"地点","value":"德国柏林"},{"label":"主要国家","value":"德国、美国及参赛国家"},{"label":"一句话概括","value":"1936年柏林奥运会被纳粹用作国际形象工程，同时也因杰西·欧文斯等表现暴露其种族神话的矛盾。"},{"label":"参与者","value":"纳粹德国政府和宣传机构；国际奥委会；各国运动员；杰西·欧文斯等。"},{"label":"发生了什么","value":"纳粹德国精心组织柏林奥运会，临时淡化公开反犹标语和暴力形象，展示秩序、建筑、体育和现代传媒能力。比赛通过广播、新闻摄影和莱妮·里芬施塔尔电影传播。美国黑人运动员杰西·欧文斯获得多枚金牌，使纳粹种族优越叙事受到象征性冲击。"},{"label":"为什么重要","value":"它说明现代体育、电影和国际公共关系可以被独裁政权用于形象包装，也提醒文化盛事并不自动脱离政治。"},{"label":"前因","value":"纳粹政权需要改善国际形象并展示新德国的秩序和活力，国际奥委会既有安排也给德国提供了全球宣传舞台。"},{"label":"后果","value":"奥运会短暂美化纳粹德国形象，但也暴露体育、种族主义和国家宣传之间的关系，成为现代体育政治化的重要案例。"},{"label":"出处","value":"Encyclopaedia Britannica，“Berlin 1936 Olympic Games”；United States Holocaust Memorial Museum，“The Nazi Olympics Berlin 1936”。"}],"relationItems":["← 前因：纳粹宣传机器","← 前因：纳粹高速公路宣传","→ 后果：纳粹德国“退化艺术”展","→ 后果：第二次世界大战前国际绥靖气氛","↔ 相关：莱妮·里芬施塔尔","↔ 相关：杰西·欧文斯","✗ 对立/冲突：奥林匹克国际主义","✗ 对立/冲突：纳粹种族主义","↔ 同时期参考：纳粹大众汽车计划"],"relations":[{"text":"← 前因：纳粹宣传机器","id":"extra94"},{"text":"← 前因：纳粹高速公路宣传","id":"extra123"},{"text":"→ 后果：纳粹德国“退化艺术”展","id":"extra126"},{"text":"↔ 同时期参考：纳粹大众汽车计划","id":"extra124"}],"source":"history","id":"extra129"},{"title":"纳粹德国冬季救济事业","level":"B","type":"组织/机构卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1933年开始","place":"纳粹德国","summary":"纳粹德国冬季救济事业以慈善救助包装社会控制，把捐献、宣传和民族共同体表演结合起来。","fields":[{"label":"标题","value":"纳粹德国冬季救济事业"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1933年开始"},{"label":"地点","value":"纳粹德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"纳粹德国冬季救济事业以慈善救助包装社会控制，把捐献、宣传和民族共同体表演结合起来。"},{"label":"性质/类型","value":"国家主导的社会救济和宣传动员组织。"},{"label":"成立/解散时间","value":"1933年纳粹上台后制度化推行，持续到纳粹德国末期。"},{"label":"核心目标/宗旨","value":"为贫困者筹集冬季救济资源，同时通过强制性社会压力展示“民族共同体”团结。"},{"label":"关键人物（可选）","value":"纳粹人民福利组织和宣传机构参与运作。"},{"label":"关键行动/事件","value":"街头募捐、徽章售卖、捐献日、公开宣传和救济分配。"},{"label":"为什么重要","value":"它把福利、羞辱、忠诚展示和群众动员结合，显示纳粹社会政策不是中性的慈善。"},{"label":"争议/局限","value":"捐献常带有社会压力和政治监视，救助对象也受种族和政治排除逻辑限制。"},{"label":"出处","value":"United States Holocaust Memorial Museum，Nazi social welfare and propaganda materials；Deutsches Historisches Museum/LeMO，Winterhilfswerk materials。"}],"relationItems":["← 前因：纳粹德国劳工阵线","← 前因：纳粹一体化政策","→ 后果：纳粹人民共同体宣传","↔ 相关：纳粹德国“力量来自欢乐”组织","↔ 相关：纳粹家庭政策","✗ 对立/冲突：社会救济","✗ 对立/冲突：政治忠诚表演","↔ 同时期参考：纳粹德国人民收音机"],"relations":[{"text":"← 前因：纳粹德国劳工阵线","id":"extra103"},{"text":"← 前因：纳粹一体化政策","id":"extra100"},{"text":"↔ 相关：纳粹德国“力量来自欢乐”组织","id":"extra104"},{"text":"↔ 相关：纳粹家庭政策","id":"extra117"},{"text":"↔ 同时期参考：纳粹德国人民收音机","id":"extra285"}],"source":"history","id":"extra130"},{"title":"纳粹母亲十字勋章","level":"C","type":"制度/文本卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1938年设立，1939年首次颁发","place":"纳粹德国","summary":"纳粹母亲十字勋章奖励多子女“雅利安”母亲，把生育变成可被国家表彰的政治职责。","fields":[{"label":"标题","value":"纳粹母亲十字勋章"},{"label":"分级","value":"C"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1938年设立，1939年首次颁发"},{"label":"地点","value":"纳粹德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"纳粹母亲十字勋章奖励多子女“雅利安”母亲，把生育变成可被国家表彰的政治职责。"},{"label":"制定方/签署方","value":"纳粹德国政府。"},{"label":"主要内容","value":"按子女数量分等级授予母亲荣誉，通常为铜、银、金三个等级。"},{"label":"它试图解决什么问题","value":"纳粹政权希望提高被认定为“种族合格”家庭的生育率，并把女性角色固定为母亲和家庭照护者。"},{"label":"为什么重要","value":"它把亲密家庭生活仪式化、国家化，说明纳粹性别政策如何把荣誉、福利和排除结合。"},{"label":"争议/局限","value":"荣誉只服务种族国家逻辑，犹太人、残障者和被视为“不合格”的人被排除甚至迫害。"},{"label":"造成的影响","value":"强化纳粹母职宣传和性别分工，与优生政策、家庭政策共同构成生育政治。"},{"label":"出处","value":"German History in Documents and Images，Mother’s Cross materials；United States Holocaust Memorial Museum，Nazi family and race policy materials。"}],"relationItems":["← 前因：纳粹家庭政策","← 前因：纳粹优生政策","→ 后果：纳粹德国生命之泉协会","↔ 相关：纳粹德国少女联盟","↔ 相关：纳粹《遗传病后代预防法》","✗ 对立/冲突：女性自主","✗ 对立/冲突：国家母职政治","↔ 同时期参考：纳粹德国冬季救济事业"],"relations":[{"text":"← 前因：纳粹家庭政策","id":"extra117"},{"text":"← 前因：纳粹优生政策","id":"extra118"},{"text":"→ 后果：纳粹德国生命之泉协会","id":"extra290"},{"text":"↔ 相关：纳粹德国少女联盟","id":"extra116"},{"text":"↔ 相关：纳粹《遗传病后代预防法》","id":"extra127"},{"text":"↔ 同时期参考：纳粹德国冬季救济事业","id":"extra130"}],"source":"history","id":"extra131"},{"title":"纳粹德国动物保护法","level":"C","type":"制度/文本卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1933年","place":"纳粹德国","summary":"纳粹德国动物保护法显示纳粹能把保护动物话语与排斥人类群体的暴力政治并置。","fields":[{"label":"标题","value":"纳粹德国动物保护法"},{"label":"分级","value":"C"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1933年"},{"label":"地点","value":"纳粹德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"纳粹德国动物保护法显示纳粹能把保护动物话语与排斥人类群体的暴力政治并置。"},{"label":"制定方/签署方","value":"纳粹德国政府。"},{"label":"主要内容","value":"规定动物保护、屠宰和实验等方面限制，并以国家权力塑造“爱护动物”的公共形象。"},{"label":"它试图解决什么问题","value":"政权借动物保护塑造道德形象，同时把自然、纯洁和民族共同体话语纳入国家法制。"},{"label":"为什么重要","value":"它提醒人道话语本身不能自动防止暴政；同一政权可以保护动物却迫害人类。"},{"label":"争议/局限","value":"法律常被纳粹宣传用于自我美化，并与反犹、反现代医学和民族自然观交织。"},{"label":"造成的影响","value":"成为研究纳粹环境、动物伦理和政治宣传复杂关系的典型案例。"},{"label":"出处","value":"German History in Documents and Images，Nazi animal protection materials；academic studies on Nazi animal protection law。"}],"relationItems":["← 前因：德意志生命改革运动","← 前因：纳粹文化控制","→ 后果：纳粹德国自然保护法","↔ 相关：纳粹优生政策","↔ 相关：纳粹T4行动","✗ 对立/冲突：动物保护道德","✗ 对立/冲突：人类群体迫害","↔ 同时期参考：纳粹《遗传病后代预防法》"],"relations":[{"text":"← 前因：德意志生命改革运动","id":"extra726"},{"text":"← 前因：纳粹文化控制","id":"extra113"},{"text":"→ 后果：纳粹德国自然保护法","id":"extra133"},{"text":"↔ 相关：纳粹优生政策","id":"extra118"},{"text":"↔ 相关：纳粹T4行动","id":"extra128"},{"text":"↔ 同时期参考：纳粹《遗传病后代预防法》","id":"extra127"}],"source":"history","id":"extra132"},{"title":"纳粹德国自然保护法","level":"C","type":"制度/文本卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1935年","place":"纳粹德国","summary":"纳粹德国自然保护法把风景、乡土和自然保护纳入国家治理，体现环境保护与民族主义政治的复杂交织。","fields":[{"label":"标题","value":"纳粹德国自然保护法"},{"label":"分级","value":"C"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1935年"},{"label":"地点","value":"纳粹德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"纳粹德国自然保护法把风景、乡土和自然保护纳入国家治理，体现环境保护与民族主义政治的复杂交织。"},{"label":"制定方/签署方","value":"纳粹德国政府。"},{"label":"主要内容","value":"规定自然纪念物、风景保护区和物种保护等事项，强化国家在自然保护中的角色。"},{"label":"它试图解决什么问题","value":"在工业化和城市化背景下，政权借保护自然和乡土景观塑造民族共同体与“血与土”想象。"},{"label":"为什么重要","value":"它说明环境保护不必然等同自由主义或民主政治，也可能被威权国家吸收为民族主义治理工具。"},{"label":"争议/局限","value":"法律保护自然的同时，纳粹政权持续推进再武装、强制劳动、扩张战争和种族暴力。"},{"label":"造成的影响","value":"成为德国环境史中必须谨慎处理的遗产。"},{"label":"出处","value":"German History in Documents and Images，Reich Nature Protection Law materials；environmental history studies of Nazi Germany。"}],"relationItems":["← 前因：德意志生命改革运动","← 前因：纳粹德国动物保护法","→ 后果：战后德国环境保护争论","↔ 相关：纳粹血与土思想","↔ 相关：纳粹家庭政策","✗ 对立/冲突：自然保护","✗ 对立/冲突：扩张主义国家暴力","↔ 同时期参考：纳粹高速公路宣传"],"relations":[{"text":"← 前因：德意志生命改革运动","id":"extra726"},{"text":"← 前因：纳粹德国动物保护法","id":"extra132"},{"text":"↔ 相关：纳粹血与土思想","id":"extra859"},{"text":"↔ 相关：纳粹家庭政策","id":"extra117"},{"text":"↔ 同时期参考：纳粹高速公路宣传","id":"extra123"}],"source":"history","id":"extra133"},{"title":"纳粹“美化劳动”运动","level":"C","type":"组织/机构卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"1934年起","place":"纳粹德国","summary":"纳粹“美化劳动”运动以改善工作环境为名，把工厂空间改造成民族共同体和劳动纪律的展示场。","fields":[{"label":"标题","value":"纳粹“美化劳动”运动"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1934年起"},{"label":"地点","value":"纳粹德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"纳粹“美化劳动”运动以改善工作环境为名，把工厂空间改造成民族共同体和劳动纪律的展示场。"},{"label":"性质/类型","value":"纳粹德国劳工阵线下属的工作场所改造和宣传项目。"},{"label":"成立/解散时间","value":"1934年开始推动，持续至纳粹时期。"},{"label":"核心目标/宗旨","value":"通过改善照明、卫生、食堂、休息室和厂区形象，提升工人归属感并削弱独立工人组织记忆。"},{"label":"关键人物（可选）","value":"纳粹德国劳工阵线及其领导层。"},{"label":"关键行动/事件","value":"工厂环境改造竞赛、宣传展览、 workplace 改善标准和视觉化劳动荣誉。"},{"label":"为什么重要","value":"它说明纳粹社会政策不是单纯镇压，也会通过空间、美学和福利包装制造服从。"},{"label":"争议/局限","value":"工人缺乏自由工会和真实谈判权，改善环境不能替代劳动权利。"},{"label":"出处","value":"German History in Documents and Images，Beauty of Labour materials；Deutsches Historisches Museum/LeMO，German Labour Front materials。"}],"relationItems":["← 前因：纳粹取缔德国工会","← 前因：纳粹德国劳工阵线","→ 后果：纳粹德国“力量来自欢乐”组织","↔ 相关：纳粹大众汽车计划","↔ 相关：纳粹德国冬季救济事业","✗ 对立/冲突：工作环境改善","✗ 对立/冲突：工人权利剥夺","↔ 同时期参考：纳粹德国人民收音机"],"relations":[{"text":"← 前因：纳粹取缔德国工会","id":"extra102"},{"text":"← 前因：纳粹德国劳工阵线","id":"extra103"},{"text":"→ 后果：纳粹德国“力量来自欢乐”组织","id":"extra104"},{"text":"↔ 相关：纳粹大众汽车计划","id":"extra124"},{"text":"↔ 相关：纳粹德国冬季救济事业","id":"extra130"},{"text":"↔ 同时期参考：纳粹德国人民收音机","id":"extra285"}],"source":"history","id":"extra134"},{"title":"纳粹人民法院","level":"B","type":"组织/机构卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1934年设立","place":"纳粹德国","summary":"纳粹人民法院把审判变成政治镇压舞台，是纳粹司法恐怖制度化的重要机构。","fields":[{"label":"标题","value":"纳粹人民法院"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1934年设立"},{"label":"地点","value":"纳粹德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"纳粹人民法院把审判变成政治镇压舞台，是纳粹司法恐怖制度化的重要机构。"},{"label":"性质/类型","value":"政治刑事特别法院。"},{"label":"成立/解散时间","value":"1934年设立，1945年纳粹德国覆灭后结束。"},{"label":"核心目标/宗旨","value":"审理叛国、破坏军心和政治反对等案件，以法律形式打击反纳粹者。"},{"label":"关键人物（可选）","value":"罗兰德·弗赖斯勒等。"},{"label":"关键行动/事件","value":"审判抵抗者、反战者和“7月20日密谋案”相关人员，判处大量死刑。"},{"label":"为什么重要","value":"它说明纳粹统治不只靠秘密警察，也把法院改造成公开羞辱和消灭敌人的工具。"},{"label":"争议/局限","value":"法院缺乏独立司法原则，判决服务政权意志。"},{"label":"出处","value":"United States Holocaust Memorial Museum，Nazi courts materials；German History in Documents and Images，People’s Court materials。"}],"relationItems":["← 前因：德国国会纵火法令","← 前因：纳粹一体化政策","→ 后果：纳粹司法恐怖","↔ 相关：纳粹盖世太保","↔ 相关：纳粹特别法院","✗ 对立/冲突：法治审判","✗ 对立/冲突：政治审判表演","↔ 同时期参考：纳粹德国帝国文化院"],"relations":[{"text":"← 前因：德国国会纵火法令","id":"extra98"},{"text":"← 前因：纳粹一体化政策","id":"extra100"},{"text":"↔ 相关：纳粹盖世太保","id":"extra106"},{"text":"↔ 相关：纳粹特别法院","id":"extra140"},{"text":"↔ 同时期参考：纳粹德国帝国文化院","id":"extra125"}],"source":"history","id":"extra135"},{"title":"纳粹遗传健康法院","level":"B","type":"组织/机构卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1934年开始运作","place":"纳粹德国","summary":"纳粹遗传健康法院把强制绝育包装成法律程序，是医学、司法和优生暴力结合的机构。","fields":[{"label":"标题","value":"纳粹遗传健康法院"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1934年开始运作"},{"label":"地点","value":"纳粹德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"纳粹遗传健康法院把强制绝育包装成法律程序，是医学、司法和优生暴力结合的机构。"},{"label":"性质/类型","value":"处理强制绝育案件的专门法院。"},{"label":"成立/解散时间","value":"依据1933年《遗传病后代预防法》设立，1934年后广泛运作。"},{"label":"核心目标/宗旨","value":"裁定被认定患有“遗传病”的人是否应被强制绝育。"},{"label":"关键人物（可选）","value":"医生、法官和卫生官员共同参与。"},{"label":"关键行动/事件","value":"审理大量强制绝育申请，形成医学档案、家族调查和法院命令结合的流程。"},{"label":"为什么重要","value":"它说明纳粹种族政策并不总以暴力突袭出现，也可能通过表面合法、专业和行政化程序推进。"},{"label":"争议/局限","value":"所谓审理建立在伪科学和国家强制基础上，受害者几乎没有真正自主权。"},{"label":"出处","value":"United States Holocaust Memorial Museum，forced sterilization materials；German History in Documents and Images，Hereditary Health Courts materials。"}],"relationItems":["← 前因：纳粹《遗传病后代预防法》","← 前因：纳粹优生政策","→ 后果：纳粹T4行动","↔ 相关：纳粹人民法院","↔ 相关：德国刑法典第175条","✗ 对立/冲突：医学专业权威","✗ 对立/冲突：身体自主权","↔ 同时期参考：纳粹母亲十字勋章"],"relations":[{"text":"← 前因：纳粹《遗传病后代预防法》","id":"extra127"},{"text":"← 前因：纳粹优生政策","id":"extra118"},{"text":"→ 后果：纳粹T4行动","id":"extra128"},{"text":"↔ 相关：纳粹人民法院","id":"extra135"},{"text":"↔ 相关：德国刑法典第175条","id":"extra721"},{"text":"✗ 对立/冲突：身体自主权","id":"extra860"},{"text":"↔ 同时期参考：纳粹母亲十字勋章","id":"extra131"}],"source":"history","id":"extra136"},{"title":"纳粹帝国劳役团","level":"B","type":"组织/机构卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1935年义务化","place":"纳粹德国","summary":"纳粹帝国劳役团把青年劳动、军事预备训练和政治教育合为一体，是纳粹日常动员制度。","fields":[{"label":"标题","value":"纳粹帝国劳役团"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1935年义务化"},{"label":"地点","value":"纳粹德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"纳粹帝国劳役团把青年劳动、军事预备训练和政治教育合为一体，是纳粹日常动员制度。"},{"label":"性质/类型","value":"国家劳动服务和青年动员机构。"},{"label":"成立/解散时间","value":"1930年代形成，1935年男性义务劳役制度化；战时继续扩展。"},{"label":"核心目标/宗旨","value":"通过劳动营、纪律训练和政治教育塑造服从国家的青年身体。"},{"label":"关键人物（可选）","value":"康斯坦丁·希尔等劳役系统领导人。"},{"label":"关键行动/事件","value":"组织道路、农田、水利等劳动项目，进行准军事纪律和意识形态教育。"},{"label":"为什么重要","value":"它说明纳粹就业政策和青年教育不是单纯经济措施，而是为战争社会和服从文化做准备。"},{"label":"争议/局限","value":"劳役团消除自由选择，把劳动变成国家义务和政治训练。"},{"label":"出处","value":"German History in Documents and Images，Reich Labour Service materials；Deutsches Historisches Museum/LeMO，Reichsarbeitsdienst materials。"}],"relationItems":["← 前因：纳粹希特勒青年团","← 前因：德国大萧条失业危机","→ 后果：纳粹德国再武装","↔ 相关：纳粹“美化劳动”运动","↔ 相关：纳粹高速公路宣传","✗ 对立/冲突：自由劳动市场","✗ 对立/冲突：国家强制劳役","↔ 同时期参考：纳粹德国人民收音机"],"relations":[{"text":"← 前因：纳粹希特勒青年团","id":"extra115"},{"text":"← 前因：德国大萧条失业危机","id":"card99"},{"text":"→ 后果：纳粹德国再武装","id":"extra119"},{"text":"↔ 相关：纳粹“美化劳动”运动","id":"extra134"},{"text":"↔ 相关：纳粹高速公路宣传","id":"extra123"},{"text":"↔ 同时期参考：纳粹德国人民收音机","id":"extra285"}],"source":"history","id":"extra137"},{"title":"纳粹世袭农场法","level":"C","type":"制度/文本卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"1933年","place":"纳粹德国","summary":"纳粹世袭农场法以保护农民为名固定土地继承，把农业政策纳入“血与土”意识形态。","fields":[{"label":"标题","value":"纳粹世袭农场法"},{"label":"分级","value":"C"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1933年"},{"label":"地点","value":"纳粹德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"纳粹世袭农场法以保护农民为名固定土地继承，把农业政策纳入“血与土”意识形态。"},{"label":"制定方/签署方","value":"纳粹德国政府。"},{"label":"主要内容","value":"规定一定规模农场作为世袭农场不可自由分割或抵押，并将继承权与种族和家庭资格联系起来。"},{"label":"它试图解决什么问题","value":"纳粹声称要防止农地破碎、农民负债和农村衰败，同时塑造“健康农民阶层”。"},{"label":"为什么重要","value":"它把农村经济、家庭继承和种族政治结合，显示纳粹社会政策并不只针对城市工人。"},{"label":"争议/局限","value":"法律限制农民处分财产自由，也把农业身份纳入国家和种族审查。"},{"label":"造成的影响","value":"加强农民与国家控制的绑定，并服务纳粹“血与土”宣传。"},{"label":"出处","value":"German History in Documents and Images，Reich Hereditary Farm Law materials；USHMM，Nazi race and society materials。"}],"relationItems":["← 前因：纳粹家庭政策","← 前因：纳粹血与土思想","→ 后果：纳粹帝国粮食署","↔ 相关：纳粹德国自然保护法","↔ 相关：德国合作银行运动","✗ 对立/冲突：土地市场自由","✗ 对立/冲突：种族化农民秩序","↔ 同时期参考：纳粹母亲十字勋章"],"relations":[{"text":"← 前因：纳粹家庭政策","id":"extra117"},{"text":"← 前因：纳粹血与土思想","id":"extra859"},{"text":"→ 后果：纳粹帝国粮食署","id":"extra139"},{"text":"↔ 相关：纳粹德国自然保护法","id":"extra133"},{"text":"↔ 相关：德国合作银行运动","id":"extra518"},{"text":"↔ 同时期参考：纳粹母亲十字勋章","id":"extra131"}],"source":"history","id":"extra138"},{"title":"纳粹帝国粮食署","level":"B","type":"组织/机构卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1933年建立","place":"纳粹德国","summary":"纳粹帝国粮食署把农业生产、价格和农民组织纳入国家控制，是纳粹经济统制的重要组成。","fields":[{"label":"标题","value":"纳粹帝国粮食署"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1933年建立"},{"label":"地点","value":"纳粹德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"纳粹帝国粮食署把农业生产、价格和农民组织纳入国家控制，是纳粹经济统制的重要组成。"},{"label":"性质/类型","value":"农业统制和农民组织机构。"},{"label":"成立/解散时间","value":"1933年建立，1945年结束。"},{"label":"核心目标/宗旨","value":"组织农民、调控农业生产与销售、维护粮食供应，并服务自给自足和战争准备。"},{"label":"关键人物（可选）","value":"理查德·瓦尔特·达雷。"},{"label":"关键行动/事件","value":"控制农业市场、价格、生产计划和农民组织，宣传“血与土”农民理想。"},{"label":"为什么重要","value":"它把农村社会纳入纳粹统制经济，连接食品供应、农民政治和四年计划。"},{"label":"争议/局限","value":"国家控制压缩农民自主，也无法完全解决德国粮食自给问题。"},{"label":"出处","value":"German History in Documents and Images，Reich Food Estate materials；Deutsches Historisches Museum/LeMO，Reichsnährstand materials。"}],"relationItems":["← 前因：纳粹世袭农场法","← 前因：纳粹一体化政策","→ 后果：纳粹德国四年计划","↔ 相关：纳粹德国冬季救济事业","↔ 相关：纳粹德国自然保护法","✗ 对立/冲突：农民自治","✗ 对立/冲突：国家农业统制","↔ 同时期参考：纳粹“美化劳动”运动"],"relations":[{"text":"← 前因：纳粹世袭农场法","id":"extra138"},{"text":"← 前因：纳粹一体化政策","id":"extra100"},{"text":"→ 后果：纳粹德国四年计划","id":"extra122"},{"text":"↔ 相关：纳粹德国冬季救济事业","id":"extra130"},{"text":"↔ 相关：纳粹德国自然保护法","id":"extra133"},{"text":"↔ 同时期参考：纳粹“美化劳动”运动","id":"extra134"}],"source":"history","id":"extra139"},{"title":"纳粹特别法院","level":"B","type":"组织/机构卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1933年起设立","place":"纳粹德国","summary":"纳粹特别法院以快速审判和严厉处罚打击政治与社会“不服从”，扩大了日常司法恐怖。","fields":[{"label":"标题","value":"纳粹特别法院"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1933年起设立"},{"label":"地点","value":"纳粹德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"纳粹特别法院以快速审判和严厉处罚打击政治与社会“不服从”，扩大了日常司法恐怖。"},{"label":"性质/类型","value":"特别刑事法院。"},{"label":"成立/解散时间","value":"1933年后陆续设立，战时权力扩大，1945年结束。"},{"label":"核心目标/宗旨","value":"迅速处理政权认为危害国家、秩序或战时社会稳定的案件。"},{"label":"关键人物（可选）","value":"纳粹司法部、地方检察和法院系统。"},{"label":"关键行动/事件","value":"审理政治言论、偷听敌台、经济犯罪、战时“破坏军心”等案件。"},{"label":"为什么重要","value":"它把纳粹恐怖带入普通法院层级，使普通违法、政治不满和生存犯罪都可能被严厉政治化。"},{"label":"争议/局限","value":"审判程序服务政权效率，严重牺牲被告权利和司法独立。"},{"label":"出处","value":"United States Holocaust Memorial Museum，Nazi judiciary materials；German History in Documents and Images，Special Courts materials。"}],"relationItems":["← 前因：德国国会纵火法令","← 前因：纳粹一体化政策","→ 后果：纳粹人民法院","↔ 相关：纳粹盖世太保","↔ 相关：纳粹人民法院","✗ 对立/冲突：普通法治程序","✗ 对立/冲突：政治化快速惩罚","↔ 同时期参考：纳粹遗传健康法院"],"relations":[{"text":"← 前因：德国国会纵火法令","id":"extra98"},{"text":"← 前因：纳粹一体化政策","id":"extra100"},{"text":"→ 后果：纳粹人民法院","id":"extra135"},{"text":"↔ 相关：纳粹盖世太保","id":"extra106"},{"text":"↔ 相关：纳粹人民法院","id":"extra135"},{"text":"↔ 同时期参考：纳粹遗传健康法院","id":"extra136"}],"source":"history","id":"extra140"},{"title":"纳粹“职业犯罪者”集中营关押机制","level":"C","type":"制度/文本卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1930年代形成并扩大","place":"纳粹德国集中营体系","summary":"纳粹以“职业犯罪者”等标签关押社会边缘人群，把治安治理、劳动强制和集中营制度连接起来。","fields":[{"label":"标题","value":"纳粹“职业犯罪者”集中营关押机制"},{"label":"分级","value":"C"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1930年代形成并扩大"},{"label":"地点","value":"纳粹德国集中营体系"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"纳粹以“职业犯罪者”等标签关押社会边缘人群，把治安治理、劳动强制和集中营制度连接起来。"},{"label":"制定方/签署方","value":"纳粹警察、刑警和集中营管理系统。"},{"label":"主要内容","value":"将被认定为惯犯、流浪者、所谓“反社会者”等人通过预防性拘押或警方命令送入集中营。"},{"label":"它试图解决什么问题","value":"政权把贫困、流动、失业和犯罪问题解释为社会清洗对象，而非社会经济问题。"},{"label":"为什么重要","value":"它说明集中营不只针对公开政治反对者，也用于治理和消灭被定义为“不配属于民族共同体”的人。"},{"label":"争议/局限","value":"标签高度任意并带有阶级、性别和种族偏见，受害者长期在战后记忆中被边缘化。"},{"label":"造成的影响","value":"扩大集中营劳动力来源，并强化纳粹社会排除机制。"},{"label":"出处","value":"United States Holocaust Memorial Museum，Nazi concentration camps and prisoner categories materials；Arolsen Archives，prisoner classification materials。"}],"relationItems":["← 前因：魏玛柏林“戒指会”犯罪网络","← 前因：纳粹达豪集中营建立","→ 后果：纳粹强迫劳动体系","↔ 相关：纳粹特别法院","↔ 相关：纳粹盖世太保","✗ 对立/冲突：社会救助","✗ 对立/冲突：治安清洗","↔ 同时期参考：纳粹德国冬季救济事业"],"relations":[{"text":"← 前因：魏玛柏林“戒指会”犯罪网络","id":"card74"},{"text":"← 前因：纳粹达豪集中营建立","id":"extra105"},{"text":"→ 后果：纳粹强迫劳动体系","id":"extra225"},{"text":"↔ 相关：纳粹特别法院","id":"extra140"},{"text":"↔ 相关：纳粹盖世太保","id":"extra106"},{"text":"↔ 同时期参考：纳粹德国冬季救济事业","id":"extra130"}],"source":"history","id":"extra141"},{"title":"纳粹反爵士乐运动","level":"C","type":"概念/思潮卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1933年—1945年","place":"纳粹德国","summary":"纳粹反爵士乐运动把音乐趣味种族化和政治化，显示大众文化如何成为独裁审查对象。","fields":[{"label":"标题","value":"纳粹反爵士乐运动"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1933年—1945年"},{"label":"地点","value":"纳粹德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"纳粹反爵士乐运动把音乐趣味种族化和政治化，显示大众文化如何成为独裁审查对象。"},{"label":"核心主张/思路","value":"纳粹宣传把爵士乐污名化为“非德国”“黑人化”或“犹太化”的退化音乐，并推动广播、舞厅和音乐教育管制。"},{"label":"提出者/代表人物（可选）","value":"纳粹宣传机构、帝国音乐院和文化官员。"},{"label":"它从何而来","value":"魏玛舞厅文化、美国大众音乐传播、纳粹种族主义和文化民族主义。"},{"label":"典型表现","value":"限制爵士演出、审查曲目、攻击摇摆青年，宣传所谓“德国音乐”纯洁性。"},{"label":"为什么重要","value":"它说明纳粹文化控制不仅针对高雅现代艺术，也深入舞曲、青年休闲和日常听觉经验。"},{"label":"争议/局限","value":"禁令和管制并不总能完全消灭爵士和摇摆音乐，青年文化仍有灰色空间。"},{"label":"出处","value":"United States Holocaust Memorial Museum，Swing Youth materials；German History in Documents and Images，Nazi music policy materials。"}],"relationItems":["← 前因：魏玛德国大众消费文化","← 前因：纳粹德国帝国文化院","→ 后果：摇摆青年受迫害","↔ 相关：纳粹文化控制","↔ 相关：纳粹德国人民收音机","✗ 对立/冲突：跨国大众音乐","✗ 对立/冲突：种族化文化审查","↔ 同时期参考：纳粹德国“退化艺术”展"],"relations":[{"text":"← 前因：魏玛德国大众消费文化","id":"card87"},{"text":"← 前因：纳粹德国帝国文化院","id":"extra125"},{"text":"↔ 相关：纳粹文化控制","id":"extra113"},{"text":"↔ 相关：纳粹德国人民收音机","id":"extra285"},{"text":"↔ 同时期参考：纳粹德国“退化艺术”展","id":"extra126"}],"source":"history","id":"extra142"},{"title":"纳粹德国Pervitin兴奋剂","level":"B","type":"事件卡","tags":["经济与社会","战争与外交"],"mainTag":"经济与社会","subTag":"战争与外交","timeText":"1938年上市，1939年后在军队中大量使用","place":"纳粹德国及二战战场","summary":"Pervitin作为甲基苯丙胺兴奋剂在纳粹德国流行，并被用于提高士兵警觉和耐疲劳能力。","fields":[{"label":"标题","value":"纳粹德国Pervitin兴奋剂"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1938年上市，1939年后在军队中大量使用"},{"label":"地点","value":"纳粹德国及二战战场"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"Pervitin作为甲基苯丙胺兴奋剂在纳粹德国流行，并被用于提高士兵警觉和耐疲劳能力。"},{"label":"参与者","value":"特姆勒制药公司；德国军医系统；德军士兵；纳粹国家和消费者市场。"},{"label":"发生了什么","value":"1938年，特姆勒公司推出甲基苯丙胺药片Pervitin，并以提高精力、警觉和效率为卖点进入市场。二战初期，德军大量发放该药以帮助士兵长时间行军、驾驶和作战。随着副作用、依赖性和滥用问题显现，军方后来加强限制，但药物仍与战争机器紧密相连。"},{"label":"为什么重要","value":"它显示纳粹战争社会不只依赖钢铁和纪律，也依赖药物化身体管理，把现代药品工业用于军事动员。"},{"label":"前因","value":"德国化学制药工业具备合成药生产能力，魏玛以来的药物管制并未阻止军队和社会对兴奋剂效率的兴趣。"},{"label":"后果","value":"Pervitin在德军中的使用引发战后关于药物、军事效率和成瘾风险的讨论，也提醒二战战争机器并不只依赖武器和意识形态。"},{"label":"出处","value":"Nicolas Rasmussen, “Medical Science and the Military: The Allies’ Use of Amphetamine during World War II”；German History in Documents and Images，Nazi society and war mobilization materials；Smithsonian Magazine，Pervitin history materials。"}],"relationItems":["← 前因：德国化学工业","← 前因：魏玛德国鸦片法","→ 后果：二战德军药物使用争议","↔ 相关：纳粹帝国劳役团","↔ 相关：纳粹德国再武装","✗ 对立/冲突：身体极限","✗ 对立/冲突：药物化动员","↔ 同时期参考：纳粹德国四年计划"],"relations":[{"text":"← 前因：德国化学工业","id":"extra680"},{"text":"← 前因：魏玛德国鸦片法","id":"card100"},{"text":"↔ 相关：纳粹帝国劳役团","id":"extra137"},{"text":"↔ 相关：纳粹德国再武装","id":"extra119"},{"text":"↔ 同时期参考：纳粹德国四年计划","id":"extra122"}],"source":"history","id":"extra143"},{"title":"特姆勒制药公司","level":"C","type":"组织/机构卡","tags":["经济与社会","战争与外交"],"mainTag":"经济与社会","subTag":"战争与外交","timeText":"二十世纪初成立，1930年代因Pervitin知名","place":"德国柏林","summary":"特姆勒制药公司因生产Pervitin而成为纳粹德国药物化效率和战争动员的代表企业。","fields":[{"label":"标题","value":"特姆勒制药公司"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"二十世纪初成立，1930年代因Pervitin知名"},{"label":"地点","value":"德国柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"特姆勒制药公司因生产Pervitin而成为纳粹德国药物化效率和战争动员的代表企业。"},{"label":"性质/类型","value":"制药企业。"},{"label":"成立/解散时间","value":"二十世纪初成立；1930年代推出Pervitin后迅速知名。"},{"label":"核心目标/宗旨","value":"生产和销售药品，包括面向普通消费者和军队需求的兴奋剂类产品。"},{"label":"关键人物（可选）","value":"公司研发和营销人员；德国军医系统作为重要使用方。"},{"label":"关键行动/事件","value":"1938年推出Pervitin，并通过广告和军方采购扩大影响。"},{"label":"为什么重要","value":"它把企业营销、药物科学、消费文化和纳粹战争需求连接起来，是研究制药工业责任的具体入口。"},{"label":"争议/局限","value":"企业成功建立在对兴奋剂风险的低估和战争动员需求上，药品商业化与公共健康存在冲突。"},{"label":"出处","value":"Smithsonian Magazine，Pervitin and Temmler history；historical studies of pharmaceuticals in Nazi Germany；Deutsches Technikmuseum/medical history materials。"}],"relationItems":["← 前因：德国化学工业","← 前因：拜耳海洛因商品化","→ 后果：纳粹德国Pervitin兴奋剂","↔ 相关：德国IG法本公司成立","↔ 相关：纳粹德国四年计划","✗ 对立/冲突：药品市场成功","✗ 对立/冲突：成瘾与滥用风险","↔ 同时期参考：纳粹德国人民收音机"],"relations":[{"text":"← 前因：德国化学工业","id":"extra680"},{"text":"← 前因：拜耳海洛因商品化","id":"extra743"},{"text":"→ 后果：纳粹德国Pervitin兴奋剂","id":"extra143"},{"text":"↔ 相关：德国IG法本公司成立","id":"card98"},{"text":"↔ 相关：纳粹德国四年计划","id":"extra122"},{"text":"↔ 同时期参考：纳粹德国人民收音机","id":"extra285"}],"source":"history","id":"extra144"},{"title":"纳粹德国“波茨坦日”政治仪式","level":"B","type":"事件卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1933年3月21日","place":"德国；波茨坦卫戍教堂","summary":"波茨坦日用希特勒与兴登堡同台的仪式，把纳粹政权包装成普鲁士传统和民族复兴的继承者。","fields":[{"label":"标题","value":"纳粹德国“波茨坦日”政治仪式"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1933年3月21日"},{"label":"地点","value":"德国；波茨坦卫戍教堂"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"波茨坦日用希特勒与兴登堡同台的仪式，把纳粹政权包装成普鲁士传统和民族复兴的继承者。"},{"label":"参与者","value":"阿道夫·希特勒、保罗·冯·兴登堡、纳粹政府、国会代表、军方和保守民族主义精英。"},{"label":"发生了什么","value":"新一届国会开幕仪式没有放在柏林国会大厦，而是安排在象征普鲁士王权和军国传统的波茨坦卫戍教堂。希特勒以克制姿态向兴登堡行礼，纳粹宣传把这一画面塑造成“旧德国”和“新德国”和解的象征。SPD没有参加，KPD议员已被排除在政治生活之外。"},{"label":"为什么重要","value":"它是纳粹夺权初期最典型的政治剧场，帮助保守派和普通公众相信希特勒政权不是革命性破坏，而是民族传统的延续。"},{"label":"前因","value":"国会纵火后，纳粹已用紧急法令压制左翼，但授权法尚未通过，政权仍需要争取中央党、保守派和总统权威的外观支持。"},{"label":"后果","value":"两天后授权法通过，波茨坦日营造的“合法、传统、秩序”形象成为纳粹消除议会监督的重要舆论背景。"},{"label":"出处","value":"German History in Documents and Images: Hitler and Hindenburg on the “Day of Potsdam”；1000dokumente: Rede Adolf Hitlers bei der Eröffnung des neu einberufenen Reichstags；Deutschlandmuseum: The Day of Potsdam。"}],"relationItems":["← 前因：1933年3月德国国会选举","← 前因：德国国会纵火法令","→ 后果：纳粹德国授权法","↔ 相关：保罗·冯·兴登堡","↔ 相关：纳粹宣传机器"],"relations":[{"text":"← 前因：1933年3月德国国会选举","id":"card57"},{"text":"← 前因：德国国会纵火法令","id":"extra98"},{"text":"→ 后果：纳粹德国授权法","id":"extra99"},{"text":"↔ 相关：保罗·冯·兴登堡","id":"card37"},{"text":"↔ 相关：纳粹宣传机器","id":"extra94"}],"source":"history","id":"extra145"},{"title":"纳粹德国帝国宣传部","level":"B","type":"组织/机构卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1933年3月13日成立，持续至1945年","place":"德国；柏林","summary":"帝国宣传部把新闻、广播、电影、文学和艺术纳入国家控制，是纳粹塑造公共现实的核心机构。","fields":[{"label":"标题","value":"纳粹德国帝国宣传部"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1933年3月13日成立，持续至1945年"},{"label":"地点","value":"德国；柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"帝国宣传部把新闻、广播、电影、文学和艺术纳入国家控制，是纳粹塑造公共现实的核心机构。"},{"label":"性质/类型","value":"中央政府部门，全称为“帝国国民教育与宣传部”。"},{"label":"成立/解散时间","value":"1933年3月13日建立，1945年纳粹德国崩溃后终结。"},{"label":"核心目标/宗旨","value":"集中管理宣传、新闻审查、文化动员和舆论塑造，使社会信息环境服从纳粹意识形态。"},{"label":"关键人物","value":"约瑟夫·戈培尔。"},{"label":"关键行动/事件","value":"控制新闻和广播，参与组织大型政治仪式，推动帝国文化院体系，管理电影、戏剧、文学和视觉艺术的政治方向。"},{"label":"为什么重要","value":"纳粹统治不只依靠警察暴力，也依靠持续制造可被相信、可被重复、可被日常消费的政治叙事。"},{"label":"争议/局限","value":"宣传部并非单独控制一切文化活动，它与党宣传系统、SS、地方党组织和其他部委存在竞争，但总体上显著压缩了公共表达空间。"},{"label":"出处","value":"German History Intersections: Decree Establishing the Reich Ministry for Public Enlightenment and Propaganda；DHM/LeMO: NS-Propaganda；DHM/LeMO: Reichskulturkammer。"}],"relationItems":["← 前因：纳粹宣传机器","↔ 相关：约瑟夫·戈培尔","↔ 相关：纳粹德国帝国文化院","→ 后果：纳粹德国《报刊编辑法》","→ 后果：纳粹德国人民收音机"],"relations":[{"text":"← 前因：纳粹宣传机器","id":"extra94"},{"text":"↔ 相关：约瑟夫·戈培尔","id":"card49"},{"text":"↔ 相关：纳粹德国帝国文化院","id":"extra125"},{"text":"→ 后果：纳粹德国《报刊编辑法》","id":"extra151"},{"text":"→ 后果：纳粹德国人民收音机","id":"extra285"}],"source":"history","id":"extra146"},{"title":"纳粹德国各州一体化法","level":"B","type":"制度/文本卡","tags":["政治与制度"],"mainTag":"政治与制度","subTag":"","timeText":"1933年3月31日","place":"德国","summary":"各州一体化法把德国各邦议会按3月国会选举结果重组，迅速摧毁联邦层面的民主制衡。","fields":[{"label":"标题","value":"纳粹德国各州一体化法"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"时间","value":"1933年3月31日"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"各州一体化法把德国各邦议会按3月国会选举结果重组，迅速摧毁联邦层面的民主制衡。"},{"label":"制定方/签署方","value":"纳粹德国中央政府，利用授权法后的立法权发布。"},{"label":"主要内容","value":"解散或重组各邦议会，使邦议会席位按1933年3月5日国会选举结果分配，并排除共产党政治影响。"},{"label":"它试图解决什么问题","value":"纳粹中央政府要消除各邦尤其地方议会中的反对力量，让地方政权跟随中央一体化。"},{"label":"为什么重要","value":"它把夺权从中央政府扩展到联邦结构内部，是魏玛联邦制被纳粹单一国家取代的第一步。"},{"label":"争议/局限","value":"形式上仍保留州议会外壳，但选举代表性已被恐怖、禁令和排除反对派扭曲，地方自治实质上失效。"},{"label":"造成的影响","value":"地方议会和政府迅速纳粹化，为帝国总督制度和1934年废除邦主权铺路。"},{"label":"出处","value":"USHMM Holocaust Encyclopedia: Gleichschaltung, Coordinating the Nazi State；Deutschlandmuseum: Germany becomes a centralized state；DocumentArchiv/Servat: Provisional Law on the Coordination of the States with the Reich。"}],"relationItems":["← 前因：纳粹德国授权法","↔ 相关：纳粹一体化政策","→ 后果：纳粹德国《帝国总督法》","→ 后果：纳粹德国《重建帝国法》"],"relations":[{"text":"← 前因：纳粹德国授权法","id":"extra99"},{"text":"↔ 相关：纳粹一体化政策","id":"extra100"},{"text":"→ 后果：纳粹德国《帝国总督法》","id":"extra148"},{"text":"→ 后果：纳粹德国《重建帝国法》","id":"extra157"}],"source":"history","id":"extra147"},{"title":"纳粹德国《帝国总督法》","level":"B","type":"制度/文本卡","tags":["政治与制度"],"mainTag":"政治与制度","subTag":"","timeText":"1933年4月7日","place":"德国","summary":"《帝国总督法》在各邦设置中央任命的帝国总督，把地方政府置于希特勒路线之下。","fields":[{"label":"标题","value":"纳粹德国《帝国总督法》"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"时间","value":"1933年4月7日"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"《帝国总督法》在各邦设置中央任命的帝国总督，把地方政府置于希特勒路线之下。"},{"label":"制定方/签署方","value":"纳粹德国中央政府。"},{"label":"主要内容","value":"由中央任命帝国总督监督各邦政府，确保各邦政治执行中央政府和希特勒的政策方向。"},{"label":"它试图解决什么问题","value":"纳粹要绕开魏玛时代的联邦分权和地方民主传统，防止州政府成为反对中央的制度堡垒。"},{"label":"为什么重要","value":"帝国总督制度把党和国家权力嵌入地方行政，是纳粹国家从联邦制转向中央集权的关键机制。"},{"label":"争议/局限","value":"总督权力与既有州政府、党大区领袖和中央部委经常交叠，造成纳粹体制内部典型的多头权力竞争。"},{"label":"造成的影响","value":"各邦政府逐渐失去独立性，1934年《重建帝国法》进一步取消邦主权。"},{"label":"出处","value":"USHMM Holocaust Encyclopedia: Gleichschaltung, Coordinating the Nazi State；DHM/LeMO: Innenpolitik des NS-Regimes；Servat: Second Law for the Coordination of the Länder with the Reich。"}],"relationItems":["← 前因：纳粹德国各州一体化法","↔ 相关：纳粹一体化政策","→ 后果：纳粹德国《重建帝国法》","↔ 相关：赫尔曼·戈林"],"relations":[{"text":"← 前因：纳粹德国各州一体化法","id":"extra147"},{"text":"↔ 相关：纳粹一体化政策","id":"extra100"},{"text":"→ 后果：纳粹德国《重建帝国法》","id":"extra157"},{"text":"↔ 相关：赫尔曼·戈林","id":"extra160"}],"source":"history","id":"extra148"},{"title":"纳粹德国《反新党法》","level":"B","type":"制度/文本卡","tags":["政治与制度"],"mainTag":"政治与制度","subTag":"","timeText":"1933年7月14日","place":"德国","summary":"《反新党法》把纳粹党规定为德国唯一合法政党，使一党制获得正式法律外壳。","fields":[{"label":"标题","value":"纳粹德国《反新党法》"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"时间","value":"1933年7月14日"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"《反新党法》把纳粹党规定为德国唯一合法政党，使一党制获得正式法律外壳。"},{"label":"制定方/签署方","value":"纳粹德国政府。"},{"label":"主要内容","value":"规定NSDAP为德国唯一政党，禁止成立或维持其他政党组织。"},{"label":"它试图解决什么问题","value":"纳粹要把此前通过恐怖、解散和逼迫造成的反对党消失，转化为正式法律状态。"},{"label":"为什么重要","value":"这不是一体化的泛泛结果，而是德国从多党议会政治转为一党国家的明确制度节点。"},{"label":"争议/局限","value":"法律是在反对派已被逮捕、恐吓或解散后颁布的，因此它更多是确认既成事实，而不是公平竞争后的制度选择。"},{"label":"造成的影响","value":"德国政党政治终结，国家、社会组织和公共职业体系被迫围绕NSDAP重新排列。"},{"label":"出处","value":"USHMM Holocaust Encyclopedia: Law against the Founding of New Parties；DHM/LeMO: Einparteienstaat；Deutschlandmuseum: Laws to consolidate the Third Reich。"}],"relationItems":["← 前因：纳粹一体化政策","↔ 相关：纳粹一党制","↔ 相关：纳粹取缔德国工会","→ 后果：纳粹元首国家"],"relations":[{"text":"← 前因：纳粹一体化政策","id":"extra100"},{"text":"↔ 相关：纳粹一党制","id":"extra101"},{"text":"↔ 相关：纳粹取缔德国工会","id":"extra102"},{"text":"→ 后果：纳粹元首国家","id":"extra110"}],"source":"history","id":"extra149"},{"title":"纳粹保护性拘留制度","level":"B","type":"概念/思潮卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1933—1945年","place":"纳粹德国；警察机关、监狱和集中营","summary":"“保护性拘留”把任意拘押包装成维护秩序的行政措施，是纳粹集中营系统早期运转的核心工具。","fields":[{"label":"标题","value":"纳粹保护性拘留制度"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1933—1945年"},{"label":"地点","value":"纳粹德国；警察机关、监狱和集中营"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"“保护性拘留”把任意拘押包装成维护秩序的行政措施，是纳粹集中营系统早期运转的核心工具。"},{"label":"核心主张/思路","value":"国家可以不经正常司法程序，以“保护人民和国家”名义拘押政治敌人和被污名化群体。"},{"label":"提出者/代表人物（可选）","value":"纳粹警察机关、盖世太保、SS和地方行政机构。"},{"label":"它从何而来","value":"国会纵火法令暂停基本权利后，警察获得大规模打击政治对手的空间；魏玛时期已有行政拘押传统，但纳粹把它系统化和无限期化。"},{"label":"典型表现","value":"共产党人、社民党人、工会人士、犹太人、同性恋者和其他被标记群体可被送入早期集中营，且难以通过法院救济。"},{"label":"为什么重要","value":"它解释了纳粹恐怖统治如何绕开普通司法，把“例外状态”变成日常治理。"},{"label":"争议/局限","value":"名称中的“保护”是政治伪装，实际保护的是政权免受反对，而不是被拘押者的人身安全。"},{"label":"出处","value":"DHM/LeMO: Schutzhaft；DHM/LeMO: Homosexuellenverfolgung；USHMM Holocaust Encyclopedia: Nazi camps and early persecution materials。"}],"relationItems":["← 前因：德国国会纵火法令","↔ 相关：纳粹达豪集中营建立","↔ 相关：纳粹盖世太保","→ 后果：纳粹“职业犯罪者”集中营关押机制"],"relations":[{"text":"← 前因：德国国会纵火法令","id":"extra98"},{"text":"↔ 相关：纳粹达豪集中营建立","id":"extra105"},{"text":"↔ 相关：纳粹盖世太保","id":"extra106"},{"text":"→ 后果：纳粹“职业犯罪者”集中营关押机制","id":"extra141"}],"source":"history","id":"extra150"},{"title":"纳粹德国《报刊编辑法》","level":"C","type":"制度/文本卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1933年10月4日通过，1934年1月1日生效","place":"德国","summary":"《报刊编辑法》把记者职业变成受国家政治资格审查的职业，终结德国新闻自由。","fields":[{"label":"标题","value":"纳粹德国《报刊编辑法》"},{"label":"分级","value":"C"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1933年10月4日通过，1934年1月1日生效"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"《报刊编辑法》把记者职业变成受国家政治资格审查的职业，终结德国新闻自由。"},{"label":"制定方/签署方","value":"纳粹德国政府和宣传系统。"},{"label":"主要内容","value":"要求编辑和记者符合政治可靠性、职业登记和“雅利安”资格等条件，并服从国家利益和宣传导向。"},{"label":"它试图解决什么问题","value":"纳粹要防止报刊独立报道和批评，使新闻职业从公共监督者变成政权话语的执行者。"},{"label":"为什么重要","value":"它说明审查不只是删文章，也可以通过资格、注册、职业纪律和种族排除来控制谁有资格发声。"},{"label":"争议/局限","value":"法律以“整顿职业”和“国家责任”为名，实际摧毁了新闻行业的独立性，并把犹太人与政治异见者排除出职业空间。"},{"label":"造成的影响","value":"德国新闻界被纳入宣传部和帝国文化院体系，报纸内容更彻底地服从纳粹国家目标。"},{"label":"出处","value":"USHMM Holocaust Encyclopedia: Editors Law；Servat: Law on Editors, October 4, 1933；DHM/LeMO: NS-Propaganda。"}],"relationItems":["← 前因：纳粹德国帝国宣传部","↔ 相关：纳粹文化控制","↔ 相关：纳粹德国帝国文化院","→ 后果：纳粹宣传机器"],"relations":[{"text":"← 前因：纳粹德国帝国宣传部","id":"extra146"},{"text":"↔ 相关：纳粹文化控制","id":"extra113"},{"text":"↔ 相关：纳粹德国帝国文化院","id":"extra125"},{"text":"→ 后果：纳粹宣传机器","id":"extra94"}],"source":"history","id":"extra151"},{"title":"纳粹德国德意志基督徒运动","level":"C","type":"组织/机构卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1930年代，1933年后影响显著扩大","place":"德国；新教教会体系","summary":"“德意志基督徒”运动试图把德国新教纳入纳粹民族主义和种族意识形态，推动教会一体化。","fields":[{"label":"标题","value":"纳粹德国德意志基督徒运动"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1930年代，1933年后影响显著扩大"},{"label":"地点","value":"德国；新教教会体系"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"“德意志基督徒”运动试图把德国新教纳入纳粹民族主义和种族意识形态，推动教会一体化。"},{"label":"性质/类型","value":"亲纳粹的新教教会运动和派别。"},{"label":"成立/解散时间","value":"魏玛末期形成，1933年后在纳粹支持下迅速扩张，二战后失去政治基础。"},{"label":"核心目标/宗旨","value":"把新教教会改造成符合纳粹世界观的“民族教会”，强调民族共同体、反犹和对元首国家的顺从。"},{"label":"关键人物","value":"路德维希·穆勒等亲纳粹教会人士。"},{"label":"关键行动/事件","value":"支持建立德国福音教会，推动教会职务中的“雅利安条款”，引发牧师紧急联盟和忏悔教会反对。"},{"label":"为什么重要","value":"它说明纳粹一体化不只针对政党和工会，也试图改写宗教共同体的神学和组织边界。"},{"label":"争议/局限","value":"其把基督教信仰服从种族民族主义的做法引发大量神学反对，也暴露纳粹政权与教会之间的深层冲突。"},{"label":"出处","value":"DHM/LeMO: Deutsche Christen；Encyclopaedia Britannica: Confessing Church；bpb materials on church and National Socialism。"}],"relationItems":["← 前因：纳粹一体化政策","↔ 相关：纳粹德国与梵蒂冈《帝国协约》","→ 后果：德国新教教会斗争","→ 后果：德国忏悔教会"],"relations":[{"text":"← 前因：纳粹一体化政策","id":"extra100"},{"text":"↔ 相关：纳粹德国与梵蒂冈《帝国协约》","id":"extra292"},{"text":"→ 后果：德国新教教会斗争","id":"extra153"},{"text":"→ 后果：德国忏悔教会","id":"extra154"}],"source":"history","id":"extra152"},{"title":"德国新教教会斗争","level":"C","type":"概念/思潮卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1933年后，1930年代持续发展","place":"德国；新教教会体系","summary":"德国新教教会斗争围绕教会是否服从纳粹国家、是否接受种族化神学而展开。","fields":[{"label":"标题","value":"德国新教教会斗争"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1933年后，1930年代持续发展"},{"label":"地点","value":"德国；新教教会体系"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国新教教会斗争围绕教会是否服从纳粹国家、是否接受种族化神学而展开。"},{"label":"核心主张/思路","value":"一方主张教会服从民族国家和纳粹世界观，另一方主张教会不能把福音从属于元首原则和种族政治。"},{"label":"提出者/代表人物（可选）","value":"亲纳粹的“德意志基督徒”；反对方包括马丁·尼莫öller、卡尔·巴特等忏悔教会人物。"},{"label":"它从何而来","value":"纳粹夺权后试图一体化社会组织，新教教会内部原本也存在民族主义、反共和和反犹倾向。"},{"label":"典型表现","value":"德国福音教会重组、教会“雅利安条款”争议、牧师紧急联盟成立、巴门宣言和忏悔教会形成。"},{"label":"为什么重要","value":"它展示纳粹统治下的抵抗不只发生在政党政治中，也发生在信仰、职业伦理和组织自主权内部。"},{"label":"争议/局限","value":"忏悔教会的抵抗主要集中于教会自主和神学原则，并不等同于整体政治反纳粹或系统性保护犹太人。"},{"label":"出处","value":"Encyclopaedia Britannica: Confessing Church；DHM/LeMO: Deutsche Christen；United States Holocaust Memorial Museum: Churches and the Nazi State。"}],"relationItems":["← 前因：纳粹德国德意志基督徒运动","↔ 相关：纳粹一体化政策","→ 后果：德国忏悔教会","↔ 相关：纳粹德国与梵蒂冈《帝国协约》"],"relations":[{"text":"← 前因：纳粹德国德意志基督徒运动","id":"extra152"},{"text":"↔ 相关：纳粹一体化政策","id":"extra100"},{"text":"→ 后果：德国忏悔教会","id":"extra154"},{"text":"↔ 相关：纳粹德国与梵蒂冈《帝国协约》","id":"extra292"}],"source":"history","id":"extra153"},{"title":"德国忏悔教会","level":"B","type":"组织/机构卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1934年形成，纳粹时期持续存在","place":"德国；新教教会网络","summary":"忏悔教会是在纳粹试图控制新教教会时形成的反对派教会运动，但其政治抵抗范围有限。","fields":[{"label":"标题","value":"德国忏悔教会"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1934年形成，纳粹时期持续存在"},{"label":"地点","value":"德国；新教教会网络"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"忏悔教会是在纳粹试图控制新教教会时形成的反对派教会运动，但其政治抵抗范围有限。"},{"label":"性质/类型","value":"德国新教内部反对纳粹教会一体化的教会运动。"},{"label":"成立/解散时间","value":"1933年牧师紧急联盟为前身，1934年巴门会议后形成更明确的忏悔教会。"},{"label":"核心目标/宗旨","value":"维护教会宣讲和组织自主，反对把教会信仰服从于纳粹国家、元首原则和种族化神学。"},{"label":"关键人物","value":"马丁·尼莫öller、卡尔·巴特、迪特里希·朋霍费尔等。"},{"label":"关键行动/事件","value":"牧师紧急联盟、巴门宣言、反对德意志基督徒和帝国教会控制。"},{"label":"为什么重要","value":"它是纳粹德国内部少数具有组织形态的非党派反对力量之一，显示“抵抗”有宗教和伦理维度。"},{"label":"争议/局限","value":"忏悔教会并非整体政治反抗组织，许多成员仍保有民族主义或传统反犹观念，对犹太人迫害的公开抵抗并不一致。"},{"label":"出处","value":"Encyclopaedia Britannica: Confessing Church；DHM/LeMO: Deutsche Christen；USHMM: Churches and the Nazi State。"}],"relationItems":["← 前因：德国新教教会斗争","↔ 相关：纳粹德国德意志基督徒运动","↔ 相关：纳粹一体化政策","→ 后果：巴门宣言"],"relations":[{"text":"← 前因：德国新教教会斗争","id":"extra153"},{"text":"↔ 相关：纳粹德国德意志基督徒运动","id":"extra152"},{"text":"↔ 相关：纳粹一体化政策","id":"extra100"}],"source":"history","id":"extra154"},{"title":"纳粹德国退出一战后国际联盟","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1933年10月宣布，1933年11月公投确认","place":"德国；日内瓦一战后国际联盟体系","summary":"纳粹德国退出一战后国际联盟，把魏玛修约外交转向公开对抗凡尔赛和集体安全体系。","fields":[{"label":"标题","value":"纳粹德国退出一战后国际联盟"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1933年10月宣布，1933年11月公投确认"},{"label":"地点","value":"德国；日内瓦一战后国际联盟体系"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"纳粹德国退出一战后国际联盟，把魏玛修约外交转向公开对抗凡尔赛和集体安全体系。"},{"label":"参与者","value":"阿道夫·希特勒、康斯坦丁·冯·纽赖特、德国政府、一战后国际联盟、德国选民。"},{"label":"发生了什么","value":"德国以裁军会议未能承认德国军备平等为理由，宣布退出日内瓦裁军会议和一战后国际联盟。纳粹随后把退出决定交给全民公投和国会选举包装，制造“民族一致支持”的外观。"},{"label":"为什么重要","value":"它标志纳粹外交不再延续施特雷泽曼式在体系内修约，而是转向以退出、威胁和单边行动争取军备自由。"},{"label":"前因","value":"1932年日内瓦裁军会议虽原则上承认德国平等权利，但具体军备安排迟迟无果，纳粹政权利用这一点宣传德国仍被羞辱。"},{"label":"后果","value":"德国进一步摆脱国际监督，一战后国际联盟难以再用集体安全机制约束德国；之后公开扩军、恢复征兵和莱茵兰再军事化的外交风险门槛明显降低。"},{"label":"出处","value":"German History in Documents and Images: Neurath justifies Germany’s withdrawal from the League of Nations；Library of Congress: Withdrawal of Germany from the League of Nations；Encyclopaedia Britannica: Third Reich, foreign policy context。"}],"relationItems":["← 前因：1932年日内瓦裁军会议德国平权争议","↔ 相关：一战后国际联盟","→ 后果：纳粹德国再武装","→ 后果：德国莱茵兰再军事化"],"relations":[{"text":"← 前因：1932年日内瓦裁军会议德国平权争议","id":"card166"},{"text":"↔ 相关：一战后国际联盟","id":"card4"},{"text":"→ 后果：纳粹德国再武装","id":"extra119"},{"text":"→ 后果：德国莱茵兰再军事化","id":"extra121"}],"source":"history","id":"extra155"},{"title":"纳粹德国《德波互不侵犯条约》","level":"B","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1934年1月26日","place":"德国柏林","summary":"《德波互不侵犯条约》暂时缓和德波关系，削弱法国东方安全体系，也为希特勒塑造和平形象服务。","fields":[{"label":"标题","value":"纳粹德国《德波互不侵犯条约》"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1934年1月26日"},{"label":"地点","value":"德国柏林"},{"label":"主要国家","value":"德国；波兰"},{"label":"一句话概括","value":"《德波互不侵犯条约》暂时缓和德波关系，削弱法国东方安全体系，也为希特勒塑造和平形象服务。"},{"label":"制定方/签署方","value":"纳粹德国政府和波兰第二共和国政府。"},{"label":"主要内容","value":"双方承诺以和平方式处理争端，在一定期限内避免以武力解决两国冲突。"},{"label":"它试图解决什么问题","value":"波兰希望在德国和苏联之间争取外交回旋，德国则希望分化法国同盟体系并降低外界对纳粹扩张的警惕。"},{"label":"为什么重要","value":"它表明希特勒早期外交并非一开始就全面军事冒进，而是会用双边协议拆解对手安全网络。"},{"label":"争议/局限","value":"条约没有解决德国对波兰边界和但泽问题的根本敌意；1939年德国单方面废弃该条约并入侵波兰。"},{"label":"造成的影响","value":"法波关系受到压力，德国获得短期外交声望，欧洲各国对纳粹德国真实意图的判断更加困难。"},{"label":"出处","value":"Encyclopaedia Britannica: German-Polish Nonaggression Pact；Encyclopaedia Britannica: History of Germany, Germany from 1918 to 1945；Encyclopaedia Britannica: Poland, The Second Republic。"}],"relationItems":["← 前因：纳粹德国退出一战后国际联盟","↔ 相关：《凯洛格-白里安公约》","↔ 相关：德苏《柏林条约》","→ 后果：德国入侵波兰"],"relations":[{"text":"← 前因：纳粹德国退出一战后国际联盟","id":"extra155"},{"text":"↔ 相关：《凯洛格-白里安公约》","id":"card22"},{"text":"↔ 相关：德苏《柏林条约》","id":"card141"},{"text":"→ 后果：德国入侵波兰","id":"extra179"}],"source":"history","id":"extra156"},{"title":"纳粹德国《重建帝国法》","level":"B","type":"制度/文本卡","tags":["政治与制度"],"mainTag":"政治与制度","subTag":"","timeText":"1934年1月30日","place":"德国","summary":"《重建帝国法》取消各邦主权，把德国正式推向单一制纳粹国家。","fields":[{"label":"标题","value":"纳粹德国《重建帝国法》"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"时间","value":"1934年1月30日"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"《重建帝国法》取消各邦主权，把德国正式推向单一制纳粹国家。"},{"label":"制定方/签署方","value":"纳粹德国政府。"},{"label":"主要内容","value":"取消各邦作为主权单位的地位，把邦权转移给帝国中央政府，州政府服从中央。"},{"label":"它试图解决什么问题","value":"纳粹要彻底废除魏玛联邦制残余，消除地方自治和邦级政治作为独立权力来源的可能。"},{"label":"为什么重要","value":"这张卡解释纳粹国家结构的转变：德国不是简单由一个强人统治，还是通过法律把联邦制拆成中央集权。"},{"label":"争议/局限","value":"中央集权并不意味着行政秩序清晰，纳粹体制仍充满党、国家、SS和个人权力网络之间的重叠竞争。"},{"label":"造成的影响","value":"各邦政治主权终结，帝国参议院作为联邦代表机构也很快被废除。"},{"label":"出处","value":"DHM/LeMO: Innenpolitik des NS-Regimes；USHMM Holocaust Encyclopedia: Gleichschaltung；DocumentArchiv: Gesetz über den Neuaufbau des Reichs, January 30, 1934。"}],"relationItems":["← 前因：纳粹德国《帝国总督法》","↔ 相关：纳粹一体化政策","→ 后果：纳粹德国废除帝国参议院","↔ 相关：纳粹元首国家"],"relations":[{"text":"← 前因：纳粹德国《帝国总督法》","id":"extra148"},{"text":"↔ 相关：纳粹一体化政策","id":"extra100"},{"text":"→ 后果：纳粹德国废除帝国参议院","id":"extra158"},{"text":"↔ 相关：纳粹元首国家","id":"extra110"}],"source":"history","id":"extra157"},{"title":"纳粹德国废除帝国参议院","level":"C","type":"制度/文本卡","tags":["政治与制度"],"mainTag":"政治与制度","subTag":"","timeText":"1934年2月14日","place":"德国","summary":"废除帝国参议院清除了德国联邦代表机构，使各邦失去最后一层中央制度表达。","fields":[{"label":"标题","value":"纳粹德国废除帝国参议院"},{"label":"分级","value":"C"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"时间","value":"1934年2月14日"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"废除帝国参议院清除了德国联邦代表机构，使各邦失去最后一层中央制度表达。"},{"label":"制定方/签署方","value":"纳粹德国政府。"},{"label":"主要内容","value":"废除代表各邦参与中央立法的帝国参议院。"},{"label":"它试图解决什么问题","value":"在各邦主权被取消后，纳粹中央政府不再需要保留联邦代表机构这一魏玛和帝国时代的制度残余。"},{"label":"为什么重要","value":"它是德国联邦制被清空的具体收尾节点，能帮助用户理解“纳粹一体化”如何落到机构层面。"},{"label":"争议/局限","value":"参议院在纳粹夺权前已被削弱，但其废除仍具有象征意义，标志地方在中央立法中的制度声音消失。"},{"label":"造成的影响","value":"德国中央立法体系进一步集中，地方政治只能通过党大区、帝国总督和行政命令与中央发生关系。"},{"label":"出处","value":"DocumentArchiv: Gesetz über die Aufhebung des Reichsrats, February 14, 1934；DHM/LeMO: Innenpolitik des NS-Regimes；USHMM Holocaust Encyclopedia: Gleichschaltung。"}],"relationItems":["← 前因：纳粹德国《重建帝国法》","↔ 相关：德意志帝国联邦参议院","↔ 相关：魏玛宪法","→ 后果：纳粹元首国家"],"relations":[{"text":"← 前因：纳粹德国《重建帝国法》","id":"extra157"},{"text":"↔ 相关：德意志帝国联邦参议院","id":"extra670"},{"text":"↔ 相关：魏玛宪法","id":"card11"},{"text":"→ 后果：纳粹元首国家","id":"extra110"}],"source":"history","id":"extra158"},{"title":"恩斯特·罗姆","level":"B","type":"人物卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1887—1934年；纳粹运动中活跃于1920年代至1934年","place":"德国；纳粹冲锋队体系","summary":"罗姆是纳粹冲锋队的核心领导者，他的“第二革命”和军队野心最终触发长刀之夜。","fields":[{"label":"标题","value":"恩斯特·罗姆"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1887—1934年；纳粹运动中活跃于1920年代至1934年"},{"label":"地点","value":"德国；纳粹冲锋队体系"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"罗姆是纳粹冲锋队的核心领导者，他的“第二革命”和军队野心最终触发长刀之夜。"},{"label":"生卒年/活跃年代","value":"1887年出生，1934年在长刀之夜中被杀。"},{"label":"身份/职务","value":"纳粹早期成员、冲锋队领导人、退役军官。"},{"label":"关键贡献/作为","value":"重建并扩张SA，使冲锋队成为纳粹街头暴力和群众动员的主要工具；主张把SA纳入或取代传统军队。"},{"label":"核心主张/立场","value":"支持纳粹革命继续推进，强调SA战斗团体的社会和军事地位，要求冲锋队在新国家中获得更大权力。"},{"label":"为什么重要","value":"罗姆解释了纳粹夺权后内部矛盾：希特勒既依靠SA夺权，又必须安抚国防军和保守精英来巩固国家权力。"},{"label":"争议/评价","value":"罗姆不是民主反对派，而是纳粹暴力政治的核心人物；他的被清洗是纳粹内部权力整肃，不是法治恢复。"},{"label":"关联事件","value":"罗姆与纳粹冲锋队激进化；纳粹长刀之夜。"},{"label":"出处","value":"Encyclopaedia Britannica: Third Reich, The Nazi revolution and Night of the Long Knives；DHM/LeMO: SA and Röhm-related materials；USHMM Holocaust Encyclopedia: SA and early Nazi terror。"}],"relationItems":["← 前因：纳粹冲锋队","↔ 相关：罗姆与纳粹冲锋队激进化","→ 后果：纳粹长刀之夜","↔ 相关：德国国防军向希特勒宣誓"],"relations":[{"text":"← 前因：纳粹冲锋队","id":"extra93"},{"text":"↔ 相关：罗姆与纳粹冲锋队激进化","id":"extra95"},{"text":"→ 后果：纳粹长刀之夜","id":"extra108"},{"text":"↔ 相关：德国国防军向希特勒宣誓","id":"extra109"}],"source":"history","id":"extra159"},{"title":"赫尔曼·戈林","level":"A","type":"人物卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1893—1946年；纳粹核心权力期为1933—1945年","place":"德国；普鲁士、柏林、纳粹国家机构","summary":"戈林从普鲁士警察权、盖世太保创建到空军和四年计划，贯穿纳粹国家暴力、军备和经济动员。","fields":[{"label":"标题","value":"赫尔曼·戈林"},{"label":"分级","value":"A"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1893—1946年；纳粹核心权力期为1933—1945年"},{"label":"地点","value":"德国；普鲁士、柏林、纳粹国家机构"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"戈林从普鲁士警察权、盖世太保创建到空军和四年计划，贯穿纳粹国家暴力、军备和经济动员。"},{"label":"生卒年/活跃年代","value":"1893年出生，1946年在纽伦堡审判后自杀。"},{"label":"身份/职务","value":"纳粹领导人、普鲁士部长主席、帝国空军负责人、四年计划负责人。"},{"label":"关键贡献/作为","value":"利用普鲁士内政和警察权打击政治反对派，参与建立盖世太保；推动德国空军建设；1936年后负责四年计划和战争经济准备。"},{"label":"核心主张/立场","value":"忠于希特勒的纳粹权力政治，强调军备、国家干预经济和对反对派的暴力镇压。"},{"label":"为什么重要","value":"戈林是理解纳粹国家早期夺权和后期战争经济的连接人物，既掌握警察暴力，也掌握军备经济资源。"},{"label":"争议/评价","value":"他在纳粹犯罪中负有核心责任，战后纽伦堡审判被判死刑；其个人腐败和奢靡也成为纳粹高层权力腐化的典型。"},{"label":"关联事件","value":"纳粹盖世太保；纳粹德国四年计划；纳粹德国再武装。"},{"label":"出处","value":"Encyclopaedia Britannica: Hermann Göring；Avalon Project/Britannica IMT judgement on Nazi organizations and Göring；Yad Vashem: Hermann Goering。"}],"relationItems":["← 前因：德国国会纵火法令","↔ 相关：纳粹盖世太保","↔ 相关：纳粹德国四年计划","→ 后果：纳粹德国再武装","→ 后果：纳粹战犯纽伦堡审判"],"relations":[{"text":"← 前因：德国国会纵火法令","id":"extra98"},{"text":"↔ 相关：纳粹盖世太保","id":"extra106"},{"text":"↔ 相关：纳粹德国四年计划","id":"extra122"},{"text":"→ 后果：纳粹德国再武装","id":"extra119"},{"text":"→ 后果：纳粹战犯纽伦堡审判","id":"extra6"}],"source":"history","id":"extra160"},{"title":"海因里希·希姆莱","level":"A","type":"人物卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1900—1945年；纳粹核心权力期为1929—1945年","place":"德国及纳粹占领区；SS和警察系统","summary":"希姆莱把SS、警察和集中营系统整合成纳粹恐怖国家核心，是纳粹犹太人大屠杀执行体系的关键组织者。","fields":[{"label":"标题","value":"海因里希·希姆莱"},{"label":"分级","value":"A"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1900—1945年；纳粹核心权力期为1929—1945年"},{"label":"地点","value":"德国及纳粹占领区；SS和警察系统"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"希姆莱把SS、警察和集中营系统整合成纳粹恐怖国家核心，是纳粹犹太人大屠杀执行体系的关键组织者。"},{"label":"生卒年/活跃年代","value":"1900年出生，1945年被盟军俘获后自杀。"},{"label":"身份/职务","value":"党卫队全国领袖，德国警察首脑，内政与安全体系核心人物。"},{"label":"关键贡献/作为","value":"扩张SS，接管和整合政治警察，建立集中营管理体系；战争期间主导种族政策、占领区镇压和犹太人纳粹犹太人大屠杀执行网络。"},{"label":"核心主张/立场","value":"极端种族主义、反犹主义和SS精英秩序观，追求以警察和种族工程重塑国家与社会。"},{"label":"为什么重要","value":"没有希姆莱，就很难理解纳粹德国如何把意识形态仇恨转化为制度化逮捕、驱逐、集中营和灭绝行动。"},{"label":"争议/评价","value":"希姆莱是纳粹国家最核心的犯罪组织者之一；他后期试图与盟军单独接触并不能改变其在纳粹犹太人大屠杀中的责任。"},{"label":"关联事件","value":"纳粹党卫队；纳粹达豪集中营建立；纳粹T4行动；犹太人纳粹犹太人大屠杀。"},{"label":"出处","value":"Encyclopaedia Britannica: Heinrich Himmler；United States Holocaust Memorial Museum: Heinrich Himmler and SS materials；Yad Vashem: Heinrich Himmler。"}],"relationItems":["← 前因：纳粹党卫队","↔ 相关：纳粹盖世太保","↔ 相关：纳粹保护性拘留制度","→ 后果：纳粹犹太人大屠杀","↔ 相关：纳粹T4行动"],"relations":[{"text":"← 前因：纳粹党卫队","id":"extra107"},{"text":"↔ 相关：纳粹盖世太保","id":"extra106"},{"text":"↔ 相关：纳粹保护性拘留制度","id":"extra150"},{"text":"→ 后果：纳粹犹太人大屠杀","id":"extra218"},{"text":"↔ 相关：纳粹T4行动","id":"extra128"}],"source":"history","id":"extra161"},{"title":"纳粹德国元首职位合并","level":"A","type":"事件卡","tags":["政治与制度"],"mainTag":"政治与制度","subTag":"","timeText":"1934年8月1—19日","place":"德国","summary":"兴登堡去世前后，希特勒把总统和总理职位合并为“元首兼帝国总理”，完成个人独裁的制度封顶。","fields":[{"label":"标题","value":"纳粹德国元首职位合并"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"时间","value":"1934年8月1—19日"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"兴登堡去世前后，希特勒把总统和总理职位合并为“元首兼帝国总理”，完成个人独裁的制度封顶。"},{"label":"参与者","value":"阿道夫·希特勒、保罗·冯·兴登堡、纳粹内阁、德国选民、国防军。"},{"label":"发生了什么","value":"1934年8月1日，在兴登堡病危时，纳粹内阁通过法律规定总统职权将在其去世后并入总理职位。8月2日兴登堡去世后，希特勒宣布自己为“元首兼帝国总理”，并取得国家元首、政府首脑和武装力量最高统帅地位。8月19日，纳粹通过公投为这一安排制造民意确认。"},{"label":"为什么重要","value":"它把魏玛宪法中仍可能制衡总理的总统职位消除，使“元首国家”不再只是政治口号，而成为国家权力结构。"},{"label":"前因","value":"长刀之夜清洗SA后，希特勒已得到国防军和保守精英支持；兴登堡的死亡则移除了最后一个具有旧国家合法性的权威人物。"},{"label":"后果","value":"国防军随后向希特勒个人宣誓，德国国家忠诚从宪法和职位转向个人领袖，为战争动员和政治犯罪提供了更强服从链条。"},{"label":"出处","value":"USHMM: Law on the Head of State of the German Reich；Deutschlandmuseum: Hitler acclaimed as “Führer and Reich Chancellor”；Encyclopaedia Britannica: Adolf Hitler。"}],"relationItems":["← 前因：纳粹长刀之夜","← 前因：保罗·冯·兴登堡","→ 后果：德国国防军向希特勒宣誓","↔ 相关：纳粹元首国家"],"relations":[{"text":"← 前因：纳粹长刀之夜","id":"extra108"},{"text":"← 前因：保罗·冯·兴登堡","id":"card37"},{"text":"→ 后果：德国国防军向希特勒宣誓","id":"extra109"},{"text":"↔ 相关：纳粹元首国家","id":"extra110"}],"source":"history","id":"extra162"},{"title":"纳粹德国萨尔公投与回归","level":"B","type":"事件卡","tags":["战争与外交","文化与思想"],"mainTag":"战争与外交","subTag":"文化与思想","timeText":"1935年1月13日公投，1935年3月1日回归德国","place":"萨尔盆地地区","summary":"萨尔公投让一战后由一战后国际联盟管理的萨尔地区回归德国，成为希特勒早期外交和宣传胜利。","fields":[{"label":"标题","value":"纳粹德国萨尔公投与回归"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1935年1月13日公投，1935年3月1日回归德国"},{"label":"地点","value":"萨尔盆地地区"},{"label":"主要国家","value":"德国；法国；一战后国际联盟"},{"label":"一句话概括","value":"萨尔公投让一战后由一战后国际联盟管理的萨尔地区回归德国，成为希特勒早期外交和宣传胜利。"},{"label":"参与者","value":"萨尔地区选民、一战后国际联盟、德国政府、法国政府、萨尔德意志阵线和反纳粹团体。"},{"label":"发生了什么","value":"凡尔赛体系规定萨尔由一战后国际联盟管理十五年，煤矿收益归法国，并在期满后举行公投。1935年1月，选民在“回归德国、留在一战后国际联盟管理、并入法国”之间选择。绝大多数选民支持回归德国，3月萨尔正式并入德意志国。纳粹宣传把结果塑造成民族统一和凡尔赛修正的证明。"},{"label":"为什么重要","value":"这是一项通过国际安排和投票实现的领土回归，帮助希特勒在未开战前积累国内声望。"},{"label":"前因","value":"凡尔赛和约把萨尔置于一战后国际联盟管理，法国获得煤矿利益；纳粹上台后，萨尔回归被纳入反凡尔赛民族宣传。"},{"label":"后果","value":"希特勒获得一次低风险胜利，进一步相信西方在修约问题上倾向让步，为公开再武装和莱茵兰冒险提供政治信心。"},{"label":"出处","value":"German History in Documents and Images: Ballot for the Saarland Referendum；Encyclopaedia Britannica: Third Reich, totalitarian police state；DHM/LeMO: Saarabstimmung 1935。"}],"relationItems":["← 前因：《凡尔赛和约》","↔ 相关：一战后国际联盟","↔ 相关：纳粹宣传机器","→ 后果：纳粹德国恢复征兵"],"relations":[{"text":"← 前因：《凡尔赛和约》","id":"card59"},{"text":"↔ 相关：一战后国际联盟","id":"card4"},{"text":"↔ 相关：纳粹宣传机器","id":"extra94"},{"text":"→ 后果：纳粹德国恢复征兵","id":"extra164"}],"source":"history","id":"extra163"},{"title":"纳粹德国恢复征兵","level":"A","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1935年3月16日","place":"德国","summary":"1935年恢复普遍义务兵役公开违反凡尔赛军备限制，标志纳粹德国再武装从秘密转为公开。","fields":[{"label":"标题","value":"纳粹德国恢复征兵"},{"label":"分级","value":"A"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1935年3月16日"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1935年恢复普遍义务兵役公开违反凡尔赛军备限制，标志纳粹德国再武装从秘密转为公开。"},{"label":"制定方/签署方","value":"纳粹德国政府。"},{"label":"主要内容","value":"宣布恢复普遍义务兵役，把德国陆军扩编为和平时期三十六个师的规模。"},{"label":"它试图解决什么问题","value":"纳粹政权要突破凡尔赛条约对德国军队规模和兵役制度的限制，为未来扩张准备军事基础。"},{"label":"为什么重要","value":"它是纳粹德国公开挑战凡尔赛体系的核心节点，比一般军备扩张更直接地改变欧洲安全格局。"},{"label":"争议/局限","value":"英法虽抗议，但没有采取强制措施；这种有限反应让希特勒更相信单边行动可以获得成功。"},{"label":"造成的影响","value":"德国军队迅速扩张，随后英德海军协定和莱茵兰再军事化进一步削弱战后安全安排。"},{"label":"出处","value":"Encyclopaedia Britannica: Military Service Law；Encyclopaedia Britannica: History of Germany, Germany from 1918 to 1945；DHM/LeMO: Aufrüstung。"}],"relationItems":["← 前因：纳粹德国再武装","← 前因：《凡尔赛和约》","→ 后果：纳粹德国《英德海军协定》","→ 后果：德国莱茵兰再军事化","↔ 相关：纳粹德国空军公开化"],"relations":[{"text":"← 前因：纳粹德国再武装","id":"extra119"},{"text":"← 前因：《凡尔赛和约》","id":"card59"},{"text":"→ 后果：纳粹德国《英德海军协定》","id":"extra120"},{"text":"→ 后果：德国莱茵兰再军事化","id":"extra121"},{"text":"↔ 相关：纳粹德国空军公开化","id":"extra165"}],"source":"history","id":"extra164"},{"title":"纳粹德国空军公开化","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1935年2—3月","place":"德国","summary":"纳粹德国公开承认并组建空军，直接撕开凡尔赛条约对德国军事航空的禁令。","fields":[{"label":"标题","value":"纳粹德国空军公开化"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1935年2—3月"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"纳粹德国公开承认并组建空军，直接撕开凡尔赛条约对德国军事航空的禁令。"},{"label":"参与者","value":"阿道夫·希特勒、赫尔曼·戈林、德国航空部、德国军方和航空工业。"},{"label":"发生了什么","value":"德国在魏玛后期和纳粹初期已通过民航、滑翔训练和秘密合作维持航空能力。1935年，希特勒政权公开宣布德国拥有空军，戈林成为空军建设的核心人物。新空军与再武装、航空工业扩张和战争准备紧密结合。"},{"label":"为什么重要","value":"空军公开化让德国重新获得现代战争关键兵种，也让欧洲各国意识到纳粹德国再武装已不是可以继续遮掩的秘密。"},{"label":"前因","value":"凡尔赛条约禁止德国军事航空，但德国长期通过隐蔽训练和技术积累规避限制；纳粹上台后军备扩张速度明显提高。"},{"label":"后果","value":"德国空军成为后来闪击战和战略轰炸威胁的重要工具，也推动英国等国重新评估空防和绥靖政策风险。"},{"label":"出处","value":"Encyclopaedia Britannica: History of Germany, Germany from 1918 to 1945；History.com: Hitler organizes Luftwaffe；DHM/LeMO: Aufrüstung。"}],"relationItems":["← 前因：纳粹德国再武装","↔ 相关：赫尔曼·戈林","→ 后果：纳粹德国恢复征兵","→ 后果：德国入侵波兰"],"relations":[{"text":"← 前因：纳粹德国再武装","id":"extra119"},{"text":"↔ 相关：赫尔曼·戈林","id":"extra160"},{"text":"→ 后果：纳粹德国恢复征兵","id":"extra164"},{"text":"→ 后果：德国入侵波兰","id":"extra179"}],"source":"history","id":"extra165"},{"title":"纳粹德国犹太企业“雅利安化”","level":"B","type":"概念/思潮卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1933—1939年，1938年后急剧强化","place":"德国及1938年后被纳入纳粹统治的地区","summary":"“雅利安化”通过强迫出售、没收和排除职业，把犹太人的经济财产转移给非犹太德国人和国家。","fields":[{"label":"标题","value":"纳粹德国犹太企业“雅利安化”"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1933—1939年，1938年后急剧强化"},{"label":"地点","value":"德国及1938年后被纳入纳粹统治的地区"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"“雅利安化”通过强迫出售、没收和排除职业，把犹太人的经济财产转移给非犹太德国人和国家。"},{"label":"核心主张/思路","value":"以种族政治为理由，把犹太人从商业、职业和财产所有权中排除，并把财富重新分配给所谓“雅利安”德国人。"},{"label":"提出者/代表人物（可选）","value":"纳粹党、经济部、财政机构、地方党组织、商会和受益企业。"},{"label":"它从何而来","value":"纳粹反犹政策从抵制商店、职业排除和纽伦堡法逐步发展到系统性剥夺经济生存空间。"},{"label":"典型表现","value":"犹太企业被迫低价出售，银行账户和财产受限，职业许可被取消，水晶之夜后剥夺进一步公开化和强制化。"},{"label":"为什么重要","value":"它说明迫害犹太人不只是意识形态和暴力，也包含巨大的财产转移和社会共谋机制。"},{"label":"争议/局限","value":"许多普通德国人、企业和地方机构从中受益，这使纳粹反犹政策获得了制度和利益层面的参与者。"},{"label":"出处","value":"USHMM Holocaust Encyclopedia: Aryanization；DHM/LeMO: Arisierung；Yad Vashem: Aryanization of Jewish property。"}],"relationItems":["← 前因：纳粹1933年抵制犹太商店","← 前因：纳粹纽伦堡法","→ 后果：纳粹德国水晶之夜","↔ 相关：纳粹德国职业公务员法"],"relations":[{"text":"← 前因：纳粹1933年抵制犹太商店","id":"extra111"},{"text":"← 前因：纳粹纽伦堡法","id":"extra114"},{"text":"→ 后果：纳粹德国水晶之夜","id":"extra173"},{"text":"↔ 相关：纳粹德国职业公务员法","id":"extra112"}],"source":"history","id":"extra166"},{"title":"霍斯巴赫备忘录","level":"B","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1937年11月5日会议，11月10日形成记录","place":"德国；柏林帝国总理府","summary":"霍斯巴赫备忘录记录希特勒向军政高层阐述扩张设想，是理解纳粹战争意图的重要文本。","fields":[{"label":"标题","value":"霍斯巴赫备忘录"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1937年11月5日会议，11月10日形成记录"},{"label":"地点","value":"德国；柏林帝国总理府"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"霍斯巴赫备忘录记录希特勒向军政高层阐述扩张设想，是理解纳粹战争意图的重要文本。"},{"label":"制定方/签署方","value":"希特勒军事副官弗里德里希·霍斯巴赫根据会议内容整理。"},{"label":"主要内容","value":"记录希特勒在秘密会议上谈到德国生存空间、武力扩张和对奥地利、捷克斯洛伐克方向的战略设想。"},{"label":"它试图解决什么问题","value":"文本本身不是政策法令，而是保留了纳粹高层讨论战争与扩张时的战略逻辑。"},{"label":"为什么重要","value":"它在纽伦堡审判中成为证明纳粹侵略意图的重要材料，也帮助解释1938年后外交危机为何迅速转向军事压力。"},{"label":"争议/局限","value":"它是会后记录而非逐字速记，学界对它是否等于完整战争蓝图有讨论；但其作为扩张意图证据仍非常关键。"},{"label":"造成的影响","value":"随后布隆贝格-弗里奇事件削弱传统军方高层，德国政策更明显转向奥地利和捷克斯洛伐克方向的冒险。"},{"label":"出处","value":"Avalon Project/Britannica: Hossbach Memorandum；German History in Documents and Images: Hossbach Protocol；International Military Tribunal records。"}],"relationItems":["← 前因：纳粹德国四年计划","↔ 相关：纳粹德国再武装","→ 后果：布隆贝格-弗里奇事件","→ 后果：纳粹德国吞并奥地利"],"relations":[{"text":"← 前因：纳粹德国四年计划","id":"extra122"},{"text":"↔ 相关：纳粹德国再武装","id":"extra119"},{"text":"→ 后果：布隆贝格-弗里奇事件","id":"extra168"},{"text":"→ 后果：纳粹德国吞并奥地利","id":"extra170"}],"source":"history","id":"extra167"},{"title":"布隆贝格-弗里奇事件","level":"B","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1938年1—2月","place":"德国；柏林和国防军高层","summary":"布隆贝格-弗里奇事件清除国防军高层障碍，使希特勒更直接控制战争机器。","fields":[{"label":"标题","value":"布隆贝格-弗里奇事件"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1938年1—2月"},{"label":"地点","value":"德国；柏林和国防军高层"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"布隆贝格-弗里奇事件清除国防军高层障碍，使希特勒更直接控制战争机器。"},{"label":"参与者","value":"维尔纳·冯·布隆贝格、维尔纳·冯·弗里奇、阿道夫·希特勒、赫尔曼·戈林、海因里希·希姆莱、国防军高层。"},{"label":"发生了什么","value":"国防部长布隆贝格因婚姻丑闻被迫辞职，陆军总司令弗里奇又因伪造或操纵的同性恋指控被解除职务。希特勒借机重组军事领导结构，亲自掌握武装力量最高指挥，并建立国防军最高统帅部（OKW）。"},{"label":"为什么重要","value":"这不是普通人事变动，而是传统军方相对独立性被进一步压缩的节点，为1938年后的冒险外交和战争准备扫清障碍。"},{"label":"前因","value":"霍斯巴赫会议后，部分传统军方高层对快速扩张和战争风险保持疑虑；希特勒需要让军事指挥体系更服从个人意志。"},{"label":"后果","value":"希特勒对军队的直接控制增强，传统军方高层更难用制度身份制衡扩张政策；德国很快推进奥地利合并、苏台德危机和对捷克斯洛伐克的压力。"},{"label":"出处","value":"Encyclopaedia Britannica: Third Reich, peaceful annexations；DHM/LeMO: Blomberg-Fritsch-Krise；German History in Documents and Images: Nazi Germany military leadership materials。"}],"relationItems":["← 前因：霍斯巴赫备忘录","↔ 相关：德国国防军向希特勒宣誓","↔ 相关：赫尔曼·戈林","↔ 相关：海因里希·希姆莱","→ 后果：纳粹德国吞并奥地利"],"relations":[{"text":"← 前因：霍斯巴赫备忘录","id":"extra167"},{"text":"↔ 相关：德国国防军向希特勒宣誓","id":"extra109"},{"text":"↔ 相关：赫尔曼·戈林","id":"extra160"},{"text":"↔ 相关：海因里希·希姆莱","id":"extra161"},{"text":"→ 后果：纳粹德国吞并奥地利","id":"extra170"}],"source":"history","id":"extra168"},{"title":"约阿希姆·冯·里宾特洛甫","level":"B","type":"人物卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1893—1946年；任德国外长为1938—1945年","place":"德国及纳粹外交场域","summary":"里宾特洛甫是纳粹后期外交的关键执行者，参与英德海军协定、反共产国际轴心和苏德互不侵犯条约。","fields":[{"label":"标题","value":"约阿希姆·冯·里宾特洛甫"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1893—1946年；任德国外长为1938—1945年"},{"label":"地点","value":"德国及纳粹外交场域"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"里宾特洛甫是纳粹后期外交的关键执行者，参与英德海军协定、反共产国际轴心和苏德互不侵犯条约。"},{"label":"生卒年/活跃年代","value":"1893年出生，1946年在纽伦堡审判后被处决。"},{"label":"身份/职务","value":"纳粹外交官，1938年至1945年任德国外交部长。"},{"label":"关键贡献/作为","value":"早期作为希特勒外交特使参与对英关系和英德海军协定；任外长后执行扩张外交，签署苏德互不侵犯条约。"},{"label":"核心主张/立场","value":"忠于希特勒的侵略性外交路线，倾向用双边交易、威胁和突然转向瓦解对手联盟。"},{"label":"为什么重要","value":"他连接了纳粹德国从“和平修约”外观到侵略战争外交准备的转变。"},{"label":"争议/评价","value":"里宾特洛甫外交能力常被批评，但他在纳粹侵略政策和战争罪责中具有核心责任。"},{"label":"关联事件","value":"英德海军协定；纳粹德国《德波互不侵犯条约》；《苏德互不侵犯条约》。"},{"label":"出处","value":"Encyclopaedia Britannica: Joachim von Ribbentrop；USHMM Holocaust Encyclopedia: Joachim von Ribbentrop；Nuremberg Trial records。"}],"relationItems":["← 前因：纳粹德国《英德海军协定》","↔ 相关：纳粹德国退出一战后国际联盟","→ 后果：纳粹德国与苏联《互不侵犯条约》","↔ 相关：德国入侵波兰"],"relations":[{"text":"← 前因：纳粹德国《英德海军协定》","id":"extra120"},{"text":"↔ 相关：纳粹德国退出一战后国际联盟","id":"extra155"},{"text":"→ 后果：纳粹德国与苏联《互不侵犯条约》","id":"extra177"},{"text":"↔ 相关：德国入侵波兰","id":"extra179"}],"source":"history","id":"extra169"},{"title":"纳粹德国吞并奥地利","level":"A","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1938年3月11—13日","place":"奥地利；德国","summary":"纳粹德国通过威胁、政变压力和军事进入吞并奥地利，公开破坏一战后禁止德奥合并的安排。","fields":[{"label":"标题","value":"纳粹德国吞并奥地利"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1938年3月11—13日"},{"label":"地点","value":"奥地利；德国"},{"label":"主要国家","value":"德国；奥地利"},{"label":"一句话概括","value":"纳粹德国通过威胁、政变压力和军事进入吞并奥地利，公开破坏一战后禁止德奥合并的安排。"},{"label":"参与者","value":"阿道夫·希特勒、库尔特·舒施尼格、阿图尔·赛斯-英夸特、奥地利纳粹、德国国防军、英法等欧洲国家。"},{"label":"发生了什么","value":"希特勒向奥地利总理舒施尼格施压，要求释放并任用奥地利纳粹。舒施尼格试图通过公投抵抗德奥合并，但在德国军事威胁下辞职。赛斯-英夸特上台后，德国军队进入奥地利，纳粹随后宣布奥地利并入德国，并通过受操控的公投确认。"},{"label":"为什么重要","value":"它是希特勒第一次直接吞并一个主权国家，显示西方列强未能阻止纳粹扩张。"},{"label":"前因","value":"德奥合并长期存在民族主义吸引力，但圣日耳曼条约和凡尔赛体系禁止这一安排；1938年军方高层被整肃后，希特勒更敢采取行动。"},{"label":"后果","value":"德国战略位置、人口和资源增强，捷克斯洛伐克从西北和南方都受到更大压力；苏台德问题随即从少数族群争议变成欧洲外交危机。"},{"label":"出处","value":"Encyclopaedia Britannica: Austria, First Republic and the Anschluss；Encyclopaedia Britannica: Third Reich, peaceful annexations；USHMM Holocaust Encyclopedia: Anschluss。"}],"relationItems":["← 前因：布隆贝格-弗里奇事件","← 前因：德奥关税同盟计划","→ 后果：纳粹德国苏台德危机","↔ 相关：纳粹德国犹太企业“雅利安化”"],"relations":[{"text":"← 前因：布隆贝格-弗里奇事件","id":"extra168"},{"text":"← 前因：德奥关税同盟计划","id":"card156"},{"text":"→ 后果：纳粹德国苏台德危机","id":"extra171"},{"text":"↔ 相关：纳粹德国犹太企业“雅利安化”","id":"extra166"}],"source":"history","id":"extra170"},{"title":"纳粹德国苏台德危机","level":"A","type":"事件卡","tags":["战争与外交","文化与思想"],"mainTag":"战争与外交","subTag":"文化与思想","timeText":"1938年春—9月","place":"捷克斯洛伐克苏台德地区；德国；英国；法国","summary":"苏台德危机把民族自决话语、纳粹扩张和英法绥靖推向高潮，欧洲战争风险急剧上升。","fields":[{"label":"标题","value":"纳粹德国苏台德危机"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1938年春—9月"},{"label":"地点","value":"捷克斯洛伐克苏台德地区；德国；英国；法国"},{"label":"主要国家","value":"德国；捷克斯洛伐克；英国；法国"},{"label":"一句话概括","value":"苏台德危机把民族自决话语、纳粹扩张和英法绥靖推向高潮，欧洲战争风险急剧上升。"},{"label":"参与者","value":"阿道夫·希特勒、康拉德·亨莱因、捷克斯洛伐克政府、英国首相张伯伦、法国政府、意大利墨索里尼。"},{"label":"发生了什么","value":"希特勒支持苏台德德意志人党提出自治和民族权利诉求，并不断升级对捷克斯洛伐克的压力。捷克斯洛伐克拥有边防工事和盟约支持，但英法担心战争，倾向迫使其让步。危机经过多轮谈判后走向慕尼黑会议，捷克斯洛伐克本身被排除在关键决策之外。"},{"label":"为什么重要","value":"它说明纳粹扩张不只靠坦克，也靠少数族群问题、外交威胁和对战争恐惧的操纵。"},{"label":"前因","value":"奥地利被吞并后，捷克斯洛伐克在战略上更加孤立；苏台德德意志人问题给希特勒提供了攻击捷克国家的借口。"},{"label":"后果","value":"慕尼黑协定允许德国取得苏台德地区，捷克斯洛伐克边防工事、工业安全和国际地位遭重创；英法绥靖政策在此达到顶点。"},{"label":"出处","value":"Encyclopaedia Britannica: Munich Agreement；Encyclopaedia Britannica: Third Reich, peaceful annexations；German History in Documents and Images: Sudeten crisis materials。"}],"relationItems":["← 前因：纳粹德国吞并奥地利","→ 后果：苏台德危机《慕尼黑协定》","↔ 相关：霍斯巴赫备忘录","↔ 相关：绥靖政策"],"relations":[{"text":"← 前因：纳粹德国吞并奥地利","id":"extra170"},{"text":"→ 后果：苏台德危机《慕尼黑协定》","id":"extra172"},{"text":"↔ 相关：霍斯巴赫备忘录","id":"extra167"}],"source":"history","id":"extra171"},{"title":"苏台德危机《慕尼黑协定》","level":"A","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1938年9月30日","place":"德国慕尼黑","summary":"《慕尼黑协定》允许德国吞并苏台德地区，成为绥靖政策最著名也最具灾难性的象征。","fields":[{"label":"标题","value":"苏台德危机《慕尼黑协定》"},{"label":"分级","value":"A"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1938年9月30日"},{"label":"地点","value":"德国慕尼黑"},{"label":"主要国家","value":"德国；英国；法国；意大利；捷克斯洛伐克"},{"label":"一句话概括","value":"《慕尼黑协定》允许德国吞并苏台德地区，成为绥靖政策最著名也最具灾难性的象征。"},{"label":"制定方/签署方","value":"德国、英国、法国、意大利签署；捷克斯洛伐克没有参与最终谈判。"},{"label":"主要内容","value":"同意捷克斯洛伐克把苏台德地区移交德国，并安排分阶段撤出和占领。"},{"label":"它试图解决什么问题","value":"英法希望通过满足希特勒对苏台德地区的要求来避免欧洲战争，德国则借机摧毁捷克斯洛伐克防线。"},{"label":"为什么重要","value":"它是二战前国际秩序失灵的核心文本，展示大国以牺牲小国方式换取短期和平的后果。"},{"label":"争议/局限","value":"协定没有带来稳定和平，反而鼓励希特勒相信英法会继续退让；捷克斯洛伐克被迫承受战略灾难。"},{"label":"造成的影响","value":"德国取得苏台德地区，捷克斯洛伐克防御体系崩溃；1939年德国继续占领捷克地区，慕尼黑承诺彻底破产。"},{"label":"出处","value":"Encyclopaedia Britannica: Munich Agreement；United States Holocaust Memorial Museum: Munich Agreement；The National Archives: Munich Agreement 1938。"}],"relationItems":["← 前因：纳粹德国苏台德危机","→ 后果：纳粹德国占领捷克地区","↔ 相关：纳粹德国吞并奥地利","↔ 相关：英法对波兰安全保证"],"relations":[{"text":"← 前因：纳粹德国苏台德危机","id":"extra171"},{"text":"→ 后果：纳粹德国占领捷克地区","id":"extra174"},{"text":"↔ 相关：纳粹德国吞并奥地利","id":"extra170"},{"text":"↔ 相关：英法对波兰安全保证","id":"extra175"}],"source":"history","id":"extra172"},{"title":"纳粹德国水晶之夜","level":"A","type":"事件卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1938年11月9—10日","place":"德国、奥地利及纳粹控制地区","summary":"水晶之夜是纳粹政权组织和纵容的大规模反犹暴力，标志反犹迫害从法律排斥转向公开恐怖。","fields":[{"label":"标题","value":"纳粹德国水晶之夜"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1938年11月9—10日"},{"label":"地点","value":"德国、奥地利及纳粹控制地区"},{"label":"主要国家","value":"德国；奥地利"},{"label":"一句话概括","value":"水晶之夜是纳粹政权组织和纵容的大规模反犹暴力，标志反犹迫害从法律排斥转向公开恐怖。"},{"label":"参与者","value":"纳粹党组织、SA、SS、希特勒青年团、德国警察、约瑟夫·戈培尔、犹太社群和普通旁观者。"},{"label":"发生了什么","value":"以德国外交官恩斯特·冯·拉特在巴黎遇刺为借口，纳粹在德国和奥地利发动反犹暴力。犹太商店、住宅和会堂被破坏或焚烧，犹太人遭殴打、杀害和逮捕，大批男性犹太人被送入集中营。政权随后还向犹太社群强加巨额罚款，并加速财产剥夺。"},{"label":"为什么重要","value":"它是纳粹犹太人大屠杀道路上的重大转折，让反犹迫害从制度排除和经济剥夺明显升级为国家支持的群体暴力。"},{"label":"前因","value":"纽伦堡法、职业排除和“雅利安化”已经系统压缩犹太人生存空间，1938年奥地利合并后迫害范围扩大。"},{"label":"后果","value":"犹太人被迫移民的压力急剧增加，财产剥夺和职业排除加速；集中营恐怖与反犹政策更加紧密结合，迫害进入更公开的暴力阶段。"},{"label":"出处","value":"Encyclopaedia Britannica: Kristallnacht；USHMM Holocaust Encyclopedia: Kristallnacht；Yad Vashem: Kristallnacht。"}],"relationItems":["← 前因：纳粹纽伦堡法","← 前因：纳粹德国犹太企业“雅利安化”","→ 后果：纳粹犹太人大屠杀","↔ 相关：纳粹保护性拘留制度"],"relations":[{"text":"← 前因：纳粹纽伦堡法","id":"extra114"},{"text":"← 前因：纳粹德国犹太企业“雅利安化”","id":"extra166"},{"text":"→ 后果：纳粹犹太人大屠杀","id":"extra218"},{"text":"↔ 相关：纳粹保护性拘留制度","id":"extra150"}],"source":"history","id":"extra173"},{"title":"纳粹德国占领捷克地区","level":"A","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1939年3月14—15日","place":"捷克斯洛伐克；波希米亚、摩拉维亚和斯洛伐克","summary":"德国占领捷克地区撕毁慕尼黑承诺，证明纳粹目标已超出德意志民族地区。","fields":[{"label":"标题","value":"纳粹德国占领捷克地区"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1939年3月14—15日"},{"label":"地点","value":"捷克斯洛伐克；波希米亚、摩拉维亚和斯洛伐克"},{"label":"主要国家","value":"德国；捷克斯洛伐克"},{"label":"一句话概括","value":"德国占领捷克地区撕毁慕尼黑承诺，证明纳粹目标已超出德意志民族地区。"},{"label":"参与者","value":"阿道夫·希特勒、埃米尔·哈查、捷克斯洛伐克政府、斯洛伐克政治力量、德国国防军。"},{"label":"发生了什么","value":"慕尼黑协定后，捷克斯洛伐克已经失去边防和战略纵深。1939年3月，希特勒迫使捷克总统哈查接受德国“保护”，德国军队进入布拉格，并建立波希米亚和摩拉维亚保护国。斯洛伐克在德国压力和支持下宣布独立，实际成为德国附庸。"},{"label":"为什么重要","value":"它摧毁了“希特勒只要求德意志人地区”的说法，是英法从绥靖转向对波兰作出安全保证的重要背景。"},{"label":"前因","value":"慕尼黑协定割走苏台德地区后，捷克斯洛伐克失去关键边防工事和战略纵深，国内民族问题也被继续放大；德国因此更容易施压布拉格。"},{"label":"后果","value":"英国和法国对纳粹继续扩张的判断发生变化，认为希特勒并不满足于德意志人地区；波兰问题因此成为下一场欧洲危机的中心。"},{"label":"出处","value":"Encyclopaedia Britannica: Third Reich, peaceful annexations；Encyclopaedia Britannica: Czechoslovak history；USHMM Holocaust Encyclopedia: German occupation of Bohemia and Moravia。"}],"relationItems":["← 前因：苏台德危机《慕尼黑协定》","→ 后果：英法对波兰安全保证","↔ 相关：纳粹德国苏台德危机","↔ 相关：但泽与波兰走廊危机"],"relations":[{"text":"← 前因：苏台德危机《慕尼黑协定》","id":"extra172"},{"text":"→ 后果：英法对波兰安全保证","id":"extra175"},{"text":"↔ 相关：纳粹德国苏台德危机","id":"extra171"},{"text":"↔ 相关：但泽与波兰走廊危机","id":"extra176"}],"source":"history","id":"extra174"},{"title":"英法对波兰安全保证","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1939年3月31日起","place":"英国、法国、波兰和欧洲外交场域","summary":"英法对波兰安全保证标志绥靖政策转向遏制，但也把波兰危机变成欧洲战争触发点。","fields":[{"label":"标题","value":"英法对波兰安全保证"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1939年3月31日起"},{"label":"地点","value":"英国、法国、波兰和欧洲外交场域"},{"label":"主要国家","value":"英国；法国；波兰；德国"},{"label":"一句话概括","value":"英法对波兰安全保证标志绥靖政策转向遏制，但也把波兰危机变成欧洲战争触发点。"},{"label":"参与者","value":"英国政府、法国政府、波兰政府、纳粹德国。"},{"label":"发生了什么","value":"德国占领捷克地区后，英国和法国判断希特勒不会止步于德意志人地区。英国宣布若波兰独立受到威胁将给予援助，法国也延续和强化对波兰的承诺。该保证旨在阻止德国对波兰进一步施压，但并未提供足以即时保卫波兰的军事手段。"},{"label":"为什么重要","value":"它让德国进攻波兰不再只是德波冲突，而会触发德国与英法之间的战争。"},{"label":"前因","value":"慕尼黑协定破产和德国进入布拉格使英法认识到继续让步无法换来稳定；德国随后把但泽和波兰走廊问题推到前台，波兰成为下一个受压目标。"},{"label":"后果","value":"希特勒仍决定对波兰施压，但必须处理苏联可能干预和英法可能参战的问题；这推动德国寻找与苏联临时交易的空间。"},{"label":"出处","value":"Encyclopaedia Britannica: World War II, The war in Europe 1939–41；Encyclopaedia Britannica: Third Reich, peaceful annexations；UK National Archives: Britain and the coming of war。"}],"relationItems":["← 前因：纳粹德国占领捷克地区","↔ 相关：但泽与波兰走廊危机","→ 后果：纳粹德国与苏联《互不侵犯条约》","→ 后果：英法对纳粹德国宣战"],"relations":[{"text":"← 前因：纳粹德国占领捷克地区","id":"extra174"},{"text":"↔ 相关：但泽与波兰走廊危机","id":"extra176"},{"text":"→ 后果：纳粹德国与苏联《互不侵犯条约》","id":"extra177"},{"text":"→ 后果：英法对纳粹德国宣战","id":"extra180"}],"source":"history","id":"extra175"},{"title":"但泽与波兰走廊危机","level":"B","type":"事件卡","tags":["战争与外交","文化与思想"],"mainTag":"战争与外交","subTag":"文化与思想","timeText":"1938年10月—1939年9月","place":"但泽自由市、波兰走廊、德国和波兰","summary":"但泽和波兰走廊问题被希特勒用作对波兰施压的借口，最终成为入侵波兰前的外交焦点。","fields":[{"label":"标题","value":"但泽与波兰走廊危机"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1938年10月—1939年9月"},{"label":"地点","value":"但泽自由市、波兰走廊、德国和波兰"},{"label":"主要国家","value":"德国；波兰"},{"label":"一句话概括","value":"但泽和波兰走廊问题被希特勒用作对波兰施压的借口，最终成为入侵波兰前的外交焦点。"},{"label":"参与者","value":"纳粹德国、波兰第二共和国、但泽自由市、英国、法国。"},{"label":"发生了什么","value":"慕尼黑协定后，德国要求但泽回归德国，并要求修建穿越波兰走廊、连接德国本土和东普鲁士的治外法权公路和铁路。波兰拒绝接受会损害主权的安排。德国宣传把问题包装成纠正凡尔赛边界不公，实际目标则是削弱波兰并为军事行动制造理由。"},{"label":"为什么重要","value":"它把凡尔赛边界遗留问题与纳粹扩张结合起来，是理解德国为什么把波兰作为下一目标的关键。"},{"label":"前因","value":"凡尔赛体系造成但泽自由市和波兰走廊安排，德国民族主义长期把它视为战后羞辱；捷克危机后希特勒转向波兰。"},{"label":"后果","value":"外交谈判破裂后，德国通过苏德互不侵犯条约解决东线顾虑，并用伪造边境事件为入侵制造宣传借口。"},{"label":"出处","value":"Encyclopaedia Britannica: Third Reich, peaceful annexations；Encyclopaedia Britannica: World War II, the war in Europe；German History in Documents and Images: Nazi foreign policy materials。"}],"relationItems":["← 前因：《凡尔赛和约》","← 前因：纳粹德国占领捷克地区","→ 后果：纳粹德国与苏联《互不侵犯条约》","→ 后果：纳粹德国格莱维茨事件"],"relations":[{"text":"← 前因：《凡尔赛和约》","id":"card59"},{"text":"← 前因：纳粹德国占领捷克地区","id":"extra174"},{"text":"→ 后果：纳粹德国与苏联《互不侵犯条约》","id":"extra177"},{"text":"→ 后果：纳粹德国格莱维茨事件","id":"extra178"}],"source":"history","id":"extra176"},{"title":"纳粹德国与苏联《互不侵犯条约》","level":"A","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1939年8月23日签署","place":"苏联莫斯科","summary":"《苏德互不侵犯条约》及秘密议定书划分东欧势力范围，直接打开德国入侵波兰的道路。","fields":[{"label":"标题","value":"纳粹德国与苏联《互不侵犯条约》"},{"label":"分级","value":"A"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1939年8月23日签署"},{"label":"地点","value":"苏联莫斯科"},{"label":"主要国家","value":"德国；苏联；波兰"},{"label":"一句话概括","value":"《苏德互不侵犯条约》及秘密议定书划分东欧势力范围，直接打开德国入侵波兰的道路。"},{"label":"制定方/签署方","value":"德国外长约阿希姆·冯·里宾特洛甫和苏联外长维亚切斯拉夫·莫洛托夫代表两国签署。"},{"label":"主要内容","value":"公开部分规定德苏互不侵犯；秘密议定书划分波兰、波罗的海地区、芬兰和比萨拉比亚等地的势力范围。"},{"label":"它试图解决什么问题","value":"德国希望避免入侵波兰时陷入东西两线压力，苏联则希望争取时间并扩大在东欧的战略空间。"},{"label":"为什么重要","value":"它震动世界政治，把意识形态死敌变成短期交易伙伴，并使波兰在军事上陷入被德苏夹击的处境。"},{"label":"争议/局限","value":"公开条约掩盖了秘密瓜分安排，战后围绕秘密议定书和责任问题长期存在政治争论。"},{"label":"造成的影响","value":"德国很快发动入侵波兰，苏联随后从东部进入波兰，欧洲战争全面爆发。"},{"label":"出处","value":"Encyclopaedia Britannica: German-Soviet Nonaggression Pact；Encyclopaedia Britannica: World War II, the war in Europe；Avalon Project: Nazi-Soviet Relations 1939–1941。"}],"relationItems":["← 前因：英法对波兰安全保证","← 前因：但泽与波兰走廊危机","→ 后果：德国入侵波兰","↔ 相关：约阿希姆·冯·里宾特洛甫"],"relations":[{"text":"← 前因：英法对波兰安全保证","id":"extra175"},{"text":"← 前因：但泽与波兰走廊危机","id":"extra176"},{"text":"→ 后果：德国入侵波兰","id":"extra179"},{"text":"↔ 相关：约阿希姆·冯·里宾特洛甫","id":"extra169"}],"source":"history","id":"extra177"},{"title":"纳粹德国格莱维茨事件","level":"C","type":"事件卡","tags":["战争与外交","文化与思想"],"mainTag":"战争与外交","subTag":"文化与思想","timeText":"1939年8月31日","place":"德国格莱维茨电台；今波兰格利维采","summary":"格莱维茨事件是纳粹伪造的边境袭击，用来为入侵波兰制造宣传借口。","fields":[{"label":"标题","value":"纳粹德国格莱维茨事件"},{"label":"分级","value":"C"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1939年8月31日"},{"label":"地点","value":"德国格莱维茨电台；今波兰格利维采"},{"label":"主要国家","value":"德国；波兰"},{"label":"一句话概括","value":"格莱维茨事件是纳粹伪造的边境袭击，用来为入侵波兰制造宣传借口。"},{"label":"参与者","value":"SS和安全机构人员、莱因哈德·海德里希体系、被杀害并伪装成袭击者的囚犯、德国宣传机构。"},{"label":"发生了什么","value":"德国人员伪装成波兰武装分子袭击格莱维茨电台，并留下尸体作为“证据”。这一行动是更大范围伪旗行动的一部分，旨在让德国公众和国际社会相信波兰先发动挑衅。希特勒随后在战争宣传中声称德国是在回应波兰攻击。"},{"label":"为什么重要","value":"它不是导致战争的真实原因，而是纳粹如何用伪造事件包装侵略战争的典型案例。"},{"label":"前因","value":"德国已决定进攻波兰，但仍需要在宣传上制造“防御性战争”的外观，尤其要把波兰塑造成破坏和平的一方。"},{"label":"后果","value":"次日德国入侵波兰，格莱维茨等伪旗事件被纳粹用来支撑“防御性战争”的开战叙事；但这种宣传没有阻止英法按安全保证作出战争回应。"},{"label":"出处","value":"Encyclopaedia Britannica: World War II, the war in Europe；USHMM Holocaust Encyclopedia: Nazi propaganda and invasion of Poland materials；DHM/LeMO: Überfall auf Polen。"}],"relationItems":["← 前因：但泽与波兰走廊危机","← 前因：纳粹德国与苏联《互不侵犯条约》","→ 后果：德国入侵波兰","↔ 相关：纳粹宣传机器"],"relations":[{"text":"← 前因：但泽与波兰走廊危机","id":"extra176"},{"text":"← 前因：纳粹德国与苏联《互不侵犯条约》","id":"extra177"},{"text":"→ 后果：德国入侵波兰","id":"extra179"},{"text":"↔ 相关：纳粹宣传机器","id":"extra94"}],"source":"history","id":"extra178"},{"title":"德国入侵波兰","level":"S","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1939年9月1日开始","place":"波兰；德国东部边境；但泽和波兰走廊方向","summary":"德国入侵波兰触发英法对德宣战，标志第二次世界大战在欧洲爆发。","fields":[{"label":"标题","value":"德国入侵波兰"},{"label":"分级","value":"S"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1939年9月1日开始"},{"label":"地点","value":"波兰；德国东部边境；但泽和波兰走廊方向"},{"label":"主要国家","value":"德国；波兰；苏联；英国；法国"},{"label":"一句话概括","value":"德国入侵波兰触发英法对德宣战，标志第二次世界大战在欧洲爆发。"},{"label":"参与者","value":"纳粹德国国防军和空军、波兰军队、阿道夫·希特勒、波兰政府、苏联、英国和法国。"},{"label":"发生了什么","value":"1939年9月1日，德国从多个方向进攻波兰，空军和装甲部队配合推进，试图迅速摧毁波兰抵抗。德国以边境挑衅和但泽问题为宣传理由，但实际已通过苏德互不侵犯条约降低苏联干预风险。9月17日，苏联从东部进入波兰，波兰最终被德苏分割占领。"},{"label":"为什么重要","value":"它是世界史坐标级节点：欧洲大战由此爆发，纳粹扩张从外交胁迫和局部吞并进入全面战争阶段。"},{"label":"前因","value":"但泽与波兰走廊危机、英法安全保证和苏德互不侵犯条约共同塑造了开战条件；纳粹已不再满足于以谈判取得领土。"},{"label":"后果","value":"英国和法国对德国宣战，欧洲进入第二次世界大战；波兰被占领后，纳粹暴力统治和种族政策在占领区迅速展开。"},{"label":"出处","value":"Encyclopaedia Britannica: Invasion of Poland；Encyclopaedia Britannica: World War II, the war in Europe 1939–41；DHM/LeMO: Überfall auf Polen。"}],"relationItems":["← 前因：纳粹德国与苏联《互不侵犯条约》","← 前因：纳粹德国格莱维茨事件","→ 后果：英法对纳粹德国宣战","→ 后果：纳粹德国占领波兰","↔ 相关：第二次世界大战在欧洲爆发"],"relations":[{"text":"← 前因：纳粹德国与苏联《互不侵犯条约》","id":"extra177"},{"text":"← 前因：纳粹德国格莱维茨事件","id":"extra178"},{"text":"→ 后果：英法对纳粹德国宣战","id":"extra180"},{"text":"↔ 相关：第二次世界大战在欧洲爆发","id":"extra854"}],"source":"history","id":"extra179"},{"title":"英法对纳粹德国宣战","level":"A","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1939年9月3日","place":"英国、法国、德国和欧洲外交体系","summary":"英法在德国入侵波兰后对德宣战，使波兰战争升级为欧洲大战。","fields":[{"label":"标题","value":"英法对纳粹德国宣战"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1939年9月3日"},{"label":"地点","value":"英国、法国、德国和欧洲外交体系"},{"label":"主要国家","value":"英国；法国；德国；波兰"},{"label":"一句话概括","value":"英法在德国入侵波兰后对德宣战，使波兰战争升级为欧洲大战。"},{"label":"参与者","value":"英国政府、法国政府、纳粹德国、波兰政府、英国国王和议会、法国政府机构。"},{"label":"发生了什么","value":"德国入侵波兰后，英国和法国要求德国停止进攻并撤军。德国没有接受最后通牒，英国和法国于9月3日对德国宣战。虽然英法短期内无法有效阻止波兰被击败，但战争状态已经正式形成。"},{"label":"为什么重要","value":"它说明二战不是德国入侵一国后自动形成的抽象结果，而是英法安全承诺和外交最后通牒转化为国家间战争的制度节点。"},{"label":"前因","value":"英法对波兰作出安全保证后，德国入侵波兰直接触发承诺；慕尼黑协定破产后，英国和法国继续退让的政治空间已经大幅缩小。"},{"label":"后果","value":"欧洲正式进入长期战争状态，但英法短期内无法有效援救波兰，西线初期出现“静坐战”局面；到1940年德国进攻西欧时，战争才迅速升级。"},{"label":"出处","value":"Encyclopaedia Britannica: World War II, the war in Europe 1939–41；UK Parliament and National Archives materials on declaration of war；France 1939 war declaration references。"}],"relationItems":["← 前因：德国入侵波兰","← 前因：英法对波兰安全保证","→ 后果：二战西线“静坐战”","↔ 相关：第二次世界大战在欧洲爆发"],"relations":[{"text":"← 前因：德国入侵波兰","id":"extra179"},{"text":"← 前因：英法对波兰安全保证","id":"extra175"},{"text":"→ 后果：二战西线“静坐战”","id":"extra181"},{"text":"↔ 相关：第二次世界大战在欧洲爆发","id":"extra854"}],"source":"history","id":"extra180"},{"title":"二战西线“静坐战”","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1939年9月—1940年5月","place":"西欧；法国、比利时边境和德国西线","summary":"西线“静坐战”指英法对德宣战后长期缺乏大规模攻势的阶段，为德国集中准备西欧攻势争取时间。","fields":[{"label":"标题","value":"二战西线“静坐战”"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1939年9月—1940年5月"},{"label":"地点","value":"西欧；法国、比利时边境和德国西线"},{"label":"主要国家","value":"德国；英国；法国"},{"label":"一句话概括","value":"西线“静坐战”指英法对德宣战后长期缺乏大规模攻势的阶段，为德国集中准备西欧攻势争取时间。"},{"label":"参与者","value":"德国国防军、英国远征军、法国军队、英国政府、法国政府、纳粹德国。"},{"label":"发生了什么","value":"英法在德国入侵波兰后对德宣战，但西线没有立即发生决定性大战。法国依托马奇诺防线，英国向法国派出远征军，德国则在击败波兰后重新部署和制定西线攻势方案。双方存在侦察、空袭和有限行动，但直到1940年5月德国发动大规模进攻前，整体战局相对停滞。"},{"label":"为什么重要","value":"它解释了为什么波兰迅速失败后欧洲战争没有马上进入全面机动作战，也显示英法战略主动性不足。"},{"label":"前因","value":"英法对波兰安全保证触发宣战，但两国军事计划仍偏重防御、动员和等待德国下一步行动；政治上已进入战争，军事上却未能迅速以西线攻势牵制德国。"},{"label":"后果","value":"德国获得时间整合波兰胜利后的兵力，并准备绕过马奇诺防线的西欧攻势；英法则在心理上低估了德国机动作战速度。"},{"label":"出处","value":"Encyclopaedia Britannica: Phony War；Encyclopaedia Britannica: World War II, the war in Europe 1939–41；Imperial War Museums: The Phoney War。"}],"relationItems":["← 前因：英法对纳粹德国宣战","→ 后果：德国进攻荷兰、比利时和卢森堡","↔ 相关：二战德国入侵法国战役"],"relations":[{"text":"← 前因：英法对纳粹德国宣战","id":"extra180"},{"text":"→ 后果：德国进攻荷兰、比利时和卢森堡","id":"extra189"},{"text":"↔ 相关：二战德国入侵法国战役","id":"extra191"}],"source":"history","id":"extra181"},{"title":"纳粹德国波兰总督府","level":"B","type":"组织/机构卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1939年10月—1945年","place":"德占波兰中部；克拉科夫为行政中心","summary":"波兰总督府是德国在未直接并入帝国的波兰占领区建立的殖民式统治机构。","fields":[{"label":"标题","value":"纳粹德国波兰总督府"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1939年10月—1945年"},{"label":"地点","value":"德占波兰中部；克拉科夫为行政中心"},{"label":"主要国家","value":"德国；波兰"},{"label":"一句话概括","value":"波兰总督府是德国在未直接并入帝国的波兰占领区建立的殖民式统治机构。"},{"label":"性质/类型","value":"德占波兰行政区和殖民统治机构。"},{"label":"成立/解散时间","value":"1939年10月建立，1945年随纳粹德国败退而瓦解。"},{"label":"核心目标/宗旨","value":"控制未并入德国的波兰地区，剥削劳动力和资源，压制波兰政治、教育和文化，并为反犹和种族政策提供行政空间。"},{"label":"关键人物","value":"汉斯·弗兰克。"},{"label":"关键行动/事件","value":"关闭和限制波兰教育文化机构，强迫劳动，配合警察和SS镇压，建立隔都并参与后续犹太人驱逐和灭绝政策。"},{"label":"为什么重要","value":"它说明纳粹占领不是单纯军事占领，而是带有殖民、剥削和种族重组目标的长期统治结构。"},{"label":"争议/局限","value":"总督府行政权与SS、警察、经济机构和军方存在冲突，但这些冲突没有减轻其对波兰社会和犹太人的压迫。"},{"label":"出处","value":"bpb: Die deutsche Politik im Generalgouvernement Polen 1939-1945；USHMM Holocaust Encyclopedia: Invasion of Poland, Fall 1939；Encyclopaedia Britannica: World War II, German-occupied Europe。"}],"relationItems":["← 前因：德国入侵波兰","↔ 相关：汉斯·弗兰克","↔ 相关：纳粹德国波兰知识分子清洗","→ 后果：纳粹建立华沙隔都"],"relations":[{"text":"← 前因：德国入侵波兰","id":"extra179"},{"text":"↔ 相关：汉斯·弗兰克","id":"extra183"},{"text":"↔ 相关：纳粹德国波兰知识分子清洗","id":"extra184"},{"text":"→ 后果：纳粹建立华沙隔都","id":"extra216"}],"source":"history","id":"extra182"},{"title":"汉斯·弗兰克","level":"B","type":"人物卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1900—1946年；任波兰总督府总督为1939—1945年","place":"德国；德占波兰","summary":"汉斯·弗兰克作为波兰总督府总督，是纳粹在波兰殖民统治和反犹政策的重要执行者。","fields":[{"label":"标题","value":"汉斯·弗兰克"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1900—1946年；任波兰总督府总督为1939—1945年"},{"label":"地点","value":"德国；德占波兰"},{"label":"主要国家","value":"德国；波兰"},{"label":"一句话概括","value":"汉斯·弗兰克作为波兰总督府总督，是纳粹在波兰殖民统治和反犹政策的重要执行者。"},{"label":"生卒年/活跃年代","value":"1900年出生，1946年在纽伦堡审判后被处决。"},{"label":"身份/职务","value":"纳粹法学家、希特勒私人律师、波兰总督府总督。"},{"label":"关键贡献/作为","value":"管理德占波兰中部地区，推动对波兰社会的压制、经济剥削和反犹政策；其日记成为战后审判的重要证据。"},{"label":"核心主张/立场","value":"以纳粹种族等级和殖民统治逻辑对待波兰和犹太人，强调德国统治权和对本地社会的剥夺。"},{"label":"为什么重要","value":"他把纳粹意识形态转化为占领区行政日常，是理解德占波兰暴力统治的关键人物。"},{"label":"争议/评价","value":"弗兰克战后在纽伦堡试图表现悔罪，但其行政体系与大规模迫害、剥削和谋杀密切相关。"},{"label":"关联事件","value":"纳粹德国波兰总督府；纳粹建立华沙隔都；犹太人纳粹犹太人大屠杀。"},{"label":"出处","value":"Encyclopaedia Britannica: Hans Frank；bpb: Die deutsche Politik im Generalgouvernement Polen 1939-1945；USHMM Holocaust Encyclopedia: Nazi occupation of Poland materials。"}],"relationItems":["← 前因：德国入侵波兰","↔ 相关：纳粹德国波兰总督府","→ 后果：纳粹战犯纽伦堡审判","↔ 相关：纳粹犹太人大屠杀"],"relations":[{"text":"← 前因：德国入侵波兰","id":"extra179"},{"text":"↔ 相关：纳粹德国波兰总督府","id":"extra182"},{"text":"→ 后果：纳粹战犯纽伦堡审判","id":"extra6"},{"text":"↔ 相关：纳粹犹太人大屠杀","id":"extra218"}],"source":"history","id":"extra183"},{"title":"纳粹德国波兰知识分子清洗","level":"B","type":"事件卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1939—1940年","place":"德占波兰；尤其西部并入区和总督府","summary":"纳粹在德占波兰系统清洗教师、神父、官员和知识分子，意在摧毁波兰社会领导层。","fields":[{"label":"标题","value":"纳粹德国波兰知识分子清洗"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1939—1940年"},{"label":"地点","value":"德占波兰；尤其西部并入区和总督府"},{"label":"主要国家","value":"德国；波兰"},{"label":"一句话概括","value":"纳粹在德占波兰系统清洗教师、神父、官员和知识分子，意在摧毁波兰社会领导层。"},{"label":"参与者","value":"SS、安全警察、SD、特别行动队、德国占领行政机构、波兰知识分子和社会精英。"},{"label":"发生了什么","value":"德国入侵波兰前后，纳粹安全机构准备目标名单，并在占领后逮捕、枪杀或驱逐波兰社会精英。教师、大学人员、神职人员、地方官员、军官和文化人士成为重点对象。行动包括“坦能堡行动”和后续知识分子清洗，旨在让波兰社会失去组织抵抗和文化延续的骨干。"},{"label":"为什么重要","value":"它显示德占波兰暴力从战争初期就具有社会灭绝和殖民统治性质，不只是军事镇压。"},{"label":"前因","value":"纳粹把波兰人视为应被统治和剥削的低等民族，入侵前安全机构已经为占领后的政治和社会清洗做准备。"},{"label":"后果","value":"波兰教育、文化和地方治理遭到重创，社会领导层被有意削弱；地下国家和抵抗运动只能在极端暴力和秘密组织条件下形成。"},{"label":"出处","value":"Institute of National Remembrance: World War II historical view；USHMM: Invasion of Poland, Fall 1939；Encyclopaedia Britannica: World War II, German-occupied Europe。"}],"relationItems":["← 前因：德国入侵波兰","↔ 相关：纳粹德国波兰总督府","↔ 相关：纳粹保护性拘留制度","→ 后果：波兰地下国家"],"relations":[{"text":"← 前因：德国入侵波兰","id":"extra179"},{"text":"↔ 相关：纳粹德国波兰总督府","id":"extra182"},{"text":"↔ 相关：纳粹保护性拘留制度","id":"extra150"}],"source":"history","id":"extra184"},{"title":"纳粹德国特别行动队","level":"A","type":"组织/机构卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1939—1945年；1941年后规模和杀戮范围急剧扩大","place":"德占欧洲；波兰、苏联及其他占领区","summary":"特别行动队是纳粹安全警察和SD的机动杀戮部队，从波兰清洗发展到东线大规模枪杀。","fields":[{"label":"标题","value":"纳粹德国特别行动队"},{"label":"分级","value":"A"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1939—1945年；1941年后规模和杀戮范围急剧扩大"},{"label":"地点","value":"德占欧洲；波兰、苏联及其他占领区"},{"label":"主要国家","value":"德国；波兰；苏联"},{"label":"一句话概括","value":"特别行动队是纳粹安全警察和SD的机动杀戮部队，从波兰清洗发展到东线大规模枪杀。"},{"label":"性质/类型","value":"SS、安全警察和SD体系下的机动特遣队。"},{"label":"成立/解散时间","value":"战前和战争初期形成，二战期间随德军推进在占领区行动，1945年随纳粹失败终结。"},{"label":"核心目标/宗旨","value":"跟随德军进入占领区，逮捕、镇压和杀害被纳粹视为政治、种族或安全威胁的人群。"},{"label":"关键人物","value":"莱因哈德·海德里希、海因里希·希姆莱及各行动队指挥官。"},{"label":"关键行动/事件","value":"1939年在波兰参与清洗波兰精英；1941年入侵苏联后，大规模枪杀犹太人、共产党干部、罗姆人和其他群体。"},{"label":"为什么重要","value":"它是从占领区镇压走向纳粹犹太人大屠杀执行机制的核心组织，说明战争、警察和种族灭绝如何合并。"},{"label":"争议/局限","value":"特别行动队并非孤立行动，常与国防军、地方辅助人员和占领行政合作，这挑战了“普通军队无关犯罪”的说法。"},{"label":"出处","value":"USHMM Holocaust Encyclopedia: Einsatzgruppen；Encyclopaedia Britannica: Einsatzgruppen；Yad Vashem: Einsatzgruppen。"}],"relationItems":["← 前因：纳粹党卫队","← 前因：纳粹德国波兰知识分子清洗","→ 后果：巴比亚尔大屠杀","→ 后果：纳粹犹太人大屠杀","↔ 相关：海因里希·希姆莱"],"relations":[{"text":"← 前因：纳粹党卫队","id":"extra107"},{"text":"← 前因：纳粹德国波兰知识分子清洗","id":"extra184"},{"text":"→ 后果：巴比亚尔大屠杀","id":"extra214"},{"text":"→ 后果：纳粹犹太人大屠杀","id":"extra218"},{"text":"↔ 相关：海因里希·希姆莱","id":"extra161"}],"source":"history","id":"extra185"},{"title":"纳粹德国闪击战","level":"B","type":"概念/思潮卡","tags":["战争与外交","文化与思想"],"mainTag":"战争与外交","subTag":"文化与思想","timeText":"1939—1941年最常被用于描述德国早期战役","place":"欧洲战场；波兰、西欧和苏联初期战役","summary":"闪击战指以速度、突然性、装甲突击和空地协同制造敌方崩溃的机动作战方式。","fields":[{"label":"标题","value":"纳粹德国闪击战"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1939—1941年最常被用于描述德国早期战役"},{"label":"地点","value":"欧洲战场；波兰、西欧和苏联初期战役"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"闪击战指以速度、突然性、装甲突击和空地协同制造敌方崩溃的机动作战方式。"},{"label":"核心主张/思路","value":"集中装甲和机动部队突破关键点，空军压制和扰乱敌后方，使敌军指挥、补给和心理状态迅速失序。"},{"label":"提出者/代表人物（可选）","value":"德国装甲战理论和国防军实战经验相关人物包括海因茨·古德里安等，但“闪击战”并非单一正式 doctrine 名称。"},{"label":"它从何而来","value":"一战堑壕战僵局、战间期机械化理论、无线电指挥、航空兵发展和德国对速胜的战略需求共同塑造了这一战法。"},{"label":"典型表现","value":"波兰战役、法国战役中的阿登突破和早期东线推进常被视为典型案例。"},{"label":"为什么重要","value":"它解释了德国为何能在1940年迅速击败法国，但也提醒用户不要把早期胜利简化成神话化的“无敌战法”。"},{"label":"争议/局限","value":"闪击战成功依赖对手部署、战略突袭和后勤条件；当战线拉长、敌方动员增强时，它的局限迅速显现。"},{"label":"出处","value":"Encyclopaedia Britannica: Blitzkrieg；Encyclopaedia Britannica: Battle of France；Encyclopaedia Britannica: World War II, technology and strategy。"}],"relationItems":["← 前因：纳粹德国再武装","↔ 相关：德国入侵波兰","↔ 相关：德国突破阿登与色当","→ 后果：二战德国入侵法国战役"],"relations":[{"text":"← 前因：纳粹德国再武装","id":"extra119"},{"text":"↔ 相关：德国入侵波兰","id":"extra179"},{"text":"↔ 相关：德国突破阿登与色当","id":"extra190"},{"text":"→ 后果：二战德国入侵法国战役","id":"extra191"}],"source":"history","id":"extra186"},{"title":"德国入侵丹麦和挪威","level":"A","type":"事件卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1940年4月9日—6月10日","place":"丹麦、挪威和北海—北大西洋海域","summary":"德国入侵丹麦和挪威夺取北欧战略通道，保护铁矿运输，并把战争扩大到北海和北大西洋。","fields":[{"label":"标题","value":"德国入侵丹麦和挪威"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1940年4月9日—6月10日"},{"label":"地点","value":"丹麦、挪威和北海—北大西洋海域"},{"label":"主要国家","value":"德国；丹麦；挪威；英国；法国"},{"label":"一句话概括","value":"德国入侵丹麦和挪威夺取北欧战略通道，保护铁矿运输，并把战争扩大到北海和北大西洋。"},{"label":"参与者","value":"德国国防军、德国海军和空军、丹麦政府、挪威政府、英国和法国部队、维德孔·吉斯林。"},{"label":"发生了什么","value":"1940年4月9日，德国突然进攻丹麦和挪威。丹麦因地理和军力劣势很快被迫接受占领，挪威则在王室和政府撤离后继续抵抗，英法也派兵干预。德国最终占领挪威主要港口和交通线，盟军因法国战役压力撤出北欧。"},{"label":"为什么重要","value":"它使德国获得通往北大西洋的基地和对瑞典铁矿运输的保护，同时暴露英国海上战略的压力。"},{"label":"前因","value":"德国担心英国通过挪威威胁铁矿运输和北海通道，英法也在考虑北欧行动；双方战略竞争使中立北欧成为战场。"},{"label":"后果","value":"挪威进入长期占领，吉斯林成为合作主义象征；英国政府因挪威战役失败发生政治危机，丘吉尔随后出任首相。"},{"label":"出处","value":"Encyclopaedia Britannica: 20th-century international relations, World War II 1939-45；Encyclopaedia Britannica: Norway, World War II；Imperial War Museums: Norway Campaign。"}],"relationItems":["← 前因：二战西线“静坐战”","→ 后果：维德孔·吉斯林","↔ 相关：二战德国入侵法国战役","↔ 相关：大西洋战役"],"relations":[{"text":"← 前因：二战西线“静坐战”","id":"extra181"},{"text":"→ 后果：维德孔·吉斯林","id":"extra188"},{"text":"↔ 相关：二战德国入侵法国战役","id":"extra191"},{"text":"↔ 相关：大西洋战役","id":"extra199"}],"source":"history","id":"extra187"},{"title":"维德孔·吉斯林","level":"C","type":"人物卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1887—1945年；纳粹占领挪威时期活跃于1940—1945年","place":"挪威；奥斯陆","summary":"吉斯林在德国入侵挪威时试图夺权，后来成为纳粹扶植的合作政权象征。","fields":[{"label":"标题","value":"维德孔·吉斯林"},{"label":"分级","value":"C"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1887—1945年；纳粹占领挪威时期活跃于1940—1945年"},{"label":"地点","value":"挪威；奥斯陆"},{"label":"主要国家","value":"挪威；德国"},{"label":"一句话概括","value":"吉斯林在德国入侵挪威时试图夺权，后来成为纳粹扶植的合作政权象征。"},{"label":"生卒年/活跃年代","value":"1887年出生，1945年战后被挪威处决。"},{"label":"身份/职务","value":"挪威法西斯政治人物，民族团结党领导人，德占挪威合作政权首脑。"},{"label":"关键贡献/作为","value":"1940年德国入侵当天通过广播宣布夺权，虽初期未获稳定承认，但后来在德国占领体系下担任傀儡政府首脑。"},{"label":"核心主张/立场","value":"亲纳粹、反共、民族主义和威权主义，主张挪威与德国占领秩序合作。"},{"label":"为什么重要","value":"他的姓氏在多国语言中成为“卖国合作者”的代名词，说明二战占领政治不仅有外来征服，也有本土合作。"},{"label":"争议/评价","value":"吉斯林并非德国战略的主导者，但其合作行为在战后被视为叛国典型。"},{"label":"关联事件","value":"德国入侵丹麦和挪威。"},{"label":"出处","value":"Encyclopaedia Britannica: Norway, World War II；Britannica Kids: Vidkun Quisling；Imperial War Museums: Norway Campaign。"}],"relationItems":["← 前因：德国入侵丹麦和挪威","↔ 相关：纳粹一体化政策","→ 后果：战后欧洲合作主义审判","↔ 相关：俗语卡“吉斯林”"],"relations":[{"text":"← 前因：德国入侵丹麦和挪威","id":"extra187"},{"text":"↔ 相关：纳粹一体化政策","id":"extra100"}],"source":"history","id":"extra188"},{"title":"德国进攻荷兰、比利时和卢森堡","level":"A","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1940年5月10日起","place":"荷兰、比利时、卢森堡和西欧战场","summary":"德国进攻低地国家绕开法国正面防线，拉开法国战役和西欧崩溃的序幕。","fields":[{"label":"标题","value":"德国进攻荷兰、比利时和卢森堡"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1940年5月10日起"},{"label":"地点","value":"荷兰、比利时、卢森堡和西欧战场"},{"label":"主要国家","value":"德国；荷兰；比利时；卢森堡；英国；法国"},{"label":"一句话概括","value":"德国进攻低地国家绕开法国正面防线，拉开法国战役和西欧崩溃的序幕。"},{"label":"参与者","value":"德国国防军、荷兰军队、比利时军队、卢森堡、英国远征军、法国军队。"},{"label":"发生了什么","value":"1940年5月10日，德国同时进攻荷兰、比利时和卢森堡。空降兵、装甲部队和空军协同行动，快速夺取关键桥梁、机场和交通节点。盟军按预期向比利时方向移动，却因此更容易被德国在阿登方向的主攻切断。"},{"label":"为什么重要","value":"低地国家进攻不是法国战役的边角，而是德国欺骗和牵制盟军部署的关键环节。"},{"label":"前因","value":"西线“静坐战”期间，德国准备通过低地国家绕过马奇诺防线，迫使英法在不利地形和错误预判下作战。"},{"label":"后果","value":"荷兰很快投降，比利时战线崩溃，英法主力被迫向敦刻尔克方向后撤；法国防御体系失去整体性，德军得以把局部突破转化为战略包围。"},{"label":"出处","value":"Encyclopaedia Britannica: Battle of France；Encyclopaedia Britannica: World War II, the war in Europe 1939–41；Imperial War Museums: Battle of France。"}],"relationItems":["← 前因：二战西线“静坐战”","→ 后果：德国突破阿登与色当","→ 后果：敦刻尔克大撤退","↔ 相关：二战德国入侵法国战役"],"relations":[{"text":"← 前因：二战西线“静坐战”","id":"extra181"},{"text":"→ 后果：德国突破阿登与色当","id":"extra190"},{"text":"→ 后果：敦刻尔克大撤退","id":"extra192"},{"text":"↔ 相关：二战德国入侵法国战役","id":"extra191"}],"source":"history","id":"extra189"},{"title":"德国突破阿登与色当","level":"B","type":"事件卡","tags":["战争与外交"],"mainTag":"战争与外交","subTag":"","timeText":"1940年5月10—15日","place":"阿登地区；法国色当一线","summary":"德国装甲部队穿越阿登并在色当突破，使盟军主力被切断，是法国战役的决定性战术节点。","fields":[{"label":"标题","value":"德国突破阿登与色当"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"时间","value":"1940年5月10—15日"},{"label":"地点","value":"阿登地区；法国色当一线"},{"label":"主要国家","value":"德国；法国；英国；比利时"},{"label":"一句话概括","value":"德国装甲部队穿越阿登并在色当突破，使盟军主力被切断，是法国战役的决定性战术节点。"},{"label":"参与者","value":"德国装甲部队、古德里安等德军将领、法国第二集团军、英国和法国联军。"},{"label":"发生了什么","value":"盟军预期德国主攻会经过比利时北部，低估了阿登森林对大规模装甲部队的可通行性。德军装甲集群穿越阿登，在色当附近强渡默兹河，空军轰炸和快速推进使法国防线崩溃。突破后，德军向英吉利海峡方向推进，切断在比利时方向作战的盟军主力。"},{"label":"为什么重要","value":"它解释了法国战役为什么会从边境攻防迅速变成战略崩溃，是“闪击战”神话背后的具体战场机制。"},{"label":"前因","value":"德国采用穿越阿登的主攻方案，利用盟军对低地国家方向的预判，把主要装甲力量集中在更出乎意料的位置。"},{"label":"后果","value":"盟军北翼被包围风险急剧上升，英国远征军与部分法军被压向海岸；敦刻尔克撤退成为保存人员、避免被全歼的紧急选择。"},{"label":"出处","value":"Encyclopaedia Britannica: Battle of France；Encyclopaedia Britannica: Blitzkrieg；Imperial War Museums: Battle of France。"}],"relationItems":["← 前因：德国进攻荷兰、比利时和卢森堡","↔ 相关：纳粹德国闪击战","→ 后果：敦刻尔克大撤退","→ 后果：二战德国入侵法国战役"],"relations":[{"text":"← 前因：德国进攻荷兰、比利时和卢森堡","id":"extra189"},{"text":"↔ 相关：纳粹德国闪击战","id":"extra186"},{"text":"→ 后果：敦刻尔克大撤退","id":"extra192"},{"text":"→ 后果：二战德国入侵法国战役","id":"extra191"}],"source":"history","id":"extra190"},{"title":"二战德国入侵法国战役","level":"A","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1940年5月10日—6月25日","place":"法国、比利时、荷兰、卢森堡和西欧战场","summary":"德国法国战役在六周内击败法国和低地国家，彻底改变欧洲战争格局。","fields":[{"label":"标题","value":"二战德国入侵法国战役"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1940年5月10日—6月25日"},{"label":"地点","value":"法国、比利时、荷兰、卢森堡和西欧战场"},{"label":"主要国家","value":"德国；法国；英国；比利时；荷兰"},{"label":"一句话概括","value":"德国法国战役在六周内击败法国和低地国家，彻底改变欧洲战争格局。"},{"label":"参与者","value":"德国国防军、法国军队、英国远征军、荷兰和比利时军队、法国政府、纳粹德国。"},{"label":"发生了什么","value":"德国先攻击低地国家牵制盟军主力，再以装甲集群穿越阿登并在色当突破。英法主力被切断后，英军和部分法军从敦刻尔克撤离。随后德军向法国腹地推进，巴黎失守，法国政府请求停战。1940年6月下旬，法国签署停战协定，国家被分为德占区和维希政权控制区。"},{"label":"为什么重要","value":"它让德国从欧洲大陆强国变成西欧霸权，迫使英国独自承受下一阶段德国压力。"},{"label":"前因","value":"西线“静坐战”给德国准备进攻时间，盟军防御思维依赖马奇诺防线和对低地国家方向的预判；德国则把装甲主攻集中到更出人意料的阿登方向。"},{"label":"后果","value":"法国退出主要战斗，英国失去最重要的大陆盟友和前沿基地；德国把压力转向英国本土和海上交通线，不列颠空战和大西洋战役成为下一阶段重点。"},{"label":"出处","value":"Encyclopaedia Britannica: Battle of France；Encyclopaedia Britannica: World War II, the war in Europe 1939–41；Imperial War Museums: Battle of France。"}],"relationItems":["← 前因：二战西线“静坐战”","← 前因：德国突破阿登与色当","→ 后果：二战法国投降与第二次贡比涅停战协定","→ 后果：不列颠空战","↔ 相关：纳粹德国闪击战"],"relations":[{"text":"← 前因：二战西线“静坐战”","id":"extra181"},{"text":"← 前因：德国突破阿登与色当","id":"extra190"},{"text":"→ 后果：二战法国投降与第二次贡比涅停战协定","id":"extra193"},{"text":"→ 后果：不列颠空战","id":"extra196"},{"text":"↔ 相关：纳粹德国闪击战","id":"extra186"}],"source":"history","id":"extra191"},{"title":"敦刻尔克大撤退","level":"A","type":"事件卡","tags":["战争与外交","文化与思想"],"mainTag":"战争与外交","subTag":"文化与思想","timeText":"1940年5月26日—6月4日","place":"法国敦刻尔克及英吉利海峡","summary":"敦刻尔克大撤退从德国包围中撤出三十多万盟军，使英国保住继续作战的核心军力。","fields":[{"label":"标题","value":"敦刻尔克大撤退"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1940年5月26日—6月4日"},{"label":"地点","value":"法国敦刻尔克及英吉利海峡"},{"label":"主要国家","value":"英国；法国；德国"},{"label":"一句话概括","value":"敦刻尔克大撤退从德国包围中撤出三十多万盟军，使英国保住继续作战的核心军力。"},{"label":"参与者","value":"英国远征军、法国军队、德国陆空军、英国皇家海军、民用船只和英国政府。"},{"label":"发生了什么","value":"德国突破西线后，英法主力被压向法国北部海岸。英国组织“发电机行动”，用军舰、商船和大量民用小船把被围部队从敦刻尔克撤回英国。撤退是军事失败中的成功撤离，盟军留下大量装备，但保存了人员。"},{"label":"为什么重要","value":"它避免英国陆军主力被消灭，使英国可以在法国沦陷后继续独立作战。"},{"label":"前因","value":"阿登和色当突破切断了盟军北翼，德国装甲推进至海峡一线，使英法部队被困在法国北部；盟军只能在港口周边寻找撤离机会。"},{"label":"后果","value":"英国获得继续战争的人力基础，虽然丢失大量重装备，但避免了陆军主力覆灭；法国则继续走向停战、占领和政权分裂。"},{"label":"出处","value":"Encyclopaedia Britannica: Dunkirk evacuation；Imperial War Museums: Dunkirk evacuation；UK National Archives: Dunkirk 1940。"}],"relationItems":["← 前因：德国突破阿登与色当","↔ 相关：二战德国入侵法国战役","→ 后果：二战法国投降与第二次贡比涅停战协定","→ 后果：不列颠空战"],"relations":[{"text":"← 前因：德国突破阿登与色当","id":"extra190"},{"text":"↔ 相关：二战德国入侵法国战役","id":"extra191"},{"text":"→ 后果：二战法国投降与第二次贡比涅停战协定","id":"extra193"},{"text":"→ 后果：不列颠空战","id":"extra196"}],"source":"history","id":"extra192"},{"title":"二战法国投降与第二次贡比涅停战协定","level":"A","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1940年6月22日签署，6月25日生效","place":"法国贡比涅森林；法国和德占区","summary":"贡比涅停战协定结束法国战役，把法国分裂为德占区和维希政权控制区。","fields":[{"label":"标题","value":"二战法国投降与第二次贡比涅停战协定"},{"label":"分级","value":"A"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1940年6月22日签署，6月25日生效"},{"label":"地点","value":"法国贡比涅森林；法国和德占区"},{"label":"主要国家","value":"法国；德国"},{"label":"一句话概括","value":"贡比涅停战协定结束法国战役，把法国分裂为德占区和维希政权控制区。"},{"label":"制定方/签署方","value":"纳粹德国与法国第三共和国代表签署，意大利另与法国签署停战。"},{"label":"主要内容","value":"法国停止抵抗，德国占领法国北部和西部关键地区，法国军力受限，维希政府在南部保留一定行政权。"},{"label":"它试图解决什么问题","value":"德国要以停战方式控制法国战略资源和交通，同时避免立即承担全部直接治理成本。"},{"label":"为什么重要","value":"它是欧洲战局的重大转折点，使德国获得法国资源、海岸线和对英国施压的前沿位置。"},{"label":"争议/局限","value":"停战不是和平条约，法国国家主权被严重削弱；维希政权的存在也带来合作、抵抗和合法性争议。"},{"label":"造成的影响","value":"法国第三共和国瓦解，法国维希政权建立，自由法国运动在海外继续抵抗。"},{"label":"出处","value":"Encyclopaedia Britannica: Battle of France；Encyclopaedia Britannica: Vichy France；Avalon Project: Franco-German Armistice, June 22, 1940。"}],"relationItems":["← 前因：二战德国入侵法国战役","→ 后果：法国维希政权","→ 后果：不列颠空战","↔ 相关：敦刻尔克大撤退"],"relations":[{"text":"← 前因：二战德国入侵法国战役","id":"extra191"},{"text":"→ 后果：法国维希政权","id":"extra194"},{"text":"→ 后果：不列颠空战","id":"extra196"},{"text":"↔ 相关：敦刻尔克大撤退","id":"extra192"}],"source":"history","id":"extra193"},{"title":"法国维希政权","level":"B","type":"组织/机构卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1940—1944年","place":"法国维希；法国本土和殖民帝国部分地区","summary":"维希法国是在法国战败后形成的威权合作政权，既保留法国行政外壳，又与德国占领秩序合作。","fields":[{"label":"标题","value":"法国维希政权"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1940—1944年"},{"label":"地点","value":"法国维希；法国本土和殖民帝国部分地区"},{"label":"主要国家","value":"法国；德国"},{"label":"一句话概括","value":"维希法国是在法国战败后形成的威权合作政权，既保留法国行政外壳，又与德国占领秩序合作。"},{"label":"性质/类型","value":"战败后法国国家政权和合作主义威权政府。"},{"label":"成立/解散时间","value":"1940年夏建立，1944年随盟军解放和德国退败而崩溃。"},{"label":"核心目标/宗旨","value":"在战败条件下保留有限法国行政权，同时推行“民族革命”保守威权政策并与德国占领者合作。"},{"label":"关键人物","value":"菲利普·贝当、皮埃尔·赖伐尔。"},{"label":"关键行动/事件","value":"与德国合作管理占领秩序，实施反犹政策，镇压抵抗运动，参与对犹太人的登记、拘押和遣送。"},{"label":"为什么重要","value":"它说明纳粹欧洲秩序不仅靠直接军事占领，也依赖被击败国家内部的合作政权。"},{"label":"争议/局限","value":"维希政权长期以“保护法国”为辩解，但其合作政策在反犹迫害和镇压抵抗方面负有直接责任。"},{"label":"出处","value":"Encyclopaedia Britannica: Vichy France；USHMM Holocaust Encyclopedia: Vichy France；Encyclopaedia Britannica: Philippe Pétain。"}],"relationItems":["← 前因：二战法国投降与第二次贡比涅停战协定","↔ 相关：二战德国入侵法国战役","→ 后果：法国抵抗运动","↔ 相关：纳粹犹太人大屠杀"],"relations":[{"text":"← 前因：二战法国投降与第二次贡比涅停战协定","id":"extra193"},{"text":"↔ 相关：二战德国入侵法国战役","id":"extra191"},{"text":"↔ 相关：纳粹犹太人大屠杀","id":"extra218"}],"source":"history","id":"extra194"},{"title":"德国“海狮计划”","level":"B","type":"制度/文本卡","tags":["战争与外交"],"mainTag":"战争与外交","subTag":"","timeText":"1940年夏秋","place":"德国、英吉利海峡和英国南部方向","summary":"“海狮计划”是德国准备入侵英国的方案，但因未取得制空权而未能实施。","fields":[{"label":"标题","value":"德国“海狮计划”"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"时间","value":"1940年夏秋"},{"label":"地点","value":"德国、英吉利海峡和英国南部方向"},{"label":"主要国家","value":"德国；英国"},{"label":"一句话概括","value":"“海狮计划”是德国准备入侵英国的方案，但因未取得制空权而未能实施。"},{"label":"制定方/签署方","value":"纳粹德国最高统帅部和军种指挥体系，依据希特勒指令准备。"},{"label":"主要内容","value":"计划在英吉利海峡渡海登陆英国南部，前提是德国空军削弱或压制英国皇家空军和海上防御。"},{"label":"它试图解决什么问题","value":"法国战败后，英国继续作战，德国希望通过登陆威胁、空袭和军事准备迫使英国屈服。"},{"label":"为什么重要","value":"它说明不列颠空战不是单纯空军对决，而是德国能否把欧洲大陆胜利转化为对英国本土入侵的前提战。"},{"label":"争议/局限","value":"德国海军登陆能力不足，英国皇家海军仍很强；即使空军取得优势，海狮计划的实际可行性也存在很大疑问。"},{"label":"造成的影响","value":"德国未能实施登陆，战略重点最终转向长期空袭、大西洋战和对苏战争准备。"},{"label":"出处","value":"Encyclopaedia Britannica: Battle of Britain；Imperial War Museums: Operation Sea Lion；Encyclopaedia Britannica: World War II, the Battle of Britain。"}],"relationItems":["← 前因：二战法国投降与第二次贡比涅停战协定","→ 后果：不列颠空战","↔ 相关：赫尔曼·戈林","↔ 相关：二战德国入侵法国战役"],"relations":[{"text":"← 前因：二战法国投降与第二次贡比涅停战协定","id":"extra193"},{"text":"→ 后果：不列颠空战","id":"extra196"},{"text":"↔ 相关：赫尔曼·戈林","id":"extra160"},{"text":"↔ 相关：二战德国入侵法国战役","id":"extra191"}],"source":"history","id":"extra195"},{"title":"不列颠空战","level":"A","type":"事件卡","tags":["战争与外交","文化与思想"],"mainTag":"战争与外交","subTag":"文化与思想","timeText":"1940年7月—10月，空袭压力延续至1941年","place":"英国上空；英吉利海峡和英国南部","summary":"不列颠空战中英国皇家空军抵御德国空军进攻，使德国无法为入侵英国取得制空权。","fields":[{"label":"标题","value":"不列颠空战"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1940年7月—10月，空袭压力延续至1941年"},{"label":"地点","value":"英国上空；英吉利海峡和英国南部"},{"label":"主要国家","value":"英国；德国"},{"label":"一句话概括","value":"不列颠空战中英国皇家空军抵御德国空军进攻，使德国无法为入侵英国取得制空权。"},{"label":"参与者","value":"德国空军、英国皇家空军、赫尔曼·戈林、休·道丁、英国平民和防空体系。"},{"label":"发生了什么","value":"法国战败后，德国空军试图削弱英国皇家空军、机场、雷达和工业目标，为可能的登陆或迫使英国求和创造条件。英国依靠雷达预警、战斗机指挥系统和本土防御持续抵抗。德军后来加强对伦敦等城市轰炸，但未能摧毁英国空防。"},{"label":"为什么重要","value":"这是纳粹德国第一次重大战略失败，保证英国继续作为反德战争基地存在。"},{"label":"前因","value":"法国投降后，英国成为欧洲主要反德力量，德国无法仅凭大陆胜利迫使其求和；若要入侵或迫降英国，德国必须先削弱英国空中防御。"},{"label":"后果","value":"德国推迟并实际放弃海狮计划，英国保住本土防线和海外交通基础；这使英国得以坚持到美国和苏联日后加入反轴心战争。"},{"label":"出处","value":"Encyclopaedia Britannica: Battle of Britain；Imperial War Museums: Battle of Britain；Royal Air Force Museum: Battle of Britain。"}],"relationItems":["← 前因：德国“海狮计划”","← 前因：二战法国投降与第二次贡比涅停战协定","→ 后果：伦敦大轰炸","↔ 相关：赫尔曼·戈林"],"relations":[{"text":"← 前因：德国“海狮计划”","id":"extra195"},{"text":"← 前因：二战法国投降与第二次贡比涅停战协定","id":"extra193"},{"text":"→ 后果：伦敦大轰炸","id":"extra197"},{"text":"↔ 相关：赫尔曼·戈林","id":"extra160"}],"source":"history","id":"extra196"},{"title":"伦敦大轰炸","level":"B","type":"事件卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1940年9月—1941年5月","place":"英国伦敦及其他城市","summary":"伦敦大轰炸是德国对英国城市的持续空袭，试图摧毁士气和工业，却未能迫使英国投降。","fields":[{"label":"标题","value":"伦敦大轰炸"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1940年9月—1941年5月"},{"label":"地点","value":"英国伦敦及其他城市"},{"label":"主要国家","value":"德国；英国"},{"label":"一句话概括","value":"伦敦大轰炸是德国对英国城市的持续空袭，试图摧毁士气和工业，却未能迫使英国投降。"},{"label":"参与者","value":"德国空军、英国政府、英国防空体系、伦敦及其他城市平民。"},{"label":"发生了什么","value":"不列颠空战期间和之后，德国空军把攻击重点从机场和军事目标更多转向伦敦及工业城市。伦敦连续多夜遭轰炸，平民住宅、码头、交通和工业设施遭受破坏。英国政府组织防空、消防、疏散和宣传动员，维持社会运转。"},{"label":"为什么重要","value":"它把战争直接带入城市日常生活，展示现代总体战中平民成为战略目标。"},{"label":"前因","value":"德国空军未能迅速摧毁英国皇家空军和战斗机指挥体系后，转向轰炸城市与工业目标，希望打击英国士气、生产能力并迫使政府谈判。"},{"label":"后果","value":"英国没有屈服，德国空袭未能实现战略目标；但城市轰炸经验深刻影响英国社会记忆和后续盟军战略轰炸观念。"},{"label":"出处","value":"Encyclopaedia Britannica: The Blitz；Imperial War Museums: The Blitz；UK National Archives: The Blitz。"}],"relationItems":["← 前因：不列颠空战","↔ 相关：纳粹宣传机器","→ 后果：盟军战略轰炸德国","↔ 相关：总体战"],"relations":[{"text":"← 前因：不列颠空战","id":"extra196"},{"text":"↔ 相关：纳粹宣传机器","id":"extra94"},{"text":"→ 后果：盟军战略轰炸德国","id":"extra228"}],"source":"history","id":"extra197"},{"title":"轴心国《三国同盟条约》","level":"A","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1940年9月27日","place":"德国柏林","summary":"《三国同盟条约》把德国、意大利和日本的轴心合作正式制度化，扩大了战争的全球联动。","fields":[{"label":"标题","value":"轴心国《三国同盟条约》"},{"label":"分级","value":"A"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1940年9月27日"},{"label":"地点","value":"德国柏林"},{"label":"主要国家","value":"德国；意大利；日本"},{"label":"一句话概括","value":"《三国同盟条约》把德国、意大利和日本的轴心合作正式制度化，扩大了战争的全球联动。"},{"label":"制定方/签署方","value":"德国外长里宾特洛甫、意大利外长齐亚诺、日本代表来栖三郎代表三国签署。"},{"label":"主要内容","value":"三国承认彼此在欧洲和亚洲的主导地位，并承诺若遭尚未参战大国攻击时相互支援。"},{"label":"它试图解决什么问题","value":"轴心国希望通过正式同盟威慑美国等潜在对手，并把欧洲和亚太的扩张战争联系起来。"},{"label":"为什么重要","value":"它让二战不再只是欧洲战争和亚洲战争的平行发展，而具有更明确的全球同盟结构。"},{"label":"争议/局限","value":"三国战略目标并不完全一致，军事协同也有限；但条约在政治和威慑层面具有重要象征与制度作用。"},{"label":"造成的影响","value":"匈牙利、罗马尼亚、保加利亚等国后来加入轴心体系；美国对轴心威胁的判断进一步强化。"},{"label":"出处","value":"Encyclopaedia Britannica: Tripartite Pact；Encyclopaedia Britannica: Empire of Japan, The rise of the Axis；Avalon Project: The Tripartite Pact。"}],"relationItems":["← 前因：德意日《反共产国际协定》","↔ 相关：约阿希姆·冯·里宾特洛甫","→ 后果：轴心国体系","→ 后果：太平洋战争爆发"],"relations":[{"text":"↔ 相关：约阿希姆·冯·里宾特洛甫","id":"extra169"}],"source":"history","id":"extra198"},{"title":"大西洋战役","level":"A","type":"事件卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1939—1945年，1940—1943年尤为关键","place":"北大西洋、英国周边海域、北美至欧洲航线","summary":"大西洋战役是德国潜艇与盟军护航体系围绕海上补给线展开的长期消耗战。","fields":[{"label":"标题","value":"大西洋战役"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1939—1945年，1940—1943年尤为关键"},{"label":"地点","value":"北大西洋、英国周边海域、北美至欧洲航线"},{"label":"主要国家","value":"德国；英国；加拿大；美国"},{"label":"一句话概括","value":"大西洋战役是德国潜艇与盟军护航体系围绕海上补给线展开的长期消耗战。"},{"label":"参与者","value":"德国海军潜艇部队、英国皇家海军、加拿大海军、美国海军、盟军商船队、德国空军和水面舰艇。"},{"label":"发生了什么","value":"德国试图用潜艇、水面袭击舰和飞机切断英国及后来盟军的跨大西洋补给。盟军则发展护航船队、声呐、雷达、远程飞机、护航航母和破译情报来保护运输线。1940年法国沦陷后，德国潜艇获得更靠近大西洋的基地，威胁明显增大；到1943年盟军技术和护航体系逐渐扭转局势。"},{"label":"为什么重要","value":"它决定英国能否继续作战，也决定美国工业和物资能否安全转化为欧洲战场上的军事力量。"},{"label":"前因","value":"法国战败后，德国获得大西洋沿岸基地，潜艇可以更快进入航线；英国又必须依赖海上进口维持战争、工业生产和民生供应。"},{"label":"后果","value":"盟军最终守住运输线，为北非、意大利、诺曼底和对德战略轰炸提供后勤基础；德国潜艇战未能迫使英国屈服。"},{"label":"出处","value":"Encyclopaedia Britannica: Battle of the Atlantic；Encyclopaedia Britannica: Convoy；Imperial War Museums: Battle of the Atlantic。"}],"relationItems":["← 前因：二战法国投降与第二次贡比涅停战协定","↔ 相关：德国潜艇“狼群战术”","↔ 相关：美国《租借法案》","→ 后果：诺曼底登陆"],"relations":[{"text":"← 前因：二战法国投降与第二次贡比涅停战协定","id":"extra193"},{"text":"↔ 相关：德国潜艇“狼群战术”","id":"extra200"},{"text":"↔ 相关：美国《租借法案》","id":"extra201"},{"text":"→ 后果：诺曼底登陆","id":"extra250"}],"source":"history","id":"extra199"},{"title":"德国潜艇“狼群战术”","level":"C","type":"概念/思潮卡","tags":["战争与外交"],"mainTag":"战争与外交","subTag":"","timeText":"二战期间，1940—1943年最典型","place":"北大西洋航线","summary":"狼群战术是德国潜艇集中发现、跟踪并夜间围攻盟军船队的作战方式。","fields":[{"label":"标题","value":"德国潜艇“狼群战术”"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"战争与外交"},{"label":"时间","value":"二战期间，1940—1943年最典型"},{"label":"地点","value":"北大西洋航线"},{"label":"主要国家","value":"德国；英国；加拿大；美国"},{"label":"一句话概括","value":"狼群战术是德国潜艇集中发现、跟踪并夜间围攻盟军船队的作战方式。"},{"label":"核心主张/思路","value":"单艘潜艇发现船队后不立即孤立攻击，而是报告位置、召集多艘潜艇，在夜间或薄弱环节集中袭击。"},{"label":"提出者/代表人物（可选）","value":"德国海军潜艇司令卡尔·邓尼茨。"},{"label":"它从何而来","value":"英国采用护航船队后，单艇猎杀效率下降；德国潜艇部队试图通过协同和集中打击突破护航防御。"},{"label":"典型表现","value":"北大西洋船队遭多艘U艇持续跟踪、攻击和分散护航力量。"},{"label":"为什么重要","value":"它是大西洋战役中德国最具代表性的战术机制，解释了为什么海上运输线一度面临严重危机。"},{"label":"争议/局限","value":"狼群战术依赖无线电通信和情报，一旦盟军雷达、破译和空中巡逻能力提高，潜艇集中反而更容易暴露。"},{"label":"出处","value":"Encyclopaedia Britannica: Convoy；Encyclopaedia Britannica: Battle of the Atlantic；U.S. Naval History and Heritage Command: Battle of the Atlantic materials。"}],"relationItems":["← 前因：大西洋战役","↔ 相关：卡尔·邓尼茨","→ 后果：盟军反潜护航体系"],"relations":[{"text":"← 前因：大西洋战役","id":"extra199"},{"text":"↔ 相关：卡尔·邓尼茨","id":"extra278"}],"source":"history","id":"extra200"},{"title":"美国《租借法案》","level":"A","type":"制度/文本卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1941年3月11日","place":"美国；英国、苏联及其他盟国受援地区","summary":"《租借法案》让美国在正式参战前大规模支援反轴心国家，改变了战争资源格局。","fields":[{"label":"标题","value":"美国《租借法案》"},{"label":"分级","value":"A"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1941年3月11日"},{"label":"地点","value":"美国；英国、苏联及其他盟国受援地区"},{"label":"主要国家","value":"美国；英国；苏联；德国"},{"label":"一句话概括","value":"《租借法案》让美国在正式参战前大规模支援反轴心国家，改变了战争资源格局。"},{"label":"制定方/签署方","value":"美国国会通过，美国总统富兰克林·罗斯福签署。"},{"label":"主要内容","value":"授权美国向被认为对美国防务重要的国家提供武器、物资、食品、车辆和工业资源。"},{"label":"它试图解决什么问题","value":"英国等反轴心国家资金和物资压力巨大，美国又尚未正式参战，需要用法律机制把美国工业能力投入战争。"},{"label":"为什么重要","value":"它把美国从中立旁观推向事实上的反轴心后勤支柱，是世界大战资源力量转折的重要制度节点。"},{"label":"争议/局限","value":"美国国内孤立主义者反对将国家拖入战争；法案本身也不能立即解决运输线安全问题，仍依赖大西洋护航。"},{"label":"造成的影响","value":"英国获得持续支援，德国对美国立场更加敌视；1941年苏德战争爆发后，苏联也成为重要受援对象。"},{"label":"出处","value":"Encyclopaedia Britannica: Lend-Lease Act；U.S. National Archives: Lend-Lease Act；Office of the Historian: Lend-Lease and Military Aid。"}],"relationItems":["← 前因：不列颠空战","↔ 相关：大西洋战役","→ 后果：纳粹德国对美国宣战","↔ 相关：苏德战争"],"relations":[{"text":"← 前因：不列颠空战","id":"extra196"},{"text":"↔ 相关：大西洋战役","id":"extra199"},{"text":"→ 后果：纳粹德国对美国宣战","id":"extra217"}],"source":"history","id":"extra201"},{"title":"纳粹德国非洲军","level":"B","type":"组织/机构卡","tags":["战争与外交"],"mainTag":"战争与外交","subTag":"","timeText":"1941—1943年","place":"北非；利比亚、埃及、突尼斯战场","summary":"纳粹德国非洲军是纳粹德国派往北非支援意大利的机动作战部队，扩大了地中海战争。","fields":[{"label":"标题","value":"纳粹德国非洲军"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"战争与外交"},{"label":"时间","value":"1941—1943年"},{"label":"地点","value":"北非；利比亚、埃及、突尼斯战场"},{"label":"主要国家","value":"德国；意大利；英国"},{"label":"一句话概括","value":"纳粹德国非洲军是纳粹德国派往北非支援意大利的机动作战部队，扩大了地中海战争。"},{"label":"性质/类型","value":"德国陆军远征部队，隶属轴心国北非战场体系。"},{"label":"成立/解散时间","value":"1941年初派往北非，1943年北非轴心部队投降后终结。"},{"label":"核心目标/宗旨","value":"支援意大利在利比亚和埃及方向的战争，保护轴心国在北非的战略位置，并威胁英国在地中海和苏伊士方向的利益。"},{"label":"关键人物","value":"埃尔温·隆美尔。"},{"label":"关键行动/事件","value":"1941年推进至昔兰尼加，围攻托布鲁克；后来参与加扎拉、阿拉曼和突尼斯战役。"},{"label":"为什么重要","value":"它把德国战争从欧洲大陆进一步延伸到地中海和中东门户，也显示德国不得不为盟友失败投入资源。"},{"label":"争议/局限","value":"非洲军战术表现突出，但长期受制于补给线、海空控制和德国战略优先级。"},{"label":"出处","value":"Encyclopaedia Britannica: North Africa campaigns；Encyclopaedia Britannica: Erwin Rommel；Imperial War Museums: The North African Campaign。"}],"relationItems":["← 前因：轴心国《三国同盟条约》","↔ 相关：埃尔温·隆美尔","↔ 相关：北非战役","→ 后果：第二次阿拉曼战役"],"relations":[{"text":"← 前因：轴心国《三国同盟条约》","id":"extra198"},{"text":"↔ 相关：埃尔温·隆美尔","id":"extra203"},{"text":"↔ 相关：北非战役","id":"extra863"},{"text":"→ 后果：第二次阿拉曼战役","id":"extra232"}],"source":"history","id":"extra202"},{"title":"埃尔温·隆美尔","level":"B","type":"人物卡","tags":["战争与外交","文化与思想"],"mainTag":"战争与外交","subTag":"文化与思想","timeText":"1891—1944年；二战高峰为1940—1944年","place":"法国、北非、德国及西线防御体系","summary":"隆美尔因法国战役和北非战场成名，是纳粹德国最具公众形象的将领之一。","fields":[{"label":"标题","value":"埃尔温·隆美尔"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1891—1944年；二战高峰为1940—1944年"},{"label":"地点","value":"法国、北非、德国及西线防御体系"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"隆美尔因法国战役和北非战场成名，是纳粹德国最具公众形象的将领之一。"},{"label":"生卒年/活跃年代","value":"1891年出生，1944年在希特勒逼迫下自杀。"},{"label":"身份/职务","value":"德国陆军将领，曾指挥第7装甲师、纳粹德国非洲军和后来的西线防御部队。"},{"label":"关键贡献/作为","value":"在1940年法国战役中快速推进，1941年后在北非战场机动作战并获得“沙漠之狐”称号；1944年参与西线防御。"},{"label":"核心主张/立场","value":"强调快速机动、前线指挥和战术主动性，但仍是纳粹德国战争机器的重要将领。"},{"label":"为什么重要","value":"隆美尔卡可以帮助区分“战术名将神话”和其所服务的侵略战争结构。"},{"label":"争议/评价","value":"战后隆美尔常被包装为“干净国防军”形象，但这一记忆需要与纳粹战争目标、宣传和其实际角色一起审视。"},{"label":"关联事件","value":"纳粹德国非洲军；北非战役；德国1944年7月20日密谋案。"},{"label":"出处","value":"Encyclopaedia Britannica: Erwin Rommel；Encyclopaedia Britannica: North Africa campaigns；Imperial War Museums: Erwin Rommel materials。"}],"relationItems":["← 前因：二战德国入侵法国战役","↔ 相关：纳粹德国非洲军","→ 后果：德国1944年7月20日密谋案","↔ 相关：纳粹德国闪击战"],"relations":[{"text":"← 前因：二战德国入侵法国战役","id":"extra191"},{"text":"↔ 相关：纳粹德国非洲军","id":"extra202"},{"text":"→ 后果：德国1944年7月20日密谋案","id":"extra254"},{"text":"↔ 相关：纳粹德国闪击战","id":"extra186"}],"source":"history","id":"extra203"},{"title":"德国巴尔干战役","level":"A","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1941年4月6日—6月1日","place":"南斯拉夫、希腊、克里特岛和巴尔干地区","summary":"德国巴尔干战役击败南斯拉夫和希腊，稳住东南欧侧翼，但也占用对苏战争前的时间和资源。","fields":[{"label":"标题","value":"德国巴尔干战役"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1941年4月6日—6月1日"},{"label":"地点","value":"南斯拉夫、希腊、克里特岛和巴尔干地区"},{"label":"主要国家","value":"德国；意大利；南斯拉夫；希腊；英国"},{"label":"一句话概括","value":"德国巴尔干战役击败南斯拉夫和希腊，稳住东南欧侧翼，但也占用对苏战争前的时间和资源。"},{"label":"参与者","value":"德国国防军、德国空军、意大利军队、南斯拉夫军队、希腊军队、英国和英联邦部队。"},{"label":"发生了什么","value":"意大利进攻希腊受挫后，德国准备通过巴尔干支援盟友并保护对苏战争南翼。南斯拉夫加入轴心安排后很快发生政变，德国随即进攻南斯拉夫和希腊。德军轰炸贝尔格莱德，迅速击溃南斯拉夫，并占领希腊本土，随后又攻占克里特岛。"},{"label":"为什么重要","value":"它把巴尔干纳入轴心控制，也让德国在进攻苏联前背上更复杂的占领和反游击压力。"},{"label":"前因","value":"意大利在希腊失败，英国试图在希腊方向建立防线，南斯拉夫政变又使德国担心东南欧侧翼不稳；这些因素都威胁到即将发动的对苏战争准备。"},{"label":"后果","value":"南斯拉夫被肢解，希腊进入轴心占领，德国暂时稳住东南欧侧翼；但巴尔干游击战争长期牵制德国兵力和占领资源。"},{"label":"出处","value":"Encyclopaedia Britannica: World War II, Central Europe and the Balkans 1940–41；Encyclopaedia Britannica: Third Reich, peaceful annexations；Imperial War Museums: Greece and Crete 1941。"}],"relationItems":["← 前因：轴心国《三国同盟条约》","↔ 相关：德国入侵丹麦和挪威","→ 后果：南斯拉夫肢解与克罗地亚独立国","→ 后果：德国入侵苏联“巴巴罗萨行动”"],"relations":[{"text":"← 前因：轴心国《三国同盟条约》","id":"extra198"},{"text":"↔ 相关：德国入侵丹麦和挪威","id":"extra187"},{"text":"→ 后果：南斯拉夫肢解与克罗地亚独立国","id":"extra205"},{"text":"→ 后果：德国入侵苏联“巴巴罗萨行动”","id":"extra209"}],"source":"history","id":"extra204"},{"title":"南斯拉夫肢解与克罗地亚独立国","level":"B","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1941年4月以后","place":"南斯拉夫地区；克罗地亚、波斯尼亚、塞尔维亚等地","summary":"南斯拉夫被轴心国肢解后，克罗地亚独立国成为极端暴力的合作政权和种族迫害中心。","fields":[{"label":"标题","value":"南斯拉夫肢解与克罗地亚独立国"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1941年4月以后"},{"label":"地点","value":"南斯拉夫地区；克罗地亚、波斯尼亚、塞尔维亚等地"},{"label":"主要国家","value":"德国；意大利；克罗地亚；南斯拉夫"},{"label":"一句话概括","value":"南斯拉夫被轴心国肢解后，克罗地亚独立国成为极端暴力的合作政权和种族迫害中心。"},{"label":"参与者","value":"纳粹德国、法西斯意大利、乌斯塔沙、克罗地亚独立国、塞尔维亚人、犹太人、罗姆人和南斯拉夫抵抗力量。"},{"label":"发生了什么","value":"德国和意大利击败南斯拉夫后，将其领土分割给多个轴心国家和附庸政权。克罗地亚独立国在德国和意大利支持下建立，乌斯塔沙政权对塞尔维亚人、犹太人、罗姆人和政治反对者实施大规模迫害和屠杀。"},{"label":"为什么重要","value":"这张卡说明纳粹欧洲秩序会制造本地合作政权，并把种族暴力外包、扩散和地方化。"},{"label":"前因","value":"德国巴尔干战役摧毁南斯拉夫国家结构，轴心国需要低成本控制复杂地区；它们利用地区民族矛盾和本土极右翼力量重组统治。"},{"label":"后果","value":"南斯拉夫陷入占领、内战和游击战争，德国和合作政权的暴力激化族群创伤；战后地区记忆长期围绕合作、抵抗和屠杀展开。"},{"label":"出处","value":"Encyclopaedia Britannica: World War II, Central Europe and the Balkans 1940–41；USHMM Holocaust Encyclopedia: Croatia and Jasenovac materials；Yad Vashem: Croatia during the Holocaust。"}],"relationItems":["← 前因：德国巴尔干战役","↔ 相关：法国维希政权","↔ 相关：纳粹德国特别行动队","→ 后果：南斯拉夫游击战争"],"relations":[{"text":"← 前因：德国巴尔干战役","id":"extra204"},{"text":"↔ 相关：法国维希政权","id":"extra194"},{"text":"↔ 相关：纳粹德国特别行动队","id":"extra185"}],"source":"history","id":"extra205"},{"title":"《巴巴罗萨作战指令第21号》","level":"A","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1940年12月18日","place":"德国；纳粹最高统帅部","summary":"《巴巴罗萨作战指令第21号》正式部署对苏进攻，把德苏战争从设想推进到军事准备。","fields":[{"label":"标题","value":"《巴巴罗萨作战指令第21号》"},{"label":"分级","value":"A"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1940年12月18日"},{"label":"地点","value":"德国；纳粹最高统帅部"},{"label":"主要国家","value":"德国；苏联"},{"label":"一句话概括","value":"《巴巴罗萨作战指令第21号》正式部署对苏进攻，把德苏战争从设想推进到军事准备。"},{"label":"制定方/签署方","value":"阿道夫·希特勒签发，德国最高统帅部和各军种执行。"},{"label":"主要内容","value":"要求德国国防军准备在一次快速战役中击败苏联欧洲部分的主要军事力量，进攻方向包括北方列宁格勒、中央莫斯科和南方乌克兰。"},{"label":"它试图解决什么问题","value":"纳粹德国希望在英国尚未被击败的情况下，通过摧毁苏联获得生存空间、资源和战略主动权。"},{"label":"为什么重要","value":"这是东线战争的制度性起点，连接了希特勒意识形态、军事计划和后来的灭绝性占领政策。"},{"label":"争议/局限","value":"指令假定苏联会迅速崩溃，严重低估地理、后勤、苏联动员能力和长期战争风险。"},{"label":"造成的影响","value":"德国开始大规模调动兵力、制定占领和经济剥夺方案，并在1941年6月发动巴巴罗萨行动。"},{"label":"出处","value":"Avalon Project: Fuehrer Directive No. 21 Operation Barbarossa；Encyclopaedia Britannica: Operation Barbarossa；German History in Documents and Images: Hitler’s Directive No. 21。"}],"relationItems":["← 前因：纳粹德国与苏联《互不侵犯条约》","↔ 相关：霍斯巴赫备忘录","→ 后果：纳粹德国《政委命令》","→ 后果：德国入侵苏联“巴巴罗萨行动”"],"relations":[{"text":"← 前因：纳粹德国与苏联《互不侵犯条约》","id":"extra177"},{"text":"↔ 相关：霍斯巴赫备忘录","id":"extra167"},{"text":"→ 后果：纳粹德国《政委命令》","id":"extra207"},{"text":"→ 后果：德国入侵苏联“巴巴罗萨行动”","id":"extra209"}],"source":"history","id":"extra206"},{"title":"纳粹德国《政委命令》","level":"B","type":"制度/文本卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1941年6月6日","place":"德国及对苏作战区","summary":"《政委命令》要求德军处决被俘苏军政治委员，是东线战争违法和灭绝性质的典型文件。","fields":[{"label":"标题","value":"纳粹德国《政委命令》"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1941年6月6日"},{"label":"地点","value":"德国及对苏作战区"},{"label":"主要国家","value":"德国；苏联"},{"label":"一句话概括","value":"《政委命令》要求德军处决被俘苏军政治委员，是东线战争违法和灭绝性质的典型文件。"},{"label":"制定方/签署方","value":"德国国防军最高统帅部发布，服务于希特勒对苏战争目标。"},{"label":"主要内容","value":"要求德军识别、隔离并处决苏军中的政治委员，认为他们代表“布尔什维克”意识形态威胁。"},{"label":"它试图解决什么问题","value":"纳粹把对苏战争定义为意识形态战争和种族战争，试图在战场上消灭共产党组织和抵抗意志。"},{"label":"为什么重要","value":"它打破常规战争俘虏保护原则，说明国防军并非只是普通军事机构，而参与了犯罪命令执行。"},{"label":"争议/局限","value":"执行程度因单位和战场情况不同而有差异，但命令本身明确把谋杀俘虏制度化。"},{"label":"造成的影响","value":"苏军政治委员和部分战俘遭处决，东线暴力迅速升级，并与特别行动队和占领区屠杀相互衔接。"},{"label":"出处","value":"USHMM Holocaust Encyclopedia: Commissar Order；USHMM Experiencing History: Guidelines for the Treatment of Political Commissars；Yad Vashem: Barbarossa and war of annihilation materials。"}],"relationItems":["← 前因：《巴巴罗萨作战指令第21号》","↔ 相关：纳粹德国特别行动队","→ 后果：德军虐待苏军战俘","→ 后果：德国入侵苏联“巴巴罗萨行动”"],"relations":[{"text":"← 前因：《巴巴罗萨作战指令第21号》","id":"extra206"},{"text":"↔ 相关：纳粹德国特别行动队","id":"extra185"},{"text":"→ 后果：德军虐待苏军战俘","id":"extra211"},{"text":"→ 后果：德国入侵苏联“巴巴罗萨行动”","id":"extra209"}],"source":"history","id":"extra207"},{"title":"纳粹德国饥饿计划","level":"B","type":"概念/思潮卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1941年对苏战争准备和实施阶段","place":"德占苏联地区；德国经济和占领行政体系","summary":"饥饿计划试图把苏联粮食转供德国和军队，预期并接受数百万当地居民饿死。","fields":[{"label":"标题","value":"纳粹德国饥饿计划"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1941年对苏战争准备和实施阶段"},{"label":"地点","value":"德占苏联地区；德国经济和占领行政体系"},{"label":"主要国家","value":"德国；苏联"},{"label":"一句话概括","value":"饥饿计划试图把苏联粮食转供德国和军队，预期并接受数百万当地居民饿死。"},{"label":"核心主张/思路","value":"德军和德国本土应从占领区获取粮食，城市居民、战俘和被视为“多余”的苏联人口可以被牺牲。"},{"label":"提出者/代表人物（可选）","value":"德国经济部门、农业和占领规划人员，相关人物包括赫伯特·巴克等。"},{"label":"它从何而来","value":"德国担心长期战争和英国封锁造成粮食压力，同时纳粹种族殖民思想把东欧人口视为可剥夺对象。"},{"label":"典型表现","value":"从乌克兰等农业区征粮，压低或切断城市、战俘营和被占地区居民供应。"},{"label":"为什么重要","value":"它说明东线战争不是单纯军事占领，而是把经济剥夺和种族政治结合起来的大规模死亡规划。"},{"label":"争议/局限","value":"计划并非完全按原设想机械执行，但德国占领政策确实造成广泛饥饿，特别是苏军战俘和城市居民。"},{"label":"出处","value":"DHM Documentation Centre: Hunger；USHMM: Treatment of Soviet POWs；German Historical Institute references on the Hunger Plan。"}],"relationItems":["← 前因：《巴巴罗萨作战指令第21号》","↔ 相关：德军虐待苏军战俘","↔ 相关：德军围困列宁格勒","→ 后果：纳粹德国东方总计划"],"relations":[{"text":"← 前因：《巴巴罗萨作战指令第21号》","id":"extra206"},{"text":"↔ 相关：德军虐待苏军战俘","id":"extra211"},{"text":"↔ 相关：德军围困列宁格勒","id":"extra212"},{"text":"→ 后果：纳粹德国东方总计划","id":"extra862"}],"source":"history","id":"extra208"},{"title":"德国入侵苏联“巴巴罗萨行动”","level":"S","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1941年6月22日开始","place":"苏联西部；从波罗的海到黑海的东线战场","summary":"巴巴罗萨行动是德国入侵苏联的开端，把欧洲战争转化为规模空前的东线总体战争和灭绝战争。","fields":[{"label":"标题","value":"德国入侵苏联“巴巴罗萨行动”"},{"label":"分级","value":"S"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1941年6月22日开始"},{"label":"地点","value":"苏联西部；从波罗的海到黑海的东线战场"},{"label":"主要国家","value":"德国；苏联"},{"label":"一句话概括","value":"巴巴罗萨行动是德国入侵苏联的开端，把欧洲战争转化为规模空前的东线总体战争和灭绝战争。"},{"label":"参与者","value":"纳粹德国国防军、德国空军、德国盟国部队、苏联红军、苏联政府、特别行动队和占领行政机构。"},{"label":"发生了什么","value":"1941年6月22日，德国和盟国部队沿广大正面突然进攻苏联。北方集团军群指向列宁格勒，中央集团军群指向斯摩棱斯克和莫斯科，南方集团军群指向乌克兰。德军初期推进迅速，包围大量苏军，但未能在冬季前摧毁苏联国家和军队。"},{"label":"为什么重要","value":"这是世界史坐标级节点：它打开二战最大、最血腥的战场，并把纳粹种族灭绝政策推向系统化杀戮。"},{"label":"前因","value":"纳粹长期追求东方“生存空间”，同时希望夺取粮食、石油和战略纵深；德国误判苏联会像法国一样快速崩溃。"},{"label":"后果","value":"苏德战争成为二战欧洲主战场，德国陷入长期消耗；特别行动队、战俘虐待和占领区饥饿政策随军事推进同步展开。"},{"label":"出处","value":"Encyclopaedia Britannica: Operation Barbarossa；Encyclopaedia Britannica: World War II, Invasion of the Soviet Union 1941；USHMM Holocaust Encyclopedia: Operation Barbarossa。"}],"relationItems":["← 前因：《巴巴罗萨作战指令第21号》","← 前因：纳粹德国《政委命令》","→ 后果：德军围困列宁格勒","→ 后果：莫斯科战役","↔ 相关：纳粹德国特别行动队"],"relations":[{"text":"← 前因：《巴巴罗萨作战指令第21号》","id":"extra206"},{"text":"← 前因：纳粹德国《政委命令》","id":"extra207"},{"text":"→ 后果：德军围困列宁格勒","id":"extra212"},{"text":"→ 后果：莫斯科战役","id":"extra215"},{"text":"↔ 相关：纳粹德国特别行动队","id":"extra185"}],"source":"history","id":"extra209"},{"title":"纳粹德国东线灭绝战争","level":"A","type":"概念/思潮卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1941—1945年","place":"苏联、东欧和德占东部地区","summary":"纳粹德国东线灭绝战争指纳粹德国在对苏战争中把军事作战、种族屠杀和殖民剥夺合为一体。","fields":[{"label":"标题","value":"纳粹德国东线灭绝战争"},{"label":"分级","value":"A"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1941—1945年"},{"label":"地点","value":"苏联、东欧和德占东部地区"},{"label":"主要国家","value":"德国；苏联"},{"label":"一句话概括","value":"纳粹德国东线灭绝战争指纳粹德国在对苏战争中把军事作战、种族屠杀和殖民剥夺合为一体。"},{"label":"核心主张/思路","value":"对苏战争不是常规国家战争，而是消灭“布尔什维克”、征服东方土地、剥夺资源并重塑人口结构的战争。"},{"label":"提出者/代表人物（可选）","value":"希特勒、纳粹党、SS、国防军和经济占领规划体系共同推动。"},{"label":"它从何而来","value":"纳粹反共、反犹、种族等级和东方生存空间思想，与德国战争经济需求和军事冒险结合。"},{"label":"典型表现","value":"政委命令、特别行动队枪杀、苏军战俘大规模死亡、饥饿政策、反游击报复和对犹太人的系统性屠杀。"},{"label":"为什么重要","value":"它是理解苏德战争死亡规模和纳粹犹太人大屠杀升级的总框架，不能把东线只看成坦克和战役。"},{"label":"争议/局限","value":"不同机构之间存在执行差异和利益冲突，但这种混乱并不削弱其总体犯罪性质。"},{"label":"出处","value":"USHMM Holocaust Encyclopedia: Operation Barbarossa；Yad Vashem: The Holocaust in the Soviet Union；DHM Documentation Centre: German occupation of Europe。"}],"relationItems":["← 前因：德国入侵苏联“巴巴罗萨行动”","↔ 相关：纳粹德国《政委命令》","↔ 相关：纳粹德国饥饿计划","→ 后果：纳粹犹太人大屠杀"],"relations":[{"text":"← 前因：德国入侵苏联“巴巴罗萨行动”","id":"extra209"},{"text":"↔ 相关：纳粹德国《政委命令》","id":"extra207"},{"text":"↔ 相关：纳粹德国饥饿计划","id":"extra208"},{"text":"→ 后果：纳粹犹太人大屠杀","id":"extra218"}],"source":"history","id":"extra210"},{"title":"德军虐待苏军战俘","level":"A","type":"事件卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1941—1945年；1941—1942年死亡最集中","place":"德占东欧、德国本土和战俘营体系","summary":"德军和纳粹体系对苏军战俘实施饥饿、暴露、强迫劳动和处决，造成数百万死亡。","fields":[{"label":"标题","value":"德军虐待苏军战俘"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1941—1945年；1941—1942年死亡最集中"},{"label":"地点","value":"德占东欧、德国本土和战俘营体系"},{"label":"主要国家","value":"德国；苏联"},{"label":"一句话概括","value":"德军和纳粹体系对苏军战俘实施饥饿、暴露、强迫劳动和处决，造成数百万死亡。"},{"label":"参与者","value":"德国国防军、SS、警察机构、苏军战俘、德国经济和劳工机构。"},{"label":"发生了什么","value":"巴巴罗萨行动后，大批苏军士兵被德国俘虏。德军将他们关押在临时营地或战俘营，供应严重不足，许多人死于饥饿、疾病、寒冷、枪杀和强迫劳动。纳粹还筛选并处决政治委员、犹太人和被视为危险的战俘。"},{"label":"为什么重要","value":"它揭示国防军在东线犯罪中的直接责任，也说明纳粹种族战争并非只针对平民犹太人。"},{"label":"前因","value":"纳粹把苏联士兵视为意识形态和种族敌人，且不愿为大量俘虏投入粮食和设施；政委命令和饥饿计划都使正常战俘保护被系统破坏。"},{"label":"后果","value":"苏军战俘死亡成为东线最大规模战争罪之一，幸存者又常被投入强迫劳动；这种待遇加深苏德战争的残酷性和报复循环。"},{"label":"出处","value":"USHMM Holocaust Encyclopedia: The Treatment of Soviet POWs；DHM Documentation Centre: Hunger；Yad Vashem: Soviet POWs。"}],"relationItems":["← 前因：德国入侵苏联“巴巴罗萨行动”","← 前因：纳粹德国《政委命令》","↔ 相关：纳粹德国饥饿计划","↔ 相关：纳粹德国东线灭绝战争"],"relations":[{"text":"← 前因：德国入侵苏联“巴巴罗萨行动”","id":"extra209"},{"text":"← 前因：纳粹德国《政委命令》","id":"extra207"},{"text":"↔ 相关：纳粹德国饥饿计划","id":"extra208"},{"text":"↔ 相关：纳粹德国东线灭绝战争","id":"extra210"}],"source":"history","id":"extra211"},{"title":"德军围困列宁格勒","level":"A","type":"事件卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1941年9月8日—1944年1月27日","place":"苏联列宁格勒；今俄罗斯圣彼得堡","summary":"列宁格勒围困是二战中最惨烈的城市围困之一，饥饿和炮轰造成巨大平民死亡。","fields":[{"label":"标题","value":"德军围困列宁格勒"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1941年9月8日—1944年1月27日"},{"label":"地点","value":"苏联列宁格勒；今俄罗斯圣彼得堡"},{"label":"主要国家","value":"德国；苏联；芬兰"},{"label":"一句话概括","value":"列宁格勒围困是二战中最惨烈的城市围困之一，饥饿和炮轰造成巨大平民死亡。"},{"label":"参与者","value":"德国北方集团军群、芬兰军队、苏联红军、列宁格勒市民、苏联地方和中央政府。"},{"label":"发生了什么","value":"巴巴罗萨行动后，德军向列宁格勒推进，并在1941年9月切断城市与外部的主要陆路联系。德军没有立即强攻市区，而是围困、炮轰并试图通过饥饿摧毁城市。苏联通过拉多加湖“生命之路”等方式维持有限补给和疏散，围困持续近三年。"},{"label":"为什么重要","value":"它展示东线战争中城市平民如何成为战略目标，也是纳粹饥饿政策和总体战暴力的代表。"},{"label":"前因","value":"德国计划摧毁苏联北方政治、工业和象征中心，而不是单纯占领城市；芬兰参战又使列宁格勒北部压力增大，城市更容易被封锁。"},{"label":"后果","value":"大量平民死于饥饿、寒冷和炮轰，但城市没有投降；列宁格勒成为苏联抵抗记忆的重要象征，也成为纳粹围困政策的犯罪证据。"},{"label":"出处","value":"Encyclopaedia Britannica: St. Petersburg, The Soviet period；History.com: Siege of Leningrad；DHM Documentation Centre: Hunger。"}],"relationItems":["← 前因：德国入侵苏联“巴巴罗萨行动”","↔ 相关：纳粹德国饥饿计划","↔ 相关：纳粹德国东线灭绝战争","→ 后果：苏联红军战略反攻"],"relations":[{"text":"← 前因：德国入侵苏联“巴巴罗萨行动”","id":"extra209"},{"text":"↔ 相关：纳粹德国饥饿计划","id":"extra208"},{"text":"↔ 相关：纳粹德国东线灭绝战争","id":"extra210"},{"text":"→ 后果：苏联红军战略反攻","id":"extra856"}],"source":"history","id":"extra212"},{"title":"基辅包围战","level":"B","type":"事件卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1941年8—9月","place":"苏联乌克兰；基辅及周边地区","summary":"基辅包围战是德军1941年南线巨大包围胜利，但也使进攻莫斯科的时间和资源发生调整。","fields":[{"label":"标题","value":"基辅包围战"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1941年8—9月"},{"label":"地点","value":"苏联乌克兰；基辅及周边地区"},{"label":"主要国家","value":"德国；苏联"},{"label":"一句话概括","value":"基辅包围战是德军1941年南线巨大包围胜利，但也使进攻莫斯科的时间和资源发生调整。"},{"label":"参与者","value":"德国南方集团军群、中央集团军群部分装甲力量、苏联西南方面军、德国空军。"},{"label":"发生了什么","value":"巴巴罗萨行动中，德军南线推进到乌克兰。希特勒决定把中央方向部分装甲力量南调，与南方集团军群合围基辅附近苏军。大量苏军被俘或歼灭，基辅失守。德国获得重大战术和战役胜利，但中央方向对莫斯科的攻势被推迟。"},{"label":"为什么重要","value":"它说明德国1941年战略目标在摧毁苏军、夺取资源和攻向莫斯科之间摇摆。"},{"label":"前因","value":"德军南线希望夺取乌克兰粮食、工业和交通枢纽，希特勒也重视南方资源目标；苏军在基辅方向仍保有大量兵力，使德军选择大规模合围。"},{"label":"后果","value":"乌克兰大部落入德国控制，巴比亚尔等大规模屠杀很快发生；德国随后转向莫斯科方向时已接近秋冬。"},{"label":"出处","value":"Encyclopaedia Britannica: World War II, Invasion of the Soviet Union 1941；Encyclopaedia Britannica: Battle of Moscow；USHMM: Babi Yar materials。"}],"relationItems":["← 前因：德国入侵苏联“巴巴罗萨行动”","↔ 相关：纳粹德国饥饿计划","→ 后果：巴比亚尔大屠杀","→ 后果：莫斯科战役"],"relations":[{"text":"← 前因：德国入侵苏联“巴巴罗萨行动”","id":"extra209"},{"text":"↔ 相关：纳粹德国饥饿计划","id":"extra208"},{"text":"→ 后果：巴比亚尔大屠杀","id":"extra214"},{"text":"→ 后果：莫斯科战役","id":"extra215"}],"source":"history","id":"extra213"},{"title":"巴比亚尔大屠杀","level":"A","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1941年9月29—30日","place":"苏联乌克兰基辅附近巴比亚尔 ravine","summary":"巴比亚尔大屠杀中，德军、SS和辅助力量在两天内枪杀三万多名基辅犹太人。","fields":[{"label":"标题","value":"巴比亚尔大屠杀"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1941年9月29—30日"},{"label":"地点","value":"苏联乌克兰基辅附近巴比亚尔 ravine"},{"label":"主要国家","value":"德国；苏联；乌克兰"},{"label":"一句话概括","value":"巴比亚尔大屠杀中，德军、SS和辅助力量在两天内枪杀三万多名基辅犹太人。"},{"label":"参与者","value":"特别行动队C下属单位、德国警察和SS、国防军占领机构、当地辅助人员、基辅犹太居民。"},{"label":"发生了什么","value":"德军占领基辅后，纳粹发布命令要求犹太人集合。受害者被带到巴比亚尔 ravine，交出财物和衣物后被分批枪杀。9月29日至30日，三万多名犹太人在该地遇害；之后巴比亚尔还继续成为杀害罗姆人、苏军战俘和其他受害者的地点。"},{"label":"为什么重要","value":"它是纳粹犹太人大屠杀“子弹屠杀”阶段的标志性事件，显示德国入侵苏联后反犹政策如何迅速转为大规模现场杀戮。"},{"label":"前因","value":"巴巴罗萨行动后，特别行动队跟随德军进入苏联占领区，纳粹把犹太人和“布尔什维克敌人”绑定为清除对象。"},{"label":"后果","value":"东欧占领区枪杀规模持续扩大，地方犹太社群被迅速摧毁；纳粹逐步走向更系统化、跨区域组织的“最终解决”政策。"},{"label":"出处","value":"USHMM Holocaust Encyclopedia: Kiev and Babi Yar；USHMM tag: Babyn Yar；Yad Vashem: Babi Yar。"}],"relationItems":["← 前因：基辅包围战","← 前因：纳粹德国特别行动队","→ 后果：纳粹犹太人大屠杀","↔ 相关：纳粹德国东线灭绝战争"],"relations":[{"text":"← 前因：基辅包围战","id":"extra213"},{"text":"← 前因：纳粹德国特别行动队","id":"extra185"},{"text":"→ 后果：纳粹犹太人大屠杀","id":"extra218"},{"text":"↔ 相关：纳粹德国东线灭绝战争","id":"extra210"}],"source":"history","id":"extra214"},{"title":"莫斯科战役","level":"A","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1941年9月30日—1942年1月7日","place":"苏联莫斯科及周边地区","summary":"莫斯科战役中德军未能夺取苏联首都，巴巴罗萨速胜设想破产。","fields":[{"label":"标题","value":"莫斯科战役"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1941年9月30日—1942年1月7日"},{"label":"地点","value":"苏联莫斯科及周边地区"},{"label":"主要国家","value":"德国；苏联"},{"label":"一句话概括","value":"莫斯科战役中德军未能夺取苏联首都，巴巴罗萨速胜设想破产。"},{"label":"参与者","value":"德国中央集团军群、苏联红军、约瑟夫·斯大林、格奥尔基·朱可夫、莫斯科市民和民兵。"},{"label":"发生了什么","value":"德军在1941年秋发动“台风行动”进攻莫斯科，初期形成包围和突破，但泥泞、补给困难、苏军抵抗和严寒削弱推进。苏联调集预备队并组织首都防御，12月发动反攻，把德军推离莫斯科外围。"},{"label":"为什么重要","value":"这是德国陆军在二战中首次遭遇战略性挫败，证明苏联不会像希特勒预期那样迅速崩溃。"},{"label":"前因","value":"巴巴罗萨行动初期德军取得巨大包围战胜利，但基辅方向调整、后勤拉长和苏军动员使莫斯科攻势时间紧迫。"},{"label":"后果","value":"德国被迫面对长期东线战争，苏联士气和国际信心提升；战争消耗、冬季危机和后勤困难开始改变轴心国优势。"},{"label":"出处","value":"Encyclopaedia Britannica: Battle of Moscow；Encyclopaedia Britannica: World War II, Invasion of the Soviet Union 1941；Imperial War Museums: Operation Barbarossa。"}],"relationItems":["← 前因：德国入侵苏联“巴巴罗萨行动”","← 前因：基辅包围战","→ 后果：斯大林格勒战役","↔ 相关：纳粹德国东线灭绝战争"],"relations":[{"text":"← 前因：德国入侵苏联“巴巴罗萨行动”","id":"extra209"},{"text":"← 前因：基辅包围战","id":"extra213"},{"text":"→ 后果：斯大林格勒战役","id":"extra230"},{"text":"↔ 相关：纳粹德国东线灭绝战争","id":"extra210"}],"source":"history","id":"extra215"},{"title":"纳粹建立华沙隔都","level":"A","type":"事件卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1940年10月建立，1940年11月封闭","place":"德占波兰华沙","summary":"华沙隔都是纳粹在欧洲最大犹太社群之一上建立的封闭隔离区，成为迫害、饥饿和后续灭绝的前站。","fields":[{"label":"标题","value":"纳粹建立华沙隔都"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1940年10月建立，1940年11月封闭"},{"label":"地点","value":"德占波兰华沙"},{"label":"主要国家","value":"德国；波兰"},{"label":"一句话概括","value":"华沙隔都是纳粹在欧洲最大犹太社群之一上建立的封闭隔离区，成为迫害、饥饿和后续灭绝的前站。"},{"label":"参与者","value":"德国占领当局、华沙犹太居民、犹太委员会、波兰非犹太居民、德国警察和SS。"},{"label":"发生了什么","value":"德国占领当局把华沙及周边大量犹太人强制迁入城市内狭小区域，并用墙和警戒把隔都封闭。隔都人口拥挤、食物短缺、疾病流行，居民在极端条件下维持教育、救济、秘密记录和文化生活。后来隔都居民被大规模驱逐到灭绝营。"},{"label":"为什么重要","value":"它展示纳粹反犹政策在灭绝营之前的城市隔离、剥夺和强制管理机制。"},{"label":"前因","value":"德国占领波兰后，纳粹把犹太人集中到隔都中，以便隔离、剥削劳动力和控制财产；华沙庞大的犹太人口使其成为重点对象。"},{"label":"后果","value":"隔都饥饿和疾病造成大量死亡，1942年后大规模驱逐通向特雷布林卡灭绝营；幸存者在绝望处境中最终发动华沙隔都起义。"},{"label":"出处","value":"USHMM Holocaust Encyclopedia: The Warsaw Ghetto；USHMM: Ghettos in occupied Poland；Yad Vashem: Warsaw Ghetto。"}],"relationItems":["← 前因：纳粹德国波兰总督府","↔ 相关：纳粹德国犹太企业“雅利安化”","→ 后果：纳粹占领下华沙隔都起义","→ 后果：纳粹犹太人大屠杀"],"relations":[{"text":"← 前因：纳粹德国波兰总督府","id":"extra182"},{"text":"↔ 相关：纳粹德国犹太企业“雅利安化”","id":"extra166"},{"text":"→ 后果：纳粹占领下华沙隔都起义","id":"extra238"},{"text":"→ 后果：纳粹犹太人大屠杀","id":"extra218"}],"source":"history","id":"extra216"},{"title":"纳粹德国对美国宣战","level":"A","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1941年12月11日","place":"德国柏林；美国华盛顿","summary":"德国在珍珠港事件后对美国宣战，使美国正式进入欧洲反德战争。","fields":[{"label":"标题","value":"纳粹德国对美国宣战"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1941年12月11日"},{"label":"地点","value":"德国柏林；美国华盛顿"},{"label":"主要国家","value":"德国；美国；日本；英国"},{"label":"一句话概括","value":"德国在珍珠港事件后对美国宣战，使美国正式进入欧洲反德战争。"},{"label":"参与者","value":"阿道夫·希特勒、纳粹德国政府、美国政府、富兰克林·罗斯福、日本帝国。"},{"label":"发生了什么","value":"1941年12月7日，日本袭击珍珠港后，美国对日本宣战。德国虽然并未被条约明确强制作出该行动，但希特勒于12月11日宣布对美国开战。美国随即对德国宣战，欧洲战争和太平洋战争在美国参战下更加紧密地合为全球战争。"},{"label":"为什么重要","value":"它是德国战略误判的关键节点，把美国工业和军事力量完全推入反德阵营。"},{"label":"前因","value":"美国已通过租借法案、大西洋护航和对英援助与德国处于事实对抗，日本袭击珍珠港改变了美国国内参战条件。"},{"label":"后果","value":"德国必须面对美国、英国和苏联三大工业与军事力量联合，美国资源开始更全面进入欧洲战场；轴心国长期胜算大幅下降。"},{"label":"出处","value":"Encyclopaedia Britannica: World War II, The United States enters the war；National WWII Museum: Germany declares war on the United States；Avalon Project: German Declaration of War with the United States。"}],"relationItems":["← 前因：美国《租借法案》","← 前因：轴心国《三国同盟条约》","→ 后果：盟军战略轰炸德国","→ 后果：盟国大同盟"],"relations":[{"text":"← 前因：美国《租借法案》","id":"extra201"},{"text":"← 前因：轴心国《三国同盟条约》","id":"extra198"},{"text":"→ 后果：盟军战略轰炸德国","id":"extra228"}],"source":"history","id":"extra217"},{"title":"纳粹犹太人大屠杀","level":"S","type":"事件卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1941—1945年为系统灭绝阶段；迫害始于1933年后","place":"纳粹德国、德占欧洲和灭绝营体系","summary":"犹太人纳粹犹太人大屠杀是纳粹德国系统谋杀约六百万犹太人的种族灭绝，是世界史坐标级罪行。","fields":[{"label":"标题","value":"纳粹犹太人大屠杀"},{"label":"分级","value":"S"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1941—1945年为系统灭绝阶段；迫害始于1933年后"},{"label":"地点","value":"纳粹德国、德占欧洲和灭绝营体系"},{"label":"主要国家","value":"德国；波兰；苏联；欧洲多国"},{"label":"一句话概括","value":"犹太人纳粹犹太人大屠杀是纳粹德国系统谋杀约六百万犹太人的种族灭绝，是世界史坐标级罪行。"},{"label":"参与者","value":"纳粹党、SS、德国警察和安全机构、国防军部分单位、占领行政、合作政权、受害犹太社群和抵抗者。"},{"label":"发生了什么","value":"纳粹反犹政策从排斥、剥夺和隔离逐步升级为系统杀戮。1941年入侵苏联后，特别行动队在东欧大规模枪杀犹太人。1942年前后，纳粹通过万湖会议协调跨部门行动，并在德占波兰建立或扩展灭绝营，用毒气室、强迫劳动、饥饿和枪杀等方式杀害欧洲犹太人。"},{"label":"为什么重要","value":"这是二十世纪最核心的种族灭绝事件之一，改变了战后国际法、人权观念、德国记忆政治和世界史叙事。"},{"label":"前因","value":"纳粹意识形态把犹太人塑造成种族和政治敌人，纽伦堡法、雅利安化、隔都和纳粹德国东线灭绝战争逐步拆除了犹太人生存空间。"},{"label":"后果","value":"战后纽伦堡审判和《防止及惩治灭绝种族罪公约》等制度回应，将纳粹犹太人大屠杀变成现代国际法和历史记忆的中心议题。"},{"label":"出处","value":"USHMM Holocaust Encyclopedia: Introduction to the Holocaust；Yad Vashem: The Holocaust；Encyclopaedia Britannica: Holocaust。"}],"relationItems":["← 前因：纳粹纽伦堡法","← 前因：纳粹德国东线灭绝战争","← 前因：纳粹建立华沙隔都","→ 后果：纳粹战犯纽伦堡审判","→ 后果：德国去纳粹化","↔ 相关：纳粹德国特别行动队"],"relations":[{"text":"← 前因：纳粹纽伦堡法","id":"extra114"},{"text":"← 前因：纳粹德国东线灭绝战争","id":"extra210"},{"text":"← 前因：纳粹建立华沙隔都","id":"extra216"},{"text":"→ 后果：纳粹战犯纽伦堡审判","id":"extra6"},{"text":"→ 后果：德国去纳粹化","id":"extra5"},{"text":"↔ 相关：纳粹德国特别行动队","id":"extra185"}],"source":"history","id":"extra218"},{"title":"纳粹万湖会议","level":"A","type":"事件卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1942年1月20日","place":"德国柏林万湖别墅","summary":"万湖会议不是纳粹犹太人大屠杀的开始，而是纳粹跨部门协调“最终解决”的关键官僚会议。","fields":[{"label":"标题","value":"纳粹万湖会议"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1942年1月20日"},{"label":"地点","value":"德国柏林万湖别墅"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"万湖会议不是纳粹犹太人大屠杀的开始，而是纳粹跨部门协调“最终解决”的关键官僚会议。"},{"label":"参与者","value":"莱因哈德·海德里希、阿道夫·艾希曼、党卫队、内政部、司法部、外交部、总督府等机构代表。"},{"label":"发生了什么","value":"15名纳粹党、SS和政府高级官员在柏林万湖会面，讨论欧洲犹太人的登记、驱逐、劳役和杀害安排。海德里希主导会议，艾希曼负责记录。会议以官僚语言协调各部门参与，使已经展开的屠杀政策获得更清晰的行政分工。"},{"label":"为什么重要","value":"它展示纳粹犹太人大屠杀如何以会议、表格、部门权限和运输安排的形式制度化，而不只是街头暴力。"},{"label":"前因","value":"东线枪杀、隔都政策和切尔姆诺等杀戮实践已在1941年前后展开，纳粹需要协调欧洲范围内的驱逐和灭绝。"},{"label":"后果","value":"欧洲犹太人驱逐和灭绝行动加速，纳粹灭绝营“莱因哈德行动”和奥斯维辛-比克瑙等杀戮中心在1942年成为核心执行场所。"},{"label":"出处","value":"USHMM Holocaust Encyclopedia: The Wannsee Conference and the Final Solution；Encyclopaedia Britannica: Wannsee Conference；House of the Wannsee Conference Memorial and Educational Site。"}],"relationItems":["← 前因：巴比亚尔大屠杀","← 前因：纳粹建立华沙隔都","→ 后果：纳粹德国“最终解决”政策","→ 后果：纳粹灭绝营“莱因哈德行动”","↔ 相关：阿道夫·艾希曼"],"relations":[{"text":"← 前因：巴比亚尔大屠杀","id":"extra214"},{"text":"← 前因：纳粹建立华沙隔都","id":"extra216"},{"text":"→ 后果：纳粹德国“最终解决”政策","id":"extra220"},{"text":"→ 后果：纳粹灭绝营“莱因哈德行动”","id":"extra222"},{"text":"↔ 相关：阿道夫·艾希曼","id":"extra221"}],"source":"history","id":"extra219"},{"title":"纳粹德国“最终解决”政策","level":"A","type":"概念/思潮卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1941—1945年；1942年后组织化程度显著提高","place":"德占欧洲和纳粹德国行政体系","summary":"“最终解决”是纳粹对欧洲犹太人实施系统性灭绝的官僚代称。","fields":[{"label":"标题","value":"纳粹德国“最终解决”政策"},{"label":"分级","value":"A"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1941—1945年；1942年后组织化程度显著提高"},{"label":"地点","value":"德占欧洲和纳粹德国行政体系"},{"label":"主要国家","value":"德国；欧洲多国"},{"label":"一句话概括","value":"“最终解决”是纳粹对欧洲犹太人实施系统性灭绝的官僚代称。"},{"label":"核心主张/思路","value":"把欧洲犹太人视为必须从社会和生命层面消除的对象，通过驱逐、隔离、强迫劳动和杀戮实现种族灭绝。"},{"label":"提出者/代表人物（可选）","value":"希特勒、希姆莱、海德里希、艾希曼及SS和国家行政机构。"},{"label":"它从何而来","value":"纳粹反犹主义、战争扩张、纳粹德国东线灭绝战争和移民方案失败共同推动政策从排除转向杀戮。"},{"label":"典型表现","value":"万湖会议协调、隔都清场、铁路驱逐、灭绝营毒气杀害、特别行动队枪杀和财产掠夺。"},{"label":"为什么重要","value":"它是理解纳粹犹太人大屠杀制度机制的核心概念，把意识形态仇恨、战争行政和工业化杀戮连接起来。"},{"label":"争议/局限","value":"政策形成不是单一日子突然决定，而是在1941年前后多条杀戮实践和命令链中逐步成形。"},{"label":"出处","value":"USHMM Holocaust Encyclopedia: The “Final Solution”；Auschwitz-Birkenau Memorial: The Final Solution；Yad Vashem: The Final Solution。"}],"relationItems":["← 前因：纳粹万湖会议","↔ 相关：纳粹犹太人大屠杀","→ 后果：纳粹灭绝营“莱因哈德行动”","→ 后果：奥斯维辛-比克瑙灭绝营"],"relations":[{"text":"← 前因：纳粹万湖会议","id":"extra219"},{"text":"↔ 相关：纳粹犹太人大屠杀","id":"extra218"},{"text":"→ 后果：纳粹灭绝营“莱因哈德行动”","id":"extra222"},{"text":"→ 后果：奥斯维辛-比克瑙灭绝营","id":"extra224"}],"source":"history","id":"extra220"},{"title":"阿道夫·艾希曼","level":"B","type":"人物卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1906—1962年；纳粹核心行动期为1930年代末至1945年","place":"德国、德占欧洲、战后阿根廷和以色列","summary":"艾希曼负责犹太人驱逐和运输协调，是纳粹犹太人大屠杀官僚执行链中的关键人物。","fields":[{"label":"标题","value":"阿道夫·艾希曼"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1906—1962年；纳粹核心行动期为1930年代末至1945年"},{"label":"地点","value":"德国、德占欧洲、战后阿根廷和以色列"},{"label":"主要国家","value":"德国；以色列"},{"label":"一句话概括","value":"艾希曼负责犹太人驱逐和运输协调，是纳粹犹太人大屠杀官僚执行链中的关键人物。"},{"label":"生卒年/活跃年代","value":"1906年出生，1962年在以色列被处决。"},{"label":"身份/职务","value":"SS军官，帝国安全总局犹太事务部门负责人之一。"},{"label":"关键贡献/作为","value":"参与万湖会议记录和后续执行，协调欧洲犹太人登记、集中、铁路运输和驱逐到隔都及灭绝营。"},{"label":"核心主张/立场","value":"忠于纳粹反犹政策，以官僚效率推动驱逐和灭绝程序。"},{"label":"为什么重要","value":"艾希曼说明纳粹犹太人大屠杀不仅需要最高命令和杀戮现场，也需要中层官僚把人变成名单、车次和行政流程。"},{"label":"争议/评价","value":"战后“平庸之恶”讨论常围绕艾希曼展开，但不能因此淡化其主动参与和犯罪责任。"},{"label":"关联事件","value":"万湖会议；纳粹德国“最终解决”政策；艾希曼审判。"},{"label":"出处","value":"Encyclopaedia Britannica: Adolf Eichmann；USHMM Holocaust Encyclopedia: Adolf Eichmann；Yad Vashem: Adolf Eichmann。"}],"relationItems":["← 前因：纳粹万湖会议","↔ 相关：纳粹灭绝营“莱因哈德行动”","→ 后果：艾希曼审判","↔ 相关：纳粹犹太人大屠杀"],"relations":[{"text":"← 前因：纳粹万湖会议","id":"extra219"},{"text":"↔ 相关：纳粹灭绝营“莱因哈德行动”","id":"extra222"},{"text":"↔ 相关：纳粹犹太人大屠杀","id":"extra218"}],"source":"history","id":"extra221"},{"title":"纳粹灭绝营“莱因哈德行动”","level":"A","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1942—1943年","place":"德占波兰总督府；贝乌热茨、索比堡、特雷布林卡等灭绝营","summary":"纳粹灭绝营“莱因哈德行动”是纳粹在德占波兰总督府大规模屠杀犹太人的核心灭绝行动。","fields":[{"label":"标题","value":"纳粹灭绝营“莱因哈德行动”"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1942—1943年"},{"label":"地点","value":"德占波兰总督府；贝乌热茨、索比堡、特雷布林卡等灭绝营"},{"label":"主要国家","value":"德国；波兰"},{"label":"一句话概括","value":"纳粹灭绝营“莱因哈德行动”是纳粹在德占波兰总督府大规模屠杀犹太人的核心灭绝行动。"},{"label":"参与者","value":"SS和警察领导层、奥迪洛·格洛博奇尼克、灭绝营人员、铁路和占领行政、受害犹太社群。"},{"label":"发生了什么","value":"纳粹在德占波兰建立贝乌热茨、索比堡和特雷布林卡灭绝营，主要通过毒气杀害被从隔都和各地驱逐来的犹太人。行动还包括财产掠夺、隔都清场和毁灭证据。大量工作人员来自T4安乐死项目，杀戮技术和人员经验被转移到波兰。"},{"label":"为什么重要","value":"它是纳粹犹太人大屠杀中杀戮效率最高、最集中阶段之一，尤其针对波兰犹太人。"},{"label":"前因","value":"万湖会议前后，纳粹需要把总督府和欧洲其他地区的犹太人从隔都驱逐到专门杀戮中心；波兰总督府已有大量被隔离、饥饿和等待驱逐的犹太人口。"},{"label":"后果","value":"波兰犹太社群遭毁灭性打击，许多隔都被清空；灭绝营后来被拆除和伪装，但幸存者证词、档案和调查使其杀戮规模成为纳粹犹太人大屠杀核心证据。"},{"label":"出处","value":"USHMM Holocaust Encyclopedia: Killing Centers in Depth；USHMM: Operation Reinhard；Yad Vashem: Operation Reinhard。"}],"relationItems":["← 前因：纳粹万湖会议","← 前因：纳粹建立华沙隔都","→ 后果：特雷布林卡灭绝营","↔ 相关：纳粹德国波兰总督府","↔ 相关：纳粹犹太人大屠杀"],"relations":[{"text":"← 前因：纳粹万湖会议","id":"extra219"},{"text":"← 前因：纳粹建立华沙隔都","id":"extra216"},{"text":"→ 后果：特雷布林卡灭绝营","id":"extra223"},{"text":"↔ 相关：纳粹德国波兰总督府","id":"extra182"},{"text":"↔ 相关：纳粹犹太人大屠杀","id":"extra218"}],"source":"history","id":"extra222"},{"title":"特雷布林卡灭绝营","level":"A","type":"组织/机构卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1942—1943年","place":"德占波兰；华沙东北方向","summary":"特雷布林卡是纳粹灭绝营“莱因哈德行动”三大灭绝营之一，主要用于杀害从华沙等隔都驱逐来的犹太人。","fields":[{"label":"标题","value":"特雷布林卡灭绝营"},{"label":"分级","value":"A"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1942—1943年"},{"label":"地点","value":"德占波兰；华沙东北方向"},{"label":"主要国家","value":"德国；波兰"},{"label":"一句话概括","value":"特雷布林卡是纳粹灭绝营“莱因哈德行动”三大灭绝营之一，主要用于杀害从华沙等隔都驱逐来的犹太人。"},{"label":"性质/类型","value":"专门灭绝营，而不是普通集中营或劳改营。"},{"label":"成立/解散时间","value":"1942年开始运作，1943年囚犯起义后逐步关闭和拆毁。"},{"label":"核心目标/宗旨","value":"快速接收、剥夺并杀害被驱逐犹太人，同时掠夺财物并销毁犯罪痕迹。"},{"label":"关键人物","value":"纳粹灭绝营“莱因哈德行动”相关SS和警察体系，营地德国人员及被迫协助的囚犯。"},{"label":"关键行动/事件","value":"华沙隔都大驱逐期间，大量犹太人被送往特雷布林卡；1943年发生囚犯起义。"},{"label":"为什么重要","value":"特雷布林卡体现了灭绝营的核心逻辑：目的不是长期关押，而是把铁路运输直接转化为杀戮流程。"},{"label":"争议/局限","value":"纳粹试图拆毁营地并伪装现场，战后重建历史高度依赖幸存者证词、调查和档案碎片。"},{"label":"出处","value":"USHMM Holocaust Encyclopedia: Treblinka；Yad Vashem: Treblinka；Encyclopaedia Britannica: Treblinka。"}],"relationItems":["← 前因：纳粹灭绝营“莱因哈德行动”","← 前因：纳粹建立华沙隔都","→ 后果：纳粹占领下华沙隔都起义","↔ 相关：纳粹犹太人大屠杀"],"relations":[{"text":"← 前因：纳粹灭绝营“莱因哈德行动”","id":"extra222"},{"text":"← 前因：纳粹建立华沙隔都","id":"extra216"},{"text":"→ 后果：纳粹占领下华沙隔都起义","id":"extra238"},{"text":"↔ 相关：纳粹犹太人大屠杀","id":"extra218"}],"source":"history","id":"extra223"},{"title":"奥斯维辛-比克瑙灭绝营","level":"S","type":"组织/机构卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1940—1945年；1942年后成为大规模灭绝中心","place":"德占波兰奥斯维辛；今波兰奥święcim附近","summary":"奥斯维辛-比克瑙是纳粹最大集中营和灭绝营复合体，成为纳粹犹太人大屠杀最具象征性的地点。","fields":[{"label":"标题","value":"奥斯维辛-比克瑙灭绝营"},{"label":"分级","value":"S"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1940—1945年；1942年后成为大规模灭绝中心"},{"label":"地点","value":"德占波兰奥斯维辛；今波兰奥święcim附近"},{"label":"主要国家","value":"德国；波兰；欧洲多国"},{"label":"一句话概括","value":"奥斯维辛-比克瑙是纳粹最大集中营和灭绝营复合体，成为纳粹犹太人大屠杀最具象征性的地点。"},{"label":"性质/类型","value":"集中营、强迫劳动营和灭绝营复合体。"},{"label":"成立/解散时间","value":"奥斯维辛主营1940年建立，比克瑙1941年后扩建，1945年1月被苏军解放。"},{"label":"核心目标/宗旨","value":"关押、强迫劳动和大规模杀害犹太人、波兰人、罗姆人、苏军战俘及其他被迫害群体。"},{"label":"关键人物","value":"SS营地管理体系，鲁道夫·赫斯等营地指挥官。"},{"label":"关键行动/事件","value":"1942年后大规模犹太人运输、到站筛选、毒气杀害和焚尸；1944年匈牙利犹太人被大规模送入。"},{"label":"为什么重要","value":"它是工业化种族灭绝、强迫劳动和纳粹医学犯罪的集中象征，也是战后世界记忆纳粹犹太人大屠杀的核心地点。"},{"label":"争议/局限","value":"奥斯维辛的象征地位不应遮蔽贝乌热茨、索比堡、特雷布林卡等其他灭绝营和东线枪杀的大规模死亡。"},{"label":"出处","value":"USHMM Holocaust Encyclopedia: Auschwitz；Auschwitz-Birkenau Memorial: Auschwitz and Shoah；Encyclopaedia Britannica: Auschwitz。"}],"relationItems":["← 前因：纳粹德国“最终解决”政策","↔ 相关：纳粹强迫劳动体系","↔ 相关：纳粹犹太人大屠杀","→ 后果：苏军解放奥斯维辛"],"relations":[{"text":"← 前因：纳粹德国“最终解决”政策","id":"extra220"},{"text":"↔ 相关：纳粹强迫劳动体系","id":"extra225"},{"text":"↔ 相关：纳粹犹太人大屠杀","id":"extra218"},{"text":"→ 后果：苏军解放奥斯维辛","id":"extra268"}],"source":"history","id":"extra224"},{"title":"纳粹强迫劳动体系","level":"A","type":"概念/思潮卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1939—1945年；1942年后急剧扩大","place":"纳粹德国、德占欧洲和集中营体系","summary":"纳粹强迫劳动体系把战俘、占领区平民和集中营囚犯转化为德国战争经济资源。","fields":[{"label":"标题","value":"纳粹强迫劳动体系"},{"label":"分级","value":"A"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1939—1945年；1942年后急剧扩大"},{"label":"地点","value":"纳粹德国、德占欧洲和集中营体系"},{"label":"主要国家","value":"德国；欧洲多国"},{"label":"一句话概括","value":"纳粹强迫劳动体系把战俘、占领区平民和集中营囚犯转化为德国战争经济资源。"},{"label":"核心主张/思路","value":"用国家暴力和占领权强制非德国劳动力为德国农业、工业、军工和基础设施服务。"},{"label":"提出者/代表人物（可选）","value":"弗里茨·绍克尔、阿尔贝特·斯佩尔、SS经济管理部门和德国企业。"},{"label":"它从何而来","value":"长期战争造成德国劳动力短缺，东线扩张和占领区控制又提供了可被强制征用的人口。"},{"label":"典型表现","value":"外国劳工被强制运往德国，苏军战俘和集中营囚犯被投入军工、矿山、建筑和农业。"},{"label":"为什么重要","value":"它说明德国战争经济并非只靠技术和组织效率，也依赖大规模奴役、剥削和死亡。"},{"label":"争议/局限","value":"战后企业责任、赔偿和“谁知道强迫劳动”长期存在争议，但强迫劳动是纳粹经济的基础事实。"},{"label":"出处","value":"USHMM Holocaust Encyclopedia: Forced Labor: An Overview；Encyclopaedia Britannica: Forced labour；German Historical Institute materials on forced labor。"}],"relationItems":["← 前因：德军虐待苏军战俘","↔ 相关：弗里茨·绍克尔","↔ 相关：阿尔贝特·斯佩尔","→ 后果：战后德国被迫劳工赔偿问题"],"relations":[{"text":"← 前因：德军虐待苏军战俘","id":"extra211"},{"text":"↔ 相关：弗里茨·绍克尔","id":"extra226"},{"text":"↔ 相关：阿尔贝特·斯佩尔","id":"extra227"}],"source":"history","id":"extra225"},{"title":"弗里茨·绍克尔","level":"C","type":"人物卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1894—1946年；1942—1945年主管劳动力征用","place":"德国及德占欧洲","summary":"绍克尔作为劳动力总负责人，大规模强征占领区人口到德国服务战争经济。","fields":[{"label":"标题","value":"弗里茨·绍克尔"},{"label":"分级","value":"C"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1894—1946年；1942—1945年主管劳动力征用"},{"label":"地点","value":"德国及德占欧洲"},{"label":"主要国家","value":"德国；欧洲多国"},{"label":"一句话概括","value":"绍克尔作为劳动力总负责人，大规模强征占领区人口到德国服务战争经济。"},{"label":"生卒年/活跃年代","value":"1894年出生，1946年在纽伦堡审判后被处决。"},{"label":"身份/职务","value":"纳粹党大区长，1942年起任劳动力部署总全权代表。"},{"label":"关键贡献/作为","value":"组织从德占欧洲强制征调平民和战俘，把他们送入德国工厂、农场和军工体系。"},{"label":"核心主张/立场","value":"把占领区人口视为可动员的战争资源，以强制、威胁和行政配额满足德国劳动力需求。"},{"label":"为什么重要","value":"绍克尔是理解纳粹强迫劳动从地方征用变成全欧洲制度化掠夺的关键人物。"},{"label":"争议/评价","value":"纽伦堡审判认定其对强迫劳动和奴役负有重大责任，最终判处死刑。"},{"label":"关联事件","value":"纳粹强迫劳动体系；纽伦堡审判。"},{"label":"出处","value":"Encyclopaedia Britannica: Fritz Sauckel；USHMM Holocaust Encyclopedia: Forced Labor: An Overview；Yad Vashem: Sauckel, Fritz。"}],"relationItems":["← 前因：纳粹强迫劳动体系","↔ 相关：阿尔贝特·斯佩尔","→ 后果：纳粹战犯纽伦堡审判"],"relations":[{"text":"← 前因：纳粹强迫劳动体系","id":"extra225"},{"text":"↔ 相关：阿尔贝特·斯佩尔","id":"extra227"},{"text":"→ 后果：纳粹战犯纽伦堡审判","id":"extra6"}],"source":"history","id":"extra226"},{"title":"阿尔贝特·斯佩尔","level":"B","type":"人物卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1905—1981年；1942—1945年任军备部长","place":"德国；柏林和纳粹军工体系","summary":"斯佩尔从希特勒建筑师转为军备部长，通过组织军工生产延长了德国战争能力。","fields":[{"label":"标题","value":"阿尔贝特·斯佩尔"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1905—1981年；1942—1945年任军备部长"},{"label":"地点","value":"德国；柏林和纳粹军工体系"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"斯佩尔从希特勒建筑师转为军备部长，通过组织军工生产延长了德国战争能力。"},{"label":"生卒年/活跃年代","value":"1905年出生，1981年去世；纳粹高层角色集中在1930年代至1945年。"},{"label":"身份/职务","value":"建筑师，纳粹德国军备和战争生产部长。"},{"label":"关键贡献/作为","value":"1942年接替弗里茨·托特，整合军备生产、提高军工效率，并与强迫劳动体系深度相连。"},{"label":"核心主张/立场","value":"以技术官僚和组织效率服务纳粹战争目标，强调集中管理、生产优先和资源调配。"},{"label":"为什么重要","value":"斯佩尔说明纳粹战争机器不仅由意识形态狂热推动，也由技术官僚、企业和强迫劳动共同支撑。"},{"label":"争议/评价","value":"战后斯佩尔塑造“不了解纳粹犹太人大屠杀的技术官僚”形象，但学界普遍强调其对强迫劳动和战争经济负有重大责任。"},{"label":"关联事件","value":"纳粹强迫劳动体系；盟军战略轰炸德国；纽伦堡审判。"},{"label":"出处","value":"Encyclopaedia Britannica: Albert Speer；USHMM Holocaust Encyclopedia: Forced Labor；German Historical Institute materials on Speer and armaments production。"}],"relationItems":["← 前因：纳粹德国四年计划","↔ 相关：弗里茨·绍克尔","↔ 相关：纳粹强迫劳动体系","→ 后果：盟军战略轰炸德国"],"relations":[{"text":"← 前因：纳粹德国四年计划","id":"extra122"},{"text":"↔ 相关：弗里茨·绍克尔","id":"extra226"},{"text":"↔ 相关：纳粹强迫劳动体系","id":"extra225"},{"text":"→ 后果：盟军战略轰炸德国","id":"extra228"}],"source":"history","id":"extra227"},{"title":"盟军战略轰炸德国","level":"A","type":"事件卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1942—1945年大规模展开","place":"德国城市、工业区和交通网络","summary":"盟军战略轰炸德国以城市、工业和交通为目标，试图削弱纳粹战争经济和民众承受力。","fields":[{"label":"标题","value":"盟军战略轰炸德国"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1942—1945年大规模展开"},{"label":"地点","value":"德国城市、工业区和交通网络"},{"label":"主要国家","value":"英国；美国；德国"},{"label":"一句话概括","value":"盟军战略轰炸德国以城市、工业和交通为目标，试图削弱纳粹战争经济和民众承受力。"},{"label":"参与者","value":"英国皇家空军轰炸机司令部、美国陆军航空队、德国防空体系、德国平民和工业企业。"},{"label":"发生了什么","value":"1942年后，英国加强夜间区域轰炸，美国逐步展开白天精确轰炸。目标包括鲁尔工业区、交通枢纽、石油设施、军工厂和城市中心。轰炸造成巨大破坏和平民伤亡，也迫使德国投入大量防空、修复和分散生产资源。"},{"label":"为什么重要","value":"它把战争带回德国本土，直接冲击德国城市社会和战争经济，也是二战道德争议最集中的军事行动之一。"},{"label":"前因","value":"英国经历伦敦大轰炸后发展对德轰炸能力，美国参战后提供重型轰炸机和工业资源，空中攻势逐步升级。"},{"label":"后果","value":"德国军工和交通压力加重，防空和修复消耗大量资源，城市平民承受巨大伤亡；轰炸争议在战后持续影响对二战空战的评价。"},{"label":"出处","value":"Encyclopaedia Britannica: Strategic bombing during World War II；Encyclopaedia Britannica: World War II, Air warfare 1942–43；Imperial War Museums: Strategic Bombing Campaign。"}],"relationItems":["← 前因：伦敦大轰炸","← 前因：纳粹德国对美国宣战","↔ 相关：阿尔贝特·斯佩尔","→ 后果：盟军轰炸汉堡“蛾摩拉行动”"],"relations":[{"text":"← 前因：伦敦大轰炸","id":"extra197"},{"text":"← 前因：纳粹德国对美国宣战","id":"extra217"},{"text":"↔ 相关：阿尔贝特·斯佩尔","id":"extra227"},{"text":"→ 后果：盟军轰炸汉堡“蛾摩拉行动”","id":"extra247"}],"source":"history","id":"extra228"},{"title":"德国东线“蓝色方案”攻势","level":"B","type":"制度/文本卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1942年夏季攻势计划","place":"苏联南部；顿河、伏尔加河、高加索方向","summary":"“蓝色方案”是德国1942年南线攻势计划，目标指向高加索石油和伏尔加交通。","fields":[{"label":"标题","value":"德国东线“蓝色方案”攻势"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1942年夏季攻势计划"},{"label":"地点","value":"苏联南部；顿河、伏尔加河、高加索方向"},{"label":"主要国家","value":"德国；苏联"},{"label":"一句话概括","value":"“蓝色方案”是德国1942年南线攻势计划，目标指向高加索石油和伏尔加交通。"},{"label":"制定方/签署方","value":"希特勒和德国最高统帅部制定并推动。"},{"label":"主要内容","value":"将1942年东线重点放在苏联南部，计划夺取顿河—伏尔加方向，并推进高加索油田。"},{"label":"它试图解决什么问题","value":"德国在莫斯科失败后需要新的战略突破，尤其需要石油资源支撑长期战争。"},{"label":"为什么重要","value":"它解释斯大林格勒不是孤立城市争夺，而是德国资源战争和南线战略的一部分。"},{"label":"争议/局限","value":"计划目标过大，兵力和后勤被拉向高加索与斯大林格勒两个方向，削弱了集中力量。"},{"label":"造成的影响","value":"德军推进到斯大林格勒和高加索，但战线过长、侧翼薄弱，最终导致第六集团军被包围。"},{"label":"出处","value":"Encyclopaedia Britannica: Battle of Stalingrad；Encyclopaedia Britannica: World War II, Invasion of the Soviet Union 1941；German military history references on Fall Blau。"}],"relationItems":["← 前因：莫斯科战役","↔ 相关：纳粹德国饥饿计划","→ 后果：斯大林格勒战役","→ 后果：高加索战役（1942）"],"relations":[{"text":"← 前因：莫斯科战役","id":"extra215"},{"text":"↔ 相关：纳粹德国饥饿计划","id":"extra208"},{"text":"→ 后果：斯大林格勒战役","id":"extra230"}],"source":"history","id":"extra229"},{"title":"斯大林格勒战役","level":"S","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1942年8月—1943年2月","place":"苏联斯大林格勒；今俄罗斯伏尔加格勒","summary":"斯大林格勒战役以德军第六集团军被围歼告终，是二战欧洲战场最重要转折点之一。","fields":[{"label":"标题","value":"斯大林格勒战役"},{"label":"分级","value":"S"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1942年8月—1943年2月"},{"label":"地点","value":"苏联斯大林格勒；今俄罗斯伏尔加格勒"},{"label":"主要国家","value":"德国；苏联；罗马尼亚；意大利；匈牙利"},{"label":"一句话概括","value":"斯大林格勒战役以德军第六集团军被围歼告终，是二战欧洲战场最重要转折点之一。"},{"label":"参与者","value":"德国第六集团军、苏联红军、弗里德里希·保卢斯、瓦西里·崔可夫、朱可夫、德国盟军部队。"},{"label":"发生了什么","value":"德国南线攻势推进到伏尔加河畔斯大林格勒，城市争夺演变成残酷巷战。苏军在城市内牵制德军，同时于1942年11月发动“天王星行动”，攻击德军侧翼的罗马尼亚等盟军部队，合围第六集团军。希特勒拒绝突围，第六集团军在1943年初投降。"},{"label":"为什么重要","value":"它是世界史坐标级节点，标志德国东线战略主动权开始丧失，苏联由防御逐渐转入战略反攻。"},{"label":"前因","value":"德国“蓝色方案”把东线重点转向南方资源和伏尔加交通，德军推进过深且侧翼依赖装备较弱的盟军。"},{"label":"后果","value":"德国在东线的不可战胜神话破裂，轴心国士气、兵力和盟友信心遭重大打击；苏联战略主动权上升，东线战争方向开始反转。"},{"label":"出处","value":"Encyclopaedia Britannica: Battle of Stalingrad；Imperial War Museums: Battle of Stalingrad；National WWII Museum: Battle of Stalingrad。"}],"relationItems":["← 前因：德国东线“蓝色方案”攻势","← 前因：莫斯科战役","→ 后果：库尔斯克战役","↔ 相关：弗里德里希·保卢斯"],"relations":[{"text":"← 前因：德国东线“蓝色方案”攻势","id":"extra229"},{"text":"← 前因：莫斯科战役","id":"extra215"},{"text":"→ 后果：库尔斯克战役","id":"extra241"},{"text":"↔ 相关：弗里德里希·保卢斯","id":"extra231"}],"source":"history","id":"extra230"},{"title":"弗里德里希·保卢斯","level":"C","type":"人物卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1890—1957年；斯大林格勒时期为1942—1943年","place":"德国；苏联东线；斯大林格勒","summary":"保卢斯作为德国第六集团军司令，在斯大林格勒被围后投降，成为纳粹军事失败象征。","fields":[{"label":"标题","value":"弗里德里希·保卢斯"},{"label":"分级","value":"C"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1890—1957年；斯大林格勒时期为1942—1943年"},{"label":"地点","value":"德国；苏联东线；斯大林格勒"},{"label":"主要国家","value":"德国；苏联"},{"label":"一句话概括","value":"保卢斯作为德国第六集团军司令，在斯大林格勒被围后投降，成为纳粹军事失败象征。"},{"label":"生卒年/活跃年代","value":"1890年出生，1957年去世。"},{"label":"身份/职务","value":"德国陆军将领，第六集团军司令，1943年被晋升为元帅。"},{"label":"关键贡献/作为","value":"指挥第六集团军参与斯大林格勒攻防，合围后遵从希特勒命令未能突围，最终向苏军投降。"},{"label":"核心主张/立场","value":"典型国防军职业军官，战前和战时服从纳粹战争决策，战俘后参与反希特勒宣传。"},{"label":"为什么重要","value":"保卢斯卡帮助用户理解斯大林格勒失败中的指挥服从、希特勒干预和军队崩溃。"},{"label":"争议/评价","value":"他不是纳粹意识形态核心人物，但作为高级将领参与侵略战争，对东线灾难负有军事责任。"},{"label":"关联事件","value":"斯大林格勒战役。"},{"label":"出处","value":"Encyclopaedia Britannica: Battle of Stalingrad；German Federal Archives and military history references；National WWII Museum: Stalingrad materials。"}],"relationItems":["← 前因：德国东线“蓝色方案”攻势","↔ 相关：斯大林格勒战役","→ 后果：德国国防军失败神话破裂"],"relations":[{"text":"← 前因：德国东线“蓝色方案”攻势","id":"extra229"},{"text":"↔ 相关：斯大林格勒战役","id":"extra230"}],"source":"history","id":"extra231"},{"title":"第二次阿拉曼战役","level":"A","type":"事件卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1942年10月23日—11月4日","place":"埃及阿拉曼一线","summary":"第二次阿拉曼战役击退轴心国北非攻势，终结德国和意大利威胁埃及与苏伊士的希望。","fields":[{"label":"标题","value":"第二次阿拉曼战役"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1942年10月23日—11月4日"},{"label":"地点","value":"埃及阿拉曼一线"},{"label":"主要国家","value":"英国；德国；意大利；埃及"},{"label":"一句话概括","value":"第二次阿拉曼战役击退轴心国北非攻势，终结德国和意大利威胁埃及与苏伊士的希望。"},{"label":"参与者","value":"英国第八集团军、伯纳德·蒙哥马利、纳粹德国非洲军、埃尔温·隆美尔、意大利部队。"},{"label":"发生了什么","value":"英军在阿拉曼一线集结优势兵力、火炮和补给，向轴心军防线发动系统攻势。隆美尔部队因补给不足、兵力劣势和盟军空海压力陷入被动。战役结束后，轴心军被迫从埃及和利比亚方向长期撤退。"},{"label":"为什么重要","value":"它是西方盟军对德意陆战的关键胜利，配合火炬行动使北非轴心国处境迅速恶化。"},{"label":"前因","value":"纳粹德国非洲军和意大利部队推进到埃及边缘，但补给线过长且受盟军海空力量打击；英军则在本土和帝国资源支撑下重新组织。"},{"label":"后果","value":"轴心军失去进攻苏伊士和中东方向的机会，北非战局转入盟军反攻阶段；配合火炬行动后，轴心军最终被压向突尼斯。"},{"label":"出处","value":"Encyclopaedia Britannica: North Africa campaigns, Montgomery in the desert；National Army Museum: Second Battle of El Alamein；Imperial War Museums: North African Campaign。"}],"relationItems":["← 前因：纳粹德国非洲军","↔ 相关：埃尔温·隆美尔","→ 后果：盟军北非“火炬行动”","→ 后果：北非轴心军投降"],"relations":[{"text":"← 前因：纳粹德国非洲军","id":"extra202"},{"text":"↔ 相关：埃尔温·隆美尔","id":"extra203"},{"text":"→ 后果：盟军北非“火炬行动”","id":"extra233"},{"text":"→ 后果：北非轴心军投降","id":"extra239"}],"source":"history","id":"extra232"},{"title":"盟军北非“火炬行动”","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1942年11月8日开始","place":"法属北非；摩洛哥、阿尔及利亚","summary":"火炬行动是英美在法属北非登陆的行动，使美国陆军正式进入对德地面战争。","fields":[{"label":"标题","value":"盟军北非“火炬行动”"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1942年11月8日开始"},{"label":"地点","value":"法属北非；摩洛哥、阿尔及利亚"},{"label":"主要国家","value":"美国；英国；法国；德国；意大利"},{"label":"一句话概括","value":"火炬行动是英美在法属北非登陆的行动，使美国陆军正式进入对德地面战争。"},{"label":"参与者","value":"美国军队、英国军队、维希法国部队、德国和意大利、德怀特·艾森豪威尔等盟军指挥官。"},{"label":"发生了什么","value":"英美盟军在摩洛哥和阿尔及利亚登陆，目标是控制法属北非并从西面夹击轴心军。维希法国部队最初抵抗，随后部分转向与盟军合作。德国则加强突尼斯方向部署，北非战场进入最后阶段。"},{"label":"为什么重要","value":"它打开西方盟军对德国的地面攻势路径，也是美国参战后第一次重要欧洲—地中海战区行动。"},{"label":"前因","value":"英国希望缓解埃及和地中海压力，美国则需要在尚未具备横渡英吉利海峡条件前投入对德地面作战；北非因此成为较现实的登陆选择。"},{"label":"后果","value":"轴心国在北非被东西夹击，德国为防止盟军利用法属北非和维希空间而占领法国未占区；地中海战局随后向意大利方向推进。"},{"label":"出处","value":"Encyclopaedia Britannica: Operation Torch；National WWII Museum: Operation Torch；Eisenhower Presidential Library: Operation Torch materials。"}],"relationItems":["← 前因：第二次阿拉曼战役","↔ 相关：法国维希政权","→ 后果：北非轴心军投降","→ 后果：盟军登陆西西里岛"],"relations":[{"text":"← 前因：第二次阿拉曼战役","id":"extra232"},{"text":"↔ 相关：法国维希政权","id":"extra194"},{"text":"→ 后果：北非轴心军投降","id":"extra239"},{"text":"→ 后果：盟军登陆西西里岛","id":"extra242"}],"source":"history","id":"extra233"},{"title":"卡萨布兰卡会议","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1943年1月14—24日","place":"法属摩洛哥卡萨布兰卡","summary":"卡萨布兰卡会议确立轴心国“无条件投降”原则，并决定继续从地中海方向打击德国。","fields":[{"label":"标题","value":"卡萨布兰卡会议"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1943年1月14—24日"},{"label":"地点","value":"法属摩洛哥卡萨布兰卡"},{"label":"主要国家","value":"美国；英国；德国；意大利；日本"},{"label":"一句话概括","value":"卡萨布兰卡会议确立轴心国“无条件投降”原则，并决定继续从地中海方向打击德国。"},{"label":"参与者","value":"富兰克林·罗斯福、温斯顿·丘吉尔、盟军参谋机构、自由法国代表等。"},{"label":"发生了什么","value":"美英领导人在北非会晤，讨论下一阶段对德、对意和对日战争。会议决定继续推进地中海战场，计划攻击西西里，并公开提出要求德国、意大利和日本无条件投降。斯大林因苏德战场压力没有参加。"},{"label":"为什么重要","value":"它把盟军战争目标从击退轴心推进到彻底摧毁轴心政权，为战后处置德国预设了高门槛。"},{"label":"前因","value":"火炬行动后，盟军已进入北非并具备从地中海继续进攻的条件；斯大林格勒战役也使盟国开始重新评估德国败局可能。"},{"label":"后果","value":"无条件投降原则强化盟军合作目标，也被纳粹宣传用来宣称德国“没有退路”；地中海方向随即转向西西里和意大利，德国南翼压力增加，并被迫继续分散本已紧张的兵力、防空资源和后勤能力，战略防御面进一步拉长，意大利战场也逐渐成为消耗德国预备队的长期战场。"},{"label":"出处","value":"Encyclopaedia Britannica: Casablanca Conference；Office of the Historian: The Casablanca Conference；National WWII Museum: Casablanca Conference。"}],"relationItems":["← 前因：盟军北非“火炬行动”","↔ 相关：斯大林格勒战役","→ 后果：盟军登陆西西里岛","→ 后果：纳粹德国无条件投降"],"relations":[{"text":"← 前因：盟军北非“火炬行动”","id":"extra233"},{"text":"↔ 相关：斯大林格勒战役","id":"extra230"},{"text":"→ 后果：盟军登陆西西里岛","id":"extra242"},{"text":"→ 后果：纳粹德国无条件投降","id":"extra1"}],"source":"history","id":"extra234"},{"title":"纳粹德国总体战动员","level":"B","type":"概念/思潮卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1943年2月后强化","place":"德国；柏林体育宫及全国动员体系","summary":"总体战动员试图在斯大林格勒失败后把德国社会剩余资源更彻底地投入战争。","fields":[{"label":"标题","value":"纳粹德国总体战动员"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1943年2月后强化"},{"label":"地点","value":"德国；柏林体育宫及全国动员体系"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"总体战动员试图在斯大林格勒失败后把德国社会剩余资源更彻底地投入战争。"},{"label":"核心主张/思路","value":"压缩民用消费和日常生活，把劳动力、工业、宣传、女性劳动和社会纪律更集中地服务于战争。"},{"label":"提出者/代表人物（可选）","value":"约瑟夫·戈培尔、阿尔贝特·斯佩尔、纳粹党和国家动员机构。"},{"label":"它从何而来","value":"斯大林格勒失败、盟军轰炸升级和多线战争压力暴露德国资源不足，纳粹需要用宣传和行政命令维持战斗意志。"},{"label":"典型表现","value":"戈培尔体育宫演说，关闭或限制非必要行业，扩大女性和外国劳工投入，加强节约、配给和士气宣传。"},{"label":"为什么重要","value":"它显示纳粹德国不是在胜利时最极端，而是在失败压力下进一步压榨社会和战争经济。"},{"label":"争议/局限","value":"总体战口号掩盖了资源结构性不足；纳粹仍受意识形态、性别观念、党政竞争和轰炸破坏制约。"},{"label":"出处","value":"German History in Documents and Images: “Total War” Sportpalast speech；DHM/LeMO: Totaler Krieg；Encyclopaedia Britannica: Joseph Goebbels。"}],"relationItems":["← 前因：斯大林格勒战役","↔ 相关：约瑟夫·戈培尔","↔ 相关：阿尔贝特·斯佩尔","↔ 相关：纳粹强迫劳动体系","→ 后果：德国本土战争社会崩溃"],"relations":[{"text":"← 前因：斯大林格勒战役","id":"extra230"},{"text":"↔ 相关：约瑟夫·戈培尔","id":"card49"},{"text":"↔ 相关：阿尔贝特·斯佩尔","id":"extra227"},{"text":"↔ 相关：纳粹强迫劳动体系","id":"extra225"},{"text":"→ 后果：德国本土战争社会崩溃","id":"extra274"}],"source":"history","id":"extra235"},{"title":"纳粹德国白玫瑰抵抗组织","level":"B","type":"组织/机构卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1942—1943年","place":"德国慕尼黑及大学圈层","summary":"白玫瑰是慕尼黑学生和教授组成的非暴力反纳粹抵抗组织，以传单揭露战争和政权罪行。","fields":[{"label":"标题","value":"纳粹德国白玫瑰抵抗组织"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1942—1943年"},{"label":"地点","value":"德国慕尼黑及大学圈层"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"白玫瑰是慕尼黑学生和教授组成的非暴力反纳粹抵抗组织，以传单揭露战争和政权罪行。"},{"label":"性质/类型","value":"学生和知识分子反纳粹抵抗小组。"},{"label":"成立/解散时间","value":"1942年形成，1943年主要成员被捕并处决后瓦解。"},{"label":"核心目标/宗旨","value":"通过传单、邮寄和涂写口号呼吁德国人反对希特勒、结束战争并承担道德责任。"},{"label":"关键人物","value":"汉斯·朔尔、索菲·朔尔、克里斯托夫·普罗布斯特、亚历山大·施莫雷尔、维利·格拉夫、库尔特·胡贝尔。"},{"label":"关键行动/事件","value":"撰写并散发六批传单，1943年2月在慕尼黑大学散发传单时被捕，多名成员被人民法院判死刑。"},{"label":"为什么重要","value":"它证明纳粹德国并非完全没有内部反抗，也展示道德抵抗在极权环境中的成本和局限。"},{"label":"争议/局限","value":"白玫瑰规模很小，无法实际推翻政权；其历史意义更多在道德见证和战后德国记忆。"},{"label":"出处","value":"Encyclopaedia Britannica: White Rose；Weiße Rose Stiftung: White Rose Resistance Group；German History in Documents and Images: White Rose leaflet。"}],"relationItems":["← 前因：斯大林格勒战役","↔ 相关：纳粹人民法院","↔ 相关：索菲·朔尔","→ 后果：德国1944年7月20日密谋案"],"relations":[{"text":"← 前因：斯大林格勒战役","id":"extra230"},{"text":"↔ 相关：纳粹人民法院","id":"extra135"},{"text":"↔ 相关：索菲·朔尔","id":"extra237"},{"text":"→ 后果：德国1944年7月20日密谋案","id":"extra254"}],"source":"history","id":"extra236"},{"title":"索菲·朔尔","level":"C","type":"人物卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1921—1943年","place":"德国；乌尔姆、慕尼黑","summary":"索菲·朔尔是纳粹德国白玫瑰抵抗组织成员，因散发反纳粹传单被处决，成为德国反抗记忆象征。","fields":[{"label":"标题","value":"索菲·朔尔"},{"label":"分级","value":"C"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1921—1943年"},{"label":"地点","value":"德国；乌尔姆、慕尼黑"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"索菲·朔尔是纳粹德国白玫瑰抵抗组织成员，因散发反纳粹传单被处决，成为德国反抗记忆象征。"},{"label":"生卒年/活跃年代","value":"1921年出生，1943年被纳粹处决。"},{"label":"身份/职务","value":"慕尼黑大学学生，纳粹德国白玫瑰抵抗组织成员。"},{"label":"关键贡献/作为","value":"参与白玫瑰传单散发和反纳粹宣传，1943年2月与汉斯·朔尔在慕尼黑大学被捕。"},{"label":"核心主张/立场","value":"反对纳粹独裁和侵略战争，强调良知、信仰和个人道德责任。"},{"label":"为什么重要","value":"她不是军事或政治高层，却代表普通青年在极端压力下仍可能做出的道德选择。"},{"label":"争议/评价","value":"战后索菲·朔尔被高度纪念，但也应避免把她个人英雄化到遮蔽白玫瑰整体网络和更复杂抵抗史。"},{"label":"关联事件","value":"纳粹德国白玫瑰抵抗组织。"},{"label":"出处","value":"Encyclopaedia Britannica: White Rose；Weiße Rose Stiftung: Sophie Scholl；DHM/LeMO: Sophie Scholl。"}],"relationItems":["← 前因：纳粹德国白玫瑰抵抗组织","↔ 相关：纳粹人民法院","→ 后果：战后德国反纳粹抵抗记忆"],"relations":[{"text":"← 前因：纳粹德国白玫瑰抵抗组织","id":"extra236"},{"text":"↔ 相关：纳粹人民法院","id":"extra135"}],"source":"history","id":"extra237"},{"title":"纳粹占领下华沙隔都起义","level":"A","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1943年4月19日—5月16日","place":"德占波兰华沙隔都","summary":"华沙隔都起义是犹太人在纳粹清场驱逐中发动的武装抵抗，成为纳粹犹太人大屠杀中最重要的抵抗事件之一。","fields":[{"label":"标题","value":"纳粹占领下华沙隔都起义"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1943年4月19日—5月16日"},{"label":"地点","value":"德占波兰华沙隔都"},{"label":"主要国家","value":"德国；波兰"},{"label":"一句话概括","value":"华沙隔都起义是犹太人在纳粹清场驱逐中发动的武装抵抗，成为纳粹犹太人大屠杀中最重要的抵抗事件之一。"},{"label":"参与者","value":"犹太战斗组织、犹太军事联盟、华沙隔都居民、SS和德国警察、尤尔根·施特罗普等。"},{"label":"发生了什么","value":"在此前大规模驱逐到特雷布林卡后，华沙隔都剩余犹太人准备武装抵抗。1943年4月，德国进入隔都试图清场，犹太战斗组织等用少量武器、地道和街垒坚持抵抗。德军逐区焚毁建筑、清剿地堡，并在5月16日炸毁大犹太会堂，宣称起义结束。"},{"label":"为什么重要","value":"它不是军事胜利，而是在几乎无生还希望下拒绝被动送死的政治和道德抵抗。"},{"label":"前因","value":"华沙隔都长期饥饿、疾病和驱逐已经摧毁大部分社群；特雷布林卡灭绝营的命运让幸存者意识到“转移”意味着死亡。"},{"label":"后果","value":"隔都被彻底摧毁，大量幸存者被杀害或送往集中营、灭绝营；起义虽未能阻止清场，却成为战后犹太抵抗和纳粹犹太人大屠杀记忆的核心象征。"},{"label":"出处","value":"USHMM Holocaust Encyclopedia: Warsaw Ghetto Uprising；Encyclopaedia Britannica: Warsaw Ghetto Uprising；Yad Vashem: Warsaw Ghetto Uprising。"}],"relationItems":["← 前因：纳粹建立华沙隔都","← 前因：特雷布林卡灭绝营","↔ 相关：纳粹犹太人大屠杀","→ 后果：波兰华沙起义"],"relations":[{"text":"← 前因：纳粹建立华沙隔都","id":"extra216"},{"text":"← 前因：特雷布林卡灭绝营","id":"extra223"},{"text":"↔ 相关：纳粹犹太人大屠杀","id":"extra218"},{"text":"→ 后果：波兰华沙起义","id":"extra257"}],"source":"history","id":"extra238"},{"title":"北非轴心军投降","level":"B","type":"事件卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1943年5月13日","place":"突尼斯及北非战场","summary":"北非轴心军投降结束北非战役，使盟军获得进攻西西里和意大利的跳板。","fields":[{"label":"标题","value":"北非轴心军投降"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1943年5月13日"},{"label":"地点","value":"突尼斯及北非战场"},{"label":"主要国家","value":"德国；意大利；英国；美国；法国"},{"label":"一句话概括","value":"北非轴心军投降结束北非战役，使盟军获得进攻西西里和意大利的跳板。"},{"label":"参与者","value":"纳粹德国非洲军、意大利部队、英美盟军、自由法国和殖民部队、轴心国驻突尼斯部队。"},{"label":"发生了什么","value":"第二次阿拉曼后，轴心军从埃及和利比亚方向撤退；火炬行动后，英美又从西面推进。轴心部队被压缩到突尼斯，补给困难且失去战略空间。1943年5月，大批德意部队向盟军投降，北非战场结束。"},{"label":"为什么重要","value":"它使地中海战局转向欧洲本土，意大利成为盟军下一步进攻目标。"},{"label":"前因","value":"阿拉曼战败和火炬行动形成东西夹击，轴心国在突尼斯方向被压缩；盟军海空优势又使德国和意大利难以维持足够补给。"},{"label":"后果","value":"盟军控制北非和地中海南岸，获得进攻西西里和意大利的跳板；意大利法西斯政权的军事和政治危机迅速加速。"},{"label":"出处","value":"Encyclopaedia Britannica: North Africa campaigns；Imperial War Museums: North African Campaign；National WWII Museum: Tunisia Campaign。"}],"relationItems":["← 前因：第二次阿拉曼战役","← 前因：盟军北非“火炬行动”","→ 后果：盟军登陆西西里岛","↔ 相关：纳粹德国非洲军"],"relations":[{"text":"← 前因：第二次阿拉曼战役","id":"extra232"},{"text":"← 前因：盟军北非“火炬行动”","id":"extra233"},{"text":"→ 后果：盟军登陆西西里岛","id":"extra242"},{"text":"↔ 相关：纳粹德国非洲军","id":"extra202"}],"source":"history","id":"extra239"},{"title":"德国库尔斯克“堡垒行动”","level":"B","type":"制度/文本卡","tags":["战争与外交"],"mainTag":"战争与外交","subTag":"","timeText":"1943年7月5日发动","place":"苏联库尔斯克突出部","summary":"“堡垒行动”是德国对库尔斯克突出部的攻势计划，试图在东线重新夺回主动权。","fields":[{"label":"标题","value":"德国库尔斯克“堡垒行动”"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"时间","value":"1943年7月5日发动"},{"label":"地点","value":"苏联库尔斯克突出部"},{"label":"主要国家","value":"德国；苏联"},{"label":"一句话概括","value":"“堡垒行动”是德国对库尔斯克突出部的攻势计划，试图在东线重新夺回主动权。"},{"label":"制定方/签署方","value":"希特勒和德国最高统帅部，执行者包括中央集团军群和南方集团军群。"},{"label":"主要内容","value":"从库尔斯克突出部南北两翼夹击，切断并消灭苏军突出部兵力，恢复德国东线战略主动。"},{"label":"它试图解决什么问题","value":"斯大林格勒失败后，德国需要一次有限但决定性的胜利来稳定东线和政治士气。"},{"label":"为什么重要","value":"它把库尔斯克战役从“坦克大战”还原为德国战略困境下的最后大型攻势尝试。"},{"label":"争议/局限","value":"行动被多次推迟，苏军获得充分准备时间；德国装甲力量虽强，但无法承受长期消耗。"},{"label":"造成的影响","value":"攻势失败后，德国在东线基本失去战略进攻能力。"},{"label":"出处","value":"Encyclopaedia Britannica: Battle of Kursk；U.S. Army Center of Military History: Kursk materials；German military history references on Operation Citadel。"}],"relationItems":["← 前因：斯大林格勒战役","→ 后果：库尔斯克战役","↔ 相关：纳粹德国闪击战"],"relations":[{"text":"← 前因：斯大林格勒战役","id":"extra230"},{"text":"→ 后果：库尔斯克战役","id":"extra241"},{"text":"↔ 相关：纳粹德国闪击战","id":"extra186"}],"source":"history","id":"extra240"},{"title":"库尔斯克战役","level":"A","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1943年7月5日—8月23日","place":"苏联库尔斯克突出部","summary":"库尔斯克战役中德军最后一次大型东线攻势失败，苏联从此更稳定地掌握战略主动。","fields":[{"label":"标题","value":"库尔斯克战役"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1943年7月5日—8月23日"},{"label":"地点","value":"苏联库尔斯克突出部"},{"label":"主要国家","value":"德国；苏联"},{"label":"一句话概括","value":"库尔斯克战役中德军最后一次大型东线攻势失败，苏联从此更稳定地掌握战略主动。"},{"label":"参与者","value":"德国中央和南方集团军群、苏联红军、朱可夫、曼施坦因、莫德尔、德国装甲部队和苏联防御体系。"},{"label":"发生了什么","value":"德国发动“堡垒行动”，从南北两翼夹击库尔斯克突出部。苏军事先构筑纵深防御、布雷区和反坦克阵地，逐步消耗德军装甲力量。普罗霍罗夫卡等装甲战成为战役象征。德军攻势未能突破，苏军随即发动反攻，收复奥廖尔和哈尔科夫等方向。"},{"label":"为什么重要","value":"它标志德国在东线由进攻转入防御，斯大林格勒后的转折在库尔斯克得到巩固。"},{"label":"前因","value":"德国希望用有限攻势修复斯大林格勒后的战略和士气损失，但苏联已掌握情报并为防御消耗战做足准备。"},{"label":"后果","value":"德国东线装甲力量受重创，预备队和精锐单位被大量消耗；苏联反攻节奏加快，德国再难组织类似规模的战略进攻。"},{"label":"出处","value":"Encyclopaedia Britannica: Battle of Kursk；Encyclopaedia Britannica: Eastern Front, Stalingrad and Kursk；Imperial War Museums: Eastern Front materials。"}],"relationItems":["← 前因：德国库尔斯克“堡垒行动”","← 前因：斯大林格勒战役","→ 后果：苏联红军战略反攻","↔ 相关：纳粹德国东线灭绝战争"],"relations":[{"text":"← 前因：德国库尔斯克“堡垒行动”","id":"extra240"},{"text":"← 前因：斯大林格勒战役","id":"extra230"},{"text":"→ 后果：苏联红军战略反攻","id":"extra856"},{"text":"↔ 相关：纳粹德国东线灭绝战争","id":"extra210"}],"source":"history","id":"extra241"},{"title":"盟军登陆西西里岛","level":"A","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1943年7月9日—8月17日","place":"意大利西西里岛","summary":"盟军登陆西西里岛打开进攻意大利的大门，并直接加速墨索里尼政权倒台。","fields":[{"label":"标题","value":"盟军登陆西西里岛"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1943年7月9日—8月17日"},{"label":"地点","value":"意大利西西里岛"},{"label":"主要国家","value":"美国；英国；加拿大；意大利；德国"},{"label":"一句话概括","value":"盟军登陆西西里岛打开进攻意大利的大门，并直接加速墨索里尼政权倒台。"},{"label":"参与者","value":"美国、英国、加拿大等盟军部队，意大利军队，德国守军，艾森豪威尔、蒙哥马利、巴顿等。"},{"label":"发生了什么","value":"盟军在北非胜利后横渡地中海登陆西西里岛。空降、海军和地面部队协同作战，逐步击败意大利和德国守军。战役期间，意大利国内对继续战争的不满迅速上升，法西斯大委员会和国王推动解除墨索里尼职务。"},{"label":"为什么重要","value":"它把战争带到轴心国欧洲本土，迫使德国分兵防守意大利和地中海。"},{"label":"前因","value":"北非轴心军投降后，盟军获得地中海跳板和空海基地；美英希望通过攻击意大利削弱轴心国同盟，并迫使德国分散兵力。"},{"label":"后果","value":"墨索里尼倒台，意大利新政府寻找与盟军停战，德国则准备接管意大利战场；轴心国同盟开始从内部裂解。"},{"label":"出处","value":"Encyclopaedia Britannica: Allied invasion of Sicily；Encyclopaedia Britannica: Italian Campaign；National WWII Museum: Operation Husky。"}],"relationItems":["← 前因：北非轴心军投降","→ 后果：法西斯意大利墨索里尼倒台","→ 后果：意大利与盟军《卡西比莱停战协定》"],"relations":[{"text":"← 前因：北非轴心军投降","id":"extra239"},{"text":"→ 后果：法西斯意大利墨索里尼倒台","id":"extra243"},{"text":"→ 后果：意大利与盟军《卡西比莱停战协定》","id":"extra244"}],"source":"history","id":"extra242"},{"title":"法西斯意大利墨索里尼倒台","level":"B","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1943年7月24—25日","place":"意大利罗马","summary":"墨索里尼倒台标志意大利法西斯政权崩解，也让德国失去最重要的欧洲盟友。","fields":[{"label":"标题","value":"法西斯意大利墨索里尼倒台"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1943年7月24—25日"},{"label":"地点","value":"意大利罗马"},{"label":"主要国家","value":"意大利；德国"},{"label":"一句话概括","value":"墨索里尼倒台标志意大利法西斯政权崩解，也让德国失去最重要的欧洲盟友。"},{"label":"参与者","value":"贝尼托·墨索里尼、意大利法西斯大委员会、国王维托里奥·埃马努埃莱三世、彼得罗·巴多格里奥。"},{"label":"发生了什么","value":"盟军登陆西西里后，意大利军事和政治危机加深。法西斯大委员会通过动议削弱墨索里尼权力，国王随后召见并逮捕墨索里尼，任命巴多格里奥组阁。新政府表面继续战争，实际上开始寻求与盟军停战。"},{"label":"为什么重要","value":"轴心国同盟由此出现裂缝，德国必须把意大利从盟友区域变成占领和防御战场。"},{"label":"前因","value":"北非失败、西西里登陆和意大利国内战争疲惫使法西斯精英和王室相信继续追随德国会导致国家崩溃。"},{"label":"后果","value":"意大利秘密谈判停战，德国预备接管意大利军队和领土；欧洲南线从盟友协同作战转为德国占领、盟军进攻和意大利内战交织。"},{"label":"出处","value":"Encyclopaedia Britannica: Benito Mussolini；Encyclopaedia Britannica: Italian Campaign；Britannica: Fall of Fascism in Italy references。"}],"relationItems":["← 前因：盟军登陆西西里岛","→ 后果：意大利与盟军《卡西比莱停战协定》","↔ 相关：轴心国《三国同盟条约》"],"relations":[{"text":"← 前因：盟军登陆西西里岛","id":"extra242"},{"text":"→ 后果：意大利与盟军《卡西比莱停战协定》","id":"extra244"},{"text":"↔ 相关：轴心国《三国同盟条约》","id":"extra198"}],"source":"history","id":"extra243"},{"title":"意大利与盟军《卡西比莱停战协定》","level":"B","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1943年9月3日签署，9月8日公布","place":"西西里卡西比莱；意大利和盟军战区","summary":"《卡西比莱停战协定》使意大利退出对盟军作战，德国随即占领意大利大部。","fields":[{"label":"标题","value":"意大利与盟军《卡西比莱停战协定》"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1943年9月3日签署，9月8日公布"},{"label":"地点","value":"西西里卡西比莱；意大利和盟军战区"},{"label":"主要国家","value":"意大利；美国；英国；德国"},{"label":"一句话概括","value":"《卡西比莱停战协定》使意大利退出对盟军作战，德国随即占领意大利大部。"},{"label":"制定方/签署方","value":"意大利巴多格里奥政府代表与盟军代表签署。"},{"label":"主要内容","value":"意大利停止与盟军敌对并接受军事停战条件；公布后意大利军队和政府需要重新选择阵营。"},{"label":"它试图解决什么问题","value":"意大利新政府希望摆脱失败战争，盟军则希望把意大利从轴心体系中剥离。"},{"label":"为什么重要","value":"它把意大利从德国盟友变成战场和分裂国家，迫使德国在南欧投入大量占领和防御资源。"},{"label":"争议/局限","value":"协定公布突然，意大利军队缺乏明确指令，许多部队被德国解除武装或俘虏。"},{"label":"造成的影响","value":"德国发动接管行动，墨索里尼被救出并建立意大利社会共和国，意大利战役长期化。"},{"label":"出处","value":"Avalon Project: Armistice with Italy, September 3, 1943；Encyclopaedia Britannica: Italian Campaign；Treccani: Armistizio di Cassibile。"}],"relationItems":["← 前因：法西斯意大利墨索里尼倒台","→ 后果：纳粹德国占领意大利","→ 后果：意大利社会共和国"],"relations":[{"text":"← 前因：法西斯意大利墨索里尼倒台","id":"extra243"},{"text":"→ 后果：纳粹德国占领意大利","id":"extra245"},{"text":"→ 后果：意大利社会共和国","id":"extra246"}],"source":"history","id":"extra244"},{"title":"纳粹德国占领意大利","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1943年9月起","place":"意大利本土、南法、巴尔干和爱琴海相关意军驻地","summary":"意大利停战后，德国迅速解除意军武装并占领意大利大部，把前盟友区域变成防御战场。","fields":[{"label":"标题","value":"纳粹德国占领意大利"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1943年9月起"},{"label":"地点","value":"意大利本土、南法、巴尔干和爱琴海相关意军驻地"},{"label":"主要国家","value":"德国；意大利"},{"label":"一句话概括","value":"意大利停战后，德国迅速解除意军武装并占领意大利大部，把前盟友区域变成防御战场。"},{"label":"参与者","value":"德国国防军、SS、意大利王国军队、巴多格里奥政府、墨索里尼和意大利法西斯残余力量。"},{"label":"发生了什么","value":"停战公布后，德国启动预备方案，迅速控制意大利北部和中部、罗马及意军在巴尔干和法国等地的驻地。许多意大利士兵被解除武装并送往德国劳役，拒绝合作者遭到屠杀或关押。德国同时营救墨索里尼，扶植意大利社会共和国。"},{"label":"为什么重要","value":"它说明轴心同盟瓦解并没有立即减少德国控制区，反而把意大利变成更复杂的占领、内战和抵抗战场。"},{"label":"前因","value":"意大利停战使德国南翼面临突然崩溃风险，盟军可能利用意大利半岛北上；希特勒需要保住亚平宁半岛和通往中欧的防线。"},{"label":"后果","value":"意大利北部和中部进入德军控制，盟军被迫沿山地缓慢推进，意大利抵抗运动和法西斯合作政权同时出现。"},{"label":"出处","value":"Encyclopaedia Britannica: Italian Campaign；USHMM: German occupation and Holocaust in Italy materials；Avalon Project: Armistice with Italy。"}],"relationItems":["← 前因：意大利与盟军《卡西比莱停战协定》","→ 后果：意大利社会共和国","→ 后果：意大利战役","↔ 相关：纳粹强迫劳动体系"],"relations":[{"text":"← 前因：意大利与盟军《卡西比莱停战协定》","id":"extra244"},{"text":"→ 后果：意大利社会共和国","id":"extra246"},{"text":"↔ 相关：纳粹强迫劳动体系","id":"extra225"}],"source":"history","id":"extra245"},{"title":"意大利社会共和国","level":"C","type":"组织/机构卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1943—1945年","place":"意大利北部；萨洛等地","summary":"意大利社会共和国是德国扶植的墨索里尼傀儡政权，维持法西斯合作和意大利内战。","fields":[{"label":"标题","value":"意大利社会共和国"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1943—1945年"},{"label":"地点","value":"意大利北部；萨洛等地"},{"label":"主要国家","value":"意大利；德国"},{"label":"一句话概括","value":"意大利社会共和国是德国扶植的墨索里尼傀儡政权，维持法西斯合作和意大利内战。"},{"label":"性质/类型","value":"法西斯合作政权和德国占领体系附庸。"},{"label":"成立/解散时间","value":"1943年9月后建立，1945年德国和意大利法西斯失败后崩溃。"},{"label":"核心目标/宗旨","value":"在德国占领保护下延续法西斯统治，动员残余力量对抗盟军和意大利抵抗运动。"},{"label":"关键人物","value":"贝尼托·墨索里尼及意大利法西斯残余领导层。"},{"label":"关键行动/事件","value":"配合德国占领，参与镇压抵抗，重新组织法西斯军政机构，并加剧对犹太人和政治敌人的迫害。"},{"label":"为什么重要","value":"它说明意大利退出轴心后并非立即统一转向盟军，而是陷入国家分裂、占领和内战。"},{"label":"争议/局限","value":"其主权极其有限，关键军事和安全决策受德国控制；但本土合作者仍对镇压和迫害负有责任。"},{"label":"出处","value":"Encyclopaedia Britannica: Italian Social Republic；USHMM: Italy and the Holocaust；Encyclopaedia Britannica: Benito Mussolini。"}],"relationItems":["← 前因：纳粹德国占领意大利","↔ 相关：法国维希政权","↔ 相关：维德孔·吉斯林","→ 后果：意大利抵抗运动"],"relations":[{"text":"← 前因：纳粹德国占领意大利","id":"extra245"},{"text":"↔ 相关：法国维希政权","id":"extra194"},{"text":"↔ 相关：维德孔·吉斯林","id":"extra188"}],"source":"history","id":"extra246"},{"title":"盟军轰炸汉堡“蛾摩拉行动”","level":"B","type":"事件卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1943年7月24日—8月3日","place":"德国汉堡","summary":"汉堡“蛾摩拉行动”造成火风暴和巨大平民伤亡，是盟军战略轰炸德国的重要升级。","fields":[{"label":"标题","value":"盟军轰炸汉堡“蛾摩拉行动”"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1943年7月24日—8月3日"},{"label":"地点","value":"德国汉堡"},{"label":"主要国家","value":"英国；美国；德国"},{"label":"一句话概括","value":"汉堡“蛾摩拉行动”造成火风暴和巨大平民伤亡，是盟军战略轰炸德国的重要升级。"},{"label":"参与者","value":"英国皇家空军、美国陆军航空队、德国防空系统、汉堡平民和救援机构。"},{"label":"发生了什么","value":"盟军对汉堡发动连续空袭，英国夜间轰炸与美国白天轰炸配合。英军使用“窗口”干扰德国雷达，轰炸在部分城区引发火风暴，造成大规模死亡和城市破坏。汉堡作为港口、工业和交通中心受到沉重打击。"},{"label":"为什么重要","value":"它展示战略轰炸从打击工业目标扩展到摧毁城市空间的极端后果。"},{"label":"前因","value":"盟军战略轰炸德国在1942年后扩大，英国希望通过区域轰炸削弱德国城市和士气，美国则参与白天轰炸压力。"},{"label":"后果","value":"德国防空和救灾压力加重，平民战争体验急剧恶化；汉堡也成为战后关于战略轰炸道德争议的重要案例。"},{"label":"出处","value":"Imperial War Museums: Operation Gomorrah；World History Encyclopedia: Operation Gomorrah；Encyclopaedia Britannica: Strategic bombing during World War II。"}],"relationItems":["← 前因：盟军战略轰炸德国","↔ 相关：伦敦大轰炸","→ 后果：盟军轰炸德累斯顿"],"relations":[{"text":"← 前因：盟军战略轰炸德国","id":"extra228"},{"text":"↔ 相关：伦敦大轰炸","id":"extra197"},{"text":"→ 后果：盟军轰炸德累斯顿","id":"extra270"}],"source":"history","id":"extra247"},{"title":"德黑兰会议","level":"A","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1943年11月28日—12月1日","place":"伊朗德黑兰","summary":"德黑兰会议中美英苏确认开辟西欧第二战场，加速形成对德国东西夹击格局。","fields":[{"label":"标题","value":"德黑兰会议"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1943年11月28日—12月1日"},{"label":"地点","value":"伊朗德黑兰"},{"label":"主要国家","value":"苏联；美国；英国；德国"},{"label":"一句话概括","value":"德黑兰会议中美英苏确认开辟西欧第二战场，加速形成对德国东西夹击格局。"},{"label":"参与者","value":"斯大林、罗斯福、丘吉尔及三国军事和外交顾问。"},{"label":"发生了什么","value":"三大盟国领导人首次共同会晤，讨论对德作战、诺曼底登陆、苏联配合攻势、战后边界和国际秩序等问题。会议确认将在1944年发动横渡英吉利海峡的主攻，并使苏联得到西线开辟的明确承诺。"},{"label":"为什么重要","value":"它把德国失败从可能性推进到战略安排：东线苏军反攻和西线登陆将形成结构性夹击。"},{"label":"前因","value":"斯大林格勒和库尔斯克后苏联掌握东线主动，西方盟军在北非和意大利取得进展，但苏联仍要求真正的第二战场。"},{"label":"后果","value":"诺曼底登陆进入更明确准备阶段，苏军也准备配合东线攻势；盟国关于战后德国、东欧边界和国际秩序的讨论开始具体化。"},{"label":"出处","value":"Encyclopaedia Britannica: Tehran Conference；Office of the Historian: The Tehran Conference；National WWII Museum: Tehran Conference。"}],"relationItems":["← 前因：库尔斯克战役","↔ 相关：盟军登陆西西里岛","→ 后果：诺曼底登陆","→ 后果：雅尔塔会议"],"relations":[{"text":"← 前因：库尔斯克战役","id":"extra241"},{"text":"↔ 相关：盟军登陆西西里岛","id":"extra242"},{"text":"→ 后果：诺曼底登陆","id":"extra250"},{"text":"→ 后果：雅尔塔会议","id":"extra265"}],"source":"history","id":"extra248"},{"title":"德国大西洋壁垒","level":"B","type":"概念/思潮卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1942—1944年重点建设","place":"西欧海岸；法国、比利时、荷兰、丹麦、挪威等地","summary":"大西洋壁垒是纳粹德国沿西欧海岸修建的防御体系，旨在阻止盟军跨海登陆。","fields":[{"label":"标题","value":"德国大西洋壁垒"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1942—1944年重点建设"},{"label":"地点","value":"西欧海岸；法国、比利时、荷兰、丹麦、挪威等地"},{"label":"主要国家","value":"德国；法国；英国；美国；加拿大"},{"label":"一句话概括","value":"大西洋壁垒是纳粹德国沿西欧海岸修建的防御体系，旨在阻止盟军跨海登陆。"},{"label":"核心主张/思路","value":"通过海岸炮台、碉堡、雷区、障碍物和要塞化港口，把西欧海岸变成难以突破的防御带。"},{"label":"提出者/代表人物（可选）","value":"希特勒、托特组织、国防军西线指挥体系，后期埃尔温·隆美尔参与强化诺曼底和海岸防御。"},{"label":"它从何而来","value":"法国战败后德国占据漫长西欧海岸，随着英美准备反攻，德国必须用防御工程弥补兵力、制空权和机动预备队不足。"},{"label":"典型表现","value":"诺曼底海滩障碍、海岸炮台、混凝土碉堡、反登陆桩和水下障碍。"},{"label":"为什么重要","value":"它解释诺曼底登陆不是单纯“上岸”，而是对一个多年建设的防御体系的突破。"},{"label":"争议/局限","value":"壁垒宣传上被说成坚不可摧，实际质量和密度差异巨大，且无法弥补德国制空权和战略预备队不足。"},{"label":"出处","value":"Encyclopaedia Britannica: Normandy Invasion, German preparations；Imperial War Museums: The Atlantic Wall；DHM/LeMO: Atlantikwall。"}],"relationItems":["← 前因：二战法国投降与第二次贡比涅停战协定","↔ 相关：埃尔温·隆美尔","→ 后果：诺曼底登陆","↔ 相关：托特组织"],"relations":[{"text":"← 前因：二战法国投降与第二次贡比涅停战协定","id":"extra193"},{"text":"↔ 相关：埃尔温·隆美尔","id":"extra203"},{"text":"→ 后果：诺曼底登陆","id":"extra250"}],"source":"history","id":"extra249"},{"title":"诺曼底登陆","level":"S","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1944年6月6日开始","place":"法国诺曼底海岸；犹他、奥马哈、金、朱诺、剑五个滩头","summary":"诺曼底登陆开辟西欧第二战场，使德国同时面对苏联东线和英美西线的战略夹击。","fields":[{"label":"标题","value":"诺曼底登陆"},{"label":"分级","value":"S"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1944年6月6日开始"},{"label":"地点","value":"法国诺曼底海岸；犹他、奥马哈、金、朱诺、剑五个滩头"},{"label":"主要国家","value":"美国；英国；加拿大；德国；法国"},{"label":"一句话概括","value":"诺曼底登陆开辟西欧第二战场，使德国同时面对苏联东线和英美西线的战略夹击。"},{"label":"参与者","value":"美国、英国、加拿大和其他盟军部队，德国西线守军，艾森豪威尔、蒙哥马利、隆美尔、伦德施泰特等。"},{"label":"发生了什么","value":"盟军在大规模欺骗、空降、海军炮火和空中支援下，于1944年6月6日登陆诺曼底五处海滩。德军因误判登陆地点、指挥体系迟缓、盟军制空权和交通轰炸而难以及时集中反击。盟军付出重大伤亡后建立滩头阵地，并逐步把登陆扩大为解放法国的地面攻势。"},{"label":"为什么重要","value":"这是世界史坐标级节点，标志纳粹德国西线防御被打开，欧洲战场进入东西夹击的最后阶段。"},{"label":"前因","value":"德黑兰会议确认西欧第二战场，盟军在英国长期集结兵力、登陆艇、补给和空中力量；德国则依赖大西洋壁垒和机动预备队试图阻止登陆。"},{"label":"后果","value":"盟军在法国建立持久桥头堡，德国预备队被西线大量牵制并难以集中；东线苏军也在同月发动巴格拉季昂行动，德国陷入双线崩溃压力。"},{"label":"出处","value":"Encyclopaedia Britannica: Normandy Invasion；Imperial War Museums: D-Day and the Normandy Campaign；The National WWII Museum: D-Day。"}],"relationItems":["← 前因：德黑兰会议","← 前因：德国大西洋壁垒","→ 后果：盟军诺曼底突破与法莱兹包围","↔ 相关：苏联“巴格拉季昂行动”"],"relations":[{"text":"← 前因：德黑兰会议","id":"extra248"},{"text":"← 前因：德国大西洋壁垒","id":"extra249"},{"text":"→ 后果：盟军诺曼底突破与法莱兹包围","id":"extra251"},{"text":"↔ 相关：苏联“巴格拉季昂行动”","id":"extra253"}],"source":"history","id":"extra250"},{"title":"盟军诺曼底突破与法莱兹包围","level":"A","type":"事件卡","tags":["战争与外交"],"mainTag":"战争与外交","subTag":"","timeText":"1944年7—8月","place":"法国诺曼底；圣洛、阿夫朗什、法莱兹一线","summary":"诺曼底突破与法莱兹包围摧毁德军西线大量兵力，使盟军从滩头战转入法国解放。","fields":[{"label":"标题","value":"盟军诺曼底突破与法莱兹包围"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"时间","value":"1944年7—8月"},{"label":"地点","value":"法国诺曼底；圣洛、阿夫朗什、法莱兹一线"},{"label":"主要国家","value":"美国；英国；加拿大；德国；法国"},{"label":"一句话概括","value":"诺曼底突破与法莱兹包围摧毁德军西线大量兵力，使盟军从滩头战转入法国解放。"},{"label":"参与者","value":"美国第一集团军、英国和加拿大部队、德国第7集团军和装甲部队、法国抵抗力量。"},{"label":"发生了什么","value":"登陆后盟军一度陷入诺曼底树篱地区的艰苦推进。7月底美军发动“眼镜蛇行动”突破圣洛附近德军防线，随后向阿夫朗什和法国腹地推进。德军反击失败后，大量部队在法莱兹口袋中被包围、伤亡或被俘，残余力量向塞纳河以东撤退。"},{"label":"为什么重要","value":"它把诺曼底登陆的战术成功转化为战略突破，德国西线从坚守海岸转为全面后撤。"},{"label":"前因","value":"盟军在诺曼底建立滩头后，需要突破狭窄地区并打垮德军机动预备队；德国则不断投入装甲力量试图把盟军压回海岸。"},{"label":"后果","value":"巴黎和法国大部迅速获得解放，德国被迫退向本土边境和齐格菲防线；西线战场从登陆滩头争夺转入解放法国和进攻德国。"},{"label":"出处","value":"Encyclopaedia Britannica: Normandy Invasion, breakout；Imperial War Museums: Normandy Campaign；National WWII Museum: Operation Cobra and Falaise Pocket materials。"}],"relationItems":["← 前因：诺曼底登陆","→ 后果：巴黎解放","→ 后果：盟军荷兰“市场花园行动”","↔ 相关：德国大西洋壁垒"],"relations":[{"text":"← 前因：诺曼底登陆","id":"extra250"},{"text":"→ 后果：巴黎解放","id":"extra252"},{"text":"→ 后果：盟军荷兰“市场花园行动”","id":"extra261"},{"text":"↔ 相关：德国大西洋壁垒","id":"extra249"}],"source":"history","id":"extra251"},{"title":"巴黎解放","level":"B","type":"事件卡","tags":["战争与外交","文化与思想"],"mainTag":"战争与外交","subTag":"文化与思想","timeText":"1944年8月19—25日","place":"法国巴黎","summary":"巴黎解放结束德国对法国首都的占领，成为西欧反纳粹战争和法国国家恢复的象征。","fields":[{"label":"标题","value":"巴黎解放"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1944年8月19—25日"},{"label":"地点","value":"法国巴黎"},{"label":"主要国家","value":"法国；德国；美国；英国"},{"label":"一句话概括","value":"巴黎解放结束德国对法国首都的占领，成为西欧反纳粹战争和法国国家恢复的象征。"},{"label":"参与者","value":"法国抵抗力量、自由法国第2装甲师、美国部队、德国驻巴黎守军、夏尔·戴高乐。"},{"label":"发生了什么","value":"诺曼底突破后，巴黎抵抗力量发动起义。盟军原本担心城市战和补给压力，但在法国政治和军事压力下推进巴黎。勒克莱尔率自由法国第2装甲师进入城市，德国守军投降，戴高乐随后进入巴黎，重申法国共和国连续性。"},{"label":"为什么重要","value":"巴黎解放不仅是军事推进，也是法国摆脱维希阴影、重建国家合法性的政治时刻。"},{"label":"前因","value":"法莱兹包围后德军西线崩溃，德国已难以稳定控制法国；法国抵抗运动希望在盟军到来前后以本土行动夺回首都和政治主动权。"},{"label":"后果","value":"法国临时政府威望上升，德国失去重要政治象征和交通节点，西线推进转向比利时、荷兰和德国边境。"},{"label":"出处","value":"Encyclopaedia Britannica: Paris, World War II and Liberation；Imperial War Museums: Liberation of Paris；France Mémoire: Libération de Paris。"}],"relationItems":["← 前因：盟军诺曼底突破与法莱兹包围","↔ 相关：法国维希政权","→ 后果：盟军荷兰“市场花园行动”"],"relations":[{"text":"← 前因：盟军诺曼底突破与法莱兹包围","id":"extra251"},{"text":"↔ 相关：法国维希政权","id":"extra194"},{"text":"→ 后果：盟军荷兰“市场花园行动”","id":"extra261"}],"source":"history","id":"extra252"},{"title":"苏联“巴格拉季昂行动”","level":"A","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1944年6月22日—8月29日","place":"白俄罗斯、波兰东部和波罗的海方向","summary":"巴格拉季昂行动摧毁德国中央集团军群，是东线1944年最决定性的苏联战略攻势。","fields":[{"label":"标题","value":"苏联“巴格拉季昂行动”"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1944年6月22日—8月29日"},{"label":"地点","value":"白俄罗斯、波兰东部和波罗的海方向"},{"label":"主要国家","value":"苏联；德国"},{"label":"一句话概括","value":"巴格拉季昂行动摧毁德国中央集团军群，是东线1944年最决定性的苏联战略攻势。"},{"label":"参与者","value":"苏联红军多个方面军、德国中央集团军群、斯大林、朱可夫、罗科索夫斯基及德国指挥体系。"},{"label":"发生了什么","value":"苏军在诺曼底登陆后不久发动大规模夏季攻势，通过欺骗、纵深突破和多方向合围打击德国中央集团军群。德军防线在白俄罗斯迅速崩溃，大量部队被歼灭或被迫西撤。苏军推进到波兰和东欧边缘，德国东线战略态势急剧恶化。"},{"label":"为什么重要","value":"它与诺曼底登陆共同形成1944年德国东西两线崩盘，是纳粹德国败局不可逆的关键节点。"},{"label":"前因","value":"库尔斯克后苏联掌握东线主动，红军积累了兵力、炮兵和后勤优势；德国预备队又被西线登陆压力牵制，中央集团军群防线变得脆弱。"},{"label":"后果","value":"德国失去白俄罗斯和大量精锐兵力，苏军逼近波兰和德国东部边境，华沙起义的政治军事背景随之形成。"},{"label":"出处","value":"Encyclopaedia Britannica: World War II, Eastern Front June-December 1944；Encyclopedia.com: Bagration Operation；Imperial War Museums: Eastern Front 1944 materials。"}],"relationItems":["← 前因：库尔斯克战役","↔ 相关：诺曼底登陆","→ 后果：波兰华沙起义","→ 后果：苏联红军进入东欧"],"relations":[{"text":"← 前因：库尔斯克战役","id":"extra241"},{"text":"↔ 相关：诺曼底登陆","id":"extra250"},{"text":"→ 后果：波兰华沙起义","id":"extra257"}],"source":"history","id":"extra253"},{"title":"德国1944年7月20日密谋案","level":"B","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1944年7月20日","place":"东普鲁士狼穴；柏林本德勒街等地","summary":"7月20日密谋案是德国军政反希特勒力量刺杀希特勒并发动政变的失败尝试。","fields":[{"label":"标题","value":"德国1944年7月20日密谋案"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1944年7月20日"},{"label":"地点","value":"东普鲁士狼穴；柏林本德勒街等地"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"7月20日密谋案是德国军政反希特勒力量刺杀希特勒并发动政变的失败尝试。"},{"label":"参与者","value":"克劳斯·冯·施陶芬贝格、路德维希·贝克、弗里德里希·奥尔布里希特、亨宁·冯·特雷斯科夫、预备军和纳粹镇压机关。"},{"label":"发生了什么","value":"施陶芬贝格在狼穴会议室放置炸弹后返回柏林，密谋者试图启动“瓦尔基里行动”控制首都和政权机关。但爆炸未杀死希特勒，消息混乱和行动迟缓使政变迅速失败。纳粹当晚镇压柏林密谋者，随后展开大规模逮捕、审判和处决。"},{"label":"为什么重要","value":"它是纳粹德国高层内部最著名的反希特勒行动，显示德国体制内抵抗存在但迟到、分裂且能力有限。"},{"label":"前因","value":"东线和西线败局加深，部分军官和保守反对派认为希特勒继续掌权会毁灭德国，也有人出于道德原因反对纳粹犯罪。"},{"label":"后果","value":"密谋失败后，纳粹加强对军队和社会控制，人民法院进行政治审判和羞辱性宣传；德国抵抗力量遭重创，军队服从链条更紧。"},{"label":"出处","value":"Encyclopaedia Britannica: July Plot；Encyclopaedia Britannica: Claus von Stauffenberg；German History in Documents and Images: July 20, 1944 materials。"}],"relationItems":["← 前因：纳粹德国白玫瑰抵抗组织","↔ 相关：克劳斯·冯·施陶芬贝格","↔ 相关：纳粹人民法院","→ 后果：7月20日密谋失败后的纳粹清洗"],"relations":[{"text":"← 前因：纳粹德国白玫瑰抵抗组织","id":"extra236"},{"text":"↔ 相关：克劳斯·冯·施陶芬贝格","id":"extra255"},{"text":"↔ 相关：纳粹人民法院","id":"extra135"},{"text":"→ 后果：7月20日密谋失败后的纳粹清洗","id":"extra256"}],"source":"history","id":"extra254"},{"title":"克劳斯·冯·施陶芬贝格","level":"B","type":"人物卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1907—1944年","place":"德国、北非战场、东普鲁士狼穴和柏林","summary":"施陶芬贝格是7月20日密谋案的核心执行者，亲自放置刺杀希特勒的炸弹。","fields":[{"label":"标题","value":"克劳斯·冯·施陶芬贝格"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1907—1944年"},{"label":"地点","value":"德国、北非战场、东普鲁士狼穴和柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"施陶芬贝格是7月20日密谋案的核心执行者，亲自放置刺杀希特勒的炸弹。"},{"label":"生卒年/活跃年代","value":"1907年出生，1944年7月21日凌晨被处决。"},{"label":"身份/职务","value":"德国陆军军官，预备军参谋长，反希特勒密谋核心成员。"},{"label":"关键贡献/作为","value":"在狼穴会议室安放炸弹，并返回柏林推动瓦尔基里政变计划。"},{"label":"核心主张/立场","value":"从民族保守军官逐步转向反对希特勒继续统治，目标包括结束战争、推翻纳粹核心权力并重建德国政治秩序。"},{"label":"为什么重要","value":"他是德国抵抗记忆中最具象征性的人物，但他的政治背景也提醒用户抵抗并不等同于现代民主立场。"},{"label":"争议/评价","value":"施陶芬贝格早期并非反纳粹民主派，其转变过程和动机复杂；但他在1944年承担了实际刺杀风险。"},{"label":"关联事件","value":"德国1944年7月20日密谋案。"},{"label":"出处","value":"Encyclopaedia Britannica: Claus von Stauffenberg；DHM/LeMO: Claus Schenk Graf von Stauffenberg；German Resistance Memorial Center: Stauffenberg。"}],"relationItems":["← 前因：德国1944年7月20日密谋案","↔ 相关：德国国防军向希特勒宣誓","→ 后果：7月20日密谋失败后的纳粹清洗"],"relations":[{"text":"← 前因：德国1944年7月20日密谋案","id":"extra254"},{"text":"↔ 相关：德国国防军向希特勒宣誓","id":"extra109"},{"text":"→ 后果：7月20日密谋失败后的纳粹清洗","id":"extra256"}],"source":"history","id":"extra255"},{"title":"7月20日密谋失败后的纳粹清洗","level":"B","type":"事件卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1944年7月后，审判和处决持续至1945年","place":"德国；柏林、普勒岑湖监狱和人民法院","summary":"7月20日失败后，纳粹以审判、处决和连坐方式摧毁德国保守和军事抵抗网络。","fields":[{"label":"标题","value":"7月20日密谋失败后的纳粹清洗"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1944年7月后，审判和处决持续至1945年"},{"label":"地点","value":"德国；柏林、普勒岑湖监狱和人民法院"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"7月20日失败后，纳粹以审判、处决和连坐方式摧毁德国保守和军事抵抗网络。"},{"label":"参与者","value":"盖世太保、SS、纳粹人民法院、罗兰·弗赖斯勒、密谋者及其家属。"},{"label":"发生了什么","value":"刺杀失败后，纳粹迅速逮捕相关军官、官员和反对派人士。人民法院用羞辱性审判制造宣传效果，多名密谋者被处决，家属也遭到监控、拘押或连坐。希特勒利用事件强化军队忠诚审查和党对国家的控制。"},{"label":"为什么重要","value":"它说明纳粹后期即使军事失败迫近，仍能用恐怖和宣传维持内部服从。"},{"label":"前因","value":"7月20日密谋者未能杀死希特勒，也未能有效控制通信、预备军和宣传机关，给纳粹反击留下时间。"},{"label":"后果","value":"德国抵抗网络遭重创，军队内部反希特勒空间进一步缩小；纳粹将“背叛”叙事用于最后阶段动员，把失败解释为内部敌人破坏。"},{"label":"出处","value":"Encyclopaedia Britannica: July Plot；German Resistance Memorial Center: Aftermath of July 20；German History in Documents and Images: SS units seize conspiracy headquarters。"}],"relationItems":["← 前因：德国1944年7月20日密谋案","↔ 相关：纳粹人民法院","↔ 相关：克劳斯·冯·施陶芬贝格","→ 后果：纳粹德国人民冲锋队"],"relations":[{"text":"← 前因：德国1944年7月20日密谋案","id":"extra254"},{"text":"↔ 相关：纳粹人民法院","id":"extra135"},{"text":"↔ 相关：克劳斯·冯·施陶芬贝格","id":"extra255"},{"text":"→ 后果：纳粹德国人民冲锋队","id":"extra262"}],"source":"history","id":"extra256"},{"title":"波兰华沙起义","level":"A","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1944年8月1日—10月2日","place":"德占波兰华沙","summary":"华沙起义是波兰地下军在苏军逼近时发动的反德起义，最终遭德军残酷镇压。","fields":[{"label":"标题","value":"波兰华沙起义"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1944年8月1日—10月2日"},{"label":"地点","value":"德占波兰华沙"},{"label":"主要国家","value":"波兰；德国；苏联"},{"label":"一句话概括","value":"华沙起义是波兰地下军在苏军逼近时发动的反德起义，最终遭德军残酷镇压。"},{"label":"参与者","value":"波兰地下军、波兰流亡政府相关力量、德国国防军、SS和警察部队、苏联红军、华沙平民。"},{"label":"发生了什么","value":"随着苏军推进到华沙附近，波兰地下军希望在苏联进入前解放首都，证明波兰流亡政府和本土抵抗的政治合法性。起义初期控制部分城区，但缺乏重武器和外部支援。德军系统镇压、屠杀平民并摧毁城市。起义失败后，幸存者被驱逐，华沙遭到大规模破坏。"},{"label":"为什么重要","value":"它把反纳粹抵抗、德国占领暴力和苏波政治矛盾集中到同一事件中。"},{"label":"前因","value":"巴格拉季昂行动使苏军逼近波兰，波兰地下国家担心战后主权被苏联主导，因此试图在华沙主动夺权。"},{"label":"后果","value":"华沙城市和人口遭毁灭性打击，波兰非共产主义抵抗力量受重创，战后波兰政治格局更有利于苏联支持的力量。"},{"label":"出处","value":"Encyclopaedia Britannica: Warsaw, Warsaw Uprising；Encyclopaedia Britannica: History of Poland, World War II；Warsaw Rising Museum historical materials。"}],"relationItems":["← 前因：苏联“巴格拉季昂行动”","↔ 相关：纳粹占领下华沙隔都起义","→ 后果：战后波兰边界与政治重组","↔ 相关：纳粹德国东线灭绝战争"],"relations":[{"text":"← 前因：苏联“巴格拉季昂行动”","id":"extra253"},{"text":"↔ 相关：纳粹占领下华沙隔都起义","id":"extra238"},{"text":"↔ 相关：纳粹德国东线灭绝战争","id":"extra210"}],"source":"history","id":"extra257"},{"title":"纳粹德国占领匈牙利","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1944年3月19日","place":"匈牙利；布达佩斯及全国","summary":"德国占领匈牙利是为了阻止盟友脱离战争，也使匈牙利犹太人迅速陷入灭绝体系。","fields":[{"label":"标题","value":"纳粹德国占领匈牙利"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1944年3月19日"},{"label":"地点","value":"匈牙利；布达佩斯及全国"},{"label":"主要国家","value":"德国；匈牙利"},{"label":"一句话概括","value":"德国占领匈牙利是为了阻止盟友脱离战争，也使匈牙利犹太人迅速陷入灭绝体系。"},{"label":"参与者","value":"纳粹德国、匈牙利摄政霍尔蒂、德国军队、SS、匈牙利政府和行政警察体系。"},{"label":"发生了什么","value":"随着轴心国败局加深，德国担心匈牙利寻求退出战争，于1944年3月发动占领行动。霍尔蒂保留名义地位，但德国扶植更合作的政府，并派艾希曼小组进入布达佩斯。德国和匈牙利机构随后迅速组织对犹太人的登记、隔离、财产剥夺和驱逐。"},{"label":"为什么重要","value":"它说明到战争后期，纳粹即使军事形势恶化，仍优先推进反犹灭绝政策。"},{"label":"前因","value":"意大利退出轴心和东线崩溃让德国担心其他盟友倒戈，匈牙利地理位置和剩余犹太人口都极具战略和意识形态意义。"},{"label":"后果","value":"匈牙利犹太人被大规模驱逐到奥斯维辛，艾希曼的运输和灭绝协调达到最后高峰；战争末期的铁路和行政资源仍被投入纳粹犹太人大屠杀。"},{"label":"出处","value":"USHMM Holocaust Encyclopedia: Adolf Eichmann；USHMM: Collaboration and Complicity during the Holocaust；Yad Vashem: The Holocaust in Hungary。"}],"relationItems":["← 前因：意大利与盟军《卡西比莱停战协定》","↔ 相关：阿道夫·艾希曼","→ 后果：匈牙利犹太人被驱逐至奥斯维辛"],"relations":[{"text":"← 前因：意大利与盟军《卡西比莱停战协定》","id":"extra244"},{"text":"↔ 相关：阿道夫·艾希曼","id":"extra221"},{"text":"→ 后果：匈牙利犹太人被驱逐至奥斯维辛","id":"extra259"}],"source":"history","id":"extra258"},{"title":"匈牙利犹太人被驱逐至奥斯维辛","level":"A","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1944年5月—7月为高峰","place":"匈牙利；奥斯维辛-比克瑙","summary":"1944年匈牙利犹太人大规模驱逐使奥斯维辛杀戮能力达到最高峰，是纳粹犹太人大屠杀后期核心事件。","fields":[{"label":"标题","value":"匈牙利犹太人被驱逐至奥斯维辛"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1944年5月—7月为高峰"},{"label":"地点","value":"匈牙利；奥斯维辛-比克瑙"},{"label":"主要国家","value":"德国；匈牙利；波兰"},{"label":"一句话概括","value":"1944年匈牙利犹太人大规模驱逐使奥斯维辛杀戮能力达到最高峰，是纳粹犹太人大屠杀后期核心事件。"},{"label":"参与者","value":"阿道夫·艾希曼及SS小组、匈牙利宪兵和行政机构、匈牙利犹太社群、奥斯维辛SS体系。"},{"label":"发生了什么","value":"德国占领匈牙利后，艾希曼团队与匈牙利当局合作，在短时间内把地方犹太人集中、剥夺财产并装上开往奥斯维辛的列车。大量受害者抵达后被直接送入毒气室，部分被挑选为强迫劳动者。布达佩斯犹太人的驱逐后来因国际压力和政治变化暂时受阻。"},{"label":"为什么重要","value":"它表明在1944年德国败局明显时，纳粹仍把运输、行政和杀戮能力投入灭绝犹太人。"},{"label":"前因","value":"匈牙利此前虽有反犹政策和强迫劳动，但大规模灭绝性驱逐是在德国占领和艾希曼小组抵达后快速展开。"},{"label":"后果","value":"匈牙利犹太社群遭毁灭性打击，奥斯维辛-比克瑙成为纳粹犹太人大屠杀最后高峰的中心地点；幸存者人数、战后记忆和审判证词都深受这一阶段影响。"},{"label":"出处","value":"USHMM Holocaust Encyclopedia: Adolf Eichmann；USHMM: Auschwitz, Hungarian Jews in 1944；Yad Vashem: The Holocaust in Hungary。"}],"relationItems":["← 前因：纳粹德国占领匈牙利","↔ 相关：阿道夫·艾希曼","↔ 相关：奥斯维辛-比克瑙灭绝营","→ 后果：苏军解放奥斯维辛"],"relations":[{"text":"← 前因：纳粹德国占领匈牙利","id":"extra258"},{"text":"↔ 相关：阿道夫·艾希曼","id":"extra221"},{"text":"↔ 相关：奥斯维辛-比克瑙灭绝营","id":"extra224"},{"text":"→ 后果：苏军解放奥斯维辛","id":"extra268"}],"source":"history","id":"extra259"},{"title":"纳粹德国V-1和V-2武器","level":"B","type":"概念/思潮卡","tags":["战争与外交","文化与思想"],"mainTag":"战争与外交","subTag":"文化与思想","timeText":"1944—1945年投入使用","place":"德国、占领区发射基地、英国和欧洲目标城市","summary":"V-1和V-2是纳粹后期“报复武器”，军事效果有限，却预示导弹时代和战后火箭竞争。","fields":[{"label":"标题","value":"纳粹德国V-1和V-2武器"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1944—1945年投入使用"},{"label":"地点","value":"德国、占领区发射基地、英国和欧洲目标城市"},{"label":"主要国家","value":"德国；英国；法国；荷兰"},{"label":"一句话概括","value":"V-1和V-2是纳粹后期“报复武器”，军事效果有限，却预示导弹时代和战后火箭竞争。"},{"label":"核心主张/思路","value":"用无人飞行炸弹和弹道火箭打击远方城市，向德国民众宣称仍有技术奇迹可以扭转战局。"},{"label":"提出者/代表人物（可选）","value":"德国火箭和航空武器研发体系，人物包括韦纳·冯·布劳恩等。"},{"label":"它从何而来","value":"盟军轰炸德国、德国常规空军衰落和纳粹宣传对“最终胜利”的需求，共同推动V武器投入。"},{"label":"典型表现","value":"V-1从1944年6月起攻击伦敦等地，V-2从1944年9月起攻击巴黎、伦敦和安特卫普等目标。"},{"label":"为什么重要","value":"它说明纳粹后期把高技术、强迫劳动和心理战结合起来，但无法改变战略败局。"},{"label":"争议/局限","value":"V武器造成平民伤亡，却耗费巨大资源；其生产还依赖集中营强迫劳动，战后技术成果又被美苏争夺。"},{"label":"出处","value":"Encyclopaedia Britannica: V-2 rocket；Encyclopaedia Britannica: Rocket and missile system, strategic missiles；German History in Documents and Images: V-2 launch preparation。"}],"relationItems":["← 前因：盟军战略轰炸德国","↔ 相关：纳粹强迫劳动体系","→ 后果：战后美苏火箭技术竞赛","↔ 相关：德国本土战争社会崩溃"],"relations":[{"text":"← 前因：盟军战略轰炸德国","id":"extra228"},{"text":"↔ 相关：纳粹强迫劳动体系","id":"extra225"},{"text":"↔ 相关：德国本土战争社会崩溃","id":"extra274"}],"source":"history","id":"extra260"},{"title":"盟军荷兰“市场花园行动”","level":"B","type":"事件卡","tags":["战争与外交"],"mainTag":"战争与外交","subTag":"","timeText":"1944年9月17—27日","place":"德占荷兰；埃因霍温、奈梅亨、阿纳姆等地","summary":"市场花园行动试图用空降和地面突击穿越荷兰直入德国，但在阿纳姆失败。","fields":[{"label":"标题","value":"盟军荷兰“市场花园行动”"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"时间","value":"1944年9月17—27日"},{"label":"地点","value":"德占荷兰；埃因霍温、奈梅亨、阿纳姆等地"},{"label":"主要国家","value":"英国；美国；荷兰；德国"},{"label":"一句话概括","value":"市场花园行动试图用空降和地面突击穿越荷兰直入德国，但在阿纳姆失败。"},{"label":"参与者","value":"英美空降部队、英国第30军、德国西线部队、荷兰抵抗力量和平民。"},{"label":"发生了什么","value":"盟军计划空降部队夺取荷兰多座桥梁，地面装甲纵队沿单一路线快速北上，越过莱茵河进入德国北部平原。行动初期夺取部分目标，但补给和地面推进受阻，阿纳姆桥附近英军空降部队被德军围困并遭重创。"},{"label":"为什么重要","value":"它显示诺曼底突破后盟军并非一路顺利，也说明德国西线仍有恢复防御的能力。"},{"label":"前因","value":"巴黎解放后，盟军希望抓住德军撤退机会尽快进入德国，避免漫长消耗战；但补给线拉长和港口不足也迫使盟军寻找快速突破方案。"},{"label":"后果","value":"盟军未能越过莱茵河形成决定性突破，战争继续拖入1944年冬季，荷兰部分地区还要经历饥荒和占领。"},{"label":"出处","value":"Encyclopaedia Britannica: Operation Market Garden；Imperial War Museums: Operation Market Garden；National WWII Museum: Operation Market Garden。"}],"relationItems":["← 前因：巴黎解放","↔ 相关：盟军诺曼底突破与法莱兹包围","→ 后果：德国阿登反攻"],"relations":[{"text":"← 前因：巴黎解放","id":"extra252"},{"text":"↔ 相关：盟军诺曼底突破与法莱兹包围","id":"extra251"},{"text":"→ 后果：德国阿登反攻","id":"extra263"}],"source":"history","id":"extra261"},{"title":"纳粹德国人民冲锋队","level":"C","type":"组织/机构卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1944年秋—1945年","place":"德国本土和仍由纳粹控制的地区","summary":"人民冲锋队是纳粹德国末期征召老人和少年组成的民兵，体现政权的绝望动员。","fields":[{"label":"标题","value":"纳粹德国人民冲锋队"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1944年秋—1945年"},{"label":"地点","value":"德国本土和仍由纳粹控制的地区"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"人民冲锋队是纳粹德国末期征召老人和少年组成的民兵，体现政权的绝望动员。"},{"label":"性质/类型","value":"纳粹党主导的本土民兵和最后动员组织。"},{"label":"成立/解散时间","value":"1944年秋正式动员，1945年随德国战败瓦解。"},{"label":"核心目标/宗旨","value":"把尚未正规服役的男性动员起来，参与本土防御、工事修筑、警戒和最后阶段作战。"},{"label":"关键人物","value":"希特勒、戈培尔、希姆莱及地方大区长。"},{"label":"关键行动/事件","value":"在东普鲁士、柏林和德国本土防御中投入作战，常由训练不足、装备简陋的老人和少年组成。"},{"label":"为什么重要","value":"它说明总体战动员最终滑向对本国社会的自我消耗，纳粹宁愿牺牲平民也不承认败局。"},{"label":"争议/局限","value":"人民冲锋队宣传价值大于军事价值，少数单位参与激烈作战，但总体训练、装备和指挥严重不足。"},{"label":"出处","value":"DHM/LeMO: Volkssturm；Encyclopaedia Britannica: Volkssturm；USHMM: Indoctrinating Youth and Volkssturm references。"}],"relationItems":["← 前因：纳粹德国总体战动员","↔ 相关：纳粹希特勒青年团","→ 后果：柏林战役","↔ 相关：德国本土战争社会崩溃"],"relations":[{"text":"← 前因：纳粹德国总体战动员","id":"extra235"},{"text":"↔ 相关：纳粹希特勒青年团","id":"extra115"},{"text":"→ 后果：柏林战役","id":"extra276"},{"text":"↔ 相关：德国本土战争社会崩溃","id":"extra274"}],"source":"history","id":"extra262"},{"title":"德国阿登反攻","level":"A","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1944年12月16日—1945年1月","place":"比利时阿登、卢森堡和德国西线","summary":"德国阿登反攻是德国在西线最后一次大型攻势，试图分裂盟军并夺取安特卫普但最终失败。","fields":[{"label":"标题","value":"德国阿登反攻"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1944年12月16日—1945年1月"},{"label":"地点","value":"比利时阿登、卢森堡和德国西线"},{"label":"主要国家","value":"德国；美国；英国；比利时；卢森堡"},{"label":"一句话概括","value":"德国阿登反攻是德国在西线最后一次大型攻势，试图分裂盟军并夺取安特卫普但最终失败。"},{"label":"参与者","value":"德国装甲部队和步兵部队、美国军队、英国部队、希特勒、伦德施泰特、蒙哥马利、巴顿等。"},{"label":"发生了什么","value":"德国在恶劣天气掩护下从阿登森林发动突然攻势，突破美军薄弱防线，形成突出部。德军希望夺取安特卫普、切断盟军补给并制造政治震荡，但燃料不足、道路拥堵、盟军抵抗和天气转晴后的空中打击使攻势逐渐停滞。美军在巴斯托涅等地坚守，盟军随后反击恢复防线。"},{"label":"为什么重要","value":"这是德国最后一次试图主动改变西线战局的豪赌，失败后德国本土几乎不可避免地暴露在盟军进攻下。"},{"label":"前因","value":"市场花园失败后西线短暂稳定，但德国资源已极度紧张；希特勒仍希望用一次突然打击迫使西方盟军动摇。"},{"label":"后果","value":"德国消耗最后一批装甲和燃料预备队，西线防御能力进一步下降，1945年盟军进入德国本土速度加快。"},{"label":"出处","value":"Encyclopaedia Britannica: Battle of the Bulge；National WWII Museum: Battle of the Bulge；U.S. Army Center of Military History: Ardennes-Alsace Campaign。"}],"relationItems":["← 前因：盟军荷兰“市场花园行动”","↔ 相关：纳粹德国人民冲锋队","→ 后果：盟军进入德国本土"],"relations":[{"text":"← 前因：盟军荷兰“市场花园行动”","id":"extra261"},{"text":"↔ 相关：纳粹德国人民冲锋队","id":"extra262"},{"text":"→ 后果：盟军进入德国本土","id":"extra855"}],"source":"history","id":"extra263"},{"title":"西方盟军占领亚琛","level":"C","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1944年10月2—21日","place":"德国亚琛","summary":"亚琛成为西方盟军攻占的第一座德国本土大城市，显示战争已进入德国境内。","fields":[{"label":"标题","value":"西方盟军占领亚琛"},{"label":"分级","value":"C"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1944年10月2—21日"},{"label":"地点","value":"德国亚琛"},{"label":"主要国家","value":"美国；德国"},{"label":"一句话概括","value":"亚琛成为西方盟军攻占的第一座德国本土大城市，显示战争已进入德国境内。"},{"label":"参与者","value":"美国第一集团军、德国守军、亚琛平民和纳粹地方行政。"},{"label":"发生了什么","value":"盟军推进到德国边境后，亚琛因其象征意义和地理位置成为重要目标。美军经过炮击、巷战和包围后迫使德军守军投降。希特勒要求德国城市坚持抵抗，亚琛战斗也预示德国本土城市战将带来更大破坏。"},{"label":"为什么重要","value":"它不是最大战役，却是西线战争进入德国本土的标志性节点。"},{"label":"前因","value":"诺曼底突破和巴黎解放后，盟军推进到德国边境，但补给线拉长、港口能力不足和德国边境防线使攻势放慢。"},{"label":"后果","value":"德国本土战争感进一步加深，平民第一次清楚看到西方盟军进入德国城市；纳粹开始把城市防御、人民冲锋队和最后动员结合起来。"},{"label":"出处","value":"Encyclopaedia Britannica: World War II, Allied invasions of western Europe；U.S. Army Center of Military History: The Battle of Aachen；National WWII Museum: Battle of Aachen。"}],"relationItems":["← 前因：巴黎解放","↔ 相关：纳粹德国人民冲锋队","→ 后果：盟军进入德国本土"],"relations":[{"text":"← 前因：巴黎解放","id":"extra252"},{"text":"↔ 相关：纳粹德国人民冲锋队","id":"extra262"},{"text":"→ 后果：盟军进入德国本土","id":"extra855"}],"source":"history","id":"extra264"},{"title":"雅尔塔会议","level":"A","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1945年2月4—11日","place":"苏联克里米亚雅尔塔","summary":"雅尔塔会议在德国败局已定时讨论占领、赔偿、联合国和战后欧洲安排。","fields":[{"label":"标题","value":"雅尔塔会议"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1945年2月4—11日"},{"label":"地点","value":"苏联克里米亚雅尔塔"},{"label":"主要国家","value":"苏联；美国；英国；德国"},{"label":"一句话概括","value":"雅尔塔会议在德国败局已定时讨论占领、赔偿、联合国和战后欧洲安排。"},{"label":"参与者","value":"约瑟夫·斯大林、富兰克林·罗斯福、温斯顿·丘吉尔及三国外交和军事顾问。"},{"label":"发生了什么","value":"美英苏三国领导人在雅尔塔会晤，讨论如何结束对德战争、如何占领和处理德国、如何安排波兰和东欧政治，以及苏联对日参战和联合国建立等问题。会议没有立即结束战争，却把德国战败后的治理框架提前纳入盟国谈判。"},{"label":"为什么重要","value":"它把纳粹德国军事崩溃和战后欧洲秩序连接起来，是理解德国被分区占领和冷战前夜的关键节点。"},{"label":"前因","value":"斯大林格勒、库尔斯克、诺曼底和巴格拉季昂后，德国败局已难逆转，盟国必须处理胜利后的权力安排。"},{"label":"后果","value":"德国被分区占领的框架进一步明确，战后波兰和东欧问题也埋下美苏分歧；这些安排在德国投降后迅速转化为占领制度和冷战早期矛盾。"},{"label":"出处","value":"Encyclopaedia Britannica: Yalta Conference；Office of the Historian: The Yalta Conference；National WWII Museum: Yalta Conference。"}],"relationItems":["← 前因：德黑兰会议","↔ 相关：诺曼底登陆","↔ 相关：苏联“巴格拉季昂行动”","→ 后果：盟国《波茨坦协定》"],"relations":[{"text":"← 前因：德黑兰会议","id":"extra248"},{"text":"↔ 相关：诺曼底登陆","id":"extra250"},{"text":"↔ 相关：苏联“巴格拉季昂行动”","id":"extra253"},{"text":"→ 后果：盟国《波茨坦协定》","id":"extra3"}],"source":"history","id":"extra265"},{"title":"苏联维斯瓦-奥得攻势","level":"A","type":"事件卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1945年1月12日—2月初","place":"波兰、德国东部；维斯瓦河至奥得河方向","summary":"维斯瓦-奥得攻势让苏军从波兰推进到奥得河，直接威胁柏林。","fields":[{"label":"标题","value":"苏联维斯瓦-奥得攻势"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1945年1月12日—2月初"},{"label":"地点","value":"波兰、德国东部；维斯瓦河至奥得河方向"},{"label":"主要国家","value":"苏联；德国；波兰"},{"label":"一句话概括","value":"维斯瓦-奥得攻势让苏军从波兰推进到奥得河，直接威胁柏林。"},{"label":"参与者","value":"苏联第一白俄罗斯方面军、第一乌克兰方面军、德国东线部队、朱可夫、科涅夫等。"},{"label":"发生了什么","value":"苏军从维斯瓦河桥头堡发动大规模进攻，迅速突破德国防线，解放或占领波兰多地，并推进到奥得河附近。德军组织混乱、防线崩溃，苏军距离柏林已大幅缩短。攻势同时引发德国东部平民大规模逃亡和撤离。"},{"label":"为什么重要","value":"它是柏林战役前最关键的东线推进，使战争真正进入德国核心地区。"},{"label":"前因","value":"巴格拉季昂行动后，德国东线已严重削弱，苏军在波兰获得前进基地和巨大兵力优势；德国则因西线和本土防御压力难以调集足够预备队。"},{"label":"后果","value":"苏军逼近柏林，奥斯维辛等营地被解放，德国东部难民潮和纳粹死亡行军加速；纳粹东线防御从野战防线退化为本土崩溃。"},{"label":"出处","value":"Encyclopaedia Britannica: World War II, The Soviet advance to the Oder；Encyclopaedia Britannica: Eastern Front, From Vistula to the Oder；Imperial War Museums: Eastern Front 1945 materials。"}],"relationItems":["← 前因：苏联“巴格拉季昂行动”","→ 后果：苏军解放奥斯维辛","→ 后果：柏林战役","↔ 相关：德国东部难民潮"],"relations":[{"text":"← 前因：苏联“巴格拉季昂行动”","id":"extra253"},{"text":"→ 后果：苏军解放奥斯维辛","id":"extra268"},{"text":"→ 后果：柏林战役","id":"extra276"},{"text":"↔ 相关：德国东部难民潮","id":"extra267"}],"source":"history","id":"extra266"},{"title":"德国东部难民潮","level":"B","type":"事件卡","tags":["经济与社会","战争与外交"],"mainTag":"经济与社会","subTag":"战争与外交","timeText":"1944年底—1945年","place":"东普鲁士、西里西亚、波美拉尼亚和德国中西部方向","summary":"德国东部难民潮是红军推进和纳粹撤离混乱下的大规模平民逃亡。","fields":[{"label":"标题","value":"德国东部难民潮"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1944年底—1945年"},{"label":"地点","value":"东普鲁士、西里西亚、波美拉尼亚和德国中西部方向"},{"label":"主要国家","value":"德国；苏联；波兰"},{"label":"一句话概括","value":"德国东部难民潮是红军推进和纳粹撤离混乱下的大规模平民逃亡。"},{"label":"参与者","value":"德国东部平民、纳粹地方行政、德国军队、苏联红军、难民接收地区。"},{"label":"发生了什么","value":"苏军逼近德国东部时，大量德国平民向西逃离。纳粹此前常因宣传和禁止撤离拖延疏散，等到前线崩溃时，道路、铁路和海路都陷入混乱。难民遭遇寒冬、轰炸、饥饿、拥挤、海难和暴力，许多人在撤离途中死亡或失散。"},{"label":"为什么重要","value":"它把战争失败从军队层面带入德国社会内部，也是战后德国人口迁移和记忆政治的重要前奏。"},{"label":"前因","value":"苏联维斯瓦-奥得攻势和东普鲁士战事使德国东部防线崩溃，纳粹地方当局又未能及时组织有序撤离。"},{"label":"后果","value":"大量德国人流入中西部地区，战后驱逐、边界变动和住房危机进一步加深；难民问题成为战后德国社会重组的核心压力之一。"},{"label":"出处","value":"Encyclopaedia Britannica: Eastern Front, From Vistula to the Oder；German Historical Museum/LeMO: Flucht und Vertreibung；bpb: Flucht und Vertreibung im Zweiten Weltkrieg。"}],"relationItems":["← 前因：苏联维斯瓦-奥得攻势","↔ 相关：德国本土战争社会崩溃","→ 后果：战后德国饥饿与住房危机","↔ 同时期参考：纳粹死亡行军"],"relations":[{"text":"← 前因：苏联维斯瓦-奥得攻势","id":"extra266"},{"text":"↔ 相关：德国本土战争社会崩溃","id":"extra274"},{"text":"→ 后果：战后德国饥饿与住房危机","id":"extra8"},{"text":"↔ 同时期参考：纳粹死亡行军","id":"extra269"}],"source":"history","id":"extra267"},{"title":"苏军解放奥斯维辛","level":"A","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1945年1月27日","place":"德占波兰奥斯维辛；今波兰奥święcim","summary":"苏军解放奥斯维辛时发现幸存者和犯罪证据，使纳粹灭绝营罪行进一步暴露于世界。","fields":[{"label":"标题","value":"苏军解放奥斯维辛"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1945年1月27日"},{"label":"地点","value":"德占波兰奥斯维辛；今波兰奥święcim"},{"label":"主要国家","value":"苏联；德国；波兰"},{"label":"一句话概括","value":"苏军解放奥斯维辛时发现幸存者和犯罪证据，使纳粹灭绝营罪行进一步暴露于世界。"},{"label":"参与者","value":"苏联红军第一乌克兰方面军、奥斯维辛幸存囚犯、撤退中的SS和纳粹营地体系。"},{"label":"发生了什么","value":"苏军推进到奥斯维辛集中营和灭绝营复合体时，SS已强迫大多数囚犯西撤，只留下病弱者和少量幸存者。1945年1月27日，苏军进入营地，发现幸存者、仓库、焚尸设施痕迹和大量受害者遗物。"},{"label":"为什么重要","value":"它是纳粹犹太人大屠杀记忆的核心日期之一，也是战后追查纳粹犯罪的重要证据节点。"},{"label":"前因","value":"苏联维斯瓦-奥得攻势迫使德军和SS撤离波兰营地，纳粹试图转移囚犯并销毁部分犯罪证据；因此苏军进入时营地已被仓促遗弃。"},{"label":"后果","value":"奥斯维辛成为全球纳粹犹太人大屠杀记忆中心，解放时发现的幸存者、遗物和营地结构成为战后证据；1月27日后来成为国际纳粹犹太人大屠杀纪念日。"},{"label":"出处","value":"USHMM Holocaust Encyclopedia: Auschwitz Key Dates；Auschwitz-Birkenau Memorial: Day of Liberation；German History in Documents and Images: Liberation from Auschwitz。"}],"relationItems":["← 前因：奥斯维辛-比克瑙灭绝营","← 前因：匈牙利犹太人被驱逐至奥斯维辛","↔ 相关：纳粹死亡行军","→ 后果：纳粹战犯纽伦堡审判"],"relations":[{"text":"← 前因：奥斯维辛-比克瑙灭绝营","id":"extra224"},{"text":"← 前因：匈牙利犹太人被驱逐至奥斯维辛","id":"extra259"},{"text":"↔ 相关：纳粹死亡行军","id":"extra269"},{"text":"→ 后果：纳粹战犯纽伦堡审判","id":"extra6"}],"source":"history","id":"extra268"},{"title":"纳粹死亡行军","level":"B","type":"概念/思潮卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1944年底—1945年春","place":"德国、波兰、奥地利和德占中欧地区","summary":"死亡行军是纳粹在败退中强迫营地囚犯西撤，造成大量囚犯死亡的最后阶段犯罪。","fields":[{"label":"标题","value":"纳粹死亡行军"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1944年底—1945年春"},{"label":"地点","value":"德国、波兰、奥地利和德占中欧地区"},{"label":"主要国家","value":"德国；波兰；奥地利；捷克斯洛伐克"},{"label":"一句话概括","value":"死亡行军是纳粹在败退中强迫营地囚犯西撤，造成大量囚犯死亡的最后阶段犯罪。"},{"label":"核心主张/思路","value":"在盟军逼近营地时，SS不释放囚犯，而是强迫他们向德国腹地或其他营地转移，以保留劳动力并隐藏罪证。"},{"label":"提出者/代表人物（可选）","value":"SS营地系统、地方警察和营地指挥人员。"},{"label":"它从何而来","value":"东线和西线同时崩溃，纳粹既要撤退，又不愿让囚犯落入盟军之手成为证人。"},{"label":"典型表现","value":"奥斯维辛、格罗斯-罗森、布痕瓦尔德、弗洛森比格、达豪等营地囚犯被迫长距离步行或转运，途中死于枪杀、饥饿、疾病和寒冷。"},{"label":"为什么重要","value":"它说明纳粹犯罪没有随军事败局自动停止，反而在最后阶段继续杀害已经极度虚弱的受害者。"},{"label":"争议/局限","value":"死亡行军路线和死亡人数因地区而异，很多犯罪现场发生在混乱撤退中，战后追查困难。"},{"label":"出处","value":"USHMM Holocaust Encyclopedia: Death Marches；National WWII Museum: The Nazi Death Marches；Yad Vashem: Death Marches。"}],"relationItems":["← 前因：苏军解放奥斯维辛","↔ 相关：纳粹强迫劳动体系","→ 后果：盟军解放集中营","↔ 同时期参考：德国东部难民潮"],"relations":[{"text":"← 前因：苏军解放奥斯维辛","id":"extra268"},{"text":"↔ 相关：纳粹强迫劳动体系","id":"extra225"},{"text":"↔ 同时期参考：德国东部难民潮","id":"extra267"}],"source":"history","id":"extra269"},{"title":"盟军轰炸德累斯顿","level":"B","type":"事件卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1945年2月13—15日","place":"德国德累斯顿","summary":"德累斯顿轰炸在战争末期造成巨大城市破坏和平民死亡，成为战略轰炸争议的焦点。","fields":[{"label":"标题","value":"盟军轰炸德累斯顿"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1945年2月13—15日"},{"label":"地点","value":"德国德累斯顿"},{"label":"主要国家","value":"英国；美国；德国"},{"label":"一句话概括","value":"德累斯顿轰炸在战争末期造成巨大城市破坏和平民死亡，成为战略轰炸争议的焦点。"},{"label":"参与者","value":"英国皇家空军、美国陆军航空队、德国防空和民防体系、德累斯顿平民和难民。"},{"label":"发生了什么","value":"英美轰炸机对德累斯顿发动多轮空袭，使用高爆弹和燃烧弹摧毁城市中心和交通设施。袭击发生在德国败局已很明显的阶段，城市中还有大量难民。轰炸造成严重火灾、城市破坏和平民伤亡，战后被不同政治力量反复解释和利用。"},{"label":"为什么重要","value":"它是二战战略轰炸道德争议最集中的案例之一，必须同时放在纳粹战争背景和盟军空战选择中理解。"},{"label":"前因","value":"盟军战略轰炸德国已持续升级，1945年盟军希望打击德国交通、军工和东线支援能力；德累斯顿作为交通和区域中心因此被纳入目标体系。"},{"label":"后果","value":"德累斯顿成为战后德国平民受难记忆的核心地点，也被极右翼和冷战宣传反复挪用；围绕伤亡、军事必要性和责任比较的争论持续至今。"},{"label":"出处","value":"Encyclopaedia Britannica: Dresden；Imperial War Museums: Bombing of Dresden；World History Encyclopedia: The Bombing of Dresden in 1945。"}],"relationItems":["← 前因：盟军战略轰炸德国","← 前因：盟军轰炸汉堡“蛾摩拉行动”","↔ 相关：德国东部难民潮"],"relations":[{"text":"← 前因：盟军战略轰炸德国","id":"extra228"},{"text":"← 前因：盟军轰炸汉堡“蛾摩拉行动”","id":"extra247"},{"text":"↔ 相关：德国东部难民潮","id":"extra267"}],"source":"history","id":"extra270"},{"title":"盟军雷马根大桥突破","level":"B","type":"事件卡","tags":["战争与外交"],"mainTag":"战争与外交","subTag":"","timeText":"1945年3月7日","place":"德国雷马根；莱茵河鲁登道夫铁路桥","summary":"美军意外夺取雷马根大桥，在莱茵河东岸建立桥头堡，加速西线进入德国纵深。","fields":[{"label":"标题","value":"盟军雷马根大桥突破"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"时间","value":"1945年3月7日"},{"label":"地点","value":"德国雷马根；莱茵河鲁登道夫铁路桥"},{"label":"主要国家","value":"美国；德国"},{"label":"一句话概括","value":"美军意外夺取雷马根大桥，在莱茵河东岸建立桥头堡，加速西线进入德国纵深。"},{"label":"参与者","value":"美国第9装甲师、德国守桥和防御部队、美军工程部队、德国西线指挥体系。"},{"label":"发生了什么","value":"美军推进到雷马根时，发现莱茵河上的鲁登道夫铁路桥尚未被完全炸毁。美军迅速夺桥并在东岸建立桥头堡，德国随后试图用炮击、空袭和V武器摧毁桥梁。桥后来坍塌，但盟军已获得重要渡河立足点。"},{"label":"为什么重要","value":"莱茵河是德国西线最后天然屏障之一，雷马根突破削弱了德国依托莱茵河拖延战争的希望。"},{"label":"前因","value":"德国阿登反攻失败后，德国西线预备队被消耗殆尽，燃料和机动兵力不足；盟军逐步推进到莱茵河，寻找突破天然屏障的机会。"},{"label":"后果","value":"西方盟军加快进入德国本土，德国西线防御从河防转向城市和区域性迟滞；莱茵河不再能作为拖延战争的可靠屏障。"},{"label":"出处","value":"The Tank Museum: First Across the Rhine, The Bridge at Remagen；U.S. Army Center of Military History: The Remagen Bridgehead；National WWII Museum: Rhine crossing materials。"}],"relationItems":["← 前因：德国阿登反攻","↔ 相关：西方盟军占领亚琛","→ 后果：西方盟军越过莱茵河"],"relations":[{"text":"← 前因：德国阿登反攻","id":"extra263"},{"text":"↔ 相关：西方盟军占领亚琛","id":"extra264"},{"text":"→ 后果：西方盟军越过莱茵河","id":"extra272"}],"source":"history","id":"extra271"},{"title":"西方盟军越过莱茵河","level":"A","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1945年3月","place":"德国莱茵河沿线；雷马根、韦塞尔等地","summary":"西方盟军越过莱茵河后，德国西线最后天然防线瓦解，盟军进入德国腹地。","fields":[{"label":"标题","value":"西方盟军越过莱茵河"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1945年3月"},{"label":"地点","value":"德国莱茵河沿线；雷马根、韦塞尔等地"},{"label":"主要国家","value":"美国；英国；加拿大；德国"},{"label":"一句话概括","value":"西方盟军越过莱茵河后，德国西线最后天然防线瓦解，盟军进入德国腹地。"},{"label":"参与者","value":"美军、英军、加拿大军队、德国西线部队、艾森豪威尔、蒙哥马利等盟军指挥官。"},{"label":"发生了什么","value":"雷马根桥头堡建立后，盟军又在莱茵河多处组织大规模渡河行动，包括空降和工程架桥配合。德国已缺乏足够兵力和空中力量阻止渡河。盟军突破莱茵河防线后，鲁尔工业区和德国中部道路向西方盟军打开。"},{"label":"为什么重要","value":"它标志德国西线防御从战略屏障阶段进入全面崩溃阶段。"},{"label":"前因","value":"德国阿登反攻失败和雷马根大桥被夺使德国无法稳定组织莱茵河防御，西线兵力、燃料和空中掩护都严重不足。"},{"label":"后果","value":"盟军包围鲁尔、推进到易北河，并与苏军在德国中部会师；德国西部工业核心和东西联系被切断，投降已不可避免。"},{"label":"出处","value":"Encyclopaedia Britannica: World War II, Allied advance into Germany；U.S. Army Center of Military History: Rhineland Campaign；Imperial War Museums: Crossing the Rhine。"}],"relationItems":["← 前因：盟军雷马根大桥突破","↔ 相关：德国阿登反攻","→ 后果：美苏易北河会师","→ 后果：柏林战役"],"relations":[{"text":"← 前因：盟军雷马根大桥突破","id":"extra271"},{"text":"↔ 相关：德国阿登反攻","id":"extra263"},{"text":"→ 后果：美苏易北河会师","id":"extra275"},{"text":"→ 后果：柏林战役","id":"extra276"}],"source":"history","id":"extra272"},{"title":"希特勒《尼禄命令》","level":"B","type":"制度/文本卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1945年3月19日","place":"德国","summary":"《尼禄命令》要求破坏德国基础设施，体现希特勒末期宁可毁灭国家也不承认失败。","fields":[{"label":"标题","value":"希特勒《尼禄命令》"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1945年3月19日"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"《尼禄命令》要求破坏德国基础设施，体现希特勒末期宁可毁灭国家也不承认失败。"},{"label":"制定方/签署方","value":"阿道夫·希特勒签发，德国军政和地方机构被要求执行。"},{"label":"主要内容","value":"命令破坏交通、工业、通信、供水、电力和其他可能被盟军利用的设施。"},{"label":"它试图解决什么问题","value":"希特勒希望用焦土方式阻止盟军使用德国资源，同时把失败归咎于德国人民“不配生存”。"},{"label":"为什么重要","value":"这份命令说明纳粹国家最后阶段已经从动员社会转向可能毁灭本国社会的逻辑。"},{"label":"争议/局限","value":"阿尔贝特·斯佩尔等人战后声称抵制或削弱命令执行，但这种自我叙述也服务于其“救德国”的形象建构。"},{"label":"造成的影响","value":"命令没有被完全执行，但局部破坏加剧德国基础设施和战后恢复压力。"},{"label":"出处","value":"German History in Documents and Images: Hitler’s Scorched Earth Decree (Nero Decree)；Deutschlandmuseum: Hitler’s “Nero Order”；DHM/LeMO: Kriegsende 1945。"}],"relationItems":["← 前因：德国本土战争社会崩溃","↔ 相关：阿尔贝特·斯佩尔","→ 后果：柏林战役"],"relations":[{"text":"← 前因：德国本土战争社会崩溃","id":"extra274"},{"text":"↔ 相关：阿尔贝特·斯佩尔","id":"extra227"},{"text":"→ 后果：柏林战役","id":"extra276"}],"source":"history","id":"extra273"},{"title":"德国本土战争社会崩溃","level":"B","type":"概念/思潮卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1944—1945年","place":"德国本土；城市、农村、难民路线和前线后方","summary":"德国本土战争社会崩溃指轰炸、难民、征兵、物资短缺和政权恐怖共同瓦解日常生活。","fields":[{"label":"标题","value":"德国本土战争社会崩溃"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1944—1945年"},{"label":"地点","value":"德国本土；城市、农村、难民路线和前线后方"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国本土战争社会崩溃指轰炸、难民、征兵、物资短缺和政权恐怖共同瓦解日常生活。"},{"label":"核心主张/思路","value":"纳粹政权用总体战和最后动员维持战斗，但德国社会已被轰炸、前线逼近、难民潮和物资危机撕裂。"},{"label":"提出者/代表人物（可选）","value":"不是单一人物提出，而是对纳粹末期社会状态的概括。"},{"label":"它从何而来","value":"盟军战略轰炸、东线崩溃、西线进入德国、强迫劳动体系瓦解和纳粹拒绝投降共同造成。"},{"label":"典型表现","value":"城市废墟、铁路瘫痪、难民拥挤、人民冲锋队动员、食物和住房短缺、处决逃兵和“失败主义者”。"},{"label":"为什么重要","value":"它补足战争史中常被战役叙事遮蔽的社会层面：德国不是只在战场失败，也在内部生活秩序上崩塌。"},{"label":"争议/局限","value":"德国平民受难不能被用来抵消或遮蔽德国发动侵略战争和实施纳粹犹太人大屠杀的责任。"},{"label":"出处","value":"DHM/LeMO: Kriegsende 1945；Encyclopaedia Britannica: World War II, Germany’s surrender；bpb materials on German society in 1945。"}],"relationItems":["← 前因：盟军战略轰炸德国","← 前因：德国东部难民潮","↔ 相关：纳粹德国人民冲锋队","→ 后果：战后德国饥饿与住房危机"],"relations":[{"text":"← 前因：盟军战略轰炸德国","id":"extra228"},{"text":"← 前因：德国东部难民潮","id":"extra267"},{"text":"↔ 相关：纳粹德国人民冲锋队","id":"extra262"},{"text":"→ 后果：战后德国饥饿与住房危机","id":"extra8"}],"source":"history","id":"extra274"},{"title":"美苏易北河会师","level":"A","type":"事件卡","tags":["战争与外交","文化与思想"],"mainTag":"战争与外交","subTag":"文化与思想","timeText":"1945年4月25日","place":"德国托尔高附近易北河","summary":"易北河会师标志美苏军队在德国中部相遇，纳粹德国被东西两面切开。","fields":[{"label":"标题","value":"美苏易北河会师"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1945年4月25日"},{"label":"地点","value":"德国托尔高附近易北河"},{"label":"主要国家","value":"美国；苏联；德国"},{"label":"一句话概括","value":"易北河会师标志美苏军队在德国中部相遇，纳粹德国被东西两面切开。"},{"label":"参与者","value":"美国陆军、苏联红军、德国残余部队、盟军指挥体系。"},{"label":"发生了什么","value":"西方盟军从莱茵河以东推进，苏军从东线向德国中部推进。1945年4月25日，美军和苏军在易北河托尔高附近会师。会师具有强烈象征意义，显示德国已被盟军从东西方向分割，纳粹政权的军事空间所剩无几。"},{"label":"为什么重要","value":"它是欧洲战争最后阶段的标志性场景，也预示德国将被不同盟国占领区分割。"},{"label":"前因","value":"西方盟军越过莱茵河后快速推进，苏军则在柏林方向发动最后攻势；两条战线同时压缩，使德国中部成为会师地带。"},{"label":"后果","value":"德国军事上被切成残片，东西线残余部队难以互相支援；柏林战役和最终投降进入倒计时，盟军占领区边界也开始具有现实形态。"},{"label":"出处","value":"U.S. National Archives: Elbe Day；National WWII Museum: Elbe Day；Encyclopaedia Britannica: World War II, Germany’s surrender。"}],"relationItems":["← 前因：西方盟军越过莱茵河","↔ 相关：苏联维斯瓦-奥得攻势","→ 后果：柏林战役","→ 后果：纳粹德国无条件投降"],"relations":[{"text":"← 前因：西方盟军越过莱茵河","id":"extra272"},{"text":"↔ 相关：苏联维斯瓦-奥得攻势","id":"extra266"},{"text":"→ 后果：柏林战役","id":"extra276"},{"text":"→ 后果：纳粹德国无条件投降","id":"extra1"}],"source":"history","id":"extra275"},{"title":"柏林战役","level":"S","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1945年4月16日—5月2日","place":"德国柏林及周边地区","summary":"柏林战役是纳粹德国首都的最后争夺，直接导致希特勒自杀和第三帝国崩溃。","fields":[{"label":"标题","value":"柏林战役"},{"label":"分级","value":"S"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1945年4月16日—5月2日"},{"label":"地点","value":"德国柏林及周边地区"},{"label":"主要国家","value":"苏联；德国；波兰"},{"label":"一句话概括","value":"柏林战役是纳粹德国首都的最后争夺，直接导致希特勒自杀和第三帝国崩溃。"},{"label":"参与者","value":"苏联红军、波兰部队、德国国防军残部、SS、人民冲锋队、希特勒青年团、柏林平民。"},{"label":"发生了什么","value":"苏军从奥得河和尼斯河方向发动总攻，突破泽洛高地后包围柏林。德军用正规军残部、SS、人民冲锋队和少年兵进行城市防御。柏林陷入炮击、巷战、地下掩体生活和社会崩溃。希特勒在地堡中拒绝撤离，最终自杀；5月2日柏林守军投降。"},{"label":"为什么重要","value":"这是世界史坐标级节点，标志纳粹政权核心空间被攻克，欧洲战争进入最终投降阶段。"},{"label":"前因","value":"维斯瓦-奥得攻势和后续东线推进使苏军抵达德国首都外围，西方盟军则已从西面进入德国腹地；柏林成为最后政治象征和军事目标。"},{"label":"后果","value":"希特勒自杀，柏林被苏军占领，德国中央指挥体系彻底瓦解；弗伦斯堡政府只能处理投降残局，纳粹政权进入最后清算阶段。"},{"label":"出处","value":"Encyclopaedia Britannica: World War II, Germany’s surrender；Imperial War Museums: Battle of Berlin；National WWII Museum: Battle of Berlin。"}],"relationItems":["← 前因：苏联维斯瓦-奥得攻势","← 前因：美苏易北河会师","→ 后果：柏林地堡希特勒自杀","→ 后果：纳粹德国无条件投降","↔ 相关：纳粹德国人民冲锋队"],"relations":[{"text":"← 前因：苏联维斯瓦-奥得攻势","id":"extra266"},{"text":"← 前因：美苏易北河会师","id":"extra275"},{"text":"→ 后果：柏林地堡希特勒自杀","id":"extra277"},{"text":"→ 后果：纳粹德国无条件投降","id":"extra1"},{"text":"↔ 相关：纳粹德国人民冲锋队","id":"extra262"}],"source":"history","id":"extra276"},{"title":"柏林地堡希特勒自杀","level":"A","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1945年4月30日","place":"德国柏林；元首地堡","summary":"希特勒在柏林战役末期自杀，纳粹政权失去核心领袖但战争仍持续数日。","fields":[{"label":"标题","value":"柏林地堡希特勒自杀"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1945年4月30日"},{"label":"地点","value":"德国柏林；元首地堡"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"希特勒在柏林战役末期自杀，纳粹政权失去核心领袖但战争仍持续数日。"},{"label":"参与者","value":"阿道夫·希特勒、爱娃·布劳恩、约瑟夫·戈培尔、马丁·鲍曼、元首地堡人员和逼近柏林的苏军。"},{"label":"发生了什么","value":"苏军包围并攻入柏林时，希特勒留在元首地堡，拒绝撤离。4月29日他与爱娃·布劳恩结婚，并在政治遗嘱中任命邓尼茨为继任国家元首。4月30日，希特勒和爱娃·布劳恩自杀，尸体被焚烧。"},{"label":"为什么重要","value":"它结束了希特勒个人统治，但不等于德国立即投降，说明纳粹国家机器仍能短暂延续。"},{"label":"前因","value":"柏林战役使希特勒失去逃脱和继续指挥的现实条件，东西线崩溃也使“最终胜利”宣传彻底破产；地堡成为纳粹政权最后的封闭空间。"},{"label":"后果","value":"邓尼茨成为名义继任者并组织弗伦斯堡政府，德国投降谈判进入最后阶段；纳粹政权从个人独裁退化为等待盟军接管的残余行政。"},{"label":"出处","value":"Encyclopaedia Britannica: How Did Adolf Hitler Die?；Encyclopaedia Britannica: Adolf Hitler, World War II；National WWII Museum: The Death of Adolf Hitler。"}],"relationItems":["← 前因：柏林战役","↔ 相关：纳粹元首国家","→ 后果：卡尔·邓尼茨","→ 后果：纳粹德国弗伦斯堡政府"],"relations":[{"text":"← 前因：柏林战役","id":"extra276"},{"text":"↔ 相关：纳粹元首国家","id":"extra110"},{"text":"→ 后果：卡尔·邓尼茨","id":"extra278"},{"text":"→ 后果：纳粹德国弗伦斯堡政府","id":"extra279"}],"source":"history","id":"extra277"},{"title":"卡尔·邓尼茨","level":"B","type":"人物卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1891—1980年；1945年短暂任德国国家元首","place":"德国；弗伦斯堡、海军和潜艇战场","summary":"邓尼茨是德国潜艇战核心指挥官，也是希特勒指定的最后继任国家元首。","fields":[{"label":"标题","value":"卡尔·邓尼茨"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1891—1980年；1945年短暂任德国国家元首"},{"label":"地点","value":"德国；弗伦斯堡、海军和潜艇战场"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"邓尼茨是德国潜艇战核心指挥官，也是希特勒指定的最后继任国家元首。"},{"label":"生卒年/活跃年代","value":"1891年出生，1980年去世；二战核心角色集中在1939—1945年。"},{"label":"身份/职务","value":"德国海军元帅，潜艇部队指挥官，1945年5月短暂担任德国国家元首。"},{"label":"关键贡献/作为","value":"组织大西洋潜艇战和狼群战术，1943年任海军总司令；希特勒死后领导弗伦斯堡政府并处理投降。"},{"label":"核心主张/立场","value":"职业海军军官，忠于纳粹战争机器，末期试图优先向西方盟军投降以让更多德军和平民逃离苏军。"},{"label":"为什么重要","value":"他把二战德国海军战争和纳粹政权最后投降阶段连接起来。"},{"label":"争议/评价","value":"纽伦堡审判中邓尼茨被判有罪，其“只是军人”的辩护不能抹去潜艇战和继续作战的责任。"},{"label":"关联事件","value":"大西洋战役；德国潜艇“狼群战术”；弗伦斯堡政府。"},{"label":"出处","value":"Encyclopaedia Britannica: Karl Dönitz；Encyclopaedia Britannica: Battle of the Atlantic；National WWII Museum: Dönitz and Germany’s surrender materials。"}],"relationItems":["← 前因：德国潜艇“狼群战术”","← 前因：柏林地堡希特勒自杀","→ 后果：纳粹德国弗伦斯堡政府","→ 后果：纳粹战犯纽伦堡审判"],"relations":[{"text":"← 前因：德国潜艇“狼群战术”","id":"extra200"},{"text":"← 前因：柏林地堡希特勒自杀","id":"extra277"},{"text":"→ 后果：纳粹德国弗伦斯堡政府","id":"extra279"},{"text":"→ 后果：纳粹战犯纽伦堡审判","id":"extra6"}],"source":"history","id":"extra278"},{"title":"纳粹德国弗伦斯堡政府","level":"B","type":"组织/机构卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1945年5月2日—5月23日","place":"德国北部弗伦斯堡-米尔维克","summary":"弗伦斯堡政府是希特勒死后邓尼茨领导的残余政府，主要功能是处理德国投降残局。","fields":[{"label":"标题","value":"纳粹德国弗伦斯堡政府"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1945年5月2日—5月23日"},{"label":"地点","value":"德国北部弗伦斯堡-米尔维克"},{"label":"主要国家","value":"德国；英国；美国；苏联"},{"label":"一句话概括","value":"弗伦斯堡政府是希特勒死后邓尼茨领导的残余政府，主要功能是处理德国投降残局。"},{"label":"性质/类型","value":"纳粹德国末期残余中央政府。"},{"label":"成立/解散时间","value":"1945年5月初形成，5月23日被盟军逮捕解散。"},{"label":"核心目标/宗旨","value":"尽量让德军向西方盟军投降、拖延或区分东西线投降，同时维持名义国家连续性。"},{"label":"关键人物","value":"卡尔·邓尼茨、路德维希·施韦林·冯·克罗西克等。"},{"label":"关键行动/事件","value":"授权签署德国无条件投降，试图维持行政残余，最终被英国军队逮捕。"},{"label":"为什么重要","value":"它说明第三帝国不是在希特勒死亡瞬间行政上消失，而是在盟军接管下被彻底终结。"},{"label":"争议/局限","value":"弗伦斯堡政府没有真正主权，也未被盟国承认为合法战后政府，其存在更多是投降过渡中的残余现象。"},{"label":"出处","value":"Encyclopaedia Britannica: Karl Dönitz；DHM/LeMO: Kriegsende 1945；German History in Documents and Images: German surrender and the end of the Reich。"}],"relationItems":["← 前因：柏林地堡希特勒自杀","↔ 相关：卡尔·邓尼茨","→ 后果：纳粹德国无条件投降","→ 后果：盟国管制委员会"],"relations":[{"text":"← 前因：柏林地堡希特勒自杀","id":"extra277"},{"text":"↔ 相关：卡尔·邓尼茨","id":"extra278"},{"text":"→ 后果：纳粹德国无条件投降","id":"extra1"},{"text":"→ 后果：盟国管制委员会","id":"extra4"}],"source":"history","id":"extra279"},{"title":"纳粹德国第175条加严","level":"B","type":"制度/文本卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1935年","place":"德国","summary":"纳粹加严刑法第175条，扩大对男同性恋者的刑事迫害和集中营关押。","fields":[{"label":"标题","value":"纳粹德国第175条加严"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1935年"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"纳粹加严刑法第175条，扩大对男同性恋者的刑事迫害和集中营关押。"},{"label":"制定方/签署方","value":"纳粹德国司法和立法机构。"},{"label":"主要内容","value":"扩大可被定罪的同性性行为范围，加重处罚，并使警察和法院更容易以模糊标准追捕男性同性恋者。"},{"label":"它试图解决什么问题","value":"纳粹把同性恋男性视为威胁民族共同体、生育秩序和军国男性气质的对象。"},{"label":"为什么重要","value":"它说明纳粹迫害不只针对政治敌人和犹太人，也系统攻击性少数群体。"},{"label":"争议/局限","value":"第175条战后在西德长期保留，造成许多受害者解放后仍难以获得承认。"},{"label":"造成的影响","value":"大量男性被调查、判刑或送入集中营，粉红三角成为相关迫害记忆的象征。"},{"label":"出处","value":"USHMM Holocaust Encyclopedia: Gay Men under the Nazi Regime；USHMM: Nazi Persecution of Homosexuals 1933-1945；Experiencing History: Sexuality, Gender, and Nazi Persecution。"}],"relationItems":["← 前因：德国刑法典第175条","↔ 相关：马格努斯·赫希菲尔德性科学研究所","↔ 相关：纳粹保护性拘留制度","→ 后果：纳粹集中营医学实验"],"relations":[{"text":"← 前因：德国刑法典第175条","id":"extra721"},{"text":"↔ 相关：马格努斯·赫希菲尔德性科学研究所","id":"card72"},{"text":"↔ 相关：纳粹保护性拘留制度","id":"extra150"},{"text":"→ 后果：纳粹集中营医学实验","id":"extra282"}],"source":"history","id":"extra280"},{"title":"纳粹德国帝国刑事警察局","level":"C","type":"组织/机构卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1936年后中央化，1939年并入帝国安全总局体系","place":"德国；柏林及全国刑警网络","summary":"帝国刑事警察局把刑事警察中央化，并与SS安全体系结合，服务纳粹社会控制。","fields":[{"label":"标题","value":"纳粹德国帝国刑事警察局"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1936年后中央化，1939年并入帝国安全总局体系"},{"label":"地点","value":"德国；柏林及全国刑警网络"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"帝国刑事警察局把刑事警察中央化，并与SS安全体系结合，服务纳粹社会控制。"},{"label":"性质/类型","value":"纳粹德国刑事警察中央机构。"},{"label":"成立/解散时间","value":"1936年警察中央化后形成帝国层面刑警体系，1939年成为帝国安全总局第五局。"},{"label":"核心目标/宗旨","value":"侦查普通犯罪，同时追踪和关押纳粹定义的“职业犯罪者”“反社会者”等群体。"},{"label":"关键人物（可选）","value":"阿图尔·内贝等。"},{"label":"关键行动/事件","value":"参与犯罪人登记、预防性拘押、集中营送押和占领区安全工作。"},{"label":"为什么重要","value":"它连接魏玛刑侦专业化和纳粹警察国家，说明专业警务可被极权政权改造为社会清洗工具。"},{"label":"争议/局限","value":"刑警并非全部等同盖世太保，但其专业知识和档案体系成为纳粹迫害的重要资源。"},{"label":"出处","value":"Encyclopaedia Britannica: Kriminalpolizei；Virtual Shtetl: Kriminalpolizei；Humboldt University: Die Berliner Kriminalpolizei in Republik und Nationalsozialismus。"}],"relationItems":["← 前因：魏玛柏林凶杀科改革","↔ 相关：纳粹“职业犯罪者”集中营关押机制","↔ 相关：纳粹盖世太保","→ 后果：纳粹保护性拘留制度"],"relations":[{"text":"← 前因：魏玛柏林凶杀科改革","id":"card170"},{"text":"↔ 相关：纳粹“职业犯罪者”集中营关押机制","id":"extra141"},{"text":"↔ 相关：纳粹盖世太保","id":"extra106"},{"text":"→ 后果：纳粹保护性拘留制度","id":"extra150"}],"source":"history","id":"extra281"},{"title":"纳粹集中营医学实验","level":"A","type":"事件卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1939—1945年，战争期间扩大","place":"纳粹集中营；达豪、奥斯维辛、拉文斯布吕克等","summary":"纳粹集中营医学实验在囚犯身上实施强制人体实验，是医学犯罪和种族国家暴力的集中表现。","fields":[{"label":"标题","value":"纳粹集中营医学实验"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1939—1945年，战争期间扩大"},{"label":"地点","value":"纳粹集中营；达豪、奥斯维辛、拉文斯布吕克等"},{"label":"主要国家","value":"德国；欧洲多国受害者"},{"label":"一句话概括","value":"纳粹集中营医学实验在囚犯身上实施强制人体实验，是医学犯罪和种族国家暴力的集中表现。"},{"label":"参与者","value":"SS医生、德国医学机构、集中营管理体系、囚犯受害者、军方和制药相关利益。"},{"label":"发生了什么","value":"纳粹医生在未经同意的囚犯身上进行低温、高空、传染病、药物、绝育、骨骼和毒气等实验。受害者包括犹太人、罗姆人、波兰人、苏军战俘、同性恋者和其他集中营囚犯。许多人被折磨、致残或杀害，实验结果常服务军方、种族政策或医生个人晋升。"},{"label":"为什么重要","value":"它彻底破坏医学伦理，战后直接推动纽伦堡医生审判和现代人体研究伦理规范。"},{"label":"前因","value":"纳粹种族主义和优生政策把被关押群体视为可支配材料，集中营制度又剥夺了囚犯拒绝实验和寻求救济的可能。战争中的低温、高空、传染病和药物需求进一步刺激党卫队医生把人体实验当作军事医学资源。"},{"label":"后果","value":"战后盟军在纽伦堡医生审判中追究部分涉案医生和官员责任，集中营医学实验成为纳粹罪行的重要证据。审判经验促成《纽伦堡法典》，使自愿同意、风险控制和医学伦理审查成为战后医学伦理的重要原则来源。"},{"label":"出处","value":"USHMM Holocaust Encyclopedia: Nazi Medical Experiments；USHMM: Doctors Trial；Yad Vashem: Medical Experiments during the Holocaust。"}],"relationItems":["← 前因：纳粹优生政策","← 前因：奥斯维辛-比克瑙灭绝营","↔ 相关：纳粹保护性拘留制度","→ 后果：纽伦堡医生审判"],"relations":[{"text":"← 前因：纳粹优生政策","id":"extra118"},{"text":"← 前因：奥斯维辛-比克瑙灭绝营","id":"extra224"},{"text":"↔ 相关：纳粹保护性拘留制度","id":"extra150"},{"text":"→ 后果：纽伦堡医生审判","id":"extra853"}],"source":"history","id":"extra282"},{"title":"卡尔·勃兰特","level":"C","type":"人物卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1904—1948年；纳粹医学权力高峰为1939—1945年","place":"德国；纳粹医学和卫生行政体系","summary":"卡尔·勃兰特是希特勒私人医生和T4行动负责人之一，战后在医生审判中被处决。","fields":[{"label":"标题","value":"卡尔·勃兰特"},{"label":"分级","value":"C"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1904—1948年；纳粹医学权力高峰为1939—1945年"},{"label":"地点","value":"德国；纳粹医学和卫生行政体系"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"卡尔·勃兰特是希特勒私人医生和T4行动负责人之一，战后在医生审判中被处决。"},{"label":"生卒年/活跃年代","value":"1904年出生，1948年被处决。"},{"label":"身份/职务","value":"外科医生、希特勒随从医生、纳粹卫生和医学政策高层人物。"},{"label":"关键贡献/作为","value":"参与组织T4“安乐死”杀害计划，战争后期担任卫生和医疗领域重要职务。"},{"label":"核心主张/立场","value":"以纳粹种族卫生和战争国家需求为医疗政策服务对象，将医生角色服从于杀戮和排除。"},{"label":"为什么重要","value":"他说明纳粹医学犯罪不是边缘医生的个人暴行，而是与国家最高权力相连的制度实践。"},{"label":"争议/评价","value":"战后纽伦堡医生审判认定其对医学犯罪负有重大责任，判处死刑。"},{"label":"关联事件","value":"纳粹T4行动；纳粹集中营医学实验；纽伦堡医生审判。"},{"label":"出处","value":"USHMM Holocaust Encyclopedia: Karl Brandt；USHMM: Doctors Trial；Encyclopaedia Britannica: Nuremberg Trials, subsequent trials。"}],"relationItems":["← 前因：纳粹T4行动","↔ 相关：纳粹集中营医学实验","→ 后果：纽伦堡医生审判"],"relations":[{"text":"← 前因：纳粹T4行动","id":"extra128"},{"text":"↔ 相关：纳粹集中营医学实验","id":"extra282"},{"text":"→ 后果：纽伦堡医生审判","id":"extra853"}],"source":"history","id":"extra283"},{"title":"纳粹德国焚书运动","level":"B","type":"事件卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1933年5月前后","place":"柏林及德国多个大学城市","summary":"1933年纳粹学生组织和支持者公开焚烧所谓“非德国”书籍，把文化清洗变成可观看的政治仪式。","fields":[{"label":"标题","value":"纳粹德国焚书运动"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1933年5月前后"},{"label":"地点","value":"柏林及德国多个大学城市"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1933年纳粹学生组织和支持者公开焚烧所谓“非德国”书籍，把文化清洗变成可观看的政治仪式。"},{"label":"参与者","value":"德国学生会、纳粹学生组织、宣传部门、大学师生、冲锋队和地方支持者。"},{"label":"发生了什么","value":"1933年纳粹上台后，亲纳粹学生组织发起“反非德国精神”运动，列出被视为犹太、左翼、自由主义、和平主义或“堕落”的作者和作品。5月10日前后，柏林和许多大学城市举行公开焚书仪式，学生、党组织和围观群众把书籍投入火堆，戈培尔等纳粹高层在部分场合发表宣传演说，把书籍毁灭包装成民族文化净化。"},{"label":"为什么重要","value":"焚书运动把思想控制、反犹主义和大学青年动员结合起来，是纳粹文化统制的标志性场面。"},{"label":"前因","value":"纳粹夺权后迅速推进一体化，大学学生组织、出版社和图书馆成为文化清洗目标；魏玛时期多元出版、性科学研究、马克思主义和现代主义文化都被纳粹视为要清除的对象。"},{"label":"后果","value":"许多作家、学者和出版人流亡或被封杀，公共文化空间急速收缩；焚书也预示了纳粹德国将用国家暴力处理思想、族群和政治敌人。"},{"label":"出处","value":"USHMM Holocaust Encyclopedia, Nazi Book Burnings；DHM Blog, Consigned to the Flames。"}],"relationItems":["← 前因：纳粹夺权","→ 后果：纳粹德国帝国文化院","↔ 相关：马格努斯·赫希菲尔德性科学研究所","↔ 相关：纳粹德国《报刊编辑法》","↔ 同时期参考：苏联文化审查"],"relations":[{"text":"← 前因：纳粹夺权","id":"extra852"},{"text":"→ 后果：纳粹德国帝国文化院","id":"extra125"},{"text":"↔ 相关：马格努斯·赫希菲尔德性科学研究所","id":"card72"},{"text":"↔ 相关：纳粹德国《报刊编辑法》","id":"extra151"}],"source":"history","id":"extra284"},{"title":"纳粹德国人民收音机","level":"C","type":"概念/思潮卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1933年起","place":"纳粹德国","summary":"人民收音机是纳粹推动的低价广播接收设备，目的是把政治演说、新闻和宣传带入普通家庭。","fields":[{"label":"标题","value":"纳粹德国人民收音机"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1933年起"},{"label":"地点","value":"纳粹德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"人民收音机是纳粹推动的低价广播接收设备，目的是把政治演说、新闻和宣传带入普通家庭。"},{"label":"核心主张/思路","value":"通过降低收音机价格和扩大广播覆盖，让更多家庭能接收国家控制下的广播内容。"},{"label":"提出者/代表人物（可选）","value":"约瑟夫·戈培尔推动，工程师奥托·格里辛参与设计。"},{"label":"它从何而来","value":"魏玛广播网络已经建立，但广播接收设备价格和收听规模仍有限；纳粹把广播视为绕过报纸阅读门槛、直接塑造群众情绪的媒介。"},{"label":"典型表现","value":"低价、标准化、便于大量生产；常与希特勒演说、国家仪式、战争消息和日常宣传节目配套使用。"},{"label":"为什么重要","value":"它说明极权宣传依赖具体技术和消费品，不只是口号。收音机把国家声音带入客厅，使政治动员更日常化。"},{"label":"争议/局限","value":"设备并不能自动保证每个听众都相信宣传；同时德国民众也可能偷听外国广播，因此纳粹后期加强对“敌台”收听的惩罚。"},{"label":"出处","value":"Smithsonian Institution, German type DKE 38 Volksempfänger radio receiver；DW, Vor 90 Jahren: der Volksempfänger als Instrument der Nazi-Propaganda。"}],"relationItems":["← 前因：魏玛德国帝国广播公司","→ 后果：纳粹宣传机器","↔ 相关：纳粹德国帝国宣传部","↔ 相关：纳粹高速公路宣传","↔ 同时期参考：苏联广播宣传"],"relations":[{"text":"← 前因：魏玛德国帝国广播公司","id":"card173"},{"text":"→ 后果：纳粹宣传机器","id":"extra94"},{"text":"↔ 相关：纳粹德国帝国宣传部","id":"extra146"},{"text":"↔ 相关：纳粹高速公路宣传","id":"extra123"}],"source":"history","id":"extra285"},{"title":"纳粹德国学校课程纳粹化","level":"B","type":"概念/思潮卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1933—1945年","place":"纳粹德国学校体系","summary":"纳粹政权把种族主义、领袖崇拜、军事化和反犹主义注入学校课程，把教育变成政治塑造工具。","fields":[{"label":"标题","value":"纳粹德国学校课程纳粹化"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1933—1945年"},{"label":"地点","value":"纳粹德国学校体系"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"纳粹政权把种族主义、领袖崇拜、军事化和反犹主义注入学校课程，把教育变成政治塑造工具。"},{"label":"核心主张/思路","value":"学校应培养服从希特勒、相信种族等级、愿意为民族共同体和战争服务的青年，而不是培养独立共和公民。"},{"label":"提出者/代表人物（可选）","value":"纳粹教育行政、全国教师联盟、希特勒青年团和宣传部门共同推动。"},{"label":"它从何而来","value":"纳粹夺权后一体化教育系统，清洗不可靠教师和教材，压制魏玛时期的共和教育、自由主义教育和改革教育传统。"},{"label":"典型表现","value":"生物课强化种族卫生和遗传观念，历史课服务民族主义叙事，体育和军事训练地位上升，反犹主义内容进入教材与课堂。"},{"label":"为什么重要","value":"它解释纳粹政权如何试图塑造下一代政治忠诚，把学校、青年组织和宣传机器连成一套社会控制体系。"},{"label":"争议/局限","value":"课程纳粹化不等于所有教师和学生都完全内化意识形态，但它显著压缩了批判教育空间，并为种族迫害和战争动员提供心理准备。"},{"label":"出处","value":"Britannica, Education: Nazi Germany；USHMM Holocaust Encyclopedia, Nazi Racism and related educational material。"}],"relationItems":["← 前因：魏玛德国学校改革运动","→ 后果：纳粹希特勒青年团","↔ 相关：纳粹德国全国教师联盟","↔ 相关：纳粹优生政策","↔ 同时期参考：意大利法西斯青年教育"],"relations":[{"text":"← 前因：魏玛德国学校改革运动","id":"card172"},{"text":"→ 后果：纳粹希特勒青年团","id":"extra115"},{"text":"↔ 相关：纳粹德国全国教师联盟","id":"extra288"},{"text":"↔ 相关：纳粹优生政策","id":"extra118"}],"source":"history","id":"extra286"},{"title":"纳粹德国大学清洗","level":"B","type":"事件卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1933年起","place":"纳粹德国各大学","summary":"1933年后纳粹政权通过法律和政治压力驱逐犹太人、左翼和自由派学者，重塑德国大学生态。","fields":[{"label":"标题","value":"纳粹德国大学清洗"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1933年起"},{"label":"地点","value":"纳粹德国各大学"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1933年后纳粹政权通过法律和政治压力驱逐犹太人、左翼和自由派学者，重塑德国大学生态。"},{"label":"参与者","value":"纳粹政府、大学行政、学生组织、教授群体、被驱逐的犹太和政治异见学者。"},{"label":"发生了什么","value":"纳粹夺权后，《职业公务员法》等措施被用于大学和研究机构，许多犹太裔、左翼、民主派或政治上不可靠的学者被停职、退休、解雇或迫使流亡。学生组织和纳粹教师、讲师组织也参与施压，大学课程、任命和学术公共空间迅速向纳粹意识形态靠拢。"},{"label":"为什么重要","value":"德国原本是世界研究型大学中心之一，大学清洗使德国学术遭受重大损失，同时推动大量科学家、人文学者和医生流亡英美等地。"},{"label":"前因","value":"德意志帝国和魏玛时期德国大学具有强大国际学术地位，但也存在民族主义、反犹主义和保守教授文化；纳粹夺权后，这些结构被法律暴力和党组织动员迅速改造。"},{"label":"后果","value":"德国大学失去大量人才，许多流亡学者改变英美学术和科学版图；留在德国的大学则更深卷入战争研究、种族政策和纳粹国家服务。"},{"label":"出处","value":"Michael Grüttner, The Expulsion of Academic Teaching Staff from German Universities, 1933-45；LMU Munich, 1933 historical overview。"}],"relationItems":["← 前因：德意志帝国研究型大学扩张","→ 后果：德国去纳粹化","↔ 相关：纳粹德国焚书运动","↔ 相关：纳粹德国全国教师联盟","↔ 同时期参考：欧洲学术流亡"],"relations":[{"text":"← 前因：德意志帝国研究型大学扩张","id":"extra821"},{"text":"→ 后果：德国去纳粹化","id":"extra5"},{"text":"↔ 相关：纳粹德国焚书运动","id":"extra284"},{"text":"↔ 相关：纳粹德国全国教师联盟","id":"extra288"}],"source":"history","id":"extra287"},{"title":"纳粹德国全国教师联盟","level":"C","type":"组织/机构卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1929—1943年","place":"德国","summary":"全国教师联盟把教师职业组织纳入纳粹党体系，协助学校思想控制、教师动员和教育一体化。","fields":[{"label":"标题","value":"纳粹德国全国教师联盟"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1929—1943年"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"全国教师联盟把教师职业组织纳入纳粹党体系，协助学校思想控制、教师动员和教育一体化。"},{"label":"性质/类型","value":"纳粹党外围教师组织和职业动员机构。"},{"label":"成立/解散时间","value":"1929年成立；纳粹掌权后影响扩大，1943年停止独立运作。"},{"label":"核心目标/宗旨","value":"把教师培养为纳粹意识形态执行者，通过组织、培训和职业压力确保课堂服务于种族主义、民族主义和领袖原则。"},{"label":"关键人物（可选）","value":"汉斯·舍姆等纳粹教育组织人物。"},{"label":"关键行动/事件","value":"吸纳教师入会，推广纳粹教育材料和培训，协助排斥政治上或种族上被视为不可靠的教育工作者。"},{"label":"为什么重要","value":"它连接国家教育行政和基层课堂，使纳粹化不只是课程文件变化，也通过教师日常行为进入学生生活。"},{"label":"争议/局限","value":"组织并不能完全控制每个教师的真实想法，但它通过职业压力和政治审查显著削弱教师独立性。"},{"label":"出处","value":"Britannica, Education: Nazi Germany；National Socialist Teachers League historical summaries。"}],"relationItems":["← 前因：纳粹德国学校课程纳粹化","→ 后果：德国去纳粹化","↔ 相关：纳粹希特勒青年团","↔ 相关：纳粹德国大学清洗","↔ 同时期参考：苏联教师政治培训"],"relations":[{"text":"← 前因：纳粹德国学校课程纳粹化","id":"extra286"},{"text":"→ 后果：德国去纳粹化","id":"extra5"},{"text":"↔ 相关：纳粹希特勒青年团","id":"extra115"},{"text":"↔ 相关：纳粹德国大学清洗","id":"extra287"}],"source":"history","id":"extra288"},{"title":"纳粹德国《婚姻健康法》","level":"C","type":"制度/文本卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1935年10月18日","place":"纳粹德国","summary":"1935年《婚姻健康法》把结婚资格同遗传健康、种族政策和国家人口目标绑定，是纳粹优生治理的一部分。","fields":[{"label":"标题","value":"纳粹德国《婚姻健康法》"},{"label":"分级","value":"C"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1935年10月18日"},{"label":"地点","value":"纳粹德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1935年《婚姻健康法》把结婚资格同遗传健康、种族政策和国家人口目标绑定，是纳粹优生治理的一部分。"},{"label":"制定方/签署方","value":"纳粹德国政府。"},{"label":"主要内容","value":"法律要求婚姻登记前出具婚姻健康证明，并以遗传病、传染病、精神疾病等理由限制某些婚姻成立。"},{"label":"它试图解决什么问题","value":"纳粹政权把婚姻视为“民族身体”再生产工具，试图阻止被视为遗传上“不适合”的人繁衍，并把私人婚姻纳入国家种族卫生管理。"},{"label":"为什么重要","value":"它补足了纳粹家庭政策的法律层面：鼓励“合格”人口生育，与禁止、隔离、绝育和排斥“非合格”人口是同一套逻辑。"},{"label":"争议/局限","value":"法律以医学和公共健康语言包装国家对个人婚姻和生育的强制控制，侵犯身体自主和婚姻自由。"},{"label":"造成的影响","value":"婚姻登记、医生证明和遗传健康审查结合起来，强化了纳粹对家庭和人口再生产的制度控制。"},{"label":"出处","value":"Gesetz zum Schutze der Erbgesundheit des deutschen Volkes (1935), verfassungen.de；GHDI, Law for the Prevention of Offspring with Hereditary Diseases。"}],"relationItems":["← 前因：纳粹优生政策","→ 后果：纳粹德国生命之泉协会","↔ 相关：纳粹《遗传病后代预防法》","↔ 相关：纳粹家庭政策","↔ 同时期参考：美国优生绝育法"],"relations":[{"text":"← 前因：纳粹优生政策","id":"extra118"},{"text":"→ 后果：纳粹德国生命之泉协会","id":"extra290"},{"text":"↔ 相关：纳粹《遗传病后代预防法》","id":"extra127"},{"text":"↔ 相关：纳粹家庭政策","id":"extra117"}],"source":"history","id":"extra289"},{"title":"纳粹德国生命之泉协会","level":"C","type":"组织/机构卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1935—1945年","place":"德国及被占领欧洲部分地区","summary":"生命之泉协会是党卫队推动的生育和儿童机构，服务于纳粹种族卫生、人口政策和“优质血统”再生产想象。","fields":[{"label":"标题","value":"纳粹德国生命之泉协会"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1935—1945年"},{"label":"地点","value":"德国及被占领欧洲部分地区"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"生命之泉协会是党卫队推动的生育和儿童机构，服务于纳粹种族卫生、人口政策和“优质血统”再生产想象。"},{"label":"性质/类型","value":"党卫队关联的注册协会和生育、儿童照护机构网络。"},{"label":"成立/解散时间","value":"1935年12月由海因里希·希姆莱推动成立；1945年纳粹战败后终结。"},{"label":"核心目标/宗旨","value":"为按纳粹标准被认定为“种族上有价值”的母亲和儿童提供产育、照护和收养安排，鼓励所谓“优质”德国人口增长。"},{"label":"关键人物（可选）","value":"海因里希·希姆莱。"},{"label":"关键行动/事件","value":"在德国和被占领地区设立产院和儿童之家；与党卫队家庭政策、种族审查和被占领地区儿童转移问题相连。"},{"label":"为什么重要","value":"它显示纳粹人口政策不只是奖章和宣传，还通过机构、医生、社会工作和儿童安置直接介入生育过程。"},{"label":"争议/局限","value":"生命之泉常被简单想象成“繁殖工厂”，这不准确；但它确实服务于种族主义生育政策，并与被占领地区儿童掠夺和同化问题存在联系。"},{"label":"出处","value":"Bundesarchiv, Der Lebensborn e.V. der SS；Deutschlandmuseum, SS-Verein Lebensborn, 1935。"}],"relationItems":["← 前因：纳粹德国《婚姻健康法》","→ 后果：纳粹德国儿童掠夺与日耳曼化政策","↔ 相关：纳粹母亲十字勋章","↔ 相关：纳粹优生政策","↔ 同时期参考：苏联人口奖励政策"],"relations":[{"text":"← 前因：纳粹德国《婚姻健康法》","id":"extra289"},{"text":"↔ 相关：纳粹母亲十字勋章","id":"extra131"},{"text":"↔ 相关：纳粹优生政策","id":"extra118"}],"source":"history","id":"extra290"},{"title":"纳粹德国摇摆青年","level":"C","type":"概念/思潮卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1930年代后期—1940年代","place":"汉堡、柏林等德国城市","summary":"摇摆青年通过爵士、美国化服饰和舞会同希特勒青年团的纪律文化拉开距离，是纳粹德国城市青年反文化现象。","fields":[{"label":"标题","value":"纳粹德国摇摆青年"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1930年代后期—1940年代"},{"label":"地点","value":"汉堡、柏林等德国城市"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"摇摆青年通过爵士、美国化服饰和舞会同希特勒青年团的纪律文化拉开距离，是纳粹德国城市青年反文化现象。"},{"label":"核心主张/思路","value":"通过听爵士和摇摆乐、穿英美风格服饰、参加舞会和使用戏仿语言，表达对纳粹青年组织、军事化和文化管制的疏离。"},{"label":"提出者/代表人物（可选）","value":"不是正式组织，而是汉堡、柏林等城市中松散的青年圈子。"},{"label":"它从何而来","value":"魏玛时期爵士和舞厅文化已经在德国城市流行；纳粹上台后压制“非德国”音乐和青年自由，反而使某些音乐风格变成距离政权的符号。"},{"label":"典型表现","value":"秘密或半公开舞会、收藏唱片、模仿英美服饰、用“Swing Heil”等戏仿问候语嘲弄纳粹仪式。"},{"label":"为什么重要","value":"它提醒用户，纳粹德国社会不是铁板一块。即使在高压环境中，青年也可能通过音乐、身体和风格进行有限抵抗或逃离。"},{"label":"争议/局限","value":"摇摆青年并不一定都有明确政治纲领，很多行动更像生活方式反抗；但政权仍把它视为纪律、种族和民族文化秩序的威胁。"},{"label":"出处","value":"National WWII Museum, “Swing Heil”: Swing Youth, Schlurfs, and others in Nazi Germany；GHDI, Listening to Swing Music (1937)；USHMM, Hitler Youth。"}],"relationItems":["← 前因：魏玛德国爵士文化","→ 后果：纳粹德国白玫瑰抵抗组织","↔ 相关：纳粹希特勒青年团","↔ 相关：纳粹德国帝国文化院","↔ 同时期参考：法国 zazou 青年文化"],"relations":[{"text":"← 前因：魏玛德国爵士文化","id":"card184"},{"text":"→ 后果：纳粹德国白玫瑰抵抗组织","id":"extra236"},{"text":"↔ 相关：纳粹希特勒青年团","id":"extra115"},{"text":"↔ 相关：纳粹德国帝国文化院","id":"extra125"}],"source":"history","id":"extra291"},{"title":"纳粹德国与梵蒂冈《帝国协约》","level":"B","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1933年7月20日签署","place":"梵蒂冈；柏林","summary":"1933年《帝国协约》是纳粹德国与教廷签订的政教条约，试图用外交协议处理天主教会在德国的地位。","fields":[{"label":"标题","value":"纳粹德国与梵蒂冈《帝国协约》"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1933年7月20日签署"},{"label":"地点","value":"梵蒂冈；柏林"},{"label":"主要国家","value":"德国；梵蒂冈"},{"label":"一句话概括","value":"1933年《帝国协约》是纳粹德国与教廷签订的政教条约，试图用外交协议处理天主教会在德国的地位。"},{"label":"制定方/签署方","value":"圣座与德意志国；代表包括欧根尼奥·帕切利和弗朗茨·冯·巴本。"},{"label":"主要内容","value":"协约确认天主教会在德国的若干宗教和教育权利，涉及教会组织、宗教教育、神职人员、青年组织和政党活动限制等问题。"},{"label":"它试图解决什么问题","value":"纳粹政权希望削弱天主教政治力量并获得国际合法性；教廷则希望在德国一体化压力下为教会活动争取法律保障。"},{"label":"为什么重要","value":"它展示纳粹政权早期如何通过外交和法律形式稳定统治，而不是只靠公开暴力；也把德国宗教问题放进国际关系框架。"},{"label":"争议/局限","value":"协约长期争议很大。批评者认为它客观上提高纳粹政权合法性，支持者则强调教廷试图保护教会空间；纳粹后来多次违反协约。"},{"label":"造成的影响","value":"德国中央党政治空间进一步消失；1937年教皇庇护十一世发表《急难之中》通谕，抗议纳粹违约和教会受压。"},{"label":"出处","value":"Vatican, Konkordat zwischen dem Hl. Stuhl und dem Deutschen Reich, 20. Juli 1933；DHM LeMO, Reichskonkordat 1933。"}],"relationItems":["← 前因：德国中央党","→ 后果：德国新教教会斗争","↔ 相关：纳粹夺权","↔ 相关：纳粹德国德意志基督徒运动","↔ 同时期参考：墨索里尼与《拉特兰条约》"],"relations":[{"text":"← 前因：德国中央党","id":"extra673"},{"text":"→ 后果：德国新教教会斗争","id":"extra153"},{"text":"↔ 相关：纳粹夺权","id":"extra852"},{"text":"↔ 相关：纳粹德国德意志基督徒运动","id":"extra152"}],"source":"history","id":"extra292"},{"title":"纳粹德国配给票制度","level":"C","type":"制度/文本卡","tags":["经济与社会","战争与外交"],"mainTag":"经济与社会","subTag":"战争与外交","timeText":"1939年起，二战期间持续","place":"纳粹德国及部分占领区","summary":"纳粹德国二战初期即实行配给票制度，把食品、衣物和燃料消费纳入战争经济控制。","fields":[{"label":"标题","value":"纳粹德国配给票制度"},{"label":"分级","value":"C"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1939年起，二战期间持续"},{"label":"地点","value":"纳粹德国及部分占领区"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"纳粹德国二战初期即实行配给票制度，把食品、衣物和燃料消费纳入战争经济控制。"},{"label":"制定方/签署方","value":"纳粹德国政府、经济与粮食管理部门。"},{"label":"主要内容","value":"通过食品票、衣物票和其他配给凭证限制个人购买量，按年龄、职业、劳动强度和政治种族身份区分供应。"},{"label":"它试图解决什么问题","value":"战争经济需要把有限粮食和原料优先分配给军队、军工和被认为重要的人口，同时避免一战式饥饿危机引发社会动荡。"},{"label":"为什么重要","value":"配给票把战争带入每个家庭和商店，说明总体战不只在前线发生，也在厨房、排队和购物本上发生。"},{"label":"争议/局限","value":"配给并不平等。犹太人、强迫劳动者、战俘和被占领地区民众常被系统性压低供应，德国本土消费者则依赖占领掠夺维持水平。"},{"label":"造成的影响","value":"黑市、替代食品、家庭储藏和对占领区资源的依赖加深；战后配给制度在德国仍持续多年。"},{"label":"出处","value":"German History in Documents and Images, rationing and wartime economy materials；USHMM, Food and Hunger under Nazi rule references。"}],"relationItems":["← 前因：纳粹德国四年计划","→ 后果：战后德国配给票制度","↔ 相关：纳粹德国饥饿计划","↔ 相关：纳粹德国总体战动员","↔ 同时期参考：英国二战配给制度"],"relations":[{"text":"← 前因：纳粹德国四年计划","id":"extra122"},{"text":"→ 后果：战后德国配给票制度","id":"extra54"},{"text":"↔ 相关：纳粹德国饥饿计划","id":"extra208"},{"text":"↔ 相关：纳粹德国总体战动员","id":"extra235"}],"source":"history","id":"extra293"},{"title":"纳粹德国《德国周刊》新闻片","level":"C","type":"组织/机构卡","tags":["文化与思想","战争与外交"],"mainTag":"文化与思想","subTag":"战争与外交","timeText":"1940—1945年","place":"纳粹德国电影院和占领区影院","summary":"《德国周刊》把战争新闻、前线影像和宣传叙事带进电影院，是纳粹战时视听宣传的重要载体。","fields":[{"label":"标题","value":"纳粹德国《德国周刊》新闻片"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1940—1945年"},{"label":"地点","value":"纳粹德国电影院和占领区影院"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"《德国周刊》把战争新闻、前线影像和宣传叙事带进电影院，是纳粹战时视听宣传的重要载体。"},{"label":"性质/类型","value":"国家控制的电影新闻片系列。"},{"label":"成立/解散时间","value":"1940年整合形成；1945年纳粹德国战败后停止。"},{"label":"核心目标/宗旨","value":"在故事片放映前向观众提供经过剪辑和配音的战争新闻与政治宣传，塑造德国胜利、军队英勇和敌人形象。"},{"label":"关键人物（可选）","value":"约瑟夫·戈培尔宣传部、新闻片摄影队、电影发行系统。"},{"label":"关键行动/事件","value":"报道闪电战、东线、空袭、防御战和国内动员，用旁白、音乐和镜头组织观众情绪。"},{"label":"为什么重要","value":"它说明纳粹宣传不是只靠广播和集会，电影院里的“新闻”也被变成战争体验和政治教育。"},{"label":"争议/局限","value":"新闻片具有现场影像外观，但内容经严格选择和剪辑；战局恶化后，影像真实感与宣传乐观叙事之间矛盾加深。"},{"label":"出处","value":"Deutsches Historisches Museum / LeMO, Deutsche Wochenschau；Bundesarchiv film holdings, Die Deutsche Wochenschau；USHMM film and propaganda references。"}],"relationItems":["← 前因：魏玛德国电影院日常","→ 后果：纳粹德国总体战动员","↔ 相关：纳粹宣传机器","↔ 相关：莱妮·里芬施塔尔《意志的胜利》","↔ 同时期参考：英国战时新闻片"],"relations":[{"text":"← 前因：魏玛德国电影院日常","id":"card187"},{"text":"→ 后果：纳粹德国总体战动员","id":"extra235"},{"text":"↔ 相关：纳粹宣传机器","id":"extra94"},{"text":"↔ 相关：莱妮·里芬施塔尔《意志的胜利》","id":"extra88"}],"source":"history","id":"extra294"},{"title":"纳粹德国MEFO票据","level":"B","type":"制度/文本卡","tags":["经济与社会","战争与外交"],"mainTag":"经济与社会","subTag":"战争与外交","timeText":"1934年起","place":"纳粹德国","summary":"MEFO票据是纳粹德国隐蔽融资重整军备的工具，让国家绕开预算限制扩大军费支出。","fields":[{"label":"标题","value":"纳粹德国MEFO票据"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1934年起"},{"label":"地点","value":"纳粹德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"MEFO票据是纳粹德国隐蔽融资重整军备的工具，让国家绕开预算限制扩大军费支出。"},{"label":"制定方/签署方","value":"德国经济与财政当局、德国央行、以“冶金研究公司”名义设立的MEFO公司体系。"},{"label":"主要内容","value":"军工企业收到由MEFO公司承兑的票据，银行可贴现，国家日后兑付，从而把军备支出推迟和隐藏在正式预算之外。"},{"label":"它试图解决什么问题","value":"纳粹政权想快速重整军备，但公开赤字和财政约束会暴露军备规模并引发金融压力，因此需要准财政工具。"},{"label":"为什么重要","value":"它说明纳粹经济复苏与重整军备高度绑定，不是普通凯恩斯主义就业政策，而是战争准备融资。"},{"label":"争议/局限","value":"MEFO票据积累巨大潜在债务，依赖未来扩张和掠夺来解决财政压力，长期不可持续。"},{"label":"造成的影响","value":"军备生产快速扩张，失业下降，但德国经济越来越依赖战争订单和国家控制。"},{"label":"出处","value":"Bundesbank historical materials on Mefo bills; Adam Tooze, The Wages of Destruction references; Britannica/Nazi economy summaries。"}],"relationItems":["← 前因：大萧条冲击德国社会","→ 后果：纳粹德国四年计划","↔ 相关：纳粹大众汽车计划","↔ 相关：赫尔曼·戈林","↔ 同时期参考：日本军费扩张"],"relations":[{"text":"← 前因：大萧条冲击德国社会","id":"card198"},{"text":"→ 后果：纳粹德国四年计划","id":"extra122"},{"text":"↔ 相关：纳粹大众汽车计划","id":"extra124"},{"text":"↔ 相关：赫尔曼·戈林","id":"extra160"}],"source":"history","id":"extra295"},{"title":"纳粹德国国家劳动役","level":"B","type":"组织/机构卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1935年强制化；1930年代至1945年","place":"纳粹德国","summary":"国家劳动役把青年劳动、军事化训练和意识形态教育结合起来，是纳粹社会动员的重要机构。","fields":[{"label":"标题","value":"纳粹德国国家劳动役"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1935年强制化；1930年代至1945年"},{"label":"地点","value":"纳粹德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"国家劳动役把青年劳动、军事化训练和意识形态教育结合起来，是纳粹社会动员的重要机构。"},{"label":"性质/类型","value":"国家强制劳动和青年动员组织。"},{"label":"成立/解散时间","value":"1930年代初已有前身；1935年《国家劳动役法》使青年服役制度化；1945年终结。"},{"label":"核心目标/宗旨","value":"通过劳动营、制服、队列、农业和基础设施劳动训练青年服从、纪律和民族共同体意识。"},{"label":"关键人物（可选）","value":"康斯坦丁·希尔。"},{"label":"关键行动/事件","value":"组织青年参与道路、排水、农田和公共工程劳动；战争时期与军事和后方服务联系更紧。"},{"label":"为什么重要","value":"它说明纳粹减少失业和塑造青年并不是分开的政策，劳动本身被政治化和军事化。"},{"label":"争议/局限","value":"所谓劳动教育建立在强制服从和性别、种族排除上，不能简单理解为普通公共就业计划。"},{"label":"出处","value":"DHM LeMO, Reichsarbeitsdienst; United States Holocaust Memorial Museum related Nazi youth and labor mobilization materials。"}],"relationItems":["← 前因：纳粹夺权","→ 后果：纳粹德国总体战动员","↔ 相关：纳粹希特勒青年团","↔ 相关：纳粹高速公路宣传","↔ 同时期参考：美国平民保护队"],"relations":[{"text":"← 前因：纳粹夺权","id":"extra852"},{"text":"→ 后果：纳粹德国总体战动员","id":"extra235"},{"text":"↔ 相关：纳粹希特勒青年团","id":"extra115"},{"text":"↔ 相关：纳粹高速公路宣传","id":"extra123"}],"source":"history","id":"extra296"},{"title":"纳粹德国粮食产制","level":"B","type":"组织/机构卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1933—1945年","place":"纳粹德国农村和农业市场","summary":"纳粹粮食产制把农民、农业价格和粮食供应纳入国家控制，服务自给自足和战争经济。","fields":[{"label":"标题","value":"纳粹德国粮食产制"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1933—1945年"},{"label":"地点","value":"纳粹德国农村和农业市场"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"纳粹粮食产制把农民、农业价格和粮食供应纳入国家控制，服务自给自足和战争经济。"},{"label":"性质/类型","value":"农业统制组织和市场管理体系。"},{"label":"成立/解散时间","value":"1933年建立帝国粮食产制（Reichsnährstand）；1945年随纳粹政权崩溃终结。"},{"label":"核心目标/宗旨","value":"组织农民、控制农业生产和价格，宣传“血与土”，提高粮食自给，为战争准备稳定供应。"},{"label":"关键人物（可选）","value":"里夏德·瓦尔特·达雷。"},{"label":"关键行动/事件","value":"统一农业组织，控制市场和农产品流通，配合世袭农场法和农民宣传。"},{"label":"为什么重要","value":"它把纳粹经济从城市军工扩展到乡村，说明纳粹并非只靠工业动员，也试图把农业纳入种族和战争国家。"},{"label":"争议/局限","value":"价格和生产管制限制农民自由，粮食自给目标难以完全实现，战争中德国越来越依赖占领区掠夺。"},{"label":"出处","value":"DHM LeMO, Reichsnährstand; German History in Documents and Images, Nazi agricultural policy materials。"}],"relationItems":["← 前因：纳粹血与土思想","→ 后果：纳粹德国饥饿计划","↔ 相关：纳粹德国四年计划","↔ 相关：纳粹家庭政策","↔ 同时期参考：苏联农业集体化"],"relations":[{"text":"← 前因：纳粹血与土思想","id":"extra859"},{"text":"→ 后果：纳粹德国饥饿计划","id":"extra208"},{"text":"↔ 相关：纳粹德国四年计划","id":"extra122"},{"text":"↔ 相关：纳粹家庭政策","id":"extra117"}],"source":"history","id":"extra297"},{"title":"纳粹德国“周日一锅饭”","level":"C","type":"概念/思潮卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1933年后，冬季救济期间推广","place":"纳粹德国","summary":"“周日一锅饭”要求家庭用简单饭菜节省开支并捐给冬季救济，把餐桌变成民族共同体表演。","fields":[{"label":"标题","value":"纳粹德国“周日一锅饭”"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1933年后，冬季救济期间推广"},{"label":"地点","value":"纳粹德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"“周日一锅饭”要求家庭用简单饭菜节省开支并捐给冬季救济，把餐桌变成民族共同体表演。"},{"label":"核心主张/思路","value":"家庭在指定周日少吃或吃简单炖锅，把省下的钱捐给冬季救济，以显示节约、牺牲和共同体团结。"},{"label":"提出者/代表人物（可选）","value":"纳粹人民福利、宣传部和冬季救济事业。"},{"label":"它从何而来","value":"纳粹政权希望把社会救济、道德压力和日常生活仪式结合起来，使民众在私人家庭中也参与政治表演。"},{"label":"典型表现","value":"宣传海报、广播提醒、家庭炖锅、捐款、邻里监督和领袖也“同吃一锅饭”的宣传图像。"},{"label":"为什么重要","value":"它说明纳粹社会控制不只靠警察，也靠饭桌、邻里眼光和看似自愿的日常仪式。"},{"label":"争议/局限","value":"它被包装为共同体互助，但参与压力很强，且犹太人等被排斥者不属于这套“共同体”福利想象。"},{"label":"出处","value":"DHM LeMO, Eintopfsonntag; German Propaganda Archive, Winterhilfswerk materials。"}],"relationItems":["← 前因：纳粹德国冬季救济事业","→ 后果：纳粹德国总体战动员","↔ 相关：纳粹宣传机器","↔ 相关：纳粹德国配给票制度","↔ 同时期参考：英国战时节约饮食宣传"],"relations":[{"text":"← 前因：纳粹德国冬季救济事业","id":"extra130"},{"text":"→ 后果：纳粹德国总体战动员","id":"extra235"},{"text":"↔ 相关：纳粹宣传机器","id":"extra94"},{"text":"↔ 相关：纳粹德国配给票制度","id":"extra293"}],"source":"history","id":"extra298"},{"title":"纳粹夺权","level":"A","type":"事件卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1933年1月—1934年8月","place":"德国","summary":"纳粹夺权不是一次单点政变，而是任命、法令、暴力和一体化逐步摧毁魏玛民主的过程。","fields":[{"label":"标题","value":"纳粹夺权"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1933年1月—1934年8月"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"纳粹夺权不是一次单点政变，而是任命、法令、暴力和一体化逐步摧毁魏玛民主的过程。"},{"label":"参与者","value":"阿道夫·希特勒、保罗·冯·兴登堡、弗朗茨·冯·巴本、纳粹党、冲锋队、保守精英、德国国会和各州政府。"},{"label":"发生了什么","value":"1933年1月，希特勒被任命为总理。国会纵火案后，纳粹通过紧急法令限制公民权利；3月授权法使政府绕过议会立法。随后政党、工会、各州、文化机构和社会组织被一体化，政治反对派遭逮捕和集中营关押。1934年长刀之夜清洗冲锋队和保守威胁，兴登堡去世后总统与总理职位合并。"},{"label":"为什么重要","value":"它解释纳粹政权如何从合法任命转变为独裁统治。魏玛制度弱点、保守精英误判、街头暴力和宣传共同参与了这个过程。"},{"label":"前因","value":"大萧条冲击德国社会、总统内阁、保守派反议会政治和纳粹群众动员。"},{"label":"后果","value":"魏玛共和国终结，纳粹一党制和元首国家形成，德国进入系统性迫害、再武装和侵略扩张阶段。"},{"label":"出处","value":"DHM/LeMO: Machtübernahme；German History in Documents and Images: Nazi seizure of power；Encyclopaedia Britannica: Adolf Hitler。"}],"relationItems":["← 前因：希特勒出任德国总理","← 前因：大萧条冲击德国社会","→ 后果：德国国会纵火法令","→ 后果：纳粹德国授权法","→ 后果：纳粹一体化政策","→ 后果：纳粹元首国家"],"relations":[{"text":"← 前因：希特勒出任德国总理","id":"card71"},{"text":"← 前因：大萧条冲击德国社会","id":"card198"},{"text":"→ 后果：德国国会纵火法令","id":"extra98"},{"text":"→ 后果：纳粹德国授权法","id":"extra99"},{"text":"→ 后果：纳粹一体化政策","id":"extra100"},{"text":"→ 后果：纳粹元首国家","id":"extra110"}],"source":"history","id":"extra852"},{"title":"纽伦堡医生审判","level":"B","type":"事件卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1946—1947年","place":"德国纽伦堡","summary":"纽伦堡医生审判追究纳粹医学实验和杀害行为，并推动现代医学伦理规范形成。","fields":[{"label":"标题","value":"纽伦堡医生审判"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1946—1947年"},{"label":"地点","value":"德国纽伦堡"},{"label":"主要国家","value":"美国；德国"},{"label":"一句话概括","value":"纽伦堡医生审判追究纳粹医学实验和杀害行为，并推动现代医学伦理规范形成。"},{"label":"参与者","value":"美国军事法庭、纳粹医生和官员、集中营幸存者、卡尔·勃兰特等被告。"},{"label":"发生了什么","value":"二战后，美国在纽伦堡对纳粹医生和医学官员进行审判，指控他们参与集中营人体实验、强制绝育、杀害病人和其他战争罪、反人道罪。审判听取受害者证词和医学文件，部分被告被判死刑或长期监禁。"},{"label":"为什么重要","value":"它把纳粹医学犯罪从一般战争罪中凸显出来，并促成“纽伦堡准则”等关于知情同意和人体实验伦理的原则。"},{"label":"前因","value":"纳粹T4行动、纳粹集中营医学实验、纳粹优生政策和战争末期罪证发现。"},{"label":"后果","value":"卡尔·勃兰特等被告被定罪，医学伦理和人体实验规范获得国际关注，战后德国责任讨论深化。"},{"label":"出处","value":"United States Holocaust Memorial Museum: Doctors Trial；Harvard Law School Nuremberg Trials Project；DHM/LeMO: Nürnberger Prozesse。"}],"relationItems":["← 前因：纳粹T4行动","← 前因：纳粹集中营医学实验","↔ 相关：卡尔·勃兰特","→ 后果：纽伦堡后续审判","↔ 相关：纳粹战犯纽伦堡审判"],"relations":[{"text":"← 前因：纳粹T4行动","id":"extra128"},{"text":"← 前因：纳粹集中营医学实验","id":"extra282"},{"text":"↔ 相关：卡尔·勃兰特","id":"extra283"},{"text":"→ 后果：纽伦堡后续审判","id":"extra37"},{"text":"↔ 相关：纳粹战犯纽伦堡审判","id":"extra6"}],"source":"history","id":"extra853"},{"title":"第二次世界大战在欧洲爆发","level":"S","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1939年9月","place":"波兰、德国、英国、法国及欧洲国际体系","summary":"德国入侵波兰引发英法对德宣战，第二次世界大战欧洲战场正式爆发。","fields":[{"label":"标题","value":"第二次世界大战在欧洲爆发"},{"label":"分级","value":"S"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1939年9月"},{"label":"地点","value":"波兰、德国、英国、法国及欧洲国际体系"},{"label":"主要国家","value":"德国；波兰；英国；法国；苏联"},{"label":"一句话概括","value":"德国入侵波兰引发英法对德宣战，第二次世界大战欧洲战场正式爆发。"},{"label":"参与者","value":"纳粹德国、波兰、英国、法国、苏联、但泽和波兰走廊相关政治力量。"},{"label":"发生了什么","value":"1939年9月1日，德国以格莱维茨事件等借口入侵波兰。英国和法国根据对波兰的安全保证要求德国撤军，德国拒绝后，英法于9月3日对德宣战。苏联随后根据《苏德互不侵犯条约》秘密议定书从东面进入波兰。"},{"label":"为什么重要","value":"它把纳粹德国的扩张从危机外交推向全面战争。欧洲战场爆发后，德国占领政策、种族战争和全球战争升级逐步展开。"},{"label":"前因","value":"纳粹德国占领捷克地区、英法对波兰安全保证、但泽与波兰走廊危机、苏德互不侵犯条约。"},{"label":"后果","value":"波兰被瓜分，英法对德宣战，二战西线“静坐战”和随后德国入侵法国战役铺开。"},{"label":"出处","value":"Encyclopaedia Britannica: World War II；United States Holocaust Memorial Museum: Invasion of Poland；DHM/LeMO: Beginn des Zweiten Weltkriegs。"}],"relationItems":["← 前因：纳粹德国与苏联《互不侵犯条约》","← 前因：德国入侵波兰","→ 后果：英法对纳粹德国宣战","→ 后果：二战西线“静坐战”","→ 后果：纳粹德国波兰总督府"],"relations":[{"text":"← 前因：纳粹德国与苏联《互不侵犯条约》","id":"extra177"},{"text":"← 前因：德国入侵波兰","id":"extra179"},{"text":"→ 后果：英法对纳粹德国宣战","id":"extra180"},{"text":"→ 后果：二战西线“静坐战”","id":"extra181"},{"text":"→ 后果：纳粹德国波兰总督府","id":"extra182"}],"source":"history","id":"extra854"},{"title":"盟军进入德国本土","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1944年9月—1945年春","place":"德国西部、莱茵河、亚琛、鲁尔等地","summary":"盟军进入德国本土标志西线战争从解放被占领区转为直接攻入纳粹德国。","fields":[{"label":"标题","value":"盟军进入德国本土"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1944年9月—1945年春"},{"label":"地点","value":"德国西部、莱茵河、亚琛、鲁尔等地"},{"label":"主要国家","value":"美国；英国；加拿大；法国；德国"},{"label":"一句话概括","value":"盟军进入德国本土标志西线战争从解放被占领区转为直接攻入纳粹德国。"},{"label":"参与者","value":"西方盟军、德国国防军、德国平民、纳粹党地方组织。"},{"label":"发生了什么","value":"诺曼底登陆和巴黎解放后，西方盟军推进到德国边境。1944年秋，亚琛成为第一个被盟军占领的德国大城市。随后盟军在阿登反攻后恢复推进，雷马根大桥突破和越过莱茵河使德国西部防线瓦解。"},{"label":"为什么重要","value":"盟军进入德国本土改变了战争心理和政治现实。德国社会开始直接面对战败、占领、轰炸和政权崩溃，纳粹仍试图用人民冲锋队和恐怖手段维持抵抗。"},{"label":"前因","value":"诺曼底登陆、盟军诺曼底突破与法莱兹包围、德国阿登反攻失败。"},{"label":"后果","value":"西方盟军越过莱茵河，鲁尔被包围，德国本土战争社会崩溃并走向无条件投降。"},{"label":"出处","value":"United States Army Center of Military History: Rhineland Campaign；Encyclopaedia Britannica: World War II；DHM/LeMO: Kriegsende 1945。"}],"relationItems":["← 前因：西方盟军占领亚琛","← 前因：德国阿登反攻","→ 后果：盟军雷马根大桥突破","→ 后果：西方盟军越过莱茵河","→ 后果：德国本土战争社会崩溃"],"relations":[{"text":"← 前因：西方盟军占领亚琛","id":"extra264"},{"text":"← 前因：德国阿登反攻","id":"extra263"},{"text":"→ 后果：盟军雷马根大桥突破","id":"extra271"},{"text":"→ 后果：西方盟军越过莱茵河","id":"extra272"},{"text":"→ 后果：德国本土战争社会崩溃","id":"extra274"}],"source":"history","id":"extra855"},{"title":"苏联红军战略反攻","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1942年底—1945年","place":"东线，斯大林格勒、库尔斯克、白俄罗斯、波兰、德国东部","summary":"苏联红军战略反攻从斯大林格勒后逐步夺回主动权，最终推进到柏林。","fields":[{"label":"标题","value":"苏联红军战略反攻"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1942年底—1945年"},{"label":"地点","value":"东线，斯大林格勒、库尔斯克、白俄罗斯、波兰、德国东部"},{"label":"主要国家","value":"苏联；德国；波兰；罗马尼亚；匈牙利"},{"label":"一句话概括","value":"苏联红军战略反攻从斯大林格勒后逐步夺回主动权，最终推进到柏林。"},{"label":"参与者","value":"苏联红军、德国国防军、苏联最高统帅部、东欧各地平民和抵抗力量。"},{"label":"发生了什么","value":"斯大林格勒战役后，苏联逐渐掌握东线主动。库尔斯克战役挫败德军大规模反攻后，红军连续发动战略攻势，解放乌克兰和白俄罗斯，推进到波兰和德国东部。1945年维斯瓦-奥得攻势把红军推到柏林门户。"},{"label":"为什么重要","value":"它是纳粹德国战败的军事核心过程。东线反攻不仅摧毁德军主力，也决定东欧战后政治格局。"},{"label":"前因","value":"德国入侵苏联“巴巴罗萨行动”、莫斯科战役、斯大林格勒战役和苏联战争工业恢复。"},{"label":"后果","value":"苏联“巴格拉季昂行动”、维斯瓦-奥得攻势、苏军解放奥斯维辛和柏林战役相继发生。"},{"label":"出处","value":"Encyclopaedia Britannica: Eastern Front World War II；USHMM: Eastern Front；DHM/LeMO: Ostfront。"}],"relationItems":["← 前因：斯大林格勒战役","← 前因：库尔斯克战役","→ 后果：苏联“巴格拉季昂行动”","→ 后果：苏联维斯瓦-奥得攻势","→ 后果：柏林战役"],"relations":[{"text":"← 前因：斯大林格勒战役","id":"extra230"},{"text":"← 前因：库尔斯克战役","id":"extra241"},{"text":"→ 后果：苏联“巴格拉季昂行动”","id":"extra253"},{"text":"→ 后果：苏联维斯瓦-奥得攻势","id":"extra266"},{"text":"→ 后果：柏林战役","id":"extra276"}],"source":"history","id":"extra856"},{"title":"纳粹同性恋迫害","level":"B","type":"事件卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1933—1945年","place":"德国及纳粹控制区","summary":"纳粹政权通过刑法、警察和集中营体系迫害男同性恋者，并摧毁魏玛性改革空间。","fields":[{"label":"标题","value":"纳粹同性恋迫害"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1933—1945年"},{"label":"地点","value":"德国及纳粹控制区"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"纳粹政权通过刑法、警察和集中营体系迫害男同性恋者，并摧毁魏玛性改革空间。"},{"label":"参与者","value":"纳粹警察和司法机关、盖世太保、刑警系统、同性恋者、马格努斯·赫希菲尔德性科学研究所相关群体。"},{"label":"发生了什么","value":"纳粹上台后关闭同性恋社交空间，摧毁性科学研究所，并在1935年加严刑法第175条。大量男同性恋者被调查、逮捕、判刑或送入集中营，部分佩戴粉色三角标识。"},{"label":"为什么重要","value":"它说明纳粹迫害不仅针对犹太人，也通过性别、身体和道德秩序重塑社会。它还把魏玛性改革与纳粹身体政治之间的断裂展示出来。"},{"label":"前因","value":"德国刑法典第175条、魏玛德国性改革运动、保守性道德和纳粹种族/性别秩序。"},{"label":"后果","value":"同性恋社群被摧毁，战后第175条仍长期存在，受害者承认和赔偿迟到。"},{"label":"出处","value":"United States Holocaust Memorial Museum: Persecution of Homosexuals；DHM/LeMO: Homosexuelle im Nationalsozialismus；German History in Documents and Images: Paragraph 175。"}],"relationItems":["← 前因：德国刑法典第175条","← 前因：马格努斯·赫希菲尔德性科学研究所","→ 后果：纳粹德国第175条加严","↔ 相关：纳粹集中营体系","↔ 相关：身体自主权"],"relations":[{"text":"← 前因：德国刑法典第175条","id":"extra721"},{"text":"← 前因：马格努斯·赫希菲尔德性科学研究所","id":"card72"},{"text":"→ 后果：纳粹德国第175条加严","id":"extra280"},{"text":"↔ 相关：身体自主权","id":"extra860"}],"source":"history","id":"extra857"},{"title":"纳粹治安国家","level":"B","type":"概念/思潮卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1933—1945年","place":"德国及纳粹占领区","summary":"纳粹治安国家把警察、告密、特别法院和集中营结合起来，用恐惧治理社会。","fields":[{"label":"标题","value":"纳粹治安国家"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1933—1945年"},{"label":"地点","value":"德国及纳粹占领区"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"纳粹治安国家把警察、告密、特别法院和集中营结合起来，用恐惧治理社会。"},{"label":"核心主张/思路","value":"政权不只靠法律统治，而通过盖世太保、刑警、党组织、保护性拘留和特别法院，预防、打击和制造“敌人”。"},{"label":"提出者/代表人物（可选）","value":"海因里希·希姆莱、莱因哈德·海德里希、盖世太保和刑警系统。"},{"label":"它从何而来","value":"魏玛政治暴力、警察专业化、纳粹夺权后的法治破坏和集中营体系建立。"},{"label":"典型表现","value":"保护性拘留、盖世太保、纳粹特别法院、职业犯罪者集中营关押机制、帝国刑事警察局。"},{"label":"为什么重要","value":"它解释纳粹独裁如何深入日常社会。纳粹恐怖不是单靠一支秘密警察完成，而是警察机构、司法、党组织和普通告密共同构成。"},{"label":"争议/局限","value":"盖世太保规模并非无限大，社会合作、告密和地方机关协同是治安国家有效运行的重要条件。"},{"label":"出处","value":"United States Holocaust Memorial Museum: Gestapo；DHM/LeMO: Gestapo；Robert Gellately, Backing Hitler。"}],"relationItems":["← 前因：纳粹夺权","↔ 相关：纳粹盖世太保","↔ 相关：纳粹保护性拘留制度","↔ 相关：纳粹特别法院","→ 后果：集中营体系"],"relations":[{"text":"← 前因：纳粹夺权","id":"extra852"},{"text":"↔ 相关：纳粹盖世太保","id":"extra106"},{"text":"↔ 相关：纳粹保护性拘留制度","id":"extra150"},{"text":"↔ 相关：纳粹特别法院","id":"extra140"},{"text":"→ 后果：集中营体系","id":"extra861"}],"source":"history","id":"extra858"},{"title":"纳粹血与土思想","level":"B","type":"概念/思潮卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1920年代—1945年","place":"德国及纳粹占领区","summary":"纳粹血与土思想把种族、农民、土地和民族共同体捆绑起来，为农业政策和东欧扩张提供话语。","fields":[{"label":"标题","value":"纳粹血与土思想"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1920年代—1945年"},{"label":"地点","value":"德国及纳粹占领区"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"纳粹血与土思想把种族、农民、土地和民族共同体捆绑起来，为农业政策和东欧扩张提供话语。"},{"label":"核心主张/思路","value":"所谓“血”指种族共同体，“土”指土地和农民生活，被纳粹用来反对城市现代性、自由市场和多元社会。"},{"label":"提出者/代表人物（可选）","value":"理查德·瓦尔特·达雷、纳粹农业政策集团、民族主义农本思想者。"},{"label":"它从何而来","value":"19世纪民族主义、农本浪漫主义、反城市现代性情绪、种族主义和一战后土地焦虑。"},{"label":"典型表现","value":"纳粹世袭农场法、帝国粮食署、东方总计划、自然保护话语中的种族化土地观。"},{"label":"为什么重要","value":"它让农业政策、生态话语和种族扩张联系起来。纳粹并非单纯现代工业政权，也大量调用反现代和农本想象。"},{"label":"争议/局限","value":"血与土宣传美化农民，却服务于国家统制、种族排斥和侵略扩张。"},{"label":"出处","value":"United States Holocaust Memorial Museum: Nazi ideology；DHM/LeMO: Blut und Boden；German History in Documents and Images: Nazi agriculture。"}],"relationItems":["↔ 相关：纳粹世袭农场法","↔ 相关：纳粹帝国粮食署","↔ 相关：纳粹德国自然保护法","→ 后果：纳粹德国东方总计划","✗ 对立/冲突：魏玛柏林现代性"],"relations":[{"text":"↔ 相关：纳粹世袭农场法","id":"extra138"},{"text":"↔ 相关：纳粹帝国粮食署","id":"extra139"},{"text":"↔ 相关：纳粹德国自然保护法","id":"extra133"},{"text":"→ 后果：纳粹德国东方总计划","id":"extra862"},{"text":"✗ 对立/冲突：魏玛柏林现代性","id":"card33"}],"source":"history","id":"extra859"},{"title":"身体自主权","level":"C","type":"概念/思潮卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"20世纪，魏玛和纳粹时期冲突尤为明显","place":"德国、欧洲和现代法律政治语境","summary":"身体自主权指个人对生育、性、医疗和身体处置的决定权，在现代国家治理中常受挑战。","fields":[{"label":"标题","value":"身体自主权"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"20世纪，魏玛和纳粹时期冲突尤为明显"},{"label":"地点","value":"德国、欧洲和现代法律政治语境"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"身体自主权指个人对生育、性、医疗和身体处置的决定权，在现代国家治理中常受挑战。"},{"label":"核心主张/思路","value":"个人身体不应完全由家庭、教会、国家、医学专家或种族政策支配，尤其涉及避孕、堕胎、绝育、性取向和医疗实验。"},{"label":"提出者/代表人物（可选）","value":"女性运动、性改革者、人权组织、医学伦理倡导者。"},{"label":"它从何而来","value":"现代个人权利、女性运动、性改革、医学发展和国家人口政策之间的冲突。"},{"label":"典型表现","value":"魏玛第218条堕胎争议、性科学研究所、纳粹强制绝育、T4行动和集中营医学实验。"},{"label":"为什么重要","value":"它把魏玛自由化和纳粹身体政治放在同一条问题线上：现代国家既可能扩大身体自由，也可能以前所未有的方式控制身体。"},{"label":"争议/局限","value":"不同社会对身体自主权边界存在争论，涉及宗教、医学伦理、人口政策和公共卫生。"},{"label":"出处","value":"German History in Documents and Images: Reproductive politics；USHMM: Forced sterilization；Cornelie Usborne, The Politics of the Body in Weimar Germany。"}],"relationItems":["↔ 相关：魏玛第218条堕胎争议","↔ 相关：魏玛德国性改革运动","✗ 对立/冲突：纳粹《遗传病后代预防法》","✗ 对立/冲突：纳粹遗传健康法院","→ 后果：纽伦堡医生审判"],"relations":[{"text":"↔ 相关：魏玛第218条堕胎争议","id":"card96"},{"text":"↔ 相关：魏玛德国性改革运动","id":"card85"},{"text":"✗ 对立/冲突：纳粹《遗传病后代预防法》","id":"extra127"},{"text":"✗ 对立/冲突：纳粹遗传健康法院","id":"extra136"},{"text":"→ 后果：纽伦堡医生审判","id":"extra853"}],"source":"history","id":"extra860"},{"title":"集中营体系","level":"A","type":"组织/机构卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1933—1945年","place":"德国及纳粹占领欧洲","summary":"纳粹集中营体系从政治恐怖工具扩展为强迫劳动、种族迫害和灭绝政策的重要制度网络。","fields":[{"label":"标题","value":"集中营体系"},{"label":"分级","value":"A"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1933—1945年"},{"label":"地点","value":"德国及纳粹占领欧洲"},{"label":"主要国家","value":"德国；波兰；奥地利；捷克等被占领地区"},{"label":"一句话概括","value":"纳粹集中营体系从政治恐怖工具扩展为强迫劳动、种族迫害和灭绝政策的重要制度网络。"},{"label":"性质/类型","value":"由党卫队主导的关押、惩罚、强迫劳动和杀戮机构网络。"},{"label":"成立/解散时间","value":"1933年达豪集中营建立后逐步扩展；1945年随纳粹德国崩溃被盟军解放和接管。"},{"label":"核心目标/宗旨","value":"关押政治敌人和被定义为“共同体外人”的群体，实施恐怖统治、强迫劳动、惩罚和种族灭绝。"},{"label":"关键人物（可选）","value":"海因里希·希姆莱、党卫队经济和行政机构、集中营看守系统。"},{"label":"关键行动/事件","value":"达豪建立，战前关押政治犯、犹太人、同性恋者和“职业犯罪者”等；战争期间与强迫劳动、医学实验和灭绝营系统连接。"},{"label":"为什么重要","value":"集中营体系是纳粹治安国家和种族战争的核心制度。它说明纳粹暴力如何从国内镇压扩展到欧洲范围的奴役和屠杀。"},{"label":"争议/局限","value":"集中营、灭绝营、战俘营和隔都功能不同，不能混为一谈，但它们在纳粹统治中相互连接。"},{"label":"出处","value":"United States Holocaust Memorial Museum: Concentration Camp System；DHM/LeMO: Konzentrationslager；Encyclopaedia Britannica: concentration camp。"}],"relationItems":["← 前因：纳粹达豪集中营建立","← 前因：纳粹保护性拘留制度","↔ 相关：纳粹党卫队","→ 后果：纳粹强迫劳动体系","→ 后果：纳粹集中营医学实验","↔ 相关：纳粹犹太人大屠杀"],"relations":[{"text":"← 前因：纳粹达豪集中营建立","id":"extra105"},{"text":"← 前因：纳粹保护性拘留制度","id":"extra150"},{"text":"↔ 相关：纳粹党卫队","id":"extra107"},{"text":"→ 后果：纳粹强迫劳动体系","id":"extra225"},{"text":"→ 后果：纳粹集中营医学实验","id":"extra282"},{"text":"↔ 相关：纳粹犹太人大屠杀","id":"extra218"}],"source":"history","id":"extra861"},{"title":"纳粹德国东方总计划","level":"A","type":"制度/文本卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1939—1942年形成，1941—1945年部分实施","place":"纳粹占领的中东欧和东欧地区","summary":"纳粹德国东方总计划把东欧设想为德国殖民空间，包含驱逐、奴役、饥饿和种族重组。","fields":[{"label":"标题","value":"纳粹德国东方总计划"},{"label":"分级","value":"A"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1939—1942年形成，1941—1945年部分实施"},{"label":"地点","value":"纳粹占领的中东欧和东欧地区"},{"label":"主要国家","value":"德国；波兰；苏联；乌克兰；白俄罗斯；波罗的海地区"},{"label":"一句话概括","value":"纳粹德国东方总计划把东欧设想为德国殖民空间，包含驱逐、奴役、饥饿和种族重组。"},{"label":"制定方/签署方","value":"党卫队、帝国强化德意志民族性专员机构、纳粹规划专家和占领当局。"},{"label":"主要内容","value":"规划对东欧人口进行德意志化、驱逐、奴役和重新安置，为德国移民和“生存空间”扩张腾出土地。"},{"label":"它试图解决什么问题","value":"纳粹试图用种族殖民方式解决所谓德国土地、粮食和人口空间问题，并摧毁被视为低等的东欧民族社会。"},{"label":"为什么重要","value":"它把纳粹种族主义、血与土思想、东方战争和大屠杀放在同一个殖民规划框架中。"},{"label":"争议/局限","value":"该计划有多个版本，许多内容因战争进程未能完全实施，但其逻辑已在占领、饥饿政策、强迫劳动和屠杀中部分体现。"},{"label":"造成的影响","value":"东欧占领区遭遇大规模驱逐、饥荒、屠杀和强迫劳动，战后成为审判纳粹种族政策的重要证据之一。"},{"label":"出处","value":"United States Holocaust Memorial Museum: Nazi racial ideology and occupied East；DHM/LeMO: Generalplan Ost；Czesław Madajczyk, Generalplan Ost。"}],"relationItems":["← 前因：纳粹血与土思想","← 前因：纳粹德国入侵苏联","↔ 相关：纳粹犹太人大屠杀","↔ 相关：纳粹强迫劳动体系","→ 后果：战后德国驱逐与人口迁移"],"relations":[{"text":"← 前因：纳粹血与土思想","id":"extra859"},{"text":"↔ 相关：纳粹犹太人大屠杀","id":"extra218"},{"text":"↔ 相关：纳粹强迫劳动体系","id":"extra225"}],"source":"history","id":"extra862"},{"title":"北非战役","level":"B","type":"事件卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1940年6月—1943年5月","place":"利比亚、埃及、摩洛哥、阿尔及利亚、突尼斯","summary":"北非战役围绕地中海、苏伊士运河和殖民地空间展开，是二战欧洲战场的重要外围战役群。","fields":[{"label":"标题","value":"北非战役"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1940年6月—1943年5月"},{"label":"地点","value":"利比亚、埃及、摩洛哥、阿尔及利亚、突尼斯"},{"label":"主要国家","value":"英国；德国；意大利；美国；法国；澳大利亚；新西兰"},{"label":"一句话概括","value":"北非战役围绕地中海、苏伊士运河和殖民地空间展开，是二战欧洲战场的重要外围战役群。"},{"label":"参与者","value":"英联邦军队、意大利军队、德国非洲军、维希法国部队、美国军队和自由法国力量。"},{"label":"发生了什么","value":"意大利从利比亚进攻埃及失败后，德国派隆美尔率非洲军支援。双方在昔兰尼加、托布鲁克和阿拉曼反复拉锯。1942年阿拉曼战役后轴心国西撤，同年盟军火炬行动登陆法属北非。1943年突尼斯轴心军投降，北非战役结束。"},{"label":"为什么重要","value":"它保护了盟军通往苏伊士和中东的战略通道，并为盟军进攻西西里和意大利本土提供跳板。"},{"label":"前因","value":"意大利参战后试图扩张北非殖民地，英国必须保卫埃及、苏伊士运河和中东交通线。"},{"label":"后果","value":"轴心国失去北非，盟军获得地中海主动权，并打开意大利战役道路。"},{"label":"出处","value":"Encyclopaedia Britannica: North Africa campaigns；Bundesarchiv: Der Afrikafeldzug；Imperial War Museums: North Africa campaign。"}],"relationItems":["← 前因：意大利参加第二次世界大战","↔ 相关：纳粹德国非洲军","↔ 相关：阿拉曼战役","→ 后果：盟军西西里登陆"],"relations":[{"text":"↔ 相关：纳粹德国非洲军","id":"extra202"}],"source":"history","id":"extra863"},{"title":"纳粹德国战争经济","level":"B","type":"概念/思潮卡","tags":["经济与社会","战争与外交"],"mainTag":"经济与社会","subTag":"战争与外交","timeText":"1936—1945年","place":"德国及纳粹占领欧洲","summary":"纳粹德国战争经济通过军备扩张、占领掠夺和强迫劳动支撑侵略战争，但长期资源瓶颈严重。","fields":[{"label":"标题","value":"纳粹德国战争经济"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1936—1945年"},{"label":"地点","value":"德国及纳粹占领欧洲"},{"label":"主要国家","value":"德国；奥地利；波兰；法国；苏联；捷克斯洛伐克"},{"label":"一句话概括","value":"纳粹德国战争经济通过军备扩张、占领掠夺和强迫劳动支撑侵略战争，但长期资源瓶颈严重。"},{"label":"核心主张/思路","value":"经济服从再武装和战争目标，国家以价格、劳动力、原料、外汇和生产优先级控制企业与社会。"},{"label":"提出者/代表人物（可选）","value":"希特勒、赫尔曼·戈林、阿尔伯特·施佩尔、军备部、四年计划机构和大工业企业。"},{"label":"它从何而来","value":"纳粹四年计划、凡尔赛修正目标、失业政治、军备竞赛和对自给自足的追求。"},{"label":"典型表现","value":"军备订单、合成燃料和橡胶、占领区征用、外籍劳工和集中营强迫劳动、施佩尔时期军备合理化。"},{"label":"为什么重要","value":"它解释德国早期军事扩张的物质基础，也解释为什么石油、劳动力和交通瓶颈成为战争后期致命弱点。"},{"label":"争议/局限","value":"纳粹经济既有国家统制，也保留私人企业利润和竞争；“效率提升”不能脱离奴役、掠夺和暴力来看。"},{"label":"出处","value":"Adam Tooze, The Wages of Destruction；DHM/LeMO: Kriegswirtschaft；United States Holocaust Memorial Museum: Forced labor。"}],"relationItems":["← 前因：纳粹德国四年计划","↔ 相关：德国IG法本公司成立","↔ 相关：纳粹强迫劳动体系","→ 后果：盟军战略轰炸德国"],"relations":[{"text":"← 前因：纳粹德国四年计划","id":"extra122"},{"text":"↔ 相关：德国IG法本公司成立","id":"card98"},{"text":"↔ 相关：纳粹强迫劳动体系","id":"extra225"},{"text":"→ 后果：盟军战略轰炸德国","id":"extra228"}],"source":"history","id":"extra864"},{"title":"纳粹德国党国体制","level":"B","type":"概念/思潮卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1933—1945年","place":"德国及纳粹控制区","summary":"纳粹德国党国体制让纳粹党、国家机关、党卫队和元首权威交错运作，形成多中心竞争的独裁统治。","fields":[{"label":"标题","value":"纳粹德国党国体制"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1933—1945年"},{"label":"地点","value":"德国及纳粹控制区"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"纳粹德国党国体制让纳粹党、国家机关、党卫队和元首权威交错运作，形成多中心竞争的独裁统治。"},{"label":"核心主张/思路","value":"政党不只是执政工具，而要渗透国家、社会和日常生活；国家机关则围绕“元首意志”竞争性执行政策。"},{"label":"提出者/代表人物（可选）","value":"希特勒、纳粹党领导层、党卫队、各部委、地方大区长官和安全机构。"},{"label":"它从何而来","value":"纳粹一党制、授权法、协调化、领袖原则和对魏玛多党议会制的摧毁。"},{"label":"典型表现","value":"党政机构重叠，大区长官干预地方治理，党卫队扩张，盖世太保与司法并行，希特勒以模糊授权促成下级激进化。"},{"label":"为什么重要","value":"它解释纳粹统治为何既高度独裁又制度混乱，也解释政策激进化如何在相互竞争中不断升级。"},{"label":"争议/局限","value":"纳粹国家并非单一命令机器，党、国家、军队和经济机构之间存在权力竞争，但共同服务于独裁和战争目标。"},{"label":"出处","value":"Ian Kershaw, The Nazi Dictatorship；DHM/LeMO: NS-Staat；Richard J. Evans, The Third Reich in Power。"}],"relationItems":["← 前因：纳粹一党制","↔ 相关：领袖原则","↔ 相关：纳粹盖世太保","→ 后果：纳粹治安国家"],"relations":[{"text":"← 前因：纳粹一党制","id":"extra101"},{"text":"↔ 相关：纳粹盖世太保","id":"extra106"},{"text":"→ 后果：纳粹治安国家","id":"extra858"}],"source":"history","id":"extra865"},{"title":"古腾堡活字印刷革命","level":"S","type":"事件卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"约1450年代","place":"美因茨","summary":"古腾堡活字印刷术把文本复制成本大幅降低，改变知识传播、宗教改革和欧洲公共舆论形成方式。","fields":[{"label":"标题","value":"古腾堡活字印刷革命"},{"label":"分级","value":"S"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"约1450年代"},{"label":"地点","value":"美因茨"},{"label":"主要国家","value":"德意志地区；欧洲"},{"label":"一句话概括","value":"古腾堡活字印刷术把文本复制成本大幅降低，改变知识传播、宗教改革和欧洲公共舆论形成方式。"},{"label":"参与者","value":"约翰内斯·古腾堡、美因茨工匠和商人、早期印刷商、欧洲读者群体。"},{"label":"发生了什么","value":"15世纪中期，古腾堡在美因茨把金属活字、油性油墨、压印设备和商业化书籍生产结合起来，形成可持续复制文本的印刷体系。《古腾堡圣经》展示了这种技术可以生产高质量、较大批量的书籍。印刷业随后从德意志地区扩散到意大利、法国、低地国家和英格兰。"},{"label":"为什么重要","value":"它是世界史坐标级技术和文化节点。印刷术加速知识传播，削弱手抄本垄断，为宗教改革、科学革命、民族语言文学和近代公共舆论提供媒介条件。"},{"label":"前因","value":"欧洲大学、城市商业、纸张生产和读写需求扩大，使更低成本、更稳定的文本复制方式具有巨大市场价值；美因茨等德意志城市拥有金属加工和商业融资条件。"},{"label":"后果","value":"书籍、传单、圣经译本和争论文献快速扩散。16世纪宗教改革能在欧洲范围内迅速传播，与印刷网络密切相关。"},{"label":"出处","value":"Britannica, Johannes Gutenberg；Library of Congress, Gutenberg Bible；British Library, Gutenberg and the history of printing。"}],"relationItems":["→ 后果：欧洲宗教改革","↔ 相关：路德德语圣经翻译","↔ 相关：马丁·路德发表《九十五条论纲》","↔ 同时期参考：文艺复兴人文主义"],"relations":[{"text":"→ 后果：欧洲宗教改革","id":"extra301"},{"text":"↔ 相关：路德德语圣经翻译","id":"extra304"},{"text":"↔ 相关：马丁·路德发表《九十五条论纲》","id":"extra302"},{"text":"↔ 同时期参考：文艺复兴人文主义","id":"extra885"}],"source":"history","id":"extra299"},{"title":"神圣罗马帝国","level":"A","type":"组织/机构卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"962—1806年","place":"中欧，核心为德意志地区，并长期涉及意大利、波希米亚、奥地利等地","summary":"神圣罗马帝国是中欧长期存在的复合政治秩序，解释德意志为何长期不是统一民族国家。","fields":[{"label":"标题","value":"神圣罗马帝国"},{"label":"分级","value":"A"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"962—1806年"},{"label":"地点","value":"中欧，核心为德意志地区，并长期涉及意大利、波希米亚、奥地利等地"},{"label":"主要国家","value":"德意志地区；奥地利；捷克；意大利部分地区"},{"label":"一句话概括","value":"神圣罗马帝国是中欧长期存在的复合政治秩序，解释德意志为何长期不是统一民族国家。"},{"label":"性质/类型","value":"复合君主制和帝国等级政治体系。"},{"label":"成立/解散时间","value":"通常以962年奥托一世加冕为起点，1806年弗朗茨二世退位后解体。"},{"label":"核心目标/宗旨","value":"以皇帝、帝国诸侯、自由城市、主教领地和帝国法庭等结构维系中欧政治秩序。"},{"label":"关键人物（可选）","value":"奥托一世、查理四世、哈布斯堡皇帝、帝国选侯等。"},{"label":"关键行动/事件","value":"神圣罗马帝国《金玺诏书》确立选侯制度；宗教改革后帝国内部教派分裂；威斯特伐利亚和约后诸侯权利进一步稳定。"},{"label":"为什么重要","value":"它是理解德意志早期历史的基本容器。没有神圣罗马帝国，就很难理解宗教改革、三十年战争、奥地利-普鲁士二元和1815年德意志邦联。"},{"label":"争议/局限","value":"帝国不是现代中央集权国家，权力分散、层级复杂，因此既能容纳多元，也常难以统一行动。"},{"label":"出处","value":"Britannica, Holy Roman Empire；German History in Documents and Images, Holy Roman Empire materials。"}],"relationItems":["→ 后果：神圣罗马帝国解体","↔ 相关：宗教改革《奥格斯堡和约》","↔ 相关：威斯特伐利亚和约","↔ 同时期参考：奥斯曼帝国"],"relations":[{"text":"→ 后果：神圣罗马帝国解体","id":"extra520"},{"text":"↔ 相关：宗教改革《奥格斯堡和约》","id":"extra305"},{"text":"↔ 相关：威斯特伐利亚和约","id":"extra308"},{"text":"↔ 同时期参考：奥斯曼帝国","id":"extra872"}],"source":"history","id":"extra300"},{"title":"欧洲宗教改革","level":"S","type":"概念/思潮卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"16世纪起，1517年后迅速扩展","place":"德意志地区、瑞士、英格兰、法国、低地国家及欧洲多地","summary":"宗教改革打破西欧天主教统一格局，使信仰、国家权力、教育和战争秩序发生深刻变化。","fields":[{"label":"标题","value":"欧洲宗教改革"},{"label":"分级","value":"S"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"16世纪起，1517年后迅速扩展"},{"label":"地点","value":"德意志地区、瑞士、英格兰、法国、低地国家及欧洲多地"},{"label":"主要国家","value":"德意志地区；瑞士；英格兰；法国；荷兰"},{"label":"一句话概括","value":"宗教改革打破西欧天主教统一格局，使信仰、国家权力、教育和战争秩序发生深刻变化。"},{"label":"核心主张/思路","value":"反对教会腐败和赎罪券等做法，强调圣经权威、信仰得救、地方教会改革和宗教共同体重组。"},{"label":"提出者/代表人物（可选）","value":"马丁·路德、慈运理、加尔文、托马斯·克兰麦等。"},{"label":"它从何而来","value":"中世纪晚期教会财政、赎罪券、人文主义圣经研究、城市读者、印刷术和地方政治力量共同促成改革爆发。"},{"label":"典型表现","value":"新教教会出现，圣经被翻译成民族语言，修道院和教会财产被重组，宗教战争和国家教会制度兴起。"},{"label":"为什么重要","value":"它是世界史坐标级节点，不只是德国教会改革，而是近代欧洲国家形成、识字教育、资本主义伦理讨论和国际关系重组的重要起点。"},{"label":"争议/局限","value":"宗教改革既推动个人信仰和文本阅读，也带来宗教迫害、教派战争和政治权力对教会的重新控制。"},{"label":"出处","value":"Britannica, Reformation；Encyclopaedia Britannica, Martin Luther；German History in Documents and Images, Reformation materials。"}],"relationItems":["← 前因：古腾堡活字印刷革命","→ 后果：宗教改革《奥格斯堡和约》","↔ 相关：马丁·路德发表《九十五条论纲》","↔ 相关：路德德语圣经翻译","↔ 同时期参考：欧洲天主教改革"],"relations":[{"text":"← 前因：古腾堡活字印刷革命","id":"extra299"},{"text":"→ 后果：宗教改革《奥格斯堡和约》","id":"extra305"},{"text":"↔ 相关：马丁·路德发表《九十五条论纲》","id":"extra302"},{"text":"↔ 相关：路德德语圣经翻译","id":"extra304"},{"text":"↔ 同时期参考：欧洲天主教改革","id":"extra329"}],"source":"history","id":"extra301"},{"title":"马丁·路德发表《九十五条论纲》","level":"A","type":"事件卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1517年10月31日","place":"维滕贝格","summary":"路德《九十五条论纲》批判赎罪券，把一场教会内部争论推向欧洲宗教改革的开端。","fields":[{"label":"标题","value":"马丁·路德发表《九十五条论纲》"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1517年10月31日"},{"label":"地点","value":"维滕贝格"},{"label":"主要国家","value":"德意志地区；教皇国"},{"label":"一句话概括","value":"路德《九十五条论纲》批判赎罪券，把一场教会内部争论推向欧洲宗教改革的开端。"},{"label":"参与者","value":"马丁·路德、维滕贝格大学、赎罪券销售者、罗马教廷、德意志诸侯和城市读者。"},{"label":"发生了什么","value":"1517年，奥古斯丁修士兼神学教授马丁·路德围绕赎罪券、悔罪和教会权威提出九十五条论题。论纲本来是学术争论形式，但印刷传播使其迅速超出大学和教会内部，成为欧洲范围的宗教与政治事件。"},{"label":"为什么重要","value":"它不是宗教改革全部内容，却是宗教改革的标志性起点。它把教会财政、信仰权威、印刷传播和德意志地方政治连接起来。"},{"label":"前因","value":"罗马教廷和地方教会通过赎罪券筹集资金，引发对教会财政和救赎观念的质疑；人文主义学术和印刷业又使批判文本更容易扩散。"},{"label":"后果","value":"路德与罗马教廷冲突升级，神学争论迅速变成帝国政治问题。到沃姆斯帝国议会时，路德拒绝撤回主张，地方诸侯保护、印刷传播和教会分裂共同推动新教改革制度化和政治化。"},{"label":"出处","value":"Britannica, Ninety-five Theses；Encyclopaedia Britannica, Martin Luther；Luther.de, 95 Theses historical material。"}],"relationItems":["← 前因：古腾堡活字印刷革命","→ 后果：沃姆斯帝国议会","↔ 相关：欧洲宗教改革","↔ 相关：路德德语圣经翻译","↔ 同时期参考：伊拉斯谟与基督教人文主义"],"relations":[{"text":"← 前因：古腾堡活字印刷革命","id":"extra299"},{"text":"→ 后果：沃姆斯帝国议会","id":"extra303"},{"text":"↔ 相关：欧洲宗教改革","id":"extra301"},{"text":"↔ 相关：路德德语圣经翻译","id":"extra304"},{"text":"↔ 同时期参考：伊拉斯谟与基督教人文主义","id":"extra886"}],"source":"history","id":"extra302"},{"title":"沃姆斯帝国议会","level":"A","type":"事件卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1521年","place":"沃姆斯","summary":"沃姆斯帝国议会要求路德撤回主张，路德拒绝退让，宗教改革由此成为帝国政治问题。","fields":[{"label":"标题","value":"沃姆斯帝国议会"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1521年"},{"label":"地点","value":"沃姆斯"},{"label":"主要国家","value":"神圣罗马帝国；教皇国；德意志地区"},{"label":"一句话概括","value":"沃姆斯帝国议会要求路德撤回主张，路德拒绝退让，宗教改革由此成为帝国政治问题。"},{"label":"参与者","value":"马丁·路德、皇帝查理五世、帝国诸侯、教会代表、萨克森选侯腓特烈。"},{"label":"发生了什么","value":"1521年，路德被传唤到沃姆斯帝国议会，为其著作和观点答辩。面对皇帝和帝国权威，他拒绝简单撤回观点，随后被《反路德《沃姆斯敕令》》宣布为异端和帝国法外之人。萨克森选侯保护路德，使其得以继续翻译和写作。"},{"label":"为什么重要","value":"这场会议把神学争论升级为帝国政治危机，显示教会权威、皇帝权威和地方诸侯保护之间的张力。"},{"label":"前因","value":"《九十五条论纲》传播后，路德批判教会权威和救赎制度，罗马教廷与皇帝需要在帝国层面处理这一挑战。"},{"label":"后果","value":"路德虽被定罪，但地方保护使宗教改革继续扩散；神圣罗马帝国逐渐陷入教派分裂和帝国权威受限的长期格局。"},{"label":"出处","value":"Britannica, Diet of Worms；German History in Documents and Images, Luther at Worms materials。"}],"relationItems":["← 前因：马丁·路德发表《九十五条论纲》","→ 后果：路德德语圣经翻译","↔ 相关：欧洲宗教改革","↔ 相关：神圣罗马帝国","↔ 同时期参考：查理五世的哈布斯堡帝国"],"relations":[{"text":"← 前因：马丁·路德发表《九十五条论纲》","id":"extra302"},{"text":"→ 后果：路德德语圣经翻译","id":"extra304"},{"text":"↔ 相关：欧洲宗教改革","id":"extra301"},{"text":"↔ 相关：神圣罗马帝国","id":"extra300"},{"text":"↔ 同时期参考：查理五世的哈布斯堡帝国","id":"extra901"}],"source":"history","id":"extra303"},{"title":"路德德语圣经翻译","level":"B","type":"事件卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1522年新约出版；1534年完整圣经出版","place":"瓦特堡；维滕贝格","summary":"路德德语圣经把宗教改革、印刷术和德语书面语连接起来，深刻影响德语文化共同体。","fields":[{"label":"标题","value":"路德德语圣经翻译"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1522年新约出版；1534年完整圣经出版"},{"label":"地点","value":"瓦特堡；维滕贝格"},{"label":"主要国家","value":"德意志地区"},{"label":"一句话概括","value":"路德德语圣经把宗教改革、印刷术和德语书面语连接起来，深刻影响德语文化共同体。"},{"label":"参与者","value":"马丁·路德、维滕贝格改革者、印刷商、德语读者和新教教会。"},{"label":"发生了什么","value":"路德在瓦特堡期间将新约翻译成德语，1522年出版；随后与合作者继续翻译旧约，1534年完整德语圣经出版。译本大量印刷传播，进入教会、学校和家庭阅读。"},{"label":"为什么重要","value":"它不仅改变信徒接触圣经的方式，也强化德语书面表达和共同文化空间，对德意志语言史和宗教教育影响极大。"},{"label":"前因","value":"宗教改革强调圣经权威和个人阅读，印刷术提供传播条件；路德在沃姆斯后受保护隐居，有时间进行翻译。"},{"label":"后果","value":"德语圣经成为新教教育和礼拜核心文本，推动识字、学校教育和德语文化认同，但也加深天主教与新教分裂。"},{"label":"出处","value":"Britannica, Luther Bible；Luther.de, Luther’s Bible translation；German Bible Society historical materials。"}],"relationItems":["← 前因：沃姆斯帝国议会","→ 后果：宗教改革《奥格斯堡和约》","↔ 相关：古腾堡活字印刷革命","↔ 相关：欧洲宗教改革","↔ 同时期参考：英王钦定版圣经"],"relations":[{"text":"← 前因：沃姆斯帝国议会","id":"extra303"},{"text":"→ 后果：宗教改革《奥格斯堡和约》","id":"extra305"},{"text":"↔ 相关：古腾堡活字印刷革命","id":"extra299"},{"text":"↔ 相关：欧洲宗教改革","id":"extra301"},{"text":"↔ 同时期参考：英王钦定版圣经","id":"extra898"}],"source":"history","id":"extra304"},{"title":"宗教改革《奥格斯堡和约》","level":"A","type":"制度/文本卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1555年","place":"奥格斯堡；神圣罗马帝国","summary":"宗教改革《奥格斯堡和约》承认路德宗在帝国内的合法地位，以“谁的领地，谁的宗教”暂时冻结教派冲突。","fields":[{"label":"标题","value":"宗教改革《奥格斯堡和约》"},{"label":"分级","value":"A"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1555年"},{"label":"地点","value":"奥格斯堡；神圣罗马帝国"},{"label":"主要国家","value":"神圣罗马帝国；德意志诸邦"},{"label":"一句话概括","value":"宗教改革《奥格斯堡和约》承认路德宗在帝国内的合法地位，以“谁的领地，谁的宗教”暂时冻结教派冲突。"},{"label":"制定方/签署方","value":"皇帝查理五世一方与神圣罗马帝国诸侯，实际由斐迪南代表皇帝处理。"},{"label":"主要内容","value":"承认天主教和路德宗诸侯在各自领地内决定宗教归属的权利，帝国臣民可在一定条件下迁往自己信仰所在地区。"},{"label":"它试图解决什么问题","value":"宗教改革后帝国内部天主教与路德宗冲突持续，皇帝无法用军事和教会权威恢复统一，需要法律妥协维持帝国秩序。"},{"label":"为什么重要","value":"它是欧洲宗教政治史的重要节点，承认帝国内教派分裂的制度现实，也显示早期近代国家权力开始介入宗教选择。"},{"label":"争议/局限","value":"和约不承认加尔文宗，普通臣民选择有限；宗教问题被领地主权化，埋下三十年战争前的长期矛盾。"},{"label":"造成的影响","value":"帝国获得数十年相对稳定，但教派边界和诸侯权力进一步固定，宗教和平只是暂时解决方案。"},{"label":"出处","value":"Britannica, Peace of Augsburg；German History in Documents and Images, Religious Peace of Augsburg materials。"}],"relationItems":["← 前因：欧洲宗教改革","→ 后果：三十年战争","↔ 相关：神圣罗马帝国","↔ 相关：路德德语圣经翻译","↔ 同时期参考：法国南特敕令"],"relations":[{"text":"← 前因：欧洲宗教改革","id":"extra301"},{"text":"→ 后果：三十年战争","id":"extra307"},{"text":"↔ 相关：神圣罗马帝国","id":"extra300"},{"text":"↔ 相关：路德德语圣经翻译","id":"extra304"},{"text":"↔ 同时期参考：法国南特敕令","id":"extra899"}],"source":"history","id":"extra305"},{"title":"布拉格掷出窗外事件","level":"B","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1618年5月23日","place":"布拉格","summary":"1618年布拉格掷出窗外事件引爆波希米亚危机，成为三十年战争的直接导火索。","fields":[{"label":"标题","value":"布拉格掷出窗外事件"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1618年5月23日"},{"label":"地点","value":"布拉格"},{"label":"主要国家","value":"波希米亚；神圣罗马帝国；哈布斯堡君主国"},{"label":"一句话概括","value":"1618年布拉格掷出窗外事件引爆波希米亚危机，成为三十年战争的直接导火索。"},{"label":"参与者","value":"波希米亚新教贵族、哈布斯堡皇帝代表、斐迪南二世支持者。"},{"label":"发生了什么","value":"波希米亚新教贵族抗议哈布斯堡方面限制宗教和政治权利，将两名皇帝代表和一名书记员从布拉格城堡窗口扔出。三人虽幸存，但事件迅速升级为波希米亚反哈布斯堡起义，并牵动帝国和欧洲多方力量。"},{"label":"为什么重要","value":"它是三十年战争的高辨识度起点，说明宗教冲突、贵族特权和哈布斯堡中央化之间的矛盾已经无法通过帝国内部程序化解。"},{"label":"前因","value":"宗教改革《奥格斯堡和约》未解决加尔文宗合法性和波希米亚宗教权利问题，哈布斯堡王权强化又威胁地方贵族自治。"},{"label":"后果","value":"波希米亚起义虽然被哈布斯堡镇压，但冲突没有停留在地方叛乱层面。帝国诸侯、丹麦、瑞典、法国和西班牙等力量陆续卷入，使战争从帝国内部宗教政治危机扩大为欧洲长期战争。"},{"label":"出处","value":"Britannica, Defenestration of Prague；Britannica, Thirty Years’ War。"}],"relationItems":["← 前因：宗教改革《奥格斯堡和约》","→ 后果：三十年战争","↔ 相关：哈布斯堡君主国","↔ 相关：神圣罗马帝国","↔ 同时期参考：荷兰独立战争"],"relations":[{"text":"← 前因：宗教改革《奥格斯堡和约》","id":"extra305"},{"text":"→ 后果：三十年战争","id":"extra307"},{"text":"↔ 相关：哈布斯堡君主国","id":"extra309"},{"text":"↔ 相关：神圣罗马帝国","id":"extra300"},{"text":"↔ 同时期参考：荷兰独立战争","id":"extra873"}],"source":"history","id":"extra306"},{"title":"三十年战争","level":"A","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1618—1648年","place":"神圣罗马帝国及中欧多地","summary":"三十年战争从帝国宗教危机扩展为欧洲霸权战争，给中欧社会和国际秩序造成深远影响。","fields":[{"label":"标题","value":"三十年战争"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1618—1648年"},{"label":"地点","value":"神圣罗马帝国及中欧多地"},{"label":"主要国家","value":"神圣罗马帝国；哈布斯堡君主国；瑞典；法国；西班牙；丹麦"},{"label":"一句话概括","value":"三十年战争从帝国宗教危机扩展为欧洲霸权战争，给中欧社会和国际秩序造成深远影响。"},{"label":"参与者","value":"神圣罗马帝国皇帝、德意志诸侯、波希米亚反叛者、瑞典、法国、西班牙、丹麦及雇佣军。"},{"label":"发生了什么","value":"战争从波希米亚起义开始，逐步经历波希米亚、丹麦、瑞典和法国等阶段。各方以宗教、王朝和地缘政治为名参战，神圣罗马帝国大量地区反复被军队征发、劫掠和占领。法国虽为天主教国家，却为削弱哈布斯堡加入反皇帝阵营，显示战争已超出单纯宗教冲突。"},{"label":"为什么重要","value":"它是欧洲早期近代最重要战争之一，暴露复合帝国和宗教妥协的极限，也促成威斯特伐利亚和约和欧洲国际秩序重组。"},{"label":"前因","value":"宗教改革《奥格斯堡和约》未能容纳加尔文宗和复杂的宗教政治现实，哈布斯堡中央化、诸侯自治和欧洲王朝竞争不断叠加。"},{"label":"后果","value":"中欧人口、农业、城市和乡村社会遭受长期破坏，许多地区财政和人口恢复缓慢。战后和约进一步确认帝国内诸侯权利，神圣罗马帝国更难形成中央集权，法国和瑞典则在欧洲权力格局中上升。"},{"label":"出处","value":"Britannica, Thirty Years’ War；German History in Documents and Images, Thirty Years’ War materials。"}],"relationItems":["← 前因：布拉格掷出窗外事件","→ 后果：威斯特伐利亚和约","↔ 相关：哈布斯堡君主国","↔ 相关：神圣罗马帝国","↔ 同时期参考：英国内战"],"relations":[{"text":"← 前因：布拉格掷出窗外事件","id":"extra306"},{"text":"→ 后果：威斯特伐利亚和约","id":"extra308"},{"text":"↔ 相关：哈布斯堡君主国","id":"extra309"},{"text":"↔ 相关：神圣罗马帝国","id":"extra300"},{"text":"↔ 同时期参考：英国内战","id":"extra894"}],"source":"history","id":"extra307"},{"title":"威斯特伐利亚和约","level":"S","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1648年","place":"明斯特、奥斯纳布吕克","summary":"威斯特伐利亚和约结束三十年战争，重塑帝国诸侯权利和欧洲国际秩序，是世界史坐标级外交节点。","fields":[{"label":"标题","value":"威斯特伐利亚和约"},{"label":"分级","value":"S"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1648年"},{"label":"地点","value":"明斯特、奥斯纳布吕克"},{"label":"主要国家","value":"神圣罗马帝国；法国；瑞典；西班牙；荷兰；德意志诸邦"},{"label":"一句话概括","value":"威斯特伐利亚和约结束三十年战争，重塑帝国诸侯权利和欧洲国际秩序，是世界史坐标级外交节点。"},{"label":"制定方/签署方","value":"神圣罗马帝国皇帝、帝国等级、法国、瑞典、西班牙、荷兰等多方代表。"},{"label":"主要内容","value":"确认帝国内天主教、路德宗和加尔文宗的法律地位，承认荷兰和瑞士独立地位，调整领土安排，并强化帝国诸侯在外交和内政上的权利。"},{"label":"它试图解决什么问题","value":"三十年战争使宗教、王朝和国际冲突交织，欧洲需要通过多边谈判结束战争并稳定帝国与周边国家关系。"},{"label":"为什么重要","value":"它不仅结束战争，也成为近代国际关系史上的关键参照。所谓“威斯特伐利亚体系”后来常被用来讨论主权、国家平等和多边外交。"},{"label":"争议/局限","value":"把1648年直接等同于现代主权国家体系起点有简化风险；和约仍保留神圣罗马帝国复杂结构，不是现代民族国家秩序。"},{"label":"造成的影响","value":"德意志地区政治分散长期延续，法国和瑞典影响力上升，欧洲外交更重视条约、平衡和多方会议。"},{"label":"出处","value":"Britannica, Peace of Westphalia；Oxford Public International Law, Peace of Westphalia；German History in Documents and Images, Westphalia materials。"}],"relationItems":["← 前因：三十年战争","→ 后果：神圣罗马帝国的诸侯主权化","↔ 相关：哈布斯堡君主国","↔ 相关：欧洲均势政治","↔ 同时期参考：荷兰独立战争"],"relations":[{"text":"← 前因：三十年战争","id":"extra307"},{"text":"→ 后果：神圣罗马帝国的诸侯主权化","id":"extra904"},{"text":"↔ 相关：哈布斯堡君主国","id":"extra309"},{"text":"↔ 相关：欧洲均势政治","id":"extra866"},{"text":"↔ 同时期参考：荷兰独立战争","id":"extra873"}],"source":"history","id":"extra308"},{"title":"哈布斯堡君主国","level":"A","type":"组织/机构卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"中世纪晚期形成，早期近代至1918年长期存在","place":"中欧、东南欧和意大利部分地区，核心包括奥地利、波希米亚、匈牙利等","summary":"哈布斯堡君主国是中欧多民族王朝帝国，长期影响神圣罗马帝国、奥斯曼边疆和德意志权力结构。","fields":[{"label":"标题","value":"哈布斯堡君主国"},{"label":"分级","value":"A"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"中世纪晚期形成，早期近代至1918年长期存在"},{"label":"地点","value":"中欧、东南欧和意大利部分地区，核心包括奥地利、波希米亚、匈牙利等"},{"label":"主要国家","value":"奥地利；匈牙利；捷克；克罗地亚；意大利部分地区；德意志地区"},{"label":"一句话概括","value":"哈布斯堡君主国是中欧多民族王朝帝国，长期影响神圣罗马帝国、奥斯曼边疆和德意志权力结构。"},{"label":"性质/类型","value":"复合王朝君主国、多民族帝国。"},{"label":"成立/解散时间","value":"哈布斯堡家族自中世纪晚期扩张领地，1526年后控制波希米亚和匈牙利部分地区，1918年一战后解体。"},{"label":"核心目标/宗旨","value":"通过王朝继承、婚姻、战争和行政整合维系统治多个民族、语言和法律传统不同的地区。"},{"label":"关键人物（可选）","value":"查理五世、斐迪南一世、玛丽亚·特蕾莎、约瑟夫二世、弗朗茨一世等。"},{"label":"关键行动/事件","value":"长期担任神圣罗马帝国皇帝，抵御奥斯曼扩张，参与三十年战争、奥地利王位继承战争和德意志二元竞争。"},{"label":"为什么重要","value":"它把“德国史”放进中欧和世界史。德意志统一与奥普领导权问题长期不是单一民族国家问题，而是哈布斯堡多民族帝国、普鲁士和欧洲列强互动的结果。"},{"label":"争议/局限","value":"王朝帝国能容纳多元，但也长期面对中央集权、民族自治、宗教差异和财政军事压力。"},{"label":"出处","value":"Britannica, House of Habsburg；Britannica, Austria-Hungary and Habsburg monarchy materials。"}],"relationItems":["← 前因：神圣罗马帝国","→ 后果：奥地利与普鲁士二元主义","↔ 相关：三十年战争","↔ 相关：奥斯曼第二次围攻维也纳","↔ 同时期参考：奥斯曼帝国"],"relations":[{"text":"← 前因：神圣罗马帝国","id":"extra300"},{"text":"→ 后果：奥地利与普鲁士二元主义","id":"extra535"},{"text":"↔ 相关：三十年战争","id":"extra307"},{"text":"↔ 相关：奥斯曼第二次围攻维也纳","id":"extra310"},{"text":"↔ 同时期参考：奥斯曼帝国","id":"extra872"}],"source":"history","id":"extra309"},{"title":"奥斯曼第二次围攻维也纳","level":"A","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1683年","place":"维也纳","summary":"1683年维也纳解围阻止奥斯曼继续深入中欧，推动哈布斯堡在东南欧反攻和欧洲力量格局变化。","fields":[{"label":"标题","value":"奥斯曼第二次围攻维也纳"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1683年"},{"label":"地点","value":"维也纳"},{"label":"主要国家","value":"奥斯曼帝国；哈布斯堡君主国；波兰立陶宛联邦；神圣罗马帝国诸邦"},{"label":"一句话概括","value":"1683年维也纳解围阻止奥斯曼继续深入中欧，推动哈布斯堡在东南欧反攻和欧洲力量格局变化。"},{"label":"参与者","value":"奥斯曼大维齐尔卡拉·穆斯塔法、哈布斯堡守军、波兰国王扬三世·索别斯基、神圣罗马帝国援军。"},{"label":"发生了什么","value":"奥斯曼军队围攻维也纳，试图打开通往中欧的战略门户。维也纳守军坚持到援军抵达，波兰国王索别斯基和神圣罗马帝国诸军发动解围战，击败奥斯曼军队。此后哈布斯堡和盟友转入反攻。"},{"label":"为什么重要","value":"它是中欧和奥斯曼关系的重大转折，影响哈布斯堡东扩、匈牙利格局和欧洲对奥斯曼的战略想象。"},{"label":"前因","value":"奥斯曼帝国与哈布斯堡长期争夺匈牙利和中欧边疆，哈布斯堡内部压力和奥斯曼扩张机会共同促成围攻。"},{"label":"后果","value":"哈布斯堡在东南欧地位上升，奥斯曼在中欧扩张势头受挫，欧洲联盟政治和基督教共同防御叙事得到强化。"},{"label":"出处","value":"Britannica, Siege of Vienna；Encyclopaedia Britannica, John III Sobieski；Austrian historical materials on 1683 Vienna。"}],"relationItems":["← 前因：哈布斯堡君主国","→ 后果：哈布斯堡东南欧扩张","↔ 相关：神圣罗马帝国","↔ 相关：欧洲均势政治","↔ 同时期参考：奥斯曼帝国衰退争论"],"relations":[{"text":"← 前因：哈布斯堡君主国","id":"extra309"},{"text":"→ 后果：哈布斯堡东南欧扩张","id":"extra905"},{"text":"↔ 相关：神圣罗马帝国","id":"extra300"},{"text":"↔ 相关：欧洲均势政治","id":"extra866"}],"source":"history","id":"extra310"},{"title":"勃兰登堡-普鲁士崛起","level":"A","type":"概念/思潮卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"17世纪后期—18世纪","place":"勃兰登堡、普鲁士、柏林、柯尼斯堡等地","summary":"勃兰登堡-普鲁士从分散领地成长为军事官僚国家，改变德意志和欧洲权力平衡。","fields":[{"label":"标题","value":"勃兰登堡-普鲁士崛起"},{"label":"分级","value":"A"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"17世纪后期—18世纪"},{"label":"地点","value":"勃兰登堡、普鲁士、柏林、柯尼斯堡等地"},{"label":"主要国家","value":"普鲁士；神圣罗马帝国；波兰立陶宛联邦"},{"label":"一句话概括","value":"勃兰登堡-普鲁士从分散领地成长为军事官僚国家，改变德意志和欧洲权力平衡。"},{"label":"核心主张/思路","value":"通过常备军、税收、官僚行政和王朝领地整合，把地理分散、资源有限的领地组织成高效军事国家。"},{"label":"提出者/代表人物（可选）","value":"大选侯腓特烈·威廉、腓特烈一世、腓特烈·威廉一世、腓特烈大王。"},{"label":"它从何而来","value":"三十年战争暴露中欧领地脆弱性，霍亨索伦统治者试图通过军事和财政改革增强生存能力。"},{"label":"典型表现","value":"常备军扩张，贵族军官化，税收中央化，柏林行政中心加强，普鲁士王国成立。"},{"label":"为什么重要","value":"它解释为什么后来“德国问题”不是哈布斯堡单独主导，而是出现普鲁士-奥地利二元竞争。"},{"label":"争议/局限","value":"普鲁士国家能力建立在高税收、军队优先和等级社会基础上，现代化与军事化紧密纠缠。"},{"label":"出处","value":"Britannica, Prussia；Britannica, Frederick William, the Great Elector；German History in Documents and Images, Brandenburg-Prussia materials。"}],"relationItems":["← 前因：三十年战争","→ 后果：普鲁士王国成立","↔ 相关：哈布斯堡君主国","↔ 相关：奥地利与普鲁士二元主义","↔ 同时期参考：法国绝对主义国家建设"],"relations":[{"text":"← 前因：三十年战争","id":"extra307"},{"text":"→ 后果：普鲁士王国成立","id":"extra312"},{"text":"↔ 相关：哈布斯堡君主国","id":"extra309"},{"text":"↔ 相关：奥地利与普鲁士二元主义","id":"extra535"},{"text":"↔ 同时期参考：法国绝对主义国家建设","id":"extra890"}],"source":"history","id":"extra311"},{"title":"普鲁士王国成立","level":"B","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1701年1月18日","place":"柯尼斯堡","summary":"1701年勃兰登堡选侯加冕为“在普鲁士的国王”，使霍亨索伦国家获得王国身份和更高国际地位。","fields":[{"label":"标题","value":"普鲁士王国成立"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1701年1月18日"},{"label":"地点","value":"柯尼斯堡"},{"label":"主要国家","value":"普鲁士；神圣罗马帝国"},{"label":"一句话概括","value":"1701年勃兰登堡选侯加冕为“在普鲁士的国王”，使霍亨索伦国家获得王国身份和更高国际地位。"},{"label":"参与者","value":"腓特烈三世/腓特烈一世、霍亨索伦王朝、神圣罗马帝国皇帝利奥波德一世、欧洲列强外交环境。"},{"label":"发生了什么","value":"勃兰登堡选侯腓特烈三世在柯尼斯堡加冕为普鲁士国王，称“在普鲁士的国王”。由于普鲁士部分领土位于帝国之外，这一称号绕开了帝国内部对王号的限制，同时提升了霍亨索伦家族地位。"},{"label":"为什么重要","value":"王国身份增强了普鲁士在欧洲外交中的地位，为18世纪普鲁士军事和政治崛起提供象征资本。"},{"label":"前因","value":"勃兰登堡-普鲁士通过战争、继承和行政改革增强实力，霍亨索伦统治者希望用王号匹配实际权力和国际抱负。"},{"label":"后果","value":"王国身份提高了霍亨索伦国家的外交等级，也为军队、官僚和财政体系扩张提供更强象征支撑。18世纪中期，普鲁士在腓特烈大王手中成为欧洲强国，并开始与奥地利争夺德意志领导权。"},{"label":"出处","value":"Britannica, Prussia；Britannica, Frederick I king of Prussia；German History in Documents and Images, The Kingdom of Prussia materials。"}],"relationItems":["← 前因：勃兰登堡-普鲁士崛起","→ 后果：普鲁士腓特烈大王","↔ 相关：哈布斯堡君主国","↔ 相关：奥地利与普鲁士二元主义","↔ 同时期参考：俄国彼得大帝改革"],"relations":[{"text":"← 前因：勃兰登堡-普鲁士崛起","id":"extra311"},{"text":"→ 后果：普鲁士腓特烈大王","id":"extra315"},{"text":"↔ 相关：哈布斯堡君主国","id":"extra309"},{"text":"↔ 相关：奥地利与普鲁士二元主义","id":"extra535"},{"text":"↔ 同时期参考：俄国彼得大帝改革","id":"extra891"}],"source":"history","id":"extra312"},{"title":"奥地利王位继承战争","level":"A","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1740—1748年","place":"中欧、意大利、低地国家及海外战场","summary":"奥地利王位继承战争围绕玛丽亚·特蕾莎继承权展开，使普鲁士夺取西里西亚并跃升欧洲强国。","fields":[{"label":"标题","value":"奥地利王位继承战争"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1740—1748年"},{"label":"地点","value":"中欧、意大利、低地国家及海外战场"},{"label":"主要国家","value":"奥地利；普鲁士；法国；英国；西班牙；巴伐利亚等"},{"label":"一句话概括","value":"奥地利王位继承战争围绕玛丽亚·特蕾莎继承权展开，使普鲁士夺取西里西亚并跃升欧洲强国。"},{"label":"参与者","value":"玛丽亚·特蕾莎、腓特烈二世、哈布斯堡君主国、普鲁士、法国、英国、巴伐利亚等。"},{"label":"发生了什么","value":"查理六世去世后，玛丽亚·特蕾莎继承哈布斯堡领地，但多个列强挑战其继承权。腓特烈二世趁机入侵西里西亚，普鲁士与奥地利爆发战争。战争扩展为欧洲列强冲突，最终奥地利保住大部分继承权，但失去西里西亚。"},{"label":"为什么重要","value":"它使普鲁士从区域强国跃升为欧洲一流强国，也让奥地利-普鲁士竞争成为德意志政治长期主轴。"},{"label":"前因","value":"哈布斯堡家族为确保女性继承发布《国事诏书》，但列强在权力机会面前不愿完全承认；普鲁士希望通过夺取富庶西里西亚扩大实力。"},{"label":"后果","value":"西里西亚归普鲁士，奥地利启动行政和军事改革；两国矛盾延续到七年战争和19世纪德意志统一问题。"},{"label":"出处","value":"Britannica, War of the Austrian Succession；Britannica, Maria Theresa；Britannica, Frederick II。"}],"relationItems":["← 前因：哈布斯堡君主国","→ 后果：七年战争","↔ 相关：玛丽亚·特蕾莎","↔ 相关：普鲁士腓特烈大王","↔ 同时期参考：英法殖民竞争"],"relations":[{"text":"← 前因：哈布斯堡君主国","id":"extra309"},{"text":"→ 后果：七年战争","id":"extra316"},{"text":"↔ 相关：玛丽亚·特蕾莎","id":"extra314"},{"text":"↔ 相关：普鲁士腓特烈大王","id":"extra315"},{"text":"↔ 同时期参考：英法殖民竞争","id":"extra875"}],"source":"history","id":"extra313"},{"title":"玛丽亚·特蕾莎","level":"B","type":"人物卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1717—1780年；统治期1740—1780年","place":"维也纳；哈布斯堡君主国","summary":"玛丽亚·特蕾莎在王位继承危机中保住哈布斯堡大部分领地，并推动行政、军事和教育改革。","fields":[{"label":"标题","value":"玛丽亚·特蕾莎"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1717—1780年；统治期1740—1780年"},{"label":"地点","value":"维也纳；哈布斯堡君主国"},{"label":"主要国家","value":"奥地利；匈牙利；捷克等哈布斯堡领地"},{"label":"一句话概括","value":"玛丽亚·特蕾莎在王位继承危机中保住哈布斯堡大部分领地，并推动行政、军事和教育改革。"},{"label":"生卒年/活跃年代","value":"1717—1780年；1740年继承哈布斯堡领地后成为欧洲核心统治者。"},{"label":"身份/职务","value":"哈布斯堡君主国统治者，奥地利大公、匈牙利和波希米亚女王。"},{"label":"关键贡献/作为","value":"在奥地利王位继承战争中保住大部分继承权；推动财政、军队、教育和行政改革，增强哈布斯堡国家能力。"},{"label":"核心主张/立场","value":"维护王朝继承和天主教君主秩序，同时接受必要的国家行政改革，以增强帝国竞争力。"},{"label":"为什么重要","value":"她是理解奥地利如何在普鲁士冲击下自我改革的关键人物，也是18世纪欧洲女性君主权力的核心案例。"},{"label":"争议/评价","value":"她的改革增强国家能力，但仍保留等级社会和宗教保守性；其与腓特烈大王的竞争塑造中欧格局。"},{"label":"关联事件（可选）","value":"奥地利王位继承战争、七年战争、约瑟夫二世改革。"},{"label":"出处","value":"Britannica, Maria Theresa；Habsburg historical sources on Maria Theresa。"}],"relationItems":["← 前因：哈布斯堡君主国","→ 后果：约瑟夫二世改革","↔ 相关：奥地利王位继承战争","↔ 相关：普鲁士腓特烈大王","↔ 同时期参考：俄国叶卡捷琳娜二世"],"relations":[{"text":"← 前因：哈布斯堡君主国","id":"extra309"},{"text":"→ 后果：约瑟夫二世改革","id":"extra318"},{"text":"↔ 相关：奥地利王位继承战争","id":"extra313"},{"text":"↔ 相关：普鲁士腓特烈大王","id":"extra315"},{"text":"↔ 同时期参考：俄国叶卡捷琳娜二世","id":"extra892"}],"source":"history","id":"extra314"},{"title":"普鲁士腓特烈大王","level":"A","type":"人物卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1712—1786年；统治期1740—1786年","place":"普鲁士；柏林、波茨坦等地","summary":"腓特烈大王通过夺取西里西亚、军事改革和开明专制实践，使普鲁士成为欧洲强国。","fields":[{"label":"标题","value":"普鲁士腓特烈大王"},{"label":"分级","value":"A"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1712—1786年；统治期1740—1786年"},{"label":"地点","value":"普鲁士；柏林、波茨坦等地"},{"label":"主要国家","value":"普鲁士"},{"label":"一句话概括","value":"腓特烈大王通过夺取西里西亚、军事改革和开明专制实践，使普鲁士成为欧洲强国。"},{"label":"生卒年/活跃年代","value":"1712—1786年；1740年即位为普鲁士国王。"},{"label":"身份/职务","value":"普鲁士国王、军事统帅、开明专制君主。"},{"label":"关键贡献/作为","value":"发动西里西亚战争，参与奥地利王位继承战争和七年战争；强化官僚和军队；支持部分法律、农业和宗教宽容改革。"},{"label":"核心主张/立场","value":"把君主视为国家第一公仆，强调国家效率、军事力量和理性行政，同时维护贵族军官体系和王权专制。"},{"label":"为什么重要","value":"他使普鲁士成为可与奥地利竞争的欧洲强国，是后来德意志二元主义和普鲁士主导统一的重要前史。"},{"label":"争议/评价","value":"他既是启蒙君主形象代表，也通过侵略战争和高度军事化国家塑造了普鲁士权力传统。"},{"label":"关联事件（可选）","value":"奥地利王位继承战争、七年战争、普鲁士王国成立。"},{"label":"出处","value":"Britannica, Frederick II；German History in Documents and Images, Frederick II materials。"}],"relationItems":["← 前因：普鲁士王国成立","→ 后果：七年战争","↔ 相关：玛丽亚·特蕾莎","↔ 相关：奥地利与普鲁士二元主义","↔ 同时期参考：欧洲启蒙专制"],"relations":[{"text":"← 前因：普鲁士王国成立","id":"extra312"},{"text":"→ 后果：七年战争","id":"extra316"},{"text":"↔ 相关：玛丽亚·特蕾莎","id":"extra314"},{"text":"↔ 相关：奥地利与普鲁士二元主义","id":"extra535"},{"text":"↔ 同时期参考：欧洲启蒙专制","id":"extra883"}],"source":"history","id":"extra315"},{"title":"七年战争","level":"S","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1756—1763年","place":"欧洲、中北美、加勒比、印度洋和印度等地","summary":"七年战争是全球性列强战争，巩固普鲁士强国地位，也重塑英国、法国和欧洲殖民竞争格局。","fields":[{"label":"标题","value":"七年战争"},{"label":"分级","value":"S"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1756—1763年"},{"label":"地点","value":"欧洲、中北美、加勒比、印度洋和印度等地"},{"label":"主要国家","value":"普鲁士；奥地利；英国；法国；俄国；西班牙；多地殖民势力"},{"label":"一句话概括","value":"七年战争是全球性列强战争，巩固普鲁士强国地位，也重塑英国、法国和欧洲殖民竞争格局。"},{"label":"参与者","value":"普鲁士、奥地利、英国、法国、俄国、西班牙、瑞典，以及北美、印度等地殖民军和盟友。"},{"label":"发生了什么","value":"欧洲战场上，普鲁士面对奥地利、法国、俄国等多方压力，在腓特烈大王指挥下艰难维持。英国与法国在北美、加勒比和印度展开殖民战争。1763年和约结束后，普鲁士保住西里西亚，英国大幅扩大海外优势。"},{"label":"为什么重要","value":"它是世界史坐标级战争，被许多历史学者视为早期全球战争之一。它同时改变中欧权力平衡和英法殖民竞争，影响美国革命前史。"},{"label":"前因","value":"奥地利试图夺回西里西亚，普鲁士希望保住新获得的强国地位；英法海外竞争和欧洲同盟重组使地区矛盾全球化。"},{"label":"后果","value":"普鲁士强国地位被确认，奥地利无法恢复中欧霸权；英国获得更大殖民优势，但战争债务也加深北美殖民地税收冲突。"},{"label":"出处","value":"Britannica, Seven Years’ War；Encyclopaedia Britannica, French and Indian War；German History in Documents and Images, Frederick II and Seven Years’ War materials。"}],"relationItems":["← 前因：奥地利王位继承战争","→ 后果：奥地利与普鲁士二元主义","↔ 相关：普鲁士腓特烈大王","↔ 相关：玛丽亚·特蕾莎","↔ 同时期参考：法国印第安战争"],"relations":[{"text":"← 前因：奥地利王位继承战争","id":"extra313"},{"text":"→ 后果：奥地利与普鲁士二元主义","id":"extra535"},{"text":"↔ 相关：普鲁士腓特烈大王","id":"extra315"},{"text":"↔ 相关：玛丽亚·特蕾莎","id":"extra314"},{"text":"↔ 同时期参考：法国印第安战争","id":"extra907"}],"source":"history","id":"extra316"},{"title":"德意志启蒙运动","level":"B","type":"概念/思潮卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"18世纪","place":"德意志各邦、普鲁士、哈布斯堡领地及大学城市","summary":"德意志启蒙运动强调理性、教育、宗教宽容和公共讨论，为改革官僚国家和现代哲学提供思想资源。","fields":[{"label":"标题","value":"德意志启蒙运动"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"18世纪"},{"label":"地点","value":"德意志各邦、普鲁士、哈布斯堡领地及大学城市"},{"label":"主要国家","value":"德意志地区；普鲁士；奥地利"},{"label":"一句话概括","value":"德意志启蒙运动强调理性、教育、宗教宽容和公共讨论，为改革官僚国家和现代哲学提供思想资源。"},{"label":"核心主张/思路","value":"以理性批判、教育改良、宗教宽容、法治和公共使用理性来改善社会和国家治理。"},{"label":"提出者/代表人物（可选）","value":"莱布尼茨、莱辛、门德尔松、康德、普鲁士和奥地利改革官僚等。"},{"label":"它从何而来","value":"欧洲启蒙运动、大学学术、印刷公共领域、宗教多元和开明专制改革共同推动德语思想界发展。"},{"label":"典型表现","value":"哲学论文、剧场和文学批评、教育改革、宽容讨论、学会和期刊公共辩论。"},{"label":"为什么重要","value":"它让德意志地区在18世纪世界思想史中占据核心位置，康德哲学、宗教宽容和国家改革都从中获得动力。"},{"label":"争议/局限","value":"启蒙理性常与君主国家改革结合，普通民众政治参与有限；女性、犹太人和农民的实际平等仍受限制。"},{"label":"出处","value":"Britannica, Enlightenment；Stanford Encyclopedia of Philosophy, German Enlightenment references；German History in Documents and Images, Enlightenment materials。"}],"relationItems":["← 前因：欧洲宗教改革","→ 后果：德意志浪漫主义","↔ 相关：约瑟夫二世改革","↔ 相关：普鲁士腓特烈大王","↔ 同时期参考：法国启蒙运动"],"relations":[{"text":"← 前因：欧洲宗教改革","id":"extra301"},{"text":"→ 后果：德意志浪漫主义","id":"extra552"},{"text":"↔ 相关：约瑟夫二世改革","id":"extra318"},{"text":"↔ 相关：普鲁士腓特烈大王","id":"extra315"}],"source":"history","id":"extra317"},{"title":"约瑟夫二世改革","level":"B","type":"事件卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1780—1790年为核心阶段","place":"哈布斯堡君主国","summary":"约瑟夫二世改革以开明专制方式推动宗教宽容、农民减负和行政中央化，显示启蒙改革与帝国多元结构的冲突。","fields":[{"label":"标题","value":"约瑟夫二世改革"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1780—1790年为核心阶段"},{"label":"地点","value":"哈布斯堡君主国"},{"label":"主要国家","value":"奥地利；匈牙利；捷克等哈布斯堡领地"},{"label":"一句话概括","value":"约瑟夫二世改革以开明专制方式推动宗教宽容、农民减负和行政中央化，显示启蒙改革与帝国多元结构的冲突。"},{"label":"参与者","value":"皇帝约瑟夫二世、哈布斯堡官僚、教会、贵族、农民和各地等级机构。"},{"label":"发生了什么","value":"约瑟夫二世即位后推动一系列改革，包括限制教会权力、关闭部分修道院、发布宗教宽容政策、试图减轻农民束缚、统一行政和法律制度。他希望用理性化国家治理改造多民族帝国，但许多改革触动教会、贵族和地方特权，引发抵制。"},{"label":"为什么重要","value":"它是欧洲开明专制的重要案例，说明启蒙改革不一定来自革命，也可能由君主和官僚自上而下推动。"},{"label":"前因","value":"玛丽亚·特蕾莎时期已推动行政、财政和教育改革；七年战争后的竞争压力迫使哈布斯堡继续增强国家能力。"},{"label":"后果","value":"约瑟夫二世去世后，部分改革因地方抵制和帝国压力被撤回或削弱，但宗教宽容、行政理性化、国家干预教育和社会治理的方向仍影响哈布斯堡后续改革。改革的挫折也暴露多民族帝国整合的难度。"},{"label":"出处","value":"Britannica, Joseph II；German History in Documents and Images, Joseph II reform materials；Habsburg historical sources。"}],"relationItems":["← 前因：玛丽亚·特蕾莎","→ 后果：哈布斯堡君主国改革困境","↔ 相关：德意志启蒙运动","↔ 相关：哈布斯堡君主国","↔ 同时期参考：俄国叶卡捷琳娜二世"],"relations":[{"text":"← 前因：玛丽亚·特蕾莎","id":"extra314"},{"text":"↔ 相关：德意志启蒙运动","id":"extra317"},{"text":"↔ 相关：哈布斯堡君主国","id":"extra309"},{"text":"↔ 同时期参考：俄国叶卡捷琳娜二世","id":"extra892"}],"source":"history","id":"extra318"},{"title":"法国大革命的欧洲冲击","level":"S","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1789年后，1790年代至拿破仑时代持续","place":"法国、欧洲大陆、大西洋世界","summary":"法国大革命重塑政治合法性、战争动员和欧洲均势，开启革命战争与拿破仑时代。","fields":[{"label":"标题","value":"法国大革命的欧洲冲击"},{"label":"分级","value":"S"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1789年后，1790年代至拿破仑时代持续"},{"label":"地点","value":"法国、欧洲大陆、大西洋世界"},{"label":"主要国家","value":"法国；奥地利；普鲁士；英国；俄国；意大利诸邦；低地地区；神圣罗马帝国"},{"label":"一句话概括","value":"法国大革命重塑政治合法性、战争动员和欧洲均势，开启革命战争与拿破仑时代。"},{"label":"参与者","value":"法国革命政府、欧洲君主国、反法同盟、革命支持者、保守派、军队和各地政治社群。"},{"label":"发生了什么","value":"1789年法国革命推翻旧制度后，人民主权、宪政、共和、反封建和民族动员等观念迅速外溢。奥地利、普鲁士等君主国担心革命扩散并与法国发生战争，法国革命军则向外推进，在莱茵地区、低地国家、意大利和瑞士等地扶植或改造政治秩序。革命战争把征兵、宣传、占领改革和反法联盟连在一起，使法国国内革命转化为欧洲体系危机。"},{"label":"为什么重要","value":"它不是某一国受到法国影响的局部事件，而是近代世界政治转型的核心节点。它挑战王朝合法性和等级秩序，推动现代民族主义、群众政治和总体动员，也为神圣罗马帝国解体、拿破仑帝国、维也纳体系和19世纪革命潮提供前提。"},{"label":"前因","value":"启蒙思想、旧制度财政危机、社会等级矛盾和美国革命经验削弱法国王权合法性；欧洲各君主国又担心革命原则外溢。"},{"label":"后果","value":"法国革命战争和拿破仑战争重组欧洲版图，旧帝国和许多封建特权被削弱，反法同盟和维也纳会议则试图重新建立均势与保守秩序。1830年、1848年的革命浪潮也继承了法国革命留下的政治语言。"},{"label":"出处","value":"Encyclopaedia Britannica: French Revolution；Encyclopaedia Britannica: French Revolutionary Wars；German History in Documents and Images, French Revolution impact on Germany。"}],"relationItems":["← 前因：德意志启蒙运动","→ 后果：第一次反法同盟战争","→ 后果：神圣罗马帝国代表会议主要决议","→ 后果：神圣罗马帝国解体","↔ 相关：普鲁士施泰因-哈登贝格改革","↔ 同时期参考：法国革命战争"],"relations":[{"text":"← 前因：德意志启蒙运动","id":"extra317"},{"text":"→ 后果：第一次反法同盟战争","id":"extra475"},{"text":"→ 后果：神圣罗马帝国代表会议主要决议","id":"extra320"},{"text":"→ 后果：神圣罗马帝国解体","id":"extra520"},{"text":"↔ 相关：普鲁士施泰因-哈登贝格改革","id":"extra522"},{"text":"↔ 同时期参考：法国革命战争","id":"extra919"}],"source":"history","id":"extra319"},{"title":"神圣罗马帝国代表会议主要决议","level":"B","type":"制度/文本卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1803年","place":"雷根斯堡；神圣罗马帝国","summary":"1803年主要决议大规模世俗化和领土重组，拆解神圣罗马帝国旧结构，为其1806年解体铺路。","fields":[{"label":"标题","value":"神圣罗马帝国代表会议主要决议"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1803年"},{"label":"地点","value":"雷根斯堡；神圣罗马帝国"},{"label":"主要国家","value":"神圣罗马帝国；法国；德意志诸邦"},{"label":"一句话概括","value":"1803年主要决议大规模世俗化和领土重组，拆解神圣罗马帝国旧结构，为其1806年解体铺路。"},{"label":"制定方/签署方","value":"神圣罗马帝国帝国代表会议，在法国压力和德意志诸侯利益重组背景下形成。"},{"label":"主要内容","value":"大量教会领地被世俗化，自由帝国城市被并入较大邦国，用领土补偿失去莱茵左岸土地的诸侯。"},{"label":"它试图解决什么问题","value":"法国占领莱茵左岸后，许多德意志诸侯失去领地，帝国需要通过重新分配教会和城市领土来补偿。"},{"label":"为什么重要","value":"它是旧帝国结构崩塌前最重要的制度重组之一，极大减少小邦和教会领地数量，推动德意志政治版图向较大邦国集中。"},{"label":"争议/局限","value":"决议以补偿和理性化为名，实际上牺牲大量教会领地和自由城市自治，显示帝国已无力抵抗法国主导的重组。"},{"label":"造成的影响","value":"德意志领土格局被彻底改变，莱茵邦和神圣罗马帝国解体随之而来，19世纪德意志国家整合获得新前提。"},{"label":"出处","value":"German History in Documents and Images, Final Recess of the Imperial Deputation (1803)；Britannica, Holy Roman Empire dissolution context。"}],"relationItems":["← 前因：法国大革命的欧洲冲击","→ 后果：神圣罗马帝国解体","↔ 相关：拿破仑莱茵邦","↔ 相关：普鲁士施泰因-哈登贝格改革","↔ 同时期参考：拿破仑重组意大利"],"relations":[{"text":"← 前因：法国大革命的欧洲冲击","id":"extra319"},{"text":"→ 后果：神圣罗马帝国解体","id":"extra520"},{"text":"↔ 相关：拿破仑莱茵邦","id":"extra521"},{"text":"↔ 相关：普鲁士施泰因-哈登贝格改革","id":"extra522"}],"source":"history","id":"extra320"},{"title":"中世纪汉萨同盟","level":"B","type":"组织/机构卡","tags":["经济与社会","战争与外交"],"mainTag":"经济与社会","subTag":"战争与外交","timeText":"约13世纪—17世纪逐渐衰落","place":"北海、波罗的海沿岸城市，核心包括吕贝克、汉堡、不来梅等","summary":"汉萨同盟是北欧和波罗的海城市商业网络，显示中世纪晚期到早期近代贸易并不只靠王国国家推动。","fields":[{"label":"标题","value":"中世纪汉萨同盟"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"约13世纪—17世纪逐渐衰落"},{"label":"地点","value":"北海、波罗的海沿岸城市，核心包括吕贝克、汉堡、不来梅等"},{"label":"主要国家","value":"德意志地区；丹麦；瑞典；波兰；波罗的海地区；低地国家"},{"label":"一句话概括","value":"汉萨同盟是北欧和波罗的海城市商业网络，显示中世纪晚期到早期近代贸易并不只靠王国国家推动。"},{"label":"性质/类型","value":"城市商业联盟和贸易网络。"},{"label":"成立/解散时间","value":"13世纪逐渐形成，14—15世纪达到高峰，17世纪后明显衰落。"},{"label":"核心目标/宗旨","value":"保护德意志和北欧商人在北海、波罗的海及海外商站中的贸易特权，协调航运、法律和共同防御。"},{"label":"关键人物（可选）","value":"无单一创始人，吕贝克等城市商人和市政精英长期主导。"},{"label":"关键行动/事件","value":"建立伦敦、布鲁日、卑尔根、诺夫哥罗德等商站；控制谷物、木材、鱼、盐、毛皮等贸易；同丹麦等王权发生战争和谈判。"},{"label":"为什么重要","value":"它把德意志早期历史放进北欧贸易和城市自治世界史中，说明德意志地区在民族国家形成前已深度参与跨区域商业网络。"},{"label":"争议/局限","value":"汉萨不是现代国家或统一组织，成员松散、利益不一，面对大西洋贸易兴起和强王权国家竞争逐渐失去优势。"},{"label":"出处","value":"Britannica, Hanseatic League；European Hansemuseum, Hanse history。"}],"relationItems":["→ 后果：汉堡自由港与仓库城","↔ 相关：德意志城市自治传统","↔ 相关：北德劳埃德航运公司","↔ 同时期参考：威尼斯共和国"],"relations":[{"text":"→ 后果：汉堡自由港与仓库城","id":"extra839"},{"text":"↔ 相关：北德劳埃德航运公司","id":"extra841"}],"source":"history","id":"extra321"},{"title":"富格尔家族银行网络","level":"B","type":"组织/机构卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"15世纪后期—16世纪","place":"奥格斯堡；神圣罗马帝国；欧洲金融网络","summary":"富格尔家族用矿业、贸易和信贷连接欧洲王朝政治，是早期近代金融资本影响国家权力的典型案例。","fields":[{"label":"标题","value":"富格尔家族银行网络"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"15世纪后期—16世纪"},{"label":"地点","value":"奥格斯堡；神圣罗马帝国；欧洲金融网络"},{"label":"主要国家","value":"德意志地区；西班牙；奥地利；意大利地区"},{"label":"一句话概括","value":"富格尔家族用矿业、贸易和信贷连接欧洲王朝政治，是早期近代金融资本影响国家权力的典型案例。"},{"label":"性质/类型","value":"商人银行家族和跨国金融网络。"},{"label":"成立/解散时间","value":"15世纪后期崛起，16世纪达到顶峰。"},{"label":"核心目标/宗旨","value":"通过纺织、金属贸易、矿业投资和向王侯教会提供贷款积累财富和政治影响。"},{"label":"关键人物（可选）","value":"雅各布·富格尔“富人”。"},{"label":"关键行动/事件","value":"资助哈布斯堡王朝，参与查理五世皇帝竞选融资，经营蒂罗尔和匈牙利矿业利益。"},{"label":"为什么重要","value":"它说明宗教改革时代的欧洲政治背后有复杂金融网络，皇帝、教会和战争都离不开信贷。"},{"label":"争议/局限","value":"富格尔财富与教会财政、赎罪券和王朝债务有关，常被批评为金钱支配政治和宗教的象征。"},{"label":"出处","value":"Britannica, Fugger family；Fugger.de, Jakob Fugger and family history。"}],"relationItems":["← 前因：中世纪汉萨同盟","→ 后果：马丁·路德发表《九十五条论纲》","↔ 相关：哈布斯堡君主国","↔ 相关：欧洲宗教改革","↔ 同时期参考：美第奇家族银行"],"relations":[{"text":"← 前因：中世纪汉萨同盟","id":"extra321"},{"text":"→ 后果：马丁·路德发表《九十五条论纲》","id":"extra302"},{"text":"↔ 相关：哈布斯堡君主国","id":"extra309"},{"text":"↔ 相关：欧洲宗教改革","id":"extra301"}],"source":"history","id":"extra322"},{"title":"德意志农民战争","level":"A","type":"事件卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1524—1525年","place":"神圣罗马帝国南部和中部多地","summary":"德意志农民战争把宗教改革语言、农民负担和地方权力冲突结合起来，是早期近代欧洲最大社会起义之一。","fields":[{"label":"标题","value":"德意志农民战争"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1524—1525年"},{"label":"地点","value":"神圣罗马帝国南部和中部多地"},{"label":"主要国家","value":"德意志地区；神圣罗马帝国"},{"label":"一句话概括","value":"德意志农民战争把宗教改革语言、农民负担和地方权力冲突结合起来，是早期近代欧洲最大社会起义之一。"},{"label":"参与者","value":"农民、城市平民、地方诸侯、骑士、牧师、托马斯·闵采尔、马丁·路德等。"},{"label":"发生了什么","value":"1524年起，德意志南部和中部多地农民因租税、劳役、森林和渔猎权、地方司法等问题起事。他们用基督教自由、共同体权利和《十二条款》等语言提出诉求。起义迅速扩大，但缺乏统一军事组织，最终被诸侯军队镇压，造成大量死亡。"},{"label":"为什么重要","value":"它说明宗教改革不是单纯神学争论，普通农民和城市下层也会把新宗教语言转化为社会权利诉求。"},{"label":"前因","value":"农民经济负担和领主权力扩张长期积累不满，宗教改革传播又让人们用圣经和“基督徒自由”重新理解服从与正义。"},{"label":"后果","value":"起义失败后，诸侯权力在许多地区加强，路德与激进改革派分裂更明显；农民社会诉求虽被压制，却成为欧洲社会史的重要参照。"},{"label":"出处","value":"Britannica, Peasants’ War；German History in Documents and Images, The Twelve Articles of the Swabian Peasants。"}],"relationItems":["← 前因：欧洲宗教改革","→ 后果：德意志农民战争《十二条款》","↔ 相关：马丁·路德发表《九十五条论纲》","↔ 相关：再洗礼派与明斯特事件","↔ 同时期参考：英格兰凯特叛乱"],"relations":[{"text":"← 前因：欧洲宗教改革","id":"extra301"},{"text":"→ 后果：德意志农民战争《十二条款》","id":"extra324"},{"text":"↔ 相关：马丁·路德发表《九十五条论纲》","id":"extra302"},{"text":"↔ 相关：再洗礼派与明斯特事件","id":"extra325"}],"source":"history","id":"extra323"},{"title":"德意志农民战争《十二条款》","level":"B","type":"制度/文本卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"1525年","place":"施瓦本等德意志地区","summary":"《十二条款》把农民诉求整理成带有圣经依据的权利文本，是德意志农民战争最重要的纲领文献。","fields":[{"label":"标题","value":"德意志农民战争《十二条款》"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1525年"},{"label":"地点","value":"施瓦本等德意志地区"},{"label":"主要国家","value":"德意志地区；神圣罗马帝国"},{"label":"一句话概括","value":"《十二条款》把农民诉求整理成带有圣经依据的权利文本，是德意志农民战争最重要的纲领文献。"},{"label":"制定方/签署方","value":"施瓦本农民代表和相关起义共同体。"},{"label":"主要内容","value":"文本要求自由选举牧师、减轻什一税和劳役、恢复公共使用森林和水域的权利、反对任意司法和过重租税，并以圣经正义作为论证依据。"},{"label":"它试图解决什么问题","value":"农民希望把分散的经济和司法不满整理成可以谈判、传播和辩护的共同诉求，而不只是地方暴动。"},{"label":"为什么重要","value":"它是早期近代欧洲社会抗议史的重要文本，显示印刷、宗教语言和权利诉求如何结合。"},{"label":"争议/局限","value":"文本的权利语言仍以基督教共同体为基础，并非现代民主纲领；起义失败后，其政治效果被大幅压制。"},{"label":"造成的影响","value":"《十二条款》通过印刷传播扩大农民战争影响，也成为后来研究社会权利、宗教改革和大众政治表达的重要史料。"},{"label":"出处","value":"German History in Documents and Images, The Twelve Articles of the Swabian Peasants (1525)；Britannica, Peasants’ War。"}],"relationItems":["← 前因：德意志农民战争","→ 后果：德意志农民战争","↔ 相关：欧洲宗教改革","↔ 相关：古腾堡活字印刷革命","↔ 同时期参考：英格兰平等派纲领"],"relations":[{"text":"← 前因：德意志农民战争","id":"extra323"},{"text":"→ 后果：德意志农民战争","id":"extra323"},{"text":"↔ 相关：欧洲宗教改革","id":"extra301"},{"text":"↔ 相关：古腾堡活字印刷革命","id":"extra299"}],"source":"history","id":"extra324"},{"title":"再洗礼派与明斯特事件","level":"B","type":"事件卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1534—1535年","place":"明斯特","summary":"明斯特再洗礼派政权把宗教改革激进化为末世共同体实验，其失败强化了各方对激进宗教政治的恐惧。","fields":[{"label":"标题","value":"再洗礼派与明斯特事件"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1534—1535年"},{"label":"地点","value":"明斯特"},{"label":"主要国家","value":"德意志地区；神圣罗马帝国"},{"label":"一句话概括","value":"明斯特再洗礼派政权把宗教改革激进化为末世共同体实验，其失败强化了各方对激进宗教政治的恐惧。"},{"label":"参与者","value":"再洗礼派领袖、明斯特市民、主教军队、周边诸侯和宗教改革阵营。"},{"label":"发生了什么","value":"1534年，再洗礼派在明斯特取得政权，推行成人洗礼、共同体纪律和末世主义政治，部分领袖建立强制性宗教秩序。主教军队围城镇压，1535年明斯特被攻陷，领袖被处决。"},{"label":"为什么重要","value":"它说明宗教改革内部并非只有路德宗和天主教对立，还有更激进的社会和宗教实验。明斯特事件使再洗礼派长期被视为危险激进主义。"},{"label":"前因","value":"宗教改革打开了重新组织教会和共同体的可能，农民战争失败后部分激进派仍追求更彻底的宗教社会秩序。"},{"label":"后果","value":"明斯特失败后，再洗礼派在天主教和主流新教地区都遭到压制，激进千禧年政治路线失去空间；许多温和再洗礼派随后转向和平主义、成人洗礼和与国家教会保持距离的分离主义传统。"},{"label":"出处","value":"Britannica, Anabaptist；Britannica, Münster Rebellion；Global Anabaptist Mennonite Encyclopedia Online, Münster。"}],"relationItems":["← 前因：德意志农民战争","→ 后果：宗教改革《奥格斯堡和约》","↔ 相关：欧洲宗教改革","↔ 相关：沃姆斯帝国议会","↔ 同时期参考：英格兰清教激进派"],"relations":[{"text":"← 前因：德意志农民战争","id":"extra323"},{"text":"→ 后果：宗教改革《奥格斯堡和约》","id":"extra305"},{"text":"↔ 相关：欧洲宗教改革","id":"extra301"},{"text":"↔ 相关：沃姆斯帝国议会","id":"extra303"}],"source":"history","id":"extra325"},{"title":"施马尔卡尔登同盟","level":"B","type":"组织/机构卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1531—1547年","place":"神圣罗马帝国新教诸侯和城市","summary":"施马尔卡尔登同盟把路德宗诸侯和城市组织成军事政治联盟，使宗教改革获得制度性防御力量。","fields":[{"label":"标题","value":"施马尔卡尔登同盟"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1531—1547年"},{"label":"地点","value":"神圣罗马帝国新教诸侯和城市"},{"label":"主要国家","value":"德意志地区；神圣罗马帝国"},{"label":"一句话概括","value":"施马尔卡尔登同盟把路德宗诸侯和城市组织成军事政治联盟，使宗教改革获得制度性防御力量。"},{"label":"性质/类型","value":"新教诸侯和城市的军事政治联盟。"},{"label":"成立/解散时间","value":"1531年成立，1547年在施马尔卡尔登战争中失败后解体。"},{"label":"核心目标/宗旨","value":"保护路德宗诸侯和城市免受皇帝及天主教力量压制，维护宗教改革成果和地方政治自治。"},{"label":"关键人物（可选）","value":"萨克森选侯、黑森方伯腓力等。"},{"label":"关键行动/事件","value":"协调新教军事和外交行动，与法国、丹麦等寻求外部支持；最终被查理五世击败。"},{"label":"为什么重要","value":"它说明宗教改革能延续，不只是因为信仰传播，也因为有诸侯、城市、军队和财政组织保护。"},{"label":"争议/局限","value":"同盟内部成员利益不一，宗教原则与政治自治诉求交织，难以形成长期统一战略。"},{"label":"出处","value":"Britannica, Schmalkaldic League；German History in Documents and Images, Schmalkaldic League materials。"}],"relationItems":["← 前因：沃姆斯帝国议会","→ 后果：施马尔卡尔登战争","↔ 相关：欧洲宗教改革","↔ 相关：宗教改革《奥格斯堡和约》","↔ 同时期参考：法国胡格诺派政治组织"],"relations":[{"text":"← 前因：沃姆斯帝国议会","id":"extra303"},{"text":"→ 后果：施马尔卡尔登战争","id":"extra327"},{"text":"↔ 相关：欧洲宗教改革","id":"extra301"},{"text":"↔ 相关：宗教改革《奥格斯堡和约》","id":"extra305"}],"source":"history","id":"extra326"},{"title":"施马尔卡尔登战争","level":"B","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1546—1547年","place":"神圣罗马帝国","summary":"施马尔卡尔登战争是查理五世压制新教诸侯联盟的战争，显示皇帝虽能取胜却难以恢复宗教统一。","fields":[{"label":"标题","value":"施马尔卡尔登战争"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1546—1547年"},{"label":"地点","value":"神圣罗马帝国"},{"label":"主要国家","value":"神圣罗马帝国；德意志新教诸邦；哈布斯堡君主国"},{"label":"一句话概括","value":"施马尔卡尔登战争是查理五世压制新教诸侯联盟的战争，显示皇帝虽能取胜却难以恢复宗教统一。"},{"label":"参与者","value":"皇帝查理五世、施马尔卡尔登同盟、萨克森和黑森等新教力量、帝国诸侯。"},{"label":"发生了什么","value":"查理五世在国际压力暂缓后，出兵打击施马尔卡尔登同盟。1547年米尔贝格战役中皇帝军队获胜，新教同盟被击败，主要领袖被俘。然而皇帝试图以《奥格斯堡临时协定》重建宗教秩序，引发新的抵抗。"},{"label":"为什么重要","value":"它说明神圣罗马帝国宗教问题不能通过一次军事胜利解决，诸侯政治和地方信仰已经形成难以逆转的力量。"},{"label":"前因","value":"施马尔卡尔登同盟形成后，新教诸侯拥有共同防卫机制，帝国宗教分裂从教义争论变成武装政治问题；皇帝查理五世在对外压力缓和后，试图重新恢复帝国和天主教会权威。"},{"label":"后果","value":"皇帝虽然击败同盟主力，但军事胜利未能重建统一宗教秩序；1552年诸侯反击迫使查理五世妥协，帝国最终通过1555年宗教改革《奥格斯堡和约》承认路德宗诸侯的合法地位。"},{"label":"出处","value":"Britannica, Schmalkaldic War；German History in Documents and Images, Charles V and the Protestants materials。"}],"relationItems":["← 前因：施马尔卡尔登同盟","→ 后果：宗教改革《奥格斯堡和约》","↔ 相关：欧洲宗教改革","↔ 相关：哈布斯堡君主国","↔ 同时期参考：法国宗教战争"],"relations":[{"text":"← 前因：施马尔卡尔登同盟","id":"extra326"},{"text":"→ 后果：宗教改革《奥格斯堡和约》","id":"extra305"},{"text":"↔ 相关：欧洲宗教改革","id":"extra301"},{"text":"↔ 相关：哈布斯堡君主国","id":"extra309"},{"text":"↔ 同时期参考：法国宗教战争","id":"extra900"}],"source":"history","id":"extra327"},{"title":"天主教特伦托会议","level":"A","type":"制度/文本卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1545—1563年","place":"特伦托","summary":"特伦托会议明确天主教教义并推动教会改革，是欧洲天主教改革和反宗教改革的核心会议。","fields":[{"label":"标题","value":"天主教特伦托会议"},{"label":"分级","value":"A"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1545—1563年"},{"label":"地点","value":"特伦托"},{"label":"主要国家","value":"教皇国；神圣罗马帝国；欧洲天主教地区"},{"label":"一句话概括","value":"特伦托会议明确天主教教义并推动教会改革，是欧洲天主教改革和反宗教改革的核心会议。"},{"label":"制定方/签署方","value":"罗马教廷、天主教主教和神学家，在欧洲天主教君主政治背景下召开。"},{"label":"主要内容","value":"会议重申传统教义、圣礼和教会权威，回应新教批判，同时要求改革神职教育、纪律和教会行政。"},{"label":"它试图解决什么问题","value":"宗教改革挑战天主教权威，教会既需要反驳新教教义，也必须处理神职腐败、教育不足和纪律松弛等内部问题。"},{"label":"为什么重要","value":"它重塑了近代天主教世界，使天主教会更制度化、教育化和纪律化，并深刻影响欧洲宗教战争和全球传教。"},{"label":"争议/局限","value":"会议巩固天主教内部改革，却没有弥合新教和天主教分裂，反而使欧洲教派边界更清晰。"},{"label":"造成的影响","value":"神学院制度、主教责任、教义教育和耶稣会等改革力量增强，欧洲进入更长期的教派竞争时代。"},{"label":"出处","value":"Britannica, Council of Trent；Catholic Encyclopedia / Vatican historical materials on Council of Trent。"}],"relationItems":["← 前因：欧洲宗教改革","→ 后果：欧洲天主教改革","↔ 相关：欧洲耶稣会教育网络","↔ 相关：宗教改革《奥格斯堡和约》","↔ 同时期参考：西班牙欧洲天主教改革"],"relations":[{"text":"← 前因：欧洲宗教改革","id":"extra301"},{"text":"→ 后果：欧洲天主教改革","id":"extra329"},{"text":"↔ 相关：欧洲耶稣会教育网络","id":"extra330"},{"text":"↔ 相关：宗教改革《奥格斯堡和约》","id":"extra305"}],"source":"history","id":"extra328"},{"title":"欧洲天主教改革","level":"A","type":"概念/思潮卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"16世纪中期—17世纪","place":"欧洲天主教地区；神圣罗马帝国天主教邦国；意大利、西班牙、法国等地","summary":"欧洲天主教改革既是对新教挑战的回应，也是天主教内部纪律、教育和传教体系的重组。","fields":[{"label":"标题","value":"欧洲天主教改革"},{"label":"分级","value":"A"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"16世纪中期—17世纪"},{"label":"地点","value":"欧洲天主教地区；神圣罗马帝国天主教邦国；意大利、西班牙、法国等地"},{"label":"主要国家","value":"教皇国；西班牙；奥地利；德意志天主教诸邦；法国"},{"label":"一句话概括","value":"欧洲天主教改革既是对新教挑战的回应，也是天主教内部纪律、教育和传教体系的重组。"},{"label":"核心主张/思路","value":"通过明确教义、整顿神职、强化教育、推动传教和重塑宗教艺术，恢复并扩大天主教权威。"},{"label":"提出者/代表人物（可选）","value":"教皇保罗三世、特伦托会议主教、耶稣会、加尔默罗改革者等。"},{"label":"它从何而来","value":"中世纪晚期教会问题和宗教改革冲击迫使天主教会改革内部制度，同时与新教展开教派竞争。"},{"label":"典型表现","value":"神学院、耶稣会学校、巴洛克宗教艺术、忏悔纪律、传教网络和天主教诸侯再天主教化政策。"},{"label":"为什么重要","value":"它把欧洲宗教改革放入双向过程：新教改革和欧洲天主教改革共同塑造近代欧洲宗教地图。"},{"label":"争议/局限","value":"改革加强教育和纪律，也强化宗教审查、迫害和教派对抗，宗教宽容并非其核心目标。"},{"label":"出处","value":"Britannica, Counter-Reformation；Britannica, Catholic Reformation；German History in Documents and Images, Confessionalization materials。"}],"relationItems":["← 前因：天主教特伦托会议","→ 后果：三十年战争","↔ 相关：欧洲耶稣会教育网络","↔ 相关：哈布斯堡君主国","↔ 同时期参考：欧洲巴洛克艺术"],"relations":[{"text":"← 前因：天主教特伦托会议","id":"extra328"},{"text":"→ 后果：三十年战争","id":"extra307"},{"text":"↔ 相关：欧洲耶稣会教育网络","id":"extra330"},{"text":"↔ 相关：哈布斯堡君主国","id":"extra309"}],"source":"history","id":"extra329"},{"title":"欧洲耶稣会教育网络","level":"B","type":"组织/机构卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1540年耶稣会获批后，16—17世纪快速扩张","place":"欧洲及全球传教地区；神圣罗马帝国天主教邦国","summary":"欧洲耶稣会教育网络把欧洲天主教改革、精英教育和全球传教连接起来，是早期近代知识与宗教竞争的重要机构。","fields":[{"label":"标题","value":"欧洲耶稣会教育网络"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1540年耶稣会获批后，16—17世纪快速扩张"},{"label":"地点","value":"欧洲及全球传教地区；神圣罗马帝国天主教邦国"},{"label":"主要国家","value":"教皇国；西班牙；奥地利；德意志天主教诸邦；全球多地"},{"label":"一句话概括","value":"欧洲耶稣会教育网络把欧洲天主教改革、精英教育和全球传教连接起来，是早期近代知识与宗教竞争的重要机构。"},{"label":"性质/类型","value":"天主教修会教育和传教网络。"},{"label":"成立/解散时间","value":"耶稣会1540年获教皇批准；16—17世纪学校网络迅速扩大。"},{"label":"核心目标/宗旨","value":"通过学院、神学训练、古典教育和传教活动，培养天主教精英并回应新教挑战。"},{"label":"关键人物（可选）","value":"依纳爵·罗耀拉、彼得·卡尼修斯等。"},{"label":"关键行动/事件","value":"在欧洲建立学校和大学学院，在亚洲、美洲等地开展传教；在神圣罗马帝国天主教地区推动再天主教化和教育改革。"},{"label":"为什么重要","value":"它说明宗教竞争也是教育竞争。学校、修辞、语言和知识训练成为教派边界形成的重要工具。"},{"label":"争议/局限","value":"耶稣会教育质量高，但也被新教和启蒙批评者视为教会权力和政治影响的工具。"},{"label":"出处","value":"Britannica, Jesuit；Britannica, Counter-Reformation；Jesuit historical education materials。"}],"relationItems":["← 前因：欧洲天主教改革","→ 后果：德意志帝国反耶稣会法","↔ 相关：天主教特伦托会议","↔ 相关：欧洲宗教改革","↔ 同时期参考：加尔文学院传统"],"relations":[{"text":"← 前因：欧洲天主教改革","id":"extra329"},{"text":"→ 后果：德意志帝国反耶稣会法","id":"extra751"},{"text":"↔ 相关：天主教特伦托会议","id":"extra328"},{"text":"↔ 相关：欧洲宗教改革","id":"extra301"}],"source":"history","id":"extra330"},{"title":"三十年战争白山战役","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1620年11月8日","place":"布拉格附近白山","summary":"三十年战争白山战役击败波希米亚新教起义，使哈布斯堡重掌波希米亚，并推动三十年战争继续扩大。","fields":[{"label":"标题","value":"三十年战争白山战役"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1620年11月8日"},{"label":"地点","value":"布拉格附近白山"},{"label":"主要国家","value":"波希米亚；哈布斯堡君主国；神圣罗马帝国"},{"label":"一句话概括","value":"三十年战争白山战役击败波希米亚新教起义，使哈布斯堡重掌波希米亚，并推动三十年战争继续扩大。"},{"label":"参与者","value":"波希米亚新教军队、哈布斯堡皇帝斐迪南二世、德意志天主教联盟军队、巴伐利亚力量。"},{"label":"发生了什么","value":"布拉格掷出窗外事件后，波希米亚贵族反抗哈布斯堡统治并选出新国王。1620年，皇帝和德意志天主教联盟军队在白山附近击败波希米亚新教军，起义迅速瓦解。"},{"label":"为什么重要","value":"它是三十年战争早期关键转折，决定波希米亚重新被哈布斯堡控制，也使战争从地方起义演变为更广泛的帝国和欧洲冲突。"},{"label":"前因","value":"波希米亚贵族既反对哈布斯堡王朝强化中央控制，也担心天主教复兴削弱新教权利；1618年布拉格掷出窗外事件后，地方等级反抗迅速升级为围绕王位和宗教秩序的战争。"},{"label":"后果","value":"波希米亚新教贵族遭清洗，天主教化和哈布斯堡控制加强；流亡、没收和政治镇压改变波希米亚社会结构。"},{"label":"出处","value":"Britannica, Battle of White Mountain；Britannica, Thirty Years’ War。"}],"relationItems":["← 前因：布拉格掷出窗外事件","→ 后果：三十年战争","↔ 相关：哈布斯堡君主国","↔ 相关：欧洲天主教改革","↔ 同时期参考：荷兰独立战争"],"relations":[{"text":"← 前因：布拉格掷出窗外事件","id":"extra306"},{"text":"→ 后果：三十年战争","id":"extra307"},{"text":"↔ 相关：哈布斯堡君主国","id":"extra309"},{"text":"↔ 相关：欧洲天主教改革","id":"extra329"},{"text":"↔ 同时期参考：荷兰独立战争","id":"extra873"}],"source":"history","id":"extra331"},{"title":"阿尔布雷希特·冯·华伦斯坦","level":"B","type":"人物卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1583—1634年","place":"波希米亚、神圣罗马帝国各战场","summary":"华伦斯坦是三十年战争中最重要的军事承包人与统帅之一，体现雇佣军、财政和王朝战争的结合。","fields":[{"label":"标题","value":"阿尔布雷希特·冯·华伦斯坦"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1583—1634年"},{"label":"地点","value":"波希米亚、神圣罗马帝国各战场"},{"label":"主要国家","value":"神圣罗马帝国；哈布斯堡君主国"},{"label":"一句话概括","value":"华伦斯坦是三十年战争中最重要的军事承包人与统帅之一，体现雇佣军、财政和王朝战争的结合。"},{"label":"生卒年/活跃年代","value":"1583—1634年；三十年战争中活跃。"},{"label":"身份/职务","value":"波希米亚贵族、帝国军统帅、军事企业家。"},{"label":"关键贡献/作为","value":"为皇帝组建大规模军队，以征发、军费和占领地资源维持战争；在战争中多次指挥帝国军队。"},{"label":"核心主张/立场","value":"以个人权力、军事效率和王朝服务为核心，政治立场复杂，后期与皇帝关系紧张。"},{"label":"为什么重要","value":"他说明三十年战争不是现代国家军队之间的简单战争，而是依赖军事承包、掠夺财政和个人统帅网络。"},{"label":"争议/评价","value":"华伦斯坦既被视为军事天才，也被认为权力过大、野心危险；1634年被皇帝方面谋杀，成为欧洲戏剧和历史记忆中的复杂人物。"},{"label":"关联事件（可选）","value":"三十年战争、三十年战争马格德堡劫掠、三十年战争布赖滕费尔德战役。"},{"label":"出处","value":"Britannica, Albrecht von Wallenstein；Britannica, Thirty Years’ War。"}],"relationItems":["← 前因：三十年战争","→ 后果：威斯特伐利亚和约","↔ 相关：哈布斯堡君主国","↔ 相关：瑞典介入三十年战争","↔ 同时期参考：早期近代军事革命"],"relations":[{"text":"← 前因：三十年战争","id":"extra307"},{"text":"→ 后果：威斯特伐利亚和约","id":"extra308"},{"text":"↔ 相关：哈布斯堡君主国","id":"extra309"},{"text":"↔ 相关：瑞典介入三十年战争","id":"extra334"},{"text":"↔ 同时期参考：早期近代军事革命","id":"extra876"}],"source":"history","id":"extra332"},{"title":"三十年战争马格德堡劫掠","level":"B","type":"事件卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1631年5月","place":"马格德堡","summary":"三十年战争马格德堡劫掠是三十年战争中最恐怖的城市毁灭事件之一，成为早期近代战争暴力的象征。","fields":[{"label":"标题","value":"三十年战争马格德堡劫掠"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1631年5月"},{"label":"地点","value":"马格德堡"},{"label":"主要国家","value":"神圣罗马帝国；德意志地区"},{"label":"一句话概括","value":"三十年战争马格德堡劫掠是三十年战争中最恐怖的城市毁灭事件之一，成为早期近代战争暴力的象征。"},{"label":"参与者","value":"帝国和德意志天主教联盟军队、马格德堡守军和市民、蒂利伯爵等。"},{"label":"发生了什么","value":"1631年，帝国军和德意志天主教联盟军围攻支持新教阵营的马格德堡。攻城后城市遭到大规模屠杀、纵火和劫掠，居民大量死亡，城市几乎被毁。"},{"label":"为什么重要","value":"它让三十年战争的破坏性有了强烈象征画面，也在新教宣传中成为天主教暴力和战争灾难的代表事件。"},{"label":"前因","value":"三十年战争进入瑞典介入前后，皇帝军希望巩固北德控制并压制新教城市抵抗；马格德堡拒绝接受皇帝安排，又具有象征性的路德宗城市地位，因此成为军事进攻和政治恐吓目标。"},{"label":"后果","value":"马格德堡的毁灭加深新教地区恐惧，推动更多力量支持瑞典和反皇帝阵营，也强化三十年战争“总体灾难”的历史记忆。"},{"label":"出处","value":"Britannica, Thirty Years’ War；German History in Documents and Images, Magdeburg and war violence materials。"}],"relationItems":["← 前因：三十年战争","→ 后果：瑞典介入三十年战争","↔ 相关：阿尔布雷希特·冯·华伦斯坦","↔ 相关：三十年战争布赖滕费尔德战役","↔ 同时期参考：英国内战城市围攻"],"relations":[{"text":"← 前因：三十年战争","id":"extra307"},{"text":"→ 后果：瑞典介入三十年战争","id":"extra334"},{"text":"↔ 相关：阿尔布雷希特·冯·华伦斯坦","id":"extra332"},{"text":"↔ 相关：三十年战争布赖滕费尔德战役","id":"extra335"}],"source":"history","id":"extra333"},{"title":"瑞典介入三十年战争","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1630年起","place":"波罗的海沿岸、神圣罗马帝国北部和中部","summary":"瑞典在古斯塔夫二世·阿道夫领导下介入三十年战争，把波罗的海战略、宗教政治和欧洲均势连在一起。","fields":[{"label":"标题","value":"瑞典介入三十年战争"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1630年起"},{"label":"地点","value":"波罗的海沿岸、神圣罗马帝国北部和中部"},{"label":"主要国家","value":"瑞典；神圣罗马帝国；法国；哈布斯堡君主国"},{"label":"一句话概括","value":"瑞典在古斯塔夫二世·阿道夫领导下介入三十年战争，把波罗的海战略、宗教政治和欧洲均势连在一起。"},{"label":"参与者","value":"瑞典国王古斯塔夫二世·阿道夫、瑞典军队、德意志新教诸侯、法国外交支持者、皇帝军队。"},{"label":"发生了什么","value":"1630年，瑞典军队登陆德意志北部，宣布保护新教和波罗的海利益。瑞典通过现代化军队、纪律和火力战术改变战局，并在法国财政支持下成为反哈布斯堡阵营核心力量。"},{"label":"为什么重要","value":"它说明三十年战争已成为国际战争，德意志地区是欧洲列强争夺安全和影响力的战场。"},{"label":"前因","value":"皇帝和德意志天主教联盟在帝国北部的扩张威胁瑞典在波罗的海的安全和贸易利益，同时德意志新教阵营在连续失败后缺乏足够军事支撑；宗教保护、战略安全和法国外交资助共同推动瑞典出兵。"},{"label":"后果","value":"瑞典在布赖滕费尔德取得重大胜利，哈布斯堡优势被打破；瑞典也获得战后帝国内地位和波罗的海影响。"},{"label":"出处","value":"Britannica, Gustavus Adolphus；Britannica, Thirty Years’ War；Swedish historical materials on Gustavus Adolphus。"}],"relationItems":["← 前因：三十年战争马格德堡劫掠","→ 后果：三十年战争布赖滕费尔德战役","↔ 相关：三十年战争","↔ 相关：威斯特伐利亚和约","↔ 同时期参考：法国反哈布斯堡外交"],"relations":[{"text":"← 前因：三十年战争马格德堡劫掠","id":"extra333"},{"text":"→ 后果：三十年战争布赖滕费尔德战役","id":"extra335"},{"text":"↔ 相关：三十年战争","id":"extra307"},{"text":"↔ 相关：威斯特伐利亚和约","id":"extra308"}],"source":"history","id":"extra334"},{"title":"三十年战争布赖滕费尔德战役","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1631年9月17日","place":"莱比锡附近布赖滕费尔德","summary":"三十年战争布赖滕费尔德战役中瑞典和萨克森击败皇帝军，打破哈布斯堡在三十年战争中的优势。","fields":[{"label":"标题","value":"三十年战争布赖滕费尔德战役"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1631年9月17日"},{"label":"地点","value":"莱比锡附近布赖滕费尔德"},{"label":"主要国家","value":"瑞典；神圣罗马帝国；德意志诸邦"},{"label":"一句话概括","value":"三十年战争布赖滕费尔德战役中瑞典和萨克森击败皇帝军，打破哈布斯堡在三十年战争中的优势。"},{"label":"参与者","value":"古斯塔夫二世·阿道夫、瑞典军队、萨克森军队、蒂利伯爵和帝国/德意志天主教联盟军队。"},{"label":"发生了什么","value":"瑞典军与萨克森盟军在莱比锡附近迎战帝国军。萨克森军一度崩溃，但瑞典军依靠机动、火力和纪律稳住阵线并反击，最终取得决定性胜利。"},{"label":"为什么重要","value":"这是三十年战争军事格局的重要转折，证明瑞典军队可以击败皇帝军，也使更多德意志新教诸侯转向瑞典阵营。"},{"label":"前因","value":"三十年战争马格德堡劫掠在新教地区造成强烈恐惧，也迫使更多德意志诸侯重新评估皇帝军威胁；瑞典介入后需要一场决定性胜利来证明其军事能力，并确立自己作为新教保护者和欧洲强权的地位。"},{"label":"后果","value":"皇帝军此前形成的优势被打破，瑞典得以向德意志中南部推进，并吸引更多诸侯重新站队；这场胜利使三十年战争从帝国内部宗教冲突进一步转化为欧洲列强深度介入的国际战争。"},{"label":"出处","value":"Britannica, Battle of Breitenfeld；Britannica, Gustavus Adolphus。"}],"relationItems":["← 前因：瑞典介入三十年战争","→ 后果：威斯特伐利亚和约","↔ 相关：三十年战争","↔ 相关：三十年战争马格德堡劫掠","↔ 同时期参考：早期近代军事革命"],"relations":[{"text":"← 前因：瑞典介入三十年战争","id":"extra334"},{"text":"→ 后果：威斯特伐利亚和约","id":"extra308"},{"text":"↔ 相关：三十年战争","id":"extra307"},{"text":"↔ 相关：三十年战争马格德堡劫掠","id":"extra333"},{"text":"↔ 同时期参考：早期近代军事革命","id":"extra876"}],"source":"history","id":"extra335"},{"title":"近代早期欧洲猎巫","level":"B","type":"概念/思潮卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"约15世纪后期—17世纪，德意志地区16—17世纪尤为严重","place":"欧洲多地，神圣罗马帝国部分地区尤其突出","summary":"近代早期猎巫把宗教恐惧、司法程序、地方冲突和性别偏见结合起来，德意志地区是最严重区域之一。","fields":[{"label":"标题","value":"近代早期欧洲猎巫"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"约15世纪后期—17世纪，德意志地区16—17世纪尤为严重"},{"label":"地点","value":"欧洲多地，神圣罗马帝国部分地区尤其突出"},{"label":"主要国家","value":"德意志地区；法国；瑞士；苏格兰；北欧等"},{"label":"一句话概括","value":"近代早期猎巫把宗教恐惧、司法程序、地方冲突和性别偏见结合起来，德意志地区是最严重区域之一。"},{"label":"核心主张/思路","value":"社会把疾病、灾荒、死亡和共同体危机解释为巫术与魔鬼同盟，并通过审讯、酷刑和处决寻找“罪魁”。"},{"label":"提出者/代表人物（可选）","value":"不是单一思想家提出，而是神学家、法官、地方当局、告发者和恐慌共同作用。"},{"label":"它从何而来","value":"宗教冲突、司法酷刑制度、小冰期气候压力、地方社会矛盾和恶魔学文本共同推动猎巫高潮。"},{"label":"典型表现","value":"告发、酷刑供认、连环牵连、女性被告比例高、地方领地大规模审判和公开处决。"},{"label":"为什么重要","value":"它提醒用户早期近代并非单线“理性进步”，国家司法和宗教恐惧也能结合成大规模迫害。"},{"label":"争议/局限","value":"猎巫不能简单解释为“中世纪迷信”，其高潮反而发生在早期近代，与司法制度、国家权力和教派社会有关。"},{"label":"出处","value":"Britannica, witchcraft and witch hunts；Oxford Research Encyclopedia, Witch Trials in the Holy Roman Empire；German History in Documents and Images witchcraft materials。"}],"relationItems":["← 前因：欧洲天主教改革","→ 后果：德意志启蒙运动","↔ 相关：三十年战争","↔ 相关：神圣罗马帝国","↔ 同时期参考：塞勒姆审巫案"],"relations":[{"text":"← 前因：欧洲天主教改革","id":"extra329"},{"text":"→ 后果：德意志启蒙运动","id":"extra317"},{"text":"↔ 相关：三十年战争","id":"extra307"},{"text":"↔ 相关：神圣罗马帝国","id":"extra300"}],"source":"history","id":"extra336"},{"title":"德国敬虔主义","level":"B","type":"概念/思潮卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"17世纪后期—18世纪","place":"德意志新教地区，尤其哈雷、符腾堡等地","summary":"敬虔主义强调个人虔敬、圣经阅读和实践慈善，重塑德意志新教教育、社会服务和日常宗教生活。","fields":[{"label":"标题","value":"德国敬虔主义"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"17世纪后期—18世纪"},{"label":"地点","value":"德意志新教地区，尤其哈雷、符腾堡等地"},{"label":"主要国家","value":"德意志地区"},{"label":"一句话概括","value":"敬虔主义强调个人虔敬、圣经阅读和实践慈善，重塑德意志新教教育、社会服务和日常宗教生活。"},{"label":"核心主张/思路","value":"真正信仰不只是接受正统教义，也应表现为内心更新、圣经小组、道德生活、教育和慈善实践。"},{"label":"提出者/代表人物（可选）","value":"菲利普·雅各布·施本纳、奥古斯特·赫尔曼·弗兰克等。"},{"label":"它从何而来","value":"三十年战争后的宗教疲惫、路德宗正统化和新教社会内部改革需求，使许多人寻求更生活化和实践化的信仰。"},{"label":"典型表现","value":"家庭和小组读经，学校、孤儿院、传教、慈善机构和个人灵修文字。"},{"label":"为什么重要","value":"它把宗教史和社会史连接起来，影响德意志教育、福利、传教和后来的市民道德文化。"},{"label":"争议/局限","value":"敬虔主义强化内心信仰和纪律生活，也可能带来道德监督和对世俗娱乐的压抑。"},{"label":"出处","value":"Britannica, Pietism；German History in Documents and Images, Pietism materials。"}],"relationItems":["← 前因：三十年战争","→ 后果：哈雷孤儿院与敬虔主义教育","↔ 相关：欧洲宗教改革","↔ 相关：德意志启蒙运动","↔ 同时期参考：英国卫理宗"],"relations":[{"text":"← 前因：三十年战争","id":"extra307"},{"text":"→ 后果：哈雷孤儿院与敬虔主义教育","id":"extra338"},{"text":"↔ 相关：欧洲宗教改革","id":"extra301"},{"text":"↔ 相关：德意志启蒙运动","id":"extra317"}],"source":"history","id":"extra337"},{"title":"哈雷孤儿院与敬虔主义教育","level":"C","type":"组织/机构卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"1690年代起","place":"哈雷","summary":"哈雷孤儿院把敬虔主义、学校教育、印刷和社会救济结合起来，是早期近代新教社会事业的重要样板。","fields":[{"label":"标题","value":"哈雷孤儿院与敬虔主义教育"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1690年代起"},{"label":"地点","value":"哈雷"},{"label":"主要国家","value":"德意志地区；普鲁士"},{"label":"一句话概括","value":"哈雷孤儿院把敬虔主义、学校教育、印刷和社会救济结合起来，是早期近代新教社会事业的重要样板。"},{"label":"性质/类型","value":"孤儿院、学校、印刷和慈善教育机构综合体。"},{"label":"成立/解散时间","value":"1690年代由奥古斯特·赫尔曼·弗兰克推动建立，后来扩展为哈雷基金会体系。"},{"label":"核心目标/宗旨","value":"通过教育、纪律、宗教训练和实际劳动帮助贫困儿童，同时培养教师、传教士和新教社会服务人才。"},{"label":"关键人物（可选）","value":"奥古斯特·赫尔曼·弗兰克。"},{"label":"关键行动/事件","value":"建立学校、孤儿院、出版社和药房，形成以教育和慈善为核心的敬虔主义机构网络。"},{"label":"为什么重要","value":"它说明早期近代社会福利并非只由国家提供，宗教团体和教育机构也是现代社会服务的重要前身。"},{"label":"争议/局限","value":"机构救济带有强烈宗教纪律和道德训练色彩，贫困儿童的生活被严格规训。"},{"label":"出处","value":"Francke Foundations, History；Britannica, August Hermann Francke；German Pietism historical materials。"}],"relationItems":["← 前因：德国敬虔主义","→ 后果：普鲁士教育改革传统","↔ 相关：德意志启蒙运动","↔ 相关：德国幼儿园运动","↔ 同时期参考：英国慈善学校运动"],"relations":[{"text":"← 前因：德国敬虔主义","id":"extra337"},{"text":"↔ 相关：德意志启蒙运动","id":"extra317"},{"text":"↔ 相关：德国幼儿园运动","id":"extra516"}],"source":"history","id":"extra338"},{"title":"约翰·塞巴斯蒂安·巴赫","level":"A","type":"人物卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1685—1750年","place":"艾森纳赫、魏玛、科滕、莱比锡等德意志城市","summary":"巴赫是巴洛克音乐集大成者，他的宗教音乐、键盘作品和复调技艺成为世界音乐史核心遗产。","fields":[{"label":"标题","value":"约翰·塞巴斯蒂安·巴赫"},{"label":"分级","value":"A"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1685—1750年"},{"label":"地点","value":"艾森纳赫、魏玛、科滕、莱比锡等德意志城市"},{"label":"主要国家","value":"德意志地区"},{"label":"一句话概括","value":"巴赫是巴洛克音乐集大成者，他的宗教音乐、键盘作品和复调技艺成为世界音乐史核心遗产。"},{"label":"生卒年/活跃年代","value":"1685—1750年，活跃于德意志中部多个宫廷和教会音乐岗位。"},{"label":"身份/职务","value":"作曲家、管风琴家、乐长、教会音乐家。"},{"label":"关键贡献/作为","value":"创作《马太受难曲》《勃兰登堡协奏曲》《平均律键盘曲集》等大量作品，发展复调、和声与宗教音乐表达。"},{"label":"核心主张/立场","value":"巴赫不是政治思想家，但其音乐深植路德宗礼拜、宫廷赞助、城市学校和手工业式音乐职业传统。"},{"label":"为什么重要","value":"他把德意志宗教文化、城市教会制度和欧洲巴洛克音乐推向高峰，是世界音乐史坐标级人物。"},{"label":"争议/评价","value":"巴赫生前更被视为演奏家和技艺大师，19世纪以后才被重新塑造为“伟大作曲家”经典。"},{"label":"关联事件（可选）","value":"欧洲宗教改革、德国敬虔主义、德意志启蒙运动。"},{"label":"出处","value":"Britannica, Johann Sebastian Bach；Bach Archive Leipzig, Bach biography。"}],"relationItems":["← 前因：欧洲宗教改革","→ 后果：德意志音乐传统","↔ 相关：德国敬虔主义","↔ 相关：路德德语圣经翻译","↔ 同时期参考：亨德尔"],"relations":[{"text":"← 前因：欧洲宗教改革","id":"extra301"},{"text":"↔ 相关：德国敬虔主义","id":"extra337"},{"text":"↔ 相关：路德德语圣经翻译","id":"extra304"}],"source":"history","id":"extra339"},{"title":"普鲁士开明专制","level":"B","type":"概念/思潮卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"18世纪中后期，腓特烈大王时期最具代表性","place":"普鲁士","summary":"普鲁士开明专制把启蒙语言、行政理性和君主权力结合起来，形成“改革但不民主”的国家治理模式。","fields":[{"label":"标题","value":"普鲁士开明专制"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"18世纪中后期，腓特烈大王时期最具代表性"},{"label":"地点","value":"普鲁士"},{"label":"主要国家","value":"普鲁士"},{"label":"一句话概括","value":"普鲁士开明专制把启蒙语言、行政理性和君主权力结合起来，形成“改革但不民主”的国家治理模式。"},{"label":"核心主张/思路","value":"君主以理性、效率和国家利益为名推动法律、宗教宽容、农业和行政改革，但政治权力仍集中在王权和官僚体系中。"},{"label":"提出者/代表人物（可选）","value":"腓特烈大王和普鲁士改革官僚。"},{"label":"它从何而来","value":"欧洲启蒙运动提供理性改革语言，普鲁士军事财政国家需要更有效的行政、人口和经济管理。"},{"label":"典型表现","value":"宗教相对宽容，官僚行政加强，法律编纂推进，农业和移民政策服务国家强盛。"},{"label":"为什么重要","value":"它解释德国现代化中常见的张力：国家可以推动教育、法律和效率改革，但不必同时扩大民主参与。"},{"label":"争议/局限","value":"开明专制仍是专制，贵族特权和农民束缚并未根本消除，改革目标首先服务国家实力。"},{"label":"出处","value":"Britannica, enlightened despotism；Britannica, Frederick II；German History in Documents and Images, Prussian reform materials。"}],"relationItems":["← 前因：德意志启蒙运动","→ 后果：普鲁士施泰因-哈登贝格改革","↔ 相关：普鲁士腓特烈大王","↔ 相关：七年战争","↔ 同时期参考：约瑟夫二世改革"],"relations":[{"text":"← 前因：德意志启蒙运动","id":"extra317"},{"text":"→ 后果：普鲁士施泰因-哈登贝格改革","id":"extra522"},{"text":"↔ 相关：普鲁士腓特烈大王","id":"extra315"},{"text":"↔ 相关：七年战争","id":"extra316"},{"text":"↔ 同时期参考：约瑟夫二世改革","id":"extra318"}],"source":"history","id":"extra340"},{"title":"三次波兰瓜分","level":"A","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1772年、1793年、1795年","place":"波兰立陶宛联邦及东欧中欧边境地区","summary":"波兰三次瓜分使波兰立陶宛联邦从地图上消失，扩大普鲁士和奥地利领土，也重塑东欧权力格局。","fields":[{"label":"标题","value":"三次波兰瓜分"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1772年、1793年、1795年"},{"label":"地点","value":"波兰立陶宛联邦及东欧中欧边境地区"},{"label":"主要国家","value":"俄罗斯；普鲁士；奥地利；波兰立陶宛联邦"},{"label":"一句话概括","value":"波兰三次瓜分使波兰立陶宛联邦从地图上消失，扩大普鲁士和奥地利领土，也重塑东欧权力格局。"},{"label":"参与者","value":"俄罗斯帝国、普鲁士王国、哈布斯堡君主国、波兰立陶宛联邦政治精英和改革派。"},{"label":"发生了什么","value":"1772年、1793年和1795年，俄罗斯、普鲁士和奥地利分三次瓜分波兰立陶宛联邦领土。波兰内部改革和抵抗未能阻止周边列强干预，最终国家被完全吞并，直到一战后才恢复独立。"},{"label":"为什么重要","value":"这是世界史和东欧史重大节点，说明18世纪欧洲均势政治可以直接消灭一个大国。对普鲁士而言，瓜分显著扩大了东部领土和人口。"},{"label":"前因","value":"波兰立陶宛联邦的贵族共和国制度难以形成有效中央权力，俄罗斯对其内政影响不断上升；普鲁士和奥地利既担心俄罗斯单方面扩张，也希望通过领土补偿和均势安排获得实际收益。"},{"label":"后果","value":"波兰民族问题长期成为欧洲政治问题，普鲁士和奥地利获得大量波兰人口和土地，东欧民族主义和19世纪起义由此获得深层背景。"},{"label":"出处","value":"Britannica, Partitions of Poland；Encyclopaedia Britannica, Poland history。"}],"relationItems":["← 前因：七年战争","→ 后果：拿破仑时代波兰问题","↔ 相关：普鲁士王国成立","↔ 相关：哈布斯堡君主国","↔ 同时期参考：美国独立战争"],"relations":[{"text":"← 前因：七年战争","id":"extra316"},{"text":"↔ 相关：普鲁士王国成立","id":"extra312"},{"text":"↔ 相关：哈布斯堡君主国","id":"extra309"},{"text":"↔ 同时期参考：美国独立战争","id":"extra896"}],"source":"history","id":"extra341"},{"title":"魏玛古典主义","level":"B","type":"概念/思潮卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"约1780年代—1805年","place":"萨克森-魏玛-艾森纳赫公国，尤其魏玛","summary":"魏玛古典主义以歌德和席勒为核心，把审美教育、人文理想和小邦宫廷文化结合成德语文学高峰。","fields":[{"label":"标题","value":"魏玛古典主义"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"约1780年代—1805年"},{"label":"地点","value":"萨克森-魏玛-艾森纳赫公国，尤其魏玛"},{"label":"主要国家","value":"德意志地区"},{"label":"一句话概括","value":"魏玛古典主义以歌德和席勒为核心，把审美教育、人文理想和小邦宫廷文化结合成德语文学高峰。"},{"label":"核心主张/思路","value":"通过古典形式、审美教育和人的全面发展，回应法国大革命时代的政治暴力与现代社会分裂。"},{"label":"提出者/代表人物（可选）","value":"歌德、席勒、赫尔德、维兰等。"},{"label":"它从何而来","value":"德意志启蒙、狂飙突进、古典古代研究和法国大革命震动共同促成魏玛知识圈转向审美和人文秩序。"},{"label":"典型表现","value":"诗歌、戏剧、文学批评、古典古代理想、教育和美学讨论。"},{"label":"为什么重要","value":"它让德语文学获得世界经典地位，也说明德意志文化影响力常在政治统一之前已经形成。"},{"label":"争议/局限","value":"魏玛古典主义的人文理想具有高度精英化特征，对底层社会和殖民世界关注有限。"},{"label":"出处","value":"Britannica, German literature: Classicism and Romanticism；Klassik Stiftung Weimar, Weimar Classicism materials。"}],"relationItems":["← 前因：德意志启蒙运动","→ 后果：德意志浪漫主义","↔ 相关：歌德《浮士德》","↔ 相关：康德《纯粹理性批判》","↔ 同时期参考：法国古典主义传统"],"relations":[{"text":"← 前因：德意志启蒙运动","id":"extra317"},{"text":"→ 后果：德意志浪漫主义","id":"extra552"},{"text":"↔ 相关：歌德《浮士德》","id":"extra90"},{"text":"↔ 相关：康德《纯粹理性批判》","id":"extra89"}],"source":"history","id":"extra342"},{"title":"查理曼加冕为罗马皇帝","level":"A","type":"事件卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"800年12月25日","place":"罗马圣彼得大教堂","summary":"教皇为查理曼加冕，把法兰克王权、罗马帝国名号和西欧基督教秩序重新连接起来。","fields":[{"label":"标题","value":"查理曼加冕为罗马皇帝"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"800年12月25日"},{"label":"地点","value":"罗马圣彼得大教堂"},{"label":"主要国家","value":"法兰克王国；教皇国；意大利；德意志地区"},{"label":"一句话概括","value":"教皇为查理曼加冕，把法兰克王权、罗马帝国名号和西欧基督教秩序重新连接起来。"},{"label":"参与者","value":"查理曼、教皇利奥三世、法兰克贵族、罗马教会。"},{"label":"发生了什么","value":"800年圣诞节，教皇利奥三世在罗马为法兰克国王查理曼加冕为“罗马人的皇帝”。这不是简单的礼仪，而是把西欧基督教世界的最高世俗权威重新包装为罗马帝国继承者，同时把教皇的宗教合法性与法兰克军事保护结合起来。"},{"label":"为什么重要","value":"它为中世纪西欧“皇帝—教皇”双重权威格局奠定象征基础。后来的神圣罗马帝国、德意志王权和帝国观念，都必须回到这个加冕传统中寻找合法性。"},{"label":"前因","value":"西罗马帝国崩溃后，西欧长期缺少统一帝国称号；教皇需要强大保护者，查理曼则通过征服萨克森、伦巴第等地区成为西欧最强君主。"},{"label":"后果","value":"皇帝称号成为法兰克和后来德意志统治者争夺的政治资源，也埋下教皇是否有权赋予或限制皇帝权威的长期争议。"},{"label":"出处","value":"Britannica, Charlemagne；Britannica, Holy Roman Empire。"}],"relationItems":["→ 后果：加洛林帝国《凡尔登条约》","↔ 相关：神圣罗马帝国","↔ 相关：中世纪教会格里高利改革","↔ 同时期参考：拜占庭帝国"],"relations":[{"text":"→ 后果：加洛林帝国《凡尔登条约》","id":"extra344"},{"text":"↔ 相关：神圣罗马帝国","id":"extra300"},{"text":"↔ 相关：中世纪教会格里高利改革","id":"extra350"},{"text":"↔ 同时期参考：拜占庭帝国","id":"extra888"}],"source":"history","id":"extra343"},{"title":"加洛林帝国《凡尔登条约》","level":"A","type":"制度/文本卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"843年8月","place":"凡尔登","summary":"加洛林帝国《凡尔登条约》把查理曼帝国分给三位继承人，预示西欧法兰西、德意志和中间地带的分化。","fields":[{"label":"标题","value":"加洛林帝国《凡尔登条约》"},{"label":"分级","value":"A"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"843年8月"},{"label":"地点","value":"凡尔登"},{"label":"主要国家","value":"法兰克王国；法国；德意志地区；意大利"},{"label":"一句话概括","value":"加洛林帝国《凡尔登条约》把查理曼帝国分给三位继承人，预示西欧法兰西、德意志和中间地带的分化。"},{"label":"制定方/签署方","value":"洛泰尔一世、日耳曼人路易、秃头查理。"},{"label":"主要内容","value":"条约把加洛林帝国分为三部分：洛泰尔保有皇帝称号和中部王国，日耳曼人路易获得莱茵河以东的东法兰克，秃头查理获得西法兰克。"},{"label":"它试图解决什么问题","value":"它试图结束路易一世死后其子辈之间的继承战争，把加洛林帝国从内战状态转为可执行的领土分割。"},{"label":"为什么重要","value":"它是西欧政治地图形成的关键节点。东法兰克后来发展为德意志王国和神圣罗马帝国，西法兰克则成为法国王国的基础。"},{"label":"争议/局限","value":"条约没有创造现代民族国家，也没有立即形成清晰国界；中部王国的破碎性反而长期制造洛林、勃艮第、意大利等地区争夺。"},{"label":"造成的影响","value":"加洛林统一帝国走向瓦解，东西法兰克的政治路径逐渐分开，中欧和西欧的边界问题由此获得长期结构。"},{"label":"出处","value":"Britannica, Treaty of Verdun。"}],"relationItems":["← 前因：查理曼加冕为罗马皇帝","→ 后果：东法兰克王国","↔ 相关：神圣罗马帝国","↔ 同时期参考：加洛林帝国"],"relations":[{"text":"← 前因：查理曼加冕为罗马皇帝","id":"extra343"},{"text":"→ 后果：东法兰克王国","id":"extra345"},{"text":"↔ 相关：神圣罗马帝国","id":"extra300"},{"text":"↔ 同时期参考：加洛林帝国","id":"extra897"}],"source":"history","id":"extra344"},{"title":"东法兰克王国","level":"A","type":"组织/机构卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"843—962年","place":"莱茵河以东的法兰克世界，包括萨克森、法兰肯、巴伐利亚、士瓦本等地区","summary":"东法兰克王国是德意志王国和神圣罗马帝国的前身，把莱茵以东诸公国纳入同一王权框架。","fields":[{"label":"标题","value":"东法兰克王国"},{"label":"分级","value":"A"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"843—962年"},{"label":"地点","value":"莱茵河以东的法兰克世界，包括萨克森、法兰肯、巴伐利亚、士瓦本等地区"},{"label":"主要国家","value":"德意志地区；法兰克王国"},{"label":"一句话概括","value":"东法兰克王国是德意志王国和神圣罗马帝国的前身，把莱茵以东诸公国纳入同一王权框架。"},{"label":"性质/类型","value":"加洛林帝国分裂后形成的东部王国。"},{"label":"成立/解散时间","value":"843年加洛林帝国《凡尔登条约》后形成，10世纪在奥托王朝统治下转入神圣罗马帝国传统。"},{"label":"核心目标/宗旨","value":"维持莱茵河以东诸公国的王权秩序，防御马扎尔人、斯拉夫人和西法兰克压力，并争取帝国称号。"},{"label":"关键人物（可选）","value":"日耳曼人路易、康拉德一世、亨利一世、奥托一世。"},{"label":"关键行动/事件","value":"从加洛林继承王国转为以萨克森王朝为核心的德意志王权，逐渐把王权、教会和军事边疆结合起来。"},{"label":"为什么重要","value":"它解释了“德意志”为什么不是从一个现代民族国家开始，而是从王国、公国和帝国称号交织的中世纪秩序中形成。"},{"label":"争议/局限","value":"不能把它直接等同于现代德国；其身份、疆域和政治语言仍属于中世纪王朝与基督教帝国世界。"},{"label":"出处","value":"Britannica, Treaty of Verdun；Britannica, Germany - History。"}],"relationItems":["← 前因：加洛林帝国《凡尔登条约》","→ 后果：奥托一世加冕为皇帝","↔ 相关：亨利一世（捕鸟者）","↔ 相关：神圣罗马帝国"],"relations":[{"text":"← 前因：加洛林帝国《凡尔登条约》","id":"extra344"},{"text":"→ 后果：奥托一世加冕为皇帝","id":"extra348"},{"text":"↔ 相关：亨利一世（捕鸟者）","id":"extra346"},{"text":"↔ 相关：神圣罗马帝国","id":"extra300"}],"source":"history","id":"extra345"},{"title":"亨利一世（捕鸟者）","level":"B","type":"人物卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"876—936年；919—936年为东法兰克国王","place":"萨克森、东法兰克王国","summary":"亨利一世把萨克森王朝推上东法兰克王位，为奥托一世和神圣罗马帝国形成奠定王权基础。","fields":[{"label":"标题","value":"亨利一世（捕鸟者）"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"876—936年；919—936年为东法兰克国王"},{"label":"地点","value":"萨克森、东法兰克王国"},{"label":"主要国家","value":"德意志地区"},{"label":"一句话概括","value":"亨利一世把萨克森王朝推上东法兰克王位，为奥托一世和神圣罗马帝国形成奠定王权基础。"},{"label":"生卒年/活跃年代","value":"876—936年，919年被选为东法兰克国王。"},{"label":"身份/职务","value":"萨克森公爵、东法兰克国王，奥托一世之父。"},{"label":"关键贡献/作为","value":"通过协商与军事整合巩固萨克森、法兰肯、巴伐利亚、士瓦本等公国关系，并加强对马扎尔人威胁的防御准备。"},{"label":"核心主张/立场","value":"他的统治重点不是建立中央集权国家，而是在公国贵族承认基础上重建王权威望。"},{"label":"为什么重要","value":"他把王权重心从加洛林传统转向萨克森王朝，使东法兰克王国获得更稳定的本土王朝基础。"},{"label":"争议/评价","value":"亨利一世常被后世民族叙事包装为“德国开端”，但更准确地说，他是中世纪东法兰克王权重组者。"},{"label":"关联事件（可选）","value":"东法兰克王国；奥托一世加冕为皇帝；东法兰克勒希菲尔德战役。"},{"label":"出处","value":"Britannica, Henry I；Britannica, Otto I。"}],"relationItems":["← 前因：东法兰克王国","→ 后果：奥托一世加冕为皇帝","↔ 相关：萨克森王朝","↔ 相关：神圣罗马帝国"],"relations":[{"text":"← 前因：东法兰克王国","id":"extra345"},{"text":"→ 后果：奥托一世加冕为皇帝","id":"extra348"},{"text":"↔ 相关：神圣罗马帝国","id":"extra300"}],"source":"history","id":"extra346"},{"title":"东法兰克勒希菲尔德战役","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"955年8月","place":"奥格斯堡附近勒希菲尔德","summary":"奥托一世在勒希菲尔德击败马扎尔人，巩固东法兰克王权并提升其争取帝国称号的威望。","fields":[{"label":"标题","value":"东法兰克勒希菲尔德战役"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"955年8月"},{"label":"地点","value":"奥格斯堡附近勒希菲尔德"},{"label":"主要国家","value":"东法兰克王国；德意志地区；匈牙利"},{"label":"一句话概括","value":"奥托一世在勒希菲尔德击败马扎尔人，巩固东法兰克王权并提升其争取帝国称号的威望。"},{"label":"参与者","value":"奥托一世、东法兰克诸公国军队、马扎尔骑兵。"},{"label":"发生了什么","value":"955年，马扎尔军队再次侵入东法兰克地区并围攻奥格斯堡。奥托一世集合萨克森、巴伐利亚、法兰肯、士瓦本等力量，在勒希菲尔德击败马扎尔骑兵。这场胜利削弱了马扎尔人对德意志地区的长期袭扰能力。"},{"label":"为什么重要","value":"它让奥托一世获得“保护基督教世界”的军事声望，也显示东法兰克诸公国可以在国王领导下联合行动。"},{"label":"前因","value":"9—10世纪马扎尔人多次袭扰中欧，东法兰克王权需要证明自己能提供防御和秩序；奥托一世还必须在内部贵族冲突后重新确认权威。"},{"label":"后果","value":"奥托一世的王权威望上升，为其进入意大利并在962年加冕为皇帝创造政治条件；马扎尔人随后逐渐转向定居和基督教王国化。"},{"label":"出处","value":"Britannica, Otto I；Britannica, Hungary - History。"}],"relationItems":["← 前因：东法兰克王国","→ 后果：奥托一世加冕为皇帝","↔ 相关：亨利一世（捕鸟者）","↔ 同时期参考：匈牙利王国形成"],"relations":[{"text":"← 前因：东法兰克王国","id":"extra345"},{"text":"→ 后果：奥托一世加冕为皇帝","id":"extra348"},{"text":"↔ 相关：亨利一世（捕鸟者）","id":"extra346"}],"source":"history","id":"extra347"},{"title":"奥托一世加冕为皇帝","level":"A","type":"事件卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"962年2月2日","place":"罗马","summary":"奥托一世在罗马加冕为皇帝，通常被视为神圣罗马帝国传统的制度性起点。","fields":[{"label":"标题","value":"奥托一世加冕为皇帝"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"962年2月2日"},{"label":"地点","value":"罗马"},{"label":"主要国家","value":"东法兰克王国；德意志地区；意大利；教皇国"},{"label":"一句话概括","value":"奥托一世在罗马加冕为皇帝，通常被视为神圣罗马帝国传统的制度性起点。"},{"label":"参与者","value":"奥托一世、教皇约翰十二世、德意志诸公国贵族、意大利政治势力。"},{"label":"发生了什么","value":"奥托一世在巩固东法兰克王权、击败马扎尔人并介入意大利事务后，于962年在罗马由教皇约翰十二世加冕为皇帝。这个加冕把德意志王权、意大利王权、教皇承认和罗马帝国名号连接起来。"},{"label":"为什么重要","value":"它是理解神圣罗马帝国的骨架节点。此后德意志国王与罗马皇帝头衔长期绑定，帝国政治也因此长期卷入意大利和教会事务。"},{"label":"前因","value":"东法兰克王权在萨克森王朝下增强，奥托一世通过勒希菲尔德胜利和意大利干预获得足够声望；教皇也需要世俗保护者稳定罗马局势。"},{"label":"后果","value":"神圣罗马帝国传统形成，德意志王权获得更高象征地位，但皇帝与教皇谁拥有最高合法性的矛盾也随之积累。"},{"label":"出处","value":"Britannica, Otto I；Britannica, Holy Roman Empire。"}],"relationItems":["← 前因：东法兰克勒希菲尔德战役","→ 后果：神圣罗马帝国","↔ 相关：东法兰克王国","↔ 相关：奥托王朝教会体系"],"relations":[{"text":"← 前因：东法兰克勒希菲尔德战役","id":"extra347"},{"text":"→ 后果：神圣罗马帝国","id":"extra300"},{"text":"↔ 相关：东法兰克王国","id":"extra345"},{"text":"↔ 相关：奥托王朝教会体系","id":"extra349"}],"source":"history","id":"extra348"},{"title":"奥托王朝教会体系","level":"B","type":"制度/文本卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"10世纪","place":"东法兰克王国和神圣罗马帝国早期核心地区","summary":"奥托王朝大量依靠主教和修道院长治理帝国，使教会成为王权结构的一部分。","fields":[{"label":"标题","value":"奥托王朝教会体系"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"10世纪"},{"label":"地点","value":"东法兰克王国和神圣罗马帝国早期核心地区"},{"label":"主要国家","value":"德意志地区；意大利"},{"label":"一句话概括","value":"奥托王朝大量依靠主教和修道院长治理帝国，使教会成为王权结构的一部分。"},{"label":"制定方/签署方","value":"不是单一文本，而是奥托王朝在任命主教、修道院长和授予土地权力时形成的治理实践。"},{"label":"主要内容","value":"国王和皇帝把主教、修道院长作为行政、财政和地方控制的支柱，给予他们土地、司法权和政治责任，同时期待他们提供忠诚、文书能力和军事资源。"},{"label":"它试图解决什么问题","value":"世袭诸侯容易形成地方家族权力，而高级教士通常没有合法继承人；王权借助教会职位来限制世袭割据并提高治理效率。"},{"label":"为什么重要","value":"它解释了为什么中世纪德意志政治里教会职位不是纯宗教问题，而是国家治理和帝国权力的核心资源。"},{"label":"争议/局限","value":"这种体系短期强化王权，长期却使“谁有权任命主教”成为皇帝和教皇冲突的导火索。"},{"label":"造成的影响","value":"11世纪中世纪教会格里高利改革和教皇与皇帝叙任权斗争把这种王权控制教职的模式推向危机。"},{"label":"出处","value":"Britannica, Otto I；Britannica, Investiture Controversy；Britannica, Gregorian Reform。"}],"relationItems":["← 前因：奥托一世加冕为皇帝","→ 后果：教皇与皇帝叙任权斗争","↔ 相关：中世纪教会格里高利改革","↔ 相关：叙任权斗争《沃尔姆斯宗教协定》"],"relations":[{"text":"← 前因：奥托一世加冕为皇帝","id":"extra348"},{"text":"→ 后果：教皇与皇帝叙任权斗争","id":"extra351"},{"text":"↔ 相关：中世纪教会格里高利改革","id":"extra350"},{"text":"↔ 相关：叙任权斗争《沃尔姆斯宗教协定》","id":"extra353"}],"source":"history","id":"extra349"},{"title":"中世纪教会格里高利改革","level":"B","type":"概念/思潮卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"11世纪，尤其1049年以后","place":"罗马教廷及西欧拉丁基督教世界","summary":"中世纪教会格里高利改革要求教会摆脱世俗控制，推动教皇权威上升并引发皇帝与教皇冲突。","fields":[{"label":"标题","value":"中世纪教会格里高利改革"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"11世纪，尤其1049年以后"},{"label":"地点","value":"罗马教廷及西欧拉丁基督教世界"},{"label":"主要国家","value":"教皇国；神圣罗马帝国；法国；英格兰"},{"label":"一句话概括","value":"中世纪教会格里高利改革要求教会摆脱世俗控制，推动教皇权威上升并引发皇帝与教皇冲突。"},{"label":"核心主张/思路","value":"反对圣职买卖、要求神职人员独身、强化教皇首位权，并限制世俗君主对教会职位的任命控制。"},{"label":"提出者/代表人物（可选）","value":"教皇利奥九世、教皇格里高利七世及11世纪改革派教士。"},{"label":"它从何而来","value":"10—11世纪教会内部对贵族控制教职、圣职买卖和神职婚姻的不满增加，修道院改革和罗马教廷改革逐渐汇合。"},{"label":"典型表现","value":"教皇加强对主教任命、教会纪律和教会法的控制，要求世俗权力不能随意授予主教职权象征。"},{"label":"为什么重要","value":"它改变了中世纪欧洲权威结构，使教皇从地方化宗教领袖转向跨国政治权威，也把神圣罗马帝国推入教皇与皇帝叙任权斗争。"},{"label":"争议/局限","value":"改革并非单纯道德运动，它也重塑教会权力层级，并与皇帝、国王和地方贵族的既得权力发生正面冲突。"},{"label":"出处","value":"Britannica, Gregorian Reform；Britannica, Investiture Controversy；Britannica, Papacy - medieval papacy。"}],"relationItems":["← 前因：奥托王朝教会体系","→ 后果：教皇与皇帝叙任权斗争","↔ 相关：亨利四世卡诺莎之行","↔ 同时期参考：第一次十字军"],"relations":[{"text":"← 前因：奥托王朝教会体系","id":"extra349"},{"text":"→ 后果：教皇与皇帝叙任权斗争","id":"extra351"},{"text":"↔ 相关：亨利四世卡诺莎之行","id":"extra352"},{"text":"↔ 同时期参考：第一次十字军","id":"extra877"}],"source":"history","id":"extra350"},{"title":"教皇与皇帝叙任权斗争","level":"A","type":"事件卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"约1075—1122年","place":"神圣罗马帝国、罗马、意大利北部","summary":"教皇与皇帝叙任权斗争围绕谁能任命主教展开，是中世纪欧洲皇帝权威与教皇权威的正面碰撞。","fields":[{"label":"标题","value":"教皇与皇帝叙任权斗争"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"约1075—1122年"},{"label":"地点","value":"神圣罗马帝国、罗马、意大利北部"},{"label":"主要国家","value":"神圣罗马帝国；教皇国；意大利"},{"label":"一句话概括","value":"教皇与皇帝叙任权斗争围绕谁能任命主教展开，是中世纪欧洲皇帝权威与教皇权威的正面碰撞。"},{"label":"参与者","value":"教皇格里高利七世、皇帝亨利四世、皇帝亨利五世、教皇加理斯都二世、德意志诸侯和主教。"},{"label":"发生了什么","value":"11世纪后期，教皇改革派反对世俗君主把戒指、牧杖等教职象征授予主教和修道院长。亨利四世坚持皇帝在帝国教会任命中的传统权力，双方相互废黜、绝罚并动员诸侯。冲突延续到亨利五世时期，最终以1122年叙任权斗争《沃尔姆斯宗教协定》妥协收束。"},{"label":"为什么重要","value":"它是欧洲政治史主线节点。它削弱皇帝对教会职位的直接控制，强化教皇和教会法权威，也扩大德意志诸侯在帝国内部的政治空间。"},{"label":"前因","value":"奥托王朝以来，德意志王权依靠主教和修道院长治理帝国；中世纪教会格里高利改革则要求教会摆脱世俗任命和贵族控制，两套秩序不可避免发生冲突。"},{"label":"后果","value":"皇帝无法像过去那样完全控制帝国教会，德意志王权的集中化受挫；教皇权威上升，但双方仍需在政治现实中妥协。"},{"label":"出处","value":"Britannica, Investiture Controversy；Britannica, Henry IV；Britannica, Concordat of Worms。"}],"relationItems":["← 前因：中世纪教会格里高利改革","→ 后果：叙任权斗争《沃尔姆斯宗教协定》","↔ 相关：亨利四世卡诺莎之行","↔ 相关：奥托王朝教会体系"],"relations":[{"text":"← 前因：中世纪教会格里高利改革","id":"extra350"},{"text":"→ 后果：叙任权斗争《沃尔姆斯宗教协定》","id":"extra353"},{"text":"↔ 相关：亨利四世卡诺莎之行","id":"extra352"},{"text":"↔ 相关：奥托王朝教会体系","id":"extra349"}],"source":"history","id":"extra351"},{"title":"亨利四世卡诺莎之行","level":"B","type":"事件卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1077年1月","place":"意大利卡诺莎城堡","summary":"亨利四世赴卡诺莎向教皇求赦，成为中世纪教皇权威压制皇帝权威的象征性场景。","fields":[{"label":"标题","value":"亨利四世卡诺莎之行"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1077年1月"},{"label":"地点","value":"意大利卡诺莎城堡"},{"label":"主要国家","value":"神圣罗马帝国；教皇国；意大利"},{"label":"一句话概括","value":"亨利四世赴卡诺莎向教皇求赦，成为中世纪教皇权威压制皇帝权威的象征性场景。"},{"label":"参与者","value":"亨利四世、教皇格里高利七世、托斯卡纳的玛蒂尔达、德意志诸侯。"},{"label":"发生了什么","value":"亨利四世因与教皇格里高利七世争夺主教任命权而被绝罚，德意志诸侯借机要求其限期获得赦免。1077年冬，亨利越过阿尔卑斯来到卡诺莎，在教皇所在城堡外请求解除绝罚，最终获得赦免。"},{"label":"为什么重要","value":"它把教皇与皇帝叙任权斗争变成欧洲政治记忆中的经典画面。后世常用“去卡诺莎”表示屈辱性求饶，德国政治语言中也反复调用这一典故。"},{"label":"前因","value":"中世纪教会格里高利改革挑战皇帝控制教会任命的传统，亨利四世与教皇相互否定权威；绝罚使亨利在德意志诸侯面前失去合法性。"},{"label":"后果","value":"赦免解决了亨利的短期合法性危机，却没有结束皇帝与教皇的结构性冲突；双方战争和德意志诸侯介入继续延伸。"},{"label":"出处","value":"Britannica, Henry IV - Role in the Investiture Controversy；Britannica, Investiture Controversy。"}],"relationItems":["← 前因：教皇与皇帝叙任权斗争","→ 后果：叙任权斗争《沃尔姆斯宗教协定》","↔ 相关：“Nach Canossa gehen wir nicht”","↔ 相关：中世纪教会格里高利改革"],"relations":[{"text":"← 前因：教皇与皇帝叙任权斗争","id":"extra351"},{"text":"→ 后果：叙任权斗争《沃尔姆斯宗教协定》","id":"extra353"},{"text":"↔ 相关：“Nach Canossa gehen wir nicht”","id":"proverb1"},{"text":"↔ 相关：中世纪教会格里高利改革","id":"extra350"}],"source":"history","id":"extra352"},{"title":"叙任权斗争《沃尔姆斯宗教协定》","level":"A","type":"制度/文本卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1122年9月23日","place":"沃尔姆斯","summary":"叙任权斗争《沃尔姆斯宗教协定》结束教皇与皇帝叙任权斗争，用妥协方式划分皇帝与教皇在主教任命中的权力。","fields":[{"label":"标题","value":"叙任权斗争《沃尔姆斯宗教协定》"},{"label":"分级","value":"A"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1122年9月23日"},{"label":"地点","value":"沃尔姆斯"},{"label":"主要国家","value":"神圣罗马帝国；教皇国"},{"label":"一句话概括","value":"叙任权斗争《沃尔姆斯宗教协定》结束教皇与皇帝叙任权斗争，用妥协方式划分皇帝与教皇在主教任命中的权力。"},{"label":"制定方/签署方","value":"教皇加理斯都二世与神圣罗马皇帝亨利五世。"},{"label":"主要内容","value":"皇帝放弃以戒指和牧杖授予主教属灵职位的权力，承认主教和修道院长应自由选举；但在帝国内，皇帝仍可参与选举程序，并授予主教世俗领地和政治权利。"},{"label":"它试图解决什么问题","value":"它试图结束皇帝和教皇围绕教职任命权的长期冲突，同时保留帝国教会作为政治秩序一部分的现实。"},{"label":"为什么重要","value":"它是中世纪政教关系的关键妥协。教会获得更强制度自主，皇帝保留部分世俗控制，欧洲权力分立的早期形态更加清晰。"},{"label":"争议/局限","value":"协定没有消除皇帝、教皇和诸侯之间的权力竞争，只是把最尖锐的授职象征争议制度化处理。"},{"label":"造成的影响","value":"德意志王权对教会的控制被限制，诸侯和主教的地方权力继续扩展，神圣罗马帝国更难发展为集中君主国。"},{"label":"出处","value":"Britannica, Concordat of Worms；Britannica, Investiture Controversy。"}],"relationItems":["← 前因：教皇与皇帝叙任权斗争","↔ 相关：亨利四世卡诺莎之行","↔ 相关：奥托王朝教会体系","↔ 同时期参考：第一次拉特朗公会议"],"relations":[{"text":"← 前因：教皇与皇帝叙任权斗争","id":"extra351"},{"text":"↔ 相关：亨利四世卡诺莎之行","id":"extra352"},{"text":"↔ 相关：奥托王朝教会体系","id":"extra349"}],"source":"history","id":"extra353"},{"title":"神圣罗马帝国霍亨斯陶芬王朝","level":"B","type":"组织/机构卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1138—1254年为神圣罗马帝国主要王朝","place":"士瓦本、神圣罗马帝国、意大利、西西里","summary":"神圣罗马帝国霍亨斯陶芬王朝试图重振皇帝权威，却因德意志、意大利和西西里多线政治而陷入长期冲突。","fields":[{"label":"标题","value":"神圣罗马帝国霍亨斯陶芬王朝"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1138—1254年为神圣罗马帝国主要王朝"},{"label":"地点","value":"士瓦本、神圣罗马帝国、意大利、西西里"},{"label":"主要国家","value":"神圣罗马帝国；德意志地区；意大利；西西里"},{"label":"一句话概括","value":"神圣罗马帝国霍亨斯陶芬王朝试图重振皇帝权威，却因德意志、意大利和西西里多线政治而陷入长期冲突。"},{"label":"性质/类型","value":"中世纪德意志王朝和神圣罗马帝国皇帝家族。"},{"label":"成立/解散时间","value":"12—13世纪活跃，1138年康拉德三世即位后成为帝国主要王朝，1254年前后退出帝国核心。"},{"label":"核心目标/宗旨","value":"强化皇帝在德意志和意大利的权威，并把帝国称号、伦巴第城市控制和西西里王国资源结合起来。"},{"label":"关键人物（可选）","value":"康拉德三世、腓特烈一世巴巴罗萨、亨利六世、腓特烈二世。"},{"label":"关键行动/事件","value":"参与意大利战争、与教皇和伦巴第城市冲突、通过婚姻获得西西里王国，并卷入十字军政治。"},{"label":"为什么重要","value":"它代表中世纪皇权扩张的高峰和极限。王朝越想建立跨阿尔卑斯帝国，越暴露神圣罗马帝国难以集中化的结构困境。"},{"label":"争议/局限","value":"霍亨斯陶芬政策常被浪漫化为强皇权努力，但其多线扩张也消耗德意志王权基础，并刺激城市、教皇和诸侯反制。"},{"label":"出处","value":"Britannica, Hohenstaufen Dynasty；Britannica, Frederick I。"}],"relationItems":["← 前因：叙任权斗争《沃尔姆斯宗教协定》","→ 后果：神圣罗马帝国大空位时期","↔ 相关：腓特烈一世巴巴罗萨","↔ 相关：意大利伦巴第联盟"],"relations":[{"text":"← 前因：叙任权斗争《沃尔姆斯宗教协定》","id":"extra353"},{"text":"→ 后果：神圣罗马帝国大空位时期","id":"extra376"},{"text":"↔ 相关：腓特烈一世巴巴罗萨","id":"extra355"},{"text":"↔ 相关：意大利伦巴第联盟","id":"extra356"}],"source":"history","id":"extra354"},{"title":"腓特烈一世巴巴罗萨","level":"B","type":"人物卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"约1122—1190年；1152—1190年为德意志国王，1155年加冕皇帝","place":"神圣罗马帝国、意大利北部、小亚细亚","summary":"腓特烈一世试图恢复皇帝权威，其意大利政策凸显中世纪帝国理想与城市自治的冲突。","fields":[{"label":"标题","value":"腓特烈一世巴巴罗萨"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"约1122—1190年；1152—1190年为德意志国王，1155年加冕皇帝"},{"label":"地点","value":"神圣罗马帝国、意大利北部、小亚细亚"},{"label":"主要国家","value":"神圣罗马帝国；德意志地区；意大利"},{"label":"一句话概括","value":"腓特烈一世试图恢复皇帝权威，其意大利政策凸显中世纪帝国理想与城市自治的冲突。"},{"label":"生卒年/活跃年代","value":"约1122—1190年。"},{"label":"身份/职务","value":"神圣罗马帝国霍亨斯陶芬王朝德意志国王、神圣罗马皇帝。"},{"label":"关键贡献/作为","value":"整合德意志诸侯关系，多次远征意大利，试图迫使伦巴第城市承认皇帝权利，并参加第三次十字军。"},{"label":"核心主张/立场","value":"强调皇帝作为罗马帝国继承者的法权和尊严，主张意大利城市应服从帝国司法、税收和军事义务。"},{"label":"为什么重要","value":"他是中世纪神圣罗马皇帝形象最鲜明的人物之一，也让“帝国权威能否压倒地方自治”这一问题具体化。"},{"label":"争议/评价","value":"其意大利政策提升皇帝声望，却难以稳定控制城市社会；军事努力最终必须通过意大利伦巴第联盟《康斯坦茨和约》接受妥协。"},{"label":"关联事件（可选）","value":"意大利伦巴第联盟；意大利伦巴第联盟莱尼亚诺战役；意大利伦巴第联盟《康斯坦茨和约》。"},{"label":"出处","value":"Britannica, Frederick I；Britannica, Lombard League。"}],"relationItems":["← 前因：神圣罗马帝国霍亨斯陶芬王朝","→ 后果：意大利伦巴第联盟莱尼亚诺战役","↔ 相关：意大利伦巴第联盟","↔ 相关：意大利伦巴第联盟《康斯坦茨和约》"],"relations":[{"text":"← 前因：神圣罗马帝国霍亨斯陶芬王朝","id":"extra354"},{"text":"→ 后果：意大利伦巴第联盟莱尼亚诺战役","id":"extra357"},{"text":"↔ 相关：意大利伦巴第联盟","id":"extra356"},{"text":"↔ 相关：意大利伦巴第联盟《康斯坦茨和约》","id":"extra358"}],"source":"history","id":"extra355"},{"title":"意大利伦巴第联盟","level":"B","type":"组织/机构卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1167—1183年前后最活跃","place":"意大利北部伦巴第城市区","summary":"意大利伦巴第联盟是北意城市反抗皇帝控制的同盟，显示中世纪城市自治能挑战帝国权威。","fields":[{"label":"标题","value":"意大利伦巴第联盟"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1167—1183年前后最活跃"},{"label":"地点","value":"意大利北部伦巴第城市区"},{"label":"主要国家","value":"意大利；神圣罗马帝国"},{"label":"一句话概括","value":"意大利伦巴第联盟是北意城市反抗皇帝控制的同盟，显示中世纪城市自治能挑战帝国权威。"},{"label":"性质/类型","value":"意大利北部城市军事和政治联盟。"},{"label":"成立/解散时间","value":"1167年形成，1183年意大利伦巴第联盟《康斯坦茨和约》后获得制度承认。"},{"label":"核心目标/宗旨","value":"保护伦巴第城市自治、地方司法和商业利益，反对腓特烈一世巴巴罗萨恢复帝国直接控制。"},{"label":"关键人物（可选）","value":"米兰、威尼斯、克雷莫纳、曼图亚等城市代表；教皇亚历山大三世为重要支持力量。"},{"label":"关键行动/事件","value":"重建被皇帝摧毁的米兰，联合抵抗帝国军，并在1176年意大利伦巴第联盟莱尼亚诺战役中击败腓特烈一世。"},{"label":"为什么重要","value":"它把意大利城市政治、教皇外交和神圣罗马帝国权力冲突连接起来，是欧洲城市自治史的重要节点。"},{"label":"争议/局限","value":"联盟不是现代民族独立运动，而是城市共同维护特权和自治的政治军事合作。"},{"label":"出处","value":"Britannica, Lombard League；Britannica, Frederick I。"}],"relationItems":["← 前因：腓特烈一世巴巴罗萨","→ 后果：意大利伦巴第联盟莱尼亚诺战役","→ 后果：意大利伦巴第联盟《康斯坦茨和约》","↔ 相关：中世纪意大利城市自治"],"relations":[{"text":"← 前因：腓特烈一世巴巴罗萨","id":"extra355"},{"text":"→ 后果：意大利伦巴第联盟莱尼亚诺战役","id":"extra357"},{"text":"→ 后果：意大利伦巴第联盟《康斯坦茨和约》","id":"extra358"},{"text":"↔ 相关：中世纪意大利城市自治","id":"extra870"}],"source":"history","id":"extra356"},{"title":"意大利伦巴第联盟莱尼亚诺战役","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1176年5月29日","place":"意大利北部莱尼亚诺","summary":"意大利伦巴第联盟在莱尼亚诺击败腓特烈一世，迫使皇帝承认意大利城市自治的现实。","fields":[{"label":"标题","value":"意大利伦巴第联盟莱尼亚诺战役"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1176年5月29日"},{"label":"地点","value":"意大利北部莱尼亚诺"},{"label":"主要国家","value":"神圣罗马帝国；意大利"},{"label":"一句话概括","value":"意大利伦巴第联盟在莱尼亚诺击败腓特烈一世，迫使皇帝承认意大利城市自治的现实。"},{"label":"参与者","value":"腓特烈一世巴巴罗萨、意大利伦巴第联盟城市军、米兰等北意城市。"},{"label":"发生了什么","value":"1176年，腓特烈一世再次试图用军事方式压服北意伦巴第城市。意大利伦巴第联盟在莱尼亚诺与帝国军交战并取得胜利，打破了皇帝通过军事征服恢复意大利控制的计划。"},{"label":"为什么重要","value":"它说明神圣罗马皇帝即便拥有帝国称号，也难以压倒商业城市和地方联盟的集体抵抗。"},{"label":"前因","value":"腓特烈一世长期要求伦巴第城市承认帝国司法和税收权，米兰等城市则依靠商业财富和联盟机制维护自治。"},{"label":"后果","value":"皇帝被迫转向谈判，最终在1183年意大利伦巴第联盟《康斯坦茨和约》中承认伦巴第城市在实践中的自治权；北意城市由此保住地方司法和市政空间，帝国对意大利的直接控制能力进一步受限。"},{"label":"出处","value":"Britannica, Frederick I；Britannica, Lombard League；Britannica, Legnano。"}],"relationItems":["← 前因：意大利伦巴第联盟","→ 后果：意大利伦巴第联盟《康斯坦茨和约》","↔ 相关：腓特烈一世巴巴罗萨","↔ 同时期参考：中世纪城市自治"],"relations":[{"text":"← 前因：意大利伦巴第联盟","id":"extra356"},{"text":"→ 后果：意大利伦巴第联盟《康斯坦茨和约》","id":"extra358"},{"text":"↔ 相关：腓特烈一世巴巴罗萨","id":"extra355"},{"text":"↔ 同时期参考：中世纪城市自治","id":"extra869"}],"source":"history","id":"extra357"},{"title":"意大利伦巴第联盟《康斯坦茨和约》","level":"B","type":"制度/文本卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1183年","place":"康斯坦茨","summary":"意大利伦巴第联盟《康斯坦茨和约》承认伦巴第城市实际自治，是皇帝权威与城市政治妥协的代表性文本。","fields":[{"label":"标题","value":"意大利伦巴第联盟《康斯坦茨和约》"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1183年"},{"label":"地点","value":"康斯坦茨"},{"label":"主要国家","value":"神圣罗马帝国；意大利"},{"label":"一句话概括","value":"意大利伦巴第联盟《康斯坦茨和约》承认伦巴第城市实际自治，是皇帝权威与城市政治妥协的代表性文本。"},{"label":"制定方/签署方","value":"腓特烈一世巴巴罗萨与意大利伦巴第联盟城市。"},{"label":"主要内容","value":"皇帝保留最高宗主权和象征性权利，伦巴第城市则获得较广泛的自治、选举官员、维持地方习惯和管理城市事务的实际空间。"},{"label":"它试图解决什么问题","value":"它试图结束皇帝与北意城市之间的长期战争，用法律妥协替代反复军事压服。"},{"label":"为什么重要","value":"它显示中世纪欧洲政治常通过特权、自治和宗主权妥协运行，而不是简单的中央命令。"},{"label":"争议/局限","value":"和约没有让意大利脱离帝国名义，也没有消除皇帝、教皇和城市之间的后续冲突。"},{"label":"造成的影响","value":"北意城市自治得到巩固，神圣罗马帝国在意大利的直接控制受限，德意志皇权的跨阿尔卑斯野心受到现实约束。"},{"label":"出处","value":"Britannica, Frederick I；Britannica, Lombard League。"}],"relationItems":["← 前因：意大利伦巴第联盟莱尼亚诺战役","↔ 相关：意大利伦巴第联盟","↔ 相关：腓特烈一世巴巴罗萨","↔ 同时期参考：中世纪意大利城市自治"],"relations":[{"text":"← 前因：意大利伦巴第联盟莱尼亚诺战役","id":"extra357"},{"text":"↔ 相关：意大利伦巴第联盟","id":"extra356"},{"text":"↔ 相关：腓特烈一世巴巴罗萨","id":"extra355"},{"text":"↔ 同时期参考：中世纪意大利城市自治","id":"extra870"}],"source":"history","id":"extra358"},{"title":"中世纪欧洲布汶战役","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1214年7月27日","place":"法国北部布汶","summary":"布汶战役击败英格兰—帝国联盟，强化法国王权并改变神圣罗马帝国内部王位竞争。","fields":[{"label":"标题","value":"中世纪欧洲布汶战役"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1214年7月27日"},{"label":"地点","value":"法国北部布汶"},{"label":"主要国家","value":"法国；英格兰；神圣罗马帝国；佛兰德"},{"label":"一句话概括","value":"布汶战役击败英格兰—帝国联盟，强化法国王权并改变神圣罗马帝国内部王位竞争。"},{"label":"参与者","value":"法国国王腓力二世、英格兰国王约翰的盟友、神圣罗马皇帝奥托四世、佛兰德和布洛涅贵族。"},{"label":"发生了什么","value":"1214年，法国国王腓力二世在布汶迎战由奥托四世、佛兰德伯爵和英格兰盟友组成的反法联盟。法国获胜，奥托四世威望崩溃，英格兰国王约翰在大陆政策上遭重挫。"},{"label":"为什么重要","value":"它不是德国史内部战役，而是西欧权力结构节点：法国王权增强，英格兰贵族逼迫约翰让步的背景加深，神圣罗马帝国王位竞争也转向腓特烈二世。"},{"label":"前因","value":"英法围绕法兰西西部领地持续冲突，奥托四世与霍亨斯陶芬竞争帝位，需要通过反法联盟巩固自身地位。"},{"label":"后果","value":"奥托四世政治失势，霍亨斯陶芬的腓特烈二世获得更大空间；法国卡佩王朝王权威望上升，欧洲西部均势发生变化。"},{"label":"出处","value":"Britannica, Battle of Bouvines；Britannica, Philip II；Britannica, Otto IV。"}],"relationItems":["← 前因：神圣罗马帝国霍亨斯陶芬王朝","→ 后果：神圣罗马皇帝腓特烈二世","↔ 相关：英格兰《大宪章》","↔ 同时期参考：法国卡佩王朝"],"relations":[{"text":"← 前因：神圣罗马帝国霍亨斯陶芬王朝","id":"extra354"},{"text":"→ 后果：神圣罗马皇帝腓特烈二世","id":"extra375"},{"text":"↔ 相关：英格兰《大宪章》","id":"extra895"}],"source":"history","id":"extra359"},{"title":"德意志东向殖民","level":"B","type":"概念/思潮卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"约11—14世纪","place":"易北河以东、中东欧、波罗的海沿岸、波希米亚、奥地利等地","summary":"德意志东向殖民是中世纪人口、城市法和农业扩张过程，深刻改变中东欧族群与城市格局。","fields":[{"label":"标题","value":"德意志东向殖民"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"约11—14世纪"},{"label":"地点","value":"易北河以东、中东欧、波罗的海沿岸、波希米亚、奥地利等地"},{"label":"主要国家","value":"德意志地区；波兰；捷克；波罗的海地区；匈牙利"},{"label":"一句话概括","value":"德意志东向殖民是中世纪人口、城市法和农业扩张过程，深刻改变中东欧族群与城市格局。"},{"label":"核心主张/思路","value":"这不是单一国家政策，而是贵族、修道院、城市和农民迁徙共同推动的东部开垦、建城和法律移植过程。"},{"label":"提出者/代表人物（可选）","value":"各地诸侯、主教、修道院、城市经营者和移民社群。"},{"label":"它从何而来","value":"中世纪人口增长、农业技术扩展、边疆开垦和中东欧统治者引入移民的需求共同推动了迁徙。"},{"label":"典型表现","value":"德语移民进入西里西亚、波美拉尼亚、波希米亚、普鲁士和波罗的海地区；许多城市采用德意志城市法，如中世纪马格德堡法。"},{"label":"为什么重要","value":"它解释了为什么近代以前中东欧存在大量德语城市、贵族和移民社群，也为后来普鲁士、波兰、波希米亚和波罗的海问题提供深层背景。"},{"label":"争议/局限","value":"这个概念曾被19—20世纪民族主义叙事滥用，不能简单理解成现代民族国家式扩张；它包含合作、迁徙、殖民、冲突和同化多重过程。"},{"label":"出处","value":"Encyclopaedia Britannica, Magdeburg Law；German Historical Institute, Medieval Germany resources；Robert Bartlett, The Making of Europe。"}],"relationItems":["→ 后果：中世纪马格德堡法","↔ 相关：中世纪条顿骑士团","↔ 相关：条顿骑士团国家","↔ 同时期参考：中世纪欧洲人口增长"],"relations":[{"text":"→ 后果：中世纪马格德堡法","id":"extra361"},{"text":"↔ 相关：中世纪条顿骑士团","id":"extra362"},{"text":"↔ 相关：条顿骑士团国家","id":"extra363"}],"source":"history","id":"extra360"},{"title":"中世纪马格德堡法","level":"C","type":"制度/文本卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"12世纪以后，13世纪起广泛传播","place":"马格德堡及中东欧城市","summary":"中世纪马格德堡法是从德意志城市扩散到中东欧的城市法传统，影响市民自治和商业司法。","fields":[{"label":"标题","value":"中世纪马格德堡法"},{"label":"分级","value":"C"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"12世纪以后，13世纪起广泛传播"},{"label":"地点","value":"马格德堡及中东欧城市"},{"label":"主要国家","value":"德意志地区；波兰；捷克；匈牙利；立陶宛；乌克兰地区"},{"label":"一句话概括","value":"中世纪马格德堡法是从德意志城市扩散到中东欧的城市法传统，影响市民自治和商业司法。"},{"label":"制定方/签署方","value":"源自马格德堡城市法和相关萨克森法律传统，后由各地君主、诸侯或城市特许采用。"},{"label":"主要内容","value":"规定城市自治、市场秩序、商业纠纷、城市法院、市政官员和市民权利义务等内容，具体版本会因地区而变化。"},{"label":"它试图解决什么问题","value":"它为新建或扩张城市提供可复制的法律框架，降低商业、移民和城市治理的不确定性。"},{"label":"为什么重要","value":"它把德意志城市经验传播到中东欧，使“城市自治”和“德意志法”成为跨区域制度资源。"},{"label":"争议/局限","value":"中世纪马格德堡法并不等于现代平等市民权；早期特权常对不同族群、宗教和身份群体适用不均。"},{"label":"造成的影响","value":"许多中东欧城市在数百年里以中世纪马格德堡法或其变体运作，形成城市法院、商贸规则和自治传统。"},{"label":"出处","value":"Britannica, Magdeburg Law；Encyclopedia.com, Magdeburg Law；Magdeburg-law.com, Magdeburg Law。"}],"relationItems":["← 前因：德意志东向殖民","↔ 相关：中世纪汉萨同盟","↔ 相关：中世纪城市自治","↔ 同时期参考：萨克森明镜"],"relations":[{"text":"← 前因：德意志东向殖民","id":"extra360"},{"text":"↔ 相关：中世纪汉萨同盟","id":"extra321"},{"text":"↔ 相关：中世纪城市自治","id":"extra869"}],"source":"history","id":"extra361"},{"title":"中世纪条顿骑士团","level":"B","type":"组织/机构卡","tags":["战争与外交","文化与思想"],"mainTag":"战争与外交","subTag":"文化与思想","timeText":"1189/1190年成立；中世纪后期在东欧和普鲁士最活跃","place":"阿卡、普鲁士、波罗的海地区、马林堡","summary":"条顿骑士团从十字军医院团体发展为军事修会，后来在普鲁士和波罗的海建立统治。","fields":[{"label":"标题","value":"中世纪条顿骑士团"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1189/1190年成立；中世纪后期在东欧和普鲁士最活跃"},{"label":"地点","value":"阿卡、普鲁士、波罗的海地区、马林堡"},{"label":"主要国家","value":"德意志地区；波兰；立陶宛；波罗的海地区"},{"label":"一句话概括","value":"条顿骑士团从十字军医院团体发展为军事修会，后来在普鲁士和波罗的海建立统治。"},{"label":"性质/类型","value":"天主教军事修会和医院团体。"},{"label":"成立/解散时间","value":"1189/1190年在第三次十字军期间形成；其普鲁士统治于1525年世俗化结束。"},{"label":"核心目标/宗旨","value":"最初照料十字军病患，后军事化并承担十字军、传教、边疆征服和领地治理功能。"},{"label":"关键人物（可选）","value":"赫尔曼·冯·萨尔扎、阿尔布雷希特。"},{"label":"关键行动/事件","value":"从圣地转向东欧，在普鲁士和波罗的海征服非基督教社群，建立城堡、城市和修会国家。"},{"label":"为什么重要","value":"它把十字军运动、中东欧殖民、德意志移民和普鲁士国家起源连接起来。"},{"label":"争议/局限","value":"骑士团自称传教和秩序建设者，但其扩张包含强制征服、族群压迫和与波兰—立陶宛的长期战争。"},{"label":"出处","value":"Britannica, Teutonic Order。"}],"relationItems":["← 前因：德意志东向殖民","→ 后果：条顿骑士团国家","↔ 相关：波兰立陶宛联邦","↔ 同时期参考：十字军运动"],"relations":[{"text":"← 前因：德意志东向殖民","id":"extra360"},{"text":"→ 后果：条顿骑士团国家","id":"extra363"},{"text":"↔ 相关：波兰立陶宛联邦","id":"extra867"},{"text":"↔ 同时期参考：十字军运动","id":"extra893"}],"source":"history","id":"extra362"},{"title":"条顿骑士团国家","level":"B","type":"组织/机构卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"13世纪—1525年","place":"普鲁士、利沃尼亚、马林堡及波罗的海沿岸","summary":"条顿骑士团国家是军事修会在普鲁士建立的政权，是后来普鲁士历史的重要远源。","fields":[{"label":"标题","value":"条顿骑士团国家"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"13世纪—1525年"},{"label":"地点","value":"普鲁士、利沃尼亚、马林堡及波罗的海沿岸"},{"label":"主要国家","value":"德意志地区；波兰；立陶宛；波罗的海地区"},{"label":"一句话概括","value":"条顿骑士团国家是军事修会在普鲁士建立的政权，是后来普鲁士历史的重要远源。"},{"label":"性质/类型","value":"军事修会国家和边疆殖民政权。"},{"label":"成立/解散时间","value":"13世纪征服普鲁士后逐步形成，1525年普鲁士地区世俗化为普鲁士公国。"},{"label":"核心目标/宗旨","value":"以军事修会为统治核心，控制普鲁士和波罗的海贸易、传教、城堡网络和移民殖民。"},{"label":"关键人物（可选）","value":"赫尔曼·冯·萨尔扎、历任大团长、阿尔布雷希特。"},{"label":"关键行动/事件","value":"征服普鲁士、建立马林堡中心、参与波罗的海贸易，与波兰和立陶宛长期冲突。"},{"label":"为什么重要","value":"它把中世纪十字军边疆转化为近代普鲁士国家谱系的一环；理解普鲁士不能只从1701年普鲁士王国开始。"},{"label":"争议/局限","value":"骑士团国家既有城市、贸易和行政建设，也建立在军事征服和对当地普鲁士人的暴力支配之上。"},{"label":"出处","value":"Britannica, Teutonic Order；Britannica, Prussia。"}],"relationItems":["← 前因：中世纪条顿骑士团","→ 后果：普鲁士公国世俗化","↔ 相关：德意志东向殖民","↔ 相关：波兰立陶宛联邦"],"relations":[{"text":"← 前因：中世纪条顿骑士团","id":"extra362"},{"text":"→ 后果：普鲁士公国世俗化","id":"extra430"},{"text":"↔ 相关：德意志东向殖民","id":"extra360"},{"text":"↔ 相关：波兰立陶宛联邦","id":"extra867"}],"source":"history","id":"extra363"},{"title":"黑死病冲击中欧","level":"B","type":"事件卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"1348—1351年前后","place":"中欧、德意志城市、波希米亚、奥地利等地","summary":"黑死病进入中欧后造成巨大人口损失，并加剧社会恐慌、劳动力变化和反犹暴力。","fields":[{"label":"标题","value":"黑死病冲击中欧"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1348—1351年前后"},{"label":"地点","value":"中欧、德意志城市、波希米亚、奥地利等地"},{"label":"主要国家","value":"德意志地区；捷克；奥地利；欧洲"},{"label":"一句话概括","value":"黑死病进入中欧后造成巨大人口损失，并加剧社会恐慌、劳动力变化和反犹暴力。"},{"label":"参与者","value":"中欧城市居民、乡村社群、教会、地方当局、犹太社群、流动忏悔者群体。"},{"label":"发生了什么","value":"14世纪中叶，鼠疫大流行从地中海和西欧扩散到中欧，德意志城市和周边地区出现严重死亡、经济中断和社会恐慌。许多地方把灾难归咎于犹太社群，引发迫害和屠杀；同时劳动力短缺也改变了农业和城市经济关系。"},{"label":"为什么重要","value":"它不是单纯疾病事件，而是欧洲社会结构冲击。人口下降、宗教恐慌、反犹暴力和劳动力价格变化共同改变了中世纪晚期社会。"},{"label":"前因","value":"欧亚贸易网络、战争流动、城市密度和卫生条件使鼠疫能够迅速传播；中世纪社会缺乏有效病因解释，灾难容易转化为宗教和族群恐慌。"},{"label":"后果","value":"许多城市和乡村人口锐减，劳动关系发生调整，反犹暴力造成长期创伤；中世纪晚期欧洲社会对死亡、赎罪和秩序危机的想象被深刻改变。"},{"label":"出处","value":"Britannica, Black Death；Britannica, Flagellants；United States Holocaust Memorial Museum, Black Death and antisemitic violence。"}],"relationItems":["↔ 相关：近代早期欧洲猎巫","↔ 相关：德意志城市社会","↔ 同时期参考：欧洲黑死病","→ 后果：晚期中世纪社会危机"],"relations":[{"text":"↔ 相关：近代早期欧洲猎巫","id":"extra336"}],"source":"history","id":"extra364"},{"title":"神圣罗马帝国《金玺诏书》","level":"A","type":"制度/文本卡","tags":["政治与制度"],"mainTag":"政治与制度","subTag":"","timeText":"1356年","place":"纽伦堡、梅斯；神圣罗马帝国","summary":"神圣罗马帝国《金玺诏书》固定七大选侯选举规则，使神圣罗马帝国的分权选举体制制度化。","fields":[{"label":"标题","value":"神圣罗马帝国《金玺诏书》"},{"label":"分级","value":"A"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"时间","value":"1356年"},{"label":"地点","value":"纽伦堡、梅斯；神圣罗马帝国"},{"label":"主要国家","value":"神圣罗马帝国；德意志地区；捷克"},{"label":"一句话概括","value":"神圣罗马帝国《金玺诏书》固定七大选侯选举规则，使神圣罗马帝国的分权选举体制制度化。"},{"label":"制定方/签署方","value":"神圣罗马皇帝查理四世及帝国诸侯会议。"},{"label":"主要内容","value":"确认七大选侯的地位和选举程序，规定多数票即可产生罗马人的国王，并强化选侯领地不可分割、继承和特权。"},{"label":"它试图解决什么问题","value":"它试图减少皇帝选举争议和教皇干预，把德意志王权选举程序交给固定选侯集团处理。"},{"label":"为什么重要","value":"它是神圣罗马帝国宪制史骨架卡。它没有推动中央集权，反而把诸侯尤其选侯的政治权利制度化。"},{"label":"争议/局限","value":"诏书稳定了选举程序，却牺牲城市和中央权力空间；帝国长期保持复合和分权结构。"},{"label":"造成的影响","value":"选侯成为帝国政治核心，皇帝权力更加依赖诸侯协商，后来德意志长期多中心格局得到法律基础。"},{"label":"出处","value":"Britannica, Golden Bull of Emperor Charles IV。"}],"relationItems":["← 前因：神圣罗马帝国","→ 后果：德意志统一与奥普领导权问题","↔ 相关：查理四世与布拉格宫廷","↔ 相关：德意志邦联"],"relations":[{"text":"← 前因：神圣罗马帝国","id":"extra300"},{"text":"→ 后果：德意志统一与奥普领导权问题","id":"extra526"},{"text":"↔ 相关：查理四世与布拉格宫廷","id":"extra381"},{"text":"↔ 相关：德意志邦联","id":"extra487"}],"source":"history","id":"extra365"},{"title":"波希米亚胡斯战争","level":"B","type":"事件卡","tags":["文化与思想","战争与外交"],"mainTag":"文化与思想","subTag":"战争与外交","timeText":"1419—1436年","place":"波希米亚及中欧","summary":"波希米亚胡斯战争把波希米亚宗教改革诉求转化为军事政治冲突，预示后来的欧洲宗教战争。","fields":[{"label":"标题","value":"波希米亚胡斯战争"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1419—1436年"},{"label":"地点","value":"波希米亚及中欧"},{"label":"主要国家","value":"捷克；神圣罗马帝国；教皇国"},{"label":"一句话概括","value":"波希米亚胡斯战争把波希米亚宗教改革诉求转化为军事政治冲突，预示后来的欧洲宗教战争。"},{"label":"参与者","value":"胡斯派、波希米亚贵族和城市、天主教十字军、神圣罗马皇帝西吉斯蒙德。"},{"label":"发生了什么","value":"扬·胡斯被处死后，波希米亚改革派与天主教权威和帝国力量矛盾激化。1419年起，胡斯派在波希米亚发动起义并多次击败外部十字军。不同胡斯派派别之间也发生冲突，最终通过妥协和军事胜负形成有限承认。"},{"label":"为什么重要","value":"它是宗教改革前最重要的中欧宗教战争之一，说明教义、民族语言、城市政治和帝国权威可以提前组合成大规模冲突。"},{"label":"前因","value":"布拉格大学和波希米亚教会改革思想发展，胡斯批评教会腐败并受威克里夫思想影响；康斯坦茨会议处死胡斯激化波希米亚社会反抗。"},{"label":"后果","value":"波希米亚宗教政治保持特殊性，天主教一统受到挑战；16世纪路德宗改革出现后，人们更容易把胡斯运动视为宗教改革的先声。"},{"label":"出处","value":"Britannica, Hussite Wars；Britannica, Jan Hus。"}],"relationItems":["← 前因：中世纪教会格里高利改革","↔ 相关：欧洲宗教改革","↔ 相关：马丁·路德发表《九十五条论纲》","↔ 同时期参考：康斯坦茨会议"],"relations":[{"text":"← 前因：中世纪教会格里高利改革","id":"extra350"},{"text":"↔ 相关：欧洲宗教改革","id":"extra301"},{"text":"↔ 相关：马丁·路德发表《九十五条论纲》","id":"extra302"}],"source":"history","id":"extra366"},{"title":"萨克森战争与强制基督教化","level":"B","type":"事件卡","tags":["战争与外交","文化与思想"],"mainTag":"战争与外交","subTag":"文化与思想","timeText":"772—804年","place":"萨克森地区、法兰克王国东北边疆","summary":"查理曼长期征服萨克森并强制推进基督教化，把法兰克王国边疆扩展到后来的德意志核心区域。","fields":[{"label":"标题","value":"萨克森战争与强制基督教化"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"772—804年"},{"label":"地点","value":"萨克森地区、法兰克王国东北边疆"},{"label":"主要国家","value":"法兰克王国；德意志地区"},{"label":"一句话概括","value":"查理曼长期征服萨克森并强制推进基督教化，把法兰克王国边疆扩展到后来的德意志核心区域。"},{"label":"参与者","value":"查理曼、萨克森贵族与部落社群、法兰克军队、基督教传教士。"},{"label":"发生了什么","value":"772年起，查理曼多次发动对萨克森的军事远征，摧毁异教圣地、建立要塞、迫使萨克森领袖臣服，并把洗礼和服从法兰克王权绑定。萨克森反复起义，法兰克方面则以处决、迁徙和法律惩罚镇压。到804年前后，萨克森基本被纳入加洛林秩序。"},{"label":"为什么重要","value":"它把萨克森从法兰克边疆变成中世纪德意志王权的重要地区，也显示欧洲基督教化常与征服、法律和暴力国家建设交织。"},{"label":"前因","value":"法兰克王国需要稳定东北边疆，查理曼也希望把军事扩张与基督教王权使命结合；萨克森地区仍保持较强地方独立和非基督教传统。"},{"label":"后果","value":"萨克森被纳入法兰克和拉丁基督教世界，数代以后萨克森王朝反而成为东法兰克王权核心，并推动奥托一世建立帝国传统。"},{"label":"出处","value":"Britannica, Charlemagne；Britannica, Saxon Wars。"}],"relationItems":["→ 后果：东法兰克王国","→ 后果：亨利一世（捕鸟者）","↔ 相关：查理曼加冕为罗马皇帝","↔ 同时期参考：加洛林文艺复兴"],"relations":[{"text":"→ 后果：东法兰克王国","id":"extra345"},{"text":"→ 后果：亨利一世（捕鸟者）","id":"extra346"},{"text":"↔ 相关：查理曼加冕为罗马皇帝","id":"extra343"},{"text":"↔ 同时期参考：加洛林文艺复兴","id":"extra368"}],"source":"history","id":"extra367"},{"title":"加洛林文艺复兴","level":"B","type":"概念/思潮卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"8世纪末—9世纪","place":"法兰克王国宫廷、修道院和主教座堂学校","summary":"加洛林文艺复兴通过宫廷和修道院教育复兴拉丁文化，为中世纪西欧知识秩序奠定基础。","fields":[{"label":"标题","value":"加洛林文艺复兴"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"8世纪末—9世纪"},{"label":"地点","value":"法兰克王国宫廷、修道院和主教座堂学校"},{"label":"主要国家","value":"法兰克王国；法国；德意志地区；意大利"},{"label":"一句话概括","value":"加洛林文艺复兴通过宫廷和修道院教育复兴拉丁文化，为中世纪西欧知识秩序奠定基础。"},{"label":"核心主张/思路","value":"以基督教王权为中心，恢复拉丁文教育、抄写经典、统一礼仪和改善神职人员训练。"},{"label":"提出者/代表人物（可选）","value":"查理曼、约克的阿尔昆、宫廷学者和修道院抄写员。"},{"label":"它从何而来","value":"加洛林王权扩张后需要统一行政、宗教和教育标准，教会也需要更可靠的文本、礼仪和神职训练体系。"},{"label":"典型表现","value":"宫廷学校和修道院学校发展，拉丁文教育加强，手稿抄写规范化，加洛林小写字体传播。"},{"label":"为什么重要","value":"它不是现代意义的文艺复兴，但保存和整理了大量古典及基督教文本，对西欧教育、行政文书和教会文化影响深远。"},{"label":"争议/局限","value":"它主要服务宫廷和教会精英，影响范围不等于大众教育普及。"},{"label":"出处","value":"Britannica, Carolingian Renaissance；Britannica, Charlemagne。"}],"relationItems":["← 前因：查理曼加冕为罗马皇帝","↔ 相关：萨克森战争与强制基督教化","↔ 相关：欧洲宗教改革","↔ 同时期参考：中世纪修道院文化"],"relations":[{"text":"← 前因：查理曼加冕为罗马皇帝","id":"extra343"},{"text":"↔ 相关：萨克森战争与强制基督教化","id":"extra367"},{"text":"↔ 相关：欧洲宗教改革","id":"extra301"},{"text":"↔ 同时期参考：中世纪修道院文化","id":"extra878"}],"source":"history","id":"extra368"},{"title":"加洛林帝国《梅尔森条约》","level":"B","type":"制度/文本卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"870年","place":"梅尔森；洛林地区","summary":"加洛林帝国《梅尔森条约》瓜分洛泰尔二世的洛林，把中间王国进一步拆分给东、西法兰克。","fields":[{"label":"标题","value":"加洛林帝国《梅尔森条约》"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"870年"},{"label":"地点","value":"梅尔森；洛林地区"},{"label":"主要国家","value":"东法兰克王国；西法兰克王国；法国；德意志地区；低地地区"},{"label":"一句话概括","value":"加洛林帝国《梅尔森条约》瓜分洛泰尔二世的洛林，把中间王国进一步拆分给东、西法兰克。"},{"label":"制定方/签署方","value":"日耳曼人路易与秃头查理。"},{"label":"主要内容","value":"在洛泰尔二世死后，东法兰克和西法兰克统治者瓜分洛林地区，东法兰克获得其东部和部分重要城市，西法兰克获得西部地区。"},{"label":"它试图解决什么问题","value":"它试图处理洛泰尔二世无合法继承人后中间王国的继承危机，避免洛林成为持续内战中心。"},{"label":"为什么重要","value":"它加深了加洛林帝国《凡尔登条约》后的东西分化，也让洛林成为法德之间长期争夺和身份交错的历史地带。"},{"label":"争议/局限","value":"条约没有永久解决洛林归属问题；该地区后来多次在帝国、法国、勃艮第和地方公国之间变化。"},{"label":"造成的影响","value":"中部王国进一步破碎，东法兰克获得更多莱茵—摩泽尔空间，后来神圣罗马帝国西部边界问题更复杂。"},{"label":"出处","value":"Britannica, Treaty of Mersen；Britannica, Treaty of Verdun。"}],"relationItems":["← 前因：加洛林帝国《凡尔登条约》","→ 后果：东法兰克王国","↔ 相关：洛林在法德之间的长期归属问题","↔ 同时期参考：加洛林帝国分裂"],"relations":[{"text":"← 前因：加洛林帝国《凡尔登条约》","id":"extra344"},{"text":"→ 后果：东法兰克王国","id":"extra345"},{"text":"↔ 相关：洛林在法德之间的长期归属问题","id":"extra398"}],"source":"history","id":"extra369"},{"title":"德意志部落公国","level":"B","type":"概念/思潮卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"9—10世纪形成，影响延续至中世纪盛期","place":"萨克森、巴伐利亚、士瓦本、法兰肯、洛林等地区","summary":"德意志部落公国是东法兰克王权下的区域权力结构，解释帝国长期依赖诸侯协商。","fields":[{"label":"标题","value":"德意志部落公国"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"9—10世纪形成，影响延续至中世纪盛期"},{"label":"地点","value":"萨克森、巴伐利亚、士瓦本、法兰肯、洛林等地区"},{"label":"主要国家","value":"德意志地区；神圣罗马帝国"},{"label":"一句话概括","value":"德意志部落公国是东法兰克王权下的区域权力结构，解释帝国长期依赖诸侯协商。"},{"label":"核心主张/思路","value":"“部落公国”指东法兰克王国内具有强地方认同和贵族权力的区域公国，如萨克森、巴伐利亚、士瓦本、法兰肯和洛林。"},{"label":"提出者/代表人物（可选）","value":"不是单一提出者，而是9—10世纪政治结构形成后的史学概念。"},{"label":"它从何而来","value":"加洛林帝国瓦解后，地方贵族、军事防御和区域法律习惯增强，王权需要依靠公爵维持秩序。"},{"label":"典型表现","value":"国王选举、军事动员和叛乱都与各公国贵族态度密切相关；萨克森王朝和后来的王朝都必须处理公国平衡。"},{"label":"为什么重要","value":"它说明中世纪德意志不是从中央集权国家起步，而是由多个区域权力和王权共同构成。"},{"label":"争议/局限","value":"“部落”一词容易让人误以为是原始民族共同体；实际情况是贵族权力、法律传统和区域政治的组合。"},{"label":"出处","value":"Britannica, Germany - The rise of the duchies；Britannica, Saxony；Britannica, Bavaria。"}],"relationItems":["← 前因：东法兰克王国","→ 后果：神圣罗马帝国","↔ 相关：亨利一世（捕鸟者）","↔ 相关：神圣罗马帝国《金玺诏书》"],"relations":[{"text":"← 前因：东法兰克王国","id":"extra345"},{"text":"→ 后果：神圣罗马帝国","id":"extra300"},{"text":"↔ 相关：亨利一世（捕鸟者）","id":"extra346"},{"text":"↔ 相关：神圣罗马帝国《金玺诏书》","id":"extra365"}],"source":"history","id":"extra370"},{"title":"中世纪教会克吕尼改革","level":"B","type":"概念/思潮卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"10—11世纪","place":"勃艮第克吕尼修道院及西欧修道院网络","summary":"中世纪教会克吕尼改革推动修道院摆脱地方贵族控制，为后来的教皇改革和教皇与皇帝叙任权斗争提供精神背景。","fields":[{"label":"标题","value":"中世纪教会克吕尼改革"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"10—11世纪"},{"label":"地点","value":"勃艮第克吕尼修道院及西欧修道院网络"},{"label":"主要国家","value":"法国；神圣罗马帝国；意大利；英格兰"},{"label":"一句话概括","value":"中世纪教会克吕尼改革推动修道院摆脱地方贵族控制，为后来的教皇改革和教皇与皇帝叙任权斗争提供精神背景。"},{"label":"核心主张/思路","value":"强调修道院纪律、礼仪纯洁、反对世俗贵族控制和圣职买卖，并把修道院直接置于教皇保护之下。"},{"label":"提出者/代表人物（可选）","value":"克吕尼修道院及其历任院长。"},{"label":"它从何而来","value":"中世纪早期许多修道院受地方贵族和领主支配，财产、任命和纪律都受到世俗权力影响，改革派希望恢复修道生活的独立和严格。"},{"label":"典型表现","value":"克吕尼修道院形成跨地区附属修道院网络，推广礼仪和纪律改革，并影响教会内部对腐败和世俗化的批评。"},{"label":"为什么重要","value":"它不是德国史内部事件，但为中世纪教会格里高利改革、教皇权威上升和欧洲政教冲突提供思想土壤。"},{"label":"争议/局限","value":"改革主要发生在修道院和教会精英层面，且其集中化网络也带来新的权力和财富问题。"},{"label":"出处","value":"Britannica, Cluniac Reform；Britannica, Cluny。"}],"relationItems":["→ 后果：中世纪教会格里高利改革","→ 后果：教皇与皇帝叙任权斗争","↔ 相关：奥托王朝教会体系","↔ 同时期参考：中世纪修道院文化"],"relations":[{"text":"→ 后果：中世纪教会格里高利改革","id":"extra350"},{"text":"→ 后果：教皇与皇帝叙任权斗争","id":"extra351"},{"text":"↔ 相关：奥托王朝教会体系","id":"extra349"},{"text":"↔ 同时期参考：中世纪修道院文化","id":"extra878"}],"source":"history","id":"extra371"},{"title":"神圣罗马帝国萨利安王朝","level":"B","type":"组织/机构卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1024—1125年","place":"神圣罗马帝国核心地区、意大利、罗马","summary":"神圣罗马帝国萨利安王朝统治神圣罗马帝国一个世纪，其教会政策最终卷入教皇与皇帝叙任权斗争。","fields":[{"label":"标题","value":"神圣罗马帝国萨利安王朝"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1024—1125年"},{"label":"地点","value":"神圣罗马帝国核心地区、意大利、罗马"},{"label":"主要国家","value":"神圣罗马帝国；德意志地区；意大利"},{"label":"一句话概括","value":"神圣罗马帝国萨利安王朝统治神圣罗马帝国一个世纪，其教会政策最终卷入教皇与皇帝叙任权斗争。"},{"label":"性质/类型","value":"中世纪德意志王朝和神圣罗马帝国皇帝家族。"},{"label":"成立/解散时间","value":"1024年康拉德二世当选德意志国王后开始，1125年亨利五世死后结束。"},{"label":"核心目标/宗旨","value":"维持德意志王权、控制意大利和帝国教会，并延续皇帝作为基督教世界最高世俗保护者的角色。"},{"label":"关键人物（可选）","value":"康拉德二世、亨利三世、亨利四世、亨利五世。"},{"label":"关键行动/事件","value":"加强王权和帝国教会控制，介入教皇事务，后来与改革派教皇围绕主教任命权发生冲突。"},{"label":"为什么重要","value":"萨利安时期把奥托王朝教会体系推向高峰，也把它推向危机，是理解教皇与皇帝叙任权斗争的直接制度背景。"},{"label":"争议/局限","value":"王朝并非单纯走向衰落；它在王权、法律和帝国治理上仍有建设，但政教冲突严重削弱其合法性。"},{"label":"出处","value":"Britannica, Salian Dynasty；Britannica, Henry IV；Britannica, Henry V。"}],"relationItems":["← 前因：奥托王朝教会体系","→ 后果：教皇与皇帝叙任权斗争","↔ 相关：神圣罗马皇帝亨利四世","↔ 相关：叙任权斗争《沃尔姆斯宗教协定》"],"relations":[{"text":"← 前因：奥托王朝教会体系","id":"extra349"},{"text":"→ 后果：教皇与皇帝叙任权斗争","id":"extra351"},{"text":"↔ 相关：神圣罗马皇帝亨利四世","id":"extra373"},{"text":"↔ 相关：叙任权斗争《沃尔姆斯宗教协定》","id":"extra353"}],"source":"history","id":"extra372"},{"title":"神圣罗马皇帝亨利四世","level":"B","type":"人物卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1050—1106年；1056—1105年为德意志国王，1084年加冕皇帝","place":"神圣罗马帝国、意大利、卡诺莎","summary":"亨利四世是教皇与皇帝叙任权斗争中的核心皇帝，其统治暴露中世纪皇权、教权和诸侯政治的张力。","fields":[{"label":"标题","value":"神圣罗马皇帝亨利四世"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1050—1106年；1056—1105年为德意志国王，1084年加冕皇帝"},{"label":"地点","value":"神圣罗马帝国、意大利、卡诺莎"},{"label":"主要国家","value":"神圣罗马帝国；德意志地区；意大利；教皇国"},{"label":"一句话概括","value":"亨利四世是教皇与皇帝叙任权斗争中的核心皇帝，其统治暴露中世纪皇权、教权和诸侯政治的张力。"},{"label":"生卒年/活跃年代","value":"1050—1106年。"},{"label":"身份/职务","value":"神圣罗马帝国萨利安王朝德意志国王、神圣罗马皇帝。"},{"label":"关键贡献/作为","value":"坚持皇帝任命主教的传统权力，与教皇格里高利七世激烈冲突；在被绝罚后赴卡诺莎求赦，又继续与教皇和德意志诸侯斗争。"},{"label":"核心主张/立场","value":"强调皇帝在帝国教会和主教任命中的传统权威，认为教皇无权废黜皇帝。"},{"label":"为什么重要","value":"他把教皇与皇帝叙任权斗争从教会改革争议变成帝国政治危机，亨利四世卡诺莎之行也成为欧洲政治象征。"},{"label":"争议/评价","value":"他既被视为维护皇权者，也因与诸侯和教皇长期冲突而被认为削弱了帝国稳定。"},{"label":"关联事件（可选）","value":"教皇与皇帝叙任权斗争；亨利四世卡诺莎之行；叙任权斗争《沃尔姆斯宗教协定》。"},{"label":"出处","value":"Britannica, Henry IV；Britannica, Investiture Controversy。"}],"relationItems":["← 前因：神圣罗马帝国萨利安王朝","↔ 相关：教皇与皇帝叙任权斗争","↔ 相关：亨利四世卡诺莎之行","↔ 相关：中世纪教会格里高利改革"],"relations":[{"text":"← 前因：神圣罗马帝国萨利安王朝","id":"extra372"},{"text":"↔ 相关：教皇与皇帝叙任权斗争","id":"extra351"},{"text":"↔ 相关：亨利四世卡诺莎之行","id":"extra352"},{"text":"↔ 相关：中世纪教会格里高利改革","id":"extra350"}],"source":"history","id":"extra373"},{"title":"《萨克森明镜》","level":"C","type":"制度/文本卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"约1220—1235年","place":"萨克森地区","summary":"《萨克森明镜》是中世纪德语法律书，整理习惯法并影响北德和中东欧法律文化。","fields":[{"label":"标题","value":"《萨克森明镜》"},{"label":"分级","value":"C"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"约1220—1235年"},{"label":"地点","value":"萨克森地区"},{"label":"主要国家","value":"德意志地区；神圣罗马帝国"},{"label":"一句话概括","value":"《萨克森明镜》是中世纪德语法律书，整理习惯法并影响北德和中东欧法律文化。"},{"label":"制定方/签署方","value":"通常归于艾克·冯·雷普高整理，不是现代国家颁布的成文法典。"},{"label":"主要内容","value":"以德语记录萨克森地区的土地法和封建法，涉及财产、继承、司法、等级义务、领主与附庸关系等。"},{"label":"它试图解决什么问题","value":"它把口传和地方习惯法整理成较稳定文本，方便贵族、法庭和城市社群理解法律规则。"},{"label":"为什么重要","value":"它是中世纪德语法律文化的重要文本，说明德意志地区的法律发展长期依赖地方习惯、等级关系和法律书传统。"},{"label":"争议/局限","value":"它不是统一帝国法，也包含中世纪等级和身份不平等；不同地区使用和改写方式差异很大。"},{"label":"造成的影响","value":"其内容和法律语言影响北德、东德和部分中东欧地区的司法实践，与中世纪马格德堡法等城市法传统相互呼应。"},{"label":"出处","value":"Britannica, Sachsenspiegel；Oxford Reference, Sachsenspiegel。"}],"relationItems":["↔ 相关：中世纪马格德堡法","↔ 相关：德意志东向殖民","↔ 相关：德意志部落公国","↔ 同时期参考：中世纪习惯法"],"relations":[{"text":"↔ 相关：中世纪马格德堡法","id":"extra361"},{"text":"↔ 相关：德意志东向殖民","id":"extra360"},{"text":"↔ 相关：德意志部落公国","id":"extra370"}],"source":"history","id":"extra374"},{"title":"神圣罗马皇帝腓特烈二世","level":"B","type":"人物卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1194—1250年；1212年起为德意志国王，1220年加冕皇帝","place":"西西里、神圣罗马帝国、意大利、耶路撒冷","summary":"腓特烈二世把霍亨斯陶芬帝国推向地中海和意大利重心，也加深皇帝与教皇的冲突。","fields":[{"label":"标题","value":"神圣罗马皇帝腓特烈二世"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1194—1250年；1212年起为德意志国王，1220年加冕皇帝"},{"label":"地点","value":"西西里、神圣罗马帝国、意大利、耶路撒冷"},{"label":"主要国家","value":"神圣罗马帝国；德意志地区；意大利；西西里王国"},{"label":"一句话概括","value":"腓特烈二世把霍亨斯陶芬帝国推向地中海和意大利重心，也加深皇帝与教皇的冲突。"},{"label":"生卒年/活跃年代","value":"1194—1250年。"},{"label":"身份/职务","value":"西西里国王、德意志国王、神圣罗马皇帝。"},{"label":"关键贡献/作为","value":"以西西里为权力基地，改革西西里王国行政，参与十字军并通过外交取得耶路撒冷，同时与教皇和意大利城市长期冲突。"},{"label":"核心主张/立场","value":"强调皇帝在意大利和西西里的世俗权威，试图把法律化行政和帝国权威结合。"},{"label":"为什么重要","value":"他是中世纪皇权最复杂的人物之一，显示神圣罗马皇帝可以是德意志、意大利和地中海多重政治的交汇点。"},{"label":"争议/评价","value":"后世称其为“世界惊奇”，但他的跨区域帝国也消耗德意志王权基础，并在死后引发权力真空。"},{"label":"关联事件（可选）","value":"神圣罗马帝国霍亨斯陶芬王朝；布汶战役；神圣罗马帝国大空位时期。"},{"label":"出处","value":"Britannica, Frederick II；Britannica, Hohenstaufen Dynasty。"}],"relationItems":["← 前因：神圣罗马帝国霍亨斯陶芬王朝","→ 后果：神圣罗马帝国大空位时期","↔ 相关：中世纪欧洲布汶战役","↔ 同时期参考：第五次和第六次十字军"],"relations":[{"text":"← 前因：神圣罗马帝国霍亨斯陶芬王朝","id":"extra354"},{"text":"→ 后果：神圣罗马帝国大空位时期","id":"extra376"},{"text":"↔ 相关：中世纪欧洲布汶战役","id":"extra359"}],"source":"history","id":"extra375"},{"title":"神圣罗马帝国大空位时期","level":"B","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1254/1256—1273年","place":"神圣罗马帝国","summary":"大空位时期是霍亨斯陶芬衰落后的王权真空，凸显神圣罗马帝国诸侯化和选举政治。","fields":[{"label":"标题","value":"神圣罗马帝国大空位时期"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1254/1256—1273年"},{"label":"地点","value":"神圣罗马帝国"},{"label":"主要国家","value":"神圣罗马帝国；德意志地区；意大利"},{"label":"一句话概括","value":"大空位时期是霍亨斯陶芬衰落后的王权真空，凸显神圣罗马帝国诸侯化和选举政治。"},{"label":"参与者","value":"德意志选侯和诸侯、不同王位候选人、教皇、外国王室。"},{"label":"发生了什么","value":"神圣罗马帝国霍亨斯陶芬王朝衰落后，帝国出现长期缺乏有效皇帝和统一王权的局面。多个候选人获得部分诸侯支持，但很难真正控制帝国整体。1273年鲁道夫一世当选德意志国王后，这一长期混乱才结束。"},{"label":"为什么重要","value":"它说明神圣罗马帝国的皇位越来越依赖选侯和诸侯协商，而不是稳定世袭王权。"},{"label":"前因","value":"腓特烈二世与教皇和意大利势力长期冲突，霍亨斯陶芬继承体系瓦解；帝国诸侯在王权衰弱中扩大自治。"},{"label":"后果","value":"鲁道夫一世当选后重建一定秩序，但帝国中央权力已难恢复到霍亨斯陶芬高峰；哈布斯堡家族也由此进入帝国核心舞台。"},{"label":"出处","value":"Britannica, Great Interregnum；Britannica, Rudolph I。"}],"relationItems":["← 前因：神圣罗马皇帝腓特烈二世","→ 后果：鲁道夫一世与哈布斯堡崛起","↔ 相关：神圣罗马帝国《金玺诏书》","↔ 相关：神圣罗马帝国"],"relations":[{"text":"← 前因：神圣罗马皇帝腓特烈二世","id":"extra375"},{"text":"→ 后果：鲁道夫一世与哈布斯堡崛起","id":"extra377"},{"text":"↔ 相关：神圣罗马帝国《金玺诏书》","id":"extra365"},{"text":"↔ 相关：神圣罗马帝国","id":"extra300"}],"source":"history","id":"extra376"},{"title":"鲁道夫一世与哈布斯堡崛起","level":"B","type":"人物卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1218—1291年；1273—1291年为德意志国王","place":"神圣罗马帝国、奥地利、波希米亚边境","summary":"鲁道夫一世结束大空位并取得奥地利，为哈布斯堡家族长期崛起打下基础。","fields":[{"label":"标题","value":"鲁道夫一世与哈布斯堡崛起"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1218—1291年；1273—1291年为德意志国王"},{"label":"地点","value":"神圣罗马帝国、奥地利、波希米亚边境"},{"label":"主要国家","value":"神圣罗马帝国；奥地利；捷克；德意志地区"},{"label":"一句话概括","value":"鲁道夫一世结束大空位并取得奥地利，为哈布斯堡家族长期崛起打下基础。"},{"label":"生卒年/活跃年代","value":"1218—1291年。"},{"label":"身份/职务","value":"哈布斯堡伯爵、德意志国王。"},{"label":"关键贡献/作为","value":"1273年被选为德意志国王，结束大空位；随后与波希米亚国王奥托卡二世冲突，并在1278年取得决定性胜利。"},{"label":"核心主张/立场","value":"以恢复帝国秩序和追回被占帝国领地为名，扩大哈布斯堡家族在奥地利的世袭基础。"},{"label":"为什么重要","value":"他不是最有名的皇帝，却是哈布斯堡崛起的关键人物；奥地利成为哈布斯堡长期权力核心。"},{"label":"争议/评价","value":"鲁道夫未能恢复强中央皇权，但成功把王权机会转化为家族领地扩张。"},{"label":"关联事件（可选）","value":"神圣罗马帝国大空位时期；哈布斯堡崛起马尔希菲尔德战役。"},{"label":"出处","value":"Britannica, Rudolph I；Britannica, Habsburg Dynasty。"}],"relationItems":["← 前因：神圣罗马帝国大空位时期","→ 后果：哈布斯堡崛起马尔希菲尔德战役","↔ 相关：哈布斯堡君主国","↔ 相关：奥地利与普鲁士二元主义"],"relations":[{"text":"← 前因：神圣罗马帝国大空位时期","id":"extra376"},{"text":"→ 后果：哈布斯堡崛起马尔希菲尔德战役","id":"extra378"},{"text":"↔ 相关：哈布斯堡君主国","id":"extra309"},{"text":"↔ 相关：奥地利与普鲁士二元主义","id":"extra535"}],"source":"history","id":"extra377"},{"title":"哈布斯堡崛起马尔希菲尔德战役","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1278年8月26日","place":"杜恩克鲁特附近马尔希菲尔德，今奥地利东北部","summary":"鲁道夫一世击败波希米亚国王奥托卡二世，哈布斯堡由此取得奥地利核心领地。","fields":[{"label":"标题","value":"哈布斯堡崛起马尔希菲尔德战役"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1278年8月26日"},{"label":"地点","value":"杜恩克鲁特附近马尔希菲尔德，今奥地利东北部"},{"label":"主要国家","value":"神圣罗马帝国；奥地利；捷克；匈牙利"},{"label":"一句话概括","value":"鲁道夫一世击败波希米亚国王奥托卡二世，哈布斯堡由此取得奥地利核心领地。"},{"label":"参与者","value":"鲁道夫一世、波希米亚国王奥托卡二世、匈牙利盟军、奥地利和波希米亚贵族。"},{"label":"发生了什么","value":"奥托卡二世在大空位时期控制奥地利等地区，鲁道夫一世当选后要求其交还帝国领地。双方冲突升级，1278年在马尔希菲尔德交战，奥托卡二世战败阵亡，鲁道夫取得对奥地利的实际控制。"},{"label":"为什么重要","value":"这场战役让哈布斯堡从地方伯爵家族跃升为奥地利统治者，改变中欧长期权力结构。"},{"label":"前因","value":"大空位时期帝国权威弱化，奥托卡二世扩张到奥地利；鲁道夫一世需要用恢复帝国权利来巩固新王权并扩大哈布斯堡基础。"},{"label":"后果","value":"奥地利成为哈布斯堡家族核心领地，哈布斯堡由地方伯爵家族转向中欧王朝大族；这一领地基础后来发展为哈布斯堡君主国，并成为欧洲大国政治的重要支点。"},{"label":"出处","value":"Britannica, Rudolph I；Britannica, Habsburg Dynasty。"}],"relationItems":["← 前因：鲁道夫一世与哈布斯堡崛起","→ 后果：哈布斯堡君主国","↔ 相关：神圣罗马帝国大空位时期","↔ 同时期参考：中欧王朝竞争"],"relations":[{"text":"← 前因：鲁道夫一世与哈布斯堡崛起","id":"extra377"},{"text":"→ 后果：哈布斯堡君主国","id":"extra309"},{"text":"↔ 相关：神圣罗马帝国大空位时期","id":"extra376"}],"source":"history","id":"extra378"},{"title":"旧瑞士永久同盟","level":"B","type":"制度/文本卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1291年","place":"乌里、施维茨、下瓦尔登","summary":"1291年瑞士三地结盟被视为瑞士邦联传统起点，反映阿尔卑斯地方自治与哈布斯堡压力。","fields":[{"label":"标题","value":"旧瑞士永久同盟"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1291年"},{"label":"地点","value":"乌里、施维茨、下瓦尔登"},{"label":"主要国家","value":"瑞士；神圣罗马帝国；奥地利"},{"label":"一句话概括","value":"1291年瑞士三地结盟被视为瑞士邦联传统起点，反映阿尔卑斯地方自治与哈布斯堡压力。"},{"label":"制定方/签署方","value":"乌里、施维茨和下瓦尔登三个森林州代表。"},{"label":"主要内容","value":"三地约定相互援助、共同维护传统权利、抵抗外来司法和暴力侵害，并在争议时通过共同协商处理。"},{"label":"它试图解决什么问题","value":"它试图在哈布斯堡等外部领主压力上升时保护地方自治、山地通道利益和共同安全。"},{"label":"为什么重要","value":"它是瑞士邦联传统的标志性起点，也说明神圣罗马帝国内部存在大量地方共同体和自治政治。"},{"label":"争议/局限","value":"1291文件在后世民族叙事中被高度象征化；早期同盟仍处于帝国框架内，不等于现代瑞士国家立即诞生。"},{"label":"造成的影响","value":"森林州同盟为后来瑞士邦联扩展提供政治记忆和制度样本，并与哈布斯堡发生长期冲突。"},{"label":"出处","value":"Britannica, Switzerland - Origins of the Confederation；Swiss Federal Archives, Federal Charter of 1291。"}],"relationItems":["→ 后果：瑞士-哈布斯堡莫尔加滕战役","↔ 相关：哈布斯堡君主国","↔ 相关：神圣罗马帝国","↔ 同时期参考：中世纪地方自治"],"relations":[{"text":"→ 后果：瑞士-哈布斯堡莫尔加滕战役","id":"extra380"},{"text":"↔ 相关：哈布斯堡君主国","id":"extra309"},{"text":"↔ 相关：神圣罗马帝国","id":"extra300"}],"source":"history","id":"extra379"},{"title":"瑞士-哈布斯堡莫尔加滕战役","level":"C","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1315年11月15日","place":"瑞士莫尔加滕附近","summary":"瑞士森林州在莫尔加滕击败哈布斯堡军队，巩固早期邦联的自治声望。","fields":[{"label":"标题","value":"瑞士-哈布斯堡莫尔加滕战役"},{"label":"分级","value":"C"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1315年11月15日"},{"label":"地点","value":"瑞士莫尔加滕附近"},{"label":"主要国家","value":"瑞士；奥地利；神圣罗马帝国"},{"label":"一句话概括","value":"瑞士森林州在莫尔加滕击败哈布斯堡军队，巩固早期邦联的自治声望。"},{"label":"参与者","value":"乌里、施维茨、下瓦尔登同盟民兵，哈布斯堡公爵利奥波德一世的军队。"},{"label":"发生了什么","value":"1315年，哈布斯堡军队试图压制施维茨等森林州的反抗。瑞士同盟民兵利用山地地形伏击并击败哈布斯堡部队，随后三州重申同盟关系。"},{"label":"为什么重要","value":"它在瑞士历史记忆中象征山地自治共同体击败贵族骑士军队，也显示帝国内部地方共同体可以通过军事合作维护特权。"},{"label":"前因","value":"瑞士森林州希望维护地方自治和帝国直属权利，哈布斯堡则试图扩展在阿尔卑斯通道和周边地区的领主控制。"},{"label":"后果","value":"瑞士早期邦联凝聚力增强，森林州把胜利转化为共同体自治的政治记忆；与哈布斯堡的长期冲突继续发展，后来更多城市和乡村共同体加入邦联。"},{"label":"出处","value":"Britannica, Switzerland - The early Confederation；Britannica, Leopold I of Austria。"}],"relationItems":["← 前因：旧瑞士永久同盟","↔ 相关：哈布斯堡君主国","↔ 相关：哈布斯堡崛起马尔希菲尔德战役","↔ 同时期参考：中世纪步兵战术变化"],"relations":[{"text":"← 前因：旧瑞士永久同盟","id":"extra379"},{"text":"↔ 相关：哈布斯堡君主国","id":"extra309"},{"text":"↔ 相关：哈布斯堡崛起马尔希菲尔德战役","id":"extra378"}],"source":"history","id":"extra380"},{"title":"查理四世与布拉格宫廷","level":"B","type":"人物卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1316—1378年；1346年为罗马人的国王，1355年加冕皇帝","place":"布拉格、波希米亚、神圣罗马帝国","summary":"查理四世把帝国政治重心部分转向布拉格，并用神圣罗马帝国《金玺诏书》制度化选侯秩序。","fields":[{"label":"标题","value":"查理四世与布拉格宫廷"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1316—1378年；1346年为罗马人的国王，1355年加冕皇帝"},{"label":"地点","value":"布拉格、波希米亚、神圣罗马帝国"},{"label":"主要国家","value":"捷克；神圣罗马帝国；德意志地区"},{"label":"一句话概括","value":"查理四世把帝国政治重心部分转向布拉格，并用神圣罗马帝国《金玺诏书》制度化选侯秩序。"},{"label":"生卒年/活跃年代","value":"1316—1378年。"},{"label":"身份/职务","value":"卢森堡王朝波希米亚国王、罗马人的国王、神圣罗马皇帝。"},{"label":"关键贡献/作为","value":"建设布拉格为帝国文化和政治中心，1348年创办布拉格大学，1356年颁布神圣罗马帝国《金玺诏书》。"},{"label":"核心主张/立场","value":"通过王朝领地建设、城市文化赞助和法律制度化来巩固皇权，而不是单纯依赖意大利军事远征。"},{"label":"为什么重要","value":"他让波希米亚成为帝国核心之一，说明神圣罗马帝国并不只是“德国本土”结构，而是中欧复合政治秩序。"},{"label":"争议/评价","value":"查理四世强化了波希米亚和选侯秩序，但神圣罗马帝国《金玺诏书》也进一步承认帝国分权。"},{"label":"关联事件（可选）","value":"神圣罗马帝国《金玺诏书》；中欧布拉格大学成立；波希米亚胡斯战争。"},{"label":"出处","value":"Britannica, Charles IV；Britannica, Golden Bull of Emperor Charles IV。"}],"relationItems":["→ 后果：中欧布拉格大学成立","→ 后果：神圣罗马帝国《金玺诏书》","↔ 相关：神圣罗马帝国","↔ 相关：波希米亚胡斯战争"],"relations":[{"text":"→ 后果：中欧布拉格大学成立","id":"extra382"},{"text":"→ 后果：神圣罗马帝国《金玺诏书》","id":"extra365"},{"text":"↔ 相关：神圣罗马帝国","id":"extra300"},{"text":"↔ 相关：波希米亚胡斯战争","id":"extra366"}],"source":"history","id":"extra381"},{"title":"中欧布拉格大学成立","level":"B","type":"事件卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1348年","place":"布拉格","summary":"查理四世创办布拉格大学，使布拉格成为中欧学术中心，并影响波希米亚宗教改革土壤。","fields":[{"label":"标题","value":"中欧布拉格大学成立"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1348年"},{"label":"地点","value":"布拉格"},{"label":"主要国家","value":"捷克；神圣罗马帝国；德意志地区"},{"label":"一句话概括","value":"查理四世创办布拉格大学，使布拉格成为中欧学术中心，并影响波希米亚宗教改革土壤。"},{"label":"参与者","value":"查理四世、教皇克莱孟六世、布拉格神职人员、来自波希米亚和帝国各地的学生与教师。"},{"label":"发生了什么","value":"1348年，查理四世在布拉格创办大学，这是中欧最早的重要大学之一。大学吸引德语、捷克语和其他地区学者，成为神学、法律、医学和文艺教育中心。"},{"label":"为什么重要","value":"它把布拉格提升为帝国文化中心，也为后来波希米亚宗教争论和胡斯运动提供知识制度环境。"},{"label":"前因","value":"查理四世希望把波希米亚王国和布拉格建设为帝国核心，而大学能够为王权提供官僚、神职人员、法律人才和文化声望；中欧也需要本地高等教育机构来减少对巴黎、博洛尼亚等地的依赖。"},{"label":"后果","value":"布拉格大学成为中欧知识网络节点，民族和教义冲突也在大学内部积累，最终与胡斯改革运动发生联系。"},{"label":"出处","value":"Britannica, Charles IV；Charles University, History；Britannica, Prague。"}],"relationItems":["← 前因：查理四世与布拉格宫廷","→ 后果：波希米亚胡斯战争","↔ 相关：神圣罗马帝国《金玺诏书》","↔ 同时期参考：中世纪大学"],"relations":[{"text":"← 前因：查理四世与布拉格宫廷","id":"extra381"},{"text":"→ 后果：波希米亚胡斯战争","id":"extra366"},{"text":"↔ 相关：神圣罗马帝国《金玺诏书》","id":"extra365"},{"text":"↔ 同时期参考：中世纪大学","id":"extra879"}],"source":"history","id":"extra382"},{"title":"天主教康斯坦茨会议","level":"B","type":"事件卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1414—1418年","place":"康斯坦茨","summary":"康斯坦茨会议结束西方教会大分裂，却处死胡斯并加剧波希米亚宗教冲突。","fields":[{"label":"标题","value":"天主教康斯坦茨会议"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1414—1418年"},{"label":"地点","value":"康斯坦茨"},{"label":"主要国家","value":"神圣罗马帝国；教皇国；捷克；法国；英格兰"},{"label":"一句话概括","value":"康斯坦茨会议结束西方教会大分裂，却处死胡斯并加剧波希米亚宗教冲突。"},{"label":"参与者","value":"教皇和枢机主教、皇帝西吉斯蒙德、欧洲主教和神学家、扬·胡斯。"},{"label":"发生了什么","value":"1414年起，康斯坦茨会议召开，试图解决多个教皇并立的西方教会大分裂。会议废黜或接受辞职的竞争教皇，并选出马丁五世；同时审判并处死捷克改革者扬·胡斯。"},{"label":"为什么重要","value":"它是公会议主义高峰，也是宗教改革前欧洲教会危机的集中表现。它恢复教皇统一，却未能化解教会改革诉求。"},{"label":"前因","value":"西方教会大分裂削弱教皇权威，欧洲统治者和教会精英需要通过大公会议恢复统一；胡斯等改革者则挑战教会腐败和权威结构。"},{"label":"后果","value":"西方教会在名义上重新统一，但深层改革问题没有解决；胡斯被处死激化波希米亚反抗，使大学争论和教会批评转化为地方政治动员，1419年后爆发波希米亚胡斯战争。"},{"label":"出处","value":"Britannica, Council of Constance；Britannica, Western Schism；Britannica, Jan Hus。"}],"relationItems":["→ 后果：波希米亚胡斯战争","↔ 相关：中世纪天主教公会议主义","↔ 相关：中欧布拉格大学成立","↔ 同时期参考：西方教会大分裂"],"relations":[{"text":"→ 后果：波希米亚胡斯战争","id":"extra366"},{"text":"↔ 相关：中世纪天主教公会议主义","id":"extra384"},{"text":"↔ 相关：中欧布拉格大学成立","id":"extra382"},{"text":"↔ 同时期参考：西方教会大分裂","id":"extra880"}],"source":"history","id":"extra383"},{"title":"中世纪天主教公会议主义","level":"C","type":"概念/思潮卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"14—15世纪，康斯坦茨会议时期达到高峰","place":"西欧教会和大学知识圈","summary":"公会议主义主张大公会议可高于教皇，是中世纪晚期教会危机中的制度改革思想。","fields":[{"label":"标题","value":"中世纪天主教公会议主义"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"14—15世纪，康斯坦茨会议时期达到高峰"},{"label":"地点","value":"西欧教会和大学知识圈"},{"label":"主要国家","value":"神圣罗马帝国；教皇国；法国；英格兰"},{"label":"一句话概括","value":"公会议主义主张大公会议可高于教皇，是中世纪晚期教会危机中的制度改革思想。"},{"label":"核心主张/思路","value":"当教皇权威陷入危机时，代表整个教会的大公会议可以拥有高于教皇的权威，并有权解决分裂和推动改革。"},{"label":"提出者/代表人物（可选）","value":"让·热尔松、皮埃尔·达伊等神学家和教会法学家。"},{"label":"它从何而来","value":"西方教会大分裂造成多个教皇并立，单靠教皇权威无法解决危机，大学神学家和君主政治需要新的合法性机制。"},{"label":"典型表现","value":"比萨会议、康斯坦茨会议和巴塞尔会议围绕教会最高权威、改革和教皇限制展开争论。"},{"label":"为什么重要","value":"它说明中世纪晚期已经出现用代表会议约束最高权威的思想，对教会政治和欧洲宪制想象都有影响。"},{"label":"争议/局限","value":"公会议主义最终未能长期压倒教皇制度；它的代表性也主要限于教会精英，而非现代民主代表。"},{"label":"出处","value":"Britannica, Conciliarism；Britannica, Council of Constance。"}],"relationItems":["← 前因：天主教康斯坦茨会议","↔ 相关：中世纪教会格里高利改革","↔ 相关：欧洲宗教改革","↔ 同时期参考：西方教会大分裂"],"relations":[{"text":"← 前因：天主教康斯坦茨会议","id":"extra383"},{"text":"↔ 相关：中世纪教会格里高利改革","id":"extra350"},{"text":"↔ 相关：欧洲宗教改革","id":"extra301"},{"text":"↔ 同时期参考：西方教会大分裂","id":"extra880"}],"source":"history","id":"extra384"},{"title":"约翰内斯·罗伊希林","level":"C","type":"人物卡","tags":["文化与思想"],"mainTag":"文化与思想","subTag":"","timeText":"1455—1522年","place":"神圣罗马帝国西南部、普福尔茨海姆、蒂宾根等地","summary":"罗伊希林是德意志人文主义者和希伯来学者，其护书争论预示宗教改革前的知识冲突。","fields":[{"label":"标题","value":"约翰内斯·罗伊希林"},{"label":"分级","value":"C"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"文化与思想"},{"label":"时间","value":"1455—1522年"},{"label":"地点","value":"神圣罗马帝国西南部、普福尔茨海姆、蒂宾根等地"},{"label":"主要国家","value":"德意志地区；神圣罗马帝国"},{"label":"一句话概括","value":"罗伊希林是德意志人文主义者和希伯来学者，其护书争论预示宗教改革前的知识冲突。"},{"label":"生卒年/活跃年代","value":"1455—1522年。"},{"label":"身份/职务","value":"德意志人文主义者、法学家、希伯来语学者。"},{"label":"关键贡献/作为","value":"推动希腊语和希伯来语学习，反对约翰内斯·普费弗科恩焚毁犹太书籍的主张，成为欧洲人文主义护学争论焦点。"},{"label":"核心主张/立场","value":"主张通过原典语言理解圣经和古代知识，认为犹太文献不应被简单销毁。"},{"label":"为什么重要","value":"他体现宗教改革前德意志人文主义的知识取向：回到原典、批评经院权威，并通过印刷舆论扩大争论。"},{"label":"争议/评价","value":"罗伊希林并非现代宗教宽容主义者，但他反对粗暴禁毁文献，推动希伯来学进入基督教学术。"},{"label":"关联事件（可选）","value":"欧洲宗教改革；古腾堡活字印刷革命。"},{"label":"出处","value":"Britannica, Johann Reuchlin；Britannica, Humanism。"}],"relationItems":["← 前因：加洛林文艺复兴","→ 后果：欧洲宗教改革","↔ 相关：古腾堡活字印刷革命","↔ 相关：马丁·路德发表《九十五条论纲》"],"relations":[{"text":"← 前因：加洛林文艺复兴","id":"extra368"},{"text":"→ 后果：欧洲宗教改革","id":"extra301"},{"text":"↔ 相关：古腾堡活字印刷革命","id":"extra299"},{"text":"↔ 相关：马丁·路德发表《九十五条论纲》","id":"extra302"}],"source":"history","id":"extra385"},{"title":"马克西米利安一世","level":"B","type":"人物卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1459—1519年；1493—1519年为罗马人的国王，1508年称皇帝","place":"神圣罗马帝国、奥地利、勃艮第、意大利","summary":"马克西米利安一世通过婚姻、战争和帝国改革扩大哈布斯堡影响，被称为近代哈布斯堡崛起关键人物。","fields":[{"label":"标题","value":"马克西米利安一世"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1459—1519年；1493—1519年为罗马人的国王，1508年称皇帝"},{"label":"地点","value":"神圣罗马帝国、奥地利、勃艮第、意大利"},{"label":"主要国家","value":"神圣罗马帝国；奥地利；德意志地区；低地地区"},{"label":"一句话概括","value":"马克西米利安一世通过婚姻、战争和帝国改革扩大哈布斯堡影响，被称为近代哈布斯堡崛起关键人物。"},{"label":"生卒年/活跃年代","value":"1459—1519年。"},{"label":"身份/职务","value":"哈布斯堡王朝罗马人的国王、神圣罗马皇帝。"},{"label":"关键贡献/作为","value":"通过与勃艮第的玛丽联姻获得低地和勃艮第遗产，推动1495年沃尔姆斯帝国改革，并安排哈布斯堡王朝婚姻战略。"},{"label":"核心主张/立场","value":"希望强化帝国秩序和哈布斯堡家族地位，但需要在诸侯权利、财政限制和欧洲战争之间妥协。"},{"label":"为什么重要","value":"他连接中世纪帝国改革和近代哈布斯堡世界帝国扩张，是查理五世继承广大领地的直接前提。"},{"label":"争议/评价","value":"改革常被称为“帝国改革”，但实际效果有限；他更成功的是家族王朝扩张而非建立强中央帝国。"},{"label":"关联事件（可选）","value":"沃尔姆斯帝国改革；查理五世当选神圣罗马皇帝。"},{"label":"出处","value":"Britannica, Maximilian I；Britannica, Habsburg Dynasty。"}],"relationItems":["→ 后果：沃尔姆斯帝国改革","→ 后果：查理五世当选神圣罗马皇帝","↔ 相关：哈布斯堡君主国","↔ 相关：神圣罗马帝国《金玺诏书》"],"relations":[{"text":"→ 后果：沃尔姆斯帝国改革","id":"extra387"},{"text":"→ 后果：查理五世当选神圣罗马皇帝","id":"extra390"},{"text":"↔ 相关：哈布斯堡君主国","id":"extra309"},{"text":"↔ 相关：神圣罗马帝国《金玺诏书》","id":"extra365"}],"source":"history","id":"extra386"},{"title":"沃尔姆斯帝国改革","level":"B","type":"事件卡","tags":["政治与制度"],"mainTag":"政治与制度","subTag":"","timeText":"1495年","place":"路德案沃尔姆斯帝国议会","summary":"1495年路德案沃尔姆斯帝国议会推动永久治安、帝国法院和财政改革，试图治理帝国分权困境。","fields":[{"label":"标题","value":"沃尔姆斯帝国改革"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"时间","value":"1495年"},{"label":"地点","value":"路德案沃尔姆斯帝国议会"},{"label":"主要国家","value":"神圣罗马帝国；德意志地区；奥地利"},{"label":"一句话概括","value":"1495年路德案沃尔姆斯帝国议会推动永久治安、帝国法院和财政改革，试图治理帝国分权困境。"},{"label":"参与者","value":"马克西米利安一世、帝国诸侯、选侯、帝国城市代表。"},{"label":"发生了什么","value":"1495年路德案沃尔姆斯帝国议会通过一系列改革安排，包括宣布永久禁止私人复仇战争、建立神圣罗马帝国最高法院、讨论帝国税收和共同防御机制。改革试图把帝国内部冲突从私战和地方暴力转向法律和帝国公共秩序。"},{"label":"为什么重要","value":"它是神圣罗马帝国从中世纪向近代早期治理转型的关键尝试，说明帝国不是没有制度，而是以协商、法庭和诸侯合作维系秩序。"},{"label":"前因","value":"帝国内部私战、诸侯割据和财政军事实力不足长期困扰皇帝；马克西米利安一世需要诸侯支持来应对法国、奥斯曼和意大利战争压力。"},{"label":"后果","value":"神圣罗马帝国最高法院等制度逐渐运转，但帝国税收和军事整合仍受诸侯制约，神圣罗马帝国行政圈等后续安排继续补充改革。"},{"label":"出处","value":"Britannica, Maximilian I；Britannica, Reichskammergericht；Britannica, Holy Roman Empire。"}],"relationItems":["← 前因：马克西米利安一世","→ 后果：神圣罗马帝国最高法院","→ 后果：神圣罗马帝国行政圈","↔ 相关：神圣罗马帝国"],"relations":[{"text":"← 前因：马克西米利安一世","id":"extra386"},{"text":"→ 后果：神圣罗马帝国最高法院","id":"extra388"},{"text":"→ 后果：神圣罗马帝国行政圈","id":"extra389"},{"text":"↔ 相关：神圣罗马帝国","id":"extra300"}],"source":"history","id":"extra387"},{"title":"神圣罗马帝国最高法院","level":"B","type":"组织/机构卡","tags":["政治与制度"],"mainTag":"政治与制度","subTag":"","timeText":"1495—1806年","place":"最初设于法兰克福等地，后长期在施派尔和韦茨拉尔","summary":"神圣罗马帝国最高法院是神圣罗马帝国重要司法机构，试图用法律程序替代诸侯私战。","fields":[{"label":"标题","value":"神圣罗马帝国最高法院"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"时间","value":"1495—1806年"},{"label":"地点","value":"最初设于法兰克福等地，后长期在施派尔和韦茨拉尔"},{"label":"主要国家","value":"神圣罗马帝国；德意志地区"},{"label":"一句话概括","value":"神圣罗马帝国最高法院是神圣罗马帝国重要司法机构，试图用法律程序替代诸侯私战。"},{"label":"性质/类型","value":"神圣罗马帝国最高司法机构之一。"},{"label":"成立/解散时间","value":"1495年沃尔姆斯帝国改革中设立，1806年随神圣罗马帝国解体而终结。"},{"label":"核心目标/宗旨","value":"处理帝国等级、城市、诸侯和臣民之间的法律争议，维护永久治安和帝国公共秩序。"},{"label":"关键人物（可选）","value":"皇帝、帝国等级和职业法官共同影响法院构成。"},{"label":"关键行动/事件","value":"受理领地争端、财产权、帝国直属地位和司法上诉等案件，成为帝国法文化的重要中心。"},{"label":"为什么重要","value":"它说明神圣罗马帝国并非纯粹松散无序，而是依靠法律化和多中心机构维持长期秩序。"},{"label":"争议/局限","value":"法院程序常很慢，执行依赖诸侯合作；它不能变成现代中央国家式司法权。"},{"label":"出处","value":"Britannica, Reichskammergericht；Britannica, Maximilian I。"}],"relationItems":["← 前因：沃尔姆斯帝国改革","↔ 相关：神圣罗马帝国行政圈","↔ 相关：神圣罗马帝国","↔ 同时期参考：近代早期法制化"],"relations":[{"text":"← 前因：沃尔姆斯帝国改革","id":"extra387"},{"text":"↔ 相关：神圣罗马帝国行政圈","id":"extra389"},{"text":"↔ 相关：神圣罗马帝国","id":"extra300"}],"source":"history","id":"extra388"},{"title":"神圣罗马帝国行政圈","level":"C","type":"制度/文本卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1500年初设，1512年扩展定型","place":"神圣罗马帝国各地区","summary":"神圣罗马帝国行政圈把帝国地区分组，以便征税、防务和执行法律，是分权帝国的协调工具。","fields":[{"label":"标题","value":"神圣罗马帝国行政圈"},{"label":"分级","value":"C"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1500年初设，1512年扩展定型"},{"label":"地点","value":"神圣罗马帝国各地区"},{"label":"主要国家","value":"神圣罗马帝国；德意志地区；奥地利；捷克部分地区"},{"label":"一句话概括","value":"神圣罗马帝国行政圈把帝国地区分组，以便征税、防务和执行法律，是分权帝国的协调工具。"},{"label":"制定方/签署方","value":"帝国议会和皇帝在1500年后逐步形成的区域组织安排。"},{"label":"主要内容","value":"把帝国领地划分为若干行政圈，由各圈内部协调征税、治安、防务和帝国法院判决执行等事务。"},{"label":"它试图解决什么问题","value":"神圣罗马帝国缺乏统一中央行政，神圣罗马帝国行政圈试图在不取消诸侯自治的情况下建立区域协作机制。"},{"label":"为什么重要","value":"它体现近代早期帝国治理的实际逻辑：不是中央集权，而是通过区域分组、法律义务和等级协商管理复杂领地。"},{"label":"争议/局限","value":"行政圈权力不均，哈布斯堡世袭领地和部分边疆地区适用有限，执行效果取决于地方合作。"},{"label":"造成的影响","value":"帝国在财政、防务和法律执行上获得一定协调能力，也为理解后来德意志多中心政治提供制度背景。"},{"label":"出处","value":"Britannica, Holy Roman Empire；Britannica, Maximilian I；German History in Documents and Images, Imperial Reform resources。"}],"relationItems":["← 前因：沃尔姆斯帝国改革","↔ 相关：神圣罗马帝国最高法院","↔ 相关：神圣罗马帝国","↔ 同时期参考：近代早期国家建设"],"relations":[{"text":"← 前因：沃尔姆斯帝国改革","id":"extra387"},{"text":"↔ 相关：神圣罗马帝国最高法院","id":"extra388"},{"text":"↔ 相关：神圣罗马帝国","id":"extra300"}],"source":"history","id":"extra389"},{"title":"查理五世当选神圣罗马皇帝","level":"A","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1519年6月28日","place":"法兰克福","summary":"查理五世当选皇帝，把西班牙、哈布斯堡和神圣罗马帝国权力连接成欧洲超级王朝格局。","fields":[{"label":"标题","value":"查理五世当选神圣罗马皇帝"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1519年6月28日"},{"label":"地点","value":"法兰克福"},{"label":"主要国家","value":"神圣罗马帝国；西班牙；奥地利；法国；德意志地区"},{"label":"一句话概括","value":"查理五世当选皇帝，把西班牙、哈布斯堡和神圣罗马帝国权力连接成欧洲超级王朝格局。"},{"label":"参与者","value":"查理五世、神圣罗马帝国七大选侯、法国国王弗朗索瓦一世、富格尔家族等金融支持者。"},{"label":"发生了什么","value":"1519年马克西米利安一世去世后，帝国选侯在查理和法国国王弗朗索瓦一世之间选择。查理依靠哈布斯堡继承权、政治承诺和大规模贷款支持赢得选举，成为罗马人的国王，后加冕为皇帝。"},{"label":"为什么重要","value":"这是近代欧洲权力结构节点。查理五世的领地连接西班牙、尼德兰、奥地利、意大利和美洲殖民体系，使法国、奥斯曼、宗教改革和帝国政治都被卷入同一大格局。"},{"label":"前因","value":"哈布斯堡通过马克西米利安一世的婚姻战略积累勃艮第、奥地利和西班牙继承权；帝国选举制度要求候选人争取选侯支持和财政资源。"},{"label":"后果","value":"查理五世面对法国竞争、奥斯曼扩张和路德宗改革三重压力，神圣罗马帝国政治与全球殖民财富、欧洲均势和宗教改革紧密相连。"},{"label":"出处","value":"Britannica, Charles V；Britannica, Maximilian I；Britannica, Fugger Family。"}],"relationItems":["← 前因：马克西米利安一世","← 前因：富格尔家族银行网络","→ 后果：沃姆斯帝国议会","↔ 相关：欧洲宗教改革"],"relations":[{"text":"← 前因：马克西米利安一世","id":"extra386"},{"text":"← 前因：富格尔家族银行网络","id":"extra322"},{"text":"→ 后果：沃姆斯帝国议会","id":"extra303"},{"text":"↔ 相关：欧洲宗教改革","id":"extra301"}],"source":"history","id":"extra390"},{"title":"罗马帝国莱茵-多瑙边疆","level":"B","type":"概念/思潮卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"约公元1—5世纪","place":"莱茵河、多瑙河沿线及日耳曼尼亚边疆","summary":"罗马帝国在莱茵和多瑙沿线建立边疆体系，把日耳曼地区纳入贸易、军事和文化接触带。","fields":[{"label":"标题","value":"罗马帝国莱茵-多瑙边疆"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"约公元1—5世纪"},{"label":"地点","value":"莱茵河、多瑙河沿线及日耳曼尼亚边疆"},{"label":"主要国家","value":"罗马帝国；德意志地区；奥地利；瑞士"},{"label":"一句话概括","value":"罗马帝国在莱茵和多瑙沿线建立边疆体系，把日耳曼地区纳入贸易、军事和文化接触带。"},{"label":"核心主张/思路","value":"这不是单一边墙，而是军营、道路、城镇、关口、河运和边境市场组成的罗马边疆体系。"},{"label":"提出者/代表人物（可选）","value":"罗马帝国皇帝、边疆总督和军团。"},{"label":"它从何而来","value":"罗马向高卢、莱茵和多瑙地区扩张后，需要在可防守河流、道路和山地之间建立稳定防线。"},{"label":"典型表现","value":"莱茵和多瑙军团营地、上日耳曼-雷蒂安长城、边境贸易、罗马化城市和跨境日耳曼雇佣兵。"},{"label":"为什么重要","value":"它为后来德意志地区的城市、道路、军事边界和“罗马-日耳曼”对立想象提供早期背景。"},{"label":"争议/局限","value":"罗马边疆不是封闭铁幕，贸易、迁徙、服役和文化交流始终存在。"},{"label":"出处","value":"Britannica, Limes；UNESCO, Frontiers of the Roman Empire - Upper German-Raetian Limes。"}],"relationItems":["→ 后果：条顿堡森林战役（9年）","↔ 相关：塔西佗《日耳曼尼亚》","↔ 同时期参考：罗马帝国","↔ 同时期参考：日耳曼诸部落"],"relations":[{"text":"→ 后果：条顿堡森林战役（9年）","id":"extra392"},{"text":"↔ 相关：塔西佗《日耳曼尼亚》","id":"extra91"},{"text":"↔ 同时期参考：罗马帝国","id":"extra871"}],"source":"history","id":"extra391"},{"title":"条顿堡森林战役（9年）","level":"B","type":"事件卡","tags":["战争与外交","文化与思想"],"mainTag":"战争与外交","subTag":"文化与思想","timeText":"公元9年","place":"条顿堡森林，今德国西北部","summary":"阿尔米尼乌斯伏击瓦鲁斯军团，阻止罗马把易北河以西日耳曼地区稳定行省化。","fields":[{"label":"标题","value":"条顿堡森林战役（9年）"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"公元9年"},{"label":"地点","value":"条顿堡森林，今德国西北部"},{"label":"主要国家","value":"罗马帝国；日耳曼诸部落；德意志地区"},{"label":"一句话概括","value":"阿尔米尼乌斯伏击瓦鲁斯军团，阻止罗马把易北河以西日耳曼地区稳定行省化。"},{"label":"参与者","value":"日耳曼首领阿尔米尼乌斯、罗马将领瓦鲁斯、罗马第十七至十九军团及日耳曼盟友。"},{"label":"发生了什么","value":"公元9年，受过罗马训练的日耳曼首领阿尔米尼乌斯诱导瓦鲁斯率军进入不利地形，随后联合日耳曼部队在森林和沼泽地带伏击罗马军团。三支罗马军团几乎被歼灭，瓦鲁斯自杀。"},{"label":"为什么重要","value":"它限制了罗马在莱茵以东的直接统治野心，使莱茵河边疆长期保持重要性；后世德国民族主义也反复把它塑造成“日耳曼自由”的象征。"},{"label":"前因","value":"罗马在奥古斯都时期试图把日耳曼地区纳入行省体系，地方部落既与罗马贸易和服役，也反感税收、司法和军事控制。"},{"label":"后果","value":"罗马虽继续发动报复性远征，但没有把莱茵以东稳定建成行省；日耳曼地区在罗马边疆外保持多中心部落政治。"},{"label":"出处","value":"Britannica, Battle of the Teutoburg Forest；Britannica, Arminius。"}],"relationItems":["← 前因：罗马帝国莱茵-多瑙边疆","↔ 相关：塔西佗《日耳曼尼亚》","↔ 同时期参考：罗马帝国","→ 后果：民族大迁徙与日耳曼王国"],"relations":[{"text":"← 前因：罗马帝国莱茵-多瑙边疆","id":"extra391"},{"text":"↔ 相关：塔西佗《日耳曼尼亚》","id":"extra91"},{"text":"↔ 同时期参考：罗马帝国","id":"extra871"},{"text":"→ 后果：民族大迁徙与日耳曼王国","id":"extra393"}],"source":"history","id":"extra392"},{"title":"民族大迁徙与日耳曼王国","level":"A","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"约4—6世纪","place":"西欧、中欧、地中海西部","summary":"民族大迁徙时期日耳曼和其他群体进入罗马世界，推动西罗马帝国瓦解和新王国形成。","fields":[{"label":"标题","value":"民族大迁徙与日耳曼王国"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"约4—6世纪"},{"label":"地点","value":"西欧、中欧、地中海西部"},{"label":"主要国家","value":"罗马帝国；德意志地区；法国；意大利；西班牙"},{"label":"一句话概括","value":"民族大迁徙时期日耳曼和其他群体进入罗马世界，推动西罗马帝国瓦解和新王国形成。"},{"label":"参与者","value":"哥特人、汪达尔人、法兰克人、伦巴第人、勃艮第人、匈人、罗马帝国及地方军政精英。"},{"label":"发生了什么","value":"4—6世纪，多个日耳曼及非日耳曼群体在战争、联盟、逃亡和定居中进入罗马帝国边疆与腹地。西罗马军政结构逐渐无法控制这些武装移民集团，西欧出现法兰克、东哥特、西哥特、汪达尔和伦巴第等王国。"},{"label":"为什么重要","value":"它是欧洲中世纪政治地图形成的关键转折。后来的法兰克王国、神圣罗马帝国和德意志地区，都不能脱离罗马帝国瓦解后的王国化过程理解。"},{"label":"前因","value":"罗马边疆压力、帝国内部财政军事危机、匈人西迁压力、地方军队日耳曼化和跨境迁徙共同推动人口和权力重组。"},{"label":"后果","value":"西罗马帝国政治结构瓦解，拉丁基督教、罗马法律传统和日耳曼王权逐渐结合，法兰克王国成为最重要的继承性力量之一。"},{"label":"出处","value":"Britannica, Migration Period；Britannica, Germanic Peoples；Britannica, Franks。"}],"relationItems":["← 前因：罗马帝国莱茵-多瑙边疆","→ 后果：法兰克王国","↔ 同时期参考：西罗马帝国灭亡","↔ 相关：法兰克国王克洛维皈依尼西亚基督教"],"relations":[{"text":"← 前因：罗马帝国莱茵-多瑙边疆","id":"extra391"},{"text":"→ 后果：法兰克王国","id":"extra394"},{"text":"↔ 同时期参考：西罗马帝国灭亡","id":"extra908"},{"text":"↔ 相关：法兰克国王克洛维皈依尼西亚基督教","id":"extra395"}],"source":"history","id":"extra393"},{"title":"法兰克王国","level":"A","type":"组织/机构卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"5世纪末—843年后逐步分裂","place":"高卢、莱茵地区、德意志西部和意大利北部","summary":"法兰克王国把罗马高卢、基督教会和日耳曼王权结合起来，是法国和德意志中世纪起源的共同前史。","fields":[{"label":"标题","value":"法兰克王国"},{"label":"分级","value":"A"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"5世纪末—843年后逐步分裂"},{"label":"地点","value":"高卢、莱茵地区、德意志西部和意大利北部"},{"label":"主要国家","value":"法兰克王国；法国；德意志地区；意大利"},{"label":"一句话概括","value":"法兰克王国把罗马高卢、基督教会和日耳曼王权结合起来，是法国和德意志中世纪起源的共同前史。"},{"label":"性质/类型","value":"后罗马西欧的日耳曼王国和加洛林帝国基础。"},{"label":"成立/解散时间","value":"5世纪末克洛维统一法兰克诸部后成形，843年加洛林帝国《凡尔登条约》后分裂为东西法兰克等政治体。"},{"label":"核心目标/宗旨","value":"通过王朝、军事征服、教会支持和地方贵族联盟统治高卢、莱茵和后来的中欧地区。"},{"label":"关键人物（可选）","value":"克洛维、查理·马特、丕平三世、查理曼。"},{"label":"关键行动/事件","value":"克洛维皈依、墨洛温王朝扩张、加洛林王朝取代墨洛温王朝、查理曼帝国扩张。"},{"label":"为什么重要","value":"法兰克王国是理解法国、德意志和神圣罗马帝国共同起源的骨架卡。"},{"label":"争议/局限","value":"不能把法兰克王国直接等同于法国或德国，它是现代民族国家之前的王朝和基督教政治共同体。"},{"label":"出处","value":"Britannica, Franks；Britannica, Merovingian Dynasty；Britannica, Carolingian Dynasty。"}],"relationItems":["← 前因：民族大迁徙与日耳曼王国","→ 后果：法兰克加洛林王朝","→ 后果：加洛林帝国《凡尔登条约》","↔ 相关：法兰克国王克洛维皈依尼西亚基督教"],"relations":[{"text":"← 前因：民族大迁徙与日耳曼王国","id":"extra393"},{"text":"→ 后果：法兰克加洛林王朝","id":"extra396"},{"text":"→ 后果：加洛林帝国《凡尔登条约》","id":"extra344"},{"text":"↔ 相关：法兰克国王克洛维皈依尼西亚基督教","id":"extra395"}],"source":"history","id":"extra394"},{"title":"法兰克国王克洛维皈依尼西亚基督教","level":"B","type":"事件卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"约496年或5世纪末","place":"兰斯传统相关地区，高卢法兰克王国","summary":"法兰克国王克洛维皈依尼西亚基督教，使法兰克王权与高卢罗马教会结盟，区别于许多阿里乌派日耳曼王国。","fields":[{"label":"标题","value":"法兰克国王克洛维皈依尼西亚基督教"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"约496年或5世纪末"},{"label":"地点","value":"兰斯传统相关地区，高卢法兰克王国"},{"label":"主要国家","value":"法兰克王国；法国；德意志地区"},{"label":"一句话概括","value":"法兰克国王克洛维皈依尼西亚基督教，使法兰克王权与高卢罗马教会结盟，区别于许多阿里乌派日耳曼王国。"},{"label":"参与者","value":"法兰克国王克洛维、王后克洛蒂尔德、兰斯主教雷米吉乌斯、高卢罗马教会。"},{"label":"发生了什么","value":"克洛维在统一法兰克诸部和扩张高卢过程中接受尼西亚基督教洗礼。与许多信奉阿里乌派的日耳曼王国不同，法兰克王权与高卢主流天主教主教集团形成联盟。"},{"label":"为什么重要","value":"这让法兰克王国更容易获得罗马化地方精英和教会支持，为其成为西欧最强后罗马王国提供合法性资源。"},{"label":"前因","value":"克洛维需要整合法兰克军事贵族、高卢罗马人口和教会网络；王后克洛蒂尔德和主教集团也推动其接受基督教。"},{"label":"后果","value":"法兰克王权与拉丁教会关系加强，后来的加洛林王朝和查理曼帝国都建立在这种王权-教会联盟传统上。"},{"label":"出处","value":"Britannica, Clovis I；Britannica, Franks。"}],"relationItems":["← 前因：法兰克王国","→ 后果：法兰克加洛林王朝","↔ 相关：查理曼加冕为罗马皇帝","↔ 同时期参考：阿里乌派日耳曼王国"],"relations":[{"text":"← 前因：法兰克王国","id":"extra394"},{"text":"→ 后果：法兰克加洛林王朝","id":"extra396"},{"text":"↔ 相关：查理曼加冕为罗马皇帝","id":"extra343"}],"source":"history","id":"extra395"},{"title":"法兰克加洛林王朝","level":"A","type":"组织/机构卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"751—887年左右","place":"法兰克王国、西欧和中欧","summary":"加洛林王朝取代墨洛温王朝并建立查理曼帝国，是西欧帝国传统和东西法兰克分裂的关键前史。","fields":[{"label":"标题","value":"法兰克加洛林王朝"},{"label":"分级","value":"A"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"751—887年左右"},{"label":"地点","value":"法兰克王国、西欧和中欧"},{"label":"主要国家","value":"法兰克王国；法国；德意志地区；意大利"},{"label":"一句话概括","value":"加洛林王朝取代墨洛温王朝并建立查理曼帝国，是西欧帝国传统和东西法兰克分裂的关键前史。"},{"label":"性质/类型","value":"法兰克王国王朝和西欧帝国统治家族。"},{"label":"成立/解散时间","value":"751年丕平三世成为国王后正式建立，9世纪后期王朝权威逐步瓦解。"},{"label":"核心目标/宗旨","value":"以军事扩张、教会联盟、王朝分封和帝国称号维持西欧基督教王权。"},{"label":"关键人物（可选）","value":"查理·马特、丕平三世、查理曼、路易一世。"},{"label":"关键行动/事件","value":"丕平受教皇支持称王，查理曼征服萨克森和伦巴第，800年加冕为皇帝，843年后帝国分裂。"},{"label":"为什么重要","value":"它把法兰克王权、罗马皇帝名号、教会改革和中欧扩张结合起来，是神圣罗马帝国传统的直接来源。"},{"label":"争议/局限","value":"加洛林帝国缺乏现代官僚国家能力，王朝继承分割和地方贵族力量导致统一难以维持。"},{"label":"出处","value":"Britannica, Carolingian Dynasty；Britannica, Charlemagne。"}],"relationItems":["← 前因：法兰克王国","→ 后果：查理曼加冕为罗马皇帝","→ 后果：加洛林帝国《凡尔登条约》","↔ 相关：加洛林文艺复兴"],"relations":[{"text":"← 前因：法兰克王国","id":"extra394"},{"text":"→ 后果：查理曼加冕为罗马皇帝","id":"extra343"},{"text":"→ 后果：加洛林帝国《凡尔登条约》","id":"extra344"},{"text":"↔ 相关：加洛林文艺复兴","id":"extra368"}],"source":"history","id":"extra396"},{"title":"查理曼征服伦巴第王国","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"773—774年","place":"意大利北部，帕维亚等地","summary":"查理曼征服伦巴第王国，把法兰克王权带入意大利政治，并强化其作为教皇保护者的地位。","fields":[{"label":"标题","value":"查理曼征服伦巴第王国"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"773—774年"},{"label":"地点","value":"意大利北部，帕维亚等地"},{"label":"主要国家","value":"法兰克王国；意大利；伦巴第王国；教皇国"},{"label":"一句话概括","value":"查理曼征服伦巴第王国，把法兰克王权带入意大利政治，并强化其作为教皇保护者的地位。"},{"label":"参与者","value":"查理曼、伦巴第国王德西德里乌斯、教皇哈德良一世、法兰克军队。"},{"label":"发生了什么","value":"伦巴第王国与教皇国关系紧张后，查理曼越过阿尔卑斯进攻意大利。774年，法兰克军队攻下帕维亚，查理曼废黜伦巴第国王并自称伦巴第国王。"},{"label":"为什么重要","value":"它让法兰克王权直接卷入意大利和教皇政治，为800年查理曼加冕为罗马皇帝创造条件。"},{"label":"前因","value":"教皇需要法兰克保护以抵御伦巴第压力；丕平三世以来，法兰克王朝已与罗马教廷形成互利联盟，查理曼也希望通过意大利行动巩固王朝合法性和基督教保护者形象。"},{"label":"后果","value":"意大利北部进入法兰克势力范围，查理曼成为西欧最强君主，教皇与法兰克王权的政治合作进一步加深。"},{"label":"出处","value":"Britannica, Charlemagne；Britannica, Lombard。"}],"relationItems":["← 前因：法兰克王国","→ 后果：查理曼加冕为罗马皇帝","↔ 相关：法兰克加洛林王朝","↔ 同时期参考：教皇国"],"relations":[{"text":"← 前因：法兰克王国","id":"extra394"},{"text":"→ 后果：查理曼加冕为罗马皇帝","id":"extra343"},{"text":"↔ 相关：法兰克加洛林王朝","id":"extra396"}],"source":"history","id":"extra397"},{"title":"洛林在法德之间的长期归属问题","level":"B","type":"概念/思潮卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"9世纪以后，尤其870年后长期延续","place":"洛林、莱茵-摩泽尔地区","summary":"洛林是中法兰克破碎后的边界地带，长期牵动法国、德意志和神圣罗马帝国的权力竞争。","fields":[{"label":"标题","value":"洛林在法德之间的长期归属问题"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"9世纪以后，尤其870年后长期延续"},{"label":"地点","value":"洛林、莱茵-摩泽尔地区"},{"label":"主要国家","value":"法国；德意志地区；神圣罗马帝国；低地地区"},{"label":"一句话概括","value":"洛林是中法兰克破碎后的边界地带，长期牵动法国、德意志和神圣罗马帝国的权力竞争。"},{"label":"核心主张/思路","value":"洛林问题指凡尔登和梅尔森等分割后，中间王国遗产在东、西法兰克及后来的法国和帝国之间反复争夺。"},{"label":"提出者/代表人物（可选）","value":"不是单一思想，而是由王朝继承、边境公国、帝国和法国扩张共同形成的历史问题。"},{"label":"它从何而来","value":"查理曼帝国分裂后，中间王国缺乏稳定政治核心，洛林位于莱茵和法兰西之间，具有军事、商业和象征价值。"},{"label":"典型表现","value":"洛林公国分化为上洛林和下洛林，部分地区长期属于帝国，法国在近代逐步向东扩张并争夺该地。"},{"label":"为什么重要","value":"它是理解法德边界问题、阿尔萨斯-洛林争议和西欧中间地带历史的深层前史。"},{"label":"争议/局限","value":"不能用现代民族归属倒推中世纪洛林；当地政治身份长期混合，王朝、城市、教会和语言边界并不重合。"},{"label":"出处","value":"Britannica, Lotharingia；Britannica, Lorraine；Britannica, Treaty of Mersen。"}],"relationItems":["← 前因：加洛林帝国《凡尔登条约》","← 前因：加洛林帝国《梅尔森条约》","→ 后果：阿尔萨斯-洛林并入德意志帝国","↔ 同时期参考：中法兰克王国"],"relations":[{"text":"← 前因：加洛林帝国《凡尔登条约》","id":"extra344"},{"text":"← 前因：加洛林帝国《梅尔森条约》","id":"extra369"},{"text":"→ 后果：阿尔萨斯-洛林并入德意志帝国","id":"extra745"},{"text":"↔ 同时期参考：中法兰克王国","id":"extra921"}],"source":"history","id":"extra398"},{"title":"勃艮第王国并入神圣罗马帝国","level":"B","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1032—1033年","place":"勃艮第王国、阿尔勒王国地区","summary":"勃艮第王国并入帝国，使神圣罗马帝国获得阿尔卑斯西部和罗讷河流域的名义权利。","fields":[{"label":"标题","value":"勃艮第王国并入神圣罗马帝国"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1032—1033年"},{"label":"地点","value":"勃艮第王国、阿尔勒王国地区"},{"label":"主要国家","value":"神圣罗马帝国；法国；瑞士；意大利"},{"label":"一句话概括","value":"勃艮第王国并入帝国，使神圣罗马帝国获得阿尔卑斯西部和罗讷河流域的名义权利。"},{"label":"参与者","value":"神圣罗马皇帝康拉德二世、勃艮第国王鲁道夫三世、当地贵族。"},{"label":"发生了什么","value":"勃艮第国王鲁道夫三世无嗣后，萨利安皇帝康拉德二世依据继承安排主张王位。1032年鲁道夫去世后，康拉德经历地方抵抗后取得勃艮第王国，即后来的阿尔勒王国。"},{"label":"为什么重要","value":"它显示神圣罗马帝国不是单纯德意志王国，而是包含德意志、意大利和勃艮第三重王国传统的复合帝国。"},{"label":"前因","value":"勃艮第王国继承危机与帝国王朝婚姻、盟约相连；皇帝希望控制阿尔卑斯通道和西部边界，同时把帝国权威扩展到德意志、意大利之外的第三个王国传统。"},{"label":"后果","value":"帝国获得勃艮第名义王权，但当地自治强，法国和地方势力后来逐渐扩大影响，帝国西南权威趋于形式化。"},{"label":"出处","value":"Britannica, Conrad II；Britannica, Burgundy；Britannica, Kingdom of Arles。"}],"relationItems":["← 前因：神圣罗马帝国萨利安王朝","↔ 相关：神圣罗马帝国","↔ 相关：洛林在法德之间的长期归属问题","↔ 同时期参考：中世纪王朝继承"],"relations":[{"text":"← 前因：神圣罗马帝国萨利安王朝","id":"extra372"},{"text":"↔ 相关：神圣罗马帝国","id":"extra300"},{"text":"↔ 相关：洛林在法德之间的长期归属问题","id":"extra398"}],"source":"history","id":"extra399"},{"title":"意大利王国与帝国加冕传统","level":"B","type":"制度/文本卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"10—15世纪影响最强","place":"意大利北部、帕维亚、罗马、神圣罗马帝国","summary":"中世纪德意志国王常需进入意大利争取王冠和皇帝加冕，使帝国政治长期跨越阿尔卑斯。","fields":[{"label":"标题","value":"意大利王国与帝国加冕传统"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"10—15世纪影响最强"},{"label":"地点","value":"意大利北部、帕维亚、罗马、神圣罗马帝国"},{"label":"主要国家","value":"神圣罗马帝国；意大利；德意志地区；教皇国"},{"label":"一句话概括","value":"中世纪德意志国王常需进入意大利争取王冠和皇帝加冕，使帝国政治长期跨越阿尔卑斯。"},{"label":"制定方/签署方","value":"不是单一文本，而是中世纪帝国加冕和王权传统。"},{"label":"主要内容","value":"德意志国王通常先取得罗马人的国王身份，再争取意大利王冠和教皇加冕皇帝；意大利城市、教皇和地方贵族因此成为帝国政治的一部分。"},{"label":"它试图解决什么问题","value":"这一传统试图把罗马帝国名号、意大利王权和德意志王权连接起来，为皇帝提供超越地方王国的普世合法性。"},{"label":"为什么重要","value":"它解释了为什么许多神圣罗马皇帝不断远征意大利，也解释德意志王权为何常被跨阿尔卑斯事务消耗。"},{"label":"争议/局限","value":"意大利王权常更像名义和争夺对象，而非稳定行政控制；城市和教皇经常抵抗皇帝直接统治。"},{"label":"造成的影响","value":"帝国长期卷入意大利战争、教皇冲突和城市自治问题，神圣罗马帝国霍亨斯陶芬王朝时期矛盾尤其尖锐。"},{"label":"出处","value":"Britannica, Holy Roman Empire；Britannica, Otto I；Britannica, Frederick I。"}],"relationItems":["← 前因：奥托一世加冕为皇帝","→ 后果：意大利伦巴第联盟","↔ 相关：腓特烈一世巴巴罗萨","↔ 相关：意大利伦巴第联盟《康斯坦茨和约》"],"relations":[{"text":"← 前因：奥托一世加冕为皇帝","id":"extra348"},{"text":"→ 后果：意大利伦巴第联盟","id":"extra356"},{"text":"↔ 相关：腓特烈一世巴巴罗萨","id":"extra355"},{"text":"↔ 相关：意大利伦巴第联盟《康斯坦茨和约》","id":"extra358"}],"source":"history","id":"extra400"},{"title":"神圣罗马帝国主教领","level":"B","type":"制度/文本卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"10世纪以后长期存在","place":"神圣罗马帝国各主教辖区，如科隆、美因茨、特里尔、萨尔茨堡","summary":"帝国主教领把宗教职位和世俗领地结合起来，是中世纪德意志分权政治的重要结构。","fields":[{"label":"标题","value":"神圣罗马帝国主教领"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"10世纪以后长期存在"},{"label":"地点","value":"神圣罗马帝国各主教辖区，如科隆、美因茨、特里尔、萨尔茨堡"},{"label":"主要国家","value":"神圣罗马帝国；德意志地区；奥地利"},{"label":"一句话概括","value":"帝国主教领把宗教职位和世俗领地结合起来，是中世纪德意志分权政治的重要结构。"},{"label":"制定方/签署方","value":"由王权授予、教会制度、地方领地和帝国法权长期共同形成。"},{"label":"主要内容","value":"主教和大主教不仅管理教会事务，也作为帝国诸侯拥有领地、税收、司法和政治权利，部分大主教还成为选侯。"},{"label":"它试图解决什么问题","value":"王权借助无世袭合法子嗣的高级教士治理地方，同时教会获得世俗资源来维持机构和政治影响。"},{"label":"为什么重要","value":"它解释了为什么神圣罗马帝国的“教会”也是政治地图的一部分，宗教改革和世俗化会直接改变领土秩序。"},{"label":"争议/局限","value":"主教领常造成属灵权威和世俗利益混合，也使教会改革和王权任命问题更复杂。"},{"label":"造成的影响","value":"美因茨、科隆、特里尔等教会诸侯在帝国选举、法律和外交中长期发挥作用。"},{"label":"出处","value":"Britannica, Holy Roman Empire；Britannica, Mainz；Britannica, Cologne。"}],"relationItems":["← 前因：奥托王朝教会体系","→ 后果：教皇与皇帝叙任权斗争","↔ 相关：神圣罗马帝国《金玺诏书》","↔ 相关：神圣罗马帝国代表会议主要决议"],"relations":[{"text":"← 前因：奥托王朝教会体系","id":"extra349"},{"text":"→ 后果：教皇与皇帝叙任权斗争","id":"extra351"},{"text":"↔ 相关：神圣罗马帝国《金玺诏书》","id":"extra365"},{"text":"↔ 相关：神圣罗马帝国代表会议主要决议","id":"extra320"}],"source":"history","id":"extra401"},{"title":"神圣罗马帝国自由城市","level":"B","type":"组织/机构卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"中世纪盛期—1806年","place":"帝国境内的纽伦堡、法兰克福、奥格斯堡、吕贝克等城市","summary":"帝国自由城市直属皇帝并拥有自治权，是德意志多中心政治和城市经济的重要力量。","fields":[{"label":"标题","value":"神圣罗马帝国自由城市"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"中世纪盛期—1806年"},{"label":"地点","value":"帝国境内的纽伦堡、法兰克福、奥格斯堡、吕贝克等城市"},{"label":"主要国家","value":"神圣罗马帝国；德意志地区"},{"label":"一句话概括","value":"帝国自由城市直属皇帝并拥有自治权，是德意志多中心政治和城市经济的重要力量。"},{"label":"性质/类型","value":"具有帝国直属地位和较高自治权的城市共同体。"},{"label":"成立/解散时间","value":"中世纪盛期逐步形成，1806年神圣罗马帝国解体前后多数被并入领邦国家。"},{"label":"核心目标/宗旨","value":"维护城市自治、市场权、司法权和帝国直属地位，避免受周边诸侯控制。"},{"label":"关键人物（可选）","value":"城市议会、商人精英、行会代表和皇帝。"},{"label":"关键行动/事件","value":"参与帝国议会、组织城市同盟、经营贸易和手工业，并在宗教改革时期常成为新教传播中心。"},{"label":"为什么重要","value":"它说明德意志历史不只是王朝和诸侯史，城市自治和商业网络也是帝国结构的关键部分。"},{"label":"争议/局限","value":"自由城市内部通常由寡头商人和行会精英控制，并不等于现代民主城市。"},{"label":"出处","value":"Britannica, Free Imperial City；Britannica, Holy Roman Empire；Britannica, Nuremberg。"}],"relationItems":["← 前因：中世纪德意志城市兴起","↔ 相关：中世纪汉萨同盟","↔ 相关：中世纪马格德堡法","↔ 相关：沃尔姆斯帝国改革"],"relations":[{"text":"← 前因：中世纪德意志城市兴起","id":"extra403"},{"text":"↔ 相关：中世纪汉萨同盟","id":"extra321"},{"text":"↔ 相关：中世纪马格德堡法","id":"extra361"},{"text":"↔ 相关：沃尔姆斯帝国改革","id":"extra387"}],"source":"history","id":"extra402"},{"title":"中世纪德意志城市兴起","level":"B","type":"事件卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"约11—14世纪","place":"莱茵、萨克森、巴伐利亚、波罗的海沿岸等城市地区","summary":"11世纪以后德意志城市增长，市场、手工业和市民自治成为帝国社会的重要力量。","fields":[{"label":"标题","value":"中世纪德意志城市兴起"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"约11—14世纪"},{"label":"地点","value":"莱茵、萨克森、巴伐利亚、波罗的海沿岸等城市地区"},{"label":"主要国家","value":"神圣罗马帝国；德意志地区"},{"label":"一句话概括","value":"11世纪以后德意志城市增长，市场、手工业和市民自治成为帝国社会的重要力量。"},{"label":"参与者","value":"商人、手工业者、城市领主、皇帝、主教、行会、市民共同体。"},{"label":"发生了什么","value":"中世纪盛期，德意志地区人口和贸易增长推动城市复兴与新城建立。许多城市获得市场权、铸币权、城墙和自治特许，手工业与商人群体通过行会和城市议会组织起来。"},{"label":"为什么重要","value":"城市兴起改变了德意志社会结构，使经济权力不再只属于贵族和教会；它也是宗教改革、印刷业和市民政治的前提。"},{"label":"前因","value":"农业扩张和人口增长提供了剩余产品与劳动力，道路河运贸易扩大了市场空间；东向殖民和封建领主对市场税收的需求，也共同推动城市发展。"},{"label":"后果","value":"帝国自由城市、汉萨同盟、城市法和行会制度发展起来，德意志政治呈现王侯、教会、城市并存的多中心格局。"},{"label":"出处","value":"Britannica, Germany - Medieval towns；Britannica, Free Imperial City；Britannica, Guild。"}],"relationItems":["→ 后果：神圣罗马帝国自由城市","→ 后果：中世纪汉萨同盟","↔ 相关：中世纪欧洲行会制度","↔ 相关：中世纪马格德堡法"],"relations":[{"text":"→ 后果：神圣罗马帝国自由城市","id":"extra402"},{"text":"→ 后果：中世纪汉萨同盟","id":"extra321"},{"text":"↔ 相关：中世纪欧洲行会制度","id":"extra404"},{"text":"↔ 相关：中世纪马格德堡法","id":"extra361"}],"source":"history","id":"extra403"},{"title":"中世纪欧洲行会制度","level":"C","type":"组织/机构卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"约11—16世纪","place":"欧洲城市，德意志地区尤见于帝国城市和商业城市","summary":"行会把手工业和商业组织成城市共同体规则，影响生产、培训、价格和市民政治。","fields":[{"label":"标题","value":"中世纪欧洲行会制度"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"约11—16世纪"},{"label":"地点","value":"欧洲城市，德意志地区尤见于帝国城市和商业城市"},{"label":"主要国家","value":"欧洲；神圣罗马帝国；德意志地区"},{"label":"一句话概括","value":"行会把手工业和商业组织成城市共同体规则，影响生产、培训、价格和市民政治。"},{"label":"性质/类型","value":"城市手工业者和商人的职业组织。"},{"label":"成立/解散时间","value":"中世纪盛期广泛发展，近代早期后逐步受到国家和市场竞争冲击。"},{"label":"核心目标/宗旨","value":"控制职业准入、学徒训练、产品质量、价格竞争、互助救济和城市政治代表。"},{"label":"关键人物（可选）","value":"师傅、学徒、帮工、城市议会和行会长老。"},{"label":"关键行动/事件","value":"制定行业规则，组织学徒制，参与城市防务和宗教仪式，并在部分城市争取政治权利。"},{"label":"为什么重要","value":"行会是理解中世纪和近代早期城市经济的关键机制，也影响德意志职业教育和手工业文化传统。"},{"label":"争议/局限","value":"行会保护成员利益，也可能限制竞争、排斥女性、外来者和非成员。"},{"label":"出处","value":"Britannica, Guild；Britannica, Apprenticeship。"}],"relationItems":["← 前因：中世纪德意志城市兴起","↔ 相关：德意志帝国职业教育与学徒制","↔ 相关：中世纪汉萨同盟","↔ 同时期参考：欧洲城市自治"],"relations":[{"text":"← 前因：中世纪德意志城市兴起","id":"extra403"},{"text":"↔ 相关：德意志帝国职业教育与学徒制","id":"extra820"},{"text":"↔ 相关：中世纪汉萨同盟","id":"extra321"}],"source":"history","id":"extra404"},{"title":"中世纪莱茵商业走廊","level":"C","type":"概念/思潮卡","tags":["经济与社会","战争与外交"],"mainTag":"经济与社会","subTag":"战争与外交","timeText":"中世纪盛期—近代早期","place":"莱茵河沿线，从瑞士、科隆到低地地区","summary":"莱茵河连接阿尔卑斯、德意志城市和低地市场，是中欧商业和政治联系的重要通道。","fields":[{"label":"标题","value":"中世纪莱茵商业走廊"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"中世纪盛期—近代早期"},{"label":"地点","value":"莱茵河沿线，从瑞士、科隆到低地地区"},{"label":"主要国家","value":"神圣罗马帝国；德意志地区；瑞士；低地地区"},{"label":"一句话概括","value":"莱茵河连接阿尔卑斯、德意志城市和低地市场，是中欧商业和政治联系的重要通道。"},{"label":"核心主张/思路","value":"莱茵不是单纯自然河流，而是城市、关税、主教领、商人网络和军事通道共同构成的经济走廊。"},{"label":"提出者/代表人物（可选）","value":"科隆、斯特拉斯堡、美因茨、巴塞尔等城市商人和沿岸领主。"},{"label":"它从何而来","value":"罗马道路和河运遗产、中世纪城市复兴、葡萄酒和谷物贸易、阿尔卑斯通道与北海市场共同提升莱茵地位。"},{"label":"典型表现","value":"沿岸城市收取关税、组织市场和航运，科隆等城市成为宗教、商业和政治中心。"},{"label":"为什么重要","value":"它解释德意志西部为何长期商业化程度高，也解释法德边界、洛林和低地地区为什么在欧洲史中反复重要。"},{"label":"争议/局限","value":"莱茵商业不是自由流通的现代市场，沿岸关税和诸侯权力也常阻碍贸易。"},{"label":"出处","value":"Britannica, Rhine River；Britannica, Cologne；Britannica, Strasbourg。"}],"relationItems":["↔ 相关：洛林在法德之间的长期归属问题","↔ 相关：神圣罗马帝国自由城市","↔ 相关：中世纪汉萨同盟","↔ 同时期参考：低地国家商业兴起"],"relations":[{"text":"↔ 相关：洛林在法德之间的长期归属问题","id":"extra398"},{"text":"↔ 相关：神圣罗马帝国自由城市","id":"extra402"},{"text":"↔ 相关：中世纪汉萨同盟","id":"extra321"}],"source":"history","id":"extra405"},{"title":"戈斯拉尔与拉默尔斯贝格银矿","level":"C","type":"组织/机构卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"10世纪以后长期开采","place":"戈斯拉尔、拉默尔斯贝格山，哈尔茨地区","summary":"拉默尔斯贝格银矿支撑戈斯拉尔和皇权财政，是中世纪德意志矿业经济的代表。","fields":[{"label":"标题","value":"戈斯拉尔与拉默尔斯贝格银矿"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"10世纪以后长期开采"},{"label":"地点","value":"戈斯拉尔、拉默尔斯贝格山，哈尔茨地区"},{"label":"主要国家","value":"神圣罗马帝国；德意志地区"},{"label":"一句话概括","value":"拉默尔斯贝格银矿支撑戈斯拉尔和皇权财政，是中世纪德意志矿业经济的代表。"},{"label":"性质/类型","value":"矿山、矿业城市和帝国财政资源。"},{"label":"成立/解散时间","value":"10世纪起大规模开采，长期延续到近现代。"},{"label":"核心目标/宗旨","value":"开采银、铜、铅等矿产，为铸币、贸易和王权财政提供资源。"},{"label":"关键人物（可选）","value":"萨克森和萨利安时期的皇帝、矿工、戈斯拉尔城市精英。"},{"label":"关键行动/事件","value":"戈斯拉尔因矿业和皇宫地位繁荣，拉默尔斯贝格成为帝国经济资源和矿业技术中心。"},{"label":"为什么重要","value":"它说明中世纪德意志经济不只是农业和城市贸易，矿业也是王权财政、铸币和技术发展的关键。"},{"label":"争议/局限","value":"矿业繁荣依赖劳工和环境代价，收益也常在皇帝、地方领主和城市之间争夺。"},{"label":"出处","value":"UNESCO, Mines of Rammelsberg and Historic Town of Goslar；Britannica, Goslar。"}],"relationItems":["↔ 相关：中世纪德意志城市兴起","↔ 相关：德意志帝国马克与金本位","↔ 同时期参考：中世纪欧洲矿业","↔ 相关：神圣罗马帝国萨利安王朝"],"relations":[{"text":"↔ 相关：中世纪德意志城市兴起","id":"extra403"},{"text":"↔ 相关：德意志帝国马克与金本位","id":"extra746"},{"text":"↔ 同时期参考：中世纪欧洲矿业","id":"extra881"},{"text":"↔ 相关：神圣罗马帝国萨利安王朝","id":"extra372"}],"source":"history","id":"extra406"},{"title":"弗赖贝格银矿与矿业城市","level":"C","type":"组织/机构卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"12世纪以后","place":"萨克森弗赖贝格及厄尔士山地区","summary":"弗赖贝格因银矿兴起，展示中世纪德意志矿业、城市法和山地殖民的结合。","fields":[{"label":"标题","value":"弗赖贝格银矿与矿业城市"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"12世纪以后"},{"label":"地点","value":"萨克森弗赖贝格及厄尔士山地区"},{"label":"主要国家","value":"神圣罗马帝国；德意志地区；捷克"},{"label":"一句话概括","value":"弗赖贝格因银矿兴起，展示中世纪德意志矿业、城市法和山地殖民的结合。"},{"label":"性质/类型","value":"矿业城市和银矿经济中心。"},{"label":"成立/解散时间","value":"12世纪发现银矿后兴起，矿业影响延续数百年。"},{"label":"核心目标/宗旨","value":"围绕银矿开采、冶炼、铸币和矿业管理形成城市经济。"},{"label":"关键人物（可选）","value":"萨克森统治者、矿工、商人和城市管理者。"},{"label":"关键行动/事件","value":"银矿发现吸引移民和技术人员，推动弗赖贝格城市发展，并影响萨克森财政和矿业法规。"},{"label":"为什么重要","value":"它把东向开垦、矿业资本、城市兴起和中欧山地经济连接起来，是理解萨克森经济的重要早期节点。"},{"label":"争议/局限","value":"矿业城市繁荣具有周期性，矿脉、技术、资本和劳工冲突都会影响其发展。"},{"label":"出处","value":"Britannica, Freiberg；Saxony state historical resources, Freiberg mining history。"}],"relationItems":["↔ 相关：德意志东向殖民","↔ 相关：中世纪马格德堡法","↔ 相关：戈斯拉尔与拉默尔斯贝格银矿","↔ 同时期参考：中世纪欧洲矿业"],"relations":[{"text":"↔ 相关：德意志东向殖民","id":"extra360"},{"text":"↔ 相关：中世纪马格德堡法","id":"extra361"},{"text":"↔ 相关：戈斯拉尔与拉默尔斯贝格银矿","id":"extra406"},{"text":"↔ 同时期参考：中世纪欧洲矿业","id":"extra881"}],"source":"history","id":"extra407"},{"title":"中世纪德意志犹太社群","level":"B","type":"概念/思潮卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"约10—15世纪","place":"莱茵城市、帝国城市和德意志各地","summary":"中世纪德意志犹太社群在贸易、放贷和学术中重要，却长期面对特权保护与暴力迫害并存。","fields":[{"label":"标题","value":"中世纪德意志犹太社群"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"约10—15世纪"},{"label":"地点","value":"莱茵城市、帝国城市和德意志各地"},{"label":"主要国家","value":"神圣罗马帝国；德意志地区"},{"label":"一句话概括","value":"中世纪德意志犹太社群在贸易、放贷和学术中重要，却长期面对特权保护与暴力迫害并存。"},{"label":"核心主张/思路","value":"犹太社群作为宗教少数群体，常依靠皇帝、主教或城市授予的保护特权生活，同时承担商业、金融和跨地区联系角色。"},{"label":"提出者/代表人物（可选）","value":"各地犹太社群领袖、拉比、商人和保护其居住权的领主。"},{"label":"它从何而来","value":"中世纪城市商业发展需要跨区域网络和信用机制，犹太社群也在拉丁基督教社会中形成相对自治的宗教法律共同体。"},{"label":"典型表现","value":"莱茵城市犹太社区、犹太学校和墓地、放贷与贸易活动、保护状与特别税、周期性驱逐和迫害。"},{"label":"为什么重要","value":"它是德意志社会史不可缺的部分，也为理解反犹主义、宗教少数、城市经济和后来的欧洲犹太史提供前史。"},{"label":"争议/局限","value":"不能把中世纪犹太社群只简化为金融角色；这种印象本身部分来自基督教社会限制职业和反犹刻板印象。"},{"label":"出处","value":"Encyclopaedia Judaica, Germany；UNESCO, ShUM Sites of Speyer, Worms and Mainz；United States Holocaust Memorial Museum, Antisemitism in history。"}],"relationItems":["→ 后果：施派尔、沃尔姆斯、美因茨ShUM社群","→ 后果：第一次十字军期间莱茵兰屠杀","↔ 相关：黑死病冲击中欧","↔ 相关：德意志帝国现代政治反犹主义"],"relations":[{"text":"→ 后果：施派尔、沃尔姆斯、美因茨ShUM社群","id":"extra409"},{"text":"→ 后果：第一次十字军期间莱茵兰屠杀","id":"extra410"},{"text":"↔ 相关：黑死病冲击中欧","id":"extra364"},{"text":"↔ 相关：德意志帝国现代政治反犹主义","id":"extra825"}],"source":"history","id":"extra408"},{"title":"施派尔、沃尔姆斯、美因茨ShUM社群","level":"B","type":"组织/机构卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"约10—14世纪最具影响","place":"施派尔、沃尔姆斯、美因茨","summary":"ShUM三城是中世纪阿什肯纳兹犹太文化核心，形成宗教法律、教育和社群自治传统。","fields":[{"label":"标题","value":"施派尔、沃尔姆斯、美因茨ShUM社群"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"约10—14世纪最具影响"},{"label":"地点","value":"施派尔、沃尔姆斯、美因茨"},{"label":"主要国家","value":"神圣罗马帝国；德意志地区"},{"label":"一句话概括","value":"ShUM三城是中世纪阿什肯纳兹犹太文化核心，形成宗教法律、教育和社群自治传统。"},{"label":"性质/类型","value":"中世纪莱茵犹太社群网络。"},{"label":"成立/解散时间","value":"10世纪以后发展，12—13世纪影响尤大；其遗产在后世持续被记忆和研究。"},{"label":"核心目标/宗旨","value":"维持犹太宗教教育、礼拜、法律裁决、慈善和社群自治，并与城市及领主权力协商生存空间。"},{"label":"关键人物（可选）","value":"各地拉比、社群长老、学者和商人。"},{"label":"关键行动/事件","value":"建立会堂、学校、墓地和社群规章，形成对阿什肯纳兹犹太法传统有深远影响的宗教文化中心。"},{"label":"为什么重要","value":"它说明中世纪德意志不仅有基督教帝国和城市史，也有高度发达的犹太学术和社群制度。"},{"label":"争议/局限","value":"ShUM社群成就与脆弱性并存，十字军暴力、驱逐和瘟疫时期迫害不断打断其发展。"},{"label":"出处","value":"UNESCO, ShUM Sites of Speyer, Worms and Mainz；Jewish Virtual Library, ShUM Cities。"}],"relationItems":["← 前因：中世纪德意志犹太社群","→ 后果：第一次十字军期间莱茵兰屠杀","↔ 相关：黑死病冲击中欧","↔ 同时期参考：阿什肯纳兹犹太文化"],"relations":[{"text":"← 前因：中世纪德意志犹太社群","id":"extra408"},{"text":"→ 后果：第一次十字军期间莱茵兰屠杀","id":"extra410"},{"text":"↔ 相关：黑死病冲击中欧","id":"extra364"}],"source":"history","id":"extra409"},{"title":"第一次十字军期间莱茵兰屠杀","level":"B","type":"事件卡","tags":["文化与思想","战争与外交"],"mainTag":"文化与思想","subTag":"战争与外交","timeText":"1096年","place":"施派尔、沃尔姆斯、美因茨、科隆等莱茵城市","summary":"第一次十字军动员期间，莱茵犹太社群遭到暴力屠杀，暴露宗教战争动员的内部迫害逻辑。","fields":[{"label":"标题","value":"第一次十字军期间莱茵兰屠杀"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1096年"},{"label":"地点","value":"施派尔、沃尔姆斯、美因茨、科隆等莱茵城市"},{"label":"主要国家","value":"神圣罗马帝国；德意志地区；法国"},{"label":"一句话概括","value":"第一次十字军动员期间，莱茵犹太社群遭到暴力屠杀，暴露宗教战争动员的内部迫害逻辑。"},{"label":"参与者","value":"十字军民众队伍、地方贵族和城市居民、莱茵犹太社群、部分试图保护犹太人的主教和地方当局。"},{"label":"发生了什么","value":"1096年，第一次十字军动员扩散到莱茵地区后，一些十字军队伍和暴民把犹太人视为基督教敌人并要求改宗或掠夺。施派尔、沃尔姆斯、美因茨等地犹太社群遭屠杀、强迫改宗和财产抢夺。"},{"label":"为什么重要","value":"它说明十字军运动不仅指向东方穆斯林，也在欧洲内部制造针对犹太人的宗教暴力。"},{"label":"前因","value":"教皇号召十字军后，宗教激情、债务关系、社会紧张和反犹神学想象在莱茵城市中结合，地方保护机制无法有效阻止暴力。"},{"label":"后果","value":"莱茵犹太社群遭受巨大创伤，殉难记忆进入犹太传统；这类暴力也为后来的危机时期反犹迫害提供了危险范式，欧洲反犹暴力在十字军和瘟疫等语境中反复出现。"},{"label":"出处","value":"United States Holocaust Memorial Museum, The First Crusade and Jewish communities；Jewish Virtual Library, Rhineland Massacres；Britannica, First Crusade。"}],"relationItems":["← 前因：施派尔、沃尔姆斯、美因茨ShUM社群","↔ 相关：中世纪德意志犹太社群","↔ 相关：黑死病冲击中欧","↔ 同时期参考：第一次十字军"],"relations":[{"text":"← 前因：施派尔、沃尔姆斯、美因茨ShUM社群","id":"extra409"},{"text":"↔ 相关：中世纪德意志犹太社群","id":"extra408"},{"text":"↔ 相关：黑死病冲击中欧","id":"extra364"},{"text":"↔ 同时期参考：第一次十字军","id":"extra877"}],"source":"history","id":"extra410"},{"title":"德意志海德堡大学成立","level":"B","type":"事件卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1386年","place":"海德堡","summary":"海德堡大学是德意志地区最早大学之一，显示中世纪晚期帝国知识和官僚训练需求上升。","fields":[{"label":"标题","value":"德意志海德堡大学成立"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1386年"},{"label":"地点","value":"海德堡"},{"label":"主要国家","value":"神圣罗马帝国；德意志地区"},{"label":"一句话概括","value":"海德堡大学是德意志地区最早大学之一，显示中世纪晚期帝国知识和官僚训练需求上升。"},{"label":"参与者","value":"普法尔茨选侯鲁普雷希特一世、教皇乌尔班六世、学者和学生。"},{"label":"发生了什么","value":"1386年，普法尔茨选侯鲁普雷希特一世创办海德堡大学。大学设神学、法学、医学和文艺等传统学科，为教会、领地政府和城市社会培养人才。"},{"label":"为什么重要","value":"它是德意志大学史的重要节点，说明帝国诸侯也开始通过大学建设提升领地治理、文化声望和政治竞争力。"},{"label":"前因","value":"中世纪晚期欧洲大学网络扩张，领地和教会需要受过训练的法学家、神学家和行政人才；西方教会大分裂也影响学生流动和大学布局。"},{"label":"后果","value":"海德堡成为德意志西南重要学术中心，为普法尔茨领地提供法律、神学和行政人才；后来它在宗教改革、人文主义和近代大学传统中持续发挥作用。"},{"label":"出处","value":"Britannica, Heidelberg University；Heidelberg University, History。"}],"relationItems":["↔ 相关：中欧布拉格大学成立","↔ 相关：德意志人文主义","↔ 相关：欧洲宗教改革","↔ 同时期参考：中世纪大学"],"relations":[{"text":"↔ 相关：中欧布拉格大学成立","id":"extra382"},{"text":"↔ 相关：德意志人文主义","id":"extra412"},{"text":"↔ 相关：欧洲宗教改革","id":"extra301"},{"text":"↔ 同时期参考：中世纪大学","id":"extra879"}],"source":"history","id":"extra411"},{"title":"德意志人文主义","level":"B","type":"概念/思潮卡","tags":["文化与思想"],"mainTag":"文化与思想","subTag":"","timeText":"15世纪末—16世纪初","place":"神圣罗马帝国城市、大学和印刷中心","summary":"德意志人文主义强调回到原典、语言学和教育改革，为宗教改革前的知识批判提供工具。","fields":[{"label":"标题","value":"德意志人文主义"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"时间","value":"15世纪末—16世纪初"},{"label":"地点","value":"神圣罗马帝国城市、大学和印刷中心"},{"label":"主要国家","value":"神圣罗马帝国；德意志地区"},{"label":"一句话概括","value":"德意志人文主义强调回到原典、语言学和教育改革，为宗教改革前的知识批判提供工具。"},{"label":"核心主张/思路","value":"学习古典语言和希伯来语，回到圣经与古典文本原典，批评经院僵化和教会腐败，重视教育与文献校勘。"},{"label":"提出者/代表人物（可选）","value":"约翰内斯·罗伊希林、乌尔里希·冯·胡滕、伊拉斯谟影响下的德意志学者。"},{"label":"它从何而来","value":"意大利文艺复兴人文主义、大学教育、印刷传播和德意志城市文化共同推动北方人文主义发展。"},{"label":"典型表现","value":"希伯来学争论、古典文本校勘、讽刺文学、教育改革和对教会制度的学术批评。"},{"label":"为什么重要","value":"它为路德宗改革提供语言学、文本批判和公共舆论环境，但它本身不等于宗教改革。"},{"label":"争议/局限","value":"许多人文主义者希望温和改革而非教会分裂；运动主要属于受教育精英和城市文化圈。"},{"label":"出处","value":"Britannica, Humanism；Britannica, Johann Reuchlin；Britannica, Ulrich von Hutten。"}],"relationItems":["← 前因：约翰内斯·罗伊希林","← 前因：古腾堡活字印刷革命","→ 后果：欧洲宗教改革","↔ 相关：马丁·路德发表《九十五条论纲》"],"relations":[{"text":"← 前因：约翰内斯·罗伊希林","id":"extra385"},{"text":"← 前因：古腾堡活字印刷革命","id":"extra299"},{"text":"→ 后果：欧洲宗教改革","id":"extra301"},{"text":"↔ 相关：马丁·路德发表《九十五条论纲》","id":"extra302"}],"source":"history","id":"extra412"},{"title":"西多会与中欧开垦","level":"C","type":"组织/机构卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"12—14世纪","place":"中欧、德意志地区东部、波兰、波希米亚、匈牙利等地","summary":"西多会修道院参与农业开垦、技术传播和边疆定居，是中世纪中欧社会经济扩张的一股力量。","fields":[{"label":"标题","value":"西多会与中欧开垦"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"12—14世纪"},{"label":"地点","value":"中欧、德意志地区东部、波兰、波希米亚、匈牙利等地"},{"label":"主要国家","value":"神圣罗马帝国；德意志地区；波兰；捷克；匈牙利"},{"label":"一句话概括","value":"西多会修道院参与农业开垦、技术传播和边疆定居，是中世纪中欧社会经济扩张的一股力量。"},{"label":"性质/类型","value":"天主教修道会网络及其修道院经济体系。"},{"label":"成立/解散时间","value":"西多会1098年创立，12世纪以后在欧洲迅速扩张。"},{"label":"核心目标/宗旨","value":"追求较严格的本笃会修道生活，同时通过修道院、农庄、祈祷和劳动组织宗教共同体。"},{"label":"关键人物（可选）","value":"克莱尔沃的伯尔纳、各地修道院院长、俗兄弟和捐赠贵族。"},{"label":"关键行动/事件","value":"西多会修道院在森林、沼泽和边疆地区经营土地，组织农业生产、水利、畜牧和手工业，并参与中欧定居和基督教化过程。"},{"label":"为什么重要","value":"它说明中世纪扩张不只是骑士和城市，也包括修道院经济、农业技术和宗教网络；这能补足德意志东向殖民背后的社会机制。"},{"label":"争议/局限","value":"西多会并非所有地区开垦的唯一动力，其经济作用也常依赖贵族捐赠、劳工和地方权力安排。"},{"label":"出处","value":"Britannica, Cistercians；Britannica, Monasticism；Britannica, Agriculture - The medieval period。"}],"relationItems":["← 前因：中世纪教会克吕尼改革","↔ 相关：德意志东向殖民","↔ 相关：中世纪条顿骑士团","↔ 同时期参考：中世纪欧洲农业扩张"],"relations":[{"text":"← 前因：中世纪教会克吕尼改革","id":"extra371"},{"text":"↔ 相关：德意志东向殖民","id":"extra360"},{"text":"↔ 相关：中世纪条顿骑士团","id":"extra362"}],"source":"history","id":"extra413"},{"title":"神圣罗马帝国帝国议会","level":"B","type":"组织/机构卡","tags":["政治与制度"],"mainTag":"政治与制度","subTag":"","timeText":"中世纪后期—1806年，1495年后制度化程度提高","place":"神圣罗马帝国各帝国议会召开城市，如沃尔姆斯、奥格斯堡、雷根斯堡","summary":"帝国议会是皇帝、选侯、诸侯和城市协商帝国事务的机构，体现神圣罗马帝国的等级政治。","fields":[{"label":"标题","value":"神圣罗马帝国帝国议会"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"时间","value":"中世纪后期—1806年，1495年后制度化程度提高"},{"label":"地点","value":"神圣罗马帝国各帝国议会召开城市，如沃尔姆斯、奥格斯堡、雷根斯堡"},{"label":"主要国家","value":"神圣罗马帝国；德意志地区；奥地利；捷克"},{"label":"一句话概括","value":"帝国议会是皇帝、选侯、诸侯和城市协商帝国事务的机构，体现神圣罗马帝国的等级政治。"},{"label":"性质/类型","value":"神圣罗马帝国的等级会议和政治协商机构。"},{"label":"成立/解散时间","value":"中世纪后期逐渐形成，1495年沃尔姆斯帝国改革后更制度化，1806年随帝国解体结束。"},{"label":"核心目标/宗旨","value":"讨论税收、防务、法律、宗教和帝国公共秩序，要求皇帝与帝国等级共同决定重大事务。"},{"label":"关键人物（可选）","value":"皇帝、七大选侯、世俗和教会诸侯、帝国自由城市代表。"},{"label":"关键行动/事件","value":"1495年沃尔姆斯帝国改革、1521年沃姆斯帝国议会、1530年奥格斯堡帝国议会等。"},{"label":"为什么重要","value":"它说明神圣罗马帝国不是单纯由皇帝命令统治，而是通过等级代表、协商和法律程序运行。"},{"label":"争议/局限","value":"帝国议会代表的是等级和特权，不是现代民选议会；城市、诸侯和皇帝之间也经常利益冲突。"},{"label":"出处","value":"Britannica, Reichstag；Britannica, Holy Roman Empire；German History in Documents and Images, Imperial Reform resources。"}],"relationItems":["↔ 相关：沃尔姆斯帝国改革","↔ 相关：沃姆斯帝国议会","↔ 相关：神圣罗马帝国《金玺诏书》","↔ 同时期参考：欧洲等级会议"],"relations":[{"text":"↔ 相关：沃尔姆斯帝国改革","id":"extra387"},{"text":"↔ 相关：沃姆斯帝国议会","id":"extra303"},{"text":"↔ 相关：神圣罗马帝国《金玺诏书》","id":"extra365"}],"source":"history","id":"extra414"},{"title":"神圣罗马帝国选侯制度","level":"B","type":"制度/文本卡","tags":["政治与制度"],"mainTag":"政治与制度","subTag":"","timeText":"13世纪后成形，1356年神圣罗马帝国《金玺诏书》制度化","place":"神圣罗马帝国","summary":"选侯制度把皇帝选举权集中到少数诸侯手中，塑造神圣罗马帝国长期分权格局。","fields":[{"label":"标题","value":"神圣罗马帝国选侯制度"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"时间","value":"13世纪后成形，1356年神圣罗马帝国《金玺诏书》制度化"},{"label":"地点","value":"神圣罗马帝国"},{"label":"主要国家","value":"神圣罗马帝国；德意志地区；捷克"},{"label":"一句话概括","value":"选侯制度把皇帝选举权集中到少数诸侯手中，塑造神圣罗马帝国长期分权格局。"},{"label":"制定方/签署方","value":"由帝国政治实践长期形成，1356年查理四世的神圣罗马帝国《金玺诏书》正式固定七大选侯地位。"},{"label":"主要内容","value":"美因茨、科隆、特里尔三位大主教和波希米亚、普法尔茨、萨克森、勃兰登堡等世俗选侯掌握选举罗马人的国王的核心权力。"},{"label":"它试图解决什么问题","value":"它试图把原本容易争议的王位选举程序交给固定群体，减少双重选举和教皇干预。"},{"label":"为什么重要","value":"它让神圣罗马帝国皇位成为协商选举职位，而非稳定世袭王位，深刻影响德意志无法早早中央集权。"},{"label":"争议/局限","value":"选侯制度稳定了规则，也强化少数大诸侯特权，牺牲皇帝和中小等级的政治空间。"},{"label":"造成的影响","value":"选侯成为帝国政治核心，哈布斯堡、勃兰登堡和萨克森等家族都通过选侯身份增强欧洲影响力。"},{"label":"出处","value":"Britannica, Golden Bull of Emperor Charles IV；Britannica, Elector；Britannica, Holy Roman Empire。"}],"relationItems":["← 前因：神圣罗马帝国《金玺诏书》","↔ 相关：神圣罗马帝国帝国议会","↔ 相关：查理五世当选神圣罗马皇帝","↔ 相关：德意志统一与奥普领导权问题"],"relations":[{"text":"← 前因：神圣罗马帝国《金玺诏书》","id":"extra365"},{"text":"↔ 相关：神圣罗马帝国帝国议会","id":"extra414"},{"text":"↔ 相关：查理五世当选神圣罗马皇帝","id":"extra390"},{"text":"↔ 相关：德意志统一与奥普领导权问题","id":"extra526"}],"source":"history","id":"extra415"},{"title":"神圣罗马帝国宫廷法院","level":"C","type":"组织/机构卡","tags":["政治与制度"],"mainTag":"政治与制度","subTag":"","timeText":"1497—1806年","place":"皇帝宫廷所在地，常随哈布斯堡宫廷运行","summary":"神圣罗马帝国宫廷法院是皇帝直接控制的重要司法机构，与神圣罗马帝国最高法院共同构成帝国司法体系。","fields":[{"label":"标题","value":"神圣罗马帝国宫廷法院"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"时间","value":"1497—1806年"},{"label":"地点","value":"皇帝宫廷所在地，常随哈布斯堡宫廷运行"},{"label":"主要国家","value":"神圣罗马帝国；奥地利；德意志地区"},{"label":"一句话概括","value":"神圣罗马帝国宫廷法院是皇帝直接控制的重要司法机构，与神圣罗马帝国最高法院共同构成帝国司法体系。"},{"label":"性质/类型","value":"神圣罗马帝国中央司法和咨询机构，又称Reichshofrat。"},{"label":"成立/解散时间","value":"15世纪末在马克西米利安一世时期制度化，1806年随帝国解体结束。"},{"label":"核心目标/宗旨","value":"处理帝国封臣、特权、领地争议、皇帝保留权和上诉案件，同时服务皇帝的帝国治理。"},{"label":"关键人物（可选）","value":"皇帝、宫廷法官、哈布斯堡顾问和帝国当事人。"},{"label":"关键行动/事件","value":"与神圣罗马帝国最高法院并行受理帝国案件，尤其在皇帝权利、封地和特权事务中发挥作用。"},{"label":"为什么重要","value":"它补足了神圣罗马帝国司法结构：帝国既有等级参与的法院，也有皇帝宫廷方向的司法渠道。"},{"label":"争议/局限","value":"法院和皇帝关系更密切，常被认为更受哈布斯堡政治影响；执行仍依赖帝国内部合作。"},{"label":"出处","value":"Britannica, Aulic Council；Britannica, Reichskammergericht；Britannica, Holy Roman Empire。"}],"relationItems":["← 前因：沃尔姆斯帝国改革","↔ 相关：神圣罗马帝国最高法院","↔ 相关：神圣罗马帝国帝国议会","↔ 同时期参考：近代早期司法国家"],"relations":[{"text":"← 前因：沃尔姆斯帝国改革","id":"extra387"},{"text":"↔ 相关：神圣罗马帝国最高法院","id":"extra388"},{"text":"↔ 相关：神圣罗马帝国帝国议会","id":"extra414"}],"source":"history","id":"extra416"},{"title":"神圣罗马帝国帝国骑士","level":"C","type":"组织/机构卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"中世纪后期—1806年","place":"德意志西南和法兰肯等帝国直属小领地","summary":"帝国骑士是直属皇帝的小贵族群体，显示帝国政治中存在大量微型权力单元。","fields":[{"label":"标题","value":"神圣罗马帝国帝国骑士"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"中世纪后期—1806年"},{"label":"地点","value":"德意志西南和法兰肯等帝国直属小领地"},{"label":"主要国家","value":"神圣罗马帝国；德意志地区"},{"label":"一句话概括","value":"帝国骑士是直属皇帝的小贵族群体，显示帝国政治中存在大量微型权力单元。"},{"label":"性质/类型","value":"直属皇帝但不拥有帝国议会席位的低级贵族群体。"},{"label":"成立/解散时间","value":"中世纪后期形成，1806年前后随帝国解体和领土重组消失。"},{"label":"核心目标/宗旨","value":"维护帝国直属地位、贵族特权、领地司法和税收豁免，避免被周边诸侯吞并。"},{"label":"关键人物（可选）","value":"弗朗茨·冯·西金根等骑士政治人物。"},{"label":"关键行动/事件","value":"参与地方战争、宗教改革冲突和帝国法律争端，并通过骑士团体维护共同利益。"},{"label":"为什么重要","value":"它说明神圣罗马帝国的分权不只是大诸侯问题，还包括大量小贵族、自由城市和教会领地。"},{"label":"争议/局限","value":"帝国骑士享有特权却缺乏强大政治代表，近代国家建设压力下生存空间越来越小。"},{"label":"出处","value":"Britannica, Imperial Knight；Britannica, Holy Roman Empire。"}],"relationItems":["↔ 相关：神圣罗马帝国","↔ 相关：神圣罗马帝国代表会议主要决议","↔ 相关：德意志部落公国","↔ 同时期参考：欧洲贵族等级社会"],"relations":[{"text":"↔ 相关：神圣罗马帝国","id":"extra300"},{"text":"↔ 相关：神圣罗马帝国代表会议主要决议","id":"extra320"},{"text":"↔ 相关：德意志部落公国","id":"extra370"}],"source":"history","id":"extra417"},{"title":"反路德《沃姆斯敕令》","level":"A","type":"制度/文本卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1521年5月","place":"沃姆斯帝国议会后颁布","summary":"反路德《沃姆斯敕令》宣布路德为非法者并禁止其著作，却没能阻止宗教改革扩散。","fields":[{"label":"标题","value":"反路德《沃姆斯敕令》"},{"label":"分级","value":"A"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1521年5月"},{"label":"地点","value":"沃姆斯帝国议会后颁布"},{"label":"主要国家","value":"神圣罗马帝国；德意志地区；教皇国"},{"label":"一句话概括","value":"反路德《沃姆斯敕令》宣布路德为非法者并禁止其著作，却没能阻止宗教改革扩散。"},{"label":"制定方/签署方","value":"神圣罗马皇帝查理五世在沃姆斯帝国议会后颁布。"},{"label":"主要内容","value":"宣布马丁·路德为帝国非法者，禁止收藏、阅读和传播其著作，要求逮捕并惩罚支持者。"},{"label":"它试图解决什么问题","value":"它试图用帝国法律和皇帝权威压制路德争论，恢复教会和帝国宗教秩序。"},{"label":"为什么重要","value":"它把路德问题从神学争论升级为帝国政治和法律问题，也是宗教改革无法在帝国层面被简单压制的标志。"},{"label":"争议/局限","value":"敕令执行依赖诸侯和城市合作；萨克森等地保护路德，印刷传播和地方政治使禁令难以生效。"},{"label":"造成的影响","value":"路德被保护到瓦特堡并继续写作，宗教改革在德意志城市和诸侯领地中扩散。"},{"label":"出处","value":"Britannica, Diet of Worms；Britannica, Martin Luther；German History in Documents and Images, Edict of Worms。"}],"relationItems":["← 前因：沃姆斯帝国议会","→ 后果：路德德语圣经翻译","↔ 相关：欧洲宗教改革","↔ 相关：马丁·路德发表《九十五条论纲》"],"relations":[{"text":"← 前因：沃姆斯帝国议会","id":"extra303"},{"text":"→ 后果：路德德语圣经翻译","id":"extra304"},{"text":"↔ 相关：欧洲宗教改革","id":"extra301"},{"text":"↔ 相关：马丁·路德发表《九十五条论纲》","id":"extra302"}],"source":"history","id":"extra418"},{"title":"《奥格斯堡信纲》","level":"A","type":"制度/文本卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1530年","place":"奥格斯堡帝国议会","summary":"《奥格斯堡信纲》系统陈述路德宗信仰，成为德意志新教合法化和身份凝聚的核心文本。","fields":[{"label":"标题","value":"《奥格斯堡信纲》"},{"label":"分级","value":"A"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1530年"},{"label":"地点","value":"奥格斯堡帝国议会"},{"label":"主要国家","value":"神圣罗马帝国；德意志地区"},{"label":"一句话概括","value":"《奥格斯堡信纲》系统陈述路德宗信仰，成为德意志新教合法化和身份凝聚的核心文本。"},{"label":"制定方/签署方","value":"主要由菲利普·梅兰希通起草，路德宗诸侯和城市在1530年奥格斯堡帝国议会上提交。"},{"label":"主要内容","value":"阐述路德宗关于称义、圣礼、教会、礼仪和教会改革的立场，同时试图表明其并非完全背离古代教会信仰。"},{"label":"它试图解决什么问题","value":"它试图向查理五世和帝国等级说明路德宗信仰内容，争取被视为可协商的基督教改革而非叛乱。"},{"label":"为什么重要","value":"它是路德宗身份的核心文件，也让宗教改革阵营从松散争论转向可被政治承认的信仰共同体。"},{"label":"争议/局限","value":"天主教方面没有接受其主要主张，宗教分裂继续加深；文本也不能代表所有新教派别，尤其不代表改革宗和再洗礼派。"},{"label":"造成的影响","value":"奥格斯堡信纲成为施马尔卡尔登同盟、宗教改革《奥格斯堡和约》和后世路德宗教会传统的重要基础。"},{"label":"出处","value":"Britannica, Augsburg Confession；Britannica, Philip Melanchthon。"}],"relationItems":["← 前因：欧洲宗教改革","→ 后果：施马尔卡尔登同盟","↔ 相关：宗教改革《奥格斯堡和约》","↔ 相关：菲利普·梅兰希通"],"relations":[{"text":"← 前因：欧洲宗教改革","id":"extra301"},{"text":"→ 后果：施马尔卡尔登同盟","id":"extra326"},{"text":"↔ 相关：宗教改革《奥格斯堡和约》","id":"extra305"}],"source":"history","id":"extra419"},{"title":"路德与茨温利宗教改革马尔堡会谈","level":"B","type":"事件卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1529年10月","place":"马尔堡","summary":"路德与茨温利在路德与茨温利宗教改革马尔堡会谈中未能就圣餐问题达成一致，新教内部分裂由此清晰化。","fields":[{"label":"标题","value":"路德与茨温利宗教改革马尔堡会谈"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1529年10月"},{"label":"地点","value":"马尔堡"},{"label":"主要国家","value":"神圣罗马帝国；瑞士；德意志地区"},{"label":"一句话概括","value":"路德与茨温利在路德与茨温利宗教改革马尔堡会谈中未能就圣餐问题达成一致，新教内部分裂由此清晰化。"},{"label":"参与者","value":"马丁·路德、乌尔里希·茨温利、菲利普·梅兰希通、黑森的菲利普等。"},{"label":"发生了什么","value":"黑森的菲利普希望联合德意志路德宗和瑞士改革派，以形成共同政治宗教阵线。1529年，路德与茨温利等人在马尔堡讨论多项教义，许多问题达成接近意见，但在圣餐中基督是否真实临在的问题上无法妥协。"},{"label":"为什么重要","value":"它显示宗教改革不是单一阵营，而是从早期就分化为路德宗、改革宗和其他派别。"},{"label":"前因","value":"帝国和天主教压力加大，新教诸侯需要联合；茨温利与加尔文的瑞士宗教改革和德意志路德宗改革在政治上接近，在神学上仍有关键差异。"},{"label":"后果","value":"路德宗和改革宗未能完全结盟，德意志新教政治长期受到教义边界限制；改革宗后来在普法尔茨等地发展。"},{"label":"出处","value":"Britannica, Marburg Colloquy；Britannica, Huldrych Zwingli；Britannica, Martin Luther。"}],"relationItems":["← 前因：茨温利与加尔文的瑞士宗教改革","↔ 相关：《奥格斯堡信纲》","↔ 相关：普法尔茨加尔文宗化","↔ 相关：欧洲宗教改革"],"relations":[{"text":"← 前因：茨温利与加尔文的瑞士宗教改革","id":"extra421"},{"text":"↔ 相关：《奥格斯堡信纲》","id":"extra419"},{"text":"↔ 相关：普法尔茨加尔文宗化","id":"extra423"},{"text":"↔ 相关：欧洲宗教改革","id":"extra301"}],"source":"history","id":"extra420"},{"title":"茨温利与加尔文的瑞士宗教改革","level":"B","type":"事件卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1520年代起","place":"苏黎世、伯尔尼、日内瓦等瑞士城市","summary":"茨温利与加尔文的瑞士宗教改革由茨温利和后来加尔文推动，形成区别于路德宗的改革宗传统。","fields":[{"label":"标题","value":"茨温利与加尔文的瑞士宗教改革"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1520年代起"},{"label":"地点","value":"苏黎世、伯尔尼、日内瓦等瑞士城市"},{"label":"主要国家","value":"瑞士；神圣罗马帝国；法国"},{"label":"一句话概括","value":"茨温利与加尔文的瑞士宗教改革由茨温利和后来加尔文推动，形成区别于路德宗的改革宗传统。"},{"label":"参与者","value":"乌尔里希·茨温利、约翰·加尔文、瑞士城市议会、神职人员和市民。"},{"label":"发生了什么","value":"1520年代，茨温利在苏黎世推动讲道改革、取消部分天主教仪式并强调圣经权威。随后伯尔尼等地加入改革阵营，日内瓦在加尔文影响下成为改革宗中心。"},{"label":"为什么重要","value":"它使宗教改革从德意志路德宗扩展为多中心欧洲运动，并对法国、尼德兰、苏格兰和普法尔茨产生深远影响。"},{"label":"前因","value":"印刷传播和人文主义圣经研究让教会批评更易扩散，瑞士城市自治政治则给改革派提供地方执行空间；市民对教会财产、雇佣兵制度和礼仪权威的不满共同推动城市改革。"},{"label":"后果","value":"改革宗传统形成并向欧洲扩散，新教内部与路德宗在圣餐、教会纪律和政治组织上形成差异；这种差异后来影响普法尔茨、尼德兰、法国和英伦诸岛的宗教政治。"},{"label":"出处","value":"Britannica, Huldrych Zwingli；Britannica, John Calvin；Britannica, Reformation。"}],"relationItems":["↔ 相关：路德与茨温利宗教改革马尔堡会谈","↔ 相关：普法尔茨加尔文宗化","↔ 相关：欧洲宗教改革","↔ 同时期参考：日内瓦宗教改革"],"relations":[{"text":"↔ 相关：路德与茨温利宗教改革马尔堡会谈","id":"extra420"},{"text":"↔ 相关：普法尔茨加尔文宗化","id":"extra423"},{"text":"↔ 相关：欧洲宗教改革","id":"extra301"}],"source":"history","id":"extra421"},{"title":"海德堡教理问答","level":"B","type":"制度/文本卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1563年","place":"海德堡","summary":"海德堡教理问答是改革宗重要信仰文本，巩固普法尔茨的加尔文宗身份。","fields":[{"label":"标题","value":"海德堡教理问答"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1563年"},{"label":"地点","value":"海德堡"},{"label":"主要国家","value":"神圣罗马帝国；德意志地区；瑞士"},{"label":"一句话概括","value":"海德堡教理问答是改革宗重要信仰文本，巩固普法尔茨的加尔文宗身份。"},{"label":"制定方/签署方","value":"普法尔茨选侯腓特烈三世推动，由海德堡神学家参与编写。"},{"label":"主要内容","value":"以问答形式阐述人的罪、基督救赎、感恩生活、圣礼和教会纪律等改革宗教义。"},{"label":"它试图解决什么问题","value":"它试图统一普法尔茨教会教育和信仰表达，在路德宗与改革宗争论中确立本地改革宗路线。"},{"label":"为什么重要","value":"它是改革宗传统最重要的教理文本之一，也说明德意志宗教版图在宗教改革《奥格斯堡和约》后并未固定为天主教与路德宗两分。"},{"label":"争议/局限","value":"宗教改革《奥格斯堡和约》最初只承认天主教和路德宗，改革宗普法尔茨的合法地位长期存在争议。"},{"label":"造成的影响","value":"普法尔茨成为德意志改革宗中心，影响尼德兰、瑞士和后来的三十年战争前宗教政治。"},{"label":"出处","value":"Britannica, Heidelberg Catechism；Britannica, Calvinism；Britannica, Palatinate。"}],"relationItems":["← 前因：普法尔茨加尔文宗化","↔ 相关：茨温利与加尔文的瑞士宗教改革","↔ 相关：宗教改革《奥格斯堡和约》","↔ 相关：德意志海德堡大学成立"],"relations":[{"text":"← 前因：普法尔茨加尔文宗化","id":"extra423"},{"text":"↔ 相关：茨温利与加尔文的瑞士宗教改革","id":"extra421"},{"text":"↔ 相关：宗教改革《奥格斯堡和约》","id":"extra305"},{"text":"↔ 相关：德意志海德堡大学成立","id":"extra411"}],"source":"history","id":"extra422"},{"title":"普法尔茨加尔文宗化","level":"B","type":"事件卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1559—1560年代","place":"普法尔茨选侯国，中心为海德堡","summary":"普法尔茨转向改革宗，使神圣罗马帝国内部新教阵营出现路德宗与加尔文宗分裂。","fields":[{"label":"标题","value":"普法尔茨加尔文宗化"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1559—1560年代"},{"label":"地点","value":"普法尔茨选侯国，中心为海德堡"},{"label":"主要国家","value":"神圣罗马帝国；德意志地区；瑞士"},{"label":"一句话概括","value":"普法尔茨转向改革宗，使神圣罗马帝国内部新教阵营出现路德宗与加尔文宗分裂。"},{"label":"参与者","value":"普法尔茨选侯腓特烈三世、海德堡神学家、普法尔茨教会、路德宗和改革宗阵营。"},{"label":"发生了什么","value":"16世纪中期，普法尔茨选侯国从路德宗倾向转向加尔文宗改革。腓特烈三世支持改革宗神学和教会纪律，并推动1563年海德堡教理问答作为教会教育文本。"},{"label":"为什么重要","value":"它让改革宗进入帝国选侯政治核心，打破宗教改革《奥格斯堡和约》下“天主教—路德宗”二元框架。"},{"label":"前因","value":"茨温利与加尔文的瑞士宗教改革和加尔文宗思想向德意志西南传播，普法尔茨选侯希望通过教会改革重塑领地秩序和宗教身份。"},{"label":"后果","value":"普法尔茨成为改革宗堡垒，既挑战宗教改革《奥格斯堡和约》的天主教—路德宗框架，也使德意志新教联盟和三十年战争前的帝国宗教政治更复杂。"},{"label":"出处","value":"Britannica, Palatinate；Britannica, Heidelberg Catechism；Britannica, Calvinism。"}],"relationItems":["→ 后果：海德堡教理问答","→ 后果：德意志新教联盟","↔ 相关：茨温利与加尔文的瑞士宗教改革","↔ 相关：路德与茨温利宗教改革马尔堡会谈"],"relations":[{"text":"→ 后果：海德堡教理问答","id":"extra422"},{"text":"→ 后果：德意志新教联盟","id":"extra425"},{"text":"↔ 相关：茨温利与加尔文的瑞士宗教改革","id":"extra421"},{"text":"↔ 相关：路德与茨温利宗教改革马尔堡会谈","id":"extra420"}],"source":"history","id":"extra423"},{"title":"神圣罗马帝国科隆战争","level":"C","type":"事件卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1583—1588年","place":"科隆选侯国及莱茵地区","summary":"神圣罗马帝国科隆战争围绕科隆大主教改宗和选侯领地归属爆发，显示帝国宗教和平的脆弱性。","fields":[{"label":"标题","value":"神圣罗马帝国科隆战争"},{"label":"分级","value":"C"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1583—1588年"},{"label":"地点","value":"科隆选侯国及莱茵地区"},{"label":"主要国家","value":"神圣罗马帝国；德意志地区；教皇国；西班牙"},{"label":"一句话概括","value":"神圣罗马帝国科隆战争围绕科隆大主教改宗和选侯领地归属爆发，显示帝国宗教和平的脆弱性。"},{"label":"参与者","value":"科隆大主教格布哈德·特鲁赫泽斯、天主教继任者恩斯特、科隆教会领地、巴伐利亚和西班牙支持者。"},{"label":"发生了什么","value":"科隆大主教格布哈德改宗新教并试图把教会选侯国世俗化、保留统治权，引发天主教势力反击。战争在莱茵地区持续数年，最终天主教阵营获胜。"},{"label":"为什么重要","value":"科隆是七大选侯之一，一旦转为新教将改变皇帝选举平衡；战争显示宗教改革《奥格斯堡和约》对教会领地改宗问题处理不稳。"},{"label":"前因","value":"宗教改革《奥格斯堡和约》允许世俗诸侯决定领地宗教，但教会诸侯改宗后是否能保留教会领地存在尖锐争议；科隆又是选侯国，归属变化会影响皇帝选举格局。"},{"label":"后果","value":"科隆选侯国保留天主教地位，天主教阵营稳住选侯格局；但教会领地改宗和世俗化问题没有消失，帝国宗教冲突继续积累。"},{"label":"出处","value":"Britannica, Cologne War；Britannica, Cologne；Britannica, Counter-Reformation。"}],"relationItems":["← 前因：宗教改革《奥格斯堡和约》","↔ 相关：神圣罗马帝国选侯制度","↔ 相关：德意志新教联盟","↔ 同时期参考：欧洲宗教战争"],"relations":[{"text":"← 前因：宗教改革《奥格斯堡和约》","id":"extra305"},{"text":"↔ 相关：神圣罗马帝国选侯制度","id":"extra415"},{"text":"↔ 相关：德意志新教联盟","id":"extra425"}],"source":"history","id":"extra424"},{"title":"德意志新教联盟","level":"B","type":"组织/机构卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1608—1621年","place":"神圣罗马帝国新教诸侯和城市，中心与普法尔茨相关","summary":"德意志新教联盟是三十年战争前德意志新教诸侯的防卫同盟，反映帝国宗教对立军事化。","fields":[{"label":"标题","value":"德意志新教联盟"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1608—1621年"},{"label":"地点","value":"神圣罗马帝国新教诸侯和城市，中心与普法尔茨相关"},{"label":"主要国家","value":"神圣罗马帝国；德意志地区"},{"label":"一句话概括","value":"德意志新教联盟是三十年战争前德意志新教诸侯的防卫同盟，反映帝国宗教对立军事化。"},{"label":"性质/类型","value":"新教诸侯和城市组成的政治军事同盟。"},{"label":"成立/解散时间","value":"1608年成立，三十年战争初期后逐渐瓦解，1621年解散。"},{"label":"核心目标/宗旨","value":"保护新教领地权利和宗教安全，抵御天主教阵营和皇帝权威扩大。"},{"label":"关键人物（可选）","value":"普法尔茨选侯腓特烈四世及后继者、德意志新教诸侯。"},{"label":"关键行动/事件","value":"在尤利希-克莱沃继承危机和波希米亚危机前后成为新教政治协调平台。"},{"label":"为什么重要","value":"它说明三十年战争不是突然爆发，帝国内部宗教阵营在战前已经形成同盟和安全困境。"},{"label":"争议/局限","value":"德意志新教联盟内部路德宗和改革宗利益并不一致，许多诸侯不愿为普法尔茨冒险。"},{"label":"出处","value":"Britannica, Protestant Union；Britannica, Thirty Years War；Britannica, Palatinate。"}],"relationItems":["← 前因：普法尔茨加尔文宗化","↔ 相关：德意志天主教联盟","→ 后果：布拉格掷出窗外事件","↔ 相关：三十年战争"],"relations":[{"text":"← 前因：普法尔茨加尔文宗化","id":"extra423"},{"text":"↔ 相关：德意志天主教联盟","id":"extra426"},{"text":"→ 后果：布拉格掷出窗外事件","id":"extra306"},{"text":"↔ 相关：三十年战争","id":"extra307"}],"source":"history","id":"extra425"},{"title":"德意志天主教联盟","level":"B","type":"组织/机构卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1609—1635年","place":"巴伐利亚及神圣罗马帝国天主教领地","summary":"德意志天主教联盟由巴伐利亚主导，是德意志新教联盟的对手，成为三十年战争初期皇帝阵营重要力量。","fields":[{"label":"标题","value":"德意志天主教联盟"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1609—1635年"},{"label":"地点","value":"巴伐利亚及神圣罗马帝国天主教领地"},{"label":"主要国家","value":"神圣罗马帝国；德意志地区；奥地利"},{"label":"一句话概括","value":"德意志天主教联盟由巴伐利亚主导，是德意志新教联盟的对手，成为三十年战争初期皇帝阵营重要力量。"},{"label":"性质/类型","value":"天主教诸侯政治军事同盟。"},{"label":"成立/解散时间","value":"1609年成立，1635年布拉格和约后基本结束。"},{"label":"核心目标/宗旨","value":"维护天主教诸侯权利和宗教改革《奥格斯堡和约》中的天主教利益，抵御德意志新教联盟压力。"},{"label":"关键人物（可选）","value":"巴伐利亚公爵马克西米利安一世、蒂利伯爵。"},{"label":"关键行动/事件","value":"在三十年战争白山战役和三十年战争初期支持皇帝与波希米亚反叛者、新教诸侯作战。"},{"label":"为什么重要","value":"它把帝国内部宗教分裂军事化，巴伐利亚也借此在帝国政治中显著上升。"},{"label":"争议/局限","value":"德意志天主教联盟与皇帝利益并非总一致，巴伐利亚也追求自身选侯地位和领地利益。"},{"label":"出处","value":"Britannica, Catholic League；Britannica, Thirty Years War；Britannica, Maximilian I of Bavaria。"}],"relationItems":["← 前因：德意志新教联盟","→ 后果：三十年战争白山战役","↔ 相关：三十年战争","↔ 相关：欧洲天主教改革"],"relations":[{"text":"← 前因：德意志新教联盟","id":"extra425"},{"text":"→ 后果：三十年战争白山战役","id":"extra331"},{"text":"↔ 相关：三十年战争","id":"extra307"},{"text":"↔ 相关：欧洲天主教改革","id":"extra329"}],"source":"history","id":"extra426"},{"title":"尤利希-克莱沃继承危机","level":"C","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1609—1614年","place":"莱茵下游和威斯特伐利亚地区","summary":"尤利希-克莱沃继承危机围绕莱茵重要领地继承展开，暴露三十年战争前的国际化风险。","fields":[{"label":"标题","value":"尤利希-克莱沃继承危机"},{"label":"分级","value":"C"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1609—1614年"},{"label":"地点","value":"莱茵下游和威斯特伐利亚地区"},{"label":"主要国家","value":"神圣罗马帝国；德意志地区；法国；西班牙；尼德兰"},{"label":"一句话概括","value":"尤利希-克莱沃继承危机围绕莱茵重要领地继承展开，暴露三十年战争前的国际化风险。"},{"label":"参与者","value":"勃兰登堡选侯、普法尔茨-诺伊堡、皇帝、法国、荷兰共和国、西班牙等。"},{"label":"发生了什么","value":"1609年尤利希-克莱沃-贝格公爵无嗣去世后，多个继承人争夺其莱茵和威斯特伐利亚领地。危机吸引法国、荷兰和西班牙关注，最后通过分割安排暂时缓和。"},{"label":"为什么重要","value":"它显示帝国内部继承问题很容易牵动欧洲列强，莱茵地区的战略价值使宗教和王朝纠纷国际化。"},{"label":"前因","value":"该公国地处莱茵和尼德兰附近，兼具宗教、贸易和军事价值；继承权不清叠加德意志新教联盟与天主教阵营对立。"},{"label":"后果","value":"危机虽未立即引发大战，却强化德意志新教联盟、天主教阵营和周边列强的不信任；它预示三十年战争很快会从德意志内部争端扩大为国际问题。"},{"label":"出处","value":"Britannica, Julich-Cleves-Berg；Britannica, Thirty Years War；Britannica, Brandenburg。"}],"relationItems":["← 前因：德意志新教联盟","↔ 相关：德意志天主教联盟","↔ 相关：三十年战争","↔ 同时期参考：荷兰独立战争"],"relations":[{"text":"← 前因：德意志新教联盟","id":"extra425"},{"text":"↔ 相关：德意志天主教联盟","id":"extra426"},{"text":"↔ 相关：三十年战争","id":"extra307"},{"text":"↔ 同时期参考：荷兰独立战争","id":"extra873"}],"source":"history","id":"extra427"},{"title":"奥斯曼-匈牙利莫哈奇战役","level":"A","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1526年8月29日","place":"匈牙利莫哈奇","summary":"奥斯曼在莫哈奇击败匈牙利，打开中欧权力真空，使哈布斯堡直接面对奥斯曼压力。","fields":[{"label":"标题","value":"奥斯曼-匈牙利莫哈奇战役"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1526年8月29日"},{"label":"地点","value":"匈牙利莫哈奇"},{"label":"主要国家","value":"匈牙利；奥斯曼帝国；奥地利；神圣罗马帝国"},{"label":"一句话概括","value":"奥斯曼在莫哈奇击败匈牙利，打开中欧权力真空，使哈布斯堡直接面对奥斯曼压力。"},{"label":"参与者","value":"奥斯曼苏丹苏莱曼一世、匈牙利国王拉约什二世、匈牙利军队、哈布斯堡继承人。"},{"label":"发生了什么","value":"1526年，苏莱曼一世率奥斯曼军队进入匈牙利，在莫哈奇击败匈牙利军队，拉约什二世战死。匈牙利王国继承危机随即爆发，哈布斯堡和奥斯曼都介入其领土和王位。"},{"label":"为什么重要","value":"它把奥斯曼帝国推进到中欧门口，也让哈布斯堡成为抵抗奥斯曼扩张的主要欧洲王朝之一。"},{"label":"前因","value":"奥斯曼帝国在巴尔干扩张已久，匈牙利王国政治和军事资源不足；哈布斯堡通过婚姻继承安排与匈牙利王位相连。"},{"label":"后果","value":"匈牙利被分裂为哈布斯堡控制区、奥斯曼控制区和特兰西瓦尼亚等部分，中欧进入长期哈布斯堡-奥斯曼对抗。"},{"label":"出处","value":"Britannica, Battle of Mohacs；Britannica, Suleyman the Magnificent；Britannica, Hungary。"}],"relationItems":["→ 后果：奥斯曼第一次围攻维也纳","↔ 相关：哈布斯堡君主国","↔ 相关：查理五世当选神圣罗马皇帝","↔ 同时期参考：奥斯曼帝国扩张"],"relations":[{"text":"→ 后果：奥斯曼第一次围攻维也纳","id":"extra429"},{"text":"↔ 相关：哈布斯堡君主国","id":"extra309"},{"text":"↔ 相关：查理五世当选神圣罗马皇帝","id":"extra390"}],"source":"history","id":"extra428"},{"title":"奥斯曼第一次围攻维也纳","level":"A","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1529年9—10月","place":"维也纳","summary":"苏莱曼一世围攻维也纳未果，标志奥斯曼扩张抵达中欧核心边界。","fields":[{"label":"标题","value":"奥斯曼第一次围攻维也纳"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1529年9—10月"},{"label":"地点","value":"维也纳"},{"label":"主要国家","value":"奥斯曼帝国；奥地利；神圣罗马帝国；匈牙利"},{"label":"一句话概括","value":"苏莱曼一世围攻维也纳未果，标志奥斯曼扩张抵达中欧核心边界。"},{"label":"参与者","value":"奥斯曼苏丹苏莱曼一世、哈布斯堡的斐迪南一世、维也纳守军、匈牙利相关势力。"},{"label":"发生了什么","value":"莫哈奇战役后，奥斯曼和哈布斯堡争夺匈牙利。1529年，苏莱曼一世率军向维也纳推进并围城，但因补给、天气、火炮运输和守军抵抗等因素未能攻下城市。"},{"label":"为什么重要","value":"它使维也纳成为欧洲抵御奥斯曼扩张的象征，也把德意志、奥地利和匈牙利问题纳入同一大战略。"},{"label":"前因","value":"莫哈奇战役造成匈牙利王位真空，哈布斯堡的斐迪南主张继承匈牙利，奥斯曼则扶持其盟友并向中欧推进。"},{"label":"后果","value":"奥斯曼未能攻占维也纳，但哈布斯堡-奥斯曼边境战争长期化，匈牙利分裂格局持续；维也纳也逐渐成为中欧抵御奥斯曼扩张的象征城市。"},{"label":"出处","value":"Britannica, Siege of Vienna；Britannica, Suleyman the Magnificent；Britannica, Ferdinand I。"}],"relationItems":["← 前因：奥斯曼-匈牙利莫哈奇战役","→ 后果：奥斯曼第二次围攻维也纳","↔ 相关：哈布斯堡君主国","↔ 同时期参考：奥斯曼帝国"],"relations":[{"text":"← 前因：奥斯曼-匈牙利莫哈奇战役","id":"extra428"},{"text":"→ 后果：奥斯曼第二次围攻维也纳","id":"extra310"},{"text":"↔ 相关：哈布斯堡君主国","id":"extra309"},{"text":"↔ 同时期参考：奥斯曼帝国","id":"extra872"}],"source":"history","id":"extra429"},{"title":"普鲁士公国世俗化","level":"A","type":"事件卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1525年","place":"柯尼斯堡、普鲁士","summary":"条顿骑士团普鲁士领地世俗化为路德宗公国，是普鲁士国家谱系的重要开端。","fields":[{"label":"标题","value":"普鲁士公国世俗化"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1525年"},{"label":"地点","value":"柯尼斯堡、普鲁士"},{"label":"主要国家","value":"普鲁士；波兰；神圣罗马帝国；德意志地区"},{"label":"一句话概括","value":"条顿骑士团普鲁士领地世俗化为路德宗公国，是普鲁士国家谱系的重要开端。"},{"label":"参与者","value":"条顿骑士团大团长阿尔布雷希特、波兰国王齐格蒙特一世、路德宗改革者。"},{"label":"发生了什么","value":"1525年，条顿骑士团大团长阿尔布雷希特接受路德宗改革，将骑士团在普鲁士的领地世俗化，成为波兰王冠封臣下的普鲁士公爵。"},{"label":"为什么重要","value":"它把中世纪军事修会国家转化为世俗领地，为后来的勃兰登堡-普鲁士和普鲁士王国提供关键远源。"},{"label":"前因","value":"条顿骑士团国家长期衰落并受波兰压力制约，宗教改革为其统治者提供了摆脱修会身份、重组领地的路径。"},{"label":"后果","value":"普鲁士成为欧洲第一个重要路德宗公国之一，骑士团国家转为世俗王朝领地；1618年该公国由勃兰登堡霍亨索伦家族继承，形成普鲁士崛起的关键组合。"},{"label":"出处","value":"Britannica, Prussia；Britannica, Teutonic Order；Britannica, Albert。"}],"relationItems":["← 前因：条顿骑士团国家","→ 后果：勃兰登堡继承普鲁士公国","↔ 相关：欧洲宗教改革","↔ 相关：普鲁士王国成立"],"relations":[{"text":"← 前因：条顿骑士团国家","id":"extra363"},{"text":"→ 后果：勃兰登堡继承普鲁士公国","id":"extra431"},{"text":"↔ 相关：欧洲宗教改革","id":"extra301"},{"text":"↔ 相关：普鲁士王国成立","id":"extra312"}],"source":"history","id":"extra430"},{"title":"勃兰登堡继承普鲁士公国","level":"B","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1618年","place":"勃兰登堡、普鲁士公国","summary":"1618年霍亨索伦家族把勃兰登堡选侯国与普鲁士公国连接起来，形成勃兰登堡-普鲁士。","fields":[{"label":"标题","value":"勃兰登堡继承普鲁士公国"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1618年"},{"label":"地点","value":"勃兰登堡、普鲁士公国"},{"label":"主要国家","value":"勃兰登堡；普鲁士；波兰；神圣罗马帝国"},{"label":"一句话概括","value":"1618年霍亨索伦家族把勃兰登堡选侯国与普鲁士公国连接起来，形成勃兰登堡-普鲁士。"},{"label":"参与者","value":"勃兰登堡选侯约翰·西吉斯蒙德、普鲁士公国霍亨索伦支系、波兰王冠。"},{"label":"发生了什么","value":"普鲁士公国的阿尔布雷希特·腓特烈去世后，勃兰登堡霍亨索伦支系继承普鲁士公国。由于普鲁士公国在帝国之外且为波兰封地，勃兰登堡-普鲁士从一开始就是跨法权的复合领地。"},{"label":"为什么重要","value":"它是普鲁士崛起的关键结构节点：一个帝国内选侯国与帝国外公国结合，后来使霍亨索伦能够在1701年以普鲁士为王国名号加冕。"},{"label":"前因","value":"1525年普鲁士公国世俗化后由霍亨索伦支系统治，家族婚姻和继承安排把普鲁士与勃兰登堡联系起来。"},{"label":"后果","value":"勃兰登堡-普鲁士成为跨地域、跨法权领地组合，统治者必须建设军队、财政和官僚体系来整合分散领地；这种压力推动了后来的财政军事国家化。"},{"label":"出处","value":"Britannica, Prussia；Britannica, Brandenburg；Britannica, Hohenzollern Dynasty。"}],"relationItems":["← 前因：普鲁士公国世俗化","→ 后果：弗里德里希·威廉“大选侯”","↔ 相关：勃兰登堡-普鲁士崛起","↔ 相关：普鲁士王国成立"],"relations":[{"text":"← 前因：普鲁士公国世俗化","id":"extra430"},{"text":"→ 后果：弗里德里希·威廉“大选侯”","id":"extra432"},{"text":"↔ 相关：勃兰登堡-普鲁士崛起","id":"extra311"},{"text":"↔ 相关：普鲁士王国成立","id":"extra312"}],"source":"history","id":"extra431"},{"title":"弗里德里希·威廉“大选侯”","level":"B","type":"人物卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1620—1688年；1640—1688年为勃兰登堡选侯","place":"勃兰登堡-普鲁士、柏林、柯尼斯堡","summary":"大选侯通过军队、财政和外交整合分散领地，为普鲁士崛起奠定国家能力基础。","fields":[{"label":"标题","value":"弗里德里希·威廉“大选侯”"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1620—1688年；1640—1688年为勃兰登堡选侯"},{"label":"地点","value":"勃兰登堡-普鲁士、柏林、柯尼斯堡"},{"label":"主要国家","value":"勃兰登堡；普鲁士；神圣罗马帝国；波兰"},{"label":"一句话概括","value":"大选侯通过军队、财政和外交整合分散领地，为普鲁士崛起奠定国家能力基础。"},{"label":"生卒年/活跃年代","value":"1620—1688年。"},{"label":"身份/职务","value":"勃兰登堡选侯、普鲁士公爵。"},{"label":"关键贡献/作为","value":"三十年战争后重建领地，扩张常备军和税收体系，在瑞典、波兰和帝国之间灵活外交，并吸纳胡格诺移民。"},{"label":"核心主张/立场","value":"以王朝领地安全和统治效率为中心，强化选侯权力，削弱地方等级对财政和军事的控制。"},{"label":"为什么重要","value":"他不是普鲁士国王，却是普鲁士国家能力形成的关键人物；后来的军国财政国家有许多基础在其时期建立。"},{"label":"争议/评价","value":"其改革提高国家能力，也强化君主专制和军事化倾向，地方等级自治空间被压缩。"},{"label":"关联事件（可选）","value":"勃兰登堡-瑞典费尔贝林战役；波茨坦敕令；普鲁士王国成立。"},{"label":"出处","value":"Britannica, Frederick William；Britannica, Prussia；Britannica, Brandenburg。"}],"relationItems":["← 前因：勃兰登堡继承普鲁士公国","→ 后果：勃兰登堡-瑞典费尔贝林战役","→ 后果：勃兰登堡-普鲁士《波茨坦敕令》","↔ 相关：勃兰登堡-普鲁士崛起"],"relations":[{"text":"← 前因：勃兰登堡继承普鲁士公国","id":"extra431"},{"text":"→ 后果：勃兰登堡-瑞典费尔贝林战役","id":"extra433"},{"text":"→ 后果：勃兰登堡-普鲁士《波茨坦敕令》","id":"extra434"},{"text":"↔ 相关：勃兰登堡-普鲁士崛起","id":"extra311"}],"source":"history","id":"extra432"},{"title":"勃兰登堡-瑞典费尔贝林战役","level":"C","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1675年6月28日","place":"勃兰登堡费尔贝林附近","summary":"大选侯在费尔贝林击败瑞典军队，提升勃兰登堡-普鲁士的军事声望。","fields":[{"label":"标题","value":"勃兰登堡-瑞典费尔贝林战役"},{"label":"分级","value":"C"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1675年6月28日"},{"label":"地点","value":"勃兰登堡费尔贝林附近"},{"label":"主要国家","value":"勃兰登堡；瑞典；神圣罗马帝国"},{"label":"一句话概括","value":"大选侯在费尔贝林击败瑞典军队，提升勃兰登堡-普鲁士的军事声望。"},{"label":"参与者","value":"弗里德里希·威廉“大选侯”、勃兰登堡军队、瑞典军队。"},{"label":"发生了什么","value":"1675年，瑞典军队进入勃兰登堡。大选侯迅速调动军队，在费尔贝林附近击败瑞典部队。战斗规模不算欧洲最大，却在勃兰登堡政治记忆中被塑造成军事崛起象征。"},{"label":"为什么重要","value":"它标志勃兰登堡-普鲁士开始具备挑战波罗的海强国瑞典的军事能力，也强化统治者建设常备军的合法性。"},{"label":"前因","value":"法荷战争和欧洲同盟变动使瑞典进攻勃兰登堡，波罗的海强权竞争直接压到霍亨索伦领地；大选侯需要证明分散领地可以被集中军事动员保护。"},{"label":"后果","value":"勃兰登堡-普鲁士声望上升，军队成为国家建设核心；虽然外交收益有限，但军事神话对后世普鲁士身份很重要。"},{"label":"出处","value":"Britannica, Frederick William；Britannica, Sweden - history；Prussian historical references on Fehrbellin。"}],"relationItems":["← 前因：弗里德里希·威廉“大选侯”","↔ 相关：勃兰登堡-普鲁士崛起","↔ 相关：普鲁士王国成立","↔ 同时期参考：瑞典帝国"],"relations":[{"text":"← 前因：弗里德里希·威廉“大选侯”","id":"extra432"},{"text":"↔ 相关：勃兰登堡-普鲁士崛起","id":"extra311"},{"text":"↔ 相关：普鲁士王国成立","id":"extra312"}],"source":"history","id":"extra433"},{"title":"勃兰登堡-普鲁士《波茨坦敕令》","level":"B","type":"制度/文本卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1685年10月29日","place":"波茨坦、勃兰登堡-普鲁士","summary":"波茨坦敕令接纳法国胡格诺难民，体现勃兰登堡-普鲁士用宗教宽容服务人口和经济建设。","fields":[{"label":"标题","value":"勃兰登堡-普鲁士《波茨坦敕令》"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1685年10月29日"},{"label":"地点","value":"波茨坦、勃兰登堡-普鲁士"},{"label":"主要国家","value":"勃兰登堡；普鲁士；法国；神圣罗马帝国"},{"label":"一句话概括","value":"波茨坦敕令接纳法国胡格诺难民，体现勃兰登堡-普鲁士用宗教宽容服务人口和经济建设。"},{"label":"制定方/签署方","value":"勃兰登堡选侯弗里德里希·威廉。"},{"label":"主要内容","value":"向受迫害的法国胡格诺新教徒提供入境、定居、税收优惠、职业自由和宗教礼拜保障。"},{"label":"它试图解决什么问题","value":"它试图吸引熟练工匠、商人和专业人才，补充三十年战争后人口与经济损失，同时扩大新教君主的声望。"},{"label":"为什么重要","value":"它显示近代早期“宽容”有现实国家建设逻辑：宗教政策、移民政策和经济重建可以结合。"},{"label":"争议/局限","value":"这种宽容并非现代平等原则，而是面向特定有用移民群体的特许政策。"},{"label":"造成的影响","value":"大量胡格诺进入柏林和勃兰登堡-普鲁士，推动手工业、商业和城市文化发展。"},{"label":"出处","value":"Britannica, Frederick William；Britannica, Huguenot；German History in Documents and Images, Edict of Potsdam。"}],"relationItems":["← 前因：弗里德里希·威廉“大选侯”","↔ 相关：勃兰登堡-普鲁士崛起","↔ 同时期参考：法国废除南特敕令（1685）","↔ 相关：普鲁士开明专制"],"relations":[{"text":"← 前因：弗里德里希·威廉“大选侯”","id":"extra432"},{"text":"↔ 相关：勃兰登堡-普鲁士崛起","id":"extra311"},{"text":"↔ 同时期参考：法国废除南特敕令（1685）","id":"extra902"},{"text":"↔ 相关：普鲁士开明专制","id":"extra340"}],"source":"history","id":"extra434"},{"title":"三十年战争《归还敕令》","level":"B","type":"制度/文本卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1629年3月6日","place":"神圣罗马帝国","summary":"《归还敕令》要求归还被新教占有的天主教教产，使三十年战争宗教冲突进一步激化。","fields":[{"label":"标题","value":"三十年战争《归还敕令》"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1629年3月6日"},{"label":"地点","value":"神圣罗马帝国"},{"label":"主要国家","value":"神圣罗马帝国；德意志地区；奥地利"},{"label":"一句话概括","value":"《归还敕令》要求归还被新教占有的天主教教产，使三十年战争宗教冲突进一步激化。"},{"label":"制定方/签署方","value":"神圣罗马皇帝斐迪南二世。"},{"label":"主要内容","value":"要求自1552年以来被新教诸侯和城市占有的天主教教会财产归还，并强化宗教改革《奥格斯堡和约》中天主教解释。"},{"label":"它试图解决什么问题","value":"它试图利用皇帝和天主教阵营军事优势，逆转宗教改革以来教会财产转移和新教扩张。"},{"label":"为什么重要","value":"它是三十年战争升级节点，令许多新教诸侯担心皇帝要重建天主教和中央权威。"},{"label":"争议/局限","value":"敕令过于激进，执行会冲击大量领地利益，连部分天主教盟友也担心皇帝权力过强。"},{"label":"造成的影响","value":"新教恐惧加深，瑞典介入获得更多政治理由；战争从帝国内战进一步走向国际化。"},{"label":"出处","value":"Britannica, Edict of Restitution；Britannica, Thirty Years War；Britannica, Ferdinand II。"}],"relationItems":["← 前因：三十年战争白山战役","→ 后果：瑞典介入三十年战争","↔ 相关：三十年战争","↔ 相关：宗教改革《奥格斯堡和约》"],"relations":[{"text":"← 前因：三十年战争白山战役","id":"extra331"},{"text":"→ 后果：瑞典介入三十年战争","id":"extra334"},{"text":"↔ 相关：三十年战争","id":"extra307"},{"text":"↔ 相关：宗教改革《奥格斯堡和约》","id":"extra305"}],"source":"history","id":"extra435"},{"title":"吕岑战役（1632）","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1632年11月16日","place":"萨克森吕岑附近","summary":"吕岑战役中瑞典获战术胜利但古斯塔夫二世战死，三十年战争失去关键新教军事领袖。","fields":[{"label":"标题","value":"吕岑战役（1632）"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1632年11月16日"},{"label":"地点","value":"萨克森吕岑附近"},{"label":"主要国家","value":"瑞典；神圣罗马帝国；德意志地区"},{"label":"一句话概括","value":"吕岑战役中瑞典获战术胜利但古斯塔夫二世战死，三十年战争失去关键新教军事领袖。"},{"label":"参与者","value":"瑞典国王古斯塔夫二世·阿道夫、华伦斯坦、瑞典军队、帝国军队。"},{"label":"发生了什么","value":"瑞典介入三十年战争后继续在德意志作战。1632年，古斯塔夫二世与华伦斯坦在吕岑附近交战，瑞典军队最终迫使帝国军撤退，但古斯塔夫二世在战斗中阵亡。"},{"label":"为什么重要","value":"它改变了战争领导格局。瑞典仍是强大参战方，但失去具有个人威望和战略能力的国王，德意志战局更依赖联盟和外交。"},{"label":"前因","value":"瑞典在布赖滕费尔德胜利后深入德意志中部，威胁皇帝和天主教阵营的战略空间；华伦斯坦重新组织帝国军，试图阻止瑞典继续推进。"},{"label":"后果","value":"瑞典继续参战但政治军事协调变复杂，新教阵营失去具有个人威望的领袖；法国和其他力量在后续战争中的作用逐渐上升。"},{"label":"出处","value":"Britannica, Battle of Lutzen；Britannica, Gustavus Adolphus；Britannica, Thirty Years War。"}],"relationItems":["← 前因：三十年战争布赖滕费尔德战役","↔ 相关：瑞典介入三十年战争","↔ 相关：阿尔布雷希特·冯·华伦斯坦","→ 后果：三十年战争诺德林根战役"],"relations":[{"text":"← 前因：三十年战争布赖滕费尔德战役","id":"extra335"},{"text":"↔ 相关：瑞典介入三十年战争","id":"extra334"},{"text":"↔ 相关：阿尔布雷希特·冯·华伦斯坦","id":"extra332"},{"text":"→ 后果：三十年战争诺德林根战役","id":"extra438"}],"source":"history","id":"extra436"},{"title":"勃兰登堡-普鲁士常备军与财政国家","level":"B","type":"概念/思潮卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"17世纪中后期起","place":"勃兰登堡-普鲁士各分散领地","summary":"勃兰登堡-普鲁士通过常备军、税收和官僚整合分散领地，为后来的普鲁士强国化奠基。","fields":[{"label":"标题","value":"勃兰登堡-普鲁士常备军与财政国家"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"17世纪中后期起"},{"label":"地点","value":"勃兰登堡-普鲁士各分散领地"},{"label":"主要国家","value":"勃兰登堡；普鲁士；神圣罗马帝国"},{"label":"一句话概括","value":"勃兰登堡-普鲁士通过常备军、税收和官僚整合分散领地，为后来的普鲁士强国化奠基。"},{"label":"核心主张/思路","value":"统治者把安全压力转化为制度建设，用常备军、固定税收、中央官僚和领地协调整合分散的霍亨索伦领地。"},{"label":"提出者/代表人物（可选）","value":"弗里德里希·威廉“大选侯”及其财政、军事官僚。"},{"label":"它从何而来","value":"三十年战争暴露勃兰登堡分散领地的脆弱性，波兰、瑞典、法国和帝国政治压力也要求统治者拥有可持续军事动员能力。"},{"label":"典型表现","value":"扩大常备军、加强征税、削弱地方等级对财政的控制、建设行政机构，并把军队作为王朝安全和国家整合核心。"},{"label":"为什么重要","value":"它解释普鲁士崛起不只是几场战争胜利，而是长期财政军事制度建设的结果。"},{"label":"争议/局限","value":"这种国家建设提高了效率和安全，也强化君主权力、军事优先和社会服从，给后来的普鲁士政治文化留下深刻印记。"},{"label":"出处","value":"Britannica, Frederick William；Britannica, Prussia；Christopher Clark, Iron Kingdom。"}],"relationItems":["← 前因：弗里德里希·威廉“大选侯”","→ 后果：普鲁士王国成立","↔ 相关：勃兰登堡-瑞典费尔贝林战役","↔ 相关：勃兰登堡-普鲁士崛起"],"relations":[{"text":"← 前因：弗里德里希·威廉“大选侯”","id":"extra432"},{"text":"→ 后果：普鲁士王国成立","id":"extra312"},{"text":"↔ 相关：勃兰登堡-瑞典费尔贝林战役","id":"extra433"},{"text":"↔ 相关：勃兰登堡-普鲁士崛起","id":"extra311"}],"source":"history","id":"extra437"},{"title":"三十年战争诺德林根战役","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1634年9月5—6日","place":"德意志南部诺德林根附近","summary":"三十年战争诺德林根战役中皇帝和西班牙军击败瑞典-新教军，改变三十年战争力量平衡。","fields":[{"label":"标题","value":"三十年战争诺德林根战役"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1634年9月5—6日"},{"label":"地点","value":"德意志南部诺德林根附近"},{"label":"主要国家","value":"神圣罗马帝国；瑞典；西班牙；德意志地区"},{"label":"一句话概括","value":"三十年战争诺德林根战役中皇帝和西班牙军击败瑞典-新教军，改变三十年战争力量平衡。"},{"label":"参与者","value":"皇帝军、西班牙哈布斯堡军、瑞典军、德意志新教盟军。"},{"label":"发生了什么","value":"1634年，皇帝军与西班牙援军在诺德林根附近同瑞典及德意志新教军交战。瑞典阵营遭遇重大失败，失去此前在德意志南部的战略优势。"},{"label":"为什么重要","value":"它使瑞典在德意志的军事优势受挫，也让许多新教诸侯重新评估继续战争的代价。"},{"label":"前因","value":"古斯塔夫二世死后，瑞典军虽继续作战，但指挥和政治协调不如此前；皇帝阵营则得到西班牙哈布斯堡支援，试图恢复南德控制。"},{"label":"后果","value":"新教阵营分化，萨克森等诸侯更愿意与皇帝妥协，1635年布拉格和约由此获得现实基础；瑞典在德意志的主导地位下降，法国公开介入的空间扩大。"},{"label":"出处","value":"Britannica, Battle of Nördlingen；Britannica, Thirty Years War。"}],"relationItems":["← 前因：吕岑战役（1632）","→ 后果：布拉格和约（1635）","↔ 相关：三十年战争","↔ 相关：瑞典介入三十年战争"],"relations":[{"text":"← 前因：吕岑战役（1632）","id":"extra436"},{"text":"→ 后果：布拉格和约（1635）","id":"extra439"},{"text":"↔ 相关：三十年战争","id":"extra307"},{"text":"↔ 相关：瑞典介入三十年战争","id":"extra334"}],"source":"history","id":"extra438"},{"title":"布拉格和约（1635）","level":"B","type":"制度/文本卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1635年5月30日","place":"布拉格","summary":"布拉格和约试图让皇帝与多数德意志诸侯停战，但未能结束国际化的三十年战争。","fields":[{"label":"标题","value":"布拉格和约（1635）"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1635年5月30日"},{"label":"地点","value":"布拉格"},{"label":"主要国家","value":"神圣罗马帝国；德意志地区；萨克森；奥地利"},{"label":"一句话概括","value":"布拉格和约试图让皇帝与多数德意志诸侯停战，但未能结束国际化的三十年战争。"},{"label":"制定方/签署方","value":"神圣罗马皇帝斐迪南二世与萨克森选侯约翰·格奥尔格一世，后有多个帝国等级加入。"},{"label":"主要内容","value":"撤回或缓和《归还敕令》的执行，皇帝与德意志诸侯寻求共同和平，并把诸侯军队纳入更统一的帝国军事安排。"},{"label":"它试图解决什么问题","value":"它试图结束帝国内部天主教与新教诸侯间的战争，把冲突从宗教内战转向反对外部干预。"},{"label":"为什么重要","value":"它说明三十年战争已不只是德意志宗教战争；即便帝国内部达成妥协，法国、瑞典和西班牙仍会继续争夺欧洲霸权。"},{"label":"争议/局限","value":"和约排除加尔文宗等部分力量，也无法让瑞典和法国接受退出战争。"},{"label":"造成的影响","value":"萨克森等诸侯脱离瑞典阵营，德意志天主教联盟解散，但战争继续以更明显的国际战争形态展开。"},{"label":"出处","value":"Britannica, Peace of Prague；Britannica, Thirty Years War。"}],"relationItems":["← 前因：三十年战争诺德林根战役","→ 后果：法国直接介入三十年战争","↔ 相关：三十年战争《归还敕令》","↔ 相关：三十年战争"],"relations":[{"text":"← 前因：三十年战争诺德林根战役","id":"extra438"},{"text":"→ 后果：法国直接介入三十年战争","id":"extra440"},{"text":"↔ 相关：三十年战争《归还敕令》","id":"extra435"},{"text":"↔ 相关：三十年战争","id":"extra307"}],"source":"history","id":"extra439"},{"title":"法国直接介入三十年战争","level":"A","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1635年起","place":"法兰西、德意志西部、尼德兰和莱茵地区","summary":"法国在1635年公开参战，使三十年战争从帝国内部冲突彻底转为欧洲霸权战争。","fields":[{"label":"标题","value":"法国直接介入三十年战争"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1635年起"},{"label":"地点","value":"法兰西、德意志西部、尼德兰和莱茵地区"},{"label":"主要国家","value":"法国；神圣罗马帝国；西班牙；瑞典"},{"label":"一句话概括","value":"法国在1635年公开参战，使三十年战争从帝国内部冲突彻底转为欧洲霸权战争。"},{"label":"参与者","value":"法国王室、黎塞留、哈布斯堡西班牙和奥地利、瑞典、德意志诸侯。"},{"label":"发生了什么","value":"在长期资助反哈布斯堡力量后，法国于1635年公开对西班牙宣战，并在德意志和莱茵方向扩大军事行动。天主教法国与新教瑞典在反哈布斯堡目标上形成事实合作。"},{"label":"为什么重要","value":"它是三十年战争性质转变的关键节点：宗教阵营不再能解释全部战争逻辑，国家利益和反哈布斯堡均势成为主线。"},{"label":"前因","value":"三十年战争诺德林根战役和布拉格和约削弱瑞典与德意志新教阵营，法国担心哈布斯堡重新控制帝国并包围法国。"},{"label":"后果","value":"战争继续延长十余年，莱茵和德意志西部遭受更多破坏；最终威斯特伐利亚体系承认法国和瑞典的战后收益。"},{"label":"出处","value":"Britannica, Thirty Years War；Britannica, Cardinal de Richelieu。"}],"relationItems":["← 前因：布拉格和约（1635）","→ 后果：威斯特伐利亚和约","↔ 相关：三十年战争","↔ 同时期参考：黎塞留反哈布斯堡政策"],"relations":[{"text":"← 前因：布拉格和约（1635）","id":"extra439"},{"text":"→ 后果：威斯特伐利亚和约","id":"extra308"},{"text":"↔ 相关：三十年战争","id":"extra307"},{"text":"↔ 同时期参考：黎塞留反哈布斯堡政策","id":"extra903"}],"source":"history","id":"extra440"},{"title":"法西《比利牛斯条约》","level":"B","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1659年11月7日","place":"比利牛斯边界附近费桑岛","summary":"法西《比利牛斯条约》结束法西战争，标志西班牙哈布斯堡衰落和法国霸权上升。","fields":[{"label":"标题","value":"法西《比利牛斯条约》"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1659年11月7日"},{"label":"地点","value":"比利牛斯边界附近费桑岛"},{"label":"主要国家","value":"法国；西班牙；神圣罗马帝国相关哈布斯堡体系"},{"label":"一句话概括","value":"法西《比利牛斯条约》结束法西战争，标志西班牙哈布斯堡衰落和法国霸权上升。"},{"label":"制定方/签署方","value":"法国王室与西班牙王室。"},{"label":"主要内容","value":"西班牙向法国割让部分边境领地，安排路易十四与西班牙公主玛丽-泰蕾莎的婚姻，并结束1635年以来的法西战争。"},{"label":"它试图解决什么问题","value":"它试图结束三十年战争后仍持续的法西冲突，重新划定西欧权力边界。"},{"label":"为什么重要","value":"它不是德意志内部条约，但对哈布斯堡体系和欧洲均势影响巨大，法国从此成为德意志西部最强外部压力。"},{"label":"争议/局限","value":"婚姻安排后来成为西班牙王位继承战争的理由之一，条约没有永久稳定法国与哈布斯堡关系。"},{"label":"造成的影响","value":"西班牙霸权进一步衰落，法国在莱茵和低地地区影响扩大，神圣罗马帝国西部长期面临法国扩张压力。"},{"label":"出处","value":"Britannica, Peace of the Pyrenees；Britannica, Louis XIV。"}],"relationItems":["← 前因：法国直接介入三十年战争","↔ 相关：威斯特伐利亚和约","→ 后果：西班牙王位继承战争","↔ 同时期参考：路易十四法国"],"relations":[{"text":"← 前因：法国直接介入三十年战争","id":"extra440"},{"text":"↔ 相关：威斯特伐利亚和约","id":"extra308"},{"text":"→ 后果：西班牙王位继承战争","id":"extra447"},{"text":"↔ 同时期参考：路易十四法国","id":"extra882"}],"source":"history","id":"extra441"},{"title":"利奥波德一世","level":"B","type":"人物卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1640—1705年；1658—1705年为神圣罗马皇帝","place":"维也纳、神圣罗马帝国、匈牙利和中欧战场","summary":"利奥波德一世统治时期，哈布斯堡同时面对法国扩张和奥斯曼压力，并巩固奥地利大国地位。","fields":[{"label":"标题","value":"利奥波德一世"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1640—1705年；1658—1705年为神圣罗马皇帝"},{"label":"地点","value":"维也纳、神圣罗马帝国、匈牙利和中欧战场"},{"label":"主要国家","value":"奥地利；神圣罗马帝国；匈牙利；奥斯曼帝国"},{"label":"一句话概括","value":"利奥波德一世统治时期，哈布斯堡同时面对法国扩张和奥斯曼压力，并巩固奥地利大国地位。"},{"label":"生卒年/活跃年代","value":"1640—1705年。"},{"label":"身份/职务","value":"哈布斯堡君主、神圣罗马皇帝。"},{"label":"关键贡献/作为","value":"在位期间经历第二次维也纳围城、大土耳其战争、反法战争和西班牙王位继承危机，并推动哈布斯堡在匈牙利和中欧扩张。"},{"label":"核心主张/立场","value":"维护哈布斯堡王朝利益和天主教王权，同时在帝国、匈牙利和欧洲均势中周旋。"},{"label":"为什么重要","value":"他处在哈布斯堡从中欧防御者转向多民族大国的关键时期。"},{"label":"争议/评价","value":"其统治强化哈布斯堡权力，也加剧匈牙利贵族和新教徒对中央化和反宗教改革政策的不满。"},{"label":"关联事件（可选）","value":"奥斯曼第二次围攻维也纳；卡洛维茨条约；西班牙王位继承战争。"},{"label":"出处","value":"Britannica, Leopold I；Britannica, Austria - history。"}],"relationItems":["← 前因：威斯特伐利亚和约","→ 后果：奥斯曼第二次围攻维也纳","→ 后果：奥斯曼-哈布斯堡《卡洛维茨条约》","↔ 相关：哈布斯堡君主国"],"relations":[{"text":"← 前因：威斯特伐利亚和约","id":"extra308"},{"text":"→ 后果：奥斯曼第二次围攻维也纳","id":"extra310"},{"text":"→ 后果：奥斯曼-哈布斯堡《卡洛维茨条约》","id":"extra446"},{"text":"↔ 相关：哈布斯堡君主国","id":"extra309"}],"source":"history","id":"extra442"},{"title":"神圣同盟与大土耳其战争","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1684—1699年","place":"匈牙利、巴尔干、维也纳至多瑙河流域","summary":"维也纳解围后，神圣同盟持续反攻奥斯曼，改变中欧和巴尔干权力格局。","fields":[{"label":"标题","value":"神圣同盟与大土耳其战争"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1684—1699年"},{"label":"地点","value":"匈牙利、巴尔干、维也纳至多瑙河流域"},{"label":"主要国家","value":"奥地利；奥斯曼帝国；波兰立陶宛；威尼斯；俄罗斯"},{"label":"一句话概括","value":"维也纳解围后，神圣同盟持续反攻奥斯曼，改变中欧和巴尔干权力格局。"},{"label":"参与者","value":"哈布斯堡奥地利、波兰立陶宛、威尼斯、教皇国、后来加入的俄罗斯、奥斯曼帝国。"},{"label":"发生了什么","value":"1683年维也纳解围后，反奥斯曼力量在教皇支持下形成神圣同盟。哈布斯堡军队和盟友沿多瑙河与巴尔干方向持续进攻，夺回布达等重要地区，战争持续到1699年卡洛维茨条约。"},{"label":"为什么重要","value":"它使奥斯曼在中欧的扩张转入退却，哈布斯堡则获得匈牙利和巴尔干北部的巨大影响力。"},{"label":"前因","value":"奥斯曼第二次围攻维也纳失败后，欧洲天主教力量看到反攻机会；哈布斯堡也希望把匈牙利从奥斯曼控制中夺回。"},{"label":"后果","value":"奥斯曼失去大片中欧领土，哈布斯堡君主国的多民族结构显著扩大；匈牙利、特兰西瓦尼亚和巴尔干北部问题由此成为奥地利长期治理重点。"},{"label":"出处","value":"Britannica, Holy League；Britannica, Ottoman Empire；Britannica, Treaty of Karlowitz。"}],"relationItems":["← 前因：奥斯曼第二次围攻维也纳","→ 后果：奥斯曼-哈布斯堡《卡洛维茨条约》","↔ 相关：利奥波德一世","↔ 相关：哈布斯堡将领欧根亲王"],"relations":[{"text":"← 前因：奥斯曼第二次围攻维也纳","id":"extra310"},{"text":"→ 后果：奥斯曼-哈布斯堡《卡洛维茨条约》","id":"extra446"},{"text":"↔ 相关：利奥波德一世","id":"extra442"},{"text":"↔ 相关：哈布斯堡将领欧根亲王","id":"extra444"}],"source":"history","id":"extra443"},{"title":"哈布斯堡将领欧根亲王","level":"B","type":"人物卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1663—1736年","place":"奥地利、匈牙利、意大利、尼德兰和巴尔干战场","summary":"欧根亲王是哈布斯堡名将，在反奥斯曼和反法战争中推动奥地利成为欧洲大国。","fields":[{"label":"标题","value":"哈布斯堡将领欧根亲王"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1663—1736年"},{"label":"地点","value":"奥地利、匈牙利、意大利、尼德兰和巴尔干战场"},{"label":"主要国家","value":"奥地利；神圣罗马帝国；法国；奥斯曼帝国"},{"label":"一句话概括","value":"欧根亲王是哈布斯堡名将，在反奥斯曼和反法战争中推动奥地利成为欧洲大国。"},{"label":"生卒年/活跃年代","value":"1663—1736年。"},{"label":"身份/职务","value":"哈布斯堡军队统帅、政治顾问。"},{"label":"关键贡献/作为","value":"参与维也纳解围后的反奥斯曼战争，在哈布斯堡-奥斯曼森塔战役等战斗中成名，并在西班牙王位继承战争中与马尔伯勒合作。"},{"label":"核心主张/立场","value":"服务哈布斯堡王朝，以军事改革和联盟战争维护奥地利在中欧、意大利和巴尔干的利益。"},{"label":"为什么重要","value":"他代表奥地利军事强国化时期的统帅类型，也是哈布斯堡从防御奥斯曼转向主动扩张的象征。"},{"label":"争议/评价","value":"欧根的军事成就显著，但战争扩张也加重哈布斯堡财政和多民族统治压力。"},{"label":"关联事件（可选）","value":"哈布斯堡-奥斯曼森塔战役；西班牙王位继承战争布伦海姆战役；卡洛维茨条约。"},{"label":"出处","value":"Britannica, Eugene of Savoy；Britannica, Austria - history。"}],"relationItems":["← 前因：神圣同盟与大土耳其战争","→ 后果：哈布斯堡-奥斯曼森塔战役","↔ 相关：利奥波德一世","↔ 相关：西班牙王位继承战争"],"relations":[{"text":"← 前因：神圣同盟与大土耳其战争","id":"extra443"},{"text":"→ 后果：哈布斯堡-奥斯曼森塔战役","id":"extra445"},{"text":"↔ 相关：利奥波德一世","id":"extra442"},{"text":"↔ 相关：西班牙王位继承战争","id":"extra447"}],"source":"history","id":"extra444"},{"title":"哈布斯堡-奥斯曼森塔战役","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1697年9月11日","place":"蒂萨河畔森塔，今塞尔维亚森塔","summary":"欧根亲王在森塔重创奥斯曼军队，为1699年卡洛维茨条约创造军事条件。","fields":[{"label":"标题","value":"哈布斯堡-奥斯曼森塔战役"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1697年9月11日"},{"label":"地点","value":"蒂萨河畔森塔，今塞尔维亚森塔"},{"label":"主要国家","value":"奥地利；奥斯曼帝国；匈牙利"},{"label":"一句话概括","value":"欧根亲王在森塔重创奥斯曼军队，为1699年卡洛维茨条约创造军事条件。"},{"label":"参与者","value":"欧根亲王、哈布斯堡军队、奥斯曼苏丹穆斯塔法二世及奥斯曼军队。"},{"label":"发生了什么","value":"1697年，欧根亲王抓住奥斯曼军队渡过蒂萨河时机发动攻击，造成奥斯曼军重大损失。战斗削弱奥斯曼继续在匈牙利方向作战的能力。"},{"label":"为什么重要","value":"它是大土耳其战争后期关键胜利，直接推动奥斯曼接受谈判。"},{"label":"前因","value":"维也纳围城失败后，哈布斯堡和神圣同盟持续反攻，奥斯曼试图稳住匈牙利和巴尔干防线；长期战争使双方都希望通过一次决定性行动改变谈判地位。"},{"label":"后果","value":"奥斯曼被迫在卡洛维茨谈判中承认中欧大规模领土损失，哈布斯堡在匈牙利地位大幅巩固；欧根亲王也由此成为奥地利军事崛起的象征人物。"},{"label":"出处","value":"Britannica, Eugene of Savoy；Britannica, Treaty of Karlowitz。"}],"relationItems":["← 前因：神圣同盟与大土耳其战争","→ 后果：奥斯曼-哈布斯堡《卡洛维茨条约》","↔ 相关：哈布斯堡将领欧根亲王","↔ 同时期参考：奥斯曼帝国军事转折"],"relations":[{"text":"← 前因：神圣同盟与大土耳其战争","id":"extra443"},{"text":"→ 后果：奥斯曼-哈布斯堡《卡洛维茨条约》","id":"extra446"},{"text":"↔ 相关：哈布斯堡将领欧根亲王","id":"extra444"}],"source":"history","id":"extra445"},{"title":"奥斯曼-哈布斯堡《卡洛维茨条约》","level":"A","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1699年1月26日","place":"卡洛维茨，今塞尔维亚斯雷姆斯基卡尔洛夫奇","summary":"卡洛维茨条约结束大土耳其战争，标志奥斯曼在中欧扩张的重大退潮。","fields":[{"label":"标题","value":"奥斯曼-哈布斯堡《卡洛维茨条约》"},{"label":"分级","value":"A"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1699年1月26日"},{"label":"地点","value":"卡洛维茨，今塞尔维亚斯雷姆斯基卡尔洛夫奇"},{"label":"主要国家","value":"奥地利；奥斯曼帝国；波兰立陶宛；威尼斯；俄罗斯"},{"label":"一句话概括","value":"卡洛维茨条约结束大土耳其战争，标志奥斯曼在中欧扩张的重大退潮。"},{"label":"制定方/签署方","value":"奥斯曼帝国与神圣同盟成员，包括哈布斯堡奥地利、波兰立陶宛、威尼斯等。"},{"label":"主要内容","value":"奥斯曼向哈布斯堡让出匈牙利和特兰西瓦尼亚大部分地区，向威尼斯和波兰等作出其他领土让步。"},{"label":"它试图解决什么问题","value":"它试图结束1683年以来的长期战争，并用条约形式确认奥斯曼在中欧战败后的新边界。"},{"label":"为什么重要","value":"它是欧洲和奥斯曼关系的重大转折。哈布斯堡从边境防御者转变为中欧和巴尔干北部扩张大国。"},{"label":"争议/局限","value":"条约没有结束哈布斯堡-奥斯曼竞争，巴尔干和匈牙利治理问题仍复杂。"},{"label":"造成的影响","value":"奥地利控制多民族领土扩大，匈牙利贵族、宗教和民族问题成为哈布斯堡长期内政难题。"},{"label":"出处","value":"Britannica, Treaty of Karlowitz；Britannica, Ottoman Empire；Britannica, Leopold I。"}],"relationItems":["← 前因：哈布斯堡-奥斯曼森塔战役","↔ 相关：神圣同盟与大土耳其战争","↔ 相关：利奥波德一世","↔ 同时期参考：奥斯曼帝国转型"],"relations":[{"text":"← 前因：哈布斯堡-奥斯曼森塔战役","id":"extra445"},{"text":"↔ 相关：神圣同盟与大土耳其战争","id":"extra443"},{"text":"↔ 相关：利奥波德一世","id":"extra442"}],"source":"history","id":"extra446"},{"title":"西班牙王位继承战争","level":"A","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1701—1714年","place":"西欧、中欧、意大利、低地国家和海外殖民地","summary":"西班牙王位继承战争围绕西班牙帝国继承展开，是欧洲均势政治的代表性大战。","fields":[{"label":"标题","value":"西班牙王位继承战争"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1701—1714年"},{"label":"地点","value":"西欧、中欧、意大利、低地国家和海外殖民地"},{"label":"主要国家","value":"法国；奥地利；西班牙；英国；荷兰共和国；神圣罗马帝国"},{"label":"一句话概括","value":"西班牙王位继承战争围绕西班牙帝国继承展开，是欧洲均势政治的代表性大战。"},{"label":"参与者","value":"波旁法国、西班牙波旁继承人、奥地利哈布斯堡、英国、荷兰共和国、神圣罗马帝国诸侯。"},{"label":"发生了什么","value":"西班牙哈布斯堡绝嗣后，法国波旁和奥地利哈布斯堡争夺西班牙王位及其全球帝国。欧洲多国结盟阻止法国和西班牙合并为超级王朝，战争在欧洲和海外多战场展开。"},{"label":"为什么重要","value":"它决定18世纪初欧洲均势格局，也影响奥地利在意大利和低地的地位。"},{"label":"前因","value":"法西《比利牛斯条约》的婚姻安排留下继承争议，西班牙哈布斯堡绝嗣使问题爆发；路易十四法国扩张又让欧洲列强担心波旁王朝同时控制法国和西班牙。"},{"label":"后果","value":"西班牙王位继承战争《乌得勒支和约》确认波旁继承西班牙王位但限制法西合并，奥地利获得西属尼德兰和意大利部分领地；英国则在海权和殖民利益上显著上升。"},{"label":"出处","value":"Britannica, War of the Spanish Succession；Britannica, Louis XIV。"}],"relationItems":["← 前因：法西《比利牛斯条约》","→ 后果：西班牙王位继承战争布伦海姆战役","→ 后果：西班牙王位继承战争《乌得勒支和约》","↔ 相关：哈布斯堡将领欧根亲王"],"relations":[{"text":"← 前因：法西《比利牛斯条约》","id":"extra441"},{"text":"→ 后果：西班牙王位继承战争布伦海姆战役","id":"extra448"},{"text":"→ 后果：西班牙王位继承战争《乌得勒支和约》","id":"extra449"},{"text":"↔ 相关：哈布斯堡将领欧根亲王","id":"extra444"}],"source":"history","id":"extra447"},{"title":"西班牙王位继承战争布伦海姆战役","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1704年8月13日","place":"巴伐利亚布伦海姆附近","summary":"西班牙王位继承战争布伦海姆战役中英奥联军击败法巴军队，挫败法国控制中欧的战略威胁。","fields":[{"label":"标题","value":"西班牙王位继承战争布伦海姆战役"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1704年8月13日"},{"label":"地点","value":"巴伐利亚布伦海姆附近"},{"label":"主要国家","value":"英国；奥地利；法国；巴伐利亚；神圣罗马帝国"},{"label":"一句话概括","value":"西班牙王位继承战争布伦海姆战役中英奥联军击败法巴军队，挫败法国控制中欧的战略威胁。"},{"label":"参与者","value":"马尔伯勒公爵、欧根亲王、法国和巴伐利亚军队、哈布斯堡军队。"},{"label":"发生了什么","value":"1704年，法国与巴伐利亚试图威胁维也纳并削弱奥地利。马尔伯勒率英荷军与欧根亲王的哈布斯堡军协同，在布伦海姆附近击败法巴军队。"},{"label":"为什么重要","value":"它是西班牙王位继承战争转折性战役之一，终结路易十四在中欧取得决定性胜利的可能。"},{"label":"前因","value":"法国和巴伐利亚的联盟给奥地利造成巨大压力，若维也纳受威胁，反法同盟可能瓦解；英奥双方因此需要在德意志南部阻止法军和巴伐利亚军会合推进。"},{"label":"后果","value":"巴伐利亚被占领，法国战略主动权受挫，英奥合作在欧洲均势战争中显示强大威力；路易十四取得中欧决定性胜利的可能性基本消失。"},{"label":"出处","value":"Britannica, Battle of Blenheim；Britannica, Eugene of Savoy；Britannica, Marlborough。"}],"relationItems":["← 前因：西班牙王位继承战争","↔ 相关：哈布斯堡将领欧根亲王","→ 后果：西班牙王位继承战争《乌得勒支和约》","↔ 同时期参考：路易十四法国"],"relations":[{"text":"← 前因：西班牙王位继承战争","id":"extra447"},{"text":"↔ 相关：哈布斯堡将领欧根亲王","id":"extra444"},{"text":"→ 后果：西班牙王位继承战争《乌得勒支和约》","id":"extra449"},{"text":"↔ 同时期参考：路易十四法国","id":"extra882"}],"source":"history","id":"extra448"},{"title":"西班牙王位继承战争《乌得勒支和约》","level":"A","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1713年","place":"乌得勒支","summary":"西班牙王位继承战争《乌得勒支和约》重组西班牙王位继承战争后的欧洲均势，限制法国和西班牙合并。","fields":[{"label":"标题","value":"西班牙王位继承战争《乌得勒支和约》"},{"label":"分级","value":"A"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1713年"},{"label":"地点","value":"乌得勒支"},{"label":"主要国家","value":"法国；西班牙；英国；奥地利；荷兰共和国"},{"label":"一句话概括","value":"西班牙王位继承战争《乌得勒支和约》重组西班牙王位继承战争后的欧洲均势，限制法国和西班牙合并。"},{"label":"制定方/签署方","value":"法国、西班牙、英国、荷兰共和国、普鲁士、葡萄牙、萨伏依等；奥地利稍后通过拉施塔特和巴登等和约处理。"},{"label":"主要内容","value":"承认腓力五世为西班牙国王，但禁止法国和西班牙王冠合并；英国获得直布罗陀等战略利益，欧洲领土重新分配。"},{"label":"它试图解决什么问题","value":"它试图结束围绕西班牙继承的欧洲大战，并防止任何一个王朝控制法国与西班牙两大权力中心。"},{"label":"为什么重要","value":"它是18世纪欧洲均势体系的重要文本，奥地利也通过相关和约获得西属尼德兰和意大利利益。"},{"label":"争议/局限","value":"和约牺牲部分地区意愿，殖民和商业利益也被列强重新瓜分；欧洲竞争并未结束。"},{"label":"造成的影响","value":"英国海上和殖民地位增强，法国霸权受限，奥地利在中欧以外的领地负担扩大。"},{"label":"出处","value":"Britannica, Treaties of Utrecht；Britannica, War of the Spanish Succession。"}],"relationItems":["← 前因：西班牙王位继承战争","↔ 相关：西班牙王位继承战争布伦海姆战役","↔ 相关：哈布斯堡将领欧根亲王","↔ 同时期参考：欧洲均势"],"relations":[{"text":"← 前因：西班牙王位继承战争","id":"extra447"},{"text":"↔ 相关：西班牙王位继承战争布伦海姆战役","id":"extra448"},{"text":"↔ 相关：哈布斯堡将领欧根亲王","id":"extra444"}],"source":"history","id":"extra449"},{"title":"哈布斯堡《国事诏书》","level":"B","type":"制度/文本卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1713年4月19日","place":"维也纳","summary":"查理六世的《国事诏书》试图保障哈布斯堡领地不可分割，并允许女性继承。","fields":[{"label":"标题","value":"哈布斯堡《国事诏书》"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1713年4月19日"},{"label":"地点","value":"维也纳"},{"label":"主要国家","value":"奥地利；哈布斯堡君主国；神圣罗马帝国"},{"label":"一句话概括","value":"查理六世的《国事诏书》试图保障哈布斯堡领地不可分割，并允许女性继承。"},{"label":"制定方/签署方","value":"哈布斯堡皇帝查理六世颁布，并长期争取欧洲列强和各领地等级承认。"},{"label":"主要内容","value":"规定哈布斯堡世袭领地应保持不可分割，并在无男性继承人时允许女性继承，最终指向玛丽亚·特蕾莎的继承权。"},{"label":"它试图解决什么问题","value":"查理六世缺少男性继承人，需要防止其死后哈布斯堡领地被分割或遭外部挑战。"},{"label":"为什么重要","value":"它是奥地利王位继承战争的制度前因。欧洲列强表面承认，实际在查理六世死后纷纷挑战哈布斯堡继承。"},{"label":"争议/局限","value":"国际承认取决于利益而非法律本身，诏书无法阻止普鲁士、巴伐利亚和法国等势力行动。"},{"label":"造成的影响","value":"1740年查理六世去世后，玛丽亚·特蕾莎继位引发奥地利王位继承战争。"},{"label":"出处","value":"Britannica, Pragmatic Sanction of Emperor Charles VI；Britannica, Charles VI。"}],"relationItems":["→ 后果：奥地利王位继承战争","↔ 相关：玛丽亚·特蕾莎","↔ 相关：哈布斯堡君主查理六世","↔ 同时期参考：欧洲王朝继承政治"],"relations":[{"text":"→ 后果：奥地利王位继承战争","id":"extra313"},{"text":"↔ 相关：玛丽亚·特蕾莎","id":"extra314"},{"text":"↔ 相关：哈布斯堡君主查理六世","id":"extra451"}],"source":"history","id":"extra450"},{"title":"哈布斯堡君主查理六世","level":"B","type":"人物卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1685—1740年；1711—1740年为神圣罗马皇帝","place":"维也纳、哈布斯堡君主国和神圣罗马帝国","summary":"查理六世用《国事诏书》维护哈布斯堡继承，却在死后引发欧洲列强挑战。","fields":[{"label":"标题","value":"哈布斯堡君主查理六世"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1685—1740年；1711—1740年为神圣罗马皇帝"},{"label":"地点","value":"维也纳、哈布斯堡君主国和神圣罗马帝国"},{"label":"主要国家","value":"奥地利；神圣罗马帝国；匈牙利；波希米亚"},{"label":"一句话概括","value":"查理六世用《国事诏书》维护哈布斯堡继承，却在死后引发欧洲列强挑战。"},{"label":"生卒年/活跃年代","value":"1685—1740年。"},{"label":"身份/职务","value":"哈布斯堡君主、神圣罗马皇帝。"},{"label":"关键贡献/作为","value":"争取欧洲承认《国事诏书》，维护哈布斯堡领地整体继承，并在奥斯曼、意大利和帝国事务中延续王朝政策。"},{"label":"核心主张/立场","value":"保障哈布斯堡世袭领地完整和玛丽亚·特蕾莎继承权，是其晚年外交核心。"},{"label":"为什么重要","value":"他的继承安排直接引发奥地利王位继承战争，使普鲁士夺取西里西亚并打开德意志二元竞争。"},{"label":"争议/评价","value":"查理六世花费巨大外交代价换取承认，但没有同步建设足够军事实力来保证继承安排。"},{"label":"关联事件（可选）","value":"《国事诏书》；奥地利王位继承战争。"},{"label":"出处","value":"Britannica, Charles VI；Britannica, Pragmatic Sanction。"}],"relationItems":["→ 后果：哈布斯堡《国事诏书》","→ 后果：奥地利王位继承战争","↔ 相关：玛丽亚·特蕾莎","↔ 相关：哈布斯堡君主国"],"relations":[{"text":"→ 后果：哈布斯堡《国事诏书》","id":"extra450"},{"text":"→ 后果：奥地利王位继承战争","id":"extra313"},{"text":"↔ 相关：玛丽亚·特蕾莎","id":"extra314"},{"text":"↔ 相关：哈布斯堡君主国","id":"extra309"}],"source":"history","id":"extra451"},{"title":"弗里德里希·威廉一世“士兵王”","level":"B","type":"人物卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1688—1740年；1713—1740年为普鲁士国王","place":"柏林、波茨坦、普鲁士王国","summary":"弗里德里希·威廉一世把普鲁士塑造成财政严厉、军队优先的国家机器。","fields":[{"label":"标题","value":"弗里德里希·威廉一世“士兵王”"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1688—1740年；1713—1740年为普鲁士国王"},{"label":"地点","value":"柏林、波茨坦、普鲁士王国"},{"label":"主要国家","value":"普鲁士；勃兰登堡；神圣罗马帝国"},{"label":"一句话概括","value":"弗里德里希·威廉一世把普鲁士塑造成财政严厉、军队优先的国家机器。"},{"label":"生卒年/活跃年代","value":"1688—1740年。"},{"label":"身份/职务","value":"普鲁士国王，绰号“士兵王”。"},{"label":"关键贡献/作为","value":"大幅扩充和规范常备军，强化财政节约和官僚纪律，建立更有效的国家管理体系。"},{"label":"核心主张/立场","value":"国家资源优先服务军队和王权，官僚必须服从效率、节俭和纪律。"},{"label":"为什么重要","value":"他为腓特烈大王的军事扩张提供制度和军队基础，是普鲁士强国化的关键建构者。"},{"label":"争议/评价","value":"其统治高效但严厉，强化军事化和君主专制，社会文化空间受到压缩。"},{"label":"关联事件（可选）","value":"普鲁士总督府与战争财政机构合并；普鲁士征兵 canton 制。"},{"label":"出处","value":"Britannica, Frederick William I；Britannica, Prussia。"}],"relationItems":["← 前因：普鲁士王国成立","→ 后果：普鲁士总督府与战争财政机构合并","→ 后果：普鲁士征兵 canton 制","↔ 相关：普鲁士腓特烈大王"],"relations":[{"text":"← 前因：普鲁士王国成立","id":"extra312"},{"text":"→ 后果：普鲁士总督府与战争财政机构合并","id":"extra453"},{"text":"→ 后果：普鲁士征兵 canton 制","id":"extra454"},{"text":"↔ 相关：普鲁士腓特烈大王","id":"extra315"}],"source":"history","id":"extra452"},{"title":"普鲁士总督府与战争财政机构合并","level":"C","type":"制度/文本卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1723年","place":"柏林","summary":"1723年普鲁士合并中央行政和战争财政机构，提升军队、税收与官僚管理效率。","fields":[{"label":"标题","value":"普鲁士总督府与战争财政机构合并"},{"label":"分级","value":"C"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1723年"},{"label":"地点","value":"柏林"},{"label":"主要国家","value":"普鲁士；勃兰登堡"},{"label":"一句话概括","value":"1723年普鲁士合并中央行政和战争财政机构，提升军队、税收与官僚管理效率。"},{"label":"制定方/签署方","value":"普鲁士国王弗里德里希·威廉一世。"},{"label":"主要内容","value":"将总督府和战争财政相关机构整合为更集中的中央管理机关，协调财政、军事、领地行政和经济事务。"},{"label":"它试图解决什么问题","value":"普鲁士领地分散、财政有限，却需要维持大军；机构合并试图减少重叠，提高税收和行政执行力。"},{"label":"为什么重要","value":"它是普鲁士国家机器形成的重要机制卡，说明普鲁士强大来自行政财政改革而不只是战场胜利。"},{"label":"争议/局限","value":"高效行政服务于军队优先，地方等级和社会自主空间进一步受限。"},{"label":"造成的影响","value":"普鲁士官僚体系更加集中，财政军事国家能力增强，为腓特烈大王时期的战争动员打下基础。"},{"label":"出处","value":"Britannica, Frederick William I；Britannica, Prussia；Christopher Clark, Iron Kingdom。"}],"relationItems":["← 前因：弗里德里希·威廉一世“士兵王”","↔ 相关：勃兰登堡-普鲁士常备军与财政国家","↔ 相关：普鲁士征兵 canton 制","→ 后果：普鲁士腓特烈大王"],"relations":[{"text":"← 前因：弗里德里希·威廉一世“士兵王”","id":"extra452"},{"text":"↔ 相关：勃兰登堡-普鲁士常备军与财政国家","id":"extra437"},{"text":"↔ 相关：普鲁士征兵 canton 制","id":"extra454"},{"text":"→ 后果：普鲁士腓特烈大王","id":"extra315"}],"source":"history","id":"extra453"},{"title":"普鲁士征兵 canton 制","level":"C","type":"制度/文本卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1730年代形成","place":"普鲁士王国各征兵区","summary":"普鲁士 canton 制把农村人口编入固定征兵区，使常备军与地方社会长期绑定。","fields":[{"label":"标题","value":"普鲁士征兵 canton 制"},{"label":"分级","value":"C"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1730年代形成"},{"label":"地点","value":"普鲁士王国各征兵区"},{"label":"主要国家","value":"普鲁士；勃兰登堡"},{"label":"一句话概括","value":"普鲁士 canton 制把农村人口编入固定征兵区，使常备军与地方社会长期绑定。"},{"label":"制定方/签署方","value":"普鲁士王权和军事行政在弗里德里希·威廉一世时期推进。"},{"label":"主要内容","value":"把国家划分为征兵区，男性农民被登记到特定团队，平时务农，定期训练或服役，以支持庞大常备军。"},{"label":"它试图解决什么问题","value":"普鲁士人口和财政有限，无法像大国那样只靠雇佣兵；canton 制试图用本土人口稳定补充军队。"},{"label":"为什么重要","value":"它把普鲁士社会军事化制度化，强化军队、乡村和国家之间的直接联系。"},{"label":"争议/局限","value":"制度对贵族地主和农民义务安排不平等，贵族军官团地位得到加强，农民负担沉重。"},{"label":"造成的影响","value":"普鲁士能够维持远超人口规模的军队，并在西里西亚战争和七年战争中体现动员优势。"},{"label":"出处","value":"Britannica, Frederick William I；Britannica, Prussia；Christopher Clark, Iron Kingdom。"}],"relationItems":["← 前因：弗里德里希·威廉一世“士兵王”","↔ 相关：普鲁士总督府与战争财政机构合并","↔ 相关：勃兰登堡-普鲁士常备军与财政国家","→ 后果：第一次西里西亚战争"],"relations":[{"text":"← 前因：弗里德里希·威廉一世“士兵王”","id":"extra452"},{"text":"↔ 相关：普鲁士总督府与战争财政机构合并","id":"extra453"},{"text":"↔ 相关：勃兰登堡-普鲁士常备军与财政国家","id":"extra437"},{"text":"→ 后果：第一次西里西亚战争","id":"extra456"}],"source":"history","id":"extra454"},{"title":"萨尔茨堡新教徒迁入东普鲁士","level":"C","type":"事件卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"1731—1732年","place":"萨尔茨堡、东普鲁士","summary":"萨尔茨堡新教徒被驱逐后迁入东普鲁士，体现宗教难民、人口政策和国家建设的结合。","fields":[{"label":"标题","value":"萨尔茨堡新教徒迁入东普鲁士"},{"label":"分级","value":"C"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1731—1732年"},{"label":"地点","value":"萨尔茨堡、东普鲁士"},{"label":"主要国家","value":"奥地利；普鲁士；神圣罗马帝国"},{"label":"一句话概括","value":"萨尔茨堡新教徒被驱逐后迁入东普鲁士，体现宗教难民、人口政策和国家建设的结合。"},{"label":"参与者","value":"萨尔茨堡大主教、新教难民、普鲁士国王弗里德里希·威廉一世、东普鲁士地方官员。"},{"label":"发生了什么","value":"1731年，萨尔茨堡大主教驱逐大量新教徒。普鲁士接纳其中许多人，并将他们安置到东普鲁士，尤其是此前遭受瘟疫和人口损失的地区。"},{"label":"为什么重要","value":"它显示普鲁士继续把宗教宽容、移民安置和经济重建结合起来，也反映神圣罗马帝国内部宗教和平仍不等于个人信仰自由。"},{"label":"前因","value":"奥地利天主教领地的反宗教改革压力和地方宗教控制导致新教徒被迫迁徙；普鲁士则需要人口和劳动力开发东部地区。"},{"label":"后果","value":"东普鲁士人口得到补充，普鲁士新教保护者形象增强，同时宗教少数在旧制度欧洲中的脆弱性再次显现。"},{"label":"出处","value":"German History in Documents and Images, Salzburg Protestants；Britannica, Salzburg；Britannica, Frederick William I。"}],"relationItems":["← 前因：勃兰登堡-普鲁士《波茨坦敕令》","↔ 相关：普鲁士开明专制","↔ 相关：弗里德里希·威廉一世“士兵王”","↔ 同时期参考：欧洲宗教难民"],"relations":[{"text":"← 前因：勃兰登堡-普鲁士《波茨坦敕令》","id":"extra434"},{"text":"↔ 相关：普鲁士开明专制","id":"extra340"},{"text":"↔ 相关：弗里德里希·威廉一世“士兵王”","id":"extra452"}],"source":"history","id":"extra455"},{"title":"第一次西里西亚战争","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1740—1742年","place":"西里西亚、波希米亚、奥地利和普鲁士战场","summary":"腓特烈二世趁哈布斯堡继承危机进攻西里西亚，打开普奥竞争的新阶段。","fields":[{"label":"标题","value":"第一次西里西亚战争"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1740—1742年"},{"label":"地点","value":"西里西亚、波希米亚、奥地利和普鲁士战场"},{"label":"主要国家","value":"普鲁士；奥地利；神圣罗马帝国"},{"label":"一句话概括","value":"腓特烈二世趁哈布斯堡继承危机进攻西里西亚，打开普奥竞争的新阶段。"},{"label":"参与者","value":"普鲁士国王腓特烈二世、玛丽亚·特蕾莎、奥地利军队、普鲁士军队。"},{"label":"发生了什么","value":"1740年查理六世去世后，玛丽亚·特蕾莎继承哈布斯堡领地。腓特烈二世很快出兵西里西亚，利用奥地利继承危机夺取这一富庶地区。战争以1742年西里西亚战争《布雷斯劳和约》等安排暂时结束，普鲁士获得大部分西里西亚。"},{"label":"为什么重要","value":"它标志普鲁士从二流王国跃升为欧洲强权，也把奥地利和普鲁士的德意志领导权竞争推上主线。"},{"label":"前因","value":"《国事诏书》无法阻止列强挑战玛丽亚·特蕾莎继承，普鲁士拥有经过弗里德里希·威廉一世建设的强大军队。"},{"label":"后果","value":"普鲁士夺取西里西亚，奥地利失去重要工业和财政地区；奥地利王位继承战争扩大，普奥之间围绕西里西亚的长期竞争由此定型。"},{"label":"出处","value":"Britannica, War of the Austrian Succession；Britannica, Frederick II；Britannica, Silesian Wars。"}],"relationItems":["← 前因：哈布斯堡《国事诏书》","↔ 相关：奥地利王位继承战争","→ 后果：西里西亚战争《布雷斯劳和约》","↔ 相关：普鲁士腓特烈大王"],"relations":[{"text":"← 前因：哈布斯堡《国事诏书》","id":"extra450"},{"text":"↔ 相关：奥地利王位继承战争","id":"extra313"},{"text":"→ 后果：西里西亚战争《布雷斯劳和约》","id":"extra458"},{"text":"↔ 相关：普鲁士腓特烈大王","id":"extra315"}],"source":"history","id":"extra456"},{"title":"第一次西里西亚战争莫尔维茨战役","level":"C","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1741年4月10日","place":"西里西亚莫尔维茨附近","summary":"第一次西里西亚战争莫尔维茨战役是腓特烈二世早期重要胜利，显示普鲁士军队训练优势。","fields":[{"label":"标题","value":"第一次西里西亚战争莫尔维茨战役"},{"label":"分级","value":"C"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1741年4月10日"},{"label":"地点","value":"西里西亚莫尔维茨附近"},{"label":"主要国家","value":"普鲁士；奥地利；神圣罗马帝国"},{"label":"一句话概括","value":"第一次西里西亚战争莫尔维茨战役是腓特烈二世早期重要胜利，显示普鲁士军队训练优势。"},{"label":"参与者","value":"腓特烈二世、普鲁士军队、奥地利军队。"},{"label":"发生了什么","value":"第一次西里西亚战争中，普鲁士与奥地利在莫尔维茨交战。普鲁士步兵凭借纪律和火力取得胜利，尽管腓特烈本人在战斗中一度离场。"},{"label":"为什么重要","value":"它巩固普鲁士夺取西里西亚的军事可信度，也让欧洲列强更加认真看待普鲁士。"},{"label":"前因","value":"普鲁士入侵西里西亚后需要击败奥地利反击，否则军事冒险可能迅速失败；腓特烈二世也需要证明其父留下的军队能够赢得欧洲级大战。"},{"label":"后果","value":"普鲁士在战争中获得主动，奥地利面临更大外交压力，更多列强加入挑战哈布斯堡继承；腓特烈二世也获得早期军事声望。"},{"label":"出处","value":"Britannica, Battle of Mollwitz；Britannica, Frederick II；Britannica, Silesian Wars。"}],"relationItems":["← 前因：第一次西里西亚战争","→ 后果：西里西亚战争《布雷斯劳和约》","↔ 相关：普鲁士腓特烈大王","↔ 相关：普鲁士征兵 canton 制"],"relations":[{"text":"← 前因：第一次西里西亚战争","id":"extra456"},{"text":"→ 后果：西里西亚战争《布雷斯劳和约》","id":"extra458"},{"text":"↔ 相关：普鲁士腓特烈大王","id":"extra315"},{"text":"↔ 相关：普鲁士征兵 canton 制","id":"extra454"}],"source":"history","id":"extra457"},{"title":"西里西亚战争《布雷斯劳和约》","level":"B","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1742年6月11日","place":"布雷斯劳，今波兰弗罗茨瓦夫","summary":"西里西亚战争《布雷斯劳和约》使奥地利割让大部分西里西亚，确认普鲁士在中欧的重大突破。","fields":[{"label":"标题","value":"西里西亚战争《布雷斯劳和约》"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1742年6月11日"},{"label":"地点","value":"布雷斯劳，今波兰弗罗茨瓦夫"},{"label":"主要国家","value":"普鲁士；奥地利；神圣罗马帝国"},{"label":"一句话概括","value":"西里西亚战争《布雷斯劳和约》使奥地利割让大部分西里西亚，确认普鲁士在中欧的重大突破。"},{"label":"制定方/签署方","value":"普鲁士与奥地利。"},{"label":"主要内容","value":"奥地利将大部分西里西亚和格拉茨地区割让给普鲁士，第一次西里西亚战争告一段落。"},{"label":"它试图解决什么问题","value":"它试图让玛丽亚·特蕾莎暂时摆脱普鲁士战线，以集中应对奥地利王位继承战争中的其他敌人。"},{"label":"为什么重要","value":"它使普鲁士获得人口、工业和财政价值极高的西里西亚，奥地利则失去重要经济区域。"},{"label":"争议/局限","value":"和约只是暂时停火式解决，奥地利并未放弃夺回西里西亚的目标。"},{"label":"造成的影响","value":"普奥竞争制度化，第二次西里西亚战争和七年战争都围绕西里西亚问题继续展开。"},{"label":"出处","value":"Britannica, Treaty of Breslau；Britannica, Silesian Wars；Britannica, War of the Austrian Succession。"}],"relationItems":["← 前因：第一次西里西亚战争","↔ 相关：第一次西里西亚战争莫尔维茨战役","→ 后果：七年战争前欧洲外交革命","↔ 相关：奥地利王位继承战争"],"relations":[{"text":"← 前因：第一次西里西亚战争","id":"extra456"},{"text":"↔ 相关：第一次西里西亚战争莫尔维茨战役","id":"extra457"},{"text":"→ 后果：七年战争前欧洲外交革命","id":"extra459"},{"text":"↔ 相关：奥地利王位继承战争","id":"extra313"}],"source":"history","id":"extra458"},{"title":"七年战争前欧洲外交革命","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1756年","place":"欧洲外交体系，核心涉及维也纳、凡尔赛、伦敦和柏林","summary":"外交革命使奥地利与法国结盟、普鲁士与英国靠拢，重组七年战争前的欧洲联盟体系。","fields":[{"label":"标题","value":"七年战争前欧洲外交革命"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1756年"},{"label":"地点","value":"欧洲外交体系，核心涉及维也纳、凡尔赛、伦敦和柏林"},{"label":"主要国家","value":"奥地利；法国；普鲁士；英国；俄罗斯"},{"label":"一句话概括","value":"外交革命使奥地利与法国结盟、普鲁士与英国靠拢，重组七年战争前的欧洲联盟体系。"},{"label":"参与者","value":"奥地利、法国、普鲁士、英国、俄罗斯等。"},{"label":"发生了什么","value":"18世纪中期，奥地利为夺回西里西亚寻求法国支持，法国则与传统敌人奥地利接近；普鲁士与英国形成同盟关系。长期的波旁-哈布斯堡敌对格局被暂时打破。"},{"label":"为什么重要","value":"它是七年战争前的外交转折，说明西里西亚问题已经改变欧洲均势计算。"},{"label":"前因","value":"普鲁士夺取西里西亚后打破中欧平衡，奥地利需要新盟友；英国与法国殖民竞争加剧，也需要在欧洲大陆寻找牵制法国的伙伴。"},{"label":"后果","value":"七年战争爆发时，普鲁士面对奥法俄等强敌，英国则在全球和欧洲支援普鲁士；欧洲大陆战争与海外殖民战争被更紧密地连接起来。"},{"label":"出处","value":"Britannica, Diplomatic Revolution；Britannica, Seven Years War；Britannica, Maria Theresa。"}],"relationItems":["← 前因：西里西亚战争《布雷斯劳和约》","→ 后果：七年战争","↔ 相关：普鲁士腓特烈大王","↔ 相关：玛丽亚·特蕾莎"],"relations":[{"text":"← 前因：西里西亚战争《布雷斯劳和约》","id":"extra458"},{"text":"→ 后果：七年战争","id":"extra316"},{"text":"↔ 相关：普鲁士腓特烈大王","id":"extra315"},{"text":"↔ 相关：玛丽亚·特蕾莎","id":"extra314"}],"source":"history","id":"extra459"},{"title":"七年战争《胡贝图斯堡和约》","level":"A","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1763年2月15日","place":"萨克森胡贝图斯堡","summary":"七年战争《胡贝图斯堡和约》结束中欧七年战争，确认普鲁士保有西里西亚并成为欧洲强国。","fields":[{"label":"标题","value":"七年战争《胡贝图斯堡和约》"},{"label":"分级","value":"A"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1763年2月15日"},{"label":"地点","value":"萨克森胡贝图斯堡"},{"label":"主要国家","value":"普鲁士；奥地利；萨克森；神圣罗马帝国"},{"label":"一句话概括","value":"七年战争《胡贝图斯堡和约》结束中欧七年战争，确认普鲁士保有西里西亚并成为欧洲强国。"},{"label":"制定方/签署方","value":"普鲁士、奥地利和萨克森。"},{"label":"主要内容","value":"恢复战前多数领土状态，普鲁士保有西里西亚，奥地利承认既成事实，萨克森结束占领状态。"},{"label":"它试图解决什么问题","value":"它试图结束七年战争在中欧的消耗性战斗，并为普奥关系设定新的均势现实。"},{"label":"为什么重要","value":"它确认普鲁士作为欧洲大国的地位，也使奥地利与普鲁士二元主义成为德意志政治主线。"},{"label":"争议/局限","value":"和约没有解决德意志领导权问题，只是确认双方暂时无法彻底击败对方。"},{"label":"造成的影响","value":"普鲁士保住西里西亚，奥地利转向内部改革和外交调整，德意志统一与奥普领导权问题进入普奥长期竞争阶段。"},{"label":"出处","value":"Britannica, Treaty of Hubertusburg；Britannica, Seven Years War；Britannica, Frederick II。"}],"relationItems":["← 前因：七年战争","↔ 相关：七年战争前欧洲外交革命","↔ 相关：普鲁士腓特烈大王","→ 后果：奥地利与普鲁士二元主义"],"relations":[{"text":"← 前因：七年战争","id":"extra316"},{"text":"↔ 相关：七年战争前欧洲外交革命","id":"extra459"},{"text":"↔ 相关：普鲁士腓特烈大王","id":"extra315"},{"text":"→ 后果：奥地利与普鲁士二元主义","id":"extra535"}],"source":"history","id":"extra460"},{"title":"巴伐利亚王位继承战争","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1778—1779年","place":"巴伐利亚、波希米亚和德意志南部","summary":"巴伐利亚王位继承战争围绕奥地利吞并巴伐利亚的企图展开，显示普奥二元竞争仍在持续。","fields":[{"label":"标题","value":"巴伐利亚王位继承战争"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1778—1779年"},{"label":"地点","value":"巴伐利亚、波希米亚和德意志南部"},{"label":"主要国家","value":"奥地利；普鲁士；巴伐利亚；萨克森；神圣罗马帝国"},{"label":"一句话概括","value":"巴伐利亚王位继承战争围绕奥地利吞并巴伐利亚的企图展开，显示普奥二元竞争仍在持续。"},{"label":"参与者","value":"约瑟夫二世、腓特烈大王、巴伐利亚继承人卡尔·特奥多尔、萨克森和帝国诸侯。"},{"label":"发生了什么","value":"1777年巴伐利亚维特尔斯巴赫支系绝嗣后，奥地利试图取得巴伐利亚部分领土，以弥补失去西里西亚后的战略劣势。普鲁士反对奥地利扩大在德意志南部的势力，双方在1778年进入战争状态，但大规模会战很少，补给和机动消耗占主导。"},{"label":"为什么重要","value":"它说明七年战争后普奥竞争没有结束，德意志内部领地继承问题仍会牵动欧洲均势。"},{"label":"前因","value":"奥地利失去西里西亚后希望通过巴伐利亚补偿地缘和财政损失，约瑟夫二世试图扩大哈布斯堡在德意志南部的实力；普鲁士则把阻止奥地利扩张视为维护德意志均势的关键。"},{"label":"后果","value":"1779年巴伐利亚继承战争《特申和约》结束战争，奥地利只获得因河区小片领土，普鲁士成功阻止哈布斯堡吞并巴伐利亚；普奥二元主义继续主导德意志政治。"},{"label":"出处","value":"Britannica, War of the Bavarian Succession；Britannica, Treaty of Teschen；Britannica, Joseph II。"}],"relationItems":["← 前因：七年战争《胡贝图斯堡和约》","↔ 相关：奥地利与普鲁士二元主义","↔ 相关：约瑟夫二世改革","→ 后果：德意志诸侯联盟"],"relations":[{"text":"← 前因：七年战争《胡贝图斯堡和约》","id":"extra460"},{"text":"↔ 相关：奥地利与普鲁士二元主义","id":"extra535"},{"text":"↔ 相关：约瑟夫二世改革","id":"extra318"},{"text":"→ 后果：德意志诸侯联盟","id":"extra463"}],"source":"history","id":"extra461"},{"title":"巴伐利亚继承战争《特申和约》","level":"B","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1779年5月13日","place":"特申，今捷克捷欣地区","summary":"巴伐利亚继承战争《特申和约》结束巴伐利亚王位继承战争，限制奥地利吞并巴伐利亚的企图。","fields":[{"label":"标题","value":"巴伐利亚继承战争《特申和约》"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1779年5月13日"},{"label":"地点","value":"特申，今捷克捷欣地区"},{"label":"主要国家","value":"奥地利；普鲁士；巴伐利亚；萨克森；神圣罗马帝国"},{"label":"一句话概括","value":"巴伐利亚继承战争《特申和约》结束巴伐利亚王位继承战争，限制奥地利吞并巴伐利亚的企图。"},{"label":"制定方/签署方","value":"奥地利、普鲁士、萨克森等相关方，并有俄罗斯、法国等列强调停影响。"},{"label":"主要内容","value":"奥地利放弃取得大部分巴伐利亚的计划，只获得因河区部分领土；巴伐利亚继承安排得到确认。"},{"label":"它试图解决什么问题","value":"它试图结束奥地利与普鲁士围绕巴伐利亚继承的战争，避免德意志内部冲突扩大为欧洲大战。"},{"label":"为什么重要","value":"它确认普鲁士有能力阻止奥地利在德意志南部扩张，普奥二元竞争继续塑造旧帝国后期政治。"},{"label":"争议/局限","value":"和约没有解决德意志领导权问题，只是暂时冻结巴伐利亚继承争议。"},{"label":"造成的影响","value":"奥地利扩张受挫，腓特烈大王随后以维护帝国诸侯自由为名推动德意志诸侯联盟。"},{"label":"出处","value":"Britannica, Treaty of Teschen；Britannica, War of the Bavarian Succession。"}],"relationItems":["← 前因：巴伐利亚王位继承战争","→ 后果：德意志诸侯联盟","↔ 相关：奥地利与普鲁士二元主义","↔ 相关：约瑟夫二世改革"],"relations":[{"text":"← 前因：巴伐利亚王位继承战争","id":"extra461"},{"text":"→ 后果：德意志诸侯联盟","id":"extra463"},{"text":"↔ 相关：奥地利与普鲁士二元主义","id":"extra535"},{"text":"↔ 相关：约瑟夫二世改革","id":"extra318"}],"source":"history","id":"extra462"},{"title":"德意志诸侯联盟","level":"B","type":"组织/机构卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1785年","place":"神圣罗马帝国，核心参与者为普鲁士、萨克森、汉诺威等","summary":"德意志诸侯联盟由普鲁士推动，旨在阻止奥地利吞并巴伐利亚并维护帝国诸侯格局。","fields":[{"label":"标题","value":"德意志诸侯联盟"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1785年"},{"label":"地点","value":"神圣罗马帝国，核心参与者为普鲁士、萨克森、汉诺威等"},{"label":"主要国家","value":"普鲁士；萨克森；汉诺威；奥地利；神圣罗马帝国"},{"label":"一句话概括","value":"德意志诸侯联盟由普鲁士推动，旨在阻止奥地利吞并巴伐利亚并维护帝国诸侯格局。"},{"label":"性质/类型","value":"神圣罗马帝国内由普鲁士主导的诸侯政治联盟。"},{"label":"成立/解散时间","value":"1785年成立，法国大革命和拿破仑战争前后实际失去作用。"},{"label":"核心目标/宗旨","value":"维护帝国诸侯既有权利，阻止约瑟夫二世推动以奥属尼德兰交换巴伐利亚的计划。"},{"label":"关键人物（可选）","value":"腓特烈大王、约瑟夫二世、萨克森和汉诺威等诸侯。"},{"label":"关键行动/事件","value":"以防御帝国宪制和诸侯自由为名，组织反对奥地利在德意志南部扩大势力。"},{"label":"为什么重要","value":"它是普鲁士以“德意志自由保护者”身份对抗奥地利的重要尝试，显示旧帝国晚期普奥竞争已进入制度政治层面。"},{"label":"争议/局限","value":"联盟更多是普鲁士外交工具，不是现代民族组织；面对法国革命战争时缺乏持久凝聚力。"},{"label":"出处","value":"Britannica, Fürstenbund；Britannica, Frederick II；Britannica, Joseph II。"}],"relationItems":["← 前因：巴伐利亚继承战争《特申和约》","↔ 相关：奥地利与普鲁士二元主义","↔ 相关：约瑟夫二世改革","↔ 同时期参考：旧制度欧洲均势"],"relations":[{"text":"← 前因：巴伐利亚继承战争《特申和约》","id":"extra462"},{"text":"↔ 相关：奥地利与普鲁士二元主义","id":"extra535"},{"text":"↔ 相关：约瑟夫二世改革","id":"extra318"}],"source":"history","id":"extra463"},{"title":"约瑟夫二世《宽容专利》","level":"B","type":"制度/文本卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1781年","place":"哈布斯堡君主国","summary":"《宽容专利》放宽对新教和东正教臣民的限制，是约瑟夫主义改革的重要体现。","fields":[{"label":"标题","value":"约瑟夫二世《宽容专利》"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1781年"},{"label":"地点","value":"哈布斯堡君主国"},{"label":"主要国家","value":"奥地利；匈牙利；捷克；神圣罗马帝国相关领地"},{"label":"一句话概括","value":"《宽容专利》放宽对新教和东正教臣民的限制，是约瑟夫主义改革的重要体现。"},{"label":"制定方/签署方","value":"哈布斯堡君主约瑟夫二世。"},{"label":"主要内容","value":"允许路德宗、改革宗和东正教臣民在一定条件下进行礼拜、从事职业、接受教育和持有财产。"},{"label":"它试图解决什么问题","value":"它试图把非天主教臣民更有效纳入国家秩序，减少宗教限制对经济和行政效率的阻碍。"},{"label":"为什么重要","value":"它体现启蒙专制下的有限宗教宽容，说明哈布斯堡改革不是单纯保守天主教复兴。"},{"label":"争议/局限","value":"宽容仍有限，天主教保持优势地位；改革由君主自上而下推行，不等于现代宗教平等。"},{"label":"造成的影响","value":"非天主教社群活动空间扩大，但也引发保守教会和部分地方社会抵触。"},{"label":"出处","value":"Britannica, Joseph II；Britannica, Toleration Patent；Britannica, Austria - Joseph II。"}],"relationItems":["← 前因：约瑟夫二世改革","↔ 相关：哈布斯堡约瑟夫主义","↔ 相关：哈布斯堡君主国","↔ 同时期参考：欧洲启蒙运动"],"relations":[{"text":"← 前因：约瑟夫二世改革","id":"extra318"},{"text":"↔ 相关：哈布斯堡约瑟夫主义","id":"extra466"},{"text":"↔ 相关：哈布斯堡君主国","id":"extra309"},{"text":"↔ 同时期参考：欧洲启蒙运动","id":"extra874"}],"source":"history","id":"extra464"},{"title":"约瑟夫二世农奴制专利","level":"B","type":"制度/文本卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1781年","place":"哈布斯堡君主国的波希米亚、奥地利等领地","summary":"约瑟夫二世改革农奴义务，试图把农民从领主控制中部分解放出来并纳入国家治理。","fields":[{"label":"标题","value":"约瑟夫二世农奴制专利"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1781年"},{"label":"地点","value":"哈布斯堡君主国的波希米亚、奥地利等领地"},{"label":"主要国家","value":"奥地利；捷克；匈牙利；哈布斯堡君主国"},{"label":"一句话概括","value":"约瑟夫二世改革农奴义务，试图把农民从领主控制中部分解放出来并纳入国家治理。"},{"label":"制定方/签署方","value":"约瑟夫二世。"},{"label":"主要内容","value":"放松农民人身依附，允许婚姻、迁徙、职业选择和教育等方面拥有更多自由，削弱领主对农民生活的直接控制。"},{"label":"它试图解决什么问题","value":"国家希望提高劳动力流动、税收能力和兵源管理，同时削弱领主对乡村人口的封建控制。"},{"label":"为什么重要","value":"它是哈布斯堡启蒙专制社会改革的核心之一，显示国家建设开始触及乡村等级秩序。"},{"label":"争议/局限","value":"改革没有彻底废除所有封建负担，地方贵族抵抗强烈，不同地区执行差异很大。"},{"label":"造成的影响","value":"农民法律地位有所改善，国家与乡村人口关系更直接，但农业社会矛盾并未消失。"},{"label":"出处","value":"Britannica, Joseph II；Britannica, Serfdom；Britannica, Austria - reforms。"}],"relationItems":["← 前因：约瑟夫二世改革","↔ 相关：哈布斯堡约瑟夫主义","↔ 相关：玛丽亚·特蕾莎","↔ 同时期参考：欧洲启蒙专制"],"relations":[{"text":"← 前因：约瑟夫二世改革","id":"extra318"},{"text":"↔ 相关：哈布斯堡约瑟夫主义","id":"extra466"},{"text":"↔ 相关：玛丽亚·特蕾莎","id":"extra314"},{"text":"↔ 同时期参考：欧洲启蒙专制","id":"extra883"}],"source":"history","id":"extra465"},{"title":"哈布斯堡约瑟夫主义","level":"B","type":"概念/思潮卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"18世纪后半期，约瑟夫二世时期最典型","place":"哈布斯堡君主国","summary":"约瑟夫主义是哈布斯堡启蒙专制改革路线，强调国家理性、宗教管控和行政效率。","fields":[{"label":"标题","value":"哈布斯堡约瑟夫主义"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"18世纪后半期，约瑟夫二世时期最典型"},{"label":"地点","value":"哈布斯堡君主国"},{"label":"主要国家","value":"奥地利；匈牙利；捷克；哈布斯堡君主国"},{"label":"一句话概括","value":"约瑟夫主义是哈布斯堡启蒙专制改革路线，强调国家理性、宗教管控和行政效率。"},{"label":"核心主张/思路","value":"国家应以理性和公共利益为名改革教会、教育、行政、法律和社会秩序，教会也应服务国家治理。"},{"label":"提出者/代表人物（可选）","value":"约瑟夫二世及其改革官僚。"},{"label":"它从何而来","value":"启蒙思想、玛丽亚·特蕾莎改革、财政军事竞争和哈布斯堡多民族国家治理压力共同推动。"},{"label":"典型表现","value":"宗教宽容专利、修道院改革、农奴制改革、行政中央化、教育和司法改革。"},{"label":"为什么重要","value":"它说明奥地利旧制度不是静止不变，而是在与普鲁士和法国竞争中自上而下改造国家。"},{"label":"争议/局限","value":"改革速度快、命令式强，常忽视地方习惯、等级权利和宗教情感，导致强烈反弹。"},{"label":"出处","value":"Britannica, Josephinism；Britannica, Joseph II。"}],"relationItems":["← 前因：约瑟夫二世改革","↔ 相关：约瑟夫二世《宽容专利》","↔ 相关：约瑟夫二世农奴制专利","↔ 同时期参考：欧洲启蒙专制"],"relations":[{"text":"← 前因：约瑟夫二世改革","id":"extra318"},{"text":"↔ 相关：约瑟夫二世《宽容专利》","id":"extra464"},{"text":"↔ 相关：约瑟夫二世农奴制专利","id":"extra465"},{"text":"↔ 同时期参考：欧洲启蒙专制","id":"extra883"}],"source":"history","id":"extra466"},{"title":"普鲁士《一般邦法》","level":"B","type":"制度/文本卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1794年","place":"普鲁士王国","summary":"普鲁士《一般邦法》系统编纂国家法律，体现启蒙官僚国家对社会秩序的规范化。","fields":[{"label":"标题","value":"普鲁士《一般邦法》"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1794年"},{"label":"地点","value":"普鲁士王国"},{"label":"主要国家","value":"普鲁士；神圣罗马帝国"},{"label":"一句话概括","value":"普鲁士《一般邦法》系统编纂国家法律，体现启蒙官僚国家对社会秩序的规范化。"},{"label":"制定方/签署方","value":"普鲁士王国在腓特烈大王后期启动，1794年腓特烈·威廉二世时期实施。"},{"label":"主要内容","value":"覆盖民法、刑法、行政、等级身份、家庭、财产、宗教和国家关系等广泛领域，试图统一普鲁士各领地法律。"},{"label":"它试图解决什么问题","value":"普鲁士领地分散、法律传统复杂，国家需要可执行的统一规则来提高司法和行政效率。"},{"label":"为什么重要","value":"它是欧洲启蒙时代重要法典之一，显示普鲁士通过法律编纂推进官僚国家建设。"},{"label":"争议/局限","value":"法典保留等级社会和贵族特权，并非现代自由平等法典。"},{"label":"造成的影响","value":"普鲁士司法和行政更规范化，也为19世纪改革前的国家秩序提供法律基础。"},{"label":"出处","value":"Britannica, Allgemeines Landrecht；Britannica, Prussia；Britannica, Frederick William II。"}],"relationItems":["← 前因：普鲁士开明专制","↔ 相关：普鲁士总督府与战争财政机构合并","↔ 相关：普鲁士王国成立","↔ 同时期参考：启蒙时代法典化"],"relations":[{"text":"← 前因：普鲁士开明专制","id":"extra340"},{"text":"↔ 相关：普鲁士总督府与战争财政机构合并","id":"extra453"},{"text":"↔ 相关：普鲁士王国成立","id":"extra312"}],"source":"history","id":"extra467"},{"title":"德意志哥廷根大学成立","level":"B","type":"事件卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1737年","place":"哥廷根","summary":"哥廷根大学成为18世纪德意志启蒙和研究型大学传统的重要中心。","fields":[{"label":"标题","value":"德意志哥廷根大学成立"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1737年"},{"label":"地点","value":"哥廷根"},{"label":"主要国家","value":"汉诺威；神圣罗马帝国；德意志地区"},{"label":"一句话概括","value":"哥廷根大学成为18世纪德意志启蒙和研究型大学传统的重要中心。"},{"label":"参与者","value":"汉诺威选侯兼英国国王乔治二世、哥廷根学者、德意志和欧洲学生。"},{"label":"发生了什么","value":"1737年，哥廷根大学在汉诺威选侯国建立。它重视法学、历史、自然科学和现代学术研究，吸引欧洲学生和学者。"},{"label":"为什么重要","value":"哥廷根大学体现18世纪德意志大学从神学中心向研究、国家服务和现代学科扩展的转型。"},{"label":"前因","value":"德意志诸侯竞争文化声望和行政人才，启蒙时代知识需求扩大，大学成为国家建设工具；汉诺威也希望通过新大学提升领地治理和国际学术声誉。"},{"label":"后果","value":"哥廷根学派在历史学、法学、自然科学和统计学等领域产生影响，推动德意志学术专业化；这种大学模式也为后来研究型大学改革提供经验。"},{"label":"出处","value":"Britannica, University of Göttingen；University of Göttingen, History。"}],"relationItems":["↔ 相关：德意志启蒙运动","↔ 相关：德国洪堡大学模式","↔ 相关：德意志帝国研究型大学扩张","↔ 同时期参考：欧洲启蒙运动"],"relations":[{"text":"↔ 相关：德意志启蒙运动","id":"extra317"},{"text":"↔ 相关：德国洪堡大学模式","id":"extra515"},{"text":"↔ 相关：德意志帝国研究型大学扩张","id":"extra821"},{"text":"↔ 同时期参考：欧洲启蒙运动","id":"extra874"}],"source":"history","id":"extra468"},{"title":"摩西·门德尔松","level":"B","type":"人物卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1729—1786年","place":"柏林","summary":"摩西·门德尔松是德意志犹太启蒙代表人物，推动犹太社群与启蒙公共文化对话。","fields":[{"label":"标题","value":"摩西·门德尔松"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1729—1786年"},{"label":"地点","value":"柏林"},{"label":"主要国家","value":"普鲁士；德意志地区；犹太社群"},{"label":"一句话概括","value":"摩西·门德尔松是德意志犹太启蒙代表人物，推动犹太社群与启蒙公共文化对话。"},{"label":"生卒年/活跃年代","value":"1729—1786年。"},{"label":"身份/职务","value":"犹太哲学家、启蒙思想家、作家。"},{"label":"关键贡献/作为","value":"参与柏林启蒙文化，倡导理性、教育和宗教宽容，并推动犹太人学习德语和参与欧洲思想世界。"},{"label":"核心主张/立场","value":"主张犹太信仰与理性启蒙并不矛盾，反对强制改宗，强调公民宽容和宗教自由。"},{"label":"为什么重要","value":"他是哈斯卡拉的核心人物，连接德意志启蒙、犹太社群改革和近代宗教宽容讨论。"},{"label":"争议/评价","value":"他的道路受到传统犹太社群和基督教改宗压力两方面挑战，后世也争论同化与身份保持之间的张力。"},{"label":"关联事件（可选）","value":"犹太启蒙运动（哈斯卡拉）；柏林启蒙。"},{"label":"出处","value":"Britannica, Moses Mendelssohn；Britannica, Haskalah。"}],"relationItems":["→ 后果：犹太启蒙运动（哈斯卡拉）","↔ 相关：德意志启蒙运动","↔ 相关：普鲁士开明专制","↔ 相关：中世纪德意志犹太社群"],"relations":[{"text":"→ 后果：犹太启蒙运动（哈斯卡拉）","id":"extra470"},{"text":"↔ 相关：德意志启蒙运动","id":"extra317"},{"text":"↔ 相关：普鲁士开明专制","id":"extra340"},{"text":"↔ 相关：中世纪德意志犹太社群","id":"extra408"}],"source":"history","id":"extra469"},{"title":"犹太启蒙运动（哈斯卡拉）","level":"B","type":"概念/思潮卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"18世纪后半期—19世纪","place":"柏林及中东欧犹太社群","summary":"哈斯卡拉推动犹太教育、语言和社会参与改革，是近代欧洲犹太史的重要转折。","fields":[{"label":"标题","value":"犹太启蒙运动（哈斯卡拉）"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"18世纪后半期—19世纪"},{"label":"地点","value":"柏林及中东欧犹太社群"},{"label":"主要国家","value":"普鲁士；德意志地区；波兰立陶宛；奥地利"},{"label":"一句话概括","value":"哈斯卡拉推动犹太教育、语言和社会参与改革，是近代欧洲犹太史的重要转折。"},{"label":"核心主张/思路","value":"强调世俗知识、德语或当地语言学习、理性宗教理解、职业拓展和犹太人与周围社会的互动。"},{"label":"提出者/代表人物（可选）","value":"摩西·门德尔松及柏林犹太启蒙圈。"},{"label":"它从何而来","value":"德意志启蒙、宗教宽容讨论、犹太社群内部教育改革需求和城市经济变化共同推动。"},{"label":"典型表现","value":"翻译圣经、创办教育机构、出版启蒙刊物、鼓励犹太青年学习现代知识和语言。"},{"label":"为什么重要","value":"它为19世纪犹太解放、同化、改革犹太教和现代犹太身份争论提供思想基础。"},{"label":"争议/局限","value":"哈斯卡拉常面对传统权威反对，也可能带来同化压力和社群分裂。"},{"label":"出处","value":"Britannica, Haskalah；Britannica, Moses Mendelssohn。"}],"relationItems":["← 前因：摩西·门德尔松","↔ 相关：德意志启蒙运动","↔ 相关：中世纪德意志犹太社群","↔ 同时期参考：欧洲宗教宽容"],"relations":[{"text":"← 前因：摩西·门德尔松","id":"extra469"},{"text":"↔ 相关：德意志启蒙运动","id":"extra317"},{"text":"↔ 相关：中世纪德意志犹太社群","id":"extra408"}],"source":"history","id":"extra470"},{"title":"德意志狂飙突进运动","level":"B","type":"概念/思潮卡","tags":["文化与思想"],"mainTag":"文化与思想","subTag":"","timeText":"约1760年代末—1780年代","place":"德意志文学和思想圈","summary":"狂飙突进运动强调情感、天才和反叛，挑战启蒙理性主义的单一权威。","fields":[{"label":"标题","value":"德意志狂飙突进运动"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"时间","value":"约1760年代末—1780年代"},{"label":"地点","value":"德意志文学和思想圈"},{"label":"主要国家","value":"德意志地区；神圣罗马帝国"},{"label":"一句话概括","value":"狂飙突进运动强调情感、天才和反叛，挑战启蒙理性主义的单一权威。"},{"label":"核心主张/思路","value":"强调个人情感、自然、创造性天才、民族语言和对僵化社会规范的反抗。"},{"label":"提出者/代表人物（可选）","value":"青年歌德、青年席勒、赫尔德、克林格尔等。"},{"label":"它从何而来","value":"启蒙文化内部的反思、卢梭影响、德意志青年知识分子不满和文学形式创新共同推动。"},{"label":"典型表现","value":"《少年维特之烦恼》《强盗》等作品表现强烈情感、反权威冲突和个体自我。"},{"label":"为什么重要","value":"它是德意志文学从启蒙走向浪漫主义和民族文化意识的重要过渡。"},{"label":"争议/局限","value":"运动时间短，政治上并非统一纲领，更多体现文学和文化心理转向。"},{"label":"出处","value":"Britannica, Sturm und Drang；Britannica, Johann Wolfgang von Goethe；Britannica, Friedrich Schiller。"}],"relationItems":["← 前因：德意志启蒙运动","↔ 相关：约翰·戈特弗里德·赫尔德","↔ 相关：魏玛古典主义","↔ 相关：德意志浪漫主义"],"relations":[{"text":"← 前因：德意志启蒙运动","id":"extra317"},{"text":"↔ 相关：约翰·戈特弗里德·赫尔德","id":"extra472"},{"text":"↔ 相关：魏玛古典主义","id":"extra342"},{"text":"↔ 相关：德意志浪漫主义","id":"extra552"}],"source":"history","id":"extra471"},{"title":"约翰·戈特弗里德·赫尔德","level":"B","type":"人物卡","tags":["文化与思想"],"mainTag":"文化与思想","subTag":"","timeText":"1744—1803年","place":"东普鲁士、魏玛、德意志思想圈","summary":"赫尔德强调语言、民歌和民族文化独特性，影响德意志民族文化观念和浪漫主义。","fields":[{"label":"标题","value":"约翰·戈特弗里德·赫尔德"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"文化与思想"},{"label":"时间","value":"1744—1803年"},{"label":"地点","value":"东普鲁士、魏玛、德意志思想圈"},{"label":"主要国家","value":"德意志地区；普鲁士"},{"label":"一句话概括","value":"赫尔德强调语言、民歌和民族文化独特性，影响德意志民族文化观念和浪漫主义。"},{"label":"生卒年/活跃年代","value":"1744—1803年。"},{"label":"身份/职务","value":"哲学家、神学家、文学批评家。"},{"label":"关键贡献/作为","value":"强调每个民族都有自身语言、历史和文化精神，重视民歌、民间文学和历史发展差异。"},{"label":"核心主张/立场","value":"反对用单一文明尺度衡量所有民族，主张理解各民族文化的内在生命。"},{"label":"为什么重要","value":"他的思想为德意志浪漫主义、民族文化研究和19世纪民族主义提供重要资源。"},{"label":"争议/评价","value":"赫尔德的文化民族观原本不等于排外政治民族主义，但后世民族主义常选择性借用其思想。"},{"label":"关联事件（可选）","value":"德意志狂飙突进运动；德意志浪漫主义。"},{"label":"出处","value":"Britannica, Johann Gottfried von Herder；Britannica, Sturm und Drang。"}],"relationItems":["↔ 相关：德意志狂飙突进运动","↔ 相关：德意志浪漫主义","↔ 相关：德意志民族主义","↔ 同时期参考：欧洲启蒙运动"],"relations":[{"text":"↔ 相关：德意志狂飙突进运动","id":"extra471"},{"text":"↔ 相关：德意志浪漫主义","id":"extra552"},{"text":"↔ 相关：德意志民族主义","id":"extra504"},{"text":"↔ 同时期参考：欧洲启蒙运动","id":"extra874"}],"source":"history","id":"extra472"},{"title":"戈特霍尔德·埃夫莱姆·莱辛","level":"B","type":"人物卡","tags":["文化与思想"],"mainTag":"文化与思想","subTag":"","timeText":"1729—1781年","place":"萨克森、汉堡、沃尔芬比特尔等地","summary":"莱辛是德意志启蒙文学关键人物，推动戏剧改革、宗教宽容和公共批评文化。","fields":[{"label":"标题","value":"戈特霍尔德·埃夫莱姆·莱辛"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"文化与思想"},{"label":"时间","value":"1729—1781年"},{"label":"地点","value":"萨克森、汉堡、沃尔芬比特尔等地"},{"label":"主要国家","value":"德意志地区；神圣罗马帝国"},{"label":"一句话概括","value":"莱辛是德意志启蒙文学关键人物，推动戏剧改革、宗教宽容和公共批评文化。"},{"label":"生卒年/活跃年代","value":"1729—1781年。"},{"label":"身份/职务","value":"剧作家、批评家、启蒙思想家。"},{"label":"关键贡献/作为","value":"发展德语市民戏剧和文学批评，作品《智者纳坦》表达宗教宽容思想。"},{"label":"核心主张/立场","value":"强调理性批评、艺术独立和宗教之间的宽容理解。"},{"label":"为什么重要","value":"他帮助德语文学摆脱对法国古典主义的单纯模仿，推动德意志公共文化成熟。"},{"label":"争议/评价","value":"其宗教观点挑战正统神学，曾引发激烈争论。"},{"label":"关联事件（可选）","value":"德意志启蒙运动；德意志狂飙突进运动。"},{"label":"出处","value":"Britannica, Gotthold Ephraim Lessing；Britannica, Nathan the Wise。"}],"relationItems":["↔ 相关：德意志启蒙运动","↔ 相关：摩西·门德尔松","↔ 相关：德意志狂飙突进运动","↔ 同时期参考：欧洲启蒙戏剧"],"relations":[{"text":"↔ 相关：德意志启蒙运动","id":"extra317"},{"text":"↔ 相关：摩西·门德尔松","id":"extra469"},{"text":"↔ 相关：德意志狂飙突进运动","id":"extra471"}],"source":"history","id":"extra473"},{"title":"反法国革命《皮尔尼茨宣言》","level":"B","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1791年8月27日","place":"萨克森皮尔尼茨","summary":"皮尔尼茨宣言表达奥普对法国王室命运的关切，加剧革命法国与欧洲君主国紧张。","fields":[{"label":"标题","value":"反法国革命《皮尔尼茨宣言》"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1791年8月27日"},{"label":"地点","value":"萨克森皮尔尼茨"},{"label":"主要国家","value":"奥地利；普鲁士；法国；神圣罗马帝国"},{"label":"一句话概括","value":"皮尔尼茨宣言表达奥普对法国王室命运的关切，加剧革命法国与欧洲君主国紧张。"},{"label":"制定方/签署方","value":"奥地利皇帝利奥波德二世与普鲁士国王腓特烈·威廉二世。"},{"label":"主要内容","value":"宣称欧洲君主若能共同采取行动，奥地利和普鲁士愿意支持恢复法国国王路易十六的安全和权威。"},{"label":"它试图解决什么问题","value":"它试图向法国革命局势施压，同时安抚流亡贵族和欧洲君主舆论。"},{"label":"为什么重要","value":"它成为革命法国认为欧洲君主国威胁革命的证据之一，推动战争气氛升高。"},{"label":"争议/局限","value":"宣言带有条件性和外交姿态，并非立即开战命令，但政治效果远超文本本身。"},{"label":"造成的影响","value":"法国与奥普关系恶化，1792年法国对奥地利宣战，第一次反法同盟战争爆发。"},{"label":"出处","value":"Britannica, Declaration of Pillnitz；Britannica, French Revolutionary Wars。"}],"relationItems":["← 前因：法国大革命的欧洲冲击","→ 后果：第一次反法同盟战争","↔ 相关：奥地利与普鲁士二元主义","↔ 同时期参考：法国大革命"],"relations":[{"text":"← 前因：法国大革命的欧洲冲击","id":"extra319"},{"text":"→ 后果：第一次反法同盟战争","id":"extra475"},{"text":"↔ 相关：奥地利与普鲁士二元主义","id":"extra535"},{"text":"↔ 同时期参考：法国大革命","id":"extra887"}],"source":"history","id":"extra474"},{"title":"第一次反法同盟战争","level":"A","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1792—1797年","place":"法国边境、莱茵地区、尼德兰、意大利等","summary":"第一次反法同盟战争把法国大革命冲击转化为欧洲大战，并直接冲击莱茵和旧帝国秩序。","fields":[{"label":"标题","value":"第一次反法同盟战争"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1792—1797年"},{"label":"地点","value":"法国边境、莱茵地区、尼德兰、意大利等"},{"label":"主要国家","value":"法国；奥地利；普鲁士；英国；神圣罗马帝国"},{"label":"一句话概括","value":"第一次反法同盟战争把法国大革命冲击转化为欧洲大战，并直接冲击莱茵和旧帝国秩序。"},{"label":"参与者","value":"法国革命政府、奥地利、普鲁士、英国、荷兰共和国、西班牙及神圣罗马帝国部分力量。"},{"label":"发生了什么","value":"1792年法国对奥地利宣战，普鲁士随后参战。战争从法国边境扩展到莱茵、尼德兰和意大利。法国革命军在瓦尔密稳定局势，随后逐渐反攻并输出革命制度。"},{"label":"为什么重要","value":"它把法国革命从国内危机变成欧洲体系危机，德意志西部和神圣罗马帝国成为直接战场。"},{"label":"前因","value":"皮尔尼茨宣言、法国王室危机、革命派对外战争期待和欧洲君主国对革命扩散的恐惧共同推动开战；奥普也希望通过军事压力影响法国政局。"},{"label":"后果","value":"普鲁士1795年退出战争，奥地利1797年签署坎波福尔米奥条约；莱茵左岸问题成为旧帝国瓦解的关键。"},{"label":"出处","value":"Britannica, French Revolutionary Wars；Britannica, First Coalition。"}],"relationItems":["← 前因：反法国革命《皮尔尼茨宣言》","→ 后果：法国革命战争瓦尔密战役","→ 后果：普法《巴塞尔和约》","↔ 相关：法国大革命的欧洲冲击"],"relations":[{"text":"← 前因：反法国革命《皮尔尼茨宣言》","id":"extra474"},{"text":"→ 后果：法国革命战争瓦尔密战役","id":"extra476"},{"text":"→ 后果：普法《巴塞尔和约》","id":"extra477"},{"text":"↔ 相关：法国大革命的欧洲冲击","id":"extra319"}],"source":"history","id":"extra475"},{"title":"法国革命战争瓦尔密战役","level":"B","type":"事件卡","tags":["战争与外交","文化与思想"],"mainTag":"战争与外交","subTag":"文化与思想","timeText":"1792年9月20日","place":"法国香槟地区瓦尔密","summary":"瓦尔密战役中法国革命军挡住普奥进攻，成为革命法国继续作战的重要心理转折。","fields":[{"label":"标题","value":"法国革命战争瓦尔密战役"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1792年9月20日"},{"label":"地点","value":"法国香槟地区瓦尔密"},{"label":"主要国家","value":"法国；普鲁士；奥地利"},{"label":"一句话概括","value":"瓦尔密战役中法国革命军挡住普奥进攻，成为革命法国继续作战的重要心理转折。"},{"label":"参与者","value":"法国革命军、普鲁士军队、奥地利盟军。"},{"label":"发生了什么","value":"1792年，普鲁士和奥地利军队侵入法国，试图压制革命局势。法国革命军在瓦尔密附近顶住联军推进，战斗规模有限，但普鲁士军撤退。"},{"label":"为什么重要","value":"它证明革命法国并非一击即溃，增强法国国内革命信心，也使战争从短期干预变成长期欧洲冲突。"},{"label":"前因","value":"第一次反法同盟战争爆发后，普奥希望通过军事压力恢复法国王权秩序，法国革命政府则需要证明共和国能够抵御外部干预。"},{"label":"后果","value":"法国国民公会次日宣布共和国，革命战争继续扩大，莱茵和德意志边境很快成为法国进攻方向；革命军胜利也强化了法国输出革命的信心。"},{"label":"出处","value":"Britannica, Battle of Valmy；Britannica, French Revolutionary Wars。"}],"relationItems":["← 前因：第一次反法同盟战争","→ 后果：法国大革命的欧洲冲击","↔ 相关：普法《巴塞尔和约》","↔ 同时期参考：法兰西第一共和国"],"relations":[{"text":"← 前因：第一次反法同盟战争","id":"extra475"},{"text":"→ 后果：法国大革命的欧洲冲击","id":"extra319"},{"text":"↔ 相关：普法《巴塞尔和约》","id":"extra477"}],"source":"history","id":"extra476"},{"title":"普法《巴塞尔和约》","level":"B","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1795年4月5日","place":"巴塞尔","summary":"巴塞尔和约使普鲁士退出第一次反法同盟，暴露普奥在对法战争中的利益分裂。","fields":[{"label":"标题","value":"普法《巴塞尔和约》"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1795年4月5日"},{"label":"地点","value":"巴塞尔"},{"label":"主要国家","value":"普鲁士；法国；神圣罗马帝国"},{"label":"一句话概括","value":"巴塞尔和约使普鲁士退出第一次反法同盟，暴露普奥在对法战争中的利益分裂。"},{"label":"制定方/签署方","value":"普鲁士王国与法国共和国。"},{"label":"主要内容","value":"普鲁士与法国单独媾和，承认莱茵左岸在未来安排中的法国控制现实，并在北德保持中立区。"},{"label":"它试图解决什么问题","value":"普鲁士希望退出消耗性对法战争，集中处理波兰瓜分和自身利益，而法国希望削弱反法同盟。"},{"label":"为什么重要","value":"它显示德意志诸侯面对法国革命战争缺乏统一战略，普奥二元主义削弱旧帝国共同防御。"},{"label":"争议/局限","value":"和约损害帝国共同利益，尤其使莱茵左岸帝国领地更孤立。"},{"label":"造成的影响","value":"普鲁士暂时退出西线战争，奥地利继续对法作战，帝国政治裂痕加深。"},{"label":"出处","value":"Britannica, Peace of Basel；Britannica, French Revolutionary Wars；Britannica, Prussia。"}],"relationItems":["← 前因：第一次反法同盟战争","↔ 相关：三次波兰瓜分","→ 后果：法奥《坎波福尔米奥条约》","↔ 相关：奥地利与普鲁士二元主义"],"relations":[{"text":"← 前因：第一次反法同盟战争","id":"extra475"},{"text":"↔ 相关：三次波兰瓜分","id":"extra341"},{"text":"→ 后果：法奥《坎波福尔米奥条约》","id":"extra478"},{"text":"↔ 相关：奥地利与普鲁士二元主义","id":"extra535"}],"source":"history","id":"extra477"},{"title":"法奥《坎波福尔米奥条约》","level":"B","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1797年10月17日","place":"坎波福尔米奥，威尼斯附近","summary":"坎波福尔米奥条约结束法国与奥地利的第一阶段战争，并承认法国在莱茵左岸的扩张。","fields":[{"label":"标题","value":"法奥《坎波福尔米奥条约》"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1797年10月17日"},{"label":"地点","value":"坎波福尔米奥，威尼斯附近"},{"label":"主要国家","value":"法国；奥地利；神圣罗马帝国；意大利"},{"label":"一句话概括","value":"坎波福尔米奥条约结束法国与奥地利的第一阶段战争，并承认法国在莱茵左岸的扩张。"},{"label":"制定方/签署方","value":"法国共和国与奥地利。"},{"label":"主要内容","value":"奥地利承认法国在比利时和莱茵左岸的利益，法国则以威尼斯等地补偿奥地利，意大利和德意志边界被重新安排。"},{"label":"它试图解决什么问题","value":"它试图结束拿破仑意大利战役后法国与奥地利的战争，并用领土交换处理法国扩张。"},{"label":"为什么重要","value":"它把旧帝国西部的领土牺牲变成外交现实，莱茵左岸赔偿问题直接推动1803年帝国重组。"},{"label":"争议/局限","value":"条约牺牲威尼斯共和国和帝国小领地利益，和平很快被第二次反法同盟战争打破。"},{"label":"造成的影响","value":"奥地利暂时退出战争，法国在意大利和莱茵方向影响扩大，神圣罗马帝国补偿机制被迫启动。"},{"label":"出处","value":"Britannica, Treaty of Campo Formio；Britannica, Napoleon I；Britannica, French Revolutionary Wars。"}],"relationItems":["← 前因：普法《巴塞尔和约》","→ 后果：法奥拉施塔特会议","→ 后果：莱茵左岸并入法国","↔ 相关：第一次反法同盟战争"],"relations":[{"text":"← 前因：普法《巴塞尔和约》","id":"extra477"},{"text":"→ 后果：法奥拉施塔特会议","id":"extra479"},{"text":"→ 后果：莱茵左岸并入法国","id":"extra482"},{"text":"↔ 相关：第一次反法同盟战争","id":"extra475"}],"source":"history","id":"extra478"},{"title":"法奥拉施塔特会议","level":"C","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1797—1799年","place":"拉施塔特","summary":"拉施塔特会议试图处理莱茵左岸割让后的帝国赔偿问题，但因战争重启而失败。","fields":[{"label":"标题","value":"法奥拉施塔特会议"},{"label":"分级","value":"C"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1797—1799年"},{"label":"地点","value":"拉施塔特"},{"label":"主要国家","value":"法国；神圣罗马帝国；奥地利；德意志地区"},{"label":"一句话概括","value":"拉施塔特会议试图处理莱茵左岸割让后的帝国赔偿问题，但因战争重启而失败。"},{"label":"参与者","value":"法国代表、神圣罗马帝国等级代表、奥地利和各德意志诸侯代表。"},{"label":"发生了什么","value":"坎波福尔米奥条约后，法国和帝国代表在拉施塔特讨论莱茵左岸割让和右岸诸侯补偿问题。会议争执不断，1799年第二次反法同盟战争爆发后崩溃。"},{"label":"为什么重要","value":"它显示旧帝国已经进入领土重组倒计时，世俗化和媒介化的补偿逻辑在此阶段逐渐成形。"},{"label":"前因","value":"法国控制莱茵左岸导致大量帝国诸侯失去领地，必须讨论如何在帝国右岸补偿；这使教会领地、自由城市和小等级的命运被推上谈判桌。"},{"label":"后果","value":"会议失败未能阻止重组，1801年吕内维尔和约后，赔偿问题通过1803年神圣罗马帝国代表会议主要决议集中处理。"},{"label":"出处","value":"Britannica, Rastatt Congress；Britannica, Treaty of Campo Formio；Britannica, Treaty of Lunéville。"}],"relationItems":["← 前因：法奥《坎波福尔米奥条约》","→ 后果：法奥《吕内维尔和约》","↔ 相关：神圣罗马帝国世俗化","↔ 相关：德意志帝国媒介化"],"relations":[{"text":"← 前因：法奥《坎波福尔米奥条约》","id":"extra478"},{"text":"→ 后果：法奥《吕内维尔和约》","id":"extra481"},{"text":"↔ 相关：神圣罗马帝国世俗化","id":"extra483"},{"text":"↔ 相关：德意志帝国媒介化","id":"extra484"}],"source":"history","id":"extra479"},{"title":"第二次反法同盟战争","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1798—1802年","place":"意大利、瑞士、莱茵地区、尼德兰和地中海","summary":"第二次反法同盟战争再次把奥地利和德意志南部卷入对法战争，最终确认法国莱茵优势。","fields":[{"label":"标题","value":"第二次反法同盟战争"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1798—1802年"},{"label":"地点","value":"意大利、瑞士、莱茵地区、尼德兰和地中海"},{"label":"主要国家","value":"法国；奥地利；英国；俄罗斯；神圣罗马帝国"},{"label":"一句话概括","value":"第二次反法同盟战争再次把奥地利和德意志南部卷入对法战争，最终确认法国莱茵优势。"},{"label":"参与者","value":"法国、奥地利、英国、俄罗斯、奥斯曼帝国、那不勒斯等。"},{"label":"发生了什么","value":"法国在意大利、瑞士和地中海扩张后，欧洲列强再次组成同盟。战争初期法国遭遇压力，但拿破仑回国执政后重新稳定局面，并在马伦哥等战役后迫使奥地利谈判。"},{"label":"为什么重要","value":"它使法国对莱茵和意大利的控制进一步制度化，旧帝国无法恢复战前边界。"},{"label":"前因","value":"坎波福尔米奥后的法国扩张没有停止，意大利和瑞士秩序重组触发列强反击；英国和奥地利也担心法国把革命影响固定成欧洲霸权。"},{"label":"后果","value":"1801年吕内维尔和约确认莱茵左岸归法国，德意志领土补偿问题不可回避；旧帝国必须用内部重组消化法国扩张造成的损失。"},{"label":"出处","value":"Britannica, French Revolutionary Wars；Britannica, Second Coalition；Britannica, Napoleon I。"}],"relationItems":["← 前因：法奥《坎波福尔米奥条约》","→ 后果：法奥《吕内维尔和约》","↔ 相关：法国大革命的欧洲冲击","↔ 同时期参考：拿破仑掌权"],"relations":[{"text":"← 前因：法奥《坎波福尔米奥条约》","id":"extra478"},{"text":"→ 后果：法奥《吕内维尔和约》","id":"extra481"},{"text":"↔ 相关：法国大革命的欧洲冲击","id":"extra319"}],"source":"history","id":"extra480"},{"title":"法奥《吕内维尔和约》","level":"A","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1801年2月9日","place":"吕内维尔","summary":"吕内维尔和约确认莱茵左岸归法国，使神圣罗马帝国的领土补偿和重组不可避免。","fields":[{"label":"标题","value":"法奥《吕内维尔和约》"},{"label":"分级","value":"A"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1801年2月9日"},{"label":"地点","value":"吕内维尔"},{"label":"主要国家","value":"法国；奥地利；神圣罗马帝国"},{"label":"一句话概括","value":"吕内维尔和约确认莱茵左岸归法国，使神圣罗马帝国的领土补偿和重组不可避免。"},{"label":"制定方/签署方","value":"法国共和国与奥地利，影响整个神圣罗马帝国。"},{"label":"主要内容","value":"确认法国获得莱茵左岸，承认法国在意大利和周边地区的部分安排，并要求帝国通过右岸补偿处理失地诸侯。"},{"label":"它试图解决什么问题","value":"它试图结束第二次反法同盟战争中法国与奥地利的冲突，并把法国的莱茵边界合法化。"},{"label":"为什么重要","value":"它是旧帝国瓦解前最关键的外交节点之一，直接通向1803年神圣罗马帝国代表会议主要决议。"},{"label":"争议/局限","value":"和约以牺牲帝国内部小领地、教会领地和自由城市为代价，法国压力严重破坏帝国宪制。"},{"label":"造成的影响","value":"莱茵左岸并入法国，帝国右岸通过世俗化和媒介化补偿诸侯，旧帝国结构被大规模改造。"},{"label":"出处","value":"Britannica, Treaty of Lunéville；Britannica, French Revolutionary Wars；Britannica, Holy Roman Empire。"}],"relationItems":["← 前因：第二次反法同盟战争","→ 后果：神圣罗马帝国代表会议主要决议","→ 后果：莱茵左岸并入法国","↔ 相关：神圣罗马帝国"],"relations":[{"text":"← 前因：第二次反法同盟战争","id":"extra480"},{"text":"→ 后果：神圣罗马帝国代表会议主要决议","id":"extra320"},{"text":"→ 后果：莱茵左岸并入法国","id":"extra482"},{"text":"↔ 相关：神圣罗马帝国","id":"extra300"}],"source":"history","id":"extra481"},{"title":"莱茵左岸并入法国","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1790年代占领，1801年吕内维尔和约确认","place":"莱茵河左岸地区","summary":"莱茵左岸并入法国改变德意志西部边界，迫使旧帝国以补偿方式重组内部结构。","fields":[{"label":"标题","value":"莱茵左岸并入法国"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1790年代占领，1801年吕内维尔和约确认"},{"label":"地点","value":"莱茵河左岸地区"},{"label":"主要国家","value":"法国；神圣罗马帝国；德意志地区"},{"label":"一句话概括","value":"莱茵左岸并入法国改变德意志西部边界，迫使旧帝国以补偿方式重组内部结构。"},{"label":"参与者","value":"法国革命政府、莱茵左岸帝国领地、奥地利、普鲁士和神圣罗马帝国等级。"},{"label":"发生了什么","value":"法国革命军在1790年代占领莱茵左岸，并将当地纳入法国行政和法律体系。1801年吕内维尔和约确认法国取得莱茵左岸。"},{"label":"为什么重要","value":"它把法国革命制度直接带入德意志西部，也摧毁许多帝国领地在莱茵地区的旧权利。"},{"label":"前因","value":"第一次和第二次反法同盟战争中，法国把莱茵视为自然边界，奥地利和普鲁士无法共同维持帝国西部防线。"},{"label":"后果","value":"失地诸侯要求在莱茵右岸获得补偿，1803年世俗化和媒介化成为帝国重组的核心工具；小邦、教会领地和自由城市成为主要牺牲对象。"},{"label":"出处","value":"Britannica, Treaty of Lunéville；Britannica, Rhine River；Britannica, French Revolutionary Wars。"}],"relationItems":["← 前因：法奥《吕内维尔和约》","→ 后果：神圣罗马帝国世俗化","→ 后果：德意志帝国媒介化","↔ 相关：法国大革命的欧洲冲击"],"relations":[{"text":"← 前因：法奥《吕内维尔和约》","id":"extra481"},{"text":"→ 后果：神圣罗马帝国世俗化","id":"extra483"},{"text":"→ 后果：德意志帝国媒介化","id":"extra484"},{"text":"↔ 相关：法国大革命的欧洲冲击","id":"extra319"}],"source":"history","id":"extra482"},{"title":"神圣罗马帝国世俗化","level":"B","type":"事件卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1803年","place":"神圣罗马帝国莱茵右岸及各教会领地","summary":"1803年帝国世俗化把大量教会领地转给世俗诸侯，是旧帝国结构崩塌的关键机制。","fields":[{"label":"标题","value":"神圣罗马帝国世俗化"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1803年"},{"label":"地点","value":"神圣罗马帝国莱茵右岸及各教会领地"},{"label":"主要国家","value":"神圣罗马帝国；德意志地区；法国"},{"label":"一句话概括","value":"1803年帝国世俗化把大量教会领地转给世俗诸侯，是旧帝国结构崩塌的关键机制。"},{"label":"参与者","value":"帝国代表会议、法国、奥地利、普鲁士、巴伐利亚、符腾堡、巴登等诸侯和教会领地。"},{"label":"发生了什么","value":"为补偿莱茵左岸失地诸侯，1803年神圣罗马帝国代表会议主要决议将大量主教领、修道院领和教会财产世俗化，转给世俗统治者。"},{"label":"为什么重要","value":"它终结了帝国中大量教会诸侯的政治地位，改变德意志领土结构和教会财产格局。"},{"label":"前因","value":"莱茵左岸并入法国后，失地诸侯要求补偿；法国也希望通过重组削弱旧帝国并扶植中等邦国，奥地利和普鲁士则各自争取有利补偿。"},{"label":"后果","value":"教会领地大规模消失，巴伐利亚、符腾堡、巴登、普鲁士等获得补偿，旧帝国等级结构被严重破坏；皇帝、教会诸侯和自由城市的传统平衡不复存在。"},{"label":"出处","value":"Britannica, Reichsdeputationshauptschluss；Britannica, Secularization；Britannica, Holy Roman Empire。"}],"relationItems":["← 前因：莱茵左岸并入法国","← 前因：神圣罗马帝国代表会议主要决议","↔ 相关：神圣罗马帝国主教领","→ 后果：神圣罗马帝国解体"],"relations":[{"text":"← 前因：莱茵左岸并入法国","id":"extra482"},{"text":"← 前因：神圣罗马帝国代表会议主要决议","id":"extra320"},{"text":"↔ 相关：神圣罗马帝国主教领","id":"extra401"},{"text":"→ 后果：神圣罗马帝国解体","id":"extra520"}],"source":"history","id":"extra483"},{"title":"德意志帝国媒介化","level":"B","type":"事件卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1803年及其后延续","place":"神圣罗马帝国各小邦、骑士领和自由城市地区","summary":"帝国媒介化把大量直属小领地并入较大邦国，显著减少德意志政治碎片。","fields":[{"label":"标题","value":"德意志帝国媒介化"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1803年及其后延续"},{"label":"地点","value":"神圣罗马帝国各小邦、骑士领和自由城市地区"},{"label":"主要国家","value":"神圣罗马帝国；德意志地区；法国"},{"label":"一句话概括","value":"帝国媒介化把大量直属小领地并入较大邦国，显著减少德意志政治碎片。"},{"label":"参与者","value":"帝国代表会议、法国、德意志中等邦国、帝国骑士、帝国自由城市和小诸侯。"},{"label":"发生了什么","value":"1803年前后，大量原本直属皇帝的小领地、自由城市和骑士领被并入较大的世俗邦国，失去帝国直属地位。"},{"label":"为什么重要","value":"它是德意志领土整合的重大步骤，为19世纪较大邦国主导德意志政治创造条件。"},{"label":"前因","value":"法国占领莱茵左岸后，旧帝国用右岸领地补偿失地诸侯，中小等级成为被牺牲对象；较大邦国也借法国压力吞并周边微型领地。"},{"label":"后果","value":"帝国政治碎片减少，但旧帝国宪制基础被掏空；许多原本直属皇帝的政治单元消失，莱茵邦和神圣罗马帝国解体很快到来。"},{"label":"出处","value":"Britannica, German Mediatisation；Britannica, Reichsdeputationshauptschluss；Britannica, Holy Roman Empire。"}],"relationItems":["← 前因：莱茵左岸并入法国","← 前因：神圣罗马帝国代表会议主要决议","↔ 相关：神圣罗马帝国帝国骑士","→ 后果：拿破仑莱茵邦"],"relations":[{"text":"← 前因：莱茵左岸并入法国","id":"extra482"},{"text":"← 前因：神圣罗马帝国代表会议主要决议","id":"extra320"},{"text":"↔ 相关：神圣罗马帝国帝国骑士","id":"extra417"},{"text":"→ 后果：拿破仑莱茵邦","id":"extra521"}],"source":"history","id":"extra484"},{"title":"神圣罗马帝国自由城市大规模并合","level":"C","type":"事件卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1803年","place":"神圣罗马帝国各自由城市","summary":"1803年多数帝国自由城市被并入周边邦国，旧帝国城市自治传统遭到重创。","fields":[{"label":"标题","value":"神圣罗马帝国自由城市大规模并合"},{"label":"分级","value":"C"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1803年"},{"label":"地点","value":"神圣罗马帝国各自由城市"},{"label":"主要国家","value":"神圣罗马帝国；德意志地区"},{"label":"一句话概括","value":"1803年多数帝国自由城市被并入周边邦国，旧帝国城市自治传统遭到重创。"},{"label":"参与者","value":"帝国自由城市、巴伐利亚、符腾堡、巴登、普鲁士等扩张邦国、法国和帝国代表会议。"},{"label":"发生了什么","value":"1803年帝国重组中，绝大多数帝国自由城市失去直属皇帝的地位，被并入周边较大邦国；只有少数城市保留特殊地位。"},{"label":"为什么重要","value":"它终结了中世纪以来许多城市自治传统，使德意志政治从城市、骑士、教会多中心结构转向较大领邦体系。"},{"label":"前因","value":"莱茵左岸失地补偿需要大量领土和收入，弱小自由城市缺乏抵抗法国和大邦交易的能力；城市自治传统在列强重组中被视为可转让资源。"},{"label":"后果","value":"城市政治自主性下降，许多城市成为领邦行政体系的一部分；旧帝国等级格局进一步瓦解，德意志政治向较大领邦主导的格局转变。"},{"label":"出处","value":"Britannica, Free Imperial City；Britannica, Reichsdeputationshauptschluss；Britannica, German Mediatisation。"}],"relationItems":["← 前因：神圣罗马帝国自由城市","← 前因：神圣罗马帝国代表会议主要决议","↔ 相关：德意志帝国媒介化","→ 后果：神圣罗马帝国解体"],"relations":[{"text":"← 前因：神圣罗马帝国自由城市","id":"extra402"},{"text":"← 前因：神圣罗马帝国代表会议主要决议","id":"extra320"},{"text":"↔ 相关：德意志帝国媒介化","id":"extra484"},{"text":"→ 后果：神圣罗马帝国解体","id":"extra520"}],"source":"history","id":"extra485"},{"title":"欧洲均势政治","level":"A","type":"概念/思潮卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"16世纪后期—19世纪，近代欧洲长期存在","place":"欧洲国际体系","summary":"欧洲均势政治试图防止单一强国支配大陆，是近代欧洲外交和战争的重要逻辑。","fields":[{"label":"标题","value":"欧洲均势政治"},{"label":"分级","value":"A"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"16世纪后期—19世纪，近代欧洲长期存在"},{"label":"地点","value":"欧洲国际体系"},{"label":"主要国家","value":"法国；英国；奥地利；普鲁士；俄国；西班牙；奥斯曼帝国"},{"label":"一句话概括","value":"欧洲均势政治试图防止单一强国支配大陆，是近代欧洲外交和战争的重要逻辑。"},{"label":"核心主张/思路","value":"各国通过联盟、战争、调停、领土补偿和外交会议，维持大国之间的大致力量平衡，避免某一国家获得压倒性霸权。"},{"label":"提出者/代表人物（可选）","value":"欧洲各国外交家；梅特涅、卡斯尔雷、俾斯麦等后来均以不同方式运用均势逻辑。"},{"label":"它从何而来","value":"宗教战争、哈布斯堡—法国竞争、威斯特伐利亚体系和18世纪王朝战争共同塑造了“不能让一家独大”的国际政治经验。"},{"label":"典型表现","value":"反路易十四联盟、西班牙王位继承战争、七年战争、反拿破仑同盟、维也纳会议体系。"},{"label":"为什么重要","value":"理解德意志历史不能只看国内统一，也要看欧洲大国如何利用、限制或支持中欧权力变化。普鲁士崛起、德意志统一和德国问题都深受均势政治制约。"},{"label":"争议/局限","value":"均势政治有时稳定国际秩序，也可能把小国当作补偿对象，并通过战争来“恢复平衡”。"},{"label":"出处","value":"Encyclopaedia Britannica: balance of power；Paul W. Schroeder, The Transformation of European Politics；DHM/LeMO: Wiener Kongress。"}],"relationItems":["↔ 相关：威斯特伐利亚和约","↔ 相关：七年战争前欧洲外交革命","↔ 相关：拿破仑战后维也纳会议","→ 后果：欧洲梅特涅体系","✗ 对立/冲突：法国霸权"],"relations":[{"text":"↔ 相关：威斯特伐利亚和约","id":"extra308"},{"text":"↔ 相关：七年战争前欧洲外交革命","id":"extra459"},{"text":"↔ 相关：拿破仑战后维也纳会议","id":"extra525"},{"text":"→ 后果：欧洲梅特涅体系","id":"extra500"},{"text":"✗ 对立/冲突：法国霸权","id":"extra868"}],"source":"history","id":"extra866"},{"title":"波兰立陶宛联邦","level":"B","type":"组织/机构卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1569—1795年","place":"东中欧，波兰、立陶宛、乌克兰、白俄罗斯等地区","summary":"波兰立陶宛联邦是东中欧大型贵族共和国，后来在俄普奥竞争中被三次瓜分。","fields":[{"label":"标题","value":"波兰立陶宛联邦"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1569—1795年"},{"label":"地点","value":"东中欧，波兰、立陶宛、乌克兰、白俄罗斯等地区"},{"label":"主要国家","value":"波兰；立陶宛；俄罗斯；普鲁士；奥地利"},{"label":"一句话概括","value":"波兰立陶宛联邦是东中欧大型贵族共和国，后来在俄普奥竞争中被三次瓜分。"},{"label":"性质/类型","value":"贵族共和国和复合君主国式政治共同体。"},{"label":"成立/解散时间","value":"1569年卢布林联合形成；1795年第三次瓜分后消失。"},{"label":"核心目标/宗旨","value":"把波兰王国和立陶宛大公国结合为共同政治体，维持贵族自治、选王制和广阔东欧领土。"},{"label":"关键人物（可选）","value":"联邦贵族、选举国王、邻近大国君主。"},{"label":"关键行动/事件","value":"联邦曾是东中欧大国，但选王制、贵族自由否决权、军事财政薄弱和外部干预削弱国家能力。18世纪后，俄罗斯、普鲁士和奥地利通过三次瓜分吞并其领土。"},{"label":"为什么重要","value":"它解释普鲁士和奥地利为何能通过波兰瓜分获得领土和人口，也解释东欧民族问题、波兰复国诉求和俄普奥关系的长期背景。"},{"label":"争议/局限","value":"联邦衰落不能只归因于内部制度，邻国干预和欧洲大国均势同样关键。"},{"label":"出处","value":"Encyclopaedia Britannica: Polish-Lithuanian Commonwealth；Encyclopaedia Britannica: Partitions of Poland；Norman Davies, God’s Playground。"}],"relationItems":["→ 后果：三次波兰瓜分","↔ 相关：普鲁士王国成立","↔ 相关：哈布斯堡君主国","↔ 相关：欧洲均势政治","→ 后果：波兰民族问题"],"relations":[{"text":"→ 后果：三次波兰瓜分","id":"extra341"},{"text":"↔ 相关：普鲁士王国成立","id":"extra312"},{"text":"↔ 相关：哈布斯堡君主国","id":"extra309"},{"text":"↔ 相关：欧洲均势政治","id":"extra866"}],"source":"history","id":"extra867"},{"title":"法国霸权","level":"B","type":"概念/思潮卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"17世纪路易十四时期和拿破仑时代尤为突出","place":"欧洲大陆","summary":"法国霸权指法国在近代欧洲多次试图主导大陆秩序，引发其他大国结盟制衡。","fields":[{"label":"标题","value":"法国霸权"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"17世纪路易十四时期和拿破仑时代尤为突出"},{"label":"地点","value":"欧洲大陆"},{"label":"主要国家","value":"法国；神圣罗马帝国；奥地利；普鲁士；英国；俄国；西班牙"},{"label":"一句话概括","value":"法国霸权指法国在近代欧洲多次试图主导大陆秩序，引发其他大国结盟制衡。"},{"label":"核心主张/思路","value":"法国凭借人口、财政、军队和行政能力，在欧洲大陆追求边界安全、王朝利益和政治影响力。"},{"label":"提出者/代表人物（可选）","value":"路易十四、拿破仑一世、法国外交和军事精英。"},{"label":"它从何而来","value":"法国国家建构、王权集中、军事财政扩张和哈布斯堡包围感共同推动法国向外扩张。"},{"label":"典型表现","value":"路易十四战争、莱茵边界争夺、法国革命战争、拿破仑帝国、莱茵邦体系。"},{"label":"为什么重要","value":"法国霸权压力是德意志诸邦、奥地利、普鲁士和英国反复结盟的重要原因。德意志民族主义、普鲁士改革和维也纳体系都与反法经验相关。"},{"label":"争议/局限","value":"“法国霸权”不是法国每一阶段外交的全部目标；安全、防御和革命输出也与霸权诉求交织。"},{"label":"出处","value":"Encyclopaedia Britannica: Louis XIV；Encyclopaedia Britannica: Napoleon I；Paul Kennedy, The Rise and Fall of the Great Powers。"}],"relationItems":["↔ 相关：欧洲均势政治","↔ 相关：法国大革命的欧洲冲击","→ 后果：拿破仑莱茵邦","→ 后果：德意志反法民族动员","✗ 对立/冲突：反拿破仑同盟特拉亨贝格计划"],"relations":[{"text":"↔ 相关：欧洲均势政治","id":"extra866"},{"text":"↔ 相关：法国大革命的欧洲冲击","id":"extra319"},{"text":"→ 后果：拿破仑莱茵邦","id":"extra521"},{"text":"→ 后果：德意志反法民族动员","id":"extra588"},{"text":"✗ 对立/冲突：反拿破仑同盟特拉亨贝格计划","id":"extra587"}],"source":"history","id":"extra868"},{"title":"中世纪城市自治","level":"B","type":"概念/思潮卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"约11—15世纪","place":"欧洲城市网络","summary":"中世纪城市自治指城市通过特许状、行会和市政机构取得相对独立的司法、税收和治理空间。","fields":[{"label":"标题","value":"中世纪城市自治"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"约11—15世纪"},{"label":"地点","value":"欧洲城市网络"},{"label":"主要国家","value":"意大利城邦；神圣罗马帝国；法国；低地地区"},{"label":"一句话概括","value":"中世纪城市自治指城市通过特许状、行会和市政机构取得相对独立的司法、税收和治理空间。"},{"label":"核心主张/思路","value":"城市不是单纯受封建领主支配的聚落，而可以成为拥有市民身份、市场规则、城墙防卫和自治机构的政治共同体。"},{"label":"提出者/代表人物（可选）","value":"城市公社、市民精英、行会、商人集团、授予特许权的君主或领主。"},{"label":"它从何而来","value":"商业复兴、手工业增长、货币经济、城堡与主教城市扩张，使城市居民有能力用税收、武装和谈判换取自治权。"},{"label":"典型表现","value":"意大利城市公社、德意志自由帝国城市、低地城市、汉萨同盟城市和各地市政法院。"},{"label":"为什么重要","value":"它为欧洲城市政治、商业资本、行会制度和市民身份提供制度基础，也解释中世纪后期城市为何能影响王权、帝国和宗教改革。"},{"label":"争议/局限","value":"城市自治通常属于少数男性市民精英，妇女、贫民、外来者和乡村人口并不平等享有自治权利。"},{"label":"出处","value":"Encyclopaedia Britannica: commune；Cambridge Medieval History；Peter Blickle, Communal Reformation。"}],"relationItems":["← 前因：中世纪商业复兴","↔ 相关：中世纪马格德堡法","↔ 相关：中世纪汉萨同盟","↔ 相关：中世纪意大利城市自治","→ 后果：近代市民社会"],"relations":[{"text":"← 前因：中世纪商业复兴","id":"extra884"},{"text":"↔ 相关：中世纪马格德堡法","id":"extra361"},{"text":"↔ 相关：中世纪汉萨同盟","id":"extra321"},{"text":"↔ 相关：中世纪意大利城市自治","id":"extra870"}],"source":"history","id":"extra869"},{"title":"中世纪意大利城市自治","level":"B","type":"概念/思潮卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"约11—14世纪","place":"北意大利和中意大利城市","summary":"中世纪意大利城市自治让米兰、佛罗伦萨、威尼斯等城市成为欧洲最早成熟的城市政治实验场。","fields":[{"label":"标题","value":"中世纪意大利城市自治"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"约11—14世纪"},{"label":"地点","value":"北意大利和中意大利城市"},{"label":"主要国家","value":"意大利城邦；神圣罗马帝国；教皇国"},{"label":"一句话概括","value":"中世纪意大利城市自治让米兰、佛罗伦萨、威尼斯等城市成为欧洲最早成熟的城市政治实验场。"},{"label":"核心主张/思路","value":"城市公社通过执政官、市议会、行会和武装民兵处理司法、税收、外交和战争，不完全服从皇帝或封建领主。"},{"label":"提出者/代表人物（可选）","value":"城市贵族、商人、行会、市民民兵、各城市执政官和议会。"},{"label":"它从何而来","value":"地中海贸易复兴、主教城市传统、皇帝与教皇权力竞争，以及城市财富增长共同扩大了自治空间。"},{"label":"典型表现","value":"伦巴第联盟、佛罗伦萨行会政治、威尼斯共和国、米兰公社和城市间长期战争。"},{"label":"为什么重要","value":"它把城市自治、商业资本、银行业、共和传统和文艺复兴城市文化连接起来，是欧洲政治多元格局的重要来源。"},{"label":"争议/局限","value":"城市自治内部经常伴随派系斗争、寡头统治和对周边乡村的支配，并不等于现代民主。"},{"label":"出处","value":"Encyclopaedia Britannica: medieval Italian communes；Lauro Martines, Power and Imagination；Daniel Waley, The Italian City-Republics。"}],"relationItems":["← 前因：中世纪商业复兴","↔ 相关：意大利伦巴第联盟","↔ 相关：中世纪城市自治","→ 后果：意大利文艺复兴城市文化"],"relations":[{"text":"← 前因：中世纪商业复兴","id":"extra884"},{"text":"↔ 相关：意大利伦巴第联盟","id":"extra356"},{"text":"↔ 相关：中世纪城市自治","id":"extra869"}],"source":"history","id":"extra870"},{"title":"罗马帝国","level":"S","type":"组织/机构卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"公元前27年—公元476年（西罗马）；东罗马延续至1453年","place":"地中海世界、欧洲西部与中部、北非、西亚部分地区","summary":"罗马帝国把地中海世界纳入长期帝国秩序，深刻影响欧洲国家、法律、城市和基督教传统。","fields":[{"label":"标题","value":"罗马帝国"},{"label":"分级","value":"S"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"公元前27年—公元476年（西罗马）；东罗马延续至1453年"},{"label":"地点","value":"地中海世界、欧洲西部与中部、北非、西亚部分地区"},{"label":"主要国家","value":"罗马；意大利；希腊；埃及；高卢；日耳曼边疆地区"},{"label":"一句话概括","value":"罗马帝国把地中海世界纳入长期帝国秩序，深刻影响欧洲国家、法律、城市和基督教传统。"},{"label":"性质/类型","value":"以皇帝、军队、行省、税收和罗马法为核心的古代地中海帝国。"},{"label":"成立/解散时间","value":"通常以奥古斯都确立元首制的公元前27年为帝国开端；西罗马帝国在476年灭亡，东罗马帝国延续至1453年。"},{"label":"核心目标/宗旨","value":"维持帝国边疆、税收与城市秩序，把地方精英纳入罗马政治和法律体系。"},{"label":"关键人物（可选）","value":"奥古斯都、图拉真、戴克里先、君士坦丁、狄奥多西等。"},{"label":"关键行动/事件","value":"罗马和平、行省治理、基督教合法化、帝国分治、莱茵-多瑙边疆防御和西罗马灭亡。"},{"label":"为什么重要","value":"欧洲中世纪帝国观念、罗马法、拉丁基督教、城市网络和“罗马继承”政治都离不开罗马帝国遗产。"},{"label":"争议/局限","value":"罗马帝国不是现代民族国家，其公民权、奴隶制和行省统治具有强烈等级性。"},{"label":"出处","value":"Encyclopaedia Britannica: Roman Empire；Mary Beard, SPQR；Chris Wickham, The Inheritance of Rome。"}],"relationItems":["↔ 相关：罗马帝国莱茵-多瑙边疆","→ 后果：民族大迁徙与日耳曼王国","→ 后果：拜占庭帝国","→ 后果：查理曼加冕为罗马皇帝"],"relations":[{"text":"↔ 相关：罗马帝国莱茵-多瑙边疆","id":"extra391"},{"text":"→ 后果：民族大迁徙与日耳曼王国","id":"extra393"},{"text":"→ 后果：拜占庭帝国","id":"extra888"},{"text":"→ 后果：查理曼加冕为罗马皇帝","id":"extra343"}],"source":"history","id":"extra871"},{"title":"奥斯曼帝国","level":"A","type":"组织/机构卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"约1299—1922年","place":"安纳托利亚、巴尔干、中东、北非和东地中海","summary":"奥斯曼帝国长期横跨欧亚非，既是欧洲均势的重要参与者，也是中东欧边疆政治的核心力量。","fields":[{"label":"标题","value":"奥斯曼帝国"},{"label":"分级","value":"A"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"约1299—1922年"},{"label":"地点","value":"安纳托利亚、巴尔干、中东、北非和东地中海"},{"label":"主要国家","value":"奥斯曼帝国；土耳其；希腊；塞尔维亚；匈牙利；奥地利；阿拉伯地区"},{"label":"一句话概括","value":"奥斯曼帝国长期横跨欧亚非，既是欧洲均势的重要参与者，也是中东欧边疆政治的核心力量。"},{"label":"性质/类型","value":"由奥斯曼王朝统治的跨洲帝国，兼具伊斯兰王朝、军事财政国家和多族群帝国特征。"},{"label":"成立/解散时间","value":"约1299年兴起于安纳托利亚西北部；1922年苏丹制废除，帝国终结。"},{"label":"核心目标/宗旨","value":"通过王朝、军队、税制、宗教法和地方精英协作维持跨区域统治。"},{"label":"关键人物（可选）","value":"奥斯曼一世、穆罕默德二世、苏莱曼一世、塞利姆三世、阿卜杜勒哈米德二世。"},{"label":"关键行动/事件","value":"1453年征服君士坦丁堡、莫哈奇战役、两次围攻维也纳、坦志麦特改革和一战失败。"},{"label":"为什么重要","value":"奥斯曼帝国塑造了巴尔干、中东和东地中海秩序，也长期影响哈布斯堡、俄国和德国的外交战略。"},{"label":"争议/局限","value":"传统“衰落”叙事过于简单，近年研究更强调帝国转型、地方协商和现代化压力。"},{"label":"出处","value":"Encyclopaedia Britannica: Ottoman Empire；Suraiya Faroqhi, The Ottoman Empire and the World Around It；Gabor Agoston, The Last Muslim Conquest。"}],"relationItems":["↔ 相关：奥斯曼-匈牙利莫哈奇战役","↔ 相关：奥斯曼第二次围攻维也纳","→ 后果：巴尔干民族问题","↔ 相关：巴格达铁路"],"relations":[{"text":"↔ 相关：奥斯曼-匈牙利莫哈奇战役","id":"extra428"},{"text":"↔ 相关：奥斯曼第二次围攻维也纳","id":"extra310"},{"text":"→ 后果：巴尔干民族问题","id":"extra930"}],"source":"history","id":"extra872"},{"title":"荷兰独立战争","level":"A","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1568—1648年","place":"低地国家、西班牙帝国和欧洲海上贸易网络","summary":"荷兰独立战争使北部尼德兰脱离西班牙统治，建立荷兰共和国并推动欧洲商业与宗教政治变化。","fields":[{"label":"标题","value":"荷兰独立战争"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1568—1648年"},{"label":"地点","value":"低地国家、西班牙帝国和欧洲海上贸易网络"},{"label":"主要国家","value":"荷兰共和国；西班牙；神圣罗马帝国；英国；法国"},{"label":"一句话概括","value":"荷兰独立战争使北部尼德兰脱离西班牙统治，建立荷兰共和国并推动欧洲商业与宗教政治变化。"},{"label":"参与者","value":"西班牙哈布斯堡王朝、尼德兰各省、奥兰治亲王威廉、荷兰城市商人、加尔文派和外国支持者。"},{"label":"发生了什么","value":"西班牙试图强化税收、宗教镇压和中央控制，引发尼德兰贵族、城市和新教力量反抗。战争长期在围城、海上袭击、财政动员和国际联盟之间展开。北部省份形成联省共和国，最终在1648年《威斯特伐利亚和约》中获得国际承认。"},{"label":"为什么重要","value":"它是欧洲早期近代反哈布斯堡战争、宗教战争和商业共和国兴起的关键节点。"},{"label":"前因","value":"宗教改革、哈布斯堡中央集权、低地城市自治传统和西班牙财政压力共同引发冲突。"},{"label":"后果","value":"荷兰共和国崛起，低地商业和海上帝国扩张，欧洲均势格局发生变化。"},{"label":"出处","value":"Encyclopaedia Britannica: Eighty Years' War；Jonathan Israel, The Dutch Republic；Geoffrey Parker, The Dutch Revolt。"}],"relationItems":["← 前因：欧洲宗教改革","↔ 相关：威斯特伐利亚和约","→ 后果：荷兰共和国黄金时代","↔ 相关：英法殖民竞争"],"relations":[{"text":"← 前因：欧洲宗教改革","id":"extra301"},{"text":"↔ 相关：威斯特伐利亚和约","id":"extra308"},{"text":"↔ 相关：英法殖民竞争","id":"extra875"}],"source":"history","id":"extra873"},{"title":"欧洲启蒙运动","level":"A","type":"概念/思潮卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"约17世纪末—18世纪","place":"法国、英国、苏格兰、德意志地区、意大利、荷兰和欧洲公共空间","summary":"欧洲启蒙运动以理性、批判、科学、宽容和公共讨论为核心，重塑近代政治与思想语言。","fields":[{"label":"标题","value":"欧洲启蒙运动"},{"label":"分级","value":"A"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"约17世纪末—18世纪"},{"label":"地点","value":"法国、英国、苏格兰、德意志地区、意大利、荷兰和欧洲公共空间"},{"label":"主要国家","value":"法国；英国；德国；荷兰；意大利；奥地利；普鲁士"},{"label":"一句话概括","value":"欧洲启蒙运动以理性、批判、科学、宽容和公共讨论为核心，重塑近代政治与思想语言。"},{"label":"核心主张/思路","value":"人类可以通过理性、经验、教育和公共辩论改造知识、法律、宗教宽容、经济和政治秩序。"},{"label":"提出者/代表人物（可选）","value":"洛克、伏尔泰、孟德斯鸠、卢梭、康德、狄德罗、休谟等。"},{"label":"它从何而来","value":"科学革命、印刷出版、宗教战争反思、商业社会和城市公共空间共同推动知识权威变化。"},{"label":"典型表现","value":"百科全书、沙龙、咖啡馆、书信共和国、自然法理论、宗教宽容和改革型君主政治。"},{"label":"为什么重要","value":"它为美国革命、法国大革命、法典化、教育改革和现代公民权利语言提供思想资源。"},{"label":"争议/局限","value":"启蒙思想内部差异很大，也常与殖民主义、性别排除和欧洲中心主义纠缠在一起。"},{"label":"出处","value":"Encyclopaedia Britannica: Enlightenment；Dorinda Outram, The Enlightenment；Jonathan Israel, Radical Enlightenment。"}],"relationItems":["← 前因：科学革命","↔ 相关：德意志启蒙运动","↔ 相关：欧洲启蒙专制","→ 后果：法国大革命"],"relations":[{"text":"← 前因：科学革命","id":"extra889"},{"text":"↔ 相关：德意志启蒙运动","id":"extra317"},{"text":"↔ 相关：欧洲启蒙专制","id":"extra883"},{"text":"→ 后果：法国大革命","id":"extra887"}],"source":"history","id":"extra874"},{"title":"英法殖民竞争","level":"B","type":"概念/思潮卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"17世纪末—19世纪初","place":"北美、加勒比、印度、非洲沿岸和全球海路","summary":"英法殖民竞争把欧洲均势扩展到全球贸易、海军和殖民地战争，是近代世界秩序形成的重要动力。","fields":[{"label":"标题","value":"英法殖民竞争"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"17世纪末—19世纪初"},{"label":"地点","value":"北美、加勒比、印度、非洲沿岸和全球海路"},{"label":"主要国家","value":"英国；法国；西班牙；荷兰；印度诸邦；北美原住民社会"},{"label":"一句话概括","value":"英法殖民竞争把欧洲均势扩展到全球贸易、海军和殖民地战争，是近代世界秩序形成的重要动力。"},{"label":"核心主张/思路","value":"英国和法国不只在欧洲争夺地位，也在殖民地、海上贸易、奴隶贸易、财政信用和公司网络中竞争。"},{"label":"提出者/代表人物（可选）","value":"英国和法国王室、殖民公司、海军、种植园主、东印度公司和殖民行政官。"},{"label":"它从何而来","value":"重商主义、海权竞争、殖民贸易利润和欧洲王朝战争全球化。"},{"label":"典型表现","value":"九年战争、奥地利王位继承战争、七年战争、法国印第安战争和印度殖民竞争。"},{"label":"为什么重要","value":"它解释七年战争为何是全球战争，也解释英国海上帝国和法国财政危机的长期背景。"},{"label":"争议/局限","value":"殖民竞争常被写成欧洲大国竞争，但其代价主要落在殖民地社会、奴隶和原住民身上。"},{"label":"出处","value":"Encyclopaedia Britannica: Seven Years' War；P. J. Marshall, The Making and Unmaking of Empires；C. A. Bayly, Imperial Meridian。"}],"relationItems":["← 前因：欧洲海外扩张","↔ 相关：奥地利王位继承战争","↔ 相关：七年战争","→ 后果：英国海上帝国"],"relations":[{"text":"↔ 相关：奥地利王位继承战争","id":"extra313"},{"text":"↔ 相关：七年战争","id":"extra316"}],"source":"history","id":"extra875"},{"title":"早期近代军事革命","level":"B","type":"概念/思潮卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"约16—17世纪","place":"欧洲及其海外战争空间","summary":"早期近代军事革命指火器、堡垒、常备军和财政动员变化推动战争规模与国家能力上升。","fields":[{"label":"标题","value":"早期近代军事革命"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"约16—17世纪"},{"label":"地点","value":"欧洲及其海外战争空间"},{"label":"主要国家","value":"西班牙；荷兰共和国；法国；瑞典；神圣罗马帝国；英国"},{"label":"一句话概括","value":"早期近代军事革命指火器、堡垒、常备军和财政动员变化推动战争规模与国家能力上升。"},{"label":"核心主张/思路","value":"火药武器、线列战术、棱堡体系、军队规模扩大和军需财政改变了欧洲战争与国家建设关系。"},{"label":"提出者/代表人物（可选）","value":"迈克尔·罗伯茨、杰弗里·帕克等历史学者；古斯塔夫二世·阿道夫、莫里斯亲王等军事改革者。"},{"label":"它从何而来","value":"火炮和火绳枪扩散、围城战复杂化、雇佣军市场和王权财政需求共同改变战争模式。"},{"label":"典型表现","value":"荷兰军事改革、瑞典军制改革、三十年战争、棱堡城市和常备军扩张。"},{"label":"为什么重要","value":"它帮助解释近代国家为什么需要更强税收、官僚和军队组织，也解释三十年战争的毁灭性。"},{"label":"争议/局限","value":"“军事革命”是否存在、时间是否统一、因果是否过度强调欧洲，学界仍有争论。"},{"label":"出处","value":"Geoffrey Parker, The Military Revolution；Michael Roberts, The Military Revolution；Jeremy Black, A Military Revolution?。"}],"relationItems":["↔ 相关：阿尔布雷希特·冯·华伦斯坦","↔ 相关：瑞典介入三十年战争","→ 后果：欧洲财政军事国家","↔ 相关：三十年战争"],"relations":[{"text":"↔ 相关：阿尔布雷希特·冯·华伦斯坦","id":"extra332"},{"text":"↔ 相关：瑞典介入三十年战争","id":"extra334"},{"text":"↔ 相关：三十年战争","id":"extra307"}],"source":"history","id":"extra876"},{"title":"第一次十字军","level":"B","type":"事件卡","tags":["战争与外交","文化与思想"],"mainTag":"战争与外交","subTag":"文化与思想","timeText":"1096—1099年","place":"西欧、拜占庭帝国、小亚细亚、叙利亚和耶路撒冷","summary":"第一次十字军以宗教动员和军事远征夺取耶路撒冷，开启中世纪拉丁基督教对东方的长期军事介入。","fields":[{"label":"标题","value":"第一次十字军"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1096—1099年"},{"label":"地点","value":"西欧、拜占庭帝国、小亚细亚、叙利亚和耶路撒冷"},{"label":"主要国家","value":"法国；神圣罗马帝国地区；拜占庭帝国；塞尔柱突厥；耶路撒冷王国"},{"label":"一句话概括","value":"第一次十字军以宗教动员和军事远征夺取耶路撒冷，开启中世纪拉丁基督教对东方的长期军事介入。"},{"label":"参与者","value":"教皇乌尔班二世、法兰西和神圣罗马帝国地区贵族、拜占庭皇帝阿莱克修斯一世、塞尔柱势力和东方基督徒、穆斯林社群。"},{"label":"发生了什么","value":"乌尔班二世在克莱蒙会议号召援助东方基督徒并收复圣地后，西欧贵族和普通民众组成远征队东行。十字军经拜占庭进入小亚细亚，攻下尼西亚、安条克，1099年攻占耶路撒冷并建立十字军国家。"},{"label":"为什么重要","value":"它把教皇权威、骑士战争、朝圣和地中海政治连接起来，深刻影响中世纪东西方关系。"},{"label":"前因","value":"拜占庭求援、塞尔柱扩张、教皇改革和西欧骑士阶层暴力外向化共同促成远征。"},{"label":"后果","value":"十字军国家建立，东西方基督教关系更复杂，穆斯林世界逐渐形成反十字军动员。"},{"label":"出处","value":"Encyclopaedia Britannica: First Crusade；Thomas Asbridge, The First Crusade；Jonathan Riley-Smith, The First Crusade and the Idea of Crusading。"}],"relationItems":["← 前因：中世纪教会格里高利改革","↔ 相关：十字军运动","→ 后果：耶路撒冷王国","↔ 相关：拜占庭帝国"],"relations":[{"text":"← 前因：中世纪教会格里高利改革","id":"extra350"},{"text":"↔ 相关：十字军运动","id":"extra893"},{"text":"↔ 相关：拜占庭帝国","id":"extra888"}],"source":"history","id":"extra877"},{"title":"中世纪修道院文化","level":"B","type":"概念/思潮卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"约6—13世纪","place":"西欧和中欧基督教世界","summary":"中世纪修道院文化通过祈祷、抄写、教育、土地经营和慈善保存并重塑欧洲知识与社会秩序。","fields":[{"label":"标题","value":"中世纪修道院文化"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"约6—13世纪"},{"label":"地点","value":"西欧和中欧基督教世界"},{"label":"主要国家","value":"法兰克王国；英格兰；神圣罗马帝国；意大利；爱尔兰"},{"label":"一句话概括","value":"中世纪修道院文化通过祈祷、抄写、教育、土地经营和慈善保存并重塑欧洲知识与社会秩序。"},{"label":"核心主张/思路","value":"修道院把宗教生活组织为纪律化共同体，同时成为文字保存、农业经营、教育和地方社会服务中心。"},{"label":"提出者/代表人物（可选）","value":"本笃会、西多会、克吕尼修会、爱尔兰修士、抄经员和修道院院长。"},{"label":"它从何而来","value":"晚期罗马基督教、隐修传统、蛮族王国转型和教会土地制度共同塑造修道院网络。"},{"label":"典型表现","value":"本笃会会规、抄本室、修道院学校、西多会开垦、克吕尼改革和加洛林文艺复兴。"},{"label":"为什么重要","value":"它解释中世纪欧洲文化传承、教育、农业扩张和教会改革为何与修道院制度密切相关。"},{"label":"争议/局限","value":"修道院既可能是知识保存中心，也可能积累土地和权力，引发改革批评。"},{"label":"出处","value":"Encyclopaedia Britannica: monasticism；C. H. Lawrence, Medieval Monasticism；Diarmaid MacCulloch, A History of Christianity。"}],"relationItems":["← 前因：罗马帝国基督教化","↔ 相关：加洛林文艺复兴","↔ 相关：西多会与中欧开垦","→ 后果：中世纪大学"],"relations":[{"text":"↔ 相关：加洛林文艺复兴","id":"extra368"},{"text":"↔ 相关：西多会与中欧开垦","id":"extra413"},{"text":"→ 后果：中世纪大学","id":"extra879"}],"source":"history","id":"extra878"},{"title":"中世纪大学","level":"A","type":"组织/机构卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"约12世纪起","place":"欧洲城市，尤以博洛尼亚、巴黎、牛津、布拉格等为代表","summary":"中世纪大学把教师和学生组织成特许共同体，奠定欧洲高等教育和专业知识制度的基础。","fields":[{"label":"标题","value":"中世纪大学"},{"label":"分级","value":"A"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"约12世纪起"},{"label":"地点","value":"欧洲城市，尤以博洛尼亚、巴黎、牛津、布拉格等为代表"},{"label":"主要国家","value":"意大利；法国；英格兰；神圣罗马帝国；波希米亚"},{"label":"一句话概括","value":"中世纪大学把教师和学生组织成特许共同体，奠定欧洲高等教育和专业知识制度的基础。"},{"label":"性质/类型","value":"具有特许权、自治传统和学位授予权的教师或学生行会式教育机构。"},{"label":"成立/解散时间","value":"12世纪在博洛尼亚、巴黎、牛津等地形成，随后扩散到中欧和北欧。"},{"label":"核心目标/宗旨","value":"训练神学、法学、医学和文科人才，为教会、王权、城市和法律行政提供专业知识。"},{"label":"关键人物（可选）","value":"经院哲学家、法学家、主教、教皇、君主和大学师生共同体。"},{"label":"关键行动/事件","value":"巴黎大学发展、博洛尼亚法学传统、牛津和剑桥形成、1348年布拉格大学成立。"},{"label":"为什么重要","value":"大学让知识生产制度化，影响宗教改革、国家官僚、科学革命和现代学术共同体。"},{"label":"争议/局限","value":"中世纪大学高度男性化、拉丁语化，并受教会和特许权结构限制。"},{"label":"出处","value":"Encyclopaedia Britannica: university；Hastings Rashdall, The Universities of Europe in the Middle Ages；Jacques Verger, Men of Learning in Europe。"}],"relationItems":["← 前因：中世纪修道院文化","↔ 相关：中欧布拉格大学成立","↔ 相关：经院哲学","→ 后果：科学革命"],"relations":[{"text":"← 前因：中世纪修道院文化","id":"extra878"},{"text":"↔ 相关：中欧布拉格大学成立","id":"extra382"},{"text":"→ 后果：科学革命","id":"extra889"}],"source":"history","id":"extra879"},{"title":"西方教会大分裂","level":"B","type":"事件卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1378—1417年","place":"罗马、阿维尼翁、比萨、康斯坦茨及欧洲基督教世界","summary":"西方教会大分裂使多个教皇同时宣称合法，严重削弱拉丁教会权威并推动公会议运动。","fields":[{"label":"标题","value":"西方教会大分裂"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1378—1417年"},{"label":"地点","value":"罗马、阿维尼翁、比萨、康斯坦茨及欧洲基督教世界"},{"label":"主要国家","value":"教皇国；法国；神圣罗马帝国；英格兰；西班牙诸国"},{"label":"一句话概括","value":"西方教会大分裂使多个教皇同时宣称合法，严重削弱拉丁教会权威并推动公会议运动。"},{"label":"参与者","value":"罗马教皇、阿维尼翁教皇、欧洲王权、枢机主教团、神学家和康斯坦茨会议代表。"},{"label":"发生了什么","value":"1378年教皇选举争议后，罗马和阿维尼翁出现互不承认的教皇体系，欧洲国家按政治利益选择支持对象。1409年比萨会议试图解决分裂却制造第三位教皇。1414—1418年康斯坦茨会议最终结束多重教皇局面，选出马丁五世。"},{"label":"为什么重要","value":"它暴露教会制度危机，推动公会议高于教皇的主张，也为胡斯运动和宗教改革前的批判氛围提供背景。"},{"label":"前因","value":"阿维尼翁教廷、法王影响、教皇财政和罗马教会政治危机长期积累。"},{"label":"后果","value":"康斯坦茨会议解决分裂，但教会权威受损，改革要求没有根本消失。"},{"label":"出处","value":"Encyclopaedia Britannica: Western Schism；Francis Oakley, The Western Church in the Later Middle Ages；Brian Tierney, Foundations of the Conciliar Theory。"}],"relationItems":["← 前因：阿维尼翁教廷","→ 后果：天主教康斯坦茨会议","↔ 相关：波希米亚胡斯战争","→ 后果：欧洲宗教改革"],"relations":[{"text":"→ 后果：天主教康斯坦茨会议","id":"extra383"},{"text":"↔ 相关：波希米亚胡斯战争","id":"extra366"},{"text":"→ 后果：欧洲宗教改革","id":"extra301"}],"source":"history","id":"extra880"},{"title":"中世纪欧洲矿业","level":"C","type":"概念/思潮卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"约10—15世纪","place":"中欧、德意志地区、波希米亚、匈牙利、英格兰和阿尔卑斯地区","summary":"中世纪欧洲矿业以银、铜、铁和盐为核心，为货币经济、城市财政和王权收入提供关键资源。","fields":[{"label":"标题","value":"中世纪欧洲矿业"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"约10—15世纪"},{"label":"地点","value":"中欧、德意志地区、波希米亚、匈牙利、英格兰和阿尔卑斯地区"},{"label":"主要国家","value":"神圣罗马帝国；波希米亚；匈牙利；英格兰；意大利城市"},{"label":"一句话概括","value":"中世纪欧洲矿业以银、铜、铁和盐为核心，为货币经济、城市财政和王权收入提供关键资源。"},{"label":"核心主张/思路","value":"矿山不是单纯资源点，而是技术、劳工、特许权、铸币和地方治理交汇的经济制度。"},{"label":"提出者/代表人物（可选）","value":"矿山领主、城市商人、矿工共同体、铸币机构和王权财政官员。"},{"label":"它从何而来","value":"商业复兴、货币流通扩大、城市手工业需求和山地开采技术改进推动矿业扩张。"},{"label":"典型表现","value":"拉默尔斯贝格银矿、萨克森和波希米亚银矿、蒂罗尔矿业、盐矿和矿山法。"},{"label":"为什么重要","value":"它说明中世纪经济增长并不只靠农业，金属和盐支撑了贸易、战争财政和城市发展。"},{"label":"争议/局限","value":"矿业繁荣常伴随劳工风险、环境破坏、水患和地方权利冲突。"},{"label":"出处","value":"Encyclopaedia Britannica: mining；John Nef, Mining and Metallurgy in Medieval Civilization；Peter Spufford, Money and Its Use in Medieval Europe。"}],"relationItems":["← 前因：中世纪商业复兴","↔ 相关：戈斯拉尔与拉默尔斯贝格银矿","↔ 相关：富格尔家族银行网络","→ 后果：早期近代矿业资本"],"relations":[{"text":"← 前因：中世纪商业复兴","id":"extra884"},{"text":"↔ 相关：戈斯拉尔与拉默尔斯贝格银矿","id":"extra406"},{"text":"↔ 相关：富格尔家族银行网络","id":"extra322"}],"source":"history","id":"extra881"},{"title":"路易十四法国","level":"A","type":"概念/思潮卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1643—1715年","place":"法国及欧洲大陆","summary":"路易十四法国以王权集中、宫廷政治、常备军和扩张战争成为欧洲绝对主义国家的典型。","fields":[{"label":"标题","value":"路易十四法国"},{"label":"分级","value":"A"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1643—1715年"},{"label":"地点","value":"法国及欧洲大陆"},{"label":"主要国家","value":"法国；西班牙；神圣罗马帝国；荷兰共和国；英国；奥地利"},{"label":"一句话概括","value":"路易十四法国以王权集中、宫廷政治、常备军和扩张战争成为欧洲绝对主义国家的典型。"},{"label":"核心主张/思路","value":"君主通过宫廷、官僚、财政、军队和文化赞助集中权力，把贵族纳入凡尔赛秩序并追求法国霸权。"},{"label":"提出者/代表人物（可选）","value":"路易十四、柯尔贝尔、卢瓦、法军元帅和凡尔赛宫廷精英。"},{"label":"它从何而来","value":"法国宗教战争、投石党运动、王权财政扩张和欧洲王朝竞争推动中央集权。"},{"label":"典型表现","value":"凡尔赛宫廷、重商主义、废除南特敕令、遗产战争、荷兰战争、九年战争和西班牙王位继承战争。"},{"label":"为什么重要","value":"它解释近代欧洲为什么形成反法国霸权联盟，也影响德意志诸侯国军事财政改革和宫廷文化模仿。"},{"label":"争议/局限","value":"绝对主义并不等于君主无限权力，地方特权、财政困境和战争成本持续限制法国国家能力。"},{"label":"出处","value":"Encyclopaedia Britannica: Louis XIV；John Lynn, The Wars of Louis XIV；Peter Burke, The Fabrication of Louis XIV。"}],"relationItems":["← 前因：法国绝对主义国家建设","↔ 相关：西班牙王位继承战争《乌得勒支和约》","↔ 相关：欧洲均势政治","→ 后果：法国财政危机"],"relations":[{"text":"← 前因：法国绝对主义国家建设","id":"extra890"},{"text":"↔ 相关：西班牙王位继承战争《乌得勒支和约》","id":"extra449"},{"text":"↔ 相关：欧洲均势政治","id":"extra866"}],"source":"history","id":"extra882"},{"title":"欧洲启蒙专制","level":"B","type":"概念/思潮卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"18世纪中后期","place":"普鲁士、奥地利、俄国、西班牙和中欧国家","summary":"欧洲启蒙专制把启蒙改革语言与君主国家建设结合起来，推动法制、教育和行政改革。","fields":[{"label":"标题","value":"欧洲启蒙专制"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"18世纪中后期"},{"label":"地点","value":"普鲁士、奥地利、俄国、西班牙和中欧国家"},{"label":"主要国家","value":"普鲁士；奥地利；俄国；西班牙；葡萄牙"},{"label":"一句话概括","value":"欧洲启蒙专制把启蒙改革语言与君主国家建设结合起来，推动法制、教育和行政改革。"},{"label":"核心主张/思路","value":"君主不放弃专制权力，但以理性治理、公共利益、宗教宽容、法典化和经济改革证明统治正当性。"},{"label":"提出者/代表人物（可选）","value":"腓特烈二世、约瑟夫二世、叶卡捷琳娜二世、庞巴尔侯爵等。"},{"label":"它从何而来","value":"启蒙思想、财政军事国家竞争、官僚改革需求和宗教宽容议题共同推动改革型君主政治。"},{"label":"典型表现","value":"普鲁士法制和教育改革、约瑟夫二世宗教宽容与农奴改革、俄国法典委员会和行政改革。"},{"label":"为什么重要","value":"它说明18世纪国家改革并不只来自革命，也来自君主制内部的理性化和中央集权尝试。"},{"label":"争议/局限","value":"启蒙专制常自上而下推进，改革受贵族、教会和地方权利抵制，也可能强化国家控制。"},{"label":"出处","value":"Encyclopaedia Britannica: enlightened despotism；Derek Beales, Enlightenment and Reform in Eighteenth-Century Europe；T. C. W. Blanning, The Culture of Power。"}],"relationItems":["← 前因：欧洲启蒙运动","↔ 相关：普鲁士腓特烈大王","↔ 相关：约瑟夫二世改革","↔ 相关：俄国叶卡捷琳娜二世"],"relations":[{"text":"← 前因：欧洲启蒙运动","id":"extra874"},{"text":"↔ 相关：普鲁士腓特烈大王","id":"extra315"},{"text":"↔ 相关：约瑟夫二世改革","id":"extra318"},{"text":"↔ 相关：俄国叶卡捷琳娜二世","id":"extra892"}],"source":"history","id":"extra883"},{"title":"中世纪商业复兴","level":"B","type":"概念/思潮卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"约11—13世纪","place":"地中海、低地地区、莱茵河流域、香槟集市和波罗的海","summary":"中世纪商业复兴使长途贸易、城市、金融和行会重新扩张，推动欧洲从乡村封建秩序走向城市网络。","fields":[{"label":"标题","value":"中世纪商业复兴"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"约11—13世纪"},{"label":"地点","value":"地中海、低地地区、莱茵河流域、香槟集市和波罗的海"},{"label":"主要国家","value":"意大利城邦；法国；神圣罗马帝国；低地地区；英格兰"},{"label":"一句话概括","value":"中世纪商业复兴使长途贸易、城市、金融和行会重新扩张，推动欧洲从乡村封建秩序走向城市网络。"},{"label":"核心主张/思路","value":"人口增长、农业剩余、交通改善和货币流通让城市和商人重新成为欧洲社会的重要力量。"},{"label":"提出者/代表人物（可选）","value":"意大利商人、低地织造城市、香槟集市商人、汉萨商人和城市行会。"},{"label":"它从何而来","value":"农业扩张、相对和平、地中海贸易恢复、十字军联系和地方市场增长。"},{"label":"典型表现","value":"香槟集市、威尼斯和热那亚贸易、汉萨同盟、城市自治、汇票和商法发展。"},{"label":"为什么重要","value":"它为中世纪城市自治、大学、矿业、银行业和近代资本主义早期形态提供基础。"},{"label":"争议/局限","value":"商业复兴并未消除乡村等级和封建权力，城市繁荣也常依赖排外特权和不平等劳工关系。"},{"label":"出处","value":"Encyclopaedia Britannica: Middle Ages economy；Robert S. Lopez, The Commercial Revolution of the Middle Ages；Henri Pirenne, Medieval Cities。"}],"relationItems":["→ 后果：中世纪城市自治","→ 后果：中世纪大学","↔ 相关：中世纪汉萨同盟","→ 后果：中世纪欧洲矿业"],"relations":[{"text":"→ 后果：中世纪城市自治","id":"extra869"},{"text":"→ 后果：中世纪大学","id":"extra879"},{"text":"↔ 相关：中世纪汉萨同盟","id":"extra321"},{"text":"→ 后果：中世纪欧洲矿业","id":"extra881"}],"source":"history","id":"extra884"},{"title":"文艺复兴人文主义","level":"A","type":"概念/思潮卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"约14—16世纪","place":"意大利城市，后扩展到欧洲","summary":"文艺复兴人文主义重视古典文本、语言训练和人的现实生活，改变欧洲教育、政治和宗教批判方式。","fields":[{"label":"标题","value":"文艺复兴人文主义"},{"label":"分级","value":"A"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"约14—16世纪"},{"label":"地点","value":"意大利城市，后扩展到欧洲"},{"label":"主要国家","value":"意大利；法国；神圣罗马帝国；英格兰；荷兰"},{"label":"一句话概括","value":"文艺复兴人文主义重视古典文本、语言训练和人的现实生活，改变欧洲教育、政治和宗教批判方式。"},{"label":"核心主张/思路","value":"通过回到希腊罗马古典文本、修辞学、历史学和道德哲学，培养有判断力的公共人物和基督徒。"},{"label":"提出者/代表人物（可选）","value":"彼特拉克、薄伽丘、洛伦佐·瓦拉、皮科、伊拉斯谟等。"},{"label":"它从何而来","value":"意大利城市政治、古典手稿重发现、印刷术、宫廷赞助和大学教育共同推动人文学问兴起。"},{"label":"典型表现","value":"古典语文学、修辞教育、公民人文主义、文本校勘和北方基督教人文主义。"},{"label":"为什么重要","value":"它为宗教改革、现代教育、历史批判和政治思想提供工具，也影响德意志印刷文化和路德时代知识环境。"},{"label":"争议/局限","value":"人文主义不是现代世俗主义的简单前身，许多人文主义者仍处在基督教框架内。"},{"label":"出处","value":"Encyclopaedia Britannica: Renaissance humanism；Paul Oskar Kristeller, Renaissance Thought；Anthony Grafton, Humanists with Inky Fingers。"}],"relationItems":["← 前因：中世纪大学","↔ 相关：古腾堡活字印刷革命","→ 后果：伊拉斯谟与基督教人文主义","→ 后果：欧洲宗教改革"],"relations":[{"text":"← 前因：中世纪大学","id":"extra879"},{"text":"↔ 相关：古腾堡活字印刷革命","id":"extra299"},{"text":"→ 后果：伊拉斯谟与基督教人文主义","id":"extra886"},{"text":"→ 后果：欧洲宗教改革","id":"extra301"}],"source":"history","id":"extra885"},{"title":"伊拉斯谟与基督教人文主义","level":"B","type":"人物卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"伊拉斯谟约1466—1536年；基督教人文主义盛行于15—16世纪","place":"低地地区、法国、英格兰、瑞士和神圣罗马帝国","summary":"伊拉斯谟把人文主义语文学用于基督教改革，成为宗教改革前后欧洲知识批判的代表人物。","fields":[{"label":"标题","value":"伊拉斯谟与基督教人文主义"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"伊拉斯谟约1466—1536年；基督教人文主义盛行于15—16世纪"},{"label":"地点","value":"低地地区、法国、英格兰、瑞士和神圣罗马帝国"},{"label":"主要国家","value":"荷兰；法国；英格兰；瑞士；神圣罗马帝国"},{"label":"一句话概括","value":"伊拉斯谟把人文主义语文学用于基督教改革，成为宗教改革前后欧洲知识批判的代表人物。"},{"label":"生卒年/活跃年代","value":"约1466—1536年，活跃于1500年前后至宗教改革早期。"},{"label":"身份/职务","value":"荷兰人文主义者、神学家、古典学者、编辑和欧洲书信共和国代表。"},{"label":"关键贡献/作为","value":"编辑希腊文《新约》，批评教会迷信与形式主义，提倡回到早期基督教文本和道德更新。"},{"label":"核心主张/立场","value":"主张温和改革、教育和内在虔敬，反对粗暴教条争斗，也不认同路德的激进断裂。"},{"label":"为什么重要","value":"他说明宗教改革不是凭空出现，而与人文主义文本批判、印刷出版和教会改革愿望相连。"},{"label":"争议/评价","value":"天主教保守派认为他削弱教会权威，路德派又批评他不够坚定；他的温和立场在宗教战争时代处境艰难。"},{"label":"关联事件（可选）","value":"希腊文《新约》出版、路德宗教改革、欧洲人文主义网络。"},{"label":"出处","value":"Encyclopaedia Britannica: Erasmus；Johan Huizinga, Erasmus and the Age of Reformation；Diarmaid MacCulloch, Reformation。"}],"relationItems":["← 前因：文艺复兴人文主义","↔ 相关：古腾堡活字印刷革命","↔ 相关：马丁·路德发表《九十五条论纲》","→ 后果：欧洲宗教改革"],"relations":[{"text":"← 前因：文艺复兴人文主义","id":"extra885"},{"text":"↔ 相关：古腾堡活字印刷革命","id":"extra299"},{"text":"↔ 相关：马丁·路德发表《九十五条论纲》","id":"extra302"},{"text":"→ 后果：欧洲宗教改革","id":"extra301"}],"source":"history","id":"extra886"},{"title":"法国大革命","level":"S","type":"事件卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1789—1799年","place":"法国，影响扩展到欧洲和大西洋世界","summary":"法国大革命推翻旧制度王权，提出公民权利和人民主权，深刻改变近代欧洲政治语言。","fields":[{"label":"标题","value":"法国大革命"},{"label":"分级","value":"S"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1789—1799年"},{"label":"地点","value":"法国，影响扩展到欧洲和大西洋世界"},{"label":"主要国家","value":"法国；英国；奥地利；普鲁士；西班牙；荷兰；德意志诸邦"},{"label":"一句话概括","value":"法国大革命推翻旧制度王权，提出公民权利和人民主权，深刻改变近代欧洲政治语言。"},{"label":"参与者","value":"法国第三等级、国民议会、雅各宾派、吉伦特派、巴黎群众、路易十六、欧洲反法君主国和拿破仑等。"},{"label":"发生了什么","value":"财政危机迫使法国召开三级会议，第三等级转化为国民议会并宣布制宪。巴士底狱被攻占后，封建特权被废除，《人权和公民权宣言》公布。革命随后经历君主立宪、共和国、恐怖统治、督政府和拿破仑崛起，最终从国内制度革命走向欧洲战争。"},{"label":"为什么重要","value":"它把旧制度、等级特权和王权合法性推入危机，也让民族、公民、宪法和革命战争成为19世纪政治的核心词汇。"},{"label":"前因","value":"法国财政危机、启蒙思想、贵族特权、粮食危机和美国独立战争财政负担共同削弱旧制度。"},{"label":"后果","value":"法国革命战争和拿破仑战争爆发，欧洲保守复辟、自由主义和民族主义都围绕革命遗产展开。"},{"label":"出处","value":"Encyclopaedia Britannica: French Revolution；William Doyle, The Oxford History of the French Revolution；Lynn Hunt, Politics, Culture, and Class in the French Revolution。"}],"relationItems":["← 前因：欧洲启蒙运动","← 前因：美国独立战争","↔ 相关：法国大革命的欧洲冲击","→ 后果：法国革命战争","→ 后果：法国大革命中的《人权和公民权宣言》"],"relations":[{"text":"← 前因：欧洲启蒙运动","id":"extra874"},{"text":"← 前因：美国独立战争","id":"extra896"},{"text":"↔ 相关：法国大革命的欧洲冲击","id":"extra319"},{"text":"→ 后果：法国革命战争","id":"extra919"}],"source":"history","id":"extra887"},{"title":"拜占庭帝国","level":"A","type":"组织/机构卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"约330—1453年","place":"东地中海、巴尔干、小亚细亚、黑海和近东","summary":"拜占庭帝国延续东罗马传统，保存罗马法和希腊基督教文化，并长期影响东欧和地中海秩序。","fields":[{"label":"标题","value":"拜占庭帝国"},{"label":"分级","value":"A"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"约330—1453年"},{"label":"地点","value":"东地中海、巴尔干、小亚细亚、黑海和近东"},{"label":"主要国家","value":"拜占庭帝国；希腊；土耳其；保加利亚；塞尔维亚；意大利；俄罗斯"},{"label":"一句话概括","value":"拜占庭帝国延续东罗马传统，保存罗马法和希腊基督教文化，并长期影响东欧和地中海秩序。"},{"label":"性质/类型","value":"以君士坦丁堡为中心的东罗马帝国，兼具罗马帝国、希腊文化和东正教政治传统。"},{"label":"成立/解散时间","value":"330年君士坦丁堡奠基后逐渐成为东部帝国中心；1453年被奥斯曼帝国攻陷。"},{"label":"核心目标/宗旨","value":"维持皇帝权威、东正教秩序、税制军制和地中海—黑海贸易战略地位。"},{"label":"关键人物（可选）","value":"君士坦丁、查士丁尼一世、希拉克略、巴西尔二世、君士坦丁十一世。"},{"label":"关键行动/事件","value":"查士丁尼法典、圣像破坏运动、斯拉夫与保加利亚战争、第四次十字军攻陷君士坦丁堡、1453年灭亡。"},{"label":"为什么重要","value":"它是罗马法、东正教、斯拉夫文字文化和中世纪地中海政治的重要源头，也为奥斯曼崛起提供直接历史背景。"},{"label":"争议/局限","value":"“拜占庭”是后世称呼，帝国自身长期以罗马人自居。"},{"label":"出处","value":"Encyclopaedia Britannica: Byzantine Empire；Judith Herrin, Byzantium；John Haldon, The Byzantine Wars。"}],"relationItems":["← 前因：罗马帝国","↔ 相关：查理曼加冕为罗马皇帝","↔ 相关：第一次十字军","→ 后果：奥斯曼帝国扩张"],"relations":[{"text":"← 前因：罗马帝国","id":"extra871"},{"text":"↔ 相关：查理曼加冕为罗马皇帝","id":"extra343"},{"text":"↔ 相关：第一次十字军","id":"extra877"}],"source":"history","id":"extra888"},{"title":"科学革命","level":"A","type":"概念/思潮卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"约16—17世纪","place":"欧洲知识网络，尤以意大利、荷兰、英格兰、法国和德意志地区为中心","summary":"科学革命通过数学化自然、实验方法和新宇宙观，改变欧洲知识权威并为启蒙运动奠基。","fields":[{"label":"标题","value":"科学革命"},{"label":"分级","value":"A"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"约16—17世纪"},{"label":"地点","value":"欧洲知识网络，尤以意大利、荷兰、英格兰、法国和德意志地区为中心"},{"label":"主要国家","value":"意大利；英国；法国；荷兰；神圣罗马帝国；波兰"},{"label":"一句话概括","value":"科学革命通过数学化自然、实验方法和新宇宙观，改变欧洲知识权威并为启蒙运动奠基。"},{"label":"核心主张/思路","value":"自然可以通过观察、实验、数学和可重复推理来理解，而不只依赖古典权威和经院注释。"},{"label":"提出者/代表人物（可选）","value":"哥白尼、开普勒、伽利略、笛卡尔、牛顿、波义耳、培根等。"},{"label":"它从何而来","value":"文艺复兴人文主义、印刷术、航海和测量需求、大学与宫廷赞助共同推动知识方法变化。"},{"label":"典型表现","value":"日心说、开普勒行星运动定律、伽利略望远镜观测、牛顿力学、皇家学会和科学院。"},{"label":"为什么重要","value":"它重塑自然知识标准，推动技术、军事、航海和工业化前的知识积累，也为欧洲启蒙运动提供方法论基础。"},{"label":"争议/局限","value":"“科学革命”不是一次单一事件，也不应掩盖非欧洲知识、工匠实践和长期渐变过程。"},{"label":"出处","value":"Encyclopaedia Britannica: Scientific Revolution；Steven Shapin, The Scientific Revolution；Peter Dear, Revolutionizing the Sciences。"}],"relationItems":["← 前因：文艺复兴人文主义","↔ 相关：中世纪大学","→ 后果：欧洲启蒙运动","→ 后果：十九世纪物理学"],"relations":[{"text":"← 前因：文艺复兴人文主义","id":"extra885"},{"text":"↔ 相关：中世纪大学","id":"extra879"},{"text":"→ 后果：欧洲启蒙运动","id":"extra874"}],"source":"history","id":"extra889"},{"title":"法国绝对主义国家建设","level":"B","type":"概念/思潮卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"约16世纪末—18世纪","place":"法国及欧洲王朝外交体系","summary":"法国绝对主义国家建设通过王权、官僚、财政和常备军扩张，形成近代欧洲强国模式之一。","fields":[{"label":"标题","value":"法国绝对主义国家建设"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"约16世纪末—18世纪"},{"label":"地点","value":"法国及欧洲王朝外交体系"},{"label":"主要国家","value":"法国；西班牙；神圣罗马帝国；英国；荷兰共和国"},{"label":"一句话概括","value":"法国绝对主义国家建设通过王权、官僚、财政和常备军扩张，形成近代欧洲强国模式之一。"},{"label":"核心主张/思路","value":"君主应集中立法、司法、税收和军事权力，通过官僚和宫廷控制地方、贵族和宗教冲突。"},{"label":"提出者/代表人物（可选）","value":"亨利四世、黎塞留、马扎然、路易十四、柯尔贝尔等。"},{"label":"它从何而来","value":"法国宗教战争后王权需要恢复秩序，欧洲王朝竞争和财政军事压力推动中央集权。"},{"label":"典型表现","value":"王室官僚扩张、总督与督办官制度、常备军、凡尔赛宫廷、重商主义和对地方特权的整合。"},{"label":"为什么重要","value":"它解释路易十四法国为什么能成为欧洲霸权竞争中心，也为法国大革命前的旧制度矛盾提供背景。"},{"label":"争议/局限","value":"所谓“绝对主义”并不等于无限权力，地方特权、财政包税、贵族和法院仍限制王权。"},{"label":"出处","value":"Encyclopaedia Britannica: absolutism；William Beik, Absolutism and Society in Seventeenth-Century France；John Lynn, The Wars of Louis XIV。"}],"relationItems":["← 前因：法国宗教战争","↔ 相关：黎塞留反哈布斯堡政策","→ 后果：路易十四法国","→ 后果：法国财政危机"],"relations":[{"text":"← 前因：法国宗教战争","id":"extra900"},{"text":"↔ 相关：黎塞留反哈布斯堡政策","id":"extra903"},{"text":"→ 后果：路易十四法国","id":"extra882"}],"source":"history","id":"extra890"},{"title":"俄国彼得大帝改革","level":"A","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"约1682—1725年，改革高峰在彼得一世亲政后","place":"俄国、波罗的海地区和新都圣彼得堡","summary":"彼得大帝改革把俄国推向欧洲强国体系，通过军政、技术和社会改革增强国家动员能力。","fields":[{"label":"标题","value":"俄国彼得大帝改革"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"约1682—1725年，改革高峰在彼得一世亲政后"},{"label":"地点","value":"俄国、波罗的海地区和新都圣彼得堡"},{"label":"主要国家","value":"俄国；瑞典；波兰立陶宛联邦；奥斯曼帝国；普鲁士"},{"label":"一句话概括","value":"彼得大帝改革把俄国推向欧洲强国体系，通过军政、技术和社会改革增强国家动员能力。"},{"label":"参与者","value":"彼得一世、俄国贵族、军队、官僚、教会、外国技术人员和波罗的海战争对手。"},{"label":"发生了什么","value":"彼得一世重组军队和海军，改革官僚制度，削弱教会自主，推行等级表，建设圣彼得堡，并通过北方大战从瑞典手中取得波罗的海出海口。改革以强制动员和贵族服役为基础，把俄国更深纳入欧洲外交与战争体系。"},{"label":"为什么重要","value":"它使俄国成为18世纪欧洲均势的重要大国，也改变东欧、波罗的海和普鲁士崛起的外部环境。"},{"label":"前因","value":"俄国扩张、军事技术落差、对出海口的需求和欧洲财政军事国家竞争。"},{"label":"后果","value":"俄国帝国地位上升，圣彼得堡成为新政治中心，贵族国家服务体系强化。"},{"label":"出处","value":"Encyclopaedia Britannica: Peter the Great；Lindsey Hughes, Russia in the Age of Peter the Great；Robert K. Massie, Peter the Great。"}],"relationItems":["← 前因：早期近代军事革命","↔ 相关：普鲁士王国成立","→ 后果：俄国叶卡捷琳娜二世","↔ 相关：欧洲均势政治"],"relations":[{"text":"← 前因：早期近代军事革命","id":"extra876"},{"text":"↔ 相关：普鲁士王国成立","id":"extra312"},{"text":"→ 后果：俄国叶卡捷琳娜二世","id":"extra892"},{"text":"↔ 相关：欧洲均势政治","id":"extra866"}],"source":"history","id":"extra891"},{"title":"俄国叶卡捷琳娜二世","level":"B","type":"人物卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1729—1796年；1762—1796年在位","place":"俄国、波兰、黑海和欧洲外交体系","summary":"叶卡捷琳娜二世推动俄国扩张和启蒙式改革，参与瓜分波兰并强化贵族帝国秩序。","fields":[{"label":"标题","value":"俄国叶卡捷琳娜二世"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1729—1796年；1762—1796年在位"},{"label":"地点","value":"俄国、波兰、黑海和欧洲外交体系"},{"label":"主要国家","value":"俄国；波兰立陶宛联邦；奥斯曼帝国；普鲁士；奥地利"},{"label":"一句话概括","value":"叶卡捷琳娜二世推动俄国扩张和启蒙式改革，参与瓜分波兰并强化贵族帝国秩序。"},{"label":"生卒年/活跃年代","value":"1729—1796年，1762年政变后成为俄国女皇。"},{"label":"身份/职务","value":"俄国女皇，18世纪启蒙专制代表人物之一。"},{"label":"关键贡献/作为","value":"扩张黑海和东欧势力，参与三次波兰瓜分，推动行政改革、贵族特权确认和有限启蒙改革。"},{"label":"核心主张/立场","value":"以启蒙语言包装君主权威和国家改革，同时依赖贵族、农奴制和帝国扩张维持统治。"},{"label":"为什么重要","value":"她使俄国成为欧洲均势和东欧重组的核心力量，直接影响普鲁士、奥地利和波兰命运。"},{"label":"争议/评价","value":"她的改革和文化赞助常被称为启蒙专制，但农奴制强化、波兰瓜分和镇压普加乔夫起义显示其帝国统治的暴力面。"},{"label":"关联事件（可选）","value":"三次波兰瓜分、俄土战争、欧洲启蒙专制。"},{"label":"出处","value":"Encyclopaedia Britannica: Catherine the Great；Isabel de Madariaga, Russia in the Age of Catherine the Great；Simon Dixon, Catherine the Great。"}],"relationItems":["← 前因：俄国彼得大帝改革","↔ 相关：欧洲启蒙专制","↔ 相关：三次波兰瓜分","↔ 相关：玛丽亚·特蕾莎"],"relations":[{"text":"← 前因：俄国彼得大帝改革","id":"extra891"},{"text":"↔ 相关：欧洲启蒙专制","id":"extra883"},{"text":"↔ 相关：三次波兰瓜分","id":"extra341"},{"text":"↔ 相关：玛丽亚·特蕾莎","id":"extra314"}],"source":"history","id":"extra892"},{"title":"十字军运动","level":"A","type":"概念/思潮卡","tags":["战争与外交","文化与思想"],"mainTag":"战争与外交","subTag":"文化与思想","timeText":"约11—13世纪为高峰，后续延续至中世纪晚期","place":"东地中海、伊比利亚、波罗的海、巴尔干和欧洲内部异端地区","summary":"十字军运动把宗教赎罪、骑士战争和教皇权威结合起来，扩展为中世纪欧洲对外与内部战争模式。","fields":[{"label":"标题","value":"十字军运动"},{"label":"分级","value":"A"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"约11—13世纪为高峰，后续延续至中世纪晚期"},{"label":"地点","value":"东地中海、伊比利亚、波罗的海、巴尔干和欧洲内部异端地区"},{"label":"主要国家","value":"教皇国；法国；神圣罗马帝国；英格兰；拜占庭帝国；耶路撒冷王国；穆斯林诸政权"},{"label":"一句话概括","value":"十字军运动把宗教赎罪、骑士战争和教皇权威结合起来，扩展为中世纪欧洲对外与内部战争模式。"},{"label":"核心主张/思路","value":"以教皇授权和宗教赎罪为基础，把军事行动定义为神圣战争，动员骑士、民众、财政和政治联盟。"},{"label":"提出者/代表人物（可选）","value":"教皇乌尔班二世、十字军贵族、军事修会、传教士和王权。"},{"label":"它从何而来","value":"教皇改革、朝圣传统、拜占庭求援、骑士暴力和地中海贸易政治共同推动。"},{"label":"典型表现","value":"第一次十字军、耶路撒冷王国、条顿骑士团、伊比利亚再征服和阿尔比派十字军。"},{"label":"为什么重要","value":"它影响地中海关系、军事修会、东欧殖民、反异端战争和中世纪基督教身份建构。"},{"label":"争议/局限","value":"十字军并非单一方向的“东西方冲突”，其目标、参与者和地区变化很大，也常攻击欧洲内部群体。"},{"label":"出处","value":"Encyclopaedia Britannica: Crusades；Jonathan Riley-Smith, The Crusades；Christopher Tyerman, God's War。"}],"relationItems":["← 前因：中世纪教会格里高利改革","↔ 相关：第一次十字军","↔ 相关：中世纪条顿骑士团","→ 后果：第五次和第六次十字军"],"relations":[{"text":"← 前因：中世纪教会格里高利改革","id":"extra350"},{"text":"↔ 相关：第一次十字军","id":"extra877"},{"text":"↔ 相关：中世纪条顿骑士团","id":"extra362"}],"source":"history","id":"extra893"},{"title":"英国内战","level":"A","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1642—1651年","place":"英格兰、苏格兰、爱尔兰","summary":"英国内战围绕王权、议会、宗教和军队控制爆发，最终处决国王并建立共和国实验。","fields":[{"label":"标题","value":"英国内战"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1642—1651年"},{"label":"地点","value":"英格兰、苏格兰、爱尔兰"},{"label":"主要国家","value":"英格兰；苏格兰；爱尔兰；荷兰共和国；法国"},{"label":"一句话概括","value":"英国内战围绕王权、议会、宗教和军队控制爆发，最终处决国王并建立共和国实验。"},{"label":"参与者","value":"查理一世、英格兰议会、新模范军、奥利弗·克伦威尔、保王党、清教徒、苏格兰盟约派和爱尔兰力量。"},{"label":"发生了什么","value":"国王查理一世与议会因税收、宗教政策和军队控制长期冲突。1642年战争爆发，议会军在新模范军支持下击败保王党。1649年查理一世被审判并处决，英格兰进入共和国和护国公时期。1651年保王党最后失败。"},{"label":"为什么重要","value":"它让“君主是否受法律和议会约束”成为近代政治核心问题，也影响欧洲宪政和革命传统。"},{"label":"前因","value":"斯图亚特王权财政困境、宗教冲突、苏格兰战争和议会权利争执。"},{"label":"后果","value":"共和国和克伦威尔护国公政体建立，1660年王政复辟后宪政冲突仍未结束，最终通向光荣革命。"},{"label":"出处","value":"Encyclopaedia Britannica: English Civil Wars；Conrad Russell, The Causes of the English Civil War；Mark Kishlansky, A Monarchy Transformed。"}],"relationItems":["← 前因：欧洲宗教战争","↔ 相关：三十年战争","→ 后果：英格兰平等派纲领","→ 后果：光荣革命"],"relations":[{"text":"↔ 相关：三十年战争","id":"extra307"}],"source":"history","id":"extra894"},{"title":"英格兰《大宪章》","level":"A","type":"制度/文本卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1215年6月15日首次签署","place":"英格兰兰尼米德","summary":"《大宪章》限制英王任意权力，后来被重新解释为法治、议会权利和宪政传统的重要象征。","fields":[{"label":"标题","value":"英格兰《大宪章》"},{"label":"分级","value":"A"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1215年6月15日首次签署"},{"label":"地点","value":"英格兰兰尼米德"},{"label":"主要国家","value":"英格兰；法国；教皇国"},{"label":"一句话概括","value":"《大宪章》限制英王任意权力，后来被重新解释为法治、议会权利和宪政传统的重要象征。"},{"label":"制定方/签署方","value":"英格兰国王约翰与反叛贵族，教会和伦敦城市力量也参与压力形成。"},{"label":"主要内容","value":"限制国王任意征税和没收财产，保护部分自由人司法程序，确认教会自由和贵族特权，并设立监督国王执行的机制。"},{"label":"它试图解决什么问题","value":"约翰王军事失败、财政压榨和任意司法引发贵族反抗，需要用书面协议约束王权。"},{"label":"为什么重要","value":"它在当时主要保护贵族和自由人权利，但后来成为英格兰法治、有限政府和宪政记忆的核心文本。"},{"label":"争议/局限","value":"1215年文本很快被废止并多次重发，其现代自由象征意义多来自后世政治解释。"},{"label":"造成的影响","value":"《大宪章》影响英格兰议会传统、普通法想象和后来的英美宪政话语。"},{"label":"出处","value":"The National Archives: Magna Carta；Encyclopaedia Britannica: Magna Carta；J. C. Holt, Magna Carta。"}],"relationItems":["← 前因：中世纪欧洲布汶战役","↔ 相关：英国内战","→ 后果：光荣革命","↔ 相关：欧洲等级会议"],"relations":[{"text":"← 前因：中世纪欧洲布汶战役","id":"extra359"},{"text":"↔ 相关：英国内战","id":"extra894"}],"source":"history","id":"extra895"},{"title":"美国独立战争","level":"A","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1775—1783年","place":"北美十三殖民地、大西洋和欧洲外交空间","summary":"美国独立战争使十三殖民地脱离英国，并把启蒙政治、帝国财政和大西洋革命连接起来。","fields":[{"label":"标题","value":"美国独立战争"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1775—1783年"},{"label":"地点","value":"北美十三殖民地、大西洋和欧洲外交空间"},{"label":"主要国家","value":"美国；英国；法国；西班牙；荷兰共和国；德意志诸邦"},{"label":"一句话概括","value":"美国独立战争使十三殖民地脱离英国，并把启蒙政治、帝国财政和大西洋革命连接起来。"},{"label":"参与者","value":"北美殖民者、大陆会议、大陆军、英国政府和军队、法国、西班牙、荷兰及德意志雇佣兵。"},{"label":"发生了什么","value":"英国试图在七年战争后加强殖民税收和控制，引发殖民地抗议。1775年战争爆发，1776年《独立宣言》宣布十三殖民地独立。法国参战改变力量对比，1781年约克镇英军投降，1783年《巴黎条约》承认美国独立。"},{"label":"为什么重要","value":"它建立近代第一个大型共和国实验，也加重法国财政危机并影响法国大革命。"},{"label":"前因","value":"七年战争、英国帝国财政压力、殖民地自治传统和启蒙权利语言。"},{"label":"后果","value":"美国建国，法国财政负担加重，大西洋世界革命政治扩散。"},{"label":"出处","value":"Encyclopaedia Britannica: American Revolution；Gordon S. Wood, The Radicalism of the American Revolution；Alan Taylor, American Revolutions。"}],"relationItems":["← 前因：法国印第安战争","↔ 相关：欧洲启蒙运动","→ 后果：法国大革命","↔ 相关：三次波兰瓜分"],"relations":[{"text":"← 前因：法国印第安战争","id":"extra907"},{"text":"↔ 相关：欧洲启蒙运动","id":"extra874"},{"text":"→ 后果：法国大革命","id":"extra887"},{"text":"↔ 相关：三次波兰瓜分","id":"extra341"}],"source":"history","id":"extra896"},{"title":"加洛林帝国","level":"A","type":"组织/机构卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"约751—888年，查理曼帝国高峰为768—814年","place":"西欧和中欧，覆盖今法国、德国西部、低地、意大利北部等地区","summary":"加洛林帝国在查理曼时期整合西欧，成为后来法德意政治传统和“帝国”观念的重要源头。","fields":[{"label":"标题","value":"加洛林帝国"},{"label":"分级","value":"A"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"约751—888年，查理曼帝国高峰为768—814年"},{"label":"地点","value":"西欧和中欧，覆盖今法国、德国西部、低地、意大利北部等地区"},{"label":"主要国家","value":"法兰克王国；法国；德国；意大利；比利时；荷兰；瑞士"},{"label":"一句话概括","value":"加洛林帝国在查理曼时期整合西欧，成为后来法德意政治传统和“帝国”观念的重要源头。"},{"label":"性质/类型","value":"由加洛林王朝统治的法兰克扩张帝国。"},{"label":"成立/解散时间","value":"751年丕平取代墨洛温王朝；800年查理曼加冕为皇帝；843年《凡尔登条约》后分裂加深。"},{"label":"核心目标/宗旨","value":"通过军事征服、教会合作、伯爵治理和文化改革维持广域王权。"},{"label":"关键人物（可选）","value":"矮子丕平、查理曼、虔诚者路易、洛泰尔一世、日耳曼人路易、秃头查理。"},{"label":"关键行动/事件","value":"查理曼加冕、萨克森战争、加洛林文艺复兴、《凡尔登条约》和《梅尔森条约》。"},{"label":"为什么重要","value":"它把罗马帝国继承、基督教王权和法兰克政治结合起来，是神圣罗马帝国和法德分化的重要前史。"},{"label":"争议/局限","value":"加洛林帝国依赖个人王权、军事贵族和教会网络，制度整合程度有限，继承分割导致迅速分裂。"},{"label":"出处","value":"Encyclopaedia Britannica: Carolingian dynasty；Rosamond McKitterick, Charlemagne；Janet Nelson, King and Emperor。"}],"relationItems":["← 前因：法兰克王国","↔ 相关：查理曼加冕为罗马皇帝","→ 后果：加洛林帝国《凡尔登条约》","→ 后果：中法兰克王国"],"relations":[{"text":"← 前因：法兰克王国","id":"extra394"},{"text":"↔ 相关：查理曼加冕为罗马皇帝","id":"extra343"},{"text":"→ 后果：加洛林帝国《凡尔登条约》","id":"extra344"},{"text":"→ 后果：中法兰克王国","id":"extra921"}],"source":"history","id":"extra897"},{"title":"英王钦定版圣经","level":"B","type":"作品卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1604年启动翻译；1611年出版","place":"英格兰","summary":"英王钦定版圣经以庄重英语译文统一教会阅读，深刻影响英语文学、宗教和政治文化。","fields":[{"label":"标题","value":"英王钦定版圣经"},{"label":"分级","value":"B"},{"label":"类型","value":"作品卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1604年启动翻译；1611年出版"},{"label":"地点","value":"英格兰"},{"label":"主要国家","value":"英格兰；苏格兰"},{"label":"一句话概括","value":"英王钦定版圣经以庄重英语译文统一教会阅读，深刻影响英语文学、宗教和政治文化。"},{"label":"作者/创作者","value":"由詹姆斯一世授权，多组英格兰学者共同翻译。"},{"label":"媒介/体裁","value":"圣经英语译本。"},{"label":"主要内容/讲了什么","value":"将旧约、新约和次经等文本译为早期现代英语，供英格兰教会礼拜和阅读使用。"},{"label":"核心主张/表达","value":"以权威译本稳定宗教阅读秩序，同时在语言上追求庄重、清晰和公共可诵读性。"},{"label":"它出现在什么背景下","value":"宗教改革后英格兰教会内部仍有清教徒、主教制支持者和王权教会政治冲突，需要一个具有官方权威的译本。"},{"label":"为什么重要","value":"它成为英语世界最有影响力的文本之一，也说明宗教改革时代的翻译、印刷和国家教会建设如何相互连接。"},{"label":"接受与影响","value":"长期用于英语教会礼拜和家庭阅读，对英语文学、修辞和政治语言影响极大。"},{"label":"争议/局限","value":"它不是第一部英语圣经，也带有17世纪语言和教会政治背景，现代学术译本在文本依据上已有更新。"},{"label":"出处","value":"British Library: King James Bible；Encyclopaedia Britannica: King James Version；Alister McGrath, In the Beginning。"}],"relationItems":["← 前因：欧洲宗教改革","↔ 相关：路德德语圣经翻译","↔ 相关：英国内战"],"relations":[{"text":"← 前因：欧洲宗教改革","id":"extra301"},{"text":"↔ 相关：路德德语圣经翻译","id":"extra304"},{"text":"↔ 相关：英国内战","id":"extra894"}],"source":"history","id":"extra898"},{"title":"法国南特敕令","level":"B","type":"制度/文本卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1598年","place":"法国南特及法国王国","summary":"法国南特敕令给予胡格诺派有限宗教和政治保障，暂时结束法国宗教战争。","fields":[{"label":"标题","value":"法国南特敕令"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1598年"},{"label":"地点","value":"法国南特及法国王国"},{"label":"主要国家","value":"法国"},{"label":"一句话概括","value":"法国南特敕令给予胡格诺派有限宗教和政治保障，暂时结束法国宗教战争。"},{"label":"制定方/签署方","value":"法国国王亨利四世。"},{"label":"主要内容","value":"承认天主教为法国主要宗教，同时给予胡格诺派在部分地区公开礼拜、担任公职、司法保障和若干安全据点权利。"},{"label":"它试图解决什么问题","value":"法国宗教战争长期消耗王国，王权需要在天主教多数和新教少数之间重建秩序。"},{"label":"为什么重要","value":"它是近代早期宗教宽容政治的重要尝试，也为法国王权恢复和国家整合提供条件。"},{"label":"争议/局限","value":"敕令并非现代宗教平等，而是以王权授权维持有限宽容；1685年被路易十四废除。"},{"label":"造成的影响","value":"法国国内宗教冲突暂时缓和，胡格诺派保留部分权利，但其政治军事特权后来逐渐被削弱。"},{"label":"出处","value":"Encyclopaedia Britannica: Edict of Nantes；Mack P. Holt, The French Wars of Religion；Barbara Diefendorf, Beneath the Cross。"}],"relationItems":["← 前因：法国宗教战争","↔ 相关：宗教改革《奥格斯堡和约》","→ 后果：法国废除南特敕令（1685）"],"relations":[{"text":"← 前因：法国宗教战争","id":"extra900"},{"text":"↔ 相关：宗教改革《奥格斯堡和约》","id":"extra305"},{"text":"→ 后果：法国废除南特敕令（1685）","id":"extra902"}],"source":"history","id":"extra899"},{"title":"法国宗教战争","level":"B","type":"事件卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1562—1598年","place":"法国","summary":"法国宗教战争是天主教与胡格诺派冲突和王权危机交织的内战，最终以南特敕令暂时收束。","fields":[{"label":"标题","value":"法国宗教战争"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1562—1598年"},{"label":"地点","value":"法国"},{"label":"主要国家","value":"法国；西班牙；英格兰；教皇国"},{"label":"一句话概括","value":"法国宗教战争是天主教与胡格诺派冲突和王权危机交织的内战，最终以南特敕令暂时收束。"},{"label":"参与者","value":"法国王室、吉斯家族、波旁家族、胡格诺派贵族与城市、天主教联盟和外国支持者。"},{"label":"发生了什么","value":"新教传播和贵族派系斗争使法国陷入多轮内战。战争中出现瓦西屠杀、圣巴托罗缪大屠杀和天主教联盟政治。亨利四世改宗天主教并取得王位后，1598年发布南特敕令，给予胡格诺派有限保护。"},{"label":"为什么重要","value":"它说明宗教改革会在王权、贵族派系和国际政治中转化为长期内战，也推动法国绝对主义国家建设。"},{"label":"前因","value":"加尔文主义在法国传播、王权弱化、贵族派系竞争和欧洲宗教战争环境。"},{"label":"后果","value":"南特敕令确立有限宽容，法国王权在战后重建中更强调中央秩序。"},{"label":"出处","value":"Encyclopaedia Britannica: Wars of Religion；Mack P. Holt, The French Wars of Religion；Natalie Zemon Davis, Society and Culture in Early Modern France。"}],"relationItems":["← 前因：欧洲宗教改革","↔ 相关：法国胡格诺派政治组织","→ 后果：法国南特敕令","→ 后果：法国绝对主义国家建设"],"relations":[{"text":"← 前因：欧洲宗教改革","id":"extra301"},{"text":"→ 后果：法国南特敕令","id":"extra899"},{"text":"→ 后果：法国绝对主义国家建设","id":"extra890"}],"source":"history","id":"extra900"},{"title":"查理五世的哈布斯堡帝国","level":"B","type":"人物卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"查理五世1500—1558年；1519—1556年任神圣罗马皇帝","place":"神圣罗马帝国、西班牙、尼德兰、意大利、美洲殖民地和地中海","summary":"查理五世统治横跨欧洲和美洲的哈布斯堡复合帝国，面对宗教改革、法国和奥斯曼多重挑战。","fields":[{"label":"标题","value":"查理五世的哈布斯堡帝国"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"查理五世1500—1558年；1519—1556年任神圣罗马皇帝"},{"label":"地点","value":"神圣罗马帝国、西班牙、尼德兰、意大利、美洲殖民地和地中海"},{"label":"主要国家","value":"神圣罗马帝国；西班牙；奥地利；荷兰；意大利诸邦；法国；奥斯曼帝国"},{"label":"一句话概括","value":"查理五世统治横跨欧洲和美洲的哈布斯堡复合帝国，面对宗教改革、法国和奥斯曼多重挑战。"},{"label":"生卒年/活跃年代","value":"1500—1558年，1516年成为西班牙国王，1519年当选神圣罗马皇帝。"},{"label":"身份/职务","value":"神圣罗马皇帝、西班牙国王、哈布斯堡王朝君主。"},{"label":"关键贡献/作为","value":"整合西班牙、尼德兰、奥地利和帝国头衔，主持沃姆斯帝国议会，长期与法国、奥斯曼和新教诸侯斗争。"},{"label":"核心主张/立场","value":"维护天主教和哈布斯堡王朝权威，但不得不在帝国诸侯权利和欧洲多线战争中妥协。"},{"label":"为什么重要","value":"他的复合帝国说明近代早期欧洲不是民族国家体系，而是王朝继承、帝国权利和宗教冲突交织的政治世界。"},{"label":"争议/评价","value":"查理五世权力庞大但整合有限，财政和地理跨度使其帝国难以集中治理。"},{"label":"关联事件（可选）","value":"沃姆斯帝国议会、施马尔卡尔登战争、《奥格斯堡和约》。"},{"label":"出处","value":"Encyclopaedia Britannica: Charles V；Geoffrey Parker, Emperor；Martyn Rady, The Habsburgs。"}],"relationItems":["← 前因：哈布斯堡王朝婚姻政治","↔ 相关：沃姆斯帝国议会","↔ 相关：法国反哈布斯堡外交","→ 后果：宗教改革《奥格斯堡和约》"],"relations":[{"text":"↔ 相关：沃姆斯帝国议会","id":"extra303"},{"text":"→ 后果：宗教改革《奥格斯堡和约》","id":"extra305"}],"source":"history","id":"extra901"},{"title":"法国废除南特敕令（1685）","level":"B","type":"事件卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1685年","place":"法国","summary":"路易十四废除南特敕令，取消胡格诺派合法地位，引发宗教难民外流和欧洲反法情绪。","fields":[{"label":"标题","value":"法国废除南特敕令（1685）"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1685年"},{"label":"地点","value":"法国"},{"label":"主要国家","value":"法国；勃兰登堡-普鲁士；荷兰共和国；英格兰；瑞士"},{"label":"一句话概括","value":"路易十四废除南特敕令，取消胡格诺派合法地位，引发宗教难民外流和欧洲反法情绪。"},{"label":"参与者","value":"路易十四、法国天主教会、胡格诺派社群、法国军政官员和接收难民的新教国家。"},{"label":"发生了什么","value":"路易十四通过《枫丹白露敕令》撤销1598年南特敕令，关闭新教教堂和学校，禁止公开新教礼拜，并通过龙骑兵驻扎等方式强迫改宗。大量胡格诺派逃往荷兰、英格兰、瑞士和勃兰登堡-普鲁士等地。"},{"label":"为什么重要","value":"它显示路易十四绝对主义与宗教统一政策的强制性，也为普鲁士《波茨坦敕令》吸纳新教难民提供背景。"},{"label":"前因","value":"法国绝对主义国家建设、天主教统一理想和对胡格诺派政治独立性的长期压制。"},{"label":"后果","value":"胡格诺派技术和商业人口外流，新教欧洲反法联盟情绪增强。"},{"label":"出处","value":"Encyclopaedia Britannica: Revocation of the Edict of Nantes；Mack P. Holt, The French Wars of Religion；Philip Benedict, The Huguenot Population of France。"}],"relationItems":["← 前因：法国南特敕令","↔ 相关：路易十四法国","→ 后果：勃兰登堡-普鲁士《波茨坦敕令》","↔ 相关：欧洲宗教难民"],"relations":[{"text":"← 前因：法国南特敕令","id":"extra899"},{"text":"↔ 相关：路易十四法国","id":"extra882"},{"text":"→ 后果：勃兰登堡-普鲁士《波茨坦敕令》","id":"extra434"}],"source":"history","id":"extra902"},{"title":"黎塞留反哈布斯堡政策","level":"B","type":"概念/思潮卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1624—1642年黎塞留主政时期最突出","place":"法国、神圣罗马帝国、意大利和欧洲外交体系","summary":"黎塞留反哈布斯堡政策以国家利益压过宗教同盟，推动法国介入三十年战争并重塑欧洲均势。","fields":[{"label":"标题","value":"黎塞留反哈布斯堡政策"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1624—1642年黎塞留主政时期最突出"},{"label":"地点","value":"法国、神圣罗马帝国、意大利和欧洲外交体系"},{"label":"主要国家","value":"法国；西班牙；神圣罗马帝国；瑞典；荷兰共和国"},{"label":"一句话概括","value":"黎塞留反哈布斯堡政策以国家利益压过宗教同盟，推动法国介入三十年战争并重塑欧洲均势。"},{"label":"核心主张/思路","value":"法国虽为天主教国家，但应阻止西班牙和奥地利哈布斯堡包围法国，必要时支持新教盟友。"},{"label":"提出者/代表人物（可选）","value":"红衣主教黎塞留、路易十三、法国外交官和军事顾问。"},{"label":"它从何而来","value":"法国被西班牙、尼德兰、意大利和帝国方向的哈布斯堡势力包围，王权安全与欧洲宗教阵营发生冲突。"},{"label":"典型表现","value":"资助瑞典和荷兰，支持反哈布斯堡力量，1635年法国直接对西班牙宣战并介入三十年战争。"},{"label":"为什么重要","value":"它说明近代欧洲外交开始更公开地以国家利益和均势逻辑运作，而不完全受宗教阵营支配。"},{"label":"争议/局限","value":"政策增强法国地位，也加重战争破坏和财政压力。"},{"label":"出处","value":"Encyclopaedia Britannica: Cardinal de Richelieu；Joseph Bergin, Cardinal Richelieu；Geoffrey Parker, The Thirty Years' War。"}],"relationItems":["← 前因：查理五世的哈布斯堡帝国","↔ 相关：法国直接介入三十年战争","↔ 相关：瑞典介入三十年战争","→ 后果：威斯特伐利亚和约"],"relations":[{"text":"← 前因：查理五世的哈布斯堡帝国","id":"extra901"},{"text":"↔ 相关：法国直接介入三十年战争","id":"extra440"},{"text":"↔ 相关：瑞典介入三十年战争","id":"extra334"},{"text":"→ 后果：威斯特伐利亚和约","id":"extra308"}],"source":"history","id":"extra903"},{"title":"神圣罗马帝国的诸侯主权化","level":"B","type":"概念/思潮卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"16—18世纪，1648年后尤为明显","place":"神圣罗马帝国","summary":"神圣罗马帝国的诸侯主权化使帝国内部邦国获得更强外交、军事和宗教自主权，削弱皇帝集中权力。","fields":[{"label":"标题","value":"神圣罗马帝国的诸侯主权化"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"16—18世纪，1648年后尤为明显"},{"label":"地点","value":"神圣罗马帝国"},{"label":"主要国家","value":"神圣罗马帝国；奥地利；普鲁士；巴伐利亚；萨克森；法国；瑞典"},{"label":"一句话概括","value":"神圣罗马帝国的诸侯主权化使帝国内部邦国获得更强外交、军事和宗教自主权，削弱皇帝集中权力。"},{"label":"核心主张/思路","value":"帝国诸侯在帝国法律框架内不断扩大领地治理、征税、军队和外交能力，形成多中心政治秩序。"},{"label":"提出者/代表人物（可选）","value":"帝国诸侯、帝国议会、哈布斯堡皇帝、普鲁士和巴伐利亚等邦国。"},{"label":"它从何而来","value":"宗教改革、《奥格斯堡和约》、三十年战争和《威斯特伐利亚和约》共同强化邦国权利。"},{"label":"典型表现","value":"诸侯决定本邦宗教、建立常备军、参与外交结盟、发展官僚财政，并在帝国议会中维护地位。"},{"label":"为什么重要","value":"它解释德意志为何长期不是集中民族国家，也解释普鲁士和奥地利为何能在帝国框架内发展为大国。"},{"label":"争议/局限","value":"诸侯主权化并不等于完全独立，帝国法院、帝国议会和皇帝权威仍在部分领域发挥作用。"},{"label":"出处","value":"Peter H. Wilson, Heart of Europe；Joachim Whaley, Germany and the Holy Roman Empire；Encyclopaedia Britannica: Holy Roman Empire。"}],"relationItems":["← 前因：威斯特伐利亚和约","↔ 相关：宗教改革《奥格斯堡和约》","→ 后果：奥地利与普鲁士二元主义","↔ 相关：神圣罗马帝国帝国议会"],"relations":[{"text":"← 前因：威斯特伐利亚和约","id":"extra308"},{"text":"↔ 相关：宗教改革《奥格斯堡和约》","id":"extra305"},{"text":"→ 后果：奥地利与普鲁士二元主义","id":"extra535"},{"text":"↔ 相关：神圣罗马帝国帝国议会","id":"extra414"}],"source":"history","id":"extra904"},{"title":"哈布斯堡东南欧扩张","level":"B","type":"概念/思潮卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"17世纪末—18世纪","place":"匈牙利、克罗地亚、特兰西瓦尼亚、巴尔干边疆和多瑙河流域","summary":"哈布斯堡东南欧扩张在奥斯曼退却后推进，把多瑙河流域纳入奥地利多民族帝国结构。","fields":[{"label":"标题","value":"哈布斯堡东南欧扩张"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"17世纪末—18世纪"},{"label":"地点","value":"匈牙利、克罗地亚、特兰西瓦尼亚、巴尔干边疆和多瑙河流域"},{"label":"主要国家","value":"奥地利；奥斯曼帝国；匈牙利；克罗地亚；塞尔维亚；威尼斯共和国"},{"label":"一句话概括","value":"哈布斯堡东南欧扩张在奥斯曼退却后推进，把多瑙河流域纳入奥地利多民族帝国结构。"},{"label":"核心主张/思路","value":"通过战争、条约、军事边疆和贵族协商，哈布斯堡王朝把匈牙利和巴尔干边缘地区纳入王朝统治。"},{"label":"提出者/代表人物（可选）","value":"奥地利哈布斯堡王朝、欧根亲王、匈牙利贵族、军事边疆行政机构。"},{"label":"它从何而来","value":"奥斯曼第二次围攻维也纳失败后，哈布斯堡获得反攻机会，欧洲反奥斯曼联盟改变东南欧力量对比。"},{"label":"典型表现","value":"《卡洛维茨条约》、匈牙利王国整合、军事边疆、贝尔格莱德争夺和多民族边疆治理。"},{"label":"为什么重要","value":"它为奥地利帝国的多民族结构和后来的巴尔干问题奠定基础，也改变中欧与东南欧权力格局。"},{"label":"争议/局限","value":"扩张不是单向“解放”，也伴随军事化边疆、宗教政策、土地重分配和地方社会冲突。"},{"label":"出处","value":"Encyclopaedia Britannica: Habsburg Monarchy；Charles Ingrao, The Habsburg Monarchy；Peter H. Wilson, Heart of Europe。"}],"relationItems":["← 前因：奥斯曼第二次围攻维也纳","↔ 相关：奥斯曼-哈布斯堡《卡洛维茨条约》","→ 后果：奥匈帝国多民族结构","↔ 相关：欧洲均势政治"],"relations":[{"text":"← 前因：奥斯曼第二次围攻维也纳","id":"extra310"},{"text":"↔ 相关：奥斯曼-哈布斯堡《卡洛维茨条约》","id":"extra446"},{"text":"→ 后果：奥匈帝国多民族结构","id":"extra923"},{"text":"↔ 相关：欧洲均势政治","id":"extra866"}],"source":"history","id":"extra905"},{"title":"英国海上霸权","level":"A","type":"概念/思潮卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"约18世纪中期—20世纪初","place":"大西洋、印度洋、地中海、加勒比和全球海路","summary":"英国海上霸权依靠皇家海军、金融信用和殖民贸易控制全球海路，成为近代世界秩序的重要基础。","fields":[{"label":"标题","value":"英国海上霸权"},{"label":"分级","value":"A"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"约18世纪中期—20世纪初"},{"label":"地点","value":"大西洋、印度洋、地中海、加勒比和全球海路"},{"label":"主要国家","value":"英国；法国；西班牙；荷兰；美国；印度诸邦"},{"label":"一句话概括","value":"英国海上霸权依靠皇家海军、金融信用和殖民贸易控制全球海路，成为近代世界秩序的重要基础。"},{"label":"核心主张/思路","value":"海军、港口、商船、保险、金融和殖民基地共同构成国家力量，能够保护贸易并压制竞争对手。"},{"label":"提出者/代表人物（可选）","value":"英国皇家海军、议会财政体系、东印度公司、伦敦金融机构和殖民行政网络。"},{"label":"它从何而来","value":"英荷竞争、英法殖民竞争、七年战争、金融革命和工业化前商业网络共同推动英国海权上升。"},{"label":"典型表现","value":"七年战争海上胜利、特拉法加海战、拿破仑战争封锁、大英帝国港口网络和海上保险金融。"},{"label":"为什么重要","value":"它解释大陆封锁体系为何难以压垮英国，也解释19世纪英国全球帝国和自由贸易秩序的军事基础。"},{"label":"争议/局限","value":"英国海上霸权依赖殖民剥削、奴隶贸易遗产和武力强制，不能只理解为自由贸易保护。"},{"label":"出处","value":"N. A. M. Rodger, The Command of the Ocean；Encyclopaedia Britannica: Royal Navy；P. J. Marshall, The Making and Unmaking of Empires。"}],"relationItems":["← 前因：英法殖民竞争","↔ 相关：大陆封锁体系","→ 后果：英国海上帝国","↔ 相关：一战海上战争"],"relations":[{"text":"← 前因：英法殖民竞争","id":"extra875"},{"text":"↔ 相关：大陆封锁体系","id":"extra920"},{"text":"↔ 相关：一战海上战争","id":"extra957"}],"source":"history","id":"extra906"},{"title":"法国印第安战争","level":"B","type":"事件卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1754—1763年","place":"北美东部、俄亥俄河谷、加拿大和大西洋帝国空间","summary":"法国印第安战争是七年战争北美战场，决定英法北美殖民力量对比并间接引发美国独立危机。","fields":[{"label":"标题","value":"法国印第安战争"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1754—1763年"},{"label":"地点","value":"北美东部、俄亥俄河谷、加拿大和大西洋帝国空间"},{"label":"主要国家","value":"英国；法国；北美原住民联盟；西班牙；北美十三殖民地"},{"label":"一句话概括","value":"法国印第安战争是七年战争北美战场，决定英法北美殖民力量对比并间接引发美国独立危机。"},{"label":"参与者","value":"英国军队和殖民地民兵、法国军队、加拿大法裔殖民者、易洛魁联盟及多个北美原住民群体。"},{"label":"发生了什么","value":"英法围绕俄亥俄河谷贸易、堡垒和土地扩张发生冲突，战争随后并入全球七年战争。英国最终夺取加拿大和法属北美大部分权益，法国在北美大陆殖民地大幅收缩。"},{"label":"为什么重要","value":"它让英国成为北美主导殖民强国，但战争债务促使英国加强对十三殖民地征税，引发殖民地反抗。"},{"label":"前因","value":"英法殖民竞争、北美边疆扩张、原住民联盟外交和欧洲大国战争全球化。"},{"label":"后果","value":"1763年《巴黎条约》改变北美版图，英国帝国财政压力上升，殖民地矛盾加深。"},{"label":"出处","value":"Encyclopaedia Britannica: French and Indian War；Fred Anderson, Crucible of War；Colin Calloway, The Scratch of a Pen。"}],"relationItems":["← 前因：英法殖民竞争","↔ 相关：七年战争","→ 后果：美国独立战争","↔ 相关：英国海上霸权"],"relations":[{"text":"← 前因：英法殖民竞争","id":"extra875"},{"text":"↔ 相关：七年战争","id":"extra316"},{"text":"→ 后果：美国独立战争","id":"extra896"},{"text":"↔ 相关：英国海上霸权","id":"extra906"}],"source":"history","id":"extra907"},{"title":"西罗马帝国灭亡","level":"S","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"476年，长期过程可追溯至4—5世纪","place":"西欧、意大利和西罗马各行省","summary":"西罗马帝国灭亡标志西欧罗马皇帝权威终结，开启日耳曼王国和中世纪欧洲政治秩序。","fields":[{"label":"标题","value":"西罗马帝国灭亡"},{"label":"分级","value":"S"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"476年，长期过程可追溯至4—5世纪"},{"label":"地点","value":"西欧、意大利和西罗马各行省"},{"label":"主要国家","value":"西罗马帝国；东罗马帝国；日耳曼诸王国；意大利"},{"label":"一句话概括","value":"西罗马帝国灭亡标志西欧罗马皇帝权威终结，开启日耳曼王国和中世纪欧洲政治秩序。"},{"label":"参与者","value":"西罗马皇帝罗慕路斯·奥古斯都、日耳曼军官奥多亚塞、东罗马皇帝、各地日耳曼军队和地方精英。"},{"label":"发生了什么","value":"西罗马长期面临财政萎缩、军队依赖外族将领、行省流失和政治内斗。476年，奥多亚塞废黜罗慕路斯·奥古斯都，并把皇帝徽号送往东罗马，西方皇帝制度结束。各地日耳曼王国继承和改造罗马制度。"},{"label":"为什么重要","value":"它是古典世界向中世纪欧洲转型的象征节点，影响“罗马遗产”“蛮族王国”和基督教欧洲的历史叙事。"},{"label":"前因","value":"罗马帝国分治、民族大迁徙、财政军事危机和西部行省权力瓦解。"},{"label":"后果","value":"东哥特、西哥特、法兰克等日耳曼王国扩展，拜占庭帝国继续以罗马帝国身份存在。"},{"label":"出处","value":"Encyclopaedia Britannica: Fall of the Western Roman Empire；Peter Heather, The Fall of the Roman Empire；Bryan Ward-Perkins, The Fall of Rome。"}],"relationItems":["← 前因：民族大迁徙与日耳曼王国","← 前因：罗马帝国","→ 后果：法兰克王国","→ 后果：拜占庭帝国"],"relations":[{"text":"← 前因：民族大迁徙与日耳曼王国","id":"extra393"},{"text":"← 前因：罗马帝国","id":"extra871"},{"text":"→ 后果：法兰克王国","id":"extra394"},{"text":"→ 后果：拜占庭帝国","id":"extra888"}],"source":"history","id":"extra908"},{"title":"德意志关税同盟（Zollverein）","level":"A","type":"组织/机构卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1834年1月1日生效","place":"德意志邦联内多数德意志邦国，普鲁士主导","summary":"德意志关税同盟在普鲁士主导下取消成员邦之间的关税壁垒，先建立经济共同体，为后来的德国政治统一铺平道路。","fields":[{"label":"标题","value":"德意志关税同盟（Zollverein）"},{"label":"分级","value":"A"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1834年1月1日生效"},{"label":"地点","value":"德意志邦联内多数德意志邦国，普鲁士主导"},{"label":"主要国家","value":"德国、普鲁士、奥地利"},{"label":"一句话概括","value":"德意志关税同盟在普鲁士主导下取消成员邦之间的关税壁垒，先建立经济共同体，为后来的德国政治统一铺平道路。"},{"label":"性质/类型","value":"跨邦国关税与贸易同盟。"},{"label":"成立/解散时间","value":"1834年1月1日生效；1871年德意志帝国建立后，其统一关税区功能逐渐被帝国经济制度吸收。"},{"label":"核心目标/宗旨","value":"取消成员邦之间的内部关税，建立共同外部关税边界，降低德意志内部贸易成本，推动更统一的经济空间形成。"},{"label":"关键人物","value":"普鲁士政府；弗里德里希·李斯特等早期德意志经济民族主义者为关税统一和经济整合提供了思想推动。"},{"label":"关键行动/事件","value":"普鲁士先在1818年改革本国关税制度，取消内部关卡；随后与周边邦国扩展关税合作。1834年，多个德意志邦国加入以普鲁士为核心的关税同盟，奥地利被排除在外。此后汉诺威、奥尔登堡等邦国陆续加入，关税同盟覆盖范围不断扩大。"},{"label":"为什么重要","value":"它让德意志在政治统一前先形成了经济统一的现实基础。普鲁士借此增强了对中小邦国的制度吸附力，也削弱了奥地利在德意志事务中的影响力。后来的“小德意志道路”并不是突然出现的，关税同盟已经提前把经济重心推向普鲁士。"},{"label":"争议/局限","value":"关税同盟并不等于政治统一。许多中小邦国加入同盟是出于贸易利益，并不意味着愿意放弃政治自主；奥地利也曾试图打破普鲁士在关税同盟中的优势。经济整合能够降低分裂成本，但不能自动消除邦国利益、王朝政治和军事冲突。"},{"label":"出处","value":"Encyclopaedia Britannica: Zollverein；Deutsches Historisches Museum: Chronik 1834；Deutsches Historisches Museum: Der Deutsche Zollverein 1850-1866；Encyclopaedia Britannica: Prussia, the kingdom from 1815 to 1918。"},{"label":"资料备注","value":"不同资料对1834年初始成员数量有不同计数口径，所以卡片没有写死“18个”或“21个”成员邦，只保留“多个/多数德意志邦国”这一稳妥表述。"}],"relationItems":["← 前因：德意志邦联","← 前因：普鲁士1818年关税改革","→ 后果：1848年德意志革命","→ 后果：普奥战争","→ 后果：德意志帝国成立","↔ 相关：弗里德里希·李斯特","✗ 对立/冲突：奥地利的德意志领导权诉求"],"relations":[{"text":"← 前因：德意志邦联","id":"extra487"},{"text":"→ 后果：1848年德意志革命","id":"extra490"},{"text":"→ 后果：普奥战争","id":"extra495"},{"text":"→ 后果：德意志帝国成立","id":"extra621"},{"text":"↔ 相关：弗里德里希·李斯特","id":"extra506"},{"text":"✗ 对立/冲突：奥地利的德意志领导权诉求","id":"extra909"}],"source":"history","id":"extra486"},{"title":"德意志邦联","level":"A","type":"组织/机构卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1815年6月8日成立；1866年解体","place":"中欧德意志地区，法兰克福为联邦议会所在地","summary":"德意志邦联是维也纳会议后建立的松散邦国联盟，维持了德意志分裂格局，也埋下普奥争夺德意志领导权的制度背景。","fields":[{"label":"标题","value":"德意志邦联"},{"label":"分级","value":"A"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1815年6月8日成立；1866年解体"},{"label":"地点","value":"中欧德意志地区，法兰克福为联邦议会所在地"},{"label":"主要国家","value":"德国、奥地利、普鲁士"},{"label":"一句话概括","value":"德意志邦联是维也纳会议后建立的松散邦国联盟，维持了德意志分裂格局，也埋下普奥争夺德意志领导权的制度背景。"},{"label":"性质/类型","value":"由奥地利、普鲁士及众多德意志邦国组成的邦联组织。"},{"label":"成立/解散时间","value":"1815年维也纳会议后成立；1866年普奥战争后解体。"},{"label":"核心目标/宗旨","value":"在拿破仑战争后重建中欧秩序，维持德意志地区的安全、防御与王朝政治稳定，防止革命与法国扩张再次冲击中欧。"},{"label":"关键人物","value":"奥地利首相梅特涅；普鲁士国王及各邦君主。"},{"label":"关键行动/事件","value":"邦联设有常驻法兰克福的联邦议会，但没有统一政府、统一军队或真正的全国议会。奥地利长期在邦联中居于主导地位，普鲁士则通过经济与军事力量逐渐扩大影响。"},{"label":"为什么重要","value":"它是十九世纪德国问题的制度起点。德意志既不是统一民族国家，也不是完全分散的诸侯世界，而是被邦联框架临时粘合在一起。后来的关税同盟、1848革命、普奥战争和德意志帝国成立，都是围绕如何打破或改造这个框架展开。"},{"label":"争议/局限","value":"德意志邦联能够维持保守秩序，却无法解决民族统一、宪政代表和普奥双重领导权矛盾。它的松散结构使改革极其困难，也让德意志统一与奥普领导权问题长期依赖王朝外交和军事竞争来解决。"},{"label":"出处","value":"Encyclopaedia Britannica: German Confederation；German History Documents and Images: German Confederation Act；Deutsches Historisches Museum/LeMO: Deutscher Bund。"},{"label":"资料备注","value":"成员数量通常概括为39个邦国，但具体统计会随自由市、王朝领地和时期变化略有口径差异。"}],"relationItems":["← 前因：拿破仑战后维也纳会议","→ 后果：德意志邦联的卡尔斯巴德决议","→ 后果：德意志关税同盟（Zollverein）","→ 后果：1848年德意志革命","→ 后果：普奥战争","✗ 对立/冲突：奥地利的德意志领导权诉求"],"relations":[{"text":"← 前因：拿破仑战后维也纳会议","id":"extra525"},{"text":"→ 后果：德意志邦联的卡尔斯巴德决议","id":"extra488"},{"text":"→ 后果：德意志关税同盟（Zollverein）","id":"extra486"},{"text":"→ 后果：1848年德意志革命","id":"extra490"},{"text":"→ 后果：普奥战争","id":"extra495"},{"text":"✗ 对立/冲突：奥地利的德意志领导权诉求","id":"extra909"}],"source":"history","id":"extra487"},{"title":"德意志邦联的卡尔斯巴德决议","level":"B","type":"制度/文本卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1819年9月","place":"德意志邦联；决议源自卡尔斯巴德会议，后由联邦议会确认","summary":"德意志邦联的卡尔斯巴德决议以打击激进民族主义为名，加强新闻、大学和学生社团管制，成为德意志复辟时代政治压制的标志。","fields":[{"label":"标题","value":"德意志邦联的卡尔斯巴德决议"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1819年9月"},{"label":"地点","value":"德意志邦联；决议源自卡尔斯巴德会议，后由联邦议会确认"},{"label":"主要国家","value":"德国、奥地利、普鲁士"},{"label":"一句话概括","value":"德意志邦联的卡尔斯巴德决议以打击激进民族主义为名，加强新闻、大学和学生社团管制，成为德意志复辟时代政治压制的标志。"},{"label":"制定方/签署方","value":"奥地利首相梅特涅主导，德意志邦联主要邦国代表参与。"},{"label":"主要内容","value":"对大学实施监督，限制教授和学生的政治活动；取缔或打压德意志学生兄弟会；加强新闻出版审查；设立调查机制追查所谓革命和煽动活动。"},{"label":"它试图解决什么问题","value":"拿破仑战争后，德意志学生运动、民族主义和自由主义迅速发展。1819年作家科策布遇刺后，梅特涅将其作为压制激进政治的机会，试图防止革命思想在德意志邦联内扩散。"},{"label":"为什么重要","value":"它把德意志邦联的保守性质制度化，说明1815年后的秩序并不只是外交安排，也是一套压制自由主义和民族主义的内政机器。后来的德国汉巴赫节和1848革命，都可以看作这种压制秩序下积累的反弹。"},{"label":"争议/局限","value":"决议短期内削弱了公开政治动员，却无法消除民族统一和宪政改革诉求。它还让大学、出版业和学生运动成为国家监控对象，使思想文化领域高度政治化。"},{"label":"造成的影响","value":"德意志进入更强的复辟与审查氛围，许多自由派知识分子被监视、停职或流亡；民族主义和自由主义转入更隐蔽的传播方式。"},{"label":"出处","value":"German History Documents and Images: Carlsbad Decrees；Encyclopaedia Britannica: Carlsbad Decrees；Deutsches Historisches Museum/LeMO: Karlsbader Beschlüsse。"},{"label":"资料备注","value":"德意志邦联的卡尔斯巴德决议不是单一普通法律，而是一组由邦联框架确认的管制措施。"}],"relationItems":["← 前因：德意志邦联","→ 后果：德国汉巴赫节","→ 后果：1848年德意志革命","↔ 相关：欧洲梅特涅体系","✗ 对立/冲突：德意志自由主义"],"relations":[{"text":"← 前因：德意志邦联","id":"extra487"},{"text":"→ 后果：德国汉巴赫节","id":"extra489"},{"text":"→ 后果：1848年德意志革命","id":"extra490"},{"text":"↔ 相关：欧洲梅特涅体系","id":"extra500"},{"text":"✗ 对立/冲突：德意志自由主义","id":"extra501"}],"source":"history","id":"extra488"},{"title":"德国汉巴赫节","level":"B","type":"事件卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1832年5月27日至30日","place":"巴伐利亚王国普法尔茨地区，汉巴赫城堡附近","summary":"德国汉巴赫节以群众集会形式公开表达民族统一、自由宪政和公民权利诉求，成为 Vormärz 时期德意志自由民族运动的象征。","fields":[{"label":"标题","value":"德国汉巴赫节"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1832年5月27日至30日"},{"label":"地点","value":"巴伐利亚王国普法尔茨地区，汉巴赫城堡附近"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国汉巴赫节以群众集会形式公开表达民族统一、自由宪政和公民权利诉求，成为 Vormärz 时期德意志自由民族运动的象征。"},{"label":"参与者","value":"德意志自由派、学生、知识分子、市民、手工业者，以及来自波兰、法国等地的支持者。"},{"label":"发生了什么","value":"1832年5月，来自德意志各地的自由派、市民、学生、手工业者和部分外国支持者聚集到巴伐利亚普法尔茨的汉巴赫城堡附近。他们以节庆和游行形式规避直接政治集会限制，在演说中公开要求新闻自由、宪政权利、民族统一和人民主权。德国黑红金旗帜在集会中被反复展示，成为自由与统一诉求的视觉象征。集会结束后，各邦政府加强镇压，许多组织者被审判、监控或流亡。"},{"label":"为什么重要","value":"它显示德意志自由主义和民族主义已经不只是秘密社团或大学圈层的思想，而能够变成跨阶层、跨地域的公开政治动员。它也让黑红金成为德意志民族自由运动的重要颜色。"},{"label":"前因","value":"卡尔斯巴德决议后的审查和镇压压缩了德意志自由派的公开空间，法国1830年七月革命又让德意志地区的自由主义者相信群众集会可以推动政治变革。"},{"label":"后果","value":"各邦政府把汉巴赫节视为危险的自由主义和民族主义动员，随后加强镇压；但它留下的黑红金旗帜和自由统一诉求，成为1848年革命的重要政治记忆。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Hambacher Fest；Encyclopaedia Britannica: Hambach Festival。"},{"label":"资料备注","value":"参加人数在不同资料中有不同估计，常见说法约为两三万人，因此卡片使用“数万人”表述。"}],"relationItems":["← 前因：德意志邦联的卡尔斯巴德决议","← 前因：法国七月革命","→ 后果：1848年德意志革命","↔ 相关：德国黑红金旗帜","↔ 相关：德意志自由主义"],"relations":[{"text":"← 前因：德意志邦联的卡尔斯巴德决议","id":"extra488"},{"text":"← 前因：法国七月革命","id":"extra916"},{"text":"→ 后果：1848年德意志革命","id":"extra490"},{"text":"↔ 相关：德国黑红金旗帜","id":"extra505"},{"text":"↔ 相关：德意志自由主义","id":"extra501"}],"source":"history","id":"extra489"},{"title":"1848年德意志革命","level":"A","type":"事件卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1848年至1849年","place":"德意志各邦，重点包括柏林、维也纳、法兰克福等城市","summary":"1848年革命把德意志统一、宪政自由和社会改革诉求同时推上政治舞台，但最终在王朝反击和自由派分裂中失败。","fields":[{"label":"标题","value":"1848年德意志革命"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1848年至1849年"},{"label":"地点","value":"德意志各邦，重点包括柏林、维也纳、法兰克福等城市"},{"label":"主要国家","value":"德国、奥地利、普鲁士"},{"label":"一句话概括","value":"1848年革命把德意志统一、宪政自由和社会改革诉求同时推上政治舞台，但最终在王朝反击和自由派分裂中失败。"},{"label":"参与者","value":"自由派市民、学生、工人、手工业者、农民、各邦君主、普鲁士和奥地利军队、德国法兰克福国民议会代表。"},{"label":"发生了什么","value":"1848年法国二月革命后，德意志各邦迅速出现示威、请愿和街垒战。柏林、维也纳等城市群众要求宪法、新闻自由、陪审制、国民代表和民族统一，各邦君主一度让步并任命自由派部长。随后法兰克福国民议会召开，试图用全国议会和宪法完成统一。但革命阵营在君主制、共和制、民族边界和十九世纪德国社会问题上分裂，普鲁士与奥地利等王朝力量逐步恢复控制，1849年革命被军事和政治反扑压下。"},{"label":"为什么重要","value":"它第一次把“德意志如何统一”变成全国性公开政治工程，也暴露了自由派、民主派、君主派、民族主义者和社会改革力量之间的深层分歧。它失败后，德意志统一的主动权从议会和街头转向普鲁士王权、军队和俾斯麦外交。"},{"label":"前因","value":"德意志邦联长期压制自由主义和民族统一诉求，1840年代经济危机、粮食危机和法国二月革命共同把社会不满推向爆发点。"},{"label":"后果","value":"革命未能建立统一的宪政德国，各邦保守势力恢复秩序；但宪法、议会、民族国家和公民权利已经成为德意志政治无法回避的议题。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Revolution 1848；Encyclopaedia Britannica: Revolutions of 1848。"},{"label":"资料备注","value":"1848年德意志革命不是单一城市事件，而是多个邦国和社会群体同时参与的革命过程。"}],"relationItems":["← 前因：德国汉巴赫节","← 前因：德意志关税同盟（Zollverein）","→ 后果：德国法兰克福国民议会","→ 后果：普鲁士的奥尔米茨屈辱","↔ 相关：德国黑红金旗帜","✗ 对立/冲突：欧洲梅特涅体系"],"relations":[{"text":"← 前因：德国汉巴赫节","id":"extra489"},{"text":"← 前因：德意志关税同盟（Zollverein）","id":"extra486"},{"text":"→ 后果：德国法兰克福国民议会","id":"extra491"},{"text":"→ 后果：普鲁士的奥尔米茨屈辱","id":"extra492"},{"text":"↔ 相关：德国黑红金旗帜","id":"extra505"},{"text":"✗ 对立/冲突：欧洲梅特涅体系","id":"extra500"}],"source":"history","id":"extra490"},{"title":"德国法兰克福国民议会","level":"A","type":"组织/机构卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1848年5月18日至1849年","place":"法兰克福圣保罗教堂","summary":"德国法兰克福国民议会是德意志第一次全国性民选议会，试图用宪法和议会方式完成统一，却因缺乏强制力量而失败。","fields":[{"label":"标题","value":"德国法兰克福国民议会"},{"label":"分级","value":"A"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1848年5月18日至1849年"},{"label":"地点","value":"法兰克福圣保罗教堂"},{"label":"主要国家","value":"德国、普鲁士、奥地利"},{"label":"一句话概括","value":"德国法兰克福国民议会是德意志第一次全国性民选议会，试图用宪法和议会方式完成统一，却因缺乏强制力量而失败。"},{"label":"性质/类型","value":"革命时期产生的全国性代表议会和制宪机构。"},{"label":"成立/解散时间","value":"1848年5月18日开幕；1849年宪法方案失败后走向瓦解。"},{"label":"核心目标/宗旨","value":"制定统一德意志国家的宪法，确立公民权利和议会制度，并解决德意志民族国家的边界与君主形式问题。"},{"label":"关键人物","value":"海因里希·冯·加格恩、罗伯特·布鲁姆、弗里德里希·威廉四世等。"},{"label":"关键行动/事件","value":"议会讨论“大德意志方案”和“小德意志方案”，最终通过1849年法兰克福宪法，并把德意志皇帝皇冠授予普鲁士国王弗里德里希·威廉四世。普鲁士国王拒绝接受来自革命议会的皇冠，议会的统一方案失败。"},{"label":"为什么重要","value":"它是德意志自由主义统一道路的最高点，也是其失败的标志。它留下了基本权利、议会制和民族国家想象，但证明没有军队和行政权支撑的议会难以战胜王朝国家。"},{"label":"争议/局限","value":"议会代表以受教育的市民和知识精英为主，社会基础有限；它在民族边界、君主制、民主化程度和十九世纪德国社会问题上存在激烈分歧，也没有直接控制军队和税收的能力。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Frankfurter Nationalversammlung；German History Documents and Images: Frankfurt Parliament；Encyclopaedia Britannica: Frankfurt National Assembly。"},{"label":"资料备注","value":"议会开幕地点“圣保罗教堂”后来成为德国议会民主传统的重要象征。"}],"relationItems":["← 前因：1848年德意志革命","→ 后果：普鲁士的奥尔米茨屈辱","→ 后果：俾斯麦出任普鲁士首相","↔ 相关：大德意志方案与小德意志方案","↔ 相关：大德意志方案与小德意志方案"],"relations":[{"text":"← 前因：1848年德意志革命","id":"extra490"},{"text":"→ 后果：普鲁士的奥尔米茨屈辱","id":"extra492"},{"text":"→ 后果：俾斯麦出任普鲁士首相","id":"extra493"},{"text":"↔ 相关：大德意志方案与小德意志方案","id":"extra527"},{"text":"↔ 相关：大德意志方案与小德意志方案","id":"extra527"}],"source":"history","id":"extra491"},{"title":"普鲁士的奥尔米茨屈辱","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1850年11月29日","place":"奥尔米茨（今捷克奥洛穆茨）","summary":"普鲁士在奥地利和俄国压力下放弃主导德意志统一的尝试，被迫恢复德意志邦联，暴露出其尚无力挑战奥地利。","fields":[{"label":"标题","value":"普鲁士的奥尔米茨屈辱"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1850年11月29日"},{"label":"地点","value":"奥尔米茨（今捷克奥洛穆茨）"},{"label":"主要国家","value":"普鲁士、奥地利、俄国、德国"},{"label":"一句话概括","value":"普鲁士在奥地利和俄国压力下放弃主导德意志统一的尝试，被迫恢复德意志邦联，暴露出其尚无力挑战奥地利。"},{"label":"参与者","value":"普鲁士、奥地利、俄国、德意志邦联各邦。"},{"label":"发生了什么","value":"1848革命失败后，普鲁士尝试通过埃尔福特联盟在小德意志方向重组德意志政治秩序。奥地利认为这会削弱自己在德意志邦联中的领导地位，联合俄国施压，并在黑森问题上制造军事对峙。普鲁士发现自己尚无力同时对抗奥地利和俄国，最终在1850年奥尔米茨会议中退让，放弃埃尔福特联盟方案，同意恢复由奥地利主导的德意志邦联秩序。"},{"label":"为什么重要","value":"它是普鲁士在德意志统一与奥普领导权问题上遭遇的重大挫败，也让普鲁士政治精英认识到，仅靠外交和宪法方案无法取代奥地利。后来的俾斯麦路线，正是在这种失败记忆中转向军事、外交和权力政治。"},{"label":"前因","value":"法兰克福国民议会失败后，普鲁士试图用埃尔福特联盟排挤奥地利，但奥地利借俄国支持和邦联旧秩序迫使普鲁士让步。"},{"label":"后果","value":"普鲁士暂时放弃领导德意志统一，德意志邦联恢复；这次退让也强化了普鲁士精英对军事改革和日后重新挑战奥地利的需求。"},{"label":"出处","value":"Encyclopaedia Britannica: Punctation of Olmütz；Deutsches Historisches Museum/LeMO: Reaktionszeit und Deutscher Bund。"},{"label":"资料备注","value":"“屈辱”是普鲁士民族主义和后世叙事中的常用评价，卡片保留该标题是因为它概括了普鲁士政治心理上的挫败感。"}],"relationItems":["← 前因：德国法兰克福国民议会","← 前因：德意志邦联","→ 后果：俾斯麦出任普鲁士首相","→ 后果：普奥战争","✗ 对立/冲突：奥地利的德意志领导权诉求"],"relations":[{"text":"← 前因：德国法兰克福国民议会","id":"extra491"},{"text":"← 前因：德意志邦联","id":"extra487"},{"text":"→ 后果：俾斯麦出任普鲁士首相","id":"extra493"},{"text":"→ 后果：普奥战争","id":"extra495"},{"text":"✗ 对立/冲突：奥地利的德意志领导权诉求","id":"extra909"}],"source":"history","id":"extra492"},{"title":"俾斯麦出任普鲁士首相","level":"A","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1862年9月","place":"普鲁士王国，柏林","summary":"俾斯麦在普鲁士宪政危机中出任首相，把德意志统一从自由派议会道路转向王权、军队和现实政治主导的道路。","fields":[{"label":"标题","value":"俾斯麦出任普鲁士首相"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1862年9月"},{"label":"地点","value":"普鲁士王国，柏林"},{"label":"主要国家","value":"普鲁士、德国"},{"label":"一句话概括","value":"俾斯麦在普鲁士宪政危机中出任首相，把德意志统一从自由派议会道路转向王权、军队和现实政治主导的道路。"},{"label":"参与者","value":"奥托·冯·俾斯麦、普鲁士国王威廉一世、普鲁士议会自由派、陆军改革派。"},{"label":"发生了什么","value":"1860年代初，普鲁士国王威廉一世和议会自由派围绕军队改革、服役年限和军费预算爆发宪政危机。议会拒绝批准政府所需预算，国王一度考虑退位。1862年9月，威廉一世任命俾斯麦为首相兼外交大臣。俾斯麦上任后主张政府可在宪法“空白”中继续征税和执行军改，绕过议会阻力维持军队建设，并很快把国内宪政冲突同普鲁士的德意志政策结合起来。"},{"label":"为什么重要","value":"这张卡是德意志统一路线转换的关键。1848年的议会统一失败后，俾斯麦上台意味着统一问题被纳入普鲁士国家机器、军队改革和欧洲列强外交博弈之中。"},{"label":"前因","value":"普鲁士军制改革引发王权和议会的预算冲突，国王威廉一世需要一个愿意绕开自由派议会、维护军队改革的强硬首相。"},{"label":"后果","value":"俾斯麦把普鲁士宪政危机转化为国家权力重组，并通过普丹、普奥和普法三场战争把普鲁士推成德意志统一的主导者。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Otto von Bismarck；Encyclopaedia Britannica: Otto von Bismarck。"},{"label":"资料备注","value":"俾斯麦著名的“铁与血”演说发生在其上台前后军改争论语境中，卡片不把它简化为统一政策的完整纲领。"}],"relationItems":["← 前因：普鲁士的奥尔米茨屈辱","→ 后果：普丹战争","→ 后果：普奥战争","→ 后果：普法战争","↔ 相关：奥托·冯·俾斯麦","↔ 相关：铁血政策"],"relations":[{"text":"← 前因：普鲁士的奥尔米茨屈辱","id":"extra492"},{"text":"→ 后果：普丹战争","id":"extra494"},{"text":"→ 后果：普奥战争","id":"extra495"},{"text":"→ 后果：普法战争","id":"extra497"},{"text":"↔ 相关：奥托·冯·俾斯麦","id":"extra924"}],"source":"history","id":"extra493"},{"title":"普丹战争","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1864年","place":"石勒苏益、荷尔斯泰因及丹麦相关地区","summary":"普鲁士与奥地利联手击败丹麦，夺取石勒苏益和荷尔斯泰因，为随后普奥围绕德意志领导权摊牌制造了直接争端。","fields":[{"label":"标题","value":"普丹战争"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1864年"},{"label":"地点","value":"石勒苏益、荷尔斯泰因及丹麦相关地区"},{"label":"主要国家","value":"普鲁士、奥地利、丹麦、德国"},{"label":"一句话概括","value":"普鲁士与奥地利联手击败丹麦，夺取石勒苏益和荷尔斯泰因，为随后普奥围绕德意志领导权摊牌制造了直接争端。"},{"label":"参与者","value":"普鲁士、奥地利、丹麦、德意志邦联相关邦国。"},{"label":"发生了什么","value":"丹麦政府试图把石勒苏益更紧密地纳入丹麦王国，引发德意志民族主义者和德意志邦联反弹。1864年，普鲁士和奥地利联手对丹麦作战，德奥军队突破丹麦防线并取得军事优势。丹麦最终在维也纳和约中放弃石勒苏益、荷尔斯泰因和劳恩堡。战后这些公国由普鲁士和奥地利共同处理，但双方很快围绕管理权和未来归属发生冲突，成为普奥战争的直接导火索。"},{"label":"为什么重要","value":"它是俾斯麦统一战争链条中的第一环。表面上是德丹之间的公国归属问题，实质上为普鲁士创造了一个与奥地利共同获利、随后再因战利品管理发生冲突的外交局面。"},{"label":"前因","value":"石勒苏益和荷尔斯泰因的王位继承与民族归属争议长期存在，丹麦试图把石勒苏益更紧密纳入本国，刺激了德意志民族主义和普鲁士、奥地利的干预。"},{"label":"后果","value":"丹麦战败后两公国由普奥共同处置，但共同管理很快变成普奥争夺德意志领导权的新冲突点，为1866年普奥战争提供了直接导火索。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Deutsch-Dänischer Krieg 1864；Encyclopaedia Britannica: Schleswig-Holstein Question。"},{"label":"资料备注","value":"此处聚焦1864年普丹战争，不展开1848—1851年的第一次石勒苏益战争。"}],"relationItems":["← 前因：俾斯麦出任普鲁士首相","→ 后果：普奥战争","↔ 相关：石勒苏益-荷尔斯泰因问题","↔ 相关：奥托·冯·俾斯麦"],"relations":[{"text":"← 前因：俾斯麦出任普鲁士首相","id":"extra493"},{"text":"→ 后果：普奥战争","id":"extra495"},{"text":"↔ 相关：石勒苏益-荷尔斯泰因问题","id":"extra541"},{"text":"↔ 相关：奥托·冯·俾斯麦","id":"extra924"}],"source":"history","id":"extra494"},{"title":"普奥战争","level":"A","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1866年6月至8月","place":"德意志地区、波希米亚等战场","summary":"普奥战争以普鲁士击败奥地利告终，德意志邦联解体，德意志统一的主导权从奥地利转入普鲁士手中。","fields":[{"label":"标题","value":"普奥战争"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1866年6月至8月"},{"label":"地点","value":"德意志地区、波希米亚等战场"},{"label":"主要国家","value":"普鲁士、奥地利、德国、意大利"},{"label":"一句话概括","value":"普奥战争以普鲁士击败奥地利告终，德意志邦联解体，德意志统一的主导权从奥地利转入普鲁士手中。"},{"label":"参与者","value":"普鲁士、奥地利、意大利、德意志邦联中支持双方的邦国。"},{"label":"发生了什么","value":"普鲁士与奥地利围绕石勒苏益、荷尔斯泰因管理权和德意志领导权矛盾升级。俾斯麦先在外交上争取意大利结盟，并确保法国和俄国不直接干预。1866年战争爆发后，普鲁士利用铁路动员、总参谋部计划和针发枪等优势迅速集中兵力，在克尼格雷茨/萨多瓦会战中击败奥军。战后俾斯麦阻止对奥地利过度惩罚，重点是解散德意志邦联，把奥地利排除出德意志事务，并建立普鲁士主导的新秩序。"},{"label":"为什么重要","value":"它解决了“谁领导德意志”的核心问题。此后德意志统一不再可能沿着奥地利主导的大德意志道路推进，而是进入普鲁士主导的小德意志道路。"},{"label":"前因","value":"普丹战争后的公国管理冲突只是表层原因，更深层的是普鲁士和奥地利长期争夺德意志领导权；俾斯麦通过外交安排尽量避免奥地利获得强力外援。"},{"label":"后果","value":"奥地利被排除出德意志事务，德意志邦联解体，普鲁士建立北德意志邦联并同南德诸邦形成军事联系，为1871年统一铺平道路。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Deutscher Krieg 1866；Encyclopaedia Britannica: Seven Weeks’ War；German History Documents and Images: German Unification。"},{"label":"资料备注","value":"该战争也常被称为“七周战争”或“德意志战争”。"}],"relationItems":["← 前因：普丹战争","← 前因：普鲁士的奥尔米茨屈辱","→ 后果：普鲁士主导的北德意志邦联","→ 后果：普法战争","✗ 对立/冲突：奥地利的德意志领导权诉求"],"relations":[{"text":"← 前因：普丹战争","id":"extra494"},{"text":"← 前因：普鲁士的奥尔米茨屈辱","id":"extra492"},{"text":"→ 后果：普鲁士主导的北德意志邦联","id":"extra496"},{"text":"→ 后果：普法战争","id":"extra497"},{"text":"✗ 对立/冲突：奥地利的德意志领导权诉求","id":"extra909"}],"source":"history","id":"extra495"},{"title":"普鲁士主导的北德意志邦联","level":"B","type":"组织/机构卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1867年至1871年","place":"美因河以北德意志诸邦，普鲁士主导","summary":"普鲁士主导的北德意志邦联在普奥战争后建立，把普鲁士主导的军事、外交和宪政结构制度化，是德意志帝国的直接前身。","fields":[{"label":"标题","value":"普鲁士主导的北德意志邦联"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1867年至1871年"},{"label":"地点","value":"美因河以北德意志诸邦，普鲁士主导"},{"label":"主要国家","value":"德国、普鲁士"},{"label":"一句话概括","value":"普鲁士主导的北德意志邦联在普奥战争后建立，把普鲁士主导的军事、外交和宪政结构制度化，是德意志帝国的直接前身。"},{"label":"性质/类型","value":"由普鲁士主导的联邦国家结构。"},{"label":"成立/解散时间","value":"1867年成立；1871年德意志帝国成立后被帝国制度吸收。"},{"label":"核心目标/宗旨","value":"整合北德意志诸邦的军事、外交、邮政、关税和立法体系，建立排除奥地利的普鲁士主导政治框架。"},{"label":"关键人物","value":"威廉一世、奥托·冯·俾斯麦、北德意志各邦政府。"},{"label":"关键行动/事件","value":"普鲁士主导的北德意志邦联制定宪法，设立联邦议会和帝国议会雏形，普鲁士国王担任联邦主席，俾斯麦担任联邦首相。普鲁士控制军事和外交核心权力。"},{"label":"为什么重要","value":"它不是统一前的小插曲，而是1871年德意志帝国制度的预演。帝国后来许多制度安排，包括强势君主、首相负责于皇帝而非议会、联邦制与普鲁士优势，都已经在普鲁士主导的北德意志邦联中成形。"},{"label":"争议/局限","value":"邦联包含普选产生的帝国议会，但真正的行政和军事权力仍掌握在普鲁士王权与首相手中。它扩大了民族国家框架，却没有建立充分的议会责任制。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Norddeutscher Bund；Encyclopaedia Britannica: North German Confederation。"},{"label":"资料备注","value":"普鲁士主导的北德意志邦联常被视为德意志帝国的制度前身，而不只是邦国联盟。"}],"relationItems":["← 前因：普奥战争","→ 后果：普法战争","→ 后果：德意志帝国成立","↔ 相关：奥托·冯·俾斯麦","↔ 相关：大德意志方案与小德意志方案"],"relations":[{"text":"← 前因：普奥战争","id":"extra495"},{"text":"→ 后果：普法战争","id":"extra497"},{"text":"→ 后果：德意志帝国成立","id":"extra621"},{"text":"↔ 相关：奥托·冯·俾斯麦","id":"extra924"},{"text":"↔ 相关：大德意志方案与小德意志方案","id":"extra527"}],"source":"history","id":"extra496"},{"title":"普法战争","level":"A","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1870年7月至1871年5月","place":"法国、德意志边境及相关战场","summary":"普法战争使南德意志诸邦倒向普鲁士，并以法国战败和德国统一告终，重塑了欧洲大陆权力格局。","fields":[{"label":"标题","value":"普法战争"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1870年7月至1871年5月"},{"label":"地点","value":"法国、德意志边境及相关战场"},{"label":"主要国家","value":"普鲁士、德国、法国"},{"label":"一句话概括","value":"普法战争使南德意志诸邦倒向普鲁士，并以法国战败和德国统一告终，重塑了欧洲大陆权力格局。"},{"label":"参与者","value":"普鲁士及普鲁士主导的北德意志邦联、巴伐利亚等南德意志诸邦、法兰西第二帝国及后来的法国国防政府。"},{"label":"发生了什么","value":"西班牙王位继承问题引发法普外交对抗，俾斯麦通过处理普法战争前埃姆斯电报激化法国舆论和政府压力。1870年7月，法国向普鲁士宣战，南德意志诸邦根据同普鲁士的军事同盟加入作战。德军迅速动员并进入法国，在色当会战中包围法军并俘获拿破仑三世。法兰西第二帝国崩溃后，法国国防政府继续抵抗，巴黎被围。战争尚未完全结束时，德意志诸邦在凡尔赛宣布帝国成立。"},{"label":"为什么重要","value":"它把德意志统一从北德意志范围推进到全德意志帝国。共同对法战争激发了南德诸邦加入普鲁士主导统一的政治条件，也使法国失去阿尔萨斯—洛林，埋下长期法德仇恨。"},{"label":"前因","value":"北德意志邦联建立后法国担心普鲁士继续扩张，西班牙王位继承危机和普法战争前埃姆斯电报把这种战略焦虑转化为民族主义战争动员。"},{"label":"后果","value":"法国战败导致第二帝国崩溃，德意志帝国在战争胜利中成立；阿尔萨斯-洛林割让和赔款又把德法敌对固定为欧洲长期结构性矛盾。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Deutsch-Französischer Krieg；Encyclopaedia Britannica: Franco-German War；German History Documents and Images: The Franco-Prussian War and German Unification。"},{"label":"资料备注","value":"中文常称“普法战争”，但考虑南德诸邦和普鲁士主导的北德意志邦联均参与，标准卡名采用更宽的“普法战争”。"}],"relationItems":["← 前因：普鲁士主导的北德意志邦联","← 前因：普奥战争","→ 后果：德意志帝国成立","→ 后果：阿尔萨斯-洛林问题的形成","↔ 相关：普法战争前埃姆斯电报"],"relations":[{"text":"← 前因：普鲁士主导的北德意志邦联","id":"extra496"},{"text":"← 前因：普奥战争","id":"extra495"},{"text":"→ 后果：德意志帝国成立","id":"extra621"},{"text":"→ 后果：阿尔萨斯-洛林问题的形成","id":"extra620"},{"text":"↔ 相关：普法战争前埃姆斯电报","id":"extra548"}],"source":"history","id":"extra497"},{"title":"德国瓦尔特堡节","level":"B","type":"事件卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1817年10月18日","place":"德意志地区，瓦尔特堡","summary":"德国瓦尔特堡节是学生和自由派民族主义者的象征性集会，表达德意志统一、宪政和反复辟诉求。","fields":[{"label":"标题","value":"德国瓦尔特堡节"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1817年10月18日"},{"label":"地点","value":"德意志地区，瓦尔特堡"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国瓦尔特堡节是学生和自由派民族主义者的象征性集会，表达德意志统一、宪政和反复辟诉求。"},{"label":"参与者","value":"德意志大学生、德意志学生兄弟会成员、自由派知识分子。"},{"label":"发生了什么","value":"1817年，来自德意志多所大学的学生和自由派人士聚集在瓦尔特堡，纪念宗教改革三百周年和莱比锡会战周年。他们以演说、游行和象征仪式表达对民族统一、宪政自由和反拿破仑战争记忆的诉求。集会中出现焚烧反动书籍和象征物的举动，刺激保守政府警惕。德国瓦尔特堡节没有立即造成制度变革，但让学生运动和民族自由主义进入邦联政府监控视野。"},{"label":"为什么重要","value":"它是德意志民族自由主义早期公开表达的重要节点，为后来的卡尔斯巴德决议和汉巴赫节提供前史。"},{"label":"前因","value":"反拿破仑战争激发了德意志学生和知识分子的民族意识，但维也纳体系恢复了分裂的邦国秩序，使青年自由派把民族统一和宪政改革联系在一起。"},{"label":"后果","value":"保守政府把学生集会视为革命危险，开始严密监控大学和学生组织；瓦尔特堡节的象征政治也为后来的卡尔斯巴德决议提供了镇压理由。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Wartburgfest；Encyclopaedia Britannica相关资料；German History Documents and Images相关资料。"}],"relationItems":["← 前因：德意志邦联","→ 后果：德意志邦联的卡尔斯巴德决议","↔ 相关：德意志学生兄弟会"],"relations":[{"text":"← 前因：德意志邦联","id":"extra487"},{"text":"→ 后果：德意志邦联的卡尔斯巴德决议","id":"extra488"},{"text":"↔ 相关：德意志学生兄弟会","id":"extra499"}],"source":"history","id":"extra498"},{"title":"德意志学生兄弟会","level":"C","type":"组织/机构卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1815年后兴起","place":"德意志大学城市","summary":"德意志学生兄弟会把大学青年、民族统一和自由主义诉求连接起来，是复辟时期德意志政治文化的重要载体。","fields":[{"label":"标题","value":"德意志学生兄弟会"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1815年后兴起"},{"label":"地点","value":"德意志大学城市"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德意志学生兄弟会把大学青年、民族统一和自由主义诉求连接起来，是复辟时期德意志政治文化的重要载体。"},{"label":"性质/类型","value":"大学学生社团和政治文化组织。"},{"label":"成立/解散时间","value":"1815年耶拿德意志学生兄弟会具有代表性；1819年后遭卡尔斯巴德决议严厉打压。"},{"label":"核心目标/宗旨","value":"追求德意志民族统一、自由宪政、学生团结和道德自我教育。"},{"label":"关键人物（可选）","value":"无单一核心人物，大学生和教授网络共同参与。"},{"label":"关键行动/事件","value":"参与德国瓦尔特堡节；部分成员卷入激进行动，如科策布遇刺后成为保守政府打压目标。"},{"label":"为什么重要","value":"德意志学生兄弟会说明德意志民族主义最初很大程度上是文化、大学和青年政治运动，而不只是国家政策。"},{"label":"争议/局限","value":"其内部既有自由主义和反专制诉求，也存在排外、男性化和民族浪漫主义倾向。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Burschenschaften；German History Documents and Images相关资料。"}],"relationItems":["→ 后果：德国瓦尔特堡节","→ 后果：德意志邦联的卡尔斯巴德决议","↔ 相关：德意志自由主义"],"relations":[{"text":"→ 后果：德国瓦尔特堡节","id":"extra498"},{"text":"→ 后果：德意志邦联的卡尔斯巴德决议","id":"extra488"},{"text":"↔ 相关：德意志自由主义","id":"extra501"}],"source":"history","id":"extra499"},{"title":"欧洲梅特涅体系","level":"A","type":"概念/思潮卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1815年至1848年前后","place":"欧洲，尤其奥地利和德意志邦联","summary":"欧洲梅特涅体系以王朝合法性、均势和反革命为核心，试图压制民族主义和自由主义对维也纳秩序的冲击。","fields":[{"label":"标题","value":"欧洲梅特涅体系"},{"label":"分级","value":"A"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1815年至1848年前后"},{"label":"地点","value":"欧洲，尤其奥地利和德意志邦联"},{"label":"主要国家","value":"奥地利、普鲁士、德国、俄国、法国"},{"label":"一句话概括","value":"欧洲梅特涅体系以王朝合法性、均势和反革命为核心，试图压制民族主义和自由主义对维也纳秩序的冲击。"},{"label":"核心主张/思路","value":"维护王朝秩序和欧洲均势，反对革命、民族主义和自由主义扩散。"},{"label":"提出者/代表人物（可选）","value":"奥地利首相克莱门斯·冯·梅特涅。"},{"label":"它从何而来","value":"拿破仑战争后，欧洲保守君主国希望防止法国革命式动荡再次扩散。"},{"label":"典型表现","value":"维也纳会议后的列强协商、德意志邦联保守治理、卡尔斯巴德决议、新闻审查和大学监控。"},{"label":"为什么重要","value":"它是理解1815-1848年欧洲政治的基本框架，也是德意志自由民族运动反抗的主要对象。"},{"label":"争议/局限","value":"它能短期维持秩序，却无法解决工业化、民族认同和宪政要求带来的深层变化。"},{"label":"出处","value":"Encyclopaedia Britannica: Klemens von Metternich；Deutsches Historisches Museum/LeMO: Restauration；German History Documents and Images相关资料。"}],"relationItems":["← 前因：拿破仑战后维也纳会议","→ 后果：德意志邦联的卡尔斯巴德决议","→ 后果：1848年德意志革命","↔ 相关：德意志邦联"],"relations":[{"text":"← 前因：拿破仑战后维也纳会议","id":"extra525"},{"text":"→ 后果：德意志邦联的卡尔斯巴德决议","id":"extra488"},{"text":"→ 后果：1848年德意志革命","id":"extra490"},{"text":"↔ 相关：德意志邦联","id":"extra487"}],"source":"history","id":"extra500"},{"title":"德意志自由主义","level":"A","type":"概念/思潮卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"十九世纪上半叶至帝国时期持续发展","place":"德意志地区","summary":"德意志自由主义把宪政、法治、公民权利和民族统一连接起来，是十九世纪德国政治变革的核心思想力量。","fields":[{"label":"标题","value":"德意志自由主义"},{"label":"分级","value":"A"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"十九世纪上半叶至帝国时期持续发展"},{"label":"地点","value":"德意志地区"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德意志自由主义把宪政、法治、公民权利和民族统一连接起来，是十九世纪德国政治变革的核心思想力量。"},{"label":"核心主张/思路","value":"要求宪法、议会、新闻自由、法治、财产权和民族统一，反对专制和邦国分裂。"},{"label":"提出者/代表人物（可选）","value":"大学教授、律师、记者、市民政治家和部分企业家构成主要社会基础。"},{"label":"它从何而来","value":"法国革命、拿破仑战争、教育扩张、市民阶层成长和德意志分裂共同推动自由主义发展。"},{"label":"典型表现","value":"德国瓦尔特堡节、汉巴赫节、法兰克福国民议会、民族自由党。"},{"label":"为什么重要","value":"它是德国统一前最重要的反专制力量之一，但1848失败后逐步分裂，一部分同普鲁士强国家妥协。"},{"label":"争议/局限","value":"德意志自由主义常在民族统一、社会民主和君主制之间摇摆，对工人和妇女权利关注有限。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Liberalismus；German History Documents and Images相关资料；Encyclopaedia Britannica相关资料。"}],"relationItems":["← 前因：德意志学生兄弟会","→ 后果：德国汉巴赫节","→ 后果：德国法兰克福国民议会","↔ 相关：德国民族自由党"],"relations":[{"text":"← 前因：德意志学生兄弟会","id":"extra499"},{"text":"→ 后果：德国汉巴赫节","id":"extra489"},{"text":"→ 后果：德国法兰克福国民议会","id":"extra491"},{"text":"↔ 相关：德国民族自由党","id":"extra674"}],"source":"history","id":"extra501"},{"title":"德意志Vormärz时期","level":"B","type":"概念/思潮卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"通常指1815年至1848年，狭义可指1830年至1848年","place":"德意志邦联","summary":"德意志Vormärz时期是1848革命前德意志社会政治紧张积累期，自由主义、民族主义和十九世纪德国社会问题同步上升。","fields":[{"label":"标题","value":"德意志Vormärz时期"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"通常指1815年至1848年，狭义可指1830年至1848年"},{"label":"地点","value":"德意志邦联"},{"label":"主要国家","value":"德国、奥地利、普鲁士"},{"label":"一句话概括","value":"德意志Vormärz时期是1848革命前德意志社会政治紧张积累期，自由主义、民族主义和十九世纪德国社会问题同步上升。"},{"label":"核心主张/思路","value":"这不是单一思想，而是一个时代标签，指复辟秩序下革命前夜的政治、文化和社会变化。"},{"label":"提出者/代表人物（可选）","value":"德意志“青年德意志”文学运动作家、自由派记者、学生运动、早期工人和民主派。"},{"label":"它从何而来","value":"维也纳秩序压制政治改革，但工业化、人口增长、教育扩张和法国革命影响不断推动社会变化。"},{"label":"典型表现","value":"新闻审查、秘密政治社团、汉巴赫节、德意志“青年德意志”文学运动文学、工人贫困和1840年代社会危机。"},{"label":"为什么重要","value":"Vormärz解释1848革命不是突然爆发，而是长期政治压制和社会变化积累的结果。"},{"label":"争议/局限","value":"不同地区变化差异很大，普鲁士、奥地利、南德和莱茵地区不能简单等同。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Vormärz；German History Documents and Images相关资料。"}],"relationItems":["← 前因：欧洲梅特涅体系","→ 后果：1848年德意志革命","↔ 相关：德意志自由主义","↔ 相关：德意志“青年德意志”文学运动"],"relations":[{"text":"← 前因：欧洲梅特涅体系","id":"extra500"},{"text":"→ 后果：1848年德意志革命","id":"extra490"},{"text":"↔ 相关：德意志自由主义","id":"extra501"},{"text":"↔ 相关：德意志“青年德意志”文学运动","id":"extra503"}],"source":"history","id":"extra502"},{"title":"德意志“青年德意志”文学运动","level":"C","type":"概念/思潮卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1830年代","place":"德意志地区","summary":"德意志“青年德意志”文学运动是德意志Vormärz时期的文学政治潮流，用文学批判审查、宗教保守和社会压抑。","fields":[{"label":"标题","value":"德意志“青年德意志”文学运动"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1830年代"},{"label":"地点","value":"德意志地区"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德意志“青年德意志”文学运动是德意志Vormärz时期的文学政治潮流，用文学批判审查、宗教保守和社会压抑。"},{"label":"核心主张/思路","value":"文学应介入现实，批判专制、教会权威、性别压抑和社会虚伪。"},{"label":"提出者/代表人物（可选）","value":"海因里希·海涅、路德维希·伯尔纳、卡尔·古茨科等常与其相关。"},{"label":"它从何而来","value":"法国七月革命后，德意志青年作家受到自由主义、新闻政治和审查压力影响。"},{"label":"典型表现","value":"政论化文学、旅行书写、讽刺、反教权和社会批判。"},{"label":"为什么重要","value":"它说明德意志政治反抗不只在议会和街头，也在文学、出版和文化批评中展开。"},{"label":"争议/局限","value":"“德意志“青年德意志”文学运动”作为标签部分来自审查者和后世归类，相关作家并非统一组织。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Junges Deutschland；Encyclopaedia Britannica相关资料；German History Documents and Images相关资料。"}],"relationItems":["← 前因：德意志Vormärz时期","↔ 相关：《德意志，一个冬天的童话》","→ 后果：1848年德意志革命"],"relations":[{"text":"← 前因：德意志Vormärz时期","id":"extra502"},{"text":"↔ 相关：《德意志，一个冬天的童话》","id":"extra62"},{"text":"→ 后果：1848年德意志革命","id":"extra490"}],"source":"history","id":"extra503"},{"title":"德意志民族主义","level":"A","type":"概念/思潮卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"十九世纪持续发展，1871年前后转入国家民族主义阶段","place":"德意志地区","summary":"德意志民族主义从文化语言共同体想象出发，逐步转化为追求统一国家和世界地位的政治力量。","fields":[{"label":"标题","value":"德意志民族主义"},{"label":"分级","value":"A"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"十九世纪持续发展，1871年前后转入国家民族主义阶段"},{"label":"地点","value":"德意志地区"},{"label":"主要国家","value":"德国、奥地利、普鲁士"},{"label":"一句话概括","value":"德意志民族主义从文化语言共同体想象出发，逐步转化为追求统一国家和世界地位的政治力量。"},{"label":"核心主张/思路","value":"德语文化、历史记忆和民族共同体应拥有政治表达，最终形成统一国家。"},{"label":"提出者/代表人物（可选）","value":"费希特、阿恩特、雅恩等早期民族主义者；后续被自由派、保守派和帝国主义者分别改造。"},{"label":"它从何而来","value":"拿破仑占领、反法战争、浪漫主义语言文化观和德意志政治分裂共同推动民族意识。"},{"label":"典型表现","value":"体操运动、德意志学生兄弟会、德国黑红金旗帜、汉巴赫节、1848统一诉求、1871帝国成立后的国家民族主义。"},{"label":"为什么重要","value":"它是德国统一的精神动力之一，但也可能从自由解放语言转向排外、帝国主义和种族化政治。"},{"label":"争议/局限","value":"德意志民族主义内部有自由主义、保守主义、民主主义和排外民族主义多种版本。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Nationalbewegung；German History Documents and Images相关资料；Encyclopaedia Britannica相关资料。"}],"relationItems":["← 前因：拿破仑战争","→ 后果：1848年德意志革命","→ 后果：德意志帝国成立","↔ 相关：德国民族使命论"],"relations":[{"text":"← 前因：拿破仑战争","id":"extra918"},{"text":"→ 后果：1848年德意志革命","id":"extra490"},{"text":"→ 后果：德意志帝国成立","id":"extra621"},{"text":"↔ 相关：德国民族使命论","id":"extra622"}],"source":"history","id":"extra504"},{"title":"德国黑红金旗帜","level":"B","type":"概念/思潮卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"十九世纪上半叶成为自由民族运动象征","place":"德意志地区","summary":"德国黑红金旗帜从学生和自由民族运动象征发展为德国共和民主传统的重要颜色。","fields":[{"label":"标题","value":"德国黑红金旗帜"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"十九世纪上半叶成为自由民族运动象征"},{"label":"地点","value":"德意志地区"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国黑红金旗帜从学生和自由民族运动象征发展为德国共和民主传统的重要颜色。"},{"label":"核心主张/思路","value":"黑红金象征德意志统一、自由和公民权利，后来成为共和国合法性和民主传统的视觉符号。"},{"label":"提出者/代表人物（可选）","value":"无单一提出者，与学生运动、自由派集会和1848革命密切相关。"},{"label":"它从何而来","value":"常与反拿破仑战争中的志愿军颜色、学生运动和自由民族主义记忆相联系。"},{"label":"典型表现","value":"德国瓦尔特堡节、汉巴赫节、法兰克福国民议会、魏玛共和国国旗、现代德国国旗。"},{"label":"为什么重要","value":"它把德国民族主义中自由民主的一支可视化。理解德国国旗争论，就是理解德国国家认同争论。"},{"label":"争议/局限","value":"帝国时期黑白红成为官方颜色，黑红金更多代表自由派和共和传统，颜色本身也经历政治争夺。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Schwarz-Rot-Gold；German History Documents and Images相关资料；Bundestag/Bundesregierung相关资料。"}],"relationItems":["← 前因：德意志学生兄弟会","↔ 相关：德国汉巴赫节","↔ 相关：德国法兰克福国民议会","→ 后果：魏玛共和国成立"],"relations":[{"text":"← 前因：德意志学生兄弟会","id":"extra499"},{"text":"↔ 相关：德国汉巴赫节","id":"extra489"},{"text":"↔ 相关：德国法兰克福国民议会","id":"extra491"},{"text":"→ 后果：魏玛共和国成立","id":"card7"}],"source":"history","id":"extra505"},{"title":"弗里德里希·李斯特","level":"B","type":"人物卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"1789年至1846年","place":"德意志地区、美国等","summary":"李斯特是德意志经济民族主义代表人物，强调铁路、关税和生产力对民族国家建设的重要性。","fields":[{"label":"标题","value":"弗里德里希·李斯特"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1789年至1846年"},{"label":"地点","value":"德意志地区、美国等"},{"label":"主要国家","value":"德国、美国"},{"label":"一句话概括","value":"李斯特是德意志经济民族主义代表人物，强调铁路、关税和生产力对民族国家建设的重要性。"},{"label":"生卒年/活跃年代","value":"1789-1846。"},{"label":"身份/职务","value":"经济思想家、政治活动者、铁路和关税统一倡导者。"},{"label":"关键贡献/作为","value":"主张德意志通过关税统一、铁路建设和保护幼稚工业增强民族生产力；著有《政治经济学的国民体系》。"},{"label":"核心主张/立场","value":"反对把自由贸易当作普遍适用教条，强调不同国家发展阶段不同，落后国家需要保护和培育本国工业。"},{"label":"为什么重要","value":"李斯特把经济发展和民族国家建设联系起来，为关税同盟、铁路热和后来的经济民族主义提供思想资源。"},{"label":"争议/评价","value":"其保护主义思想影响广泛，但也可能被后来的国家主义和经济民族主义选择性使用。"},{"label":"关联事件（可选）","value":"德意志关税同盟（Zollverein）、德国铁路建设。"},{"label":"出处","value":"Encyclopaedia Britannica: Friedrich List；German History Documents and Images相关资料；Deutsches Historisches Museum/LeMO相关资料。"}],"relationItems":["↔ 相关：德意志关税同盟（Zollverein）","→ 后果：德国铁路建设","↔ 相关：德意志民族主义"],"relations":[{"text":"↔ 相关：德意志关税同盟（Zollverein）","id":"extra486"},{"text":"→ 后果：德国铁路建设","id":"extra507"},{"text":"↔ 相关：德意志民族主义","id":"extra504"}],"source":"history","id":"extra506"},{"title":"德国铁路建设","level":"A","type":"概念/思潮卡","tags":["经济与社会","战争与外交"],"mainTag":"经济与社会","subTag":"战争与外交","timeText":"1830年代起快速发展，十九世纪后期形成密集网络","place":"德意志地区","summary":"德国铁路建设连接市场、工业、军队和国家能力，是十九世纪德意志经济统一和军事动员的基础设施。","fields":[{"label":"标题","value":"德国铁路建设"},{"label":"分级","value":"A"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1830年代起快速发展，十九世纪后期形成密集网络"},{"label":"地点","value":"德意志地区"},{"label":"主要国家","value":"德国、普鲁士"},{"label":"一句话概括","value":"德国铁路建设连接市场、工业、军队和国家能力，是十九世纪德意志经济统一和军事动员的基础设施。"},{"label":"核心主张/思路","value":"铁路不是单一事件，而是一种基础设施革命：降低运输成本、扩大市场、加速人员和军队移动。"},{"label":"提出者/代表人物（可选）","value":"弗里德里希·李斯特积极倡导铁路网络；各邦政府和私人资本共同建设。"},{"label":"它从何而来","value":"工业化、煤铁生产、城市市场和关税同盟扩大了对运输网络的需求。"},{"label":"典型表现","value":"1835年纽伦堡至菲尔特铁路，随后普鲁士和德意志各地铁路快速扩张。"},{"label":"为什么重要","value":"铁路把分散邦国经济更紧密地连接起来，也让普鲁士在1866年和1870年战争中获得动员优势。"},{"label":"争议/局限","value":"早期铁路由各邦和私人分散建设，标准、线路和战略目标不完全一致。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Eisenbahn；German History Documents and Images相关资料；Encyclopaedia Britannica相关资料。"}],"relationItems":["← 前因：德意志关税同盟（Zollverein）","↔ 相关：弗里德里希·李斯特","→ 后果：普奥战争","→ 后果：普法战争"],"relations":[{"text":"← 前因：德意志关税同盟（Zollverein）","id":"extra486"},{"text":"↔ 相关：弗里德里希·李斯特","id":"extra506"},{"text":"→ 后果：普奥战争","id":"extra495"},{"text":"→ 后果：普法战争","id":"extra497"}],"source":"history","id":"extra507"},{"title":"纽伦堡-菲尔特铁路","level":"C","type":"事件卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"1835年12月7日开通","place":"巴伐利亚纽伦堡至菲尔特","summary":"纽伦堡-菲尔特铁路是德意志地区第一条蒸汽客运铁路，象征铁路时代进入德国。","fields":[{"label":"标题","value":"纽伦堡-菲尔特铁路"},{"label":"分级","value":"C"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1835年12月7日开通"},{"label":"地点","value":"巴伐利亚纽伦堡至菲尔特"},{"label":"主要国家","value":"德国、巴伐利亚"},{"label":"一句话概括","value":"纽伦堡-菲尔特铁路是德意志地区第一条蒸汽客运铁路，象征铁路时代进入德国。"},{"label":"参与者","value":"巴伐利亚商人和投资者、铁路公司、工程技术人员、乘客。"},{"label":"发生了什么","value":"1835年，连接纽伦堡和菲尔特的短途铁路开通，使用英国制造的“阿德勒”机车牵引客车。线路长度不长，但公众关注度高，展示了蒸汽动力运输的速度和现代性。起初它更像商业和技术展示，随后铁路建设在德意志各邦迅速扩大。铁路很快从新奇交通工具转化为市场整合、工业运输和军事动员的关键基础设施。"},{"label":"为什么重要","value":"它是德国铁路时代的象征性起点，帮助社会想象速度、工业和空间整合的新可能。"},{"label":"前因","value":"工业革命技术、李斯特等人关于铁路和全国市场的设想，以及关税同盟降低邦国贸易障碍，共同为德意志铁路建设提供了条件。"},{"label":"后果","value":"铁路缩短了地区间运输时间，推动市场整合和工业投资，也让铁路网络成为日后德意志经济统一和国家动员的重要基础设施。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Erste Eisenbahn；German History Documents and Images相关资料；DB Museum相关资料。"}],"relationItems":["→ 后果：德国铁路建设","↔ 相关：弗里德里希·李斯特"],"relations":[{"text":"→ 后果：德国铁路建设","id":"extra507"},{"text":"↔ 相关：弗里德里希·李斯特","id":"extra506"}],"source":"history","id":"extra508"},{"title":"柏林博尔西希机械厂","level":"C","type":"组织/机构卡","tags":["经济与社会","无"],"mainTag":"经济与社会","subTag":"无","timeText":"1837年创立","place":"普鲁士柏林","summary":"柏林博尔西希机械厂是德国早期机械制造和机车工业代表，体现普鲁士工业化的技术追赶。","fields":[{"label":"标题","value":"柏林博尔西希机械厂"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"无"},{"label":"时间","value":"1837年创立"},{"label":"地点","value":"普鲁士柏林"},{"label":"主要国家","value":"德国、普鲁士"},{"label":"一句话概括","value":"柏林博尔西希机械厂是德国早期机械制造和机车工业代表，体现普鲁士工业化的技术追赶。"},{"label":"性质/类型","value":"机械制造企业、机车制造企业。"},{"label":"成立/解散时间","value":"1837年由奥古斯特·博尔西希创立。"},{"label":"核心目标/宗旨","value":"生产机械设备和蒸汽机车，满足铁路和工业化需求。"},{"label":"关键人物（可选）","value":"奥古斯特·博尔西希。"},{"label":"关键行动/事件","value":"制造德国本土机车，推动柏林机械工业发展。"},{"label":"为什么重要","value":"它说明德国工业化不是只有重工业和煤钢，也包括机械制造、工程技术和企业组织能力。"},{"label":"争议/局限","value":"企业发展依赖铁路扩张和国家工业环境，不能单独解释德国工业崛起。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Borsig；German History Documents and Images相关资料；Encyclopaedia Britannica相关资料。"}],"relationItems":["← 前因：德国铁路建设","↔ 相关：西门子与德国电气工业"],"relations":[{"text":"← 前因：德国铁路建设","id":"extra507"},{"text":"↔ 相关：西门子与德国电气工业","id":"extra682"}],"source":"history","id":"extra509"},{"title":"西里西亚织工起义","level":"B","type":"事件卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1844年6月","place":"普鲁士西里西亚","summary":"西里西亚织工起义是工业化和家庭手工业危机下的社会抗议，暴露德意志Vormärz时期的贫困与十九世纪德国社会问题。","fields":[{"label":"标题","value":"西里西亚织工起义"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1844年6月"},{"label":"地点","value":"普鲁士西里西亚"},{"label":"主要国家","value":"普鲁士、德国"},{"label":"一句话概括","value":"西里西亚织工起义是工业化和家庭手工业危机下的社会抗议，暴露德意志Vormärz时期的贫困与十九世纪德国社会问题。"},{"label":"参与者","value":"西里西亚织工、工厂主和商人、普鲁士军警。"},{"label":"发生了什么","value":"十九世纪四十年代，西里西亚家庭织工受到机器生产、商人压价和市场竞争冲击，收入急剧下降。1844年6月，织工在彼得斯瓦尔道等地抗议工资和贫困，袭击厂主住宅和仓库，破坏账册和财物。普鲁士军队介入镇压，造成伤亡和逮捕。事件很快引发德意志知识界关注，海涅等人以文学形式表现织工苦难，把十九世纪德国社会问题推向公共讨论。"},{"label":"为什么重要","value":"它表明1848前的危机不只是宪政和民族统一问题，也包括早期工业化造成的社会贫困和阶级冲突。"},{"label":"前因","value":"早期工业化和国际竞争压低了家庭手工业收入，织工在承包商体系中缺乏议价能力，贫困和价格压力最终转化为暴力抗议。"},{"label":"后果","value":"起义被镇压后，德意志社会开始更集中地讨论工业化贫困和“社会问题”；这种社会不满也成为1848年革命前夕公共舆论的一部分。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Weberaufstand；German History Documents and Images相关资料；Encyclopaedia Britannica相关资料。"}],"relationItems":["← 前因：德意志Vormärz时期","→ 后果：1848年德意志革命","↔ 相关：马克思恩格斯《共产党宣言》"],"relations":[{"text":"← 前因：德意志Vormärz时期","id":"extra502"},{"text":"→ 后果：1848年德意志革命","id":"extra490"},{"text":"↔ 相关：马克思恩格斯《共产党宣言》","id":"extra61"}],"source":"history","id":"extra510"},{"title":"十九世纪德国社会问题","level":"B","type":"概念/思潮卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"十九世纪，尤其工业化加速后","place":"欧洲工业化地区，德意志地区尤为突出","summary":"“十九世纪德国社会问题”指工业化和人口增长带来的贫困、住房、劳动和阶级冲突，成为十九世纪政治改革的核心议题。","fields":[{"label":"标题","value":"十九世纪德国社会问题"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"十九世纪，尤其工业化加速后"},{"label":"地点","value":"欧洲工业化地区，德意志地区尤为突出"},{"label":"主要国家","value":"德国、英国、法国"},{"label":"一句话概括","value":"“十九世纪德国社会问题”指工业化和人口增长带来的贫困、住房、劳动和阶级冲突，成为十九世纪政治改革的核心议题。"},{"label":"核心主张/思路","value":"传统慈善和行会秩序无法处理工业资本主义造成的大规模贫困和劳动风险，国家和社会必须寻找新制度回应。"},{"label":"提出者/代表人物（可选）","value":"保守社会改革者、自由派、社会主义者、教会人士和工人运动都提出不同方案。"},{"label":"它从何而来","value":"人口增长、农村贫困、城市化、工厂劳动、家庭手工业衰落和经济周期波动。"},{"label":"典型表现","value":"工人贫困、童工、住房拥挤、疾病、失业、罢工和早期社会主义思想。"},{"label":"为什么重要","value":"它把工业化从经济增长问题变成政治合法性问题。德国后来的工人运动、社会保险和社会主义政党都围绕它发展。"},{"label":"争议/局限","value":"不同政治阵营对“十九世纪德国社会问题”的解释不同：有人强调道德救济，有人强调国家干预，有人强调阶级斗争。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Soziale Frage；German History Documents and Images相关资料；Encyclopaedia Britannica相关资料。"}],"relationItems":["← 前因：西里西亚织工起义","→ 后果：德国社会民主党（SPD）","→ 后果：德国俾斯麦社会保险立法"],"relations":[{"text":"← 前因：西里西亚织工起义","id":"extra510"},{"text":"→ 后果：德国社会民主党（SPD）","id":"extra628"},{"text":"→ 后果：德国俾斯麦社会保险立法","id":"extra629"}],"source":"history","id":"extra511"},{"title":"德国全德工人联合会","level":"B","type":"组织/机构卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1863年成立","place":"德意志地区","summary":"德国全德工人联合会是德国早期工人政党组织，拉萨尔派传统为后来德国社会民主党奠定基础。","fields":[{"label":"标题","value":"德国全德工人联合会"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1863年成立"},{"label":"地点","value":"德意志地区"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国全德工人联合会是德国早期工人政党组织，拉萨尔派传统为后来德国社会民主党奠定基础。"},{"label":"性质/类型","value":"工人政治组织、早期社会主义政党。"},{"label":"成立/解散时间","value":"1863年由拉萨尔推动成立；1875年与德国社会主义爱森纳赫派合并。"},{"label":"核心目标/宗旨","value":"争取普选权、工人政治代表和国家支持的生产合作社。"},{"label":"关键人物（可选）","value":"费迪南德·拉萨尔。"},{"label":"关键行动/事件","value":"组织工人政治动员，强调通过国家和普选权改善工人处境。"},{"label":"为什么重要","value":"它标志德国工人运动从互助和教育团体走向独立政治组织。"},{"label":"争议/局限","value":"拉萨尔派对国家作用抱有较高期待，与马克思主义和德国社会主义爱森纳赫派存在路线分歧。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Allgemeiner Deutscher Arbeiterverein；German History Documents and Images相关资料；Encyclopaedia Britannica相关资料。"}],"relationItems":["← 前因：十九世纪德国社会问题","→ 后果：德国社会民主党（SPD）","↔ 相关：费迪南德·拉萨尔"],"relations":[{"text":"← 前因：十九世纪德国社会问题","id":"extra511"},{"text":"→ 后果：德国社会民主党（SPD）","id":"extra628"},{"text":"↔ 相关：费迪南德·拉萨尔","id":"extra513"}],"source":"history","id":"extra512"},{"title":"费迪南德·拉萨尔","level":"B","type":"人物卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1825年至1864年","place":"德意志地区","summary":"拉萨尔是德国早期工人运动领袖，推动德国全德工人联合会成立并强调普选权和国家援助。","fields":[{"label":"标题","value":"费迪南德·拉萨尔"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1825年至1864年"},{"label":"地点","value":"德意志地区"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"拉萨尔是德国早期工人运动领袖，推动德国全德工人联合会成立并强调普选权和国家援助。"},{"label":"生卒年/活跃年代","value":"1825-1864。"},{"label":"身份/职务","value":"社会主义活动家、工人运动领袖、政治宣传家。"},{"label":"关键贡献/作为","value":"推动1863年德国全德工人联合会成立，提出通过普选权和国家支持改善工人状况。"},{"label":"核心主张/立场","value":"强调工人独立政治组织、普选权和国家帮助生产合作社。"},{"label":"为什么重要","value":"拉萨尔使德国工人运动获得组织形式和政治语言，是德国社会民主主义前史的关键人物。"},{"label":"争议/评价","value":"马克思和恩格斯批评其国家观和策略，但拉萨尔派在德国工人运动中影响深远。"},{"label":"关联事件（可选）","value":"德国全德工人联合会、德国社会民主党（SPD）。"},{"label":"出处","value":"Encyclopaedia Britannica: Ferdinand Lassalle；Deutsches Historisches Museum/LeMO相关资料；German History Documents and Images相关资料。"}],"relationItems":["→ 后果：德国全德工人联合会","→ 后果：德国社会民主党（SPD）","↔ 相关：十九世纪德国社会问题"],"relations":[{"text":"→ 后果：德国全德工人联合会","id":"extra512"},{"text":"→ 后果：德国社会民主党（SPD）","id":"extra628"},{"text":"↔ 相关：十九世纪德国社会问题","id":"extra511"}],"source":"history","id":"extra513"},{"title":"德国社会主义爱森纳赫派","level":"C","type":"组织/机构卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1869年至1875年","place":"德意志地区","summary":"德国社会主义爱森纳赫派是德国早期马克思主义倾向工人政党，与拉萨尔派合并后形成德国社民党前身。","fields":[{"label":"标题","value":"德国社会主义爱森纳赫派"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1869年至1875年"},{"label":"地点","value":"德意志地区"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国社会主义爱森纳赫派是德国早期马克思主义倾向工人政党，与拉萨尔派合并后形成德国社民党前身。"},{"label":"性质/类型","value":"社会主义工人政党。"},{"label":"成立/解散时间","value":"1869年成立社会民主工人党；1875年与德国全德工人联合会合并。"},{"label":"核心目标/宗旨","value":"组织工人阶级争取政治权利、社会改革和社会主义目标，较强调国际主义和马克思主义影响。"},{"label":"关键人物（可选）","value":"奥古斯特·倍倍尔、威廉·李卜克内西。"},{"label":"关键行动/事件","value":"参与工人运动组织和选举政治；1875年哥达合并。"},{"label":"为什么重要","value":"它是德国社会民主党形成中的另一条来源，代表比拉萨尔派更接近马克思主义和国际主义的传统。"},{"label":"争议/局限","value":"与拉萨尔派在国家、策略和纲领上有分歧，合并后仍存在理论张力。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Sozialdemokratische Arbeiterpartei；German History Documents and Images相关资料。"}],"relationItems":["← 前因：十九世纪德国社会问题","→ 后果：德国社会民主党（SPD）","↔ 相关：德国全德工人联合会"],"relations":[{"text":"← 前因：十九世纪德国社会问题","id":"extra511"},{"text":"→ 后果：德国社会民主党（SPD）","id":"extra628"},{"text":"↔ 相关：德国全德工人联合会","id":"extra512"}],"source":"history","id":"extra514"},{"title":"德国洪堡大学模式","level":"B","type":"概念/思潮卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"十九世纪形成，十九世纪后期影响扩大","place":"普鲁士、德意志帝国","summary":"洪堡大学模式强调研究与教学结合，使德国大学成为十九世纪世界高等教育和科学研究的样板。","fields":[{"label":"标题","value":"德国洪堡大学模式"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"十九世纪形成，十九世纪后期影响扩大"},{"label":"地点","value":"普鲁士、德意志帝国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"洪堡大学模式强调研究与教学结合，使德国大学成为十九世纪世界高等教育和科学研究的样板。"},{"label":"核心主张/思路","value":"大学不只是职业训练机构，而应通过学术自由、研究训练和教学结合来生产新知识。"},{"label":"提出者/代表人物（可选）","value":"威廉·冯·洪堡；柏林大学及德语大学体系。"},{"label":"它从何而来","value":"普鲁士教育改革、启蒙学术理想和国家现代化需求。"},{"label":"典型表现","value":"研究型教授职位、研讨班制度、博士训练、实验室和学术专业化。"},{"label":"为什么重要","value":"它解释德国为什么能在十九世纪末成为医学、化学、物理和历史学研究中心，也影响美国和日本等国大学改革。"},{"label":"争议/局限","value":"学术自由理想与国家资助、民族主义和社会排斥并存，女性和低阶层长期难以平等进入大学。"},{"label":"出处","value":"Encyclopaedia Britannica，Wilhelm von Humboldt materials；German History in Documents and Images，education and universities materials。"}],"relationItems":["← 前因：普鲁士教育改革","← 前因：德意志自由主义","→ 后果：罗伯特·科赫发现结核杆菌","→ 后果：普朗克量子假说","↔ 相关：德国大学研究体系","↔ 相关：德国化学工业","✗ 对立/冲突：学术自由","✗ 对立/冲突：国家教育管理","↔ 同时期参考：德国民法典"],"relations":[{"text":"← 前因：德意志自由主义","id":"extra501"},{"text":"→ 后果：罗伯特·科赫发现结核杆菌","id":"extra811"},{"text":"→ 后果：普朗克量子假说","id":"extra722"},{"text":"↔ 相关：德国大学研究体系","id":"extra935"},{"text":"↔ 相关：德国化学工业","id":"extra680"},{"text":"↔ 同时期参考：德国民法典","id":"extra720"}],"source":"history","id":"extra515"},{"title":"德国幼儿园运动","level":"C","type":"概念/思潮卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"十九世纪中期兴起，帝德时期继续扩展","place":"德语地区与德国城市","summary":"德国幼儿园运动把儿童早期教育视为专门事业，改变家庭、教育和社会改革之间的关系。","fields":[{"label":"标题","value":"德国幼儿园运动"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"十九世纪中期兴起，帝德时期继续扩展"},{"label":"地点","value":"德语地区与德国城市"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国幼儿园运动把儿童早期教育视为专门事业，改变家庭、教育和社会改革之间的关系。"},{"label":"核心主张/思路","value":"幼儿需要通过游戏、手工、歌唱和集体活动得到适龄发展，而不是过早接受机械识字训练。"},{"label":"提出者/代表人物（可选）","value":"弗里德里希·福禄贝尔。"},{"label":"它从何而来","value":"浪漫主义儿童观、教育改革、城市中产家庭需求和女性教育职业空间扩大。"},{"label":"典型表现","value":"Kindergarten 一词和制度向欧美传播，幼儿教师培训、玩具教具和集体游戏成为教育方法。"},{"label":"为什么重要","value":"它让“儿童期”成为现代社会政策和教育学关注对象，也为女性进入教育职业提供空间。"},{"label":"争议/局限","value":"早期幼儿园多服务城市中产阶层，工人家庭儿童照护问题仍依赖慈善、教会或地方福利。"},{"label":"出处","value":"Encyclopaedia Britannica，“Friedrich Froebel”；Froebel Trust，kindergarten history materials。"}],"relationItems":["← 前因：德意志Vormärz时期","← 前因：德国妇女运动","→ 后果：魏玛《全国青少年福利法》","↔ 相关：德国消费合作社运动","↔ 相关：十九世纪德国社会问题","✗ 对立/冲突：家庭私域教育","✗ 对立/冲突：公共儿童教育","↔ 同时期参考：洪堡大学模式"],"relations":[{"text":"← 前因：德意志Vormärz时期","id":"extra502"},{"text":"← 前因：德国妇女运动","id":"extra684"},{"text":"→ 后果：魏玛《全国青少年福利法》","id":"card73"},{"text":"↔ 相关：德国消费合作社运动","id":"extra728"},{"text":"↔ 相关：十九世纪德国社会问题","id":"extra511"}],"source":"history","id":"extra516"},{"title":"德国体操运动","level":"C","type":"概念/思潮卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"十九世纪初兴起，帝德时期社团化发展","place":"德语地区、德意志帝国","summary":"德国体操运动把身体训练、社团生活和民族教育结合起来，是现代体育与民族主义交织的早期形式。","fields":[{"label":"标题","value":"德国体操运动"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"十九世纪初兴起，帝德时期社团化发展"},{"label":"地点","value":"德语地区、德意志帝国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国体操运动把身体训练、社团生活和民族教育结合起来，是现代体育与民族主义交织的早期形式。"},{"label":"核心主张/思路","value":"通过体操锻炼强健身体、培养纪律和共同体意识，并服务民族复兴理想。"},{"label":"提出者/代表人物（可选）","value":"弗里德里希·路德维希·雅恩。"},{"label":"它从何而来","value":"拿破仑战争后的民族动员、青年社团、教育改革和市民社会组织。"},{"label":"典型表现","value":"Turnverein 体操协会、体操节、集体操练、青年男性社交和民族象征。"},{"label":"为什么重要","value":"它说明体育并不只是娱乐，也可以成为现代国家、民族身份和公民身体训练的一部分。"},{"label":"争议/局限","value":"运动中自由主义、民族主义和排外倾向交织，女性和少数群体参与长期受限。"},{"label":"出处","value":"Encyclopaedia Britannica，“Friedrich Ludwig Jahn”；German History in Documents and Images，gymnastics and nationalism materials。"}],"relationItems":["← 前因：德国瓦尔特堡节","← 前因：德意志民族主义","→ 后果：德国青年运动","→ 后果：魏玛德国大众体育文化","↔ 相关：德意志学生兄弟会","↔ 相关：德国裸体文化运动","✗ 对立/冲突：身体自由训练","✗ 对立/冲突：国家纪律化身体","↔ 同时期参考：德国幼儿园运动"],"relations":[{"text":"← 前因：德国瓦尔特堡节","id":"extra498"},{"text":"← 前因：德意志民族主义","id":"extra504"},{"text":"→ 后果：德国青年运动","id":"extra685"},{"text":"→ 后果：魏玛德国大众体育文化","id":"card86"},{"text":"↔ 相关：德意志学生兄弟会","id":"extra499"},{"text":"↔ 相关：德国裸体文化运动","id":"extra727"},{"text":"↔ 同时期参考：德国幼儿园运动","id":"extra516"}],"source":"history","id":"extra517"},{"title":"德国合作银行运动","level":"C","type":"组织/机构卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"十九世纪中期兴起，帝德时期扩展","place":"德语地区和德意志帝国","summary":"德国合作银行运动通过会员互助信贷服务小农、手工业者和小商人，是金融社会化的重要形式。","fields":[{"label":"标题","value":"德国合作银行运动"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"十九世纪中期兴起，帝德时期扩展"},{"label":"地点","value":"德语地区和德意志帝国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国合作银行运动通过会员互助信贷服务小农、手工业者和小商人，是金融社会化的重要形式。"},{"label":"性质/类型","value":"信用合作社和互助金融组织网络。"},{"label":"成立/解散时间","value":"十九世纪中期由多地实践兴起，帝德时期制度化和规模化。"},{"label":"核心目标/宗旨","value":"通过会员共同担保、储蓄和贷款，为难以获得商业银行服务的小生产者提供信用。"},{"label":"关键人物（可选）","value":"弗里德里希·威廉·赖夫艾森；赫尔曼·舒尔茨-德利奇。"},{"label":"关键行动/事件","value":"发展农村信用合作社、城市手工业信用社和合作金融联合组织。"},{"label":"为什么重要","value":"它把德国社会问题延伸到信贷和小生产者生存层面，也影响欧洲合作金融传统。"},{"label":"争议/局限","value":"互助金融能缓解小生产者困境，但无法从根本上阻止资本集中和农业市场压力。"},{"label":"出处","value":"International Cooperative Alliance，cooperative history；Deutsches Historisches Museum/LeMO，cooperative movement materials。"}],"relationItems":["← 前因：十九世纪德国社会问题","← 前因：德国消费合作社运动","→ 后果：德国社会市场经济传统","↔ 相关：德意志关税同盟（Zollverein）","↔ 相关：德国历史学派经济学","✗ 对立/冲突：商业银行集中","✗ 对立/冲突：合作互助金融","↔ 同时期参考：德国百货商店兴起"],"relations":[{"text":"← 前因：十九世纪德国社会问题","id":"extra511"},{"text":"← 前因：德国消费合作社运动","id":"extra728"},{"text":"↔ 相关：德意志关税同盟（Zollverein）","id":"extra486"},{"text":"↔ 相关：德国历史学派经济学","id":"extra734"},{"text":"↔ 同时期参考：德国百货商店兴起","id":"extra730"}],"source":"history","id":"extra518"},{"title":"恩斯特·海克尔","level":"C","type":"人物卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1834年—1919年","place":"德语学术界，尤其耶拿","summary":"恩斯特·海克尔推广达尔文进化论，也把生物学观念带入世界观、社会思想和争议性种族理论。","fields":[{"label":"标题","value":"恩斯特·海克尔"},{"label":"分级","value":"C"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1834年—1919年"},{"label":"地点","value":"德语学术界，尤其耶拿"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"恩斯特·海克尔推广达尔文进化论，也把生物学观念带入世界观、社会思想和争议性种族理论。"},{"label":"生卒年/活跃年代","value":"1834年生，1919年卒；十九世纪后半叶至一战前活跃。"},{"label":"身份/职务","value":"生物学家、进化论传播者、科普作者。"},{"label":"关键贡献/作为","value":"在德语世界传播达尔文主义，提出生态学等概念，并通过图像和通俗著作扩大进化论影响。"},{"label":"核心主张/立场","value":"主张以进化论解释生命和自然秩序，并倾向把科学发展为整体世界观。"},{"label":"为什么重要","value":"他帮助进化论进入德国大众文化，但其思想也显示科学概念如何被社会达尔文主义、种族主义和民族主义误用。"},{"label":"争议/评价","value":"海克尔的胚胎图、种族分类和一元论世界观争议很大，不能把他简单视为纯粹科学英雄。"},{"label":"关联事件（可选）","value":"德国大学研究体系；社会达尔文主义传播。"},{"label":"出处","value":"Encyclopaedia Britannica，“Ernst Haeckel”；University of California Museum of Paleontology，Haeckel materials。"}],"relationItems":["← 前因：德国洪堡大学模式","← 前因：达尔文进化论","→ 后果：德意志生命改革运动","→ 后果：纳粹优生政策","↔ 相关：德国历史学派经济学","↔ 相关：普朗克量子假说","✗ 对立/冲突：科学解释","✗ 对立/冲突：社会政治误用","↔ 同时期参考：罗伯特·科赫发现结核杆菌"],"relations":[{"text":"← 前因：德国洪堡大学模式","id":"extra515"},{"text":"→ 后果：德意志生命改革运动","id":"extra726"},{"text":"→ 后果：纳粹优生政策","id":"extra118"},{"text":"↔ 相关：德国历史学派经济学","id":"extra734"},{"text":"↔ 相关：普朗克量子假说","id":"extra722"},{"text":"↔ 同时期参考：罗伯特·科赫发现结核杆菌","id":"extra811"}],"source":"history","id":"extra519"},{"title":"神圣罗马帝国解体","level":"A","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1806年","place":"中欧德意志地区","summary":"神圣罗马帝国解体结束了延续近千年的帝国框架，为十九世纪“德意志统一与奥普领导权问题”打开制度真空。","fields":[{"label":"标题","value":"神圣罗马帝国解体"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1806年"},{"label":"地点","value":"中欧德意志地区"},{"label":"主要国家","value":"奥地利、法国、德意志诸邦"},{"label":"一句话概括","value":"神圣罗马帝国解体结束了延续近千年的帝国框架，为十九世纪“德意志统一与奥普领导权问题”打开制度真空。"},{"label":"参与者","value":"弗朗茨二世；拿破仑法国；德意志诸邦。"},{"label":"发生了什么","value":"拿破仑战争重塑中欧秩序，许多德意志邦国脱离旧帝国体系并加入法国主导的莱茵邦。1806年，神圣罗马皇帝弗朗茨二世放弃帝号，神圣罗马帝国正式终结。德意志地区不再拥有传统帝国名义上的共同政治外壳，诸邦主权和法国霸权成为新的现实。"},{"label":"为什么重要","value":"它是理解1815年后德意志统一与奥普领导权问题的前提：德意志到底应成为松散邦联、民族国家，还是由奥地利或普鲁士主导的新秩序。"},{"label":"前因","value":"拿破仑战争摧毁了旧帝国的军事和政治权威，莱茵邦的建立使许多德意志邦国脱离皇帝体系并转向法国保护。"},{"label":"后果","value":"旧帝国终结后，德意志地区不再有传统帝国框架，如何在邦国分裂和民族统一之间重建秩序成为十九世纪的“德意志统一与奥普领导权问题”。"},{"label":"出处","value":"Encyclopaedia Britannica，“Holy Roman Empire”；German History in Documents and Images，Napoleonic Germany materials。"}],"relationItems":["← 前因：拿破仑战争","→ 后果：拿破仑莱茵邦","→ 后果：德意志邦联","↔ 相关：欧洲梅特涅体系","↔ 相关：德意志民族主义","✗ 对立/冲突：旧帝国秩序","✗ 对立/冲突：拿破仑重组中欧","↔ 同时期参考：普鲁士施泰因-哈登贝格改革"],"relations":[{"text":"← 前因：拿破仑战争","id":"extra918"},{"text":"→ 后果：拿破仑莱茵邦","id":"extra521"},{"text":"→ 后果：德意志邦联","id":"extra487"},{"text":"↔ 相关：欧洲梅特涅体系","id":"extra500"},{"text":"↔ 相关：德意志民族主义","id":"extra504"},{"text":"↔ 同时期参考：普鲁士施泰因-哈登贝格改革","id":"extra522"}],"source":"history","id":"extra520"},{"title":"拿破仑莱茵邦","level":"B","type":"组织/机构卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1806年—1813年","place":"中欧德意志地区","summary":"莱茵邦是拿破仑主导的德意志邦国联盟，削弱旧帝国和奥地利影响，却也推动德意志地区制度重组。","fields":[{"label":"标题","value":"拿破仑莱茵邦"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1806年—1813年"},{"label":"地点","value":"中欧德意志地区"},{"label":"主要国家","value":"法国、德意志诸邦"},{"label":"一句话概括","value":"莱茵邦是拿破仑主导的德意志邦国联盟，削弱旧帝国和奥地利影响，却也推动德意志地区制度重组。"},{"label":"性质/类型","value":"法国保护下的德意志邦国联盟。"},{"label":"成立/解散时间","value":"1806年成立，1813年拿破仑失败后瓦解。"},{"label":"核心目标/宗旨","value":"把一批德意志邦国纳入法国霸权体系，提供军事支持并重组中欧政治秩序。"},{"label":"关键人物（可选）","value":"拿破仑；南德和西德诸邦统治者。"},{"label":"关键行动/事件","value":"成员邦退出神圣罗马帝国，进行行政、法律和社会制度改革，并向法国提供军队。"},{"label":"为什么重要","value":"它既是法国控制工具，也是德意志地区现代化和主权邦国重组的催化剂。"},{"label":"争议/局限","value":"莱茵邦不是民族统一运动，而是法国霸权下的诸邦联盟，激起反法民族情绪。"},{"label":"出处","value":"Encyclopaedia Britannica，“Confederation of the Rhine”；German History in Documents and Images，Confederation of the Rhine materials。"}],"relationItems":["← 前因：神圣罗马帝国解体","→ 后果：德意志解放战争","→ 后果：德意志邦联","↔ 相关：拿破仑战争与德意志民族意识","↔ 相关：普鲁士施泰因-哈登贝格改革","✗ 对立/冲突：法国霸权","✗ 对立/冲突：德意志反法民族动员","↔ 同时期参考：普鲁士施泰因-哈登贝格改革"],"relations":[{"text":"← 前因：神圣罗马帝国解体","id":"extra520"},{"text":"→ 后果：德意志解放战争","id":"extra523"},{"text":"→ 后果：德意志邦联","id":"extra487"},{"text":"↔ 相关：普鲁士施泰因-哈登贝格改革","id":"extra522"},{"text":"✗ 对立/冲突：法国霸权","id":"extra868"},{"text":"✗ 对立/冲突：德意志反法民族动员","id":"extra588"},{"text":"↔ 同时期参考：普鲁士施泰因-哈登贝格改革","id":"extra522"}],"source":"history","id":"extra521"},{"title":"普鲁士施泰因-哈登贝格改革","level":"A","type":"事件卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1807年—1815年前后","place":"普鲁士王国","summary":"施泰因-普鲁士哈登贝格改革在普鲁士战败后推动行政、农奴制、城市自治和军政改革，为普鲁士崛起奠基。","fields":[{"label":"标题","value":"普鲁士施泰因-哈登贝格改革"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1807年—1815年前后"},{"label":"地点","value":"普鲁士王国"},{"label":"主要国家","value":"普鲁士"},{"label":"一句话概括","value":"施泰因-普鲁士哈登贝格改革在普鲁士战败后推动行政、农奴制、城市自治和军政改革，为普鲁士崛起奠基。"},{"label":"参与者","value":"施泰因、哈登贝格、普鲁士王室、官僚和军政改革派。"},{"label":"发生了什么","value":"普鲁士在耶拿-奥尔施泰特战败后被迫反思旧制度。改革派推动废除或松动农奴制、开放职业和土地流动、改革城市自治、重组行政体系，并与军制改革相配合。改革并不彻底，也受到贵族利益限制，但显著提升了普鲁士国家动员和治理能力。"},{"label":"为什么重要","value":"它解释普鲁士为何能在十九世纪中后期成为德意志统一的核心力量。"},{"label":"前因","value":"普鲁士在拿破仑战争中惨败，暴露出等级制度、军政体制和社会动员能力的缺陷，改革派因此获得推动国家改造的空间。"},{"label":"后果","value":"改革释放了部分社会和行政活力，为解放战争中的国家动员、普鲁士军制改革和后来的宪政冲突提供了制度背景。"},{"label":"出处","value":"German History in Documents and Images，Stein-Hardenberg reforms；Encyclopaedia Britannica，Prussia materials。"}],"relationItems":["← 前因：拿破仑莱茵邦","← 前因：神圣罗马帝国解体","→ 后果：德意志解放战争","→ 后果：普鲁士军制改革","↔ 相关：普鲁士国家传统","↔ 相关：德国洪堡大学模式","✗ 对立/冲突：旧贵族特权","✗ 对立/冲突：国家改革动员","↔ 同时期参考：德意志民族主义"],"relations":[{"text":"← 前因：拿破仑莱茵邦","id":"extra521"},{"text":"← 前因：神圣罗马帝国解体","id":"extra520"},{"text":"→ 后果：德意志解放战争","id":"extra523"},{"text":"→ 后果：普鲁士军制改革","id":"extra536"},{"text":"↔ 相关：德国洪堡大学模式","id":"extra515"},{"text":"↔ 同时期参考：德意志民族主义","id":"extra504"}],"source":"history","id":"extra522"},{"title":"德意志解放战争","level":"A","type":"事件卡","tags":["战争与外交","文化与思想"],"mainTag":"战争与外交","subTag":"文化与思想","timeText":"1813年—1814年","place":"德意志地区及中欧战场","summary":"德意志解放战争把反拿破仑战争与民族动员结合起来，成为十九世纪德意志民族主义的重要记忆来源。","fields":[{"label":"标题","value":"德意志解放战争"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1813年—1814年"},{"label":"地点","value":"德意志地区及中欧战场"},{"label":"主要国家","value":"普鲁士、奥地利、俄罗斯、法国、德意志诸邦"},{"label":"一句话概括","value":"德意志解放战争把反拿破仑战争与民族动员结合起来，成为十九世纪德意志民族主义的重要记忆来源。"},{"label":"参与者","value":"普鲁士、奥地利、俄罗斯等反法联盟；拿破仑法国；德意志志愿军和学生群体。"},{"label":"发生了什么","value":"拿破仑在俄国失败后，普鲁士等力量加入反法联盟。德意志地区出现志愿军、民族宣传和反法动员，战争在莱比锡等地达到高潮。法国势力被逐出大部分德意志地区，拿破仑体系瓦解，为维也纳会议重建欧洲秩序铺路。"},{"label":"为什么重要","value":"它使“德意志民族”成为政治想象和战争动员语言，但战争结果并没有直接带来民族国家。"},{"label":"前因","value":"拿破仑控制下的莱茵邦和法国霸权激起德意志反法情绪，普鲁士改革增强了国家动员能力，俄法战争失败又削弱了拿破仑统治。"},{"label":"后果","value":"反法战争的胜利把德意志统一与奥普领导权问题带入维也纳会议，但会议恢复的是邦联而非统一民族国家，这使民族主义期待继续在学生和自由派中发酵。"},{"label":"出处","value":"Encyclopaedia Britannica，German Campaign of 1813 materials；German History in Documents and Images，Wars of Liberation materials。"}],"relationItems":["← 前因：拿破仑莱茵邦","← 前因：普鲁士施泰因-哈登贝格改革","→ 后果：拿破仑战后维也纳会议","→ 后果：德国瓦尔特堡节","↔ 相关：德意志民族主义","↔ 相关：德意志学生兄弟会","✗ 对立/冲突：法国霸权","✗ 对立/冲突：德意志反法民族动员","↔ 同时期参考：莱比锡战役"],"relations":[{"text":"← 前因：拿破仑莱茵邦","id":"extra521"},{"text":"← 前因：普鲁士施泰因-哈登贝格改革","id":"extra522"},{"text":"→ 后果：拿破仑战后维也纳会议","id":"extra525"},{"text":"→ 后果：德国瓦尔特堡节","id":"extra498"},{"text":"↔ 相关：德意志民族主义","id":"extra504"},{"text":"↔ 相关：德意志学生兄弟会","id":"extra499"},{"text":"✗ 对立/冲突：法国霸权","id":"extra868"},{"text":"✗ 对立/冲突：德意志反法民族动员","id":"extra588"},{"text":"↔ 同时期参考：莱比锡战役","id":"extra922"}],"source":"history","id":"extra523"},{"title":"反拿破仑莱比锡战役","level":"B","type":"事件卡","tags":["战争与外交","文化与思想"],"mainTag":"战争与外交","subTag":"文化与思想","timeText":"1813年10月16日—10月19日","place":"萨克森莱比锡附近","summary":"莱比锡战役是拿破仑战争中的决定性失败之一，促使法国势力退出德意志地区。","fields":[{"label":"标题","value":"反拿破仑莱比锡战役"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1813年10月16日—10月19日"},{"label":"地点","value":"萨克森莱比锡附近"},{"label":"主要国家","value":"法国、普鲁士、奥地利、俄罗斯、瑞典及德意志诸邦"},{"label":"一句话概括","value":"莱比锡战役是拿破仑战争中的决定性失败之一，促使法国势力退出德意志地区。"},{"label":"参与者","value":"拿破仑法军；普鲁士、奥地利、俄罗斯、瑞典等反法联军；德意志诸邦部队。"},{"label":"发生了什么","value":"反法联军在莱比锡周边集中兵力，与拿破仑军队展开大规模会战。经过数日战斗，法国军队遭受重大失败并向西撤退。战役规模巨大，后来被称为“民族会战”，在德意志民族记忆中被赋予反法解放意义。"},{"label":"为什么重要","value":"它是拿破仑德意志体系崩溃的军事节点，也为维也纳会议后的中欧重组创造条件。"},{"label":"前因","value":"拿破仑在俄国失败后，普鲁士、奥地利、俄国等反法力量重新集结，德意志战场成为欧洲反法联盟决定胜负的核心区域。"},{"label":"后果","value":"拿破仑在中欧的统治被决定性削弱，法国势力退出德意志大部地区，维也纳会议得以重新安排欧洲和德意志秩序。"},{"label":"出处","value":"Encyclopaedia Britannica，“Battle of Leipzig”；German History in Documents and Images，Wars of Liberation materials。"}],"relationItems":["← 前因：德意志解放战争","← 前因：拿破仑莱茵邦","→ 后果：拿破仑战后维也纳会议","→ 后果：德意志邦联","↔ 相关：德意志民族主义","↔ 相关：德国瓦尔特堡节","✗ 对立/冲突：拿破仑霸权","✗ 对立/冲突：反法联盟","↔ 同时期参考：普鲁士施泰因-哈登贝格改革"],"relations":[{"text":"← 前因：德意志解放战争","id":"extra523"},{"text":"← 前因：拿破仑莱茵邦","id":"extra521"},{"text":"→ 后果：拿破仑战后维也纳会议","id":"extra525"},{"text":"→ 后果：德意志邦联","id":"extra487"},{"text":"↔ 相关：德意志民族主义","id":"extra504"},{"text":"↔ 相关：德国瓦尔特堡节","id":"extra498"},{"text":"↔ 同时期参考：普鲁士施泰因-哈登贝格改革","id":"extra522"}],"source":"history","id":"extra524"},{"title":"拿破仑战后维也纳会议","level":"A","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1814年—1815年","place":"奥地利维也纳","summary":"维也纳会议重建拿破仑战争后的欧洲秩序，并用德意志邦联替代旧帝国和民族统一。","fields":[{"label":"标题","value":"拿破仑战后维也纳会议"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1814年—1815年"},{"label":"地点","value":"奥地利维也纳"},{"label":"主要国家","value":"奥地利、普鲁士、俄罗斯、英国、法国及德意志诸邦"},{"label":"一句话概括","value":"维也纳会议重建拿破仑战争后的欧洲秩序，并用德意志邦联替代旧帝国和民族统一。"},{"label":"参与者","value":"梅特涅、卡斯尔雷、亚历山大一世、塔列朗、哈登贝格等欧洲外交家和君主代表。"},{"label":"发生了什么","value":"拿破仑失败后，欧洲列强在维也纳重新分配领土、恢复王朝秩序并建立均势体系。德意志地区没有被统一为民族国家，而是组成由奥地利主导、普鲁士参与的松散德意志邦联。会议在稳定欧洲和压制革命之间建立新秩序。"},{"label":"为什么重要","value":"它是1815年后德国近代史的起点，直接塑造德意志统一与奥普领导权问题、奥普竞争和自由民族主义反对运动。"},{"label":"前因","value":"拿破仑帝国崩溃后，欧洲列强需要恢复大国均势、处理德意志和意大利等地区的政治空白，并防止法国革命和霸权再次外溢。"},{"label":"后果","value":"会议建立德意志邦联和梅特涅体系，暂时稳定欧洲秩序，却没有解决德意志民族统一和宪政诉求，反而为后来的自由主义运动留下张力。"},{"label":"出处","value":"Encyclopaedia Britannica，“Congress of Vienna”；German History in Documents and Images，Congress of Vienna and German Confederation materials。"}],"relationItems":["← 前因：反拿破仑莱比锡战役","← 前因：德意志解放战争","→ 后果：德意志邦联","→ 后果：欧洲梅特涅体系","↔ 相关：德意志统一与奥普领导权问题","↔ 相关：大德意志方案与小德意志方案","✗ 对立/冲突：民族统一诉求","✗ 对立/冲突：王朝均势秩序","↔ 同时期参考：德意志自由主义"],"relations":[{"text":"← 前因：反拿破仑莱比锡战役","id":"extra524"},{"text":"← 前因：德意志解放战争","id":"extra523"},{"text":"→ 后果：德意志邦联","id":"extra487"},{"text":"→ 后果：欧洲梅特涅体系","id":"extra500"},{"text":"↔ 相关：德意志统一与奥普领导权问题","id":"extra526"},{"text":"↔ 相关：大德意志方案与小德意志方案","id":"extra527"},{"text":"↔ 同时期参考：德意志自由主义","id":"extra501"}],"source":"history","id":"extra525"},{"title":"德意志统一与奥普领导权问题","level":"A","type":"概念/思潮卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1815年后长期存在，1871年小德意志方案部分解决","place":"中欧德意志地区","summary":"德意志统一与奥普领导权问题指德意志民族、邦国、奥地利与普鲁士之间如何组成国家秩序的长期难题。","fields":[{"label":"标题","value":"德意志统一与奥普领导权问题"},{"label":"分级","value":"A"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1815年后长期存在，1871年小德意志方案部分解决"},{"label":"地点","value":"中欧德意志地区"},{"label":"主要国家","value":"奥地利、普鲁士、德意志诸邦"},{"label":"一句话概括","value":"德意志统一与奥普领导权问题指德意志民族、邦国、奥地利与普鲁士之间如何组成国家秩序的长期难题。"},{"label":"核心主张/思路","value":"德意志人有共同语言和文化想象，但政治上分散在诸邦中；问题在于是否统一、由谁主导、是否包括奥地利。"},{"label":"提出者/代表人物（可选）","value":"不是单一人物提出，而是外交家、自由主义者、民族主义者和邦国统治者共同面对的结构性问题。"},{"label":"它从何而来","value":"神圣罗马帝国解体、维也纳会议的德意志邦联安排、奥普竞争和民族主义兴起。"},{"label":"典型表现","value":"大德意志/小德意志方案争论、1848法兰克福国民议会、普奥战争和1871德意志帝国成立。"},{"label":"为什么重要","value":"它是1815–1871德国近代史的核心轴线，没有这张卡，统一道路的因果链会断。"},{"label":"争议/局限","value":"1871年统一解决了国家形式问题，却没有消除奥地利排除、普鲁士优势和民族边界问题。"},{"label":"出处","value":"German History in Documents and Images，German Question materials；Encyclopaedia Britannica，German Confederation and German unification materials。"}],"relationItems":["← 前因：拿破仑战后维也纳会议","← 前因：德意志邦联","→ 后果：大德意志方案与小德意志方案","→ 后果：普奥战争","↔ 相关：德意志民族主义","↔ 相关：德意志自由主义","✗ 对立/冲突：邦国主权","✗ 对立/冲突：民族国家诉求","↔ 同时期参考：德意志关税同盟（Zollverein）"],"relations":[{"text":"← 前因：拿破仑战后维也纳会议","id":"extra525"},{"text":"← 前因：德意志邦联","id":"extra487"},{"text":"→ 后果：大德意志方案与小德意志方案","id":"extra527"},{"text":"→ 后果：普奥战争","id":"extra495"},{"text":"↔ 相关：德意志民族主义","id":"extra504"},{"text":"↔ 相关：德意志自由主义","id":"extra501"},{"text":"↔ 同时期参考：德意志关税同盟（Zollverein）","id":"extra486"}],"source":"history","id":"extra526"},{"title":"大德意志方案与小德意志方案","level":"B","type":"概念/思潮卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"十九世纪中期，1848年革命和1860年代尤为关键","place":"德意志地区","summary":"大德意志与小德意志方案争论决定统一是否包括奥地利，是德意志国家建构的核心分歧。","fields":[{"label":"标题","value":"大德意志方案与小德意志方案"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"十九世纪中期，1848年革命和1860年代尤为关键"},{"label":"地点","value":"德意志地区"},{"label":"主要国家","value":"奥地利、普鲁士、德意志诸邦"},{"label":"一句话概括","value":"大德意志与小德意志方案争论决定统一是否包括奥地利，是德意志国家建构的核心分歧。"},{"label":"核心主张/思路","value":"大德意志方案主张把奥地利德语地区纳入统一德国；小德意志方案则排除奥地利，由普鲁士主导统一。"},{"label":"提出者/代表人物（可选）","value":"1848年法兰克福国民议会代表、奥地利和普鲁士政治力量、民族自由派等。"},{"label":"它从何而来","value":"德意志统一与奥普领导权问题、奥地利多民族帝国结构、普鲁士崛起和民族统一诉求。"},{"label":"典型表现","value":"法兰克福国民议会围绕皇位和边界争论，1866年普奥战争后小德意志道路占上风。"},{"label":"为什么重要","value":"它解释为什么1871年的德意志帝国是“没有奥地利的德国”，也解释奥普冲突为何不可避免。"},{"label":"争议/局限","value":"两种方案都无法简单解决非德意志民族、边界混杂和帝国权力结构问题。"},{"label":"出处","value":"German History in Documents and Images，Frankfurt Parliament materials；Encyclopaedia Britannica，German unification materials。"}],"relationItems":["← 前因：德意志统一与奥普领导权问题","← 前因：德国法兰克福国民议会","→ 后果：普奥战争","→ 后果：德意志帝国成立","↔ 相关：德意志民族主义","↔ 相关：普鲁士主导的北德意志邦联","✗ 对立/冲突：奥地利多民族帝国","✗ 对立/冲突：民族德国边界想象","↔ 同时期参考：德意志关税同盟（Zollverein）"],"relations":[{"text":"← 前因：德意志统一与奥普领导权问题","id":"extra526"},{"text":"← 前因：德国法兰克福国民议会","id":"extra491"},{"text":"→ 后果：普奥战争","id":"extra495"},{"text":"→ 后果：德意志帝国成立","id":"extra621"},{"text":"↔ 相关：德意志民族主义","id":"extra504"},{"text":"↔ 相关：普鲁士主导的北德意志邦联","id":"extra496"},{"text":"↔ 同时期参考：德意志关税同盟（Zollverein）","id":"extra486"}],"source":"history","id":"extra527"},{"title":"1830年欧洲革命浪潮","level":"B","type":"事件卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1830—1832年","place":"法国、比利时、波兰、意大利诸邦、德意志诸邦等欧洲地区","summary":"1830年法国七月革命引发欧洲多地自由主义和民族运动，冲击维也纳体系但结果差异很大。","fields":[{"label":"标题","value":"1830年欧洲革命浪潮"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1830—1832年"},{"label":"地点","value":"法国、比利时、波兰、意大利诸邦、德意志诸邦等欧洲地区"},{"label":"主要国家","value":"法国；比利时；荷兰；波兰；俄罗斯；意大利诸邦；德意志诸邦"},{"label":"一句话概括","value":"1830年法国七月革命引发欧洲多地自由主义和民族运动，冲击维也纳体系但结果差异很大。"},{"label":"参与者","value":"法国自由派和巴黎群众、比利时独立派、波兰起义者、意大利和德意志自由主义者、各国保守政府。"},{"label":"发生了什么","value":"1830年，法国查理十世发布限制新闻和选举的敕令，引发巴黎三日战斗和七月王朝建立。革命消息鼓舞欧洲各地自由主义者和民族运动：比利时脱离荷兰并获得承认，波兰反俄起义被镇压，意大利和德意志诸邦的运动大多被保守政权压制。它没有推翻整个维也纳体系，却证明革命政治仍能跨国传播。"},{"label":"为什么重要","value":"这张卡应放在欧洲革命史主线上，而不是只讲德意志反应。它连接法国七月革命、比利时独立、波兰十一月起义、德意志Vormärz时期和1848年欧洲革命，是理解19世纪自由主义和民族主义连续波动的节点。"},{"label":"前因","value":"维也纳体系试图压制革命与民族运动，但复辟王朝、新闻审查、有限选举权和民族问题持续制造不满。"},{"label":"后果","value":"比利时独立改变低地国家格局；波兰、意大利和德意志地区的失败运动加深流亡政治与反对派网络；德意志的汉巴赫节和Vormärz时期由此升温。"},{"label":"出处","value":"Encyclopaedia Britannica: July Revolution；Encyclopaedia Britannica: Revolutions of 1830；German History in Documents and Images: Vormärz materials。"}],"relationItems":["← 前因：欧洲梅特涅体系","← 前因：德意志邦联的卡尔斯巴德决议","→ 后果：德国汉巴赫节","→ 后果：德意志Vormärz时期","→ 后果：1848年欧洲革命","↔ 相关：德意志自由主义","↔ 相关：德意志民族主义","✗ 对立/冲突：保守复辟秩序"],"relations":[{"text":"← 前因：欧洲梅特涅体系","id":"extra500"},{"text":"← 前因：德意志邦联的卡尔斯巴德决议","id":"extra488"},{"text":"→ 后果：德国汉巴赫节","id":"extra489"},{"text":"→ 后果：德意志Vormärz时期","id":"extra502"},{"text":"→ 后果：1848年欧洲革命","id":"extra530"},{"text":"↔ 相关：德意志自由主义","id":"extra501"},{"text":"↔ 相关：德意志民族主义","id":"extra504"}],"source":"history","id":"extra528"},{"title":"哥廷根七君子事件","level":"C","type":"事件卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1837年","place":"汉诺威王国哥廷根","summary":"哥廷根七君子事件以大学教授抗议废宪为核心，成为德意志自由主义和学术良知的象征。","fields":[{"label":"标题","value":"哥廷根七君子事件"},{"label":"分级","value":"C"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1837年"},{"label":"地点","value":"汉诺威王国哥廷根"},{"label":"主要国家","value":"汉诺威、德意志诸邦"},{"label":"一句话概括","value":"哥廷根七君子事件以大学教授抗议废宪为核心，成为德意志自由主义和学术良知的象征。"},{"label":"参与者","value":"哥廷根大学七名教授，包括格林兄弟等；汉诺威国王恩斯特·奥古斯特。"},{"label":"发生了什么","value":"1837年，汉诺威国王废除较自由的宪法。哥廷根大学七名教授公开抗议，认为国王违反宪政承诺。七人因此被解职，其中部分被驱逐。事件在德意志公共舆论中引发强烈反响，知识分子与宪政自由主义之间的关系更加紧密。"},{"label":"为什么重要","value":"它把大学、法治、宪政和民族公共舆论连接起来，说明德意志自由主义并非只存在于议会。"},{"label":"前因","value":"七月革命后德意志自由主义持续扩散，汉诺威国王废除宪法的举动直接挑战了教授群体对法治和宪政承诺的理解。"},{"label":"后果","value":"七名教授被免职和驱逐后成为自由主义道德抵抗的象征，大学知识分子与宪政政治的联系增强，并影响1848年前的公共舆论。"},{"label":"出处","value":"Encyclopaedia Britannica，Göttingen Seven materials；German History in Documents and Images，Göttingen Seven materials。"}],"relationItems":["← 前因：德意志自由主义","← 前因：1830年欧洲革命浪潮","→ 后果：1848年德意志革命","↔ 相关：德国洪堡大学模式","↔ 相关：德意志Vormärz时期","✗ 对立/冲突：君主废宪权","✗ 对立/冲突：宪政法治原则","↔ 同时期参考：德国汉巴赫节"],"relations":[{"text":"← 前因：德意志自由主义","id":"extra501"},{"text":"← 前因：1830年欧洲革命浪潮","id":"extra528"},{"text":"→ 后果：1848年德意志革命","id":"extra490"},{"text":"↔ 相关：德国洪堡大学模式","id":"extra515"},{"text":"↔ 相关：德意志Vormärz时期","id":"extra502"},{"text":"↔ 同时期参考：德国汉巴赫节","id":"extra489"}],"source":"history","id":"extra529"},{"title":"1848年欧洲革命","level":"A","type":"事件卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1848年—1849年","place":"法国、德意志地区、奥地利帝国、意大利、匈牙利等欧洲多地","summary":"1848年欧洲革命把自由主义、民族主义和社会问题同时推上政治舞台，是德意志革命的欧洲背景。","fields":[{"label":"标题","value":"1848年欧洲革命"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1848年—1849年"},{"label":"地点","value":"法国、德意志地区、奥地利帝国、意大利、匈牙利等欧洲多地"},{"label":"主要国家","value":"法国、奥地利、普鲁士、意大利诸邦、匈牙利等"},{"label":"一句话概括","value":"1848年欧洲革命把自由主义、民族主义和社会问题同时推上政治舞台，是德意志革命的欧洲背景。"},{"label":"参与者","value":"欧洲各地自由主义者、民族主义者、工人、学生、农民、君主政府和军队。"},{"label":"发生了什么","value":"1848年革命从法国扩散到欧洲大陆多地，抗议者要求宪法、代表制、民族自治、新闻自由和社会改革。奥地利、普鲁士和德意志诸邦相继爆发示威、起义和政治让步。革命初期君主政权被迫退让，但随着军队重整、自由派分裂和社会诉求冲突，革命逐步失败。"},{"label":"为什么重要","value":"它说明德意志革命不是孤立事件，而是欧洲旧秩序危机的一部分。"},{"label":"前因","value":"1840年代粮食危机、工业化带来的社会压力、自由主义和民族主义诉求在欧洲多地积累，法国二月革命提供了直接示范。"},{"label":"后果","value":"革命浪潮迫使德意志各邦让步并召集法兰克福国民议会，把德意志统一和宪政问题推上欧洲革命的中心舞台。"},{"label":"出处","value":"Encyclopaedia Britannica，“Revolutions of 1848”；German History in Documents and Images，1848 Revolution materials。"}],"relationItems":["← 前因：1830年欧洲革命浪潮","← 前因：十九世纪德国社会问题","→ 后果：1848年德意志革命","→ 后果：德国法兰克福国民议会","↔ 相关：德意志自由主义","↔ 相关：德意志民族主义","✗ 对立/冲突：复辟秩序","✗ 对立/冲突：自由民族革命","↔ 同时期参考：西里西亚织工起义"],"relations":[{"text":"← 前因：1830年欧洲革命浪潮","id":"extra528"},{"text":"← 前因：十九世纪德国社会问题","id":"extra511"},{"text":"→ 后果：1848年德意志革命","id":"extra490"},{"text":"→ 后果：德国法兰克福国民议会","id":"extra491"},{"text":"↔ 相关：德意志自由主义","id":"extra501"},{"text":"↔ 相关：德意志民族主义","id":"extra504"},{"text":"↔ 同时期参考：西里西亚织工起义","id":"extra510"}],"source":"history","id":"extra530"},{"title":"德国法兰克福宪法","level":"B","type":"制度/文本卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1849年3月通过","place":"法兰克福保罗教堂","summary":"法兰克福宪法是1848革命中统一德国的自由宪政方案，虽未实施却留下重要制度遗产。","fields":[{"label":"标题","value":"德国法兰克福宪法"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1849年3月通过"},{"label":"地点","value":"法兰克福保罗教堂"},{"label":"主要国家","value":"德意志诸邦、普鲁士、奥地利"},{"label":"一句话概括","value":"法兰克福宪法是1848革命中统一德国的自由宪政方案，虽未实施却留下重要制度遗产。"},{"label":"制定方/签署方","value":"法兰克福国民议会。"},{"label":"主要内容","value":"提出统一德国的宪政框架、基本权利、议会制度和世袭皇帝安排，倾向小德意志方案。"},{"label":"它试图解决什么问题","value":"革命者希望把德意志民族统一、自由权利和君主立宪结合成可执行国家制度。"},{"label":"为什么重要","value":"它是德国自由宪政传统的核心文本之一，显示1848革命失败并不等于没有制度成果。"},{"label":"争议/局限","value":"宪法缺乏强制执行力量，依赖普鲁士国王接受皇冠和诸邦承认，最终无法落地。"},{"label":"造成的影响","value":"影响后来的德国宪政讨论和基本权利传统。"},{"label":"出处","value":"German History in Documents and Images，Frankfurt Constitution materials；Encyclopaedia Britannica，Frankfurt National Assembly materials。"}],"relationItems":["← 前因：德国法兰克福国民议会","← 前因：大德意志方案与小德意志方案","→ 后果：普鲁士国王拒绝德意志皇冠","→ 后果：1848革命失败后的保守反扑","↔ 相关：德意志自由主义","↔ 相关：德国黑红金旗帜","✗ 对立/冲突：议会制宪权","✗ 对立/冲突：君主邦国权力","↔ 同时期参考：《共产党宣言》"],"relations":[{"text":"← 前因：德国法兰克福国民议会","id":"extra491"},{"text":"← 前因：大德意志方案与小德意志方案","id":"extra527"},{"text":"→ 后果：普鲁士国王拒绝德意志皇冠","id":"extra532"},{"text":"→ 后果：1848革命失败后的保守反扑","id":"extra534"},{"text":"↔ 相关：德意志自由主义","id":"extra501"},{"text":"↔ 相关：德国黑红金旗帜","id":"extra505"}],"source":"history","id":"extra531"},{"title":"普鲁士国王拒绝德意志皇冠","level":"B","type":"事件卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1849年4月","place":"普鲁士柏林与法兰克福国民议会相关政治空间","summary":"普鲁士国王拒绝法兰克福国民议会献上的皇冠，象征1848自由统一方案失败。","fields":[{"label":"标题","value":"普鲁士国王拒绝德意志皇冠"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1849年4月"},{"label":"地点","value":"普鲁士柏林与法兰克福国民议会相关政治空间"},{"label":"主要国家","value":"普鲁士、德意志诸邦"},{"label":"一句话概括","value":"普鲁士国王拒绝法兰克福国民议会献上的皇冠，象征1848自由统一方案失败。"},{"label":"参与者","value":"普鲁士国王弗里德里希·威廉四世；法兰克福国民议会代表；德意志诸邦政府。"},{"label":"发生了什么","value":"法兰克福国民议会通过宪法后，希望由普鲁士国王担任统一德国皇帝。但弗里德里希·威廉四世拒绝接受来自民选议会的皇冠，认为其缺乏君主和诸侯认可的合法性。自由派统一计划因此失去最关键的国家力量支持。"},{"label":"为什么重要","value":"它说明1848革命的自由主义议会道路无法压倒君主和军队权力，德国统一此后转向普鲁士国家权力道路。"},{"label":"前因","value":"法兰克福国民议会试图用宪法和议会授权建立小德意志帝国，但它缺乏军队和各大邦君主的稳定支持。"},{"label":"后果","value":"弗里德里希·威廉四世拒绝接受议会授予的皇帝头衔，议会统一道路崩溃，普鲁士后来转向由王权和军事力量主导的统一方案。"},{"label":"出处","value":"Encyclopaedia Britannica，Frankfurt National Assembly materials；German History in Documents and Images，Frederick William IV and imperial crown materials。"}],"relationItems":["← 前因：德国法兰克福宪法","← 前因：德国法兰克福国民议会","→ 后果：普鲁士的奥尔米茨屈辱","→ 后果：普鲁士宪法冲突","↔ 相关：德意志自由主义","↔ 相关：大德意志方案与小德意志方案","✗ 对立/冲突：人民主权","✗ 对立/冲突：君主合法性","↔ 同时期参考：1848年欧洲革命"],"relations":[{"text":"← 前因：德国法兰克福宪法","id":"extra531"},{"text":"← 前因：德国法兰克福国民议会","id":"extra491"},{"text":"→ 后果：普鲁士的奥尔米茨屈辱","id":"extra492"},{"text":"→ 后果：普鲁士宪法冲突","id":"extra539"},{"text":"↔ 相关：德意志自由主义","id":"extra501"},{"text":"↔ 相关：大德意志方案与小德意志方案","id":"extra527"},{"text":"↔ 同时期参考：1848年欧洲革命","id":"extra530"}],"source":"history","id":"extra532"},{"title":"德意志帝国宪法运动","level":"C","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1849年","place":"萨克森、巴登、普法尔茨等德意志地区","summary":"德意志帝国宪法运动试图以起义和地方动员维护法兰克福宪法，但被普鲁士等保守力量镇压。","fields":[{"label":"标题","value":"德意志帝国宪法运动"},{"label":"分级","value":"C"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1849年"},{"label":"地点","value":"萨克森、巴登、普法尔茨等德意志地区"},{"label":"主要国家","value":"德意志诸邦、普鲁士"},{"label":"一句话概括","value":"德意志帝国宪法运动试图以起义和地方动员维护法兰克福宪法，但被普鲁士等保守力量镇压。"},{"label":"参与者","value":"民主派、自由派、地方民兵和起义者；普鲁士军队；德意志邦国政府。"},{"label":"发生了什么","value":"普鲁士国王拒绝皇冠后，部分革命者试图通过群众动员和地方起义推动法兰克福宪法实施。萨克森、巴登和普法尔茨等地出现起义或武装抵抗，革命者试图保住议会制宪成果。普鲁士军队参与镇压，革命力量被击败，大批民主派流亡。"},{"label":"为什么重要","value":"它是1848革命失败的最后阶段，显示没有军队和国家机器支持的宪法很难抵抗保守反扑。"},{"label":"前因","value":"法兰克福宪法通过后，普鲁士国王拒绝皇冠使议会权威受挫，自由派和民主派试图通过地方起义迫使各邦承认宪法。"},{"label":"后果","value":"运动被镇压后，1848革命基本失败，自由主义者被迫重新评估议会、街头动员和王权之间的力量关系。"},{"label":"出处","value":"German History in Documents and Images，Imperial Constitution Campaign materials；Encyclopaedia Britannica，Revolutions of 1848 in Germany materials。"}],"relationItems":["← 前因：德国法兰克福宪法","← 前因：普鲁士国王拒绝德意志皇冠","→ 后果：1848革命失败后的保守反扑","↔ 相关：德意志自由主义","↔ 相关：德意志Vormärz时期","✗ 对立/冲突：革命制宪运动","✗ 对立/冲突：保守军队镇压","↔ 同时期参考：普鲁士的奥尔米茨屈辱"],"relations":[{"text":"← 前因：德国法兰克福宪法","id":"extra531"},{"text":"← 前因：普鲁士国王拒绝德意志皇冠","id":"extra532"},{"text":"→ 后果：1848革命失败后的保守反扑","id":"extra534"},{"text":"↔ 相关：德意志自由主义","id":"extra501"},{"text":"↔ 相关：德意志Vormärz时期","id":"extra502"},{"text":"↔ 同时期参考：普鲁士的奥尔米茨屈辱","id":"extra492"}],"source":"history","id":"extra533"},{"title":"1848革命失败后的保守反扑","level":"B","type":"概念/思潮卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1849年—1850年代","place":"德意志诸邦","summary":"1848革命失败后，德意志诸邦恢复君主和官僚控制，自由民族运动被迫转入长期低潮和策略调整。","fields":[{"label":"标题","value":"1848革命失败后的保守反扑"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1849年—1850年代"},{"label":"地点","value":"德意志诸邦"},{"label":"主要国家","value":"奥地利、普鲁士、德意志诸邦"},{"label":"一句话概括","value":"1848革命失败后，德意志诸邦恢复君主和官僚控制，自由民族运动被迫转入长期低潮和策略调整。"},{"label":"核心主张/思路","value":"保守政权重新强调君主权威、秩序、审查和邦国主权，限制革命时期扩张的政治参与。"},{"label":"提出者/代表人物（可选）","value":"奥地利与普鲁士保守派、德意志邦国政府、警察和官僚体系。"},{"label":"它从何而来","value":"法兰克福宪法失败、德意志帝国宪法运动被镇压、自由派与民主派分裂。"},{"label":"典型表现","value":"革命者流亡、报刊受压、议会权力收缩、军队和官僚重新掌握主动。"},{"label":"为什么重要","value":"它解释为什么德国统一没有沿1848自由议会道路推进，而是在1860年代转向普鲁士权力政治。"},{"label":"争议/局限","value":"保守反扑并未消除民族统一和宪政诉求，只是改变了它们的组织形式和政治机会。"},{"label":"出处","value":"German History in Documents and Images，post-1848 reaction materials；Encyclopaedia Britannica，Germany 1848 aftermath materials。"}],"relationItems":["← 前因：德意志帝国宪法运动","← 前因：普鲁士国王拒绝德意志皇冠","→ 后果：普鲁士的奥尔米茨屈辱","→ 后果：俾斯麦出任普鲁士首相","↔ 相关：德意志自由主义","↔ 相关：德意志民族主义","✗ 对立/冲突：革命自由主义","✗ 对立/冲突：君主保守秩序","↔ 同时期参考：德国社会主义爱森纳赫派"],"relations":[{"text":"← 前因：德意志帝国宪法运动","id":"extra533"},{"text":"← 前因：普鲁士国王拒绝德意志皇冠","id":"extra532"},{"text":"→ 后果：普鲁士的奥尔米茨屈辱","id":"extra492"},{"text":"→ 后果：俾斯麦出任普鲁士首相","id":"extra493"},{"text":"↔ 相关：德意志自由主义","id":"extra501"},{"text":"↔ 相关：德意志民族主义","id":"extra504"},{"text":"↔ 同时期参考：德国社会主义爱森纳赫派","id":"extra514"}],"source":"history","id":"extra534"},{"title":"奥地利与普鲁士二元主义","level":"B","type":"概念/思潮卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1815年—1866年","place":"德意志邦联与中欧","summary":"奥地利与普鲁士二元主义指两个大国在德意志邦联内竞争领导权，最终导致普奥战争。","fields":[{"label":"标题","value":"奥地利与普鲁士二元主义"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1815年—1866年"},{"label":"地点","value":"德意志邦联与中欧"},{"label":"主要国家","value":"奥地利、普鲁士、德意志诸邦"},{"label":"一句话概括","value":"奥地利与普鲁士二元主义指两个大国在德意志邦联内竞争领导权，最终导致普奥战争。"},{"label":"核心主张/思路","value":"德意志政治秩序无法同时满足奥地利传统主导地位和普鲁士不断增长的国家实力。"},{"label":"提出者/代表人物（可选）","value":"不是单一理论，而是1815年后德意志邦联权力结构的现实。"},{"label":"它从何而来","value":"维也纳会议安排、奥地利多民族帝国地位、普鲁士改革和经济军事崛起。"},{"label":"典型表现","value":"邦联议事、关税同盟排除奥地利、1850年奥尔米茨危机、1866年普奥战争。"},{"label":"为什么重要","value":"它是德意志统一道路的关键结构矛盾，解释为什么统一必须先解决奥普关系。"},{"label":"争议/局限","value":"二元主义不只是两国斗争，也牵涉中小邦国如何在两强之间保留自主。"},{"label":"出处","value":"German History in Documents and Images，Austro-Prussian dualism materials；Encyclopaedia Britannica，German Confederation and German unification materials。"}],"relationItems":["← 前因：德意志邦联","← 前因：拿破仑战后维也纳会议","→ 后果：普鲁士的奥尔米茨屈辱","→ 后果：普奥战争","↔ 相关：大德意志方案与小德意志方案","↔ 相关：德意志关税同盟（Zollverein）","✗ 对立/冲突：奥地利主导","✗ 对立/冲突：勃兰登堡-普鲁士崛起","↔ 同时期参考：德意志统一与奥普领导权问题"],"relations":[{"text":"← 前因：德意志邦联","id":"extra487"},{"text":"← 前因：拿破仑战后维也纳会议","id":"extra525"},{"text":"→ 后果：普鲁士的奥尔米茨屈辱","id":"extra492"},{"text":"→ 后果：普奥战争","id":"extra495"},{"text":"↔ 相关：大德意志方案与小德意志方案","id":"extra527"},{"text":"↔ 相关：德意志关税同盟（Zollverein）","id":"extra486"},{"text":"✗ 对立/冲突：勃兰登堡-普鲁士崛起","id":"extra311"},{"text":"↔ 同时期参考：德意志统一与奥普领导权问题","id":"extra526"}],"source":"history","id":"extra535"},{"title":"普鲁士军制改革","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1859年—1860年代","place":"普鲁士王国","summary":"普鲁士军制改革扩大常备军并强化训练体系，为1860年代统一战争提供军事基础。","fields":[{"label":"标题","value":"普鲁士军制改革"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1859年—1860年代"},{"label":"地点","value":"普鲁士王国"},{"label":"主要国家","value":"普鲁士"},{"label":"一句话概括","value":"普鲁士军制改革扩大常备军并强化训练体系，为1860年代统一战争提供军事基础。"},{"label":"参与者","value":"普鲁士摄政王威廉、阿尔布雷希特·冯·罗恩、老毛奇、普鲁士议会。"},{"label":"发生了什么","value":"普鲁士在1859年后推动军制改革，计划增加常备军、延长服役、削弱后备民兵性质较强的兰德韦尔影响，并提高军队专业化程度。改革需要追加军费，引发自由派议会反对。王室和军方坚持执行，宪法冲突随之升级。"},{"label":"为什么重要","value":"它使普鲁士在普丹、普奥和普法战争中拥有更高效的军事动员能力，也把统一道路与军队、预算和宪法冲突绑在一起。"},{"label":"前因","value":"奥尔米茨屈辱和普奥竞争使普鲁士精英认识到军事实力决定德意志领导权，人口增长也要求改革征兵和常备军结构。"},{"label":"后果","value":"军制改革引发预算和宪政冲突，促成俾斯麦上台；改革后的军队随后成为普丹、普奥和普法战争胜利的关键工具。"},{"label":"出处","value":"Encyclopaedia Britannica，Prussian army and Bismarck materials；German History in Documents and Images，Prussian military reform materials。"}],"relationItems":["← 前因：普鲁士施泰因-哈登贝格改革","← 前因：奥地利与普鲁士二元主义","→ 后果：普鲁士宪法冲突","→ 后果：普奥战争","↔ 相关：老毛奇与普鲁士总参谋部","↔ 相关：阿尔布雷希特·冯·罗恩","✗ 对立/冲突：议会预算权","✗ 对立/冲突：王室军事改革","↔ 同时期参考：俾斯麦“铁血演说”"],"relations":[{"text":"← 前因：普鲁士施泰因-哈登贝格改革","id":"extra522"},{"text":"← 前因：奥地利与普鲁士二元主义","id":"extra535"},{"text":"→ 后果：普鲁士宪法冲突","id":"extra539"},{"text":"→ 后果：普奥战争","id":"extra495"},{"text":"↔ 相关：老毛奇与普鲁士总参谋部","id":"extra538"},{"text":"↔ 相关：阿尔布雷希特·冯·罗恩","id":"extra537"},{"text":"✗ 对立/冲突：议会预算权","id":"extra915"},{"text":"↔ 同时期参考：俾斯麦“铁血演说”","id":"extra540"}],"source":"history","id":"extra536"},{"title":"阿尔布雷希特·冯·罗恩","level":"C","type":"人物卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1803年—1879年","place":"普鲁士、德意志帝国","summary":"罗恩是普鲁士军制改革的关键执行者，把王室军事目标转化为具体军队制度。","fields":[{"label":"标题","value":"阿尔布雷希特·冯·罗恩"},{"label":"分级","value":"C"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1803年—1879年"},{"label":"地点","value":"普鲁士、德意志帝国"},{"label":"主要国家","value":"普鲁士、德国"},{"label":"一句话概括","value":"罗恩是普鲁士军制改革的关键执行者，把王室军事目标转化为具体军队制度。"},{"label":"生卒年/活跃年代","value":"1803年生，1879年卒；1850年代末至1870年代影响最大。"},{"label":"身份/职务","value":"普鲁士军官、战争大臣，后任德意志帝国首相短期职务。"},{"label":"关键贡献/作为","value":"推动普鲁士军制改革，扩大常备军并强化服役、训练和军队组织。"},{"label":"核心主张/立场","value":"认为普鲁士必须通过强大、专业和可快速动员的军队保障大国地位。"},{"label":"为什么重要","value":"没有罗恩的制度执行，俾斯麦的权力政治和毛奇的作战计划都缺少军事基础。"},{"label":"争议/评价","value":"改革强化军队效率，也加剧王室与自由派议会的预算冲突。"},{"label":"关联事件（可选）","value":"普鲁士军制改革；普鲁士宪法冲突；普奥战争。"},{"label":"出处","value":"Encyclopaedia Britannica，“Albrecht von Roon”；German History in Documents and Images，Prussian military reform materials。"}],"relationItems":["← 前因：普鲁士军制改革","→ 后果：普奥战争","↔ 相关：老毛奇与普鲁士总参谋部","↔ 相关：俾斯麦出任普鲁士首相","✗ 对立/冲突：军事专业化","✗ 对立/冲突：议会控制军费","↔ 同时期参考：普鲁士宪法冲突"],"relations":[{"text":"← 前因：普鲁士军制改革","id":"extra536"},{"text":"→ 后果：普奥战争","id":"extra495"},{"text":"↔ 相关：老毛奇与普鲁士总参谋部","id":"extra538"},{"text":"↔ 相关：俾斯麦出任普鲁士首相","id":"extra493"},{"text":"↔ 同时期参考：普鲁士宪法冲突","id":"extra539"}],"source":"history","id":"extra537"},{"title":"老毛奇与普鲁士总参谋部","level":"B","type":"组织/机构卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1857年后影响显著，1860年代统一战争中发挥核心作用","place":"普鲁士王国","summary":"老毛奇领导下的普鲁士总参谋部把铁路、动员和作战计划系统化，成为统一战争的军事大脑。","fields":[{"label":"标题","value":"老毛奇与普鲁士总参谋部"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1857年后影响显著，1860年代统一战争中发挥核心作用"},{"label":"地点","value":"普鲁士王国"},{"label":"主要国家","value":"普鲁士、德国"},{"label":"一句话概括","value":"老毛奇领导下的普鲁士总参谋部把铁路、动员和作战计划系统化，成为统一战争的军事大脑。"},{"label":"性质/类型","value":"军事计划和指挥参谋机构。"},{"label":"成立/解散时间","value":"普鲁士总参谋部有较早传统；1857年老毛奇任总参谋长后影响大幅提升。"},{"label":"核心目标/宗旨","value":"通过专业参谋教育、地图、铁路运输、动员计划和战场指挥协调提高战争效率。"},{"label":"关键人物（可选）","value":"赫尔穆特·冯·毛奇。"},{"label":"关键行动/事件","value":"在普丹战争、普奥战争和普法战争中规划动员与作战，发挥决定性协调作用。"},{"label":"为什么重要","value":"它说明德国统一不只是俾斯麦外交，也依赖现代军事官僚组织和铁路时代的计划能力。"},{"label":"争议/局限","value":"总参谋部强化军事专业自主，长期看也加深德国政治中的军事权威。"},{"label":"出处","value":"Encyclopaedia Britannica，“Helmuth von Moltke”；German History in Documents and Images，Prussian General Staff materials。"}],"relationItems":["← 前因：普鲁士军制改革","← 前因：德国铁路建设","→ 后果：普奥战争","→ 后果：普法战争","↔ 相关：阿尔布雷希特·冯·罗恩","↔ 相关：俾斯麦出任普鲁士首相","✗ 对立/冲突：传统贵族军队","✗ 对立/冲突：现代参谋战争","↔ 同时期参考：普鲁士宪法冲突"],"relations":[{"text":"← 前因：普鲁士军制改革","id":"extra536"},{"text":"← 前因：德国铁路建设","id":"extra507"},{"text":"→ 后果：普奥战争","id":"extra495"},{"text":"→ 后果：普法战争","id":"extra497"},{"text":"↔ 相关：阿尔布雷希特·冯·罗恩","id":"extra537"},{"text":"↔ 相关：俾斯麦出任普鲁士首相","id":"extra493"},{"text":"↔ 同时期参考：普鲁士宪法冲突","id":"extra539"}],"source":"history","id":"extra538"},{"title":"普鲁士宪法冲突","level":"A","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1862年—1866年","place":"普鲁士王国","summary":"普鲁士宪法冲突围绕军费预算和议会权力展开，使俾斯麦以王权政府对抗自由派议会。","fields":[{"label":"标题","value":"普鲁士宪法冲突"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1862年—1866年"},{"label":"地点","value":"普鲁士王国"},{"label":"主要国家","value":"普鲁士"},{"label":"一句话概括","value":"普鲁士宪法冲突围绕军费预算和议会权力展开，使俾斯麦以王权政府对抗自由派议会。"},{"label":"参与者","value":"普鲁士国王威廉一世、俾斯麦、自由派议会多数、罗恩和军方。"},{"label":"发生了什么","value":"普鲁士政府要求为军制改革追加预算，自由派控制的议会拒绝批准。1862年俾斯麦出任首相后，主张在宪法存在“漏洞”时由政府继续征税和支出，绕过议会推动军改。冲突一直持续到普奥战争胜利后，俾斯麦通过赔偿法案寻求事后合法化。"},{"label":"为什么重要","value":"它决定德国统一不是由议会自由主义主导，而是由普鲁士王权、军队和俾斯麦权力政治主导。"},{"label":"前因","value":"军制改革需要长期财政支持，但自由派议会担心扩大常备军会强化王权并削弱议会预算控制，双方围绕军费陷入僵局。"},{"label":"后果","value":"冲突把俾斯麦推上首相职位，他以“漏洞理论”继续征税和改革军队，普鲁士政治由议会自由主义转向王权主导的统一道路。"},{"label":"出处","value":"German History in Documents and Images，Prussian Constitutional Conflict materials；Encyclopaedia Britannica，Bismarck materials。"}],"relationItems":["← 前因：普鲁士军制改革","← 前因：德意志自由主义","→ 后果：俾斯麦“铁血演说”","→ 后果：普鲁士俾斯麦赔偿法案","↔ 相关：俾斯麦出任普鲁士首相","↔ 相关：德国民族自由党","✗ 对立/冲突：议会预算权","✗ 对立/冲突：王权政府","↔ 同时期参考：老毛奇与普鲁士总参谋部"],"relations":[{"text":"← 前因：普鲁士军制改革","id":"extra536"},{"text":"← 前因：德意志自由主义","id":"extra501"},{"text":"→ 后果：俾斯麦“铁血演说”","id":"extra540"},{"text":"→ 后果：普鲁士俾斯麦赔偿法案","id":"extra545"},{"text":"↔ 相关：俾斯麦出任普鲁士首相","id":"extra493"},{"text":"↔ 相关：德国民族自由党","id":"extra674"},{"text":"✗ 对立/冲突：议会预算权","id":"extra915"},{"text":"↔ 同时期参考：老毛奇与普鲁士总参谋部","id":"extra538"}],"source":"history","id":"extra539"},{"title":"俾斯麦“铁血演说”","level":"B","type":"事件卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1862年9月30日","place":"普鲁士柏林","summary":"俾斯麦“铁血演说”把统一问题表达为权力与战争问题，成为德意志统一道路的象征性话语。","fields":[{"label":"标题","value":"俾斯麦“铁血演说”"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1862年9月30日"},{"label":"地点","value":"普鲁士柏林"},{"label":"主要国家","value":"普鲁士"},{"label":"一句话概括","value":"俾斯麦“铁血演说”把统一问题表达为权力与战争问题，成为德意志统一道路的象征性话语。"},{"label":"参与者","value":"奥托·冯·俾斯麦；普鲁士议会预算委员会；自由派议员。"},{"label":"发生了什么","value":"俾斯麦出任普鲁士首相后不久，在议会预算委员会发言，强调当代重大问题不是靠演说和多数决解决，而是靠“铁与血”。这番话发生在军费和宪法冲突背景下，表达了他愿以王权、军队和现实政治突破议会僵局。"},{"label":"为什么重要","value":"它不是简单好战口号，而是俾斯麦统一策略的高度浓缩：利用普鲁士国家力量改造德意志秩序。"},{"label":"前因","value":"普鲁士议会和王权围绕军制改革僵持不下，俾斯麦需要为绕开议会预算限制、优先建设军队提供政治辩护。"},{"label":"后果","value":"演说把德意志统一问题同权力政治和军事实力绑定起来，后来被视为俾斯麦战争统一路线的标志性表述。"},{"label":"出处","value":"German History in Documents and Images，Bismarck Blood and Iron speech；Encyclopaedia Britannica，Bismarck materials。"}],"relationItems":["← 前因：俾斯麦出任普鲁士首相","← 前因：普鲁士宪法冲突","→ 后果：普丹战争","→ 后果：普奥战争","↔ 相关：德意志统一与奥普领导权问题","↔ 相关：德意志自由主义","✗ 对立/冲突：议会自由主义","✗ 对立/冲突：现实政治","↔ 同时期参考：阿尔布雷希特·冯·罗恩"],"relations":[{"text":"← 前因：俾斯麦出任普鲁士首相","id":"extra493"},{"text":"← 前因：普鲁士宪法冲突","id":"extra539"},{"text":"→ 后果：普丹战争","id":"extra494"},{"text":"→ 后果：普奥战争","id":"extra495"},{"text":"↔ 相关：德意志统一与奥普领导权问题","id":"extra526"},{"text":"↔ 相关：德意志自由主义","id":"extra501"},{"text":"↔ 同时期参考：阿尔布雷希特·冯·罗恩","id":"extra537"}],"source":"history","id":"extra540"},{"title":"石勒苏益-荷尔斯泰因问题","level":"B","type":"概念/思潮卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"十九世纪中期，1863年—1864年危机升级","place":"石勒苏益、荷尔斯泰因、丹麦和德意志邦联相关地区","summary":"石勒苏益-荷尔斯泰因问题把王朝继承、民族边界和德意志邦联权力纠缠在一起，引发普丹战争。","fields":[{"label":"标题","value":"石勒苏益-荷尔斯泰因问题"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"十九世纪中期，1863年—1864年危机升级"},{"label":"地点","value":"石勒苏益、荷尔斯泰因、丹麦和德意志邦联相关地区"},{"label":"主要国家","value":"丹麦、普鲁士、奥地利、德意志诸邦"},{"label":"一句话概括","value":"石勒苏益-荷尔斯泰因问题把王朝继承、民族边界和德意志邦联权力纠缠在一起，引发普丹战争。"},{"label":"核心主张/思路","value":"两个公国与丹麦王室、德意志邦联和德德民族诉求关系复杂，争议焦点在其宪法地位和归属。"},{"label":"提出者/代表人物（可选）","value":"丹麦政府、德意志民族派、普鲁士和奥地利外交力量。"},{"label":"它从何而来","value":"公国继承关系、德丹混居边界、德意志民族主义和丹麦民族国家建设。"},{"label":"典型表现","value":"1863年丹麦试图把石勒苏益更紧密纳入丹麦，引发普鲁士和奥地利联合干预。"},{"label":"为什么重要","value":"它是俾斯麦统一道路的第一个战争入口，也为普奥之间的后续冲突制造管理争端。"},{"label":"争议/局限","value":"问题并不只是“德丹对立”，还涉及当地多民族居民、王朝法和大国策略。"},{"label":"出处","value":"Encyclopaedia Britannica，Schleswig-Holstein Question materials；German History in Documents and Images，Schleswig-Holstein materials。"}],"relationItems":["← 前因：德意志民族主义","← 前因：奥地利与普鲁士二元主义","→ 后果：普丹战争","→ 后果：普奥《加施泰因协定》","↔ 相关：俾斯麦“铁血演说”","↔ 相关：德意志邦联","✗ 对立/冲突：丹麦国家整合","✗ 对立/冲突：德意志民族诉求","↔ 同时期参考：普鲁士宪法冲突"],"relations":[{"text":"← 前因：德意志民族主义","id":"extra504"},{"text":"← 前因：奥地利与普鲁士二元主义","id":"extra535"},{"text":"→ 后果：普丹战争","id":"extra494"},{"text":"→ 后果：普奥《加施泰因协定》","id":"extra542"},{"text":"↔ 相关：俾斯麦“铁血演说”","id":"extra540"},{"text":"↔ 相关：德意志邦联","id":"extra487"},{"text":"↔ 同时期参考：普鲁士宪法冲突","id":"extra539"}],"source":"history","id":"extra541"},{"title":"普奥《加施泰因协定》","level":"C","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1865年8月","place":"奥地利巴特加施泰因","summary":"普奥《加施泰因协定》把石勒苏益和荷尔斯泰因分别交由普奥管理，暂时妥协却埋下普奥战争导火索。","fields":[{"label":"标题","value":"普奥《加施泰因协定》"},{"label":"分级","value":"C"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1865年8月"},{"label":"地点","value":"奥地利巴特加施泰因"},{"label":"主要国家","value":"普鲁士、奥地利"},{"label":"一句话概括","value":"普奥《加施泰因协定》把石勒苏益和荷尔斯泰因分别交由普奥管理，暂时妥协却埋下普奥战争导火索。"},{"label":"制定方/签署方","value":"普鲁士和奥地利。"},{"label":"主要内容","value":"普鲁士管理石勒苏益，奥地利管理荷尔斯泰因；双方还处理劳恩堡等相关安排。"},{"label":"它试图解决什么问题","value":"普丹战争后，普鲁士和奥地利必须处理共同夺得的公国如何管理与归属。"},{"label":"为什么重要","value":"它表面上缓和普奥冲突，实际上把奥地利行政权放在普鲁士势力包围下，给俾斯麦制造下一步冲突机会。"},{"label":"争议/局限","value":"协定没有最终解决公国归属，只是临时分管安排。"},{"label":"造成的影响","value":"荷尔斯泰因管理争议成为1866年普奥战争的直接借口之一。"},{"label":"出处","value":"Encyclopaedia Britannica，Gastein Convention materials；German History in Documents and Images，Austro-Prussian relations materials。"}],"relationItems":["← 前因：普丹战争","← 前因：石勒苏益-荷尔斯泰因问题","→ 后果：普奥战争","↔ 相关：奥地利与普鲁士二元主义","↔ 相关：俾斯麦“铁血演说”","✗ 对立/冲突：普奥临时妥协","✗ 对立/冲突：德意志领导权竞争","↔ 同时期参考：老毛奇与普鲁士总参谋部"],"relations":[{"text":"← 前因：普丹战争","id":"extra494"},{"text":"← 前因：石勒苏益-荷尔斯泰因问题","id":"extra541"},{"text":"→ 后果：普奥战争","id":"extra495"},{"text":"↔ 相关：奥地利与普鲁士二元主义","id":"extra535"},{"text":"↔ 相关：俾斯麦“铁血演说”","id":"extra540"},{"text":"↔ 同时期参考：老毛奇与普鲁士总参谋部","id":"extra538"}],"source":"history","id":"extra542"},{"title":"普奥战争克尼格雷茨战役","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1866年7月3日","place":"波希米亚克尼格雷茨/萨多瓦附近","summary":"普奥战争克尼格雷茨战役是普奥战争的决定性会战，确立普鲁士在德意志统一中的主导地位。","fields":[{"label":"标题","value":"普奥战争克尼格雷茨战役"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1866年7月3日"},{"label":"地点","value":"波希米亚克尼格雷茨/萨多瓦附近"},{"label":"主要国家","value":"普鲁士、奥地利"},{"label":"一句话概括","value":"普奥战争克尼格雷茨战役是普奥战争的决定性会战，确立普鲁士在德意志统一中的主导地位。"},{"label":"参与者","value":"普鲁士军队、奥地利军队及其盟友；老毛奇、普鲁士国王威廉一世等。"},{"label":"发生了什么","value":"普鲁士军队在波希米亚与奥地利主力决战。普军依靠铁路动员、总参谋部协调和后膛针枪等优势，在关键时刻完成兵力会合并击败奥军。战役使奥地利军队失去主动，维也纳方面难以继续争夺德意志领导权，被迫接受和谈。"},{"label":"为什么重要","value":"它把奥地利排除出德意志统一进程，使小德意志方案成为现实可能。"},{"label":"前因","value":"普奥围绕石勒苏益和荷尔斯泰因管理权的争端升级为战争，普鲁士军制改革和总参谋部体系使其具备快速决战能力。"},{"label":"后果","value":"奥地利在战场上失去争夺德意志领导权的能力，布拉格和约排除奥地利，北德意志邦联成为普鲁士统一路线的制度载体。"},{"label":"出处","value":"Encyclopaedia Britannica，“Battle of Königgrätz”；German History in Documents and Images，Austro-Prussian War materials。"}],"relationItems":["← 前因：普奥战争","← 前因：普奥《加施泰因协定》","→ 后果：布拉格和约（1866）","→ 后果：普鲁士主导的北德意志邦联","↔ 相关：老毛奇与普鲁士总参谋部","↔ 相关：大德意志方案与小德意志方案","✗ 对立/冲突：奥地利的德意志领导权诉求","✗ 对立/冲突：普鲁士军事优势","↔ 同时期参考：普鲁士俾斯麦赔偿法案"],"relations":[{"text":"← 前因：普奥战争","id":"extra495"},{"text":"← 前因：普奥《加施泰因协定》","id":"extra542"},{"text":"→ 后果：布拉格和约（1866）","id":"extra544"},{"text":"→ 后果：普鲁士主导的北德意志邦联","id":"extra496"},{"text":"↔ 相关：老毛奇与普鲁士总参谋部","id":"extra538"},{"text":"↔ 相关：大德意志方案与小德意志方案","id":"extra527"},{"text":"✗ 对立/冲突：奥地利的德意志领导权诉求","id":"extra909"},{"text":"↔ 同时期参考：普鲁士俾斯麦赔偿法案","id":"extra545"}],"source":"history","id":"extra543"},{"title":"布拉格和约（1866）","level":"B","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1866年8月23日","place":"布拉格","summary":"1866年布拉格和约结束普奥战争，确认奥地利退出德意志事务并允许普鲁士重组北德。","fields":[{"label":"标题","value":"布拉格和约（1866）"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1866年8月23日"},{"label":"地点","value":"布拉格"},{"label":"主要国家","value":"普鲁士、奥地利"},{"label":"一句话概括","value":"1866年布拉格和约结束普奥战争，确认奥地利退出德意志事务并允许普鲁士重组北德。"},{"label":"制定方/签署方","value":"普鲁士和奥地利。"},{"label":"主要内容","value":"奥地利承认德意志邦联解体和普鲁士在北德的重组权；普鲁士未对奥地利本土实施严厉割地惩罚。"},{"label":"它试图解决什么问题","value":"普奥战争后，需要以外交安排结束奥普领导权冲突，并为新的德意志政治结构打开空间。"},{"label":"为什么重要","value":"它是小德意志道路的制度转折点，体现俾斯麦避免彻底羞辱奥地利、保留未来外交空间的策略。"},{"label":"争议/局限","value":"和约解决了德意志领导权问题，却没有解决南德诸邦和法国对普鲁士扩张的反应。"},{"label":"造成的影响","value":"北德意志邦联建立，德意志统一进入最后阶段。"},{"label":"出处","value":"Encyclopaedia Britannica，Treaty of Prague 1866 materials；German History in Documents and Images，Austro-Prussian War settlement materials。"}],"relationItems":["← 前因：普奥战争克尼格雷茨战役","← 前因：普奥战争","→ 后果：普鲁士主导的北德意志邦联","→ 后果：普法战争","↔ 相关：俾斯麦出任普鲁士首相","↔ 相关：大德意志方案与小德意志方案","✗ 对立/冲突：奥地利主导秩序","✗ 对立/冲突：普鲁士北德重组","↔ 同时期参考：普鲁士俾斯麦赔偿法案"],"relations":[{"text":"← 前因：普奥战争克尼格雷茨战役","id":"extra543"},{"text":"← 前因：普奥战争","id":"extra495"},{"text":"→ 后果：普鲁士主导的北德意志邦联","id":"extra496"},{"text":"→ 后果：普法战争","id":"extra497"},{"text":"↔ 相关：俾斯麦出任普鲁士首相","id":"extra493"},{"text":"↔ 相关：大德意志方案与小德意志方案","id":"extra527"},{"text":"↔ 同时期参考：普鲁士俾斯麦赔偿法案","id":"extra545"}],"source":"history","id":"extra544"},{"title":"普鲁士俾斯麦赔偿法案","level":"B","type":"制度/文本卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1866年","place":"普鲁士王国","summary":"普鲁士俾斯麦赔偿法案为宪法冲突期间未经议会批准的预算支出寻求事后合法化，分裂了自由派。","fields":[{"label":"标题","value":"普鲁士俾斯麦赔偿法案"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1866年"},{"label":"地点","value":"普鲁士王国"},{"label":"主要国家","value":"普鲁士"},{"label":"一句话概括","value":"普鲁士俾斯麦赔偿法案为宪法冲突期间未经议会批准的预算支出寻求事后合法化，分裂了自由派。"},{"label":"制定方/签署方","value":"俾斯麦政府提出，普鲁士议会通过。"},{"label":"主要内容","value":"承认政府在宪法冲突期间已进行的征税和支出，并给予事后免责或批准。"},{"label":"它试图解决什么问题","value":"普奥战争胜利后，俾斯麦需要结束与议会的长期冲突，同时不承认政府此前行为完全违法。"},{"label":"为什么重要","value":"它使许多自由派接受“先统一、后自由”的妥协，推动民族自由派与俾斯麦合作。"},{"label":"争议/局限","value":"法案削弱议会预算权原则，也暴露自由主义在民族统一和宪政原则之间的困境。"},{"label":"造成的影响","value":"普鲁士宪法冲突缓和，民族自由主义转向支持俾斯麦统一政策。"},{"label":"出处","value":"German History in Documents and Images，Indemnity Bill materials；Encyclopaedia Britannica，Bismarck and Prussian constitutional conflict materials。"}],"relationItems":["← 前因：普鲁士宪法冲突","← 前因：普奥战争","→ 后果：德国民族自由党","→ 后果：普鲁士主导的北德意志邦联","↔ 相关：俾斯麦出任普鲁士首相","↔ 相关：德意志自由主义","✗ 对立/冲突：宪政原则","✗ 对立/冲突：民族统一成果","↔ 同时期参考：布拉格和约（1866）"],"relations":[{"text":"← 前因：普鲁士宪法冲突","id":"extra539"},{"text":"← 前因：普奥战争","id":"extra495"},{"text":"→ 后果：德国民族自由党","id":"extra674"},{"text":"→ 后果：普鲁士主导的北德意志邦联","id":"extra496"},{"text":"↔ 相关：俾斯麦出任普鲁士首相","id":"extra493"},{"text":"↔ 相关：德意志自由主义","id":"extra501"},{"text":"↔ 同时期参考：布拉格和约（1866）","id":"extra544"}],"source":"history","id":"extra545"},{"title":"北德意志邦联宪法","level":"B","type":"制度/文本卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1867年","place":"北德意志邦联","summary":"北德意志邦联宪法建立了普鲁士主导的联邦制度，成为1871年德意志帝国宪法的直接前身。","fields":[{"label":"标题","value":"北德意志邦联宪法"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1867年"},{"label":"地点","value":"北德意志邦联"},{"label":"主要国家","value":"普鲁士、北德诸邦"},{"label":"一句话概括","value":"北德意志邦联宪法建立了普鲁士主导的联邦制度，成为1871年德意志帝国宪法的直接前身。"},{"label":"制定方/签署方","value":"北德意志邦联成员国和制宪机构，普鲁士主导。"},{"label":"主要内容","value":"设立联邦主席、联邦参议机构和普选产生的帝国议会；军事、外交和关键权力集中于普鲁士主导的联邦层面。"},{"label":"它试图解决什么问题","value":"普奥战争后，普鲁士需要把北德诸邦纳入稳定制度，同时保留君主、邦国和普鲁士优势。"},{"label":"为什么重要","value":"它显示德意志统一不是突然在1871年完成，而是在1867年已形成基本制度模板。"},{"label":"争议/局限","value":"普选议会存在，但政府不对议会负责，联邦结构明显偏向普鲁士和行政权。"},{"label":"造成的影响","value":"为德意志帝国宪法提供蓝本，并把南德加入变成最后一步。"},{"label":"出处","value":"German History in Documents and Images，North German Confederation Constitution；Encyclopaedia Britannica，North German Confederation materials。"}],"relationItems":["← 前因：普鲁士主导的北德意志邦联","← 前因：布拉格和约（1866）","→ 后果：德意志帝国宪法","→ 后果：德意志帝国成立","↔ 相关：德意志帝国议会","↔ 相关：德意志帝国联邦参议院","✗ 对立/冲突：普选议会形式","✗ 对立/冲突：行政权主导实质","↔ 同时期参考：德国民族自由党"],"relations":[{"text":"← 前因：普鲁士主导的北德意志邦联","id":"extra496"},{"text":"← 前因：布拉格和约（1866）","id":"extra544"},{"text":"→ 后果：德意志帝国宪法","id":"extra624"},{"text":"→ 后果：德意志帝国成立","id":"extra621"},{"text":"↔ 相关：德意志帝国议会","id":"extra669"},{"text":"↔ 相关：德意志帝国联邦参议院","id":"extra670"},{"text":"↔ 同时期参考：德国民族自由党","id":"extra674"}],"source":"history","id":"extra546"},{"title":"霍亨索伦西班牙王位候选危机","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1870年","place":"西班牙、法国、普鲁士","summary":"霍亨索伦西班牙王位候选危机使法国担心被普鲁士势力包围，成为普法战争前的外交导火索。","fields":[{"label":"标题","value":"霍亨索伦西班牙王位候选危机"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1870年"},{"label":"地点","value":"西班牙、法国、普鲁士"},{"label":"主要国家","value":"西班牙、法国、普鲁士"},{"label":"一句话概括","value":"霍亨索伦西班牙王位候选危机使法国担心被普鲁士势力包围，成为普法战争前的外交导火索。"},{"label":"参与者","value":"霍亨索伦-西格马林根的利奥波德、拿破仑三世、俾斯麦、普鲁士国王威廉一世、西班牙政府。"},{"label":"发生了什么","value":"西班牙王位空缺后，霍亨索伦家族的利奥波德被考虑为王位候选人。法国担心普鲁士王室亲族控制西班牙，形成战略包围，强烈反对。利奥波德最终退出候选，但法国继续要求普鲁士保证未来不再支持类似候选，危机转向普法战争前埃姆斯电报事件。"},{"label":"为什么重要","value":"它说明普法战争并非单纯边境争端，而是欧洲王朝政治、民族声望和俾斯麦外交操作共同作用的结果。"},{"label":"前因","value":"普鲁士在1866年后迅速扩张，法国担心霍亨索伦家族若取得西班牙王位会使法国东西两面都受到普鲁士势力牵制。"},{"label":"后果","value":"候选人退让并未结束危机，法国要求进一步保证，普法战争前埃姆斯电报把外交争端转化为民族尊严冲突并直接推向普法战争。"},{"label":"出处","value":"Encyclopaedia Britannica，Franco-German War causes; Ems Telegram materials；German History in Documents and Images，Spanish candidacy crisis materials。"}],"relationItems":["← 前因：普鲁士主导的北德意志邦联","← 前因：布拉格和约（1866）","→ 后果：普法战争前埃姆斯电报","→ 后果：普法战争","↔ 相关：俾斯麦出任普鲁士首相","↔ 相关：法国第二帝国","✗ 对立/冲突：法国安全焦虑","✗ 对立/冲突：普鲁士外交机会","↔ 同时期参考：北德意志邦联宪法"],"relations":[{"text":"← 前因：普鲁士主导的北德意志邦联","id":"extra496"},{"text":"← 前因：布拉格和约（1866）","id":"extra544"},{"text":"→ 后果：普法战争前埃姆斯电报","id":"extra548"},{"text":"→ 后果：普法战争","id":"extra497"},{"text":"↔ 相关：俾斯麦出任普鲁士首相","id":"extra493"},{"text":"↔ 相关：法国第二帝国","id":"extra913"},{"text":"↔ 同时期参考：北德意志邦联宪法","id":"extra546"}],"source":"history","id":"extra547"},{"title":"普法战争前埃姆斯电报","level":"B","type":"事件卡","tags":["战争与外交","文化与思想"],"mainTag":"战争与外交","subTag":"文化与思想","timeText":"1870年7月","place":"普鲁士埃姆斯、柏林、巴黎","summary":"普法战争前埃姆斯电报经俾斯麦编辑公布后激化法普舆论，成为普法战争爆发的直接外交事件。","fields":[{"label":"标题","value":"普法战争前埃姆斯电报"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1870年7月"},{"label":"地点","value":"普鲁士埃姆斯、柏林、巴黎"},{"label":"主要国家","value":"普鲁士、法国"},{"label":"一句话概括","value":"普法战争前埃姆斯电报经俾斯麦编辑公布后激化法普舆论，成为普法战争爆发的直接外交事件。"},{"label":"参与者","value":"普鲁士国王威廉一世、法国大使贝内德蒂、俾斯麦、法国政府和公众舆论。"},{"label":"发生了什么","value":"法国要求普鲁士保证不再支持霍亨索伦家族成员竞逐西班牙王位。威廉一世在埃姆斯会见法国大使后向柏林报告经过。俾斯麦将电报内容压缩编辑后公布，使双方都显得受到冒犯。法国舆论和政府被推向宣战，普鲁士则获得南德诸邦支持。"},{"label":"为什么重要","value":"它是俾斯麦利用外交文本和大众舆论制造战争机会的典型案例。"},{"label":"前因","value":"西班牙王位候选危机已经使法普关系高度紧张，法国要求普鲁士国王作出额外保证，给俾斯麦制造了操作舆论的机会。"},{"label":"后果","value":"电报删改后的公开文本激怒法国舆论，法国宣战使南德诸邦站到普鲁士一边，普法战争由此爆发。"},{"label":"出处","value":"Encyclopaedia Britannica，“Ems Telegram”；German History in Documents and Images，Ems Dispatch materials。"}],"relationItems":["← 前因：霍亨索伦西班牙王位候选危机","→ 后果：普法战争","→ 后果：南德诸邦加入德意志帝国","↔ 相关：俾斯麦“铁血演说”","↔ 相关：德意志民族主义","✗ 对立/冲突：外交降温","✗ 对立/冲突：民族舆论激化","↔ 同时期参考：北德意志邦联宪法"],"relations":[{"text":"← 前因：霍亨索伦西班牙王位候选危机","id":"extra547"},{"text":"→ 后果：普法战争","id":"extra497"},{"text":"→ 后果：南德诸邦加入德意志帝国","id":"extra550"},{"text":"↔ 相关：俾斯麦“铁血演说”","id":"extra540"},{"text":"↔ 相关：德意志民族主义","id":"extra504"},{"text":"↔ 同时期参考：北德意志邦联宪法","id":"extra546"}],"source":"history","id":"extra548"},{"title":"普法战争色当战役","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1870年9月1日—9月2日","place":"法国色当","summary":"普法战争色当战役中拿破仑三世被俘，法国第二帝国崩溃，普法战争转入共和国继续抵抗阶段。","fields":[{"label":"标题","value":"普法战争色当战役"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1870年9月1日—9月2日"},{"label":"地点","value":"法国色当"},{"label":"主要国家","value":"普鲁士及德意志盟军、法国"},{"label":"一句话概括","value":"普法战争色当战役中拿破仑三世被俘，法国第二帝国崩溃，普法战争转入共和国继续抵抗阶段。"},{"label":"参与者","value":"普鲁士及德意志盟军、法国军队、拿破仑三世、老毛奇、威廉一世。"},{"label":"发生了什么","value":"普法战争初期，德意志联军在法国东北部围困法军主力。色当会战中，法军被包围并遭炮火压制，拿破仑三世和大批法军投降。巴黎随即爆发政治变化，法国第二帝国倒台，第三共和国宣布成立并继续战争。"},{"label":"为什么重要","value":"它摧毁了法国第二帝国，也为德意志统一创造了强烈民族胜利氛围。"},{"label":"前因","value":"普法战争中法国军队试图解救被围困的部队并扭转战局，但普鲁士和德意志联军在组织、动员和指挥上占据优势。"},{"label":"后果","value":"拿破仑三世被俘导致法国第二帝国崩溃，德国统一的军事和心理条件成熟，战争随后转入对法国共和国的继续作战。"},{"label":"出处","value":"Encyclopaedia Britannica，“Battle of Sedan”；German History in Documents and Images，Franco-Prussian War materials。"}],"relationItems":["← 前因：普法战争前埃姆斯电报","← 前因：普法战争","→ 后果：德意志帝国成立","→ 后果：普法战争《法兰克福和约》","↔ 相关：老毛奇与普鲁士总参谋部","↔ 相关：南德诸邦加入德意志帝国","✗ 对立/冲突：法国第二帝国","✗ 对立/冲突：普鲁士主导的北德意志邦联","↔ 同时期参考：巴黎围城"],"relations":[{"text":"← 前因：普法战争前埃姆斯电报","id":"extra548"},{"text":"← 前因：普法战争","id":"extra497"},{"text":"→ 后果：德意志帝国成立","id":"extra621"},{"text":"→ 后果：普法战争《法兰克福和约》","id":"extra551"},{"text":"↔ 相关：老毛奇与普鲁士总参谋部","id":"extra538"},{"text":"↔ 相关：南德诸邦加入德意志帝国","id":"extra550"},{"text":"✗ 对立/冲突：法国第二帝国","id":"extra913"},{"text":"✗ 对立/冲突：普鲁士主导的北德意志邦联","id":"extra496"}],"source":"history","id":"extra549"},{"title":"南德诸邦加入德意志帝国","level":"B","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1870年—1871年","place":"巴伐利亚、符腾堡、巴登、黑森南部与北德意志邦联相关地区","summary":"南德诸邦在普法战争中倒向普鲁士主导的统一框架，使小德意志帝国最终成形。","fields":[{"label":"标题","value":"南德诸邦加入德意志帝国"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1870年—1871年"},{"label":"地点","value":"巴伐利亚、符腾堡、巴登、黑森南部与北德意志邦联相关地区"},{"label":"主要国家","value":"普鲁士、巴伐利亚、符腾堡、巴登、黑森、法国"},{"label":"一句话概括","value":"南德诸邦在普法战争中倒向普鲁士主导的统一框架，使小德意志帝国最终成形。"},{"label":"参与者","value":"普鲁士政府、南德诸邦政府、俾斯麦、巴伐利亚国王路德维希二世等。"},{"label":"发生了什么","value":"普奥战争后，南德诸邦尚未加入北德意志邦联，但与普鲁士有军事同盟。普法战争爆发后，南德军队与北德并肩作战，民族主义情绪和安全需求推动统一谈判。1870年底，南德诸邦通过条约加入新的德意志帝国框架，并保留部分特殊权利。"},{"label":"为什么重要","value":"它是1871年帝国成立的最后制度步骤，说明统一需要战争动员、邦国谈判和普鲁士主导三者结合。"},{"label":"前因","value":"北德意志邦联已经形成普鲁士主导的统一框架，普法战争又把南德诸邦纳入共同民族战争和军事合作之中。"},{"label":"后果","value":"南德诸邦通过谈判加入新帝国，德意志帝国宪法继承并扩展北德意志邦联体制，1871年统一由此完成。"},{"label":"出处","value":"German History in Documents and Images，November Treaties and German unification materials；Encyclopaedia Britannica，German Empire foundation materials。"}],"relationItems":["← 前因：北德意志邦联宪法","← 前因：普法战争","→ 后果：德意志帝国成立","→ 后果：德意志帝国宪法","↔ 相关：德意志民族主义","↔ 相关：巴伐利亚特殊权利","✗ 对立/冲突：南德邦国自主","✗ 对立/冲突：普鲁士主导统一","↔ 同时期参考：普法战争色当战役"],"relations":[{"text":"← 前因：北德意志邦联宪法","id":"extra546"},{"text":"← 前因：普法战争","id":"extra497"},{"text":"→ 后果：德意志帝国成立","id":"extra621"},{"text":"→ 后果：德意志帝国宪法","id":"extra624"},{"text":"↔ 相关：德意志民族主义","id":"extra504"},{"text":"↔ 同时期参考：普法战争色当战役","id":"extra549"}],"source":"history","id":"extra550"},{"title":"普法战争《法兰克福和约》","level":"B","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1871年5月10日","place":"法兰克福","summary":"1871年普法战争《法兰克福和约》结束普法战争，法国割让阿尔萨斯-洛林并支付赔款，埋下法德长期敌意。","fields":[{"label":"标题","value":"普法战争《法兰克福和约》"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1871年5月10日"},{"label":"地点","value":"法兰克福"},{"label":"主要国家","value":"德国、法国"},{"label":"一句话概括","value":"1871年普法战争《法兰克福和约》结束普法战争，法国割让阿尔萨斯-洛林并支付赔款，埋下法德长期敌意。"},{"label":"制定方/签署方","value":"德意志帝国与法国第三共和国。"},{"label":"主要内容","value":"法国割让阿尔萨斯和洛林部分地区，支付巨额赔款，并接受德军占领至赔款支付安排完成。"},{"label":"它试图解决什么问题","value":"普法战争需要正式和平安排，德国希望通过领土和赔款巩固胜利，法国则被迫接受战败条件。"},{"label":"为什么重要","value":"它使德意志帝国成立后的欧洲秩序带有强烈复仇和安全困境色彩，阿尔萨斯-洛林问题成为法德关系核心伤口。"},{"label":"争议/局限","value":"和约短期强化德国安全和民族荣耀，长期却加深德法复仇主义。"},{"label":"造成的影响","value":"阿尔萨斯-洛林并入德国，法国赔款和军事占领影响第三共和国早期政治。"},{"label":"出处","value":"Encyclopaedia Britannica，“Treaty of Frankfurt”；German History in Documents and Images，Franco-Prussian War settlement materials。"}],"relationItems":["← 前因：普法战争","← 前因：普法战争色当战役","→ 后果：阿尔萨斯-洛林问题的形成","→ 后果：德意志帝国外交安全困境","↔ 相关：德意志帝国成立","↔ 相关：德法复仇主义","✗ 对立/冲突：德国安全需求","✗ 对立/冲突：法国复仇情绪","↔ 同时期参考：巴黎公社"],"relations":[{"text":"← 前因：普法战争","id":"extra497"},{"text":"← 前因：普法战争色当战役","id":"extra549"},{"text":"→ 后果：阿尔萨斯-洛林问题的形成","id":"extra620"},{"text":"↔ 相关：德意志帝国成立","id":"extra621"},{"text":"↔ 相关：德法复仇主义","id":"extra945"}],"source":"history","id":"extra551"},{"title":"德意志浪漫主义","level":"B","type":"概念/思潮卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"18世纪末—19世纪前期","place":"德意志各邦，尤其耶拿、海德堡、柏林等文化中心","summary":"德意志浪漫主义重视情感、民族语言、民间传统和中世纪想象，是德国民族文化建构的重要思想背景。","fields":[{"label":"标题","value":"德意志浪漫主义"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"18世纪末—19世纪前期"},{"label":"地点","value":"德意志各邦，尤其耶拿、海德堡、柏林等文化中心"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德意志浪漫主义重视情感、民族语言、民间传统和中世纪想象，是德国民族文化建构的重要思想背景。"},{"label":"核心主张/思路","value":"反对把理性和古典规则视为唯一标准，强调想象、个体内心、自然、历史记忆、民歌传说和民族语言的文化价值。"},{"label":"提出者/代表人物（可选）","value":"诺瓦利斯、施莱格尔兄弟、蒂克、阿尔尼姆、布伦塔诺、格林兄弟等。"},{"label":"它从何而来","value":"启蒙理性、法国大革命、拿破仑战争和德意志政治分裂共同促使知识分子寻找不同于法国普遍主义的文化共同体基础。"},{"label":"典型表现","value":"民歌和童话采集，中世纪和哥特传统复兴，文学中的神秘、自然和民族精神主题，以及对语言和民俗的学术兴趣。"},{"label":"为什么重要","value":"它解释德意志民族主义为什么经常以语言、文学、民俗和历史记忆为入口，而不只是领土和国家制度问题。"},{"label":"争议/局限","value":"浪漫主义能激发文化创造，也可能把民族精神神秘化、排他化，为后来的文化民族主义提供资源。"},{"label":"出处","value":"Britannica, Romanticism；Britannica, German literature: Romanticism。"}],"relationItems":["← 前因：德意志启蒙运动","→ 后果：格林兄弟《格林童话》","↔ 相关：费希特《告德意志民族书》","↔ 相关：德意志民族主义","↔ 同时期参考：欧洲浪漫主义"],"relations":[{"text":"← 前因：德意志启蒙运动","id":"extra317"},{"text":"→ 后果：格林兄弟《格林童话》","id":"extra79"},{"text":"↔ 相关：费希特《告德意志民族书》","id":"extra78"},{"text":"↔ 相关：德意志民族主义","id":"extra504"}],"source":"history","id":"extra552"},{"title":"德意志比德迈文化","level":"C","type":"概念/思潮卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1815—1848年","place":"德意志邦联和奥地利帝国德语城市","summary":"德意志比德迈文化强调家庭、室内生活、小市民安定和克制审美，是维也纳体系下德语中产生活的文化侧面。","fields":[{"label":"标题","value":"德意志比德迈文化"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1815—1848年"},{"label":"地点","value":"德意志邦联和奥地利帝国德语城市"},{"label":"主要国家","value":"德国；奥地利"},{"label":"一句话概括","value":"德意志比德迈文化强调家庭、室内生活、小市民安定和克制审美，是维也纳体系下德语中产生活的文化侧面。"},{"label":"核心主张/思路","value":"在政治压制和公共生活受限环境下，把注意力转向家庭、室内装饰、私人阅读、音乐会和日常安宁。"},{"label":"提出者/代表人物（可选）","value":"不是单一人物提出，而是文学、绘画、家具、室内装饰和市民生活共同形成的文化风格。"},{"label":"它从何而来","value":"拿破仑战争后维也纳体系压制革命和自由主义政治，许多中产阶层把自我实现转向私人生活和小尺度审美。"},{"label":"典型表现","value":"简洁家具、家庭音乐、日常题材绘画、市民小说和温和讽刺文学。"},{"label":"为什么重要","value":"它补足了1815—1848年不只是政治压抑和革命酝酿，也有一种追求安全、家庭和可控生活的中产文化。"},{"label":"争议/局限","value":"比德迈常被批评为回避政治，但它也真实反映了普通市民在保守秩序下寻找生活稳定的方式。"},{"label":"出处","value":"Britannica, Biedermeier style；Metropolitan Museum of Art, Biedermeier。"}],"relationItems":["← 前因：维也纳体系","→ 后果：德意志Vormärz时期","↔ 相关：德意志自由主义","↔ 相关：德国汉巴赫节","↔ 同时期参考：英国维多利亚早期家庭文化"],"relations":[{"text":"→ 后果：德意志Vormärz时期","id":"extra502"},{"text":"↔ 相关：德意志自由主义","id":"extra501"},{"text":"↔ 相关：德国汉巴赫节","id":"extra489"}],"source":"history","id":"extra553"},{"title":"奥地利帝国成立","level":"A","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1804年8月11日","place":"维也纳","summary":"弗朗茨二世建立奥地利帝国，为哈布斯堡在神圣罗马帝国危机中保留王朝帝号。","fields":[{"label":"标题","value":"奥地利帝国成立"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1804年8月11日"},{"label":"地点","value":"维也纳"},{"label":"主要国家","value":"奥地利；哈布斯堡君主国；神圣罗马帝国"},{"label":"一句话概括","value":"弗朗茨二世建立奥地利帝国，为哈布斯堡在神圣罗马帝国危机中保留王朝帝号。"},{"label":"参与者","value":"弗朗茨二世、哈布斯堡宫廷、奥地利世袭领地。"},{"label":"发生了什么","value":"1804年，面对拿破仑称帝和神圣罗马帝国秩序危机，弗朗茨二世宣布建立奥地利帝国，自称奥地利皇帝弗朗茨一世。"},{"label":"为什么重要","value":"它预先为哈布斯堡王朝准备了独立于神圣罗马帝国的帝号和国家框架。"},{"label":"前因","value":"法国革命战争和拿破仑崛起严重削弱旧帝国，哈布斯堡需要在帝国解体风险中维护王朝尊严和多民族领地统一。"},{"label":"后果","value":"1806年神圣罗马帝国解体后，哈布斯堡仍以奥地利帝国为中心延续大国地位；奥地利也从帝国皇权中心转向多民族王朝国家。"},{"label":"出处","value":"Britannica, Austrian Empire；Britannica, Francis II。"}],"relationItems":["← 前因：法奥《吕内维尔和约》","→ 后果：神圣罗马帝国解体","↔ 相关：弗朗茨二世/一世","↔ 相关：哈布斯堡君主国"],"relations":[{"text":"← 前因：法奥《吕内维尔和约》","id":"extra481"},{"text":"→ 后果：神圣罗马帝国解体","id":"extra520"},{"text":"↔ 相关：弗朗茨二世/一世","id":"extra555"},{"text":"↔ 相关：哈布斯堡君主国","id":"extra309"}],"source":"history","id":"extra554"},{"title":"弗朗茨二世/一世","level":"B","type":"人物卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1768—1835年；1792—1806年为神圣罗马皇帝，1804—1835年为奥地利皇帝","place":"维也纳、神圣罗马帝国、奥地利帝国","summary":"弗朗茨二世/一世见证旧帝国灭亡，并把哈布斯堡权力转入奥地利帝国框架。","fields":[{"label":"标题","value":"弗朗茨二世/一世"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1768—1835年；1792—1806年为神圣罗马皇帝，1804—1835年为奥地利皇帝"},{"label":"地点","value":"维也纳、神圣罗马帝国、奥地利帝国"},{"label":"主要国家","value":"奥地利；神圣罗马帝国；法国"},{"label":"一句话概括","value":"弗朗茨二世/一世见证旧帝国灭亡，并把哈布斯堡权力转入奥地利帝国框架。"},{"label":"生卒年/活跃年代","value":"1768—1835年。"},{"label":"身份/职务","value":"最后一位神圣罗马皇帝弗朗茨二世，第一位奥地利皇帝弗朗茨一世。"},{"label":"关键贡献/作为","value":"在法国革命战争和拿破仑战争中领导哈布斯堡抗法，1804年建立奥地利帝国，1806年放弃神圣罗马帝国皇位。"},{"label":"核心主张/立场","value":"维护哈布斯堡王朝和旧制度秩序，反对法国革命和拿破仑对欧洲格局的重塑。"},{"label":"为什么重要","value":"他是旧神圣罗马帝国与新奥地利帝国之间的转折人物。"},{"label":"争议/评价","value":"其保守路线延续哈布斯堡稳定，也限制内部改革；面对拿破仑时屡遭军事失败。"},{"label":"关联事件（可选）","value":"奥地利帝国成立；拿破仑战争奥斯特里茨战役；神圣罗马帝国解体。"},{"label":"出处","value":"Britannica, Francis II；Britannica, Austrian Empire。"}],"relationItems":["← 前因：奥地利帝国成立","→ 后果：神圣罗马帝国解体","↔ 相关：第三次反法同盟战争","↔ 相关：奥地利与普鲁士二元主义"],"relations":[{"text":"← 前因：奥地利帝国成立","id":"extra554"},{"text":"→ 后果：神圣罗马帝国解体","id":"extra520"},{"text":"↔ 相关：第三次反法同盟战争","id":"extra556"},{"text":"↔ 相关：奥地利与普鲁士二元主义","id":"extra535"}],"source":"history","id":"extra555"},{"title":"第三次反法同盟战争","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1805年","place":"中欧、意大利、德意志南部、奥地利","summary":"第三次反法同盟战争中奥俄英试图遏制拿破仑，结果奥地利在中欧遭决定性失败。","fields":[{"label":"标题","value":"第三次反法同盟战争"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1805年"},{"label":"地点","value":"中欧、意大利、德意志南部、奥地利"},{"label":"主要国家","value":"法国；奥地利；俄罗斯；英国；神圣罗马帝国"},{"label":"一句话概括","value":"第三次反法同盟战争中奥俄英试图遏制拿破仑，结果奥地利在中欧遭决定性失败。"},{"label":"参与者","value":"拿破仑法国、奥地利、俄罗斯、英国、德意志南部诸邦。"},{"label":"发生了什么","value":"1805年，英国、奥地利和俄罗斯组成反法同盟。拿破仑迅速调动大军进入德意志南部，先在乌尔姆迫使奥军投降，随后在奥斯特里茨击败奥俄联军。"},{"label":"为什么重要","value":"它直接摧毁奥地利在德意志南部的影响力，并为莱茵邦和神圣罗马帝国解体铺路。"},{"label":"前因","value":"拿破仑称帝和法国扩张引发欧洲列强担忧，奥地利希望恢复在德意志和意大利的地位；英国也需要大陆盟友牵制法国。"},{"label":"后果","value":"拿破仑战争《普雷斯堡和约》迫使奥地利割让利益，巴伐利亚、符腾堡等德意志南部邦国转向拿破仑；旧帝国南部支柱被法国体系吸走。"},{"label":"出处","value":"Britannica, Third Coalition；Britannica, Napoleonic Wars；Britannica, Napoleon I。"}],"relationItems":["← 前因：奥地利帝国成立","→ 后果：拿破仑战争乌尔姆战役","→ 后果：拿破仑战争奥斯特里茨战役","↔ 相关：拿破仑莱茵邦"],"relations":[{"text":"← 前因：奥地利帝国成立","id":"extra554"},{"text":"→ 后果：拿破仑战争乌尔姆战役","id":"extra557"},{"text":"→ 后果：拿破仑战争奥斯特里茨战役","id":"extra558"},{"text":"↔ 相关：拿破仑莱茵邦","id":"extra521"}],"source":"history","id":"extra556"},{"title":"拿破仑战争乌尔姆战役","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1805年10月","place":"乌尔姆","summary":"拿破仑在乌尔姆机动包围奥军，展示法军作战体系对旧式联军的优势。","fields":[{"label":"标题","value":"拿破仑战争乌尔姆战役"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1805年10月"},{"label":"地点","value":"乌尔姆"},{"label":"主要国家","value":"法国；奥地利；德意志地区"},{"label":"一句话概括","value":"拿破仑在乌尔姆机动包围奥军，展示法军作战体系对旧式联军的优势。"},{"label":"参与者","value":"拿破仑、法国大军团、奥地利将领马克及奥军。"},{"label":"发生了什么","value":"第三次反法同盟战争中，奥军进入德意志南部。拿破仑以快速机动切断奥军退路，在乌尔姆附近完成包围，迫使大批奥军投降。"},{"label":"为什么重要","value":"它在奥斯特里茨前削弱奥地利主力，显示拿破仑军团体系和机动作战的威力。"},{"label":"前因","value":"奥地利希望先发制人进入巴伐利亚，但德意志南部盟友不稳，法军调动速度超过奥军预期；拿破仑利用军团机动迅速切断奥军退路。"},{"label":"后果","value":"奥地利失去大量兵力，拿破仑得以继续向维也纳和摩拉维亚推进，与俄奥联军决战；第三次反法同盟的战略主动权转入法国手中。"},{"label":"出处","value":"Britannica, Battle of Ulm；Britannica, Napoleonic Wars；Britannica, Napoleon I。"}],"relationItems":["← 前因：第三次反法同盟战争","→ 后果：拿破仑战争奥斯特里茨战役","↔ 相关：拿破仑战争《普雷斯堡和约》","↔ 同时期参考：拿破仑战争"],"relations":[{"text":"← 前因：第三次反法同盟战争","id":"extra556"},{"text":"→ 后果：拿破仑战争奥斯特里茨战役","id":"extra558"},{"text":"↔ 相关：拿破仑战争《普雷斯堡和约》","id":"extra559"},{"text":"↔ 同时期参考：拿破仑战争","id":"extra918"}],"source":"history","id":"extra557"},{"title":"拿破仑战争奥斯特里茨战役","level":"A","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1805年12月2日","place":"摩拉维亚奥斯特里茨附近，今捷克斯拉夫科夫","summary":"拿破仑战争奥斯特里茨战役中拿破仑击败奥俄联军，直接导致第三次反法同盟崩溃。","fields":[{"label":"标题","value":"拿破仑战争奥斯特里茨战役"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1805年12月2日"},{"label":"地点","value":"摩拉维亚奥斯特里茨附近，今捷克斯拉夫科夫"},{"label":"主要国家","value":"法国；奥地利；俄罗斯；神圣罗马帝国"},{"label":"一句话概括","value":"拿破仑战争奥斯特里茨战役中拿破仑击败奥俄联军，直接导致第三次反法同盟崩溃。"},{"label":"参与者","value":"拿破仑、法国大军团、俄国沙皇亚历山大一世、奥地利皇帝弗朗茨二世、奥俄联军。"},{"label":"发生了什么","value":"1805年12月，拿破仑在奥斯特里茨附近诱使奥俄联军进攻其看似薄弱的右翼，随后集中力量夺取普拉岑高地并分割联军。奥俄联军惨败。"},{"label":"为什么重要","value":"它是拿破仑最著名的胜利之一，摧毁奥地利继续作战能力，并加速神圣罗马帝国终结。"},{"label":"前因","value":"乌尔姆失败后，奥地利寄望俄军支援扭转局势；拿破仑则希望以一次决战迫使奥地利退出战争，并在俄军完全整合前击败联军。"},{"label":"后果","value":"奥地利签署拿破仑战争《普雷斯堡和约》，德意志南部邦国获得奖励并靠拢法国，旧帝国权威彻底动摇；1806年莱茵邦和帝国解体随即发生。"},{"label":"出处","value":"Britannica, Battle of Austerlitz；Britannica, Napoleonic Wars；Britannica, Napoleon I。"}],"relationItems":["← 前因：拿破仑战争乌尔姆战役","→ 后果：拿破仑战争《普雷斯堡和约》","→ 后果：拿破仑莱茵邦","↔ 相关：神圣罗马帝国解体"],"relations":[{"text":"← 前因：拿破仑战争乌尔姆战役","id":"extra557"},{"text":"→ 后果：拿破仑战争《普雷斯堡和约》","id":"extra559"},{"text":"→ 后果：拿破仑莱茵邦","id":"extra521"},{"text":"↔ 相关：神圣罗马帝国解体","id":"extra520"}],"source":"history","id":"extra558"},{"title":"拿破仑战争《普雷斯堡和约》","level":"A","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1805年12月26日","place":"普雷斯堡，今斯洛伐克布拉迪斯拉发","summary":"拿破仑战争《普雷斯堡和约》惩罚奥地利并奖励德意志南部邦国，为莱茵邦和旧帝国解体铺路。","fields":[{"label":"标题","value":"拿破仑战争《普雷斯堡和约》"},{"label":"分级","value":"A"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1805年12月26日"},{"label":"地点","value":"普雷斯堡，今斯洛伐克布拉迪斯拉发"},{"label":"主要国家","value":"法国；奥地利；巴伐利亚；符腾堡；巴登"},{"label":"一句话概括","value":"拿破仑战争《普雷斯堡和约》惩罚奥地利并奖励德意志南部邦国，为莱茵邦和旧帝国解体铺路。"},{"label":"制定方/签署方","value":"拿破仑法国与奥地利。"},{"label":"主要内容","value":"奥地利割让领土和影响力，承认巴伐利亚、符腾堡等德意志南部盟友的升格和收益，并接受法国在中欧的新安排。"},{"label":"它试图解决什么问题","value":"它试图结束第三次反法同盟战争中法国与奥地利的冲突，并把奥斯特里茨胜利转化为制度和领土成果。"},{"label":"为什么重要","value":"它把德意志南部邦国推向拿破仑体系，严重削弱神圣罗马帝国和奥地利在德意志的传统权威。"},{"label":"争议/局限","value":"和约建立在法国军事优势上，并未带来稳定和平；普鲁士和奥地利很快仍会重新卷入反法战争。"},{"label":"造成的影响","value":"巴伐利亚和符腾堡等获得更高地位，1806年莱茵邦成立，神圣罗马帝国随即解体。"},{"label":"出处","value":"Britannica, Treaty of Pressburg；Britannica, Confederation of the Rhine；Britannica, Napoleonic Wars。"}],"relationItems":["← 前因：拿破仑战争奥斯特里茨战役","→ 后果：拿破仑莱茵邦","→ 后果：神圣罗马帝国解体","↔ 相关：第三次反法同盟战争"],"relations":[{"text":"← 前因：拿破仑战争奥斯特里茨战役","id":"extra558"},{"text":"→ 后果：拿破仑莱茵邦","id":"extra521"},{"text":"→ 后果：神圣罗马帝国解体","id":"extra520"},{"text":"↔ 相关：第三次反法同盟战争","id":"extra556"}],"source":"history","id":"extra559"},{"title":"第四次反法同盟战争","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1806—1807年","place":"德意志、波兰、东普鲁士、俄国边境地区","summary":"第四次反法同盟战争使普鲁士遭毁灭性失败，拿破仑体系在中欧达到高峰。","fields":[{"label":"标题","value":"第四次反法同盟战争"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1806—1807年"},{"label":"地点","value":"德意志、波兰、东普鲁士、俄国边境地区"},{"label":"主要国家","value":"法国；普鲁士；俄罗斯；萨克森；莱茵邦"},{"label":"一句话概括","value":"第四次反法同盟战争使普鲁士遭毁灭性失败，拿破仑体系在中欧达到高峰。"},{"label":"参与者","value":"拿破仑法国、普鲁士、俄罗斯、萨克森、瑞典、英国以及莱茵邦诸邦。"},{"label":"发生了什么","value":"1806年，普鲁士因法国在德意志的扩张和莱茵邦建立而对法开战，但在耶拿-奥尔施泰特遭决定性失败。法国迅速占领柏林，并继续向东与俄军交战，最终以1807年拿破仑战争《提尔西特和约》结束战争。"},{"label":"为什么重要","value":"它是普鲁士旧制度崩溃的直接触发点，也是普鲁士改革和后续德意志反法民族动员的前提。"},{"label":"前因","value":"奥斯特里茨和拿破仑战争《普雷斯堡和约》后，法国控制德意志南部并建立莱茵邦，普鲁士感到大国地位和北德影响受到威胁。"},{"label":"后果","value":"普鲁士被迫割地、赔款并接受法国控制，俄法暂时结盟，拿破仑在中欧建立提尔西特后的霸权秩序；普鲁士改革和后来的反法复仇由此获得现实动力。"},{"label":"出处","value":"Britannica, Napoleon I；Britannica, Napoleonic Wars；Britannica, Battle of Jena。"}],"relationItems":["← 前因：拿破仑战争《普雷斯堡和约》","→ 后果：拿破仑战争耶拿-奥尔施泰特战役","→ 后果：拿破仑战争《提尔西特和约》","↔ 相关：拿破仑莱茵邦"],"relations":[{"text":"← 前因：拿破仑战争《普雷斯堡和约》","id":"extra559"},{"text":"→ 后果：拿破仑战争耶拿-奥尔施泰特战役","id":"extra561"},{"text":"→ 后果：拿破仑战争《提尔西特和约》","id":"extra564"},{"text":"↔ 相关：拿破仑莱茵邦","id":"extra521"}],"source":"history","id":"extra560"},{"title":"拿破仑战争耶拿-奥尔施泰特战役","level":"A","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1806年10月14日","place":"耶拿和奥尔施泰特，今德国图林根、萨克森-安哈尔特地区","summary":"耶拿-奥尔施泰特战役中普鲁士军队被拿破仑体系击溃，旧普鲁士军事威望崩塌。","fields":[{"label":"标题","value":"拿破仑战争耶拿-奥尔施泰特战役"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1806年10月14日"},{"label":"地点","value":"耶拿和奥尔施泰特，今德国图林根、萨克森-安哈尔特地区"},{"label":"主要国家","value":"法国；普鲁士；萨克森"},{"label":"一句话概括","value":"耶拿-奥尔施泰特战役中普鲁士军队被拿破仑体系击溃，旧普鲁士军事威望崩塌。"},{"label":"参与者","value":"拿破仑、达武、普鲁士国王弗里德里希·威廉三世、布伦瑞克公爵、普鲁士和萨克森军队。"},{"label":"发生了什么","value":"1806年10月14日，法军在耶拿和奥尔施泰特两个战场同时击败普鲁士-萨克森军队。拿破仑在耶拿取胜，达武则以较少兵力在奥尔施泰特击败普鲁士主力。普鲁士军队随后迅速崩溃，大量要塞和部队投降。"},{"label":"为什么重要","value":"它打破腓特烈大王以来普鲁士军事强国神话，迫使普鲁士进行行政、社会和军事改革。"},{"label":"前因","value":"普鲁士对法国控制德意志局势不满，但军队组织、指挥和战术仍停留在旧制度模式，无法适应拿破仑军团体系。"},{"label":"后果","value":"拿破仑战争中拿破仑占领柏林，普鲁士国家濒临崩溃，拿破仑战争《提尔西特和约》把普鲁士降为法国附庸式弱国；旧军制和旧行政的失败因此无可回避。"},{"label":"出处","value":"Britannica, Battle of Jena；Britannica, Napoleon I；Britannica, Prussia。"}],"relationItems":["← 前因：第四次反法同盟战争","→ 后果：拿破仑战争中拿破仑占领柏林","→ 后果：普鲁士施泰因-哈登贝格改革","↔ 相关：沙恩霍斯特与普鲁士军事改革"],"relations":[{"text":"← 前因：第四次反法同盟战争","id":"extra560"},{"text":"→ 后果：拿破仑战争中拿破仑占领柏林","id":"extra562"},{"text":"→ 后果：普鲁士施泰因-哈登贝格改革","id":"extra522"},{"text":"↔ 相关：沙恩霍斯特与普鲁士军事改革","id":"extra574"}],"source":"history","id":"extra561"},{"title":"拿破仑战争中拿破仑占领柏林","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1806年10月27日","place":"柏林","summary":"拿破仑进入柏林象征普鲁士战败和法国对德意志北部的短期支配。","fields":[{"label":"标题","value":"拿破仑战争中拿破仑占领柏林"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1806年10月27日"},{"label":"地点","value":"柏林"},{"label":"主要国家","value":"法国；普鲁士"},{"label":"一句话概括","value":"拿破仑进入柏林象征普鲁士战败和法国对德意志北部的短期支配。"},{"label":"参与者","value":"拿破仑、法国大军团、普鲁士王室和柏林城市社会。"},{"label":"发生了什么","value":"耶拿-奥尔施泰特战役后，普鲁士主力溃散。拿破仑率军进入柏林，普鲁士王室向东撤退，法国开始控制普鲁士核心地区并征收军费、调配资源。"},{"label":"为什么重要","value":"柏林被占领让普鲁士精英直面国家生存危机，也为《柏林敕令》和拿破仑大陆封锁体系提供发布场景。"},{"label":"前因","value":"普鲁士在双重战役中被击败，军队和要塞系统连锁崩溃，法国快速推进到普鲁士首都；王室和政府来不及组织有效防御。"},{"label":"后果","value":"普鲁士行政和社会受到占领压力，法国对英国的经济战升级，普鲁士改革派获得推动重建的现实理由。"},{"label":"出处","value":"Britannica, Napoleon I；Britannica, Continental System；Britannica, Berlin Decree。"}],"relationItems":["← 前因：拿破仑战争耶拿-奥尔施泰特战役","→ 后果：拿破仑大陆封锁体系","→ 后果：拿破仑战争《提尔西特和约》","↔ 相关：普鲁士施泰因-哈登贝格改革"],"relations":[{"text":"← 前因：拿破仑战争耶拿-奥尔施泰特战役","id":"extra561"},{"text":"→ 后果：拿破仑大陆封锁体系","id":"extra563"},{"text":"→ 后果：拿破仑战争《提尔西特和约》","id":"extra564"},{"text":"↔ 相关：普鲁士施泰因-哈登贝格改革","id":"extra522"}],"source":"history","id":"extra562"},{"title":"拿破仑大陆封锁体系","level":"B","type":"制度/文本卡","tags":["经济与社会","战争与外交"],"mainTag":"经济与社会","subTag":"战争与外交","timeText":"1806—1814年","place":"法国及其附庸、盟国和占领区，覆盖欧洲大陆多地","summary":"拿破仑大陆封锁体系是拿破仑对英国的经济战，也深刻扰动德意志和欧洲大陆经济。","fields":[{"label":"标题","value":"拿破仑大陆封锁体系"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1806—1814年"},{"label":"地点","value":"法国及其附庸、盟国和占领区，覆盖欧洲大陆多地"},{"label":"主要国家","value":"法国；英国；莱茵邦；普鲁士；俄罗斯；德意志地区"},{"label":"一句话概括","value":"拿破仑大陆封锁体系是拿破仑对英国的经济战，也深刻扰动德意志和欧洲大陆经济。"},{"label":"制定方/签署方","value":"拿破仑法国，以1806年《柏林敕令》和1807年《米兰敕令》等为核心。"},{"label":"主要内容","value":"禁止法国及其盟友、附庸和占领区与英国贸易，试图把英国商品排除出欧洲大陆市场。"},{"label":"它试图解决什么问题","value":"法国海上力量无法击败英国，拿破仑试图通过经济封锁削弱英国财政、工业和战争能力。"},{"label":"为什么重要","value":"它把拿破仑战争从军事征服扩展为经济控制，也导致走私、港口衰退、工业扭曲和盟国不满。"},{"label":"争议/局限","value":"英国依靠海权和全球市场缓冲冲击，欧洲大陆许多地区反而因贸易中断受损。"},{"label":"造成的影响","value":"大陆封锁加剧德意志港口和商业地区压力，也刺激法国对北德沿海和俄罗斯政策的控制欲。"},{"label":"出处","value":"Britannica, Continental System；Britannica, Berlin Decree；Britannica, Napoleon I。"}],"relationItems":["← 前因：拿破仑战争中拿破仑占领柏林","↔ 相关：拿破仑莱茵邦","→ 后果：拿破仑入侵俄国（1812）","↔ 同时期参考：英国海上霸权"],"relations":[{"text":"← 前因：拿破仑战争中拿破仑占领柏林","id":"extra562"},{"text":"↔ 相关：拿破仑莱茵邦","id":"extra521"},{"text":"→ 后果：拿破仑入侵俄国（1812）","id":"extra910"},{"text":"↔ 同时期参考：英国海上霸权","id":"extra906"}],"source":"history","id":"extra563"},{"title":"拿破仑战争《提尔西特和约》","level":"A","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1807年7月7日、7月9日","place":"提尔西特，今俄罗斯苏维埃茨克","summary":"拿破仑战争《提尔西特和约》结束第四次反法同盟战争，使普鲁士遭重创并确立拿破仑中欧霸权。","fields":[{"label":"标题","value":"拿破仑战争《提尔西特和约》"},{"label":"分级","value":"A"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1807年7月7日、7月9日"},{"label":"地点","value":"提尔西特，今俄罗斯苏维埃茨克"},{"label":"主要国家","value":"法国；俄罗斯；普鲁士"},{"label":"一句话概括","value":"拿破仑战争《提尔西特和约》结束第四次反法同盟战争，使普鲁士遭重创并确立拿破仑中欧霸权。"},{"label":"制定方/签署方","value":"法国皇帝拿破仑、俄国沙皇亚历山大一世、普鲁士国王弗里德里希·威廉三世。"},{"label":"主要内容","value":"法国与俄国达成和解，普鲁士被迫割让大量领土、支付赔款，并接受法国主导的中欧重组；华沙公国和威斯特伐利亚王国等拿破仑附庸结构得到确认。"},{"label":"它试图解决什么问题","value":"它试图结束法国与普俄的战争，并把法国胜利转化为对中欧和东欧的制度性控制。"},{"label":"为什么重要","value":"它是普鲁士改革的直接背景。普鲁士被削弱到生存边缘，改革不再是选择而是国家存续条件。"},{"label":"争议/局限","value":"俄法联盟建立在暂时利益上，普鲁士屈辱地位也埋下复仇和改革动力。"},{"label":"造成的影响","value":"普鲁士进行施泰因-普鲁士哈登贝格改革，拿破仑在德意志建立更深的附庸和军事征发体系。"},{"label":"出处","value":"Britannica, Treaties of Tilsit；Britannica, Napoleon I；Britannica, Prussia。"}],"relationItems":["← 前因：第四次反法同盟战争","→ 后果：威斯特伐利亚王国","→ 后果：普鲁士十月敕令","↔ 相关：拿破仑入侵俄国（1812）"],"relations":[{"text":"← 前因：第四次反法同盟战争","id":"extra560"},{"text":"→ 后果：威斯特伐利亚王国","id":"extra566"},{"text":"→ 后果：普鲁士十月敕令","id":"extra570"},{"text":"↔ 相关：拿破仑入侵俄国（1812）","id":"extra910"}],"source":"history","id":"extra564"},{"title":"普鲁士割地与赔款危机","level":"B","type":"事件卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1807—1812年","place":"普鲁士王国剩余领土","summary":"提尔西特后普鲁士承担割地、赔款和占领负担，国家财政危机推动改革加速。","fields":[{"label":"标题","value":"普鲁士割地与赔款危机"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1807—1812年"},{"label":"地点","value":"普鲁士王国剩余领土"},{"label":"主要国家","value":"普鲁士；法国"},{"label":"一句话概括","value":"提尔西特后普鲁士承担割地、赔款和占领负担，国家财政危机推动改革加速。"},{"label":"参与者","value":"普鲁士王室、法国占领军、普鲁士官僚和纳税人。"},{"label":"发生了什么","value":"拿破仑战争《提尔西特和约》后，普鲁士失去约半数人口和领土，还需支付巨额赔款并供养法国驻军。国家财政、行政和社会承受巨大压力，改革派以此推动税制、农民、城市和军事改革。"},{"label":"为什么重要","value":"它解释普鲁士改革为何在战败后迅速推进：改革不是抽象启蒙理想，而是应对国家破产和法国控制的生存策略。"},{"label":"前因","value":"耶拿-奥尔施泰特惨败和拿破仑战争《提尔西特和约》使普鲁士丧失大国地位，财政收入锐减而支出暴增；法国驻军和赔款进一步压垮国家财政。"},{"label":"后果","value":"改革派获得重组国家的政治空间，但改革也受到贵族、王权保守性和法国监督限制；普鲁士改革因此既深刻又不彻底。"},{"label":"出处","value":"Britannica, Prussia；German History in Documents and Images, Prussian reforms；Christopher Clark, Iron Kingdom。"}],"relationItems":["← 前因：拿破仑战争《提尔西特和约》","→ 后果：普鲁士施泰因-哈登贝格改革","↔ 相关：普鲁士十月敕令","↔ 相关：沙恩霍斯特与普鲁士军事改革"],"relations":[{"text":"← 前因：拿破仑战争《提尔西特和约》","id":"extra564"},{"text":"→ 后果：普鲁士施泰因-哈登贝格改革","id":"extra522"},{"text":"↔ 相关：普鲁士十月敕令","id":"extra570"},{"text":"↔ 相关：沙恩霍斯特与普鲁士军事改革","id":"extra574"}],"source":"history","id":"extra565"},{"title":"威斯特伐利亚王国","level":"B","type":"组织/机构卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1807—1813年","place":"卡塞尔及德意志中西部","summary":"威斯特伐利亚王国是拿破仑在德意志建立的示范附庸国，推行法式行政和法律改革。","fields":[{"label":"标题","value":"威斯特伐利亚王国"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1807—1813年"},{"label":"地点","value":"卡塞尔及德意志中西部"},{"label":"主要国家","value":"法国；德意志地区；威斯特伐利亚王国"},{"label":"一句话概括","value":"威斯特伐利亚王国是拿破仑在德意志建立的示范附庸国，推行法式行政和法律改革。"},{"label":"性质/类型","value":"法国附庸王国和拿破仑德意志“示范国家”。"},{"label":"成立/解散时间","value":"1807年提尔西特后建立，1813年拿破仑败退后瓦解。"},{"label":"核心目标/宗旨","value":"用法国式宪法、行政、法律和社会改革改造德意志中部，同时为法国提供兵源、税收和战略缓冲。"},{"label":"关键人物（可选）","value":"热罗姆·波拿巴。"},{"label":"关键行动/事件","value":"颁布宪法，引入拿破仑法典、平等原则、行政区划和对法国的军事财政义务。"},{"label":"为什么重要","value":"它显示拿破仑统治在德意志既是外来控制，也是制度现代化实验。"},{"label":"争议/局限","value":"改革伴随高税负、征兵和附庸地位，地方社会常把它视为法国剥削。"},{"label":"出处","value":"Britannica, Kingdom of Westphalia；Britannica, Napoleon I。"}],"relationItems":["← 前因：拿破仑战争《提尔西特和约》","→ 后果：威斯特伐利亚王国宪法","↔ 相关：拿破仑法典的欧洲传播","↔ 相关：拿破仑莱茵邦改革"],"relations":[{"text":"← 前因：拿破仑战争《提尔西特和约》","id":"extra564"},{"text":"→ 后果：威斯特伐利亚王国宪法","id":"extra567"},{"text":"↔ 相关：拿破仑法典的欧洲传播","id":"extra568"},{"text":"↔ 相关：拿破仑莱茵邦改革","id":"extra569"}],"source":"history","id":"extra566"},{"title":"威斯特伐利亚王国宪法","level":"B","type":"制度/文本卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1807年11—12月","place":"卡塞尔","summary":"威斯特伐利亚王国宪法引入成文宪法、法律平等和行政改革，是德意志宪制现代化实验。","fields":[{"label":"标题","value":"威斯特伐利亚王国宪法"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1807年11—12月"},{"label":"地点","value":"卡塞尔"},{"label":"主要国家","value":"威斯特伐利亚王国；法国；德意志地区"},{"label":"一句话概括","value":"威斯特伐利亚王国宪法引入成文宪法、法律平等和行政改革，是德意志宪制现代化实验。"},{"label":"制定方/签署方","value":"拿破仑体系下的威斯特伐利亚王国，由热罗姆·波拿巴统治。"},{"label":"主要内容","value":"规定王国行政结构、代表机构、法律平等、取消部分封建特权、引入拿破仑法典和法国式行政制度。"},{"label":"它试图解决什么问题","value":"它试图把拼接起来的德意志领地整合成可管理的现代国家，并展示法国制度优越性。"},{"label":"为什么重要","value":"它是德意志地区最早的现代成文宪法实验之一，对后来的改革和宪政想象有示范意义。"},{"label":"争议/局限","value":"宪法空间受法国控制、财政征发和国王专断限制，代表性远非现代民主。"},{"label":"造成的影响","value":"许多法式改革在1813年后被废除或调整，但法律平等、行政集中和公民权观念留下影响。"},{"label":"出处","value":"Britannica, Kingdom of Westphalia；German History in Documents and Images, Napoleonic Germany。"}],"relationItems":["← 前因：威斯特伐利亚王国","↔ 相关：拿破仑法典的欧洲传播","↔ 相关：拿破仑莱茵邦改革","↔ 同时期参考：法国革命制度输出"],"relations":[{"text":"← 前因：威斯特伐利亚王国","id":"extra566"},{"text":"↔ 相关：拿破仑法典的欧洲传播","id":"extra568"},{"text":"↔ 相关：拿破仑莱茵邦改革","id":"extra569"}],"source":"history","id":"extra567"},{"title":"拿破仑法典的欧洲传播","level":"A","type":"制度/文本卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1804年颁布；1800年代—1810年代随法国扩张传播","place":"法国、低地地区、意大利诸邦、莱茵地区、威斯特伐利亚王国、莱茵邦等","summary":"拿破仑法典随法国扩张传播到欧洲多地，把民法统一、法律平等和财产权原则制度化。","fields":[{"label":"标题","value":"拿破仑法典的欧洲传播"},{"label":"分级","value":"A"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1804年颁布；1800年代—1810年代随法国扩张传播"},{"label":"地点","value":"法国、低地地区、意大利诸邦、莱茵地区、威斯特伐利亚王国、莱茵邦等"},{"label":"主要国家","value":"法国；荷兰；比利时；意大利诸邦；德意志诸邦；莱茵邦；威斯特伐利亚王国"},{"label":"一句话概括","value":"拿破仑法典随法国扩张传播到欧洲多地，把民法统一、法律平等和财产权原则制度化。"},{"label":"制定方/签署方","value":"法国拿破仑政权；后由法国占领区、附庸国和同盟政权不同程度引入或借鉴。"},{"label":"主要内容","value":"确认法律面前平等、私有财产权、契约和世俗民事制度，削弱封建特权和地方习惯法差异；同时保留强烈的父权家庭结构和性别不平等。"},{"label":"它试图解决什么问题","value":"法国需要用统一民法巩固革命后秩序，并把占领区和附庸国纳入更可治理的法律框架。"},{"label":"为什么重要","value":"它是法国革命制度成果向欧洲外溢的核心文本之一。即使拿破仑失败，许多地区仍保留、改造或借鉴其民法原则，19世纪欧洲和拉丁美洲民法典都受到影响。"},{"label":"争议/局限","value":"法典传播常与军事占领、征税和征兵并行；它宣称法律平等，却强化男性家长权，对女性权利限制明显。"},{"label":"造成的影响","value":"莱茵地区、意大利、低地国家等地的法律和行政现代化加速；后来的德国民法典等全国法典化工程，也是在这一欧洲法典化潮流中展开。"},{"label":"出处","value":"Encyclopaedia Britannica: Napoleonic Code；Britannica, Kingdom of Westphalia；Britannica, Confederation of the Rhine。"}],"relationItems":["← 前因：法国大革命的欧洲冲击","↔ 相关：威斯特伐利亚王国宪法","↔ 相关：拿破仑莱茵邦改革","↔ 同时期参考：拿破仑莱茵邦"],"relations":[{"text":"← 前因：法国大革命的欧洲冲击","id":"extra319"},{"text":"↔ 相关：威斯特伐利亚王国宪法","id":"extra567"},{"text":"↔ 相关：拿破仑莱茵邦改革","id":"extra569"},{"text":"↔ 同时期参考：拿破仑莱茵邦","id":"extra521"}],"source":"history","id":"extra568"},{"title":"拿破仑莱茵邦改革","level":"B","type":"概念/思潮卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1806—1813年","place":"巴伐利亚、符腾堡、巴登、黑森等莱茵邦成员国","summary":"莱茵邦改革在法国压力和邦国自保下推进行政、法律和社会现代化。","fields":[{"label":"标题","value":"拿破仑莱茵邦改革"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1806—1813年"},{"label":"地点","value":"巴伐利亚、符腾堡、巴登、黑森等莱茵邦成员国"},{"label":"主要国家","value":"莱茵邦；法国；德意志地区"},{"label":"一句话概括","value":"莱茵邦改革在法国压力和邦国自保下推进行政、法律和社会现代化。"},{"label":"核心主张/思路","value":"莱茵邦诸国为了适应拿破仑体系和巩固自身主权，推行行政集中、法制统一、军制和财政改革。"},{"label":"提出者/代表人物（可选）","value":"巴伐利亚、符腾堡、巴登等邦国君主和改革官僚。"},{"label":"它从何而来","value":"1803年重组和1806年莱茵邦建立使中等邦国获得大量领土，也迫使它们整合新领地并向法国提供军事资源。"},{"label":"典型表现","value":"削弱等级特权，整合行政区划，改革税制和司法，引入或借鉴法国法制。"},{"label":"为什么重要","value":"它说明拿破仑时代不只是外来压迫，也推动德意志中等邦国国家能力上升。"},{"label":"争议/局限","value":"改革常服务君主集权和法国征发，地方参与有限，社会负担很重。"},{"label":"出处","value":"Britannica, Confederation of the Rhine；German History in Documents and Images, Napoleonic Germany；Michael Rowe, From Reich to State。"}],"relationItems":["← 前因：拿破仑莱茵邦","↔ 相关：拿破仑法典的欧洲传播","↔ 相关：威斯特伐利亚王国","→ 后果：德意志邦联"],"relations":[{"text":"← 前因：拿破仑莱茵邦","id":"extra521"},{"text":"↔ 相关：拿破仑法典的欧洲传播","id":"extra568"},{"text":"↔ 相关：威斯特伐利亚王国","id":"extra566"},{"text":"→ 后果：德意志邦联","id":"extra487"}],"source":"history","id":"extra569"},{"title":"普鲁士十月敕令","level":"A","type":"制度/文本卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1807年10月9日","place":"梅梅尔，普鲁士流亡政府所在地","summary":"普鲁士十月敕令废除农奴制人身依附，是施泰因-普鲁士哈登贝格改革的开端。","fields":[{"label":"标题","value":"普鲁士十月敕令"},{"label":"分级","value":"A"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1807年10月9日"},{"label":"地点","value":"梅梅尔，普鲁士流亡政府所在地"},{"label":"主要国家","value":"普鲁士"},{"label":"一句话概括","value":"普鲁士十月敕令废除农奴制人身依附，是施泰因-普鲁士哈登贝格改革的开端。"},{"label":"制定方/签署方","value":"普鲁士国王弗里德里希·威廉三世，在施泰因等改革派推动下颁布。"},{"label":"主要内容","value":"宣布逐步废除农民人身依附，放宽土地买卖和职业限制，允许不同等级之间更自由地拥有土地和选择职业。"},{"label":"它试图解决什么问题","value":"普鲁士战败后需要动员社会活力、提高农业和税收效率，并削弱旧等级制度对国家重建的束缚。"},{"label":"为什么重要","value":"它是普鲁士社会改革的骨架节点，把农民、土地和职业秩序从旧制度中部分解放出来。"},{"label":"争议/局限","value":"它没有立即完全解决封建负担和土地补偿问题，许多农民仍需付出土地或赎金换取实际自由。"},{"label":"造成的影响","value":"普鲁士改革进入实质阶段，后续调节敕令、城市改革和军事改革在此基础上展开。"},{"label":"出处","value":"German History in Documents and Images, Prussian October Edict；Britannica, Stein；Britannica, Prussia。"}],"relationItems":["← 前因：拿破仑战争《提尔西特和约》","→ 后果：普鲁士农民调节敕令","↔ 相关：普鲁士施泰因-哈登贝格改革","↔ 相关：普鲁士城市条例"],"relations":[{"text":"← 前因：拿破仑战争《提尔西特和约》","id":"extra564"},{"text":"→ 后果：普鲁士农民调节敕令","id":"extra573"},{"text":"↔ 相关：普鲁士施泰因-哈登贝格改革","id":"extra522"},{"text":"↔ 相关：普鲁士城市条例","id":"extra571"}],"source":"history","id":"extra570"},{"title":"普鲁士城市条例","level":"B","type":"制度/文本卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1808年11月19日","place":"普鲁士王国各城市","summary":"普鲁士城市条例给予城市有限自治，试图把市民参与纳入国家重建。","fields":[{"label":"标题","value":"普鲁士城市条例"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1808年11月19日"},{"label":"地点","value":"普鲁士王国各城市"},{"label":"主要国家","value":"普鲁士"},{"label":"一句话概括","value":"普鲁士城市条例给予城市有限自治，试图把市民参与纳入国家重建。"},{"label":"制定方/签署方","value":"普鲁士王权和施泰因改革政府。"},{"label":"主要内容","value":"改革城市行政，设立市议会和市政机构，使合格市民能够参与地方公共事务和城市财政管理。"},{"label":"它试图解决什么问题","value":"普鲁士旧行政体系僵化，改革派希望通过地方自治训练公民责任，并减轻国家对城市细务的直接控制。"},{"label":"为什么重要","value":"它是普鲁士政治现代化的重要环节，为19世纪市民自治和地方行政传统提供制度基础。"},{"label":"争议/局限","value":"参与权受财产、性别和身份限制，城市自治仍处在君主国家框架之内。"},{"label":"造成的影响","value":"普鲁士城市公共管理能力增强，市民阶层在地方政治中的角色扩大。"},{"label":"出处","value":"German History in Documents and Images, Prussian Municipal Ordinance；Britannica, Stein；Britannica, Prussia。"}],"relationItems":["← 前因：普鲁士十月敕令","↔ 相关：普鲁士施泰因-哈登贝格改革","↔ 相关：施泰因城市自治改革","↔ 同时期参考：拿破仑法典的欧洲传播"],"relations":[{"text":"← 前因：普鲁士十月敕令","id":"extra570"},{"text":"↔ 相关：普鲁士施泰因-哈登贝格改革","id":"extra522"},{"text":"↔ 同时期参考：拿破仑法典的欧洲传播","id":"extra568"}],"source":"history","id":"extra571"},{"title":"普鲁士哈登贝格改革","level":"B","type":"事件卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1810年代","place":"普鲁士王国","summary":"普鲁士哈登贝格改革延续施泰因路线，以财政、行政、经济和社会改革重建战败后的普鲁士。","fields":[{"label":"标题","value":"普鲁士哈登贝格改革"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1810年代"},{"label":"地点","value":"普鲁士王国"},{"label":"主要国家","value":"普鲁士"},{"label":"一句话概括","value":"普鲁士哈登贝格改革延续施泰因路线，以财政、行政、经济和社会改革重建战败后的普鲁士。"},{"label":"参与者","value":"卡尔·奥古斯特·冯·哈登贝格、普鲁士王室、改革官僚、贵族和市民社会。"},{"label":"发生了什么","value":"施泰因离任后，哈登贝格在1810年后重新主持普鲁士改革，推动财政、行政、经济自由化、农民解放后续安排和犹太人地位改善等政策。"},{"label":"为什么重要","value":"它使普鲁士改革从战败应急转为更系统的国家重建，帮助普鲁士恢复大国能力。"},{"label":"前因","value":"提尔西特后普鲁士财政和行政危机仍未解决，施泰因改革开局后需要更长期政策延续；法国压力也迫使普鲁士持续寻找恢复国力的方法。"},{"label":"后果","value":"普鲁士国家能力提升，但宪法和代表制改革受贵族和王权保守力量限制，改革留下未完成性；这种张力延续到19世纪普鲁士政治。"},{"label":"出处","value":"Britannica, Hardenberg；German History in Documents and Images, Prussian reforms；Christopher Clark, Iron Kingdom。"}],"relationItems":["← 前因：普鲁士施泰因-哈登贝格改革","→ 后果：普鲁士农民调节敕令","↔ 相关：普鲁士《一般邦法》","↔ 相关：卡尔·冯·哈登贝格"],"relations":[{"text":"← 前因：普鲁士施泰因-哈登贝格改革","id":"extra522"},{"text":"→ 后果：普鲁士农民调节敕令","id":"extra573"},{"text":"↔ 相关：普鲁士《一般邦法》","id":"extra467"}],"source":"history","id":"extra572"},{"title":"普鲁士农民调节敕令","level":"C","type":"制度/文本卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1811年9月14日","place":"普鲁士王国","summary":"1811年调节敕令规定农民摆脱封建义务的补偿方式，推进但也限制普鲁士农民解放。","fields":[{"label":"标题","value":"普鲁士农民调节敕令"},{"label":"分级","value":"C"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1811年9月14日"},{"label":"地点","value":"普鲁士王国"},{"label":"主要国家","value":"普鲁士"},{"label":"一句话概括","value":"1811年调节敕令规定农民摆脱封建义务的补偿方式，推进但也限制普鲁士农民解放。"},{"label":"制定方/签署方","value":"普鲁士国王弗里德里希·威廉三世、哈登贝格政府。"},{"label":"主要内容","value":"规定农民通过交出部分土地或支付补偿来解除对领主的封建义务，推动农民从人身依附走向产权关系。"},{"label":"它试图解决什么问题","value":"十月敕令废除人身依附后，仍需处理地租、劳役、土地权利和领主补偿的实际问题。"},{"label":"为什么重要","value":"它显示农民解放不是一次性宣布自由，而是复杂的土地、阶级和财产重组过程。"},{"label":"争议/局限","value":"许多农民为获得自由付出土地，容克地主在土地集中中受益，农村社会不平等继续存在。"},{"label":"造成的影响","value":"普鲁士农业资本主义化加速，农民法律地位改善，但乡村阶层分化加深。"},{"label":"出处","value":"German History in Documents and Images, Prussian Regulation Edict of 1811；Britannica, Prussia；Christopher Clark, Iron Kingdom。"}],"relationItems":["← 前因：普鲁士十月敕令","↔ 相关：普鲁士哈登贝格改革","↔ 相关：普鲁士容克地主","↔ 同时期参考：欧洲农奴制废除"],"relations":[{"text":"← 前因：普鲁士十月敕令","id":"extra570"},{"text":"↔ 相关：普鲁士哈登贝格改革","id":"extra572"},{"text":"↔ 相关：普鲁士容克地主","id":"extra672"}],"source":"history","id":"extra573"},{"title":"沙恩霍斯特与普鲁士军事改革","level":"B","type":"人物卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1755—1813年；1807—1813年改革影响最大","place":"普鲁士、柏林、德意志战场","summary":"沙恩霍斯特推动普鲁士军队改革，把战败后的旧军队改造成更接近国民军的体系。","fields":[{"label":"标题","value":"沙恩霍斯特与普鲁士军事改革"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1755—1813年；1807—1813年改革影响最大"},{"label":"地点","value":"普鲁士、柏林、德意志战场"},{"label":"主要国家","value":"普鲁士；德意志地区"},{"label":"一句话概括","value":"沙恩霍斯特推动普鲁士军队改革，把战败后的旧军队改造成更接近国民军的体系。"},{"label":"生卒年/活跃年代","value":"1755—1813年。"},{"label":"身份/职务","value":"普鲁士将领、军事理论家、军事改革委员会核心人物。"},{"label":"关键贡献/作为","value":"限制体罚，推动按能力晋升，简化军事行政，训练预备兵，准备扩大兵役基础。"},{"label":"核心主张/立场","value":"军队应从旧贵族职业军队转向更能动员国家和社会资源的现代军队。"},{"label":"为什么重要","value":"他的改革使普鲁士在1813年重新参战时拥有更高动员能力，是解放战争军事基础之一。"},{"label":"争议/评价","value":"改革受到法国限制和普鲁士保守派阻碍，普遍兵役等目标在其生前并未完全实现。"},{"label":"关联事件（可选）","value":"普鲁士克吕姆佩尔制；德意志解放战争。"},{"label":"出处","value":"Britannica, Gerhard von Scharnhorst；Britannica, Prussia；German History in Documents and Images, Prussian reforms。"}],"relationItems":["← 前因：拿破仑战争耶拿-奥尔施泰特战役","→ 后果：普鲁士克吕姆佩尔制","↔ 相关：普鲁士军制改革","↔ 相关：德意志解放战争"],"relations":[{"text":"← 前因：拿破仑战争耶拿-奥尔施泰特战役","id":"extra561"},{"text":"→ 后果：普鲁士克吕姆佩尔制","id":"extra575"},{"text":"↔ 相关：普鲁士军制改革","id":"extra536"},{"text":"↔ 相关：德意志解放战争","id":"extra523"}],"source":"history","id":"extra574"},{"title":"普鲁士克吕姆佩尔制","level":"C","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1808年后","place":"普鲁士王国","summary":"克吕姆佩尔制用轮换训练绕开法国限军，秘密扩大普鲁士预备兵基础。","fields":[{"label":"标题","value":"普鲁士克吕姆佩尔制"},{"label":"分级","value":"C"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1808年后"},{"label":"地点","value":"普鲁士王国"},{"label":"主要国家","value":"普鲁士"},{"label":"一句话概括","value":"克吕姆佩尔制用轮换训练绕开法国限军，秘密扩大普鲁士预备兵基础。"},{"label":"制定方/签署方","value":"普鲁士军事改革派，核心与沙恩霍斯特改革相关。"},{"label":"主要内容","value":"在法国限制普鲁士常备军规模的情况下，通过小批士兵轮换服役和退伍，把更多男子短期训练成可动员兵员。"},{"label":"它试图解决什么问题","value":"提尔西特后普鲁士军队规模被限制，国家需要在不直接违反法国监督的情况下储备军事力量。"},{"label":"为什么重要","value":"它是普鲁士军事改革的具体机制，解释1813年普鲁士为何能较快扩大军队。"},{"label":"争议/局限","value":"训练时间有限，制度带有规避性质，真正普遍兵役和国民军建设仍需1813年战争推动。"},{"label":"造成的影响","value":"普鲁士获得更大预备兵池，为解放战争中的军队扩张和民兵动员创造条件。"},{"label":"出处","value":"Britannica, Gerhard von Scharnhorst；German History in Documents and Images, Prussian military reform；Christopher Clark, Iron Kingdom。"}],"relationItems":["← 前因：沙恩霍斯特与普鲁士军事改革","→ 后果：德意志解放战争","↔ 相关：普鲁士军制改革","↔ 同时期参考：法国全民征兵"],"relations":[{"text":"← 前因：沙恩霍斯特与普鲁士军事改革","id":"extra574"},{"text":"→ 后果：德意志解放战争","id":"extra523"},{"text":"↔ 相关：普鲁士军制改革","id":"extra536"}],"source":"history","id":"extra575"},{"title":"第五次反法同盟战争","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1809年","place":"奥地利、巴伐利亚、德意志南部、意大利和多瑙河流域","summary":"第五次反法同盟战争是奥地利趁法国陷入西班牙战事时重新挑战拿破仑的尝试。","fields":[{"label":"标题","value":"第五次反法同盟战争"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1809年"},{"label":"地点","value":"奥地利、巴伐利亚、德意志南部、意大利和多瑙河流域"},{"label":"主要国家","value":"奥地利；法国；莱茵邦；英国"},{"label":"一句话概括","value":"第五次反法同盟战争是奥地利趁法国陷入西班牙战事时重新挑战拿破仑的尝试。"},{"label":"参与者","value":"奥地利、拿破仑法国、莱茵邦诸国、英国及地方反法力量。"},{"label":"发生了什么","value":"1809年，奥地利发动对法战争，试图利用法国深陷西班牙半岛战争的机会恢复自身地位。奥军初期攻入巴伐利亚，但拿破仑迅速反击，占领维也纳，并在拿破仑战争瓦格拉姆战役后迫使奥地利求和。"},{"label":"为什么重要","value":"它是奥地利在拿破仑体系内最后一次单独大规模反击，也展示德意志反法情绪和法国控制的脆弱性。"},{"label":"前因","value":"普雷斯堡后奥地利失去德意志和意大利影响，西班牙反法战争使维也纳认为时机有利；奥地利改革军队后希望重新挑战拿破仑。"},{"label":"后果","value":"奥地利签署拿破仑战争《美泉宫和约》并被削弱，短期内失去独立挑战法国的能力；维也纳随后转向与法国结盟和王朝婚姻策略。"},{"label":"出处","value":"Britannica, War of the Fifth Coalition；Britannica, Napoleonic Wars；Britannica, Austria。"}],"relationItems":["← 前因：拿破仑战争《普雷斯堡和约》","→ 后果：拿破仑战争阿斯佩恩-埃斯灵战役","→ 后果：拿破仑战争瓦格拉姆战役","↔ 相关：反拿破仑蒂罗尔起义"],"relations":[{"text":"← 前因：拿破仑战争《普雷斯堡和约》","id":"extra559"},{"text":"→ 后果：拿破仑战争阿斯佩恩-埃斯灵战役","id":"extra577"},{"text":"→ 后果：拿破仑战争瓦格拉姆战役","id":"extra578"},{"text":"↔ 相关：反拿破仑蒂罗尔起义","id":"extra580"}],"source":"history","id":"extra576"},{"title":"拿破仑战争阿斯佩恩-埃斯灵战役","level":"B","type":"事件卡","tags":["战争与外交"],"mainTag":"战争与外交","subTag":"","timeText":"1809年5月21—22日","place":"维也纳附近多瑙河畔阿斯佩恩和埃斯灵","summary":"阿斯佩恩-埃斯灵战役中奥地利击退拿破仑渡河攻势，是拿破仑少见的战场挫败。","fields":[{"label":"标题","value":"拿破仑战争阿斯佩恩-埃斯灵战役"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"时间","value":"1809年5月21—22日"},{"label":"地点","value":"维也纳附近多瑙河畔阿斯佩恩和埃斯灵"},{"label":"主要国家","value":"奥地利；法国"},{"label":"一句话概括","value":"阿斯佩恩-埃斯灵战役中奥地利击退拿破仑渡河攻势，是拿破仑少见的战场挫败。"},{"label":"参与者","value":"拿破仑、奥地利大公卡尔、法国和奥地利军队。"},{"label":"发生了什么","value":"拿破仑占领维也纳后试图渡过多瑙河继续追击奥军。奥地利大公卡尔在阿斯佩恩和埃斯灵附近攻击法军桥头堡，迫使法军撤回洛鲍岛。"},{"label":"为什么重要","value":"它证明拿破仑可以在战场上被击退，鼓舞反法力量；但奥地利未能将胜利转化为决定性战略成果。"},{"label":"前因","value":"第五次反法同盟战争中，奥地利虽失去维也纳，但主力尚存，多瑙河成为双方决战前的关键屏障；拿破仑必须渡河才能迫使奥军决战。"},{"label":"后果","value":"拿破仑重新组织渡河和兵力，弥补阿斯佩恩-埃斯灵暴露的协同问题；数周后他在拿破仑战争瓦格拉姆战役中击败奥地利。"},{"label":"出处","value":"Britannica, Battle of Aspern-Essling；Britannica, War of the Fifth Coalition。"}],"relationItems":["← 前因：第五次反法同盟战争","→ 后果：拿破仑战争瓦格拉姆战役","↔ 相关：奥地利帝国成立","↔ 同时期参考：拿破仑战争"],"relations":[{"text":"← 前因：第五次反法同盟战争","id":"extra576"},{"text":"→ 后果：拿破仑战争瓦格拉姆战役","id":"extra578"},{"text":"↔ 相关：奥地利帝国成立","id":"extra554"},{"text":"↔ 同时期参考：拿破仑战争","id":"extra918"}],"source":"history","id":"extra577"},{"title":"拿破仑战争瓦格拉姆战役","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1809年7月5—6日","place":"维也纳东北瓦格拉姆附近","summary":"拿破仑战争瓦格拉姆战役中拿破仑击败奥地利主力，迫使第五次反法同盟瓦解。","fields":[{"label":"标题","value":"拿破仑战争瓦格拉姆战役"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1809年7月5—6日"},{"label":"地点","value":"维也纳东北瓦格拉姆附近"},{"label":"主要国家","value":"法国；奥地利；莱茵邦"},{"label":"一句话概括","value":"拿破仑战争瓦格拉姆战役中拿破仑击败奥地利主力，迫使第五次反法同盟瓦解。"},{"label":"参与者","value":"拿破仑、奥地利大公卡尔、法国及盟军、奥地利军队。"},{"label":"发生了什么","value":"阿斯佩恩-埃斯灵后，拿破仑重新集结大军并再次渡过多瑙河，在瓦格拉姆与奥军决战。战斗规模巨大、伤亡惨重，最终法军取得决定性胜利。"},{"label":"为什么重要","value":"它恢复了拿破仑在中欧的军事优势，也迫使奥地利接受严厉和约。"},{"label":"前因","value":"阿斯佩恩-埃斯灵未能摧毁法军，拿破仑有时间集中法国、德意志和意大利盟军准备第二次渡河；奥地利也未能把短暂胜利转化为战略主动。"},{"label":"后果","value":"奥地利签署拿破仑战争《美泉宫和约》，割地并被迫接受法国优势，随后通过玛丽-路易丝婚姻暂时与拿破仑靠拢；反法策略转入等待时机。"},{"label":"出处","value":"Britannica, Battle of Wagram；Britannica, War of the Fifth Coalition。"}],"relationItems":["← 前因：拿破仑战争阿斯佩恩-埃斯灵战役","→ 后果：拿破仑战争《美泉宫和约》","↔ 相关：第五次反法同盟战争","↔ 同时期参考：拿破仑战争"],"relations":[{"text":"← 前因：拿破仑战争阿斯佩恩-埃斯灵战役","id":"extra577"},{"text":"→ 后果：拿破仑战争《美泉宫和约》","id":"extra579"},{"text":"↔ 相关：第五次反法同盟战争","id":"extra576"},{"text":"↔ 同时期参考：拿破仑战争","id":"extra918"}],"source":"history","id":"extra578"},{"title":"拿破仑战争《美泉宫和约》","level":"B","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1809年10月14日","place":"维也纳美泉宫","summary":"拿破仑战争《美泉宫和约》结束第五次反法同盟战争，进一步削弱奥地利并巩固拿破仑体系。","fields":[{"label":"标题","value":"拿破仑战争《美泉宫和约》"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1809年10月14日"},{"label":"地点","value":"维也纳美泉宫"},{"label":"主要国家","value":"法国；奥地利；巴伐利亚；华沙公国"},{"label":"一句话概括","value":"拿破仑战争《美泉宫和约》结束第五次反法同盟战争，进一步削弱奥地利并巩固拿破仑体系。"},{"label":"制定方/签署方","value":"法国与奥地利。"},{"label":"主要内容","value":"奥地利割让领土给法国、巴伐利亚和华沙公国等，承认法国战后安排，并承受财政和战略损失。"},{"label":"它试图解决什么问题","value":"它试图把瓦格拉姆胜利转化为外交成果，迫使奥地利退出反法战争。"},{"label":"为什么重要","value":"它使奥地利短期内无法继续独立挑战拿破仑，并促成奥法王朝婚姻和暂时合作。"},{"label":"争议/局限","value":"奥地利只是被迫妥协，并未真正接受法国长期霸权。"},{"label":"造成的影响","value":"奥地利失去更多领土和人口，梅特涅随后转向谨慎外交，在1813年重新寻找反法机会。"},{"label":"出处","value":"Britannica, Treaty of Schönbrunn；Britannica, War of the Fifth Coalition；Britannica, Metternich。"}],"relationItems":["← 前因：拿破仑战争瓦格拉姆战役","↔ 相关：第五次反法同盟战争","→ 后果：梅特涅外交","↔ 同时期参考：拿破仑与玛丽-路易丝婚姻"],"relations":[{"text":"← 前因：拿破仑战争瓦格拉姆战役","id":"extra578"},{"text":"↔ 相关：第五次反法同盟战争","id":"extra576"}],"source":"history","id":"extra579"},{"title":"反拿破仑蒂罗尔起义","level":"C","type":"事件卡","tags":["战争与外交","文化与思想"],"mainTag":"战争与外交","subTag":"文化与思想","timeText":"1809年","place":"蒂罗尔地区","summary":"反拿破仑蒂罗尔起义反抗巴伐利亚和法国控制，体现拿破仑体系下地方宗教与乡土抵抗。","fields":[{"label":"标题","value":"反拿破仑蒂罗尔起义"},{"label":"分级","value":"C"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1809年"},{"label":"地点","value":"蒂罗尔地区"},{"label":"主要国家","value":"奥地利；巴伐利亚；法国；蒂罗尔"},{"label":"一句话概括","value":"反拿破仑蒂罗尔起义反抗巴伐利亚和法国控制，体现拿破仑体系下地方宗教与乡土抵抗。"},{"label":"参与者","value":"安德烈亚斯·霍费尔、蒂罗尔农民和民兵、巴伐利亚当局、法国和奥地利力量。"},{"label":"发生了什么","value":"1809年奥地利再次对法作战时，蒂罗尔民众起义反抗被并入巴伐利亚后的改革、征税和征兵。起义一度取得成功，但奥地利战败后失去支持，最终被法国和巴伐利亚镇压。"},{"label":"为什么重要","value":"它说明德意志和阿尔卑斯地区的反法抵抗并不总是现代民族主义，也包含宗教、地方特权和乡土秩序因素。"},{"label":"前因","value":"普雷斯堡后蒂罗尔从奥地利转给巴伐利亚，地方社会不满巴伐利亚中央化、反教会改革和兵役负担；1809年奥地利对法开战提供了起义机会。"},{"label":"后果","value":"起义失败，霍费尔被处决；但蒂罗尔抵抗记忆后来成为奥地利和地方爱国叙事的一部分，也说明拿破仑体系在地方社会中并不稳固。"},{"label":"出处","value":"Britannica, Andreas Hofer；Britannica, Tyrol；Britannica, War of the Fifth Coalition。"}],"relationItems":["← 前因：第五次反法同盟战争","↔ 相关：拿破仑战争《美泉宫和约》","↔ 相关：德意志反法民族动员","↔ 同时期参考：西班牙游击战争"],"relations":[{"text":"← 前因：第五次反法同盟战争","id":"extra576"},{"text":"↔ 相关：拿破仑战争《美泉宫和约》","id":"extra579"},{"text":"↔ 相关：德意志反法民族动员","id":"extra588"}],"source":"history","id":"extra580"},{"title":"普鲁士约克《陶罗根协定》","level":"A","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1812年12月30日","place":"陶罗根，今立陶宛陶拉盖","summary":"约克在陶罗根与俄军停战，标志普鲁士从被迫附法走向反拿破仑阵营。","fields":[{"label":"标题","value":"普鲁士约克《陶罗根协定》"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1812年12月30日"},{"label":"地点","value":"陶罗根，今立陶宛陶拉盖"},{"label":"主要国家","value":"普鲁士；俄罗斯；法国"},{"label":"一句话概括","value":"约克在陶罗根与俄军停战，标志普鲁士从被迫附法走向反拿破仑阵营。"},{"label":"参与者","value":"普鲁士将领路德维希·约克、俄军代表迪比奇、普鲁士辅助军、法国元帅麦克唐纳。"},{"label":"发生了什么","value":"拿破仑远征俄国失败后，随法军作战的普鲁士辅助军被俄军接触。约克未经普鲁士国王批准，在陶罗根与俄军签署中立协定，使其部队脱离法国指挥。"},{"label":"为什么重要","value":"它是普鲁士转向反法战争的标志性节点，打破国王谨慎等待和法国控制之间的僵局。"},{"label":"前因","value":"提尔西特后普鲁士被迫依附法国，1812年又提供部队参加俄国战役；拿破仑大军崩溃使反法机会出现。"},{"label":"后果","value":"东普鲁士反法动员迅速升温，普俄很快签署普俄《卡利什条约》，普鲁士正式加入第六次反法同盟；约克的擅自行动被事后合法化。"},{"label":"出处","value":"Britannica, Convention of Tauroggen；Britannica, Napoleonic Wars；Britannica, Prussia。"}],"relationItems":["← 前因：拿破仑入侵俄国（1812）","→ 后果：普俄《卡利什条约》","↔ 相关：德意志解放战争","↔ 相关：普鲁士克吕姆佩尔制"],"relations":[{"text":"← 前因：拿破仑入侵俄国（1812）","id":"extra910"},{"text":"→ 后果：普俄《卡利什条约》","id":"extra582"},{"text":"↔ 相关：德意志解放战争","id":"extra523"},{"text":"↔ 相关：普鲁士克吕姆佩尔制","id":"extra575"}],"source":"history","id":"extra581"},{"title":"普俄《卡利什条约》","level":"A","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1813年2月28日","place":"卡利什，今波兰卡利什","summary":"普俄《卡利什条约》使普鲁士正式与俄罗斯结盟反法，打开德意志解放战争。","fields":[{"label":"标题","value":"普俄《卡利什条约》"},{"label":"分级","value":"A"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1813年2月28日"},{"label":"地点","value":"卡利什，今波兰卡利什"},{"label":"主要国家","value":"普鲁士；俄罗斯；法国"},{"label":"一句话概括","value":"普俄《卡利什条约》使普鲁士正式与俄罗斯结盟反法，打开德意志解放战争。"},{"label":"制定方/签署方","value":"普鲁士与俄罗斯。"},{"label":"主要内容","value":"普鲁士和俄罗斯结成反拿破仑同盟，承诺共同作战，并为未来德意志和波兰安排提出政治设想。"},{"label":"它试图解决什么问题","value":"它试图把陶罗根后的事实转向变成正式国家联盟，使普鲁士摆脱法国附庸地位。"},{"label":"为什么重要","value":"它是普鲁士正式重返欧洲反法阵营的关键文本，直接通向1813年德意志战役。"},{"label":"争议/局限","value":"普鲁士仍需面对军事风险，未来德意志秩序和波兰问题也并未清晰解决。"},{"label":"造成的影响","value":"普鲁士向法国宣战，发布《告我的人民》，民族动员和改革军队投入解放战争。"},{"label":"出处","value":"Britannica, Treaty of Kalisz；Britannica, War of the Sixth Coalition；Britannica, Prussia。"}],"relationItems":["← 前因：普鲁士约克《陶罗根协定》","→ 后果：普鲁士《告我的人民》宣言","→ 后果：第六次反法同盟战争","↔ 相关：德意志解放战争"],"relations":[{"text":"← 前因：普鲁士约克《陶罗根协定》","id":"extra581"},{"text":"→ 后果：普鲁士《告我的人民》宣言","id":"extra583"},{"text":"→ 后果：第六次反法同盟战争","id":"extra584"},{"text":"↔ 相关：德意志解放战争","id":"extra523"}],"source":"history","id":"extra582"},{"title":"普鲁士《告我的人民》宣言","level":"B","type":"制度/文本卡","tags":["文化与思想","战争与外交"],"mainTag":"文化与思想","subTag":"战争与外交","timeText":"1813年3月17日","place":"布雷斯劳","summary":"普鲁士《告我的人民》宣言号召臣民反抗拿破仑，把王朝战争包装为民族解放。","fields":[{"label":"标题","value":"普鲁士《告我的人民》宣言"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1813年3月17日"},{"label":"地点","value":"布雷斯劳"},{"label":"主要国家","value":"普鲁士；德意志地区"},{"label":"一句话概括","value":"普鲁士《告我的人民》宣言号召臣民反抗拿破仑，把王朝战争包装为民族解放。"},{"label":"制定方/签署方","value":"普鲁士国王弗里德里希·威廉三世。"},{"label":"主要内容","value":"宣言号召普鲁士臣民为国家、荣誉和独立而战，要求社会各阶层支持对法国的战争。"},{"label":"它试图解决什么问题","value":"普鲁士需要把有限王朝资源扩展为更广泛社会动员，以弥补长期被法国压制后的军事不足。"},{"label":"为什么重要","value":"它把普鲁士对法战争与德意志民族情感连接起来，是解放战争政治动员的代表文本。"},{"label":"争议/局限","value":"宣言仍以国王和普鲁士国家为中心，民族自由承诺并未转化为战后宪政自由。"},{"label":"造成的影响","value":"志愿军、民兵和社会捐助扩大，德意志反法民族动员进入高潮。"},{"label":"出处","value":"German History in Documents and Images, An Mein Volk；Britannica, War of the Sixth Coalition。"}],"relationItems":["← 前因：普俄《卡利什条约》","→ 后果：德意志反法民族动员","↔ 相关：德意志解放战争","↔ 相关：德意志民族主义"],"relations":[{"text":"← 前因：普俄《卡利什条约》","id":"extra582"},{"text":"→ 后果：德意志反法民族动员","id":"extra588"},{"text":"↔ 相关：德意志解放战争","id":"extra523"},{"text":"↔ 相关：德意志民族主义","id":"extra504"}],"source":"history","id":"extra583"},{"title":"第六次反法同盟战争","level":"A","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1813—1814年","place":"德意志、法国、意大利、低地地区","summary":"第六次反法同盟战争在俄国战役后联合多国反攻拿破仑，最终迫使其第一次退位。","fields":[{"label":"标题","value":"第六次反法同盟战争"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1813—1814年"},{"label":"地点","value":"德意志、法国、意大利、低地地区"},{"label":"主要国家","value":"普鲁士；俄罗斯；奥地利；英国；瑞典；法国"},{"label":"一句话概括","value":"第六次反法同盟战争在俄国战役后联合多国反攻拿破仑，最终迫使其第一次退位。"},{"label":"参与者","value":"普鲁士、俄罗斯、奥地利、英国、瑞典及其他同盟国，法国拿破仑帝国。"},{"label":"发生了什么","value":"1812年俄国战役失败后，普鲁士和俄罗斯率先结盟，奥地利后来加入。同盟军在德意志战场与拿破仑反复作战，最终在莱比锡取得决定性胜利，随后入侵法国并占领巴黎。"},{"label":"为什么重要","value":"它结束拿破仑对德意志的直接支配，使莱茵邦瓦解，并为维也纳会议重建欧洲秩序创造条件。"},{"label":"前因","value":"拿破仑入侵俄国失败摧毁法国军事优势，陶罗根和卡利什使普鲁士转向反法阵营；俄军推进也给德意志战场创造反攻条件。"},{"label":"后果","value":"拿破仑1814年退位，法国对德意志的直接支配结束；德意志进入维也纳会议和德意志邦联重组阶段。"},{"label":"出处","value":"Britannica, War of the Sixth Coalition；Britannica, Battle of Leipzig；Britannica, Napoleon I。"}],"relationItems":["← 前因：普俄《卡利什条约》","→ 后果：反拿破仑莱比锡战役","→ 后果：拿破仑战后维也纳会议","↔ 相关：德意志解放战争"],"relations":[{"text":"← 前因：普俄《卡利什条约》","id":"extra582"},{"text":"→ 后果：反拿破仑莱比锡战役","id":"extra524"},{"text":"→ 后果：拿破仑战后维也纳会议","id":"extra525"},{"text":"↔ 相关：德意志解放战争","id":"extra523"}],"source":"history","id":"extra584"},{"title":"吕岑战役（1813）","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1813年5月2日","place":"萨克森吕岑附近","summary":"吕岑战役中拿破仑击退普俄联军，但无法取得毁灭性胜利。","fields":[{"label":"标题","value":"吕岑战役（1813）"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1813年5月2日"},{"label":"地点","value":"萨克森吕岑附近"},{"label":"主要国家","value":"法国；普鲁士；俄罗斯；萨克森"},{"label":"一句话概括","value":"吕岑战役中拿破仑击退普俄联军，但无法取得毁灭性胜利。"},{"label":"参与者","value":"拿破仑、普鲁士和俄罗斯联军、布吕歇尔、维特根施泰因等。"},{"label":"发生了什么","value":"1813年春，普鲁士和俄罗斯联军在萨克森迎战拿破仑新组建的军队。法军取得战术胜利，但骑兵不足和兵员质量下降使拿破仑无法有效追击并摧毁联军。"},{"label":"为什么重要","value":"它显示拿破仑仍有战场能力，但俄国战役后的法国军队已难以复制早期决定性胜利。"},{"label":"前因","value":"普俄《卡利什条约》后普俄向西推进，拿破仑急速重建军队试图恢复德意志控制；双方都希望在奥地利正式参战前取得优势。"},{"label":"后果","value":"普俄联军继续后撤并保存实力，拿破仑虽然赢得战术胜利却未能摧毁敌军；数周后双方在包岑再次交战。"},{"label":"出处","value":"Britannica, War of the Sixth Coalition；Britannica, Battle of Lützen。"}],"relationItems":["← 前因：第六次反法同盟战争","→ 后果：拿破仑战争包岑战役","↔ 相关：德意志解放战争","↔ 相关：反拿破仑莱比锡战役"],"relations":[{"text":"← 前因：第六次反法同盟战争","id":"extra584"},{"text":"→ 后果：拿破仑战争包岑战役","id":"extra586"},{"text":"↔ 相关：德意志解放战争","id":"extra523"},{"text":"↔ 相关：反拿破仑莱比锡战役","id":"extra524"}],"source":"history","id":"extra585"},{"title":"拿破仑战争包岑战役","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1813年5月20—21日","place":"萨克森包岑附近","summary":"拿破仑战争包岑战役中拿破仑再次击退普俄联军，但仍未能结束第六次反法同盟战争。","fields":[{"label":"标题","value":"拿破仑战争包岑战役"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1813年5月20—21日"},{"label":"地点","value":"萨克森包岑附近"},{"label":"主要国家","value":"法国；普鲁士；俄罗斯；萨克森"},{"label":"一句话概括","value":"拿破仑战争包岑战役中拿破仑再次击退普俄联军，但仍未能结束第六次反法同盟战争。"},{"label":"参与者","value":"拿破仑、普鲁士和俄罗斯联军、布吕歇尔、维特根施泰因、内伊等。"},{"label":"发生了什么","value":"吕岑之后，普俄联军在包岑附近建立阵地。拿破仑发动进攻并迫使联军撤退，但法军协同和追击不足，联军主力逃脱。"},{"label":"为什么重要","value":"它是拿破仑1813年春季两次战术胜利之一，却没有改变战略困境。"},{"label":"前因","value":"吕岑战后拿破仑希望继续压迫普俄联军，迫使其在奥地利加入前接受和平；普俄则试图拖延并保存主力。"},{"label":"后果","value":"双方进入短暂停战和外交博弈，奥地利争取调停并最终加入反法阵营；同盟军也利用停战重整兵力和战略。"},{"label":"出处","value":"Britannica, War of the Sixth Coalition；Britannica, Battle of Bautzen。"}],"relationItems":["← 前因：吕岑战役（1813）","→ 后果：反拿破仑同盟特拉亨贝格计划","↔ 相关：第六次反法同盟战争","↔ 相关：反拿破仑莱比锡战役"],"relations":[{"text":"← 前因：吕岑战役（1813）","id":"extra585"},{"text":"→ 后果：反拿破仑同盟特拉亨贝格计划","id":"extra587"},{"text":"↔ 相关：第六次反法同盟战争","id":"extra584"},{"text":"↔ 相关：反拿破仑莱比锡战役","id":"extra524"}],"source":"history","id":"extra586"},{"title":"反拿破仑同盟特拉亨贝格计划","level":"B","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1813年7月","place":"西里西亚特拉亨贝格","summary":"反拿破仑同盟特拉亨贝格计划要求同盟军避免直接迎战拿破仑本人，转而打击其元帅和分散军队。","fields":[{"label":"标题","value":"反拿破仑同盟特拉亨贝格计划"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1813年7月"},{"label":"地点","value":"西里西亚特拉亨贝格"},{"label":"主要国家","value":"普鲁士；俄罗斯；奥地利；瑞典；法国"},{"label":"一句话概括","value":"反拿破仑同盟特拉亨贝格计划要求同盟军避免直接迎战拿破仑本人，转而打击其元帅和分散军队。"},{"label":"制定方/签署方","value":"普鲁士、俄罗斯、瑞典和后来加入的奥地利同盟指挥层。"},{"label":"主要内容","value":"同盟军应避免与拿破仑亲自指挥的主力决战，集中攻击其部下指挥的部队，并通过多路军队消耗法国。"},{"label":"它试图解决什么问题","value":"拿破仑仍具极强战术指挥能力，同盟军需要一种避免被各个击破的战略。"},{"label":"为什么重要","value":"它是1813年同盟战争方式的关键调整，帮助同盟军把数量和多线优势转化为战略优势。"},{"label":"争议/局限","value":"计划需要多国军队高度协调，执行中仍存在分歧和风险。"},{"label":"造成的影响","value":"同盟军在格罗斯贝伦、登讷维茨等战斗中削弱法军，最终在莱比锡形成合围态势。"},{"label":"出处","value":"Britannica, War of the Sixth Coalition；Britannica, Battle of Leipzig；Michael Leggiere, Napoleon and Berlin。"}],"relationItems":["← 前因：拿破仑战争包岑战役","→ 后果：反拿破仑莱比锡战役","↔ 相关：第六次反法同盟战争","↔ 相关：德意志解放战争"],"relations":[{"text":"← 前因：拿破仑战争包岑战役","id":"extra586"},{"text":"→ 后果：反拿破仑莱比锡战役","id":"extra524"},{"text":"↔ 相关：第六次反法同盟战争","id":"extra584"},{"text":"↔ 相关：德意志解放战争","id":"extra523"}],"source":"history","id":"extra587"},{"title":"德意志反法民族动员","level":"B","type":"概念/思潮卡","tags":["文化与思想","战争与外交"],"mainTag":"文化与思想","subTag":"战争与外交","timeText":"1813年前后","place":"普鲁士、萨克森、北德和德意志各地","summary":"德意志反法民族动员把反拿破仑战争与民族、自由和祖国话语结合起来。","fields":[{"label":"标题","value":"德意志反法民族动员"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1813年前后"},{"label":"地点","value":"普鲁士、萨克森、北德和德意志各地"},{"label":"主要国家","value":"普鲁士；德意志地区；法国"},{"label":"一句话概括","value":"德意志反法民族动员把反拿破仑战争与民族、自由和祖国话语结合起来。"},{"label":"核心主张/思路","value":"将反抗法国支配解释为德意志民族解放，强调祖国、荣誉、公民牺牲和共同文化。"},{"label":"提出者/代表人物（可选）","value":"费希特、阿恩特、克尔纳、普鲁士改革派和志愿军宣传者。"},{"label":"它从何而来","value":"法国占领、征兵税负、普鲁士改革、浪漫主义民族文化和1812年俄国战役失败共同推动。"},{"label":"典型表现","value":"志愿军、学生和市民参军，诗歌、歌曲、宣言和公众捐助支持战争。"},{"label":"为什么重要","value":"它为19世纪德意志民族主义提供强烈记忆资源，也让王朝战争获得更广泛社会动员。"},{"label":"争议/局限","value":"动员话语中的“自由”在1815年后没有完全兑现，民族主义也可能排斥地方和多元身份。"},{"label":"出处","value":"Britannica, German nationalism；German History in Documents and Images, Wars of Liberation；Britannica, Fichte。"}],"relationItems":["← 前因：普鲁士《告我的人民》宣言","↔ 相关：德意志解放战争","↔ 相关：德意志民族主义","↔ 相关：德意志浪漫主义"],"relations":[{"text":"← 前因：普鲁士《告我的人民》宣言","id":"extra583"},{"text":"↔ 相关：德意志解放战争","id":"extra523"},{"text":"↔ 相关：德意志民族主义","id":"extra504"},{"text":"↔ 相关：德意志浪漫主义","id":"extra552"}],"source":"history","id":"extra588"},{"title":"德意志解放战争吕措夫自由军团","level":"C","type":"组织/机构卡","tags":["战争与外交","文化与思想"],"mainTag":"战争与外交","subTag":"文化与思想","timeText":"1813—1814年","place":"普鲁士和德意志战场","summary":"德意志解放战争吕措夫自由军团是解放战争中的志愿军单位，后来成为德意志民族主义记忆的重要符号。","fields":[{"label":"标题","value":"德意志解放战争吕措夫自由军团"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1813—1814年"},{"label":"地点","value":"普鲁士和德意志战场"},{"label":"主要国家","value":"普鲁士；德意志地区"},{"label":"一句话概括","value":"德意志解放战争吕措夫自由军团是解放战争中的志愿军单位，后来成为德意志民族主义记忆的重要符号。"},{"label":"性质/类型","value":"普鲁士志愿军和反法民族动员象征。"},{"label":"成立/解散时间","value":"1813年组建，拿破仑战争结束后被整编。"},{"label":"核心目标/宗旨","value":"吸收来自不同德意志地区的志愿者，参与对法作战，展示跨邦国的德意志爱国动员。"},{"label":"关键人物（可选）","value":"路德维希·阿道夫·威廉·冯·吕措夫、特奥多尔·克尔纳、弗里德里希·弗里森等。"},{"label":"关键行动/事件","value":"参与1813年解放战争，军事作用有限但宣传和象征意义很强。"},{"label":"为什么重要","value":"其黑红金颜色传统后来与德意志民族自由运动和黑红金旗帜发生联系。"},{"label":"争议/局限","value":"自由军团规模和军事效果有限，后世象征化程度超过其实际战场影响。"},{"label":"出处","value":"German History in Documents and Images, Lützow Free Corps；Britannica, German nationalism；Britannica, Wars of Liberation。"}],"relationItems":["← 前因：德意志反法民族动员","↔ 相关：德国黑红金旗帜","↔ 相关：德意志学生兄弟会","↔ 相关：德意志解放战争"],"relations":[{"text":"← 前因：德意志反法民族动员","id":"extra588"},{"text":"↔ 相关：德国黑红金旗帜","id":"extra505"},{"text":"↔ 相关：德意志学生兄弟会","id":"extra499"},{"text":"↔ 相关：德意志解放战争","id":"extra523"}],"source":"history","id":"extra589"},{"title":"德意志邦联《联邦条例》","level":"A","type":"制度/文本卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1815年6月8日","place":"维也纳会议","summary":"《联邦条例》建立德意志邦联，把拿破仑后德意志安排为松散主权国家联盟。","fields":[{"label":"标题","value":"德意志邦联《联邦条例》"},{"label":"分级","value":"A"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1815年6月8日"},{"label":"地点","value":"维也纳会议"},{"label":"主要国家","value":"德意志地区；奥地利；普鲁士"},{"label":"一句话概括","value":"《联邦条例》建立德意志邦联，把拿破仑后德意志安排为松散主权国家联盟。"},{"label":"制定方/签署方","value":"维也纳会议上的德意志各邦及欧洲列强安排，奥地利和普鲁士为关键力量。"},{"label":"主要内容","value":"规定德意志邦联由多个主权邦国组成，设立法兰克福邦联议会，成员承诺共同防御和维护德意志安全。"},{"label":"它试图解决什么问题","value":"它试图在神圣罗马帝国已解体、拿破仑体系崩溃后，为德意志地区提供稳定但不统一的政治框架。"},{"label":"为什么重要","value":"它是1815—1866年德意志政治的制度底盘。德意志统一问题、奥普竞争和自由民族运动都在这个框架内展开。"},{"label":"争议/局限","value":"条例没有建立民族国家和民选中央政府，邦联更重视王朝主权与安全秩序。"},{"label":"造成的影响","value":"德意志邦联成为维也纳体系在中欧的核心安排，也为后来的德意志统一与奥普领导权问题留下结构性矛盾。"},{"label":"出处","value":"Britannica, German Confederation；German History in Documents and Images, German Federal Act of 1815。"}],"relationItems":["← 前因：拿破仑战后维也纳会议","→ 后果：德意志邦联","→ 后果：德意志邦联议会","↔ 相关：欧洲梅特涅体系"],"relations":[{"text":"← 前因：拿破仑战后维也纳会议","id":"extra525"},{"text":"→ 后果：德意志邦联","id":"extra487"},{"text":"→ 后果：德意志邦联议会","id":"extra591"},{"text":"↔ 相关：欧洲梅特涅体系","id":"extra500"}],"source":"history","id":"extra590"},{"title":"德意志邦联议会","level":"A","type":"组织/机构卡","tags":["政治与制度"],"mainTag":"政治与制度","subTag":"","timeText":"1815—1866年","place":"法兰克福图恩与塔克西斯宫","summary":"德意志邦联议会是邦联唯一中央机构，由各邦使节组成而非民选议会。","fields":[{"label":"标题","value":"德意志邦联议会"},{"label":"分级","value":"A"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"时间","value":"1815—1866年"},{"label":"地点","value":"法兰克福图恩与塔克西斯宫"},{"label":"主要国家","value":"德意志地区；奥地利；普鲁士"},{"label":"一句话概括","value":"德意志邦联议会是邦联唯一中央机构，由各邦使节组成而非民选议会。"},{"label":"性质/类型","value":"德意志邦联常设使节会议，又称联邦会议或邦联议会。"},{"label":"成立/解散时间","value":"1815年邦联建立后设立，1866年普奥战争后随德意志邦联解体而终结。"},{"label":"核心目标/宗旨","value":"代表各成员邦政府协商邦联安全、宪制、军事和镇压革命等共同事务。"},{"label":"关键人物（可选）","value":"奥地利主席使节、普鲁士使节、各邦外交代表。"},{"label":"关键行动/事件","value":"通过卡尔斯巴德决议、处理1848革命前后的邦联危机，并在1851年复辟后恢复运作。"},{"label":"为什么重要","value":"它体现德意志邦联的本质：中央机构服务邦国政府，不代表德意志人民。"},{"label":"争议/局限","value":"多数重大事项需要高度一致，效率低且保守，无法解决统一和代表制诉求。"},{"label":"出处","value":"Britannica, German Confederation；German History in Documents and Images, German Federal Assembly。"}],"relationItems":["← 前因：德意志邦联《联邦条例》","↔ 相关：德意志邦联","↔ 相关：德意志邦联军事制度","→ 后果：德意志邦联复辟"],"relations":[{"text":"← 前因：德意志邦联《联邦条例》","id":"extra590"},{"text":"↔ 相关：德意志邦联","id":"extra487"},{"text":"↔ 相关：德意志邦联军事制度","id":"extra595"},{"text":"→ 后果：德意志邦联复辟","id":"extra606"}],"source":"history","id":"extra591"},{"title":"克莱门斯·冯·梅特涅","level":"A","type":"人物卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1773—1859年；1809—1848年主导奥地利外交","place":"维也纳、奥地利帝国和欧洲外交舞台","summary":"梅特涅是维也纳体系和德意志保守秩序的核心人物，长期压制自由主义和民族主义。","fields":[{"label":"标题","value":"克莱门斯·冯·梅特涅"},{"label":"分级","value":"A"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1773—1859年；1809—1848年主导奥地利外交"},{"label":"地点","value":"维也纳、奥地利帝国和欧洲外交舞台"},{"label":"主要国家","value":"奥地利；德意志地区；欧洲"},{"label":"一句话概括","value":"梅特涅是维也纳体系和德意志保守秩序的核心人物，长期压制自由主义和民族主义。"},{"label":"生卒年/活跃年代","value":"1773—1859年，1815年后影响力达到高峰。"},{"label":"身份/职务","value":"奥地利外交家、首相、欧洲保守秩序设计者。"},{"label":"关键贡献/作为","value":"主持维也纳会议后秩序，维护欧洲均势，推动在德意志邦联中镇压自由主义、民族主义和大学激进运动。"},{"label":"核心主张/立场","value":"维护王朝合法性、贵族秩序和多民族帝国稳定，反对革命、民族自决和激进宪政。"},{"label":"为什么重要","value":"理解1815—1848德意志政治，必须理解梅特涅体系如何把德意志邦联变成保守秩序工具。"},{"label":"争议/评价","value":"他维护了欧洲长期和平的一部分秩序，也压制了政治参与和民族诉求，积累1848革命压力。"},{"label":"关联事件（可选）","value":"欧洲梅特涅体系；德意志邦联的卡尔斯巴德决议；维也纳三月革命与梅特涅下台。"},{"label":"出处","value":"Britannica, Klemens von Metternich；Britannica, Congress of Vienna；Britannica, Carlsbad Decrees。"}],"relationItems":["← 前因：拿破仑战后维也纳会议","→ 后果：德意志邦联的卡尔斯巴德决议","→ 后果：维也纳三月革命与梅特涅下台","↔ 相关：欧洲梅特涅体系"],"relations":[{"text":"← 前因：拿破仑战后维也纳会议","id":"extra525"},{"text":"→ 后果：德意志邦联的卡尔斯巴德决议","id":"extra488"},{"text":"→ 后果：维也纳三月革命与梅特涅下台","id":"extra598"},{"text":"↔ 相关：欧洲梅特涅体系","id":"extra500"}],"source":"history","id":"extra592"},{"title":"桑德刺杀科策布事件","level":"B","type":"事件卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1819年3月23日","place":"曼海姆","summary":"学生卡尔·路德维希·桑德刺杀保守作家科策布，为卡尔斯巴德决议提供镇压借口。","fields":[{"label":"标题","value":"桑德刺杀科策布事件"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1819年3月23日"},{"label":"地点","value":"曼海姆"},{"label":"主要国家","value":"德意志地区；俄罗斯；奥地利"},{"label":"一句话概括","value":"学生卡尔·路德维希·桑德刺杀保守作家科策布，为卡尔斯巴德决议提供镇压借口。"},{"label":"参与者","value":"卡尔·路德维希·桑德、奥古斯特·冯·科策布、德意志学生兄弟会、梅特涅和德意志邦联政府。"},{"label":"发生了什么","value":"1819年，激进学生桑德刺杀被民族主义者视为反动和亲俄的作家科策布。事件震动德意志各邦，保守政府将其解释为大学和学生团体中存在革命阴谋。"},{"label":"为什么重要","value":"它是卡尔斯巴德决议的直接导火索，使个体政治暴力被保守政权转化为系统镇压自由民族运动的理由。"},{"label":"前因","value":"瓦尔特堡节后，学生兄弟会和民族主义青年被保守政府视为危险力量；科策布的政治立场激起激进学生仇恨。"},{"label":"后果","value":"梅特涅推动德意志邦联通过卡尔斯巴德决议，大学、新闻出版和政治团体受到更严厉监控；自由民族运动从公开组织转入更受压制的地下和社团空间。"},{"label":"出处","value":"Britannica, Carlsbad Decrees；German History in Documents and Images, Kotzebue assassination and Carlsbad Decrees。"}],"relationItems":["← 前因：德国瓦尔特堡节","→ 后果：德意志邦联的卡尔斯巴德决议","→ 后果：美因茨中央调查委员会","↔ 相关：德意志学生兄弟会"],"relations":[{"text":"← 前因：德国瓦尔特堡节","id":"extra498"},{"text":"→ 后果：德意志邦联的卡尔斯巴德决议","id":"extra488"},{"text":"→ 后果：美因茨中央调查委员会","id":"extra594"},{"text":"↔ 相关：德意志学生兄弟会","id":"extra499"}],"source":"history","id":"extra593"},{"title":"美因茨中央调查委员会","level":"C","type":"组织/机构卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1819—1840年代","place":"美因茨","summary":"美因茨中央调查委员会调查所谓革命阴谋，是卡尔斯巴德体系的镇压工具。","fields":[{"label":"标题","value":"美因茨中央调查委员会"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1819—1840年代"},{"label":"地点","value":"美因茨"},{"label":"主要国家","value":"德意志地区；奥地利；普鲁士"},{"label":"一句话概括","value":"美因茨中央调查委员会调查所谓革命阴谋，是卡尔斯巴德体系的镇压工具。"},{"label":"性质/类型","value":"德意志邦联设立的政治调查机构。"},{"label":"成立/解散时间","value":"1819年卡尔斯巴德决议后设立，影响延续到19世纪中期。"},{"label":"核心目标/宗旨","value":"调查大学、学生团体、出版界和自由民族主义网络中的所谓颠覆活动。"},{"label":"关键人物（可选）","value":"德意志邦联委派的调查官员，奥地利和普鲁士政府为主要支持者。"},{"label":"关键行动/事件","value":"收集材料、审讯嫌疑人、向邦联议会和各邦政府提供镇压依据。"},{"label":"为什么重要","value":"它把政治警察和跨邦协作制度化，说明维也纳体系下的德意志邦联不仅防外敌，也防内部自由主义。"},{"label":"争议/局限","value":"委员会常把自由主义和民族主义等同于阴谋，扩大政治恐惧并压制公共讨论。"},{"label":"出处","value":"Britannica, Carlsbad Decrees；German History in Documents and Images, Mainz Central Investigation Commission。"}],"relationItems":["← 前因：桑德刺杀科策布事件","↔ 相关：德意志邦联的卡尔斯巴德决议","↔ 相关：德意志Vormärz时期","↔ 同时期参考：欧洲复辟时期政治警察"],"relations":[{"text":"← 前因：桑德刺杀科策布事件","id":"extra593"},{"text":"↔ 相关：德意志邦联的卡尔斯巴德决议","id":"extra488"},{"text":"↔ 相关：德意志Vormärz时期","id":"extra502"}],"source":"history","id":"extra594"},{"title":"德意志邦联军事制度","level":"B","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1815—1866年","place":"德意志邦联各邦及联邦军事区","summary":"德意志邦联军事制度要求各邦提供联邦军队，但缺乏统一指挥和国家化动员能力。","fields":[{"label":"标题","value":"德意志邦联军事制度"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1815—1866年"},{"label":"地点","value":"德意志邦联各邦及联邦军事区"},{"label":"主要国家","value":"德意志地区；奥地利；普鲁士"},{"label":"一句话概括","value":"德意志邦联军事制度要求各邦提供联邦军队，但缺乏统一指挥和国家化动员能力。"},{"label":"制定方/签署方","value":"德意志邦联议会和成员邦政府。"},{"label":"主要内容","value":"成员邦按比例提供军队，组成邦联军，承担共同防御和邦联执行任务。"},{"label":"它试图解决什么问题","value":"维也纳会议后德意志需要共同安全机制，既防法国等外部威胁，也维护内部秩序。"},{"label":"为什么重要","value":"它显示德意志邦联是安全联盟而非统一国家；军事制度无法真正整合奥地利、普鲁士和中小邦国。"},{"label":"争议/局限","value":"各邦训练、装备、指挥体系差异大，奥普竞争又使联邦军事合作长期低效。"},{"label":"造成的影响","value":"1848和1866危机中，邦联军事制度难以形成统一政治意志，最终被普鲁士主导的新军事结构取代。"},{"label":"出处","value":"Britannica, German Confederation；German History in Documents and Images, German Confederation military arrangements。"}],"relationItems":["← 前因：德意志邦联《联邦条例》","↔ 相关：德意志邦联议会","↔ 相关：德意志邦联要塞体系","→ 后果：普奥战争"],"relations":[{"text":"← 前因：德意志邦联《联邦条例》","id":"extra590"},{"text":"↔ 相关：德意志邦联议会","id":"extra591"},{"text":"↔ 相关：德意志邦联要塞体系","id":"extra596"},{"text":"→ 后果：普奥战争","id":"extra495"}],"source":"history","id":"extra595"},{"title":"德意志邦联要塞体系","level":"C","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1815—1866年","place":"美因茨、卢森堡、兰道、拉施塔特、乌尔姆等","summary":"德意志邦联要塞体系用于防御法国和维护邦联安全，是维也纳体系军事安排的一部分。","fields":[{"label":"标题","value":"德意志邦联要塞体系"},{"label":"分级","value":"C"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1815—1866年"},{"label":"地点","value":"美因茨、卢森堡、兰道、拉施塔特、乌尔姆等"},{"label":"主要国家","value":"德意志地区；奥地利；普鲁士；卢森堡"},{"label":"一句话概括","value":"德意志邦联要塞体系用于防御法国和维护邦联安全，是维也纳体系军事安排的一部分。"},{"label":"制定方/签署方","value":"德意志邦联及维也纳会议后欧洲安全安排。"},{"label":"主要内容","value":"在战略城市设立联邦要塞，由成员邦共同承担驻军、经费和防御责任。"},{"label":"它试图解决什么问题","value":"拿破仑战争后，德意志西南和莱茵方向被视为对法防御前线，邦联需要共同堡垒体系。"},{"label":"为什么重要","value":"它体现德意志邦联最能达成共识的领域是防御法国，而不是建立民族国家。"},{"label":"争议/局限","value":"要塞维护成本高，指挥和责任分配复杂，难以解决邦联内部政治分裂。"},{"label":"造成的影响","value":"联邦要塞在1848革命、邦联执行和1866战争前后仍具有政治军事意义。"},{"label":"出处","value":"Britannica, German Confederation；German History in Documents and Images, Federal fortresses。"}],"relationItems":["← 前因：德意志邦联军事制度","↔ 相关：德意志邦联","↔ 相关：欧洲梅特涅体系","↔ 同时期参考：维也纳体系边界安全"],"relations":[{"text":"← 前因：德意志邦联军事制度","id":"extra595"},{"text":"↔ 相关：德意志邦联","id":"extra487"},{"text":"↔ 相关：欧洲梅特涅体系","id":"extra500"}],"source":"history","id":"extra596"},{"title":"柏林三月革命","level":"A","type":"事件卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1848年3月18—19日","place":"柏林","summary":"柏林三月革命迫使普鲁士国王让步，成为德意志1848革命的关键城市节点。","fields":[{"label":"标题","value":"柏林三月革命"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1848年3月18—19日"},{"label":"地点","value":"柏林"},{"label":"主要国家","value":"普鲁士；德意志地区"},{"label":"一句话概括","value":"柏林三月革命迫使普鲁士国王让步，成为德意志1848革命的关键城市节点。"},{"label":"参与者","value":"柏林市民、工人、学生、普鲁士军队、弗里德里希·威廉四世。"},{"label":"发生了什么","value":"1848年法国二月革命和维也纳革命后，柏林爆发要求宪法、新闻自由和德意志统一的示威。3月18日冲突升级为街垒战，国王最终撤军、向死者致敬，并承诺改革和支持德意志事业。"},{"label":"为什么重要","value":"它让普鲁士暂时转向革命阵营，也为法兰克福国民议会和普鲁士宪政政治打开空间。"},{"label":"前因","value":"经济危机、自由主义和民族主义诉求积累，维也纳梅特涅倒台鼓舞了柏林抗议者；普鲁士王权迟疑应对，使街头压力迅速升级。"},{"label":"后果","value":"普鲁士国民议会召开，国王短期让步，但到1848年底保守力量重新掌控柏林；普鲁士宪政转入王权主导的钦定宪法路线。"},{"label":"出处","value":"Britannica, Revolutions of 1848；German History in Documents and Images, Berlin March Revolution。"}],"relationItems":["← 前因：1848年欧洲革命","→ 后果：德国法兰克福国民议会","↔ 相关：1848年德意志革命","↔ 相关：普鲁士《钦定宪法》"],"relations":[{"text":"← 前因：1848年欧洲革命","id":"extra530"},{"text":"→ 后果：德国法兰克福国民议会","id":"extra491"},{"text":"↔ 相关：1848年德意志革命","id":"extra490"},{"text":"↔ 相关：普鲁士《钦定宪法》","id":"extra605"}],"source":"history","id":"extra597"},{"title":"维也纳三月革命与梅特涅下台","level":"A","type":"事件卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1848年3月13日","place":"维也纳","summary":"维也纳三月革命迫使梅特涅辞职，欧洲复辟秩序的核心象征崩塌。","fields":[{"label":"标题","value":"维也纳三月革命与梅特涅下台"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1848年3月13日"},{"label":"地点","value":"维也纳"},{"label":"主要国家","value":"奥地利；德意志地区；哈布斯堡君主国"},{"label":"一句话概括","value":"维也纳三月革命迫使梅特涅辞职，欧洲复辟秩序的核心象征崩塌。"},{"label":"参与者","value":"维也纳学生、市民、工人、奥地利政府、梅特涅、皇帝斐迪南一世。"},{"label":"发生了什么","value":"1848年3月，维也纳示威要求宪法、新闻自由和政治改革。街头冲突后，梅特涅失去支持并辞职流亡，奥地利政府承诺宪政改革。"},{"label":"为什么重要","value":"梅特涅下台象征1815年以来保守复辟体系的危机，也推动德意志各邦革命浪潮升级。"},{"label":"前因","value":"经济困难、民族问题、自由主义不满和法国二月革命共同冲击哈布斯堡统治；维也纳学生和市民把帝国改革要求集中指向梅特涅。"},{"label":"后果","value":"奥地利帝国陷入多民族革命危机，德意志邦联的保守中心动摇，法兰克福国民议会获得机会；但奥地利军队和王朝很快组织反击。"},{"label":"出处","value":"Britannica, Revolutions of 1848；Britannica, Klemens von Metternich；German History in Documents and Images, Vienna March Revolution。"}],"relationItems":["← 前因：克莱门斯·冯·梅特涅","→ 后果：1848年德意志革命","↔ 相关：1848年欧洲革命","↔ 相关：奥地利克雷姆西尔议会"],"relations":[{"text":"← 前因：克莱门斯·冯·梅特涅","id":"extra592"},{"text":"→ 后果：1848年德意志革命","id":"extra490"},{"text":"↔ 相关：1848年欧洲革命","id":"extra530"},{"text":"↔ 相关：奥地利克雷姆西尔议会","id":"extra599"}],"source":"history","id":"extra598"},{"title":"奥地利克雷姆西尔议会","level":"B","type":"组织/机构卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1848—1849年","place":"维也纳、克雷姆西尔","summary":"克雷姆西尔议会试图为哈布斯堡帝国制定宪法，却被新皇帝弗朗茨·约瑟夫解散。","fields":[{"label":"标题","value":"奥地利克雷姆西尔议会"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1848—1849年"},{"label":"地点","value":"维也纳、克雷姆西尔"},{"label":"主要国家","value":"奥地利；捷克；哈布斯堡君主国"},{"label":"一句话概括","value":"克雷姆西尔议会试图为哈布斯堡帝国制定宪法，却被新皇帝弗朗茨·约瑟夫解散。"},{"label":"性质/类型","value":"奥地利革命时期的帝国议会和制宪机构。"},{"label":"成立/解散时间","value":"1848年召开，因维也纳十月起义迁至克雷姆西尔，1849年3月被解散。"},{"label":"核心目标/宗旨","value":"处理农民解放和帝国宪法问题，在多民族帝国内建立较自由的宪政结构。"},{"label":"关键人物（可选）","value":"奥地利各民族代表、弗朗茨·约瑟夫、施瓦岑贝格政府。"},{"label":"关键行动/事件","value":"废除农奴制相关安排，并起草较自由的克雷姆西尔宪法草案。"},{"label":"为什么重要","value":"它显示哈布斯堡帝国也曾出现宪政重组可能，但王朝和军队最终选择自上而下恢复中央权威。"},{"label":"争议/局限","value":"民族代表之间利益复杂，议会权威依赖皇帝和军队承认，基础脆弱。"},{"label":"出处","value":"Britannica, Revolutions of 1848；German History in Documents and Images, Kremsier Parliament。"}],"relationItems":["← 前因：维也纳三月革命与梅特涅下台","↔ 相关：1848年欧洲革命","↔ 相关：法兰克福国民议会的民族边界争议","↔ 同时期参考：哈布斯堡帝国民族问题"],"relations":[{"text":"← 前因：维也纳三月革命与梅特涅下台","id":"extra598"},{"text":"↔ 相关：1848年欧洲革命","id":"extra530"},{"text":"↔ 相关：法兰克福国民议会的民族边界争议","id":"extra601"}],"source":"history","id":"extra599"},{"title":"法兰克福国民议会的左右派分裂","level":"B","type":"概念/思潮卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1848—1849年","place":"法兰克福圣保罗教堂","summary":"法兰克福国民议会内部自由派、民主派和保守派分裂，削弱了革命中央权威。","fields":[{"label":"标题","value":"法兰克福国民议会的左右派分裂"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1848—1849年"},{"label":"地点","value":"法兰克福圣保罗教堂"},{"label":"主要国家","value":"德意志地区"},{"label":"一句话概括","value":"法兰克福国民议会内部自由派、民主派和保守派分裂，削弱了革命中央权威。"},{"label":"核心主张/思路","value":"议会内部围绕君主制或共和制、中央权力强弱、普选权和社会改革形成不同政治阵营。"},{"label":"提出者/代表人物（可选）","value":"海因里希·冯·加格恩等自由派，罗伯特·布卢姆等民主派代表。"},{"label":"它从何而来","value":"1848革命把民族统一、自由宪政、民主参与和社会问题同时推上议程，议员背景和政治目标差异很大。"},{"label":"典型表现","value":"议会中形成不同俱乐部和派别，温和自由派主导宪法工作，左翼民主派批评其妥协和行动迟缓。"},{"label":"为什么重要","value":"它解释1848革命为什么难以形成统一行动：议会能辩论宪法，却难以动员军队和执行权。"},{"label":"争议/局限","value":"分裂不是单纯“内耗”，而是革命目标本身存在真实差异。"},{"label":"出处","value":"Britannica, Frankfurt National Assembly；German History in Documents and Images, Frankfurt Parliament factions。"}],"relationItems":["← 前因：德国法兰克福国民议会","↔ 相关：德国法兰克福宪法","↔ 相关：普鲁士国王拒绝德意志皇冠","↔ 相关：1848革命失败后的保守反扑"],"relations":[{"text":"← 前因：德国法兰克福国民议会","id":"extra491"},{"text":"↔ 相关：德国法兰克福宪法","id":"extra531"},{"text":"↔ 相关：普鲁士国王拒绝德意志皇冠","id":"extra532"},{"text":"↔ 相关：1848革命失败后的保守反扑","id":"extra534"}],"source":"history","id":"extra600"},{"title":"法兰克福国民议会的民族边界争议","level":"B","type":"概念/思潮卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1848—1849年","place":"法兰克福及德意志、波希米亚、波森、石勒苏益等争议地区","summary":"法兰克福国民议会无法清晰处理德意志民族边界，暴露民族国家构想的排他和矛盾。","fields":[{"label":"标题","value":"法兰克福国民议会的民族边界争议"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1848—1849年"},{"label":"地点","value":"法兰克福及德意志、波希米亚、波森、石勒苏益等争议地区"},{"label":"主要国家","value":"德意志地区；奥地利；普鲁士；捷克；波兰；丹麦"},{"label":"一句话概括","value":"法兰克福国民议会无法清晰处理德意志民族边界，暴露民族国家构想的排他和矛盾。"},{"label":"核心主张/思路","value":"议会必须决定德国是否包括奥地利、波希米亚、波森、石勒苏益等多民族或争议地区。"},{"label":"提出者/代表人物（可选）","value":"大德意志派、小德意志派，以及围绕波兰、捷克和丹麦问题的不同议员。"},{"label":"它从何而来","value":"德意志邦联边界、语言分布、王朝领地和民族自决诉求彼此不重合，1848革命迫使这些问题公开化。"},{"label":"典型表现","value":"大德意志与小德意志争论，波森德波冲突，石勒苏益-荷尔斯泰因问题，以及捷克人拒绝参加德意志民族议会。"},{"label":"为什么重要","value":"它说明民族国家建设不是单纯“统一德国”，而涉及谁被纳入、谁被排除和谁被支配。"},{"label":"争议/局限","value":"许多自由民族主义者支持德国统一，却难以承认波兰、捷克、丹麦等民族同等自决。"},{"label":"出处","value":"Britannica, Frankfurt National Assembly；Britannica, Revolutions of 1848；German History in Documents and Images, National question in 1848。"}],"relationItems":["← 前因：德国法兰克福国民议会","↔ 相关：大德意志方案与小德意志方案","↔ 相关：第一次石勒苏益战争","↔ 相关：1848年欧洲革命"],"relations":[{"text":"← 前因：德国法兰克福国民议会","id":"extra491"},{"text":"↔ 相关：大德意志方案与小德意志方案","id":"extra527"},{"text":"↔ 相关：第一次石勒苏益战争","id":"extra602"},{"text":"↔ 相关：1848年欧洲革命","id":"extra530"}],"source":"history","id":"extra601"},{"title":"第一次石勒苏益战争","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1848—1851年","place":"石勒苏益、荷尔斯泰因、日德兰和德意志北部","summary":"第一次石勒苏益战争围绕丹麦王国和德意志民族运动争夺石勒苏益-荷尔斯泰因归属。","fields":[{"label":"标题","value":"第一次石勒苏益战争"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1848—1851年"},{"label":"地点","value":"石勒苏益、荷尔斯泰因、日德兰和德意志北部"},{"label":"主要国家","value":"丹麦；德意志地区；普鲁士；德意志邦联"},{"label":"一句话概括","value":"第一次石勒苏益战争围绕丹麦王国和德意志民族运动争夺石勒苏益-荷尔斯泰因归属。"},{"label":"参与者","value":"丹麦王国、石勒苏益-荷尔斯泰因德意志派、普鲁士、德意志邦联、欧洲列强。"},{"label":"发生了什么","value":"1848年丹麦民族自由派和德意志民族运动都试图把石勒苏益纳入自己的民族国家构想。石勒苏益-荷尔斯泰因德意志派起义，普鲁士和邦联军队介入，战争持续到1851年。"},{"label":"为什么重要","value":"它把1848德意志民族议题推向国际冲突，也为1864年普丹战争埋下前因。"},{"label":"前因","value":"石勒苏益和荷尔斯泰因处于丹麦王权、德意志邦联和语言民族边界交错处，民族自由主义使旧王朝共主关系难以维持。"},{"label":"后果","value":"在列强压力下，丹麦维持整体君主国，但问题没有解决，德意志民族派和丹麦民族派都不满意；1860年代危机再次爆发并被俾斯麦利用。"},{"label":"出处","value":"Britannica, Schleswig-Holstein Question；Britannica, First Schleswig War；German History in Documents and Images, Schleswig-Holstein 1848。"}],"relationItems":["← 前因：法兰克福国民议会的民族边界争议","→ 后果：石勒苏益-荷尔斯泰因问题","↔ 相关：1848年德意志革命","↔ 相关：普丹战争"],"relations":[{"text":"← 前因：法兰克福国民议会的民族边界争议","id":"extra601"},{"text":"→ 后果：石勒苏益-荷尔斯泰因问题","id":"extra541"},{"text":"↔ 相关：1848年德意志革命","id":"extra490"},{"text":"↔ 相关：普丹战争","id":"extra494"}],"source":"history","id":"extra602"},{"title":"罗伯特·布卢姆被处决","level":"B","type":"事件卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1848年11月9日","place":"维也纳","summary":"法兰克福议员布卢姆在维也纳被处决，象征1848革命左翼和议会权威的失败。","fields":[{"label":"标题","value":"罗伯特·布卢姆被处决"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1848年11月9日"},{"label":"地点","value":"维也纳"},{"label":"主要国家","value":"奥地利；德意志地区"},{"label":"一句话概括","value":"法兰克福议员布卢姆在维也纳被处决，象征1848革命左翼和议会权威的失败。"},{"label":"参与者","value":"罗伯特·布卢姆、奥地利军队、法兰克福国民议会、维也纳革命者。"},{"label":"发生了什么","value":"1848年维也纳十月起义期间，法兰克福国民议会左翼代表罗伯特·布卢姆前往维也纳支持革命。奥地利军队镇压起义后逮捕并处决布卢姆，无视其议员豁免身份。"},{"label":"为什么重要","value":"它暴露法兰克福国民议会缺乏执行权和保护自身代表的能力，也成为革命失败的强烈象征。"},{"label":"前因","value":"法兰克福议会内部左翼同情维也纳革命，希望用跨地区革命团结抵抗保守反扑；奥地利政府则决心用军队恢复帝国权威。"},{"label":"后果","value":"革命左翼受挫，保守力量信心上升，法兰克福议会的政治威信严重受损；议会无法保护自身代表，暴露其缺乏强制权。"},{"label":"出处","value":"Britannica, Robert Blum；Britannica, Revolutions of 1848；German History in Documents and Images, Execution of Robert Blum。"}],"relationItems":["← 前因：法兰克福国民议会的左右派分裂","↔ 相关：奥地利克雷姆西尔议会","→ 后果：1848革命失败后的保守反扑","↔ 相关：德国法兰克福国民议会"],"relations":[{"text":"← 前因：法兰克福国民议会的左右派分裂","id":"extra600"},{"text":"↔ 相关：奥地利克雷姆西尔议会","id":"extra599"},{"text":"→ 后果：1848革命失败后的保守反扑","id":"extra534"},{"text":"↔ 相关：德国法兰克福国民议会","id":"extra491"}],"source":"history","id":"extra603"},{"title":"巴登革命与拉施塔特起义","level":"C","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1849年5—7月","place":"巴登、拉施塔特","summary":"巴登革命和拉施塔特起义是1848革命最后阶段的武装抵抗，被普鲁士军队镇压。","fields":[{"label":"标题","value":"巴登革命与拉施塔特起义"},{"label":"分级","value":"C"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1849年5—7月"},{"label":"地点","value":"巴登、拉施塔特"},{"label":"主要国家","value":"德意志地区；巴登；普鲁士"},{"label":"一句话概括","value":"巴登革命和拉施塔特起义是1848革命最后阶段的武装抵抗，被普鲁士军队镇压。"},{"label":"参与者","value":"巴登民主派、士兵起义者、临时革命政府、普鲁士军队、德意志邦联力量。"},{"label":"发生了什么","value":"1849年法兰克福宪法遭多邦拒绝后，巴登和普法尔茨等地爆发维护帝国宪法的起义。巴登军队部分倒向革命，拉施塔特要塞成为抵抗中心。普鲁士军队最终攻克并镇压起义。"},{"label":"为什么重要","value":"它标志德意志1848—1849革命的军事终结，也显示没有大邦军队支持的宪法运动难以成功。"},{"label":"前因","value":"普鲁士国王拒绝皇冠和法兰克福宪法后，民主派试图通过武装起义保卫革命成果；巴登军队部分倒向革命提供了短暂军事机会。"},{"label":"后果","value":"革命者流亡或被镇压，保守秩序恢复，许多“1848人”后来把经验带到美国等地；德意志民主派的组织网络遭重创。"},{"label":"出处","value":"Britannica, Revolutions of 1848；German History in Documents and Images, Baden uprising 1849。"}],"relationItems":["← 前因：德意志帝国宪法运动","→ 后果：1848革命失败后的保守反扑","↔ 相关：德国法兰克福宪法","↔ 相关：德意志自由主义"],"relations":[{"text":"← 前因：德意志帝国宪法运动","id":"extra533"},{"text":"→ 后果：1848革命失败后的保守反扑","id":"extra534"},{"text":"↔ 相关：德国法兰克福宪法","id":"extra531"},{"text":"↔ 相关：德意志自由主义","id":"extra501"}],"source":"history","id":"extra604"},{"title":"普鲁士《钦定宪法》","level":"B","type":"制度/文本卡","tags":["政治与制度"],"mainTag":"政治与制度","subTag":"","timeText":"1850年1月31日","place":"普鲁士王国","summary":"普鲁士《钦定宪法》在革命失败后保留宪政外壳，同时维持国王和保守精英优势。","fields":[{"label":"标题","value":"普鲁士《钦定宪法》"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"时间","value":"1850年1月31日"},{"label":"地点","value":"普鲁士王国"},{"label":"主要国家","value":"普鲁士"},{"label":"一句话概括","value":"普鲁士《钦定宪法》在革命失败后保留宪政外壳，同时维持国王和保守精英优势。"},{"label":"制定方/签署方","value":"普鲁士国王弗里德里希·威廉四世。"},{"label":"主要内容","value":"规定两院制议会、基本权利和君主制宪政框架，但国王保留强大行政、军事和任命权，选举制度向纳税高者倾斜。"},{"label":"它试图解决什么问题","value":"普鲁士王权需要在革命压力后给出宪法形式，同时避免真正议会主权。"},{"label":"为什么重要","value":"它是理解普鲁士宪法冲突的前提：议会存在，但军队和行政仍主要掌握在国王手中。"},{"label":"争议/局限","value":"宪法不是由制宪议会自由制定，而是王权自上而下颁布，三等选举制严重偏向富人。"},{"label":"造成的影响","value":"普鲁士进入有限宪政阶段，1860年代军制改革和预算权冲突由此爆发。"},{"label":"出处","value":"Britannica, Prussia；German History in Documents and Images, Prussian Constitution of 1850。"}],"relationItems":["← 前因：1848革命失败后的保守反扑","→ 后果：普鲁士宪法冲突","↔ 相关：柏林三月革命","↔ 相关：德意志进步党"],"relations":[{"text":"← 前因：1848革命失败后的保守反扑","id":"extra534"},{"text":"→ 后果：普鲁士宪法冲突","id":"extra539"},{"text":"↔ 相关：柏林三月革命","id":"extra597"},{"text":"↔ 相关：德意志进步党","id":"extra610"}],"source":"history","id":"extra605"},{"title":"德意志邦联复辟","level":"B","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1851年","place":"法兰克福","summary":"1851年德意志邦联议会恢复运作，标志1848统一革命失败后的旧秩序复辟。","fields":[{"label":"标题","value":"德意志邦联复辟"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1851年"},{"label":"地点","value":"法兰克福"},{"label":"主要国家","value":"德意志地区；奥地利；普鲁士"},{"label":"一句话概括","value":"1851年德意志邦联议会恢复运作，标志1848统一革命失败后的旧秩序复辟。"},{"label":"参与者","value":"奥地利、普鲁士、德意志邦联成员邦、邦联议会。"},{"label":"发生了什么","value":"1848革命期间，法兰克福国民议会一度取代邦联议会成为全国政治中心。革命失败和奥尔米茨屈辱后，旧德意志邦联议会在1851年恢复，保守邦联秩序重新建立。"},{"label":"为什么重要","value":"它表明1848革命未能创造统一民族国家，德意志统一与奥普领导权问题又回到奥普竞争和邦联框架。"},{"label":"前因","value":"普鲁士国王拒绝皇冠、德意志帝国宪法运动失败，奥地利在1850年迫使普鲁士放弃埃尔福特联盟路线；旧邦联框架因此重新获得空间。"},{"label":"后果","value":"德意志自由民族运动暂时退潮，奥地利恢复邦联主席地位，但普奥结构性矛盾继续存在；德意志统一问题并未被真正解决。"},{"label":"出处","value":"Britannica, German Confederation；German History in Documents and Images, Restoration of the German Confederation。"}],"relationItems":["← 前因：普鲁士的奥尔米茨屈辱","↔ 相关：德意志邦联议会","↔ 相关：1848革命失败后的保守反扑","→ 后果：奥地利与普鲁士二元主义"],"relations":[{"text":"← 前因：普鲁士的奥尔米茨屈辱","id":"extra492"},{"text":"↔ 相关：德意志邦联议会","id":"extra591"},{"text":"↔ 相关：1848革命失败后的保守反扑","id":"extra534"},{"text":"→ 后果：奥地利与普鲁士二元主义","id":"extra535"}],"source":"history","id":"extra606"},{"title":"克里米亚战争与奥地利外交孤立","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1853—1856年","place":"黑海、巴尔干、维也纳外交舞台","summary":"克里米亚战争中奥地利疏远俄罗斯又未赢得西方信任，削弱其后续德意志地位。","fields":[{"label":"标题","value":"克里米亚战争与奥地利外交孤立"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1853—1856年"},{"label":"地点","value":"黑海、巴尔干、维也纳外交舞台"},{"label":"主要国家","value":"俄罗斯；奥地利；法国；英国；奥斯曼帝国；普鲁士"},{"label":"一句话概括","value":"克里米亚战争中奥地利疏远俄罗斯又未赢得西方信任，削弱其后续德意志地位。"},{"label":"参与者","value":"俄罗斯、奥斯曼帝国、英国、法国、奥地利、普鲁士。"},{"label":"发生了什么","value":"克里米亚战争中，奥地利没有直接加入英法对俄战争，但对俄罗斯施压并占据多瑙公国。俄罗斯认为奥地利背弃1849年镇压匈牙利时的帮助，英法也不完全信任奥地利。"},{"label":"为什么重要","value":"它削弱奥地利外交支持，为1859年意大利战争和1866年普奥战争中奥地利孤立埋下背景。"},{"label":"前因","value":"奥地利担心俄罗斯在巴尔干扩张威胁自身多瑙和巴尔干利益，又害怕完全倒向英法引发风险；这种摇摆使各方都难以信任维也纳。"},{"label":"后果","value":"俄奥关系恶化，普鲁士在德意志统一与奥普领导权问题上拥有更大回旋空间，奥地利大国地位受到侵蚀；1866年奥地利难以获得俄罗斯支持。"},{"label":"出处","value":"Britannica, Crimean War；Britannica, Austria - history；German History in Documents and Images, Austria and the Crimean War。"}],"relationItems":["↔ 相关：奥地利与普鲁士二元主义","→ 后果：德意志民族协会","↔ 同时期参考：克里米亚战争","↔ 相关：普奥战争"],"relations":[{"text":"↔ 相关：奥地利与普鲁士二元主义","id":"extra535"},{"text":"→ 后果：德意志民族协会","id":"extra608"},{"text":"↔ 相关：普奥战争","id":"extra495"}],"source":"history","id":"extra607"},{"title":"德意志民族协会","level":"B","type":"组织/机构卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1859—1867年","place":"法兰克福、艾森纳赫及德意志各地","summary":"德意志民族协会把自由派民族主义组织化，主张由普鲁士领导小德意志统一。","fields":[{"label":"标题","value":"德意志民族协会"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1859—1867年"},{"label":"地点","value":"法兰克福、艾森纳赫及德意志各地"},{"label":"主要国家","value":"德意志地区；普鲁士"},{"label":"一句话概括","value":"德意志民族协会把自由派民族主义组织化，主张由普鲁士领导小德意志统一。"},{"label":"性质/类型","value":"自由派民族主义政治组织和准政党网络。"},{"label":"成立/解散时间","value":"1859年成立，1867年北德意志邦联建立后逐渐失去原有功能。"},{"label":"核心目标/宗旨","value":"推动德意志民族国家、宪政和议会制度，倾向小德意志方案和普鲁士领导。"},{"label":"关键人物（可选）","value":"鲁道夫·冯·贝尼希森、赫尔曼·舒尔策-德利奇等。"},{"label":"关键行动/事件","value":"组织舆论、筹款、会议和自由派网络，并与德意志进步党等政治力量发生联系。"},{"label":"为什么重要","value":"它说明1850年代后民族自由主义没有消失，而是从革命街垒转向社团和议会政治。"},{"label":"争议/局限","value":"协会依赖普鲁士领导统一，但普鲁士王权和自由派宪政目标并不一致。"},{"label":"出处","value":"Britannica, German National Association；German History in Documents and Images, Nationalverein；Heinrich August Winkler, Germany: The Long Road West。"}],"relationItems":["← 前因：德意志邦联复辟","→ 后果：德意志进步党","↔ 相关：德意志民族主义","↔ 相关：普鲁士“新纪元”"],"relations":[{"text":"← 前因：德意志邦联复辟","id":"extra606"},{"text":"→ 后果：德意志进步党","id":"extra610"},{"text":"↔ 相关：德意志民族主义","id":"extra504"},{"text":"↔ 相关：普鲁士“新纪元”","id":"extra609"}],"source":"history","id":"extra608"},{"title":"普鲁士“新纪元”","level":"B","type":"事件卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1858—1862年","place":"普鲁士王国","summary":"普鲁士“新纪元”短暂放松保守统治，激发自由派对宪政和民族统一的期待。","fields":[{"label":"标题","value":"普鲁士“新纪元”"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1858—1862年"},{"label":"地点","value":"普鲁士王国"},{"label":"主要国家","value":"普鲁士"},{"label":"一句话概括","value":"普鲁士“新纪元”短暂放松保守统治，激发自由派对宪政和民族统一的期待。"},{"label":"参与者","value":"威廉摄政王后来的威廉一世、普鲁士自由派、官僚和议会。"},{"label":"发生了什么","value":"1858年威廉成为摄政后，普鲁士政治气氛较此前宽松，自由派期待政府改革、宪政合作和德意志民族政策转向。"},{"label":"为什么重要","value":"它为德意志民族协会和德意志进步党的兴起提供政治空间，也为后来的军制改革冲突制造期待落差。"},{"label":"前因","value":"1848革命失败后的高压政治逐渐松动，普鲁士中产自由派希望通过王权合作实现改革；威廉摄政让人期待政府摆脱旧保守路线。"},{"label":"后果","value":"自由派壮大，但军制改革预算问题使王权和议会迅速冲突，新纪元以俾斯麦上台告终；合作改革转为宪法冲突。"},{"label":"出处","value":"Britannica, William I；German History in Documents and Images, Prussian New Era；Christopher Clark, Iron Kingdom。"}],"relationItems":["← 前因：德意志邦联复辟","→ 后果：德意志进步党","→ 后果：普鲁士宪法冲突","↔ 相关：德意志民族协会"],"relations":[{"text":"← 前因：德意志邦联复辟","id":"extra606"},{"text":"→ 后果：德意志进步党","id":"extra610"},{"text":"→ 后果：普鲁士宪法冲突","id":"extra539"},{"text":"↔ 相关：德意志民族协会","id":"extra608"}],"source":"history","id":"extra609"},{"title":"德意志进步党","level":"B","type":"组织/机构卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1861—1884年","place":"普鲁士及德意志自由派政治圈","summary":"德意志进步党是普鲁士首个现代自由派政党，反对俾斯麦绕过议会实施军制改革。","fields":[{"label":"标题","value":"德意志进步党"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1861—1884年"},{"label":"地点","value":"普鲁士及德意志自由派政治圈"},{"label":"主要国家","value":"普鲁士；德意志地区"},{"label":"一句话概括","value":"德意志进步党是普鲁士首个现代自由派政党，反对俾斯麦绕过议会实施军制改革。"},{"label":"性质/类型","value":"自由主义政党和议会反对派。"},{"label":"成立/解散时间","value":"1861年成立，1884年并入德意志自由思想党。"},{"label":"核心目标/宗旨","value":"主张宪政、法治、议会预算权、地方自治和小德意志统一。"},{"label":"关键人物（可选）","value":"鲁道夫·菲尔绍、贝内迪克特·瓦尔德克、赫尔曼·舒尔策-德利奇等。"},{"label":"关键行动/事件","value":"在普鲁士众议院反对政府军制改革预算，成为普鲁士宪法冲突中的主要议会力量。"},{"label":"为什么重要","value":"它说明德意志统一前存在强大的自由派宪政路线，而不是只有俾斯麦保守统一。"},{"label":"争议/局限","value":"面对俾斯麦以战争成功完成统一，进步党内部和自由派阵营发生分裂。"},{"label":"出处","value":"Britannica, German Progress Party；German History in Documents and Images, German Progress Party。"}],"relationItems":["← 前因：普鲁士“新纪元”","→ 后果：普鲁士宪法冲突","↔ 相关：俾斯麦宪法冲突策略","↔ 相关：德意志民族协会"],"relations":[{"text":"← 前因：普鲁士“新纪元”","id":"extra609"},{"text":"→ 后果：普鲁士宪法冲突","id":"extra539"},{"text":"↔ 相关：俾斯麦宪法冲突策略","id":"extra611"},{"text":"↔ 相关：德意志民族协会","id":"extra608"}],"source":"history","id":"extra610"},{"title":"俾斯麦宪法冲突策略","level":"B","type":"概念/思潮卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1862—1866年","place":"普鲁士王国","summary":"俾斯麦在宪法冲突中利用“漏洞理论”绕过议会预算权，为军制改革和统一战争赢得时间。","fields":[{"label":"标题","value":"俾斯麦宪法冲突策略"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1862—1866年"},{"label":"地点","value":"普鲁士王国"},{"label":"主要国家","value":"普鲁士；德意志地区"},{"label":"一句话概括","value":"俾斯麦在宪法冲突中利用“漏洞理论”绕过议会预算权，为军制改革和统一战争赢得时间。"},{"label":"核心主张/思路","value":"当国王、上院和下院在预算上僵持而宪法没有明确解决机制时，政府可继续按旧预算征税和支出。"},{"label":"提出者/代表人物（可选）","value":"奥托·冯·俾斯麦及保守法学支持者。"},{"label":"它从何而来","value":"普鲁士宪法没有清楚规定预算僵局时政府是否必须停摆，俾斯麦把这一空白解释为王权优势。"},{"label":"典型表现","value":"政府在没有众议院批准新军费预算的情况下继续推进军制改革，并压制议会反对。"},{"label":"为什么重要","value":"它让普鲁士王权在宪法框架内实质绕过议会，保证普鲁士在1864、1866、1870战争中的军事能力。"},{"label":"争议/局限","value":"策略明显削弱议会预算权，统一成功后才通过赔偿法案获得政治追认。"},{"label":"出处","value":"Britannica, Otto von Bismarck；German History in Documents and Images, Prussian Constitutional Conflict；Christopher Clark, Iron Kingdom。"}],"relationItems":["← 前因：普鲁士宪法冲突","↔ 相关：俾斯麦“铁血演说”","→ 后果：普鲁士俾斯麦赔偿法案","↔ 相关：德意志进步党"],"relations":[{"text":"← 前因：普鲁士宪法冲突","id":"extra539"},{"text":"↔ 相关：俾斯麦“铁血演说”","id":"extra540"},{"text":"→ 后果：普鲁士俾斯麦赔偿法案","id":"extra545"},{"text":"↔ 相关：德意志进步党","id":"extra610"}],"source":"history","id":"extra611"},{"title":"1863年法兰克福诸侯大会","level":"B","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1863年8—9月","place":"法兰克福","summary":"1863年法兰克福诸侯大会是奥地利改革德意志邦联的最后重要尝试，因普鲁士抵制而失败。","fields":[{"label":"标题","value":"1863年法兰克福诸侯大会"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1863年8—9月"},{"label":"地点","value":"法兰克福"},{"label":"主要国家","value":"奥地利；普鲁士；德意志地区"},{"label":"一句话概括","value":"1863年法兰克福诸侯大会是奥地利改革德意志邦联的最后重要尝试，因普鲁士抵制而失败。"},{"label":"参与者","value":"奥地利皇帝弗朗茨·约瑟夫、德意志诸侯、普鲁士国王威廉一世、俾斯麦。"},{"label":"发生了什么","value":"奥地利召集德意志诸侯在法兰克福讨论邦联改革方案，试图在奥地利领导下改造德意志邦联。普鲁士在俾斯麦影响下拒绝参加，使会议缺乏关键大国支持。"},{"label":"为什么重要","value":"它显示奥地利仍试图通过邦联制度保住德意志领导权，但普鲁士已不愿在奥地利框架内解决德意志统一与奥普领导权问题。"},{"label":"前因","value":"1850年代后德意志改革呼声上升，奥地利希望用制度改革回应民族压力并限制普鲁士；普鲁士则不愿接受奥地利主持的邦联改造。"},{"label":"后果","value":"邦联改革失败，奥普矛盾继续加深，石勒苏益-荷尔斯泰因问题很快成为双方合作和冲突的试金石；奥地利失去一次和平主导改革的机会。"},{"label":"出处","value":"Britannica, German Confederation；German History in Documents and Images, Frankfurt Princes Congress 1863；Otto Pflanze, Bismarck and the Development of Germany。"}],"relationItems":["← 前因：奥地利与普鲁士二元主义","→ 后果：石勒苏益-荷尔斯泰因问题","↔ 相关：俾斯麦出任普鲁士首相","↔ 相关：普奥战争"],"relations":[{"text":"← 前因：奥地利与普鲁士二元主义","id":"extra535"},{"text":"→ 后果：石勒苏益-荷尔斯泰因问题","id":"extra541"},{"text":"↔ 相关：俾斯麦出任普鲁士首相","id":"extra493"},{"text":"↔ 相关：普奥战争","id":"extra495"}],"source":"history","id":"extra612"},{"title":"加施泰因后的普奥外交破裂","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1865—1866年","place":"石勒苏益、荷尔斯泰因、柏林、维也纳和法兰克福","summary":"普奥《加施泰因协定》后，普鲁士与奥地利围绕荷尔斯泰因管理和邦联权威迅速走向决裂。","fields":[{"label":"标题","value":"加施泰因后的普奥外交破裂"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1865—1866年"},{"label":"地点","value":"石勒苏益、荷尔斯泰因、柏林、维也纳和法兰克福"},{"label":"主要国家","value":"普鲁士；奥地利；德意志地区"},{"label":"一句话概括","value":"普奥《加施泰因协定》后，普鲁士与奥地利围绕荷尔斯泰因管理和邦联权威迅速走向决裂。"},{"label":"参与者","value":"俾斯麦、奥地利政府、普鲁士政府、德意志邦联、石勒苏益-荷尔斯泰因地方力量。"},{"label":"发生了什么","value":"1865年普奥《加施泰因协定》把石勒苏益交普鲁士管理、荷尔斯泰因交奥地利管理。俾斯麦随后利用荷尔斯泰因和邦联程序制造争端，奥地利把问题提交邦联，普鲁士则宣布邦联秩序被破坏。"},{"label":"为什么重要","value":"它把1864年普奥合作转化为1866年普奥战争的直接外交前奏。"},{"label":"前因","value":"普鲁士和奥地利共同击败丹麦后，并未真正同意两公国长期归属；俾斯麦希望把问题变成排除奥地利的机会。"},{"label":"后果","value":"普鲁士提出邦联改革并准备战争，奥地利寻求邦联支持，德意志统一与奥普领导权问题进入军事决断；石勒苏益-荷尔斯泰因行政争议被升级为普奥摊牌。"},{"label":"出处","value":"Britannica, Austro-Prussian War；German History in Documents and Images, Gastein Convention and crisis。"}],"relationItems":["← 前因：普奥《加施泰因协定》","→ 后果：普奥战争","↔ 相关：石勒苏益-荷尔斯泰因问题","↔ 相关：俾斯麦宪法冲突策略"],"relations":[{"text":"← 前因：普奥《加施泰因协定》","id":"extra542"},{"text":"→ 后果：普奥战争","id":"extra495"},{"text":"↔ 相关：石勒苏益-荷尔斯泰因问题","id":"extra541"},{"text":"↔ 相关：俾斯麦宪法冲突策略","id":"extra611"}],"source":"history","id":"extra613"},{"title":"南德四国与普鲁士秘密军事同盟","level":"B","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1866年8月以后","place":"普鲁士、巴伐利亚、符腾堡、巴登、黑森-达姆施塔特","summary":"1866年后南德四国与普鲁士签署秘密军事同盟，为1870年共同对法作战奠定基础。","fields":[{"label":"标题","value":"南德四国与普鲁士秘密军事同盟"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1866年8月以后"},{"label":"地点","value":"普鲁士、巴伐利亚、符腾堡、巴登、黑森-达姆施塔特"},{"label":"主要国家","value":"普鲁士；巴伐利亚；符腾堡；巴登；黑森"},{"label":"一句话概括","value":"1866年后南德四国与普鲁士签署秘密军事同盟，为1870年共同对法作战奠定基础。"},{"label":"制定方/签署方","value":"普鲁士与巴伐利亚、符腾堡、巴登、黑森-达姆施塔特等南德邦国。"},{"label":"主要内容","value":"南德邦国在遭受外部攻击时与普鲁士共同防御，战时军队由普鲁士国王统帅，条约最初保密。"},{"label":"它试图解决什么问题","value":"普鲁士在1866年后暂时没有直接吞并南德，但需要把南德纳入自己的军事安全体系。"},{"label":"为什么重要","value":"它解释为什么1870年普法战争爆发后南德诸邦会站到普鲁士一边，而不是保持完全中立。"},{"label":"争议/局限","value":"同盟没有立即实现政治统一，南德内部仍有反普鲁士、天主教和地方主义力量。"},{"label":"造成的影响","value":"南德军事上被纳入普鲁士体系，普法战争中的共同作战为德意志帝国成立创造条件。"},{"label":"出处","value":"Britannica, North German Confederation；German History in Documents and Images, Secret military treaties with South German states。"}],"relationItems":["← 前因：布拉格和约（1866）","→ 后果：南德诸邦加入德意志帝国","↔ 相关：普法战争","↔ 相关：普鲁士主导的北德意志邦联"],"relations":[{"text":"← 前因：布拉格和约（1866）","id":"extra544"},{"text":"→ 后果：南德诸邦加入德意志帝国","id":"extra550"},{"text":"↔ 相关：普法战争","id":"extra497"},{"text":"↔ 相关：普鲁士主导的北德意志邦联","id":"extra496"}],"source":"history","id":"extra614"},{"title":"北德意志邦联议会","level":"B","type":"组织/机构卡","tags":["政治与制度"],"mainTag":"政治与制度","subTag":"","timeText":"1867—1871年","place":"柏林","summary":"北德意志邦联议会由普选男性选出，是帝国议会制度的直接前身。","fields":[{"label":"标题","value":"北德意志邦联议会"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"时间","value":"1867—1871年"},{"label":"地点","value":"柏林"},{"label":"主要国家","value":"北德意志邦联；普鲁士；德意志地区"},{"label":"一句话概括","value":"北德意志邦联议会由普选男性选出，是帝国议会制度的直接前身。"},{"label":"性质/类型","value":"北德意志邦联民选立法机构。"},{"label":"成立/解散时间","value":"1867年成立，1871年德意志帝国建立后转为帝国议会传统。"},{"label":"核心目标/宗旨","value":"与联邦参议院共同立法，批准预算和法律，代表北德意志成年男性选民。"},{"label":"关键人物（可选）","value":"爱德华·冯·西姆森、民族自由党议员、进步党议员、俾斯麦。"},{"label":"关键行动/事件","value":"审议北德意志邦联宪法，推动统一邮政、度量衡、法律和经济制度。"},{"label":"为什么重要","value":"它把普鲁士主导的统一与普选代表制结合起来，成为1871年帝国议会的模型。"},{"label":"争议/局限","value":"议会不能决定政府去留，首相只对普鲁士国王兼联邦主席负责。"},{"label":"出处","value":"Britannica, North German Confederation；German History in Documents and Images, North German Reichstag；North German Constitution。"}],"relationItems":["← 前因：北德意志邦联宪法","↔ 相关：北德意志邦联联邦参议院","→ 后果：德意志帝国议会","↔ 相关：北德意志关税议会（Zollparlament）"],"relations":[{"text":"← 前因：北德意志邦联宪法","id":"extra546"},{"text":"↔ 相关：北德意志邦联联邦参议院","id":"extra616"},{"text":"→ 后果：德意志帝国议会","id":"extra669"},{"text":"↔ 相关：北德意志关税议会（Zollparlament）","id":"extra617"}],"source":"history","id":"extra615"},{"title":"北德意志邦联联邦参议院","level":"B","type":"组织/机构卡","tags":["政治与制度"],"mainTag":"政治与制度","subTag":"","timeText":"1867—1871年","place":"柏林","summary":"北德意志邦联联邦参议院代表各邦政府，是后来德意志帝国联邦参议院的制度蓝本。","fields":[{"label":"标题","value":"北德意志邦联联邦参议院"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"时间","value":"1867—1871年"},{"label":"地点","value":"柏林"},{"label":"主要国家","value":"北德意志邦联；普鲁士；德意志地区"},{"label":"一句话概括","value":"北德意志邦联联邦参议院代表各邦政府，是后来德意志帝国联邦参议院的制度蓝本。"},{"label":"性质/类型","value":"北德意志邦联成员邦政府代表机关。"},{"label":"成立/解散时间","value":"1867年随北德意志邦联成立，1871年帝国建立后延续为帝国联邦参议院。"},{"label":"核心目标/宗旨","value":"代表各邦政府参与联邦立法和行政监督，维持邦国在普鲁士主导统一中的正式地位。"},{"label":"关键人物（可选）","value":"普鲁士代表、各邦政府代表、俾斯麦作为联邦首相主持相关运作。"},{"label":"关键行动/事件","value":"与邦联议会共同通过法律，并在联邦制度中保留邦国政府权力。"},{"label":"为什么重要","value":"它显示俾斯麦统一不是单一中央国家，而是把邦国政府纳入联邦机关来降低阻力。"},{"label":"争议/局限","value":"普鲁士票数和政治力量占优势，中小邦国代表权难以真正制衡普鲁士。"},{"label":"出处","value":"Britannica, North German Confederation；German History in Documents and Images, Bundesrat of the North German Confederation；North German Constitution。"}],"relationItems":["← 前因：北德意志邦联宪法","↔ 相关：北德意志邦联议会","→ 后果：德意志帝国联邦参议院","↔ 相关：南德诸邦加入德意志帝国"],"relations":[{"text":"← 前因：北德意志邦联宪法","id":"extra546"},{"text":"↔ 相关：北德意志邦联议会","id":"extra615"},{"text":"→ 后果：德意志帝国联邦参议院","id":"extra670"},{"text":"↔ 相关：南德诸邦加入德意志帝国","id":"extra550"}],"source":"history","id":"extra616"},{"title":"北德意志关税议会（Zollparlament）","level":"C","type":"组织/机构卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1868—1870年","place":"柏林及德意志关税同盟政治空间","summary":"关税议会把南德代表纳入关税同盟立法，却未能立刻促成政治统一。","fields":[{"label":"标题","value":"北德意志关税议会（Zollparlament）"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1868—1870年"},{"label":"地点","value":"柏林及德意志关税同盟政治空间"},{"label":"主要国家","value":"北德意志邦联；巴伐利亚；符腾堡；巴登；黑森"},{"label":"一句话概括","value":"关税议会把南德代表纳入关税同盟立法，却未能立刻促成政治统一。"},{"label":"性质/类型","value":"德意志关税同盟层面的议会机构。"},{"label":"成立/解散时间","value":"1868年首次选举后运作，1871年帝国成立后失去独立意义。"},{"label":"核心目标/宗旨","value":"处理关税同盟事务，让北德意志邦联议会成员与南德选出的代表共同参与经济立法。"},{"label":"关键人物（可选）","value":"北德意志邦联议员、南德各邦代表、俾斯麦和民族自由派。"},{"label":"关键行动/事件","value":"1868年南德地区选举代表进入关税议会，但许多南德选民支持反普鲁士或地方主义力量。"},{"label":"为什么重要","value":"它显示经济统一和政治统一并不自动等同，南德加入帝国仍需要普法战争的政治军事动员。"},{"label":"争议/局限","value":"南德代表常反对普鲁士领导，关税议会未能成为和平统一的直接工具。"},{"label":"出处","value":"Britannica, Zollverein；German History in Documents and Images, Zollparlament；North German Confederation sources。"}],"relationItems":["← 前因：德意志关税同盟（Zollverein）","↔ 相关：北德意志邦联议会","→ 后果：南德诸邦加入德意志帝国","↔ 相关：普法战争"],"relations":[{"text":"← 前因：德意志关税同盟（Zollverein）","id":"extra486"},{"text":"↔ 相关：北德意志邦联议会","id":"extra615"},{"text":"→ 后果：南德诸邦加入德意志帝国","id":"extra550"},{"text":"↔ 相关：普法战争","id":"extra497"}],"source":"history","id":"extra617"},{"title":"普法战争中的南德民族动员","level":"B","type":"事件卡","tags":["战争与外交","文化与思想"],"mainTag":"战争与外交","subTag":"文化与思想","timeText":"1870—1871年","place":"巴伐利亚、符腾堡、巴登、黑森及法德战场","summary":"普法战争中南德邦国站到普鲁士一边，民族战争氛围推动德意志最终统一。","fields":[{"label":"标题","value":"普法战争中的南德民族动员"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1870—1871年"},{"label":"地点","value":"巴伐利亚、符腾堡、巴登、黑森及法德战场"},{"label":"主要国家","value":"普鲁士；巴伐利亚；符腾堡；巴登；法国"},{"label":"一句话概括","value":"普法战争中南德邦国站到普鲁士一边，民族战争氛围推动德意志最终统一。"},{"label":"参与者","value":"普鲁士、南德四邦、法国第二帝国、德意志公众舆论。"},{"label":"发生了什么","value":"1870年普法战争爆发后，南德邦国依据秘密军事同盟和反法民族情绪加入普鲁士阵营。南德军队与北德意志邦联共同作战，战争胜利强化统一诉求。"},{"label":"为什么重要","value":"它是南德加入德意志帝国的政治心理和军事前提。没有共同对法战争，南德地方主义和天主教保留势力更难被压过。"},{"label":"前因","value":"1866年后南德与普鲁士已有秘密军事同盟，但政治统一仍受地方主义、天主教保留力量和反普情绪制约；对法战争改变了政治气氛。"},{"label":"后果","value":"南德诸邦与北德意志邦联谈判加入新帝国，1871年德意志帝国在战争胜利中建立；军事同盟被转化为政治统一。"},{"label":"出处","value":"Britannica, Franco-German War；Britannica, German Empire；German History in Documents and Images, South German states and unification。"}],"relationItems":["← 前因：南德四国与普鲁士秘密军事同盟","→ 后果：南德诸邦加入德意志帝国","↔ 相关：普法战争","↔ 相关：德意志帝国成立"],"relations":[{"text":"← 前因：南德四国与普鲁士秘密军事同盟","id":"extra614"},{"text":"→ 后果：南德诸邦加入德意志帝国","id":"extra550"},{"text":"↔ 相关：普法战争","id":"extra497"},{"text":"↔ 相关：德意志帝国成立","id":"extra621"}],"source":"history","id":"extra618"},{"title":"凡尔赛镜厅德意志帝国宣告","level":"B","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1871年1月18日","place":"法国凡尔赛宫镜厅","summary":"1871年德意志帝国在凡尔赛镜厅宣告成立，把统一与对法胜利绑定成强烈政治象征。","fields":[{"label":"标题","value":"凡尔赛镜厅德意志帝国宣告"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1871年1月18日"},{"label":"地点","value":"法国凡尔赛宫镜厅"},{"label":"主要国家","value":"普鲁士；德意志地区；法国"},{"label":"一句话概括","value":"1871年德意志帝国在凡尔赛镜厅宣告成立，把统一与对法胜利绑定成强烈政治象征。"},{"label":"参与者","value":"普鲁士国王威廉一世、俾斯麦、德意志诸侯和军队代表、北德意志邦联与南德邦国。"},{"label":"发生了什么","value":"普法战争期间，德意志诸邦代表在凡尔赛宫镜厅宣布普鲁士国王威廉一世为德意志皇帝。仪式发生在法国王权象征空间内，具有明确的胜利和权力展示意味。"},{"label":"为什么重要","value":"它不仅是国家成立仪式，也是德意志统一政治文化的象征：统一通过战争、王朝协议和普鲁士领导实现。"},{"label":"前因","value":"普法战争胜利和南德邦国加入谈判完成，北德意志邦联宪制被扩展为德意志帝国；俾斯麦选择凡尔赛作为仪式场所强化胜利象征。"},{"label":"后果","value":"德意志帝国正式进入欧洲大国体系，法国对凡尔赛屈辱的记忆也成为法德关系长期阴影；统一从一开始就带有强烈军事胜利色彩。"},{"label":"出处","value":"Britannica, German Empire；Britannica, Franco-German War；German History in Documents and Images, Proclamation of the German Empire。"}],"relationItems":["← 前因：南德诸邦加入德意志帝国","↔ 相关：德意志帝国成立","↔ 相关：普法战争《法兰克福和约》","→ 后果：阿尔萨斯-洛林问题的形成"],"relations":[{"text":"← 前因：南德诸邦加入德意志帝国","id":"extra550"},{"text":"↔ 相关：德意志帝国成立","id":"extra621"},{"text":"↔ 相关：普法战争《法兰克福和约》","id":"extra551"},{"text":"→ 后果：阿尔萨斯-洛林问题的形成","id":"extra620"}],"source":"history","id":"extra619"},{"title":"阿尔萨斯-洛林问题的形成","level":"B","type":"事件卡","tags":["战争与外交","文化与思想"],"mainTag":"战争与外交","subTag":"文化与思想","timeText":"1871年","place":"阿尔萨斯和洛林部分地区","summary":"阿尔萨斯-洛林并入德意志帝国后成为法德敌意核心问题之一。","fields":[{"label":"标题","value":"阿尔萨斯-洛林问题的形成"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1871年"},{"label":"地点","value":"阿尔萨斯和洛林部分地区"},{"label":"主要国家","value":"德意志帝国；法国"},{"label":"一句话概括","value":"阿尔萨斯-洛林并入德意志帝国后成为法德敌意核心问题之一。"},{"label":"参与者","value":"德意志帝国、法国第三共和国、阿尔萨斯和洛林当地居民。"},{"label":"发生了什么","value":"普法战争后，普法战争《法兰克福和约》规定法国割让阿尔萨斯大部和洛林部分地区给德意志帝国。新帝国把该地作为帝国直属领地管理，法国舆论则把失地视为民族屈辱。"},{"label":"为什么重要","value":"它把1871年德国统一和德法复仇主义直接连接起来，是此后法德关系和欧洲安全格局的重要矛盾。"},{"label":"前因","value":"德国军方和民族主义者认为该地区具有战略和历史价值，普法战争胜利给德国提出割地要求的机会；法国战败使其无法拒绝。"},{"label":"后果","value":"法国“复仇”情绪长期存在，阿尔萨斯-洛林成为一战前欧洲民族和边界政治的敏感核心；德国新帝国也背负长期安全和认同问题。"},{"label":"出处","value":"Britannica, Alsace-Lorraine；Britannica, Treaty of Frankfurt；Britannica, Franco-German War。"}],"relationItems":["← 前因：普法战争《法兰克福和约》","↔ 相关：阿尔萨斯-洛林并入德意志帝国","↔ 相关：凡尔赛镜厅德意志帝国宣告","↔ 同时期参考：法国第三共和国"],"relations":[{"text":"← 前因：普法战争《法兰克福和约》","id":"extra551"},{"text":"↔ 相关：阿尔萨斯-洛林并入德意志帝国","id":"extra745"},{"text":"↔ 相关：凡尔赛镜厅德意志帝国宣告","id":"extra619"}],"source":"history","id":"extra620"},{"title":"奥地利的德意志领导权诉求","level":"B","type":"概念/思潮卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1815—1866年","place":"德意志邦联、奥地利帝国、普鲁士","summary":"奥地利长期试图维持自己在德意志邦联中的传统领导地位，并阻止普鲁士主导统一。","fields":[{"label":"标题","value":"奥地利的德意志领导权诉求"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1815—1866年"},{"label":"地点","value":"德意志邦联、奥地利帝国、普鲁士"},{"label":"主要国家","value":"奥地利；普鲁士；德意志诸邦"},{"label":"一句话概括","value":"奥地利长期试图维持自己在德意志邦联中的传统领导地位，并阻止普鲁士主导统一。"},{"label":"核心主张/思路","value":"奥地利认为德意志秩序应维持在邦联和王朝均势框架内，由哈布斯堡君主国凭借历史威望、联邦议会地位和外交网络保持领导权。"},{"label":"提出者/代表人物（可选）","value":"克莱门斯·冯·梅特涅；弗朗茨·约瑟夫一世；奥地利保守外交集团。"},{"label":"它从何而来","value":"神圣罗马帝国传统、维也纳会议安排、奥地利在中欧的王朝地位，以及对普鲁士扩张和民族统一运动的警惕共同塑造了这种诉求。"},{"label":"典型表现","value":"奥地利主导德意志邦联议会，反对普鲁士单方面重组德意志；在奥尔米茨危机中迫使普鲁士退让；1863年试图通过法兰克福诸侯大会改革邦联。"},{"label":"为什么重要","value":"它是理解德意志统一与奥普领导权问题的关键背景。普鲁士统一道路并不是自然胜出，而是在与奥地利领导权竞争中通过外交、军事和制度吸附逐渐取得优势。"},{"label":"争议/局限","value":"奥地利多民族帝国难以把全部领土纳入民族国家式德意志统一；若只纳入德意志部分，又会削弱哈布斯堡帝国整体结构。"},{"label":"出处","value":"Encyclopaedia Britannica: German Confederation；German History in Documents and Images: German Unification materials；DHM/LeMO: Deutscher Bund。"}],"relationItems":["← 前因：拿破仑战后维也纳会议","↔ 相关：德意志邦联","↔ 相关：奥地利与普鲁士二元主义","→ 后果：普奥战争","✗ 对立/冲突：普鲁士主导的北德意志邦联"],"relations":[{"text":"← 前因：拿破仑战后维也纳会议","id":"extra525"},{"text":"↔ 相关：德意志邦联","id":"extra487"},{"text":"↔ 相关：奥地利与普鲁士二元主义","id":"extra535"},{"text":"→ 后果：普奥战争","id":"extra495"},{"text":"✗ 对立/冲突：普鲁士主导的北德意志邦联","id":"extra496"}],"source":"history","id":"extra909"},{"title":"拿破仑入侵俄国（1812）","level":"A","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1812年6月—12月","place":"俄罗斯帝国；从涅曼河到莫斯科及撤退路线","summary":"拿破仑远征俄国以灾难性撤退告终，摧毁其欧洲霸权基础并引发第六次反法同盟。","fields":[{"label":"标题","value":"拿破仑入侵俄国（1812）"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1812年6月—12月"},{"label":"地点","value":"俄罗斯帝国；从涅曼河到莫斯科及撤退路线"},{"label":"主要国家","value":"法国；俄罗斯；普鲁士；奥地利；莱茵邦诸邦"},{"label":"一句话概括","value":"拿破仑远征俄国以灾难性撤退告终，摧毁其欧洲霸权基础并引发第六次反法同盟。"},{"label":"参与者","value":"拿破仑一世、俄罗斯沙皇亚历山大一世、法国大军团、俄罗斯军队、法国附庸和同盟国部队。"},{"label":"发生了什么","value":"拿破仑为迫使俄国遵守大陆封锁并重新服从法国体系，率多民族大军越过涅曼河进入俄国。俄军避免决定性会战并采取撤退、消耗和焦土策略，法军虽进入莫斯科，却无法迫使俄国求和。冬季、补给崩溃、疾病、游击袭扰和俄军追击使法军撤退变成灾难。"},{"label":"为什么重要","value":"它使拿破仑体系的不可战胜神话破裂，也给普鲁士、奥地利等力量重新加入反法阵营创造条件。德意志解放战争和莱比锡战役都与这次失败直接相关。"},{"label":"前因","value":"大陆封锁体系与俄国经济利益冲突，法俄关系恶化；拿破仑试图用军事胜利重新压住俄罗斯。"},{"label":"后果","value":"法国大军团元气大伤，普俄接近，约克《陶罗根协定》和普俄《卡利什条约》相继出现，第六次反法同盟战争爆发。"},{"label":"出处","value":"Encyclopaedia Britannica: Napoleon I；Encyclopaedia Britannica: Napoleonic Wars；DHM/LeMO: Befreiungskriege。"}],"relationItems":["← 前因：拿破仑大陆封锁体系","→ 后果：普鲁士约克《陶罗根协定》","→ 后果：普俄《卡利什条约》","→ 后果：第六次反法同盟战争","↔ 相关：德意志反法民族动员"],"relations":[{"text":"← 前因：拿破仑大陆封锁体系","id":"extra563"},{"text":"→ 后果：普鲁士约克《陶罗根协定》","id":"extra581"},{"text":"→ 后果：普俄《卡利什条约》","id":"extra582"},{"text":"→ 后果：第六次反法同盟战争","id":"extra584"},{"text":"↔ 相关：德意志反法民族动员","id":"extra588"}],"source":"history","id":"extra910"},{"title":"卡尔·马克思","level":"B","type":"人物卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1818—1883年","place":"德意志地区、法国、比利时、英国","summary":"卡尔·马克思把资本主义批判、阶级斗争理论和社会主义政治运动连接成现代思想史核心传统。","fields":[{"label":"标题","value":"卡尔·马克思"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1818—1883年"},{"label":"地点","value":"德意志地区、法国、比利时、英国"},{"label":"主要国家","value":"德国；英国；法国；比利时"},{"label":"一句话概括","value":"卡尔·马克思把资本主义批判、阶级斗争理论和社会主义政治运动连接成现代思想史核心传统。"},{"label":"生卒年/活跃年代","value":"1818—1883年；19世纪中后期活跃。"},{"label":"身份/职务","value":"哲学家、经济学批判者、记者、革命活动家、国际工人协会重要人物。"},{"label":"关键贡献/作为","value":"与弗里德里希·恩格斯合写《共产党宣言》，撰写《资本论》第一卷，参与1848革命和国际工人运动。"},{"label":"核心主张/立场","value":"认为资本主义生产方式包含阶级剥削、危机和历史变动，工人阶级政治组织是社会变革的关键力量。"},{"label":"为什么重要","value":"他的思想深刻影响社会主义、工人运动、社会科学和20世纪政治革命。德国社会民主党和后来的共产主义运动都无法脱离马克思传统理解。"},{"label":"争议/评价","value":"马克思理论影响巨大，但不同政治运动对其解释差异极大；其历史预测、革命理论和国家问题长期存在争议。"},{"label":"关联事件（可选）","value":"1848年欧洲革命；德国社会主义爱森纳赫派；德国社会民主党（SPD）。"},{"label":"出处","value":"Encyclopaedia Britannica: Karl Marx；Marxists Internet Archive: Marx/Engels biographical materials；German History in Documents and Images: Socialist movement materials。"}],"relationItems":["↔ 相关：马克思恩格斯《共产党宣言》","↔ 相关：马克思恩格斯《德意志意识形态》","↔ 相关：《资本论》第一卷","↔ 相关：弗里德里希·恩格斯","→ 后果：德国社会民主党（SPD）"],"relations":[{"text":"↔ 相关：马克思恩格斯《共产党宣言》","id":"extra61"},{"text":"↔ 相关：马克思恩格斯《德意志意识形态》","id":"extra82"},{"text":"↔ 相关：《资本论》第一卷","id":"extra83"},{"text":"↔ 相关：弗里德里希·恩格斯","id":"extra912"},{"text":"→ 后果：德国社会民主党（SPD）","id":"extra628"}],"source":"history","id":"extra911"},{"title":"弗里德里希·恩格斯","level":"B","type":"人物卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1820—1895年","place":"德意志地区、英国、欧洲工人运动网络","summary":"恩格斯既是马克思最重要合作者，也是把工业社会观察、社会主义理论和工人运动连接起来的关键人物。","fields":[{"label":"标题","value":"弗里德里希·恩格斯"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1820—1895年"},{"label":"地点","value":"德意志地区、英国、欧洲工人运动网络"},{"label":"主要国家","value":"德国；英国"},{"label":"一句话概括","value":"恩格斯既是马克思最重要合作者，也是把工业社会观察、社会主义理论和工人运动连接起来的关键人物。"},{"label":"生卒年/活跃年代","value":"1820—1895年；19世纪中后期活跃。"},{"label":"身份/职务","value":"思想家、企业家家庭出身的社会批判者、革命活动家、马克思合作者。"},{"label":"关键贡献/作为","value":"撰写《英国工人阶级状况》，与马克思合写《共产党宣言》和《德意志意识形态》，在马克思去世后整理出版《资本论》后续卷。"},{"label":"核心主张/立场","value":"批判资本主义工业社会中的阶级压迫，支持社会主义工人运动，并强调历史发展与生产关系的联系。"},{"label":"为什么重要","value":"恩格斯的工业社会观察和组织支持使马克思主义从思想文本进入跨国工人运动。他也是德国社会主义传统形成的重要背景人物。"},{"label":"争议/评价","value":"恩格斯对马克思遗稿的整理和对理论的系统化影响深远，也引发后来关于“恩格斯化马克思”的学术争论。"},{"label":"关联事件（可选）","value":"德国工人阶级形成；社会主义第二国际；德国社会民主党（SPD）。"},{"label":"出处","value":"Encyclopaedia Britannica: Friedrich Engels；Marxists Internet Archive: Engels biography；German History in Documents and Images: Socialist movement materials。"}],"relationItems":["↔ 相关：卡尔·马克思","↔ 相关：马克思恩格斯《共产党宣言》","↔ 相关：马克思恩格斯《德意志意识形态》","→ 后果：德国社会民主党（SPD）"],"relations":[{"text":"↔ 相关：卡尔·马克思","id":"extra911"},{"text":"↔ 相关：马克思恩格斯《共产党宣言》","id":"extra61"},{"text":"↔ 相关：马克思恩格斯《德意志意识形态》","id":"extra82"},{"text":"→ 后果：德国社会民主党（SPD）","id":"extra628"}],"source":"history","id":"extra912"},{"title":"法国第二帝国","level":"B","type":"组织/机构卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1852—1870年","place":"法国及欧洲外交体系","summary":"法国第二帝国是拿破仑三世建立的威权现代化政权，也是普法战争前欧洲外交核心力量。","fields":[{"label":"标题","value":"法国第二帝国"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1852—1870年"},{"label":"地点","value":"法国及欧洲外交体系"},{"label":"主要国家","value":"法国；普鲁士；意大利；奥地利；英国"},{"label":"一句话概括","value":"法国第二帝国是拿破仑三世建立的威权现代化政权，也是普法战争前欧洲外交核心力量。"},{"label":"性质/类型","value":"法国威权帝国政体，后期逐渐自由化。"},{"label":"成立/解散时间","value":"1852年路易-拿破仑建立帝国；1870年普法战争失败后崩溃。"},{"label":"核心目标/宗旨","value":"恢复法国大国地位，推动经济现代化和巴黎改造，同时在欧洲事务中维护法国影响力。"},{"label":"关键人物（可选）","value":"拿破仑三世、奥斯曼男爵、法国外交和军事精英。"},{"label":"关键行动/事件","value":"参与克里米亚战争，支持意大利统一部分进程，介入墨西哥，长期试图在德意志事务中取得补偿或影响。普法战争失败后，拿破仑三世被俘，第二帝国崩溃。"},{"label":"为什么重要","value":"法国第二帝国是普法战争的直接对手。它的崩溃不仅促成德意志帝国成立，也让法国第三共和国和德法复仇主义成为欧洲政治长期变量。"},{"label":"争议/局限","value":"第二帝国兼具现代化和威权特征，不能只看成拿破仑式冒险政权。"},{"label":"出处","value":"Encyclopaedia Britannica: Second Empire；Encyclopaedia Britannica: Napoleon III；DHM/LeMO: Deutsch-Französischer Krieg。"}],"relationItems":["← 前因：1848年欧洲革命","↔ 相关：霍亨索伦西班牙王位候选危机","→ 后果：普法战争","→ 后果：德意志帝国成立","→ 后果：德法复仇主义"],"relations":[{"text":"← 前因：1848年欧洲革命","id":"extra530"},{"text":"↔ 相关：霍亨索伦西班牙王位候选危机","id":"extra547"},{"text":"→ 后果：普法战争","id":"extra497"},{"text":"→ 后果：德意志帝国成立","id":"extra621"},{"text":"→ 后果：德法复仇主义","id":"extra945"}],"source":"history","id":"extra913"},{"title":"德意志统一中的普鲁士优势","level":"B","type":"概念/思潮卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1830年代—1871年","place":"德意志邦联、普鲁士、北德意志地区","summary":"普鲁士在经济、军事和制度吸附力上的优势，使其逐渐压过奥地利并主导德意志统一。","fields":[{"label":"标题","value":"德意志统一中的普鲁士优势"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1830年代—1871年"},{"label":"地点","value":"德意志邦联、普鲁士、北德意志地区"},{"label":"主要国家","value":"普鲁士；奥地利；德意志诸邦"},{"label":"一句话概括","value":"普鲁士在经济、军事和制度吸附力上的优势，使其逐渐压过奥地利并主导德意志统一。"},{"label":"核心主张/思路","value":"普鲁士通过关税同盟、铁路、军制改革、总参谋部、工业基础和小德意志方案，积累统一竞争中的结构性优势。"},{"label":"提出者/代表人物（可选）","value":"普鲁士官僚、军方、俾斯麦、罗恩、老毛奇、经济民族主义者。"},{"label":"它从何而来","value":"德意志关税同盟排除奥地利，鲁尔和莱茵工业区增强普鲁士经济，军制改革提高作战能力。"},{"label":"典型表现","value":"关税同盟、普鲁士军制改革、普奥战争克尼格雷茨战役、北德意志邦联建立。"},{"label":"为什么重要","value":"这张卡解释为什么德意志统一最后不是奥地利主导，而是普鲁士主导。统一结果来自长期制度和能力差异，而不是单一战争偶然。"},{"label":"争议/局限","value":"普鲁士优势并非早已注定，1848革命失败、奥尔米茨屈辱和中小邦国自主都说明过程充满不确定。"},{"label":"出处","value":"German History in Documents and Images: German unification；DHM/LeMO: Reichsgründung；Encyclopaedia Britannica: German Empire。"}],"relationItems":["← 前因：德意志关税同盟（Zollverein）","↔ 相关：普鲁士军制改革","↔ 相关：奥地利的德意志领导权诉求","→ 后果：普奥战争","→ 后果：普鲁士主导的北德意志邦联"],"relations":[{"text":"← 前因：德意志关税同盟（Zollverein）","id":"extra486"},{"text":"↔ 相关：普鲁士军制改革","id":"extra536"},{"text":"↔ 相关：奥地利的德意志领导权诉求","id":"extra909"},{"text":"→ 后果：普奥战争","id":"extra495"},{"text":"→ 后果：普鲁士主导的北德意志邦联","id":"extra496"}],"source":"history","id":"extra914"},{"title":"议会预算权","level":"C","type":"概念/思潮卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"19世纪宪政政治中长期存在","place":"欧洲宪政国家，德意志邦国和普鲁士尤为相关","summary":"议会预算权是现代宪政中议会控制政府财政和军费的核心工具。","fields":[{"label":"标题","value":"议会预算权"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"19世纪宪政政治中长期存在"},{"label":"地点","value":"欧洲宪政国家，德意志邦国和普鲁士尤为相关"},{"label":"主要国家","value":"普鲁士；德国；英国；法国"},{"label":"一句话概括","value":"议会预算权是现代宪政中议会控制政府财政和军费的核心工具。"},{"label":"核心主张/思路","value":"政府征税和支出必须经过代表机构批准，尤其军费和长期财政承诺应受议会审议。"},{"label":"提出者/代表人物（可选）","value":"自由主义议员、宪政法学家、纳税人政治运动。"},{"label":"它从何而来","value":"近代国家财政扩张、代议制发展和“无代表不纳税”原则共同推动议会预算权成为宪政核心。"},{"label":"典型表现","value":"普鲁士宪法冲突中，议会拒绝批准军制改革预算，俾斯麦则以“缺口理论”绕开预算僵局。"},{"label":"为什么重要","value":"它让军事改革和国家权力问题转化为宪政冲突。理解俾斯麦“铁血政策”，必须理解他为什么要挑战议会预算控制。"},{"label":"争议/局限","value":"预算权并不自动保证民主控制，政府可以通过紧急状态、行政解释或政治压力绕开议会。"},{"label":"出处","value":"German History in Documents and Images: Prussian constitutional conflict；DHM/LeMO: Preußischer Verfassungskonflikt；Encyclopaedia Britannica: constitutionalism。"}],"relationItems":["↔ 相关：普鲁士宪法冲突","↔ 相关：俾斯麦“铁血演说”","✗ 对立/冲突：普鲁士军制改革","→ 后果：普鲁士俾斯麦赔偿法案"],"relations":[{"text":"↔ 相关：普鲁士宪法冲突","id":"extra539"},{"text":"↔ 相关：俾斯麦“铁血演说”","id":"extra540"},{"text":"✗ 对立/冲突：普鲁士军制改革","id":"extra536"},{"text":"→ 后果：普鲁士俾斯麦赔偿法案","id":"extra545"}],"source":"history","id":"extra915"},{"title":"法国七月革命","level":"A","type":"事件卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1830年7月26—29日","place":"法国巴黎","summary":"法国七月革命推翻波旁复辟王朝，建立七月王朝，并刺激1830年欧洲革命浪潮。","fields":[{"label":"标题","value":"法国七月革命"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1830年7月26—29日"},{"label":"地点","value":"法国巴黎"},{"label":"主要国家","value":"法国"},{"label":"一句话概括","value":"法国七月革命推翻波旁复辟王朝，建立七月王朝，并刺激1830年欧洲革命浪潮。"},{"label":"参与者","value":"法国国王查理十世、自由派议员、巴黎市民、新闻界、国民自卫军和路易-菲利普。"},{"label":"发生了什么","value":"查理十世发布限制出版、解散议会和改变选举制度的敕令后，巴黎爆发“三日革命”。工人、学生、自由派和市民武装筑起街垒，与王军交战。查理十世退位，奥尔良公爵路易-菲利普以“法国人的国王”身份即位，波旁复辟结束。"},{"label":"为什么重要","value":"它证明1815年后的复辟秩序并不稳固，推动比利时独立、波兰起义和德意志地区自由主义动员。"},{"label":"前因","value":"波旁复辟王朝试图恢复保守权威，但新闻自由、选举权和资产阶级政治参与要求不断增长。"},{"label":"后果","value":"七月王朝建立，欧洲多地革命者获得示范，德意志邦国中的宪政与民族运动重新活跃。"},{"label":"出处","value":"Encyclopaedia Britannica: July Revolution；Oxford Reference: July Revolution；Hobsbawm, The Age of Revolution。"}],"relationItems":["← 前因：拿破仑战后维也纳会议","→ 后果：1830年欧洲革命浪潮","→ 后果：德国汉巴赫节","↔ 相关：比利时独立革命"],"relations":[{"text":"← 前因：拿破仑战后维也纳会议","id":"extra525"},{"text":"→ 后果：1830年欧洲革命浪潮","id":"extra528"},{"text":"→ 后果：德国汉巴赫节","id":"extra489"}],"source":"history","id":"extra916"},{"title":"俄国泛斯拉夫主义","level":"B","type":"概念/思潮卡","tags":["文化与思想","战争与外交"],"mainTag":"文化与思想","subTag":"战争与外交","timeText":"19世纪中期—20世纪初","place":"俄国、巴尔干和中东欧","summary":"俄国泛斯拉夫主义把斯拉夫民族团结与俄国保护角色相连，深刻影响巴尔干危机和一战前外交。","fields":[{"label":"标题","value":"俄国泛斯拉夫主义"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"19世纪中期—20世纪初"},{"label":"地点","value":"俄国、巴尔干和中东欧"},{"label":"主要国家","value":"俄国；塞尔维亚；奥匈帝国；奥斯曼帝国"},{"label":"一句话概括","value":"俄国泛斯拉夫主义把斯拉夫民族团结与俄国保护角色相连，深刻影响巴尔干危机和一战前外交。"},{"label":"核心主张/思路","value":"强调斯拉夫民族在语言、宗教或历史上的共同性，并把俄国塑造成斯拉夫民族尤其是东正教斯拉夫人的保护者。"},{"label":"提出者/代表人物（可选）","value":"俄国斯拉夫派思想者、民族主义团体、部分外交和军事精英。"},{"label":"它从何而来","value":"浪漫民族主义、东正教身份、奥斯曼帝国衰落、巴尔干民族运动和俄国大国战略交织在一起。"},{"label":"典型表现","value":"俄国支持塞尔维亚和保加利亚民族诉求，俄奥围绕巴尔干影响力竞争，萨拉热窝危机后俄国支持塞尔维亚。"},{"label":"为什么重要","value":"它不是一战爆发的单一原因，但为俄国介入巴尔干危机提供了舆论和意识形态资源。"},{"label":"争议/局限","value":"泛斯拉夫主义内部目标并不统一，常被大国利益利用，也可能压过非俄斯拉夫民族自身的政治自主。"},{"label":"出处","value":"Encyclopaedia Britannica: Pan-Slavism；Hugh Seton-Watson, The Russian Empire；Dominic Lieven, Russia and the Origins of the First World War。"}],"relationItems":["← 前因：浪漫主义民族主义","↔ 相关：巴尔干民族问题","↔ 相关：奥匈帝国多民族结构","→ 后果：七月危机"],"relations":[{"text":"↔ 相关：巴尔干民族问题","id":"extra930"},{"text":"↔ 相关：奥匈帝国多民族结构","id":"extra923"}],"source":"history","id":"extra917"},{"title":"拿破仑战争","level":"S","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1803—1815年","place":"欧洲、地中海、大西洋殖民地和全球海上战场","summary":"拿破仑战争把法国革命成果和帝国扩张推向欧洲，重塑德意志、意大利和维也纳体系。","fields":[{"label":"标题","value":"拿破仑战争"},{"label":"分级","value":"S"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1803—1815年"},{"label":"地点","value":"欧洲、地中海、大西洋殖民地和全球海上战场"},{"label":"主要国家","value":"法国；英国；奥地利；普鲁士；俄国；西班牙；葡萄牙；神圣罗马帝国诸邦"},{"label":"一句话概括","value":"拿破仑战争把法国革命成果和帝国扩张推向欧洲，重塑德意志、意大利和维也纳体系。"},{"label":"参与者","value":"拿破仑法国、英国、奥地利、普鲁士、俄国、西班牙、葡萄牙、德意志诸邦和多次反法同盟。"},{"label":"发生了什么","value":"法国在拿破仑领导下通过一系列战争击败或压制欧洲王朝国家，建立附庸国、重组德意志和意大利，并与英国进行全球海上竞争。1812年俄国远征失败后，反法同盟反攻，1814年拿破仑退位，1815年滑铁卢战败后战争结束。"},{"label":"为什么重要","value":"它直接导致神圣罗马帝国解体、德意志民族主义兴起和维也纳会议秩序，也把现代征兵、法典和民族战争经验推向欧洲。"},{"label":"前因","value":"法国大革命、法国革命战争、欧洲王朝反革命和拿破仑掌权共同推动战争升级。"},{"label":"后果","value":"维也纳会议重建欧洲均势，德意志邦联成立，反法战争记忆成为19世纪民族主义资源。"},{"label":"出处","value":"Encyclopaedia Britannica: Napoleonic Wars；David Bell, The First Total War；Michael Broers, Europe under Napoleon。"}],"relationItems":["← 前因：法国大革命","← 前因：法国革命战争","↔ 相关：大陆封锁体系","→ 后果：拿破仑战后维也纳会议","→ 后果：德意志民族主义"],"relations":[{"text":"← 前因：法国大革命","id":"extra887"},{"text":"← 前因：法国革命战争","id":"extra919"},{"text":"↔ 相关：大陆封锁体系","id":"extra920"},{"text":"→ 后果：拿破仑战后维也纳会议","id":"extra525"},{"text":"→ 后果：德意志民族主义","id":"extra504"}],"source":"history","id":"extra918"},{"title":"法国革命战争","level":"A","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1792—1802年","place":"法国、低地地区、莱茵河流域、意大利、瑞士和地中海","summary":"法国革命战争把法国革命与欧洲王朝战争连接起来，推动征兵、共和国扩张和拿破仑崛起。","fields":[{"label":"标题","value":"法国革命战争"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1792—1802年"},{"label":"地点","value":"法国、低地地区、莱茵河流域、意大利、瑞士和地中海"},{"label":"主要国家","value":"法国；奥地利；普鲁士；英国；西班牙；俄国；荷兰"},{"label":"一句话概括","value":"法国革命战争把法国革命与欧洲王朝战争连接起来，推动征兵、共和国扩张和拿破仑崛起。"},{"label":"参与者","value":"法兰西第一共和国、奥地利、普鲁士、英国、西班牙、俄国和反法同盟各国。"},{"label":"发生了什么","value":"法国革命后，欧洲王朝国家和革命法国发生战争。法国从最初防御转向进攻，通过全民动员、征兵和革命军队击退外敌并输出共和国制度。战争扩展到低地、莱茵、意大利和埃及，拿破仑在意大利战场崛起，最终走向执政府和拿破仑战争。"},{"label":"为什么重要","value":"它使革命政治军事化，也把民族动员和意识形态战争带入欧洲国际关系。"},{"label":"前因","value":"法国大革命、君主制危机、皮尔尼茨宣言和欧洲王朝对革命扩散的恐惧。"},{"label":"后果","value":"法国势力扩展到欧洲多地，拿破仑取得军事声望，拿破仑战争由此接续展开。"},{"label":"出处","value":"Encyclopaedia Britannica: French Revolutionary wars；T. C. W. Blanning, The French Revolutionary Wars；David A. Bell, The First Total War。"}],"relationItems":["← 前因：法国大革命","↔ 相关：反法国革命《皮尔尼茨宣言》","→ 后果：拿破仑战争","↔ 相关：法国革命战争瓦尔密战役"],"relations":[{"text":"← 前因：法国大革命","id":"extra887"},{"text":"↔ 相关：反法国革命《皮尔尼茨宣言》","id":"extra474"},{"text":"→ 后果：拿破仑战争","id":"extra918"},{"text":"↔ 相关：法国革命战争瓦尔密战役","id":"extra476"}],"source":"history","id":"extra919"},{"title":"大陆封锁体系","level":"B","type":"制度/文本卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1806—1814年","place":"欧洲大陆和大西洋贸易网络","summary":"大陆封锁体系是拿破仑用欧洲大陆市场封锁英国的经济战政策，却加重附庸国压力并刺激走私。","fields":[{"label":"标题","value":"大陆封锁体系"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1806—1814年"},{"label":"地点","value":"欧洲大陆和大西洋贸易网络"},{"label":"主要国家","value":"法国；英国；普鲁士；俄国；西班牙；荷兰；德意志诸邦"},{"label":"一句话概括","value":"大陆封锁体系是拿破仑用欧洲大陆市场封锁英国的经济战政策，却加重附庸国压力并刺激走私。"},{"label":"制定方/签署方","value":"拿破仑法国，核心命令包括1806年《柏林敕令》和1807年《米兰敕令》。"},{"label":"主要内容","value":"禁止欧洲大陆国家与英国贸易，没收英国货物，并把违反封锁者视为敌对行为。"},{"label":"它试图解决什么问题","value":"法国难以直接击败英国海军，试图通过经济封锁削弱英国贸易、财政和战争能力。"},{"label":"为什么重要","value":"它说明拿破仑战争不只是战场战争，也是经济战和帝国控制问题。"},{"label":"争议/局限","value":"封锁损害欧洲商人和消费者利益，英国可转向海外市场，走私普遍存在，俄国退出封锁成为1812年冲突背景。"},{"label":"造成的影响","value":"大陆经济受扰，德意志和荷兰等地压力上升，法俄关系恶化，英国工业和海上帝国反而寻找全球市场。"},{"label":"出处","value":"Encyclopaedia Britannica: Continental System；Alexander Grab, Napoleon and the Transformation of Europe；Michael Broers, Europe under Napoleon。"}],"relationItems":["← 前因：拿破仑战争","↔ 相关：英国海上霸权","→ 后果：拿破仑远征俄国","↔ 相关：德意志民族主义"],"relations":[{"text":"← 前因：拿破仑战争","id":"extra918"},{"text":"↔ 相关：英国海上霸权","id":"extra906"},{"text":"↔ 相关：德意志民族主义","id":"extra504"}],"source":"history","id":"extra920"},{"title":"中法兰克王国","level":"B","type":"组织/机构卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"843—855年为统一王国，此后分裂为洛泰尔王国、意大利王国和普罗旺斯等","place":"从北海到意大利的狭长地带，包含洛林、勃艮第和意大利部分地区","summary":"中法兰克王国是《凡尔登条约》分出的中间王国，其分裂遗产长期影响法德之间的洛林与莱茵问题。","fields":[{"label":"标题","value":"中法兰克王国"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"843—855年为统一王国，此后分裂为洛泰尔王国、意大利王国和普罗旺斯等"},{"label":"地点","value":"从北海到意大利的狭长地带，包含洛林、勃艮第和意大利部分地区"},{"label":"主要国家","value":"法兰克王国；法国；德国；意大利；比利时；荷兰；瑞士"},{"label":"一句话概括","value":"中法兰克王国是《凡尔登条约》分出的中间王国，其分裂遗产长期影响法德之间的洛林与莱茵问题。"},{"label":"性质/类型","value":"加洛林帝国分裂后的王朝继承国家。"},{"label":"成立/解散时间","value":"843年《凡尔登条约》形成；855年洛泰尔一世死后进一步分裂。"},{"label":"核心目标/宗旨","value":"作为洛泰尔一世的帝国份额，连接北海、莱茵、勃艮第和意大利，并保留皇帝头衔的政治象征。"},{"label":"关键人物（可选）","value":"洛泰尔一世、洛泰尔二世、路易二世。"},{"label":"关键行动/事件","value":"843年《凡尔登条约》、855年《普吕姆条约》、洛林在东西法兰克之间反复争夺。"},{"label":"为什么重要","value":"它解释为什么低地、洛林、勃艮第和意大利北部长期成为西欧王朝和帝国竞争地带。"},{"label":"争议/局限","value":"中法兰克不是现代意义的“中间国家”，其边界来自王朝继承而非民族原则。"},{"label":"出处","value":"Encyclopaedia Britannica: Treaty of Verdun；Rosamond McKitterick, The Frankish Kingdoms under the Carolingians；Janet Nelson, Charles the Bald。"}],"relationItems":["← 前因：加洛林帝国《凡尔登条约》","→ 后果：洛林在法德之间的长期归属问题","↔ 相关：东法兰克王国","↔ 相关：西法兰克王国"],"relations":[{"text":"← 前因：加洛林帝国《凡尔登条约》","id":"extra344"},{"text":"→ 后果：洛林在法德之间的长期归属问题","id":"extra398"},{"text":"↔ 相关：东法兰克王国","id":"extra345"}],"source":"history","id":"extra921"},{"title":"莱比锡战役","level":"A","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1813年10月16—19日","place":"萨克森莱比锡周边","summary":"莱比锡战役是拿破仑战争中的“民族会战”，反法联军重创法国并推动莱茵邦瓦解。","fields":[{"label":"标题","value":"莱比锡战役"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1813年10月16—19日"},{"label":"地点","value":"萨克森莱比锡周边"},{"label":"主要国家","value":"法国；俄国；普鲁士；奥地利；瑞典；萨克森"},{"label":"一句话概括","value":"莱比锡战役是拿破仑战争中的“民族会战”，反法联军重创法国并推动莱茵邦瓦解。"},{"label":"参与者","value":"拿破仑法国军队、俄国、普鲁士、奥地利、瑞典等反法联军，以及萨克森等德意志邦国军队。"},{"label":"发生了什么","value":"1812年俄国远征失败后，反法联盟在中欧集结。1813年10月，双方在莱比锡周边展开多日大战。联军兵力优势逐渐压倒法军，萨克森军队在战斗中倒向联军。拿破仑被迫西撤，撤退中桥梁过早炸毁导致更多损失。"},{"label":"为什么重要","value":"它结束了拿破仑对德意志中欧的支配，推动反法联军进入法国，并成为德意志民族记忆的重要战争节点。"},{"label":"前因","value":"拿破仑远征俄国失败、普鲁士改革动员、奥地利转向反法联盟和德意志反法情绪上升。"},{"label":"后果","value":"莱茵邦瓦解，法国退回本土，1814年拿破仑首次退位。"},{"label":"出处","value":"Encyclopaedia Britannica: Battle of Leipzig；Michael Leggiere, Napoleon and the Struggle for Germany；David Chandler, The Campaigns of Napoleon。"}],"relationItems":["← 前因：德意志解放战争","↔ 相关：拿破仑战争","→ 后果：拿破仑战后维也纳会议","↔ 相关：德意志民族主义"],"relations":[{"text":"← 前因：德意志解放战争","id":"extra523"},{"text":"↔ 相关：拿破仑战争","id":"extra918"},{"text":"→ 后果：拿破仑战后维也纳会议","id":"extra525"},{"text":"↔ 相关：德意志民族主义","id":"extra504"}],"source":"history","id":"extra922"},{"title":"奥匈帝国多民族结构","level":"B","type":"概念/思潮卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1867—1918年；其前身多民族结构可追溯至哈布斯堡君主国","place":"中欧、东南欧和多瑙河流域","summary":"奥匈帝国多民族结构把多个民族、语言和历史王国纳入双元君主体制，既维持大国地位也积累民族冲突。","fields":[{"label":"标题","value":"奥匈帝国多民族结构"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1867—1918年；其前身多民族结构可追溯至哈布斯堡君主国"},{"label":"地点","value":"中欧、东南欧和多瑙河流域"},{"label":"主要国家","value":"奥匈帝国；奥地利；匈牙利；捷克；斯洛伐克；克罗地亚；塞尔维亚；波兰；乌克兰；罗马尼亚"},{"label":"一句话概括","value":"奥匈帝国多民族结构把多个民族、语言和历史王国纳入双元君主体制，既维持大国地位也积累民族冲突。"},{"label":"核心主张/思路","value":"帝国不是民族国家，而是王朝、军队、官僚、地方自治和多种民族政治之间的复杂平衡。"},{"label":"提出者/代表人物（可选）","value":"哈布斯堡王朝、奥地利和匈牙利政治精英、捷克和南斯拉夫民族运动者。"},{"label":"它从何而来","value":"哈布斯堡东南欧扩张、匈牙利王国传统、波兰瓜分和19世纪民族主义共同塑造多民族帝国。"},{"label":"典型表现","value":"1867年奥匈妥协、奥地利帝国议会、匈牙利马扎尔化政策、波希米亚问题和南斯拉夫问题。"},{"label":"为什么重要","value":"它解释俄国泛斯拉夫主义、巴尔干危机和一战前奥匈安全焦虑的制度背景。"},{"label":"争议/局限","value":"帝国既压制民族诉求，也提供跨民族行政和经济空间；不能只用“必然崩溃”解释其历史。"},{"label":"出处","value":"Encyclopaedia Britannica: Austria-Hungary；Pieter Judson, The Habsburg Empire；Robert Kann, A History of the Habsburg Empire。"}],"relationItems":["← 前因：哈布斯堡东南欧扩张","↔ 相关：俄国泛斯拉夫主义","→ 后果：奥匈帝国边疆防御","→ 后果：奥匈帝国崩溃"],"relations":[{"text":"← 前因：哈布斯堡东南欧扩张","id":"extra905"},{"text":"↔ 相关：俄国泛斯拉夫主义","id":"extra917"},{"text":"→ 后果：奥匈帝国边疆防御","id":"extra971"},{"text":"→ 后果：奥匈帝国崩溃","id":"extra947"}],"source":"history","id":"extra923"},{"title":"德意志帝国成立","level":"S","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1871年1月18日","place":"法国凡尔赛宫镜厅","summary":"德意志帝国在普鲁士主导和对法战争胜利中成立，改变欧洲均势，也为此后德国强国政治和欧洲紧张关系奠定基础。","fields":[{"label":"标题","value":"德意志帝国成立"},{"label":"分级","value":"S"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1871年1月18日"},{"label":"地点","value":"法国凡尔赛宫镜厅"},{"label":"主要国家","value":"德国、普鲁士、法国"},{"label":"一句话概括","value":"德意志帝国在普鲁士主导和对法战争胜利中成立，改变欧洲均势，也为此后德国强国政治和欧洲紧张关系奠定基础。"},{"label":"参与者","value":"普鲁士国王威廉一世、奥托·冯·俾斯麦、德意志诸邦君主和代表、普鲁士及德意志军队。"},{"label":"发生了什么","value":"普法战争中，普鲁士和南德诸邦共同对法作战，民族统一情绪和军事胜利推动各邦接受统一安排。俾斯麦同巴伐利亚、符腾堡、巴登等南德邦国谈判，保留部分邦国特权以换取加入帝国。1871年1月18日，德意志诸邦君主和军政代表在凡尔赛宫镜厅宣布建立德意志帝国，普鲁士国王威廉一世被拥立为德意志皇帝。新帝国随后把普鲁士主导的北德意志邦联的宪制框架扩展到全德意志帝国。"},{"label":"为什么重要","value":"这是德国近代史的世界史坐标级节点。它结束了德意志长期政治分裂，使一个人口、工业和军事潜力巨大的新帝国进入欧洲权力中心，彻底改变了十九世纪后期欧洲均势。"},{"label":"前因","value":"关税同盟、普奥战争后的北德意志邦联和普法战争胜利，使普鲁士既掌握制度框架，也掌握民族战争带来的政治动员力。"},{"label":"后果","value":"新帝国改变欧洲均势，法国因割地赔款形成长期复仇心理，列强外交也开始围绕如何适应和约束这个新强权重新排列。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Reichsgründung；Encyclopaedia Britannica: German Empire；Encyclopaedia Britannica: Franco-German War。"},{"label":"资料备注","value":"1871年1月18日是帝国宣告成立和皇帝加冕的象征性日期；普法战争的正式和平安排则在之后完成。"}],"relationItems":["← 前因：普法战争","← 前因：普鲁士主导的北德意志邦联","← 前因：普奥战争","← 前因：德意志关税同盟（Zollverein）","→ 后果：德意志帝国俾斯麦时代","→ 后果：阿尔萨斯-洛林问题的形成","↔ 相关：奥托·冯·俾斯麦"],"relations":[{"text":"← 前因：普法战争","id":"extra497"},{"text":"← 前因：普鲁士主导的北德意志邦联","id":"extra496"},{"text":"← 前因：普奥战争","id":"extra495"},{"text":"← 前因：德意志关税同盟（Zollverein）","id":"extra486"},{"text":"→ 后果：德意志帝国俾斯麦时代","id":"extra625"},{"text":"→ 后果：阿尔萨斯-洛林问题的形成","id":"extra620"},{"text":"↔ 相关：奥托·冯·俾斯麦","id":"extra924"}],"source":"history","id":"extra621"},{"title":"德国民族使命论","level":"C","type":"概念/思潮卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"十九世纪后期至二十世纪上半叶尤为突出","place":"德国","summary":"德国民族使命论把德国文化、秩序或民族精神说成能够拯救世界的力量，是帝国时期民族主义自我想象的一种表达。","fields":[{"label":"标题","value":"德国民族使命论"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"十九世纪后期至二十世纪上半叶尤为突出"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国民族使命论把德国文化、秩序或民族精神说成能够拯救世界的力量，是帝国时期民族主义自我想象的一种表达。"},{"label":"核心主张/思路","value":"德国不只是一个普通民族国家，而被想象为拥有特殊文化使命、道德使命或历史使命，可以为欧洲乃至世界提供更高秩序。"},{"label":"提出者/代表人物（可选）","value":"埃马努埃尔·盖贝尔的诗句“Am deutschen Wesen soll die Welt genesen”常被后世民族主义语境引用，但这一思潮并不只属于单一作者。"},{"label":"它从何而来","value":"德意志长期政治分裂使文化民族主义先于统一国家发展；1871年统一后，新帝国又需要解释自身在欧洲和世界中的位置。"},{"label":"典型表现","value":"把德国文化、纪律、国家组织或“精神”说成优越模式；在帝国主义、战争宣传和保守民族主义中常与德国世界地位诉求结合。"},{"label":"为什么重要","value":"它帮助解释德国民族主义如何从文化自豪感转向使命感，也为后来“德意志帝国世界政策”和战争动员提供了语言资源。"},{"label":"争议/局限","value":"这种观念容易把复杂的文化认同变成民族优越论。不同作者使用类似语言的语境并不完全相同，不能把所有文化民族主义都等同于后来的极端民族主义。"},{"label":"出处","value":"Emanuel Geibel《Deutschlands Beruf》相关资料；Deutsches Historisches Museum/LeMO关于帝国时期民族主义与德意志帝国世界政策资料；German History Documents and Images相关文本。"},{"label":"资料备注","value":"原来的“Am deutschen Wesen soll die Welt genesen”不再按俗语卡处理，而归入德国民族使命论这一概念卡。"}],"relationItems":["← 前因：德意志帝国成立","→ 后果：德意志帝国世界政策","↔ 相关：“Ein Platz an der Sonne”","↔ 相关：德意志民族主义"],"relations":[{"text":"← 前因：德意志帝国成立","id":"extra621"},{"text":"→ 后果：德意志帝国世界政策","id":"extra635"},{"text":"↔ 相关：“Ein Platz an der Sonne”","id":"proverb2"},{"text":"↔ 相关：德意志民族主义","id":"extra504"}],"source":"history","id":"extra622"},{"title":"德国“背后一刀”传说","level":"B","type":"概念/思潮卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1918年后形成并在魏玛共和国时期持续传播","place":"德国","summary":"德国“背后一刀”传说把德国一战失败解释为国内革命者和共和国政治家的背叛，是右翼攻击魏玛民主的核心政治神话。","fields":[{"label":"标题","value":"德国“背后一刀”传说"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1918年后形成并在魏玛共和国时期持续传播"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国“背后一刀”传说把德国一战失败解释为国内革命者和共和国政治家的背叛，是右翼攻击魏玛民主的核心政治神话。"},{"label":"核心主张/思路","value":"德国军队并非在前线被真正击败，而是被国内左翼、革命者、共和派或犹太人等“内部敌人”出卖。"},{"label":"提出者/代表人物（可选）","value":"德国军方和右翼民族主义者持续传播这一说法，兴登堡等军政人物的证词和表态强化了它的公共影响。"},{"label":"它从何而来","value":"一战战败、停战、德国十一月革命和帝制崩溃几乎同时发生，军方和右翼力量需要转移战败责任，保存军队荣誉并否认共和国合法性。"},{"label":"典型表现","value":"右翼宣传把社会民主党人、革命者和共和国支持者称为“十一月罪人”，并把《凡尔赛和约》的屈辱归咎于他们。"},{"label":"为什么重要","value":"它把战败创伤转化为阴谋论和政治仇恨，使魏玛共和国从诞生起就背负“卖国政权”的污名。"},{"label":"争议/局限","value":"这是政治神话，不是对德国战败原因的事实解释。德国失败与军事、经济、外交和社会承受能力崩溃有关，不能归咎于单一“背叛”。"},{"label":"出处","value":"Encyclopaedia Britannica: stab-in-the-back myth；United States Holocaust Memorial Museum关于魏玛共和国与纳粹宣传资料；Deutsches Historisches Museum/LeMO: Dolchstoßlegende。"},{"label":"资料备注","value":"原来的“Dolchstoß in den Rücken”不再按俗语卡处理，改为概念/思潮卡。"}],"relationItems":["← 前因：第一次世界大战德国战败","← 前因：德国十一月革命","→ 后果：希特勒出任德国总理","↔ 相关：《凡尔赛和约》","↔ 相关：魏玛共和国成立"],"relations":[{"text":"← 前因：第一次世界大战德国战败","id":"extra926"},{"text":"← 前因：德国十一月革命","id":"extra666"},{"text":"→ 后果：希特勒出任德国总理","id":"card71"},{"text":"↔ 相关：《凡尔赛和约》","id":"card59"},{"text":"↔ 相关：魏玛共和国成立","id":"card7"}],"source":"history","id":"extra623"},{"title":"德意志帝国宪法","level":"A","type":"制度/文本卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1871年4月16日通过","place":"德意志帝国","summary":"德意志帝国宪法把普鲁士主导的联邦君主制制度化，形成强皇帝、强首相、弱议会的帝国政治结构。","fields":[{"label":"标题","value":"德意志帝国宪法"},{"label":"分级","value":"A"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1871年4月16日通过"},{"label":"地点","value":"德意志帝国"},{"label":"主要国家","value":"德国、普鲁士"},{"label":"一句话概括","value":"德意志帝国宪法把普鲁士主导的联邦君主制制度化，形成强皇帝、强首相、弱议会的帝国政治结构。"},{"label":"制定方/签署方","value":"德意志帝国及各邦政府，制度基础来自普鲁士主导的北德意志邦联宪法。"},{"label":"主要内容","value":"皇帝由普鲁士国王兼任，掌握外交、军事和任命首相等核心权力；联邦参议院代表各邦政府，帝国议会由男性普选产生，但政府不对议会负责。"},{"label":"它试图解决什么问题","value":"在统一后把各邦纳入共同国家框架，同时保留普鲁士优势和各邦君主权力，避免建立完全议会制国家。"},{"label":"为什么重要","value":"它决定了帝国政治的基本矛盾：选举和政党政治越来越现代化，但行政、军事和外交权力仍主要掌握在君主与官僚体系手中。"},{"label":"争议/局限","value":"帝国议会可以影响立法和预算，却不能决定政府去留；军队和外交高度脱离议会责任。"},{"label":"造成的影响","value":"为后来的俾斯麦统治、威廉二世个人统治倾向、军政精英影响外交和一战决策留下制度空间。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Reichsverfassung；German History Documents and Images: Constitution of the German Empire；Encyclopaedia Britannica: German Empire。"}],"relationItems":["← 前因：普鲁士主导的北德意志邦联","← 前因：德意志帝国成立","→ 后果：德意志帝国俾斯麦时代","→ 后果：德国威廉二世亲政","↔ 相关：德意志统一中的普鲁士优势"],"relations":[{"text":"← 前因：普鲁士主导的北德意志邦联","id":"extra496"},{"text":"← 前因：德意志帝国成立","id":"extra621"},{"text":"→ 后果：德意志帝国俾斯麦时代","id":"extra625"},{"text":"→ 后果：德国威廉二世亲政","id":"extra634"},{"text":"↔ 相关：德意志统一中的普鲁士优势","id":"extra914"}],"source":"history","id":"extra624"},{"title":"德意志帝国俾斯麦时代","level":"A","type":"概念/思潮卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1871年至1890年","place":"德意志帝国","summary":"德意志帝国俾斯麦时代以巩固新帝国为核心，通过内政压制与社会整合、外交结盟与孤立法国维持德国安全。","fields":[{"label":"标题","value":"德意志帝国俾斯麦时代"},{"label":"分级","value":"A"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1871年至1890年"},{"label":"地点","value":"德意志帝国"},{"label":"主要国家","value":"德国、奥地利、法国、俄国、英国"},{"label":"一句话概括","value":"德意志帝国俾斯麦时代以巩固新帝国为核心，通过内政压制与社会整合、外交结盟与孤立法国维持德国安全。"},{"label":"核心主张/思路","value":"统一后的德国应作为“满足的国家”维持欧洲现状，避免被反德联盟包围；国内则通过打压敌对力量和吸纳社会诉求巩固帝国秩序。"},{"label":"提出者/代表人物（可选）","value":"奥托·冯·俾斯麦。"},{"label":"它从何而来","value":"德意志帝国刚刚建立，德法复仇主义、奥俄巴尔干竞争、天主教与社会主义运动都威胁新帝国稳定。"},{"label":"典型表现","value":"德意志帝国文化斗争、德国反社会党人法、社会保险立法、德意志帝国保护关税政策、三皇同盟、德奥意三国同盟、德俄再保险条约。"},{"label":"为什么重要","value":"德意志帝国俾斯麦时代建立了帝国的内外政策基础，也留下了强行政、弱议会和以安全焦虑管理欧洲均势的政治传统。"},{"label":"争议/局限","value":"俾斯麦能高超平衡列强，却过度依赖个人操作；内政上压制反对派没有真正解决帝国民主化问题。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Bismarck；Encyclopaedia Britannica: Otto von Bismarck；German History Documents and Images: Bismarckian Germany。"}],"relationItems":["← 前因：德意志帝国成立","→ 后果：德意志帝国文化斗争","→ 后果：德国反社会党人法","→ 后果：德国俾斯麦社会保险立法","→ 后果：德俄再保险条约","→ 后果：俾斯麦辞去德意志帝国首相"],"relations":[{"text":"← 前因：德意志帝国成立","id":"extra621"},{"text":"→ 后果：德意志帝国文化斗争","id":"extra626"},{"text":"→ 后果：德国反社会党人法","id":"extra627"},{"text":"→ 后果：德国俾斯麦社会保险立法","id":"extra629"},{"text":"→ 后果：德俄再保险条约","id":"extra632"},{"text":"→ 后果：俾斯麦辞去德意志帝国首相","id":"extra633"}],"source":"history","id":"extra625"},{"title":"德意志帝国文化斗争","level":"B","type":"事件卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"主要集中于1871年至1878年","place":"德意志帝国，重点涉及普鲁士和天主教地区","summary":"德意志帝国文化斗争是俾斯麦政府限制天主教会影响力的政治冲突，反映新帝国国家权力与宗教忠诚之间的整合焦虑。","fields":[{"label":"标题","value":"德意志帝国文化斗争"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"主要集中于1871年至1878年"},{"label":"地点","value":"德意志帝国，重点涉及普鲁士和天主教地区"},{"label":"主要国家","value":"德国、梵蒂冈"},{"label":"一句话概括","value":"德意志帝国文化斗争是俾斯麦政府限制天主教会影响力的政治冲突，反映新帝国国家权力与宗教忠诚之间的整合焦虑。"},{"label":"参与者","value":"俾斯麦政府、天主教会、教皇庇护九世、德国中央党、普鲁士和帝国议会。"},{"label":"发生了什么","value":"帝国建立后，俾斯麦担心德国中央党和罗马教廷削弱新国家整合，尤其在普鲁士的天主教地区形成另一种政治忠诚。政府陆续推出学校监督、神职人员培训和任命、教会纪律权等方面的限制措施，试图把教会置于国家控制之下。天主教会和中央党抵制政策，许多主教和神职人员被罚款、监禁或驱逐。到1870年代末，俾斯麦发现中央党反而更稳固，且需要其支持对付社会主义运动，遂逐步缓和政策。"},{"label":"为什么重要","value":"它显示德意志帝国不仅要完成领土统一，还要处理宗教、地区和政治忠诚的统一。中央党在压力下反而巩固，成为帝国政治中的稳定政党力量。"},{"label":"前因","value":"新帝国需要整合天主教人口和各邦制度，教皇无误论又加深了俾斯麦对天主教跨国忠诚和中央党政治动员能力的疑虑。"},{"label":"后果","value":"强硬政策未能削弱中央党，反而巩固了天主教政治身份；俾斯麦后来为应对社会主义和议会合作需要，逐步缓和文化斗争。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Kulturkampf；Encyclopaedia Britannica: Kulturkampf；German History Documents and Images: Bismarck and the Kulturkampf。"}],"relationItems":["← 前因：德意志帝国成立","← 前因：“Nach Canossa gehen wir nicht”","→ 后果：德国中央党","↔ 相关：德意志帝国俾斯麦时代"],"relations":[{"text":"← 前因：德意志帝国成立","id":"extra621"},{"text":"← 前因：“Nach Canossa gehen wir nicht”","id":"proverb1"},{"text":"→ 后果：德国中央党","id":"extra673"},{"text":"↔ 相关：德意志帝国俾斯麦时代","id":"extra625"}],"source":"history","id":"extra626"},{"title":"德国反社会党人法","level":"B","type":"制度/文本卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1878年至1890年","place":"德意志帝国","summary":"德国反社会党人法禁止社会主义组织、出版物和集会，却没有禁止社民党候选人参选，结果未能阻止德国社会主义运动壮大。","fields":[{"label":"标题","value":"德国反社会党人法"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1878年至1890年"},{"label":"地点","value":"德意志帝国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国反社会党人法禁止社会主义组织、出版物和集会，却没有禁止社民党候选人参选，结果未能阻止德国社会主义运动壮大。"},{"label":"制定方/签署方","value":"俾斯麦政府推动，帝国议会通过。"},{"label":"主要内容","value":"取缔社会主义、社会民主主义和共产主义组织及宣传活动，允许查禁报刊、解散协会、驱逐活动者；但社民党人仍可作为个人参加帝国议会选举。"},{"label":"它试图解决什么问题","value":"俾斯麦把快速扩张的社会主义运动视为帝国秩序威胁，并借皇帝遇刺事件后的政治气氛推动镇压。"},{"label":"为什么重要","value":"它体现帝国对现代群众政党的恐惧，也说明单靠警察管制无法消灭工业社会中的阶级政治。"},{"label":"争议/局限","value":"法律压制组织和出版，却使社民党在选举中获得殉难者形象和更强纪律，反而推动其长期成长。"},{"label":"造成的影响","value":"1890年法律失效后，社会民主党迅速公开扩张，成为帝国最大群众政党之一。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Sozialistengesetz；German History Documents and Images: Anti-Socialist Law；Encyclopaedia Britannica: Social Democratic Party of Germany。"}],"relationItems":["← 前因：德国社会民主党（SPD）","← 前因：德意志帝国俾斯麦时代","→ 后果：德国社会民主党（SPD）","↔ 相关：德国俾斯麦社会保险立法"],"relations":[{"text":"← 前因：德国社会民主党（SPD）","id":"extra628"},{"text":"← 前因：德意志帝国俾斯麦时代","id":"extra625"},{"text":"→ 后果：德国社会民主党（SPD）","id":"extra628"},{"text":"↔ 相关：德国俾斯麦社会保险立法","id":"extra629"}],"source":"history","id":"extra627"},{"title":"德国社会民主党（SPD）","level":"A","type":"组织/机构卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1875年哥达合并形成重要前身；1890年后使用“德国社会民主党（SPD）”名称","place":"德国","summary":"德国社会民主党（SPD）从工人运动中成长为帝国最大群众政党，是理解帝德、魏玛和欧洲社会主义政治的核心组织。","fields":[{"label":"标题","value":"德国社会民主党（SPD）"},{"label":"分级","value":"A"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1875年哥达合并形成重要前身；1890年后使用“德国社会民主党（SPD）”名称"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国社会民主党（SPD）从工人运动中成长为帝国最大群众政党，是理解帝德、魏玛和欧洲社会主义政治的核心组织。"},{"label":"性质/类型","value":"社会主义工人政党、群众政党。"},{"label":"成立/解散时间","value":"1875年拉萨尔派与德国社会主义爱森纳赫派合并为社会主义工人党；1890年改称德国社会民主党（SPD），延续至今。"},{"label":"核心目标/宗旨","value":"代表工人阶级利益，争取普选权、社会保障、劳动权利和社会主义改造。"},{"label":"关键人物（可选）","value":"奥古斯特·倍倍尔、威廉·李卜克内西、费迪南德·拉萨尔等。"},{"label":"关键行动/事件","value":"在德国反社会党人法期间受压制但通过选举和地下网络维持；1891年《德国社民党《爱尔福特纲领》》明确其马克思主义方向和议会斗争路线。"},{"label":"为什么重要","value":"它是世界上最重要的早期社会主义群众政党之一。到一战前，社民党已成为帝国议会第一大党，却仍被排斥在政府权力之外。"},{"label":"争议/局限","value":"党内长期存在革命纲领与议会改良实践之间的张力；1914年支持战争贷款导致国际社会主义运动严重分裂。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Sozialdemokratie；Encyclopaedia Britannica: Social Democratic Party of Germany；German History Documents and Images: German Social Democracy。"}],"relationItems":["← 前因：马克思恩格斯《共产党宣言》","→ 后果：德国反社会党人法","→ 后果：德国社民党《爱尔福特纲领》","→ 后果：德国1914年战争贷款表决","↔ 相关：德国俾斯麦社会保险立法"],"relations":[{"text":"← 前因：马克思恩格斯《共产党宣言》","id":"extra61"},{"text":"→ 后果：德国反社会党人法","id":"extra627"},{"text":"→ 后果：德国社民党《爱尔福特纲领》","id":"extra696"},{"text":"→ 后果：德国1914年战争贷款表决","id":"extra691"},{"text":"↔ 相关：德国俾斯麦社会保险立法","id":"extra629"}],"source":"history","id":"extra628"},{"title":"德国俾斯麦社会保险立法","level":"B","type":"制度/文本卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1883年至1889年","place":"德意志帝国","summary":"德国俾斯麦社会保险立法建立疾病、事故和养老保险制度，是现代福利国家的重要早期范例。","fields":[{"label":"标题","value":"德国俾斯麦社会保险立法"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1883年至1889年"},{"label":"地点","value":"德意志帝国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国俾斯麦社会保险立法建立疾病、事故和养老保险制度，是现代福利国家的重要早期范例。"},{"label":"制定方/签署方","value":"俾斯麦政府、德意志帝国议会。"},{"label":"主要内容","value":"1883年疾病保险、1884年事故保险、1889年养老和残疾保险，逐步把工人风险纳入国家和社会保险体系。"},{"label":"它试图解决什么问题","value":"在工业化和社会主义运动扩张背景下，政府试图通过社会保障吸纳工人阶级，削弱社民党的动员基础。"},{"label":"为什么重要","value":"它开创性地把现代国家、雇主和工人纳入制度化社会风险分担，对二十世纪福利国家发展具有长期影响。"},{"label":"争议/局限","value":"其政治动机带有反社会主义色彩，福利水平有限，也没有改变工人在政治权力中的边缘地位。"},{"label":"造成的影响","value":"德国成为社会保险制度先行者；社民党并未因此被削弱，反而继续扩大群众基础。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Sozialversicherung；German History Documents and Images: Social Insurance；Encyclopaedia Britannica: Otto von Bismarck。"}],"relationItems":["← 前因：德国社会民主党（SPD）","← 前因：德国反社会党人法","→ 后果：现代福利国家","↔ 相关：德意志帝国俾斯麦时代"],"relations":[{"text":"← 前因：德国社会民主党（SPD）","id":"extra628"},{"text":"← 前因：德国反社会党人法","id":"extra627"},{"text":"→ 后果：现代福利国家","id":"extra951"},{"text":"↔ 相关：德意志帝国俾斯麦时代","id":"extra625"}],"source":"history","id":"extra629"},{"title":"德意志帝国保护关税政策","level":"B","type":"制度/文本卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1879年后","place":"德意志帝国","summary":"1879年德意志帝国保护关税政策标志帝国从自由贸易转向保护主义，巩固了“铁与黑麦”联盟。","fields":[{"label":"标题","value":"德意志帝国保护关税政策"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1879年后"},{"label":"地点","value":"德意志帝国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1879年德意志帝国保护关税政策标志帝国从自由贸易转向保护主义，巩固了“铁与黑麦”联盟。"},{"label":"制定方/签署方","value":"俾斯麦政府、帝国议会中的保守派和民族自由派部分力量。"},{"label":"主要内容","value":"对进口谷物和工业品征收保护性关税，以保护东部容克农业和德国工业免受国际竞争冲击。"},{"label":"它试图解决什么问题","value":"十九世纪七十年代经济危机后，农业和工业利益集团要求国家保护市场，政府也需要更稳定财政收入和政治联盟。"},{"label":"为什么重要","value":"它改变了帝国内部政治经济格局，使容克地主和重工业资本形成更紧密的利益联盟。"},{"label":"争议/局限","value":"保护关税提高消费者负担，尤其影响工人和城市居民；也强化了帝国政治中的保守经济联盟。"},{"label":"造成的影响","value":"推动“铁与黑麦”联盟形成，为帝国后期保守民族主义、农业保护和工业扩张政策提供社会基础。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Schutzzollpolitik；German History Documents and Images: Tariff Policy；Encyclopaedia Britannica: German Empire。"}],"relationItems":["← 前因：德意志帝国俾斯麦时代","→ 后果：德国铁与黑麦联盟","↔ 相关：德国工业化","↔ 相关：普鲁士容克地主"],"relations":[{"text":"← 前因：德意志帝国俾斯麦时代","id":"extra625"},{"text":"→ 后果：德国铁与黑麦联盟","id":"extra756"},{"text":"↔ 相关：德国工业化","id":"extra933"},{"text":"↔ 相关：普鲁士容克地主","id":"extra672"}],"source":"history","id":"extra630"},{"title":"德奥意三国同盟","level":"A","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1882年签订","place":"欧洲外交体系","summary":"德奥意三国同盟把德国、奥匈帝国和意大利结成防御联盟，是一战前欧洲同盟体系的重要一极。","fields":[{"label":"标题","value":"德奥意三国同盟"},{"label":"分级","value":"A"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1882年签订"},{"label":"地点","value":"欧洲外交体系"},{"label":"主要国家","value":"德国、奥地利、意大利"},{"label":"一句话概括","value":"德奥意三国同盟把德国、奥匈帝国和意大利结成防御联盟，是一战前欧洲同盟体系的重要一极。"},{"label":"制定方/签署方","value":"德意志帝国、奥匈帝国、意大利王国。"},{"label":"主要内容","value":"三国约定在特定条件下互相提供外交或军事支持，核心是巩固德国与奥匈关系，并把意大利纳入反法外交框架。"},{"label":"它试图解决什么问题","value":"俾斯麦希望孤立法国、稳定中欧，并防止德国在欧洲陷入外交孤立。"},{"label":"为什么重要","value":"它是后来一战同盟结构的基础之一。虽然意大利1914年没有立即参战并在1915年转向协约国，但德奥意三国同盟塑造了战前欧洲阵营想象。"},{"label":"争议/局限","value":"意大利与奥匈在亚得里亚和领土问题上矛盾很深，同盟可靠性有限。"},{"label":"造成的影响","value":"推动欧洲外交逐渐向同盟集团化发展，间接刺激法国寻找俄国和英国作为伙伴。"},{"label":"出处","value":"Encyclopaedia Britannica: Triple Alliance；Deutsches Historisches Museum/LeMO: Bündnispolitik；German History Documents and Images: Bismarckian Alliance System。"}],"relationItems":["← 前因：德意志帝国俾斯麦时代","← 前因：1879年德奥同盟","→ 后果：法俄同盟","→ 后果：第一次世界大战爆发","↔ 相关：德俄再保险条约"],"relations":[{"text":"← 前因：德意志帝国俾斯麦时代","id":"extra625"},{"text":"← 前因：1879年德奥同盟","id":"extra755"},{"text":"→ 后果：法俄同盟","id":"extra928"},{"text":"→ 后果：第一次世界大战爆发","id":"extra925"},{"text":"↔ 相关：德俄再保险条约","id":"extra632"}],"source":"history","id":"extra631"},{"title":"德俄再保险条约","level":"A","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1887年签订；1890年未续约","place":"德国与俄国外交关系","summary":"德俄再保险条约是俾斯麦避免德国两线受敌的关键安排，1890年未续约后法俄接近成为可能。","fields":[{"label":"标题","value":"德俄再保险条约"},{"label":"分级","value":"A"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1887年签订；1890年未续约"},{"label":"地点","value":"德国与俄国外交关系"},{"label":"主要国家","value":"德国、俄国、奥地利"},{"label":"一句话概括","value":"德俄再保险条约是俾斯麦避免德国两线受敌的关键安排，1890年未续约后法俄接近成为可能。"},{"label":"制定方/签署方","value":"德意志帝国与俄罗斯帝国。"},{"label":"主要内容","value":"德国和俄国在特定情况下保持善意中立，同时处理巴尔干和海峡相关利益；其目的在于防止俄国倒向法国。"},{"label":"它试图解决什么问题","value":"德国既与奥匈结盟，又不希望因此把俄国推给法国；俾斯麦试图同时维持德奥关系和德俄缓和。"},{"label":"为什么重要","value":"它体现俾斯麦外交体系的核心难度：德国必须避免东西两线同时出现敌人。条约不续约是德国外交安全结构的重要转折。"},{"label":"争议/局限","value":"条约与1879年德奥同盟存在潜在矛盾，操作复杂且依赖俾斯麦个人外交管理。"},{"label":"造成的影响","value":"1890年后德俄关系降温，法俄同盟逐渐形成，德国被包围的战略焦虑加深。"},{"label":"出处","value":"Encyclopaedia Britannica: Reinsurance Treaty；Deutsches Historisches Museum/LeMO: Bismarcks Bündnissystem；German History Documents and Images: Reinsurance Treaty。"}],"relationItems":["← 前因：德奥意三国同盟","→ 后果：俾斯麦辞去德意志帝国首相","→ 后果：法俄同盟","→ 后果：德国施里芬计划"],"relations":[{"text":"← 前因：德奥意三国同盟","id":"extra631"},{"text":"→ 后果：俾斯麦辞去德意志帝国首相","id":"extra633"},{"text":"→ 后果：法俄同盟","id":"extra928"},{"text":"→ 后果：德国施里芬计划","id":"extra643"}],"source":"history","id":"extra632"},{"title":"俾斯麦辞去德意志帝国首相","level":"B","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1890年3月","place":"德意志帝国，柏林","summary":"俾斯麦辞去德意志帝国首相结束了统一后德国外交的个人化均势管理，威廉二世开始推动更主动也更冒险的新路线。","fields":[{"label":"标题","value":"俾斯麦辞去德意志帝国首相"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1890年3月"},{"label":"地点","value":"德意志帝国，柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"俾斯麦辞去德意志帝国首相结束了统一后德国外交的个人化均势管理，威廉二世开始推动更主动也更冒险的新路线。"},{"label":"参与者","value":"奥托·冯·俾斯麦、威廉二世、德国政界和宫廷集团。"},{"label":"发生了什么","value":"威廉二世即位后，希望摆脱俾斯麦长期主导的政治格局，在劳工政策、反社会党人法、外交风格和宫廷权力上与俾斯麦发生冲突。俾斯麦试图继续以首相身份控制内阁和政党关系，但新皇帝不愿被旧首相约束。1890年3月，双方矛盾公开化，威廉二世迫使俾斯麦提交辞呈。俾斯麦离任后，德国政策进入“新路线”，再保险条约未续约，世界政策和海军扩张逐步上升。"},{"label":"为什么重要","value":"这是帝国政治的分水岭。德国从谨慎维持现状的俾斯麦体系，逐步转向威廉时代的德意志帝国世界政策、海军扩张和更高调的强国竞争。"},{"label":"前因","value":"威廉二世即位后希望亲自掌控政策，反社会党人法续期和对内对外路线分歧使皇帝与俾斯麦的权力冲突公开化。"},{"label":"后果","value":"俾斯麦离任后，德国外交失去原有的平衡术，再保险条约未续约，新路线和世界政策逐渐把德国带入更冒险的国际竞争。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Bismarcks Entlassung；Encyclopaedia Britannica: Otto von Bismarck；German History Documents and Images: Wilhelm II and Bismarck。"}],"relationItems":["← 前因：德意志帝国俾斯麦时代","→ 后果：德国威廉二世亲政","→ 后果：德俄再保险条约未续约","→ 后果：德意志帝国世界政策"],"relations":[{"text":"← 前因：德意志帝国俾斯麦时代","id":"extra625"},{"text":"→ 后果：德国威廉二世亲政","id":"extra634"},{"text":"→ 后果：德意志帝国世界政策","id":"extra635"}],"source":"history","id":"extra633"},{"title":"德国威廉二世亲政","level":"B","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1888年即位；1890年俾斯麦辞去德意志帝国首相后亲政色彩增强","place":"德意志帝国","summary":"德国威廉二世亲政使帝国政治更依赖皇帝个人风格，推动德国从俾斯麦式谨慎外交转向更高调的强国路线。","fields":[{"label":"标题","value":"德国威廉二世亲政"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1888年即位；1890年俾斯麦辞去德意志帝国首相后亲政色彩增强"},{"label":"地点","value":"德意志帝国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国威廉二世亲政使帝国政治更依赖皇帝个人风格，推动德国从俾斯麦式谨慎外交转向更高调的强国路线。"},{"label":"参与者","value":"威廉二世、俾斯麦、帝国官僚、军方和外交决策圈。"},{"label":"发生了什么","value":"威廉二世1888年即位时继承了由俾斯麦主导的帝国制度。1890年俾斯麦下台后，皇帝试图更直接地影响内政和外交，频繁发表公开讲话，介入人事和政策方向。继任首相与官僚体系虽然仍承担实际行政工作，但帝国政治越来越受皇帝个人声望、军方意见和宫廷圈层影响。德国由俾斯麦时期相对谨慎的均势外交，逐步转向更强调世界地位、海军力量和殖民声望的路线。"},{"label":"为什么重要","value":"威廉二世不是单独决定德国走向战争的人，但他的统治风格放大了帝国制度中皇帝、军方和外交精英不受议会充分约束的问题。"},{"label":"前因","value":"帝国宪法赋予皇帝和首相很大行政权，俾斯麦下台后，年轻的威廉二世获得把个人意志更直接转化为国家路线的空间。"},{"label":"后果","value":"德国政策重心转向世界政策、海军扩张和更高调的大国姿态，欧洲外交危机频率上升，德国同英国和法国的矛盾加深。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Wilhelm II；Encyclopaedia Britannica: William II；German History Documents and Images: Wilhelmine Germany。"}],"relationItems":["← 前因：俾斯麦辞去德意志帝国首相","→ 后果：德意志帝国世界政策","→ 后果：德意志帝国海军扩张","↔ 相关：德意志帝国宪法"],"relations":[{"text":"← 前因：俾斯麦辞去德意志帝国首相","id":"extra633"},{"text":"→ 后果：德意志帝国世界政策","id":"extra635"},{"text":"→ 后果：德意志帝国海军扩张","id":"extra636"},{"text":"↔ 相关：德意志帝国宪法","id":"extra624"}],"source":"history","id":"extra634"},{"title":"德意志帝国世界政策","level":"A","type":"概念/思潮卡","tags":["战争与外交","文化与思想"],"mainTag":"战争与外交","subTag":"文化与思想","timeText":"十九世纪九十年代后期至一战前","place":"德意志帝国与全球殖民、海权竞争场域","summary":"德意志帝国世界政策是威廉时代德国追求全球强国地位的路线，推动海军扩张、殖民竞争和与英国关系恶化。","fields":[{"label":"标题","value":"德意志帝国世界政策"},{"label":"分级","value":"A"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"十九世纪九十年代后期至一战前"},{"label":"地点","value":"德意志帝国与全球殖民、海权竞争场域"},{"label":"主要国家","value":"德国、英国、法国、俄国、奥匈帝国"},{"label":"一句话概括","value":"德意志帝国世界政策是威廉时代德国追求全球强国地位的路线，推动海军扩张、殖民竞争和与英国关系恶化。"},{"label":"核心主张/思路","value":"德国不能只做欧洲大陆强国，还应获得殖民地、海军、海外市场和世界政治发言权。"},{"label":"提出者/代表人物（可选）","value":"威廉二世、伯恩哈德·冯·比洛、阿尔弗雷德·冯·提尔皮茨。"},{"label":"它从何而来","value":"德国统一后工业迅速扩张，但海外帝国和海上力量落后于英国、法国等老牌列强；国内民族主义也要求“Ein Platz an der Sonne”。"},{"label":"典型表现","value":"海军法、殖民政策、巴格达铁路、摩洛哥危机、对外强硬姿态。"},{"label":"为什么重要","value":"德意志帝国世界政策把德国安全问题从欧洲均势扩展到全球竞争，使德国与英国的矛盾迅速上升。"},{"label":"争议/局限","value":"它追求声望和影响力，却缺乏清晰可持续的战略边界，容易制造多线对立。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Weltpolitik；German History Documents and Images: Weltpolitik；Encyclopaedia Britannica: William II。"}],"relationItems":["← 前因：德国威廉二世亲政","← 前因：“Ein Platz an der Sonne”","→ 后果：德意志帝国海军扩张","→ 后果：德意志帝国英德海军竞赛","→ 后果：第一次摩洛哥危机"],"relations":[{"text":"← 前因：德国威廉二世亲政","id":"extra634"},{"text":"← 前因：“Ein Platz an der Sonne”","id":"proverb2"},{"text":"→ 后果：德意志帝国海军扩张","id":"extra636"},{"text":"→ 后果：德意志帝国英德海军竞赛","id":"extra637"},{"text":"→ 后果：第一次摩洛哥危机","id":"extra638"}],"source":"history","id":"extra635"},{"title":"德意志帝国海军扩张","level":"B","type":"事件卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1898年和1900年海军法后加速","place":"德意志帝国、北海和全球海权竞争场域","summary":"德意志帝国海军扩张试图把德国变成世界海权强国，却直接触动英国安全核心，加速英德关系恶化。","fields":[{"label":"标题","value":"德意志帝国海军扩张"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1898年和1900年海军法后加速"},{"label":"地点","value":"德意志帝国、北海和全球海权竞争场域"},{"label":"主要国家","value":"德国、英国"},{"label":"一句话概括","value":"德意志帝国海军扩张试图把德国变成世界海权强国，却直接触动英国安全核心，加速英德关系恶化。"},{"label":"参与者","value":"威廉二世、海军国务秘书提尔皮茨、帝国议会、德国海军协会、英国海军和政府。"},{"label":"发生了什么","value":"1890年代后，威廉二世和海军国务秘书提尔皮茨推动德国从大陆强国转向海权强国。1898年和1900年海军法确立大规模战列舰建造计划，海军协会和民族主义宣传把舰队建设塑造成国家荣誉工程。德国的目标不是立即击败英国，而是建立足以让英国在战争中承受高风险的“风险舰队”。随着无畏舰时代到来，两国造舰竞争升级，德国海军预算和工业资源被长期绑定到海权竞争中。"},{"label":"为什么重要","value":"它是德意志帝国世界政策最具体、最危险的执行形式。德国原本最需要避免英国加入反德阵营，但海军扩张反而把英国推向法国和俄国。"},{"label":"前因","value":"德国工业实力增强和世界政策野心上升后，威廉二世和提尔皮茨把远洋舰队视为争取世界地位、威慑英国和保护殖民贸易的工具。"},{"label":"后果","value":"海军建设直接触动英国海权安全底线，英德海军竞赛加速，英国更愿意同法国和俄国协调，德国的被包围感也随之增强。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Flottenpolitik；German History Documents and Images: German Naval Laws；Encyclopaedia Britannica: Alfred von Tirpitz。"}],"relationItems":["← 前因：德意志帝国世界政策","→ 后果：德意志帝国英德海军竞赛","↔ 相关：阿尔弗雷德·冯·提尔皮茨","↔ 相关：“Ein Platz an der Sonne”"],"relations":[{"text":"← 前因：德意志帝国世界政策","id":"extra635"},{"text":"→ 后果：德意志帝国英德海军竞赛","id":"extra637"},{"text":"↔ 相关：阿尔弗雷德·冯·提尔皮茨","id":"extra776"},{"text":"↔ 相关：“Ein Platz an der Sonne”","id":"proverb2"}],"source":"history","id":"extra636"},{"title":"德意志帝国英德海军竞赛","level":"A","type":"事件卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"约1898年至1914年","place":"北海、英国和德国海军政策场域","summary":"英德海军竞赛把德国德意志帝国世界政策变成英国的直接安全威胁，是一战前英德关系恶化的核心因素。","fields":[{"label":"标题","value":"德意志帝国英德海军竞赛"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"约1898年至1914年"},{"label":"地点","value":"北海、英国和德国海军政策场域"},{"label":"主要国家","value":"英国、德国"},{"label":"一句话概括","value":"英德海军竞赛把德国德意志帝国世界政策变成英国的直接安全威胁，是一战前英德关系恶化的核心因素。"},{"label":"参与者","value":"德国政府与海军、英国政府与皇家海军、提尔皮茨、威廉二世。"},{"label":"发生了什么","value":"德国海军法启动后，英国把德国战列舰队视为对北海和本土安全的直接挑战。英国原本奉行“两强标准”，要求皇家海军强于任意两个潜在对手，德国扩舰迫使英国调整造舰和外交政策。1906年英国无畏舰下水后，旧战舰价值下降，双方围绕新式主力舰数量展开竞争。德国继续推进造舰，英国则加速建造并强化同法国、俄国的战略协调。竞赛没有直接导致战争，但显著恶化英德互信。"},{"label":"为什么重要","value":"英国传统上避免欧洲大陆单一强权控制海岸和海上通道。德意志帝国海军扩张使英国从潜在旁观者变成越来越明确的德国制衡者。"},{"label":"前因","value":"德国海军扩张挑战英国传统制海优势，世界政策又让英国认为德国不只是欧洲陆上强国，而是在全球范围内争夺战略空间。"},{"label":"后果","value":"竞赛推动英国加强同法国和俄国的协约合作，使欧洲阵营更清晰；德国投入巨额海军资源，却未能换来真正的外交安全。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Flottenpolitik；Encyclopaedia Britannica: Anglo-German naval rivalry；German History Documents and Images: Navalism。"}],"relationItems":["← 前因：德意志帝国海军扩张","→ 后果：1904年英法协约","→ 后果：1907年英俄协约","→ 后果：第一次世界大战爆发","↔ 相关：无畏舰革命"],"relations":[{"text":"← 前因：德意志帝国海军扩张","id":"extra636"},{"text":"→ 后果：1904年英法协约","id":"extra782"},{"text":"→ 后果：1907年英俄协约","id":"extra785"},{"text":"→ 后果：第一次世界大战爆发","id":"extra925"}],"source":"history","id":"extra637"},{"title":"第一次摩洛哥危机","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1905年至1906年","place":"摩洛哥、丹吉尔、阿尔赫西拉斯会议","summary":"第一次摩洛哥危机中德国挑战法国在摩洛哥的扩张，结果未能拆散1904年英法协约，反而暴露自身外交孤立。","fields":[{"label":"标题","value":"第一次摩洛哥危机"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1905年至1906年"},{"label":"地点","value":"摩洛哥、丹吉尔、阿尔赫西拉斯会议"},{"label":"主要国家","value":"德国、法国、英国、摩洛哥、西班牙"},{"label":"一句话概括","value":"第一次摩洛哥危机中德国挑战法国在摩洛哥的扩张，结果未能拆散1904年英法协约，反而暴露自身外交孤立。"},{"label":"参与者","value":"威廉二世、德国政府、法国政府、英国政府、摩洛哥苏丹及列强代表。"},{"label":"发生了什么","value":"1904年英法协约后，法国在摩洛哥影响力扩大。德国担心被排除在殖民和外交安排之外，也希望测试1904年英法协约是否牢固。1905年威廉二世访问丹吉尔，公开支持摩洛哥苏丹独立，要求召开国际会议。1906年阿尔赫西拉斯会议上，多数列强支持法国和英国立场，德国只获得有限外交成果。危机的结果不是拆散1904年英法协约，而是让德国外交孤立更加明显。"},{"label":"为什么重要","value":"德国希望测试并削弱1904年英法协约，却得到相反结果：英法合作更紧，德国更显孤立。"},{"label":"前因","value":"1904年英法协约后法国在摩洛哥扩大影响，德国试图检验英法关系并阻止法国单方面改变北非格局。"},{"label":"后果","value":"阿尔赫西拉斯会议没有达到德国分化英法的目标，反而让英法合作更紧密，也为1911年第二次摩洛哥危机留下对抗惯性。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Marokkokrisen；Encyclopaedia Britannica: Moroccan crises；1914-1918 Online相关外交危机资料。"}],"relationItems":["← 前因：德意志帝国世界政策","→ 后果：第二次摩洛哥危机","↔ 相关：1904年英法协约"],"relations":[{"text":"← 前因：德意志帝国世界政策","id":"extra635"},{"text":"→ 后果：第二次摩洛哥危机","id":"extra639"},{"text":"↔ 相关：1904年英法协约","id":"extra782"}],"source":"history","id":"extra638"},{"title":"第二次摩洛哥危机","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1911年","place":"摩洛哥阿加迪尔及欧洲外交场域","summary":"第二次摩洛哥危机中德国派军舰到阿加迪尔施压法国，进一步激化英德关系并强化协约国合作。","fields":[{"label":"标题","value":"第二次摩洛哥危机"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1911年"},{"label":"地点","value":"摩洛哥阿加迪尔及欧洲外交场域"},{"label":"主要国家","value":"德国、法国、英国、摩洛哥"},{"label":"一句话概括","value":"第二次摩洛哥危机中德国派军舰到阿加迪尔施压法国，进一步激化英德关系并强化协约国合作。"},{"label":"参与者","value":"德国政府、法国政府、英国政府、摩洛哥当局、德国炮舰“豹”号。"},{"label":"发生了什么","value":"1911年摩洛哥内部局势动荡，法国派兵进入非斯并扩大控制。德国认为法国正在改变摩洛哥地位，派炮舰“豹”号前往阿加迪尔，以施压法国并争取殖民补偿。英国担心德国可能在大西洋获得海军据点，强烈警告德国。最终法德达成妥协，法国取得对摩洛哥的保护权，德国获得部分刚果地区补偿。危机表面结束，但英德关系进一步恶化。"},{"label":"为什么重要","value":"它再次证明德国强硬外交难以拆散协约，反而让英国更坚定地把德国视为主要威胁。"},{"label":"前因","value":"第一次摩洛哥危机后德国仍想挑战法国在摩洛哥的扩张，法国军事行动和德意志帝国世界政策压力使危机再次升级。"},{"label":"后果","value":"德国虽得到部分殖民补偿，却在外交上更显孤立；英国对德国意图更警惕，英法军事合作的现实意义进一步增强。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Marokkokrisen；Encyclopaedia Britannica: Agadir Incident；German History Documents and Images: Moroccan Crises。"}],"relationItems":["← 前因：第一次摩洛哥危机","→ 后果：英法军事合作","→ 后果：第一次世界大战爆发","↔ 相关：德意志帝国世界政策"],"relations":[{"text":"← 前因：第一次摩洛哥危机","id":"extra638"},{"text":"→ 后果：第一次世界大战爆发","id":"extra925"},{"text":"↔ 相关：德意志帝国世界政策","id":"extra635"}],"source":"history","id":"extra639"},{"title":"奥斯曼巴格达铁路","level":"B","type":"事件卡","tags":["经济与社会","战争与外交"],"mainTag":"经济与社会","subTag":"战争与外交","timeText":"十九世纪末至二十世纪初持续推进","place":"奥斯曼帝国境内，连接安纳托利亚至美索不达米亚方向","summary":"巴格达铁路连接奥斯曼现代化、德国资本输出和列强中东竞争，是一战前欧亚战略紧张的重要焦点。","fields":[{"label":"标题","value":"奥斯曼巴格达铁路"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"十九世纪末至二十世纪初持续推进"},{"label":"地点","value":"奥斯曼帝国境内，连接安纳托利亚至美索不达米亚方向"},{"label":"主要国家","value":"德国、奥斯曼帝国、英国、俄国、法国"},{"label":"一句话概括","value":"巴格达铁路连接奥斯曼现代化、德国资本输出和列强中东竞争，是一战前欧亚战略紧张的重要焦点。"},{"label":"参与者","value":"奥斯曼政府、德国银行和工程企业、德国政府、英国和俄国外交决策者。"},{"label":"发生了什么","value":"奥斯曼帝国希望通过铁路建设加强对安纳托利亚和美索不达米亚方向的行政、军事和经济联系。十九世纪末起，德国银行、工程企业和政府力量深度参与从安纳托利亚通往巴格达方向的铁路项目。铁路建设提升了德国在奥斯曼帝国的影响力，也让英国、俄国和法国担心德国借此进入中东、波斯湾和通向印度的战略空间。项目在技术上是基础设施工程，在政治上则成为列强围绕奥斯曼遗产和欧亚通道竞争的焦点。"},{"label":"为什么重要","value":"它说明德国德意志帝国世界政策不只体现在海军和殖民地，也通过基础设施和资本输出进入欧亚战略竞争。"},{"label":"前因","value":"德意志帝国世界政策、德国资本对海外市场的兴趣以及德奥同奥斯曼关系升温，使连接欧洲和中东的铁路计划具有经济和战略双重意义。"},{"label":"后果","value":"铁路计划加深英国、俄国等列强对德国中东意图的疑虑，也为一战中德国、奥匈和奥斯曼帝国的战略靠近提供了背景。"},{"label":"出处","value":"Encyclopaedia Britannica: Baghdad Railway；1914-1918 Online: Baghdad Railway；German History Documents and Images相关资料。"}],"relationItems":["← 前因：德意志帝国世界政策","→ 后果：德国与奥斯曼帝国结盟","↔ 相关：德意志帝国海军扩张","↔ 相关：奥斯曼帝国现代化"],"relations":[{"text":"← 前因：德意志帝国世界政策","id":"extra635"},{"text":"↔ 相关：德意志帝国海军扩张","id":"extra636"}],"source":"history","id":"extra640"},{"title":"德意志殖民帝国","level":"B","type":"组织/机构卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1884年至1919年","place":"非洲、太平洋和中国胶州湾等地","summary":"德意志殖民帝国是德国较晚参与帝国主义瓜分世界的产物，规模不如英法，却深刻体现威廉时代世界地位焦虑。","fields":[{"label":"标题","value":"德意志殖民帝国"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1884年至1919年"},{"label":"地点","value":"非洲、太平洋和中国胶州湾等地"},{"label":"主要国家","value":"德国、纳米比亚、坦桑尼亚、喀麦隆、多哥、中国、巴布亚新几内亚"},{"label":"一句话概括","value":"德意志殖民帝国是德国较晚参与帝国主义瓜分世界的产物，规模不如英法，却深刻体现威廉时代世界地位焦虑。"},{"label":"性质/类型","value":"海外殖民统治体系。"},{"label":"成立/解散时间","value":"1884年后德国正式取得多处殖民地；一战失败后根据凡尔赛体系失去殖民地。"},{"label":"核心目标/宗旨","value":"获取海外市场、资源、战略据点和国际声望，同时满足国内殖民主义与民族主义团体对世界强国地位的期待。"},{"label":"关键人物（可选）","value":"俾斯麦、威廉二世、殖民协会和殖民官员。"},{"label":"关键行动/事件","value":"德国取得德属西南非洲、德属东非、喀麦隆、多哥、太平洋岛屿和胶州湾租借地等殖民地。"},{"label":"为什么重要","value":"殖民帝国不是德国实力的核心来源，却是德意志帝国世界政策和民族主义想象的重要象征，也造成殖民地暴力统治和种族压迫。"},{"label":"争议/局限","value":"德国殖民体系成本高、收益有限，并伴随强制劳动、土地掠夺和军事镇压。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Deutsche Kolonien；Encyclopaedia Britannica: German colonial empire；German History Documents and Images: German Colonialism。"}],"relationItems":["← 前因：德意志帝国世界政策","→ 后果：德属西南非洲赫雷罗和纳马种族灭绝","→ 后果：《凡尔赛和约》","↔ 相关：“Ein Platz an der Sonne”"],"relations":[{"text":"← 前因：德意志帝国世界政策","id":"extra635"},{"text":"→ 后果：德属西南非洲赫雷罗和纳马种族灭绝","id":"extra642"},{"text":"→ 后果：《凡尔赛和约》","id":"card59"},{"text":"↔ 相关：“Ein Platz an der Sonne”","id":"proverb2"}],"source":"history","id":"extra641"},{"title":"德属西南非洲赫雷罗和纳马种族灭绝","level":"B","type":"事件卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1904年至1908年","place":"德属西南非洲","summary":"德属西南非洲对赫雷罗和纳马人的灭绝性镇压，是德国殖民暴力的极端表现，也常被视为二十世纪早期种族灭绝案例。","fields":[{"label":"标题","value":"德属西南非洲赫雷罗和纳马种族灭绝"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1904年至1908年"},{"label":"地点","value":"德属西南非洲"},{"label":"主要国家","value":"德国、纳米比亚"},{"label":"一句话概括","value":"德属西南非洲对赫雷罗和纳马人的灭绝性镇压，是德国殖民暴力的极端表现，也常被视为二十世纪早期种族灭绝案例。"},{"label":"参与者","value":"德国殖民军、洛塔尔·冯·特罗塔、赫雷罗人、纳马人。"},{"label":"发生了什么","value":"德属西南非洲殖民统治中，德国殖民者持续夺取土地、牲畜和劳动力，赫雷罗人与纳马人先后发动反抗。德国派遣殖民军镇压，洛塔尔·冯·特罗塔发布极端命令，试图把赫雷罗人驱逐到沙漠并阻止其返回水源。幸存者被关入集中营和强制劳动体系，大量人口死于饥饿、疾病、虐待和处决。纳马人的抵抗也遭到类似镇压。该事件后来成为德国殖民罪责争议的核心。"},{"label":"为什么重要","value":"它打破了把德国殖民史视为边缘事件的叙事，显示种族主义、军事暴力和殖民统治在帝国时期已经高度结合。"},{"label":"前因","value":"德国殖民统治夺取土地、牲畜和劳动力，殖民行政与定居者暴力不断压缩赫雷罗和纳马人的生存空间，最终引发反抗。"},{"label":"后果","value":"赫雷罗和纳马社会遭受毁灭性打击，德国殖民暴力成为二十世纪种族灭绝史和当代赔偿争议的重要案例。"},{"label":"出处","value":"Encyclopaedia Britannica: Herero and Nama genocide；United States Holocaust Memorial Museum相关资料；Deutsches Historisches Museum/LeMO: Kolonialkrieg in Deutsch-Südwestafrika。"},{"label":"资料备注","value":"死亡人数存在统计差异，卡片避免写死单一数字，重点保留事件性质和机制。"}],"relationItems":["← 前因：德意志殖民帝国","↔ 相关：德意志帝国世界政策","→ 后果：德国殖民罪责争议"],"relations":[{"text":"← 前因：德意志殖民帝国","id":"extra641"},{"text":"↔ 相关：德意志帝国世界政策","id":"extra635"}],"source":"history","id":"extra642"},{"title":"德国施里芬计划","level":"A","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1905年前后形成，1914年德军动员作战计划受其影响","place":"德国总参谋部；作战设想涉及法国、比利时和俄国","summary":"德国施里芬计划试图通过先击败法国再转向俄国解决两线战争问题，却把德国战略与侵犯比利时中立绑定在一起。","fields":[{"label":"标题","value":"德国施里芬计划"},{"label":"分级","value":"A"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1905年前后形成，1914年德军动员作战计划受其影响"},{"label":"地点","value":"德国总参谋部；作战设想涉及法国、比利时和俄国"},{"label":"主要国家","value":"德国、法国、比利时、俄国"},{"label":"一句话概括","value":"德国施里芬计划试图通过先击败法国再转向俄国解决两线战争问题，却把德国战略与侵犯比利时中立绑定在一起。"},{"label":"制定方/签署方","value":"德国总参谋部，常与总参谋长阿尔弗雷德·冯·施里芬相关。"},{"label":"主要内容","value":"在两线战争预期下，德国计划集中主力经比利时方向快速包抄法国，争取短期内击败法国，再把兵力转向东线对付俄国。"},{"label":"它试图解决什么问题","value":"法俄同盟使德国面临东西两线战争风险。德国军事计划试图用速度和铁路动员弥补战略位置劣势。"},{"label":"为什么重要","value":"它把外交危机转化为军事时间表问题。一旦动员开始，德国决策空间急剧缩小，并因侵犯比利时中立促使英国参战。"},{"label":"争议/局限","value":"历史学界对“原始德国施里芬计划”与1914年实际作战计划关系有争论；卡片采用稳妥表述，不把两者完全等同。"},{"label":"造成的影响","value":"1914年德国进攻比利时和法国，西线战争未能快速结束，欧洲战争演变为长期消耗战。"},{"label":"出处","value":"Encyclopaedia Britannica: Schlieffen Plan；1914-1918 Online: Schlieffen Plan；German History Documents and Images相关资料。"},{"label":"资料备注","value":"计划名称常用于概括德国两线战争设想，但1914年实际计划经过小毛奇调整。"}],"relationItems":["← 前因：法俄同盟","← 前因：德俄再保险条约","→ 后果：德国入侵比利时","→ 后果：第一次世界大战爆发","↔ 相关：德国总参谋部"],"relations":[{"text":"← 前因：法俄同盟","id":"extra928"},{"text":"← 前因：德俄再保险条约","id":"extra632"},{"text":"→ 后果：德国入侵比利时","id":"extra647"},{"text":"→ 后果：第一次世界大战爆发","id":"extra925"}],"source":"history","id":"extra643"},{"title":"萨拉热窝刺杀事件","level":"S","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1914年6月28日","place":"波斯尼亚萨拉热窝","summary":"萨拉热窝刺杀事件刺杀奥匈皇储，引发奥匈对塞尔维亚摊牌，并迅速触发一战前欧洲同盟体系连锁反应。","fields":[{"label":"标题","value":"萨拉热窝刺杀事件"},{"label":"分级","value":"S"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1914年6月28日"},{"label":"地点","value":"波斯尼亚萨拉热窝"},{"label":"主要国家","value":"奥匈帝国、塞尔维亚、德国、俄国"},{"label":"一句话概括","value":"萨拉热窝刺杀事件刺杀奥匈皇储，引发奥匈对塞尔维亚摊牌，并迅速触发一战前欧洲同盟体系连锁反应。"},{"label":"参与者","value":"弗朗茨·斐迪南大公、索菲公爵夫人、加夫里洛·普林西普、青年波斯尼亚成员、奥匈政府。"},{"label":"发生了什么","value":"1914年6月28日，奥匈皇储弗朗茨·斐迪南访问波斯尼亚首府萨拉热窝。当地南斯拉夫民族主义青年组织成员计划刺杀，以反抗奥匈对波斯尼亚的统治。当天第一次炸弹袭击未能杀死皇储，行程调整后，普林西普在街头近距离开枪，杀死皇储和索菲公爵夫人。奥匈政府随后将刺杀视为打击塞尔维亚民族主义的机会，要求德国支持，并把事件推向国际危机。"},{"label":"为什么重要","value":"刺杀本身不是一战唯一原因，但它是1914年七月危机的直接导火索，把巴尔干民族主义、奥塞冲突、1879年德奥同盟、俄国保护斯拉夫人的姿态和欧洲军事计划全部连在一起。"},{"label":"前因","value":"奥匈吞并波斯尼亚后南斯拉夫民族主义和塞尔维亚问题持续激化，巴尔干危机使奥匈与塞尔维亚之间的矛盾高度军事化。"},{"label":"后果","value":"奥匈把刺杀视为打击塞尔维亚的机会，德国提供空白支票后，局部危机被同盟体系和动员机制放大为欧洲战争。"},{"label":"出处","value":"Encyclopaedia Britannica: Assassination of Archduke Franz Ferdinand；1914-1918 Online: Sarajevo Assassination；Deutsches Historisches Museum/LeMO: Attentat von Sarajevo。"}],"relationItems":["← 前因：奥匈吞并波斯尼亚危机","→ 后果：1914年七月危机","→ 后果：德国对奥匈的“空白支票”保证","→ 后果：第一次世界大战爆发"],"relations":[{"text":"← 前因：奥匈吞并波斯尼亚危机","id":"extra787"},{"text":"→ 后果：1914年七月危机","id":"extra646"},{"text":"→ 后果：德国对奥匈的“空白支票”保证","id":"extra645"},{"text":"→ 后果：第一次世界大战爆发","id":"extra925"}],"source":"history","id":"extra644"},{"title":"德国对奥匈的“空白支票”保证","level":"A","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1914年7月5日至6日","place":"柏林与维也纳之间的外交沟通","summary":"德国向奥匈提供“空白支票”支持，使奥匈更敢于对塞尔维亚强硬行动，是1914年七月危机升级的关键节点。","fields":[{"label":"标题","value":"德国对奥匈的“空白支票”保证"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1914年7月5日至6日"},{"label":"地点","value":"柏林与维也纳之间的外交沟通"},{"label":"主要国家","value":"德国、奥匈帝国、塞尔维亚、俄国"},{"label":"一句话概括","value":"德国向奥匈提供“空白支票”支持，使奥匈更敢于对塞尔维亚强硬行动，是1914年七月危机升级的关键节点。"},{"label":"参与者","value":"德皇威廉二世、德国政府、奥匈政府、贝希托尔德等奥匈决策者。"},{"label":"发生了什么","value":"萨拉热窝刺杀后，奥匈领导层希望惩罚塞尔维亚，但担心俄国干预。1914年7月初，奥匈派代表到柏林寻求德国立场。威廉二世和德国政府表示支持奥匈采取强硬行动，即使危机扩大也会站在盟友一边。这种支持没有规定清晰边界，因此被称为“空白支票”。得到德国支持后，奥匈更有信心向塞尔维亚发出严厉最后通牒，七月危机随之升级。"},{"label":"为什么重要","value":"它不是一战爆发的唯一原因，但显著降低了奥匈采取军事摊牌的顾虑，改变了危机计算。德国由此承担了推动危机升级的重要责任。"},{"label":"前因","value":"萨拉热窝刺杀后奥匈寻求德国支持，德国决策层担心俄法包围和奥匈盟友衰弱，因而鼓励维也纳采取强硬路线。"},{"label":"后果","value":"奥匈得到德国支持后向塞尔维亚发出严厉最后通牒，七月危机升级空间被扩大，欧洲大国最终被卷入第一次世界大战。"},{"label":"出处","value":"1914-1918 Online: July Crisis；Deutsches Historisches Museum/LeMO: Julikrise；Encyclopaedia Britannica: July Crisis。"},{"label":"资料备注","value":"“空白支票”是后世概括性称呼，指德国给予奥匈较宽泛支持，并非正式文件标题。"}],"relationItems":["← 前因：萨拉热窝刺杀事件","→ 后果：1914年七月危机","→ 后果：第一次世界大战爆发","↔ 相关：1879年德奥同盟"],"relations":[{"text":"← 前因：萨拉热窝刺杀事件","id":"extra644"},{"text":"→ 后果：1914年七月危机","id":"extra646"},{"text":"→ 后果：第一次世界大战爆发","id":"extra925"},{"text":"↔ 相关：1879年德奥同盟","id":"extra755"}],"source":"history","id":"extra645"},{"title":"1914年七月危机","level":"S","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1914年6月28日至8月初","place":"欧洲列强外交和军事动员体系","summary":"1914年七月危机把萨拉热窝刺杀转化为欧洲大战，暴露出同盟体系、军事计划和强国误判如何共同失控。","fields":[{"label":"标题","value":"1914年七月危机"},{"label":"分级","value":"S"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1914年6月28日至8月初"},{"label":"地点","value":"欧洲列强外交和军事动员体系"},{"label":"主要国家","value":"奥匈帝国、塞尔维亚、德国、俄国、法国、英国"},{"label":"一句话概括","value":"1914年七月危机把萨拉热窝刺杀转化为欧洲大战，暴露出同盟体系、军事计划和强国误判如何共同失控。"},{"label":"参与者","value":"奥匈、塞尔维亚、德国、俄国、法国、英国及各国君主、内阁、外交官和总参谋部。"},{"label":"发生了什么","value":"萨拉热窝刺杀后，奥匈在德国支持下准备对塞尔维亚摊牌。7月23日，奥匈向塞尔维亚发出严厉最后通牒，塞尔维亚接受多数条款但拒绝部分损害主权的要求。奥匈随后宣战，俄国开始动员支持塞尔维亚。德国要求俄国停止动员并向法国施压，随后对俄、法宣战。德国按军事计划入侵比利时，英国因此参战。短短数周内，巴尔干危机转化为欧洲大战。"},{"label":"为什么重要","value":"1914年七月危机是一战爆发机制的核心。它显示战争不是单一刺杀自动导致，而是由最后通牒、同盟义务、动员时间表、战略恐惧和外交误判逐步推出来的。"},{"label":"前因","value":"萨拉热窝刺杀引发奥塞冲突，德国空白支票、俄国保护塞尔维亚、法国同俄国同盟以及各国军事计划相互叠加，使外交危机迅速失控。"},{"label":"后果","value":"危机以全面战争收场，德国入侵比利时触发英国参战，欧洲由大国威慑体系滑入总体战。"},{"label":"出处","value":"1914-1918 Online: July Crisis；Encyclopaedia Britannica: July Crisis；Deutsches Historisches Museum/LeMO: Erster Weltkrieg Vorgeschichte。"}],"relationItems":["← 前因：萨拉热窝刺杀事件","← 前因：德国对奥匈的“空白支票”保证","← 前因：德国施里芬计划","→ 后果：第一次世界大战爆发","→ 后果：德国入侵比利时"],"relations":[{"text":"← 前因：萨拉热窝刺杀事件","id":"extra644"},{"text":"← 前因：德国对奥匈的“空白支票”保证","id":"extra645"},{"text":"← 前因：德国施里芬计划","id":"extra643"},{"text":"→ 后果：第一次世界大战爆发","id":"extra925"},{"text":"→ 后果：德国入侵比利时","id":"extra647"}],"source":"history","id":"extra646"},{"title":"德国入侵比利时","level":"A","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1914年8月4日开始","place":"比利时","summary":"德国为执行西线速胜计划入侵中立比利时，直接促使英国对德宣战，使欧洲战争迅速扩大。","fields":[{"label":"标题","value":"德国入侵比利时"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1914年8月4日开始"},{"label":"地点","value":"比利时"},{"label":"主要国家","value":"德国、比利时、英国、法国"},{"label":"一句话概括","value":"德国为执行西线速胜计划入侵中立比利时，直接促使英国对德宣战，使欧洲战争迅速扩大。"},{"label":"参与者","value":"德意志帝国、比利时王国、英国、法国。"},{"label":"发生了什么","value":"1914年8月，德国为快速击败法国，要求中立比利时允许德军过境。比利时拒绝后，德国军队越境进攻，围攻列日等要塞并向法国北部推进。比利时军队抵抗延缓了德军时间表，德国在占领过程中实施报复和暴力，制造难民潮和国际舆论冲击。英国以维护比利时中立和欧洲均势为理由对德国宣战，西线战争随即扩大。"},{"label":"为什么重要","value":"它把德国军事计划与国际法和英国安全承诺直接冲突起来，使战争从大陆冲突升级为包括英国帝国在内的大战。"},{"label":"前因","value":"德国施里芬计划要求通过中立比利时快速击败法国，七月危机全面升级后，德国把军事时间表置于国际法和外交后果之上。"},{"label":"后果","value":"英国以维护比利时中立和欧洲均势为理由参战，战争范围扩大；德国在比利时的占领也造成严重国际舆论后果。"},{"label":"出处","value":"1914-1918 Online: Belgium；Encyclopaedia Britannica: World War I；Deutsches Historisches Museum/LeMO: Erster Weltkrieg。"}],"relationItems":["← 前因：德国施里芬计划","← 前因：1914年七月危机","→ 后果：英国参加第一次世界大战","→ 后果：第一次马恩河战役"],"relations":[{"text":"← 前因：德国施里芬计划","id":"extra643"},{"text":"← 前因：1914年七月危机","id":"extra646"},{"text":"→ 后果：英国参加第一次世界大战","id":"extra648"},{"text":"→ 后果：第一次马恩河战役","id":"extra650"}],"source":"history","id":"extra647"},{"title":"英国参加第一次世界大战","level":"A","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1914年8月4日","place":"英国、比利时、欧洲外交体系","summary":"英国因德国侵犯比利时中立并担忧欧洲均势被打破而参战，使一战真正成为全球帝国战争。","fields":[{"label":"标题","value":"英国参加第一次世界大战"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1914年8月4日"},{"label":"地点","value":"英国、比利时、欧洲外交体系"},{"label":"主要国家","value":"英国、德国、比利时、法国"},{"label":"一句话概括","value":"英国因德国侵犯比利时中立并担忧欧洲均势被打破而参战，使一战真正成为全球帝国战争。"},{"label":"参与者","value":"英国政府、德意志帝国、比利时、法国。"},{"label":"发生了什么","value":"德国入侵比利时后，英国政府召开紧急决策，认为比利时中立被破坏且法国海岸安全受到威胁。1914年8月4日，英国向德国发出最后通牒，要求停止侵犯比利时。德国未接受后，英国对德宣战。英国远征军被派往法国，皇家海军开始执行海上控制和封锁，英国帝国各自治领和殖民地也逐步卷入战争。"},{"label":"为什么重要","value":"英国参战使德国面对更强大的海上封锁和全球资源压力，也把加拿大、澳大利亚、印度等帝国资源带入战争。"},{"label":"前因","value":"德国入侵比利时触动英国对低地国家安全和欧洲均势的核心关切，1904年英法协约和海军竞争也让英国难以接受德国支配西欧。"},{"label":"后果","value":"英国参战带来全球海军、殖民地和金融资源，海上封锁逐渐压缩德国经济，并使战争从欧洲大陆冲突扩展为全球战争。"},{"label":"出处","value":"Encyclopaedia Britannica: World War I；UK Parliament/Imperial War Museums相关资料；1914-1918 Online: Great Britain。"}],"relationItems":["← 前因：德国入侵比利时","← 前因：德意志帝国英德海军竞赛","→ 后果：英国对德海上封锁","→ 后果：第一次世界大战全球化"],"relations":[{"text":"← 前因：德国入侵比利时","id":"extra647"},{"text":"← 前因：德意志帝国英德海军竞赛","id":"extra637"},{"text":"→ 后果：英国对德海上封锁","id":"extra652"},{"text":"→ 后果：第一次世界大战全球化","id":"extra953"}],"source":"history","id":"extra648"},{"title":"一战东线坦能堡战役","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1914年8月26日至30日","place":"东普鲁士","summary":"坦能堡战役中德军重创俄军第二集团军，稳定了东线局势，也造就兴登堡和鲁登道夫的军事声望。","fields":[{"label":"标题","value":"一战东线坦能堡战役"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1914年8月26日至30日"},{"label":"地点","value":"东普鲁士"},{"label":"主要国家","value":"德国、俄国"},{"label":"一句话概括","value":"坦能堡战役中德军重创俄军第二集团军，稳定了东线局势，也造就兴登堡和鲁登道夫的军事声望。"},{"label":"参与者","value":"德军第八集团军、俄军第二集团军、兴登堡、鲁登道夫、萨姆索诺夫。"},{"label":"发生了什么","value":"战争初期，俄国比德国预期更快动员，并从东线进攻东普鲁士。德军第八集团军在兴登堡和鲁登道夫指挥下，利用截获通信、铁路调动和俄军两支部队协调不良的弱点，集中兵力攻击俄军第二集团军。8月底，德军在坦能堡附近完成包围并歼灭大部俄军，俄军司令萨姆索诺夫自杀。战役稳定了德国东线，并成为德国国内宣传中的重大胜利。"},{"label":"为什么重要","value":"它缓解德国东线压力，成为德国国内宣传中的巨大胜利，也让兴登堡和鲁登道夫进入帝国权力中心。"},{"label":"前因","value":"俄国快速动员迫使德国在施里芬计划尚未完成时面对东线压力，德国东线兵力有限但依靠铁路调动和情报判断集中反击。"},{"label":"后果","value":"俄军惨败稳定了德国东线局势，兴登堡和鲁登道夫由此成为民族英雄，东线战争也进一步长期化。"},{"label":"出处","value":"Encyclopaedia Britannica: Battle of Tannenberg；1914-1918 Online: Eastern Front；Deutsches Historisches Museum/LeMO相关资料。"}],"relationItems":["← 前因：1914年七月危机","→ 后果：兴登堡和鲁登道夫崛起","↔ 相关：德国施里芬计划"],"relations":[{"text":"← 前因：1914年七月危机","id":"extra646"},{"text":"→ 后果：兴登堡和鲁登道夫崛起","id":"extra938"},{"text":"↔ 相关：德国施里芬计划","id":"extra643"}],"source":"history","id":"extra649"},{"title":"第一次马恩河战役","level":"A","type":"事件卡","tags":["战争与外交","无"],"mainTag":"战争与外交","subTag":"无","timeText":"1914年9月5日至12日","place":"法国马恩河地区","summary":"第一次马恩河战役阻止德军快速击败法国，宣告西线速胜计划破产，堑壕战和长期消耗战随之形成。","fields":[{"label":"标题","value":"第一次马恩河战役"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"无"},{"label":"时间","value":"1914年9月5日至12日"},{"label":"地点","value":"法国马恩河地区"},{"label":"主要国家","value":"法国、德国、英国"},{"label":"一句话概括","value":"第一次马恩河战役阻止德军快速击败法国，宣告西线速胜计划破产，堑壕战和长期消耗战随之形成。"},{"label":"参与者","value":"法国军队、英国远征军、德国军队。"},{"label":"发生了什么","value":"德军经比利时和法国北部快速推进，逼近巴黎。法军总司令霞飞调整部队，巴黎军政当局也调集兵力参与防御，英军远征军重新加入反击。1914年9月，法英军在马恩河地区攻击德军右翼和中路间隙，迫使德军后撤到埃纳河一线。双方随后试图向北包抄对方，形成“奔向大海”，最终西线固定为漫长堑壕线。"},{"label":"为什么重要","value":"它是战争性质变化的节点。德国无法迅速结束西线战争，两线战争和长期消耗成为现实。"},{"label":"前因","value":"德国经比利时进攻法国后推进过快，补给和右翼展开出现问题，法英联军抓住德军转向和间隙组织反击。"},{"label":"后果","value":"德国速胜法国的计划失败，西线转入堑壕战和长期消耗，德国两线作战的战略困境由此固定下来。"},{"label":"出处","value":"Encyclopaedia Britannica: First Battle of the Marne；1914-1918 Online: Western Front；Imperial War Museums相关资料。"}],"relationItems":["← 前因：德国入侵比利时","← 前因：德国施里芬计划","→ 后果：一战西线堑壕战","→ 后果：凡尔登战役"],"relations":[{"text":"← 前因：德国入侵比利时","id":"extra647"},{"text":"← 前因：德国施里芬计划","id":"extra643"},{"text":"→ 后果：一战西线堑壕战","id":"extra651"},{"text":"→ 后果：凡尔登战役","id":"extra654"}],"source":"history","id":"extra650"},{"title":"一战西线堑壕战","level":"A","type":"概念/思潮卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1914年底至1918年","place":"西线，法国和比利时","summary":"一战西线堑壕战把一战变成以火力、工业生产和人力消耗为核心的长期战争，重塑了现代战争经验。","fields":[{"label":"标题","value":"一战西线堑壕战"},{"label":"分级","value":"A"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1914年底至1918年"},{"label":"地点","value":"西线，法国和比利时"},{"label":"主要国家","value":"德国、法国、英国、比利时、美国"},{"label":"一句话概括","value":"一战西线堑壕战把一战变成以火力、工业生产和人力消耗为核心的长期战争，重塑了现代战争经验。"},{"label":"核心主张/思路","value":"这不是思想主张，而是一种战争形态：防御火力、铁丝网、机枪、炮兵和堑壕体系压倒传统机动进攻。"},{"label":"提出者/代表人物（可选）","value":"无单一提出者，源于双方军事技术、火力密度和战略僵持。"},{"label":"它从何而来","value":"第一次马恩河战役后双方无法快速突破，逐渐挖掘堑壕并建立纵深防御。"},{"label":"典型表现","value":"无人区、炮击、毒气、突击队、小规模阵地争夺、大规模伤亡但战线移动有限。"},{"label":"为什么重要","value":"它解释一战为什么变成总体战和消耗战，也解释战后“迷惘一代”和反战文化的心理来源。"},{"label":"争议/局限","value":"堑壕战不是一成不变的停滞，双方战术、炮兵协同和突击方法一直在演化。"},{"label":"出处","value":"1914-1918 Online: Trench Warfare；Encyclopaedia Britannica: World War I；Imperial War Museums: Life in the trenches。"}],"relationItems":["← 前因：第一次马恩河战役","→ 后果：凡尔登战役","→ 后果：索姆河战役","↔ 相关：《西线无战事》"],"relations":[{"text":"← 前因：第一次马恩河战役","id":"extra650"},{"text":"→ 后果：凡尔登战役","id":"extra654"},{"text":"→ 后果：索姆河战役","id":"extra655"},{"text":"↔ 相关：《西线无战事》","id":"extra64"}],"source":"history","id":"extra651"},{"title":"英国对德海上封锁","level":"A","type":"事件卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1914年至1919年","place":"北海、大西洋和全球贸易网络","summary":"英国海上封锁切断德国海外贸易和原料供应，长期削弱德国战争经济和民众生活。","fields":[{"label":"标题","value":"英国对德海上封锁"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1914年至1919年"},{"label":"地点","value":"北海、大西洋和全球贸易网络"},{"label":"主要国家","value":"英国、德国、美国、中立国"},{"label":"一句话概括","value":"英国海上封锁切断德国海外贸易和原料供应，长期削弱德国战争经济和民众生活。"},{"label":"参与者","value":"英国皇家海军、德国政府和经济体系、中立航运国家。"},{"label":"发生了什么","value":"英国参战后利用皇家海军控制北海和大西洋贸易通道，逐步限制德国进口粮食、化肥、金属、硝石和其他战略物资。英国扩大违禁品清单，并对中立国航运施压，防止物资经第三国转入德国。德国经济和民生因此长期承压，城市粮食供应恶化。封锁也刺激德国把潜艇战视为反制英国的主要手段，最终推动德国无限制潜艇战升级。"},{"label":"为什么重要","value":"它把英国海权优势转化为经济战能力，是德国转向德国无限制潜艇战的重要背景之一。"},{"label":"前因","value":"英国参战后利用海军优势切断德国海外贸易，英德海军竞赛虽然增强了德国舰队，却没有改变英国控制海上交通线的能力。"},{"label":"后果","value":"封锁削弱德国粮食、原料和民用经济供给，后方不满加深，并推动德国把无限制潜艇战视为反制英国的高风险手段。"},{"label":"出处","value":"1914-1918 Online: Blockade；Encyclopaedia Britannica: World War I；Imperial War Museums相关资料。"}],"relationItems":["← 前因：英国参加第一次世界大战","→ 后果：德国无限制潜艇战","→ 后果：德国“芜菁冬天”"],"relations":[{"text":"← 前因：英国参加第一次世界大战","id":"extra648"},{"text":"→ 后果：德国无限制潜艇战","id":"extra658"},{"text":"→ 后果：德国“芜菁冬天”","id":"extra657"}],"source":"history","id":"extra652"},{"title":"一战总动员社会","level":"B","type":"概念/思潮卡","tags":["经济与社会","战争与外交"],"mainTag":"经济与社会","subTag":"战争与外交","timeText":"1914年至1918年","place":"交战国后方社会","summary":"一战总动员社会指一战中前线战争、工业生产、粮食分配、女性劳动和国家管制全面联动的社会形态。","fields":[{"label":"标题","value":"一战总动员社会"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1914年至1918年"},{"label":"地点","value":"交战国后方社会"},{"label":"主要国家","value":"德国、英国、法国、俄国、奥匈帝国、美国"},{"label":"一句话概括","value":"一战总动员社会指一战中前线战争、工业生产、粮食分配、女性劳动和国家管制全面联动的社会形态。"},{"label":"核心主张/思路","value":"现代战争不再只由军队承担，而要求国家把劳动力、工业、财政、交通、宣传和家庭生活全部纳入战争目标。"},{"label":"提出者/代表人物（可选）","value":"无单一提出者，是总体战条件下各国共同形成的治理形态。"},{"label":"它从何而来","value":"一战长期化后，弹药、粮食、劳动力和财政需求远超战前预期，国家必须深度介入经济和社会。"},{"label":"典型表现","value":"军需工业扩张、女性进入工厂、配给制度、债券宣传、新闻审查、劳工管制。"},{"label":"为什么重要","value":"它解释一战为何改变国家与社会关系，也为战后福利、动员政治和极端主义提供经验背景。"},{"label":"争议/局限","value":"不同国家动员能力差异很大，不能把德国、英国、法国、俄国的后方经验简单等同。"},{"label":"出处","value":"1914-1918 Online: War Economy；Encyclopaedia Britannica: World War I；German History Documents and Images相关资料。"}],"relationItems":["← 前因：一战西线堑壕战","→ 后果：德国兴登堡计划","→ 后果：德国“芜菁冬天”","↔ 相关：第一次世界大战全球化"],"relations":[{"text":"← 前因：一战西线堑壕战","id":"extra651"},{"text":"→ 后果：德国兴登堡计划","id":"card1"},{"text":"→ 后果：德国“芜菁冬天”","id":"extra657"},{"text":"↔ 相关：第一次世界大战全球化","id":"extra953"}],"source":"history","id":"extra653"},{"title":"凡尔登战役","level":"A","type":"事件卡","tags":["战争与外交","文化与思想"],"mainTag":"战争与外交","subTag":"文化与思想","timeText":"1916年2月21日至12月","place":"法国凡尔登","summary":"凡尔登战役是德法在西线的长期消耗战，成为一战屠杀规模和民族记忆的象征。","fields":[{"label":"标题","value":"凡尔登战役"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1916年2月21日至12月"},{"label":"地点","value":"法国凡尔登"},{"label":"主要国家","value":"德国、法国"},{"label":"一句话概括","value":"凡尔登战役是德法在西线的长期消耗战，成为一战屠杀规模和民族记忆的象征。"},{"label":"参与者","value":"德国军队、法国军队、法金汉、贝当等。"},{"label":"发生了什么","value":"1916年2月，德军选择攻击具有高度象征意义的凡尔登要塞区，希望迫使法国投入兵力并消耗其战斗意志。德军以猛烈炮击开战，先后争夺杜奥蒙、沃堡等要点。法国在贝当等指挥下组织持续增援和防御，以“他们不会通过”的口号凝聚抵抗。战役持续近一年，双方反复争夺阵地，伤亡巨大但战线变化有限，最终法国收复部分失地。"},{"label":"为什么重要","value":"凡尔登显示西线战争已变成工业化消耗，而不是传统意义上的决定性会战。它也深刻塑造法国和德国的一战记忆。"},{"label":"前因","value":"西线堑壕战陷入僵局后，德国希望选择法国具有象征意义又必须防守的地点，通过持续攻击消耗法国军队和士气。"},{"label":"后果","value":"战役造成德法双方巨大伤亡而未带来决定性突破，索姆河战役压力随之上升，西线消耗战逻辑被进一步强化。"},{"label":"出处","value":"Encyclopaedia Britannica: Battle of Verdun；1914-1918 Online: Verdun；Imperial War Museums相关资料。"}],"relationItems":["← 前因：一战西线堑壕战","→ 后果：索姆河战役","↔ 相关：《西线无战事》"],"relations":[{"text":"← 前因：一战西线堑壕战","id":"extra651"},{"text":"→ 后果：索姆河战役","id":"extra655"},{"text":"↔ 相关：《西线无战事》","id":"extra64"}],"source":"history","id":"extra654"},{"title":"索姆河战役","level":"A","type":"事件卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1916年7月1日至11月18日","place":"法国索姆河地区","summary":"索姆河战役是协约国在西线的大规模攻势，以巨大伤亡和有限推进成为工业化消耗战的代表。","fields":[{"label":"标题","value":"索姆河战役"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1916年7月1日至11月18日"},{"label":"地点","value":"法国索姆河地区"},{"label":"主要国家","value":"英国、法国、德国"},{"label":"一句话概括","value":"索姆河战役是协约国在西线的大规模攻势，以巨大伤亡和有限推进成为工业化消耗战的代表。"},{"label":"参与者","value":"英国军队、法国军队、德国军队。"},{"label":"发生了什么","value":"1916年7月，英法军队在索姆河发动大规模攻势，原本希望突破德军防线，也为凡尔登方向减压。战役前协约国进行了长时间炮击，但德军深层掩体和机枪阵地仍保留大量战斗力。英国步兵第一天进攻遭受灾难性伤亡。此后战斗持续数月，双方围绕村庄、壕沟和高地反复推进。9月坦克首次投入战场，但数量少、技术不成熟，未能改变战役消耗性质。"},{"label":"为什么重要","value":"它集中展示炮兵、机枪、堑壕和新技术条件下进攻困难，也成为英国社会一战记忆的核心创伤。"},{"label":"前因","value":"凡尔登战役消耗法国力量，协约国需要在西线发动大规模攻势以减轻法国压力，同时尝试突破德国防线。"},{"label":"后果","value":"索姆河造成巨大伤亡但突破有限，坦克首次投入战场显示新技术潜力，双方仍被困在消耗战结构中。"},{"label":"出处","value":"Encyclopaedia Britannica: First Battle of the Somme；Imperial War Museums: Battle of the Somme；1914-1918 Online相关资料。"}],"relationItems":["← 前因：凡尔登战役","← 前因：一战西线堑壕战","↔ 相关：一战总动员社会"],"relations":[{"text":"← 前因：凡尔登战役","id":"extra654"},{"text":"← 前因：一战西线堑壕战","id":"extra651"},{"text":"↔ 相关：一战总动员社会","id":"extra653"}],"source":"history","id":"extra655"},{"title":"日德兰海战","level":"B","type":"事件卡","tags":["战争与外交","无"],"mainTag":"战争与外交","subTag":"无","timeText":"1916年5月31日至6月1日","place":"北海日德兰半岛附近海域","summary":"日德兰海战是英德主力舰队最大规模交战，战术结果有争议，但英国仍保持海上封锁和战略优势。","fields":[{"label":"标题","value":"日德兰海战"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"无"},{"label":"时间","value":"1916年5月31日至6月1日"},{"label":"地点","value":"北海日德兰半岛附近海域"},{"label":"主要国家","value":"英国、德国"},{"label":"一句话概括","value":"日德兰海战是英德主力舰队最大规模交战，战术结果有争议，但英国仍保持海上封锁和战略优势。"},{"label":"参与者","value":"英国皇家海军大舰队、德国公海舰队、杰利科、舍尔等。"},{"label":"发生了什么","value":"1916年5月底，德国公海舰队试图诱出并打击英国部分舰队，以削弱英国海上优势。英国破译情报后派出大舰队迎击。双方战列巡洋舰和主力舰队在日德兰附近海域交战，英国损失舰船和人员更多，但德国舰队未能摧毁英国主力，也未能打破封锁。战后德国公海舰队减少主动出击，英国继续保持北海战略控制。"},{"label":"为什么重要","value":"它说明德国海军扩张虽然能挑战英国，却无法夺取制海权。英国封锁继续，德国战略转向潜艇战。"},{"label":"前因","value":"英国封锁持续压迫德国，德国公海舰队试图通过诱出并削弱部分英国舰队来改变海上力量对比。"},{"label":"后果","value":"德国未能打破英国制海权，公海舰队此后更加谨慎，无限制潜艇战在德国战略中的地位上升。"},{"label":"出处","value":"Encyclopaedia Britannica: Battle of Jutland；Imperial War Museums: Jutland；1914-1918 Online相关资料。"}],"relationItems":["← 前因：德意志帝国英德海军竞赛","← 前因：英国对德海上封锁","→ 后果：德国无限制潜艇战"],"relations":[{"text":"← 前因：德意志帝国英德海军竞赛","id":"extra637"},{"text":"← 前因：英国对德海上封锁","id":"extra652"},{"text":"→ 后果：德国无限制潜艇战","id":"extra658"}],"source":"history","id":"extra656"},{"title":"德国“芜菁冬天”","level":"B","type":"事件卡","tags":["经济与社会","战争与外交"],"mainTag":"经济与社会","subTag":"战争与外交","timeText":"1916年至1917年冬季","place":"德国","summary":"德国“芜菁冬天”指德国一战后期严重粮食危机，民众被迫以芜菁等低质食物维生，后方士气遭到重创。","fields":[{"label":"标题","value":"德国“芜菁冬天”"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1916年至1917年冬季"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国、英国"},{"label":"一句话概括","value":"德国“芜菁冬天”指德国一战后期严重粮食危机，民众被迫以芜菁等低质食物维生，后方士气遭到重创。"},{"label":"参与者","value":"德国城市居民、农民、政府配给体系、英国海上封锁。"},{"label":"发生了什么","value":"1916年冬，德国遭遇粮食供应危机。马铃薯歉收、运输系统紧张、农业劳动力不足、军需优先和英国封锁叠加，使城市配给急剧恶化。政府和地方机构以芜菁等替代食品维持供应，许多家庭长期缺乏足够热量和营养。饥饿、寒冷和排队成为后方生活常态，工人不满和罢工情绪上升，德国社会对继续战争的承受力明显下降。"},{"label":"为什么重要","value":"它说明一战胜负不只取决于前线，也取决于后方社会能否承受长期封锁、饥饿和国家管制。"},{"label":"前因","value":"英国封锁、农业劳动力和马匹被战争抽走、马铃薯歉收以及战时分配失灵共同造成德国城市食品供应恶化。"},{"label":"后果","value":"饥饿和寒冷削弱后方承受力，战争疲惫和对政府的不满扩大，为1918年政治崩溃积累社会条件。"},{"label":"出处","value":"1914-1918 Online: Food and Nutrition Germany；Deutsches Historisches Museum/LeMO: Hunger und Versorgung；German History Documents and Images相关资料。"}],"relationItems":["← 前因：英国对德海上封锁","← 前因：德国兴登堡计划","→ 后果：德国十一月革命","↔ 相关：一战总动员社会"],"relations":[{"text":"← 前因：英国对德海上封锁","id":"extra652"},{"text":"← 前因：德国兴登堡计划","id":"card1"},{"text":"→ 后果：德国十一月革命","id":"extra666"},{"text":"↔ 相关：一战总动员社会","id":"extra653"}],"source":"history","id":"extra657"},{"title":"德国无限制潜艇战","level":"A","type":"事件卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1917年2月起全面恢复","place":"大西洋和英国周边海域","summary":"德国恢复德国无限制潜艇战试图切断英国海上生命线，却推动美国参战，改变了一战力量对比。","fields":[{"label":"标题","value":"德国无限制潜艇战"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1917年2月起全面恢复"},{"label":"地点","value":"大西洋和英国周边海域"},{"label":"主要国家","value":"德国、英国、美国"},{"label":"一句话概括","value":"德国恢复德国无限制潜艇战试图切断英国海上生命线，却推动美国参战，改变了一战力量对比。"},{"label":"参与者","value":"德国海军、英国商船和海军、美国政府和商船。"},{"label":"发生了什么","value":"德国认为英国海上封锁正在消耗本国，而公海舰队无法打破英国制海权。1917年初，德国决定恢复德国无限制潜艇战，宣布在指定海域不经警告攻击敌对和部分中立船只，目标是在美国充分动员前切断英国补给并迫使其求和。潜艇战初期造成协约国航运重大损失，但也击沉中立船只，激怒美国舆论。英国随后发展护航体系，潜艇战效果下降，美国则走向参战。"},{"label":"为什么重要","value":"这是德国战略赌博。它短期威胁英国航运，却在政治上把美国推入协约国阵营。"},{"label":"前因","value":"英国封锁使德国承受巨大经济压力，日德兰海战又未能改变制海权，德国决策层转而寄望潜艇切断英国补给。"},{"label":"后果","value":"无限制潜艇战刺激美国参战，虽一度打击协约国航运，但最终使德国面对更强大的经济和军事对手。"},{"label":"出处","value":"1914-1918 Online: Submarine Warfare；Encyclopaedia Britannica: unrestricted submarine warfare；National WWI Museum相关资料。"}],"relationItems":["← 前因：英国对德海上封锁","← 前因：日德兰海战","→ 后果：美国参加第一次世界大战","→ 后果：德国齐默尔曼电报"],"relations":[{"text":"← 前因：英国对德海上封锁","id":"extra652"},{"text":"← 前因：日德兰海战","id":"extra656"},{"text":"→ 后果：美国参加第一次世界大战","id":"extra660"},{"text":"→ 后果：德国齐默尔曼电报","id":"extra659"}],"source":"history","id":"extra658"},{"title":"德国齐默尔曼电报","level":"B","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1917年1月发出，3月公开","place":"德国、墨西哥、美国之间的外交通信","summary":"德国齐默尔曼电报提议墨西哥在美德开战时牵制美国，公开后强化美国社会对德国敌意。","fields":[{"label":"标题","value":"德国齐默尔曼电报"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1917年1月发出，3月公开"},{"label":"地点","value":"德国、墨西哥、美国之间的外交通信"},{"label":"主要国家","value":"德国、墨西哥、美国、英国"},{"label":"一句话概括","value":"德国齐默尔曼电报提议墨西哥在美德开战时牵制美国，公开后强化美国社会对德国敌意。"},{"label":"制定方/签署方","value":"德国外交国务秘书阿图尔·齐默尔曼发给德国驻墨西哥外交机构。"},{"label":"主要内容","value":"德国建议若美国参战，墨西哥可与德国结盟并获得收复失地的支持，涉及得克萨斯、新墨西哥和亚利桑那。"},{"label":"它试图解决什么问题","value":"德国预期德国无限制潜艇战可能导致美国参战，试图通过墨西哥牵制美国。"},{"label":"为什么重要","value":"它为美国参战提供强烈舆论刺激，与德国无限制潜艇战一起改变美国政策环境。"},{"label":"争议/局限","value":"墨西哥实际执行可能性很低，但电报的象征冲击极大。"},{"label":"造成的影响","value":"美国公众对德国威胁感上升；美国参加第一次世界大战。"},{"label":"出处","value":"Encyclopaedia Britannica: Zimmermann Telegram；US National Archives: Zimmermann Telegram；1914-1918 Online相关资料。"}],"relationItems":["← 前因：德国无限制潜艇战","→ 后果：美国参加第一次世界大战"],"relations":[{"text":"← 前因：德国无限制潜艇战","id":"extra658"},{"text":"→ 后果：美国参加第一次世界大战","id":"extra660"}],"source":"history","id":"extra659"},{"title":"美国参加第一次世界大战","level":"S","type":"事件卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1917年4月6日","place":"美国、欧洲战场和大西洋","summary":"美国参加一战打破欧洲消耗战均势，为协约国提供人力、财政和工业优势，也改变战后国际秩序。","fields":[{"label":"标题","value":"美国参加第一次世界大战"},{"label":"分级","value":"S"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1917年4月6日"},{"label":"地点","value":"美国、欧洲战场和大西洋"},{"label":"主要国家","value":"美国、德国、英国、法国"},{"label":"一句话概括","value":"美国参加一战打破欧洲消耗战均势，为协约国提供人力、财政和工业优势，也改变战后国际秩序。"},{"label":"参与者","value":"美国政府、伍德罗·威尔逊、德国、协约国。"},{"label":"发生了什么","value":"一战初期美国保持中立，但金融、贸易和舆论逐渐与协约国联系加深。德国恢复德国无限制潜艇战后，美国船只和公民安全受到威胁。德国齐默尔曼电报公开后，美国社会进一步认为德国构成直接威胁。威尔逊政府请求国会宣战，1917年4月6日美国对德国宣战。此后美国提供贷款、物资和远征军，虽然大规模作战投入较晚，但显著改变协约国的长期优势。"},{"label":"为什么重要","value":"美国参战使德国必须在美军全面到达前争取决胜，推动1918年春季攻势；也让战后和平方案进入威尔逊主义时代。"},{"label":"前因","value":"德国恢复无限制潜艇战威胁美国航运和人员安全，齐默尔曼电报又强化美国国内对德国敌意，协约国金融联系也影响美国战略选择。"},{"label":"后果","value":"美国参战改变战争资源对比，使协约国获得持续兵力和金融支持，德国被迫在美军全面到达前发动1918年春季攻势。"},{"label":"出处","value":"Encyclopaedia Britannica: United States entry into World War I；US National Archives相关资料；1914-1918 Online: USA。"}],"relationItems":["← 前因：德国无限制潜艇战","← 前因：德国齐默尔曼电报","→ 后果：威尔逊十四点原则","→ 后果：德国1918年春季攻势"],"relations":[{"text":"← 前因：德国无限制潜艇战","id":"extra658"},{"text":"← 前因：德国齐默尔曼电报","id":"extra659"},{"text":"→ 后果：威尔逊十四点原则","id":"extra661"},{"text":"→ 后果：德国1918年春季攻势","id":"extra663"}],"source":"history","id":"extra660"},{"title":"威尔逊十四点原则","level":"A","type":"制度/文本卡","tags":["战争与外交","文化与思想"],"mainTag":"战争与外交","subTag":"文化与思想","timeText":"1918年1月8日","place":"美国国会演说，影响一战后巴黎和会","summary":"威尔逊十四点原则提出公开外交、民族自决和一战后国际联盟等和平设想，成为一战结束和战后秩序争论的重要文本。","fields":[{"label":"标题","value":"威尔逊十四点原则"},{"label":"分级","value":"A"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1918年1月8日"},{"label":"地点","value":"美国国会演说，影响一战后巴黎和会"},{"label":"主要国家","value":"美国、德国、英国、法国、奥匈帝国"},{"label":"一句话概括","value":"威尔逊十四点原则提出公开外交、民族自决和一战后国际联盟等和平设想，成为一战结束和战后秩序争论的重要文本。"},{"label":"制定方/签署方","value":"美国总统伍德罗·威尔逊提出。"},{"label":"主要内容","value":"包括公开外交、海上自由、贸易平等、裁军、殖民问题调整、民族自决相关安排，以及建立一战后国际联盟。"},{"label":"它试图解决什么问题","value":"威尔逊希望把美国参战目标解释为建立持久和平，而不仅是击败德国。"},{"label":"为什么重要","value":"它为德国寻求停战提供话语依据，也深刻影响一战后巴黎和会和民族自决政治。"},{"label":"争议/局限","value":"原则与战胜国利益、殖民现实和欧洲边界复杂性冲突，执行高度不均衡。"},{"label":"造成的影响","value":"影响停战谈判和《凡尔赛和约》争论；一战后国际联盟成为战后秩序核心尝试。"},{"label":"出处","value":"Avalon Project: Wilson’s Fourteen Points；Encyclopaedia Britannica: Fourteen Points；National WWI Museum相关资料。"}],"relationItems":["← 前因：美国参加第一次世界大战","→ 后果：《凡尔赛和约》","→ 后果：一战后国际联盟"],"relations":[{"text":"← 前因：美国参加第一次世界大战","id":"extra660"},{"text":"→ 后果：《凡尔赛和约》","id":"card59"},{"text":"→ 后果：一战后国际联盟","id":"card4"}],"source":"history","id":"extra661"},{"title":"《布列斯特-立托夫斯克条约》","level":"A","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1918年3月3日","place":"布列斯特-立托夫斯克","summary":"布列斯特-立托夫斯克条约使苏俄退出一战，德国暂时获得东线胜利和大片影响区。","fields":[{"label":"标题","value":"《布列斯特-立托夫斯克条约》"},{"label":"分级","value":"A"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1918年3月3日"},{"label":"地点","value":"布列斯特-立托夫斯克"},{"label":"主要国家","value":"德国、俄国、奥匈帝国、奥斯曼帝国、保加利亚、乌克兰等"},{"label":"一句话概括","value":"布列斯特-立托夫斯克条约使苏俄退出一战，德国暂时获得东线胜利和大片影响区。"},{"label":"制定方/签署方","value":"苏维埃俄国与同盟国，包括德国、奥匈帝国、奥斯曼帝国和保加利亚。"},{"label":"主要内容","value":"苏俄放弃对波兰、波罗的海、芬兰、乌克兰等地区的控制或影响，承认严苛条件以换取退出战争。"},{"label":"它试图解决什么问题","value":"布尔什维克政权需要结束战争巩固国内革命；德国希望释放东线兵力转向西线决战。"},{"label":"为什么重要","value":"它是东线战争的巨大转折，使德国能发动1918年春季攻势，也显示帝国德国在东欧有扩张性战争目标。"},{"label":"争议/局限","value":"条约极其严苛，后来因德国战败而失效；它也加剧俄国内战和东欧权力真空。"},{"label":"造成的影响","value":"德国把兵力转向西线；东欧进入高度动荡；战后边界问题更加复杂。"},{"label":"出处","value":"Encyclopaedia Britannica: Treaty of Brest-Litovsk；1914-1918 Online: Brest-Litovsk；Avalon Project相关文本。"}],"relationItems":["← 前因：1917年俄国革命","→ 后果：德国1918年春季攻势","↔ 相关：威尔逊十四点原则"],"relations":[{"text":"← 前因：1917年俄国革命","id":"extra966"},{"text":"→ 后果：德国1918年春季攻势","id":"extra663"},{"text":"↔ 相关：威尔逊十四点原则","id":"extra661"}],"source":"history","id":"extra662"},{"title":"德国1918年春季攻势","level":"A","type":"事件卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1918年3月至7月","place":"西线，法国和比利时","summary":"德国1918年春季攻势试图在美军全面投入前决胜西线，初期突破后因补给和兵力不足失败。","fields":[{"label":"标题","value":"德国1918年春季攻势"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1918年3月至7月"},{"label":"地点","value":"西线，法国和比利时"},{"label":"主要国家","value":"德国、法国、英国、美国"},{"label":"一句话概括","value":"德国1918年春季攻势试图在美军全面投入前决胜西线，初期突破后因补给和兵力不足失败。"},{"label":"参与者","value":"德国军队、鲁登道夫、英法军队、逐步抵达的美军。"},{"label":"发生了什么","value":"布列斯特-立托夫斯克条约使德国从东线抽调兵力，鲁登道夫决定在美军大规模抵达前在西线决胜。1918年3月起，德军发动多轮攻势，使用突击队渗透战术突破英法阵地，初期取得大片进展并制造协约国危机。但德军未能夺取决定性战略目标，补给线拉长，精锐部队损耗严重。随着美军不断抵达、协约国统一指挥加强，德国攻势在夏季耗尽力量。"},{"label":"为什么重要","value":"这是德国最后一次争取胜利的赌博。攻势耗尽精锐兵力后，协约国在美国支援下转入反攻。"},{"label":"前因","value":"俄国退出战争释放了德国东线兵力，但美国参战意味着时间不在德国一边，德军试图在美军大规模部署前于西线取得决定性胜利。"},{"label":"后果","value":"攻势初期突破未能转化为战略胜利，德军精锐损失严重，协约国随后发动百日攻势并推动德国军事崩溃。"},{"label":"出处","value":"Encyclopaedia Britannica: Ludendorff Offensive；1914-1918 Online: German Spring Offensives；Imperial War Museums相关资料。"}],"relationItems":["← 前因：《布列斯特-立托夫斯克条约》","← 前因：美国参加第一次世界大战","→ 后果：一战百日攻势","→ 后果：德国十一月革命"],"relations":[{"text":"← 前因：《布列斯特-立托夫斯克条约》","id":"extra662"},{"text":"← 前因：美国参加第一次世界大战","id":"extra660"},{"text":"→ 后果：一战百日攻势","id":"extra664"},{"text":"→ 后果：德国十一月革命","id":"extra666"}],"source":"history","id":"extra663"},{"title":"一战百日攻势","level":"A","type":"事件卡","tags":["战争与外交","无"],"mainTag":"战争与外交","subTag":"无","timeText":"1918年8月8日至11月11日","place":"西线","summary":"一战百日攻势是协约国在西线连续反攻，迫使德军后撤并最终促成德国请求停战。","fields":[{"label":"标题","value":"一战百日攻势"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"无"},{"label":"时间","value":"1918年8月8日至11月11日"},{"label":"地点","value":"西线"},{"label":"主要国家","value":"法国、英国、美国、德国、加拿大、澳大利亚等"},{"label":"一句话概括","value":"一战百日攻势是协约国在西线连续反攻，迫使德军后撤并最终促成德国请求停战。"},{"label":"参与者","value":"协约国军队、德国军队、福煦、黑格、潘兴等。"},{"label":"发生了什么","value":"1918年8月，协约国在亚眠等地发动连续反攻，综合使用炮兵、坦克、飞机、步兵和更灵活的战术。德军在春季攻势后兵力和士气下降，面对连续压力不断后撤。协约国没有依赖单一突破，而是在多个方向持续攻击，迫使德国防线和盟友体系同时崩溃。到秋季，保加利亚、奥斯曼帝国和奥匈帝国相继瓦解，德国最高统帅部承认战争无法继续。"},{"label":"为什么重要","value":"它标志西线僵局被打破。德国军队没有完全被占领本土前消灭，但已无法继续承担战争。"},{"label":"前因","value":"德国春季攻势失败后兵力和士气受损，美国参战增强协约国力量，坦克、炮兵和步兵协同使协约国能够连续突破德军防线。"},{"label":"后果","value":"德军节节后退并要求停战，国内革命迅速扩散，1918年11月停战成为德国军事和政治双重崩溃的结果。"},{"label":"出处","value":"Encyclopaedia Britannica: Hundred Days Offensive；Imperial War Museums: Hundred Days；1914-1918 Online相关资料。"}],"relationItems":["← 前因：德国1918年春季攻势","← 前因：美国参加第一次世界大战","→ 后果：一战停战","→ 后果：德国十一月革命"],"relations":[{"text":"← 前因：德国1918年春季攻势","id":"extra663"},{"text":"← 前因：美国参加第一次世界大战","id":"extra660"},{"text":"→ 后果：一战停战","id":"extra667"},{"text":"→ 后果：德国十一月革命","id":"extra666"}],"source":"history","id":"extra664"},{"title":"德国基尔水兵起义","level":"B","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1918年10月底至11月初","place":"德国基尔及其他港口城市","summary":"德国基尔水兵起义从拒绝无望出海作战开始，迅速扩展为推翻帝制的革命浪潮。","fields":[{"label":"标题","value":"德国基尔水兵起义"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1918年10月底至11月初"},{"label":"地点","value":"德国基尔及其他港口城市"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国基尔水兵起义从拒绝无望出海作战开始，迅速扩展为推翻帝制的革命浪潮。"},{"label":"参与者","value":"德国海军水兵、工人、士兵委员会、帝国海军指挥层。"},{"label":"发生了什么","value":"1918年10月底，德国海军高层计划在停战谈判背景下出动舰队与英国决战，以保存荣誉或争取谈判筹码。许多水兵认为这是毫无意义的自杀命令，拒绝出海并发生抗命。军方逮捕部分水兵后，抗议在基尔扩大，工人和士兵加入，成立士兵委员会。运动迅速扩散到汉堡、不来梅、慕尼黑和柏林等地，把军事抗命转化为全国革命浪潮。"},{"label":"为什么重要","value":"它是德国十一月革命的直接引爆点，把军事失败和后方政治崩溃连在一起。"},{"label":"前因","value":"德国战争失败已成定局，海军高层仍计划发动几乎无望的最后出击，水兵拒绝被牺牲并把抗命转化为政治行动。"},{"label":"后果","value":"起义扩散为全国革命浪潮，迫使威廉二世退位，帝制崩溃并打开魏玛共和国成立的道路。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Kieler Matrosenaufstand；Encyclopaedia Britannica: German Revolution；1914-1918 Online相关资料。"}],"relationItems":["← 前因：一战百日攻势","→ 后果：德国十一月革命","→ 后果：魏玛共和国成立"],"relations":[{"text":"← 前因：一战百日攻势","id":"extra664"},{"text":"→ 后果：德国十一月革命","id":"extra666"},{"text":"→ 后果：魏玛共和国成立","id":"card7"}],"source":"history","id":"extra665"},{"title":"德国十一月革命","level":"A","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1918年11月至1919年","place":"德国","summary":"德国十一月革命推翻德意志帝国，建立共和国，把一战军事失败转化为德国政治制度断裂。","fields":[{"label":"标题","value":"德国十一月革命"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1918年11月至1919年"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国十一月革命推翻德意志帝国，建立共和国，把一战军事失败转化为德国政治制度断裂。"},{"label":"参与者","value":"工人、士兵、水兵、社会民主党、独立社民党、革命派、威廉二世。"},{"label":"发生了什么","value":"德国基尔水兵起义扩散后，德国各地出现工人和士兵委员会，地方政权接连倒向革命力量。柏林局势失控，威廉二世在军方和政治压力下退位并流亡荷兰。1918年11月9日，谢德曼宣布德国共和国，李卜克内西也宣布自由社会主义共和国，显示革命阵营内部存在分歧。社会民主党领导人艾伯特接管政府，并同军方合作维持秩序。革命随后进入共和国建构、左翼起义和镇压并存的阶段。"},{"label":"为什么重要","value":"它结束德意志帝国，开启魏玛共和国，也为“背后一刀”传说和右翼反共和国叙事提供了政治靶标。"},{"label":"前因","value":"军事失败、后方饥饿、工人不满和基尔水兵起义汇合，帝国政府已无法同时维持战争、君主制和社会秩序。"},{"label":"后果","value":"革命推翻帝制并建立共和国，但停战和战败责任很快被右翼宣传扭曲为“背后一刀”神话，成为魏玛政治的长期负担。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Novemberrevolution；Encyclopaedia Britannica: German Revolution；German History Documents and Images相关资料。"}],"relationItems":["← 前因：德国基尔水兵起义","← 前因：一战百日攻势","→ 后果：魏玛共和国成立","→ 后果：德国“背后一刀”传说"],"relations":[{"text":"← 前因：德国基尔水兵起义","id":"extra665"},{"text":"← 前因：一战百日攻势","id":"extra664"},{"text":"→ 后果：魏玛共和国成立","id":"card7"},{"text":"→ 后果：德国“背后一刀”传说","id":"extra623"}],"source":"history","id":"extra666"},{"title":"一战停战","level":"S","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1918年11月11日","place":"法国贡比涅森林","summary":"一战停战结束西线战斗，标志第一次世界大战军事阶段结束，并开启战后和约秩序。","fields":[{"label":"标题","value":"一战停战"},{"label":"分级","value":"S"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1918年11月11日"},{"label":"地点","value":"法国贡比涅森林"},{"label":"主要国家","value":"德国、法国、英国、美国"},{"label":"一句话概括","value":"一战停战结束西线战斗，标志第一次世界大战军事阶段结束，并开启战后和约秩序。"},{"label":"参与者","value":"德国停战代表团、协约国代表、福煦等。"},{"label":"发生了什么","value":"1918年秋，德军在西线持续后退，盟友相继退出战争，国内革命推翻帝制。德国新政府派代表团前往协约国控制区谈判停战。11月11日清晨，德国代表在贡比涅森林签署停战协定，接受撤军、交出大量武器、释放战俘和维持封锁等条件。上午11点，西线战斗停止。停战结束军事行动，但正式和平还要等一战后巴黎和会及《凡尔赛和约》。"},{"label":"为什么重要","value":"它结束了一战主要战斗，但不是正式和平。战败、革命和停战同时发生，深刻影响德国战后政治记忆。"},{"label":"前因","value":"百日攻势击溃德军防线，德国国内革命瓦解帝制，新的德国政府需要立即结束一场已无法继续承受的战争。"},{"label":"后果","value":"停战结束了战斗，但没有解决和平条件；凡尔赛和约、战败责任争议和背后一刀传说随后深刻塑造魏玛共和国。"},{"label":"出处","value":"Encyclopaedia Britannica: Armistice of November 11, 1918；Imperial War Museums相关资料；1914-1918 Online: Armistice。"}],"relationItems":["← 前因：一战百日攻势","← 前因：德国十一月革命","→ 后果：《凡尔赛和约》","→ 后果：德国“背后一刀”传说"],"relations":[{"text":"← 前因：一战百日攻势","id":"extra664"},{"text":"← 前因：德国十一月革命","id":"extra666"},{"text":"→ 后果：《凡尔赛和约》","id":"card59"},{"text":"→ 后果：德国“背后一刀”传说","id":"extra623"}],"source":"history","id":"extra667"},{"title":"一战后巴黎和会","level":"S","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1919年1月至1920年","place":"法国巴黎及周边会场","summary":"一战后巴黎和会重塑一战后国际秩序，处理战败国、边界、赔款、民族自决和一战后国际联盟等核心问题。","fields":[{"label":"标题","value":"一战后巴黎和会"},{"label":"分级","value":"S"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1919年1月至1920年"},{"label":"地点","value":"法国巴黎及周边会场"},{"label":"主要国家","value":"法国、英国、美国、意大利、日本、德国等"},{"label":"一句话概括","value":"一战后巴黎和会重塑一战后国际秩序，处理战败国、边界、赔款、民族自决和一战后国际联盟等核心问题。"},{"label":"参与者","value":"协约国主要战胜国代表，尤其是威尔逊、克列孟梭、劳合·乔治、奥兰多；战败国多数被排除在核心谈判之外。"},{"label":"发生了什么","value":"一战停战后，战胜国在巴黎召开和会，讨论如何处理德国、奥匈帝国、奥斯曼帝国和保加利亚等战败方。会议表面上以威尔逊十四点原则为和平框架，但实际谈判中法国安全需求、英国帝国利益、美国一战后国际联盟设想、意大利领土诉求和日本在亚太权益相互冲突。德国代表没有参与核心条款制定，只能在条约草案完成后提出有限抗议。会议最终形成多份和约和一战后国际联盟框架，但也留下德国不满、殖民地委任统治、东欧边界争议和民族自决不均衡等问题。"},{"label":"为什么重要","value":"它是二十世纪国际秩序的关键节点。和会既试图告别旧式秘密外交和帝国战争，又在现实中延续了强权分配和战胜国惩罚逻辑。"},{"label":"前因","value":"一战停战后，战胜国需要重新安排德国、奥匈、奥斯曼和俄国革命后的欧洲秩序，威尔逊十四点原则也提高了民族自决和国际组织的期待。"},{"label":"后果","value":"会议形成凡尔赛体系和一战后国际联盟，但对德国的领土、军备和赔款限制也激发修约主义，战后秩序从一开始就带有不稳定因素。"},{"label":"出处","value":"Encyclopaedia Britannica: Paris Peace Conference；Office of the Historian: Paris Peace Conference；1914-1918 Online相关资料。"}],"relationItems":["← 前因：一战停战","← 前因：威尔逊十四点原则","→ 后果：《凡尔赛和约》","→ 后果：一战后国际联盟"],"relations":[{"text":"← 前因：一战停战","id":"extra667"},{"text":"← 前因：威尔逊十四点原则","id":"extra661"},{"text":"→ 后果：《凡尔赛和约》","id":"card59"},{"text":"→ 后果：一战后国际联盟","id":"card4"}],"source":"history","id":"extra668"},{"title":"德意志帝国议会","level":"A","type":"组织/机构卡","tags":["政治与制度","无"],"mainTag":"政治与制度","subTag":"无","timeText":"1871年至1918年","place":"德意志帝国，柏林","summary":"德意志帝国议会由男性普选产生，却不能决定政府去留，体现帝国“有选举、弱责任内阁”的制度矛盾。","fields":[{"label":"标题","value":"德意志帝国议会"},{"label":"分级","value":"A"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"无"},{"label":"时间","value":"1871年至1918年"},{"label":"地点","value":"德意志帝国，柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德意志帝国议会由男性普选产生，却不能决定政府去留，体现帝国“有选举、弱责任内阁”的制度矛盾。"},{"label":"性质/类型","value":"全国性民选立法机构。"},{"label":"成立/解散时间","value":"1871年德意志帝国成立后运作；1918年帝国崩溃后被德国魏玛国民议会和共和国议会制度取代。"},{"label":"核心目标/宗旨","value":"参与帝国立法和预算审批，提供全国政治代表渠道。"},{"label":"关键人物（可选）","value":"各党派议员，尤其社会民主党、中央党、民族自由党、保守派等。"},{"label":"关键行动/事件","value":"审议预算、军费、关税、反社会党人法、海军法等关键议题；一战前社民党成为最大党，但仍不能组阁。"},{"label":"为什么重要","value":"它让德国拥有现代大众选举政治，却没有形成真正议会责任政府。政党群众化和行政权非议会化之间的断裂，是帝国政治的核心问题。"},{"label":"争议/局限","value":"议会有预算和立法影响力，但首相只对皇帝负责，不由议会多数产生。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Reichstag；German History Documents and Images: Imperial Constitution；Encyclopaedia Britannica: German Empire。"}],"relationItems":["← 前因：德意志帝国宪法","→ 后果：德国1914年战争贷款表决","↔ 相关：德国社会民主党（SPD）","↔ 相关：德意志帝国联邦参议院"],"relations":[{"text":"← 前因：德意志帝国宪法","id":"extra624"},{"text":"→ 后果：德国1914年战争贷款表决","id":"extra691"},{"text":"↔ 相关：德国社会民主党（SPD）","id":"extra628"},{"text":"↔ 相关：德意志帝国联邦参议院","id":"extra670"}],"source":"history","id":"extra669"},{"title":"德意志帝国联邦参议院","level":"B","type":"组织/机构卡","tags":["政治与制度","无"],"mainTag":"政治与制度","subTag":"无","timeText":"1871年至1918年","place":"德意志帝国，柏林","summary":"联邦参议院代表各邦政府，是德意志帝国联邦结构的核心机构，也保证普鲁士在帝国中的优势地位。","fields":[{"label":"标题","value":"德意志帝国联邦参议院"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"无"},{"label":"时间","value":"1871年至1918年"},{"label":"地点","value":"德意志帝国，柏林"},{"label":"主要国家","value":"德国、普鲁士"},{"label":"一句话概括","value":"联邦参议院代表各邦政府，是德意志帝国联邦结构的核心机构，也保证普鲁士在帝国中的优势地位。"},{"label":"性质/类型","value":"各邦政府代表组成的联邦机构。"},{"label":"成立/解散时间","value":"1871年帝国成立后运作；1918年帝制崩溃后消失。"},{"label":"核心目标/宗旨","value":"代表各邦参与帝国立法、行政监督和联邦事务决策。"},{"label":"关键人物（可选）","value":"普鲁士代表团和各邦政府代表。"},{"label":"关键行动/事件","value":"参与法律制定和行政规章，影响军事、财政和联邦事务；普鲁士凭借票数和皇帝/首相关系占据主导。"},{"label":"为什么重要","value":"它解释帝国不是单一中央集权国家，而是普鲁士优势下的联邦帝国。许多政策必须理解为皇帝、首相、普鲁士和各邦之间的权力组合。"},{"label":"争议/局限","value":"联邦参议院不是民选机构，强化了政府和邦国君主对民主代表的制衡。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Reichsverfassung；German History Documents and Images: Constitution of the German Empire；Encyclopaedia Britannica: German Empire。"}],"relationItems":["← 前因：德意志帝国宪法","↔ 相关：德意志帝国议会","↔ 相关：德意志统一中的普鲁士优势"],"relations":[{"text":"← 前因：德意志帝国宪法","id":"extra624"},{"text":"↔ 相关：德意志帝国议会","id":"extra669"},{"text":"↔ 相关：德意志统一中的普鲁士优势","id":"extra914"}],"source":"history","id":"extra670"},{"title":"普鲁士三级选举制","level":"A","type":"制度/文本卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1849年至1918年","place":"普鲁士王国","summary":"普鲁士三级选举制按纳税额分配选举影响力，使富裕阶层在普鲁士政治中长期拥有远超人数比例的权力。","fields":[{"label":"标题","value":"普鲁士三级选举制"},{"label":"分级","value":"A"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1849年至1918年"},{"label":"地点","value":"普鲁士王国"},{"label":"主要国家","value":"普鲁士、德国"},{"label":"一句话概括","value":"普鲁士三级选举制按纳税额分配选举影响力，使富裕阶层在普鲁士政治中长期拥有远超人数比例的权力。"},{"label":"制定方/签署方","value":"普鲁士王国宪政制度。"},{"label":"主要内容","value":"选民按缴纳直接税总额分成三等级，每一等级各选出同等数量选举人，再由选举人选出议员。少数高纳税者在第一等级中拥有极高政治权重。"},{"label":"它试图解决什么问题","value":"1848革命后，普鲁士统治层需要保留某种宪政代表形式，同时防止大众民主削弱王权、贵族和资产阶级精英控制。"},{"label":"为什么重要","value":"它造成帝国层面男性普选与普鲁士层面等级选举并存的矛盾。普鲁士又是帝国核心邦，普鲁士保守结构间接影响整个帝国政治。"},{"label":"争议/局限","value":"制度形式上有选举，实质上严重不平等。工人、低收入市民和农村贫民政治影响被压低。"},{"label":"造成的影响","value":"普鲁士保守派和容克地主长期维持政治优势；选举制度改革成为帝国晚期重要争议。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Dreiklassenwahlrecht；German History Documents and Images相关资料；Encyclopaedia Britannica: Prussia。"}],"relationItems":["← 前因：1848年德意志革命","↔ 相关：德意志帝国宪法","↔ 相关：普鲁士容克地主"],"relations":[{"text":"← 前因：1848年德意志革命","id":"extra490"},{"text":"↔ 相关：德意志帝国宪法","id":"extra624"},{"text":"↔ 相关：普鲁士容克地主","id":"extra672"}],"source":"history","id":"extra671"},{"title":"普鲁士容克地主","level":"B","type":"概念/思潮卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"十九世纪至二十世纪上半叶影响突出","place":"普鲁士东部，尤其易北河以东地区","summary":"普鲁士容克地主是东部大土地贵族阶层，长期影响普鲁士军队、官僚和保守政治。","fields":[{"label":"标题","value":"普鲁士容克地主"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"十九世纪至二十世纪上半叶影响突出"},{"label":"地点","value":"普鲁士东部，尤其易北河以东地区"},{"label":"主要国家","value":"普鲁士、德国"},{"label":"一句话概括","value":"普鲁士容克地主是东部大土地贵族阶层，长期影响普鲁士军队、官僚和保守政治。"},{"label":"核心主张/思路","value":"这不是思想流派，而是一个社会政治阶层：以土地、军官传统、王权忠诚和保守主义影响国家权力。"},{"label":"提出者/代表人物（可选）","value":"俾斯麦本人出身容克阶层；兴登堡也与东部地主世界关系密切。"},{"label":"它从何而来","value":"普鲁士东部农业庄园经济和贵族军官传统在近代国家建设中保留强大地位。"},{"label":"典型表现","value":"支持保护关税、维护普鲁士三级选举制、在军官团和官僚体系中占据高位。"},{"label":"为什么重要","value":"理解帝国德国不能只看工业资本和工人阶级，还要看这个保守农业贵族阶层如何影响军国主义、关税和反民主政治。"},{"label":"争议/局限","value":"容克不是铁板一块，但作为政治标签常被用来概括东部地主贵族的保守影响。"},{"label":"出处","value":"Encyclopaedia Britannica: Junker；Deutsches Historisches Museum/LeMO相关资料；German History Documents and Images相关资料。"}],"relationItems":["↔ 相关：普鲁士三级选举制","↔ 相关：德意志帝国保护关税政策","→ 后果：魏玛《东部援助》法案"],"relations":[{"text":"↔ 相关：普鲁士三级选举制","id":"extra671"},{"text":"↔ 相关：德意志帝国保护关税政策","id":"extra630"},{"text":"→ 后果：魏玛《东部援助》法案","id":"card66"}],"source":"history","id":"extra672"},{"title":"德国中央党","level":"B","type":"组织/机构卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1870年成立，帝国和魏玛时期持续重要","place":"德国","summary":"德国中央党代表天主教政治利益，在帝国文化斗争和魏玛议会政治中都是关键中间力量。","fields":[{"label":"标题","value":"德国中央党"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1870年成立，帝国和魏玛时期持续重要"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国中央党代表天主教政治利益，在帝国文化斗争和魏玛议会政治中都是关键中间力量。"},{"label":"性质/类型","value":"天主教政治政党、议会政党。"},{"label":"成立/解散时间","value":"1870年成立；魏玛时期继续存在，1933年在纳粹压力下解散。"},{"label":"核心目标/宗旨","value":"维护天主教会权利、地方和宗教自治、法治与社会政策，并在议会中保护天主教选民利益。"},{"label":"关键人物（可选）","value":"路德维希·温德霍斯特等。"},{"label":"关键行动/事件","value":"在文化斗争中抵制俾斯麦政府；后来成为帝国和魏玛时期重要议会枢纽。"},{"label":"为什么重要","value":"中央党说明帝国政治不是简单的保守派与社会主义对立，宗教身份和地区差异也是大众政治组织的基础。"},{"label":"争议/局限","value":"中央党跨阶层、跨地区，政策上常需在教会利益、社会政策和议会交易之间平衡。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Zentrum；Encyclopaedia Britannica: Centre Party；German History Documents and Images相关资料。"}],"relationItems":["← 前因：德意志帝国文化斗争","↔ 相关：“Nach Canossa gehen wir nicht”","→ 后果：魏玛共和国成立"],"relations":[{"text":"← 前因：德意志帝国文化斗争","id":"extra626"},{"text":"↔ 相关：“Nach Canossa gehen wir nicht”","id":"proverb1"},{"text":"→ 后果：魏玛共和国成立","id":"card7"}],"source":"history","id":"extra673"},{"title":"德国民族自由党","level":"C","type":"组织/机构卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1867年至1918年左右为主要活动期","place":"德国","summary":"德国民族自由党代表统一后自由派与民族国家妥协的一面，支持法治和经济自由，也长期支持俾斯麦国家建设。","fields":[{"label":"标题","value":"德国民族自由党"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1867年至1918年左右为主要活动期"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国民族自由党代表统一后自由派与民族国家妥协的一面，支持法治和经济自由，也长期支持俾斯麦国家建设。"},{"label":"性质/类型","value":"自由主义、民族主义议会政党。"},{"label":"成立/解散时间","value":"1860年代形成；帝国时期长期活跃，1918年后重组为新的自由派政党。"},{"label":"核心目标/宗旨","value":"支持德意志统一、法治、经济自由和资产阶级现代化，同时接受普鲁士主导的君主立宪框架。"},{"label":"关键人物（可选）","value":"鲁道夫·冯·本尼格森等。"},{"label":"关键行动/事件","value":"早期支持俾斯麦统一和帝国建设；在文化斗争、经济政策和关税问题上出现分裂。"},{"label":"为什么重要","value":"它体现德国自由主义的困境：自由派推动现代法治和经济发展，却在国家统一后同强行政和军国结构妥协。"},{"label":"争议/局限","value":"民族自由党未能把自由主义转化为议会责任政府，部分原因是它优先支持民族国家和秩序。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Nationalliberale Partei；German History Documents and Images相关资料；Encyclopaedia Britannica相关条目。"}],"relationItems":["← 前因：德意志帝国成立","↔ 相关：德意志帝国议会","↔ 相关：德意志帝国保护关税政策"],"relations":[{"text":"← 前因：德意志帝国成立","id":"extra621"},{"text":"↔ 相关：德意志帝国议会","id":"extra669"},{"text":"↔ 相关：德意志帝国保护关税政策","id":"extra630"}],"source":"history","id":"extra674"},{"title":"泛德意志联盟","level":"B","type":"组织/机构卡","tags":["文化与思想","战争与外交"],"mainTag":"文化与思想","subTag":"战争与外交","timeText":"1891年成立","place":"德国","summary":"泛德意志联盟是帝国时期激进民族主义压力团体，鼓吹殖民扩张、海军建设和更强硬的民族政策。","fields":[{"label":"标题","value":"泛德意志联盟"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1891年成立"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国、奥匈帝国"},{"label":"一句话概括","value":"泛德意志联盟是帝国时期激进民族主义压力团体，鼓吹殖民扩张、海军建设和更强硬的民族政策。"},{"label":"性质/类型","value":"民族主义压力团体。"},{"label":"成立/解散时间","value":"1891年成立；帝国时期和魏玛早期持续影响右翼政治文化。"},{"label":"核心目标/宗旨","value":"扩大德国世界地位，强化德意志民族共同体，支持殖民扩张、海军扩张和对外强硬政策。"},{"label":"关键人物（可选）","value":"海因里希·克拉斯等。"},{"label":"关键行动/事件","value":"通过宣传、出版和政治游说影响公众舆论，批评政府外交不够强硬。"},{"label":"为什么重要","value":"它把民族主义从国家政策支持变成社会动员压力，推动帝国晚期政治语言更激进化。"},{"label":"争议/局限","value":"其影响力不是直接执政，而是通过舆论、精英网络和右翼文化塑造政策环境。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Alldeutscher Verband；German History Documents and Images相关资料；Encyclopaedia Britannica相关资料。"}],"relationItems":["← 前因：德国民族使命论","↔ 相关：德意志帝国世界政策","↔ 相关：德意志殖民帝国"],"relations":[{"text":"← 前因：德国民族使命论","id":"extra622"},{"text":"↔ 相关：德意志帝国世界政策","id":"extra635"},{"text":"↔ 相关：德意志殖民帝国","id":"extra641"}],"source":"history","id":"extra675"},{"title":"德国海军协会","level":"B","type":"组织/机构卡","tags":["战争与外交","文化与思想"],"mainTag":"战争与外交","subTag":"文化与思想","timeText":"1898年成立","place":"德国","summary":"德国海军协会把海军扩张变成群众宣传运动，为威廉时代海权政策制造社会支持。","fields":[{"label":"标题","value":"德国海军协会"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1898年成立"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国海军协会把海军扩张变成群众宣传运动，为威廉时代海权政策制造社会支持。"},{"label":"性质/类型","value":"海军主义压力团体、群众宣传组织。"},{"label":"成立/解散时间","value":"1898年成立，帝国时期迅速扩张。"},{"label":"核心目标/宗旨","value":"宣传海军建设必要性，支持提尔皮茨海军法，塑造德国必须成为世界海权强国的公众意识。"},{"label":"关键人物（可选）","value":"与提尔皮茨海军政策和保守民族主义网络关系密切。"},{"label":"关键行动/事件","value":"发行宣传材料、组织讲座和地方分会，把舰队建设同国家荣誉、贸易保护和世界地位联系起来。"},{"label":"为什么重要","value":"它说明海军扩张不只是政府军事政策，也是一种大众民族主义动员。"},{"label":"争议/局限","value":"协会夸大海军对国家生存的必要性，助长英德互疑和造舰竞争。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Deutscher Flottenverein；German History Documents and Images: Navy League；Encyclopaedia Britannica相关资料。"}],"relationItems":["← 前因：德意志帝国世界政策","→ 后果：德意志帝国海军扩张","→ 后果：德意志帝国英德海军竞赛"],"relations":[{"text":"← 前因：德意志帝国世界政策","id":"extra635"},{"text":"→ 后果：德意志帝国海军扩张","id":"extra636"},{"text":"→ 后果：德意志帝国英德海军竞赛","id":"extra637"}],"source":"history","id":"extra676"},{"title":"德国殖民协会","level":"C","type":"组织/机构卡","tags":["战争与外交","文化与思想"],"mainTag":"战争与外交","subTag":"文化与思想","timeText":"1880年代形成并发展","place":"德国","summary":"德国殖民协会推动殖民宣传和殖民利益游说，帮助把海外扩张包装为民族国家使命。","fields":[{"label":"标题","value":"德国殖民协会"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1880年代形成并发展"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国殖民协会推动殖民宣传和殖民利益游说，帮助把海外扩张包装为民族国家使命。"},{"label":"性质/类型","value":"殖民主义压力团体和宣传组织。"},{"label":"成立/解散时间","value":"1880年代形成，后与其他殖民团体整合，帝国时期持续活动。"},{"label":"核心目标/宗旨","value":"推动德国获取和维持殖民地，宣传移民、贸易、资源和民族声望利益。"},{"label":"关键人物（可选）","value":"殖民活动家、商人、民族主义者和部分政界人士。"},{"label":"关键行动/事件","value":"组织宣传、出版材料、支持殖民政策和殖民地开发。"},{"label":"为什么重要","value":"它说明殖民主义在德国不是单纯的政府决策，也依赖社会组织制造公众想象和压力。"},{"label":"争议/局限","value":"殖民宣传往往掩盖殖民地暴力、强制劳动和种族主义统治。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Kolonialbewegung；German History Documents and Images相关资料；Encyclopaedia Britannica: German colonial empire。"}],"relationItems":["← 前因：德意志殖民帝国","↔ 相关：德意志帝国世界政策","↔ 相关：德属西南非洲赫雷罗和纳马种族灭绝"],"relations":[{"text":"← 前因：德意志殖民帝国","id":"extra641"},{"text":"↔ 相关：德意志帝国世界政策","id":"extra635"},{"text":"↔ 相关：德属西南非洲赫雷罗和纳马种族灭绝","id":"extra642"}],"source":"history","id":"extra677"},{"title":"德国克虏伯公司","level":"B","type":"组织/机构卡","tags":["经济与社会","战争与外交"],"mainTag":"经济与社会","subTag":"战争与外交","timeText":"十九世纪至二十世纪持续重要","place":"德国埃森，鲁尔区","summary":"克虏伯公司是德国重工业和军火工业代表企业，连接鲁尔工业化、国家军备和帝国强权政治。","fields":[{"label":"标题","value":"德国克虏伯公司"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"十九世纪至二十世纪持续重要"},{"label":"地点","value":"德国埃森，鲁尔区"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"克虏伯公司是德国重工业和军火工业代表企业，连接鲁尔工业化、国家军备和帝国强权政治。"},{"label":"性质/类型","value":"钢铁和军火工业企业。"},{"label":"成立/解散时间","value":"家族企业十九世纪壮大；帝国时期成为德国最大工业企业之一。"},{"label":"核心目标/宗旨","value":"生产钢铁、铁路材料、机械和军火，尤其以大炮和装甲技术闻名。"},{"label":"关键人物（可选）","value":"阿尔弗雷德·克虏伯、弗里德里希·阿尔弗雷德·克虏伯、贝尔塔·克虏伯。"},{"label":"关键行动/事件","value":"为普鲁士和德意志帝国提供火炮和军工产品；在埃森形成企业城市和工人福利体系。"},{"label":"为什么重要","value":"克虏伯是德国工业资本、技术能力和军事国家之间关系的缩影。理解德国军备和鲁尔工业，绕不开克虏伯。"},{"label":"争议/局限","value":"企业福利和技术创新并存于军火利润、劳资控制和国家军备依赖之中。"},{"label":"出处","value":"Encyclopaedia Britannica: Krupp AG；Deutsches Historisches Museum/LeMO: Krupp；German History Documents and Images相关资料。"}],"relationItems":["↔ 相关：德意志帝国海军扩张","↔ 相关：德国战争经济","↔ 相关：德国鲁尔工业区"],"relations":[{"text":"↔ 相关：德意志帝国海军扩张","id":"extra636"},{"text":"↔ 相关：德国鲁尔工业区","id":"extra679"}],"source":"history","id":"extra678"},{"title":"德国鲁尔工业区","level":"A","type":"概念/思潮卡","tags":["经济与社会","战争与外交"],"mainTag":"经济与社会","subTag":"战争与外交","timeText":"十九世纪后期至二十世纪持续重要","place":"德国西部鲁尔地区","summary":"鲁尔工业区以煤炭、钢铁和重工业为核心，是德国工业崛起、战争能力和劳工政治的关键空间。","fields":[{"label":"标题","value":"德国鲁尔工业区"},{"label":"分级","value":"A"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"十九世纪后期至二十世纪持续重要"},{"label":"地点","value":"德国西部鲁尔地区"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"鲁尔工业区以煤炭、钢铁和重工业为核心，是德国工业崛起、战争能力和劳工政治的关键空间。"},{"label":"核心主张/思路","value":"这不是思想，而是一个经济地理节点：煤炭、钢铁、铁路、资本和工人阶级在鲁尔高度集中。"},{"label":"提出者/代表人物（可选）","value":"无单一提出者；克虏伯、蒂森等企业与地方矿业资本具有代表性。"},{"label":"它从何而来","value":"煤炭资源、铁路建设、关税同盟市场和德国工业化共同推动鲁尔崛起。"},{"label":"典型表现","value":"煤矿、钢厂、城市扩张、工人社区、工会组织和重工业集团。"},{"label":"为什么重要","value":"鲁尔是德国经济和军备能力的物质基础之一。1923年鲁尔占领、大萧条下工业失业和纳粹工业政策都与它有关。"},{"label":"争议/局限","value":"鲁尔繁荣伴随污染、矿难、住房拥挤和劳资冲突。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Industrialisierung/Ruhrgebiet；Encyclopaedia Britannica: Ruhr；German History Documents and Images相关资料。"}],"relationItems":["↔ 相关：德国克虏伯公司","→ 后果：鲁尔占领与德国消极抵抗","↔ 相关：德国社会民主党（SPD）"],"relations":[{"text":"↔ 相关：德国克虏伯公司","id":"extra678"},{"text":"→ 后果：鲁尔占领与德国消极抵抗","id":"card62"},{"text":"↔ 相关：德国社会民主党（SPD）","id":"extra628"}],"source":"history","id":"extra679"},{"title":"德国化学工业","level":"B","type":"概念/思潮卡","tags":["经济与社会","战争与外交"],"mainTag":"经济与社会","subTag":"战争与外交","timeText":"十九世纪后期至二十世纪持续重要","place":"德国，莱茵-鲁尔、巴登、黑森等工业区","summary":"德国化学工业在染料、药品、化肥和炸药原料上领先世界，是帝国工业实力和一战战争经济的重要基础。","fields":[{"label":"标题","value":"德国化学工业"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"十九世纪后期至二十世纪持续重要"},{"label":"地点","value":"德国，莱茵-鲁尔、巴登、黑森等工业区"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国化学工业在染料、药品、化肥和炸药原料上领先世界，是帝国工业实力和一战战争经济的重要基础。"},{"label":"核心主张/思路","value":"这是一种产业机制：大学化学、企业实验室、专利体系和大规模工业生产结合，形成高技术工业优势。"},{"label":"提出者/代表人物（可选）","value":"BASF、拜耳、赫斯特等企业；大学和企业化学家共同推动。"},{"label":"它从何而来","value":"德国高等教育、实验室科学、煤焦油化学和工业资本结合，推动合成染料和化学品生产。"},{"label":"典型表现","value":"合成染料、药品、摄影材料、炸药前体、氨合成和企业研发实验室。"},{"label":"为什么重要","value":"化学工业说明德国崛起不只是煤钢重工业，也依赖科学密集型产业。战时封锁下，化学工业尤其关系到炸药和肥料供应。"},{"label":"争议/局限","value":"技术创新与军工需求、环境污染和战争用途紧密交织。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Chemische Industrie；Encyclopaedia Britannica: chemical industry；BASF corporate history资料。"}],"relationItems":["↔ 相关：合成氨哈伯-博施法","↔ 相关：英国对德海上封锁","↔ 相关：一战总动员社会"],"relations":[{"text":"↔ 相关：合成氨哈伯-博施法","id":"extra681"},{"text":"↔ 相关：英国对德海上封锁","id":"extra652"},{"text":"↔ 相关：一战总动员社会","id":"extra653"}],"source":"history","id":"extra680"},{"title":"合成氨哈伯-博施法","level":"A","type":"概念/思潮卡","tags":["经济与社会","战争与外交"],"mainTag":"经济与社会","subTag":"战争与外交","timeText":"1909年前后实验突破，1913年工业化生产","place":"德国","summary":"合成氨哈伯-博施法实现工业固氮，使化肥和炸药原料生产摆脱天然硝石依赖，深刻改变农业和战争。","fields":[{"label":"标题","value":"合成氨哈伯-博施法"},{"label":"分级","value":"A"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1909年前后实验突破，1913年工业化生产"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"合成氨哈伯-博施法实现工业固氮，使化肥和炸药原料生产摆脱天然硝石依赖，深刻改变农业和战争。"},{"label":"核心主张/思路","value":"通过高温高压和催化剂把空气中的氮转化为氨，再用于化肥和硝酸盐生产。"},{"label":"提出者/代表人物（可选）","value":"弗里茨·哈伯完成实验室合成，卡尔·博施推动BASF工业化。"},{"label":"它从何而来","value":"全球农业和军工都需要氮化合物，德国尤其担心海上封锁切断智利硝石进口。"},{"label":"典型表现","value":"合成氨工厂、化肥生产、炸药原料供应。"},{"label":"为什么重要","value":"它是世界史级技术节点：支撑现代农业人口增长，也让德国在一战封锁下继续生产炸药。"},{"label":"争议/局限","value":"同一技术既服务粮食生产，也服务军火生产；哈伯本人还与化学战相关，技术伦理复杂。"},{"label":"出处","value":"Encyclopaedia Britannica: Haber-Bosch process；Nobel Prize biographies of Haber and Bosch；BASF history资料。"}],"relationItems":["← 前因：德国化学工业","↔ 相关：英国对德海上封锁","↔ 相关：一战总动员社会"],"relations":[{"text":"← 前因：德国化学工业","id":"extra680"},{"text":"↔ 相关：英国对德海上封锁","id":"extra652"},{"text":"↔ 相关：一战总动员社会","id":"extra653"}],"source":"history","id":"extra681"},{"title":"西门子与德国电气工业","level":"B","type":"组织/机构卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"十九世纪后期至二十世纪持续重要","place":"德国，柏林等工业中心","summary":"西门子和德国电气工业推动电报、电力、照明和城市基础设施扩张，是第二次工业革命的德国代表。","fields":[{"label":"标题","value":"西门子与德国电气工业"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"十九世纪后期至二十世纪持续重要"},{"label":"地点","value":"德国，柏林等工业中心"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"西门子和德国电气工业推动电报、电力、照明和城市基础设施扩张，是第二次工业革命的德国代表。"},{"label":"性质/类型","value":"电气工业企业与产业部门。"},{"label":"成立/解散时间","value":"西门子1847年创立，帝国时期成长为重要电气企业；电气工业在十九世纪后期迅速扩张。"},{"label":"核心目标/宗旨","value":"生产电报、电机、电缆、发电和照明等电气设备，建设现代通信与能源基础设施。"},{"label":"关键人物（可选）","value":"维尔纳·冯·西门子。"},{"label":"关键行动/事件","value":"电报网络、电气设备、城市照明和工业电力系统建设。"},{"label":"为什么重要","value":"电气工业说明德国工业化进入科学、工程和大企业结合的新阶段，改变城市生活、工厂生产和军事通信。"},{"label":"争议/局限","value":"电气现代化在不同阶层和地区普及不均，也强化大企业和技术官僚力量。"},{"label":"出处","value":"Encyclopaedia Britannica: Siemens AG；Deutsches Historisches Museum/LeMO: Elektrotechnik；German History Documents and Images相关资料。"}],"relationItems":["↔ 相关：德国化学工业","↔ 相关：魏玛柏林现代性","→ 后果：魏玛文化"],"relations":[{"text":"↔ 相关：德国化学工业","id":"extra680"},{"text":"↔ 相关：魏玛柏林现代性","id":"card33"},{"text":"→ 后果：魏玛文化","id":"card197"}],"source":"history","id":"extra682"},{"title":"德意志帝国柏林租住营房","level":"C","type":"概念/思潮卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"十九世纪后期至魏玛时期持续存在","place":"德国柏林","summary":"柏林租住营房是工业化城市住房拥挤的典型形式，体现德国城市化背后的阶级分化和生活压力。","fields":[{"label":"标题","value":"德意志帝国柏林租住营房"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"十九世纪后期至魏玛时期持续存在"},{"label":"地点","value":"德国柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"柏林租住营房是工业化城市住房拥挤的典型形式，体现德国城市化背后的阶级分化和生活压力。"},{"label":"核心主张/思路","value":"这不是思想，而是一种城市居住形态：多层院落式出租房容纳大量工人和低收入家庭。"},{"label":"提出者/代表人物（可选）","value":"无单一提出者，由城市土地市场、建筑规制和人口流入共同形成。"},{"label":"它从何而来","value":"柏林工业化和人口快速增长，住房供给不足，开发商在有限地块上追求高密度出租收益。"},{"label":"典型表现","value":"前楼较体面，后院和侧翼拥挤、采光差、卫生条件差，多户共用设施。"},{"label":"为什么重要","value":"它把工业化的宏观增长转化为日常生活经验。理解德国工人政治、城市改革和魏玛现代性，需要看到这种住房现实。"},{"label":"争议/局限","value":"租住营房不是所有城市居民住房，但它成为批评资本主义城市和社会改革的重要象征。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Mietskaserne/Urbanisierung；German History Documents and Images: Urbanization；Encyclopaedia Britannica: Berlin history。"}],"relationItems":["↔ 相关：德国社会民主党（SPD）","↔ 相关：魏玛文化","↔ 相关：魏玛柏林现代性"],"relations":[{"text":"↔ 相关：德国社会民主党（SPD）","id":"extra628"},{"text":"↔ 相关：魏玛文化","id":"card197"},{"text":"↔ 相关：魏玛柏林现代性","id":"card33"}],"source":"history","id":"extra683"},{"title":"德国妇女运动","level":"B","type":"概念/思潮卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"十九世纪后期至二十世纪初迅速发展","place":"德国","summary":"德国妇女运动围绕教育、职业、法律地位和参政权展开，是帝国社会现代化的重要组成部分。","fields":[{"label":"标题","value":"德国妇女运动"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"十九世纪后期至二十世纪初迅速发展"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国妇女运动围绕教育、职业、法律地位和参政权展开，是帝国社会现代化的重要组成部分。"},{"label":"核心主张/思路","value":"争取女性受教育权、职业机会、婚姻和法律地位改善，以及政治参与权。"},{"label":"提出者/代表人物（可选）","value":"路易丝·奥托-彼得斯、海伦妮·朗格、格特鲁德·鲍默等。"},{"label":"它从何而来","value":"工业化、城市化、教育扩张和中产阶级公共生活变化，使女性组织和权利诉求逐渐发展。"},{"label":"典型表现","value":"妇女协会、教育改革、职业培训、社会工作、参政权运动；1894年德国妇女协会联盟成立。"},{"label":"为什么重要","value":"它说明帝国德国的现代化不只发生在工业和军备，也发生在性别秩序和公民权边界上。"},{"label":"争议/局限","value":"中产阶级妇女运动与社会主义妇女运动在阶级、策略和目标上存在差异。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Frauenbewegung；German History Documents and Images: Women’s Movement；Encyclopaedia Britannica相关资料。"}],"relationItems":["→ 后果：魏玛宪法","↔ 相关：德国社会民主党（SPD）","↔ 相关：一战总动员社会"],"relations":[{"text":"→ 后果：魏玛宪法","id":"card11"},{"text":"↔ 相关：德国社会民主党（SPD）","id":"extra628"},{"text":"↔ 相关：一战总动员社会","id":"extra653"}],"source":"history","id":"extra684"},{"title":"德国青年运动","level":"C","type":"概念/思潮卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"十九世纪末至二十世纪初兴起","place":"德国","summary":"德国青年运动以远足、自然、反都市和自我教育为特征，反映现代工业社会中青年对学校、家庭和城市秩序的反叛。","fields":[{"label":"标题","value":"德国青年运动"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"十九世纪末至二十世纪初兴起"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国青年运动以远足、自然、反都市和自我教育为特征，反映现代工业社会中青年对学校、家庭和城市秩序的反叛。"},{"label":"核心主张/思路","value":"强调青年自主、亲近自然、简朴生活、民歌和集体体验，反对被工业城市和僵化学校完全规训。"},{"label":"提出者/代表人物（可选）","value":"Wandervogel 是早期代表组织。"},{"label":"它从何而来","value":"城市化、学校纪律、中产阶级家庭秩序和民族文化寻找共同塑造青年反叛形式。"},{"label":"典型表现","value":"徒步旅行、露营、民歌、青年团体、自然崇拜和文化批判。"},{"label":"为什么重要","value":"它是理解魏玛文化、保守革命、青年政治化和纳粹青年动员背景的前史之一。"},{"label":"争议/局限","value":"青年运动内部差异很大，既有自由反叛和文化改革，也有民族主义和排他倾向。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Jugendbewegung；German History Documents and Images相关资料；Encyclopaedia Britannica相关资料。"}],"relationItems":["↔ 相关：魏玛文化","→ 后果：纳粹希特勒青年团","↔ 相关：德国民族使命论"],"relations":[{"text":"↔ 相关：魏玛文化","id":"card197"},{"text":"→ 后果：纳粹希特勒青年团","id":"extra115"},{"text":"↔ 相关：德国民族使命论","id":"extra622"}],"source":"history","id":"extra685"},{"title":"反犹主义政治运动","level":"A","type":"概念/思潮卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"十九世纪后期至二十世纪上半叶持续发展","place":"德国及欧洲多国","summary":"现代反犹主义把宗教偏见、种族理论、民族主义和社会危机解释结合起来，成为德国右翼政治文化的重要毒素。","fields":[{"label":"标题","value":"反犹主义政治运动"},{"label":"分级","value":"A"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"十九世纪后期至二十世纪上半叶持续发展"},{"label":"地点","value":"德国及欧洲多国"},{"label":"主要国家","value":"德国、奥地利、法国、俄国"},{"label":"一句话概括","value":"现代反犹主义把宗教偏见、种族理论、民族主义和社会危机解释结合起来，成为德国右翼政治文化的重要毒素。"},{"label":"核心主张/思路","value":"把犹太人构造成破坏民族、资本、革命、自由主义或现代性的替罪羊，并以“种族”语言替代传统宗教排斥。"},{"label":"提出者/代表人物（可选）","value":"德国和奥地利有多种反犹政党、宣传家和社会组织，非单一人物创造。"},{"label":"它从何而来","value":"犹太人解放、城市化、资本主义冲击、民族主义竞争和伪科学种族论共同推动现代反犹主义。"},{"label":"典型表现","value":"反犹请愿、报刊宣传、政党动员、大学和职业排斥、阴谋论。"},{"label":"为什么重要","value":"它为纳粹意识形态提供了可继承的语言和社会基础。纳粹反犹不是凭空出现，而是激进化了长期存在的现代反犹主义。"},{"label":"争议/局限","value":"帝国时期反犹政党影响有限，但反犹观念在社会文化中的渗透不能低估。"},{"label":"出处","value":"United States Holocaust Memorial Museum: Antisemitism；Deutsches Historisches Museum/LeMO: Antisemitismus；German History Documents and Images相关资料。"}],"relationItems":["→ 后果：纳粹党成立","→ 后果：希特勒《我的奋斗》","↔ 相关：德国民族使命论"],"relations":[{"text":"→ 后果：纳粹党成立","id":"extra92"},{"text":"→ 后果：希特勒《我的奋斗》","id":"extra66"},{"text":"↔ 相关：德国民族使命论","id":"extra622"}],"source":"history","id":"extra686"},{"title":"威廉二世克鲁格电报","level":"B","type":"事件卡","tags":["战争与外交","文化与思想"],"mainTag":"战争与外交","subTag":"文化与思想","timeText":"1896年1月","place":"德国、南部非洲、英国外交舆论场","summary":"克鲁格电报是威廉二世祝贺布尔人抵抗英国相关行动的电报，引发英德舆论危机。","fields":[{"label":"标题","value":"威廉二世克鲁格电报"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1896年1月"},{"label":"地点","value":"德国、南部非洲、英国外交舆论场"},{"label":"主要国家","value":"德国、英国、德兰士瓦共和国"},{"label":"一句话概括","value":"克鲁格电报是威廉二世祝贺布尔人抵抗英国相关行动的电报，引发英德舆论危机。"},{"label":"参与者","value":"威廉二世、德兰士瓦总统保罗·克鲁格、英国政府和舆论。"},{"label":"发生了什么","value":"1895年底詹姆森袭击失败后，德兰士瓦共和国抵抗了英国相关势力的突袭。1896年1月，威廉二世向克鲁格发电表示祝贺，称赞其维护独立。英国舆论把电报视为德国干预英国帝国事务和挑战英国威望的信号，英德关系明显紧张。德国国内民族主义者则把电报看作强硬世界政策的姿态。事件最终没有导致战争，但显示德国外交象征动作可能放大为国际危机。"},{"label":"为什么重要","value":"它是威廉时代“姿态外交”的早期案例，暴露德国追求世界地位与英国帝国敏感点之间的冲突。"},{"label":"前因","value":"德意志帝国世界政策和英德殖民竞争已经使两国互疑，南部非洲布尔问题给威廉二世提供了向英国施压和展示德国影响力的机会。"},{"label":"后果","value":"电报激怒英国舆论，使英国更警惕德国外交意图，英德关系在十九世纪末进一步恶化。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Krüger-Depesche；German History Documents and Images相关资料；Encyclopaedia Britannica相关资料。"}],"relationItems":["← 前因：德意志帝国世界政策","→ 后果：德意志帝国英德海军竞赛","↔ 相关：“Ein Platz an der Sonne”"],"relations":[{"text":"← 前因：德意志帝国世界政策","id":"extra635"},{"text":"→ 后果：德意志帝国英德海军竞赛","id":"extra637"},{"text":"↔ 相关：“Ein Platz an der Sonne”","id":"proverb2"}],"source":"history","id":"extra687"},{"title":"威廉二世《每日电讯报》事件","level":"B","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1908年","place":"德国和英国舆论场","summary":"威廉二世《每日电讯报》事件因威廉二世公开言论引发宪政和外交危机，暴露皇帝个人外交的制度风险。","fields":[{"label":"标题","value":"威廉二世《每日电讯报》事件"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1908年"},{"label":"地点","value":"德国和英国舆论场"},{"label":"主要国家","value":"德国、英国"},{"label":"一句话概括","value":"威廉二世《每日电讯报》事件因威廉二世公开言论引发宪政和外交危机，暴露皇帝个人外交的制度风险。"},{"label":"参与者","value":"威廉二世、英国《每日电讯报》、德国政府、帝国议会和公众。"},{"label":"发生了什么","value":"1908年，英国《每日电讯报》发表威廉二世访谈，皇帝在其中声称自己对英国友好，同时发表多项容易引发误解和冒犯的外交言论。文章在英国和德国都引起强烈反应。英国舆论质疑德国意图，德国国内则批评皇帝未经有效约束地发表外交谈话，损害国家利益。帝国议会和政治精英要求限制皇帝个人干预外交，首相比洛也受到压力。威廉二世被迫暂时收敛公开发言。"},{"label":"为什么重要","value":"事件说明德意志帝国宪法下皇帝拥有巨大外交影响，但缺少成熟的议会责任约束。"},{"label":"前因","value":"威廉二世长期以个人化外交表达德意志帝国世界政策，英德关系紧张又使皇帝任何轻率谈话都容易被解释为战略信号。"},{"label":"后果","value":"事件引发德国国内对皇帝个人统治的批评，比洛威信受损，也暴露帝国宪制中皇帝权力和公共责任之间的矛盾。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Daily-Telegraph-Affäre；German History Documents and Images相关资料；Encyclopaedia Britannica: William II。"}],"relationItems":["← 前因：德国威廉二世亲政","↔ 相关：德意志帝国宪法","↔ 相关：德意志帝国英德海军竞赛"],"relations":[{"text":"← 前因：德国威廉二世亲政","id":"extra634"},{"text":"↔ 相关：德意志帝国宪法","id":"extra624"},{"text":"↔ 相关：德意志帝国英德海军竞赛","id":"extra637"}],"source":"history","id":"extra688"},{"title":"德意志帝国“霍屯督选举”","level":"C","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1907年","place":"德国","summary":"1907年帝国议会选举被殖民战争和民族主义动员主导，被称为“德意志帝国“霍屯督选举””。","fields":[{"label":"标题","value":"德意志帝国“霍屯督选举”"},{"label":"分级","value":"C"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1907年"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国、纳米比亚"},{"label":"一句话概括","value":"1907年帝国议会选举被殖民战争和民族主义动员主导，被称为“德意志帝国“霍屯督选举””。"},{"label":"参与者","value":"帝国政府、保守派、民族自由派、社会民主党、殖民主义宣传团体、德国选民。"},{"label":"发生了什么","value":"德属西南非洲战争和殖民经费争议引发帝国议会冲突，政府解散议会并发动选举。支持政府的保守派和自由派围绕殖民政策、民族荣誉和反社会主义进行动员，把社民党描绘成不爱国力量。选举中支持政府的“比洛集团”取得优势，社民党票数仍高但席位受选区制度影响减少。这个名称使用了当时带有殖民歧视色彩的说法，反映殖民主义如何进入国内选举政治。"},{"label":"为什么重要","value":"它说明殖民战争不只是海外事件，也能成为帝国国内民族主义和反社会主义动员工具。"},{"label":"前因","value":"德属西南非洲战争和殖民经费争议激化了帝国议会冲突，政府把是否支持殖民战争转化为民族主义和反社民党的选举议题。"},{"label":"后果","value":"选举短期强化了殖民主义和民族主义动员，也加深社民党与帝国体制的对立，显示殖民问题已经进入德国大众政治。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Hottentottenwahl；German History Documents and Images相关资料。"},{"label":"资料备注","value":"“霍屯督”是殖民时代带有歧视性的旧称，卡片仅用于说明历史称谓。"}],"relationItems":["← 前因：德属西南非洲赫雷罗和纳马种族灭绝","↔ 相关：德意志帝国议会","↔ 相关：德国殖民协会"],"relations":[{"text":"← 前因：德属西南非洲赫雷罗和纳马种族灭绝","id":"extra642"},{"text":"↔ 相关：德意志帝国议会","id":"extra669"},{"text":"↔ 相关：德国殖民协会","id":"extra677"}],"source":"history","id":"extra689"},{"title":"德意志帝国萨伯恩事件","level":"B","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1913年","place":"阿尔萨斯萨伯恩","summary":"萨伯恩事件因德军侮辱和压制阿尔萨斯居民引发宪政危机，暴露帝国军队凌驾文官政治的问题。","fields":[{"label":"标题","value":"德意志帝国萨伯恩事件"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1913年"},{"label":"地点","value":"阿尔萨斯萨伯恩"},{"label":"主要国家","value":"德国、法国"},{"label":"一句话概括","value":"萨伯恩事件因德军侮辱和压制阿尔萨斯居民引发宪政危机，暴露帝国军队凌驾文官政治的问题。"},{"label":"参与者","value":"驻萨伯恩德军军官、阿尔萨斯当地居民、帝国议会、德国政府和军方。"},{"label":"发生了什么","value":"1913年，驻阿尔萨斯萨伯恩的德国军官发表侮辱当地居民的言论，引起抗议。军方随后以强硬方式逮捕和压制民众，激起全国舆论。帝国议会批评政府和军方处理不当，并通过不信任表态，但首相不需对议会负责，政府并未因此下台。军方法庭对相关军官处理有限。事件显示在民族敏感地区，军队权威可以压过地方民意和文官政治。"},{"label":"为什么重要","value":"它是帝国宪政问题的集中表现：议会舆论可以愤怒，却无法有效控制军方和政府。"},{"label":"前因","value":"阿尔萨斯-洛林的身份矛盾和军队特权长期存在，普鲁士式军官文化在当地轻视民众和议会监督，最终引发冲突。"},{"label":"后果","value":"事件暴露帝国军方凌驾文官政治的问题，公众对军国主义和议会无力的不满上升。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Zabern-Affäre；German History Documents and Images相关资料；Encyclopaedia Britannica相关资料。"}],"relationItems":["← 前因：阿尔萨斯-洛林问题的形成","↔ 相关：德意志帝国议会","↔ 相关：德意志帝国宪法"],"relations":[{"text":"← 前因：阿尔萨斯-洛林问题的形成","id":"extra620"},{"text":"↔ 相关：德意志帝国议会","id":"extra669"},{"text":"↔ 相关：德意志帝国宪法","id":"extra624"}],"source":"history","id":"extra690"},{"title":"德国1914年战争贷款表决","level":"A","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1914年8月4日","place":"德意志帝国议会","summary":"1914年德国帝国议会一致通过战争贷款，标志主要政党进入“一战德国“城堡和平”政治休战”并暂时压下国内冲突。","fields":[{"label":"标题","value":"德国1914年战争贷款表决"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1914年8月4日"},{"label":"地点","value":"德意志帝国议会"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1914年德国帝国议会一致通过战争贷款，标志主要政党进入“一战德国“城堡和平”政治休战”并暂时压下国内冲突。"},{"label":"参与者","value":"德意志帝国议会、德国社会民主党（SPD）、帝国政府、各主要党派。"},{"label":"发生了什么","value":"一战爆发后，德国政府要求帝国议会批准战争贷款以支持动员和军事开支。社民党此前长期反军国主义和反战争，但在民族防御、党内纪律和害怕被镇压等压力下决定支持贷款。1914年8月4日，帝国议会各党一致投票通过战争贷款。政府宣称国内党争应暂停，形成“一战德国“城堡和平”政治休战”。但这种团结并不稳固，随着战争长期化、伤亡和饥饿加剧，社民党内部反战派逐渐分裂出来。"},{"label":"为什么重要","value":"它解释一战初期德国国内政治为何没有立即反战崩溃，也解释后来的社会主义分裂。"},{"label":"前因","value":"七月危机后民族防御情绪高涨，社民党担心被视为不爱国力量，同时帝国议会必须批准战争财政。"},{"label":"后果","value":"社民党支持战争贷款开启“一战德国“城堡和平”政治休战”，但战争持续后党内反战派分裂，德国左翼由此走向长期分裂。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Burgfrieden/Kriegskredite；German History Documents and Images相关资料；1914-1918 Online相关资料。"}],"relationItems":["← 前因：德国社会民主党（SPD）","← 前因：1914年七月危机","→ 后果：一战德国“城堡和平”政治休战","→ 后果：德国一战债务融资政策"],"relations":[{"text":"← 前因：德国社会民主党（SPD）","id":"extra628"},{"text":"← 前因：1914年七月危机","id":"extra646"},{"text":"→ 后果：一战德国“城堡和平”政治休战","id":"extra692"},{"text":"→ 后果：德国一战债务融资政策","id":"extra699"}],"source":"history","id":"extra691"},{"title":"一战德国“城堡和平”政治休战","level":"B","type":"概念/思潮卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1914年后，一战初期最突出","place":"德国","summary":"一战德国“城堡和平”政治休战指一战初期德国各党派暂时停止国内斗争、支持战争动员的政治共识。","fields":[{"label":"标题","value":"一战德国“城堡和平”政治休战"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1914年后，一战初期最突出"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"一战德国“城堡和平”政治休战指一战初期德国各党派暂时停止国内斗争、支持战争动员的政治共识。"},{"label":"核心主张/思路","value":"战争期间国内阶级和党派冲突应让位于民族团结，政党、工会和政府共同维护战争努力。"},{"label":"提出者/代表人物（可选）","value":"威廉二世“我不再认识党派，只认识德国人”的表述常被视为其象征。"},{"label":"它从何而来","value":"战争爆发时民族主义情绪、防御战争叙事、国家压力和社会组织自我约束共同形成。"},{"label":"典型表现","value":"社民党支持战争贷款，工会暂停罢工，媒体和政党降低公开冲突。"},{"label":"为什么重要","value":"一战德国“城堡和平”政治休战让帝国政府获得战争初期社会整合，但也把反战和阶级矛盾压入地下，战争长期化后反弹更强。"},{"label":"争议/局限","value":"它不是全民一致的真实状态，而是政治压力、审查和民族动员下形成的表面团结。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Burgfrieden；1914-1918 Online: Burgfrieden；German History Documents and Images相关资料。"}],"relationItems":["← 前因：德国1914年战争贷款表决","→ 后果：德国独立社会民主党","↔ 相关：一战总动员社会"],"relations":[{"text":"← 前因：德国1914年战争贷款表决","id":"extra691"},{"text":"→ 后果：德国独立社会民主党","id":"extra693"},{"text":"↔ 相关：一战总动员社会","id":"extra653"}],"source":"history","id":"extra692"},{"title":"德国独立社会民主党","level":"B","type":"组织/机构卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1917年成立","place":"德国","summary":"德国独立社会民主党由反战社民党人分裂而来，是一战后期和德国十一月革命中重要左翼力量。","fields":[{"label":"标题","value":"德国独立社会民主党"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1917年成立"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国独立社会民主党由反战社民党人分裂而来，是一战后期和德国十一月革命中重要左翼力量。"},{"label":"性质/类型","value":"社会主义政党、反战左翼政党。"},{"label":"成立/解散时间","value":"1917年从德国社会民主党分裂成立；1920年代部分成员并入共产党或回归社民党。"},{"label":"核心目标/宗旨","value":"反对继续战争，要求民主改革和社会主义政策，代表对社民党支持战争路线的不满。"},{"label":"关键人物（可选）","value":"胡戈·哈泽、卡尔·考茨基、爱德华·伯恩施坦等曾与其相关；斯巴达克派也一度在其内部活动。"},{"label":"关键行动/事件","value":"参与反战政治和德国十一月革命；同社民党在革命后政府方向上发生分歧。"},{"label":"为什么重要","value":"它说明一战长期化如何撕裂德国社会主义运动，并为魏玛左翼分裂埋下组织基础。"},{"label":"争议/局限","value":"党内从温和民主社会主义者到革命派差异很大，难以形成稳定统一路线。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: USPD；German History Documents and Images相关资料；Encyclopaedia Britannica相关资料。"}],"relationItems":["← 前因：一战德国“城堡和平”政治休战","← 前因：德国社会民主党（SPD）","→ 后果：德国十一月革命","→ 后果：德国斯巴达克起义"],"relations":[{"text":"← 前因：一战德国“城堡和平”政治休战","id":"extra692"},{"text":"← 前因：德国社会民主党（SPD）","id":"extra628"},{"text":"→ 后果：德国十一月革命","id":"extra666"},{"text":"→ 后果：德国斯巴达克起义","id":"card8"}],"source":"history","id":"extra693"},{"title":"德国共产党成立","level":"B","type":"事件卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1918年12月30日至1919年1月1日","place":"德国柏林","summary":"德国共产党在革命高潮中成立，试图把俄国式革命道路引入德国，却很快陷入镇压和左翼分裂。","fields":[{"label":"标题","value":"德国共产党成立"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1918年12月30日至1919年1月1日"},{"label":"地点","value":"德国柏林"},{"label":"主要国家","value":"德国、俄国"},{"label":"一句话概括","value":"德国共产党在革命高潮中成立，试图把俄国式革命道路引入德国，却很快陷入镇压和左翼分裂。"},{"label":"参与者","value":"斯巴达克同盟、罗莎·卢森堡、卡尔·李卜克内西、革命左翼代表。"},{"label":"发生了什么","value":"德国十一月革命后，德国左翼内部围绕议会道路、工兵委员会和社会主义革命方向分裂。斯巴达克同盟和其他革命左翼团体在柏林召开会议，成立德国共产党。党内许多人反对参加国民议会选举，倾向依靠街头和委员会推动革命。成立不久后，柏林局势激化为德国斯巴达克起义，党主要领袖卢森堡和李卜克内西被杀，新党遭受沉重打击。"},{"label":"为什么重要","value":"德国共产党成为魏玛时期重要左翼力量，但其诞生伴随暴力镇压和同社民党的深刻敌意。"},{"label":"前因","value":"德国十一月革命中，激进左翼对社民党领导的共和国和议会道路失望，俄国革命又提供了无产阶级革命的现实样板。"},{"label":"后果","value":"共产党成立后参与革命浪潮，斯巴达克起义被镇压加深魏玛左翼分裂，共产国际影响也进入德国政治。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: KPD；German History Documents and Images相关资料；Encyclopaedia Britannica相关资料。"}],"relationItems":["← 前因：德国十一月革命","← 前因：德国独立社会民主党","→ 后果：德国斯巴达克起义"],"relations":[{"text":"← 前因：德国十一月革命","id":"extra666"},{"text":"← 前因：德国独立社会民主党","id":"extra693"},{"text":"→ 后果：德国斯巴达克起义","id":"card8"}],"source":"history","id":"extra694"},{"title":"德国社会主义工人党《哥达纲领》","level":"B","type":"制度/文本卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1875年","place":"德国哥达","summary":"德国社会主义工人党《哥达纲领》是德国社会主义两派合并时的纲领文本，标志社民党前身形成，也引发马克思批判。","fields":[{"label":"标题","value":"德国社会主义工人党《哥达纲领》"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1875年"},{"label":"地点","value":"德国哥达"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国社会主义工人党《哥达纲领》是德国社会主义两派合并时的纲领文本，标志社民党前身形成，也引发马克思批判。"},{"label":"制定方/签署方","value":"德国全德工人联合会和德国社会主义爱森纳赫派合并形成的社会主义工人党。"},{"label":"主要内容","value":"提出普选权、工人权利、合作社、社会平等和社会主义目标，同时融合拉萨尔派和德国社会主义爱森纳赫派语言。"},{"label":"它试图解决什么问题","value":"德国工人运动需要结束组织分裂，形成统一政党参与帝国政治。"},{"label":"为什么重要","value":"它是德国社会民主主义制度化的关键文本。马克思的《德国社会主义工人党《哥达纲领》批判》也成为社会主义理论史重要文献。"},{"label":"争议/局限","value":"马克思批评其对国家、劳动价值和分配问题表述含混，认为向拉萨尔派让步过多。"},{"label":"造成的影响","value":"统一后的社会主义工人党成为德国社会民主党前身，并在帝国政治中快速成长。"},{"label":"出处","value":"German History Documents and Images: Gotha Program；Marxists Internet Archive: Critique of the Gotha Programme；Deutsches Historisches Museum/LeMO相关资料。"}],"relationItems":["← 前因：德国全德工人联合会","← 前因：德国社会主义爱森纳赫派","→ 后果：德国社会民主党（SPD）","↔ 相关：马克思恩格斯《共产党宣言》"],"relations":[{"text":"← 前因：德国全德工人联合会","id":"extra512"},{"text":"← 前因：德国社会主义爱森纳赫派","id":"extra514"},{"text":"→ 后果：德国社会民主党（SPD）","id":"extra628"},{"text":"↔ 相关：马克思恩格斯《共产党宣言》","id":"extra61"}],"source":"history","id":"extra695"},{"title":"德国社民党《爱尔福特纲领》","level":"B","type":"制度/文本卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1891年","place":"德国爱尔福特","summary":"德国社民党《爱尔福特纲领》确立德国社民党马克思主义理论目标与议会改革实践并存的路线。","fields":[{"label":"标题","value":"德国社民党《爱尔福特纲领》"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1891年"},{"label":"地点","value":"德国爱尔福特"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国社民党《爱尔福特纲领》确立德国社民党马克思主义理论目标与议会改革实践并存的路线。"},{"label":"制定方/签署方","value":"德国社会民主党。"},{"label":"主要内容","value":"理论部分强调资本主义发展和阶级斗争，实践部分提出普选、言论结社自由、劳动保护、社会政策等改革要求。"},{"label":"它试图解决什么问题","value":"反社会党人法结束后，社民党需要公开合法活动纲领，既保持社会主义目标，又适应议会政治。"},{"label":"为什么重要","value":"它塑造社会主义第二国际时期社会民主主义模式：革命目标和日常改良政治并存。"},{"label":"争议/局限","value":"理论与实践之间张力长期存在，后来引发德国社民党修正主义争论和党内路线分歧。"},{"label":"造成的影响","value":"德国社民党成为欧洲社会主义政党典范，并影响国际工人运动。"},{"label":"出处","value":"German History Documents and Images: Erfurt Program；Deutsches Historisches Museum/LeMO: Erfurter Programm；Marxists Internet Archive相关文本。"}],"relationItems":["← 前因：德国反社会党人法","← 前因：德国社会主义工人党《哥达纲领》","→ 后果：德国社民党修正主义争论","↔ 相关：德国社会民主党（SPD）"],"relations":[{"text":"← 前因：德国反社会党人法","id":"extra627"},{"text":"← 前因：德国社会主义工人党《哥达纲领》","id":"extra695"},{"text":"→ 后果：德国社民党修正主义争论","id":"extra697"},{"text":"↔ 相关：德国社会民主党（SPD）","id":"extra628"}],"source":"history","id":"extra696"},{"title":"德国社民党修正主义争论","level":"B","type":"概念/思潮卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1890年代末至二十世纪初","place":"德国社会民主党和社会主义第二国际语境","summary":"德国社民党修正主义争论围绕社民党是否应从革命马克思主义转向议会改良主义，揭示社会主义运动内部路线分裂。","fields":[{"label":"标题","value":"德国社民党修正主义争论"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1890年代末至二十世纪初"},{"label":"地点","value":"德国社会民主党和社会主义第二国际语境"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国社民党修正主义争论围绕社民党是否应从革命马克思主义转向议会改良主义，揭示社会主义运动内部路线分裂。"},{"label":"核心主张/思路","value":"伯恩施坦认为资本主义没有按预期崩溃，社民党应公开承认民主改革和渐进改良路线。"},{"label":"提出者/代表人物（可选）","value":"爱德华·伯恩施坦、卡尔·考茨基、罗莎·卢森堡。"},{"label":"它从何而来","value":"社民党在合法选举和工会活动中不断壮大，实际政治越来越改良化，与革命纲领产生矛盾。"},{"label":"典型表现","value":"党内理论辩论、报刊争论、代表大会决议以及社会主义第二国际内部争论。"},{"label":"为什么重要","value":"它预示二十世纪社会主义运动的核心裂缝：革命还是改良，议会民主还是阶级决战。"},{"label":"争议/局限","value":"党正式拒绝修正主义，但实际政策中大量采取议会和工会改良路线。"},{"label":"出处","value":"Encyclopaedia Britannica: Eduard Bernstein；German History Documents and Images: Revisionism Debate；Marxists Internet Archive相关文本。"}],"relationItems":["← 前因：德国社民党《爱尔福特纲领》","↔ 相关：德国社会民主党（SPD）","→ 后果：德国1914年战争贷款表决"],"relations":[{"text":"← 前因：德国社民党《爱尔福特纲领》","id":"extra696"},{"text":"↔ 相关：德国社会民主党（SPD）","id":"extra628"},{"text":"→ 后果：德国1914年战争贷款表决","id":"extra691"}],"source":"history","id":"extra697"},{"title":"社会主义第二国际","level":"A","type":"组织/机构卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1889年至1914年为核心阶段","place":"欧洲社会主义运动网络","summary":"社会主义第二国际把欧洲社会主义政党连接成跨国组织，但在一战爆发时未能阻止各国政党支持本国战争。","fields":[{"label":"标题","value":"社会主义第二国际"},{"label":"分级","value":"A"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1889年至1914年为核心阶段"},{"label":"地点","value":"欧洲社会主义运动网络"},{"label":"主要国家","value":"德国、法国、英国、奥地利、俄国等"},{"label":"一句话概括","value":"社会主义第二国际把欧洲社会主义政党连接成跨国组织，但在一战爆发时未能阻止各国政党支持本国战争。"},{"label":"性质/类型","value":"国际社会主义政党联盟。"},{"label":"成立/解散时间","value":"1889年成立；1914年一战爆发后事实上瓦解。"},{"label":"核心目标/宗旨","value":"协调各国社会主义政党和工人运动，推动国际主义、劳动权益、普选和反军国主义。"},{"label":"关键人物（可选）","value":"恩格斯晚年影响、考茨基、倍倍尔、饶勒斯等。"},{"label":"关键行动/事件","value":"确定五一劳动节传统，召开国际社会主义大会，讨论反战、殖民、妇女和工人权利问题。"},{"label":"为什么重要","value":"社会主义第二国际是德国社民党影响欧洲的舞台，也显示社会主义国际主义在民族国家战争面前的脆弱。"},{"label":"争议/局限","value":"组织缺乏强制力，各国政党最终受本国政治压力和民族动员影响。"},{"label":"出处","value":"Encyclopaedia Britannica: Second International；German History Documents and Images相关资料；Marxists Internet Archive相关资料。"}],"relationItems":["← 前因：马克思恩格斯《共产党宣言》","← 前因：德国社会民主党（SPD）","→ 后果：德国1914年战争贷款表决","→ 后果：第三国际"],"relations":[{"text":"← 前因：马克思恩格斯《共产党宣言》","id":"extra61"},{"text":"← 前因：德国社会民主党（SPD）","id":"extra628"},{"text":"→ 后果：德国1914年战争贷款表决","id":"extra691"}],"source":"history","id":"extra698"},{"title":"德国一战债务融资政策","level":"B","type":"事件卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1914年8月","place":"德国","summary":"德国政府在战时放弃税收，选择完全依靠举债与开动印钞机来维持一战开支，为魏玛共和国埋下了恶性通胀的导火索。","fields":[{"label":"标题","value":"德国一战债务融资政策"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1914年8月"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国政府在战时放弃税收，选择完全依靠举债与开动印钞机来维持一战开支，为魏玛共和国埋下了恶性通胀的导火索。"},{"label":"参与者","value":"德国帝国议会、财政国务秘书卡尔·赫尔费里希。"},{"label":"发生了什么","value":"1914年8月起，为筹措一战资金，德国政府并没有选择通过增加税收来应对庞大的战争开支。相反，财政国务秘书赫尔费里希宣布，战争融资将完全通过借款来实现。政府通过印钞机来满足政府和私人企业的信贷需求，直到1916年之前，税收在战争成本中没有发挥任何作用。"},{"label":"为什么重要","value":"从源头上确立了魏玛经济灾难的内在机制，即放弃财政纪律，习惯于用印钞来填补缺口。这种做法导致流通中的货币量到1917年增至1913年的五倍，德国积累了巨额的内部战争债务，彻底透支了国家财富。"},{"label":"前因","value":"德国选择主要依靠战争公债和借款而非立即增税来支付战争成本，是因为政府预期胜利后可用赔款和战利品弥补财政缺口。"},{"label":"后果","value":"战败使这种融资逻辑崩塌，魏玛政府继承巨额国内债务和财政压力，为战后通胀和1923年恶性通货膨胀埋下基础。"},{"label":"出处","value":"《When Money Dies》第1章"},{"label":"资料备注","value":"资料中仅提及1914年8月起实行该政策，未明确具体到哪一日，故此处仅写至1914年8月。"}],"relationItems":["→ 后果：魏玛恶性通货膨胀","↔ 相关：《凡尔赛和约》"],"relations":[{"text":"→ 后果：魏玛恶性通货膨胀","id":"card90"},{"text":"↔ 相关：《凡尔赛和约》","id":"card59"}],"source":"history","id":"extra699"},{"title":"一战列日战役","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1914年8月5日—8月16日","place":"比利时列日及周边要塞","summary":"列日战役是德国入侵比利时后的第一场关键战役，比利时要塞抵抗拖慢了德军进入法国的节奏。","fields":[{"label":"标题","value":"一战列日战役"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1914年8月5日—8月16日"},{"label":"地点","value":"比利时列日及周边要塞"},{"label":"主要国家","value":"比利时、德国"},{"label":"一句话概括","value":"列日战役是德国入侵比利时后的第一场关键战役，比利时要塞抵抗拖慢了德军进入法国的节奏。"},{"label":"参与者","value":"德国第一、第二集团军部分部队；比利时列日守军；埃里希·鲁登道夫等德军指挥官。"},{"label":"发生了什么","value":"德军按照西线进攻计划越过比利时边境，试图迅速夺取列日交通枢纽和默兹河通道。比利时守军依托环形要塞体系抵抗，德军初期正面强攻受挫，随后投入重炮，逐个摧毁要塞阵地。列日城较早失守，但外围要塞持续抵抗到8月中旬。"},{"label":"为什么重要","value":"它显示小国抵抗和现代要塞体系仍能影响大国作战节奏，也让德国入侵比利时的国际政治后果更快显现。"},{"label":"前因","value":"施里芬计划要求德军迅速通过比利时，列日要塞挡在德军通往法国北部的关键通道上。"},{"label":"后果","value":"德军攻克列日打开进入比利时的道路，但比利时抵抗拖慢推进，也加速英国参战和西线战局扩大。"},{"label":"出处","value":"Encyclopaedia Britannica，“World War I: The war in the west, 1914”；1914-1918 Online，“Belgium”。"},{"label":"资料备注","value":"列日城与列日要塞群失守时间不同，卡片时间按整个要塞战斗阶段处理。"}],"relationItems":["← 前因：德国施里芬计划","← 前因：德国入侵比利时","→ 后果：一战西线边境战役","→ 后果：第一次马恩河战役","↔ 相关：比利时中立","↔ 相关：一战西线堑壕战","✗ 对立/冲突：德国速决战设想","✗ 对立/冲突：比利时中立保障","↔ 同时期参考：一战东线坦能堡战役"],"relations":[{"text":"← 前因：德国施里芬计划","id":"extra643"},{"text":"← 前因：德国入侵比利时","id":"extra647"},{"text":"→ 后果：一战西线边境战役","id":"extra701"},{"text":"→ 后果：第一次马恩河战役","id":"extra650"},{"text":"↔ 相关：一战西线堑壕战","id":"extra651"},{"text":"✗ 对立/冲突：德国速决战设想","id":"extra927"},{"text":"↔ 同时期参考：一战东线坦能堡战役","id":"extra649"}],"source":"history","id":"extra700"},{"title":"一战西线边境战役","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1914年8月14日—8月24日","place":"法国东北部、比利时南部、阿尔萨斯-洛林","summary":"一战西线边境战役是一战西线开局的大规模交锋，法国进攻计划与德国侧翼推进同时碰撞并造成巨大伤亡。","fields":[{"label":"标题","value":"一战西线边境战役"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1914年8月14日—8月24日"},{"label":"地点","value":"法国东北部、比利时南部、阿尔萨斯-洛林"},{"label":"主要国家","value":"法国、德国、比利时、英国"},{"label":"一句话概括","value":"一战西线边境战役是一战西线开局的大规模交锋，法国进攻计划与德国侧翼推进同时碰撞并造成巨大伤亡。"},{"label":"参与者","value":"法国陆军、德国陆军、比利时军队、英国远征军。"},{"label":"发生了什么","value":"法国按照第十七号计划向阿尔萨斯-洛林和阿登方向进攻，希望夺回失地并压迫德军正面。与此同时，德国主力经比利时和卢森堡向法国北部推进。双方在洛林、阿登、沙勒罗瓦、蒙斯等地连续交战，法军多次在机枪、重炮和纵深火力面前受挫，被迫后撤；英军在蒙斯迟滞德军后也加入撤退。"},{"label":"为什么重要","value":"它粉碎了法国早期主动进攻的乐观预期，也把西线战局推向巴黎方向，为第一次马恩河战役铺垫。"},{"label":"前因","value":"德国施里芬计划和法国第十七号计划同时启动，双方都试图在战争初期通过进攻掌握主动。"},{"label":"后果","value":"法国在边境进攻中受挫，德军继续向巴黎方向推进，最终把双方带入第一次马恩河战役。"},{"label":"出处","value":"Encyclopaedia Britannica，“World War I: The war in the west, 1914”；Imperial War Museums，First World War western front materials。"}],"relationItems":["← 前因：德国施里芬计划","← 前因：一战列日战役","→ 后果：第一次马恩河战役","→ 后果：一战西线堑壕战","↔ 相关：英国参加第一次世界大战","✗ 对立/冲突：德国速决战设想","✗ 对立/冲突：德法复仇主义","↔ 同时期参考：一战东线坦能堡战役"],"relations":[{"text":"← 前因：德国施里芬计划","id":"extra643"},{"text":"← 前因：一战列日战役","id":"extra700"},{"text":"→ 后果：第一次马恩河战役","id":"extra650"},{"text":"→ 后果：一战西线堑壕战","id":"extra651"},{"text":"↔ 相关：英国参加第一次世界大战","id":"extra648"},{"text":"✗ 对立/冲突：德国速决战设想","id":"extra927"},{"text":"✗ 对立/冲突：德法复仇主义","id":"extra945"},{"text":"↔ 同时期参考：一战东线坦能堡战役","id":"extra649"}],"source":"history","id":"extra701"},{"title":"一战东线加利西亚战役","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1914年8月—9月","place":"加利西亚地区，今波兰东南部与乌克兰西部一带","summary":"一战东线加利西亚战役是东线开局的大规模会战，奥匈军队遭俄军重创，暴露出同盟国东线结构性弱点。","fields":[{"label":"标题","value":"一战东线加利西亚战役"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1914年8月—9月"},{"label":"地点","value":"加利西亚地区，今波兰东南部与乌克兰西部一带"},{"label":"主要国家","value":"奥匈帝国、俄罗斯帝国"},{"label":"一句话概括","value":"一战东线加利西亚战役是东线开局的大规模会战，奥匈军队遭俄军重创，暴露出同盟国东线结构性弱点。"},{"label":"参与者","value":"奥匈帝国军队、俄罗斯帝国军队。"},{"label":"发生了什么","value":"奥匈帝国试图在东线主动进攻俄军，同时还要应付塞尔维亚战场。俄军从多个方向进入加利西亚，双方在伦贝格等地连续作战。奥匈军队起初取得局部进展，但很快被俄军反击压倒，被迫放弃伦贝格并大规模后撤，损失大量兵员和装备。"},{"label":"为什么重要","value":"它使奥匈帝国很早就依赖德国支援，改变了同盟国内部力量关系，也让东线战争从一开始就成为德国无法忽视的压力源。"},{"label":"前因","value":"奥匈对塞尔维亚开战后又面对俄国总动员，东线兵力分配和情报判断失误使奥匈在加利西亚承受巨大压力。"},{"label":"后果","value":"奥匈遭受重创后更依赖德国支援，东线负担加重，并为1915年德奥联合反攻创造背景。"},{"label":"出处","value":"1914-1918 Online，“Eastern Front”；Encyclopaedia Britannica，World War I Eastern Front overview。"}],"relationItems":["← 前因：1914年七月危机","← 前因：德国对奥匈的“空白支票”保证","→ 后果：戈尔利采-塔尔努夫攻势","→ 后果：布鲁西洛夫攻势","↔ 相关：一战东线坦能堡战役","↔ 相关：奥匈帝国民族问题","✗ 对立/冲突：俄国泛斯拉夫主义","✗ 对立/冲突：奥匈帝国多民族军队","↔ 同时期参考：一战西线边境战役"],"relations":[{"text":"← 前因：1914年七月危机","id":"extra646"},{"text":"← 前因：德国对奥匈的“空白支票”保证","id":"extra645"},{"text":"→ 后果：戈尔利采-塔尔努夫攻势","id":"extra708"},{"text":"→ 后果：布鲁西洛夫攻势","id":"extra710"},{"text":"↔ 相关：一战东线坦能堡战役","id":"extra649"},{"text":"↔ 相关：奥匈帝国民族问题","id":"extra929"},{"text":"✗ 对立/冲突：俄国泛斯拉夫主义","id":"extra917"},{"text":"✗ 对立/冲突：奥匈帝国多民族军队","id":"extra948"},{"text":"↔ 同时期参考：一战西线边境战役","id":"extra701"}],"source":"history","id":"extra702"},{"title":"一战日英攻占青岛战役","level":"C","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1914年8月27日—11月7日","place":"中国山东青岛及胶州湾租借地","summary":"一战日英攻占青岛战役使德国在东亚的主要殖民据点被日本夺取，也扩大了日本在中国山东的影响。","fields":[{"label":"标题","value":"一战日英攻占青岛战役"},{"label":"分级","value":"C"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1914年8月27日—11月7日"},{"label":"地点","value":"中国山东青岛及胶州湾租借地"},{"label":"主要国家","value":"日本、德国、英国、中国"},{"label":"一句话概括","value":"一战日英攻占青岛战役使德国在东亚的主要殖民据点被日本夺取，也扩大了日本在中国山东的影响。"},{"label":"参与者","value":"日本陆海军、英国支援部队、德国青岛守军、中国北洋政府作为战场所在地相关方。"},{"label":"发生了什么","value":"日本以英日同盟和对德宣战为背景，要求德国交出胶州湾租借地，遭拒后从海陆方向围攻青岛。日军在山东登陆并推进，英军小部队参加作战，德国守军依托要塞和港口防御。经过炮击、围困和阵地推进，德军于1914年11月投降。"},{"label":"为什么重要","value":"它说明第一次世界大战从一开始就是全球战争，也直接连接到战后山东问题、五四运动和东亚国际秩序变化。"},{"label":"前因","value":"一战爆发后，日本根据英日同盟和自身在东亚扩张利益，向德国在山东的租借地和军事据点发动进攻。"},{"label":"后果","value":"德国失去在中国的重要据点，山东权益问题进入一战后巴黎和会，并在中国引发强烈民族主义反应。"},{"label":"出处","value":"1914-1918 Online，“Tsingtao”；Encyclopaedia Britannica，World War I global war materials。"}],"relationItems":["← 前因：德国殖民扩张","← 前因：英日同盟","→ 后果：巴黎和会山东问题","→ 后果：五四运动","↔ 相关：德国海外殖民地","↔ 相关：日本参加第一次世界大战","✗ 对立/冲突：德国在华权益","✗ 对立/冲突：日本对华扩张","↔ 同时期参考：加里波利战役","↔ 同时期参考：一战德属东非战役"],"relations":[{"text":"← 前因：德国殖民扩张","id":"extra942"},{"text":"→ 后果：巴黎和会山东问题","id":"card206"},{"text":"→ 后果：五四运动","id":"card205"},{"text":"↔ 同时期参考：加里波利战役","id":"extra706"},{"text":"↔ 同时期参考：一战德属东非战役","id":"extra719"}],"source":"history","id":"extra703"},{"title":"第一次伊普尔战役","level":"B","type":"事件卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1914年10月19日—11月22日","place":"比利时伊普尔突出部","summary":"第一次伊普尔战役是“奔向大海”后的关键战斗，西线机动战基本结束，堑壕战格局固定下来。","fields":[{"label":"标题","value":"第一次伊普尔战役"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1914年10月19日—11月22日"},{"label":"地点","value":"比利时伊普尔突出部"},{"label":"主要国家","value":"德国、英国、法国、比利时"},{"label":"一句话概括","value":"第一次伊普尔战役是“奔向大海”后的关键战斗，西线机动战基本结束，堑壕战格局固定下来。"},{"label":"参与者","value":"德国陆军；英国远征军；法国军队；比利时军队。"},{"label":"发生了什么","value":"马恩河战役后，德法英双方试图从北翼包抄对方，战线一路延伸到北海附近。双方在伊普尔周围反复争夺交通节点和高地，德军投入大量新编部队，英法比军队拼死防守。战役造成巨大伤亡，但没有一方取得决定性突破，伊普尔突出部成为此后西线长期争夺的焦点。"},{"label":"为什么重要","value":"它标志西线从运动战转入阵地战，使伊普尔成为现代工业化消耗战的象征地点之一。"},{"label":"前因","value":"马恩河战役后双方向北机动争夺侧翼，试图控制通往海峡港口和佛兰德斯的战略通道。"},{"label":"后果","value":"双方未能形成决定性突破，西线从机动作战转入连续堑壕体系，伊普尔成为长期消耗战象征。"},{"label":"出处","value":"Imperial War Museums，First Ypres materials；Encyclopaedia Britannica，World War I western front overview。"}],"relationItems":["← 前因：第一次马恩河战役","← 前因：一战西线边境战役","→ 后果：一战西线堑壕战","→ 后果：第二次伊普尔战役","↔ 相关：英国远征军","↔ 相关：德军预备役动员","✗ 对立/冲突：德国速决战设想","✗ 对立/冲突：协约国守势防御","↔ 同时期参考：一战日英攻占青岛战役"],"relations":[{"text":"← 前因：第一次马恩河战役","id":"extra650"},{"text":"← 前因：一战西线边境战役","id":"extra701"},{"text":"→ 后果：一战西线堑壕战","id":"extra651"},{"text":"→ 后果：第二次伊普尔战役","id":"extra707"},{"text":"✗ 对立/冲突：德国速决战设想","id":"extra927"},{"text":"↔ 同时期参考：一战日英攻占青岛战役","id":"extra703"}],"source":"history","id":"extra704"},{"title":"1914年圣诞休战","level":"C","type":"事件卡","tags":["文化与思想","战争与外交"],"mainTag":"文化与思想","subTag":"战争与外交","timeText":"1914年12月24日—12月25日前后","place":"西线部分战壕地段，尤其是佛兰德地区","summary":"1914年圣诞休战是西线士兵自发停火的著名片段，反映战争初期人性经验与总体战逻辑之间的张力。","fields":[{"label":"标题","value":"1914年圣诞休战"},{"label":"分级","value":"C"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1914年12月24日—12月25日前后"},{"label":"地点","value":"西线部分战壕地段，尤其是佛兰德地区"},{"label":"主要国家","value":"英国、德国、法国、比利时"},{"label":"一句话概括","value":"1914年圣诞休战是西线士兵自发停火的著名片段，反映战争初期人性经验与总体战逻辑之间的张力。"},{"label":"参与者","value":"西线部分英军、德军、法军和比利时士兵，主要是前线基层士兵自发参与。"},{"label":"发生了什么","value":"1914年圣诞前后，西线若干地段出现非正式停火。部分士兵唱圣诞歌、交换香烟和食物、埋葬阵亡者，甚至短暂进入无人区交流。但休战并非全线发生，也没有得到最高指挥层正式批准。此后军方加强纪律和轮换，类似大规模自发休战很难再次出现。"},{"label":"为什么重要","value":"它不是改变战局的战役，却是理解一战士兵经验、民族主义动员和战争机器如何压倒个人情感的重要窗口。"},{"label":"前因","value":"西线堑壕战初期，士兵长期近距离对峙且尚未完全适应总体战纪律，圣诞节宗教和文化共同性促成局部自发接触。"},{"label":"后果","value":"各国指挥层随后加强军纪和宣传，类似大规模自发休战难以再出现，总体战对士兵日常生活的控制进一步强化。"},{"label":"出处","value":"Imperial War Museums，“The Christmas Truce”；1914-1918 Online，Christmas Truce materials。"}],"relationItems":["← 前因：第一次伊普尔战役","← 前因：一战西线堑壕战","→ 后果：一战总动员社会","↔ 相关：一战士兵经验","↔ 相关：战争宣传","✗ 对立/冲突：前线士兵互认经验","✗ 对立/冲突：国家战争动员","↔ 同时期参考：一战日英攻占青岛战役"],"relations":[{"text":"← 前因：第一次伊普尔战役","id":"extra704"},{"text":"← 前因：一战西线堑壕战","id":"extra651"},{"text":"→ 后果：一战总动员社会","id":"extra653"},{"text":"↔ 相关：一战士兵经验","id":"extra936"},{"text":"↔ 相关：战争宣传","id":"extra946"},{"text":"↔ 同时期参考：一战日英攻占青岛战役","id":"extra703"}],"source":"history","id":"extra705"},{"title":"加里波利战役","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1915年2月—1916年1月","place":"达达尼尔海峡与加里波利半岛","summary":"加里波利战役是协约国试图打通达达尼尔海峡的失败行动，深刻影响奥斯曼、英国和澳新历史记忆。","fields":[{"label":"标题","value":"加里波利战役"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1915年2月—1916年1月"},{"label":"地点","value":"达达尼尔海峡与加里波利半岛"},{"label":"主要国家","value":"奥斯曼帝国、英国、法国、澳大利亚、新西兰"},{"label":"一句话概括","value":"加里波利战役是协约国试图打通达达尼尔海峡的失败行动，深刻影响奥斯曼、英国和澳新历史记忆。"},{"label":"参与者","value":"奥斯曼帝国军队；英国、法国、澳大利亚、新西兰等协约国部队；温斯顿·丘吉尔、穆斯塔法·凯末尔等相关人物。"},{"label":"发生了什么","value":"协约国希望通过海军突破达达尼尔海峡，迫使奥斯曼退出战争并建立通向俄国的补给线。海军强攻受阻后，英法及澳新部队在加里波利半岛登陆，却陷入地形狭窄、防守坚固、补给困难和疾病流行的困境。奥斯曼军队在凯末尔等指挥官组织下坚守，协约国最终撤退。"},{"label":"为什么重要","value":"它是协约国一次战略性失败，巩固了奥斯曼战争地位，也成为土耳其民族主义和澳新军团记忆的重要起点。"},{"label":"前因","value":"奥斯曼帝国加入同盟国后，协约国希望打通达达尼尔海峡，恢复对俄补给并迫使奥斯曼退出战争。"},{"label":"后果","value":"战役失败使丘吉尔政治受挫，奥斯曼获得重要防御胜利，中东和巴尔干方向的战争继续扩大。"},{"label":"出处","value":"Encyclopaedia Britannica，“Gallipoli Campaign”；Australian War Memorial，Gallipoli campaign overview。"}],"relationItems":["← 前因：奥斯曼帝国参加第一次世界大战","← 前因：英俄法协约体系","→ 后果：土耳其民族运动","→ 后果：中东战场","↔ 相关：穆斯塔法·凯末尔","↔ 相关：澳新军团记忆","✗ 对立/冲突：协约国海峡战略","✗ 对立/冲突：奥斯曼帝国防御","↔ 同时期参考：第二次伊普尔战役","↔ 同时期参考：戈尔利采-塔尔努夫攻势"],"relations":[{"text":"↔ 同时期参考：第二次伊普尔战役","id":"extra707"},{"text":"↔ 同时期参考：戈尔利采-塔尔努夫攻势","id":"extra708"}],"source":"history","id":"extra706"},{"title":"第二次伊普尔战役","level":"B","type":"事件卡","tags":["战争与外交","文化与思想"],"mainTag":"战争与外交","subTag":"文化与思想","timeText":"1915年4月22日—5月25日","place":"比利时伊普尔突出部","summary":"第二次伊普尔战役因德军大规模使用氯气而著名，化学武器进入现代战场的恐怖记忆由此定型。","fields":[{"label":"标题","value":"第二次伊普尔战役"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1915年4月22日—5月25日"},{"label":"地点","value":"比利时伊普尔突出部"},{"label":"主要国家","value":"德国、英国、法国、加拿大、比利时"},{"label":"一句话概括","value":"第二次伊普尔战役因德军大规模使用氯气而著名，化学武器进入现代战场的恐怖记忆由此定型。"},{"label":"参与者","value":"德国陆军；英军、法军、加拿大军队和比利时军队。"},{"label":"发生了什么","value":"德军在伊普尔突出部向协约国阵地释放大量氯气，造成法军殖民部队和相邻阵地严重混乱，并打开战线缺口。德军未能及时投入足够预备队扩大战果，英军和加拿大部队在极大伤亡中稳住防线。战役持续数周，伊普尔突出部仍未被德军完全夺取。"},{"label":"为什么重要","value":"它使化学武器成为一战的标志性恐怖，也显示技术突破如果缺乏战役层面配合，仍难改变西线僵局。"},{"label":"前因","value":"第一次伊普尔战役后西线在佛兰德斯陷入僵持，德国需要寻找突破堑壕防线的新手段，毒气武器因此被投入大规模战场试验。"},{"label":"后果","value":"毒气大规模使用开启化学战升级，双方发展防护和报复性化学武器，西线战争更加残酷。"},{"label":"出处","value":"Imperial War Museums，“Second Battle of Ypres”；1914-1918 Online，chemical warfare materials。"}],"relationItems":["← 前因：第一次伊普尔战役","← 前因：一战西线堑壕战","→ 后果：第三次伊普尔战役","→ 后果：战后化学武器禁忌","↔ 相关：弗里茨·哈伯","↔ 相关：现代化学工业","✗ 对立/冲突：军事技术突破","✗ 对立/冲突：国际战争伦理","↔ 同时期参考：加里波利战役","↔ 同时期参考：戈尔利采-塔尔努夫攻势"],"relations":[{"text":"← 前因：第一次伊普尔战役","id":"extra704"},{"text":"← 前因：一战西线堑壕战","id":"extra651"},{"text":"→ 后果：第三次伊普尔战役","id":"extra713"},{"text":"↔ 相关：弗里茨·哈伯","id":"extra940"},{"text":"↔ 同时期参考：加里波利战役","id":"extra706"},{"text":"↔ 同时期参考：戈尔利采-塔尔努夫攻势","id":"extra708"}],"source":"history","id":"extra707"},{"title":"戈尔利采-塔尔努夫攻势","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1915年5月—9月","place":"加利西亚，主要从戈尔利采—塔尔努夫一线向东推进","summary":"戈尔利采-塔尔努夫攻势是同盟国在东线的重大突破，迫使俄军大撤退并缓解奥匈危机。","fields":[{"label":"标题","value":"戈尔利采-塔尔努夫攻势"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1915年5月—9月"},{"label":"地点","value":"加利西亚，主要从戈尔利采—塔尔努夫一线向东推进"},{"label":"主要国家","value":"德国、奥匈帝国、俄罗斯帝国"},{"label":"一句话概括","value":"戈尔利采-塔尔努夫攻势是同盟国在东线的重大突破，迫使俄军大撤退并缓解奥匈危机。"},{"label":"参与者","value":"德国第十一集团军、奥匈军队、俄罗斯帝国军队；奥古斯特·冯·马肯森等指挥官。"},{"label":"发生了什么","value":"德国和奥匈在加利西亚集中重炮和精锐部队，对俄军防线实施突破。攻势从戈尔利采—塔尔努夫地区开始，德奥军队在炮火准备后快速推进，俄军防线崩溃并向东大撤退。同盟国重新夺回加利西亚重要地区，并把俄军推出波兰大部。"},{"label":"为什么重要","value":"它证明东线仍可通过集中火力实现突破，也使俄国战争压力和国内危机进一步加深。"},{"label":"前因","value":"一战东线加利西亚战役使奥匈东线处境恶化，德国需要通过集中火力和兵力稳定盟友并打击俄军。"},{"label":"后果","value":"俄军被迫大撤退，东线暂时向同盟国有利方向转变，但俄国战争压力和社会不满继续积累。"},{"label":"出处","value":"Encyclopaedia Britannica，World War I Eastern Front overview；1914-1918 Online，“Eastern Front”。"}],"relationItems":["← 前因：一战东线加利西亚战役","← 前因：一战东线坦能堡战役","→ 后果：布鲁西洛夫攻势","→ 后果：俄国二月革命","↔ 相关：德国东线战略","↔ 相关：奥匈帝国军事依赖","✗ 对立/冲突：同盟国集中突破","✗ 对立/冲突：俄军补给与指挥危机","↔ 同时期参考：第二次伊普尔战役","↔ 同时期参考：加里波利战役"],"relations":[{"text":"← 前因：一战东线加利西亚战役","id":"extra702"},{"text":"← 前因：一战东线坦能堡战役","id":"extra649"},{"text":"→ 后果：布鲁西洛夫攻势","id":"extra710"},{"text":"→ 后果：俄国二月革命","id":"extra937"},{"text":"↔ 同时期参考：第二次伊普尔战役","id":"extra707"},{"text":"↔ 同时期参考：加里波利战役","id":"extra706"}],"source":"history","id":"extra708"},{"title":"卢西塔尼亚号沉没","level":"B","type":"事件卡","tags":["战争与外交","文化与思想"],"mainTag":"战争与外交","subTag":"文化与思想","timeText":"1915年5月7日","place":"爱尔兰近海","summary":"卢西塔尼亚号沉没使德国潜艇战激怒美国舆论，成为美国最终走向参战的重要背景。","fields":[{"label":"标题","value":"卢西塔尼亚号沉没"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1915年5月7日"},{"label":"地点","value":"爱尔兰近海"},{"label":"主要国家","value":"德国、英国、美国"},{"label":"一句话概括","value":"卢西塔尼亚号沉没使德国潜艇战激怒美国舆论，成为美国最终走向参战的重要背景。"},{"label":"参与者","value":"德国U-20潜艇；英国邮轮卢西塔尼亚号；船上乘客与船员；美国政府和公众舆论。"},{"label":"发生了什么","value":"德国潜艇U-20在爱尔兰近海击沉英国客轮卢西塔尼亚号，造成大量平民死亡，其中包括美国公民。德国方面强调该船属于敌国船只且可能载有军需品，英美舆论则集中谴责德国对民用船只发动攻击。事件引发美国强烈抗议，迫使德国一度调整潜艇战策略。"},{"label":"为什么重要","value":"它没有立刻使美国参战，但极大改变了美国公众对德国的观感，为1917年无限制潜艇战引发美国参战埋下伏笔。"},{"label":"前因","value":"英国封锁和德国潜艇战升级使民用航运处在危险中，德国试图用潜艇削弱英国补给线。"},{"label":"后果","value":"美国反德舆论显著增强，德国一度限制潜艇战，但这一事件成为后来美国参战舆论的重要背景。"},{"label":"出处","value":"Encyclopaedia Britannica，“Lusitania”；National WWI Museum and Memorial，Lusitania materials。"}],"relationItems":["← 前因：英国对德海上封锁","← 前因：德国海军战略","→ 后果：德国无限制潜艇战","→ 后果：美国参加第一次世界大战","↔ 相关：战争宣传","↔ 相关：一战海上战争","✗ 对立/冲突：封锁战","✗ 对立/冲突：一战中立国航行权","↔ 同时期参考：戈尔利采-塔尔努夫攻势"],"relations":[{"text":"← 前因：英国对德海上封锁","id":"extra652"},{"text":"→ 后果：德国无限制潜艇战","id":"extra658"},{"text":"→ 后果：美国参加第一次世界大战","id":"extra660"},{"text":"↔ 相关：战争宣传","id":"extra946"},{"text":"↔ 相关：一战海上战争","id":"extra957"},{"text":"✗ 对立/冲突：一战中立国航行权","id":"extra964"},{"text":"↔ 同时期参考：戈尔利采-塔尔努夫攻势","id":"extra708"}],"source":"history","id":"extra709"},{"title":"布鲁西洛夫攻势","level":"A","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1916年6月—9月","place":"东线加利西亚、布科维纳等地区","summary":"布鲁西洛夫攻势是俄军在一战中最成功的大规模攻势之一，重创奥匈并牵动同盟国整体战略。","fields":[{"label":"标题","value":"布鲁西洛夫攻势"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1916年6月—9月"},{"label":"地点","value":"东线加利西亚、布科维纳等地区"},{"label":"主要国家","value":"俄罗斯帝国、奥匈帝国、德国"},{"label":"一句话概括","value":"布鲁西洛夫攻势是俄军在一战中最成功的大规模攻势之一，重创奥匈并牵动同盟国整体战略。"},{"label":"参与者","value":"俄罗斯西南方面军、奥匈帝国军队、德国支援部队；阿列克谢·布鲁西洛夫。"},{"label":"发生了什么","value":"俄军为配合协约国总体压力，在东线南段发动攻势。布鲁西洛夫采用较短炮火准备、多点突破和突击队渗透等方式，突破奥匈防线并俘获大量士兵。奥匈军队遭受严重打击，德国不得不调兵救援。攻势后期因补给、增援和俄军其他方面配合不足而放缓。"},{"label":"为什么重要","value":"它削弱奥匈帝国战争能力，促使罗马尼亚加入协约国，也加重俄国军队与社会的消耗。"},{"label":"前因","value":"协约国希望通过多线攻势减轻凡尔登压力，俄军也需要恢复东线主动权并支援意大利。"},{"label":"后果","value":"奥匈军队遭受沉重打击并更加依赖德国，罗马尼亚受鼓舞参战，同时俄国自身消耗也加剧革命压力。"},{"label":"出处","value":"Encyclopaedia Britannica，World War I Eastern Front overview；1914-1918 Online，“Brusilov Offensive”。"}],"relationItems":["← 前因：凡尔登战役","← 前因：戈尔利采-塔尔努夫攻势","→ 后果：一战罗马尼亚战役","→ 后果：俄国二月革命","↔ 相关：奥匈帝国民族问题","↔ 相关：协约国协调战略","✗ 对立/冲突：俄军战术创新","✗ 对立/冲突：同盟国东线防御","↔ 同时期参考：索姆河战役"],"relations":[{"text":"← 前因：凡尔登战役","id":"extra654"},{"text":"← 前因：戈尔利采-塔尔努夫攻势","id":"extra708"},{"text":"→ 后果：一战罗马尼亚战役","id":"extra711"},{"text":"→ 后果：俄国二月革命","id":"extra937"},{"text":"↔ 相关：奥匈帝国民族问题","id":"extra929"},{"text":"↔ 同时期参考：索姆河战役","id":"extra655"}],"source":"history","id":"extra710"},{"title":"一战罗马尼亚战役","level":"B","type":"事件卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1916年8月—1917年1月","place":"罗马尼亚、特兰西瓦尼亚、瓦拉几亚、摩尔达维亚","summary":"罗马尼亚战役显示小国参战收益与风险并存，同盟国迅速占领瓦拉几亚并获得重要资源。","fields":[{"label":"标题","value":"一战罗马尼亚战役"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1916年8月—1917年1月"},{"label":"地点","value":"罗马尼亚、特兰西瓦尼亚、瓦拉几亚、摩尔达维亚"},{"label":"主要国家","value":"罗马尼亚、德国、奥匈帝国、保加利亚、奥斯曼帝国、俄罗斯帝国"},{"label":"一句话概括","value":"罗马尼亚战役显示小国参战收益与风险并存，同盟国迅速占领瓦拉几亚并获得重要资源。"},{"label":"参与者","value":"罗马尼亚军队；德国、奥匈、保加利亚、奥斯曼军队；俄罗斯支援部队；奥古斯特·冯·马肯森、埃里希·冯·法金汉等。"},{"label":"发生了什么","value":"罗马尼亚在布鲁西洛夫攻势后加入协约国，进攻奥匈控制的特兰西瓦尼亚。德国、奥匈、保加利亚和奥斯曼迅速组织反击，从多个方向压迫罗马尼亚。罗马尼亚军队后撤，首都布加勒斯特失守，瓦拉几亚和油田区被同盟国占领，罗马尼亚政府和残余军队退往摩尔达维亚。"},{"label":"为什么重要","value":"它让德国获得罗马尼亚粮食和石油资源，但也进一步拉长战线，暴露巴尔干—东线战略联动的重要性。"},{"label":"前因","value":"布鲁西洛夫攻势后罗马尼亚认为协约国形势有利，并希望通过参战实现领土诉求。"},{"label":"后果","value":"同盟国迅速击败罗马尼亚并占领布加勒斯特，获得粮食和石油资源，但也增加了占领和战线管理负担。"},{"label":"出处","value":"1914-1918 Online，“Romania”；Encyclopaedia Britannica，World War I Balkan and Eastern Front materials。"}],"relationItems":["← 前因：布鲁西洛夫攻势","← 前因：奥匈帝国民族问题","→ 后果：布加勒斯特条约","→ 后果：同盟国资源危机缓解","↔ 相关：巴尔干民族问题","↔ 相关：一战资源战","✗ 对立/冲突：罗马尼亚领土民族主义","✗ 对立/冲突：同盟国军事反击","↔ 同时期参考：索姆河战役","↔ 同时期参考：凡尔登战役"],"relations":[{"text":"← 前因：布鲁西洛夫攻势","id":"extra710"},{"text":"← 前因：奥匈帝国民族问题","id":"extra929"},{"text":"↔ 相关：巴尔干民族问题","id":"extra930"},{"text":"↔ 相关：一战资源战","id":"extra959"},{"text":"↔ 同时期参考：索姆河战役","id":"extra655"},{"text":"↔ 同时期参考：凡尔登战役","id":"extra654"}],"source":"history","id":"extra711"},{"title":"卡波雷托战役","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1917年10月24日—11月19日","place":"意大利东北部伊松佐河与卡波雷托地区","summary":"卡波雷托战役是同盟国在意大利战线的重大突破，意大利军队溃退并迫使协约国加强支援。","fields":[{"label":"标题","value":"卡波雷托战役"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1917年10月24日—11月19日"},{"label":"地点","value":"意大利东北部伊松佐河与卡波雷托地区"},{"label":"主要国家","value":"意大利、奥匈帝国、德国"},{"label":"一句话概括","value":"卡波雷托战役是同盟国在意大利战线的重大突破，意大利军队溃退并迫使协约国加强支援。"},{"label":"参与者","value":"意大利军队；奥匈帝国军队；德国第十四集团军；奥托·冯·贝洛、路易吉·卡多尔纳等。"},{"label":"发生了什么","value":"德国和奥匈在意大利战线集中兵力，使用毒气、渗透突击和山地突破战术攻击意军防线。意军在卡波雷托附近被突破后发生大规模撤退，损失大量人员、火炮和物资。战线后撤到皮亚韦河，意大利指挥层更换，英法也派兵支援稳定局势。"},{"label":"为什么重要","value":"它是渗透战术成功运用的典型案例，也让意大利战线从局部战场变成协约国必须共同支撑的战略方向。"},{"label":"前因","value":"意大利和奥匈在伊松佐河长期消耗，奥匈需要德国支援来打破意大利战线压力。"},{"label":"后果","value":"意大利惨败后重组军队和防线，协约国加强跨国军事协调，意大利战线暂时稳定在皮亚韦河一线。"},{"label":"出处","value":"Encyclopaedia Britannica，“Battle of Caporetto”；1914-1918 Online，“Italian Front”。"}],"relationItems":["← 前因：意大利参加第一次世界大战","← 前因：伊松佐河战役","→ 后果：维托里奥·威尼托战役","→ 后果：奥匈帝国崩溃","↔ 相关：德国渗透战术","↔ 相关：奥匈帝国民族问题","✗ 对立/冲突：意大利民族统一诉求","✗ 对立/冲突：奥匈帝国边疆防御","↔ 同时期参考：第三次伊普尔战役","↔ 同时期参考：俄国十月革命"],"relations":[{"text":"← 前因：意大利参加第一次世界大战","id":"extra969"},{"text":"← 前因：伊松佐河战役","id":"extra965"},{"text":"→ 后果：奥匈帝国崩溃","id":"extra947"},{"text":"↔ 相关：奥匈帝国民族问题","id":"extra929"},{"text":"✗ 对立/冲突：奥匈帝国边疆防御","id":"extra971"},{"text":"↔ 同时期参考：第三次伊普尔战役","id":"extra713"}],"source":"history","id":"extra712"},{"title":"第三次伊普尔战役","level":"B","type":"事件卡","tags":["战争与外交","文化与思想"],"mainTag":"战争与外交","subTag":"文化与思想","timeText":"1917年7月31日—11月10日","place":"比利时伊普尔突出部，帕森达勒一带","summary":"第三次伊普尔战役又称帕森达勒战役，是一战泥泞、火力和消耗战记忆的代表性战役。","fields":[{"label":"标题","value":"第三次伊普尔战役"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1917年7月31日—11月10日"},{"label":"地点","value":"比利时伊普尔突出部，帕森达勒一带"},{"label":"主要国家","value":"英国、德国、法国、加拿大、澳大利亚、新西兰"},{"label":"一句话概括","value":"第三次伊普尔战役又称帕森达勒战役，是一战泥泞、火力和消耗战记忆的代表性战役。"},{"label":"参与者","value":"英国及自治领军队、法国军队、德国军队；道格拉斯·黑格等。"},{"label":"发生了什么","value":"英军希望突破伊普尔突出部，夺取高地并威胁德国潜艇基地方向。战役在长期炮击、排水系统破坏和恶劣天气中展开，战场变成泥泞地狱。双方为村庄、高地和阵地反复争夺，英军和自治领部队最终占领帕森达勒村附近，但战略突破没有实现。"},{"label":"为什么重要","value":"它强化了一战在英语世界中“无意义消耗”的公共记忆，也显示西线攻势在火力、地形和后勤面前的局限。"},{"label":"前因","value":"协约国希望突破佛兰德斯防线并削弱德国潜艇基地威胁，西线堑壕战仍迫使双方依靠大规模消耗攻势。"},{"label":"后果","value":"泥泞和伤亡使突破收益极低，协约国内部对消耗战代价反思加深，德国防御纵深战术继续发展。"},{"label":"出处","value":"Imperial War Museums，“Passchendaele”；Encyclopaedia Britannica，World War I western front materials。"}],"relationItems":["← 前因：第二次伊普尔战役","← 前因：德国无限制潜艇战","→ 后果：康布雷战役","→ 后果：德国1918年春季攻势","↔ 相关：帕森达勒记忆","↔ 相关：一战士兵经验","✗ 对立/冲突：协约国突破企图","✗ 对立/冲突：德国纵深防御","↔ 同时期参考：卡波雷托战役"],"relations":[{"text":"← 前因：第二次伊普尔战役","id":"extra707"},{"text":"← 前因：德国无限制潜艇战","id":"extra658"},{"text":"→ 后果：康布雷战役","id":"extra714"},{"text":"→ 后果：德国1918年春季攻势","id":"extra663"},{"text":"↔ 相关：一战士兵经验","id":"extra936"},{"text":"↔ 同时期参考：卡波雷托战役","id":"extra712"}],"source":"history","id":"extra713"},{"title":"康布雷战役","level":"B","type":"事件卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1917年11月20日—12月7日","place":"法国康布雷附近","summary":"康布雷战役以英军大规模集中使用坦克著称，预示机械化突破战术但也暴露协同不足。","fields":[{"label":"标题","value":"康布雷战役"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1917年11月20日—12月7日"},{"label":"地点","value":"法国康布雷附近"},{"label":"主要国家","value":"英国、德国"},{"label":"一句话概括","value":"康布雷战役以英军大规模集中使用坦克著称，预示机械化突破战术但也暴露协同不足。"},{"label":"参与者","value":"英国陆军坦克部队、步兵和炮兵；德国陆军。"},{"label":"发生了什么","value":"英军在康布雷附近使用大量坦克配合炮兵和步兵，避开长时间炮火准备，突然攻击德国兴登堡防线。初期英军取得明显突破，坦克压过铁丝网并撕开防线。但后续预备队和后勤不足，德军很快组织反击，使用突击队和纵深反攻夺回许多失地。"},{"label":"为什么重要","value":"它不是决定性胜利，却展示了坦克、炮兵、步兵协同突破堑壕体系的潜力，是后续机械化战争想象的重要节点。"},{"label":"前因","value":"西线僵局促使英国尝试集中使用坦克、炮兵校射和步兵协同，以测试突破堑壕体系的新方法。"},{"label":"后果","value":"战役显示坦克集中使用的潜力，也暴露突破后保持战果的困难，双方都从中吸收了1918年攻防战术经验。"},{"label":"出处","value":"Encyclopaedia Britannica，“Battle of Cambrai”；Imperial War Museums，Cambrai and tanks materials。"}],"relationItems":["← 前因：一战西线堑壕战","← 前因：第三次伊普尔战役","→ 后果：德国1918年春季攻势","→ 后果：亚眠战役","↔ 相关：坦克技术","↔ 相关：兴登堡防线","✗ 对立/冲突：机械化突破","✗ 对立/冲突：纵深防御","↔ 同时期参考：卡波雷托战役"],"relations":[{"text":"← 前因：一战西线堑壕战","id":"extra651"},{"text":"← 前因：第三次伊普尔战役","id":"extra713"},{"text":"→ 后果：德国1918年春季攻势","id":"extra663"},{"text":"→ 后果：亚眠战役","id":"extra716"},{"text":"↔ 相关：坦克技术","id":"extra939"},{"text":"↔ 相关：兴登堡防线","id":"extra956"},{"text":"✗ 对立/冲突：纵深防御","id":"extra955"},{"text":"↔ 同时期参考：卡波雷托战役","id":"extra712"}],"source":"history","id":"extra714"},{"title":"第二次马恩河战役","level":"A","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1918年7月15日—8月6日","place":"法国马恩河地区","summary":"第二次马恩河战役击退了德军最后一次大型攻势，西线主动权转向协约国。","fields":[{"label":"标题","value":"第二次马恩河战役"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1918年7月15日—8月6日"},{"label":"地点","value":"法国马恩河地区"},{"label":"主要国家","value":"德国、法国、美国、英国、意大利"},{"label":"一句话概括","value":"第二次马恩河战役击退了德军最后一次大型攻势，西线主动权转向协约国。"},{"label":"参与者","value":"德国陆军；法国、美国、英国、意大利等协约国部队；费迪南·福煦、埃里希·鲁登道夫等。"},{"label":"发生了什么","value":"德军在1918年春夏连续攻势后，试图在马恩河地区再次突破协约国防线。协约国已经掌握较多德军计划，防御准备更充分，并有美国新兵力持续投入。德军攻击受阻后，法美等部队发动反击，迫使德军从马恩突出部后撤，德国攻势能力明显衰竭。"},{"label":"为什么重要","value":"它是1918年战局转折点之一，标志德军从主动进攻转入被动防守，为百日攻势打开道路。"},{"label":"前因","value":"德国春季攻势试图在美军完全到达前取得胜利，但德军推进过深、补给困难，协约国反击条件逐渐成熟。"},{"label":"后果","value":"德军最后一次大规模攻势失败，协约国掌握战略主动，亚眠战役和百日攻势随即展开。"},{"label":"出处","value":"Encyclopaedia Britannica，“Second Battle of the Marne”；Imperial War Museums，1918 Western Front materials。"}],"relationItems":["← 前因：德国1918年春季攻势","← 前因：美国参加第一次世界大战","→ 后果：亚眠战役","→ 后果：一战百日攻势","↔ 相关：埃里希·鲁登道夫","↔ 相关：协约国统一指挥","✗ 对立/冲突：德国最后攻势","✗ 对立/冲突：协约国反攻能力","↔ 同时期参考：瓦尔达尔攻势"],"relations":[{"text":"← 前因：德国1918年春季攻势","id":"extra663"},{"text":"← 前因：美国参加第一次世界大战","id":"extra660"},{"text":"→ 后果：亚眠战役","id":"extra716"},{"text":"→ 后果：一战百日攻势","id":"extra664"},{"text":"↔ 相关：埃里希·鲁登道夫","id":"extra798"},{"text":"↔ 相关：协约国统一指挥","id":"extra931"},{"text":"↔ 同时期参考：瓦尔达尔攻势","id":"extra718"}],"source":"history","id":"extra715"},{"title":"亚眠战役","level":"B","type":"事件卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1918年8月8日—8月11日","place":"法国亚眠附近","summary":"亚眠战役是协约国百日攻势的开端，德军士气和防线稳定性遭到重大打击。","fields":[{"label":"标题","value":"亚眠战役"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1918年8月8日—8月11日"},{"label":"地点","value":"法国亚眠附近"},{"label":"主要国家","value":"英国、法国、澳大利亚、加拿大、德国"},{"label":"一句话概括","value":"亚眠战役是协约国百日攻势的开端，德军士气和防线稳定性遭到重大打击。"},{"label":"参与者","value":"英国第四集团军、澳大利亚军、加拿大军、法国军队、德国陆军；道格拉斯·黑格、埃里希·鲁登道夫等。"},{"label":"发生了什么","value":"协约国在亚眠附近组织突然进攻，综合使用坦克、飞机、炮兵、步兵和严格保密的部署。德军前线被迅速突破，大量士兵被俘。1918年8月8日被鲁登道夫称为德国陆军的“黑日”，虽然战役并非单独结束战争，但它开启了持续压迫德军退却的百日攻势阶段。"},{"label":"为什么重要","value":"它显示协约国已经形成更成熟的联合作战能力，也表明德国军队在长期消耗后士气和韧性明显下降。"},{"label":"前因","value":"第二次马恩河后德军转入被动，协约国利用坦克、航空、炮兵和步兵协同发动突然攻势。"},{"label":"后果","value":"德军防线和士气受到严重打击，兴登堡称其为德军的黑日，百日攻势由此持续推进。"},{"label":"出处","value":"Encyclopaedia Britannica，“Battle of Amiens”；Imperial War Museums，Amiens 1918 materials。"}],"relationItems":["← 前因：第二次马恩河战役","← 前因：康布雷战役","→ 后果：一战百日攻势","→ 后果：德国基尔水兵起义","↔ 相关：坦克技术","↔ 相关：协约国统一指挥","✗ 对立/冲突：协约国综合兵种攻势","✗ 对立/冲突：德军防御疲劳","↔ 同时期参考：默兹-阿贡攻势","↔ 同时期参考：瓦尔达尔攻势"],"relations":[{"text":"← 前因：第二次马恩河战役","id":"extra715"},{"text":"← 前因：康布雷战役","id":"extra714"},{"text":"→ 后果：一战百日攻势","id":"extra664"},{"text":"→ 后果：德国基尔水兵起义","id":"extra665"},{"text":"↔ 相关：坦克技术","id":"extra939"},{"text":"↔ 相关：协约国统一指挥","id":"extra931"},{"text":"↔ 同时期参考：默兹-阿贡攻势","id":"extra717"},{"text":"↔ 同时期参考：瓦尔达尔攻势","id":"extra718"}],"source":"history","id":"extra716"},{"title":"默兹-阿贡攻势","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1918年9月26日—11月11日","place":"法国默兹河与阿贡森林地区","summary":"默兹-阿贡攻势是美国远征军在一战中最大规模行动之一，推动德军西线防御进一步崩解。","fields":[{"label":"标题","value":"默兹-阿贡攻势"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1918年9月26日—11月11日"},{"label":"地点","value":"法国默兹河与阿贡森林地区"},{"label":"主要国家","value":"美国、法国、德国"},{"label":"一句话概括","value":"默兹-阿贡攻势是美国远征军在一战中最大规模行动之一，推动德军西线防御进一步崩解。"},{"label":"参与者","value":"美国远征军、法国军队、德国陆军；约翰·潘兴等。"},{"label":"发生了什么","value":"协约国在百日攻势中发动默兹-阿贡攻势，美国远征军承担大规模正面进攻任务，目标是切断德军重要交通线。美军在森林、丘陵和坚固阵地中推进，因经验不足和后勤压力付出很高代价，但持续压迫德军阵地。攻势一直持续到停战日，与其他战线压力共同迫使德国求和。"},{"label":"为什么重要","value":"它体现美国军事力量正式大规模进入欧洲陆战，也使战后美国在国际秩序中的发言权更难被忽视。"},{"label":"前因","value":"美国参战后需要在西线承担主要攻势任务，协约国百日攻势要求不断压迫德军防线。"},{"label":"后果","value":"攻势消耗并牵制德军力量，提升美国在停战和一战后巴黎和会中的地位，也加速德国要求停战。"},{"label":"出处","value":"American Battle Monuments Commission，Meuse-Argonne Offensive materials；Encyclopaedia Britannica，World War I final offensives overview。"}],"relationItems":["← 前因：美国参加第一次世界大战","← 前因：一战百日攻势","→ 后果：一战停战","→ 后果：威尔逊十四点原则","↔ 相关：美国远征军","↔ 相关：协约国统一指挥","✗ 对立/冲突：美国战争动员","✗ 对立/冲突：德国防线崩溃","↔ 同时期参考：亚眠战役","↔ 同时期参考：瓦尔达尔攻势"],"relations":[{"text":"← 前因：美国参加第一次世界大战","id":"extra660"},{"text":"← 前因：一战百日攻势","id":"extra664"},{"text":"→ 后果：一战停战","id":"extra667"},{"text":"→ 后果：威尔逊十四点原则","id":"extra661"},{"text":"↔ 相关：协约国统一指挥","id":"extra931"},{"text":"↔ 同时期参考：亚眠战役","id":"extra716"},{"text":"↔ 同时期参考：瓦尔达尔攻势","id":"extra718"}],"source":"history","id":"extra717"},{"title":"瓦尔达尔攻势","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1918年9月15日—9月29日","place":"马其顿战线，瓦尔达尔河谷与多布罗波列一带","summary":"瓦尔达尔攻势突破马其顿战线并迫使保加利亚停战，加速同盟国体系瓦解。","fields":[{"label":"标题","value":"瓦尔达尔攻势"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1918年9月15日—9月29日"},{"label":"地点","value":"马其顿战线，瓦尔达尔河谷与多布罗波列一带"},{"label":"主要国家","value":"保加利亚、法国、塞尔维亚、英国、希腊、德国、奥匈帝国"},{"label":"一句话概括","value":"瓦尔达尔攻势突破马其顿战线并迫使保加利亚停战，加速同盟国体系瓦解。"},{"label":"参与者","value":"东方协约军，包括法军、塞尔维亚军、英军、希腊军等；保加利亚军队；少量德奥支援力量。"},{"label":"发生了什么","value":"协约国在马其顿战线发动攻势，重点攻击多布罗波列等地的保加利亚阵地。塞尔维亚和法军突破山地防线后快速推进，保加利亚军队士气崩溃并出现内部动荡。保加利亚政府请求停战，于1918年9月底退出战争，德国与奥匈的巴尔干联系受到严重威胁。"},{"label":"为什么重要","value":"它说明1918年同盟国不是只在西线崩溃，外围盟友退出战争同样加速了德国的战略孤立。"},{"label":"前因","value":"巴尔干战线长期僵持削弱保加利亚，国内战争疲劳和补给困难使同盟国南线承受压力。"},{"label":"后果","value":"保加利亚退出战争后，同盟国南翼崩溃，奥斯曼和奥匈也相继失去继续战争的战略条件。"},{"label":"出处","value":"1914-1918 Online，“Macedonian Front”；Encyclopaedia Britannica，World War I Balkan front overview。"}],"relationItems":["← 前因：一战罗马尼亚战役","← 前因：巴尔干民族问题","→ 后果：奥斯曼帝国停战","→ 后果：奥匈帝国崩溃","→ 后果：一战停战","↔ 相关：一战百日攻势","↔ 相关：塞尔维亚民族主义","✗ 对立/冲突：协约国巴尔干突破","✗ 对立/冲突：同盟国盟友疲劳","↔ 同时期参考：默兹-阿贡攻势","↔ 同时期参考：亚眠战役"],"relations":[{"text":"← 前因：一战罗马尼亚战役","id":"extra711"},{"text":"← 前因：巴尔干民族问题","id":"extra930"},{"text":"→ 后果：奥匈帝国崩溃","id":"extra947"},{"text":"→ 后果：一战停战","id":"extra667"},{"text":"↔ 相关：一战百日攻势","id":"extra664"},{"text":"↔ 同时期参考：默兹-阿贡攻势","id":"extra717"},{"text":"↔ 同时期参考：亚眠战役","id":"extra716"}],"source":"history","id":"extra718"},{"title":"一战德属东非战役","level":"B","type":"事件卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1914年8月—1918年11月","place":"德属东非及周边非洲殖民地，今坦桑尼亚、肯尼亚、莫桑比克等地","summary":"一战德属东非战役是第一次世界大战在非洲持续最久的战场之一，殖民地民众承担了沉重人力和物资代价。","fields":[{"label":"标题","value":"一战德属东非战役"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1914年8月—1918年11月"},{"label":"地点","value":"德属东非及周边非洲殖民地，今坦桑尼亚、肯尼亚、莫桑比克等地"},{"label":"主要国家","value":"德国、英国、比利时、葡萄牙、南非"},{"label":"一句话概括","value":"一战德属东非战役是第一次世界大战在非洲持续最久的战场之一，殖民地民众承担了沉重人力和物资代价。"},{"label":"参与者","value":"德属东非军队及非洲士兵；英国、南非、比利时、葡萄牙等殖民军队；保罗·冯·莱托-福尔贝克。"},{"label":"发生了什么","value":"战争爆发后，德属东非部队在莱托-福尔贝克指挥下采取机动游击和牵制战略，避免被协约国一次性消灭。英、南非、比利时和葡萄牙部队多次围剿，战事跨越殖民地边界并消耗大量运输、粮食和劳力。德国部队直到欧洲停战后才停止行动。"},{"label":"为什么重要","value":"它显示一战的全球性和殖民性，欧洲战争成本被转嫁到非洲社会，许多非洲搬运工和平民死于疾病、饥荒和强制征发。"},{"label":"前因","value":"德国殖民扩张使东非成为一战全球战场的一部分，协约国试图消除德国海外基地和殖民威胁。"},{"label":"后果","value":"德国最终失去海外殖民地，凡尔赛体系用委任统治重新分配这些地区，德国殖民帝国结束。"},{"label":"出处","value":"1914-1918 Online，“East Africa”；Imperial War Museums，First World War in Africa materials。"}],"relationItems":["← 前因：德国殖民扩张","← 前因：一战日英攻占青岛战役","→ 后果：《凡尔赛和约》","→ 后果：一战后国际联盟委任统治体系","↔ 相关：莱托-福尔贝克","↔ 相关：殖民地士兵与劳工","✗ 对立/冲突：殖民帝国战争动员","✗ 对立/冲突：非洲社会承压","↔ 同时期参考：加里波利战役","↔ 同时期参考：瓦尔达尔攻势"],"relations":[{"text":"← 前因：德国殖民扩张","id":"extra942"},{"text":"← 前因：一战日英攻占青岛战役","id":"extra703"},{"text":"→ 后果：《凡尔赛和约》","id":"card59"},{"text":"→ 后果：一战后国际联盟委任统治体系","id":"card5"},{"text":"↔ 同时期参考：加里波利战役","id":"extra706"},{"text":"↔ 同时期参考：瓦尔达尔攻势","id":"extra718"}],"source":"history","id":"extra719"},{"title":"德国民法典","level":"B","type":"制度/文本卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1896年通过，1900年1月1日生效","place":"德意志帝国","summary":"德国民法典把统一后的德国私法制度系统化，影响财产、契约、家庭和继承等日常法律关系。","fields":[{"label":"标题","value":"德国民法典"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1896年通过，1900年1月1日生效"},{"label":"地点","value":"德意志帝国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国民法典把统一后的德国私法制度系统化，影响财产、契约、家庭和继承等日常法律关系。"},{"label":"制定方/签署方","value":"德意志帝国立法机构；皇帝威廉二世颁布。"},{"label":"主要内容","value":"法典分总则、债法、物权法、亲属法和继承法，规定民事主体、合同、所有权、婚姻家庭和遗产继承等规则。"},{"label":"它试图解决什么问题","value":"统一德意志帝国境内长期并存的邦国民事法律，给全国市场、财产交易和家庭关系提供统一法律框架。"},{"label":"为什么重要","value":"它是现代大陆法系的重要民法典之一，也显示民族国家、市场经济和法律理性化在十九世纪末德国如何结合。"},{"label":"争议/局限","value":"法典语言抽象、体系化强，对普通人并不友好；家庭法部分仍保留明显父权制结构。"},{"label":"造成的影响","value":"推动德国私法统一，并影响日本、瑞士、希腊等国家和地区的民法发展。"},{"label":"出处","value":"Encyclopaedia Britannica，“German Civil Code”；German History in Documents and Images，BGB materials。"}],"relationItems":["← 前因：德意志帝国成立","← 前因：德意志关税同盟（Zollverein）","→ 后果：魏玛宪法","→ 后果：德国社会国家传统","↔ 相关：德国法律实证主义","↔ 相关：德国工业资本主义","✗ 对立/冲突：地方邦国法律传统","✗ 对立/冲突：全国统一法典","↔ 同时期参考：德国俾斯麦社会保险立法"],"relations":[{"text":"← 前因：德意志帝国成立","id":"extra621"},{"text":"← 前因：德意志关税同盟（Zollverein）","id":"extra486"},{"text":"→ 后果：魏玛宪法","id":"card11"},{"text":"↔ 同时期参考：德国俾斯麦社会保险立法","id":"extra629"}],"source":"history","id":"extra720"},{"title":"德国刑法典第175条","level":"C","type":"制度/文本卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1871年纳入德意志帝国刑法典，后多次修改","place":"德意志帝国、魏玛共和国、纳粹德国、西德","summary":"德国刑法典第175条长期将男性同性性行为刑事化，成为德国性法律和少数群体迫害史的核心条文。","fields":[{"label":"标题","value":"德国刑法典第175条"},{"label":"分级","value":"C"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1871年纳入德意志帝国刑法典，后多次修改"},{"label":"地点","value":"德意志帝国、魏玛共和国、纳粹德国、西德"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国刑法典第175条长期将男性同性性行为刑事化，成为德国性法律和少数群体迫害史的核心条文。"},{"label":"制定方/签署方","value":"德意志帝国立法机构；后续政权继续保留并修改。"},{"label":"主要内容","value":"条文将男性之间的特定性行为列为犯罪；纳粹时期范围扩大、处罚加重。"},{"label":"它试图解决什么问题","value":"国家以刑法维护当时的性道德、家庭秩序和男性公民规范。"},{"label":"为什么重要","value":"它连接帝国、魏玛、纳粹和战后德国的法律连续性，说明现代国家如何通过刑法管理身体和性。"},{"label":"争议/局限","value":"条文本身建立在性别歧视和道德刑法基础上，长期造成逮捕、羞辱、勒索和社会排斥。"},{"label":"造成的影响","value":"推动魏玛时期废除条文的性改革运动，也成为纳粹迫害同性恋男性的重要法律工具。"},{"label":"出处","value":"United States Holocaust Memorial Museum，“Paragraph 175”；German History in Documents and Images，sexuality and law materials。"}],"relationItems":["← 前因：德意志帝国成立","← 前因：普鲁士刑法传统","→ 后果：马格努斯·赫希菲尔德性科学研究所","→ 后果：纳粹同性恋迫害","↔ 相关：德国妇女运动","↔ 相关：魏玛“新女性”","✗ 对立/冲突：魏玛德国性改革运动","✗ 对立/冲突：国家道德刑法","↔ 同时期参考：德国民法典"],"relations":[{"text":"← 前因：德意志帝国成立","id":"extra621"},{"text":"→ 后果：马格努斯·赫希菲尔德性科学研究所","id":"card72"},{"text":"→ 后果：纳粹同性恋迫害","id":"extra857"},{"text":"↔ 相关：德国妇女运动","id":"extra684"},{"text":"↔ 相关：魏玛“新女性”","id":"card32"},{"text":"✗ 对立/冲突：魏玛德国性改革运动","id":"card85"},{"text":"↔ 同时期参考：德国民法典","id":"extra720"}],"source":"history","id":"extra721"},{"title":"普朗克量子假说","level":"A","type":"概念/思潮卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1900年","place":"德意志帝国柏林","summary":"普朗克量子假说提出能量按离散单位交换，开启二十世纪物理学革命。","fields":[{"label":"标题","value":"普朗克量子假说"},{"label":"分级","value":"A"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1900年"},{"label":"地点","value":"德意志帝国柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"普朗克量子假说提出能量按离散单位交换，开启二十世纪物理学革命。"},{"label":"核心主张/思路","value":"黑体辐射不能完全用经典物理解释，能量吸收和发射可视为按离散“量子”进行。"},{"label":"提出者/代表人物","value":"马克斯·普朗克。"},{"label":"它从何而来","value":"十九世纪末热辐射实验、黑体辐射问题和经典物理解释困境。"},{"label":"典型表现","value":"普朗克常数成为量子理论核心常数，后来影响爱因斯坦光量子、玻尔原子模型和量子力学。"},{"label":"为什么重要","value":"它不是政治事件，却是世界科学史坐标级节点之一，也体现德国大学和研究机构在现代物理学中的中心地位。"},{"label":"争议/局限","value":"普朗克最初并非要彻底推翻经典物理，量子假说的革命含义是在后续理论发展中逐渐展开的。"},{"label":"出处","value":"Encyclopaedia Britannica，“Max Planck”；Nobel Prize，“Max Planck Facts”。"}],"relationItems":["← 前因：德国大学研究体系","← 前因：十九世纪物理学","→ 后果：爱因斯坦广义相对论","→ 后果：量子力学革命","↔ 相关：德国化学工业","↔ 相关：威廉二世时代科学体制","✗ 对立/冲突：经典物理连续性假设","✗ 对立/冲突：量子离散性","↔ 同时期参考：德意志制造联盟"],"relations":[{"text":"← 前因：德国大学研究体系","id":"extra935"},{"text":"→ 后果：爱因斯坦广义相对论","id":"extra723"},{"text":"↔ 相关：德国化学工业","id":"extra680"},{"text":"↔ 同时期参考：德意志制造联盟","id":"extra724"}],"source":"history","id":"extra722"},{"title":"爱因斯坦广义相对论","level":"A","type":"概念/思潮卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1915年形成场方程，1916年发表系统论文","place":"德国柏林","summary":"广义相对论把引力解释为时空弯曲，重塑现代宇宙观和二十世纪物理学。","fields":[{"label":"标题","value":"爱因斯坦广义相对论"},{"label":"分级","value":"A"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1915年形成场方程，1916年发表系统论文"},{"label":"地点","value":"德国柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"广义相对论把引力解释为时空弯曲，重塑现代宇宙观和二十世纪物理学。"},{"label":"核心主张/思路","value":"引力不是传统意义上的力，而是质量和能量使时空弯曲，物体沿弯曲时空运动。"},{"label":"提出者/代表人物","value":"阿尔伯特·爱因斯坦。"},{"label":"它从何而来","value":"狭义相对论、等效原理、牛顿引力理论的局限，以及数学物理的发展。"},{"label":"典型表现","value":"解释水星近日点进动，预言光线在强引力场中弯曲，并为现代宇宙学、黑洞和引力波理论奠基。"},{"label":"为什么重要","value":"它是现代科学世界观的核心理论之一，也显示一战时期科学共同体与民族国家冲突之间的复杂关系。"},{"label":"争议/局限","value":"理论高度抽象，早期实验验证困难；其公共声望在1919年日食观测后才迅速扩大。"},{"label":"出处","value":"Encyclopaedia Britannica，“Relativity”；Nobel Prize，“Albert Einstein Facts”。"}],"relationItems":["← 前因：普朗克量子假说","← 前因：德国大学研究体系","→ 后果：1919年爱丁顿日食观测","→ 后果：现代宇宙学","↔ 相关：阿尔伯特·爱因斯坦","↔ 相关：柏林科学界","✗ 对立/冲突：牛顿绝对时空观","✗ 对立/冲突：相对论时空观","↔ 同时期参考：一战总动员社会"],"relations":[{"text":"← 前因：普朗克量子假说","id":"extra722"},{"text":"← 前因：德国大学研究体系","id":"extra935"},{"text":"→ 后果：1919年爱丁顿日食观测","id":"card203"},{"text":"↔ 同时期参考：一战总动员社会","id":"extra653"}],"source":"history","id":"extra723"},{"title":"德意志制造联盟","level":"B","type":"组织/机构卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1907年成立","place":"德意志帝国慕尼黑","summary":"德意志制造联盟把艺术、工业和标准化设计连接起来，是现代设计和包豪斯的重要前史。","fields":[{"label":"标题","value":"德意志制造联盟"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1907年成立"},{"label":"地点","value":"德意志帝国慕尼黑"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德意志制造联盟把艺术、工业和标准化设计连接起来，是现代设计和包豪斯的重要前史。"},{"label":"性质/类型","value":"设计改革组织、艺术家与工业家联盟。"},{"label":"成立/解散时间","value":"1907年成立；后续经历中断和重建。"},{"label":"核心目标/宗旨","value":"提升德国工业产品质量，把艺术设计融入机器生产和出口竞争。"},{"label":"关键人物（可选）","value":"赫尔曼·穆特修斯、彼得·贝伦斯、亨利·范德费尔德等。"},{"label":"关键行动/事件","value":"推动产品设计、建筑、广告和平面设计改革；围绕标准化与艺术个性展开争论。"},{"label":"为什么重要","value":"它说明德国工业现代化不只是钢铁和军工，也包括消费品、品牌、建筑和日常审美的现代化。"},{"label":"争议/局限","value":"标准化设计有助于工业竞争，但也引发艺术自由与机器生产之间的张力。"},{"label":"出处","value":"Encyclopaedia Britannica，“Deutscher Werkbund”；Victoria and Albert Museum，Werkbund materials。"}],"relationItems":["← 前因：德国工业化","← 前因：德意志帝国世界政策","→ 后果：德国包豪斯","→ 后果：现代主义设计","↔ 相关：西门子与德国电气工业","↔ 相关：德国化学工业","✗ 对立/冲突：手工艺个性","✗ 对立/冲突：工业标准化","↔ 同时期参考：柏林分离派"],"relations":[{"text":"← 前因：德国工业化","id":"extra933"},{"text":"← 前因：德意志帝国世界政策","id":"extra635"},{"text":"→ 后果：德国包豪斯","id":"card30"},{"text":"↔ 相关：西门子与德国电气工业","id":"extra682"},{"text":"↔ 相关：德国化学工业","id":"extra680"}],"source":"history","id":"extra724"},{"title":"德意志帝国柏林分离派","level":"C","type":"组织/机构卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1898年成立","place":"德意志帝国柏林","summary":"柏林分离派挑战官方学院艺术趣味，为德国现代艺术和城市文化打开空间。","fields":[{"label":"标题","value":"德意志帝国柏林分离派"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1898年成立"},{"label":"地点","value":"德意志帝国柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"柏林分离派挑战官方学院艺术趣味，为德国现代艺术和城市文化打开空间。"},{"label":"性质/类型","value":"现代艺术团体和展览组织。"},{"label":"成立/解散时间","value":"1898年成立，二十世纪初经历分裂和影响扩散。"},{"label":"核心目标/宗旨","value":"摆脱官方沙龙和学院审查，为印象派、象征主义和现代艺术提供展览空间。"},{"label":"关键人物（可选）","value":"马克斯·利伯曼、洛维斯·科林特、凯绥·珂勒惠支等。"},{"label":"关键行动/事件","value":"组织独立展览，推动柏林艺术市场和现代城市文化发展。"},{"label":"为什么重要","value":"它让帝德时期文化不再只是威廉式纪念碑和官方历史画，也呈现资产阶级城市审美的多元化。"},{"label":"争议/局限","value":"它主要是城市中产和艺术市场现象，与工人阶级文化距离较远。"},{"label":"出处","value":"The Metropolitan Museum of Art，Berlin Secession materials；Encyclopaedia Britannica，Max Liebermann materials。"}],"relationItems":["← 前因：魏玛柏林现代性","← 前因：德意志帝国文化政策","→ 后果：德国表现主义","→ 后果：魏玛新客观主义","↔ 相关：德意志制造联盟","↔ 相关：凯绥·珂勒惠支","✗ 对立/冲突：官方学院艺术","✗ 对立/冲突：现代主义艺术市场","↔ 同时期参考：德意志生命改革运动"],"relations":[{"text":"← 前因：魏玛柏林现代性","id":"card33"},{"text":"↔ 相关：德意志制造联盟","id":"extra724"},{"text":"↔ 相关：凯绥·珂勒惠支","id":"extra732"},{"text":"↔ 同时期参考：德意志生命改革运动","id":"extra726"}],"source":"history","id":"extra725"},{"title":"德意志生命改革运动","level":"C","type":"概念/思潮卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"十九世纪末—二十世纪初","place":"德意志帝国及中欧德语地区","summary":"生命改革运动以自然、身体和反工业生活为核心，反映德国城市化时代的现代性焦虑。","fields":[{"label":"标题","value":"德意志生命改革运动"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"十九世纪末—二十世纪初"},{"label":"地点","value":"德意志帝国及中欧德语地区"},{"label":"主要国家","value":"德国、奥地利"},{"label":"一句话概括","value":"生命改革运动以自然、身体和反工业生活为核心，反映德国城市化时代的现代性焦虑。"},{"label":"核心主张/思路","value":"通过素食、自然疗法、裸体文化、田园生活、身体锻炼和衣着改革来恢复“自然”生活。"},{"label":"提出者/代表人物（可选）","value":"不是单一思想家提出，而是由多种社团、医生、出版人和生活实验者推动。"},{"label":"它从何而来","value":"工业城市扩张、环境污染、阶级拥挤、医学卫生观念变化和对资产阶级生活方式的反叛。"},{"label":"典型表现","value":"自然疗法疗养地、素食餐馆、裸体文化社团、田园公社、青年徒步和身体文化。"},{"label":"为什么重要","value":"它解释了德国现代文化中“回到自然”的持续吸引力，也与青年运动、裸体文化、后来部分右翼身体政治发生交叉。"},{"label":"争议/局限","value":"生命改革内部极其混杂，既有进步卫生和女性解放因素，也可能滑向民族主义、反城市和种族化身体观。"},{"label":"出处","value":"German History in Documents and Images，Life Reform materials；Encyclopaedia Britannica，Lebensreform related materials。"}],"relationItems":["← 前因：十九世纪德国社会问题","← 前因：德意志帝国柏林租住营房","→ 后果：德国青年运动","→ 后果：德国裸体文化运动","↔ 相关：德意志制造联盟","↔ 相关：魏玛“新女性”","✗ 对立/冲突：工业城市生活","✗ 对立/冲突：自然生活理想","↔ 同时期参考：德国妇女运动"],"relations":[{"text":"← 前因：十九世纪德国社会问题","id":"extra511"},{"text":"← 前因：德意志帝国柏林租住营房","id":"extra683"},{"text":"→ 后果：德国青年运动","id":"extra685"},{"text":"→ 后果：德国裸体文化运动","id":"extra727"},{"text":"↔ 相关：德意志制造联盟","id":"extra724"},{"text":"↔ 相关：魏玛“新女性”","id":"card32"},{"text":"↔ 同时期参考：德国妇女运动","id":"extra684"}],"source":"history","id":"extra726"},{"title":"德国裸体文化运动","level":"C","type":"概念/思潮卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"十九世纪末兴起，魏玛时期进一步扩展","place":"德国","summary":"德国裸体文化运动把身体、自然和健康联系起来，是现代德国生活改革文化的一部分。","fields":[{"label":"标题","value":"德国裸体文化运动"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"十九世纪末兴起，魏玛时期进一步扩展"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国裸体文化运动把身体、自然和健康联系起来，是现代德国生活改革文化的一部分。"},{"label":"核心主张/思路","value":"裸体并不只是色情或越界，而可被理解为健康、阳光、自然、身体平等和反束缚生活方式。"},{"label":"提出者/代表人物（可选）","value":"由多个自然疗法、体育、青年和生活改革社团推动，并无单一创始人。"},{"label":"它从何而来","value":"生命改革运动、城市卫生焦虑、身体锻炼潮流和对维多利亚式身体规范的反叛。"},{"label":"典型表现","value":"裸体浴场、阳光疗法、裸体摄影、体育社团和郊外自然活动。"},{"label":"为什么重要","value":"它展示德国现代社会对身体的重新定义，也解释魏玛文化为何常被同时视为解放、商业化和道德恐慌的对象。"},{"label":"争议/局限","value":"运动内部既有自由主义身体解放，也有民族主义和优生式身体理想，不能简单等同于现代性进步。"},{"label":"出处","value":"German History in Documents and Images，body culture materials；Oxford Reference，Freikörperkultur materials。"}],"relationItems":["← 前因：德意志生命改革运动","← 前因：德国青年运动","→ 后果：魏玛“新女性”","→ 后果：纳粹身体政治","↔ 相关：德国妇女运动","↔ 相关：马格努斯·赫希菲尔德性科学研究所","✗ 对立/冲突：资产阶级性道德","✗ 对立/冲突：身体解放文化","↔ 同时期参考：魏玛柏林现代性"],"relations":[{"text":"← 前因：德意志生命改革运动","id":"extra726"},{"text":"← 前因：德国青年运动","id":"extra685"},{"text":"→ 后果：魏玛“新女性”","id":"card32"},{"text":"↔ 相关：德国妇女运动","id":"extra684"},{"text":"↔ 相关：马格努斯·赫希菲尔德性科学研究所","id":"card72"},{"text":"↔ 同时期参考：魏玛柏林现代性","id":"card33"}],"source":"history","id":"extra727"},{"title":"德国消费合作社运动","level":"C","type":"组织/机构卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"十九世纪中后期兴起，帝德时期扩展","place":"德国城市和工业区","summary":"德国消费合作社运动通过集体采购和会员制商店改善工人生活，是工业社会自助组织的重要形式。","fields":[{"label":"标题","value":"德国消费合作社运动"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"十九世纪中后期兴起，帝德时期扩展"},{"label":"地点","value":"德国城市和工业区"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国消费合作社运动通过集体采购和会员制商店改善工人生活，是工业社会自助组织的重要形式。"},{"label":"性质/类型","value":"消费者合作组织和工人生活互助网络。"},{"label":"成立/解散时间","value":"十九世纪中后期开始发展；帝德和魏玛时期继续扩大。"},{"label":"核心目标/宗旨","value":"通过会员共同购买、分配盈余和控制商品质量，降低生活成本并增强工人阶级自助能力。"},{"label":"关键人物（可选）","value":"与工人运动、自由主义合作思想和地方社团活动相关，并非由单一人物主导。"},{"label":"关键行动/事件","value":"建立合作商店、烘焙厂、批发组织和会员教育体系。"},{"label":"为什么重要","value":"它把“社会问题”落到日常消费、食品价格和家庭预算层面，说明工人阶级组织不只存在于政党和工会。"},{"label":"争议/局限","value":"合作社需要稳定会员和资本积累，对最贫困、流动性最高的人群帮助有限。"},{"label":"出处","value":"International Cooperative Alliance，cooperative history materials；German History in Documents and Images，working-class life materials。"}],"relationItems":["← 前因：十九世纪德国社会问题","← 前因：德国社会民主党（SPD）","→ 后果：魏玛社会政策","→ 后果：德国劳工文化","↔ 相关：德国俾斯麦社会保险立法","↔ 相关：德国全德工人联合会","✗ 对立/冲突：私人零售商业","✗ 对立/冲突：工人阶级自助经济","↔ 同时期参考：柏林租住营房"],"relations":[{"text":"← 前因：十九世纪德国社会问题","id":"extra511"},{"text":"← 前因：德国社会民主党（SPD）","id":"extra628"},{"text":"↔ 相关：德国俾斯麦社会保险立法","id":"extra629"},{"text":"↔ 相关：德国全德工人联合会","id":"extra512"}],"source":"history","id":"extra728"},{"title":"德国青年风格（Jugendstil）","level":"C","type":"概念/思潮卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"约1890年代—1910年代","place":"德意志帝国，尤其慕尼黑、达姆施塔特、柏林等城市","summary":"德国青年风格是德语世界的新艺术运动，以装饰线条、整体设计和日常审美现代化为特征。","fields":[{"label":"标题","value":"德国青年风格（Jugendstil）"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"约1890年代—1910年代"},{"label":"地点","value":"德意志帝国，尤其慕尼黑、达姆施塔特、柏林等城市"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国青年风格是德语世界的新艺术运动，以装饰线条、整体设计和日常审美现代化为特征。"},{"label":"核心主张/思路","value":"艺术应进入建筑、家具、书籍、海报和日用品，把生活环境作为整体设计对象。"},{"label":"提出者/代表人物（可选）","value":"名称来自慕尼黑杂志《青年》；相关人物包括彼得·贝伦斯、奥托·埃克曼等。"},{"label":"它从何而来","value":"欧洲新艺术运动、工艺美术改革、工业商品审美化和都市消费文化。"},{"label":"典型表现","value":"植物曲线、装饰字体、海报、室内设计、建筑立面和艺术杂志。"},{"label":"为什么重要","value":"它连接十九世纪装饰艺术和二十世纪现代设计，是理解德意志制造联盟和包豪斯的前奏。"},{"label":"争议/局限","value":"青年风格仍重视装饰，与后来强调功能和标准化的现代主义存在张力。"},{"label":"出处","value":"Victoria and Albert Museum，Art Nouveau/Jugendstil materials；Encyclopaedia Britannica，Art Nouveau materials。"}],"relationItems":["← 前因：德意志帝国柏林分离派","← 前因：德意志生命改革运动","→ 后果：德意志制造联盟","→ 后果：德国包豪斯","↔ 相关：德国百货商店兴起","↔ 相关：魏玛柏林现代性","✗ 对立/冲突：历史主义装饰","✗ 对立/冲突：现代整体设计","↔ 同时期参考：普朗克量子假说"],"relations":[{"text":"← 前因：德意志帝国柏林分离派","id":"extra725"},{"text":"← 前因：德意志生命改革运动","id":"extra726"},{"text":"→ 后果：德意志制造联盟","id":"extra724"},{"text":"→ 后果：德国包豪斯","id":"card30"},{"text":"↔ 相关：德国百货商店兴起","id":"extra730"},{"text":"↔ 相关：魏玛柏林现代性","id":"card33"},{"text":"↔ 同时期参考：普朗克量子假说","id":"extra722"}],"source":"history","id":"extra729"},{"title":"德国百货商店兴起","level":"C","type":"概念/思潮卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"十九世纪末—二十世纪初","place":"德意志帝国大城市，尤其柏林","summary":"德国百货商店把城市消费、女性购物、广告和建筑景观结合起来，改变了现代都市日常生活。","fields":[{"label":"标题","value":"德国百货商店兴起"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"十九世纪末—二十世纪初"},{"label":"地点","value":"德意志帝国大城市，尤其柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国百货商店把城市消费、女性购物、广告和建筑景观结合起来，改变了现代都市日常生活。"},{"label":"核心主张/思路","value":"大规模零售通过固定价格、丰富商品、展示橱窗和集中空间，把购物变成现代城市体验。"},{"label":"提出者/代表人物（可选）","value":"赫尔曼·蒂茨、韦尔特海姆百货等企业家和商业机构。"},{"label":"它从何而来","value":"城市人口增长、交通改善、批量生产、广告业和中产消费扩张。"},{"label":"典型表现","value":"玻璃橱窗、商品陈列、目录、促销、女性顾客空间和城市中心大型商业建筑。"},{"label":"为什么重要","value":"它把工业生产转化为日常消费文化，也引发小店主、中产道德家和反犹主义政治对“大商店”的攻击。"},{"label":"争议/局限","value":"百货商店常被批评压迫小商贩、刺激消费欲望，并在反犹宣传中被污名化。"},{"label":"出处","value":"German History in Documents and Images，department stores and consumer culture materials；Deutsches Historisches Museum/LeMO，Warenhaus history materials。"}],"relationItems":["← 前因：德国工业化","← 前因：德国铁路建设","→ 后果：魏玛德国大众消费文化","↔ 相关：魏玛柏林现代性","↔ 相关：德国青年风格（Jugendstil）","✗ 对立/冲突：小店主经济","✗ 对立/冲突：现代大规模零售","↔ 同时期参考：德国消费合作社运动"],"relations":[{"text":"← 前因：德国工业化","id":"extra933"},{"text":"← 前因：德国铁路建设","id":"extra507"},{"text":"→ 后果：魏玛德国大众消费文化","id":"card87"},{"text":"↔ 相关：魏玛柏林现代性","id":"card33"},{"text":"↔ 相关：德国青年风格（Jugendstil）","id":"extra729"},{"text":"↔ 同时期参考：德国消费合作社运动","id":"extra728"}],"source":"history","id":"extra730"},{"title":"科佩尼克上尉事件","level":"C","type":"事件卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1906年10月16日","place":"德意志帝国柏林附近科佩尼克","summary":"科佩尼克上尉事件以假军官骗取市政权力，讽刺了帝德社会对军服和官僚权威的服从。","fields":[{"label":"标题","value":"科佩尼克上尉事件"},{"label":"分级","value":"C"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1906年10月16日"},{"label":"地点","value":"德意志帝国柏林附近科佩尼克"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"科佩尼克上尉事件以假军官骗取市政权力，讽刺了帝德社会对军服和官僚权威的服从。"},{"label":"参与者","value":"威廉·福格特；科佩尼克市政人员；普鲁士军队士兵。"},{"label":"发生了什么","value":"前科犯威廉·福格特穿上旧军官制服，冒充上尉，命令士兵随他前往科佩尼克市政厅。他逮捕市长并没收市政金库现金，随后逃离。事件曝光后成为全国笑谈，公众从中看到军服权威、官僚服从和社会身份制度的荒诞。"},{"label":"为什么重要","value":"它不是重大政治事件，却精准暴露威廉时代德国社会的等级秩序和军国主义日常心理。"},{"label":"前因","value":"帝国社会高度尊重军服和官僚证件，普鲁士军国主义文化使普通官员容易服从看似军事权威的命令。"},{"label":"后果","value":"事件成为讽刺军国主义和官僚服从的经典案例，后来被文学、戏剧和电影反复改编。"},{"label":"出处","value":"Encyclopaedia Britannica，“The Captain of Köpenick”；Deutsches Historisches Museum/LeMO，Hauptmann von Köpenick materials。"}],"relationItems":["← 前因：德意志帝国宪法","← 前因：普鲁士容克地主","→ 后果：德国军国主义讽刺文化","↔ 相关：德意志帝国萨伯恩事件","↔ 相关：德国民法典","✗ 对立/冲突：法治秩序","✗ 对立/冲突：制服权威崇拜","↔ 同时期参考：威廉二世《每日电讯报》事件"],"relations":[{"text":"← 前因：德意志帝国宪法","id":"extra624"},{"text":"← 前因：普鲁士容克地主","id":"extra672"},{"text":"↔ 相关：德意志帝国萨伯恩事件","id":"extra690"},{"text":"↔ 相关：德国民法典","id":"extra720"},{"text":"↔ 同时期参考：威廉二世《每日电讯报》事件","id":"extra688"}],"source":"history","id":"extra731"},{"title":"凯绥·珂勒惠支","level":"B","type":"人物卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1867年—1945年","place":"德国，尤其柏林","summary":"凯绥·珂勒惠支以版画和雕塑表现贫困、母亲、战争与哀悼，是德国社会批判艺术的重要人物。","fields":[{"label":"标题","value":"凯绥·珂勒惠支"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1867年—1945年"},{"label":"地点","value":"德国，尤其柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"凯绥·珂勒惠支以版画和雕塑表现贫困、母亲、战争与哀悼，是德国社会批判艺术的重要人物。"},{"label":"生卒年/活跃年代","value":"1867年生，1945年卒；十九世纪末至二十世纪上半叶活跃。"},{"label":"身份/职务","value":"艺术家、版画家、雕塑家，普鲁士艺术学院成员。"},{"label":"关键贡献/作为","value":"创作《织工》《农民战争》等系列版画，以黑白图像呈现工人贫困、母亲哀悼和战争创伤。"},{"label":"核心主张/立场","value":"同情底层、反战、关注女性和母亲经验，强调艺术的社会见证功能。"},{"label":"为什么重要","value":"她把德国现代艺术与社会问题、战争记忆和女性经验连接起来，不适合只放在艺术风格史里看。"},{"label":"争议/评价","value":"其艺术常被赞为道德力量和社会现实主义表达，但也因强烈悲剧性被不同政治阵营反复解释。"},{"label":"关联事件（可选）","value":"西里西亚织工起义；第一次世界大战；纳粹文化控制。"},{"label":"出处","value":"Encyclopaedia Britannica，“Käthe Kollwitz”；Käthe Kollwitz Museum，biographical materials。"}],"relationItems":["← 前因：西里西亚织工起义","← 前因：十九世纪德国社会问题","→ 后果：魏玛社会批判艺术","↔ 相关：德意志帝国柏林分离派","↔ 相关：德国妇女运动","✗ 对立/冲突：官方英雄艺术","✗ 对立/冲突：社会苦难见证","↔ 同时期参考：德国青年风格（Jugendstil）"],"relations":[{"text":"← 前因：西里西亚织工起义","id":"extra510"},{"text":"← 前因：十九世纪德国社会问题","id":"extra511"},{"text":"↔ 相关：德意志帝国柏林分离派","id":"extra725"},{"text":"↔ 相关：德国妇女运动","id":"extra684"},{"text":"↔ 同时期参考：德国青年风格（Jugendstil）","id":"extra729"}],"source":"history","id":"extra732"},{"title":"德国城市公共卫生运动","level":"C","type":"概念/思潮卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"十九世纪中后期—二十世纪初","place":"德国大城市","summary":"德国城市公共卫生运动以供水、排污、住房和传染病治理回应工业城市病，推动现代市政国家形成。","fields":[{"label":"标题","value":"德国城市公共卫生运动"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"十九世纪中后期—二十世纪初"},{"label":"地点","value":"德国大城市"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国城市公共卫生运动以供水、排污、住房和传染病治理回应工业城市病，推动现代市政国家形成。"},{"label":"核心主张/思路","value":"疾病不仅是个人问题，也与住房密度、饮水、排污、营养和城市基础设施有关。"},{"label":"提出者/代表人物（可选）","value":"鲁道夫·维尔肖等社会医学代表人物，以及地方市政工程师和卫生官员。"},{"label":"它从何而来","value":"霍乱、结核、工人住房拥挤、城市扩张和细菌学发展。"},{"label":"典型表现","value":"自来水系统、下水道、垃圾处理、卫生统计、住房调查、传染病报告和公共浴场。"},{"label":"为什么重要","value":"它把现代城市治理从治安和税收扩展到身体、环境和社会条件，解释德国福利国家和市政管理的基层来源。"},{"label":"争议/局限","value":"公共卫生改善常与贫民管教、阶级偏见和国家监控交织。"},{"label":"出处","value":"German History in Documents and Images，urban sanitation and public health materials；Encyclopaedia Britannica，Rudolf Virchow and public health materials。"}],"relationItems":["← 前因：十九世纪德国社会问题","← 前因：德意志帝国柏林租住营房","→ 后果：罗伯特·科赫发现结核杆菌","→ 后果：魏玛《全国青少年福利法》","↔ 相关：德国民法典","↔ 相关：德国俾斯麦社会保险立法","✗ 对立/冲突：私人生活空间","✗ 对立/冲突：市政卫生干预","↔ 同时期参考：德国消费合作社运动"],"relations":[{"text":"← 前因：十九世纪德国社会问题","id":"extra511"},{"text":"← 前因：德意志帝国柏林租住营房","id":"extra683"},{"text":"→ 后果：罗伯特·科赫发现结核杆菌","id":"extra811"},{"text":"→ 后果：魏玛《全国青少年福利法》","id":"card73"},{"text":"↔ 相关：德国民法典","id":"extra720"},{"text":"↔ 相关：德国俾斯麦社会保险立法","id":"extra629"},{"text":"↔ 同时期参考：德国消费合作社运动","id":"extra728"}],"source":"history","id":"extra733"},{"title":"德国历史学派经济学","level":"C","type":"概念/思潮卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"十九世纪中期—二十世纪初","place":"德语大学和政策讨论空间","summary":"德国历史学派经济学反对抽象普遍经济法则，强调经济制度必须放在历史、法律和民族发展中理解。","fields":[{"label":"标题","value":"德国历史学派经济学"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"十九世纪中期—二十世纪初"},{"label":"地点","value":"德语大学和政策讨论空间"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国历史学派经济学反对抽象普遍经济法则，强调经济制度必须放在历史、法律和民族发展中理解。"},{"label":"核心主张/思路","value":"经济生活受历史阶段、制度、法律和文化影响，不能只用抽象自由市场模型解释。"},{"label":"提出者/代表人物（可选）","value":"威廉·罗雪尔、古斯塔夫·施穆勒等。"},{"label":"它从何而来","value":"德国后发工业化、国家统一、社会问题和大学历史研究传统。"},{"label":"典型表现","value":"社会政策研究、统计调查、工人问题讨论和“讲坛社会主义”争论。"},{"label":"为什么重要","value":"它影响德国社会政策、经济史和制度经济学传统，也解释为什么帝德时期经济讨论常与国家干预相连。"},{"label":"争议/局限","value":"过度强调历史特殊性可能削弱理论普遍性，也常被自由主义经济学家批评为国家主义倾向。"},{"label":"出处","value":"Encyclopaedia Britannica，German historical school of economics materials；New School History of Economic Thought，German Historical School materials。"}],"relationItems":["← 前因：弗里德里希·李斯特","← 前因：十九世纪德国社会问题","→ 后果：德国俾斯麦社会保险立法","→ 后果：《新教伦理与资本主义精神》","↔ 相关：德国大学研究体系","↔ 相关：德国消费合作社运动","✗ 对立/冲突：古典自由市场理论","✗ 对立/冲突：历史制度分析","↔ 同时期参考：德国民法典"],"relations":[{"text":"← 前因：弗里德里希·李斯特","id":"extra506"},{"text":"← 前因：十九世纪德国社会问题","id":"extra511"},{"text":"→ 后果：德国俾斯麦社会保险立法","id":"extra629"},{"text":"→ 后果：《新教伦理与资本主义精神》","id":"extra71"},{"text":"↔ 相关：德国大学研究体系","id":"extra935"},{"text":"↔ 相关：德国消费合作社运动","id":"extra728"},{"text":"↔ 同时期参考：德国民法典","id":"extra720"}],"source":"history","id":"extra734"},{"title":"德国物理学家伦琴发现X射线","level":"B","type":"事件卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1895年","place":"德意志帝国维尔茨堡","summary":"德国物理学家伦琴发现X射线打开了医学影像时代，使不可见的身体内部成为现代科学和临床诊断对象。","fields":[{"label":"标题","value":"德国物理学家伦琴发现X射线"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1895年"},{"label":"地点","value":"德意志帝国维尔茨堡"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国物理学家伦琴发现X射线打开了医学影像时代，使不可见的身体内部成为现代科学和临床诊断对象。"},{"label":"参与者","value":"威廉·康拉德·伦琴；维尔茨堡大学物理实验室；欧洲医学与科学界。"},{"label":"发生了什么","value":"1895年，伦琴在研究阴极射线管时发现一种能穿透不透明物体并使荧光屏发光的新射线。他拍摄了著名的手部骨骼影像，并迅速发表研究结果。X射线很快被医学界用于骨折、异物和内部结构检查，科学发现几乎立即转化为临床技术。"},{"label":"为什么重要","value":"它把物理学发现直接变成医学工具，也说明德意志帝国大学实验室、仪器技术和医学实践之间的紧密联系。"},{"label":"前因","value":"十九世纪实验物理学快速发展，德国大学实验室和电磁、阴极射线研究为新现象发现提供了技术条件。"},{"label":"后果","value":"X射线很快进入医学诊断，现代医学影像由此开端，伦琴也因这一发现获得首届诺贝尔物理学奖。"},{"label":"出处","value":"Nobel Prize，“Wilhelm Conrad Röntgen Facts”；Encyclopaedia Britannica，“Wilhelm Conrad Röntgen”。"}],"relationItems":["← 前因：德国洪堡大学模式","← 前因：德国城市公共卫生运动","→ 后果：现代医学影像","→ 后果：诺贝尔奖制度","↔ 相关：罗伯特·科赫发现结核杆菌","↔ 相关：普朗克量子假说","✗ 对立/冲突：外部症状诊断","✗ 对立/冲突：身体内部可视化","↔ 同时期参考：德国拜耳推出阿司匹林"],"relations":[{"text":"← 前因：德国洪堡大学模式","id":"extra515"},{"text":"← 前因：德国城市公共卫生运动","id":"extra733"},{"text":"↔ 相关：罗伯特·科赫发现结核杆菌","id":"extra811"},{"text":"↔ 相关：普朗克量子假说","id":"extra722"},{"text":"↔ 同时期参考：德国拜耳推出阿司匹林","id":"extra738"}],"source":"history","id":"extra735"},{"title":"德国奔驰专利汽车","level":"B","type":"事件卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"1886年取得专利","place":"德意志帝国曼海姆","summary":"奔驰专利汽车是以内燃机驱动的早期实用汽车，标志个人机动交通和汽车工业的开端之一。","fields":[{"label":"标题","value":"德国奔驰专利汽车"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1886年取得专利"},{"label":"地点","value":"德意志帝国曼海姆"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"奔驰专利汽车是以内燃机驱动的早期实用汽车，标志个人机动交通和汽车工业的开端之一。"},{"label":"参与者","value":"卡尔·本茨；贝尔塔·本茨；德国机械制造和交通技术环境。"},{"label":"发生了什么","value":"卡尔·本茨把小型汽油内燃机、三轮车架、转向系统和传动装置组合成可运行车辆，并在1886年取得专利。1888年，贝尔塔·本茨长途驾驶证明车辆并非实验室玩具，而具备实际交通潜力。此后汽车制造逐步从发明转向产业化。"},{"label":"为什么重要","value":"它把德国机械工业、化学燃料和现代消费交通连接起来，是二十世纪汽车社会的早期节点。"},{"label":"前因","value":"内燃机、机械制造和交通需求的发展为汽车发明提供了条件，德国工业化积累了精密制造和工程实验能力。"},{"label":"后果","value":"专利汽车开启现代汽车工业的技术路径，后来德国汽车工业成为工业经济和国家形象的重要组成部分。"},{"label":"出处","value":"Mercedes-Benz Museum，Patent Motor Car history；Encyclopaedia Britannica，“Karl Benz”。"}],"relationItems":["← 前因：德国铁路建设","← 前因：德国化学工业","→ 后果：德国汽车工业","→ 后果：纳粹大众汽车计划","↔ 相关：西门子与德国电气工业","↔ 相关：德国百货商店兴起","✗ 对立/冲突：铁路时代交通","✗ 对立/冲突：个人机动交通","↔ 同时期参考：德国齐柏林飞艇首飞"],"relations":[{"text":"← 前因：德国铁路建设","id":"extra507"},{"text":"← 前因：德国化学工业","id":"extra680"},{"text":"→ 后果：纳粹大众汽车计划","id":"extra124"},{"text":"↔ 相关：西门子与德国电气工业","id":"extra682"},{"text":"↔ 相关：德国百货商店兴起","id":"extra730"},{"text":"↔ 同时期参考：德国齐柏林飞艇首飞","id":"extra737"}],"source":"history","id":"extra736"},{"title":"德国齐柏林飞艇首飞","level":"C","type":"事件卡","tags":["经济与社会","战争与外交"],"mainTag":"经济与社会","subTag":"战争与外交","timeText":"1900年7月2日","place":"德意志帝国博登湖上空","summary":"德国齐柏林飞艇首飞展示了德国大型航空器工程能力，也把航空想象推向商业、民族声望和军事用途。","fields":[{"label":"标题","value":"德国齐柏林飞艇首飞"},{"label":"分级","value":"C"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1900年7月2日"},{"label":"地点","value":"德意志帝国博登湖上空"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国齐柏林飞艇首飞展示了德国大型航空器工程能力，也把航空想象推向商业、民族声望和军事用途。"},{"label":"参与者","value":"斐迪南·冯·齐柏林；齐柏林飞艇制造团队；德国公众和军方观察者。"},{"label":"发生了什么","value":"1900年，齐柏林设计的硬式飞艇LZ 1在博登湖上空进行首次飞行。飞行时间不长，也暴露出技术问题，但它证明大型硬式飞艇具备可操作可能。随后齐柏林飞艇获得公众募资、国家兴趣和工业支持，逐渐成为德国技术现代性的象征。"},{"label":"为什么重要","value":"它连接航空工程、民族技术自豪和军民两用技术，预示一战空战和二十世纪航空交通的发展。"},{"label":"前因","value":"德国工业化和轻金属、发动机技术发展，使刚性飞艇从军事幻想和工程设想变成可测试的飞行器。"},{"label":"后果","value":"飞艇推动德国航空工业和公众技术想象，一战中又被用于侦察和轰炸，显示空中战争时代正在到来。"},{"label":"出处","value":"Encyclopaedia Britannica，“Ferdinand von Zeppelin”；Deutsches Museum，Zeppelin materials。"}],"relationItems":["← 前因：德国工业化","← 前因：德意志帝国世界政策","→ 后果：一战战略空袭","→ 后果：德国航空工业","↔ 相关：德国奔驰专利汽车","↔ 相关：德国海军协会","✗ 对立/冲突：技术乌托邦","✗ 对立/冲突：军事化应用","↔ 同时期参考：德意志制造联盟"],"relations":[{"text":"← 前因：德国工业化","id":"extra933"},{"text":"← 前因：德意志帝国世界政策","id":"extra635"},{"text":"→ 后果：一战战略空袭","id":"extra958"},{"text":"↔ 相关：德国奔驰专利汽车","id":"extra736"},{"text":"↔ 相关：德国海军协会","id":"extra676"},{"text":"↔ 同时期参考：德意志制造联盟","id":"extra724"}],"source":"history","id":"extra737"},{"title":"德国拜耳推出阿司匹林","level":"C","type":"事件卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"1899年注册商标并商业推广","place":"德意志帝国伍珀塔尔-埃尔伯费尔德等地","summary":"拜耳阿司匹林把德国化学工业、药品品牌和大众医疗消费联系起来，成为现代制药工业标志。","fields":[{"label":"标题","value":"德国拜耳推出阿司匹林"},{"label":"分级","value":"C"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1899年注册商标并商业推广"},{"label":"地点","value":"德意志帝国伍珀塔尔-埃尔伯费尔德等地"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"拜耳阿司匹林把德国化学工业、药品品牌和大众医疗消费联系起来，成为现代制药工业标志。"},{"label":"参与者","value":"拜耳公司；费利克斯·霍夫曼等化学家；医生、药剂师和消费者。"},{"label":"发生了什么","value":"拜耳公司在十九世纪末研发并推广乙酰水杨酸药品，以“Aspirin”作为商标进入市场。它以镇痛、退热和抗炎功效获得广泛使用，借助工业化生产、商标、包装、医生推荐和全球销售成为现代药品消费品。阿司匹林的成功也显示实验室化学、专利商标和大众医疗市场正在结合。"},{"label":"为什么重要","value":"它说明德国化学工业不只生产染料和军需，也创造了现代制药企业、药品品牌和日常自我治疗文化。"},{"label":"前因","value":"德国化学工业和制药研究快速发展，城市社会对标准化止痛、退热药物的需求扩大。"},{"label":"后果","value":"阿司匹林成为现代药品品牌化和全球制药市场的代表，也巩固了德国化学制药工业的国际影响。"},{"label":"出处","value":"Bayer，Aspirin history；Encyclopaedia Britannica，aspirin materials。"}],"relationItems":["← 前因：德国化学工业","← 前因：德国城市公共卫生运动","→ 后果：现代制药工业","↔ 相关：罗伯特·科赫发现结核杆菌","↔ 相关：德国物理学家伦琴发现X射线","✗ 对立/冲突：传统药剂","✗ 对立/冲突：工业化药品品牌","↔ 同时期参考：德国百货商店兴起"],"relations":[{"text":"← 前因：德国化学工业","id":"extra680"},{"text":"← 前因：德国城市公共卫生运动","id":"extra733"},{"text":"→ 后果：现代制药工业","id":"extra950"},{"text":"↔ 相关：罗伯特·科赫发现结核杆菌","id":"extra811"},{"text":"↔ 相关：德国物理学家伦琴发现X射线","id":"extra735"},{"text":"↔ 同时期参考：德国百货商店兴起","id":"extra730"}],"source":"history","id":"extra738"},{"title":"德国自由工会总委员会","level":"B","type":"组织/机构卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1890年成立","place":"德意志帝国","summary":"德国自由工会总委员会把分散行业工会协调起来，是帝德工人阶级组织化的重要节点。","fields":[{"label":"标题","value":"德国自由工会总委员会"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1890年成立"},{"label":"地点","value":"德意志帝国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国自由工会总委员会把分散行业工会协调起来，是帝德工人阶级组织化的重要节点。"},{"label":"性质/类型","value":"社会主义倾向自由工会的全国协调机构。"},{"label":"成立/解散时间","value":"1890年成立；一战后被德国自由工会总联盟继承。"},{"label":"核心目标/宗旨","value":"协调行业工会、维护工资和劳动条件、支持集体行动，并与德国社会民主党保持密切关系。"},{"label":"关键人物（可选）","value":"卡尔·莱金等工会领导人。"},{"label":"关键行动/事件","value":"组织罢工支持、会员扩展、工会财政和劳动条件谈判。"},{"label":"为什么重要","value":"它说明德国工人运动不只有政党和理论纲领，还有日常工资、工时和组织能力建设。"},{"label":"争议/局限","value":"工会在革命策略、改良主义和战时合作问题上长期面临争议。"},{"label":"出处","value":"German History in Documents and Images，German trade unions materials；Friedrich Ebert Stiftung，German labour movement history。"}],"relationItems":["← 前因：德国反社会党人法","← 前因：德国社会民主党（SPD）","→ 后果：德国自由工会总联盟","→ 后果：德国1914年战争贷款表决","↔ 相关：德国消费合作社运动","↔ 相关：德国俾斯麦社会保险立法","✗ 对立/冲突：雇主权威","✗ 对立/冲突：工人集体谈判","↔ 同时期参考：德国合作银行运动"],"relations":[{"text":"← 前因：德国反社会党人法","id":"extra627"},{"text":"← 前因：德国社会民主党（SPD）","id":"extra628"},{"text":"→ 后果：德国自由工会总联盟","id":"card95"},{"text":"→ 后果：德国1914年战争贷款表决","id":"extra691"},{"text":"↔ 相关：德国消费合作社运动","id":"extra728"},{"text":"↔ 相关：德国俾斯麦社会保险立法","id":"extra629"},{"text":"↔ 同时期参考：德国合作银行运动","id":"extra518"}],"source":"history","id":"extra739"},{"title":"德国疾病保险法","level":"C","type":"制度/文本卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1883年","place":"德意志帝国","summary":"德国疾病保险法为工业工人建立强制性疾病保险，是现代社会保险国家的早期制度基石。","fields":[{"label":"标题","value":"德国疾病保险法"},{"label":"分级","value":"C"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1883年"},{"label":"地点","value":"德意志帝国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国疾病保险法为工业工人建立强制性疾病保险，是现代社会保险国家的早期制度基石。"},{"label":"制定方/签署方","value":"德意志帝国政府和帝国议会。"},{"label":"主要内容","value":"为部分工人提供疾病期间医疗和现金补助，资金通常由工人与雇主共同承担，并通过保险基金管理。"},{"label":"它试图解决什么问题","value":"工业工人患病会迅速失去收入并陷入贫困，国家也希望削弱社会主义运动吸引力。"},{"label":"为什么重要","value":"它把社会风险从个人家庭责任转化为法定保险责任，是福利国家制度化的重要起点。"},{"label":"争议/局限","value":"早期覆盖范围有限，且有明显政治安抚和国家控制目的。"},{"label":"造成的影响","value":"成为俾斯麦社会保险体系第一块核心拼图，并影响欧洲社会政策。"},{"label":"出处","value":"Encyclopaedia Britannica，social insurance Germany materials；German History in Documents and Images，Bismarck social legislation materials。"}],"relationItems":["← 前因：十九世纪德国社会问题","← 前因：德国社会民主党（SPD）","→ 后果：德国事故保险法","→ 后果：德国俾斯麦社会保险立法","↔ 相关：德国城市公共卫生运动","↔ 相关：德国自由工会总委员会","✗ 对立/冲突：私人慈善救济","✗ 对立/冲突：法定社会保险","↔ 同时期参考：德国民法典"],"relations":[{"text":"← 前因：十九世纪德国社会问题","id":"extra511"},{"text":"← 前因：德国社会民主党（SPD）","id":"extra628"},{"text":"→ 后果：德国事故保险法","id":"extra741"},{"text":"→ 后果：德国俾斯麦社会保险立法","id":"extra629"},{"text":"↔ 相关：德国城市公共卫生运动","id":"extra733"},{"text":"↔ 相关：德国自由工会总委员会","id":"extra739"},{"text":"↔ 同时期参考：德国民法典","id":"extra720"}],"source":"history","id":"extra740"},{"title":"德国事故保险法","level":"C","type":"制度/文本卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1884年","place":"德意志帝国","summary":"德国事故保险法把工伤风险制度化处理，使工业事故成为国家和雇主必须承担的社会问题。","fields":[{"label":"标题","value":"德国事故保险法"},{"label":"分级","value":"C"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1884年"},{"label":"地点","value":"德意志帝国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国事故保险法把工伤风险制度化处理，使工业事故成为国家和雇主必须承担的社会问题。"},{"label":"制定方/签署方","value":"德意志帝国政府和帝国议会。"},{"label":"主要内容","value":"为工业劳动者提供工伤事故赔偿，主要通过雇主行业协会筹资和管理。"},{"label":"它试图解决什么问题","value":"工业机器、矿山和工厂事故频发，工伤会把劳动者家庭推向长期贫困。"},{"label":"为什么重要","value":"它使工业化的身体代价进入法律和保险制度，也扩大了国家对劳动关系的介入。"},{"label":"争议/局限","value":"制度承认工伤风险，却不等于赋予工人充分的安全监督和谈判权。"},{"label":"造成的影响","value":"与疾病保险和养老保险共同构成德国社会保险体系。"},{"label":"出处","value":"German History in Documents and Images，Bismarck social legislation materials；Encyclopaedia Britannica，workers compensation history materials。"}],"relationItems":["← 前因：德国疾病保险法","← 前因：德国鲁尔工业区","→ 后果：德国俾斯麦社会保险立法","↔ 相关：德国自由工会总委员会","↔ 相关：德国城市公共卫生运动","✗ 对立/冲突：工业利润","✗ 对立/冲突：劳动者身体安全","↔ 同时期参考：德国化学工业"],"relations":[{"text":"← 前因：德国疾病保险法","id":"extra740"},{"text":"← 前因：德国鲁尔工业区","id":"extra679"},{"text":"→ 后果：德国俾斯麦社会保险立法","id":"extra629"},{"text":"↔ 相关：德国自由工会总委员会","id":"extra739"},{"text":"↔ 相关：德国城市公共卫生运动","id":"extra733"},{"text":"↔ 同时期参考：德国化学工业","id":"extra680"}],"source":"history","id":"extra741"},{"title":"德意志博物馆成立","level":"C","type":"事件卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1903年成立","place":"德意志帝国慕尼黑","summary":"德意志博物馆成立把科学技术作为大众教育和民族成就展示对象，体现工业时代的知识公共化。","fields":[{"label":"标题","value":"德意志博物馆成立"},{"label":"分级","value":"C"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1903年成立"},{"label":"地点","value":"德意志帝国慕尼黑"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德意志博物馆成立把科学技术作为大众教育和民族成就展示对象，体现工业时代的知识公共化。"},{"label":"参与者","value":"奥斯卡·冯·米勒；巴伐利亚和德国科学技术界；工程师、企业与公众。"},{"label":"发生了什么","value":"1903年，德意志博物馆在慕尼黑创立，目标是收藏和展示自然科学与技术成就。它通过实物、模型和互动展示，让机器、电力、交通、化学和物理知识进入公共文化空间，把专家知识转化为面向大众的现代技术叙事。"},{"label":"为什么重要","value":"它说明帝德时期技术崇拜不仅体现在工厂和军备，也体现在博物馆、教育和公共文化中。"},{"label":"前因","value":"德国工业化、工程教育和科学民族主义上升，使技术成就需要被集中展示并纳入公共教育。"},{"label":"后果","value":"博物馆推动科学技术的大众传播，也把工业和工程能力塑造成德国民族成就的一部分。"},{"label":"出处","value":"Deutsches Museum，official history；Encyclopaedia Britannica，Deutsches Museum materials。"}],"relationItems":["← 前因：德国工业化","← 前因：德国洪堡大学模式","→ 后果：科学技术大众教育","↔ 相关：西门子与德国电气工业","↔ 相关：德国奔驰专利汽车","✗ 对立/冲突：专家知识封闭","✗ 对立/冲突：技术知识公共展示","↔ 同时期参考：德国齐柏林飞艇首飞"],"relations":[{"text":"← 前因：德国工业化","id":"extra933"},{"text":"← 前因：德国洪堡大学模式","id":"extra515"},{"text":"↔ 相关：西门子与德国电气工业","id":"extra682"},{"text":"↔ 相关：德国奔驰专利汽车","id":"extra736"},{"text":"↔ 同时期参考：德国齐柏林飞艇首飞","id":"extra737"}],"source":"history","id":"extra742"},{"title":"拜耳海洛因商品化","level":"C","type":"事件卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"1898年前后开始商业推广","place":"德意志帝国及国际药品市场","summary":"拜耳将海洛因作为药品推向市场，显示现代制药工业早期对成瘾风险认识不足。","fields":[{"label":"标题","value":"拜耳海洛因商品化"},{"label":"分级","value":"C"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1898年前后开始商业推广"},{"label":"地点","value":"德意志帝国及国际药品市场"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"拜耳将海洛因作为药品推向市场，显示现代制药工业早期对成瘾风险认识不足。"},{"label":"参与者","value":"拜耳公司；德国化学家和制药工业；医生、药剂师和患者。"},{"label":"发生了什么","value":"十九世纪末，拜耳公司把二乙酰吗啡以“Heroin”商标作为止咳、镇痛等用途药品推广。它最初被包装成现代化学制药成果，并进入医生处方和药品市场。随着依赖性和滥用风险逐渐显现，海洛因在二十世纪逐步受到更严格限制。"},{"label":"为什么重要","value":"它把德国化学工业、药品品牌、医学市场和成瘾风险连接起来，是理解现代药物监管如何从经验教训中形成的案例。"},{"label":"前因","value":"德国化学制药工业尝试从吗啡衍生物中寻找新药，阿司匹林等品牌化药品成功也鼓励企业扩大合成药市场。"},{"label":"后果","value":"海洛因的商业推广后来暴露成瘾风险，推动国际禁毒监管和德国国内鸦片法制逐步加强。"},{"label":"出处","value":"Bayer company history materials；United Nations Office on Drugs and Crime，history of drug control materials；Encyclopaedia Britannica，heroin materials。"}],"relationItems":["← 前因：德国化学工业","← 前因：德国拜耳推出阿司匹林","→ 后果：海牙《国际鸦片公约》","→ 后果：魏玛德国鸦片法","↔ 相关：现代制药工业","↔ 相关：德国城市公共卫生运动","✗ 对立/冲突：药品商业创新","✗ 对立/冲突：成瘾风险管制","↔ 同时期参考：德国物理学家伦琴发现X射线"],"relations":[{"text":"← 前因：德国化学工业","id":"extra680"},{"text":"← 前因：德国拜耳推出阿司匹林","id":"extra738"},{"text":"→ 后果：海牙《国际鸦片公约》","id":"extra744"},{"text":"→ 后果：魏玛德国鸦片法","id":"card100"},{"text":"↔ 相关：现代制药工业","id":"extra950"},{"text":"↔ 相关：德国城市公共卫生运动","id":"extra733"},{"text":"↔ 同时期参考：德国物理学家伦琴发现X射线","id":"extra735"}],"source":"history","id":"extra743"},{"title":"海牙《国际鸦片公约》","level":"B","type":"制度/文本卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1912年签署，第一次世界大战后通过和约体系推动执行","place":"海牙及签署国","summary":"国际鸦片公约是早期国际毒品管制制度的核心文本，把鸦片、吗啡和可卡因纳入跨国治理。","fields":[{"label":"标题","value":"海牙《国际鸦片公约》"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1912年签署，第一次世界大战后通过和约体系推动执行"},{"label":"地点","value":"海牙及签署国"},{"label":"主要国家","value":"中国、英国、德国、美国、荷兰等签署国"},{"label":"一句话概括","value":"国际鸦片公约是早期国际毒品管制制度的核心文本，把鸦片、吗啡和可卡因纳入跨国治理。"},{"label":"制定方/签署方","value":"海牙国际鸦片会议与相关签署国。"},{"label":"主要内容","value":"要求各国控制鸦片、吗啡、可卡因等物质的生产、销售、进出口和医疗用途。"},{"label":"它试图解决什么问题","value":"鸦片贸易、殖民地消费、药品市场扩张和新型生物碱滥用已超出单一国家治理范围。"},{"label":"为什么重要","value":"它是现代国际禁毒制度的起点之一，也把德国等化学制药国家纳入全球药物监管秩序。"},{"label":"争议/局限","value":"早期国际管制执行能力有限，并与帝国主义贸易、殖民治理和道德改革运动交织。"},{"label":"造成的影响","value":"战后和约推动签署国履行义务，各国陆续建立更具体的国内毒品法律。"},{"label":"出处","value":"United Nations Office on Drugs and Crime，history of international drug control；Library of Congress，International Opium Convention materials。"}],"relationItems":["← 前因：拜耳海洛因商品化","← 前因：十九世纪全球鸦片贸易","→ 后果：魏玛德国鸦片法","↔ 相关：一战后巴黎和会","↔ 相关：一战后国际联盟","✗ 对立/冲突：药品贸易自由","✗ 对立/冲突：国际毒品管制","↔ 同时期参考：一战总动员社会"],"relations":[{"text":"← 前因：拜耳海洛因商品化","id":"extra743"},{"text":"← 前因：十九世纪全球鸦片贸易","id":"extra972"},{"text":"→ 后果：魏玛德国鸦片法","id":"card100"},{"text":"↔ 相关：一战后巴黎和会","id":"extra668"},{"text":"↔ 相关：一战后国际联盟","id":"card4"},{"text":"✗ 对立/冲突：国际毒品管制","id":"extra962"},{"text":"↔ 同时期参考：一战总动员社会","id":"extra653"}],"source":"history","id":"extra744"},{"title":"阿尔萨斯-洛林并入德意志帝国","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1871年5月10日后","place":"阿尔萨斯、洛林部分地区；德意志帝国","summary":"普法战争后，法国割让阿尔萨斯和洛林部分地区给德国，使边境安全、民族认同和德法复仇主义长期纠缠在一起。","fields":[{"label":"标题","value":"阿尔萨斯-洛林并入德意志帝国"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1871年5月10日后"},{"label":"地点","value":"阿尔萨斯、洛林部分地区；德意志帝国"},{"label":"主要国家","value":"德国、法国"},{"label":"一句话概括","value":"普法战争后，法国割让阿尔萨斯和洛林部分地区给德国，使边境安全、民族认同和德法复仇主义长期纠缠在一起。"},{"label":"参与者","value":"德意志帝国政府、法国第三共和国、阿尔萨斯-洛林居民、德国皇帝与帝国官僚体系。"},{"label":"发生了什么","value":"1871年《普法战争《法兰克福和约》》结束普法战争，法国被迫割让阿尔萨斯和洛林的一部分，其中包括战略城市梅斯。德国把这片地区组织为“帝国领地阿尔萨斯-洛林”，不把它作为普通邦国纳入联邦，而是由帝国中央更直接地管理。当地居民后来获得帝国议会选举权，但自治权长期有限，地方政治围绕身份归属、行政管制和对德国统治的接受程度展开。"},{"label":"为什么重要","value":"它把德法敌对制度化为一个长期边境问题。阿尔萨斯-洛林既是德国统一胜利的战利品，也是德法复仇主义的象征，成为1871年后欧洲不稳定和平的重要来源。"},{"label":"前因","value":"普法战争的德国胜利使俾斯麦政府获得了向法国索取领土和赔款的条件，德国军方也把梅斯等地视为对法防御的重要战略屏障。"},{"label":"后果","value":"法国国内围绕“收复失地”的情绪持续存在，德国则不得不长期处理帝国领地的身份政治和自治问题，德法关系因此难以真正缓和。"},{"label":"出处","value":"Encyclopaedia Britannica: Alsace-Lorraine；Encyclopaedia Britannica: Treaty of Frankfurt；Deutsches Historisches Museum/LeMO: Elsass-Lothringen。"},{"label":"资料备注","value":"本卡重点是“并入德国后的政治后果”，不重复《普法战争《法兰克福和约》》作为条约本身的内容。"}],"relationItems":["← 前因：普法战争","← 前因：普法战争《法兰克福和约》","→ 后果：德法复仇主义","↔ 相关：德意志帝国成立","↔ 相关：第一次世界大战爆发"],"relations":[{"text":"← 前因：普法战争","id":"extra497"},{"text":"← 前因：普法战争《法兰克福和约》","id":"extra551"},{"text":"→ 后果：德法复仇主义","id":"extra945"},{"text":"↔ 相关：德意志帝国成立","id":"extra621"},{"text":"↔ 相关：第一次世界大战爆发","id":"extra925"}],"source":"history","id":"extra745"},{"title":"德意志帝国马克与金本位","level":"B","type":"制度/文本卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1871—1876年","place":"德意志帝国","summary":"新帝国通过货币改革确立马克和金本位，把分散邦国货币整合为统一的帝国货币制度。","fields":[{"label":"标题","value":"德意志帝国马克与金本位"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1871—1876年"},{"label":"地点","value":"德意志帝国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"新帝国通过货币改革确立马克和金本位，把分散邦国货币整合为统一的帝国货币制度。"},{"label":"制定方/签署方","value":"德意志帝国政府、联邦参议院、帝国议会。"},{"label":"主要内容","value":"1871年后，帝国逐步以马克为统一货币单位，并把货币制度同金本位联系起来。1875年的帝国货币引入命令完成前期改革安排，1876年1月1日起马克和100芬尼制在整个帝国范围内成为统一通货。"},{"label":"它试图解决什么问题","value":"统一前德意志各邦长期存在多种货币和复杂兑换关系，不利于全国市场、税收、银行业务和跨区域贸易。新帝国需要一个能服务统一市场和国家财政的货币基础。"},{"label":"为什么重要","value":"货币统一是政治统一落到日常经济生活中的关键步骤。它降低交易成本，强化帝国财政和金融治理，也使德国更深地进入十九世纪后期的国际金本位体系。"},{"label":"争议/局限","value":"金本位提高了货币稳定性，但也限制了货币政策弹性；改革还与法国赔款流入、金融投机和1873年后经济波动处在同一历史背景中。"},{"label":"造成的影响","value":"统一货币为帝国银行、资本市场扩张和全国商业整合提供基础，并成为此后“金马克”稳定形象的来源。"},{"label":"出处","value":"Deutsche Bundesbank: Zur Einführung der Mark im Dezember 1871；Deutsche Bundesbank: Purchasing power comparisons of historical amounts of money；Reichsgesetzblatt 1871/1873货币立法资料。"}],"relationItems":["← 前因：德意志帝国成立","→ 后果：德意志帝国银行","↔ 相关：1873年德国创办人危机","↔ 相关：德国统一市场形成"],"relations":[{"text":"← 前因：德意志帝国成立","id":"extra621"},{"text":"→ 后果：德意志帝国银行","id":"extra747"},{"text":"↔ 相关：1873年德国创办人危机","id":"extra748"}],"source":"history","id":"extra746"},{"title":"德意志帝国银行","level":"B","type":"组织/机构卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1876—1945年","place":"柏林；德意志帝国及后继德国政权","summary":"德意志帝国银行是新帝国的核心发行银行，把货币统一进一步落实为全国性金融管理机构。","fields":[{"label":"标题","value":"德意志帝国银行"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1876—1945年"},{"label":"地点","value":"柏林；德意志帝国及后继德国政权"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德意志帝国银行是新帝国的核心发行银行，把货币统一进一步落实为全国性金融管理机构。"},{"label":"性质/类型","value":"帝国层面的中央发行银行和金融管理机构。"},{"label":"成立/解散时间","value":"1876年1月1日成立；1945年纳粹德国战败后停止作为德国中央银行运作。"},{"label":"核心目标/宗旨","value":"发行和管理帝国通货，稳定以马克为核心的货币体系，并为统一后的德国金融市场提供中央机构。"},{"label":"关键人物（可选）","value":"首任行长赫尔曼·冯·德亨德；帝国首相和联邦参议院在任命与监督中具有重要作用。"},{"label":"关键行动/事件","value":"接续普鲁士银行等既有发行银行的职能，配合1870年代货币统一；一战前维持与金本位相连的马克体系；1914年战争爆发后金兑换停止，货币稳定基础被削弱。"},{"label":"为什么重要","value":"它说明德国统一不是只靠宪法和军队完成，也依靠货币、银行和财政机构的国家化。帝国银行后来又贯穿魏玛通胀、稳定币改革和纳粹时期金融动员，是德国金融史的长线机构。"},{"label":"争议/局限","value":"帝国银行并非现代意义上完全独立的中央银行，其政策空间受帝国政府、财政需求和战争动员影响很大。"},{"label":"出处","value":"Deutsche Bundesbank: Die Gründung der Reichsbank und deren erste Banknoten aus dem Jahr 1876；Encyclopaedia Britannica: Reichsbank；Harold James, The Reichsbank 1876-1945。"}],"relationItems":["← 前因：德意志帝国马克与金本位","→ 后果：德国一战债务融资政策","↔ 相关：德国一战债务融资政策","↔ 相关：魏玛恶性通货膨胀"],"relations":[{"text":"← 前因：德意志帝国马克与金本位","id":"extra746"},{"text":"→ 后果：德国一战债务融资政策","id":"extra699"},{"text":"↔ 相关：德国一战债务融资政策","id":"extra699"},{"text":"↔ 相关：魏玛恶性通货膨胀","id":"card90"}],"source":"history","id":"extra747"},{"title":"1873年德国创办人危机","level":"B","type":"事件卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1873年起","place":"德意志帝国；维也纳、柏林等中欧金融市场","summary":"统一后的投机繁荣在1873年崩塌，德国进入长期萧条，并推动俾斯麦从自由贸易转向保护主义。","fields":[{"label":"标题","value":"1873年德国创办人危机"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1873年起"},{"label":"地点","value":"德意志帝国；维也纳、柏林等中欧金融市场"},{"label":"主要国家","value":"德国、奥匈帝国、美国"},{"label":"一句话概括","value":"统一后的投机繁荣在1873年崩塌，德国进入长期萧条，并推动俾斯麦从自由贸易转向保护主义。"},{"label":"参与者","value":"德国投资者、股份公司、银行、铁路和工业企业、俾斯麦政府、农业和重工业利益集团。"},{"label":"发生了什么","value":"德意志统一、法国赔款流入、股份公司制度放松和铁路工业扩张共同造成1871—1873年的“创办人年代”繁荣，大量新公司成立，普通投资者也进入股票市场。1873年维也纳金融危机和国际恐慌扩散后，德国股票、房地产和企业融资迅速降温，新设公司破产，投资萎缩，价格下跌。德国经济没有回到统一初期的投机乐观，而是在1870年代后半期进入被称为“创办人危机”的长期调整。"},{"label":"为什么重要","value":"这场危机打断了新帝国的自由主义经济高潮，改变了政策联盟。它为1879年保护关税、铁与黑麦联盟和俾斯麦同民族自由派的裂痕提供了经济背景。"},{"label":"前因","value":"统一胜利带来的民族乐观、法国赔款流入、货币和公司制度改革、铁路与重工业扩张共同放大了投机繁荣。"},{"label":"后果","value":"农业和工业保护主义诉求上升，俾斯麦逐渐转向保守财政与关税政策，帝国政治的自由主义阶段由此受挫。"},{"label":"出处","value":"Encyclopaedia Britannica: Panic of 1873；Encyclopaedia Britannica: German Empire；David Blackbourn, The Long Nineteenth Century: A History of Germany, 1780-1918。"}],"relationItems":["← 前因：德意志帝国马克与金本位","← 前因：普法战争《法兰克福和约》","→ 后果：德意志帝国保护关税政策","→ 后果：德国铁与黑麦联盟","↔ 相关：德国民族自由党"],"relations":[{"text":"← 前因：德意志帝国马克与金本位","id":"extra746"},{"text":"← 前因：普法战争《法兰克福和约》","id":"extra551"},{"text":"→ 后果：德意志帝国保护关税政策","id":"extra630"},{"text":"→ 后果：德国铁与黑麦联盟","id":"extra756"},{"text":"↔ 相关：德国民族自由党","id":"extra674"}],"source":"history","id":"extra748"},{"title":"德国三皇同盟","level":"B","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1873年建立，1880年代多次调整","place":"柏林、维也纳、圣彼得堡及欧洲外交体系","summary":"三皇同盟把德国、奥匈和俄国三大保守君主国暂时拉在一起，是俾斯麦孤立法国战略的早期支柱。","fields":[{"label":"标题","value":"德国三皇同盟"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1873年建立，1880年代多次调整"},{"label":"地点","value":"柏林、维也纳、圣彼得堡及欧洲外交体系"},{"label":"主要国家","value":"德国、奥匈帝国、俄罗斯帝国"},{"label":"一句话概括","value":"三皇同盟把德国、奥匈和俄国三大保守君主国暂时拉在一起，是俾斯麦孤立法国战略的早期支柱。"},{"label":"制定方/签署方","value":"德皇威廉一世、奥匈皇帝弗朗茨·约瑟夫一世、俄国沙皇亚历山大二世及三国政府。"},{"label":"主要内容","value":"三国以君主制团结和相互协商为基础，试图在欧洲革命问题、德法复仇主义和东方问题上维持大国协调。它不是一个能消除奥俄竞争的坚固军事同盟，更像维持保守秩序和外交沟通的框架。"},{"label":"它试图解决什么问题","value":"1871年后德国担心法国寻找盟友复仇，因此需要让俄国和奥匈都留在德国可协调的外交网络内，避免德国同时面对东西两线压力。"},{"label":"为什么重要","value":"它体现俾斯麦外交的核心目标：让德国成为欧洲协调中心，同时防止法国突破孤立。后来巴尔干问题反复冲击三皇关系，说明这个结构内在脆弱。"},{"label":"争议/局限","value":"奥匈和俄国在巴尔干利益相冲突，三皇同盟无法永久压住这种结构性矛盾。它的存在更多依赖俾斯麦的平衡术，而不是三国利益天然一致。"},{"label":"造成的影响","value":"三皇同盟为1870年代德国外交提供缓冲，但俄奥矛盾最终推动德国转向更明确的1879年德奥同盟，并在1887年以再保险条约继续单独安抚俄国。"},{"label":"出处","value":"Encyclopaedia Britannica: German Empire；William L. Langer, European Alliances and Alignments, 1871-1890；A. J. P. Taylor, The Struggle for Mastery in Europe, 1848-1918。"}],"relationItems":["← 前因：德意志帝国成立","→ 后果：巴尔干危机1878年柏林会议","→ 后果：1879年德奥同盟","↔ 相关：德俄再保险条约","↔ 相关：奥托·冯·俾斯麦"],"relations":[{"text":"← 前因：德意志帝国成立","id":"extra621"},{"text":"→ 后果：巴尔干危机1878年柏林会议","id":"extra753"},{"text":"→ 后果：1879年德奥同盟","id":"extra755"},{"text":"↔ 相关：德俄再保险条约","id":"extra632"},{"text":"↔ 相关：奥托·冯·俾斯麦","id":"extra924"}],"source":"history","id":"extra749"},{"title":"1875年战争在望危机","level":"C","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1875年","place":"柏林、巴黎、伦敦、圣彼得堡","summary":"德国舆论和外交围绕是否再次打击法国出现战争恐慌，英国和俄国介入后德国收敛姿态。","fields":[{"label":"标题","value":"1875年战争在望危机"},{"label":"分级","value":"C"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1875年"},{"label":"地点","value":"柏林、巴黎、伦敦、圣彼得堡"},{"label":"主要国家","value":"德国、法国、英国、俄罗斯帝国"},{"label":"一句话概括","value":"德国舆论和外交围绕是否再次打击法国出现战争恐慌，英国和俄国介入后德国收敛姿态。"},{"label":"参与者","value":"俾斯麦政府、德国报刊、法国第三共和国、英国政府、俄国政府。"},{"label":"发生了什么","value":"普法战争后，法国推进军队重建和新军事立法，引发德国对法国复仇能力恢复的警惕。1875年，德国报刊出现“战争是否在望？”之类标题，欧洲外交界开始担心德国可能考虑预防性战争。法国寻求外部支持，英国和俄国都对德国施加外交压力，最终危机没有升级为战争。俾斯麦是否主动制造危机、还是利用舆论试探列强反应，史学上仍有争论。"},{"label":"为什么重要","value":"它显示1871年后的德法和平非常脆弱，也提醒俾斯麦：德国虽然是新强权，但不能在没有列强默许的情况下随意压迫法国。"},{"label":"前因","value":"阿尔萨斯-洛林问题和德法复仇主义使德国长期担心法国恢复军力，法国军事改革又被柏林解释为未来战争风险。"},{"label":"后果","value":"德国更加重视通过同盟体系孤立法国，而不是直接发动新战争；英国和俄国也显示出不会放任德国破坏欧洲均势。"},{"label":"出处","value":"James Stone, The War Scare of 1875: Bismarck and Europe in the Mid-1870s；Encyclopaedia Britannica: German Empire；William L. Langer, European Alliances and Alignments, 1871-1890。"},{"label":"资料备注","value":"本卡对俾斯麦责任采取谨慎表述，因为学界对他在危机中的主动程度存在争议。"}],"relationItems":["← 前因：阿尔萨斯-洛林并入德意志帝国","← 前因：德国三皇同盟","→ 后果：1879年德奥同盟","↔ 相关：德法复仇主义","↔ 相关：奥托·冯·俾斯麦"],"relations":[{"text":"← 前因：阿尔萨斯-洛林并入德意志帝国","id":"extra745"},{"text":"← 前因：德国三皇同盟","id":"extra749"},{"text":"→ 后果：1879年德奥同盟","id":"extra755"},{"text":"↔ 相关：德法复仇主义","id":"extra945"},{"text":"↔ 相关：奥托·冯·俾斯麦","id":"extra924"}],"source":"history","id":"extra750"},{"title":"德意志帝国反耶稣会法","level":"C","type":"制度/文本卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1872年","place":"德意志帝国","summary":"反耶稣会法限制耶稣会在德国活动，是俾斯麦文化斗争中打击天主教组织网络的帝国层面措施。","fields":[{"label":"标题","value":"德意志帝国反耶稣会法"},{"label":"分级","value":"C"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1872年"},{"label":"地点","value":"德意志帝国"},{"label":"主要国家","value":"德国、梵蒂冈"},{"label":"一句话概括","value":"反耶稣会法限制耶稣会在德国活动，是俾斯麦文化斗争中打击天主教组织网络的帝国层面措施。"},{"label":"制定方/签署方","value":"德意志帝国政府、帝国议会、联邦参议院。"},{"label":"主要内容","value":"法律限制耶稣会及相关修会在德意志帝国内活动，关闭或禁止其机构，并允许驱逐相关成员。它把文化斗争从普鲁士教育和教会监管扩展到整个帝国范围。"},{"label":"它试图解决什么问题","value":"俾斯麦和自由派担心天主教会、教皇权威和中央党形成超国家忠诚网络，削弱新帝国的政治整合。耶稣会被视为这种教会影响力的象征性目标。"},{"label":"为什么重要","value":"它显示文化斗争不只是普鲁士地方政策，也是新帝国构建国家权威时对宗教组织的直接干预。"},{"label":"争议/局限","value":"法律把宗教群体当作政治安全问题处理，加深了天主教民众与帝国政府的对立，反而帮助中央党巩固选民基础。"},{"label":"造成的影响","value":"反耶稣会法成为文化斗争的重要标志之一，后来随着俾斯麦同天主教力量缓和关系，其实际政治意义逐渐下降。"},{"label":"出处","value":"Encyclopaedia Britannica: Kulturkampf；Deutsches Historisches Museum/LeMO: Kulturkampf。"}],"relationItems":["← 前因：德意志帝国文化斗争","→ 后果：普鲁士五月法","↔ 相关：德国中央党","↔ 相关：奥托·冯·俾斯麦"],"relations":[{"text":"← 前因：德意志帝国文化斗争","id":"extra626"},{"text":"→ 后果：普鲁士五月法","id":"extra752"},{"text":"↔ 相关：德国中央党","id":"extra673"},{"text":"↔ 相关：奥托·冯·俾斯麦","id":"extra924"}],"source":"history","id":"extra751"},{"title":"普鲁士五月法","level":"C","type":"制度/文本卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1873年","place":"普鲁士；德意志帝国政治体系","summary":"普鲁士五月法把神职教育、任命和纪律置于国家监管之下，是文化斗争中最强硬的制度工具之一。","fields":[{"label":"标题","value":"普鲁士五月法"},{"label":"分级","value":"C"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1873年"},{"label":"地点","value":"普鲁士；德意志帝国政治体系"},{"label":"主要国家","value":"德国、普鲁士、梵蒂冈"},{"label":"一句话概括","value":"普鲁士五月法把神职教育、任命和纪律置于国家监管之下，是文化斗争中最强硬的制度工具之一。"},{"label":"制定方/签署方","value":"普鲁士政府、普鲁士议会；关键推动者包括普鲁士文化部长阿达尔贝特·法尔克。"},{"label":"主要内容","value":"五月法要求神职人员接受国家认可的教育和考试，对教会任命、纪律处分和神职资格设置国家监督。它试图让天主教会的人事和教育体系服从普鲁士国家法律。"},{"label":"它试图解决什么问题","value":"普鲁士政府认为教会特别是天主教会仍掌握教育和社会组织力量，可能与新帝国的国家权威竞争。五月法旨在把教会纳入国家监管秩序。"},{"label":"为什么重要","value":"它是文化斗争从政治冲突变成制度冲突的关键节点，直接触碰教会自治和国家主权的边界。"},{"label":"争议/局限","value":"强制监管导致教士被罚、被监禁或职位空缺，未能瓦解中央党，反而让天主教政治身份更集中。"},{"label":"造成的影响","value":"文化斗争在1870年代中期达到高峰；此后俾斯麦因政治需要逐步缓和同天主教会和中央党的冲突。"},{"label":"出处","value":"Encyclopaedia Britannica: Kulturkampf；Encyclopaedia Britannica: German Empire, The Franco-German War section；Deutsches Historisches Museum/LeMO: Kulturkampf。"}],"relationItems":["← 前因：德意志帝国反耶稣会法","↔ 相关：德国中央党","↔ 相关：德意志帝国文化斗争","↔ 相关：奥托·冯·俾斯麦"],"relations":[{"text":"← 前因：德意志帝国反耶稣会法","id":"extra751"},{"text":"↔ 相关：德国中央党","id":"extra673"},{"text":"↔ 相关：德意志帝国文化斗争","id":"extra626"},{"text":"↔ 相关：奥托·冯·俾斯麦","id":"extra924"}],"source":"history","id":"extra752"},{"title":"巴尔干危机1878年柏林会议","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1878年6月13日—7月13日","place":"柏林","summary":"柏林会议修订俄土战争后的圣斯特凡诺安排，俾斯麦以“诚实经纪人”姿态协调列强利益。","fields":[{"label":"标题","value":"巴尔干危机1878年柏林会议"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1878年6月13日—7月13日"},{"label":"地点","value":"柏林"},{"label":"主要国家","value":"德国、俄罗斯帝国、奥匈帝国、英国、法国、意大利、奥斯曼帝国及巴尔干相关国家"},{"label":"一句话概括","value":"柏林会议修订俄土战争后的圣斯特凡诺安排，俾斯麦以“诚实经纪人”姿态协调列强利益。"},{"label":"参与者","value":"奥托·冯·俾斯麦、俄国、奥匈、英国、法国、意大利、奥斯曼帝国代表，以及巴尔干相关政治力量。"},{"label":"发生了什么","value":"1877—1878年俄土战争后，俄罗斯迫使奥斯曼帝国接受《圣斯特凡诺条约》，大幅扩大保加利亚并增强俄国在巴尔干影响力。英国和奥匈担心俄国势力过度扩张，欧洲大国在柏林召开会议重议条约。会议削减了大保加利亚安排，承认或调整塞尔维亚、罗马尼亚、黑山等地位，并允许奥匈占领波斯尼亚和黑塞哥维那。德国不是主要领土受益者，但俾斯麦主持会议，试图维护欧洲均势。"},{"label":"为什么重要","value":"它让德国显示出欧洲协调中心的地位，但也暴露俄奥矛盾。俄罗斯对修订结果不满，三皇同盟的脆弱性进一步显现。"},{"label":"前因","value":"巴尔干民族起义、俄土战争和《圣斯特凡诺条约》打破了东方问题的列强平衡，使英国和奥匈要求重新谈判。"},{"label":"后果","value":"俄国对德国调停结果产生怨气，德国随后更明确地靠向奥匈，1879年德奥同盟由此获得现实基础。"},{"label":"出处","value":"Encyclopaedia Britannica: Congress of Berlin；Office of the Historian: The Congress of Berlin and the Balkan Crisis；Encyclopaedia Britannica: Germany from 1871 to 1918。"}],"relationItems":["← 前因：德国三皇同盟","→ 后果：1879年德奥同盟","↔ 相关：德俄再保险条约","↔ 相关：巴尔干民族问题","↔ 同时期参考：奥斯曼帝国衰落"],"relations":[{"text":"← 前因：德国三皇同盟","id":"extra749"},{"text":"→ 后果：1879年德奥同盟","id":"extra755"},{"text":"↔ 相关：德俄再保险条约","id":"extra632"},{"text":"↔ 相关：巴尔干民族问题","id":"extra930"}],"source":"history","id":"extra753"},{"title":"德国1878年皇帝遇刺案","level":"C","type":"事件卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1878年5月11日、1878年6月2日","place":"柏林，菩提树下大街一带","summary":"1878年两次针对威廉一世的刺杀未遂，被俾斯麦用来推动反社会党人法和保守政治转向。","fields":[{"label":"标题","value":"德国1878年皇帝遇刺案"},{"label":"分级","value":"C"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1878年5月11日、1878年6月2日"},{"label":"地点","value":"柏林，菩提树下大街一带"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1878年两次针对威廉一世的刺杀未遂，被俾斯麦用来推动反社会党人法和保守政治转向。"},{"label":"参与者","value":"德皇威廉一世、马克斯·赫德尔、卡尔·诺比林、奥托·冯·俾斯麦、帝国议会和德国社会主义工人党。"},{"label":"发生了什么","value":"1878年5月11日，马克斯·赫德尔在柏林向威廉一世开枪但未击中；6月2日，卡尔·诺比林再次袭击威廉一世并造成其受伤。两名袭击者同社会民主党组织关系并不构成俾斯麦所宣称的政党责任，但政府把事件塑造成社会主义威胁。俾斯麦借此解散帝国议会、重新选举，并推动1878年《反社会党人法》通过。"},{"label":"为什么重要","value":"遇刺案本身不是德国社会主义运动发动的政变，却成为国家镇压工人运动的政治契机。它帮助解释俾斯麦如何把安全恐慌转化为法律和选举优势。"},{"label":"前因","value":"工业化带来工人运动扩张，社会主义政党得票上升，俾斯麦已经在寻找压制社会民主主义的政治机会。"},{"label":"后果","value":"《反社会党人法》限制社会主义组织、出版物和集会，但没有消灭社会民主主义，反而让工人运动形成更强的受压迫身份。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Sozialistengesetz；Deutsches Historisches Museum/LeMO: Wilhelm I.；German History in Documents and Images: Reactions to the First Attempt on the Life of Kaiser Wilhelm I。"}],"relationItems":["→ 后果：德国反社会党人法","→ 后果：德国社会民主党（SPD）","↔ 相关：德国社会主义工人党《哥达纲领》","↔ 相关：德国俾斯麦社会保险立法"],"relations":[{"text":"→ 后果：德国反社会党人法","id":"extra627"},{"text":"→ 后果：德国社会民主党（SPD）","id":"extra628"},{"text":"↔ 相关：德国社会主义工人党《哥达纲领》","id":"extra695"},{"text":"↔ 相关：德国俾斯麦社会保险立法","id":"extra629"}],"source":"history","id":"extra754"},{"title":"1879年德奥同盟","level":"A","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1879年10月7日","place":"维也纳、柏林及欧洲外交体系","summary":"1879年德奥同盟把德国同奥匈绑定为防御性同盟，成为一战前欧洲同盟体系的关键骨架。","fields":[{"label":"标题","value":"1879年德奥同盟"},{"label":"分级","value":"A"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1879年10月7日"},{"label":"地点","value":"维也纳、柏林及欧洲外交体系"},{"label":"主要国家","value":"德国、奥匈帝国、俄罗斯帝国"},{"label":"一句话概括","value":"1879年德奥同盟把德国同奥匈绑定为防御性同盟，成为一战前欧洲同盟体系的关键骨架。"},{"label":"制定方/签署方","value":"德意志帝国与奥匈帝国政府；关键推动者为奥托·冯·俾斯麦和奥匈外交决策层。"},{"label":"主要内容","value":"两国约定如一方遭俄国攻击，另一方提供军事援助；如一方遭其他大国攻击，另一方至少保持善意中立。它是一项针对俄国风险设计的防御同盟。"},{"label":"它试图解决什么问题","value":"巴尔干危机1878年柏林会议后俄奥矛盾加深，德国担心在巴尔干问题上失去奥匈或面对俄国压力，因此需要一个更明确的安全承诺。"},{"label":"为什么重要","value":"这是德意志帝国外交的长期结构性选择。它后来成为三国同盟和一战同盟集团的基础，也把德国安全越来越多地同奥匈的巴尔干困境捆绑起来。"},{"label":"争议/局限","value":"俾斯麦本意是威慑和稳定，而非发动大战；但同盟一旦长期化，德国在危机中支持奥匈的惯性增强，削弱了外交灵活性。"},{"label":"造成的影响","value":"德奥关系成为德国外交的固定支点，意大利1882年加入形成三国同盟；俄国则逐渐寻找其他安全出口，最终同法国接近。"},{"label":"出处","value":"Encyclopaedia Britannica: Austro-German Alliance；German History in Documents and Images: Dual Alliance with Austria；Encyclopaedia Britannica: Germany from 1871 to 1918。"}],"relationItems":["← 前因：巴尔干危机1878年柏林会议","← 前因：德国三皇同盟","→ 后果：德奥意三国同盟","→ 后果：第一次世界大战爆发","↔ 相关：德俄再保险条约"],"relations":[{"text":"← 前因：巴尔干危机1878年柏林会议","id":"extra753"},{"text":"← 前因：德国三皇同盟","id":"extra749"},{"text":"→ 后果：德奥意三国同盟","id":"extra631"},{"text":"→ 后果：第一次世界大战爆发","id":"extra925"},{"text":"↔ 相关：德俄再保险条约","id":"extra632"}],"source":"history","id":"extra755"},{"title":"德国铁与黑麦联盟","level":"B","type":"概念/思潮卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1879年后尤为突出","place":"德意志帝国，尤其是鲁尔重工业区和普鲁士东部农业区","summary":"铁与黑麦联盟指重工业和东部农业地主围绕保护关税结成的利益联盟，支撑帝国保守经济政策。","fields":[{"label":"标题","value":"德国铁与黑麦联盟"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1879年后尤为突出"},{"label":"地点","value":"德意志帝国，尤其是鲁尔重工业区和普鲁士东部农业区"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"铁与黑麦联盟指重工业和东部农业地主围绕保护关税结成的利益联盟，支撑帝国保守经济政策。"},{"label":"核心主张/思路","value":"重工业要求保护铁钢等工业产品，容克地主和农业利益集团要求保护谷物价格；两者通过关税政策形成共同政治利益。"},{"label":"提出者/代表人物（可选）","value":"这不是单一人物提出的正式组织，而是史学上用来概括1879年后德国保护主义政治联盟的说法。"},{"label":"它从何而来","value":"1873年后经济萧条、国际粮食竞争、工业利润压力和帝国财政需求共同削弱自由贸易共识，农业和工业保护主义者开始形成合流。"},{"label":"典型表现","value":"支持1879年保护关税；保守党、部分民族自由派、容克地主和重工业游说力量在关税问题上靠近。"},{"label":"为什么重要","value":"它解释了帝国政治为何从早期自由主义改革转向保守利益整合。德国工业化并没有自动导向自由主义政治，而是可以同地主保守势力结盟。"},{"label":"争议/局限","value":"铁与黑麦联盟是概括性概念，不能把所有工业家、农场主或政党都视为一致集团；不同地区和行业的利益仍有差异。"},{"label":"出处","value":"Encyclopaedia Britannica: German Empire；David Blackbourn, The Long Nineteenth Century: A History of Germany, 1780-1918；Hans-Ulrich Wehler, The German Empire, 1871-1918。"}],"relationItems":["← 前因：1873年德国创办人危机","← 前因：德意志帝国保护关税政策","→ 后果：德意志帝国保守政治联盟","↔ 相关：普鲁士容克地主","↔ 相关：德国鲁尔工业区"],"relations":[{"text":"← 前因：1873年德国创办人危机","id":"extra748"},{"text":"← 前因：德意志帝国保护关税政策","id":"extra630"},{"text":"↔ 相关：普鲁士容克地主","id":"extra672"},{"text":"↔ 相关：德国鲁尔工业区","id":"extra679"}],"source":"history","id":"extra756"},{"title":"德意志帝国司法法","level":"B","type":"制度/文本卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1877年通过，1879年10月1日起实施","place":"德意志帝国","summary":"帝国司法法统一法院组织和诉讼规则，把德意志政治统一推进到司法制度层面。","fields":[{"label":"标题","value":"德意志帝国司法法"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1877年通过，1879年10月1日起实施"},{"label":"地点","value":"德意志帝国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"帝国司法法统一法院组织和诉讼规则，把德意志政治统一推进到司法制度层面。"},{"label":"制定方/签署方","value":"德意志帝国政府、帝国议会、联邦参议院。"},{"label":"主要内容","value":"1877年前后通过的帝国司法立法包括法院组织、民事诉讼、刑事诉讼和破产等核心法律，1879年起实施。它建立全国更统一的普通法院体系，并为帝国法院发挥最高审级作用奠定基础。"},{"label":"它试图解决什么问题","value":"统一前各邦司法制度、程序和法院结构差异明显，不利于统一市场、跨邦权利保护和国家权威。新帝国需要在保持联邦结构的同时建立可预期的司法秩序。"},{"label":"为什么重要","value":"它是德国“法治国家”建设的重要制度节点。没有司法统一，帝国统一会停留在外交、军队和宪法层面，经济和社会生活仍会被邦国差异割裂。"},{"label":"争议/局限","value":"司法统一不等于政治自由化。帝国法院体系仍处在君主制帝国框架内，后来在政治案件和社会冲突中也会体现国家秩序优先的倾向。"},{"label":"造成的影响","value":"帝国法院1879年运作，全国民事、刑事和商业争议有了更统一的最高审级，后来的德国民法典实施也有了司法制度基础。"},{"label":"出处","value":"Bundesverwaltungsgericht: History of the Building；Reichsgesetzblatt 1877帝国司法立法资料；Michael John, Politics and the Law in Late Nineteenth-Century Germany。"}],"relationItems":["← 前因：德意志帝国宪法","→ 后果：德意志帝国法院","→ 后果：德国民法典","↔ 相关：德国刑法典第175条"],"relations":[{"text":"← 前因：德意志帝国宪法","id":"extra624"},{"text":"→ 后果：德意志帝国法院","id":"extra758"},{"text":"→ 后果：德国民法典","id":"extra720"},{"text":"↔ 相关：德国刑法典第175条","id":"extra721"}],"source":"history","id":"extra757"},{"title":"德意志帝国法院","level":"C","type":"组织/机构卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1879—1945年","place":"莱比锡","summary":"德意志帝国法院是帝国普通司法体系的最高法院，象征德国法律统一从立法进入审判实践。","fields":[{"label":"标题","value":"德意志帝国法院"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1879—1945年"},{"label":"地点","value":"莱比锡"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德意志帝国法院是帝国普通司法体系的最高法院，象征德国法律统一从立法进入审判实践。"},{"label":"性质/类型","value":"德意志帝国最高普通法院，主要处理民事和刑事案件的最高审级。"},{"label":"成立/解散时间","value":"1879年10月1日开始运作；1945年德国战败后终止。"},{"label":"核心目标/宗旨","value":"统一帝国普通司法裁判尺度，为各邦法院之上的最高审级提供权威解释和判决。"},{"label":"关键人物（可选）","value":"帝国法院法官群体；其制度基础来自1877年帝国司法法。"},{"label":"关键行动/事件","value":"法院设于莱比锡而非柏林，反映联邦政治中对普鲁士中心化的某种平衡；它在帝国、魏玛和纳粹时期都持续存在。"},{"label":"为什么重要","value":"帝国法院让统一德国拥有全国性司法权威，是理解德国国家建构和法律专业化的重要机构。它也为后来的联邦最高法院传统提供历史背景。"},{"label":"争议/局限","value":"帝国法院不是宪法法院，无法解决帝国体制中议会权力有限、君主行政权强等根本问题；其历史也跨越到纳粹时期，评价需区分不同时段。"},{"label":"出处","value":"Bundesverwaltungsgericht: History of the Building；Bundesverwaltungsgericht: Das Gebäude；Reichsgericht历史资料。"}],"relationItems":["← 前因：德意志帝国司法法","→ 后果：德国民法典","↔ 相关：德意志帝国宪法","↔ 相关：魏玛宪法"],"relations":[{"text":"← 前因：德意志帝国司法法","id":"extra757"},{"text":"→ 后果：德国民法典","id":"extra720"},{"text":"↔ 相关：德意志帝国宪法","id":"extra624"},{"text":"↔ 相关：魏玛宪法","id":"card11"}],"source":"history","id":"extra758"},{"title":"德国养老和残疾保险法","level":"B","type":"制度/文本卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1889年","place":"德意志帝国","summary":"1889年养老和残疾保险法补齐俾斯麦社会保险体系，建立世界上最早的国家养老保险制度之一。","fields":[{"label":"标题","value":"德国养老和残疾保险法"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1889年"},{"label":"地点","value":"德意志帝国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1889年养老和残疾保险法补齐俾斯麦社会保险体系，建立世界上最早的国家养老保险制度之一。"},{"label":"制定方/签署方","value":"德意志帝国政府、帝国议会、联邦参议院；由俾斯麦政府推动。"},{"label":"主要内容","value":"法律为劳动者建立老年和残疾保险安排，通过雇主、雇员和国家参与的缴费或补助机制提供养老金和残疾保障。养老金年龄门槛较高，保障水平有限，但制度上承认国家对工业劳动风险负有责任。"},{"label":"它试图解决什么问题","value":"工业化扩大了工伤、疾病、失业和老年贫困风险，传统慈善和地方救济不足以稳定工人社会。俾斯麦也希望用社会保险削弱社会民主主义吸引力。"},{"label":"为什么重要","value":"它与1883年疾病保险、1884年事故保险一起，构成现代福利国家的重要早期样板。德国由此把社会问题纳入国家制度，而不只是警察镇压或慈善救济。"},{"label":"争议/局限","value":"保险范围、给付水平和年龄门槛都有限，政治目的也包含对工人运动的控制。它改善了部分风险保障，但没有赋予工人充分政治权利。"},{"label":"造成的影响","value":"俾斯麦社会保险体系成为许多国家后来社会保障制度的参照，也让德国国家能力深入劳动者日常生活。"},{"label":"出处","value":"U.S. Social Security Administration: Otto von Bismarck；Deutsche Digitale Bibliothek: Gesetz betreffend die Invaliditäts- und Altersversicherung；German History in Documents and Images: Collecting Benefits from Old Age and Disability Insurance。"}],"relationItems":["← 前因：德国俾斯麦社会保险立法","← 前因：德国反社会党人法","↔ 相关：德国疾病保险法","↔ 相关：德国事故保险法","→ 后果：现代福利国家"],"relations":[{"text":"← 前因：德国俾斯麦社会保险立法","id":"extra629"},{"text":"← 前因：德国反社会党人法","id":"extra627"},{"text":"↔ 相关：德国疾病保险法","id":"extra740"},{"text":"↔ 相关：德国事故保险法","id":"extra741"},{"text":"→ 后果：现代福利国家","id":"extra951"}],"source":"history","id":"extra759"},{"title":"1884—1885年柏林西非会议","level":"A","type":"事件卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1884年11月15日—1885年2月26日","place":"柏林","summary":"柏林西非会议为列强在非洲扩张制定外交规则，加速“瓜分非洲”，但没有非洲代表参与。","fields":[{"label":"标题","value":"1884—1885年柏林西非会议"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1884年11月15日—1885年2月26日"},{"label":"地点","value":"柏林"},{"label":"主要国家","value":"德国、英国、法国、比利时、葡萄牙、意大利、西班牙、美国、奥斯曼帝国等"},{"label":"一句话概括","value":"柏林西非会议为列强在非洲扩张制定外交规则，加速“瓜分非洲”，但没有非洲代表参与。"},{"label":"参与者","value":"德国首相俾斯麦主持下的欧洲列强和美国代表；刚果相关利益方；非洲政治共同体未获代表权。"},{"label":"发生了什么","value":"1884年，围绕刚果盆地、通商自由、传教与航行权以及欧洲列强在非洲的竞争，德国在柏林召集国际会议。会议从1884年11月持续到1885年2月，形成《柏林会议总议定书》，确认刚果河和尼日尔河流域通商航行原则，并提出“有效占领”等殖民主张规则。会议没有让非洲国家和社会参与，却为欧洲列强扩张提供了外交框架。"},{"label":"为什么重要","value":"这是世界史上殖民帝国主义加速的关键节点之一。它不是简单“把非洲切成地图”的单一会议，却显著降低了欧洲列强协调殖民竞争的成本，推动非洲主权和边界被外部力量重塑。"},{"label":"前因","value":"十九世纪后期欧洲工业化国家争夺原料、市场和战略通道，比利时国王利奥波德二世的刚果活动以及葡萄牙、英国、法国等国竞争使西非和中非问题国际化。"},{"label":"后果","value":"非洲被纳入更密集的殖民统治和资源掠夺体系，德国也正式进入殖民帝国竞争；殖民边界和暴力治理为二十世纪非洲政治留下长期遗产。"},{"label":"出处","value":"Encyclopaedia Britannica: Berlin Conference；Office of the Historian: The Berlin Conference, 1884-1885；Encyclopaedia Britannica: Scramble for Africa。"},{"label":"资料备注","value":"标题采用“柏林西非会议”而非单独“柏林会议”，避免与巴尔干危机1878年柏林会议混淆。"}],"relationItems":["← 前因：德意志殖民帝国","→ 后果：瓜分非洲","→ 后果：刚果自由邦","↔ 相关：德意志帝国世界政策","↔ 同时期参考：英法殖民竞争"],"relations":[{"text":"← 前因：德意志殖民帝国","id":"extra641"},{"text":"→ 后果：刚果自由邦","id":"extra967"},{"text":"↔ 相关：德意志帝国世界政策","id":"extra635"},{"text":"↔ 同时期参考：英法殖民竞争","id":"extra875"}],"source":"history","id":"extra760"},{"title":"德国三皇年","level":"B","type":"事件卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1888年","place":"德意志帝国；柏林、波茨坦","summary":"1888年德国先后经历威廉一世、腓特烈三世和威廉二世三位皇帝，象征帝国从俾斯麦时代转入威廉时代。","fields":[{"label":"标题","value":"德国三皇年"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1888年"},{"label":"地点","value":"德意志帝国；柏林、波茨坦"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1888年德国先后经历威廉一世、腓特烈三世和威廉二世三位皇帝，象征帝国从俾斯麦时代转入威廉时代。"},{"label":"参与者","value":"威廉一世、腓特烈三世、威廉二世、奥托·冯·俾斯麦、德意志帝国政府。"},{"label":"发生了什么","value":"1888年3月9日，德皇威廉一世去世，其子腓特烈三世继位。腓特烈三世长期被自由派寄予较温和、较自由主义的期待，但他继位时已患喉癌，只统治99天便在6月15日去世。随后29岁的威廉二世继位，成为德意志皇帝和普鲁士国王。三位皇帝在同一年更替，使1888年被称为“三皇年”。"},{"label":"为什么重要","value":"它不是制度革命，却是政治代际转换的标志。腓特烈三世短命使自由派期待落空，威廉二世继位则为1890年俾斯麦下台、皇帝亲政和德意志帝国世界政策打开道路。"},{"label":"前因","value":"德意志帝国仍以君主、首相和普鲁士权力结构为核心，皇位继承直接影响帝国政策方向；威廉一世高龄和腓特烈三世重病使继承问题在1888年集中爆发。"},{"label":"后果","value":"威廉二世年轻继位后不愿长期受俾斯麦控制，帝国很快出现皇帝与首相权力冲突，并在1890年进入后俾斯麦时代。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Dreikaiserjahr 1888；Encyclopaedia Britannica: William II；Encyclopaedia Britannica: German Empire。"}],"relationItems":["← 前因：德意志帝国俾斯麦时代","→ 后果：俾斯麦辞去德意志帝国首相","→ 后果：德国威廉二世亲政","↔ 相关：德意志帝国宪法"],"relations":[{"text":"← 前因：德意志帝国俾斯麦时代","id":"extra625"},{"text":"→ 后果：俾斯麦辞去德意志帝国首相","id":"extra633"},{"text":"→ 后果：德国威廉二世亲政","id":"extra634"},{"text":"↔ 相关：德意志帝国宪法","id":"extra624"}],"source":"history","id":"extra761"},{"title":"德国反社会党人法失效","level":"B","type":"事件卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1890年","place":"德意志帝国","summary":"1890年反社会党人法未再延长，社会民主主义重新合法组织化，SPD很快成为帝国最大群众政党。","fields":[{"label":"标题","value":"德国反社会党人法失效"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1890年"},{"label":"地点","value":"德意志帝国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1890年反社会党人法未再延长，社会民主主义重新合法组织化，SPD很快成为帝国最大群众政党。"},{"label":"参与者","value":"威廉二世、奥托·冯·俾斯麦、帝国议会、德国社会主义工人党、德国社会民主党（SPD）。"},{"label":"发生了什么","value":"1878年以来，反社会党人法禁止社会民主主义组织、出版和集会，但社会民主党候选人仍能以个人身份参加帝国议会选举。到1890年，社会民主主义选票没有被压垮，反而明显增长。俾斯麦仍希望延长并强化法律，威廉二世初期则希望用较温和姿态争取工人阶级，帝国议会也不再支持继续维持这套非常法。法律到期后不再延长，原德国社会主义工人党重组并改名为德国社会民主党。"},{"label":"为什么重要","value":"它标志俾斯麦镇压工人运动路线失败。社会民主主义从非法化压力下走出，进入更公开的群众组织和议会政治阶段。"},{"label":"前因","value":"反社会党人法长期镇压没有消灭社会民主主义，工业工人阶级扩大和选举支持增长反而证明单纯警察手段难以解决社会问题。"},{"label":"后果","value":"SPD获得合法组织空间，工会、党报和社民党文化圈迅速发展；帝国政治也不得不长期面对一个不断壮大的反体制群众政党。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Sozialistengesetz；Deutsches Historisches Museum/LeMO: Innenpolitik；Encyclopaedia Britannica: German Empire。"}],"relationItems":["← 前因：德国反社会党人法","← 前因：德国俾斯麦社会保险立法","→ 后果：德国社会民主党（SPD）","→ 后果：德国社民党《爱尔福特纲领》","↔ 相关：德国自由工会总委员会"],"relations":[{"text":"← 前因：德国反社会党人法","id":"extra627"},{"text":"← 前因：德国俾斯麦社会保险立法","id":"extra629"},{"text":"→ 后果：德国社会民主党（SPD）","id":"extra628"},{"text":"→ 后果：德国社民党《爱尔福特纲领》","id":"extra696"},{"text":"↔ 相关：德国自由工会总委员会","id":"extra739"}],"source":"history","id":"extra762"},{"title":"利奥·冯·卡普里维","level":"B","type":"人物卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1831—1899年；1890—1894年任德意志帝国首相","place":"德意志帝国","summary":"卡普里维是俾斯麦继任者，试图用“新路线”缓和国内冲突、扩大贸易，却同时激怒农业保守派和宫廷势力。","fields":[{"label":"标题","value":"利奥·冯·卡普里维"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1831—1899年；1890—1894年任德意志帝国首相"},{"label":"地点","value":"德意志帝国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"卡普里维是俾斯麦继任者，试图用“新路线”缓和国内冲突、扩大贸易，却同时激怒农业保守派和宫廷势力。"},{"label":"生卒年/活跃年代","value":"1831年2月24日—1899年2月6日；1890—1894年任首相。"},{"label":"身份/职务","value":"普鲁士军人、德意志帝国首相、普鲁士首相。"},{"label":"关键贡献/作为","value":"接替俾斯麦后不再延长反社会党人法，推动工人保护立法和商业条约，签署或执行黑尔戈兰-桑给巴尔条约，并处理1893年陆军法案危机。"},{"label":"核心主张/立场","value":"主张在不改变帝国基本权力结构的前提下，用社会改革、贸易开放和同英国改善关系来缓和俾斯麦时代积累的冲突。"},{"label":"为什么重要","value":"他代表后俾斯麦时代第一次路线调整。卡普里维的失败说明帝国同时面对工业出口、农业保护、工人政治和皇帝个人统治，任何温和调和都很难稳定各方。"},{"label":"争议/评价","value":"农业者和保守派指责他牺牲农业利益，自由派又认为改革有限。1894年他因防止颠覆法案等问题失去皇帝信任并下台。"},{"label":"关联事件（可选）","value":"德国卡普里维“新路线”；《黑尔戈兰-桑给巴尔条约》；德国1891年工人保护法；1893年德国陆军法案与国会选举。"},{"label":"出处","value":"Encyclopaedia Britannica: Leo, count von Caprivi；Deutsches Historisches Museum/LeMO: Leo von Caprivi；Encyclopaedia Britannica: German Empire。"}],"relationItems":["← 前因：俾斯麦辞去德意志帝国首相","→ 后果：德国卡普里维“新路线”","→ 后果：德国农业者同盟","↔ 相关：《黑尔戈兰-桑给巴尔条约》"],"relations":[{"text":"← 前因：俾斯麦辞去德意志帝国首相","id":"extra633"},{"text":"→ 后果：德国卡普里维“新路线”","id":"extra764"},{"text":"→ 后果：德国农业者同盟","id":"extra768"},{"text":"↔ 相关：《黑尔戈兰-桑给巴尔条约》","id":"extra765"}],"source":"history","id":"extra763"},{"title":"德国卡普里维“新路线”","level":"B","type":"概念/思潮卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1890—1894年","place":"德意志帝国","summary":"卡普里维“新路线”试图在后俾斯麦时代缓和阶级冲突、扩大出口贸易，并重新组合帝国政治支持。","fields":[{"label":"标题","value":"德国卡普里维“新路线”"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1890—1894年"},{"label":"地点","value":"德意志帝国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"卡普里维“新路线”试图在后俾斯麦时代缓和阶级冲突、扩大出口贸易，并重新组合帝国政治支持。"},{"label":"核心主张/思路","value":"放弃俾斯麦晚期以非常法压制社会民主主义的路线，转向有限社会改革、工人保护、贸易条约和同部分自由派、中央党合作。"},{"label":"提出者/代表人物（可选）","value":"威廉二世初期和首相利奥·冯·卡普里维；“新路线”常用于概括卡普里维时期的政策尝试。"},{"label":"它从何而来","value":"俾斯麦下台后，帝国需要处理反社会党人法失败、工业出口需求、农业保护主义和皇帝亲政带来的新政治局面。"},{"label":"典型表现","value":"反社会党人法不再延长；1891年工人保护法；1891—1893年商业条约；尝试同英国改善关系；同时维持军备和君主制基本结构。"},{"label":"为什么重要","value":"它说明威廉时代并非一开始就只有高压和扩张，也曾尝试有限调和。但这种调和很快被农业者反弹、军备需求、皇帝不稳定干预和对社民党的恐惧压垮。"},{"label":"争议/局限","value":"新路线没有触动普鲁士三级选举制和帝国责任内阁缺失等根本结构，也没有真正整合SPD。它更像短暂政策调整，而非民主化转型。"},{"label":"出处","value":"Encyclopaedia Britannica: German Empire, Bismarck’s successors；Deutsches Historisches Museum/LeMO: Innenpolitik；Deutsches Historisches Museum/LeMO: Leo von Caprivi。"}],"relationItems":["← 前因：俾斯麦辞去德意志帝国首相","← 前因：德国反社会党人法失效","→ 后果：德国农业者同盟","→ 后果：德国防止颠覆法案尝试","↔ 相关：利奥·冯·卡普里维"],"relations":[{"text":"← 前因：俾斯麦辞去德意志帝国首相","id":"extra633"},{"text":"← 前因：德国反社会党人法失效","id":"extra762"},{"text":"→ 后果：德国农业者同盟","id":"extra768"},{"text":"→ 后果：德国防止颠覆法案尝试","id":"extra770"},{"text":"↔ 相关：利奥·冯·卡普里维","id":"extra763"}],"source":"history","id":"extra764"},{"title":"《黑尔戈兰-桑给巴尔条约》","level":"B","type":"制度/文本卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1890年7月1日","place":"伦敦、柏林；北海与东非殖民地","summary":"英德通过条约划分东非势力范围，德国取得黑尔戈兰岛并获得卡普里维地带，英国确认其在桑给巴尔的优势。","fields":[{"label":"标题","value":"《黑尔戈兰-桑给巴尔条约》"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1890年7月1日"},{"label":"地点","value":"伦敦、柏林；北海与东非殖民地"},{"label":"主要国家","value":"德国、英国、桑给巴尔、德属西南非洲相关地区"},{"label":"一句话概括","value":"英德通过条约划分东非势力范围，德国取得黑尔戈兰岛并获得卡普里维地带，英国确认其在桑给巴尔的优势。"},{"label":"制定方/签署方","value":"德意志帝国与大英帝国。"},{"label":"主要内容","value":"英国把北海的黑尔戈兰岛让给德国；德国承认英国在桑给巴尔的保护权和若干东非利益；英国承认德国在东非大陆的势力范围，并使德属西南非洲获得通向赞比西河方向的卡普里维地带。"},{"label":"它试图解决什么问题","value":"英德在东非和殖民地边界上存在重叠争议，卡普里维也希望通过让步改善英德关系，并获得对德国海军和北海防御有战略意义的黑尔戈兰。"},{"label":"为什么重要","value":"它是后俾斯麦外交中试图拉近英国的代表性安排。条约暂时缓和殖民争端，但没有形成英德同盟，后来德国海军扩张反而使黑尔戈兰的战略意义更突出。"},{"label":"争议/局限","value":"常见说法把它简化成“用桑给巴尔换黑尔戈兰”，但德国并不拥有桑给巴尔主权；条约实际是复杂的殖民势力范围和边界安排。"},{"label":"造成的影响","value":"德国获得北海前沿据点和卡普里维地带，英国巩固桑给巴尔地位；英德关系短期缓和，但长期仍因海军和殖民竞争恶化。"},{"label":"出处","value":"Encyclopaedia Britannica: Zanzibar Treaty；German History in Documents and Images: Anglo-German Treaty [Heligoland-Zanzibar Treaty]；UK Parliament Treaty Series: Agreement respecting Zanzibar, Heligoland, and spheres of influence in Africa。"}],"relationItems":["← 前因：德国卡普里维“新路线”","← 前因：德意志殖民帝国","→ 后果：德意志帝国海军扩张","↔ 相关：德意志帝国世界政策","↔ 相关：德属西南非洲赫雷罗和纳马种族灭绝"],"relations":[{"text":"← 前因：德国卡普里维“新路线”","id":"extra764"},{"text":"← 前因：德意志殖民帝国","id":"extra641"},{"text":"→ 后果：德意志帝国海军扩张","id":"extra636"},{"text":"↔ 相关：德意志帝国世界政策","id":"extra635"},{"text":"↔ 相关：德属西南非洲赫雷罗和纳马种族灭绝","id":"extra642"}],"source":"history","id":"extra765"},{"title":"德国1891年工人保护法","level":"B","type":"制度/文本卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1891年6月1日","place":"德意志帝国","summary":"1891年工人保护法限制妇女、儿童和星期日劳动，是卡普里维新路线中以社会改革缓和阶级冲突的代表措施。","fields":[{"label":"标题","value":"德国1891年工人保护法"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1891年6月1日"},{"label":"地点","value":"德意志帝国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1891年工人保护法限制妇女、儿童和星期日劳动，是卡普里维新路线中以社会改革缓和阶级冲突的代表措施。"},{"label":"制定方/签署方","value":"德意志帝国政府、帝国议会、联邦参议院。"},{"label":"主要内容","value":"作为《营业条例》的修正，法律加强对工厂劳动的保护，限制妇女和未成年人的工作时间，强化星期日休息，扩大国家对劳动条件的监管权。"},{"label":"它试图解决什么问题","value":"工业化加剧长工时、童工、妇女夜工和事故风险，反社会党人法失效后，帝国政府希望用有限社会改革争取工人阶级并削弱社会民主主义吸引力。"},{"label":"为什么重要","value":"它把俾斯麦社会保险以外的劳动保护纳入帝国立法，显示德国社会政策不只关注事故和保险，也开始规范工作时间和劳动条件。"},{"label":"争议/局限","value":"法律重点保护妇女和儿童，成年男性工时仍缺乏普遍上限；它改善部分劳动条件，但并未改变工人缺乏政治权力和企业控制劳动过程的结构。"},{"label":"造成的影响","value":"劳动保护成为帝国社会政策的固定议题，也为后来更系统的劳动法和工厂检查制度提供基础。"},{"label":"出处","value":"ZAAR/LMU: Arbeiterschutzgesetz vom 1.6.1891；Quellensammlung zur Geschichte der deutschen Sozialpolitik, Arbeiterschutz；Encyclopaedia Britannica: German Empire。"}],"relationItems":["← 前因：德国反社会党人法失效","← 前因：德国卡普里维“新路线”","↔ 相关：德国俾斯麦社会保险立法","↔ 相关：德国自由工会总委员会","→ 后果：德国社会民主党（SPD）"],"relations":[{"text":"← 前因：德国反社会党人法失效","id":"extra762"},{"text":"← 前因：德国卡普里维“新路线”","id":"extra764"},{"text":"↔ 相关：德国俾斯麦社会保险立法","id":"extra629"},{"text":"↔ 相关：德国自由工会总委员会","id":"extra739"},{"text":"→ 后果：德国社会民主党（SPD）","id":"extra628"}],"source":"history","id":"extra766"},{"title":"卡普里维贸易条约","level":"B","type":"制度/文本卡","tags":["经济与社会","战争与外交"],"mainTag":"经济与社会","subTag":"战争与外交","timeText":"1891—1893年","place":"德意志帝国及中欧、东南欧贸易伙伴","summary":"卡普里维通过一系列商业条约降低部分关税、扩大工业出口，却激怒德国农业保护主义者。","fields":[{"label":"标题","value":"卡普里维贸易条约"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1891—1893年"},{"label":"地点","value":"德意志帝国及中欧、东南欧贸易伙伴"},{"label":"主要国家","value":"德国、奥匈帝国、意大利、瑞士、比利时、罗马尼亚、塞尔维亚、俄罗斯帝国"},{"label":"一句话概括","value":"卡普里维通过一系列商业条约降低部分关税、扩大工业出口，却激怒德国农业保护主义者。"},{"label":"制定方/签署方","value":"德意志帝国政府与奥匈、意大利、瑞士、比利时、罗马尼亚、塞尔维亚、俄罗斯等国。"},{"label":"主要内容","value":"德国同多个欧洲国家缔结长期商业条约，用降低部分农产品和商品关税换取对德国工业品出口更有利的市场准入。"},{"label":"它试图解决什么问题","value":"德国工业化后越来越依赖出口市场，法国、俄国、美国等地保护主义上升使德国需要通过双边条约稳定外部市场。"},{"label":"为什么重要","value":"它把德国经济利益从俾斯麦式保护主义向工业出口导向拉了一步，是工业资产阶级和农业保护派分裂的重要节点。"},{"label":"争议/局限","value":"农业者认为低粮价和降低谷物关税损害地主与农民利益，卡普里维因此遭到保守农业集团猛烈攻击。"},{"label":"造成的影响","value":"贸易条约推动德国出口经济，但也促成农业者同盟兴起，并为1902年保护主义关税反弹埋下伏笔。"},{"label":"出处","value":"Encyclopaedia Britannica: Leo, count von Caprivi；Encyclopaedia Britannica: German Empire, Bismarck’s successors；JSTOR: The Challenges of Globalization: Economy and Politics in Germany, 1860-1914。"}],"relationItems":["← 前因：德国卡普里维“新路线”","← 前因：德意志帝国保护关税政策","→ 后果：德国农业者同盟","↔ 相关：德国铁与黑麦联盟","↔ 相关：德国鲁尔工业区"],"relations":[{"text":"← 前因：德国卡普里维“新路线”","id":"extra764"},{"text":"← 前因：德意志帝国保护关税政策","id":"extra630"},{"text":"→ 后果：德国农业者同盟","id":"extra768"},{"text":"↔ 相关：德国铁与黑麦联盟","id":"extra756"},{"text":"↔ 相关：德国鲁尔工业区","id":"extra679"}],"source":"history","id":"extra767"},{"title":"德国农业者同盟","level":"B","type":"组织/机构卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1893—1921年","place":"德意志帝国，尤其是普鲁士和农业地区","summary":"农业者同盟是帝国时期强大的农业压力集团，反对自由贸易和低粮价，推动保守政治向群众动员转型。","fields":[{"label":"标题","value":"德国农业者同盟"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1893—1921年"},{"label":"地点","value":"德意志帝国，尤其是普鲁士和农业地区"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"农业者同盟是帝国时期强大的农业压力集团，反对自由贸易和低粮价，推动保守政治向群众动员转型。"},{"label":"性质/类型","value":"农业利益集团、院外压力组织、保守政治动员网络。"},{"label":"成立/解散时间","value":"1893年成立；1921年并入后来的帝国农业联盟体系。"},{"label":"核心目标/宗旨","value":"维护农业保护关税、争取农民和地主利益，反对被认为损害“真正德国”的自由主义、社会民主主义和犹太资本等对象。"},{"label":"关键人物（可选）","value":"奥托·冯·赫尔多夫、康拉德·冯·万根海姆等农业保守派活动家。"},{"label":"关键行动/事件","value":"反对卡普里维贸易条约，组织农村选民和舆论，影响德国保守党和帝国议会中的农业政策。"},{"label":"为什么重要","value":"它显示帝国政治已不只是贵族和官僚的上层协商，保守派也开始使用现代群众组织、宣传和压力政治。它也是理解德国右翼群众化的重要早期组织。"},{"label":"争议/局限","value":"农业者同盟常把经济保护诉求同民族主义和反犹主义结合，既代表农民和地主利益，也强化排外和反自由主义政治。"},{"label":"出处","value":"Encyclopaedia Britannica: Agrarian League；German History in Documents and Images: Program of the Agrarian League；Deutsche Digitale Bibliothek: Bund der Landwirte materials。"}],"relationItems":["← 前因：卡普里维贸易条约","← 前因：德国铁与黑麦联盟","→ 后果：德国1902年保护主义关税","↔ 相关：普鲁士容克地主","↔ 相关：反犹主义政治运动"],"relations":[{"text":"← 前因：卡普里维贸易条约","id":"extra767"},{"text":"← 前因：德国铁与黑麦联盟","id":"extra756"},{"text":"→ 后果：德国1902年保护主义关税","id":"extra780"},{"text":"↔ 相关：普鲁士容克地主","id":"extra672"},{"text":"↔ 相关：反犹主义政治运动","id":"extra686"}],"source":"history","id":"extra768"},{"title":"1893年德国陆军法案与国会选举","level":"C","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1893年","place":"德意志帝国；柏林","summary":"卡普里维的陆军扩张法案被国会拒绝后触发选举，新国会最终批准军备扩张，显示帝国议会权力有限。","fields":[{"label":"标题","value":"1893年德国陆军法案与国会选举"},{"label":"分级","value":"C"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1893年"},{"label":"地点","value":"德意志帝国；柏林"},{"label":"主要国家","value":"德国、俄罗斯帝国、法国"},{"label":"一句话概括","value":"卡普里维的陆军扩张法案被国会拒绝后触发选举，新国会最终批准军备扩张，显示帝国议会权力有限。"},{"label":"参与者","value":"利奥·冯·卡普里维、威廉二世、帝国议会、德国社会民主党、中央党、自由思想派、保守派。"},{"label":"发生了什么","value":"1893年前后，德国因法俄接近和两线战争风险而要求扩大和平时期陆军规模。卡普里维向帝国议会提出陆军法案，但社会民主党、中央党部分议员和自由派反对增加军费与兵役负担，法案起初未获通过。政府解散国会并重新选举，新议会在政治组合变化后批准陆军经费和扩军安排。"},{"label":"为什么重要","value":"它说明帝国议会能制造危机，却很难长期阻止军备扩张。军事预算仍是君主制帝国中政府、军方和议会之间最敏感的权力接口。"},{"label":"前因","value":"德俄再保险条约未续约后，法俄接近使德国两线战争焦虑上升；总参谋部和皇帝都要求扩大军队以应对潜在安全压力。"},{"label":"后果","value":"陆军法案通过加强了德国军备基础，也强化了政府通过解散国会和选举重组多数来处理军事问题的惯例。"},{"label":"出处","value":"Encyclopaedia Britannica: German Empire, Bismarck’s successors；Deutsches Historisches Museum/LeMO: Freisinnige Vereinigung；Encyclopaedia Britannica: History of Germany, Germany from 1871 to 1918。"}],"relationItems":["← 前因：德俄再保险条约","← 前因：德国卡普里维“新路线”","→ 后果：德国施里芬计划","↔ 相关：德意志帝国议会","↔ 相关：德国社会民主党（SPD）"],"relations":[{"text":"← 前因：德俄再保险条约","id":"extra632"},{"text":"← 前因：德国卡普里维“新路线”","id":"extra764"},{"text":"→ 后果：德国施里芬计划","id":"extra643"},{"text":"↔ 相关：德意志帝国议会","id":"extra669"},{"text":"↔ 相关：德国社会民主党（SPD）","id":"extra628"}],"source":"history","id":"extra769"},{"title":"德国防止颠覆法案尝试","level":"C","type":"制度/文本卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1894—1895年","place":"德意志帝国","summary":"防止颠覆法案试图用刑法和新闻管制打击社会民主主义，但在国会失败，暴露新路线后退与议会阻力。","fields":[{"label":"标题","value":"德国防止颠覆法案尝试"},{"label":"分级","value":"C"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1894—1895年"},{"label":"地点","value":"德意志帝国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"防止颠覆法案试图用刑法和新闻管制打击社会民主主义，但在国会失败，暴露新路线后退与议会阻力。"},{"label":"制定方/签署方","value":"霍恩洛厄政府向帝国议会提出；构想与威廉二世、普鲁士保守派和反社民党力量相关。"},{"label":"主要内容","value":"法案拟修改刑法、军事刑法和新闻法，以惩治被认为煽动暴力颠覆国家和社会秩序的言论与组织活动。实际目标主要指向社会民主主义和激进反体制宣传。"},{"label":"它试图解决什么问题","value":"反社会党人法失效后，SPD继续壮大，皇帝和保守派希望重新获得法律工具来限制社会主义政治动员。"},{"label":"为什么重要","value":"它显示卡普里维新路线很快被反社民党高压诉求反噬。即便法案失败，政府和右翼对社会民主主义的恐惧仍持续塑造威廉时代内政。"},{"label":"争议/局限","value":"法案把政治反对与暴力颠覆混同，威胁言论和出版自由；帝国议会拒绝通过也说明1878式非常法已经难以原样恢复。"},{"label":"造成的影响","value":"法案失败削弱政府威信，也推动威廉时代转向“集合政策”，即试图联合保守派、民族自由派和利益集团共同压制社民党。"},{"label":"出处","value":"Encyclopaedia Britannica: Leo, count von Caprivi；Central European History: The Anti-Revolution Bill of 1894 in Wilhelmine Germany；Zeitklicks: Scheitern der Umsturzvorlage gegen die SPD。"}],"relationItems":["← 前因：德国反社会党人法失效","← 前因：德国卡普里维“新路线”","→ 后果：德意志帝国集合政策","↔ 相关：德国社会民主党（SPD）","↔ 相关：克洛德维希·霍恩洛厄"],"relations":[{"text":"← 前因：德国反社会党人法失效","id":"extra762"},{"text":"← 前因：德国卡普里维“新路线”","id":"extra764"},{"text":"→ 后果：德意志帝国集合政策","id":"extra779"},{"text":"↔ 相关：德国社会民主党（SPD）","id":"extra628"},{"text":"↔ 相关：克洛德维希·霍恩洛厄","id":"extra771"}],"source":"history","id":"extra770"},{"title":"克洛德维希·霍恩洛厄","level":"C","type":"人物卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1819—1901年；1894—1900年任德意志帝国首相","place":"德意志帝国；巴伐利亚、阿尔萨斯-洛林、柏林","summary":"霍恩洛厄是卡普里维之后的过渡型首相，任内德国向世界政策和海军扩张进一步转向。","fields":[{"label":"标题","value":"克洛德维希·霍恩洛厄"},{"label":"分级","value":"C"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1819—1901年；1894—1900年任德意志帝国首相"},{"label":"地点","value":"德意志帝国；巴伐利亚、阿尔萨斯-洛林、柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"霍恩洛厄是卡普里维之后的过渡型首相，任内德国向世界政策和海军扩张进一步转向。"},{"label":"生卒年/活跃年代","value":"1819年3月31日—1901年7月6日；1894—1900年任帝国首相。"},{"label":"身份/职务","value":"巴伐利亚贵族政治家、前巴伐利亚首相、阿尔萨斯-洛林总督、德意志帝国首相。"},{"label":"关键贡献/作为","value":"接替卡普里维后处理防止颠覆法案、对社民党压力、海军扩张和殖民外交等问题；任内提尔皮茨和比洛影响力上升。"},{"label":"核心主张/立场","value":"总体上是温和保守和行政调停型人物，倾向维持帝国既有权力结构，而不是主动推动根本改革。"},{"label":"为什么重要","value":"他的首相任期说明威廉时代权力逐渐从强势首相转向皇帝、宫廷、外交官和部门官僚共同塑造政策。海军法和世界政策在他任内走向制度化。"},{"label":"争议/评价","value":"霍恩洛厄常被评价为过渡性或较弱首相，难以制衡威廉二世和比洛、提尔皮茨等更积极的政策推动者。"},{"label":"关联事件（可选）","value":"德国防止颠覆法案尝试；德国第一次海军法；德国强租胶州湾。"},{"label":"出处","value":"Encyclopaedia Britannica: Chlodwig Karl Viktor, prince of Hohenlohe-Schillingsfürst；Encyclopaedia Britannica: German Empire, Bismarck’s successors；Central European History: Government by Procrastination。"}],"relationItems":["← 前因：利奥·冯·卡普里维","→ 后果：德国第一次海军法","→ 后果：德国强租胶州湾","↔ 相关：德国威廉二世亲政","↔ 相关：阿尔弗雷德·冯·提尔皮茨"],"relations":[{"text":"← 前因：利奥·冯·卡普里维","id":"extra763"},{"text":"→ 后果：德国第一次海军法","id":"extra774"},{"text":"→ 后果：德国强租胶州湾","id":"extra773"},{"text":"↔ 相关：德国威廉二世亲政","id":"extra634"},{"text":"↔ 相关：阿尔弗雷德·冯·提尔皮茨","id":"extra776"}],"source":"history","id":"extra771"},{"title":"弗里德里希·冯·霍尔施泰因","level":"C","type":"人物卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1837—1909年；1890—1909年外交影响力突出","place":"柏林；德国外交部","summary":"霍尔施泰因是后俾斯麦时代德国外交部幕后关键人物，影响再保险条约不续约、世界政策和复杂同盟判断。","fields":[{"label":"标题","value":"弗里德里希·冯·霍尔施泰因"},{"label":"分级","value":"C"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1837—1909年；1890—1909年外交影响力突出"},{"label":"地点","value":"柏林；德国外交部"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"霍尔施泰因是后俾斯麦时代德国外交部幕后关键人物，影响再保险条约不续约、世界政策和复杂同盟判断。"},{"label":"生卒年/活跃年代","value":"1837年4月24日—1909年5月8日；1890年后影响力尤其突出。"},{"label":"身份/职务","value":"德意志帝国外交官、外交部高级官员和政策顾问。"},{"label":"关键贡献/作为","value":"在俾斯麦下台后成为德国外交部重要幕后顾问，影响卡普里维、霍恩洛厄和比洛时期的外交判断。"},{"label":"核心主张/立场","value":"反对俾斯麦式对俄再保险安排，倾向以1879年德奥同盟为基础处理欧洲外交，并试图利用列强殖民矛盾为德国争取空间。"},{"label":"为什么重要","value":"他不是公众政治家，却体现威廉时代外交的“幕后官僚化”。理解德国外交从俾斯麦平衡术走向更冒险、更不稳定的路线，不能只看皇帝个人。"},{"label":"争议/评价","value":"霍尔施泰因影响力大但责任不透明，常被批评为推动德国放弃对俄缓冲、误判英国和殖民外交局势。"},{"label":"关联事件（可选）","value":"德俄再保险条约未续约；德意志帝国世界政策；第一次摩洛哥危机。"},{"label":"出处","value":"Encyclopaedia Britannica: Friedrich von Holstein；Encyclopaedia Britannica: German Empire, Bismarck’s successors；A. J. P. Taylor, The Struggle for Mastery in Europe, 1848-1918。"}],"relationItems":["← 前因：俾斯麦辞去德意志帝国首相","→ 后果：第一次摩洛哥危机","↔ 相关：德俄再保险条约","↔ 相关：德意志帝国世界政策","↔ 相关：德国威廉二世亲政"],"relations":[{"text":"← 前因：俾斯麦辞去德意志帝国首相","id":"extra633"},{"text":"→ 后果：第一次摩洛哥危机","id":"extra638"},{"text":"↔ 相关：德俄再保险条约","id":"extra632"},{"text":"↔ 相关：德意志帝国世界政策","id":"extra635"},{"text":"↔ 相关：德国威廉二世亲政","id":"extra634"}],"source":"history","id":"extra772"},{"title":"德国强租胶州湾","level":"B","type":"事件卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1897—1898年","place":"中国山东胶州湾、青岛","summary":"德国以传教士遇害为借口占领胶州湾，并迫使清政府租借99年，取得青岛基地和山东权益。","fields":[{"label":"标题","value":"德国强租胶州湾"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1897—1898年"},{"label":"地点","value":"中国山东胶州湾、青岛"},{"label":"主要国家","value":"德国、中国"},{"label":"一句话概括","value":"德国以传教士遇害为借口占领胶州湾，并迫使清政府租借99年，取得青岛基地和山东权益。"},{"label":"参与者","value":"德意志帝国政府、德国东亚舰队、清政府、山东地方社会、德国传教团体。"},{"label":"发生了什么","value":"1897年山东发生巨野教案，两名德国传教士遇害。德国政府以此为借口派舰队占领胶州湾。1898年，清政府被迫同意德国租借胶州湾地区99年，并给予德国在山东修筑铁路、开采矿产和建设青岛港的权利。德国把青岛建设为东亚海军和商业据点，胶州湾成为德国海外帝国在中国的核心基地。"},{"label":"为什么重要","value":"这是德意志帝国世界政策在东亚的标志性扩张，也把德国纳入列强在中国划分势力范围的竞赛。后来日本在一战中夺取青岛，并引出一战后巴黎和会山东问题。"},{"label":"前因","value":"德国在殖民竞争中起步较晚，威廉时代希望获得海外基地和远东市场；巨野教案给德国提供了以保护传教士为名采取军事行动的借口。"},{"label":"后果","value":"德国在山东取得港口、铁路和矿业权益，青岛成为德国东亚基地；一战爆发后日本攻占青岛，山东问题又成为中国五四运动的重要导火索。"},{"label":"出处","value":"Encyclopaedia Britannica: Qingdao；Office of the Historian: FRUS 1900 Kiaochow document；Deutsches Historisches Museum: Tsingtao - A Chapter of German Colonial History in China。"}],"relationItems":["← 前因：德意志帝国世界政策","← 前因：德意志殖民帝国","→ 后果：一战日英攻占青岛战役","→ 后果：巴黎和会山东问题","↔ 相关：1884—1885年柏林西非会议"],"relations":[{"text":"← 前因：德意志帝国世界政策","id":"extra635"},{"text":"← 前因：德意志殖民帝国","id":"extra641"},{"text":"→ 后果：一战日英攻占青岛战役","id":"extra703"},{"text":"→ 后果：巴黎和会山东问题","id":"card206"},{"text":"↔ 相关：1884—1885年柏林西非会议","id":"extra760"}],"source":"history","id":"extra773"},{"title":"德国第一次海军法","level":"B","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1898年","place":"德意志帝国；柏林","summary":"1898年第一次海军法把德国海军扩张制度化，使提尔皮茨的大战列舰计划获得长期财政和法律基础。","fields":[{"label":"标题","value":"德国第一次海军法"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1898年"},{"label":"地点","value":"德意志帝国；柏林"},{"label":"主要国家","value":"德国、英国"},{"label":"一句话概括","value":"1898年第一次海军法把德国海军扩张制度化，使提尔皮茨的大战列舰计划获得长期财政和法律基础。"},{"label":"制定方/签署方","value":"德意志帝国政府、帝国海军部、帝国议会、联邦参议院；关键推动者为阿尔弗雷德·冯·提尔皮茨。"},{"label":"主要内容","value":"法律规定建设和维持一定规模的战列舰、巡洋舰等舰队力量，用多年计划方式锁定海军建设，减少每年预算谈判的不确定性。"},{"label":"它试图解决什么问题","value":"德意志帝国世界政策需要远洋舰队支撑，提尔皮茨则希望用法律把海军扩张变成长期国家项目，而不是每年受制于国会预算争议。"},{"label":"为什么重要","value":"它是英德海军竞赛的制度起点之一。德国海军扩张从口号变成持续造舰计划，英国开始更认真地把德国视为海上挑战者。"},{"label":"争议/局限","value":"德国海军扩张消耗巨大，却无法真正追平英国；它试图通过“风险舰队”威慑英国，实际效果却是刺激英国寻求外交伙伴。"},{"label":"造成的影响","value":"海军协会和民族主义宣传获得政策支点，1900年第二次海军法进一步扩大舰队规模，英德关系长期恶化。"},{"label":"出处","value":"Encyclopaedia Britannica: German Empire, Tirpitz and the German navy；Deutsches Historisches Museum/LeMO: Flottenbau；Deutsche Digitale Bibliothek: Flottengesetz von 1898。"}],"relationItems":["← 前因：德意志帝国世界政策","← 前因：德国强租胶州湾","→ 后果：德国第二次海军法","→ 后果：德意志帝国英德海军竞赛","↔ 相关：阿尔弗雷德·冯·提尔皮茨"],"relations":[{"text":"← 前因：德意志帝国世界政策","id":"extra635"},{"text":"← 前因：德国强租胶州湾","id":"extra773"},{"text":"→ 后果：德国第二次海军法","id":"extra775"},{"text":"→ 后果：德意志帝国英德海军竞赛","id":"extra637"},{"text":"↔ 相关：阿尔弗雷德·冯·提尔皮茨","id":"extra776"}],"source":"history","id":"extra774"},{"title":"德国第二次海军法","level":"B","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1900年","place":"德意志帝国；柏林","summary":"1900年第二次海军法大幅扩大德国舰队计划，把海军建设推向公开挑战英国海权的轨道。","fields":[{"label":"标题","value":"德国第二次海军法"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1900年"},{"label":"地点","value":"德意志帝国；柏林"},{"label":"主要国家","value":"德国、英国"},{"label":"一句话概括","value":"1900年第二次海军法大幅扩大德国舰队计划，把海军建设推向公开挑战英国海权的轨道。"},{"label":"制定方/签署方","value":"德意志帝国政府、帝国海军部、帝国议会、联邦参议院；关键推动者为提尔皮茨和威廉二世。"},{"label":"主要内容","value":"在1898年海军法基础上，1900年法案显著扩大舰队规模，目标是把德国海军建设成足以让最强海权国家在对德战争中承受不可接受风险的“风险舰队”。"},{"label":"它试图解决什么问题","value":"威廉时代德国认为世界政策和殖民、商业利益需要强大舰队保护；提尔皮茨则希望通过海军力量迫使英国尊重德国并考虑合作。"},{"label":"为什么重要","value":"第二次海军法把英德海军竞赛推到更高层级。它使英国更难把德国视为普通大陆强国，而是视为潜在海上对手。"},{"label":"争议/局限","value":"风险舰队理论假定英国会因成本过高而妥协，但英国选择扩军和外交结盟。德国因此花费巨资制造了一个无法带来安全的战略威胁。"},{"label":"造成的影响","value":"德国海军扩张成为英德关系恶化核心因素之一，后续无畏舰竞争和协约体系强化都与此有关。"},{"label":"出处","value":"Encyclopaedia Britannica: German Empire, Tirpitz and the German navy；Deutsches Historisches Museum/LeMO: Flottenbau；Deutsches Historisches Museum/LeMO: Flottenverein。"}],"relationItems":["← 前因：德国第一次海军法","→ 后果：德意志帝国英德海军竞赛","→ 后果：德意志帝国海军扩张","↔ 相关：德国海军协会","↔ 相关：阿尔弗雷德·冯·提尔皮茨"],"relations":[{"text":"← 前因：德国第一次海军法","id":"extra774"},{"text":"→ 后果：德意志帝国英德海军竞赛","id":"extra637"},{"text":"→ 后果：德意志帝国海军扩张","id":"extra636"},{"text":"↔ 相关：德国海军协会","id":"extra676"},{"text":"↔ 相关：阿尔弗雷德·冯·提尔皮茨","id":"extra776"}],"source":"history","id":"extra775"},{"title":"阿尔弗雷德·冯·提尔皮茨","level":"B","type":"人物卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1849—1930年；1897—1916年任帝国海军部国务秘书","place":"德意志帝国；柏林、德国海军基地","summary":"提尔皮茨是德国大舰队建设的核心设计者，用海军法和风险舰队理论推动英德海军竞赛升级。","fields":[{"label":"标题","value":"阿尔弗雷德·冯·提尔皮茨"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1849—1930年；1897—1916年任帝国海军部国务秘书"},{"label":"地点","value":"德意志帝国；柏林、德国海军基地"},{"label":"主要国家","value":"德国、英国"},{"label":"一句话概括","value":"提尔皮茨是德国大舰队建设的核心设计者，用海军法和风险舰队理论推动英德海军竞赛升级。"},{"label":"生卒年/活跃年代","value":"1849年3月19日—1930年3月6日；1897—1916年任帝国海军部国务秘书。"},{"label":"身份/职务","value":"德国海军军官、帝国海军部国务秘书、后来的海军元帅。"},{"label":"关键贡献/作为","value":"推动1898年和1900年海军法，建立长期造舰计划，组织海军宣传和政治游说，使德国海军建设成为威廉时代国家战略核心。"},{"label":"核心主张/立场","value":"主张德国必须拥有足够强大的战列舰舰队，让英国即使获胜也要付出危及海权地位的代价，从而迫使英国尊重或接近德国。"},{"label":"为什么重要","value":"他把世界政策从外交姿态转化为具体军备项目。英德海军竞赛不是抽象民族情绪，而是由提尔皮茨这类制度设计者通过法律、预算和宣传持续推动。"},{"label":"争议/评价","value":"提尔皮茨计划高估了英国妥协可能，低估了英国造舰能力和结盟反应。德国海军最终既未压倒英国，也加深了德国外交孤立。"},{"label":"关联事件（可选）","value":"德国第一次海军法；德国第二次海军法；英德海军竞赛；德国无限制潜艇战。"},{"label":"出处","value":"Encyclopaedia Britannica: German Empire, Tirpitz and the German navy；Deutsches Historisches Museum/LeMO: Flottenbau；German History in Documents and Images: Alfred von Tirpitz on Submarine Warfare against Great Britain。"}],"relationItems":["← 前因：德意志帝国世界政策","→ 后果：德国第一次海军法","→ 后果：德国第二次海军法","↔ 相关：德国海军协会","↔ 相关：德意志帝国英德海军竞赛"],"relations":[{"text":"← 前因：德意志帝国世界政策","id":"extra635"},{"text":"→ 后果：德国第一次海军法","id":"extra774"},{"text":"→ 后果：德国第二次海军法","id":"extra775"},{"text":"↔ 相关：德国海军协会","id":"extra676"},{"text":"↔ 相关：德意志帝国英德海军竞赛","id":"extra637"}],"source":"history","id":"extra776"},{"title":"八国联军干预义和团运动","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1900—1901年","place":"中国北方；天津、北京及直隶、山东等地","summary":"八国联军以解除使馆危机和镇压义和团为名出兵中国，最终迫使清政府签订《辛丑条约》。","fields":[{"label":"标题","value":"八国联军干预义和团运动"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1900—1901年"},{"label":"地点","value":"中国北方；天津、北京及直隶、山东等地"},{"label":"主要国家","value":"中国；日本；俄罗斯；英国；法国；美国；德国；奥匈帝国；意大利"},{"label":"一句话概括","value":"八国联军以解除使馆危机和镇压义和团为名出兵中国，最终迫使清政府签订《辛丑条约》。"},{"label":"参与者","value":"清政府、义和团、八国联军、各国驻华外交人员和军队、慈禧太后、李鸿章、阿尔弗雷德·冯·瓦德西等。"},{"label":"发生了什么","value":"义和团运动在华北兴起后，反教反洋暴力、列强军事行动和清政府态度摇摆共同导致危机升级。1900年，列强组成八国联军进入中国北方，攻占天津和北京，解除使馆区围困，并在占领期间进行惩罚性行动和掠夺。德国因驻华公使克林德被杀而要求严厉惩罚，瓦德西后来任联军统帅，但北京被攻占时他尚未抵达。"},{"label":"为什么重要","value":"这张卡的主角是中国危机和列强联合干预，不是德国单独行动。它体现晚清主权危机、帝国主义在华竞争、跨国军事干涉和不平等条约体系，对中国近代史和全球帝国主义史都很关键。"},{"label":"前因","value":"列强在华势力范围竞争、传教冲突、地方社会危机和反洋情绪推动义和团运动扩张；使馆被围和清廷对列强宣战使危机军事化。"},{"label":"后果","value":"1901年《辛丑条约》要求清政府赔款、惩办官员、允许外国驻兵并限制军事防务，进一步削弱清朝财政、主权和政治威信，也刺激晚清新政。"},{"label":"出处","value":"Encyclopaedia Britannica: Boxer Rebellion；German History in Documents and Images: The Hun Speech；Deutsches Historisches Museum/LeMO: Kolonialismus und Weltpolitik。"}],"relationItems":["← 前因：德国强租胶州湾","← 前因：德意志帝国世界政策","→ 后果：威廉二世《匈奴演说》","→ 后果：《辛丑条约》","↔ 相关：一战日英攻占青岛战役"],"relations":[{"text":"← 前因：德国强租胶州湾","id":"extra773"},{"text":"← 前因：德意志帝国世界政策","id":"extra635"},{"text":"→ 后果：威廉二世《匈奴演说》","id":"extra75"},{"text":"→ 后果：《辛丑条约》","id":"extra963"},{"text":"↔ 相关：一战日英攻占青岛战役","id":"extra703"}],"source":"history","id":"extra777"},{"title":"伯恩哈德·冯·比洛","level":"B","type":"人物卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1849—1929年；1900—1909年任德意志帝国首相","place":"德意志帝国；柏林","summary":"比洛是威廉时代世界政策和集合政策的关键首相，任内海军扩张、殖民政治和反社民党路线进一步制度化。","fields":[{"label":"标题","value":"伯恩哈德·冯·比洛"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1849—1929年；1900—1909年任德意志帝国首相"},{"label":"地点","value":"德意志帝国；柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"比洛是威廉时代世界政策和集合政策的关键首相，任内海军扩张、殖民政治和反社民党路线进一步制度化。"},{"label":"生卒年/活跃年代","value":"1849年5月3日—1929年10月28日；1897年任外交国务秘书，1900—1909年任帝国首相。"},{"label":"身份/职务","value":"德意志帝国外交官、外交国务秘书、帝国首相、普鲁士首相。"},{"label":"关键贡献/作为","value":"推动和包装德意志帝国世界政策，支持海军扩张；在内政上推进集合政策，试图联合保守派、民族自由派和利益集团对抗社会民主党。"},{"label":"核心主张/立场","value":"主张德国应取得世界强国地位，同时在国内以民族主义、军备和殖民议题凝聚非社会主义政治力量。"},{"label":"为什么重要","value":"比洛把威廉二世的世界地位欲望转化为更可操作的议会和舆论政治。他的首相任期连接了海军法、殖民危机、摩洛哥危机和1907年德意志帝国“霍屯督选举”。"},{"label":"争议/评价","value":"他擅长政治语言和宫廷平衡，却未能解决德国外交孤立和国内议会碎片化问题；威廉二世《每日电讯报》事件后其政治地位显著受损。"},{"label":"关联事件（可选）","value":"德意志帝国世界政策；德意志帝国集合政策；德意志帝国“霍屯督选举”；威廉二世《每日电讯报》事件。"},{"label":"出处","value":"Encyclopaedia Britannica: Bernhard, prince von Bülow；Deutsches Historisches Museum/LeMO: Bernhard von Bülow；Encyclopaedia Britannica: German Empire。"}],"relationItems":["← 前因：克洛德维希·霍恩洛厄","→ 后果：德意志帝国集合政策","→ 后果：德意志帝国“霍屯督选举”","↔ 相关：德意志帝国世界政策","↔ 相关：德国海军协会"],"relations":[{"text":"← 前因：克洛德维希·霍恩洛厄","id":"extra771"},{"text":"→ 后果：德意志帝国集合政策","id":"extra779"},{"text":"→ 后果：德意志帝国“霍屯督选举”","id":"extra689"},{"text":"↔ 相关：德意志帝国世界政策","id":"extra635"},{"text":"↔ 相关：德国海军协会","id":"extra676"}],"source":"history","id":"extra778"},{"title":"德意志帝国集合政策","level":"B","type":"概念/思潮卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1897—1909年尤为突出","place":"德意志帝国","summary":"集合政策试图把保守派、民族自由派、重工业和农业利益集团集合起来，以民族主义和反社会主义巩固帝国统治。","fields":[{"label":"标题","value":"德意志帝国集合政策"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1897—1909年尤为突出"},{"label":"地点","value":"德意志帝国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"集合政策试图把保守派、民族自由派、重工业和农业利益集团集合起来，以民族主义和反社会主义巩固帝国统治。"},{"label":"核心主张/思路","value":"用海军扩张、殖民政策、保护关税和反社民党立场，把不同非社会主义力量组成支持政府的议会与社会联盟。"},{"label":"提出者/代表人物（可选）","value":"常与比洛政府、威廉二世时代政治和保守民族主义利益集团相联系。"},{"label":"它从何而来","value":"反社会党人法失效后SPD持续壮大，卡普里维新路线又激怒农业保守派，帝国政府需要新的政治整合方式来维持多数和压制社会主义。"},{"label":"典型表现","value":"支持海军法、保护主义关税和殖民扩张；借助海军协会、农业者同盟等组织动员舆论；1907年德意志帝国“霍屯督选举”是集合政策的典型时刻。"},{"label":"为什么重要","value":"它解释威廉时代内政和外交为何绑在一起。海军、殖民和民族主义不只是对外政策，也被用来重组国内政治联盟。"},{"label":"争议/局限","value":"集合政策能短期压制社民党，却无法吸收工人阶级和解决宪政问题；它还把民族主义和利益集团政治推得更深。"},{"label":"出处","value":"Encyclopaedia Britannica: German Empire；Deutsches Historisches Museum/LeMO: Innenpolitik im Kaiserreich；Hans-Ulrich Wehler, The German Empire, 1871-1918。"}],"relationItems":["← 前因：德国防止颠覆法案尝试","← 前因：德国农业者同盟","→ 后果：德意志帝国“霍屯督选举”","→ 后果：德国1912年国会选举","↔ 相关：伯恩哈德·冯·比洛"],"relations":[{"text":"← 前因：德国防止颠覆法案尝试","id":"extra770"},{"text":"← 前因：德国农业者同盟","id":"extra768"},{"text":"→ 后果：德意志帝国“霍屯督选举”","id":"extra689"},{"text":"→ 后果：德国1912年国会选举","id":"extra789"},{"text":"↔ 相关：伯恩哈德·冯·比洛","id":"extra778"}],"source":"history","id":"extra779"},{"title":"德国1902年保护主义关税","level":"B","type":"制度/文本卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1902年通过，1906年起全面生效","place":"德意志帝国","summary":"1902年关税提高农产品保护水平，标志卡普里维贸易开放路线退潮和农业保守派反弹成功。","fields":[{"label":"标题","value":"德国1902年保护主义关税"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1902年通过，1906年起全面生效"},{"label":"地点","value":"德意志帝国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1902年关税提高农产品保护水平，标志卡普里维贸易开放路线退潮和农业保守派反弹成功。"},{"label":"制定方/签署方","value":"比洛政府、帝国议会、联邦参议院。"},{"label":"主要内容","value":"新关税提高谷物等农产品最低关税，同时维护部分工业保护，试图在农业者同盟、容克地主和工业利益之间重建政治平衡。"},{"label":"它试图解决什么问题","value":"卡普里维贸易条约降低谷物关税后，农业者同盟和保守派认为德国农业利益受损。政府需要重新争取农业保守派支持，并为集合政策打造利益基础。"},{"label":"为什么重要","value":"它说明德国经济政策在工业出口和农业保护之间摇摆。1902年关税是“铁与黑麦”联盟在威廉时代的延续和重组。"},{"label":"争议/局限","value":"高粮食关税保护农业收入，却可能提高城市工人生活成本，加深工人阶级对帝国保守政策的不满。"},{"label":"造成的影响","value":"农业者同盟影响力增强，集合政策的经济基础更稳；德国贸易政策也更难回到卡普里维式开放路线。"},{"label":"出处","value":"Encyclopaedia Britannica: German Empire；JSTOR: The Challenges of Globalization: Economy and Politics in Germany, 1860-1914；Hans-Ulrich Wehler, The German Empire, 1871-1918。"}],"relationItems":["← 前因：卡普里维贸易条约","← 前因：德国农业者同盟","→ 后果：德意志帝国集合政策","↔ 相关：德意志帝国保护关税政策","↔ 相关：德国铁与黑麦联盟"],"relations":[{"text":"← 前因：卡普里维贸易条约","id":"extra767"},{"text":"← 前因：德国农业者同盟","id":"extra768"},{"text":"→ 后果：德意志帝国集合政策","id":"extra779"},{"text":"↔ 相关：德意志帝国保护关税政策","id":"extra630"},{"text":"↔ 相关：德国铁与黑麦联盟","id":"extra756"}],"source":"history","id":"extra780"},{"title":"英德同盟谈判失败","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1898—1901年","place":"伦敦、柏林及欧洲外交体系","summary":"世纪之交英德多次试探同盟可能，但因利益预期、殖民问题和德国海军扩张而未能形成战略合作。","fields":[{"label":"标题","value":"英德同盟谈判失败"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1898—1901年"},{"label":"地点","value":"伦敦、柏林及欧洲外交体系"},{"label":"主要国家","value":"英国、德国"},{"label":"一句话概括","value":"世纪之交英德多次试探同盟可能，但因利益预期、殖民问题和德国海军扩张而未能形成战略合作。"},{"label":"参与者","value":"英国索尔兹伯里政府、约瑟夫·张伯伦、德皇威廉二世、比洛、德国外交部。"},{"label":"发生了什么","value":"1898年至1901年前后，英国在布尔战争和全球帝国压力下考虑过与德国改善关系，德国也希望通过谈判提高自身外交身价。双方就殖民、欧洲安全和可能的政治合作进行接触，但德国希望英国作出更明确同盟承诺，英国则不愿无条件卷入德国大陆风险。与此同时德国海军法让英国越来越怀疑德国意图，谈判最终无果。"},{"label":"为什么重要","value":"谈判失败不是一个单一条约的失败，而是德国错失同英国建立稳定关系的关键窗口。此后英国逐渐转向同法国、俄国缓和矛盾。"},{"label":"前因","value":"德意志帝国世界政策希望提高德国全球地位，英国也因殖民压力和欧洲不确定性考虑调整“光荣孤立”，两国一度存在相互试探空间。"},{"label":"后果","value":"英德没有形成同盟，德国海军扩张继续刺激英国；英国随后与法国、俄国达成协约，德国的外交孤立感进一步加深。"},{"label":"出处","value":"Encyclopaedia Britannica: German Empire；Encyclopaedia Britannica: 20th-century international relations；A. J. P. Taylor, The Struggle for Mastery in Europe, 1848-1918。"}],"relationItems":["← 前因：德意志帝国世界政策","← 前因：德国第一次海军法","→ 后果：1904年英法协约","→ 后果：1907年英俄协约","↔ 相关：德意志帝国英德海军竞赛"],"relations":[{"text":"← 前因：德意志帝国世界政策","id":"extra635"},{"text":"← 前因：德国第一次海军法","id":"extra774"},{"text":"→ 后果：1904年英法协约","id":"extra782"},{"text":"→ 后果：1907年英俄协约","id":"extra785"},{"text":"↔ 相关：德意志帝国英德海军竞赛","id":"extra637"}],"source":"history","id":"extra781"},{"title":"1904年英法协约","level":"B","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1904年4月8日","place":"伦敦、巴黎；埃及、摩洛哥等殖民争议地区","summary":"1904年英法协约通过解决殖民争端改善英法关系，并在德国挑战法国摩洛哥政策时变成协约体系核心支柱。","fields":[{"label":"标题","value":"1904年英法协约"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1904年4月8日"},{"label":"地点","value":"伦敦、巴黎；埃及、摩洛哥等殖民争议地区"},{"label":"主要国家","value":"英国、法国、德国"},{"label":"一句话概括","value":"1904年英法协约通过解决殖民争端改善英法关系，并在德国挑战法国摩洛哥政策时变成协约体系核心支柱。"},{"label":"制定方/签署方","value":"英国政府与法国政府。"},{"label":"主要内容","value":"协约解决英法在埃及、摩洛哥和其他殖民地问题上的争端，英国承认法国在摩洛哥的特殊利益，法国承认英国在埃及的地位。"},{"label":"它试图解决什么问题","value":"英国和法国长期在殖民地竞争，但德国崛起和全球战略压力使双方都有必要减少彼此矛盾，集中处理更大的安全不确定性。"},{"label":"为什么重要","value":"它起初不是正式军事同盟，却成为一战前协约国集团形成的关键一步。德国在摩洛哥危机中挑战法国，反而使英法合作更加坚固。"},{"label":"争议/局限","value":"协约本身没有立即规定英国必须为法国参战，很多军事和外交承诺是在之后危机中逐渐加深的。"},{"label":"造成的影响","value":"第一次摩洛哥危机把1904年英法协约从殖民和解推向欧洲战略合作，德国对“被包围”的感受随之增强。"},{"label":"出处","value":"Encyclopaedia Britannica: Entente Cordiale；UK National Archives: The Entente Cordiale；Encyclopaedia Britannica: 20th-century international relations。"}],"relationItems":["← 前因：英德同盟谈判失败","→ 后果：第一次摩洛哥危机","→ 后果：1907年英俄协约","↔ 相关：德意志帝国世界政策","↔ 相关：德意志帝国英德海军竞赛"],"relations":[{"text":"← 前因：英德同盟谈判失败","id":"extra781"},{"text":"→ 后果：第一次摩洛哥危机","id":"extra638"},{"text":"→ 后果：1907年英俄协约","id":"extra785"},{"text":"↔ 相关：德意志帝国世界政策","id":"extra635"},{"text":"↔ 相关：德意志帝国英德海军竞赛","id":"extra637"}],"source":"history","id":"extra782"},{"title":"1904—1905年日俄战争","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1904—1905年","place":"满洲、朝鲜半岛、黄海、日本海及俄国国内","summary":"1904—1905年日俄战争以日本胜利和俄国受挫告终，改变东亚力量格局，也间接影响欧洲同盟关系和德国战略判断。","fields":[{"label":"标题","value":"1904—1905年日俄战争"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1904—1905年"},{"label":"地点","value":"满洲、朝鲜半岛、黄海、日本海及俄国国内"},{"label":"主要国家","value":"日本、俄罗斯帝国、清朝、中国、英国、德国"},{"label":"一句话概括","value":"1904—1905年日俄战争以日本胜利和俄国受挫告终，改变东亚力量格局，也间接影响欧洲同盟关系和德国战略判断。"},{"label":"参与者","value":"日本帝国、俄罗斯帝国、清政府、美国调停者、欧洲列强观察者。"},{"label":"发生了什么","value":"日本与俄国围绕朝鲜和满洲利益冲突升级。1904年日本攻击旅顺口，随后在陆上和海上连续击败俄军。1905年俄国波罗的海舰队在对马海峡遭毁灭性失败，俄国内部革命压力上升。美国总统西奥多·罗斯福调停后，双方签订《朴次茅斯和约》。"},{"label":"为什么重要","value":"这是非欧洲强国击败欧洲大国的世界史节点，也改变德国对俄国实力、东亚局势和欧洲战略平衡的判断。俄国受挫后更需要在欧洲恢复地位，英俄和解空间也扩大。"},{"label":"前因","value":"日本和俄国都试图扩大在朝鲜和满洲的影响力，清朝战败后的东亚秩序和列强租借地竞争使地区矛盾高度国际化。"},{"label":"后果","value":"日本成为东亚强国，俄国国内危机加深；英国和俄国后来更容易解决亚洲争端，1907年英俄协约形成，德国面对的协约体系进一步完整。"},{"label":"出处","value":"Encyclopaedia Britannica: Russo-Japanese War；Office of the Historian: Treaty of Portsmouth and the Russo-Japanese War；Encyclopaedia Britannica: 20th-century international relations。"}],"relationItems":["← 前因：德国强租胶州湾","→ 后果：1907年英俄协约","↔ 相关：德意志帝国世界政策","↔ 相关：一战日英攻占青岛战役","↔ 同时期参考：第一次摩洛哥危机"],"relations":[{"text":"← 前因：德国强租胶州湾","id":"extra773"},{"text":"→ 后果：1907年英俄协约","id":"extra785"},{"text":"↔ 相关：德意志帝国世界政策","id":"extra635"},{"text":"↔ 相关：一战日英攻占青岛战役","id":"extra703"},{"text":"↔ 同时期参考：第一次摩洛哥危机","id":"extra638"}],"source":"history","id":"extra783"},{"title":"1905年鲁尔矿工大罢工","level":"C","type":"事件卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1905年1—2月","place":"德意志帝国鲁尔工业区","summary":"1905年鲁尔矿工大罢工把矿工工时、工资和劳动条件问题推向帝国政治，显示工业社会冲突持续扩大。","fields":[{"label":"标题","value":"1905年鲁尔矿工大罢工"},{"label":"分级","value":"C"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1905年1—2月"},{"label":"地点","value":"德意志帝国鲁尔工业区"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1905年鲁尔矿工大罢工把矿工工时、工资和劳动条件问题推向帝国政治，显示工业社会冲突持续扩大。"},{"label":"参与者","value":"鲁尔矿工、矿主、自由工会与基督教工会、帝国和普鲁士政府、德国社会民主党。"},{"label":"发生了什么","value":"1905年初，鲁尔区矿工因工资、工时、罚款制度和劳动条件不满发动大规模罢工，参与者达到数十万人规模。罢工显示矿工群体的组织能力和工业区劳资矛盾，也迫使政府关注矿业劳动条件。虽然罢工并未完全实现所有要求，但它推动了矿业监管和工人组织的公共讨论。"},{"label":"为什么重要","value":"它说明威廉时代的社会问题并未被社会保险和工人保护立法消除。重工业区工人运动已经成为帝国政治无法绕开的社会力量。"},{"label":"前因","value":"鲁尔工业化快速扩大矿工队伍，长工时、高风险、企业纪律和工资压力积累了强烈不满，工会组织也提高了集体行动能力。"},{"label":"后果","value":"罢工推动矿工劳动条件和矿业监管进入政治议程，也强化了政府、工会和社民党围绕工人问题的竞争。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Arbeiterbewegung im Kaiserreich；Deutsche Digitale Bibliothek: Bergarbeiterstreik 1905 materials；German History in Documents and Images: Labor and Society in Wilhelmine Germany。"}],"relationItems":["← 前因：德国鲁尔工业区","← 前因：德国自由工会总委员会","→ 后果：德国1912年国会选举","↔ 相关：德国社会民主党（SPD）","↔ 相关：德国1891年工人保护法"],"relations":[{"text":"← 前因：德国鲁尔工业区","id":"extra679"},{"text":"← 前因：德国自由工会总委员会","id":"extra739"},{"text":"→ 后果：德国1912年国会选举","id":"extra789"},{"text":"↔ 相关：德国社会民主党（SPD）","id":"extra628"},{"text":"↔ 相关：德国1891年工人保护法","id":"extra766"}],"source":"history","id":"extra784"},{"title":"1907年英俄协约","level":"B","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1907年8月31日","place":"圣彼得堡、伦敦；波斯、阿富汗、西藏等亚洲争议地区","summary":"1907年英俄协约解决双方在亚洲的部分争端，使英法俄三国协约格局基本成形，德国包围感加深。","fields":[{"label":"标题","value":"1907年英俄协约"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1907年8月31日"},{"label":"地点","value":"圣彼得堡、伦敦；波斯、阿富汗、西藏等亚洲争议地区"},{"label":"主要国家","value":"英国、俄罗斯帝国、法国、德国"},{"label":"一句话概括","value":"1907年英俄协约解决双方在亚洲的部分争端，使英法俄三国协约格局基本成形，德国包围感加深。"},{"label":"制定方/签署方","value":"英国政府与俄罗斯帝国政府。"},{"label":"主要内容","value":"协约划分或确认双方在波斯、阿富汗和西藏问题上的利益边界，缓和十九世纪以来英俄在亚洲的“大博弈”矛盾。"},{"label":"它试图解决什么问题","value":"英国希望减少亚洲战略压力并应对德国海军挑战，俄国在1904—1905年日俄战争和1905年革命后也需要稳定外部环境。"},{"label":"为什么重要","value":"它同1904年英法协约、法俄同盟一起构成三国协约的外交基础。德国并不是协约文本的签署对象，但其崛起和海军扩张是英国战略调整的重要背景。"},{"label":"争议/局限","value":"协约不是正式三国军事同盟，各国承诺程度不同；但它在危机中形成了越来越强的战略协调效果。"},{"label":"造成的影响","value":"欧洲分化为三国同盟和三国协约两大集团的趋势更明显，一战前危机处理空间随之缩小。"},{"label":"出处","value":"Encyclopaedia Britannica: Anglo-Russian Entente；Encyclopaedia Britannica: 20th-century international relations；UK National Archives: The Anglo-Russian Entente。"}],"relationItems":["← 前因：1904年英法协约","← 前因：1904—1905年日俄战争","→ 后果：1914年七月危机","↔ 相关：德奥意三国同盟","↔ 相关：德意志帝国英德海军竞赛"],"relations":[{"text":"← 前因：1904年英法协约","id":"extra782"},{"text":"← 前因：1904—1905年日俄战争","id":"extra783"},{"text":"→ 后果：1914年七月危机","id":"extra646"},{"text":"↔ 相关：德奥意三国同盟","id":"extra631"},{"text":"↔ 相关：德意志帝国英德海军竞赛","id":"extra637"}],"source":"history","id":"extra785"},{"title":"德国1908年帝国结社法","level":"C","type":"制度/文本卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1908年","place":"德意志帝国","summary":"1908年帝国结社法统一结社规则，并允许女性参加政治组织，是德国群众政治扩张的重要制度节点。","fields":[{"label":"标题","value":"德国1908年帝国结社法"},{"label":"分级","value":"C"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1908年"},{"label":"地点","value":"德意志帝国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1908年帝国结社法统一结社规则，并允许女性参加政治组织，是德国群众政治扩张的重要制度节点。"},{"label":"制定方/签署方","value":"德意志帝国政府、帝国议会、联邦参议院。"},{"label":"主要内容","value":"法律把此前各邦差异很大的结社规则统一到帝国层面，并取消许多邦对女性参加政治协会的限制，使女性能更公开地加入政党和政治组织。"},{"label":"它试图解决什么问题","value":"随着政党、工会、妇女运动和群众组织扩张，各邦旧有结社管制越来越不适应全国政治。帝国需要统一规则，同时仍保留对集会和结社的警察监管。"},{"label":"为什么重要","value":"它扩大了德国政治参与的社会基础，尤其对妇女运动和社民党女性组织具有重要意义。"},{"label":"争议/局限","value":"法律并未给予女性选举权，也仍允许国家以治安和秩序名义限制政治活动。它是参与空间扩大，而不是民主化完成。"},{"label":"造成的影响","value":"女性更容易进入政党和政治协会，德国妇女运动和社民党组织能力增强，战后女性参政权获得时已有更成熟组织基础。"},{"label":"出处","value":"German History in Documents and Images: The Reich Association Law；Deutsches Historisches Museum/LeMO: Frauenbewegung；Bundeszentrale für politische Bildung: Frauenwahlrecht in Deutschland。"}],"relationItems":["← 前因：德国妇女运动","← 前因：德国社会民主党（SPD）","→ 后果：魏玛共和国女性选举权","↔ 相关：德意志帝国议会","↔ 相关：德国自由工会总委员会"],"relations":[{"text":"← 前因：德国妇女运动","id":"extra684"},{"text":"← 前因：德国社会民主党（SPD）","id":"extra628"},{"text":"↔ 相关：德意志帝国议会","id":"extra669"},{"text":"↔ 相关：德国自由工会总委员会","id":"extra739"}],"source":"history","id":"extra786"},{"title":"奥匈吞并波斯尼亚危机","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1908—1909年","place":"波斯尼亚和黑塞哥维那、维也纳、贝尔格莱德、圣彼得堡、柏林","summary":"奥匈吞并波斯尼亚引发欧洲危机，德国支持奥匈迫使俄塞退让，却加深巴尔干怨恨和大国对立。","fields":[{"label":"标题","value":"奥匈吞并波斯尼亚危机"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1908—1909年"},{"label":"地点","value":"波斯尼亚和黑塞哥维那、维也纳、贝尔格莱德、圣彼得堡、柏林"},{"label":"主要国家","value":"奥匈帝国、塞尔维亚、俄罗斯帝国、德国、奥斯曼帝国"},{"label":"一句话概括","value":"奥匈吞并波斯尼亚引发欧洲危机，德国支持奥匈迫使俄塞退让，却加深巴尔干怨恨和大国对立。"},{"label":"参与者","value":"奥匈帝国、塞尔维亚、俄罗斯帝国、德国、奥斯曼帝国、欧洲列强。"},{"label":"发生了什么","value":"1908年，奥匈帝国正式吞并自1878年以来实际占领的波斯尼亚和黑塞哥维那。塞尔维亚和俄国强烈反对，认为这打击了南斯拉夫民族诉求并扩大奥匈在巴尔干的势力。德国在外交上支持奥匈，并对俄国施加强硬压力。俄国因1904—1905年日俄战争和1905年革命后尚未恢复，只能退让。危机没有导致战争，但敌意显著加深。"},{"label":"为什么重要","value":"它是一战前巴尔干危机链条中的关键节点。德国支持奥匈取得短期胜利，却让俄国和塞尔维亚在下一次危机中更不愿退让。"},{"label":"前因","value":"巴尔干危机1878年柏林会议允许奥匈占领波斯尼亚和黑塞哥维那，但名义主权问题长期悬而未决；青年土耳其革命又使奥匈担心其控制地位被重新谈判。"},{"label":"后果","value":"塞尔维亚民族主义和反奥情绪上升，俄国对1909年退让记忆深刻；1914年萨拉热窝刺杀和七月危机因此更难被温和处理。"},{"label":"出处","value":"Encyclopaedia Britannica: Bosnian crisis of 1908；Office of the Historian: The Bosnian Crisis, 1908；Encyclopaedia Britannica: 20th-century international relations。"}],"relationItems":["← 前因：巴尔干危机1878年柏林会议","→ 后果：萨拉热窝刺杀事件","→ 后果：1914年七月危机","↔ 相关：1879年德奥同盟","↔ 相关：1907年英俄协约"],"relations":[{"text":"← 前因：巴尔干危机1878年柏林会议","id":"extra753"},{"text":"→ 后果：萨拉热窝刺杀事件","id":"extra644"},{"text":"→ 后果：1914年七月危机","id":"extra646"},{"text":"↔ 相关：1879年德奥同盟","id":"extra755"},{"text":"↔ 相关：1907年英俄协约","id":"extra785"}],"source":"history","id":"extra787"},{"title":"德国1911年帝国保险条例","level":"C","type":"制度/文本卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1911年","place":"德意志帝国","summary":"1911年帝国保险条例整合疾病、事故、养老和残疾保险，是德国社会保险制度体系化的重要步骤。","fields":[{"label":"标题","value":"德国1911年帝国保险条例"},{"label":"分级","value":"C"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1911年"},{"label":"地点","value":"德意志帝国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1911年帝国保险条例整合疾病、事故、养老和残疾保险，是德国社会保险制度体系化的重要步骤。"},{"label":"制定方/签署方","value":"德意志帝国政府、帝国议会、联邦参议院。"},{"label":"主要内容","value":"条例汇编和整合了既有社会保险法律，把疾病保险、事故保险、残疾和养老保险等纳入更统一的法规体系，并扩展部分适用范围。"},{"label":"它试图解决什么问题","value":"俾斯麦以来的社会保险分散在多部法律中，工业社会风险和行政管理需求扩大后，帝国需要更系统的社会保险法典。"},{"label":"为什么重要","value":"它说明德国福利国家不是一次性由俾斯麦完成，而是在帝国后期继续制度化和行政化。"},{"label":"争议/局限","value":"保险制度仍以雇佣关系和缴费资格为核心，覆盖不足与给付水平有限的问题仍存在；它也不能消除阶级冲突和工人政治不满。"},{"label":"造成的影响","value":"帝国保险条例成为德国社会保险法的重要基础，影响魏玛和后续德国社会保障制度的发展。"},{"label":"出处","value":"Deutsche Rentenversicherung: Reichsversicherungsordnung 1911；Quellensammlung zur Geschichte der deutschen Sozialpolitik: Reichsversicherungsordnung；German History in Documents and Images: Social Insurance materials。"}],"relationItems":["← 前因：德国疾病保险法","← 前因：德国事故保险法","← 前因：德国养老和残疾保险法","↔ 相关：德国俾斯麦社会保险立法","→ 后果：魏玛德国失业保险法"],"relations":[{"text":"← 前因：德国疾病保险法","id":"extra740"},{"text":"← 前因：德国事故保险法","id":"extra741"},{"text":"← 前因：德国养老和残疾保险法","id":"extra759"},{"text":"↔ 相关：德国俾斯麦社会保险立法","id":"extra629"},{"text":"→ 后果：魏玛德国失业保险法","id":"card81"}],"source":"history","id":"extra788"},{"title":"德国1912年国会选举","level":"B","type":"事件卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1912年1月","place":"德意志帝国","summary":"1912年国会选举中SPD成为帝国议会最大党团，暴露普选议会与君主制政府之间的结构性矛盾。","fields":[{"label":"标题","value":"德国1912年国会选举"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1912年1月"},{"label":"地点","value":"德意志帝国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1912年国会选举中SPD成为帝国议会最大党团，暴露普选议会与君主制政府之间的结构性矛盾。"},{"label":"参与者","value":"德国社会民主党、中央党、保守党、民族自由党、进步人民党、德国选民、帝国政府。"},{"label":"发生了什么","value":"1912年帝国议会选举中，德国社会民主党获得最多选票并成为最大党团。由于帝国政府不对国会多数负责，SPD的议会胜利并没有转化为组阁权。保守派、民族自由派和政府仍试图通过军备、民族主义和制度限制维持统治。"},{"label":"为什么重要","value":"它显示德国社会已经发生深刻变化，但帝国宪制没有相应民主化。最大群众政党被排除在政府权力之外，增加了制度紧张。"},{"label":"前因","value":"工业化扩大工人阶级，反社会党人法失败后SPD长期合法组织化；矿工罢工、城市社会问题和普选权动员持续扩大社民党基础。"},{"label":"后果","value":"政府更依赖军备和民族主义议题绕开社会民主主义压力，1913年陆军扩军法和战前政治动员在这种紧张结构中展开。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Reichstagswahl 1912；Encyclopaedia Britannica: German Empire；German History in Documents and Images: Reichstag Election Results。"}],"relationItems":["← 前因：德国社会民主党（SPD）","← 前因：1905年鲁尔矿工大罢工","→ 后果：德国1913年陆军扩军法","→ 后果：德国1914年战争贷款表决","↔ 相关：德意志帝国议会"],"relations":[{"text":"← 前因：德国社会民主党（SPD）","id":"extra628"},{"text":"← 前因：1905年鲁尔矿工大罢工","id":"extra784"},{"text":"→ 后果：德国1913年陆军扩军法","id":"extra790"},{"text":"→ 后果：德国1914年战争贷款表决","id":"extra691"},{"text":"↔ 相关：德意志帝国议会","id":"extra669"}],"source":"history","id":"extra789"},{"title":"德国1913年陆军扩军法","level":"B","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1913年","place":"德意志帝国；柏林","summary":"1913年德国陆军扩军法大幅增加军力和军费，是一战前欧洲军备竞赛升级的重要节点。","fields":[{"label":"标题","value":"德国1913年陆军扩军法"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1913年"},{"label":"地点","value":"德意志帝国；柏林"},{"label":"主要国家","value":"德国、法国、俄罗斯帝国"},{"label":"一句话概括","value":"1913年德国陆军扩军法大幅增加军力和军费，是一战前欧洲军备竞赛升级的重要节点。"},{"label":"制定方/签署方","value":"德意志帝国政府、帝国议会、联邦参议院；军方和总参谋部推动。"},{"label":"主要内容","value":"法律扩大德军和平时期兵力，增加军费，并通过特别国防税等方式筹措资金。其背景是德国对俄国军备恢复、法国三年兵役法和两线战争风险的担忧。"},{"label":"它试图解决什么问题","value":"德国军方认为法俄力量增长会削弱德国在未来战争中的时间优势，因此要求在战争可能到来前扩大陆军规模。"},{"label":"为什么重要","value":"它表明一战前德国不只在海军上扩张，也在陆军上加速备战。军备竞赛使各国更倾向把危机看成必须抢先行动的安全问题。"},{"label":"争议/局限","value":"扩军强化安全焦虑而非消除它。高军费也加剧议会财政争议，并让SPD等反军国主义力量与政府矛盾加深。"},{"label":"造成的影响","value":"德国战前动员能力增强，欧洲军备竞赛进一步升温；1914年七月危机爆发时，军事时间表和总参谋部判断更容易压倒外交妥协。"},{"label":"出处","value":"Encyclopaedia Britannica: German Empire；German History in Documents and Images: The Army Bill of 1913；David Stevenson, Armaments and the Coming of War。"}],"relationItems":["← 前因：德国1912年国会选举","← 前因：德国施里芬计划","→ 后果：1914年七月危机","→ 后果：德国入侵比利时","↔ 相关：德国对奥匈的“空白支票”保证"],"relations":[{"text":"← 前因：德国1912年国会选举","id":"extra789"},{"text":"← 前因：德国施里芬计划","id":"extra643"},{"text":"→ 后果：1914年七月危机","id":"extra646"},{"text":"→ 后果：德国入侵比利时","id":"extra647"},{"text":"↔ 相关：德国对奥匈的“空白支票”保证","id":"extra645"}],"source":"history","id":"extra790"},{"title":"阿尔弗雷德·冯·施里芬","level":"B","type":"人物卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1833—1913年；1891—1906年任德国总参谋长","place":"德意志帝国；柏林总参谋部","summary":"施里芬是德国总参谋部核心人物，其对两线战争的作战设想后来被概括为施里芬计划。","fields":[{"label":"标题","value":"阿尔弗雷德·冯·施里芬"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1833—1913年；1891—1906年任德国总参谋长"},{"label":"地点","value":"德意志帝国；柏林总参谋部"},{"label":"主要国家","value":"德国、法国、俄罗斯帝国"},{"label":"一句话概括","value":"施里芬是德国总参谋部核心人物，其对两线战争的作战设想后来被概括为施里芬计划。"},{"label":"生卒年/活跃年代","value":"1833年2月28日—1913年1月4日；1891—1906年任德国总参谋长。"},{"label":"身份/职务","value":"普鲁士和德意志帝国军官、德国总参谋长。"},{"label":"关键贡献/作为","value":"长期研究德国在法俄夹击下的作战问题，强调集中兵力先击败法国，再转向俄国。1905年前后的备忘录成为后来“施里芬计划”争论的核心文本。"},{"label":"核心主张/立场","value":"认为德国无法长期承受两线战争，必须利用铁路动员和右翼大包抄迅速击败法国，以时间优势抵消战略劣势。"},{"label":"为什么重要","value":"他体现德国战略思维如何被地缘焦虑、铁路动员和总参谋部计划化塑造。施里芬本人不是1914年决策者，但他的作战框架深刻影响德国开战方案。"},{"label":"争议/评价","value":"史学界对“施里芬计划”究竟是固定蓝图还是后来概括存在争论。不能把1914年德国战略完全归因于施里芬个人。"},{"label":"关联事件（可选）","value":"德国施里芬计划；德国入侵比利时；第一次马恩河战役。"},{"label":"出处","value":"Encyclopaedia Britannica: Alfred von Schlieffen；German History in Documents and Images: The Schlieffen Plan；Terence Zuber, Inventing the Schlieffen Plan。"}],"relationItems":["← 前因：德俄再保险条约","→ 后果：德国施里芬计划","↔ 相关：赫尔穆特·约翰内斯·冯·毛奇","↔ 相关：德国1913年陆军扩军法","↔ 相关：第一次马恩河战役"],"relations":[{"text":"← 前因：德俄再保险条约","id":"extra632"},{"text":"→ 后果：德国施里芬计划","id":"extra643"},{"text":"↔ 相关：赫尔穆特·约翰内斯·冯·毛奇","id":"extra792"},{"text":"↔ 相关：德国1913年陆军扩军法","id":"extra790"},{"text":"↔ 相关：第一次马恩河战役","id":"extra650"}],"source":"history","id":"extra791"},{"title":"赫尔穆特·约翰内斯·冯·毛奇","level":"C","type":"人物卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1848—1916年；1906—1914年任德国总参谋长","place":"德意志帝国；柏林总参谋部","summary":"小毛奇在1914年担任德国总参谋长，负责将施里芬式西线方案转化为实际动员和进攻。","fields":[{"label":"标题","value":"赫尔穆特·约翰内斯·冯·毛奇"},{"label":"分级","value":"C"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1848—1916年；1906—1914年任德国总参谋长"},{"label":"地点","value":"德意志帝国；柏林总参谋部"},{"label":"主要国家","value":"德国、法国、俄罗斯帝国、比利时"},{"label":"一句话概括","value":"小毛奇在1914年担任德国总参谋长，负责将施里芬式西线方案转化为实际动员和进攻。"},{"label":"生卒年/活跃年代","value":"1848年5月25日—1916年6月18日；1906—1914年任德国总参谋长。"},{"label":"身份/职务","value":"德国军官、总参谋长，老毛奇的侄子。"},{"label":"关键贡献/作为","value":"继承并调整施里芬之后的两线战争计划；1914年七月危机中参与军事判断和动员决策；开战后指挥西线初期作战，马恩河失败后被撤换。"},{"label":"核心主张/立场","value":"认为德国必须在法俄包围中快速行动，但在实际部署中比施里芬设想更重视东线和左翼安全。"},{"label":"为什么重要","value":"他是连接纸面计划和1914年现实战争的关键人物。德国入侵比利时、速胜失败和马恩河转折，都不能只看施里芬计划文本，也要看小毛奇的执行和调整。"},{"label":"争议/评价","value":"传统观点常批评他削弱右翼导致失败；后来的研究则强调1914年后勤、政治和敌方反应本就使计划极难成功。"},{"label":"关联事件（可选）","value":"德国施里芬计划；1914年七月危机；德国入侵比利时；第一次马恩河战役。"},{"label":"出处","value":"Encyclopaedia Britannica: Helmuth von Moltke；German History in Documents and Images: The Schlieffen Plan；Annika Mombauer, Helmuth von Moltke and the Origins of the First World War。"}],"relationItems":["← 前因：阿尔弗雷德·冯·施里芬","→ 后果：德国入侵比利时","→ 后果：第一次马恩河战役","↔ 相关：德国1913年陆军扩军法","↔ 相关：1914年七月危机"],"relations":[{"text":"← 前因：阿尔弗雷德·冯·施里芬","id":"extra791"},{"text":"→ 后果：德国入侵比利时","id":"extra647"},{"text":"→ 后果：第一次马恩河战役","id":"extra650"},{"text":"↔ 相关：德国1913年陆军扩军法","id":"extra790"},{"text":"↔ 相关：1914年七月危机","id":"extra646"}],"source":"history","id":"extra792"},{"title":"特奥巴尔德·冯·贝特曼-霍尔维格","level":"B","type":"人物卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1856—1921年；1909—1917年任德意志帝国首相","place":"德意志帝国；柏林","summary":"贝特曼-霍尔维格是一战爆发时的德国首相，代表帝国文官政府在军方、皇帝和议会之间逐渐失去主动权。","fields":[{"label":"标题","value":"特奥巴尔德·冯·贝特曼-霍尔维格"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1856—1921年；1909—1917年任德意志帝国首相"},{"label":"地点","value":"德意志帝国；柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"贝特曼-霍尔维格是一战爆发时的德国首相，代表帝国文官政府在军方、皇帝和议会之间逐渐失去主动权。"},{"label":"生卒年/活跃年代","value":"1856年11月29日—1921年1月1日；1909—1917年任帝国首相。"},{"label":"身份/职务","value":"德意志帝国首相、普鲁士首相、文官政治家。"},{"label":"关键贡献/作为","value":"任内经历英德关系恶化、1914年七月危机、一战爆发、德国九月纲领、一战德国“城堡和平”政治休战、无限制潜艇战争议和1917年议会和平决议前后的政治危机。"},{"label":"核心主张/立场","value":"试图在君主制、军方压力、议会多数和有限改革之间维持平衡；对外并非单纯冒险派，但在战争目标和军事决策上不断向强硬力量让步。"},{"label":"为什么重要","value":"他说明德意志帝国的文官政府并不能有效控制战争机器。随着战争长期化，首相权威被最高陆军统帅部、皇帝和利益集团逐步挤压。"},{"label":"争议/评价","value":"史学界对他在1914年战争责任和九月纲领中的主动性评价不一；他既不是完全被动的和平派，也不是唯一决定战争升级的人。"},{"label":"关联事件（可选）","value":"德国《九月纲领》；1914年七月危机；德国无限制潜艇战；德国帝国议会和平决议。"},{"label":"出处","value":"Encyclopaedia Britannica: Theobald von Bethmann Hollweg；Deutsches Historisches Museum/LeMO: Bethmann Hollweg；1914-1918 Online: Bethmann Hollweg, Theobald von。"}],"relationItems":["← 前因：伯恩哈德·冯·比洛","→ 后果：德国《九月纲领》","→ 后果：德国帝国议会和平决议","↔ 相关：1914年七月危机","↔ 相关：德国第三最高陆军统帅部"],"relations":[{"text":"← 前因：伯恩哈德·冯·比洛","id":"extra778"},{"text":"→ 后果：德国《九月纲领》","id":"extra794"},{"text":"→ 后果：德国帝国议会和平决议","id":"extra800"},{"text":"↔ 相关：1914年七月危机","id":"extra646"},{"text":"↔ 相关：德国第三最高陆军统帅部","id":"extra797"}],"source":"history","id":"extra793"},{"title":"德国《九月纲领》","level":"B","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1914年9月9日","place":"德意志帝国政府；柏林","summary":"《九月纲领》列出德国若获胜后的广泛战争目标，是理解一战德国扩张设想和战争目标争论的关键文本。","fields":[{"label":"标题","value":"德国《九月纲领》"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1914年9月9日"},{"label":"地点","value":"德意志帝国政府；柏林"},{"label":"主要国家","value":"德国、法国、比利时、俄罗斯帝国、卢森堡"},{"label":"一句话概括","value":"《九月纲领》列出德国若获胜后的广泛战争目标，是理解一战德国扩张设想和战争目标争论的关键文本。"},{"label":"制定方/签署方","value":"由首相贝特曼-霍尔维格授权形成，核心起草与帝国政府、外交和利益集团战争目标讨论相关。"},{"label":"主要内容","value":"纲领设想削弱法国、控制或支配比利时和卢森堡、建立以德国为中心的中欧经济体系，并在东欧和殖民地寻求扩张安排。"},{"label":"它试图解决什么问题","value":"德国在战争初期需要想象胜利后如何确保安全、经济优势和大陆主导地位；不同军事、工业、农业和民族主义集团也借此表达战争目标。"},{"label":"为什么重要","value":"它显示德国战争目标远超单纯防御叙事。虽然不等于最终官方和约方案，但它把帝国精英对欧洲重组的扩张性想象集中呈现出来。"},{"label":"争议/局限","value":"学界争论它代表贝特曼个人想法、政府临时草案，还是更广泛精英共识；不能把它机械等同于所有德国人的战争目标。"},{"label":"造成的影响","value":"它成为后世讨论德国一战责任和战争目标的重要证据，也帮助解释为什么战争长期化后国内右派仍反对无兼并和平。"},{"label":"出处","value":"Encyclopaedia Britannica: September Program；Deutsches Historisches Museum/LeMO: Septemberprogramm 1914；German History in Documents and Images: September Program。"}],"relationItems":["← 前因：德国入侵比利时","← 前因：特奥巴尔德·冯·贝特曼-霍尔维格","→ 后果：德国祖国党","↔ 相关：第一次马恩河战役","↔ 相关：德国帝国议会和平决议"],"relations":[{"text":"← 前因：德国入侵比利时","id":"extra647"},{"text":"← 前因：特奥巴尔德·冯·贝特曼-霍尔维格","id":"extra793"},{"text":"→ 后果：德国祖国党","id":"extra801"},{"text":"↔ 相关：第一次马恩河战役","id":"extra650"},{"text":"↔ 相关：德国帝国议会和平决议","id":"extra800"}],"source":"history","id":"extra794"},{"title":"德国战争原料部","level":"C","type":"组织/机构卡","tags":["经济与社会","战争与外交"],"mainTag":"经济与社会","subTag":"战争与外交","timeText":"1914年成立","place":"德意志帝国；柏林","summary":"德国战争原料部在一战初期统筹关键原料供应，标志国家、工业和战争经济开始深度结合。","fields":[{"label":"标题","value":"德国战争原料部"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1914年成立"},{"label":"地点","value":"德意志帝国；柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国战争原料部在一战初期统筹关键原料供应，标志国家、工业和战争经济开始深度结合。"},{"label":"性质/类型","value":"战时经济管理机构，隶属于普鲁士战争部体系。"},{"label":"成立/解散时间","value":"1914年成立；一战期间持续发挥战时原料统筹作用。"},{"label":"核心目标/宗旨","value":"调查、征用、分配和替代关键战争原料，确保军需工业在封锁和长期战争中继续运转。"},{"label":"关键人物（可选）","value":"瓦尔特·拉特瑙参与创建并在早期发挥关键作用。"},{"label":"关键行动/事件","value":"建立原料统计和管制机制，推动企业、军方和国家行政之间形成战时合作网络，为后来的更全面战争经济管制提供经验。"},{"label":"为什么重要","value":"它说明一战不是传统军队在前线作战，而是工业国家对原料、企业和劳动力的系统调动。德国在英国封锁下尤其需要这种国家经济管制。"},{"label":"争议/局限","value":"原料管制有助于军需生产，却无法解决粮食短缺和社会分配不平等；国家与大工业合作也引发战时利润和权力集中争议。"},{"label":"出处","value":"1914-1918 Online: War Raw Materials Department；German History in Documents and Images: War Economy materials；Encyclopaedia Britannica: Walter Rathenau。"}],"relationItems":["← 前因：英国对德海上封锁","← 前因：德国化学工业","→ 后果：德国兴登堡计划","↔ 相关：瓦尔特·拉特瑙","↔ 相关：一战总动员社会"],"relations":[{"text":"← 前因：英国对德海上封锁","id":"extra652"},{"text":"← 前因：德国化学工业","id":"extra680"},{"text":"→ 后果：德国兴登堡计划","id":"card1"},{"text":"↔ 相关：瓦尔特·拉特瑙","id":"card120"},{"text":"↔ 相关：一战总动员社会","id":"extra653"}],"source":"history","id":"extra795"},{"title":"德国东线“上东”占领区","level":"C","type":"组织/机构卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1915—1918年","place":"立陶宛、拉脱维亚部分地区、白俄罗斯和波兰东北部等德军占领区","summary":"“上东”是德国在东线占领区建立的军事行政体系，体现一战东欧占领、资源控制和民族政策实验。","fields":[{"label":"标题","value":"德国东线“上东”占领区"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1915—1918年"},{"label":"地点","value":"立陶宛、拉脱维亚部分地区、白俄罗斯和波兰东北部等德军占领区"},{"label":"主要国家","value":"德国、俄罗斯帝国、立陶宛、拉脱维亚、白俄罗斯、波兰"},{"label":"一句话概括","value":"“上东”是德国在东线占领区建立的军事行政体系，体现一战东欧占领、资源控制和民族政策实验。"},{"label":"性质/类型","value":"德军东线占领行政体系，德文常称 Ober Ost。"},{"label":"成立/解散时间","value":"1915年德军推进后形成；1918年德国战败和东欧局势变化后瓦解。"},{"label":"核心目标/宗旨","value":"在占领区维持军事秩序、征用资源、管理交通和劳动力，并通过民族分类与行政规划塑造德国势力范围。"},{"label":"关键人物（可选）","value":"兴登堡和鲁登道夫领导的东线军事体系；占领行政官员和军方人员。"},{"label":"关键行动/事件","value":"对人口流动、粮食、交通、教育和出版进行严格管制；同时推动民族调查和文化分类，以服务德国对东欧的战时统治想象。"},{"label":"为什么重要","value":"它把德国一战战争目标从西线和海军问题扩展到东欧空间。上东经验影响了德国对东欧秩序、边疆治理和占领行政的长期想象。"},{"label":"争议/局限","value":"上东既有现代行政和基础设施管理面向，也包含军事强制、资源掠夺和民族等级化治理，不能被浪漫化为单纯建设项目。"},{"label":"出处","value":"1914-1918 Online: Ober Ost；Vejas Gabriel Liulevicius, War Land on the Eastern Front；German History in Documents and Images: Eastern Front materials。"}],"relationItems":["← 前因：一战东线坦能堡战役","→ 后果：《布列斯特-立托夫斯克条约》","↔ 相关：德国《九月纲领》","↔ 相关：德国第三最高陆军统帅部","↔ 同时期参考：俄国革命"],"relations":[{"text":"← 前因：一战东线坦能堡战役","id":"extra649"},{"text":"→ 后果：《布列斯特-立托夫斯克条约》","id":"extra662"},{"text":"↔ 相关：德国《九月纲领》","id":"extra794"},{"text":"↔ 相关：德国第三最高陆军统帅部","id":"extra797"}],"source":"history","id":"extra796"},{"title":"德国第三最高陆军统帅部","level":"B","type":"组织/机构卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1916—1918年","place":"德意志帝国最高统帅部；大本营和柏林政治体系","summary":"第三最高陆军统帅部由兴登堡和鲁登道夫主导，使德国一战后期接近军事独裁状态。","fields":[{"label":"标题","value":"德国第三最高陆军统帅部"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1916—1918年"},{"label":"地点","value":"德意志帝国最高统帅部；大本营和柏林政治体系"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"第三最高陆军统帅部由兴登堡和鲁登道夫主导，使德国一战后期接近军事独裁状态。"},{"label":"性质/类型","value":"德国陆军最高指挥机构和事实上的战时权力中心。"},{"label":"成立/解散时间","value":"1916年8月兴登堡和鲁登道夫接掌最高陆军统帅部后形成；1918年战败和革命中失势。"},{"label":"核心目标/宗旨","value":"集中军事、经济和政治资源以继续战争，推动兴登堡计划、劳动力动员、无限制潜艇战和战时宣传。"},{"label":"关键人物（可选）","value":"保罗·冯·兴登堡、埃里希·鲁登道夫。"},{"label":"关键行动/事件","value":"推动德国兴登堡计划和《祖国辅助服务法》；支持无限制潜艇战；压制和平妥协；1918年要求文官政府寻求停战。"},{"label":"为什么重要","value":"它说明德意志帝国在战时没有走向议会责任政府，而是让军方获得越来越大的政治支配权。魏玛时期“军方把战败责任转给文官”的结构也与此有关。"},{"label":"争议/局限","value":"称其为“军事独裁”是概括性说法，皇帝、首相和各邦制度仍存在，但实际政策主动权在1916年后明显向军方倾斜。"},{"label":"出处","value":"Encyclopaedia Britannica: Erich Ludendorff；1914-1918 Online: Supreme Army Command；Deutsches Historisches Museum/LeMO: Erster Weltkrieg Innenpolitik。"}],"relationItems":["← 前因：凡尔登战役","← 前因：索姆河战役","→ 后果：德国兴登堡计划","→ 后果：德国《祖国辅助服务法》","↔ 相关：埃里希·鲁登道夫"],"relations":[{"text":"← 前因：凡尔登战役","id":"extra654"},{"text":"← 前因：索姆河战役","id":"extra655"},{"text":"→ 后果：德国兴登堡计划","id":"card1"},{"text":"→ 后果：德国《祖国辅助服务法》","id":"extra799"},{"text":"↔ 相关：埃里希·鲁登道夫","id":"extra798"}],"source":"history","id":"extra797"},{"title":"埃里希·鲁登道夫","level":"B","type":"人物卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1865—1937年；1914—1918年一战中影响力突出","place":"德意志帝国；东线、西线和最高陆军统帅部","summary":"鲁登道夫是一战后期德国实际军事强人之一，推动总体战、无限制潜艇战和1918年西线决战。","fields":[{"label":"标题","value":"埃里希·鲁登道夫"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1865—1937年；1914—1918年一战中影响力突出"},{"label":"地点","value":"德意志帝国；东线、西线和最高陆军统帅部"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"鲁登道夫是一战后期德国实际军事强人之一，推动总体战、无限制潜艇战和1918年西线决战。"},{"label":"生卒年/活跃年代","value":"1865年4月9日—1937年12月20日；1914年后因列日、坦能堡和最高统帅部地位成名。"},{"label":"身份/职务","value":"德国将领，第一军需总监，兴登堡的核心搭档。"},{"label":"关键贡献/作为","value":"参与列日战役和坦能堡战役；1916年后与兴登堡主导第三最高陆军统帅部；支持兴登堡计划、无限制潜艇战和1918年春季攻势。"},{"label":"核心主张/立场","value":"主张把社会和经济全面服从战争需要，坚持以军事手段争取胜利，并在战败前后试图把责任转移给文官政府和国内政治力量。"},{"label":"为什么重要","value":"他连接一战德国军事化、魏玛反共和国神话和纳粹早期政治。理解“背后一刀”传说和右翼反民主政治，鲁登道夫是关键人物。"},{"label":"争议/评价","value":"他在战术和组织上能力突出，但战略判断高度冒险；1918年后宣扬战败责任转移，严重破坏魏玛共和国合法性。"},{"label":"关联事件（可选）","value":"坦能堡战役；德国第三最高陆军统帅部；德国1918年春季攻势；希特勒啤酒馆政变。"},{"label":"出处","value":"Encyclopaedia Britannica: Erich Ludendorff；Deutsches Historisches Museum/LeMO: Ludendorff；1914-1918 Online: Ludendorff, Erich。"}],"relationItems":["← 前因：一战东线坦能堡战役","→ 后果：德国第三最高陆军统帅部","→ 后果：德国“背后一刀”传说","↔ 相关：保罗·冯·兴登堡","↔ 相关：希特勒啤酒馆政变"],"relations":[{"text":"← 前因：一战东线坦能堡战役","id":"extra649"},{"text":"→ 后果：德国第三最高陆军统帅部","id":"extra797"},{"text":"→ 后果：德国“背后一刀”传说","id":"extra623"},{"text":"↔ 相关：保罗·冯·兴登堡","id":"card37"},{"text":"↔ 相关：希特勒啤酒馆政变","id":"card18"}],"source":"history","id":"extra798"},{"title":"德国《祖国辅助服务法》","level":"B","type":"制度/文本卡","tags":["经济与社会","战争与外交"],"mainTag":"经济与社会","subTag":"战争与外交","timeText":"1916年12月5日","place":"德意志帝国","summary":"《祖国辅助服务法》要求成年男性为战争经济服务，是德国一战后期劳动力军事化动员的核心法律。","fields":[{"label":"标题","value":"德国《祖国辅助服务法》"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1916年12月5日"},{"label":"地点","value":"德意志帝国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"《祖国辅助服务法》要求成年男性为战争经济服务，是德国一战后期劳动力军事化动员的核心法律。"},{"label":"制定方/签署方","value":"德意志帝国政府、帝国议会、联邦参议院；由第三最高陆军统帅部强力推动。"},{"label":"主要内容","value":"法律规定17至60岁德国男性如未服兵役，原则上需从事对战争重要的劳动或服务；同时建立调配和仲裁机制，以把劳动力引向军需生产。"},{"label":"它试图解决什么问题","value":"凡尔登和索姆河后，德国同时缺士兵、工人、弹药和运输能力。兴登堡计划要求扩大军需产量，必须更强制地调动劳动力。"},{"label":"为什么重要","value":"它把“全民战争”推进到劳动力制度层面。国家不只征召士兵，也开始更直接地支配民用劳动。"},{"label":"争议/局限","value":"法律提高军需动员能力，却加剧工人不满；工会获得一定参与渠道，但劳动者自由和生活条件被进一步压缩。"},{"label":"造成的影响","value":"军需生产和劳动力管制加强，工人阶级对战争负担的不满上升，并为1918年一月罢工等后方抗议积累条件。"},{"label":"出处","value":"German History in Documents and Images: Auxiliary Service Law；1914-1918 Online: War Economy；Deutsches Historisches Museum/LeMO: Hilfsdienstgesetz。"}],"relationItems":["← 前因：德国第三最高陆军统帅部","← 前因：德国兴登堡计划","→ 后果：德国1918年一月罢工","↔ 相关：一战总动员社会","↔ 相关：德国自由工会总委员会"],"relations":[{"text":"← 前因：德国第三最高陆军统帅部","id":"extra797"},{"text":"← 前因：德国兴登堡计划","id":"card1"},{"text":"→ 后果：德国1918年一月罢工","id":"extra802"},{"text":"↔ 相关：一战总动员社会","id":"extra653"},{"text":"↔ 相关：德国自由工会总委员会","id":"extra739"}],"source":"history","id":"extra799"},{"title":"德国帝国议会和平决议","level":"B","type":"制度/文本卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1917年7月19日","place":"德意志帝国议会；柏林","summary":"1917年和平决议要求无兼并、无赔款和平，显示国会多数开始公开挑战军方和右翼战争目标。","fields":[{"label":"标题","value":"德国帝国议会和平决议"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1917年7月19日"},{"label":"地点","value":"德意志帝国议会；柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1917年和平决议要求无兼并、无赔款和平，显示国会多数开始公开挑战军方和右翼战争目标。"},{"label":"制定方/签署方","value":"帝国议会多数派推动，主要包括中央党、社会民主党和进步人民党等。"},{"label":"主要内容","value":"决议主张通过理解和解实现和平，反对强制兼并和战争赔款式目标，同时要求国内政治改革和更大议会影响。"},{"label":"它试图解决什么问题","value":"战争长期化、粮食危机、俄国革命和美国参战使德国社会承受力下降，议会多数希望推动可谈判和平并限制军方战争目标。"},{"label":"为什么重要","value":"它是帝国议会在战时少有的政治主动尝试，显示德国国内已不再维持1914年的一战德国“城堡和平”政治休战。"},{"label":"争议/局限","value":"决议没有强制政府和军方改变路线。第三最高陆军统帅部和右翼民族主义者继续坚持胜利和平，和平决议无法结束战争。"},{"label":"造成的影响","value":"决议刺激右派组织反击，德国祖国党兴起；它也预示1918年十月改革中议会多数将被迫承担停战责任。"},{"label":"出处","value":"German History in Documents and Images: Peace Resolution of the Reichstag；Deutsches Historisches Museum/LeMO: Friedensresolution；1914-1918 Online: Peace Initiatives。"}],"relationItems":["← 前因：德国“芜菁冬天”","← 前因：德国独立社会民主党","→ 后果：德国祖国党","→ 后果：德国1918年十月改革","↔ 相关：德意志帝国议会"],"relations":[{"text":"← 前因：德国“芜菁冬天”","id":"extra657"},{"text":"← 前因：德国独立社会民主党","id":"extra693"},{"text":"→ 后果：德国祖国党","id":"extra801"},{"text":"→ 后果：德国1918年十月改革","id":"extra805"},{"text":"↔ 相关：德意志帝国议会","id":"extra669"}],"source":"history","id":"extra800"},{"title":"德国祖国党","level":"C","type":"组织/机构卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1917—1918年","place":"德意志帝国","summary":"德国祖国党是一战后期的右翼群众组织，反对议会和平决议，鼓吹胜利和平和强硬战争目标。","fields":[{"label":"标题","value":"德国祖国党"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1917—1918年"},{"label":"地点","value":"德意志帝国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国祖国党是一战后期的右翼群众组织，反对议会和平决议，鼓吹胜利和平和强硬战争目标。"},{"label":"性质/类型","value":"右翼民族主义压力组织和群众动员团体。"},{"label":"成立/解散时间","value":"1917年成立；1918年德国战败和革命后失去基础。"},{"label":"核心目标/宗旨","value":"反对无兼并和平，支持继续战争、扩大德国战果和维护君主制、军方与民族主义战争目标。"},{"label":"关键人物（可选）","value":"阿尔弗雷德·冯·提尔皮茨、沃尔夫冈·卡普等。"},{"label":"关键行动/事件","value":"组织宣传和请愿，攻击和平决议与议会多数，试图把社会不满导向民族主义和反左翼动员。"},{"label":"为什么重要","value":"它是战时右翼群众化的重要节点。后来魏玛右翼的反共和国、反议会和修约主义政治，在祖国党这类组织中已有早期形态。"},{"label":"争议/局限","value":"祖国党声势很大，但无法改变德国军事和经济劣势；它的宣传加剧国内撕裂，并为战后右翼神话提供语言资源。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Deutsche Vaterlandspartei；1914-1918 Online: German Fatherland Party；Encyclopaedia Britannica: Wolfgang Kapp。"}],"relationItems":["← 前因：德国帝国议会和平决议","← 前因：德国《九月纲领》","→ 后果：德国“背后一刀”传说","↔ 相关：阿尔弗雷德·冯·提尔皮茨","↔ 相关：德国哈尔茨堡阵线"],"relations":[{"text":"← 前因：德国帝国议会和平决议","id":"extra800"},{"text":"← 前因：德国《九月纲领》","id":"extra794"},{"text":"→ 后果：德国“背后一刀”传说","id":"extra623"},{"text":"↔ 相关：阿尔弗雷德·冯·提尔皮茨","id":"extra776"},{"text":"↔ 相关：德国哈尔茨堡阵线","id":"card48"}],"source":"history","id":"extra801"},{"title":"德国1918年一月罢工","level":"B","type":"事件卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1918年1—2月","place":"柏林、莱比锡、汉堡、鲁尔区等德国工业城市","summary":"1918年一月罢工把粮食、和平、民主改革和工人代表问题结合起来，是德国革命前的重要后方抗议。","fields":[{"label":"标题","value":"德国1918年一月罢工"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1918年1—2月"},{"label":"地点","value":"柏林、莱比锡、汉堡、鲁尔区等德国工业城市"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1918年一月罢工把粮食、和平、民主改革和工人代表问题结合起来，是德国革命前的重要后方抗议。"},{"label":"参与者","value":"军需工人、革命工长、德国独立社会民主党、部分社民党人、工会、帝国政府和军方。"},{"label":"发生了什么","value":"1918年初，德国多个工业中心爆发大规模罢工，柏林军需工人尤其突出。罢工者提出改善粮食供应、无兼并和平、释放政治犯、改革选举制度和工人代表参与谈判等要求。政府和军方将罢工视为危害战争努力，采取镇压、征兵和控制工厂等手段结束运动。"},{"label":"为什么重要","value":"它表明德国后方已经从忍耐战争转向公开政治抗议。罢工把社会经济痛苦和反战民主诉求结合起来，为十一月革命提供组织和心理准备。"},{"label":"前因","value":"《祖国辅助服务法》加强劳动控制，粮食短缺和战争疲惫持续恶化；俄国革命和和平口号也鼓励德国工人把经济抗议转化为政治行动。"},{"label":"后果","value":"罢工被压制后，工人激进化没有消失，革命工长和独立社民党继续积累影响；1918年秋军事失败时，后方抗议很快与水兵起义汇合。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Januarstreik 1918；1914-1918 Online: Labour Movements, Trade Unions and Strikes；German History in Documents and Images: The Spread of the 1918 Revolution。"}],"relationItems":["← 前因：德国《祖国辅助服务法》","← 前因：德国“芜菁冬天”","→ 后果：德国基尔水兵起义","→ 后果：德国工人士兵委员会","↔ 相关：德国独立社会民主党"],"relations":[{"text":"← 前因：德国《祖国辅助服务法》","id":"extra799"},{"text":"← 前因：德国“芜菁冬天”","id":"extra657"},{"text":"→ 后果：德国基尔水兵起义","id":"extra665"},{"text":"→ 后果：德国工人士兵委员会","id":"extra807"},{"text":"↔ 相关：德国独立社会民主党","id":"extra693"}],"source":"history","id":"extra802"},{"title":"德国最高统帅部要求停战谈判","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1918年9月29日","place":"斯帕大本营；柏林政治体系","summary":"1918年9月德国最高统帅部突然要求文官政府寻求停战，把军事失败责任推向即将议会化的政府。","fields":[{"label":"标题","value":"德国最高统帅部要求停战谈判"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1918年9月29日"},{"label":"地点","value":"斯帕大本营；柏林政治体系"},{"label":"主要国家","value":"德国、美国、法国、英国"},{"label":"一句话概括","value":"1918年9月德国最高统帅部突然要求文官政府寻求停战，把军事失败责任推向即将议会化的政府。"},{"label":"参与者","value":"兴登堡、鲁登道夫、威廉二世、帝国政府、即将组阁的马克斯·冯·巴登。"},{"label":"发生了什么","value":"百日攻势和保加利亚停战后，德国最高陆军统帅部判断战局已无法挽回。1918年9月29日，鲁登道夫和兴登堡要求立即以威尔逊十四点为基础寻求停战，并同时推动建立更具议会基础的新政府。军方此前主导战争决策，此时却把求和任务交给文官和议会多数。"},{"label":"为什么重要","value":"这是帝国崩溃的关键转折。军方承认战败现实，却通过让文官政府出面求和，为战后“背后一刀”叙事制造了政治空间。"},{"label":"前因","value":"德国春季攻势失败后，协约国百日攻势持续突破，保加利亚退出战争又使同盟国体系崩塌，德国军方认识到继续战争风险过高。"},{"label":"后果","value":"马克斯·冯·巴登内阁成立并向美国求和，十月改革加速推进；军方后来却把停战和战败责任转嫁给新政府和共和国政治家。"},{"label":"出处","value":"Encyclopaedia Britannica: World War I, The end of the German war；Deutsches Historisches Museum/LeMO: Revolution 1918/19；German History in Documents and Images: Prince Max of Baden and the Armistice。"}],"relationItems":["← 前因：一战百日攻势","← 前因：瓦尔达尔攻势","→ 后果：马克斯·冯·巴登内阁","→ 后果：德国“背后一刀”传说","↔ 相关：威尔逊十四点原则"],"relations":[{"text":"← 前因：一战百日攻势","id":"extra664"},{"text":"← 前因：瓦尔达尔攻势","id":"extra718"},{"text":"→ 后果：马克斯·冯·巴登内阁","id":"extra804"},{"text":"→ 后果：德国“背后一刀”传说","id":"extra623"},{"text":"↔ 相关：威尔逊十四点原则","id":"extra661"}],"source":"history","id":"extra803"},{"title":"马克斯·冯·巴登内阁","level":"B","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1918年10月3日—11月9日","place":"德意志帝国；柏林","summary":"马克斯·冯·巴登内阁试图在军事失败中完成议会化和求和，却很快被革命浪潮和帝制崩溃吞没。","fields":[{"label":"标题","value":"马克斯·冯·巴登内阁"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1918年10月3日—11月9日"},{"label":"地点","value":"德意志帝国；柏林"},{"label":"主要国家","value":"德国、美国"},{"label":"一句话概括","value":"马克斯·冯·巴登内阁试图在军事失败中完成议会化和求和，却很快被革命浪潮和帝制崩溃吞没。"},{"label":"参与者","value":"马克斯·冯·巴登、威廉二世、SPD、中央党、进步人民党、最高陆军统帅部、伍德罗·威尔逊政府。"},{"label":"发生了什么","value":"1918年10月，马克斯·冯·巴登出任帝国首相，组建包含议会多数派支持的政府，并向美国总统威尔逊请求停战谈判。内阁推动十月改革，使首相对帝国议会负责，试图把德国改造为议会君主制。但军事失败、停战条件、海军最后出击计划和革命扩散使内阁难以维持局势。11月9日，马克斯宣布威廉二世退位，并把首相职位交给艾伯特。"},{"label":"为什么重要","value":"这是德意志帝国从君主制向共和国过渡的短暂桥梁。它完成了迟到的议会化，却无法阻止帝制崩溃。"},{"label":"前因","value":"最高统帅部要求停战谈判后，旧帝国需要一个更能被协约国和国内议会接受的政府来承担求和任务。"},{"label":"后果","value":"十月改革没有保住君主制，水兵起义和工人士兵委员会扩散后，马克斯宣布皇帝退位并把权力交给社会民主党。"},{"label":"出处","value":"Encyclopaedia Britannica: Maximilian, prince of Baden；Deutsches Historisches Museum/LeMO: Revolution 1918/19；German History in Documents and Images: Prince Max of Baden and the Armistice。"}],"relationItems":["← 前因：德国最高统帅部要求停战谈判","→ 后果：德国1918年十月改革","→ 后果：德国皇帝威廉二世退位","→ 后果：德国十一月革命","↔ 相关：威尔逊十四点原则"],"relations":[{"text":"← 前因：德国最高统帅部要求停战谈判","id":"extra803"},{"text":"→ 后果：德国1918年十月改革","id":"extra805"},{"text":"→ 后果：德国皇帝威廉二世退位","id":"extra806"},{"text":"→ 后果：德国十一月革命","id":"extra666"},{"text":"↔ 相关：威尔逊十四点原则","id":"extra661"}],"source":"history","id":"extra804"},{"title":"德国1918年十月改革","level":"B","type":"制度/文本卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1918年10月","place":"德意志帝国","summary":"1918年十月改革把首相责任转向帝国议会，试图把帝国改造成议会君主制，但来得太晚。","fields":[{"label":"标题","value":"德国1918年十月改革"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1918年10月"},{"label":"地点","value":"德意志帝国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1918年十月改革把首相责任转向帝国议会，试图把帝国改造成议会君主制，但来得太晚。"},{"label":"制定方/签署方","value":"马克斯·冯·巴登内阁、帝国议会、联邦参议院、皇帝批准。"},{"label":"主要内容","value":"改革修改帝国宪制，使首相和政府需要帝国议会信任，限制皇帝单独宣战媾和权力，并把战争与外交责任部分议会化。"},{"label":"它试图解决什么问题","value":"德国希望以民主化姿态回应威尔逊和协约国，同时在国内把求和政府建立在议会多数基础上，缓解革命压力。"},{"label":"为什么重要","value":"它是德意志帝国迟到的宪政转型。如果它早几年发生，可能意味着君主制议会化；但在1918年10月，它已经被军事失败和群众革命追上。"},{"label":"争议/局限","value":"改革在旧政权崩溃前夕才实施，无法重建群众对君主制的信任，也使议会政党被迫承担战败和停战的政治成本。"},{"label":"造成的影响","value":"帝国形式上短暂成为议会君主制，但十一月革命和威廉二世退位很快把德国推向共和国。"},{"label":"出处","value":"German History in Documents and Images: October Reforms；Deutsches Historisches Museum/LeMO: Revolution 1918/19；Encyclopaedia Britannica: Weimar Republic。"}],"relationItems":["← 前因：马克斯·冯·巴登内阁","← 前因：德国帝国议会和平决议","→ 后果：德国皇帝威廉二世退位","→ 后果：魏玛共和国成立","↔ 相关：德意志帝国宪法"],"relations":[{"text":"← 前因：马克斯·冯·巴登内阁","id":"extra804"},{"text":"← 前因：德国帝国议会和平决议","id":"extra800"},{"text":"→ 后果：德国皇帝威廉二世退位","id":"extra806"},{"text":"→ 后果：魏玛共和国成立","id":"card7"},{"text":"↔ 相关：德意志帝国宪法","id":"extra624"}],"source":"history","id":"extra805"},{"title":"德国皇帝威廉二世退位","level":"B","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1918年11月9日","place":"柏林、斯帕、荷兰边境","summary":"1918年11月9日马克斯·冯·巴登宣布威廉二世退位，德意志帝国君主制由此终结。","fields":[{"label":"标题","value":"德国皇帝威廉二世退位"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1918年11月9日"},{"label":"地点","value":"柏林、斯帕、荷兰边境"},{"label":"主要国家","value":"德国、荷兰"},{"label":"一句话概括","value":"1918年11月9日马克斯·冯·巴登宣布威廉二世退位，德意志帝国君主制由此终结。"},{"label":"参与者","value":"威廉二世、马克斯·冯·巴登、弗里德里希·艾伯特、最高陆军统帅部、革命群众。"},{"label":"发生了什么","value":"十一月革命扩散到柏林时，威廉二世仍在斯帕大本营犹豫是否只放弃德皇称号而保留普鲁士王位。为了平息革命局势，首相马克斯·冯·巴登在未获威廉明确同意的情况下宣布皇帝和皇太子退位。威廉随后前往荷兰流亡。当天柏林先后出现共和国宣告，帝制权威迅速瓦解。"},{"label":"为什么重要","value":"这是1871年德意志帝国的终结点。它把军事失败、革命和宪政危机压缩在同一天，德国从君主制转向共和国。"},{"label":"前因","value":"德国军事失败、基尔水兵起义和工人士兵委员会扩散使君主制失去支撑，马克斯内阁已无法用十月改革保住皇位。"},{"label":"后果","value":"共和国在柏林被宣布，艾伯特接掌政府；威廉流亡荷兰，德国政治进入革命政府和魏玛制宪进程。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Revolution 1918/19；Encyclopaedia Britannica: William II, Role in World War I；German History in Documents and Images: Kaiser Wilhelm II on his Abdication。"}],"relationItems":["← 前因：马克斯·冯·巴登内阁","← 前因：德国基尔水兵起义","→ 后果：魏玛共和国成立","→ 后果：德国工人士兵委员会","↔ 相关：德国十一月革命"],"relations":[{"text":"← 前因：马克斯·冯·巴登内阁","id":"extra804"},{"text":"← 前因：德国基尔水兵起义","id":"extra665"},{"text":"→ 后果：魏玛共和国成立","id":"card7"},{"text":"→ 后果：德国工人士兵委员会","id":"extra807"},{"text":"↔ 相关：德国十一月革命","id":"extra666"}],"source":"history","id":"extra806"},{"title":"德国工人士兵委员会","level":"B","type":"组织/机构卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1918—1919年","place":"德国各大城市、军港和工业区","summary":"工人士兵委员会在十一月革命中接管地方权力，是帝制崩溃和共和国诞生之间的革命性组织形式。","fields":[{"label":"标题","value":"德国工人士兵委员会"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1918—1919年"},{"label":"地点","value":"德国各大城市、军港和工业区"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"工人士兵委员会在十一月革命中接管地方权力，是帝制崩溃和共和国诞生之间的革命性组织形式。"},{"label":"性质/类型","value":"革命委员会、地方权力机构、工人和士兵代表组织。"},{"label":"成立/解散时间","value":"1918年11月随基尔水兵起义和革命扩散大量出现；1919年魏玛制度稳定后逐步消退。"},{"label":"核心目标/宗旨","value":"结束战争、推翻旧军政权威、维持地方秩序，并在议会共和国或委员会共和国之间争夺革命方向。"},{"label":"关键人物（可选）","value":"各地工人、士兵代表；柏林革命工长、SPD和USPD成员在不同委员会中影响较大。"},{"label":"关键行动/事件","value":"从基尔扩散到全国，接管地方行政、军营和交通节点；1918年12月全国工人士兵委员会代表大会决定支持召开国民议会。"},{"label":"为什么重要","value":"它说明德国革命不是单纯由上层政党宣布共和国，而是由士兵和工人的地方行动摧毁旧秩序。魏玛共和国最终选择议会道路，也是在与委员会道路竞争中形成的。"},{"label":"争议/局限","value":"委员会内部高度分化，多数并不追求布尔什维克式政权；其组织松散，难以在全国层面持续行使统一权力。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Arbeiter- und Soldatenräte；Encyclopaedia Britannica: German Revolution 1918-1919；German History in Documents and Images: The Spread of the 1918 Revolution。"}],"relationItems":["← 前因：德国基尔水兵起义","← 前因：德国1918年一月罢工","→ 后果：魏玛共和国成立","→ 后果：德国艾伯特-格勒纳协议","↔ 相关：德国十一月革命"],"relations":[{"text":"← 前因：德国基尔水兵起义","id":"extra665"},{"text":"← 前因：德国1918年一月罢工","id":"extra802"},{"text":"→ 后果：魏玛共和国成立","id":"card7"},{"text":"→ 后果：德国艾伯特-格勒纳协议","id":"card6"},{"text":"↔ 相关：德国十一月革命","id":"extra666"}],"source":"history","id":"extra807"},{"title":"德国战时食品署","level":"C","type":"组织/机构卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1916—1919年","place":"德意志帝国；柏林及各地食品配给体系","summary":"德国战时食品署试图统一粮食供应和配给管理，却无法阻止一战后期严重饥荒和民众不满。","fields":[{"label":"标题","value":"德国战时食品署"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1916—1919年"},{"label":"地点","value":"德意志帝国；柏林及各地食品配给体系"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国战时食品署试图统一粮食供应和配给管理，却无法阻止一战后期严重饥荒和民众不满。"},{"label":"性质/类型","value":"战时食品供应和营养政策管理机构，1917年后升格为帝国食品署。"},{"label":"成立/解散时间","value":"1916年成立为 Kriegsernährungsamt；1917年成为 Reichsernährungsamt；战后早期继续影响食品管理。"},{"label":"核心目标/宗旨","value":"集中协调粮食采购、配给、价格、屠宰和替代食品政策，以维持军队和城市人口基本供应。"},{"label":"关键人物（可选）","value":"帝国内政和食品行政官员；地方食品办公室与配给机构共同执行。"},{"label":"关键行动/事件","value":"建立更统一的食品行政和配给规则，处理马铃薯歉收、肉类和脂肪短缺、公共厨房和城市供应危机。"},{"label":"为什么重要","value":"它说明德国后方危机不是单纯“没有食物”，而是封锁、农业劳动力短缺、运输、价格和行政能力共同失灵。国家越介入，越暴露治理能力不足。"},{"label":"争议/局限","value":"战时食品署成立较晚，权力和执行能力有限，无法克服1916—1917年芜菁冬天及其后的结构性粮食短缺。"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Industrie und Wirtschaft im Ersten Weltkrieg；Deutsche Digitale Bibliothek: Kriegsernährungsamt；Universität Heidelberg: Ein deutscher Hunger。"}],"relationItems":["← 前因：英国对德海上封锁","← 前因：一战总动员社会","→ 后果：德国“芜菁冬天”","→ 后果：德国1918年一月罢工","↔ 相关：德国战争原料部"],"relations":[{"text":"← 前因：英国对德海上封锁","id":"extra652"},{"text":"← 前因：一战总动员社会","id":"extra653"},{"text":"→ 后果：德国“芜菁冬天”","id":"extra657"},{"text":"→ 后果：德国1918年一月罢工","id":"extra802"},{"text":"↔ 相关：德国战争原料部","id":"extra795"}],"source":"history","id":"extra808"},{"title":"德意志帝国卫生署","level":"C","type":"组织/机构卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1876年成立；1918年后称帝国卫生署","place":"德国；柏林","summary":"德意志帝国卫生署是德国公共卫生、疾病监测和医学行政国家化的重要机构。","fields":[{"label":"标题","value":"德意志帝国卫生署"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1876年成立；1918年后称帝国卫生署"},{"label":"地点","value":"德国；柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德意志帝国卫生署是德国公共卫生、疾病监测和医学行政国家化的重要机构。"},{"label":"性质/类型","value":"帝国层面的公共卫生和医学行政机构。"},{"label":"成立/解散时间","value":"1876年作为帝国卫生署前身成立，魏玛后继续以Reichsgesundheitsamt名称存在。"},{"label":"核心目标/宗旨","value":"负责公共卫生、传染病、食品和兽医卫生等领域的调查、建议和行政支持。"},{"label":"关键人物（可选）","value":"罗伯特·科赫曾在帝国卫生署任职并推动细菌学研究。"},{"label":"关键行动/事件","value":"支持传染病研究、公共卫生调查和卫生行政专业化，成为德国国家公共卫生体系的核心节点之一。"},{"label":"为什么重要","value":"它说明德国医学现代化不只是实验室突破，也依赖国家机构把卫生知识转化为治理能力。"},{"label":"争议/局限","value":"帝国卫生行政仍受联邦结构、地方利益和城市基础设施差异制约，不能自动解决所有公共卫生危机。"},{"label":"出处","value":"Archivführer Deutsche Kolonialzeit: Reichsgesundheitsamt Bestand；Robert Koch Institute historical materials；Encyclopaedia Britannica: Robert Koch。"}],"relationItems":["↔ 相关：德国城市公共卫生运动","↔ 相关：罗伯特·科赫","→ 后果：德意志帝国汉堡霍乱疫情","→ 后果：德意志帝国种族卫生学会"],"relations":[{"text":"↔ 相关：德国城市公共卫生运动","id":"extra733"},{"text":"↔ 相关：罗伯特·科赫","id":"extra810"},{"text":"→ 后果：德意志帝国汉堡霍乱疫情","id":"extra812"},{"text":"→ 后果：德意志帝国种族卫生学会","id":"extra815"}],"source":"history","id":"extra809"},{"title":"罗伯特·科赫","level":"A","type":"人物卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"1843—1910年；研究高峰为1870—1890年代","place":"德国；柏林等地","summary":"罗伯特·科赫奠定细菌学和传染病病原学基础，使德国成为现代医学研究中心之一。","fields":[{"label":"标题","value":"罗伯特·科赫"},{"label":"分级","value":"A"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1843—1910年；研究高峰为1870—1890年代"},{"label":"地点","value":"德国；柏林等地"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"罗伯特·科赫奠定细菌学和传染病病原学基础，使德国成为现代医学研究中心之一。"},{"label":"生卒年/活跃年代","value":"1843年出生，1910年去世；1870年代至1890年代为医学研究高峰。"},{"label":"身份/职务","value":"德国医生、细菌学家，诺贝尔生理学或医学奖获得者。"},{"label":"关键贡献/作为","value":"研究炭疽病、结核病和霍乱，发展纯培养、染色和病原证明方法，1882年公布结核杆菌发现。"},{"label":"核心主张/立场","value":"以实验室证据确认特定微生物与特定疾病之间的因果关系。"},{"label":"为什么重要","value":"科赫把德国医学带入实验室细菌学时代，影响公共卫生、传染病防治和国家卫生机构建设。"},{"label":"争议/评价","value":"科赫的结核菌素治疗曾引发过度期待并遭遇失败，但不改变其病原学贡献的世界史地位。"},{"label":"关联事件","value":"罗伯特·科赫发现结核杆菌；汉堡霍乱疫情。"},{"label":"出处","value":"Encyclopaedia Britannica: Robert Koch；Encyclopaedia Britannica: Robert Koch, studies of tuberculosis and cholera；Robert Koch Institute: Robert Koch biography。"}],"relationItems":["← 前因：德意志帝国卫生署","→ 后果：罗伯特·科赫发现结核杆菌","↔ 相关：德国城市公共卫生运动"],"relations":[{"text":"← 前因：德意志帝国卫生署","id":"extra809"},{"text":"→ 后果：罗伯特·科赫发现结核杆菌","id":"extra811"},{"text":"↔ 相关：德国城市公共卫生运动","id":"extra733"}],"source":"history","id":"extra810"},{"title":"罗伯特·科赫发现结核杆菌","level":"A","type":"事件卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"1882年3月24日","place":"德国柏林","summary":"科赫公布结核杆菌发现，证明结核病由特定微生物引起，是现代病原学的重要节点。","fields":[{"label":"标题","value":"罗伯特·科赫发现结核杆菌"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1882年3月24日"},{"label":"地点","value":"德国柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"科赫公布结核杆菌发现，证明结核病由特定微生物引起，是现代病原学的重要节点。"},{"label":"参与者","value":"罗伯特·科赫、柏林生理学会、德国医学界和国际医学界。"},{"label":"发生了什么","value":"1882年3月24日，科赫在柏林发表研究，展示他如何染色、观察、培养并证明结核杆菌与结核病之间的关系。结核病当时是欧洲主要致死疾病之一，长期被视为体质、贫困或遗传问题。科赫的报告把结核病明确纳入传染病和微生物病因框架。"},{"label":"为什么重要","value":"它改变了结核病理解方式，也为后来的实验室诊断、公共卫生隔离和医学研究提供基础。"},{"label":"前因","value":"19世纪欧洲城市化、贫困住房和工厂劳动条件使结核病长期保持高死亡率，医学界急需把“痨病”从模糊体质解释转向可验证的病原学解释。与此同时，显微镜、染色技术和细菌培养方法进步，为实验室确认病因提供了条件。"},{"label":"后果","value":"结核病被纳入细菌学和公共卫生治理框架，德国医学声望上升，传染病研究更加依赖实验室证据。它也推动了结核筛查、疗养院制度和后续疫苗、药物研究，科赫本人后来获得诺贝尔奖。"},{"label":"出处","value":"Encyclopaedia Britannica: Robert Koch, Studies of tuberculosis；Encyclopaedia Britannica: Tuberculosis；PMC: Robert Koch, Centenary of the Discovery of the Tubercle Bacillus。"}],"relationItems":["← 前因：罗伯特·科赫","↔ 相关：德国城市公共卫生运动","→ 后果：德意志帝国卫生署"],"relations":[{"text":"← 前因：罗伯特·科赫","id":"extra810"},{"text":"↔ 相关：德国城市公共卫生运动","id":"extra733"},{"text":"→ 后果：德意志帝国卫生署","id":"extra809"}],"source":"history","id":"extra811"},{"title":"德意志帝国汉堡霍乱疫情","level":"B","type":"事件卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1892年8—10月","place":"德国汉堡","summary":"1892年汉堡霍乱疫情暴露城市供水、贫民住房和地方自治治理的严重缺陷。","fields":[{"label":"标题","value":"德意志帝国汉堡霍乱疫情"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1892年8—10月"},{"label":"地点","value":"德国汉堡"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1892年汉堡霍乱疫情暴露城市供水、贫民住房和地方自治治理的严重缺陷。"},{"label":"参与者","value":"汉堡市政当局、居民、罗伯特·科赫、帝国卫生力量、港口和贫民区人口。"},{"label":"发生了什么","value":"1892年夏秋，霍乱在汉堡爆发并迅速扩散。汉堡饮用水过滤不足、贫民区拥挤和市政反应迟缓加剧疫情。罗伯特·科赫到场调查并批评当地卫生条件。疫情造成大量死亡，也迫使汉堡加快水务、卫生和城市管理改革。"},{"label":"为什么重要","value":"它是帝国德国公共卫生史的标志性危机，说明医学知识必须配合城市基础设施和政治执行。"},{"label":"前因","value":"汉堡作为港口和贸易城市人口密集、流动频繁，贫民区住房拥挤，公共供水和污水处理没有跟上城市扩张。地方政府对现代水过滤设施推进迟缓，使被污染水源更容易把霍乱扩散为城市灾难。"},{"label":"后果","value":"疫情暴露了自由港城市自治、商业利益和公共卫生之间的冲突，迫使汉堡加快水过滤、污水处理和卫生行政改革。德国城市公共卫生治理的政治重要性随之上升，罗伯特·科赫等专家的权威也更受重视。"},{"label":"出处","value":"German History in Documents and Images: Cholera Epidemic in Hamburg (1892)；Geschichtsbuch Hamburg: Cholera 1892；Encyclopaedia Britannica: Cholera。"}],"relationItems":["← 前因：德国城市公共卫生运动","↔ 相关：罗伯特·科赫","↔ 相关：德意志帝国卫生署"],"relations":[{"text":"← 前因：德国城市公共卫生运动","id":"extra733"},{"text":"↔ 相关：罗伯特·科赫","id":"extra810"},{"text":"↔ 相关：德意志帝国卫生署","id":"extra809"}],"source":"history","id":"extra812"},{"title":"保罗·埃尔利希","level":"B","type":"人物卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"1854—1915年；研究高峰为1890年代至1910年代","place":"德国；柏林、法兰克福","summary":"保罗·埃尔利希推动免疫学和化学疗法，萨尔瓦散使靶向治疗成为现代医学想象。","fields":[{"label":"标题","value":"保罗·埃尔利希"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1854—1915年；研究高峰为1890年代至1910年代"},{"label":"地点","value":"德国；柏林、法兰克福"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"保罗·埃尔利希推动免疫学和化学疗法，萨尔瓦散使靶向治疗成为现代医学想象。"},{"label":"生卒年/活跃年代","value":"1854年出生，1915年去世；1908年获诺贝尔生理学或医学奖。"},{"label":"身份/职务","value":"德国医学科学家、免疫学家和化学疗法先驱。"},{"label":"关键贡献/作为","value":"研究染色、免疫、血清疗法和抗感染化学药物，提出“魔弹”式选择性治疗思路。"},{"label":"核心主张/立场","value":"希望用化学物质选择性攻击病原体而尽量减少对人体伤害。"},{"label":"为什么重要","value":"埃尔利希把德国医学从病原发现推进到药物治疗方向，连接实验室、工业制药和临床医学。"},{"label":"争议/评价","value":"早期化学疗法仍有毒性和使用限制，但其思路深刻影响现代药物研发。"},{"label":"关联事件","value":"保罗·埃尔利希萨尔瓦散（606号药物）。"},{"label":"出处","value":"Encyclopaedia Britannica: Paul Ehrlich；Nobel Prize: Paul Ehrlich facts；Georg-Speyer-Haus historical materials。"}],"relationItems":["← 前因：罗伯特·科赫发现结核杆菌","→ 后果：保罗·埃尔利希萨尔瓦散（606号药物）","↔ 相关：德国城市公共卫生运动"],"relations":[{"text":"← 前因：罗伯特·科赫发现结核杆菌","id":"extra811"},{"text":"→ 后果：保罗·埃尔利希萨尔瓦散（606号药物）","id":"extra814"},{"text":"↔ 相关：德国城市公共卫生运动","id":"extra733"}],"source":"history","id":"extra813"},{"title":"保罗·埃尔利希萨尔瓦散（606号药物）","level":"B","type":"概念/思潮卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"1909年发现疗效，1910年上市使用","place":"德国；法兰克福和德国制药工业体系","summary":"萨尔瓦散是治疗梅毒的早期化学疗法药物，象征实验医学和制药工业结合。","fields":[{"label":"标题","value":"保罗·埃尔利希萨尔瓦散（606号药物）"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1909年发现疗效，1910年上市使用"},{"label":"地点","value":"德国；法兰克福和德国制药工业体系"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"萨尔瓦散是治疗梅毒的早期化学疗法药物，象征实验医学和制药工业结合。"},{"label":"核心主张/思路","value":"用人工合成化学物质选择性杀伤病原体，从而治疗传染病。"},{"label":"提出者/代表人物（可选）","value":"保罗·埃尔利希、秦佐八郎及法兰克福研究团队。"},{"label":"它从何而来","value":"细菌学和免疫学已经证明疾病有特定病因，埃尔利希进一步寻找能针对病原体的“魔弹”。"},{"label":"典型表现","value":"606号化合物被用于治疗梅毒，商品名萨尔瓦散，成为现代化学疗法的重要早期案例。"},{"label":"为什么重要","value":"它显示德国医学现代化不仅是公共卫生制度，也包括实验室药物、企业生产和临床治疗的结合。"},{"label":"争议/局限","value":"萨尔瓦散使用复杂且有毒性，后来被更安全有效的药物替代。"},{"label":"出处","value":"Encyclopaedia Britannica: Paul Ehrlich；Science History Institute: Salvarsan and chemotherapy materials；Georg-Speyer-Haus historical materials。"}],"relationItems":["← 前因：保罗·埃尔利希","↔ 相关：魏玛德国性改革运动","→ 后果：现代化学疗法"],"relations":[{"text":"← 前因：保罗·埃尔利希","id":"extra813"},{"text":"↔ 相关：魏玛德国性改革运动","id":"card85"}],"source":"history","id":"extra814"},{"title":"德意志帝国种族卫生学会","level":"C","type":"组织/机构卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1905年成立","place":"德国；柏林等地","summary":"种族卫生学会把优生学和社会达尔文主义组织化，为后来纳粹种族医学提供思想资源。","fields":[{"label":"标题","value":"德意志帝国种族卫生学会"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1905年成立"},{"label":"地点","value":"德国；柏林等地"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"种族卫生学会把优生学和社会达尔文主义组织化，为后来纳粹种族医学提供思想资源。"},{"label":"性质/类型","value":"优生学和种族卫生思想组织。"},{"label":"成立/解散时间","value":"1905年由阿尔弗雷德·普勒茨等人创立，后来在魏玛和纳粹时期继续产生影响。"},{"label":"核心目标/宗旨","value":"推广所谓“种族卫生”理念，主张通过生育、遗传和人口政策改善民族“质量”。"},{"label":"关键人物（可选）","value":"阿尔弗雷德·普勒茨、弗里茨·伦茨、欧根·菲舍尔等。"},{"label":"关键行动/事件","value":"传播优生学话语，推动医学、人口学和社会政策中的遗传主义解释。"},{"label":"为什么重要","value":"它说明纳粹优生政策并非凭空出现，而是吸收了帝国和魏玛时期已经存在的科学化种族话语。"},{"label":"争议/局限","value":"优生学以科学外观包装社会偏见和等级观念，后来在纳粹国家中转化为强制绝育和杀戮政策。"},{"label":"出处","value":"Springer: Public health and social movements, Alfred Ploetz and racial hygiene；Encyclopaedia Britannica: Eugenics；German Historical Institute references on racial hygiene。"}],"relationItems":["← 前因：德国城市公共卫生运动","↔ 相关：纳粹优生政策","→ 后果：纳粹《遗传病后代预防法》"],"relations":[{"text":"← 前因：德国城市公共卫生运动","id":"extra733"},{"text":"↔ 相关：纳粹优生政策","id":"extra118"},{"text":"→ 后果：纳粹《遗传病后代预防法》","id":"extra127"}],"source":"history","id":"extra815"},{"title":"德意志帝国《帝国报刊法》","level":"B","type":"制度/文本卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1874年5月7日","place":"德意志帝国","summary":"1874年《帝国报刊法》统一了帝国新闻出版规则，形式上削弱预防审查，却仍保留事后追诉和政治压制空间。","fields":[{"label":"标题","value":"德意志帝国《帝国报刊法》"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1874年5月7日"},{"label":"地点","value":"德意志帝国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1874年《帝国报刊法》统一了帝国新闻出版规则，形式上削弱预防审查，却仍保留事后追诉和政治压制空间。"},{"label":"制定方/签署方","value":"德意志帝国国会与帝国政府。"},{"label":"主要内容","value":"法律把各邦分散的报刊管理规则统一到帝国层面，取消许多预防性许可和审查限制，规定出版人、编辑、印刷人责任，并保留对违法出版物的扣押、诉讼和处罚机制。"},{"label":"它试图解决什么问题","value":"统一后的德国需要全国性新闻出版规则；自由派希望摆脱1848/49革命失败后形成的审查束缚，政府则希望把报刊自由纳入可追责的法律框架。"},{"label":"为什么重要","value":"它让帝国时期报刊市场获得更清晰的法律环境，推动大众报纸、政党报刊和商业出版扩张，同时也说明“新闻自由”仍受国家安全、秩序和政治诉讼限制。"},{"label":"争议/局限","value":"法律并没有消除国家对新闻界的压力。政府可以通过诉讼、查禁、紧急措施和特别法继续压制社会主义者、天主教派或反政府言论。"},{"label":"造成的影响","value":"帝国报刊迅速发展，政治动员和公共舆论更依赖新闻媒介；后来的反社会党人法、战时新闻控制和魏玛新闻争议都在这个基础上展开。"},{"label":"出处","value":"German History in Documents and Images, Imperial Press Law (May 7, 1874)；DHM LeMO, Gesetz über die Pressefreiheit, 1874。"}],"relationItems":["← 前因：1848年德意志革命","→ 后果：德国反社会党人法","↔ 相关：德意志帝国社会民主党报刊网络","↔ 相关：德国沃尔夫电报局","↔ 同时期参考：德意志帝国国会"],"relations":[{"text":"← 前因：1848年德意志革命","id":"extra490"},{"text":"→ 后果：德国反社会党人法","id":"extra627"},{"text":"↔ 相关：德意志帝国社会民主党报刊网络","id":"extra822"},{"text":"↔ 相关：德国沃尔夫电报局","id":"extra817"}],"source":"history","id":"extra816"},{"title":"德国沃尔夫电报局","level":"C","type":"组织/机构卡","tags":["文化与思想","战争与外交"],"mainTag":"文化与思想","subTag":"战争与外交","timeText":"1849—1934年","place":"柏林；德意志各地及国际新闻网络","summary":"沃尔夫电报局是德国最重要的早期通讯社，把电报技术、报纸市场和国家外交宣传连接起来。","fields":[{"label":"标题","value":"德国沃尔夫电报局"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1849—1934年"},{"label":"地点","value":"柏林；德意志各地及国际新闻网络"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"沃尔夫电报局是德国最重要的早期通讯社，把电报技术、报纸市场和国家外交宣传连接起来。"},{"label":"性质/类型","value":"商业通讯社，后期带有半官方新闻渠道性质。"},{"label":"成立/解散时间","value":"1849年由伯恩哈德·沃尔夫在柏林创立；1934年被纳粹时期的新通讯社体系取代。"},{"label":"核心目标/宗旨","value":"用电报收集、转发国内外新闻，为报纸、金融市场和政府相关信息流通提供快速新闻服务。"},{"label":"关键人物","value":"伯恩哈德·沃尔夫。"},{"label":"关键行动/事件","value":"与哈瓦斯、路透等欧洲通讯社一起塑造国际新闻交换格局；德意志帝国时期成为德国国内外新闻流通的重要节点；一战期间更明显承担政府政策和战争信息传播功能。"},{"label":"为什么重要","value":"它说明现代政治不只是靠议会和军队运行，也靠新闻基础设施运行。通讯社决定哪些消息能快速进入报纸，从而影响民众、市场和外交舆论。"},{"label":"争议/局限","value":"通讯社依赖电报线路、订户和政府关系，容易在战争和危机中变成半官方宣传渠道，新闻独立性有限。"},{"label":"出处","value":"Britannica, Wolff Telegraphic Bureau；1914-1918-Online, Wolff Telegraph Bureau。"}],"relationItems":["← 前因：电报通信网络扩张","→ 后果：德国战时新闻宣传","↔ 相关：德意志帝国《帝国报刊法》","↔ 相关：德国齐默尔曼电报","↔ 同时期参考：路透社"],"relations":[{"text":"← 前因：电报通信网络扩张","id":"extra952"},{"text":"↔ 相关：德意志帝国《帝国报刊法》","id":"extra816"},{"text":"↔ 相关：德国齐默尔曼电报","id":"extra659"}],"source":"history","id":"extra817"},{"title":"德意志帝国古典文理中学","level":"C","type":"概念/思潮卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"19世纪—1918年","place":"德意志帝国","summary":"古典文理中学是德国精英教育的重要通道，以古典语言和大学预备为核心，连接官僚、专业阶层和文化资本。","fields":[{"label":"标题","value":"德意志帝国古典文理中学"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"19世纪—1918年"},{"label":"地点","value":"德意志帝国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"古典文理中学是德国精英教育的重要通道，以古典语言和大学预备为核心，连接官僚、专业阶层和文化资本。"},{"label":"核心主张/思路","value":"通过拉丁文、希腊文、人文学科和严格考试训练，把学生送入大学、专业职业和国家官僚体系。"},{"label":"提出者/代表人物（可选）","value":"不是单一人物提出，而是普鲁士和德意志各邦长期教育传统的一部分。"},{"label":"它从何而来","value":"19世纪德意志教育改革把中学毕业考试、大学入学资格和国家职业资格逐渐绑定，古典文理中学由此成为社会上升和精英再生产的制度通道。"},{"label":"典型表现","value":"课程重视古典语言、历史和文学；学生通过毕业考试取得大学入学资格；学校身份常与中产阶级家庭、官员家庭和专业阶层期待相连。"},{"label":"为什么重要","value":"它解释了帝国德国为何能形成高水平大学和专业官僚，同时也解释了教育机会如何被阶层、性别和地区差异限制。"},{"label":"争议/局限","value":"古典教育被批评过于偏重人文学术和精英筛选，不一定适应工业化、技术教育和商业社会需要；女性和工人家庭子女进入渠道尤其有限。"},{"label":"出处","value":"Britannica, Education: Spencer's scientism；Britannica, Western education in the 19th century。"}],"relationItems":["← 前因：德国洪堡大学模式","→ 后果：德意志帝国研究型大学扩张","↔ 相关：德意志帝国实科中学","↔ 相关：德意志帝国职业教育与学徒制","↔ 同时期参考：英国公学教育"],"relations":[{"text":"← 前因：德国洪堡大学模式","id":"extra515"},{"text":"→ 后果：德意志帝国研究型大学扩张","id":"extra821"},{"text":"↔ 相关：德意志帝国实科中学","id":"extra819"},{"text":"↔ 相关：德意志帝国职业教育与学徒制","id":"extra820"}],"source":"history","id":"extra818"},{"title":"德意志帝国实科中学","level":"C","type":"概念/思潮卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"19世纪—1918年","place":"德意志帝国","summary":"实科中学以现代语言、数学、自然科学和商业技术知识为重点，回应工业化社会对非古典教育的需求。","fields":[{"label":"标题","value":"德意志帝国实科中学"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"19世纪—1918年"},{"label":"地点","value":"德意志帝国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"实科中学以现代语言、数学、自然科学和商业技术知识为重点，回应工业化社会对非古典教育的需求。"},{"label":"核心主张/思路","value":"中等教育不应只服务古典人文学术，也要服务工业、商业、工程和现代行政需要。"},{"label":"提出者/代表人物（可选）","value":"由各邦教育行政、城市中产阶层和工业化需求共同推动。"},{"label":"它从何而来","value":"工业化扩张后，传统古典文理中学无法覆盖技术、商业和应用科学训练需求，实科中学因此获得更大社会空间。"},{"label":"典型表现","value":"课程更重视数学、自然科学、现代外语、地理和应用知识；毕业生可进入技术学校、商业岗位和部分高等教育路径。"},{"label":"为什么重要","value":"它体现德国教育体系在精英人文传统和工业技术需求之间的调整，是理解德国工程、化学和工业竞争力的重要背景。"},{"label":"争议/局限","value":"实科中学的社会声望和大学通道长期低于古典文理中学，教育分流也容易把阶层差异制度化。"},{"label":"出处","value":"Britannica, Education: Spencer's scientism；Britannica, Western education in the 19th century。"}],"relationItems":["← 前因：工业化时代的德国城市社会","→ 后果：德意志帝国研究型大学扩张","↔ 相关：德意志帝国古典文理中学","↔ 相关：德意志帝国职业教育与学徒制","↔ 同时期参考：第二次工业革命"],"relations":[{"text":"← 前因：工业化时代的德国城市社会","id":"extra934"},{"text":"→ 后果：德意志帝国研究型大学扩张","id":"extra821"},{"text":"↔ 相关：德意志帝国古典文理中学","id":"extra818"},{"text":"↔ 相关：德意志帝国职业教育与学徒制","id":"extra820"},{"text":"↔ 同时期参考：第二次工业革命","id":"extra954"}],"source":"history","id":"extra819"},{"title":"德意志帝国职业教育与学徒制","level":"B","type":"概念/思潮卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"19世纪后期—1918年","place":"德意志帝国","summary":"职业教育与学徒制把企业训练、行业规范和补习学校结合起来，成为德国工业社会技能培养的重要基础。","fields":[{"label":"标题","value":"德意志帝国职业教育与学徒制"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"19世纪后期—1918年"},{"label":"地点","value":"德意志帝国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"职业教育与学徒制把企业训练、行业规范和补习学校结合起来，成为德国工业社会技能培养的重要基础。"},{"label":"核心主张/思路","value":"年轻人通过企业或手工业作坊学徒训练获得职业技能，同时接受学校或行业组织提供的基础教育和职业规范训练。"},{"label":"提出者/代表人物（可选）","value":"并非单一理论产物，而是行会传统、手工业组织、企业需求和国家教育政策共同塑造。"},{"label":"它从何而来","value":"中世纪以来德意志手工业学徒传统长期存在；19世纪工业化后，城市、企业和国家把学徒训练同补习学校、行业监管和技术教育连接起来。"},{"label":"典型表现","value":"学徒在工作场所学习具体技能，地方或行业学校补充读写、计算、职业伦理和公民教育；手工业和工业部门都逐渐纳入制度化训练。"},{"label":"为什么重要","value":"它为德国提供了大量熟练劳动力，是理解德国制造业、社会流动和工人阶层分化的关键机制。"},{"label":"争议/局限","value":"学徒制可能强化行业等级和性别分工，也容易把工人早早纳入劳动市场；不同地区、行业和企业的训练质量并不一致。"},{"label":"出处","value":"Cambridge Core, Actors and Practices of German Apprenticeship, Fifteenth-Nineteenth Centuries；Cedefop, Apprenticeship schemes in Germany。"}],"relationItems":["← 前因：德国手工业行会传统","→ 后果：德意志帝国工业竞争力","↔ 相关：德意志帝国实科中学","↔ 相关：德国工人阶级形成","↔ 同时期参考：英国工厂学徒制度"],"relations":[{"text":"↔ 相关：德意志帝国实科中学","id":"extra819"},{"text":"↔ 相关：德国工人阶级形成","id":"extra941"}],"source":"history","id":"extra820"},{"title":"德意志帝国研究型大学扩张","level":"B","type":"概念/思潮卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1871—1918年","place":"德意志帝国各大学城市","summary":"帝国时期德国大学把科研、实验室和博士训练推向高峰，成为国际高等教育改革的重要样板。","fields":[{"label":"标题","value":"德意志帝国研究型大学扩张"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1871—1918年"},{"label":"地点","value":"德意志帝国各大学城市"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"帝国时期德国大学把科研、实验室和博士训练推向高峰，成为国际高等教育改革的重要样板。"},{"label":"核心主张/思路","value":"大学不只是传授已有知识，还应生产新知识；教授、实验室、研讨班和博士训练共同构成现代研究体制。"},{"label":"提出者/代表人物（可选）","value":"延续洪堡大学理念，并由帝国时期各大学、国家财政、工业需求和教授群体共同扩展。"},{"label":"它从何而来","value":"19世纪初大学改革确立研究与教学结合原则；帝国统一和工业化带来更大的财政、技术和科学需求，使研究型大学获得扩张条件。"},{"label":"典型表现","value":"自然科学和医学实验室扩张，博士训练制度化，德国大学吸引国际学生，美国等国借鉴德国研究生教育模式。"},{"label":"为什么重要","value":"它把德国放到世界科学史和高等教育史的中心位置，解释了德国在化学、医学、物理和历史学等领域的国际影响。"},{"label":"争议/局限","value":"大学自治并不等于政治中立，教授群体常与国家主义、性别排斥和阶层门槛相连；实践技术教育与传统学术声望之间也有张力。"},{"label":"出处","value":"Britannica, Education: Spencer's scientism；Britannica, Western education in the 19th century。"}],"relationItems":["← 前因：德国洪堡大学模式","→ 后果：罗伯特·科赫","↔ 相关：德意志帝国古典文理中学","↔ 相关：德意志帝国女性大学入学开放","↔ 同时期参考：美国研究型大学兴起"],"relations":[{"text":"← 前因：德国洪堡大学模式","id":"extra515"},{"text":"→ 后果：罗伯特·科赫","id":"extra810"},{"text":"↔ 相关：德意志帝国古典文理中学","id":"extra818"},{"text":"↔ 相关：德意志帝国女性大学入学开放","id":"extra823"}],"source":"history","id":"extra821"},{"title":"德意志帝国社会民主党报刊网络","level":"C","type":"组织/机构卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1870年代—1918年","place":"德意志帝国各工业城市","summary":"社会民主党报刊网络把工人读者、政党组织和日常政治教育连接起来，是帝国大众政治的重要传播渠道。","fields":[{"label":"标题","value":"德意志帝国社会民主党报刊网络"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1870年代—1918年"},{"label":"地点","value":"德意志帝国各工业城市"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"社会民主党报刊网络把工人读者、政党组织和日常政治教育连接起来，是帝国大众政治的重要传播渠道。"},{"label":"性质/类型","value":"政党报刊和工人运动媒体网络。"},{"label":"成立/解散时间","value":"19世纪70年代逐步形成；反社会党人法时期遭压制，1890年后迅速恢复和扩张。"},{"label":"核心目标/宗旨","value":"传播社会主义和社会民主主义立场，报道劳工、选举、议会和工会消息，为工人阶层提供政治教育和组织动员。"},{"label":"关键人物（可选）","value":"与德国社会民主党地方组织、编辑群体和《前进报》等党报相关。"},{"label":"关键行动/事件","value":"反社会党人法期间许多出版物被查禁或转入地下；法律废止后，党报、讽刺刊物和地方报纸成为SPD扩大群众基础的重要工具。"},{"label":"为什么重要","value":"它说明帝国德国的大众政治并不只发生在议会席位上，也发生在报纸订阅、阅读小组、酒馆讨论和地方党组织之间。"},{"label":"争议/局限","value":"党报容易被政府追诉，也可能形成封闭政治信息环境；战时审查和SPD内部路线分裂削弱了统一传播效果。"},{"label":"出处","value":"Hamburg State and University Library / IFLA, Retrodigitization of Vorwärts；DBIS, Historische Presse der deutschen Sozialdemokratie online。"}],"relationItems":["← 前因：德国反社会党人法","→ 后果：德国社会民主党成为群众性政党","↔ 相关：德意志帝国《帝国报刊法》","↔ 相关：德国工人阶级形成","↔ 同时期参考：欧洲社会主义报刊文化"],"relations":[{"text":"← 前因：德国反社会党人法","id":"extra627"},{"text":"↔ 相关：德意志帝国《帝国报刊法》","id":"extra816"},{"text":"↔ 相关：德国工人阶级形成","id":"extra941"}],"source":"history","id":"extra822"},{"title":"德意志帝国女性大学入学开放","level":"C","type":"事件卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"1900—1908年前后","place":"德意志帝国各邦大学","summary":"20世纪初德国各邦逐步允许女性正式进入大学学习，改变了高等教育长期排斥女性的制度边界。","fields":[{"label":"标题","value":"德意志帝国女性大学入学开放"},{"label":"分级","value":"C"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1900—1908年前后"},{"label":"地点","value":"德意志帝国各邦大学"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"20世纪初德国各邦逐步允许女性正式进入大学学习，改变了高等教育长期排斥女性的制度边界。"},{"label":"参与者","value":"各邦教育行政、大学、女性教育运动者、申请入学的女性学生。"},{"label":"发生了什么","value":"19世纪末德国女性通常只能以旁听生身份进入大学课堂，正式注册和取得学位的权利受到各邦制度限制。1900年巴登率先允许女性正式入学，随后其他邦陆续跟进；到1908年前后，普鲁士等关键邦也开放女性大学注册，使女性进入大学从例外请求变成制度化可能。"},{"label":"为什么重要","value":"它把女性教育权、专业职业资格和现代中产阶级形成联系起来，为女性进入医学、教育、学术和公共职业打开通道。"},{"label":"前因","value":"19世纪女性教育运动、女子中学发展和中产阶级职业需求不断挑战“女性不适合高等学术”的观念；同时，德国研究型大学扩张也使大学入学资格问题更显突出。"},{"label":"后果","value":"女性大学生数量逐步增加，但性别偏见、职业壁垒和家庭角色期待仍限制她们的发展；魏玛时期女性政治权利和职业参与扩大时，高等教育开放成为重要前提。"},{"label":"出处","value":"German History in Documents and Images, Female University Students (1908)；Britannica, Western education in the 19th century。"}],"relationItems":["← 前因：德意志帝国古典文理中学","→ 后果：魏玛“新女性”","↔ 相关：德意志帝国研究型大学扩张","↔ 相关：德国妇女运动","↔ 同时期参考：英国女性高等教育扩张"],"relations":[{"text":"← 前因：德意志帝国古典文理中学","id":"extra818"},{"text":"→ 后果：魏玛“新女性”","id":"card32"},{"text":"↔ 相关：德意志帝国研究型大学扩张","id":"extra821"},{"text":"↔ 相关：德国妇女运动","id":"extra684"}],"source":"history","id":"extra823"},{"title":"德意志帝国强制民事婚姻制度","level":"C","type":"制度/文本卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1875年起","place":"德意志帝国","summary":"1875年德国确立国家承认婚姻须经民事登记的制度，把婚姻合法性从教会仪式转移到国家登记。","fields":[{"label":"标题","value":"德意志帝国强制民事婚姻制度"},{"label":"分级","value":"C"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1875年起"},{"label":"地点","value":"德意志帝国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1875年德国确立国家承认婚姻须经民事登记的制度，把婚姻合法性从教会仪式转移到国家登记。"},{"label":"制定方/签署方","value":"德意志帝国立法机关与帝国政府。"},{"label":"主要内容","value":"法律要求婚姻必须经过民事登记程序才获得国家法律承认，教会婚礼可以保留为宗教仪式，但不能替代国家法上的婚姻成立。"},{"label":"它试图解决什么问题","value":"新帝国希望把出生、婚姻、死亡等人口事务纳入国家行政管理，并削弱教会对家庭法和身份登记的控制。"},{"label":"为什么重要","value":"它是现代国家把私人生活纳入法律和行政体系的典型节点，也体现文化斗争并不只发生在讲坛和议会，还深入婚姻、户籍和家庭制度。"},{"label":"争议/局限","value":"天主教和保守派认为这削弱宗教婚姻神圣性；国家法承认婚姻并不意味着性别平等，家庭结构仍由父权和传统民法原则支配。"},{"label":"造成的影响","value":"民事登记成为德国婚姻制度的基础，后来的婚姻、离婚、继承和人口统计都依赖这一法律行政框架。"},{"label":"出处","value":"Law Library of Congress, State Recognition of Religious Marriages；German legal history summaries on civil marriage since 1875。"}],"relationItems":["← 前因：德意志帝国文化斗争","→ 后果：德国民法典","↔ 相关：德国中央党","↔ 相关：德国妇女运动","↔ 同时期参考：法国民事婚姻制度"],"relations":[{"text":"← 前因：德意志帝国文化斗争","id":"extra626"},{"text":"→ 后果：德国民法典","id":"extra720"},{"text":"↔ 相关：德国中央党","id":"extra673"},{"text":"↔ 相关：德国妇女运动","id":"extra684"}],"source":"history","id":"extra824"},{"title":"德意志帝国现代政治反犹主义","level":"B","type":"概念/思潮卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1870年代末—1918年","place":"德意志帝国","summary":"帝国时期反犹主义从传统宗教偏见转向民族、种族和社会危机话语，为后来极右政治提供了重要语言资源。","fields":[{"label":"标题","value":"德意志帝国现代政治反犹主义"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1870年代末—1918年"},{"label":"地点","value":"德意志帝国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"帝国时期反犹主义从传统宗教偏见转向民族、种族和社会危机话语，为后来极右政治提供了重要语言资源。"},{"label":"核心主张/思路","value":"把犹太人描绘成德国民族、经济秩序、新闻舆论或现代社会危机的“外来威胁”，并以民族主义、种族主义或反自由主义语言包装排斥诉求。"},{"label":"提出者/代表人物（可选）","value":"威廉·马尔、海因里希·冯·特赖奇克、奥托·伯克尔、狄奥多尔·弗里奇等反犹宣传者。"},{"label":"它从何而来","value":"犹太人法律解放、城市化、金融资本发展、自由主义政治和经济危机共同制造了社会焦虑，反犹宣传把这些焦虑转嫁到犹太人身上。"},{"label":"典型表现","value":"1879年前后“反犹主义”一词在德国政治语境中流行；反犹联盟和小党出现；大学、报刊、乡村选举和民族主义社团中出现反犹煽动。"},{"label":"为什么重要","value":"它不是纳粹凭空发明的观念，而是19世纪晚期欧洲民族主义、种族思想和大众政治结合的结果，是理解纳粹反犹主义前史的重要卡片。"},{"label":"争议/局限","value":"帝国时期反犹党派影响有限，许多德国犹太人仍高度融入社会；不能把1870年代后的全部德国政治简单等同于纳粹主义前奏。"},{"label":"出处","value":"DHM LeMO, Antisemitische Parteien；Cambridge Core, Anti-Philosemitism and Anti-Antisemitism in Imperial Germany；Britannica, Antisemitism。"}],"relationItems":["← 前因：德意志帝国成立","→ 后果：纳粹反犹主义","↔ 相关：德国中央党","↔ 相关：德意志帝国种族卫生学会","↔ 同时期参考：法国德雷福斯事件"],"relations":[{"text":"← 前因：德意志帝国成立","id":"extra621"},{"text":"↔ 相关：德国中央党","id":"extra673"},{"text":"↔ 相关：德意志帝国种族卫生学会","id":"extra815"}],"source":"history","id":"extra825"},{"title":"德国足球协会成立","level":"C","type":"事件卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"1900年1月28日","place":"莱比锡","summary":"1900年德国足球协会在莱比锡成立，把分散足球俱乐部纳入全国组织，标志足球从校园和地方社团走向全国运动。","fields":[{"label":"标题","value":"德国足球协会成立"},{"label":"分级","value":"C"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1900年1月28日"},{"label":"地点","value":"莱比锡"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"1900年德国足球协会在莱比锡成立，把分散足球俱乐部纳入全国组织，标志足球从校园和地方社团走向全国运动。"},{"label":"参与者","value":"来自德国各地的足球俱乐部代表；德国足球协会创始成员。"},{"label":"发生了什么","value":"19世纪末足球在德国逐渐从英国输入的学校和俱乐部运动变成城市青年、学生和中产社团活动。1900年1月28日，各地俱乐部代表在莱比锡集会，成立德国足球协会，开始统一比赛规则、组织全国赛事并代表德国足球参与国际交流。"},{"label":"为什么重要","value":"足球协会的成立说明现代大众体育需要全国性组织、规则和赛事网络。它也为20世纪德国足球的大众化、媒体化和国家象征意义奠定基础。"},{"label":"前因","value":"德国体操运动长期占据身体教育主导地位，但19世纪末英式足球在学校、港口和城市俱乐部中扩散；地方比赛增多后，统一规则和全国协调的需求上升。"},{"label":"后果","value":"德国足球在1903年举行首届全国冠军赛，魏玛时期进一步大众化；但职业化问题长期受到业余主义和体育道德观念限制。"},{"label":"出处","value":"DFB, Historie: 1900 Gründung des DFB；UEFA, Germany National Association overview。"}],"relationItems":["← 前因：德国体操运动","→ 后果：魏玛德国足球职业化争议","↔ 相关：魏玛德国大众体育文化","↔ 相关：德意志帝国工人体育运动","↔ 同时期参考：英格兰足球联赛"],"relations":[{"text":"← 前因：德国体操运动","id":"extra517"},{"text":"→ 后果：魏玛德国足球职业化争议","id":"card182"},{"text":"↔ 相关：魏玛德国大众体育文化","id":"card86"},{"text":"↔ 相关：德意志帝国工人体育运动","id":"extra827"}],"source":"history","id":"extra826"},{"title":"德意志帝国工人体育运动","level":"C","type":"概念/思潮卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1893—1933年","place":"德意志帝国；魏玛共和国","summary":"工人体育运动把体操、足球和社团生活纳入劳工文化，形成区别于民族主义体育组织的社会主义身体政治。","fields":[{"label":"标题","value":"德意志帝国工人体育运动"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1893—1933年"},{"label":"地点","value":"德意志帝国；魏玛共和国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"工人体育运动把体操、足球和社团生活纳入劳工文化，形成区别于民族主义体育组织的社会主义身体政治。"},{"label":"核心主张/思路","value":"体育不应只服务民族主义、军事训练或中产娱乐，也应服务工人健康、团结、组织能力和民主社团生活。"},{"label":"提出者/代表人物（可选）","value":"工人体育俱乐部、社会民主党周边组织、1893年成立的工人体操联盟及其后继组织。"},{"label":"它从何而来","value":"反社会党人法废止后，工人阶级社团活动扩大；民族主义体操组织排斥社会主义者，促使工人另建自己的体育组织。"},{"label":"典型表现","value":"工人体育俱乐部、体操节、足球队、报刊、训练学校和与社会民主党、工会相连的地方社团网络。"},{"label":"为什么重要","value":"它说明体育也是阶级政治和文化认同的一部分。德国现代社会不是只有军队操练和奥运竞技，还有工人用体育建立自己的公共生活。"},{"label":"争议/局限","value":"工人体育内部也有社民党和共产党路线分裂；纳粹上台后，独立工人体育组织被取缔或纳入纳粹体育体系。"},{"label":"出处","value":"bpb, 150 Jahre SPD - 150 Jahre Arbeiterturn- und Sportbewegung；Deutschlandfunk, Sport unter roten Fahnen。"}],"relationItems":["← 前因：反社会党人法废止","→ 后果：魏玛德国工人体育联盟","↔ 相关：德国足球协会成立","↔ 相关：魏玛德国大众体育文化","↔ 同时期参考：欧洲社会主义体育运动"],"relations":[{"text":"→ 后果：魏玛德国工人体育联盟","id":"card181"},{"text":"↔ 相关：德国足球协会成立","id":"extra826"},{"text":"↔ 相关：魏玛德国大众体育文化","id":"card86"}],"source":"history","id":"extra827"},{"title":"德国AEG电气公司","level":"B","type":"组织/机构卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"1883年创立；1887年改名为AEG","place":"柏林；德意志帝国及国际市场","summary":"AEG是帝国德国电气工业的代表企业之一，把发电、照明、电车和工业设计连接成现代电气生活图景。","fields":[{"label":"标题","value":"德国AEG电气公司"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1883年创立；1887年改名为AEG"},{"label":"地点","value":"柏林；德意志帝国及国际市场"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"AEG是帝国德国电气工业的代表企业之一，把发电、照明、电车和工业设计连接成现代电气生活图景。"},{"label":"性质/类型","value":"电气工业企业。"},{"label":"成立/解散时间","value":"1883年由埃米尔·拉特瑙创立德国爱迪生公司，1887年改名为Allgemeine Elektricitäts-Gesellschaft（AEG）。"},{"label":"核心目标/宗旨","value":"生产和推广电灯、电机、发电设备、电车和家用电器，把电力技术转化为城市基础设施和消费品。"},{"label":"关键人物（可选）","value":"埃米尔·拉特瑙、瓦尔特·拉特瑙、彼得·贝伦斯。"},{"label":"关键行动/事件","value":"参与柏林和德国城市电气化，发展电车和工业电气设备；20世纪初通过企业形象、建筑和产品设计推动现代工业设计。"},{"label":"为什么重要","value":"AEG说明第二次工业革命中的德国不只是钢铁和煤炭强国，也是电气、设计和城市现代性的实验场。"},{"label":"争议/局限","value":"电气化依赖资本、专利、城市特许和劳工组织，企业扩张也伴随垄断、工人管理和军工经济问题。"},{"label":"出处","value":"AEG company history；Encyclopaedia.com, Allgemeine Elektricitäts Gesellschaft AEG；Britannica, Peter Behrens。"}],"relationItems":["← 前因：第二次工业革命","→ 后果：德意志帝国城市电车网络","↔ 相关：西门子与德国电气工业","↔ 相关：德意志制造联盟","↔ 同时期参考：美国通用电气公司"],"relations":[{"text":"← 前因：第二次工业革命","id":"extra954"},{"text":"→ 后果：德意志帝国城市电车网络","id":"extra832"},{"text":"↔ 相关：西门子与德国电气工业","id":"extra682"},{"text":"↔ 相关：德意志制造联盟","id":"extra724"}],"source":"history","id":"extra828"},{"title":"BASF与德国染料工业","level":"B","type":"组织/机构卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"1865年创立；19世纪后期快速扩张","place":"曼海姆、路德维希港；德意志帝国","summary":"BASF从合成染料企业成长为德国化学工业巨头，体现帝国德国科学、大学和工业结合的竞争力。","fields":[{"label":"标题","value":"BASF与德国染料工业"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1865年创立；19世纪后期快速扩张"},{"label":"地点","value":"曼海姆、路德维希港；德意志帝国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"BASF从合成染料企业成长为德国化学工业巨头，体现帝国德国科学、大学和工业结合的竞争力。"},{"label":"性质/类型","value":"化学工业企业。"},{"label":"成立/解散时间","value":"1865年成立为Badische Anilin- & Soda-Fabrik；后发展为大型化工企业。"},{"label":"核心目标/宗旨","value":"生产煤焦油染料、化学原料和后续多种化工产品，把实验室化学转化为工业规模生产。"},{"label":"关键人物（可选）","value":"弗里德里希·恩格尔霍恩及公司科学家、工程师群体。"},{"label":"关键行动/事件","value":"发展合成染料技术，扩大路德维希港生产基地，与德国大学化学教育和专利体系形成密切联系。"},{"label":"为什么重要","value":"BASF说明德国工业优势不只来自廉价劳动力，也来自研究、专利、企业实验室和高等教育体系。"},{"label":"争议/局限","value":"化学工业带来污染、劳工风险和战时军工转化；后续德国化工企业与战争经济、IG法本等问题相连。"},{"label":"出处","value":"BASF, Our History；Britannica, BASF Aktiengesellschaft；Science History Institute, Synthetic Dye Industry。"}],"relationItems":["← 前因：德意志帝国研究型大学扩张","→ 后果：德国IG法本公司成立","↔ 相关：德国拜耳推出阿司匹林","↔ 相关：德国化学工业","↔ 同时期参考：英国染料工业衰落"],"relations":[{"text":"← 前因：德意志帝国研究型大学扩张","id":"extra821"},{"text":"→ 后果：德国IG法本公司成立","id":"card98"},{"text":"↔ 相关：德国拜耳推出阿司匹林","id":"extra738"},{"text":"↔ 相关：德国化学工业","id":"extra680"}],"source":"history","id":"extra829"},{"title":"卡尔蔡司与耶拿光学工业","level":"B","type":"组织/机构卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"1846年创立；19世纪后期成为世界级光学企业","place":"耶拿","summary":"蔡司公司把精密制造、大学科学和企业研究结合起来，使耶拿成为现代光学工业中心。","fields":[{"label":"标题","value":"卡尔蔡司与耶拿光学工业"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1846年创立；19世纪后期成为世界级光学企业"},{"label":"地点","value":"耶拿"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"蔡司公司把精密制造、大学科学和企业研究结合起来，使耶拿成为现代光学工业中心。"},{"label":"性质/类型","value":"精密光学和科学仪器企业。"},{"label":"成立/解散时间","value":"1846年由卡尔·蔡司在耶拿创立。"},{"label":"核心目标/宗旨","value":"生产显微镜、光学仪器、镜头和科学设备，服务医学、自然科学、工业和军事测量等领域。"},{"label":"关键人物（可选）","value":"卡尔·蔡司、恩斯特·阿贝、奥托·肖特。"},{"label":"关键行动/事件","value":"通过阿贝的光学理论和肖特的玻璃技术改进显微镜与镜头，建立企业实验室和社会福利制度。"},{"label":"为什么重要","value":"它是德国“科学型工业”的典型案例，说明德国现代化不只靠大工厂，也靠精密知识、工程师和专业仪器。"},{"label":"争议/局限","value":"精密光学既服务科学研究，也能服务军事侦察、瞄准和战争技术，科学工业并不天然中立。"},{"label":"出处","value":"ZEISS, History of ZEISS；Britannica, Carl Zeiss；Britannica, Ernst Abbe。"}],"relationItems":["← 前因：德意志帝国研究型大学扩张","→ 后果：罗伯特·科赫发现结核杆菌","↔ 相关：德意志帝国实科中学","↔ 相关：第二次工业革命","↔ 同时期参考：瑞士精密仪器工业"],"relations":[{"text":"← 前因：德意志帝国研究型大学扩张","id":"extra821"},{"text":"→ 后果：罗伯特·科赫发现结核杆菌","id":"extra811"},{"text":"↔ 相关：德意志帝国实科中学","id":"extra819"},{"text":"↔ 相关：第二次工业革命","id":"extra954"}],"source":"history","id":"extra830"},{"title":"德意志帝国电话网络","level":"C","type":"概念/思潮卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1880年代—1918年","place":"德意志帝国城市和邮政电信体系","summary":"帝国电话网络把商业、行政和城市生活连接得更快，也显示现代通信基础设施由国家邮政体系强力塑造。","fields":[{"label":"标题","value":"德意志帝国电话网络"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1880年代—1918年"},{"label":"地点","value":"德意志帝国城市和邮政电信体系"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"帝国电话网络把商业、行政和城市生活连接得更快，也显示现代通信基础设施由国家邮政体系强力塑造。"},{"label":"核心主张/思路","value":"电话把声音变成可跨距离即时传递的信息，使企业管理、政府行政、新闻和城市服务更依赖通信网络。"},{"label":"提出者/代表人物（可选）","value":"德意志帝国邮政系统、电气企业、城市商界和行政机关共同推动。"},{"label":"它从何而来","value":"电报网络、城市商业扩张和电气工业发展为电话普及提供技术和制度基础。"},{"label":"典型表现","value":"城市电话交换台、商号和银行电话、政府机关通信、电话簿和接线员工作。"},{"label":"为什么重要","value":"电话网络说明现代德国不是只通过铁路和军队整合，也通过看不见的信息线路整合市场和行政。"},{"label":"争议/局限","value":"早期电话主要服务企业、机关和中上层用户，普通家庭普及有限；网络建设也受国家监管和地区差异影响。"},{"label":"出处","value":"Museum for Communication Berlin, telephone history references；ITU historical materials on telephone networks；German Reichspost telecommunication histories。"}],"relationItems":["← 前因：电报通信网络扩张","→ 后果：魏玛德国大众消费文化","↔ 相关：德国AEG电气公司","↔ 相关：西门子与德国电气工业","↔ 同时期参考：贝尔电话公司"],"relations":[{"text":"← 前因：电报通信网络扩张","id":"extra952"},{"text":"→ 后果：魏玛德国大众消费文化","id":"card87"},{"text":"↔ 相关：德国AEG电气公司","id":"extra828"},{"text":"↔ 相关：西门子与德国电气工业","id":"extra682"}],"source":"history","id":"extra831"},{"title":"德意志帝国城市电车网络","level":"C","type":"概念/思潮卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"1880年代—1918年","place":"柏林、汉堡、慕尼黑、法兰克福等德国城市","summary":"城市电车改变了德国大城市通勤、居住和消费空间，使工人和白领能在更大城市范围内工作生活。","fields":[{"label":"标题","value":"德意志帝国城市电车网络"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1880年代—1918年"},{"label":"地点","value":"柏林、汉堡、慕尼黑、法兰克福等德国城市"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"城市电车改变了德国大城市通勤、居住和消费空间，使工人和白领能在更大城市范围内工作生活。"},{"label":"核心主张/思路","value":"电车是一种城市基础设施，把居住区、工厂、商业街和车站连接起来，扩大城市日常活动半径。"},{"label":"提出者/代表人物（可选）","value":"城市政府、交通公司、电气企业和地产开发者共同推动。"},{"label":"它从何而来","value":"城市人口增长、工厂外迁、住宅区扩展和电气技术进步，使马车和步行难以满足通勤需求。"},{"label":"典型表现","value":"有轨电车线路、工人通勤、郊区住宅开发、商业街客流扩大和城市时间表生活。"},{"label":"为什么重要","value":"它把城市现代性落到每天上下班和购物的身体经验上，是理解德国城市扩张的重要基础卡。"},{"label":"争议/局限","value":"线路布局常优先服务盈利区域和中产通勤，贫民区和边缘地区接入不均；票价也影响工人使用频率。"},{"label":"出处","value":"Siemens historical materials on electric tramways；Urban transport histories of Berlin and German cities；Britannica, streetcar。"}],"relationItems":["← 前因：工业化时代的德国城市社会","→ 后果：魏玛德国城市交通与通勤","↔ 相关：德国AEG电气公司","↔ 相关：德意志帝国柏林租住营房","↔ 同时期参考：巴黎地铁开通"],"relations":[{"text":"← 前因：工业化时代的德国城市社会","id":"extra934"},{"text":"↔ 相关：德国AEG电气公司","id":"extra828"},{"text":"↔ 相关：德意志帝国柏林租住营房","id":"extra683"}],"source":"history","id":"extra832"},{"title":"德意志帝国家政女工","level":"C","type":"概念/思潮卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"19世纪后期—1918年","place":"德意志帝国城市中产家庭","summary":"家政女工是帝国德国城市女性劳动的重要群体，连接乡村迁移、性别秩序和中产家庭生活。","fields":[{"label":"标题","value":"德意志帝国家政女工"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"19世纪后期—1918年"},{"label":"地点","value":"德意志帝国城市中产家庭"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"家政女工是帝国德国城市女性劳动的重要群体，连接乡村迁移、性别秩序和中产家庭生活。"},{"label":"核心主张/思路","value":"大量年轻女性以住家女佣、厨娘、保姆或清洁帮佣身份进入城市家庭工作，劳动空间在私人家庭内部。"},{"label":"提出者/代表人物（可选）","value":"不是思想流派，而是社会劳动结构；雇主多为城市中产和上层家庭。"},{"label":"它从何而来","value":"乡村贫困、女性就业机会有限和城市中产家庭对体面生活的需求，共同推动年轻女性进入家政服务。"},{"label":"典型表现","value":"长工时、住家管理、低工资、缺乏私人空间和严格道德监管；女佣也常是城市流动和女性独立的第一步。"},{"label":"为什么重要","value":"它提醒用户德国工业社会不只有男工和工厂，家庭内部的女性服务劳动同样支撑城市中产生活。"},{"label":"争议/局限","value":"家政劳动长期不被视为“真正工业劳动”，法律保护和组织能力弱；雇主家庭权力关系容易造成剥削和性骚扰。"},{"label":"出处","value":"German History in Documents and Images, Domestic Servants and Industrial Workers statistical materials；Ute Frevert, Women in German History。"}],"relationItems":["← 前因：工业化时代的德国城市社会","→ 后果：魏玛“新女性”","↔ 相关：德国妇女运动","↔ 相关：德意志帝国女性大学入学开放","↔ 同时期参考：英国维多利亚女佣文化"],"relations":[{"text":"← 前因：工业化时代的德国城市社会","id":"extra934"},{"text":"→ 后果：魏玛“新女性”","id":"card32"},{"text":"↔ 相关：德国妇女运动","id":"extra684"},{"text":"↔ 相关：德意志帝国女性大学入学开放","id":"extra823"}],"source":"history","id":"extra833"},{"title":"德意志帝国广告业兴起","level":"C","type":"概念/思潮卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"19世纪后期—1918年","place":"德意志帝国大城市和报刊市场","summary":"帝国时期广告随报刊、百货商店和消费品扩张而兴起，把城市空间变成商业视觉竞争场。","fields":[{"label":"标题","value":"德意志帝国广告业兴起"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"19世纪后期—1918年"},{"label":"地点","value":"德意志帝国大城市和报刊市场"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"帝国时期广告随报刊、百货商店和消费品扩张而兴起，把城市空间变成商业视觉竞争场。"},{"label":"核心主张/思路","value":"商品不再只靠店铺和口碑销售，也靠报纸广告、海报、橱窗、品牌名和包装塑造欲望。"},{"label":"提出者/代表人物（可选）","value":"广告商、出版商、百货公司、消费品企业和海报艺术家共同推动。"},{"label":"它从何而来","value":"大众报刊、城市消费、识字率提高、彩色印刷和品牌商品扩张，为现代广告提供了受众和媒介。"},{"label":"典型表现","value":"报纸广告、街头海报、商品目录、橱窗展示、商标和早期广告代理。"},{"label":"为什么重要","value":"它把经济史和视觉文化连接起来，说明现代消费社会不仅生产商品，也生产看见商品、想要商品的方式。"},{"label":"争议/局限","value":"广告被批评制造虚假需求、诱导消费和污染城市景观；同时也为女性、儿童和中产消费者创造新身份想象。"},{"label":"出处","value":"German History in Documents and Images, Advertising and Consumer Culture materials；Routledge histories of German advertising；DHM LeMO consumer culture references。"}],"relationItems":["← 前因：德国百货商店兴起","→ 后果：魏玛德国广告专业化","↔ 相关：德意志帝国《帝国报刊法》","↔ 相关：魏玛德国插图新闻杂志文化","↔ 同时期参考：法国新艺术海报"],"relations":[{"text":"← 前因：德国百货商店兴起","id":"extra730"},{"text":"→ 后果：魏玛德国广告专业化","id":"card186"},{"text":"↔ 相关：德意志帝国《帝国报刊法》","id":"extra816"},{"text":"↔ 相关：魏玛德国插图新闻杂志文化","id":"card175"}],"source":"history","id":"extra834"},{"title":"德意志帝国纪念碑文化","level":"C","type":"概念/思潮卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1871—1918年","place":"德意志帝国各城市、战场和民族纪念地点","summary":"帝国纪念碑文化通过皇帝像、战争纪念碑和民族纪念建筑，把统一、牺牲和忠诚刻进公共空间。","fields":[{"label":"标题","value":"德意志帝国纪念碑文化"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1871—1918年"},{"label":"地点","value":"德意志帝国各城市、战场和民族纪念地点"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"帝国纪念碑文化通过皇帝像、战争纪念碑和民族纪念建筑，把统一、牺牲和忠诚刻进公共空间。"},{"label":"核心主张/思路","value":"国家和民族记忆可以通过可见建筑、雕像、纪念日和公共仪式固定下来，让普通人在城市空间中反复遭遇国家叙事。"},{"label":"提出者/代表人物（可选）","value":"皇室、退伍军人协会、地方政府、民族主义团体、建筑师和雕塑家。"},{"label":"它从何而来","value":"1871年统一战争胜利后，新帝国需要把各邦居民转化为共同的德国国民，公共纪念物成为政治教育工具。"},{"label":"典型表现","value":"威廉一世纪念碑、俾斯麦塔、战争阵亡纪念碑、凯撒像、民族纪念建筑和纪念仪式。"},{"label":"为什么重要","value":"它说明民族国家不是只靠法律存在，也靠石头、广场、仪式和日常视觉反复制造归属感。"},{"label":"争议/局限","value":"纪念碑常强化军功、男性牺牲和帝国忠诚，遮蔽工人、女性、少数族群和殖民暴力经验。"},{"label":"出处","value":"German History in Documents and Images, National Monuments and Memorial Culture；DHM LeMO, Kaiserreich memorial culture references。"}],"relationItems":["← 前因：德意志帝国成立","→ 后果：一战阵亡者纪念文化","↔ 相关：泛德意志联盟","↔ 相关：德意志帝国国庆与皇帝崇拜","↔ 同时期参考：法国第三共和国纪念碑文化"],"relations":[{"text":"← 前因：德意志帝国成立","id":"extra621"},{"text":"→ 后果：一战阵亡者纪念文化","id":"extra961"},{"text":"↔ 相关：泛德意志联盟","id":"extra675"}],"source":"history","id":"extra835"},{"title":"德意志现实主义文学","level":"C","type":"概念/思潮卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"19世纪中后期","place":"德意志各邦；德意志帝国","summary":"德意志现实主义文学关注市民生活、地方社会和道德冲突，以克制叙事回应现代化带来的社会变化。","fields":[{"label":"标题","value":"德意志现实主义文学"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"19世纪中后期"},{"label":"地点","value":"德意志各邦；德意志帝国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德意志现实主义文学关注市民生活、地方社会和道德冲突，以克制叙事回应现代化带来的社会变化。"},{"label":"核心主张/思路","value":"文学应观察现实社会，但不必像自然主义那样强调赤裸贫困和决定论，而是在日常生活中呈现社会关系和个人命运。"},{"label":"提出者/代表人物（可选）","value":"特奥多尔·冯塔纳、戈特弗里德·凯勒、威廉·拉贝、特奥多尔·施托姆等。"},{"label":"它从何而来","value":"1848革命失败后，政治理想受挫，德语文学逐渐转向市民社会、地方经验、婚姻家庭和现代化阴影。"},{"label":"典型表现","value":"小说、短篇和中篇关注地方共同体、阶层差异、婚姻困境、荣誉观念和个人选择。"},{"label":"为什么重要","value":"它补足了统一战争和工业化之外的德国社会感受，让用户看到中产世界如何用文学理解变化中的现实。"},{"label":"争议/局限","value":"德意志现实主义较少直接描写工人运动和殖民问题，也常保持温和、含蓄和中产立场。"},{"label":"出处","value":"Britannica, German literature: The 19th century；Oxford Reference, Poetic Realism in German literature。"}],"relationItems":["← 前因：德意志Vormärz时期","→ 后果：德国自然主义文学","↔ 相关：德意志比德迈文化","↔ 相关：托马斯·曼《布登勃洛克一家》","↔ 同时期参考：法国现实主义文学"],"relations":[{"text":"← 前因：德意志Vormärz时期","id":"extra502"},{"text":"→ 后果：德国自然主义文学","id":"extra848"},{"text":"↔ 相关：德意志比德迈文化","id":"extra553"},{"text":"↔ 相关：托马斯·曼《布登勃洛克一家》","id":"extra85"}],"source":"history","id":"extra836"},{"title":"德国桥社","level":"B","type":"组织/机构卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1905—1913年","place":"德累斯顿；柏林","summary":"桥社是德国表现主义绘画的重要团体，用强烈色彩和扭曲形体反抗学院传统和市民审美。","fields":[{"label":"标题","value":"德国桥社"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1905—1913年"},{"label":"地点","value":"德累斯顿；柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"桥社是德国表现主义绘画的重要团体，用强烈色彩和扭曲形体反抗学院传统和市民审美。"},{"label":"性质/类型","value":"现代艺术团体。"},{"label":"成立/解散时间","value":"1905年在德累斯顿成立；1913年解散。"},{"label":"核心目标/宗旨","value":"把青年艺术家连接成通向新艺术的“桥”，用直接、粗粝和情绪化的形式表达现代生活紧张。"},{"label":"关键人物（可选）","value":"恩斯特·路德维希·基希纳、弗里茨·布莱尔、埃里希·赫克尔、卡尔·施密特-罗特卢夫等。"},{"label":"关键行动/事件","value":"创作木刻、绘画和城市题材作品，后来迁向柏林都市经验，成为德国表现主义核心来源之一。"},{"label":"为什么重要","value":"它说明德国现代艺术不只是包豪斯设计，也包括对城市焦虑、身体、性和现代生活压力的激烈视觉表达。"},{"label":"争议/局限","value":"桥社艺术家常以原始主义眼光处理非欧洲文化和身体形象，带有时代局限。"},{"label":"出处","value":"MoMA, Brücke；Tate, Die Brücke；Britannica, Die Brücke。"}],"relationItems":["← 前因：德意志帝国城市现代性","→ 后果：德国表现主义电影","↔ 相关：德国蓝骑士社","↔ 相关：纳粹德国“退化艺术”展","↔ 同时期参考：法国野兽派"],"relations":[{"text":"← 前因：德意志帝国城市现代性","id":"extra944"},{"text":"→ 后果：德国表现主义电影","id":"card78"},{"text":"↔ 相关：德国蓝骑士社","id":"extra838"},{"text":"↔ 相关：纳粹德国“退化艺术”展","id":"extra126"}],"source":"history","id":"extra837"},{"title":"德国蓝骑士社","level":"B","type":"组织/机构卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1911—1914年","place":"慕尼黑","summary":"蓝骑士社是慕尼黑现代艺术团体，推动抽象艺术和精神性表达，是德国表现主义另一条重要路径。","fields":[{"label":"标题","value":"德国蓝骑士社"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1911—1914年"},{"label":"地点","value":"慕尼黑"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"蓝骑士社是慕尼黑现代艺术团体，推动抽象艺术和精神性表达，是德国表现主义另一条重要路径。"},{"label":"性质/类型","value":"现代艺术团体和展览网络。"},{"label":"成立/解散时间","value":"1911年形成；一战爆发后解体。"},{"label":"核心目标/宗旨","value":"突破学院艺术和自然主义再现，强调色彩、形式、音乐性和艺术中的精神维度。"},{"label":"关键人物（可选）","value":"瓦西里·康定斯基、弗朗茨·马克、加布里埃莱·明特、奥古斯特·马克等。"},{"label":"关键行动/事件","value":"举办展览，出版《蓝骑士年鉴》，吸收民间艺术、儿童画、非欧洲艺术和音乐类比，推动抽象艺术发展。"},{"label":"为什么重要","value":"蓝骑士社把德国现代艺术与抽象、精神性和国际先锋网络连接起来，是理解20世纪艺术转向的重要节点。"},{"label":"争议/局限","value":"其精神化语言有时较抽象，和社会现实、阶级政治联系不如达达或新客观主义直接。"},{"label":"出处","value":"Tate, Der Blaue Reiter；Britannica, Der Blaue Reiter；MoMA, German Expressionism resources。"}],"relationItems":["← 前因：德意志帝国城市现代性","→ 后果：纳粹德国“退化艺术”展","↔ 相关：德国桥社","↔ 相关：德国表现主义电影","↔ 同时期参考：欧洲抽象艺术兴起"],"relations":[{"text":"← 前因：德意志帝国城市现代性","id":"extra944"},{"text":"→ 后果：纳粹德国“退化艺术”展","id":"extra126"},{"text":"↔ 相关：德国桥社","id":"extra837"},{"text":"↔ 相关：德国表现主义电影","id":"card78"}],"source":"history","id":"extra838"},{"title":"汉堡自由港与仓库城","level":"B","type":"事件卡","tags":["经济与社会","战争与外交"],"mainTag":"经济与社会","subTag":"战争与外交","timeText":"1880年代，仓库城1883年开建，1888年汉堡并入德国关税区","place":"汉堡","summary":"汉堡自由港与仓库城把帝国关税统一、全球贸易和港口城市改造连接起来，是德国海洋商业现代化的标志。","fields":[{"label":"标题","value":"汉堡自由港与仓库城"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1880年代，仓库城1883年开建，1888年汉堡并入德国关税区"},{"label":"地点","value":"汉堡"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"汉堡自由港与仓库城把帝国关税统一、全球贸易和港口城市改造连接起来，是德国海洋商业现代化的标志。"},{"label":"参与者","value":"汉堡市政府、德意志帝国政府、港口商人、被拆迁居民、仓储和航运企业。"},{"label":"发生了什么","value":"德意志帝国统一后，汉堡作为自由港城市需要在地方商业传统和帝国关税统一之间重新定位。1880年代，汉堡通过建设仓库城和设立自由港区域，把转口贸易、仓储、海关监管和港口基础设施整合起来。工程拆迁旧城区居民，建成大规模红砖仓库和水路装卸系统。"},{"label":"为什么重要","value":"它说明德国统一不仅改变议会和军队，也改变港口、关税、城市空间和全球贸易网络。"},{"label":"前因","value":"德意志帝国成立后，统一关税和国内市场要求汉堡调整自由贸易城市身份；全球海运和殖民贸易扩张又要求更现代的仓储和港口设施。"},{"label":"后果","value":"汉堡成为德国最重要的国际港口之一，仓库城成为全球贸易、咖啡、香料、地毯和殖民商品流通的城市基础设施象征。"},{"label":"出处","value":"UNESCO, Speicherstadt and Kontorhaus District with Chilehaus；Hamburg Port Authority, History of the Port of Hamburg；Hamburg.com, Speicherstadt history。"}],"relationItems":["← 前因：德意志关税同盟（Zollverein）","→ 后果：汉堡-美洲航运公司","↔ 相关：德国殖民协会","↔ 相关：德意志帝国世界贸易扩张","↔ 同时期参考：伦敦港现代化"],"relations":[{"text":"← 前因：德意志关税同盟（Zollverein）","id":"extra486"},{"text":"→ 后果：汉堡-美洲航运公司","id":"extra840"},{"text":"↔ 相关：德国殖民协会","id":"extra677"},{"text":"↔ 相关：德意志帝国世界贸易扩张","id":"extra932"}],"source":"history","id":"extra839"},{"title":"汉堡-美洲航运公司","level":"C","type":"组织/机构卡","tags":["经济与社会","战争与外交"],"mainTag":"经济与社会","subTag":"战争与外交","timeText":"1847年成立；帝国时期快速扩张","place":"汉堡；大西洋和全球航线","summary":"汉堡-美洲航运公司把德国港口、移民、大西洋航运和全球商业连接起来，是帝国德国海运实力的代表企业。","fields":[{"label":"标题","value":"汉堡-美洲航运公司"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1847年成立；帝国时期快速扩张"},{"label":"地点","value":"汉堡；大西洋和全球航线"},{"label":"主要国家","value":"德国；美国"},{"label":"一句话概括","value":"汉堡-美洲航运公司把德国港口、移民、大西洋航运和全球商业连接起来，是帝国德国海运实力的代表企业。"},{"label":"性质/类型","value":"远洋航运公司。"},{"label":"成立/解散时间","value":"1847年在汉堡成立；20世纪继续发展，后与北德劳埃德合并形成赫伯罗特。"},{"label":"核心目标/宗旨","value":"经营客运、移民运输、货运和跨大西洋航线，把汉堡连接到纽约、美洲和全球港口。"},{"label":"关键人物（可选）","value":"阿尔伯特·巴林。"},{"label":"关键行动/事件","value":"扩大跨大西洋客运和移民运输，发展大型客轮和国际航线；帝国时期成为世界重要航运公司之一。"},{"label":"为什么重要","value":"它把德国近代史从内陆统一和欧洲战争拉向海洋、移民和全球资本主义。"},{"label":"争议/局限","value":"航运繁荣依赖移民潮、殖民贸易和全球不平等；一战爆发后德国商船和航运网络受到严重打击。"},{"label":"出处","value":"Hapag-Lloyd, History；Britannica, Albert Ballin；Hamburg Port history materials。"}],"relationItems":["← 前因：汉堡自由港与仓库城","→ 后果：德意志帝国世界政策","↔ 相关：北德劳埃德航运公司","↔ 相关：德国移民潮","↔ 同时期参考：英国白星航运公司"],"relations":[{"text":"← 前因：汉堡自由港与仓库城","id":"extra839"},{"text":"→ 后果：德意志帝国世界政策","id":"extra635"},{"text":"↔ 相关：北德劳埃德航运公司","id":"extra841"},{"text":"↔ 相关：德国移民潮","id":"extra943"}],"source":"history","id":"extra840"},{"title":"北德劳埃德航运公司","level":"C","type":"组织/机构卡","tags":["经济与社会","战争与外交"],"mainTag":"经济与社会","subTag":"战争与外交","timeText":"1857年成立；帝国时期成为大型远洋航运公司","place":"不来梅；不来梅港；跨大西洋航线","summary":"北德劳埃德以不来梅为基地经营远洋客货运输，是德国移民出海和跨大西洋商业的重要载体。","fields":[{"label":"标题","value":"北德劳埃德航运公司"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1857年成立；帝国时期成为大型远洋航运公司"},{"label":"地点","value":"不来梅；不来梅港；跨大西洋航线"},{"label":"主要国家","value":"德国；美国"},{"label":"一句话概括","value":"北德劳埃德以不来梅为基地经营远洋客货运输，是德国移民出海和跨大西洋商业的重要载体。"},{"label":"性质/类型","value":"远洋航运公司。"},{"label":"成立/解散时间","value":"1857年在不来梅成立；1970年与汉堡-美洲航运公司合并为赫伯罗特。"},{"label":"核心目标/宗旨","value":"经营德国与美洲之间的客运、移民运输、邮件和货运服务。"},{"label":"关键人物（可选）","value":"赫尔曼·亨里希·迈尔等不来梅商界人物。"},{"label":"关键行动/事件","value":"发展不来梅港和跨大西洋航线，承担大量德语区移民前往美国的运输。"},{"label":"为什么重要","value":"它说明19世纪德国社会变化不仅是人们从乡村进城，也包括数百万人跨海离开欧洲。"},{"label":"争议/局限","value":"移民运输既是商业服务，也与贫困、人口压力和全球劳动力流动中的脆弱处境相关。"},{"label":"出处","value":"Hapag-Lloyd, History of North German Lloyd and Hapag; Bremen/Bremerhaven maritime history materials。"}],"relationItems":["← 前因：德国移民潮","→ 后果：德裔美国人社群形成","↔ 相关：汉堡-美洲航运公司","↔ 相关：德意志帝国世界贸易扩张","↔ 同时期参考：爱尔兰移民美国"],"relations":[{"text":"← 前因：德国移民潮","id":"extra943"},{"text":"↔ 相关：汉堡-美洲航运公司","id":"extra840"},{"text":"↔ 相关：德意志帝国世界贸易扩张","id":"extra932"}],"source":"history","id":"extra841"},{"title":"德意志银行成立","level":"B","type":"组织/机构卡","tags":["经济与社会","战争与外交"],"mainTag":"经济与社会","subTag":"战争与外交","timeText":"1870年","place":"柏林","summary":"德意志银行成立时以支持德国对外贸易和海外业务为目标，体现统一前后德国金融资本的国际化野心。","fields":[{"label":"标题","value":"德意志银行成立"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1870年"},{"label":"地点","value":"柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德意志银行成立时以支持德国对外贸易和海外业务为目标，体现统一前后德国金融资本的国际化野心。"},{"label":"性质/类型","value":"商业银行、投资银行。"},{"label":"成立/解散时间","value":"1870年在柏林成立。"},{"label":"核心目标/宗旨","value":"为德国企业、对外贸易和国际金融业务提供资本支持，减少德国商人对伦敦金融市场的依赖。"},{"label":"关键人物（可选）","value":"阿德尔伯特·德尔布吕克、路德维希·班贝格尔等创办者。"},{"label":"关键行动/事件","value":"参与铁路、工业、海外贸易和大型企业融资，逐步成为德国最重要的银行之一。"},{"label":"为什么重要","value":"它补足工业化的金融侧面。德国企业扩张、铁路和国际贸易需要银行资本，而不是只靠工厂和技术。"},{"label":"争议/局限","value":"大银行与工业企业关系密切，既能推动投资，也可能强化金融集中和经济权力不平等。"},{"label":"出处","value":"Deutsche Bank, History; Britannica, Deutsche Bank AG。"}],"relationItems":["← 前因：德意志帝国成立","→ 后果：德意志帝国世界贸易扩张","↔ 相关：德意志帝国银行","↔ 相关：奥斯曼巴格达铁路","↔ 同时期参考：伦敦金融城"],"relations":[{"text":"← 前因：德意志帝国成立","id":"extra621"},{"text":"→ 后果：德意志帝国世界贸易扩张","id":"extra932"},{"text":"↔ 相关：德意志帝国银行","id":"extra747"},{"text":"↔ 相关：奥斯曼巴格达铁路","id":"extra640"}],"source":"history","id":"extra842"},{"title":"柏林霍布雷希特排水系统","level":"C","type":"制度/文本卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1860年代规划；1870年代后实施","place":"柏林","summary":"霍布雷希特排水系统把柏林污水、公共卫生和城市工程连成整体，是现代城市治理的重要基础设施。","fields":[{"label":"标题","value":"柏林霍布雷希特排水系统"},{"label":"分级","value":"C"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1860年代规划；1870年代后实施"},{"label":"地点","value":"柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"霍布雷希特排水系统把柏林污水、公共卫生和城市工程连成整体，是现代城市治理的重要基础设施。"},{"label":"制定方/签署方","value":"柏林市政工程体系；规划者詹姆斯·霍布雷希特。"},{"label":"主要内容","value":"通过地下排水管网、泵站和污水灌溉田系统处理城市污水，减少街道污物和水源污染。"},{"label":"它试图解决什么问题","value":"工业化和人口爆炸使柏林排泄物、污水、传染病和街道卫生问题急剧恶化，传统排污方式已无法支撑大城市。"},{"label":"为什么重要","value":"它把公共卫生从道德劝告转化为工程和市政财政问题，说明现代国家和城市必须通过管网治理身体和环境。"},{"label":"争议/局限","value":"排水改善并未消除贫民住房拥挤，污水灌溉田也带来环境和管理问题；基础设施常优先服务城市核心区。"},{"label":"造成的影响","value":"柏林卫生条件改善，市政工程和公共卫生行政能力提升，也为德国城市公共卫生运动提供示范。"},{"label":"出处","value":"Berlin Senate / Berliner Wasserbetriebe history of sewerage; German History in Documents and Images urban sanitation materials。"}],"relationItems":["← 前因：德意志帝国柏林租住营房","→ 后果：德国城市公共卫生运动","↔ 相关：德意志帝国汉堡霍乱疫情","↔ 相关：德意志帝国卫生署","↔ 同时期参考：伦敦下水道系统"],"relations":[{"text":"← 前因：德意志帝国柏林租住营房","id":"extra683"},{"text":"→ 后果：德国城市公共卫生运动","id":"extra733"},{"text":"↔ 相关：德意志帝国汉堡霍乱疫情","id":"extra812"},{"text":"↔ 相关：德意志帝国卫生署","id":"extra809"}],"source":"history","id":"extra843"},{"title":"德意志帝国城市公用事业","level":"C","type":"概念/思潮卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"19世纪后期—1918年","place":"德意志帝国城市","summary":"城市公用事业把水、电、煤气、交通和卫生纳入市政管理，显示德国城市现代化的组织能力。","fields":[{"label":"标题","value":"德意志帝国城市公用事业"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"19世纪后期—1918年"},{"label":"地点","value":"德意志帝国城市"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"城市公用事业把水、电、煤气、交通和卫生纳入市政管理，显示德国城市现代化的组织能力。"},{"label":"核心主张/思路","value":"现代城市需要稳定供水、照明、排污、交通和公共服务，这些领域不能完全依赖零散私人安排。"},{"label":"提出者/代表人物（可选）","value":"城市议会、市政工程师、地方行政官和城市改革者。"},{"label":"它从何而来","value":"工业化城市人口激增，私人企业和传统社区无法独立解决卫生、能源和交通问题，市政政府权力和财政随之扩展。"},{"label":"典型表现","value":"市营煤气厂、电厂、自来水厂、有轨电车、屠宰场、浴场和垃圾处理系统。"},{"label":"为什么重要","value":"它说明德国现代性不只来自中央帝国，也来自地方城市政府把日常生活基础设施组织起来。"},{"label":"争议/局限","value":"市政服务扩张常伴随税费、债务和阶层不平等；贫民区接入、票价和服务质量仍存在差异。"},{"label":"出处","value":"German municipal utilities and public works histories; German History in Documents and Images urban modernization materials。"}],"relationItems":["← 前因：工业化时代的德国城市社会","→ 后果：德意志帝国城市电车网络","↔ 相关：柏林霍布雷希特排水系统","↔ 相关：德国城市公共卫生运动","↔ 同时期参考：英国市政社会主义"],"relations":[{"text":"← 前因：工业化时代的德国城市社会","id":"extra934"},{"text":"→ 后果：德意志帝国城市电车网络","id":"extra832"},{"text":"↔ 相关：柏林霍布雷希特排水系统","id":"extra843"},{"text":"↔ 相关：德国城市公共卫生运动","id":"extra733"}],"source":"history","id":"extra844"},{"title":"德意志帝国威廉皇帝学会","level":"B","type":"组织/机构卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1911年成立","place":"柏林及德国研究所网络","summary":"威廉皇帝学会通过专门研究所支持基础科学和应用研究，是德国现代科研组织的重要节点。","fields":[{"label":"标题","value":"德意志帝国威廉皇帝学会"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1911年成立"},{"label":"地点","value":"柏林及德国研究所网络"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"威廉皇帝学会通过专门研究所支持基础科学和应用研究，是德国现代科研组织的重要节点。"},{"label":"性质/类型","value":"非大学研究机构网络。"},{"label":"成立/解散时间","value":"1911年成立；1948年后由马克斯·普朗克学会继承。"},{"label":"核心目标/宗旨","value":"在大学之外建立高水平研究所，为科学家提供更稳定的科研环境和资金支持。"},{"label":"关键人物（可选）","value":"阿道夫·冯·哈纳克、威廉二世、马克斯·普朗克等。"},{"label":"关键行动/事件","value":"建立化学、物理、生物、医学等研究所，推动德国科学研究制度化和专业化。"},{"label":"为什么重要","value":"它说明20世纪科学不再只靠个人教授和大学课堂，也依赖研究所、经费、国家和工业网络。"},{"label":"争议/局限","value":"学会部分研究所后来卷入战争研究、种族卫生和纳粹体制，科学组织的政治责任问题非常突出。"},{"label":"出处","value":"Max Planck Society, History of the Kaiser Wilhelm Society; Britannica, Max Planck Society。"}],"relationItems":["← 前因：德意志帝国研究型大学扩张","→ 后果：纳粹德国大学清洗","↔ 相关：卡尔蔡司与耶拿光学工业","↔ 相关：弗里茨·哈伯","↔ 同时期参考：法国巴斯德研究所"],"relations":[{"text":"← 前因：德意志帝国研究型大学扩张","id":"extra821"},{"text":"→ 后果：纳粹德国大学清洗","id":"extra287"},{"text":"↔ 相关：卡尔蔡司与耶拿光学工业","id":"extra830"},{"text":"↔ 相关：弗里茨·哈伯","id":"extra940"}],"source":"history","id":"extra845"},{"title":"柏林乌拉尼亚科学普及机构","level":"C","type":"组织/机构卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1888年成立","place":"柏林","summary":"柏林乌拉尼亚把天文、物理和技术知识带给城市公众，是德国科学大众化的重要机构。","fields":[{"label":"标题","value":"柏林乌拉尼亚科学普及机构"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1888年成立"},{"label":"地点","value":"柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"柏林乌拉尼亚把天文、物理和技术知识带给城市公众，是德国科学大众化的重要机构。"},{"label":"性质/类型","value":"科学普及机构、公众教育场所。"},{"label":"成立/解散时间","value":"1888年在柏林成立。"},{"label":"核心目标/宗旨","value":"通过讲座、展览、演示和天文设备向普通公众传播自然科学和技术知识。"},{"label":"关键人物（可选）","value":"威廉·迈耶、马克斯·威廉·迈耶等科学普及人物。"},{"label":"关键行动/事件","value":"举办科学讲座、天文观测和技术展示，使科学成为城市中产和大众娱乐教育的一部分。"},{"label":"为什么重要","value":"它把德国科学史从实验室和大学扩展到普通公众，说明现代社会需要“理解科学”的城市观众。"},{"label":"争议/局限","value":"科学普及可能简化复杂知识，也更多服务受教育城市公众，工人和贫困群体参与有限。"},{"label":"出处","value":"Urania Berlin, Geschichte; German science popularization histories; Berliner Wissenschaftsgeschichte references。"}],"relationItems":["← 前因：德意志帝国研究型大学扩张","→ 后果：德意志帝国科学大众化","↔ 相关：德意志博物馆成立","↔ 相关：德意志帝国威廉皇帝学会","↔ 同时期参考：英国皇家学会公众讲座传统"],"relations":[{"text":"← 前因：德意志帝国研究型大学扩张","id":"extra821"},{"text":"↔ 相关：德意志博物馆成立","id":"extra742"},{"text":"↔ 相关：德意志帝国威廉皇帝学会","id":"extra845"}],"source":"history","id":"extra846"},{"title":"德国S. Fischer出版社","level":"C","type":"组织/机构卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1886年成立","place":"柏林","summary":"德国S. Fischer出版社是德语现代文学出版重镇，连接自然主义、现代主义、魏玛文学和流亡文学。","fields":[{"label":"标题","value":"德国S. Fischer出版社"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1886年成立"},{"label":"地点","value":"柏林"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国S. Fischer出版社是德语现代文学出版重镇，连接自然主义、现代主义、魏玛文学和流亡文学。"},{"label":"性质/类型","value":"文学出版机构。"},{"label":"成立/解散时间","value":"1886年由萨穆埃尔·费舍尔在柏林创立。"},{"label":"核心目标/宗旨","value":"出版当代德语和欧洲文学，推动现代戏剧、小说和知识文化进入市场。"},{"label":"关键人物（可选）","value":"萨穆埃尔·费舍尔、彼得·苏尔坎普；作者包括托马斯·曼、格哈特·霍普特曼等。"},{"label":"关键行动/事件","value":"出版自然主义和现代文学作品，成为帝国后期和魏玛时期重要文学机构；纳粹时期因犹太背景和政治环境遭受压力。"},{"label":"为什么重要","value":"它说明文学现代性也依赖出版制度、编辑判断、版权市场和读者网络。"},{"label":"争议/局限","value":"出版社的商业成功和文学声望并存，现代文学的传播始终受市场、审查和政治环境制约。"},{"label":"出处","value":"S. Fischer Verlag, Verlagsgeschichte; Deutsche Biographie, Samuel Fischer。"}],"relationItems":["← 前因：德意志现实主义文学","→ 后果：托马斯·曼《布登勃洛克一家》","↔ 相关：德国自然主义文学","↔ 相关：魏玛德国乌尔施泰因出版社","↔ 同时期参考：法国伽利玛出版社"],"relations":[{"text":"← 前因：德意志现实主义文学","id":"extra836"},{"text":"→ 后果：托马斯·曼《布登勃洛克一家》","id":"extra85"},{"text":"↔ 相关：德国自然主义文学","id":"extra848"},{"text":"↔ 相关：魏玛德国乌尔施泰因出版社","id":"card174"}],"source":"history","id":"extra847"},{"title":"德国自然主义文学","level":"C","type":"概念/思潮卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1880年代—1890年代","place":"德意志帝国，尤其柏林等城市","summary":"德国自然主义文学用贫困、遗传、环境和社会问题挑战市民审美，把工业社会的阴暗面搬上舞台和纸面。","fields":[{"label":"标题","value":"德国自然主义文学"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1880年代—1890年代"},{"label":"地点","value":"德意志帝国，尤其柏林等城市"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国自然主义文学用贫困、遗传、环境和社会问题挑战市民审美，把工业社会的阴暗面搬上舞台和纸面。"},{"label":"核心主张/思路","value":"文学应更直接、更科学化地描写现实，尤其是贫困、酗酒、性、阶级压迫和环境决定个人命运的问题。"},{"label":"提出者/代表人物（可选）","value":"格哈特·霍普特曼、阿诺·霍尔茨、约翰内斯·施拉夫等。"},{"label":"它从何而来","value":"工业化、城市贫民区、社会主义运动和法国自然主义影响促使德语作家挑战传统市民文学。"},{"label":"典型表现","value":"方言、破碎对话、工人和贫民题材、舞台现实主义、对家庭和环境压迫的描写。"},{"label":"为什么重要","value":"它把德国文化视线从市民客厅转向贫民屋、工厂和社会问题，是理解帝国晚期社会批判文学的重要入口。"},{"label":"争议/局限","value":"自然主义常被批评过度决定论或沉迷丑陋现实；其“科学化”文学观本身也带有时代局限。"},{"label":"出处","value":"Britannica, German literature: Naturalism; Encyclopaedia.com, Naturalism in German literature; S. Fischer Verlag historical materials。"}],"relationItems":["← 前因：德意志现实主义文学","→ 后果：德国表现主义电影","↔ 相关：工业化时代的德国城市社会","↔ 相关：德国社会民主党（SPD）","↔ 同时期参考：左拉与法国自然主义"],"relations":[{"text":"← 前因：德意志现实主义文学","id":"extra836"},{"text":"→ 后果：德国表现主义电影","id":"card78"},{"text":"↔ 相关：工业化时代的德国城市社会","id":"extra934"},{"text":"↔ 相关：德国社会民主党（SPD）","id":"extra628"}],"source":"history","id":"extra848"},{"title":"奥托·冯·俾斯麦","level":"A","type":"人物卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1815—1898年；1862—1890年为核心政治活跃期","place":"普鲁士、德意志帝国、欧洲外交体系","summary":"俾斯麦通过王朝政治、战争和外交联盟完成德意志统一，并塑造德意志帝国早期秩序。","fields":[{"label":"标题","value":"奥托·冯·俾斯麦"},{"label":"分级","value":"A"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1815—1898年；1862—1890年为核心政治活跃期"},{"label":"地点","value":"普鲁士、德意志帝国、欧洲外交体系"},{"label":"主要国家","value":"普鲁士；德国；奥地利；法国；俄国"},{"label":"一句话概括","value":"俾斯麦通过王朝政治、战争和外交联盟完成德意志统一，并塑造德意志帝国早期秩序。"},{"label":"生卒年/活跃年代","value":"1815—1898年；1862年任普鲁士首相，1871—1890年任德意志帝国首相。"},{"label":"身份/职务","value":"普鲁士首相、北德意志邦联首相、德意志帝国首相。"},{"label":"关键贡献/作为","value":"处理普鲁士宪法冲突，推动普丹战争、普奥战争和普法战争后的统一；建立德意志帝国；通过文化斗争、反社会党人法和社会保险立法治理帝国社会；构建复杂联盟体系维持欧洲均势。"},{"label":"核心主张/立场","value":"维护君主制和普鲁士主导地位，强调现实政治、有限战争和外交孤立法国；在社会政策上以国家干预削弱社会主义吸引力。"},{"label":"为什么重要","value":"他是德意志统一的关键操盘者，也是19世纪欧洲国际政治的核心人物。德国帝国制度、奥普关系、德法敌对和福利国家早期实验都与他密切相关。"},{"label":"争议/评价","value":"俾斯麦不是自由民族主义者，他的统一道路保留强烈的君主、军队和普鲁士权力结构；其对内高压政策也加深政治裂缝。"},{"label":"关联事件（可选）","value":"普奥战争；普法战争；德意志帝国成立；德意志帝国俾斯麦时代。"},{"label":"出处","value":"Encyclopaedia Britannica: Otto von Bismarck；German History in Documents and Images: Bismarck and German unification；DHM/LeMO: Otto von Bismarck。"}],"relationItems":["← 前因：普鲁士宪法冲突","→ 后果：德意志帝国成立","↔ 相关：俾斯麦出任普鲁士首相","↔ 相关：德意志帝国俾斯麦时代","✗ 对立/冲突：德意志自由主义"],"relations":[{"text":"← 前因：普鲁士宪法冲突","id":"extra539"},{"text":"→ 后果：德意志帝国成立","id":"extra621"},{"text":"↔ 相关：俾斯麦出任普鲁士首相","id":"extra493"},{"text":"↔ 相关：德意志帝国俾斯麦时代","id":"extra625"},{"text":"✗ 对立/冲突：德意志自由主义","id":"extra501"}],"source":"history","id":"extra924"},{"title":"第一次世界大战爆发","level":"S","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1914年7月—8月","place":"欧洲，随后扩展为全球战争","summary":"1914年七月危机升级为列强战争，欧洲联盟体系、动员机制和战略误判共同引爆第一次世界大战。","fields":[{"label":"标题","value":"第一次世界大战爆发"},{"label":"分级","value":"S"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1914年7月—8月"},{"label":"地点","value":"欧洲，随后扩展为全球战争"},{"label":"主要国家","value":"奥匈帝国；塞尔维亚；德国；俄国；法国；英国；比利时"},{"label":"一句话概括","value":"1914年七月危机升级为列强战争，欧洲联盟体系、动员机制和战略误判共同引爆第一次世界大战。"},{"label":"参与者","value":"奥匈帝国、塞尔维亚、德国、俄国、法国、英国、比利时及各国政府和军队。"},{"label":"发生了什么","value":"萨拉热窝刺杀后，奥匈在德国“空白支票”支持下向塞尔维亚施压并宣战。俄国支持塞尔维亚并开始动员，德国对俄法宣战，并依据作战计划入侵比利时以进攻法国。英国因比利时中立和欧洲均势问题参战。局部巴尔干危机在数周内转化为欧洲大战。"},{"label":"为什么重要","value":"它是20世纪世界史的决定性断裂点，导致帝国崩溃、革命、民族国家重组、美国和日本角色上升，以及战后凡尔赛体系。德国近代史中的帝国终结、魏玛共和国和纳粹兴起都与它相连。"},{"label":"前因","value":"联盟体系、军备竞赛、巴尔干民族问题、奥匈帝国民族问题、德法复仇主义和军事动员计划共同提高危机升级风险。"},{"label":"后果","value":"欧洲进入长期总体战，德国入侵比利时引发英国参战，西线和东线战场形成，全球殖民地和海上战争也被卷入。"},{"label":"出处","value":"1914-1918 Online: July Crisis 1914；Encyclopaedia Britannica: World War I；German History in Documents and Images: July Crisis documents。"}],"relationItems":["← 前因：萨拉热窝刺杀事件","← 前因：1914年七月危机","→ 后果：德国入侵比利时","→ 后果：英国参加第一次世界大战","→ 后果：第一次马恩河战役","↔ 相关：德奥意三国同盟","↔ 相关：法俄同盟"],"relations":[{"text":"← 前因：萨拉热窝刺杀事件","id":"extra644"},{"text":"← 前因：1914年七月危机","id":"extra646"},{"text":"→ 后果：德国入侵比利时","id":"extra647"},{"text":"→ 后果：英国参加第一次世界大战","id":"extra648"},{"text":"→ 后果：第一次马恩河战役","id":"extra650"},{"text":"↔ 相关：德奥意三国同盟","id":"extra631"},{"text":"↔ 相关：法俄同盟","id":"extra928"}],"source":"history","id":"extra925"},{"title":"第一次世界大战德国战败","level":"A","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1918年夏—11月","place":"西线、德国本土、欧洲外交战场","summary":"德国在军事、经济、社会和盟友体系多重崩溃下被迫求停战，结束德意志帝国战争努力。","fields":[{"label":"标题","value":"第一次世界大战德国战败"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1918年夏—11月"},{"label":"地点","value":"西线、德国本土、欧洲外交战场"},{"label":"主要国家","value":"德国；法国；英国；美国；奥匈帝国；俄国/苏俄"},{"label":"一句话概括","value":"德国在军事、经济、社会和盟友体系多重崩溃下被迫求停战，结束德意志帝国战争努力。"},{"label":"参与者","value":"德国最高统帅部、德意志帝国政府、协约国军队、美国远征军、德国工人和士兵、德国盟友。"},{"label":"发生了什么","value":"德国1918年春季攻势未能迫使协约国求和，反而消耗精锐部队。夏秋之际，协约国在百日攻势中持续推进，美国兵力和物资改变力量对比。保加利亚、奥斯曼帝国和奥匈帝国相继崩溃，德国国内粮食短缺、罢工和厌战情绪加深。最高统帅部转而要求文官政府寻求停战，最终引发十月改革、基尔水兵起义和十一月革命。"},{"label":"为什么重要","value":"德国战败不是单一“背叛”造成，而是总体战承受能力崩溃的结果。它直接结束德意志帝国，开启魏玛共和国、凡尔赛和约和“背后一刀”政治神话。"},{"label":"前因","value":"英国海上封锁、德国“芜菁冬天”、无限制潜艇战失败、美国参战、春季攻势失利和盟友崩溃。"},{"label":"后果","value":"德国十一月革命爆发，威廉二世退位，德国签署一战停战，随后面对凡尔赛和约和赔款问题。"},{"label":"出处","value":"1914-1918 Online: Germany and the Armistice；Encyclopaedia Britannica: World War I；DHM/LeMO: Kriegsende 1918。"}],"relationItems":["← 前因：德国1918年春季攻势","← 前因：一战百日攻势","→ 后果：德国十一月革命","→ 后果：一战停战","→ 后果：德国“背后一刀”传说","↔ 相关：第一次世界大战爆发"],"relations":[{"text":"← 前因：德国1918年春季攻势","id":"extra663"},{"text":"← 前因：一战百日攻势","id":"extra664"},{"text":"→ 后果：德国十一月革命","id":"extra666"},{"text":"→ 后果：一战停战","id":"extra667"},{"text":"→ 后果：德国“背后一刀”传说","id":"extra623"},{"text":"↔ 相关：第一次世界大战爆发","id":"extra925"}],"source":"history","id":"extra926"},{"title":"德国速决战设想","level":"B","type":"概念/思潮卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"19世纪末—1914年","place":"德国总参谋部、欧洲战略环境","summary":"德国速决战设想试图先快速击败法国再转向俄国，是德国两线战争焦虑下的战略方案。","fields":[{"label":"标题","value":"德国速决战设想"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"19世纪末—1914年"},{"label":"地点","value":"德国总参谋部、欧洲战略环境"},{"label":"主要国家","value":"德国；法国；俄国；比利时"},{"label":"一句话概括","value":"德国速决战设想试图先快速击败法国再转向俄国，是德国两线战争焦虑下的战略方案。"},{"label":"核心主张/思路","value":"在面对法俄夹击风险时，德国军方认为长期两线战争难以承受，因此必须用铁路动员和侧翼包抄争取迅速击败法国，再集中力量应对俄国。"},{"label":"提出者/代表人物（可选）","value":"阿尔弗雷德·冯·施里芬；小毛奇；德国总参谋部。"},{"label":"它从何而来","value":"德国地处欧洲中部，法俄同盟形成后两线战争压力增大；普法战争胜利经验和总参谋部计划文化强化了对快速决战的信心。"},{"label":"典型表现","value":"施里芬计划、德国入侵比利时、1914年西线向巴黎方向推进。"},{"label":"为什么重要","value":"它把德国战略选择推向高风险路径。为了争取速度，德国侵犯比利时中立，导致英国参战；一旦速胜失败，德国就陷入长期消耗战。"},{"label":"争议/局限","value":"速决战设想低估补给、敌方抵抗、英国参战和现代火力防御；它更像一套逐步演化的计划文化，而不是机械执行的单一蓝图。"},{"label":"出处","value":"1914-1918 Online: Schlieffen Plan；German History in Documents and Images: German military planning；Encyclopaedia Britannica: Schlieffen Plan。"}],"relationItems":["← 前因：法俄同盟","↔ 相关：德国施里芬计划","→ 后果：德国入侵比利时","→ 后果：第一次马恩河战役","✗ 对立/冲突：一战西线堑壕战"],"relations":[{"text":"← 前因：法俄同盟","id":"extra928"},{"text":"↔ 相关：德国施里芬计划","id":"extra643"},{"text":"→ 后果：德国入侵比利时","id":"extra647"},{"text":"→ 后果：第一次马恩河战役","id":"extra650"},{"text":"✗ 对立/冲突：一战西线堑壕战","id":"extra651"}],"source":"history","id":"extra927"},{"title":"法俄同盟","level":"B","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1891—1894年形成","place":"法国、俄国、欧洲外交体系","summary":"法俄同盟打破俾斯麦时代法国孤立局面，使德国重新面对两线战争压力。","fields":[{"label":"标题","value":"法俄同盟"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1891—1894年形成"},{"label":"地点","value":"法国、俄国、欧洲外交体系"},{"label":"主要国家","value":"法国；俄国；德国；奥匈帝国"},{"label":"一句话概括","value":"法俄同盟打破俾斯麦时代法国孤立局面，使德国重新面对两线战争压力。"},{"label":"制定方/签署方","value":"法兰西第三共和国与俄罗斯帝国。"},{"label":"主要内容","value":"双方通过外交协议和军事协定承诺在德国或三国同盟威胁下相互支持，并协调军事动员。"},{"label":"它试图解决什么问题","value":"法国需要摆脱普法战争后的外交孤立，俄国需要资金、外交伙伴和制衡1879年德奥同盟的安全支撑。"},{"label":"为什么重要","value":"它重塑欧洲联盟体系，使德国的安全焦虑从法国复仇转为东西两线压力。德国速决战设想、1904年英法协约和协约国体系都与这个结构变化有关。"},{"label":"争议/局限","value":"法国共和制与俄国专制制度差异巨大，同盟更多出于战略需要而非价值一致；它也加剧欧洲集团对立。"},{"label":"造成的影响","value":"德国总参谋部更重视两线战争计划，英国后来逐渐与法俄接近，欧洲形成三国同盟与协约体系对峙。"},{"label":"出处","value":"Encyclopaedia Britannica: Franco-Russian Alliance；German History in Documents and Images: Alliance systems；1914-1918 Online: Pre-war alliances。"}],"relationItems":["← 前因：1879年德奥同盟","→ 后果：机械化战争","→ 后果：1904年英法协约","↔ 相关：德俄再保险条约","✗ 对立/冲突：德国三皇同盟"],"relations":[{"text":"← 前因：1879年德奥同盟","id":"extra755"},{"text":"→ 后果：机械化战争","id":"extra949"},{"text":"→ 后果：1904年英法协约","id":"extra782"},{"text":"↔ 相关：德俄再保险条约","id":"extra632"},{"text":"✗ 对立/冲突：德国三皇同盟","id":"extra749"}],"source":"history","id":"extra928"},{"title":"奥匈帝国民族问题","level":"B","type":"概念/思潮卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1867—1918年，根源更早","place":"奥匈帝国，尤其波希米亚、匈牙利、加利西亚、克罗地亚、波斯尼亚等地","summary":"奥匈帝国民族问题指多民族帝国内民族自治、语言权利和国家忠诚之间的长期张力。","fields":[{"label":"标题","value":"奥匈帝国民族问题"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1867—1918年，根源更早"},{"label":"地点","value":"奥匈帝国，尤其波希米亚、匈牙利、加利西亚、克罗地亚、波斯尼亚等地"},{"label":"主要国家","value":"奥匈帝国；奥地利；匈牙利；捷克；克罗地亚；塞尔维亚；波兰"},{"label":"一句话概括","value":"奥匈帝国民族问题指多民族帝国内民族自治、语言权利和国家忠诚之间的长期张力。"},{"label":"核心主张/思路","value":"帝国内德意志人、匈牙利人、捷克人、南斯拉夫人、波兰人、鲁塞尼亚人、罗马尼亚人等群体在代表权、语言、教育、自治和边界问题上诉求不同。"},{"label":"提出者/代表人物（可选）","value":"捷克民族政治家、匈牙利政治精英、南斯拉夫民族主义者、奥地利皇室改革派等。"},{"label":"它从何而来","value":"1848革命、1867年奥匈妥协、工业化和大众政治扩大了民族政治动员；帝国制度却很难让所有群体获得平等承认。"},{"label":"典型表现","value":"捷克自治要求、匈牙利马扎尔化政策、南斯拉夫统一诉求、波斯尼亚危机、萨拉热窝刺杀。"},{"label":"为什么重要","value":"它不是一战的唯一原因，但解释了奥匈为什么对塞尔维亚民族主义高度敏感，也解释帝国在一战末期为什么迅速解体。"},{"label":"争议/局限","value":"不能把奥匈帝国简单看作必然崩溃的“民族监狱”；帝国内部也存在妥协、地方自治和跨民族合作。"},{"label":"出处","value":"Encyclopaedia Britannica: Austria-Hungary；1914-1918 Online: Nationalities in Austria-Hungary；DHM/LeMO: Österreich-Ungarn。"}],"relationItems":["← 前因：奥匈吞并波斯尼亚危机","↔ 相关：巴尔干民族问题","→ 后果：萨拉热窝刺杀事件","→ 后果：奥匈帝国崩溃","✗ 对立/冲突：奥匈帝国多民族军队"],"relations":[{"text":"← 前因：奥匈吞并波斯尼亚危机","id":"extra787"},{"text":"↔ 相关：巴尔干民族问题","id":"extra930"},{"text":"→ 后果：萨拉热窝刺杀事件","id":"extra644"},{"text":"→ 后果：奥匈帝国崩溃","id":"extra947"},{"text":"✗ 对立/冲突：奥匈帝国多民族军队","id":"extra948"}],"source":"history","id":"extra929"},{"title":"巴尔干民族问题","level":"B","type":"概念/思潮卡","tags":["战争与外交","文化与思想"],"mainTag":"战争与外交","subTag":"文化与思想","timeText":"19世纪—20世纪初","place":"巴尔干半岛","summary":"巴尔干民族问题把奥斯曼衰落、民族建国和大国竞争缠在一起，成为一战前欧洲最危险的火药桶。","fields":[{"label":"标题","value":"巴尔干民族问题"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"19世纪—20世纪初"},{"label":"地点","value":"巴尔干半岛"},{"label":"主要国家","value":"塞尔维亚；奥匈帝国；奥斯曼帝国；保加利亚；希腊；俄罗斯；罗马尼亚"},{"label":"一句话概括","value":"巴尔干民族问题把奥斯曼衰落、民族建国和大国竞争缠在一起，成为一战前欧洲最危险的火药桶。"},{"label":"核心主张/思路","value":"不同民族和国家围绕独立、边界、族群归属和保护权展开竞争，大国则借保护斯拉夫人、维护帝国边界或控制海峡介入。"},{"label":"提出者/代表人物（可选）","value":"塞尔维亚民族主义者、南斯拉夫主义者、俄国泛斯拉夫主义者、奥匈外交集团、奥斯曼改革者。"},{"label":"它从何而来","value":"奥斯曼帝国在欧洲退却，民族主义传播，俄奥两国在东南欧竞争，柏林会议和巴尔干战争留下许多未解决边界与族群问题。"},{"label":"典型表现","value":"波斯尼亚危机、巴尔干战争、塞尔维亚扩张、萨拉热窝刺杀、奥匈对塞尔维亚最后通牒。"},{"label":"为什么重要","value":"它让地区冲突具备牵动联盟体系的能力。1914年，塞尔维亚与奥匈之间的危机正是通过俄国、德国、法国和英国的介入扩展为欧洲大战。"},{"label":"争议/局限","value":"巴尔干不是被动“火药桶”，当地民族政治有自身逻辑；大国干预和帝国边界同样制造了危机。"},{"label":"出处","value":"Encyclopaedia Britannica: Balkan Wars；1914-1918 Online: Balkans；German History in Documents and Images: July Crisis materials。"}],"relationItems":["← 前因：巴尔干危机1878年柏林会议","← 前因：奥匈吞并波斯尼亚危机","↔ 相关：奥匈帝国民族问题","→ 后果：萨拉热窝刺杀事件","→ 后果：第一次世界大战爆发"],"relations":[{"text":"← 前因：巴尔干危机1878年柏林会议","id":"extra753"},{"text":"← 前因：奥匈吞并波斯尼亚危机","id":"extra787"},{"text":"↔ 相关：奥匈帝国民族问题","id":"extra929"},{"text":"→ 后果：萨拉热窝刺杀事件","id":"extra644"},{"text":"→ 后果：第一次世界大战爆发","id":"extra925"}],"source":"history","id":"extra930"},{"title":"协约国统一指挥","level":"C","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1918年3月后","place":"西线协约国司令体系","summary":"协约国统一指挥在1918年把西线协调权集中到福煦手中，提高了抵抗德军攻势和组织反攻的效率。","fields":[{"label":"标题","value":"协约国统一指挥"},{"label":"分级","value":"C"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1918年3月后"},{"label":"地点","value":"西线协约国司令体系"},{"label":"主要国家","value":"法国；英国；美国；意大利；德国"},{"label":"一句话概括","value":"协约国统一指挥在1918年把西线协调权集中到福煦手中，提高了抵抗德军攻势和组织反攻的效率。"},{"label":"制定方/签署方","value":"法国、英国、美国等协约国领导人和军事指挥层。"},{"label":"主要内容","value":"在德国春季攻势压力下，协约国加强跨国战略协调，法国将领费迪南·福煦逐渐成为西线盟军总协调者。"},{"label":"它试图解决什么问题","value":"协约国此前常因各国军队目标、补给、预备队和政治压力不同而协调困难；1918年德军突破威胁迫使其统一指挥。"},{"label":"为什么重要","value":"统一指挥有助于协约国在第二次马恩河战役后转入连续反攻，并支撑百日攻势。它说明现代联盟战争不只拼兵力，也拼协调机制。"},{"label":"争议/局限","value":"统一指挥并不等于完全取消各国自主权，美国、英国和法国仍保留许多政治与军事边界。"},{"label":"造成的影响","value":"协约国反攻能力增强，德国春季攻势失败后难以重新夺回主动权，德国战败进程加速。"},{"label":"出处","value":"1914-1918 Online: Foch, Ferdinand；Encyclopaedia Britannica: Ferdinand Foch；Imperial War Museums: 1918 Allied command materials。"}],"relationItems":["← 前因：德国1918年春季攻势","↔ 相关：第二次马恩河战役","→ 后果：一战百日攻势","✗ 对立/冲突：德国速决战设想"],"relations":[{"text":"← 前因：德国1918年春季攻势","id":"extra663"},{"text":"↔ 相关：第二次马恩河战役","id":"extra715"},{"text":"→ 后果：一战百日攻势","id":"extra664"},{"text":"✗ 对立/冲突：德国速决战设想","id":"extra927"}],"source":"history","id":"extra931"},{"title":"德意志帝国世界贸易扩张","level":"C","type":"概念/思潮卡","tags":["经济与社会","战争与外交"],"mainTag":"经济与社会","subTag":"战争与外交","timeText":"1871—1914年","place":"德国、欧洲市场、全球贸易网络","summary":"德意志帝国通过工业品出口、航运、银行和海外投资快速进入世界市场，引发经济自信和国际摩擦。","fields":[{"label":"标题","value":"德意志帝国世界贸易扩张"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1871—1914年"},{"label":"地点","value":"德国、欧洲市场、全球贸易网络"},{"label":"主要国家","value":"德国；英国；法国；美国；俄罗斯；奥斯曼帝国；中国"},{"label":"一句话概括","value":"德意志帝国通过工业品出口、航运、银行和海外投资快速进入世界市场，引发经济自信和国际摩擦。"},{"label":"核心主张/思路","value":"德国工业化后需要原料、市场、投资机会和航运通道，经济精英与政府逐渐把世界贸易和国家地位联系起来。"},{"label":"提出者/代表人物（可选）","value":"德国工业家、银行家、汉堡和不来梅航运集团、世界政策支持者。"},{"label":"它从何而来","value":"钢铁、化工、电气和机械工业扩张提高出口能力；德意志银行、航运公司和海外商会推动全球经济联系。"},{"label":"典型表现","value":"汉堡-美洲航运公司扩张、德意志银行海外业务、奥斯曼巴格达铁路、对拉美和东亚市场兴趣上升。"},{"label":"为什么重要","value":"世界贸易扩张解释了德意志帝国为什么不满足于欧洲大陆强国地位，也解释了世界政策、海军扩张和殖民诉求背后的经济动力。"},{"label":"争议/局限","value":"德国对外贸易扩张不必然导致战争，但在保护主义、海军竞争和殖民政治中被赋予强烈地缘意义。"},{"label":"出处","value":"German History in Documents and Images: Imperial Germany economy；DHM/LeMO: Kaiserreich Wirtschaft；Encyclopaedia Britannica: Germany, history。"}],"relationItems":["← 前因：德国工业化","↔ 相关：德意志帝国世界政策","↔ 相关：汉堡-美洲航运公司","↔ 相关：德意志银行成立","→ 后果：德意志帝国海军扩张"],"relations":[{"text":"← 前因：德国工业化","id":"extra933"},{"text":"↔ 相关：德意志帝国世界政策","id":"extra635"},{"text":"↔ 相关：汉堡-美洲航运公司","id":"extra840"},{"text":"↔ 相关：德意志银行成立","id":"extra842"},{"text":"→ 后果：德意志帝国海军扩张","id":"extra636"}],"source":"history","id":"extra932"},{"title":"德国工业化","level":"A","type":"概念/思潮卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"19世纪中期—20世纪初","place":"鲁尔、萨尔、西里西亚、柏林、萨克森等工业区","summary":"德国工业化把分散邦国经济转变为欧洲领先工业体系，重塑社会阶级、城市和国家能力。","fields":[{"label":"标题","value":"德国工业化"},{"label":"分级","value":"A"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"19世纪中期—20世纪初"},{"label":"地点","value":"鲁尔、萨尔、西里西亚、柏林、萨克森等工业区"},{"label":"主要国家","value":"德国；普鲁士"},{"label":"一句话概括","value":"德国工业化把分散邦国经济转变为欧洲领先工业体系，重塑社会阶级、城市和国家能力。"},{"label":"核心主张/思路","value":"铁路、煤铁、化学、电气、银行和技术教育共同推动生产扩张，国家制度和市场整合为工业化提供条件。"},{"label":"提出者/代表人物（可选）","value":"企业家、工程师、银行家、普鲁士和帝国政府经济官僚。"},{"label":"它从何而来","value":"德意志关税同盟、铁路建设、煤铁资源、普鲁士教育体系和后发工业化的技术引进共同积累基础。"},{"label":"典型表现","value":"鲁尔工业区扩张、克虏伯公司成长、化学工业和电气工业崛起、城市人口快速增加。"},{"label":"为什么重要","value":"它是德意志统一和帝国强国地位的经济底座，也制造工人阶级、社会问题、城市住房、工会和社会主义政治的压力。"},{"label":"争议/局限","value":"工业化带来财富和技术能力，也带来阶级分化、环境污染、住房拥挤和劳资冲突。"},{"label":"出处","value":"German History in Documents and Images: Industrialization；DHM/LeMO: Industrialisierung；Encyclopaedia Britannica: Germany, economy and history。"}],"relationItems":["← 前因：德意志关税同盟（Zollverein）","← 前因：德国铁路建设","→ 后果：德国工人阶级形成","→ 后果：工业化时代的德国城市社会","↔ 相关：德国鲁尔工业区","↔ 相关：德国化学工业"],"relations":[{"text":"← 前因：德意志关税同盟（Zollverein）","id":"extra486"},{"text":"← 前因：德国铁路建设","id":"extra507"},{"text":"→ 后果：德国工人阶级形成","id":"extra941"},{"text":"→ 后果：工业化时代的德国城市社会","id":"extra934"},{"text":"↔ 相关：德国鲁尔工业区","id":"extra679"},{"text":"↔ 相关：德国化学工业","id":"extra680"}],"source":"history","id":"extra933"},{"title":"工业化时代的德国城市社会","level":"B","type":"概念/思潮卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"19世纪后期—20世纪初","place":"柏林、鲁尔城市、汉堡、慕尼黑、莱比锡等","summary":"工业化时代德国城市社会由工厂、租住营房、公共卫生、交通和大众消费共同塑造。","fields":[{"label":"标题","value":"工业化时代的德国城市社会"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"19世纪后期—20世纪初"},{"label":"地点","value":"柏林、鲁尔城市、汉堡、慕尼黑、莱比锡等"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"工业化时代德国城市社会由工厂、租住营房、公共卫生、交通和大众消费共同塑造。"},{"label":"核心主张/思路","value":"工业就业吸引人口进入城市，城市空间成为阶级分化、公共治理、卫生改革、交通网络和现代文化的集中场所。"},{"label":"提出者/代表人物（可选）","value":"城市规划者、卫生官员、工人组织、地产商、市政改革者。"},{"label":"它从何而来","value":"德国工业化、铁路和电车网络、农村人口流动、工厂集中和市政管理能力扩张。"},{"label":"典型表现","value":"柏林租住营房、城市公共卫生运动、电车网络、百货商店、广告业、工人区和市政公用事业。"},{"label":"为什么重要","value":"它把帝国德国的经济增长转化为日常生活经验。理解魏玛柏林现代性、工人政治和大众文化，都要从帝国时期城市化开始。"},{"label":"争议/局限","value":"城市现代性并不均衡，住房拥挤、疾病、阶级隔离和治安焦虑长期存在。"},{"label":"出处","value":"German History in Documents and Images: Urban society in Imperial Germany；DHM/LeMO: Urbanisierung；Encyclopaedia Britannica: Berlin, history。"}],"relationItems":["← 前因：德国工业化","↔ 相关：德意志帝国柏林租住营房","↔ 相关：德国城市公共卫生运动","↔ 相关：德意志帝国城市电车网络","→ 后果：魏玛柏林现代性"],"relations":[{"text":"← 前因：德国工业化","id":"extra933"},{"text":"↔ 相关：德意志帝国柏林租住营房","id":"extra683"},{"text":"↔ 相关：德国城市公共卫生运动","id":"extra733"},{"text":"↔ 相关：德意志帝国城市电车网络","id":"extra832"},{"text":"→ 后果：魏玛柏林现代性","id":"card33"}],"source":"history","id":"extra934"},{"title":"德国大学研究体系","level":"B","type":"概念/思潮卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"19世纪—20世纪初","place":"柏林、哥廷根、海德堡、慕尼黑、耶拿等大学城市","summary":"德国大学研究体系把教学、实验室和专业学科结合起来，成为现代研究型大学的重要范式。","fields":[{"label":"标题","value":"德国大学研究体系"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"19世纪—20世纪初"},{"label":"地点","value":"柏林、哥廷根、海德堡、慕尼黑、耶拿等大学城市"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国大学研究体系把教学、实验室和专业学科结合起来，成为现代研究型大学的重要范式。"},{"label":"核心主张/思路","value":"大学不仅传授知识，也应通过研究生产新知识；学术自由、研究所、博士训练和国家支持共同构成制度基础。"},{"label":"提出者/代表人物（可选）","value":"威廉·冯·洪堡；德国大学教授群体；国家教育官僚。"},{"label":"它从何而来","value":"洪堡大学模式、邦国教育改革、科学专业化和工业化对技术知识的需求。"},{"label":"典型表现","value":"研究型研讨班、实验室、博士制度、专业期刊、威廉皇帝学会和大学—工业合作。"},{"label":"为什么重要","value":"它影响全球高等教育制度，也解释德国为何在化学、物理、医学和工程领域形成强大科研能力。"},{"label":"争议/局限","value":"大学体系高度精英化，女性和少数群体进入受限；国家和工业资助也可能影响研究方向。"},{"label":"出处","value":"German History in Documents and Images: German universities；DHM/LeMO: Wissenschaft und Bildung；Encyclopaedia Britannica: Wilhelm von Humboldt。"}],"relationItems":["← 前因：德国洪堡大学模式","↔ 相关：德意志帝国研究型大学扩张","↔ 相关：德意志帝国威廉皇帝学会","→ 后果：普朗克量子假说","→ 后果：爱因斯坦广义相对论"],"relations":[{"text":"← 前因：德国洪堡大学模式","id":"extra515"},{"text":"↔ 相关：德意志帝国研究型大学扩张","id":"extra821"},{"text":"↔ 相关：德意志帝国威廉皇帝学会","id":"extra845"},{"text":"→ 后果：普朗克量子假说","id":"extra722"},{"text":"→ 后果：爱因斯坦广义相对论","id":"extra723"}],"source":"history","id":"extra935"},{"title":"一战士兵经验","level":"C","type":"概念/思潮卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"1914—1918年","place":"西线、东线、意大利战线、巴尔干和殖民地战场","summary":"一战士兵经验由堑壕、炮火、等待、伤亡、战友关系和战后记忆共同构成。","fields":[{"label":"标题","value":"一战士兵经验"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1914—1918年"},{"label":"地点","value":"西线、东线、意大利战线、巴尔干和殖民地战场"},{"label":"主要国家","value":"德国；法国；英国；俄国；奥匈帝国；意大利；美国"},{"label":"一句话概括","value":"一战士兵经验由堑壕、炮火、等待、伤亡、战友关系和战后记忆共同构成。"},{"label":"核心主张/思路","value":"现代工业战争把士兵置于长时间火力、泥泞、疾病、恐惧和纪律之下，同时也形成战友共同体、敌我想象和对国家动员的复杂感受。"},{"label":"提出者/代表人物（可选）","value":"前线士兵、战地记者、战后回忆录作者、文学作品作者。"},{"label":"它从何而来","value":"机枪、重炮、堑壕体系、动员国家和长期消耗战改变了传统战斗经验。"},{"label":"典型表现","value":"堑壕生活、圣诞休战、毒气恐惧、炮弹休克、战友团体、休假与后方疏离。"},{"label":"为什么重要","value":"士兵经验影响战后政治文化、纪念文化和反战文学，也被民族主义和右翼政治重新解释。德国“前线共同体”想象和《西线无战事》的反战表达都来自这类经验。"},{"label":"争议/局限","value":"不同战线、军队和阶层的经验差异很大，不能把所有士兵体验简化为同一种“堑壕经验”。"},{"label":"出处","value":"1914-1918 Online: Soldiers；Imperial War Museums: Life in the trenches；German History in Documents and Images: War experience。"}],"relationItems":["← 前因：一战西线堑壕战","↔ 相关：1914年圣诞休战","↔ 相关：毒气战","→ 后果：第一次世界大战德国战败","↔ 相关：《西线无战事》"],"relations":[{"text":"← 前因：一战西线堑壕战","id":"extra651"},{"text":"↔ 相关：1914年圣诞休战","id":"extra705"},{"text":"→ 后果：第一次世界大战德国战败","id":"extra926"},{"text":"↔ 相关：《西线无战事》","id":"extra64"}],"source":"history","id":"extra936"},{"title":"俄国二月革命","level":"A","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1917年3月（俄历2月）","place":"彼得格勒及俄罗斯帝国","summary":"俄国二月革命推翻沙皇制度，使俄国战争能力和东线格局迅速发生变化。","fields":[{"label":"标题","value":"俄国二月革命"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1917年3月（俄历2月）"},{"label":"地点","value":"彼得格勒及俄罗斯帝国"},{"label":"主要国家","value":"俄罗斯；德国；奥匈帝国；协约国"},{"label":"一句话概括","value":"俄国二月革命推翻沙皇制度，使俄国战争能力和东线格局迅速发生变化。"},{"label":"参与者","value":"彼得格勒工人和士兵、国家杜马、临时政府、沙皇尼古拉二世、革命政党。"},{"label":"发生了什么","value":"战争消耗、粮食短缺、政府失能和军队厌战在彼得格勒引发罢工与示威。士兵倒戈后，沙皇失去控制并退位。临时政府成立，但继续参战，与苏维埃并存的双重权力局面形成。"},{"label":"为什么重要","value":"它削弱协约国东线力量，并为十月革命和《布列斯特-立托夫斯克条约》铺路。德国则试图利用俄国革命退出战争来集中兵力于西线。"},{"label":"前因","value":"一战长期消耗、俄军失败、粮食与运输危机、沙皇政府合法性崩溃。"},{"label":"后果","value":"沙皇制度终结，临时政府继续参战但难以稳定局势，布尔什维克最终夺权并推动俄国退出战争。"},{"label":"出处","value":"Encyclopaedia Britannica: Russian Revolution of 1917；1914-1918 Online: Russian Revolution；German History in Documents and Images: Brest-Litovsk context。"}],"relationItems":["← 前因：一战东线加利西亚战役","← 前因：布鲁西洛夫攻势","→ 后果：《布列斯特-立托夫斯克条约》","↔ 相关：德国1918年春季攻势","↔ 相关：第一次世界大战德国战败"],"relations":[{"text":"← 前因：一战东线加利西亚战役","id":"extra702"},{"text":"← 前因：布鲁西洛夫攻势","id":"extra710"},{"text":"→ 后果：《布列斯特-立托夫斯克条约》","id":"extra662"},{"text":"↔ 相关：德国1918年春季攻势","id":"extra663"},{"text":"↔ 相关：第一次世界大战德国战败","id":"extra926"}],"source":"history","id":"extra937"},{"title":"兴登堡和鲁登道夫崛起","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1914—1916年，1916年后达到顶点","place":"东线、德国最高统帅部","summary":"兴登堡和鲁登道夫借东线胜利建立声望，并在1916年后成为德国事实上的军事政治核心。","fields":[{"label":"标题","value":"兴登堡和鲁登道夫崛起"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1914—1916年，1916年后达到顶点"},{"label":"地点","value":"东线、德国最高统帅部"},{"label":"主要国家","value":"德国；俄国；奥匈帝国"},{"label":"一句话概括","value":"兴登堡和鲁登道夫借东线胜利建立声望，并在1916年后成为德国事实上的军事政治核心。"},{"label":"参与者","value":"保罗·冯·兴登堡、埃里希·鲁登道夫、德国总参谋部、德皇威廉二世、贝特曼-霍尔维格政府。"},{"label":"发生了什么","value":"1914年坦能堡战役后，兴登堡和鲁登道夫成为德国公众眼中的东线英雄。1916年，法金汉下台，两人进入第三最高陆军统帅部，掌握战略决策和国内动员巨大权力，推动兴登堡计划、无限制潜艇战和更激进的战争目标。"},{"label":"为什么重要","value":"他们的崛起说明一战后期德国政治军事化加深，文官政府被最高统帅部压制。魏玛时期兴登堡的声望和鲁登道夫的右翼政治活动，也延续了这种战时权威。"},{"label":"前因","value":"坦能堡战役胜利、东线宣传、德军对决定性军事领导的需求。"},{"label":"后果","value":"第三最高陆军统帅部权力上升，德国进入更彻底的战争动员，也为战败责任转嫁和“背后一刀”传说创造条件。"},{"label":"出处","value":"1914-1918 Online: Hindenburg, Ludendorff；DHM/LeMO: Hindenburg und Ludendorff；Encyclopaedia Britannica: Erich Ludendorff。"}],"relationItems":["← 前因：一战东线坦能堡战役","→ 后果：德国兴登堡计划","→ 后果：德国第三最高陆军统帅部","↔ 相关：埃里希·鲁登道夫","↔ 相关：保罗·冯·兴登堡"],"relations":[{"text":"← 前因：一战东线坦能堡战役","id":"extra649"},{"text":"→ 后果：德国兴登堡计划","id":"card1"},{"text":"→ 后果：德国第三最高陆军统帅部","id":"extra797"},{"text":"↔ 相关：埃里希·鲁登道夫","id":"extra798"},{"text":"↔ 相关：保罗·冯·兴登堡","id":"card37"}],"source":"history","id":"extra938"},{"title":"坦克技术","level":"C","type":"概念/思潮卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1916年后，20世纪持续发展","place":"西线战场，尤其英国、法国和德国军工体系","summary":"坦克技术在一战中为突破堑壕和火力防御而出现，起初粗糙但预示装甲战争方向。","fields":[{"label":"标题","value":"坦克技术"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1916年后，20世纪持续发展"},{"label":"地点","value":"西线战场，尤其英国、法国和德国军工体系"},{"label":"主要国家","value":"英国；法国；德国；美国"},{"label":"一句话概括","value":"坦克技术在一战中为突破堑壕和火力防御而出现，起初粗糙但预示装甲战争方向。"},{"label":"核心主张/思路","value":"用装甲、履带和火力结合，跨越壕沟、铁丝网和泥地，在机枪火力下保护步兵并恢复战场机动性。"},{"label":"提出者/代表人物（可选）","value":"英国陆军和海军技术推动者、法国雷诺坦克设计体系、各国军工工程师。"},{"label":"它从何而来","value":"西线堑壕僵局、机枪和炮兵防御、步兵突破高伤亡迫使军队寻找机械化突破工具。"},{"label":"典型表现","value":"1916年索姆河战役首次使用坦克，1917年康布雷战役较集中使用，1918年协约国在综合兵种作战中更有效运用。"},{"label":"为什么重要","value":"坦克在一战中尚未决定战争，但改变了军事想象。二战装甲战和机械化战争的基础，正是在一战末期的技术与战术实验中形成。"},{"label":"争议/局限","value":"早期坦克速度慢、故障多、通信差，单独使用效果有限，必须与炮兵、步兵、航空和后勤协同。"},{"label":"出处","value":"1914-1918 Online: Tanks and Tank Warfare；Imperial War Museums: First World War tanks；Encyclopaedia Britannica: tank military vehicle。"}],"relationItems":["← 前因：一战西线堑壕战","↔ 相关：索姆河战役","↔ 相关：康布雷战役","→ 后果：机械化战争","✗ 对立/冲突：纵深防御"],"relations":[{"text":"← 前因：一战西线堑壕战","id":"extra651"},{"text":"↔ 相关：索姆河战役","id":"extra655"},{"text":"↔ 相关：康布雷战役","id":"extra714"},{"text":"→ 后果：机械化战争","id":"extra949"},{"text":"✗ 对立/冲突：纵深防御","id":"extra955"}],"source":"history","id":"extra939"},{"title":"弗里茨·哈伯","level":"B","type":"人物卡","tags":["文化与思想","战争与外交"],"mainTag":"文化与思想","subTag":"战争与外交","timeText":"1868—1934年","place":"德国科研机构、化学工业和一战战场","summary":"弗里茨·哈伯既因合成氨技术改变农业和工业，也因推动化学战而成为科学伦理争议人物。","fields":[{"label":"标题","value":"弗里茨·哈伯"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1868—1934年"},{"label":"地点","value":"德国科研机构、化学工业和一战战场"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"弗里茨·哈伯既因合成氨技术改变农业和工业，也因推动化学战而成为科学伦理争议人物。"},{"label":"生卒年/活跃年代","value":"1868—1934年；20世纪初至一战期间最具影响力。"},{"label":"身份/职务","value":"化学家、德国科研机构负责人、诺贝尔化学奖获得者。"},{"label":"关键贡献/作为","value":"与工业体系共同推动合成氨技术，为化肥和炸药原料生产提供基础；一战中参与毒气战组织和化学武器研发。"},{"label":"核心主张/立场","value":"强调科学服务国家和工业需求，一战中将化学研究直接纳入战争动员。"},{"label":"为什么重要","value":"哈伯体现现代科学的双重性：同一套化学能力既能提高粮食生产，也能服务工业化战争。德国化学工业、合成氨哈伯-博施法和毒气战都与他相关。"},{"label":"争议/评价","value":"他因合成氨获得科学声望，却因化学战留下严重伦理争议；作为犹太裔德国人，他后来也被纳粹排斥。"},{"label":"关联事件（可选）","value":"合成氨哈伯-博施法；第二次伊普尔战役；德国化学工业。"},{"label":"出处","value":"Encyclopaedia Britannica: Fritz Haber；Nobel Prize: Fritz Haber biography；1914-1918 Online: Gas Warfare。"}],"relationItems":["↔ 相关：合成氨哈伯-博施法","↔ 相关：德国化学工业","→ 后果：第二次伊普尔战役","↔ 相关：德国大学研究体系"],"relations":[{"text":"↔ 相关：合成氨哈伯-博施法","id":"extra681"},{"text":"↔ 相关：德国化学工业","id":"extra680"},{"text":"→ 后果：第二次伊普尔战役","id":"extra707"},{"text":"↔ 相关：德国大学研究体系","id":"extra935"}],"source":"history","id":"extra940"},{"title":"德国工人阶级形成","level":"B","type":"概念/思潮卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"19世纪中期—20世纪初","place":"鲁尔、柏林、萨克森、西里西亚、汉堡等工业区","summary":"德国工人阶级形成伴随工业化、城市化和劳工组织扩张，成为帝国政治和社会政策的核心力量。","fields":[{"label":"标题","value":"德国工人阶级形成"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"19世纪中期—20世纪初"},{"label":"地点","value":"鲁尔、柏林、萨克森、西里西亚、汉堡等工业区"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德国工人阶级形成伴随工业化、城市化和劳工组织扩张，成为帝国政治和社会政策的核心力量。"},{"label":"核心主张/思路","value":"大量农村人口和手工业者进入工厂、矿山、铁路和城市服务业，逐渐形成以工资劳动、工会、社民党和工人文化为纽带的社会群体。"},{"label":"提出者/代表人物（可选）","value":"工会组织者、社民党活动家、拉萨尔、倍倍尔、李卜克内西等。"},{"label":"它从何而来","value":"德国工业化、铁路建设、煤钢产业、城市扩张和人口流动改变了劳动结构。"},{"label":"典型表现","value":"全德工人联合会、爱森纳赫派、德国社会民主党、自由工会、工人体育和工人报刊网络。"},{"label":"为什么重要","value":"工人阶级形成推动了德国社会民主主义、社会保险立法和阶级政治，也解释帝德和魏玛时期劳资冲突与福利国家建设。"},{"label":"争议/局限","value":"工人阶级内部按技能、性别、地区、宗教和政治倾向差异很大，并非天然统一。"},{"label":"出处","value":"German History in Documents and Images: Labor movement；DHM/LeMO: Arbeiterbewegung；Encyclopaedia Britannica: Social Democratic Party of Germany。"}],"relationItems":["← 前因：德国工业化","↔ 相关：十九世纪德国社会问题","→ 后果：德国社会民主党（SPD）","→ 后果：德国自由工会总委员会","↔ 相关：德国俾斯麦社会保险立法"],"relations":[{"text":"← 前因：德国工业化","id":"extra933"},{"text":"↔ 相关：十九世纪德国社会问题","id":"extra511"},{"text":"→ 后果：德国社会民主党（SPD）","id":"extra628"},{"text":"→ 后果：德国自由工会总委员会","id":"extra739"},{"text":"↔ 相关：德国俾斯麦社会保险立法","id":"extra629"}],"source":"history","id":"extra941"},{"title":"德国殖民扩张","level":"B","type":"事件卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1880年代—1914年","place":"非洲、太平洋、中国胶州湾等","summary":"德国殖民扩张使后起的德意志帝国进入海外帝国竞争，也带来殖民暴力和国际摩擦。","fields":[{"label":"标题","value":"德国殖民扩张"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1880年代—1914年"},{"label":"地点","value":"非洲、太平洋、中国胶州湾等"},{"label":"主要国家","value":"德国；喀麦隆；多哥；纳米比亚；坦桑尼亚；中国；英国；法国"},{"label":"一句话概括","value":"德国殖民扩张使后起的德意志帝国进入海外帝国竞争，也带来殖民暴力和国际摩擦。"},{"label":"参与者","value":"德意志帝国政府、殖民协会、商人和传教网络、殖民地居民、非洲和太平洋地方政权。"},{"label":"发生了什么","value":"1880年代起，德国在非洲和太平洋建立保护地，后来又强租胶州湾。殖民扩张最初与商业、传教和民族声望相关，随后被纳入世界政策和海军扩张。德国殖民统治在德属西南非洲等地造成严重暴力。"},{"label":"为什么重要","value":"它说明德意志帝国不只是欧洲大陆强国，也参与全球帝国主义竞争。殖民扩张影响德国世界政策、国内民族主义和一战中的海外战场。"},{"label":"前因","value":"德国工业化、世界贸易扩张、泛德意志民族主义、殖民协会宣传和列强瓜分非洲。"},{"label":"后果","value":"德国建立德意志殖民帝国，参与柏林西非会议和八国联军干预义和团运动，一战后殖民地被委任统治体系接管。"},{"label":"出处","value":"DHM/LeMO: Deutscher Kolonialismus；German History in Documents and Images: Colonialism；Encyclopaedia Britannica: German East Africa, German South West Africa。"}],"relationItems":["← 前因：德意志帝国世界贸易扩张","↔ 相关：德意志殖民帝国","↔ 相关：德国殖民协会","→ 后果：德属西南非洲赫雷罗和纳马种族灭绝","→ 后果：一战后国际联盟委任统治体系"],"relations":[{"text":"← 前因：德意志帝国世界贸易扩张","id":"extra932"},{"text":"↔ 相关：德意志殖民帝国","id":"extra641"},{"text":"↔ 相关：德国殖民协会","id":"extra677"},{"text":"→ 后果：德属西南非洲赫雷罗和纳马种族灭绝","id":"extra642"},{"text":"→ 后果：一战后国际联盟委任统治体系","id":"card5"}],"source":"history","id":"extra942"},{"title":"德国移民潮","level":"C","type":"概念/思潮卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"19世纪，尤其1830年代—1890年代","place":"德意志地区、美国、巴西、阿根廷等移民目的地","summary":"19世纪德国移民潮把贫困、政治流亡、土地压力和跨大西洋机会连接起来。","fields":[{"label":"标题","value":"德国移民潮"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"19世纪，尤其1830年代—1890年代"},{"label":"地点","value":"德意志地区、美国、巴西、阿根廷等移民目的地"},{"label":"主要国家","value":"德国；美国；巴西；阿根廷"},{"label":"一句话概括","value":"19世纪德国移民潮把贫困、政治流亡、土地压力和跨大西洋机会连接起来。"},{"label":"核心主张/思路","value":"人口增长、农业压力、经济危机、宗教和政治限制推动许多德意志人离开欧洲，前往美洲寻找土地、工作和自由空间。"},{"label":"提出者/代表人物（可选）","value":"普通农民、手工业者、1848革命流亡者、移民代理和航运公司。"},{"label":"它从何而来","value":"德意志地区经济转型不均、1848革命失败、农村土地不足、跨大西洋航运和美国西进机会共同推动迁徙。"},{"label":"典型表现","value":"德裔美国社群扩大，1848革命者流亡美国，汉堡和不来梅成为重要出境港。"},{"label":"为什么重要","value":"它把德国近代史放入全球人口流动史。德国并不只是移入工人的工业国家，也曾是重要移民输出地。"},{"label":"争议/局限","value":"移民原因并不单一，不同地区、阶层和宗教群体迁徙动机差异很大。"},{"label":"出处","value":"German Historical Institute: German migration materials；German History in Documents and Images: Emigration；Encyclopaedia Britannica: German Americans。"}],"relationItems":["← 前因：十九世纪德国社会问题","↔ 相关：德国工业化","↔ 相关：汉堡-美洲航运公司","→ 后果：德意志帝国世界贸易扩张"],"relations":[{"text":"← 前因：十九世纪德国社会问题","id":"extra511"},{"text":"↔ 相关：德国工业化","id":"extra933"},{"text":"↔ 相关：汉堡-美洲航运公司","id":"extra840"},{"text":"→ 后果：德意志帝国世界贸易扩张","id":"extra932"}],"source":"history","id":"extra943"},{"title":"德意志帝国城市现代性","level":"C","type":"概念/思潮卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"1871—1914年","place":"柏林、汉堡、慕尼黑、莱比锡、鲁尔城市群","summary":"德意志帝国城市现代性表现为电车、广告、百货商店、公共卫生和大众娱乐的新城市经验。","fields":[{"label":"标题","value":"德意志帝国城市现代性"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1871—1914年"},{"label":"地点","value":"柏林、汉堡、慕尼黑、莱比锡、鲁尔城市群"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"德意志帝国城市现代性表现为电车、广告、百货商店、公共卫生和大众娱乐的新城市经验。"},{"label":"核心主张/思路","value":"现代城市不只是人口集中，也是技术、消费、阶级、性别和视觉文化重组的空间。"},{"label":"提出者/代表人物（可选）","value":"市政官员、企业家、广告业者、城市居民、文化评论者。"},{"label":"它从何而来","value":"德国工业化、城市化、市政公用事业、电力和交通网络扩张。"},{"label":"典型表现","value":"柏林电车和排水系统、百货商店、广告业、电影院前身娱乐、公共卫生改革、租住营房和城市匿名性。"},{"label":"为什么重要","value":"它为魏玛柏林现代性提供基础。许多看似魏玛时期突然出现的都市文化，其实在帝国晚期已经形成。"},{"label":"争议/局限","value":"城市现代性常与贫困、拥挤、道德恐慌和社会控制并存。"},{"label":"出处","value":"German History in Documents and Images: Urban modernity；DHM/LeMO: Kaiserreich Alltag；Peter Fritzsche, Reading Berlin 1900。"}],"relationItems":["← 前因：工业化时代的德国城市社会","↔ 相关：德意志帝国城市电车网络","↔ 相关：德意志帝国广告业兴起","→ 后果：魏玛柏林现代性","↔ 相关：德国百货商店兴起"],"relations":[{"text":"← 前因：工业化时代的德国城市社会","id":"extra934"},{"text":"↔ 相关：德意志帝国城市电车网络","id":"extra832"},{"text":"↔ 相关：德意志帝国广告业兴起","id":"extra834"},{"text":"→ 后果：魏玛柏林现代性","id":"card33"},{"text":"↔ 相关：德国百货商店兴起","id":"extra730"}],"source":"history","id":"extra944"},{"title":"德法复仇主义","level":"C","type":"概念/思潮卡","tags":["文化与思想","战争与外交"],"mainTag":"文化与思想","subTag":"战争与外交","timeText":"1871—1914年","place":"法国、德国、阿尔萨斯-洛林","summary":"德法复仇主义围绕普法战争记忆和阿尔萨斯-洛林归属，长期毒化两国关系。","fields":[{"label":"标题","value":"德法复仇主义"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1871—1914年"},{"label":"地点","value":"法国、德国、阿尔萨斯-洛林"},{"label":"主要国家","value":"法国；德国"},{"label":"一句话概括","value":"德法复仇主义围绕普法战争记忆和阿尔萨斯-洛林归属，长期毒化两国关系。"},{"label":"核心主张/思路","value":"法国部分舆论要求收复阿尔萨斯-洛林、洗刷1871年战败屈辱；德国则把新边界视为帝国安全和统一胜利象征。"},{"label":"提出者/代表人物（可选）","value":"法国民族主义者、退伍军人团体、德国民族主义者、边境地区政治力量。"},{"label":"它从何而来","value":"普法战争、巴黎公社后的法国政治创伤、法兰克福和约割地、德国帝国成立。"},{"label":"典型表现","value":"阿尔萨斯-洛林纪念政治、法国军队改革、德国对法国复仇能力的警惕、萨伯恩事件中的身份冲突。"},{"label":"为什么重要","value":"它解释了法俄同盟、德国战争在望危机和一战前德法敌对情绪的长期背景。"},{"label":"争议/局限","value":"法国外交并不总是被复仇主义完全支配，现实安全、殖民利益和国内政治同样重要。"},{"label":"出处","value":"Encyclopaedia Britannica: Alsace-Lorraine；German History in Documents and Images: Franco-German relations；DHM/LeMO: Elsass-Lothringen。"}],"relationItems":["← 前因：普法战争","← 前因：阿尔萨斯-洛林问题的形成","↔ 相关：阿尔萨斯-洛林并入德意志帝国","→ 后果：法俄同盟","↔ 相关：德意志帝国萨伯恩事件"],"relations":[{"text":"← 前因：普法战争","id":"extra497"},{"text":"← 前因：阿尔萨斯-洛林问题的形成","id":"extra620"},{"text":"↔ 相关：阿尔萨斯-洛林并入德意志帝国","id":"extra745"},{"text":"→ 后果：法俄同盟","id":"extra928"},{"text":"↔ 相关：德意志帝国萨伯恩事件","id":"extra690"}],"source":"history","id":"extra945"},{"title":"战争宣传","level":"C","type":"概念/思潮卡","tags":["文化与思想","战争与外交"],"mainTag":"文化与思想","subTag":"战争与外交","timeText":"一战期间尤为突出，20世纪持续发展","place":"欧洲交战国、美国及全球舆论空间","summary":"战争宣传通过新闻、海报、电影、演说和敌人形象塑造，把社会动员和战争合法性连在一起。","fields":[{"label":"标题","value":"战争宣传"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"一战期间尤为突出，20世纪持续发展"},{"label":"地点","value":"欧洲交战国、美国及全球舆论空间"},{"label":"主要国家","value":"德国；英国；法国；美国；奥匈帝国；俄国"},{"label":"一句话概括","value":"战争宣传通过新闻、海报、电影、演说和敌人形象塑造，把社会动员和战争合法性连在一起。"},{"label":"核心主张/思路","value":"现代战争需要动员士兵、纳税人、工人和家庭，因此国家与媒体用爱国、恐惧、仇恨、牺牲和胜利叙事维持战争支持。"},{"label":"提出者/代表人物（可选）","value":"政府宣传机构、报刊业、艺术家、电影制作者、军方新闻部门。"},{"label":"它从何而来","value":"大众报刊、识字率提高、政党政治、总动员战争和国家宣传机构发展。"},{"label":"典型表现","value":"英国反德暴行宣传、德国战争贷款宣传、美国参战宣传、威廉二世《匈奴演说》战后形象化传播。"},{"label":"为什么重要","value":"战争宣传影响公众对敌人的理解，也影响战后责任、记忆和政治极化。魏玛和纳粹宣传机器都继承并改造了一战宣传经验。"},{"label":"争议/局限","value":"宣传不是单向灌输，公众会选择性接受、抵抗或重新解释宣传内容。"},{"label":"出处","value":"1914-1918 Online: Propaganda；Imperial War Museums: First World War propaganda；German History in Documents and Images: Wartime propaganda。"}],"relationItems":["← 前因：一战总动员社会","↔ 相关：威廉二世《匈奴演说》","↔ 相关：德国1914年战争贷款表决","→ 后果：纳粹宣传机器","✗ 对立/冲突：一战士兵经验"],"relations":[{"text":"← 前因：一战总动员社会","id":"extra653"},{"text":"↔ 相关：威廉二世《匈奴演说》","id":"extra75"},{"text":"↔ 相关：德国1914年战争贷款表决","id":"extra691"},{"text":"→ 后果：纳粹宣传机器","id":"extra94"},{"text":"✗ 对立/冲突：一战士兵经验","id":"extra936"}],"source":"history","id":"extra946"},{"title":"奥匈帝国崩溃","level":"A","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1918年","place":"奥匈帝国及中东欧","summary":"一战末期奥匈帝国在军事失败、民族运动和政治合法性崩溃中解体。","fields":[{"label":"标题","value":"奥匈帝国崩溃"},{"label":"分级","value":"A"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1918年"},{"label":"地点","value":"奥匈帝国及中东欧"},{"label":"主要国家","value":"奥匈帝国；奥地利；匈牙利；捷克斯洛伐克；南斯拉夫；意大利"},{"label":"一句话概括","value":"一战末期奥匈帝国在军事失败、民族运动和政治合法性崩溃中解体。"},{"label":"参与者","value":"哈布斯堡皇室、奥地利和匈牙利政府、捷克、南斯拉夫、波兰、罗马尼亚等民族政治力量、协约国。"},{"label":"发生了什么","value":"一战长期消耗使奥匈帝国粮食、财政和军队承受力下降。1918年，前线失败和国内民族委员会行动加速帝国瓦解。捷克斯洛伐克、南斯拉夫国家和波兰复国运动相继宣布脱离帝国结构，匈牙利也与奥地利分离。哈布斯堡皇帝失去实际统治权。"},{"label":"为什么重要","value":"奥匈帝国崩溃重画中东欧地图，也使德国失去最重要盟友之一。凡尔赛体系、圣日耳曼条约和特里亚农条约都建立在这一解体事实上。"},{"label":"前因","value":"奥匈帝国民族问题、巴尔干民族问题、一战军事消耗、粮食危机和协约国支持民族自决。"},{"label":"后果","value":"奥地利共和国、匈牙利、捷克斯洛伐克和南斯拉夫等新国家出现，中东欧边界和少数民族问题长期不稳定。"},{"label":"出处","value":"Encyclopaedia Britannica: Austria-Hungary；1914-1918 Online: Austria-Hungary；DHM/LeMO: Ende des Ersten Weltkriegs。"}],"relationItems":["← 前因：奥匈帝国民族问题","← 前因：瓦尔达尔攻势","→ 后果：一战停战","→ 后果：一战后巴黎和会","↔ 相关：第一次世界大战德国战败"],"relations":[{"text":"← 前因：奥匈帝国民族问题","id":"extra929"},{"text":"← 前因：瓦尔达尔攻势","id":"extra718"},{"text":"→ 后果：一战停战","id":"extra667"},{"text":"→ 后果：一战后巴黎和会","id":"extra668"},{"text":"↔ 相关：第一次世界大战德国战败","id":"extra926"}],"source":"history","id":"extra947"},{"title":"奥匈帝国多民族军队","level":"C","type":"组织/机构卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1867—1918年","place":"奥匈帝国及一战各战线","summary":"奥匈帝国军队由多民族士兵组成，既体现帝国整合能力，也暴露语言、忠诚和补给难题。","fields":[{"label":"标题","value":"奥匈帝国多民族军队"},{"label":"分级","value":"C"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1867—1918年"},{"label":"地点","value":"奥匈帝国及一战各战线"},{"label":"主要国家","value":"奥匈帝国；奥地利；匈牙利；捷克；克罗地亚；波兰；罗马尼亚"},{"label":"一句话概括","value":"奥匈帝国军队由多民族士兵组成，既体现帝国整合能力，也暴露语言、忠诚和补给难题。"},{"label":"性质/类型","value":"多民族帝国常备军和战争动员体系。"},{"label":"成立/解散时间","value":"1867年奥匈妥协后形成双元结构下的共同军队和地方军制；1918年随帝国解体崩溃。"},{"label":"核心目标/宗旨","value":"保卫哈布斯堡帝国，维持内外安全，并在一战中承担东线、巴尔干和意大利战线作战。"},{"label":"关键人物（可选）","value":"弗朗茨·约瑟夫一世、康拉德·冯·赫岑多夫、各民族军官与士兵。"},{"label":"关键行动/事件","value":"参加一战东线加利西亚战役、塞尔维亚战场、意大利战线和卡波雷托战役。战争后期，民族政治和补给危机削弱军队凝聚力。"},{"label":"为什么重要","value":"它是奥匈帝国民族问题在军事层面的集中体现。德国对奥匈的军事依赖和担忧，都与这支军队的能力和脆弱性有关。"},{"label":"争议/局限","value":"不能简单说多民族必然导致军队无效；许多部队长期保持战斗力，但长期总体战放大了帝国内部裂缝。"},{"label":"出处","value":"1914-1918 Online: Austria-Hungary, Army；Encyclopaedia Britannica: Austria-Hungary；Alexander Watson, Ring of Steel。"}],"relationItems":["← 前因：奥匈帝国民族问题","↔ 相关：一战东线加利西亚战役","↔ 相关：一战罗马尼亚战役","→ 后果：奥匈帝国崩溃","✗ 对立/冲突：奥匈帝国边疆防御"],"relations":[{"text":"← 前因：奥匈帝国民族问题","id":"extra929"},{"text":"↔ 相关：一战东线加利西亚战役","id":"extra702"},{"text":"↔ 相关：一战罗马尼亚战役","id":"extra711"},{"text":"→ 后果：奥匈帝国崩溃","id":"extra947"},{"text":"✗ 对立/冲突：奥匈帝国边疆防御","id":"extra971"}],"source":"history","id":"extra948"},{"title":"机械化战争","level":"B","type":"概念/思潮卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"20世纪，尤其一战后至二战","place":"欧洲及全球现代战场","summary":"机械化战争把坦克、汽车、飞机、无线电和工业后勤结合起来，重塑现代战场机动。","fields":[{"label":"标题","value":"机械化战争"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"20世纪，尤其一战后至二战"},{"label":"地点","value":"欧洲及全球现代战场"},{"label":"主要国家","value":"德国；英国；法国；苏联；美国"},{"label":"一句话概括","value":"机械化战争把坦克、汽车、飞机、无线电和工业后勤结合起来，重塑现代战场机动。"},{"label":"核心主张/思路","value":"战争不再只依靠步兵和骑兵推进，而是通过装甲车辆、摩托化运输、航空侦察和通信系统实现快速突破、包围和纵深打击。"},{"label":"提出者/代表人物（可选）","value":"富勒、古德里安、图哈切夫斯基、戴高乐等军事思想者。"},{"label":"它从何而来","value":"一战堑壕僵局、坦克技术、内燃机工业、无线电通信和航空技术共同推动军队寻找新的机动作战方式。"},{"label":"典型表现","value":"坦克技术、战间期装甲理论、德国闪击战、苏联纵深作战、盟军机械化后勤。"},{"label":"为什么重要","value":"它连接一战技术实验和二战作战方式。德国闪击战并非凭空出现，而是机械化、通信、空地协同和战略环境共同作用的结果。"},{"label":"争议/局限","value":"机械化战争依赖燃料、维修、道路、训练和通信，不能简单等同于“坦克越多越强”。"},{"label":"出处","value":"Encyclopaedia Britannica: armoured warfare；Imperial War Museums: Tanks and mechanised warfare；1914-1918 Online: Tank warfare。"}],"relationItems":["← 前因：坦克技术","← 前因：第二次工业革命","→ 后果：纳粹德国闪击战","↔ 相关：德国速决战设想","↔ 相关：德国库尔斯克“堡垒行动”"],"relations":[{"text":"← 前因：坦克技术","id":"extra939"},{"text":"← 前因：第二次工业革命","id":"extra954"},{"text":"→ 后果：纳粹德国闪击战","id":"extra186"},{"text":"↔ 相关：德国速决战设想","id":"extra927"},{"text":"↔ 相关：德国库尔斯克“堡垒行动”","id":"extra240"}],"source":"history","id":"extra949"},{"title":"现代制药工业","level":"C","type":"概念/思潮卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"19世纪后期—20世纪","place":"德国、瑞士、英国、美国等工业国家","summary":"现代制药工业把化学研究、专利、品牌药和工业生产结合起来，改变医疗与商业。","fields":[{"label":"标题","value":"现代制药工业"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"19世纪后期—20世纪"},{"label":"地点","value":"德国、瑞士、英国、美国等工业国家"},{"label":"主要国家","value":"德国；瑞士；英国；美国"},{"label":"一句话概括","value":"现代制药工业把化学研究、专利、品牌药和工业生产结合起来，改变医疗与商业。"},{"label":"核心主张/思路","value":"药物从传统药剂和小规模调配，转向实验室研发、标准化生产、商标营销和跨国企业经营。"},{"label":"提出者/代表人物（可选）","value":"拜耳、赫斯特、默克、保罗·埃尔利希等企业和科学家。"},{"label":"它从何而来","value":"染料化学、大学研究体系、工业资本、专利制度和城市医疗需求共同推动药品产业化。"},{"label":"典型表现","value":"阿司匹林商品化、海洛因商品化、萨尔瓦散、合成染料企业转向药物研发。"},{"label":"为什么重要","value":"德国化学工业在现代制药业早期处于核心位置。它既带来有效药物和公共健康改善，也制造药物营销、监管和成瘾问题。"},{"label":"争议/局限","value":"早期药物监管有限，疗效、安全性和商业宣传之间经常存在张力。"},{"label":"出处","value":"German History in Documents and Images: Chemical and pharmaceutical industry；Bayer historical materials；Encyclopaedia Britannica: pharmaceutical industry。"}],"relationItems":["← 前因：德国化学工业","↔ 相关：德国拜耳推出阿司匹林","↔ 相关：拜耳海洛因商品化","↔ 相关：保罗·埃尔利希萨尔瓦散（606号药物）","→ 后果：国际毒品管制"],"relations":[{"text":"← 前因：德国化学工业","id":"extra680"},{"text":"↔ 相关：德国拜耳推出阿司匹林","id":"extra738"},{"text":"↔ 相关：拜耳海洛因商品化","id":"extra743"},{"text":"↔ 相关：保罗·埃尔利希萨尔瓦散（606号药物）","id":"extra814"},{"text":"→ 后果：国际毒品管制","id":"extra962"}],"source":"history","id":"extra950"},{"title":"现代福利国家","level":"B","type":"概念/思潮卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"19世纪后期—20世纪","place":"德国、英国、北欧及现代工业国家","summary":"现代福利国家通过社会保险、救济和公共服务，让国家承担部分社会风险治理责任。","fields":[{"label":"标题","value":"现代福利国家"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"19世纪后期—20世纪"},{"label":"地点","value":"德国、英国、北欧及现代工业国家"},{"label":"主要国家","value":"德国；英国；法国；瑞典；美国"},{"label":"一句话概括","value":"现代福利国家通过社会保险、救济和公共服务，让国家承担部分社会风险治理责任。"},{"label":"核心主张/思路","value":"疾病、工伤、老年、失业和贫困不再完全由家庭或慈善处理，而由国家、雇主和社会保险制度共同分担。"},{"label":"提出者/代表人物（可选）","value":"俾斯麦、社会改革者、工会、社会民主党和后来的福利国家设计者。"},{"label":"它从何而来","value":"工业化社会风险、工人运动、城市贫困、社会民主主义挑战和国家治理能力扩张。"},{"label":"典型表现","value":"德国疾病保险法、事故保险法、养老和残疾保险法，后来的失业保险和全民福利制度。"},{"label":"为什么重要","value":"德国俾斯麦社会保险立法是现代福利国家的重要早期样板。福利国家也成为20世纪民主政治和社会整合的重要基础。"},{"label":"争议/局限","value":"福利国家既能保护社会，也可能用于政治控制、排除“非成员”或加重财政负担。"},{"label":"出处","value":"Encyclopaedia Britannica: welfare state；DHM/LeMO: Sozialgesetzgebung；German History in Documents and Images: Social insurance。"}],"relationItems":["← 前因：德国工人阶级形成","↔ 相关：德国俾斯麦社会保险立法","↔ 相关：德国疾病保险法","↔ 相关：德国事故保险法","→ 后果：魏玛德国失业保险法"],"relations":[{"text":"← 前因：德国工人阶级形成","id":"extra941"},{"text":"↔ 相关：德国俾斯麦社会保险立法","id":"extra629"},{"text":"↔ 相关：德国疾病保险法","id":"extra740"},{"text":"↔ 相关：德国事故保险法","id":"extra741"},{"text":"→ 后果：魏玛德国失业保险法","id":"card81"}],"source":"history","id":"extra951"},{"title":"电报通信网络扩张","level":"C","type":"事件卡","tags":["经济与社会","战争与外交"],"mainTag":"经济与社会","subTag":"战争与外交","timeText":"19世纪中期—20世纪初","place":"欧洲、跨大西洋和全球通信网络","summary":"电报通信网络扩张压缩信息时间，改变新闻、外交、金融和战争指挥方式。","fields":[{"label":"标题","value":"电报通信网络扩张"},{"label":"分级","value":"C"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"19世纪中期—20世纪初"},{"label":"地点","value":"欧洲、跨大西洋和全球通信网络"},{"label":"主要国家","value":"英国；德国；法国；美国；俄国"},{"label":"一句话概括","value":"电报通信网络扩张压缩信息时间，改变新闻、外交、金融和战争指挥方式。"},{"label":"参与者","value":"国家邮电部门、私营电报公司、新闻机构、银行、外交部和军队。"},{"label":"发生了什么","value":"19世纪中期以后，陆上电报线和海底电缆迅速铺设，把欧洲城市、殖民地港口和大西洋两岸连接起来。政府、报社和企业可在数小时内传递信息，国际新闻和金融交易速度显著提高。"},{"label":"为什么重要","value":"它是现代全球化的基础设施之一。德国沃尔夫电报局、电话网络、战争动员和外交危机处理都依赖更快的信息流。"},{"label":"前因","value":"第二次工业革命、电气技术、铁路和国家行政需求推动远距离通信。"},{"label":"后果","value":"新闻机构国际竞争加剧，外交危机节奏加快，军事指挥和金融市场更依赖实时信息。"},{"label":"出处","value":"Encyclopaedia Britannica: telegraph；German History in Documents and Images: Communications；DHM/LeMO: Technik und Kommunikation。"}],"relationItems":["← 前因：第二次工业革命","↔ 相关：德国沃尔夫电报局","↔ 相关：德意志帝国电话网络","→ 后果：战争宣传","↔ 相关：德意志帝国世界贸易扩张"],"relations":[{"text":"← 前因：第二次工业革命","id":"extra954"},{"text":"↔ 相关：德国沃尔夫电报局","id":"extra817"},{"text":"↔ 相关：德意志帝国电话网络","id":"extra831"},{"text":"→ 后果：战争宣传","id":"extra946"},{"text":"↔ 相关：德意志帝国世界贸易扩张","id":"extra932"}],"source":"history","id":"extra952"},{"title":"第一次世界大战全球化","level":"B","type":"概念/思潮卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1914—1918年","place":"欧洲、非洲、中东、亚洲、海洋和殖民地体系","summary":"第一次世界大战全球化指欧洲战争通过帝国、海运、殖民地和美国参战扩展为世界性冲突。","fields":[{"label":"标题","value":"第一次世界大战全球化"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1914—1918年"},{"label":"地点","value":"欧洲、非洲、中东、亚洲、海洋和殖民地体系"},{"label":"主要国家","value":"英国；法国；德国；奥斯曼帝国；日本；美国；俄国；殖民地社会"},{"label":"一句话概括","value":"第一次世界大战全球化指欧洲战争通过帝国、海运、殖民地和美国参战扩展为世界性冲突。"},{"label":"核心主张/思路","value":"一战不只是欧洲大陆战争，殖民帝国、全球金融、粮食与原料、海上封锁和远征军把多个大陆卷入战争。"},{"label":"提出者/代表人物（可选）","value":"交战国政府、殖民地军队、海军、商贸网络和全球劳工动员体系。"},{"label":"它从何而来","value":"帝国主义、世界贸易、殖民地统治、海上通信和联盟体系把欧洲冲突连接到全球网络。"},{"label":"典型表现","value":"一战日英攻占青岛战役、一战德属东非战役、加里波利战役、海上封锁、美国参战、殖民地士兵和劳工动员。"},{"label":"为什么重要","value":"它说明一战从一开始就具有世界史性质。战后委任统治体系、民族运动和国际联盟都与战争全球化有关。"},{"label":"争议/局限","value":"不同地区卷入战争的方式差异很大，有些是战场，有些是劳工、原料、财政或政治动员。"},{"label":"出处","value":"1914-1918 Online: Global War；Encyclopaedia Britannica: World War I；Imperial War Museums: First World War global conflict。"}],"relationItems":["← 前因：第一次世界大战爆发","↔ 相关：一战日英攻占青岛战役","↔ 相关：一战德属东非战役","↔ 相关：美国参加第一次世界大战","→ 后果：一战后国际联盟委任统治体系"],"relations":[{"text":"← 前因：第一次世界大战爆发","id":"extra925"},{"text":"↔ 相关：一战日英攻占青岛战役","id":"extra703"},{"text":"↔ 相关：一战德属东非战役","id":"extra719"},{"text":"↔ 相关：美国参加第一次世界大战","id":"extra660"},{"text":"→ 后果：一战后国际联盟委任统治体系","id":"card5"}],"source":"history","id":"extra953"},{"title":"第二次工业革命","level":"S","type":"概念/思潮卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"约1870年代—20世纪初","place":"欧洲、美国、日本等工业化地区","summary":"第二次工业革命以钢铁、化学、电力、内燃机和大企业为核心，重塑全球经济和国家能力。","fields":[{"label":"标题","value":"第二次工业革命"},{"label":"分级","value":"S"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"约1870年代—20世纪初"},{"label":"地点","value":"欧洲、美国、日本等工业化地区"},{"label":"主要国家","value":"德国；美国；英国；法国；日本"},{"label":"一句话概括","value":"第二次工业革命以钢铁、化学、电力、内燃机和大企业为核心，重塑全球经济和国家能力。"},{"label":"核心主张/思路","value":"工业增长从煤铁和蒸汽扩展到电气、化学、精密机械、通信、制药、汽车和大型企业组织。"},{"label":"提出者/代表人物（可选）","value":"工程师、企业家、科学家、大银行和国家技术教育体系。"},{"label":"它从何而来","value":"第一次工业革命积累的机械生产、科学教育、资本市场和交通网络为新技术扩散提供条件。"},{"label":"典型表现","value":"德国化学工业、AEG电气公司、合成氨哈伯-博施法、奔驰专利汽车、电话和电报网络扩张。"},{"label":"为什么重要","value":"它解释德国和美国为什么在19世纪末迅速追赶并挑战英国工业优势，也解释现代战争、城市生活和大众消费的技术基础。"},{"label":"争议/局限","value":"第二次工业革命带来生产力增长，也加剧垄断、劳资冲突、殖民资源竞争和环境压力。"},{"label":"出处","value":"Encyclopaedia Britannica: Industrial Revolution；German History in Documents and Images: Industrial Germany；DHM/LeMO: Industrialisierung。"}],"relationItems":["→ 后果：德国工业化","→ 后果：德国化学工业","→ 后果：现代制药工业","→ 后果：电报通信网络扩张","↔ 相关：德国大学研究体系"],"relations":[{"text":"→ 后果：德国工业化","id":"extra933"},{"text":"→ 后果：德国化学工业","id":"extra680"},{"text":"→ 后果：现代制药工业","id":"extra950"},{"text":"→ 后果：电报通信网络扩张","id":"extra952"},{"text":"↔ 相关：德国大学研究体系","id":"extra935"}],"source":"history","id":"extra954"},{"title":"纵深防御","level":"C","type":"概念/思潮卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"一战后期形成，20世纪继续发展","place":"西线及现代战场","summary":"纵深防御通过多层阵地、弹性撤退和预备队反击，减少前沿被突破的灾难后果。","fields":[{"label":"标题","value":"纵深防御"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"一战后期形成，20世纪继续发展"},{"label":"地点","value":"西线及现代战场"},{"label":"主要国家","value":"德国；法国；英国；苏联"},{"label":"一句话概括","value":"纵深防御通过多层阵地、弹性撤退和预备队反击，减少前沿被突破的灾难后果。"},{"label":"核心主张/思路","value":"不把全部兵力押在第一道壕线，而是在后方布置多层防御、火力区和机动预备队，允许局部退让后组织反击。"},{"label":"提出者/代表人物（可选）","value":"一战后期德国防御战术改革者、各国参谋部。"},{"label":"它从何而来","value":"炮兵和步兵正面进攻造成巨大伤亡，固定堑壕防线容易被集中火力摧毁，促使军队寻求弹性防御。"},{"label":"典型表现","value":"兴登堡防线、德国西线弹性防御、反坦克纵深和二战时期的多层防御体系。"},{"label":"为什么重要","value":"它解释为什么单次突破不一定带来战略胜利，也解释坦克和机械化战争为何必须解决后续扩张、补给和协同问题。"},{"label":"争议/局限","value":"纵深防御要求训练、通信和预备队，如果士气、补给或指挥崩溃，多层阵地也可能迅速失效。"},{"label":"出处","value":"1914-1918 Online: Trench Warfare；Imperial War Museums: Hindenburg Line；Encyclopaedia Britannica: trench warfare。"}],"relationItems":["← 前因：一战西线堑壕战","↔ 相关：兴登堡防线","✗ 对立/冲突：坦克技术","↔ 相关：康布雷战役","→ 后果：机械化战争"],"relations":[{"text":"← 前因：一战西线堑壕战","id":"extra651"},{"text":"↔ 相关：兴登堡防线","id":"extra956"},{"text":"✗ 对立/冲突：坦克技术","id":"extra939"},{"text":"↔ 相关：康布雷战役","id":"extra714"},{"text":"→ 后果：机械化战争","id":"extra949"}],"source":"history","id":"extra955"},{"title":"兴登堡防线","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1916年底—1918年","place":"法国东北部西线战场","summary":"兴登堡防线是德军在一战西线构筑并撤入的纵深防御体系，体现战争后期防御战术变化。","fields":[{"label":"标题","value":"兴登堡防线"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1916年底—1918年"},{"label":"地点","value":"法国东北部西线战场"},{"label":"主要国家","value":"德国；法国；英国；美国"},{"label":"一句话概括","value":"兴登堡防线是德军在一战西线构筑并撤入的纵深防御体系，体现战争后期防御战术变化。"},{"label":"参与者","value":"德国最高陆军指挥部、保罗·冯·兴登堡、埃里希·鲁登道夫、协约国英法美军队和西线平民。"},{"label":"发生了什么","value":"1916年底德军在西线后方建设多层阵地、掩体、铁丝网、炮兵阵地和交通壕。1917年春，德军主动从索姆突出部撤至这条新防线，沿途破坏道路、村庄和设施以迟滞协约国。1917—1918年，阿拉斯、康布雷、圣康坦运河等战斗围绕这套防线展开，直到百日攻势中被突破。"},{"label":"为什么重要","value":"它体现一战后期从死守前沿到纵深防御的转变，也说明现代防线依赖工程、火力、交通和预备队协同。"},{"label":"前因","value":"索姆河战役后德军消耗严重，需要缩短战线、节约兵力，并降低协约国炮火对前沿阵地的杀伤。"},{"label":"后果","value":"协约国必须发展坦克、炮兵、步兵和航空协同来突破纵深防御，1918年突破防线后德国战略局势急剧恶化。"},{"label":"出处","value":"Imperial War Museums: Hindenburg Line；1914-1918 Online: Western Front；Encyclopaedia Britannica: World War I。"}],"relationItems":["← 前因：索姆河战役","↔ 相关：纵深防御","↔ 相关：康布雷战役","→ 后果：百日攻势"],"relations":[{"text":"← 前因：索姆河战役","id":"extra655"},{"text":"↔ 相关：纵深防御","id":"extra955"},{"text":"↔ 相关：康布雷战役","id":"extra714"}],"source":"history","id":"extra956"},{"title":"一战海上战争","level":"B","type":"概念/思潮卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1914—1918年","place":"北海、大西洋、地中海和全球海路","summary":"一战海上战争以英国封锁、德国潜艇战和全球海路控制为核心，把战争变成资源与贸易的较量。","fields":[{"label":"标题","value":"一战海上战争"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1914—1918年"},{"label":"地点","value":"北海、大西洋、地中海和全球海路"},{"label":"主要国家","value":"英国；德国；法国；美国；奥匈帝国；奥斯曼帝国；日本"},{"label":"一句话概括","value":"一战海上战争以英国封锁、德国潜艇战和全球海路控制为核心，把战争变成资源与贸易的较量。"},{"label":"核心主张/思路","value":"海军不只寻找决战，还通过封锁、护航、袭击商船、争夺海峡和保护运输来影响国家经济和战争持久力。"},{"label":"提出者/代表人物（可选）","value":"英国皇家海军、德国公海舰队、德国潜艇部队、美国海军和各国海军参谋部。"},{"label":"它从何而来","value":"英德海军竞赛、全球贸易依赖、殖民帝国补给线和无畏舰时代的海权理论。"},{"label":"典型表现","value":"英国海上封锁、日德兰海战、德国无限制潜艇战、卢西塔尼亚号沉没和协约国护航体系。"},{"label":"为什么重要","value":"它解释德国为何被资源封锁压迫，也解释美国为何因潜艇战和齐默尔曼电报逐渐走向参战。"},{"label":"争议/局限","value":"海上战争常被陆地战线掩盖，但它对粮食、原料、金融和外交的影响同样关键。"},{"label":"出处","value":"1914-1918 Online: Naval Warfare；Imperial War Museums: War at Sea；Encyclopaedia Britannica: World War I naval operations。"}],"relationItems":["← 前因：英德海军军备竞赛","↔ 相关：卢西塔尼亚号沉没","↔ 相关：德国无限制潜艇战","→ 后果：美国参加第一次世界大战"],"relations":[{"text":"↔ 相关：卢西塔尼亚号沉没","id":"extra709"},{"text":"↔ 相关：德国无限制潜艇战","id":"extra658"},{"text":"→ 后果：美国参加第一次世界大战","id":"extra660"}],"source":"history","id":"extra957"},{"title":"一战战略空袭","level":"C","type":"概念/思潮卡","tags":["战争与外交","文化与思想"],"mainTag":"战争与外交","subTag":"文化与思想","timeText":"1914—1918年","place":"英国、法国、德国、意大利等战区后方城市","summary":"一战战略空袭把飞艇和轰炸机用于打击城市与工业后方，预示20世纪空中战争形态。","fields":[{"label":"标题","value":"一战战略空袭"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1914—1918年"},{"label":"地点","value":"英国、法国、德国、意大利等战区后方城市"},{"label":"主要国家","value":"德国；英国；法国；意大利；奥匈帝国"},{"label":"一句话概括","value":"一战战略空袭把飞艇和轰炸机用于打击城市与工业后方，预示20世纪空中战争形态。"},{"label":"核心主张/思路","value":"空中力量可以越过前线袭击敌方港口、工厂、铁路和城市居民，以破坏工业能力并制造心理压力。"},{"label":"提出者/代表人物（可选）","value":"德国齐柏林飞艇部队、哥达轰炸机部队、英国皇家飞行队和各国空军理论探索者。"},{"label":"它从何而来","value":"飞艇、飞机和航空发动机技术发展，使战场侦察逐渐扩展到对后方目标的攻击。"},{"label":"典型表现","value":"德国飞艇空袭英国、哥达轰炸机袭击伦敦、协约国对德国工业目标的报复性轰炸。"},{"label":"为什么重要","value":"它让平民后方直接暴露在战争中，也为两次大战之间关于防空、空军独立和战略轰炸的争论提供经验。"},{"label":"争议/局限","value":"一战空袭的物理破坏有限，但心理影响和政治震动很大；它并未单独改变战争结局。"},{"label":"出处","value":"Imperial War Museums: First World War air raids；1914-1918 Online: Air Warfare；Susan Grayzel, At Home and Under Fire。"}],"relationItems":["← 前因：德国齐柏林飞艇首飞","↔ 相关：一战总体战","↔ 相关：一战反德宣传","→ 后果：二战战略轰炸"],"relations":[{"text":"← 前因：德国齐柏林飞艇首飞","id":"extra737"},{"text":"↔ 相关：一战反德宣传","id":"extra960"}],"source":"history","id":"extra958"},{"title":"一战资源战","level":"B","type":"概念/思潮卡","tags":["经济与社会","战争与外交"],"mainTag":"经济与社会","subTag":"战争与外交","timeText":"1914—1918年","place":"欧洲、全球贸易网络和殖民地资源区","summary":"一战资源战指各国围绕粮食、煤炭、钢铁、硝酸盐、石油和运输能力展开的长期消耗竞争。","fields":[{"label":"标题","value":"一战资源战"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1914—1918年"},{"label":"地点","value":"欧洲、全球贸易网络和殖民地资源区"},{"label":"主要国家","value":"德国；英国；法国；俄国；美国；奥匈帝国"},{"label":"一句话概括","value":"一战资源战指各国围绕粮食、煤炭、钢铁、硝酸盐、石油和运输能力展开的长期消耗竞争。"},{"label":"核心主张/思路","value":"现代战争胜负不仅取决于战场兵力，也取决于国家能否持续获得原料、能源、劳动力、粮食和运输能力。"},{"label":"提出者/代表人物（可选）","value":"战时经济机构、军需部门、企业集团、海军封锁机构和殖民地行政体系。"},{"label":"它从何而来","value":"第二次工业革命使战争高度依赖钢铁、化学品、燃料、铁路和全球贸易。"},{"label":"典型表现","value":"英国海上封锁、德国战时原料管理、合成氨生产、粮食配给、罗马尼亚石油争夺和美国物资供应。"},{"label":"为什么重要","value":"它解释一战为何演变为总体战，也解释德国和奥匈帝国为何在军事崩溃前已出现粮食、原料和社会承受力危机。"},{"label":"争议/局限","value":"资源战不是纯经济过程，它与国家强制、殖民剥削、劳工动员和民众生活危机紧密相连。"},{"label":"出处","value":"1914-1918 Online: War Economy；Avner Offer, The First World War: An Agrarian Interpretation；DHM/LeMO: Erster Weltkrieg Heimatfront。"}],"relationItems":["← 前因：第二次工业革命","↔ 相关：一战海上战争","↔ 相关：德国战时原料部","↔ 相关：合成氨哈伯-博施法","→ 后果：德国1918年国内危机"],"relations":[{"text":"← 前因：第二次工业革命","id":"extra954"},{"text":"↔ 相关：一战海上战争","id":"extra957"},{"text":"↔ 相关：合成氨哈伯-博施法","id":"extra681"}],"source":"history","id":"extra959"},{"title":"一战反德宣传","level":"C","type":"概念/思潮卡","tags":["文化与思想","战争与外交"],"mainTag":"文化与思想","subTag":"战争与外交","timeText":"1914—1918年","place":"英国、法国、美国及协约国舆论空间","summary":"一战反德宣传把德国塑造成侵略、野蛮和军国主义象征，服务于征兵、募债和对外动员。","fields":[{"label":"标题","value":"一战反德宣传"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1914—1918年"},{"label":"地点","value":"英国、法国、美国及协约国舆论空间"},{"label":"主要国家","value":"英国；法国；美国；德国；比利时"},{"label":"一句话概括","value":"一战反德宣传把德国塑造成侵略、野蛮和军国主义象征，服务于征兵、募债和对外动员。"},{"label":"核心主张/思路","value":"通过海报、报纸、报告、电影和演讲，把德国入侵比利时、潜艇战和皇帝形象转化为道德战争叙事。"},{"label":"提出者/代表人物（可选）","value":"英国战争宣传局、协约国新闻机构、美国公共信息委员会和报刊出版商。"},{"label":"它从何而来","value":"德国入侵比利时、鲁汶破坏、平民伤亡、潜艇战和战时新闻审查共同塑造了宣传素材。"},{"label":"典型表现","value":"布莱斯报告、反“匈奴”宣传、卢西塔尼亚号沉没宣传、威廉二世妖魔化和美国参战前舆论动员。"},{"label":"为什么重要","value":"它显示现代战争必须争夺国际舆论和中立国民意，也影响战后德国社会对“敌方宣传”的怨恨和防御性叙事。"},{"label":"争议/局限","value":"宣传中既有真实暴力，也有夸张、选择性呈现和虚构故事，战后反而加剧公众对战争信息的不信任。"},{"label":"出处","value":"1914-1918 Online: Propaganda；British Library: World War One propaganda；Nicoletta Gullace, British Propaganda and International Law。"}],"relationItems":["← 前因：德国入侵比利时","↔ 相关：卢西塔尼亚号沉没","↔ 相关：威廉二世《匈奴演说》","→ 后果：德国“背后一刀”传说"],"relations":[{"text":"← 前因：德国入侵比利时","id":"extra647"},{"text":"↔ 相关：卢西塔尼亚号沉没","id":"extra709"},{"text":"↔ 相关：威廉二世《匈奴演说》","id":"extra75"},{"text":"→ 后果：德国“背后一刀”传说","id":"extra623"}],"source":"history","id":"extra960"},{"title":"一战阵亡者纪念文化","level":"C","type":"概念/思潮卡","tags":["文化与思想","战争与外交"],"mainTag":"文化与思想","subTag":"战争与外交","timeText":"1918年后，1920年代尤为突出","place":"欧洲、英联邦、美国及参战国家","summary":"一战阵亡者纪念文化通过无名战士、纪念碑、阵亡名单和纪念日处理大规模死亡的社会创伤。","fields":[{"label":"标题","value":"一战阵亡者纪念文化"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1918年后，1920年代尤为突出"},{"label":"地点","value":"欧洲、英联邦、美国及参战国家"},{"label":"主要国家","value":"英国；法国；德国；意大利；美国；澳大利亚；加拿大"},{"label":"一句话概括","value":"一战阵亡者纪念文化通过无名战士、纪念碑、阵亡名单和纪念日处理大规模死亡的社会创伤。"},{"label":"核心主张/思路","value":"国家和地方社会需要用公共仪式、墓地、纪念碑和文学艺术为数百万阵亡者赋予意义。"},{"label":"提出者/代表人物（可选）","value":"退伍军人组织、地方政府、教会、军方、纪念碑设计者和遗属团体。"},{"label":"它从何而来","value":"一战造成前所未有的兵员死亡，许多遗体无法运回家乡，传统家族葬礼不足以承载战争创伤。"},{"label":"典型表现","value":"无名战士墓、英联邦战争墓地、德国阵亡纪念碑、停战纪念日和战后反战文学。"},{"label":"为什么重要","value":"它连接战争记忆、民族身份和政治分裂。不同国家对阵亡者的解释会支持和平主义、复仇主义或民族主义。"},{"label":"争议/局限","value":"纪念文化常把士兵死亡神圣化，可能遮蔽战争责任、殖民士兵经历和普通人的反战情绪。"},{"label":"出处","value":"Jay Winter, Sites of Memory, Sites of Mourning；Imperial War Museums: Remembrance；DHM/LeMO: Kriegserinnerung。"}],"relationItems":["← 前因：第一次世界大战","↔ 相关：德意志帝国纪念碑文化","↔ 相关：《西线无战事》","→ 后果：战间期和平主义"],"relations":[{"text":"← 前因：第一次世界大战","id":"extra968"},{"text":"↔ 相关：德意志帝国纪念碑文化","id":"extra835"},{"text":"↔ 相关：《西线无战事》","id":"extra64"}],"source":"history","id":"extra961"},{"title":"国际毒品管制","level":"B","type":"概念/思潮卡","tags":["政治与制度","经济与社会"],"mainTag":"政治与制度","subTag":"经济与社会","timeText":"1909年上海万国禁烟会后逐步形成；1912年海牙公约为关键节点","place":"全球外交体系","summary":"国际毒品管制把鸦片、吗啡、海洛因和可卡因问题从贸易道德争议转化为跨国法律治理。","fields":[{"label":"标题","value":"国际毒品管制"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1909年上海万国禁烟会后逐步形成；1912年海牙公约为关键节点"},{"label":"地点","value":"全球外交体系"},{"label":"主要国家","value":"美国；中国；英国；德国；法国；荷兰；日本"},{"label":"一句话概括","value":"国际毒品管制把鸦片、吗啡、海洛因和可卡因问题从贸易道德争议转化为跨国法律治理。"},{"label":"核心主张/思路","value":"成瘾性药物不能完全由商业和殖民贸易支配，国家应通过进口、出口、制造和医疗用途监管形成国际约束。"},{"label":"提出者/代表人物（可选）","value":"美国禁毒外交推动者、中国禁烟改革者、海牙与日内瓦会议代表、国际联盟卫生和毒品机构。"},{"label":"它从何而来","value":"十九世纪全球鸦片贸易、鸦片战争后中国社会危机、医学药物工业化和美国进步主义改革共同推动国际合作。"},{"label":"典型表现","value":"1909年上海万国禁烟会、1912年海牙《国际鸦片公约》、国际联盟毒品监督机制和各国鸦片法。"},{"label":"为什么重要","value":"它是现代全球治理的早期领域之一，也解释魏玛德国鸦片法和后来国际禁毒制度的源头。"},{"label":"争议/局限","value":"早期管制常保留殖民利益和医学工业例外，执法能力有限，也容易把公共卫生问题推向刑事化。"},{"label":"出处","value":"UNODC, A Century of International Drug Control；United Nations Treaty Collection: International Opium Convention 1912；David Courtwright, Forces of Habit。"}],"relationItems":["← 前因：十九世纪全球鸦片贸易","↔ 相关：海牙《国际鸦片公约》","↔ 相关：魏玛德国鸦片法","→ 后果：国际联盟毒品管制"],"relations":[{"text":"← 前因：十九世纪全球鸦片贸易","id":"extra972"},{"text":"↔ 相关：海牙《国际鸦片公约》","id":"extra744"},{"text":"↔ 相关：魏玛德国鸦片法","id":"card100"}],"source":"history","id":"extra962"},{"title":"《辛丑条约》","level":"B","type":"制度/文本卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1901年9月7日签署","place":"中国北京","summary":"《辛丑条约》是义和团战争后的赔款和驻军安排，进一步削弱清朝主权并加深中国危机。","fields":[{"label":"标题","value":"《辛丑条约》"},{"label":"分级","value":"B"},{"label":"类型","value":"制度/文本卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1901年9月7日签署"},{"label":"地点","value":"中国北京"},{"label":"主要国家","value":"中国；英国；法国；德国；俄国；日本；美国；意大利；奥匈帝国；比利时；西班牙；荷兰"},{"label":"一句话概括","value":"《辛丑条约》是义和团战争后的赔款和驻军安排，进一步削弱清朝主权并加深中国危机。"},{"label":"制定方/签署方","value":"清政府与八国联军主要参战国及相关列强代表。"},{"label":"主要内容","value":"清政府赔款本息合计巨额白银，允许列强在北京使馆区驻兵，惩办官员，禁止反洋组织，并拆毁部分炮台、保障交通线。"},{"label":"它试图解决什么问题","value":"列强以保护使馆、惩罚义和团和清政府为名，要求清朝承担战争责任并保障列强在华权益。"},{"label":"为什么重要","value":"它是晚清半殖民地化加深的重要节点，也推动清末新政、革命思潮和中国民族主义情绪发展。"},{"label":"争议/局限","value":"条约以国际惩罚形式处理危机，但其赔款、驻军和治外压力严重损害中国财政和主权。"},{"label":"造成的影响","value":"中国财政负担加重，清政府合法性受损，列强在华军事和外交存在扩大。"},{"label":"出处","value":"Encyclopaedia Britannica: Boxer Rebellion；Chinese Maritime Customs treaty texts；Jonathan Spence, The Search for Modern China。"}],"relationItems":["← 前因：八国联军干预义和团运动","↔ 相关：德国强租胶州湾","→ 后果：清末新政","→ 后果：五四运动"],"relations":[{"text":"← 前因：八国联军干预义和团运动","id":"extra777"},{"text":"↔ 相关：德国强租胶州湾","id":"extra773"},{"text":"→ 后果：五四运动","id":"card205"}],"source":"history","id":"extra963"},{"title":"一战中立国航行权","level":"C","type":"概念/思潮卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1914—1918年","place":"大西洋、北海和国际法外交空间","summary":"一战中立国航行权争议围绕中立商船能否自由航行、运货和免遭封锁或潜艇攻击展开。","fields":[{"label":"标题","value":"一战中立国航行权"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1914—1918年"},{"label":"地点","value":"大西洋、北海和国际法外交空间"},{"label":"主要国家","value":"美国；英国；德国；荷兰；丹麦；挪威；瑞典"},{"label":"一句话概括","value":"一战中立国航行权争议围绕中立商船能否自由航行、运货和免遭封锁或潜艇攻击展开。"},{"label":"核心主张/思路","value":"中立国主张其商船在公海享有航行和贸易权，交战国则以封锁、违禁品和军事必要为由限制或攻击航运。"},{"label":"提出者/代表人物（可选）","value":"美国政府、英国海军封锁机构、德国潜艇战决策者和中立国外交部门。"},{"label":"它从何而来","value":"19世纪国际法中的中立贸易传统与一战总体战、海上封锁和潜艇技术发生冲突。"},{"label":"典型表现","value":"英国扩大违禁品清单，德国宣布战区和无限制潜艇战，美国因商船和公民伤亡不断抗议。"},{"label":"为什么重要","value":"它解释卢西塔尼亚号沉没和无限制潜艇战为何不仅是军事问题，也是国际法和美国参战问题。"},{"label":"争议/局限","value":"中立权利在总体战中很难维持，因为粮食、原料和运输本身已经成为战争资源。"},{"label":"出处","value":"1914-1918 Online: Naval Warfare；The National Archives: First World War blockade；Isabel V. Hull, A Scrap of Paper。"}],"relationItems":["← 前因：一战海上战争","↔ 相关：卢西塔尼亚号沉没","↔ 相关：德国无限制潜艇战","→ 后果：美国参加第一次世界大战"],"relations":[{"text":"← 前因：一战海上战争","id":"extra957"},{"text":"↔ 相关：卢西塔尼亚号沉没","id":"extra709"},{"text":"↔ 相关：德国无限制潜艇战","id":"extra658"},{"text":"→ 后果：美国参加第一次世界大战","id":"extra660"}],"source":"history","id":"extra964"},{"title":"伊松佐河战役","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1915年6月—1917年10月","place":"伊松佐河谷，今意大利东北部和斯洛文尼亚西部","summary":"伊松佐河战役是一战意大利战线十二次主要攻防，长期消耗后导向卡波雷托战役。","fields":[{"label":"标题","value":"伊松佐河战役"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1915年6月—1917年10月"},{"label":"地点","value":"伊松佐河谷，今意大利东北部和斯洛文尼亚西部"},{"label":"主要国家","value":"意大利；奥匈帝国；德国"},{"label":"一句话概括","value":"伊松佐河战役是一战意大利战线十二次主要攻防，长期消耗后导向卡波雷托战役。"},{"label":"参与者","value":"意大利王国军队、奥匈帝国军队、德国增援部队、路易吉·卡多尔纳和斯韦托扎尔·博罗耶维奇等指挥官。"},{"label":"发生了什么","value":"意大利参战后在伊松佐河沿线连续发动进攻，试图突破奥匈防线、夺取的里雅斯特方向。高山地形、补给困难和坚固防御造成巨大伤亡。前十一次战斗大多推进有限，1917年德奥联军在第十二次战斗中发动卡波雷托突破，迫使意军大撤退。"},{"label":"为什么重要","value":"它展示一战非西线战场同样具有高消耗和阵地化特征，也解释奥匈帝国为何必须依赖德国支援。"},{"label":"前因","value":"意大利以领土承诺加入协约国后，需要在奥匈边境发动攻势来实现战争目标。"},{"label":"后果","value":"卡波雷托战役重创意大利军队，促使协约国加强协调并改变意大利战线指挥。"},{"label":"出处","value":"Encyclopaedia Britannica: Battles of the Isonzo；1914-1918 Online: Italian Front；John Schindler, Isonzo。"}],"relationItems":["← 前因：伦敦密约","↔ 相关：意大利参加第一次世界大战","→ 后果：卡波雷托战役","↔ 相关：奥匈帝国多民族军队"],"relations":[{"text":"↔ 相关：意大利参加第一次世界大战","id":"extra969"},{"text":"→ 后果：卡波雷托战役","id":"extra712"},{"text":"↔ 相关：奥匈帝国多民族军队","id":"extra948"}],"source":"history","id":"extra965"},{"title":"1917年俄国革命","level":"S","type":"事件卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1917年2月—10月（俄历）/1917年3月—11月（公历）","place":"俄国彼得格勒及全国","summary":"1917年俄国革命推翻罗曼诺夫王朝并使布尔什维克夺权，改变一战进程和20世纪世界政治。","fields":[{"label":"标题","value":"1917年俄国革命"},{"label":"分级","value":"S"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1917年2月—10月（俄历）/1917年3月—11月（公历）"},{"label":"地点","value":"俄国彼得格勒及全国"},{"label":"主要国家","value":"俄国；德国；奥匈帝国；协约国"},{"label":"一句话概括","value":"1917年俄国革命推翻罗曼诺夫王朝并使布尔什维克夺权，改变一战进程和20世纪世界政治。"},{"label":"参与者","value":"俄国工人、士兵、农民、临时政府、苏维埃、布尔什维克、孟什维克、社会革命党和尼古拉二世。"},{"label":"发生了什么","value":"二月革命中彼得格勒罢工、粮食危机和军队哗变迫使尼古拉二世退位，临时政府与苏维埃形成双重权力。临时政府继续参战并无法解决土地和粮食问题。十月革命中布尔什维克夺取政权，随后推动停战、内战和新政权建设。"},{"label":"为什么重要","value":"它导致俄国退出一战，并开启社会主义国家实验、国际共产主义运动和欧洲反革命恐惧。"},{"label":"前因","value":"一战伤亡、粮食危机、沙皇专制失灵、土地问题和城市工人运动共同削弱旧制度。"},{"label":"后果","value":"布尔什维克政府与同盟国签署《布列斯特-立托夫斯克条约》，俄国内战爆发，欧洲政治左右极化加深。"},{"label":"出处","value":"Encyclopaedia Britannica: Russian Revolution；Orlando Figes, A People's Tragedy；Sheila Fitzpatrick, The Russian Revolution。"}],"relationItems":["← 前因：第一次世界大战","↔ 相关：俄国泛斯拉夫主义","→ 后果：《布列斯特-立托夫斯克条约》","→ 后果：欧洲共产主义运动"],"relations":[{"text":"← 前因：第一次世界大战","id":"extra968"},{"text":"↔ 相关：俄国泛斯拉夫主义","id":"extra917"},{"text":"→ 后果：《布列斯特-立托夫斯克条约》","id":"extra662"}],"source":"history","id":"extra966"},{"title":"刚果自由邦","level":"B","type":"组织/机构卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1885—1908年","place":"中部非洲刚果盆地","summary":"刚果自由邦是比利时国王利奥波德二世的私人殖民统治实体，是欧洲瓜分非洲暴力的典型案例。","fields":[{"label":"标题","value":"刚果自由邦"},{"label":"分级","value":"B"},{"label":"类型","value":"组织/机构卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1885—1908年"},{"label":"地点","value":"中部非洲刚果盆地"},{"label":"主要国家","value":"刚果；比利时；德国；英国；法国；葡萄牙"},{"label":"一句话概括","value":"刚果自由邦是比利时国王利奥波德二世的私人殖民统治实体，是欧洲瓜分非洲暴力的典型案例。"},{"label":"性质/类型","value":"名义上独立、实际由利奥波德二世私人控制的殖民国家。"},{"label":"成立/解散时间","value":"1885年在柏林西非会议后形成；1908年因暴行丑闻和国际压力被比利时政府接管为比属刚果。"},{"label":"核心目标/宗旨","value":"以“文明”和反奴隶贸易话语取得国际承认，实际目标是控制橡胶、象牙和劳动力。"},{"label":"关键人物（可选）","value":"利奥波德二世、亨利·莫顿·斯坦利、殖民公司和殖民军队。"},{"label":"关键行动/事件","value":"强迫劳动、橡胶采集、惩罚性暴力和国际反刚果暴行运动。"},{"label":"为什么重要","value":"它说明柏林西非会议并非抽象外交会议，而与殖民掠夺、强制劳动和非洲社会灾难直接相连。"},{"label":"争议/局限","value":"死亡规模和人口损失估计存在争议，但暴力统治、强迫劳动和剥削性质有充分史料支持。"},{"label":"出处","value":"Encyclopaedia Britannica: Congo Free State；Adam Hochschild, King Leopold's Ghost；Royal Museum for Central Africa historical materials。"}],"relationItems":["← 前因：1884—1885年柏林西非会议","↔ 相关：欧洲瓜分非洲","→ 后果：比属刚果","↔ 相关：殖民地强迫劳动"],"relations":[{"text":"← 前因：1884—1885年柏林西非会议","id":"extra760"}],"source":"history","id":"extra967"},{"title":"第一次世界大战","level":"S","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1914—1918年","place":"欧洲、中东、非洲、海洋和全球殖民体系","summary":"第一次世界大战是由欧洲联盟危机扩展成的全球战争，摧毁多个帝国并重塑20世纪国际秩序。","fields":[{"label":"标题","value":"第一次世界大战"},{"label":"分级","value":"S"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1914—1918年"},{"label":"地点","value":"欧洲、中东、非洲、海洋和全球殖民体系"},{"label":"主要国家","value":"德国；奥匈帝国；奥斯曼帝国；英国；法国；俄国；意大利；美国；日本"},{"label":"一句话概括","value":"第一次世界大战是由欧洲联盟危机扩展成的全球战争，摧毁多个帝国并重塑20世纪国际秩序。"},{"label":"参与者","value":"同盟国德国、奥匈帝国、奥斯曼帝国、保加利亚；协约国英国、法国、俄国、意大利、美国、日本及殖民地军队和劳工。"},{"label":"发生了什么","value":"萨拉热窝刺杀引发七月危机，欧洲联盟体系和动员计划把地区危机升级为大战。战争在西线、东线、巴尔干、中东、非洲和海上展开，堑壕战、总体战、潜艇战、封锁和殖民动员造成巨大伤亡。1917年俄国革命和美国参战改变力量对比，1918年同盟国相继崩溃。"},{"label":"为什么重要","value":"它导致德意志帝国、奥匈帝国、奥斯曼帝国和俄国帝国崩溃，并为凡尔赛体系、魏玛共和国、苏联和二战埋下结构性问题。"},{"label":"前因","value":"帝国主义竞争、联盟体系、军备竞赛、巴尔干危机和民族主义共同制造高风险国际环境。"},{"label":"后果","value":"巴黎和会、凡尔赛条约、国际联盟、战后民族国家重组和战间期政治极化。"},{"label":"出处","value":"Encyclopaedia Britannica: World War I；1914-1918 Online: International Encyclopedia of the First World War；Christopher Clark, The Sleepwalkers。"}],"relationItems":["← 前因：七月危机","↔ 相关：第一次世界大战爆发","↔ 相关：第一次世界大战全球化","→ 后果：一战后巴黎和会","→ 后果：魏玛共和国成立"],"relations":[{"text":"↔ 相关：第一次世界大战爆发","id":"extra925"},{"text":"↔ 相关：第一次世界大战全球化","id":"extra953"},{"text":"→ 后果：一战后巴黎和会","id":"extra668"},{"text":"→ 后果：魏玛共和国成立","id":"card7"}],"source":"history","id":"extra968"},{"title":"意大利参加第一次世界大战","level":"B","type":"事件卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"1915年5月","place":"意大利、奥匈边境、伦敦外交空间","summary":"意大利在《伦敦密约》后加入协约国，把战争扩展到阿尔卑斯和伊松佐战线。","fields":[{"label":"标题","value":"意大利参加第一次世界大战"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1915年5月"},{"label":"地点","value":"意大利、奥匈边境、伦敦外交空间"},{"label":"主要国家","value":"意大利；奥匈帝国；英国；法国；俄国；德国"},{"label":"一句话概括","value":"意大利在《伦敦密约》后加入协约国，把战争扩展到阿尔卑斯和伊松佐战线。"},{"label":"参与者","value":"意大利王国政府、协约国英国法国俄国、奥匈帝国、德国和意大利国内干预派与中立派。"},{"label":"发生了什么","value":"意大利原属三国同盟，但1914年宣布中立。1915年，协约国在《伦敦密约》中承诺战后给予意大利南蒂罗尔、的里雅斯特和达尔马提亚等领土。意大利随后对奥匈宣战，开辟意大利战线，长期在伊松佐河和阿尔卑斯地区作战。"},{"label":"为什么重要","value":"它加重奥匈帝国军事压力，也让战后“被 mutilated victory”的意大利民族主义不满成为法西斯崛起背景之一。"},{"label":"前因","value":"意大利统一后的未竟领土诉求、三国同盟内部矛盾和协约国外交争取。"},{"label":"后果","value":"伊松佐河战役和卡波雷托战役爆发，战后意大利对巴黎和会结果不满。"},{"label":"出处","value":"1914-1918 Online: Italy；Encyclopaedia Britannica: World War I Italian Front；John Gooch, The Italian Army and the First World War。"}],"relationItems":["← 前因：伦敦密约","↔ 相关：伊松佐河战役","→ 后果：卡波雷托战役","→ 后果：意大利法西斯主义兴起"],"relations":[{"text":"↔ 相关：伊松佐河战役","id":"extra965"},{"text":"→ 后果：卡波雷托战役","id":"extra712"}],"source":"history","id":"extra969"},{"title":"英国海上封锁","level":"B","type":"事件卡","tags":["战争与外交","经济与社会"],"mainTag":"战争与外交","subTag":"经济与社会","timeText":"1914—1919年","place":"北海、大西洋和欧洲海上贸易网络","summary":"英国海上封锁切断德国海外贸易和资源输入，是一战资源战和德国国内危机的重要原因。","fields":[{"label":"标题","value":"英国海上封锁"},{"label":"分级","value":"B"},{"label":"类型","value":"事件卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1914—1919年"},{"label":"地点","value":"北海、大西洋和欧洲海上贸易网络"},{"label":"主要国家","value":"英国；德国；美国；荷兰；丹麦；挪威；瑞典"},{"label":"一句话概括","value":"英国海上封锁切断德国海外贸易和资源输入，是一战资源战和德国国内危机的重要原因。"},{"label":"参与者","value":"英国皇家海军、英国封锁部、德国政府和海军、中立国商船与外交部门。"},{"label":"发生了什么","value":"战争爆发后，英国利用海上优势控制北海出入口，扩大违禁品范围，检查和扣押通向德国的货物。封锁不仅针对军需品，也影响粮食、棉花、化肥、金属和日用品。德国试图用潜艇战反制，封锁则持续到战后停战初期。"},{"label":"为什么重要","value":"它说明一战胜负不仅在陆战，也在海权、贸易和社会承受力。封锁造成德国营养危机和民众怨恨。"},{"label":"前因","value":"英德海军竞赛、英国海权优势和一战资源战逻辑。"},{"label":"后果","value":"德国国内生活恶化，无限制潜艇战升级，美国与德国关系恶化。"},{"label":"出处","value":"1914-1918 Online: Blockade；Avner Offer, The First World War: An Agrarian Interpretation；Nicholas Lambert, Planning Armageddon。"}],"relationItems":["← 前因：一战海上战争","↔ 相关：一战资源战","✗ 对立/冲突：德国无限制潜艇战","→ 后果：德国1918年国内危机"],"relations":[{"text":"← 前因：一战海上战争","id":"extra957"},{"text":"↔ 相关：一战资源战","id":"extra959"},{"text":"✗ 对立/冲突：德国无限制潜艇战","id":"extra658"}],"source":"history","id":"extra970"},{"title":"奥匈帝国边疆防御","level":"C","type":"概念/思潮卡","tags":["战争与外交","政治与制度"],"mainTag":"战争与外交","subTag":"政治与制度","timeText":"19世纪末—1918年","place":"奥匈帝国与意大利、塞尔维亚、俄国边境地区","summary":"奥匈帝国边疆防御依赖堡垒、山地防线、多民族军队和德国支援，暴露帝国安全困境。","fields":[{"label":"标题","value":"奥匈帝国边疆防御"},{"label":"分级","value":"C"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"19世纪末—1918年"},{"label":"地点","value":"奥匈帝国与意大利、塞尔维亚、俄国边境地区"},{"label":"主要国家","value":"奥匈帝国；意大利；塞尔维亚；俄国；德国"},{"label":"一句话概括","value":"奥匈帝国边疆防御依赖堡垒、山地防线、多民族军队和德国支援，暴露帝国安全困境。"},{"label":"核心主张/思路","value":"多民族帝国需要同时防御巴尔干、加利西亚、阿尔卑斯和亚得里亚方向，战略压力远大于资源承受力。"},{"label":"提出者/代表人物（可选）","value":"奥匈总参谋部、康拉德·冯·赫岑多夫、地方军事长官和堡垒工程部门。"},{"label":"它从何而来","value":"巴尔干民族主义、俄奥竞争、意大利领土诉求和帝国内部民族问题共同制造边疆压力。"},{"label":"典型表现","value":"加利西亚防御、塞尔维亚战役、伊松佐河战线、阿尔卑斯山地战和对德国军事支援的依赖。"},{"label":"为什么重要","value":"它解释奥匈帝国为何在一战中同时面对外部战线和内部脆弱性，也解释卡波雷托战役为何需要德军支援。"},{"label":"争议/局限","value":"边疆防御不是单纯军事问题，还受民族忠诚、铁路能力、粮食供给和财政限制影响。"},{"label":"出处","value":"1914-1918 Online: Austria-Hungary；Gunther Rothenberg, The Army of Francis Joseph；Alexander Watson, Ring of Steel。"}],"relationItems":["← 前因：奥匈帝国多民族结构","↔ 相关：伊松佐河战役","↔ 相关：一战东线加利西亚战役","→ 后果：奥匈帝国崩溃"],"relations":[{"text":"← 前因：奥匈帝国多民族结构","id":"extra923"},{"text":"↔ 相关：伊松佐河战役","id":"extra965"},{"text":"↔ 相关：一战东线加利西亚战役","id":"extra702"},{"text":"→ 后果：奥匈帝国崩溃","id":"extra947"}],"source":"history","id":"extra971"},{"title":"十九世纪全球鸦片贸易","level":"B","type":"概念/思潮卡","tags":["经济与社会","战争与外交"],"mainTag":"经济与社会","subTag":"战争与外交","timeText":"19世纪","place":"中国、印度、东南亚、英国帝国贸易网络和全球医药市场","summary":"十九世纪全球鸦片贸易把殖民财政、自由贸易、成瘾危机和国际法冲突连接起来。","fields":[{"label":"标题","value":"十九世纪全球鸦片贸易"},{"label":"分级","value":"B"},{"label":"类型","value":"概念/思潮卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"19世纪"},{"label":"地点","value":"中国、印度、东南亚、英国帝国贸易网络和全球医药市场"},{"label":"主要国家","value":"中国；英国；印度；美国；法国；德国；荷兰"},{"label":"一句话概括","value":"十九世纪全球鸦片贸易把殖民财政、自由贸易、成瘾危机和国际法冲突连接起来。"},{"label":"核心主张/思路","value":"鸦片既是殖民商品、财政收入和贸易平衡工具，也是造成社会危机和国际冲突的成瘾性药物。"},{"label":"提出者/代表人物（可选）","value":"英国东印度公司、印度殖民政府、中国清政府、走私商、传教士和禁烟改革者。"},{"label":"它从何而来","value":"英国对华贸易逆差、印度殖民种植、白银流动和亚洲消费市场共同推动鸦片贸易扩大。"},{"label":"典型表现","value":"鸦片战争、印度鸦片专卖、东亚走私网络、传教士反鸦片运动和上海万国禁烟会。"},{"label":"为什么重要","value":"它解释国际毒品管制为何从鸦片问题出发，也说明近代全球贸易与帝国暴力如何改变亚洲社会。"},{"label":"争议/局限","value":"鸦片既有医疗用途，也有成瘾和贸易剥削问题，不能只从道德或自由贸易单一角度解释。"},{"label":"出处","value":"UNODC: A Century of International Drug Control；Carl Trocki, Opium, Empire and the Global Political Economy；David Courtwright, Forces of Habit。"}],"relationItems":["↔ 相关：鸦片战争","→ 后果：国际毒品管制","→ 后果：海牙《国际鸦片公约》","↔ 相关：魏玛德国鸦片法"],"relations":[{"text":"→ 后果：国际毒品管制","id":"extra962"},{"text":"→ 后果：海牙《国际鸦片公约》","id":"extra744"},{"text":"↔ 相关：魏玛德国鸦片法","id":"card100"}],"source":"history","id":"extra972"},{"title":"威廉二世","level":"B","type":"人物卡","tags":["政治与制度","战争与外交"],"mainTag":"政治与制度","subTag":"战争与外交","timeText":"1859—1941年；1888—1918年任德意志皇帝","place":"德国、欧洲外交体系和一战相关战场","summary":"威廉二世是德意志帝国末代皇帝，其世界政策、海军扩张和政治风格加剧德国与欧洲列强紧张。","fields":[{"label":"标题","value":"威廉二世"},{"label":"分级","value":"B"},{"label":"类型","value":"人物卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1859—1941年；1888—1918年任德意志皇帝"},{"label":"地点","value":"德国、欧洲外交体系和一战相关战场"},{"label":"主要国家","value":"德国；英国；法国；俄国；奥匈帝国"},{"label":"一句话概括","value":"威廉二世是德意志帝国末代皇帝，其世界政策、海军扩张和政治风格加剧德国与欧洲列强紧张。"},{"label":"生卒年/活跃年代","value":"1859—1941年；1888年即位，1918年十一月革命中退位。"},{"label":"身份/职务","value":"德意志皇帝、普鲁士国王。"},{"label":"关键贡献/作为","value":"解除俾斯麦职务，推动世界政策和海军扩张，在一战期间名义上居于最高统帅地位。"},{"label":"核心主张/立场","value":"强调皇权、军队、德国世界地位和帝国荣誉，但政策常在强硬表态与实际妥协之间摇摆。"},{"label":"为什么重要","value":"他是帝德政治文化的象征人物，既反映君主制权威，也暴露宪政、军方、官僚和舆论之间的矛盾。"},{"label":"争议/评价","value":"威廉二世不是一战唯一责任人，但其外交言行、海军政策和统治风格确实加剧了德国孤立与欧洲不信任。"},{"label":"关联事件（可选）","value":"英德海军军备竞赛、威廉二世《匈奴演说》、七月危机、德国十一月革命。"},{"label":"出处","value":"DHM/LeMO: Wilhelm II；Encyclopaedia Britannica: William II；Christopher Clark, Kaiser Wilhelm II。"}],"relationItems":["← 前因：德意志帝国成立","↔ 相关：威廉二世《匈奴演说》","↔ 相关：德国世界政策","→ 后果：德国十一月革命"],"relations":[{"text":"← 前因：德意志帝国成立","id":"extra621"},{"text":"↔ 相关：威廉二世《匈奴演说》","id":"extra75"},{"text":"→ 后果：德国十一月革命","id":"extra666"}],"source":"history","id":"extra973"},{"title":"马克思恩格斯《共产党宣言》","level":"S","type":"作品卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1848年2月出版","place":"伦敦出版；作者为德意志流亡思想家","summary":"《共产党宣言》把阶级斗争、资本主义批判和无产阶级革命写成现代政治纲领，深刻影响十九世纪以来的世界史。","fields":[{"label":"标题","value":"马克思恩格斯《共产党宣言》"},{"label":"分级","value":"S"},{"label":"类型","value":"作品卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1848年2月出版"},{"label":"地点","value":"伦敦出版；作者为德意志流亡思想家"},{"label":"主要国家","value":"德国、英国、法国"},{"label":"一句话概括","value":"《共产党宣言》把阶级斗争、资本主义批判和无产阶级革命写成现代政治纲领，深刻影响十九世纪以来的世界史。"},{"label":"作者/创作者","value":"卡尔·马克思、弗里德里希·恩格斯。"},{"label":"媒介/体裁","value":"政治纲领、理论宣言。"},{"label":"主要内容/讲了什么","value":"宣言概述资本主义如何扩张世界市场、改造社会关系并制造资产阶级与无产阶级的对立，最后提出共产党人的政治目标和国际主义号召。"},{"label":"核心主张/表达","value":"历史由阶级斗争推动；资本主义具有革命性生产力，也制造自身矛盾；无产阶级应组织起来推翻资产阶级统治。"},{"label":"它出现在什么背景下","value":"欧洲工业化、工人运动、社会主义思想和1848年革命前夜交汇。共产主义者同盟委托马克思和恩格斯起草纲领。"},{"label":"为什么重要","value":"它是现代社会主义和共产主义运动最有影响力的文本之一，把经济分析、历史哲学和政治动员结合成一种可传播的世界革命语言。"},{"label":"接受与影响","value":"1848年出版时影响有限，但此后随着工人运动、社会民主党、社会主义第二国际、俄国革命和全球共产主义运动扩张，成为世界史级政治文本。"},{"label":"争议/局限","value":"它的革命政治和阶级分析长期引发巨大争议；后世政权和运动对其解释差异极大，不能简单等同于某一个国家实践。"},{"label":"创作时间","value":"1847年至1848年初。"},{"label":"发表/出版/首演时间","value":"1848年2月在伦敦以德文出版。"},{"label":"出处","value":"Marxists Internet Archive: Manifesto of the Communist Party；Encyclopaedia Britannica: The Communist Manifesto；German History Documents and Images相关资料。"},{"label":"资料备注","value":"卡片把它作为作品卡处理，重点在文本本身，而不是马克思个人传记。"}],"relationItems":["← 前因：工业革命","← 前因：德意志自由主义","→ 后果：德国社会民主党（SPD）","→ 后果：社会主义第二国际","↔ 相关：卡尔·马克思","↔ 相关：弗里德里希·恩格斯"],"relations":[{"text":"← 前因：德意志自由主义","id":"extra501"},{"text":"→ 后果：德国社会民主党（SPD）","id":"extra628"},{"text":"→ 后果：社会主义第二国际","id":"extra698"},{"text":"↔ 相关：卡尔·马克思","id":"extra911"},{"text":"↔ 相关：弗里德里希·恩格斯","id":"extra912"}],"source":"history","id":"extra61"},{"title":"《德意志，一个冬天的童话》","level":"B","type":"作品卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1844年出版","place":"巴黎流亡语境与德意志旅行经验之间","summary":"海涅借一次返乡旅行讽刺德意志的审查、狭隘民族主义和复辟政治，是 Vormärz 时期政治文学的代表作品。","fields":[{"label":"标题","value":"《德意志，一个冬天的童话》"},{"label":"分级","value":"B"},{"label":"类型","value":"作品卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1844年出版"},{"label":"地点","value":"巴黎流亡语境与德意志旅行经验之间"},{"label":"主要国家","value":"德国、法国"},{"label":"一句话概括","value":"海涅借一次返乡旅行讽刺德意志的审查、狭隘民族主义和复辟政治，是 Vormärz 时期政治文学的代表作品。"},{"label":"作者/创作者","value":"海因里希·海涅。"},{"label":"媒介/体裁","value":"长篇讽刺诗、政治旅行诗。"},{"label":"主要内容/讲了什么","value":"作品以诗人从法国进入德意志的旅程为线索，描写边境、城市、纪念物和政治气氛，同时穿插对德意志现实的尖锐讽刺。"},{"label":"核心主张/表达","value":"作品既批判德意志保守专制、审查制度和民族主义幻觉，也保留对德意志文化和未来自由的复杂情感。"},{"label":"它出现在什么背景下","value":"十九世纪四十年代，德意志处在1848革命前的 Vormärz 氛围中，政治审查严厉，自由主义和民族主义不断积累。海涅长期流亡巴黎，具有跨国观察视角。"},{"label":"为什么重要","value":"它把德意志统一与奥普领导权问题写成文学经验：不是抽象制度争论，而是边境、语言、记忆和政治压抑在个体旅程中的碰撞。"},{"label":"接受与影响","value":"作品因政治讽刺和反保守立场受到审查压力，也成为德语政治文学传统中的重要文本。"},{"label":"争议/局限","value":"海涅对德意志民族主义的讽刺让他在不同时期都容易被政治化解读；作品的文学反讽不能被简化成单一政治纲领。"},{"label":"创作时间","value":"1843年返乡旅行后写作。"},{"label":"发表/出版/首演时间","value":"1844年出版。"},{"label":"出处","value":"Encyclopaedia Britannica: Heinrich Heine；Deutsches Historisches Museum/LeMO: Vormärz文学与政治文化资料；Project Gutenberg-DE相关文本资料。"},{"label":"资料备注","value":"中文题名也常译作《德国，一个冬天的童话》。本库标准名暂用《德意志，一个冬天的童话》。"}],"relationItems":["← 前因：德意志邦联的卡尔斯巴德决议","→ 后果：1848年德意志革命","↔ 相关：海因里希·海涅","↔ 相关：德意志自由主义"],"relations":[{"text":"← 前因：德意志邦联的卡尔斯巴德决议","id":"extra488"},{"text":"→ 后果：1848年德意志革命","id":"extra490"},{"text":"↔ 相关：德意志自由主义","id":"extra501"}],"source":"history","id":"extra62"},{"title":"《查拉图斯特拉如是说》","level":"B","type":"作品卡","tags":["文化与思想","无"],"mainTag":"文化与思想","subTag":"无","timeText":"1883年至1885年陆续出版","place":"德语思想文化圈","summary":"尼采用诗性哲学叙事提出“上帝死了”“超人”等主题，成为现代欧洲思想中最具影响力也最易被误读的作品之一。","fields":[{"label":"标题","value":"《查拉图斯特拉如是说》"},{"label":"分级","value":"B"},{"label":"类型","value":"作品卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"无"},{"label":"时间","value":"1883年至1885年陆续出版"},{"label":"地点","value":"德语思想文化圈"},{"label":"主要国家","value":"德国、瑞士"},{"label":"一句话概括","value":"尼采用诗性哲学叙事提出“上帝死了”“超人”等主题，成为现代欧洲思想中最具影响力也最易被误读的作品之一。"},{"label":"作者/创作者","value":"弗里德里希·尼采。"},{"label":"媒介/体裁","value":"哲学文学、诗性散文、寓言式思想作品。"},{"label":"主要内容/讲了什么","value":"作品借先知查拉图斯特拉的言说，讨论价值崩塌、超人、永恒轮回、精神自我超越和现代人的虚无主义处境。"},{"label":"核心主张/表达","value":"传统宗教和形而上价值失去支配力后，人必须面对虚无主义，并重新创造价值。"},{"label":"它出现在什么背景下","value":"十九世纪后期欧洲宗教权威、科学理性、民族国家和大众社会同时变化，尼采对基督教道德、现代平庸化和传统哲学展开激烈批判。"},{"label":"为什么重要","value":"它不是德国政治史的直接事件，却深刻影响现代主义、存在主义、文学、心理学和二十世纪政治思想争论。理解德国思想文化从帝国到魏玛的张力，绕不开尼采。"},{"label":"接受与影响","value":"作品在尼采生前影响有限，二十世纪后影响迅速扩大；被许多文学家、哲学家和政治运动重新解释。"},{"label":"争议/局限","value":"尼采思想后来曾被民族主义和纳粹宣传扭曲利用，但这不能简单等同于作品原意。作品本身也因隐喻性强而容易产生相互冲突的解释。"},{"label":"创作时间","value":"1883年至1885年。"},{"label":"发表/出版/首演时间","value":"1883年至1885年分部出版，1892年四部合刊。"},{"label":"出处","value":"Encyclopaedia Britannica: Thus Spoke Zarathustra；Stanford Encyclopedia of Philosophy: Friedrich Nietzsche；Internet Archive/Project Gutenberg相关文本资料。"},{"label":"资料备注","value":"本卡只处理作品本身，不把尼采复杂思想直接归入任何单一政治阵营。"}],"relationItems":["↔ 相关：弗里德里希·尼采","↔ 相关：虚无主义","↔ 相关：魏玛文化","→ 后果：德国保守革命思潮"],"relations":[{"text":"↔ 相关：魏玛文化","id":"card197"}],"source":"history","id":"extra63"},{"title":"《西线无战事》","level":"B","type":"作品卡","tags":["文化与思想","战争与外交"],"mainTag":"文化与思想","subTag":"战争与外交","timeText":"1928年连载；1929年成书出版","place":"德国魏玛共和国","summary":"《西线无战事》以普通士兵视角呈现一战前线创伤，成为魏玛时期反战记忆和代际破碎感的代表作品。","fields":[{"label":"标题","value":"《西线无战事》"},{"label":"分级","value":"B"},{"label":"类型","value":"作品卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1928年连载；1929年成书出版"},{"label":"地点","value":"德国魏玛共和国"},{"label":"主要国家","value":"德国、法国、英国、美国"},{"label":"一句话概括","value":"《西线无战事》以普通士兵视角呈现一战前线创伤，成为魏玛时期反战记忆和代际破碎感的代表作品。"},{"label":"作者/创作者","value":"埃里希·玛利亚·雷马克。"},{"label":"媒介/体裁","value":"小说。"},{"label":"主要内容/讲了什么","value":"小说讲述德国青年保罗·博伊默和同学们在教师与爱国话语鼓动下参军，随后在西线经历死亡、恐惧、身体创伤和精神破碎。"},{"label":"核心主张/表达","value":"作品并不歌颂英雄主义，而是揭示战争如何吞噬普通青年，让一代人在战壕、医院和归乡失败中失去未来。"},{"label":"它出现在什么背景下","value":"魏玛共和国仍被一战战败、凡尔赛体系和政治极化困扰，社会对战争记忆存在尖锐冲突。"},{"label":"为什么重要","value":"它把一战写成普通士兵的创伤经验，而不是将军、民族或国家荣誉的叙事。它也让国际读者理解战后德国社会的精神伤口。"},{"label":"接受与影响","value":"小说成为国际畅销书，1930年美国电影版获得巨大影响；纳粹上台后将其视为“败坏民族精神”的作品并加以打压。"},{"label":"争议/局限","value":"德国右翼和民族主义者指责它削弱军人荣誉、传播失败主义；作品也常被讨论其反战表达与商业成功之间的关系。"},{"label":"创作时间","value":"1920年代后期。"},{"label":"发表/出版/首演时间","value":"1928年在报刊连载，1929年出版。"},{"label":"出处","value":"Encyclopaedia Britannica: All Quiet on the Western Front；United States Holocaust Memorial Museum关于纳粹德国焚书运动资料；Deutsches Historisches Museum/LeMO: Weimar culture相关资料。"},{"label":"资料备注","value":"卡片采用中文通行译名《西线无战事》，英文名为 All Quiet on the Western Front，德文原名 Im Westen nichts Neues。"}],"relationItems":["← 前因：第一次世界大战德国战败","↔ 相关：魏玛文化","↔ 相关：德国“背后一刀”传说","✗ 对立/冲突：德国“十一月罪人”政治污名","→ 后果：纳粹德国焚书运动"],"relations":[{"text":"← 前因：第一次世界大战德国战败","id":"extra926"},{"text":"↔ 相关：魏玛文化","id":"card197"},{"text":"↔ 相关：德国“背后一刀”传说","id":"extra623"},{"text":"✗ 对立/冲突：德国“十一月罪人”政治污名","id":"card204"},{"text":"→ 后果：纳粹德国焚书运动","id":"extra284"}],"source":"history","id":"extra64"},{"title":"弗里茨·朗电影《大都会》","level":"B","type":"作品卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1927年上映","place":"德国魏玛共和国，柏林电影工业语境","summary":"《大都会》用未来城市和阶级分裂的视觉寓言，表现魏玛德国对工业现代性、技术统治和社会冲突的焦虑。","fields":[{"label":"标题","value":"弗里茨·朗电影《大都会》"},{"label":"分级","value":"B"},{"label":"类型","value":"作品卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1927年上映"},{"label":"地点","value":"德国魏玛共和国，柏林电影工业语境"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"《大都会》用未来城市和阶级分裂的视觉寓言，表现魏玛德国对工业现代性、技术统治和社会冲突的焦虑。"},{"label":"作者/创作者","value":"导演弗里茨·朗；编剧西娅·冯·哈堡。"},{"label":"媒介/体裁","value":"电影，科幻默片，德国表现主义电影。"},{"label":"主要内容/讲了什么","value":"影片描绘一座高度机械化的未来城市，富人生活在地上，工人被压在地下机器世界中；统治者之子逐渐看到阶级压迫，并卷入调和冲突的故事。"},{"label":"核心主张/表达","value":"影片把现代工业城市呈现为壮丽又压迫性的机器体系，表达对资本、技术、劳动和群众政治的复杂焦虑。"},{"label":"它出现在什么背景下","value":"魏玛中期德国电影工业高度发达，城市化、合理化生产、阶级冲突和现代消费文化同时展开。"},{"label":"为什么重要","value":"它是世界电影史上最重要的科幻电影之一，也把魏玛现代性的视觉想象推到极致。其城市景观、机器人形象和阶级寓言长期影响后来的科幻电影。"},{"label":"接受与影响","value":"上映时因成本高、长度和叙事问题评价复杂，但后来被重新评价为电影经典，并入选重要文化遗产保护序列。"},{"label":"争议/局限","value":"影片结尾强调阶级调和，被批评为政治上含混；其作者之一西娅·冯·哈堡后来与纳粹关系密切，也使作品接受史更复杂。"},{"label":"创作时间","value":"1925年至1926年拍摄制作。"},{"label":"发表/出版/首演时间","value":"1927年在柏林首映。"},{"label":"出处","value":"Encyclopaedia Britannica: Metropolis；MoMA/film archive资料；UNESCO Memory of the World关于Metropolis资料。"},{"label":"资料备注","value":"本卡聚焦1927年原作及其历史语境，不展开后世修复版本。"}],"relationItems":["← 前因：魏玛工业合理化改革","↔ 相关：魏玛文化","↔ 相关：德国表现主义电影","↔ 相关：魏玛柏林现代性"],"relations":[{"text":"← 前因：魏玛工业合理化改革","id":"card63"},{"text":"↔ 相关：魏玛文化","id":"card197"},{"text":"↔ 相关：德国表现主义电影","id":"card78"},{"text":"↔ 相关：魏玛柏林现代性","id":"card33"}],"source":"history","id":"extra65"},{"title":"希特勒《我的奋斗》","level":"B","type":"作品卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"第一卷1925年出版，第二卷1926年出版","place":"德国；写作与纳粹运动早期重组有关","summary":"《我的奋斗》集中呈现希特勒的反犹主义、民族主义和扩张主义世界观，是理解纳粹意识形态的重要文本。","fields":[{"label":"标题","value":"希特勒《我的奋斗》"},{"label":"分级","value":"B"},{"label":"类型","value":"作品卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"第一卷1925年出版，第二卷1926年出版"},{"label":"地点","value":"德国；写作与纳粹运动早期重组有关"},{"label":"主要国家","value":"德国、奥地利"},{"label":"一句话概括","value":"《我的奋斗》集中呈现希特勒的反犹主义、民族主义和扩张主义世界观，是理解纳粹意识形态的重要文本。"},{"label":"作者/创作者","value":"阿道夫·希特勒；鲁道夫·赫斯等人在整理过程中有辅助作用。"},{"label":"媒介/体裁","value":"政治自传、意识形态纲领、宣传文本。"},{"label":"主要内容/讲了什么","value":"文本混合个人经历、政治怨恨、种族主义世界观、对魏玛共和国和马克思主义的攻击，以及对德国民族复兴和向东扩张的设想。"},{"label":"核心主张/表达","value":"它宣扬极端民族主义、反犹主义、反马克思主义、领袖原则和生存空间观念，将德国危机解释为种族斗争与内部敌人破坏的结果。"},{"label":"它出现在什么背景下","value":"1923年希特勒啤酒馆政变失败后，希特勒在被监禁和纳粹党重组过程中把政治失败转化为意识形态自我塑造。"},{"label":"为什么重要","value":"它不是普通回忆录，而是纳粹政治语言、敌人想象和扩张目标的重要汇集。理解纳粹如何把魏玛危机转化为种族化政治动员，必须处理这本文本。"},{"label":"接受与影响","value":"纳粹上台前销量有限但逐渐扩大；1933年后成为纳粹德国高度传播的政治文本，并被用于塑造公共意识形态。"},{"label":"争议/局限","value":"文本充满仇恨宣传、伪科学种族论和阴谋论，不能作为事实叙述使用；研究时应把它作为危险意识形态文本和政治宣传材料来读。"},{"label":"创作时间","value":"主要写于1924年监禁期间及随后时期。"},{"label":"发表/出版/首演时间","value":"第一卷1925年，第二卷1926年。"},{"label":"出处","value":"Encyclopaedia Britannica: Mein Kampf；United States Holocaust Memorial Museum: Mein Kampf；Deutsches Historisches Museum/LeMO: Hitler and National Socialism资料。"},{"label":"资料备注","value":"此卡不复述具体仇恨内容，只概括其意识形态功能。"}],"relationItems":["← 前因：希特勒啤酒馆政变","← 前因：德国“背后一刀”传说","→ 后果：希特勒出任德国总理","→ 后果：纳粹种族政策","↔ 相关：阿道夫·希特勒","↔ 相关：德国“十一月罪人”政治污名"],"relations":[{"text":"← 前因：希特勒啤酒馆政变","id":"card18"},{"text":"← 前因：德国“背后一刀”传说","id":"extra623"},{"text":"→ 后果：希特勒出任德国总理","id":"card71"},{"text":"↔ 相关：德国“十一月罪人”政治污名","id":"card204"}],"source":"history","id":"extra66"},{"title":"布莱希特《三便士歌剧》","level":"B","type":"作品卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1928年首演","place":"德国柏林","summary":"《三便士歌剧》用讽刺音乐剧形式揭露资本主义社会的伪善，成为魏玛舞台文化代表作品。","fields":[{"label":"标题","value":"布莱希特《三便士歌剧》"},{"label":"分级","value":"B"},{"label":"类型","value":"作品卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1928年首演"},{"label":"地点","value":"德国柏林"},{"label":"主要国家","value":"德国、英国"},{"label":"一句话概括","value":"《三便士歌剧》用讽刺音乐剧形式揭露资本主义社会的伪善，成为魏玛舞台文化代表作品。"},{"label":"作者/创作者","value":"贝托尔特·布莱希特、库尔特·魏尔，改编自约翰·盖伊《乞丐歌剧》。"},{"label":"媒介/体裁","value":"音乐剧/戏剧作品。"},{"label":"主要内容/讲了什么","value":"作品围绕伦敦黑帮、乞丐组织、警察和资产阶级婚姻展开，用犯罪世界映照资本主义社会秩序。"},{"label":"核心主张/表达","value":"它以疏离、讽刺和流行音乐打破传统戏剧沉浸感，质疑法律、道德和金钱之间的关系。"},{"label":"它出现在什么背景下","value":"魏玛柏林商业娱乐、左翼文化和现代戏剧实验高度活跃。"},{"label":"为什么重要","value":"它把先锋戏剧与大众娱乐结合，成为魏玛文化国际传播的重要作品。"},{"label":"接受与影响","value":"首演后获得巨大成功，其中歌曲和形式影响二十世纪戏剧和音乐剧。"},{"label":"争议/局限","value":"其政治讽刺和商业成功之间一直存在张力。"},{"label":"创作时间","value":"1928年。"},{"label":"发表/出版/首演时间","value":"1928年在柏林首演。"},{"label":"出处","value":"Encyclopaedia Britannica: The Threepenny Opera；Deutsches Historisches Museum/LeMO相关资料；Brecht/Weill研究资料。"}],"relationItems":["↔ 相关：魏玛柏林现代性","↔ 相关：德国新客观主义","↔ 相关：魏玛文化"],"relations":[{"text":"↔ 相关：魏玛柏林现代性","id":"card33"},{"text":"↔ 相关：德国新客观主义","id":"card31"},{"text":"↔ 相关：魏玛文化","id":"card197"}],"source":"history","id":"extra67"},{"title":"德国电影《蓝天使》","level":"B","type":"作品卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1930年上映","place":"德国","summary":"《蓝天使》是早期德国有声电影代表作，塑造玛琳·黛德丽明星形象，也呈现魏玛末期欲望与权威崩塌。","fields":[{"label":"标题","value":"德国电影《蓝天使》"},{"label":"分级","value":"B"},{"label":"类型","value":"作品卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1930年上映"},{"label":"地点","value":"德国"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"《蓝天使》是早期德国有声电影代表作，塑造玛琳·黛德丽明星形象，也呈现魏玛末期欲望与权威崩塌。"},{"label":"作者/创作者","value":"导演约瑟夫·冯·斯登堡，主演埃米尔·雅宁斯、玛琳·黛德丽。"},{"label":"媒介/体裁","value":"有声电影。"},{"label":"主要内容/讲了什么","value":"一名严厉教师迷恋夜总会歌女，逐步失去社会地位和自我控制，最终走向毁灭。"},{"label":"核心主张/表达","value":"影片通过性吸引、舞台表演和男性权威崩塌，呈现魏玛文化中欲望、羞辱和社会秩序的不稳定。"},{"label":"它出现在什么背景下","value":"有声电影兴起，魏玛末期电影工业和城市娱乐文化高度发达，同时政治危机加深。"},{"label":"为什么重要","value":"它是德国电影从默片向有声片转型的重要作品，也使玛琳·黛德丽成为国际明星。"},{"label":"接受与影响","value":"影片国际影响巨大，黛德丽随后进入好莱坞。"},{"label":"争议/局限","value":"作品常被作为魏玛“颓废”想象的一部分，但这种理解容易被后来的纳粹道德话语污染。"},{"label":"创作时间","value":"1929年至1930年。"},{"label":"发表/出版/首演时间","value":"1930年上映。"},{"label":"出处","value":"Encyclopaedia Britannica: The Blue Angel；Deutsches Historisches Museum/LeMO相关资料；BFI相关资料。"}],"relationItems":["↔ 相关：魏玛柏林现代性","↔ 相关：魏玛“新女性”","↔ 相关：弗里茨·朗电影《大都会》"],"relations":[{"text":"↔ 相关：魏玛柏林现代性","id":"card33"},{"text":"↔ 相关：魏玛“新女性”","id":"card32"},{"text":"↔ 相关：弗里茨·朗电影《大都会》","id":"extra65"}],"source":"history","id":"extra68"},{"title":"德布林《柏林亚历山大广场》","level":"B","type":"作品卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1929年出版","place":"德国柏林","summary":"《柏林亚历山大广场》用现代主义叙事写魏玛柏林底层生活，是理解都市现代性的重要文学作品。","fields":[{"label":"标题","value":"德布林《柏林亚历山大广场》"},{"label":"分级","value":"B"},{"label":"类型","value":"作品卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1929年出版"},{"label":"地点","value":"德国柏林"},{"label":"创作时间","value":"1920年代后期"},{"label":"发表/出版/首演时间","value":"1929年出版"},{"label":"一句话概括","value":"《柏林亚历山大广场》用现代主义叙事写魏玛柏林底层生活，是理解都市现代性的重要文学作品。"},{"label":"作者/创作者","value":"阿尔弗雷德·德布林。"},{"label":"媒介/体裁","value":"长篇小说。"},{"label":"主要内容/讲了什么","value":"小说围绕刑满释放者弗兰茨·比伯科普夫在柏林底层社会中的挣扎，展现失业、犯罪、欲望、交通、广告和大众传媒交织的都市生活。"},{"label":"核心主张/表达","value":"作品不是简单道德审判，而是用蒙太奇、内心流动和城市噪音表现现代都市如何塑造个体命运。"},{"label":"它出现在什么背景下","value":"魏玛柏林是欧洲现代都市文化中心，同时也充满贫困、犯罪、政治暴力和社会不安。"},{"label":"为什么重要","value":"它是德语现代主义小说代表作之一，把柏林变成几乎与人物同等重要的叙事主体。"},{"label":"接受与影响","value":"作品持续影响德国文学、城市叙事和影视改编，后有著名电视剧版本。"},{"label":"争议/局限","value":"复杂叙事和方言、新闻、广告拼贴使阅读门槛较高。"},{"label":"出处","value":"Encyclopaedia Britannica，“Berlin Alexanderplatz”；Oxford Reference，Alfred Döblin materials。"}],"relationItems":["← 前因：魏玛柏林现代性","← 前因：魏玛柏林“戒指会”犯罪网络","→ 后果：现代城市小说传统","↔ 相关：德国新客观主义","↔ 相关：弗里茨·朗电影《M》","✗ 对立/冲突：都市自由想象","✗ 对立/冲突：底层社会困境","↔ 同时期参考：《蓝天使》"],"relations":[{"text":"← 前因：魏玛柏林现代性","id":"card33"},{"text":"← 前因：魏玛柏林“戒指会”犯罪网络","id":"card74"},{"text":"↔ 相关：德国新客观主义","id":"card31"},{"text":"↔ 相关：弗里茨·朗电影《M》","id":"extra70"},{"text":"✗ 对立/冲突：都市自由想象","id":"card202"}],"source":"history","id":"extra69"},{"title":"弗里茨·朗电影《M》","level":"B","type":"作品卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1931年上映","place":"德国柏林","summary":"《M》用儿童杀手追捕故事呈现魏玛都市恐惧，是犯罪电影和声音电影史上的关键作品。","fields":[{"label":"标题","value":"弗里茨·朗电影《M》"},{"label":"分级","value":"B"},{"label":"类型","value":"作品卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1931年上映"},{"label":"地点","value":"德国柏林"},{"label":"创作时间","value":"1930年—1931年"},{"label":"发表/出版/首演时间","value":"1931年上映"},{"label":"一句话概括","value":"《M》用儿童杀手追捕故事呈现魏玛都市恐惧，是犯罪电影和声音电影史上的关键作品。"},{"label":"作者/创作者","value":"弗里茨·朗导演；特娅·冯·哈堡等参与编剧。"},{"label":"媒介/体裁","value":"电影，犯罪惊悚片，早期有声电影。"},{"label":"主要内容/讲了什么","value":"影片讲述一名儿童杀手引发城市恐慌，警方和地下犯罪组织分别展开追捕，最终把凶手推向类似审判的场景。"},{"label":"核心主张/表达","value":"影片关注现代城市的恐惧传播、群众正义、警察技术、犯罪组织和精神异常之间的关系。"},{"label":"它出现在什么背景下","value":"魏玛末期连环杀人案、报刊犯罪新闻、现代警务和城市不安全感构成作品背景。"},{"label":"为什么重要","value":"它把声音设计、视觉阴影和社会心理结合起来，对犯罪片、黑色电影和现代惊悚片影响很深。"},{"label":"接受与影响","value":"被广泛视为弗里茨·朗代表作和世界电影史经典。"},{"label":"争议/局限","value":"影片常被联系到真实连环杀人案，但它并不是对某一案件的直接纪实改编。"},{"label":"出处","value":"Encyclopaedia Britannica，“M”；British Film Institute，Fritz Lang and M materials。"}],"relationItems":["← 前因：哈曼连环杀人案","← 前因：彼得·库尔滕连环杀人案","→ 后果：电影黑色传统","→ 后果：现代犯罪电影","↔ 相关：德国表现主义电影","↔ 相关：德国乌发电影公司","✗ 对立/冲突：国家法律","✗ 对立/冲突：群众私刑","↔ 同时期参考：德布林《柏林亚历山大广场》"],"relations":[{"text":"← 前因：哈曼连环杀人案","id":"card75"},{"text":"← 前因：彼得·库尔滕连环杀人案","id":"card76"},{"text":"→ 后果：电影黑色传统","id":"card199"},{"text":"↔ 相关：德国表现主义电影","id":"card78"},{"text":"↔ 相关：德国乌发电影公司","id":"card77"},{"text":"↔ 同时期参考：德布林《柏林亚历山大广场》","id":"extra69"}],"source":"history","id":"extra70"},{"title":"《新教伦理与资本主义精神》","level":"A","type":"作品卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1904—1905年发表；1920年修订收入文集","place":"德国","summary":"《新教伦理与资本主义精神》把宗教伦理与现代资本主义精神相连，是社会学和现代性研究经典。","fields":[{"label":"标题","value":"《新教伦理与资本主义精神》"},{"label":"分级","value":"A"},{"label":"类型","value":"作品卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1904—1905年发表；1920年修订收入文集"},{"label":"地点","value":"德国"},{"label":"创作时间","value":"1904年—1905年以论文形式发表"},{"label":"发表/出版/首演时间","value":"1904年—1905年发表，1920年收入修订文集"},{"label":"一句话概括","value":"《新教伦理与资本主义精神》把宗教伦理与现代资本主义精神相连，是社会学和现代性研究经典。"},{"label":"作者/创作者","value":"马克斯·韦伯。"},{"label":"媒介/体裁","value":"社会学、经济史和宗教社会学著作。"},{"label":"主要内容/讲了什么","value":"韦伯分析新教禁欲伦理，尤其是加尔文主义职业观，如何与理性化劳动、储蓄、纪律和资本主义经营精神产生亲缘关系。"},{"label":"核心主张/表达","value":"资本主义不只是技术和市场制度，也与人的伦理自我约束、职业观和理性化生活方式有关。"},{"label":"它出现在什么背景下","value":"德国历史学派经济学、资本主义起源争论、宗教史研究和德国社会科学专业化。"},{"label":"为什么重要","value":"它成为现代社会学经典，提供理解资本主义文化根源和理性化进程的核心框架。"},{"label":"接受与影响","value":"长期影响经济社会学、宗教社会学、现代化理论和资本主义史讨论。"},{"label":"争议/局限","value":"韦伯命题不断受到史料、因果关系和欧洲中心主义方面的批评。"},{"label":"出处","value":"Encyclopaedia Britannica，“The Protestant Ethic and the Spirit of Capitalism”；Stanford Encyclopedia of Philosophy，Max Weber materials。"}],"relationItems":["← 前因：德国历史学派经济学","← 前因：德国大学研究体系","→ 后果：现代社会学","↔ 相关：十九世纪德国社会问题","↔ 相关：德国民法典","✗ 对立/冲突：经济决定论解释","✗ 对立/冲突：文化伦理解释","↔ 同时期参考：普朗克量子假说"],"relations":[{"text":"← 前因：德国历史学派经济学","id":"extra734"},{"text":"← 前因：德国大学研究体系","id":"extra935"},{"text":"↔ 相关：十九世纪德国社会问题","id":"extra511"},{"text":"↔ 相关：德国民法典","id":"extra720"},{"text":"↔ 同时期参考：普朗克量子假说","id":"extra722"}],"source":"history","id":"extra71"},{"title":"德国电影《卡里加里博士的小屋》","level":"B","type":"作品卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1920年上映","place":"德国","summary":"《卡里加里博士的小屋》以扭曲布景和不可靠叙事奠定德国表现主义电影的标志性形象。","fields":[{"label":"标题","value":"德国电影《卡里加里博士的小屋》"},{"label":"分级","value":"B"},{"label":"类型","value":"作品卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1920年上映"},{"label":"地点","value":"德国"},{"label":"创作时间","value":"1919年"},{"label":"发表/出版/首演时间","value":"1920年上映"},{"label":"一句话概括","value":"《卡里加里博士的小屋》以扭曲布景和不可靠叙事奠定德国表现主义电影的标志性形象。"},{"label":"作者/创作者","value":"罗伯特·维内导演；卡尔·迈耶、汉斯·雅诺维茨编剧。"},{"label":"媒介/体裁","value":"无声电影、恐怖片、德国表现主义电影。"},{"label":"主要内容/讲了什么","value":"影片讲述神秘医生卡里加里操控梦游者切萨雷实施杀人，故事通过框架叙事和精神病院情节制造现实与幻觉的摇摆。"},{"label":"核心主张/表达","value":"影片用倾斜街道、尖锐阴影和夸张布景表现权威恐惧、心理扭曲和战后不安。"},{"label":"它出现在什么背景下","value":"一战后德国社会创伤、魏玛电影工业、舞台表现主义和现代心理学兴趣。"},{"label":"为什么重要","value":"它是世界电影史中表现主义视觉语言的代表，对恐怖片、黑色电影和心理惊悚片影响深远。"},{"label":"接受与影响","value":"影片成为德国表现主义电影标志作品，持续被电影史和视觉文化研究引用。"},{"label":"争议/局限","value":"关于影片是否直接预示德国威权主义，一直存在解释争论。"},{"label":"出处","value":"Encyclopaedia Britannica，“The Cabinet of Dr. Caligari”；British Film Institute，Caligari materials。"}],"relationItems":["← 前因：德国表现主义电影","← 前因：德国乌发电影公司","→ 后果：电影黑色传统","↔ 相关：弗里茨·朗电影《M》","↔ 相关：弗里茨·朗电影《大都会》","✗ 对立/冲突：现实主义空间","✗ 对立/冲突：心理化扭曲空间","↔ 同时期参考：魏玛柏林达达运动"],"relations":[{"text":"← 前因：德国表现主义电影","id":"card78"},{"text":"← 前因：德国乌发电影公司","id":"card77"},{"text":"→ 后果：电影黑色传统","id":"card199"},{"text":"↔ 相关：弗里茨·朗电影《M》","id":"extra70"},{"text":"↔ 相关：弗里茨·朗电影《大都会》","id":"extra65"},{"text":"↔ 同时期参考：魏玛柏林达达运动","id":"card79"}],"source":"history","id":"extra72"},{"title":"《柏林：大城市交响曲》","level":"C","type":"作品卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1927年上映","place":"德国柏林","summary":"《柏林：大城市交响曲》用一天城市影像表现魏玛柏林的速度、机器、劳动和消费。","fields":[{"label":"标题","value":"《柏林：大城市交响曲》"},{"label":"分级","value":"C"},{"label":"类型","value":"作品卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1927年上映"},{"label":"地点","value":"德国柏林"},{"label":"创作时间","value":"1920年代中期"},{"label":"发表/出版/首演时间","value":"1927年上映"},{"label":"一句话概括","value":"《柏林：大城市交响曲》用一天城市影像表现魏玛柏林的速度、机器、劳动和消费。"},{"label":"作者/创作者","value":"瓦尔特·鲁特曼导演。"},{"label":"媒介/体裁","value":"无声纪录/实验电影，城市交响曲电影。"},{"label":"主要内容/讲了什么","value":"影片从清晨火车进入柏林开始，按一天时间展开，剪辑街道、工厂、办公室、交通、休闲、橱窗和夜生活，几乎不依赖传统剧情。"},{"label":"核心主张/表达","value":"城市本身成为主角，现代生活被表现为机器节奏、群众运动和视觉碎片的组合。"},{"label":"它出现在什么背景下","value":"魏玛柏林的都市现代性、电影先锋实验和大众交通、广告、工业生活快速发展。"},{"label":"为什么重要","value":"它是城市交响曲电影代表作，也为理解魏玛现代都市视觉经验提供直接入口。"},{"label":"接受与影响","value":"持续影响纪录片、实验电影和城市影像研究。"},{"label":"争议/局限","value":"影片强调形式和节奏，较少直接处理阶级矛盾和政治冲突。"},{"label":"出处","value":"British Film Institute，Berlin: Symphony of a Great City materials；Deutsche Kinemathek，Walter Ruttmann materials。"}],"relationItems":["← 前因：魏玛柏林现代性","← 前因：德国乌发电影公司","→ 后果：城市交响曲电影传统","↔ 相关：魏玛德国大众消费文化","↔ 相关：德布林《柏林亚历山大广场》","✗ 对立/冲突：传统剧情电影","✗ 对立/冲突：城市影像蒙太奇","↔ 同时期参考：《大都会》"],"relations":[{"text":"← 前因：魏玛柏林现代性","id":"card33"},{"text":"← 前因：德国乌发电影公司","id":"card77"},{"text":"↔ 相关：魏玛德国大众消费文化","id":"card87"},{"text":"↔ 相关：德布林《柏林亚历山大广场》","id":"extra69"}],"source":"history","id":"extra73"},{"title":"德国左翼电影《库勒旺佩》","level":"C","type":"作品卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1932年上映","place":"德国柏林及郊区","summary":"《库勒旺佩》以失业、住房和工人体育为题材，是魏玛末期左翼电影的重要作品。","fields":[{"label":"标题","value":"德国左翼电影《库勒旺佩》"},{"label":"分级","value":"C"},{"label":"类型","value":"作品卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1932年上映"},{"label":"地点","value":"德国柏林及郊区"},{"label":"创作时间","value":"1931年—1932年"},{"label":"发表/出版/首演时间","value":"1932年上映"},{"label":"一句话概括","value":"《库勒旺佩》以失业、住房和工人体育为题材，是魏玛末期左翼电影的重要作品。"},{"label":"作者/创作者","value":"斯拉坦·杜多夫导演；贝托尔特·布莱希特 等参与创作。"},{"label":"媒介/体裁","value":"剧情电影、左翼现实主义电影。"},{"label":"主要内容/讲了什么","value":"影片围绕经济危机中失业工人家庭的困境、搬往柏林郊外帐篷营地“库勒旺佩”、青年关系和工人体育活动展开。"},{"label":"核心主张/表达","value":"作品把个人家庭悲剧放进资本主义危机和集体行动语境，强调失业不是个人失败。"},{"label":"它出现在什么背景下","value":"大萧条下德国失业激增、魏玛政治极化、左翼文化组织活跃。"},{"label":"为什么重要","value":"它让魏玛电影不仅有表现主义和都市娱乐，也有直接介入社会危机的政治现实主义。"},{"label":"接受与影响","value":"影片曾遭审查争议，后来成为德国左翼电影史经典。"},{"label":"争议/局限","value":"作品政治立场鲜明，艺术表达与宣传功能之间存在张力。"},{"label":"出处","value":"British Film Institute，Kuhle Wampe materials；Deutsche Kinemathek，Kuhle Wampe materials。"}],"relationItems":["← 前因：德国大萧条失业危机","← 前因：魏玛德国大众体育文化","→ 后果：纳粹文化控制","↔ 相关：布莱希特《三便士歌剧》","↔ 相关：德国自由工会总联盟","✗ 对立/冲突：个人贫困解释","✗ 对立/冲突：阶级社会解释","↔ 同时期参考：《M》"],"relations":[{"text":"← 前因：德国大萧条失业危机","id":"card99"},{"text":"← 前因：魏玛德国大众体育文化","id":"card86"},{"text":"→ 后果：纳粹文化控制","id":"extra113"},{"text":"↔ 相关：布莱希特《三便士歌剧》","id":"extra67"},{"text":"↔ 相关：德国自由工会总联盟","id":"card95"}],"source":"history","id":"extra74"},{"title":"威廉二世《匈奴演说》","level":"C","type":"作品卡","tags":["文化与思想","战争与外交"],"mainTag":"文化与思想","subTag":"战争与外交","timeText":"1900年7月27日演说","place":"不来梅港；面向赴华德国远征军","summary":"威廉二世《匈奴演说》以极端暴力语言鼓动赴华远征军，成为德国帝国主义和军国主义形象的重要文本。","fields":[{"label":"标题","value":"威廉二世《匈奴演说》"},{"label":"分级","value":"C"},{"label":"类型","value":"作品卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"1900年7月27日演说"},{"label":"地点","value":"不来梅港；面向赴华德国远征军"},{"label":"主要国家","value":"德国、中国"},{"label":"一句话概括","value":"威廉二世《匈奴演说》以极端暴力语言鼓动赴华远征军，成为德国帝国主义和军国主义形象的重要文本。"},{"label":"作者/创作者","value":"德皇威廉二世。"},{"label":"媒介/体裁","value":"皇帝公开演说、战争动员讲话。"},{"label":"主要内容/讲了什么","value":"演说面向前往中国参与镇压义和团运动的德国士兵，要求他们严厉报复、展现德国威名，并用“匈奴”意象要求远征军让中国人长期记住德国力量。"},{"label":"核心主张/表达","value":"它把殖民暴力包装成国家荣誉和报复正义，强调无情惩罚、服从和军事威慑。"},{"label":"它出现在什么背景下","value":"1900年义和团运动和德国驻华公使克林德被杀后，德国派军参与八国联军。威廉二世希望借远征展示世界政策和皇帝权威。"},{"label":"为什么重要","value":"这篇演说把威廉时代德国的帝国主义姿态以非常直白的语言表现出来。后来一战中协约国也借“Hun”称呼德国士兵，将其作为德国野蛮形象宣传的一部分。"},{"label":"接受与影响","value":"演说在当时和后世都引发争议，成为研究德国殖民暴力、皇帝个人政治语言和战争宣传的重要材料。"},{"label":"争议/局限","value":"演说有多个记录版本，措辞细节存在差异；但其鼓励残酷惩罚和展示德国威名的核心含义明确。"},{"label":"创作时间","value":"1900年7月27日即席或半即席演说。"},{"label":"发表/出版/首演时间","value":"1900年7月27日在不来梅港发表；随后以报道和记录形式流传。"},{"label":"出处","value":"German History in Documents and Images: The Hun Speech；Deutsches Historisches Museum/LeMO: Hunnenrede；Encyclopaedia Britannica: Boxer Rebellion。"},{"label":"资料备注","value":"本卡作为作品卡处理，重点在演说文本和政治语言，而不是义和团运动全过程。"}],"relationItems":["← 前因：八国联军干预义和团运动","← 前因：德意志帝国世界政策","→ 后果：一战反德宣传","↔ 相关：德国强租胶州湾","↔ 相关：威廉二世"],"relations":[{"text":"← 前因：八国联军干预义和团运动","id":"extra777"},{"text":"← 前因：德意志帝国世界政策","id":"extra635"},{"text":"→ 后果：一战反德宣传","id":"extra960"},{"text":"↔ 相关：德国强租胶州湾","id":"extra773"},{"text":"↔ 相关：威廉二世","id":"extra973"}],"source":"history","id":"extra75"},{"title":"《第三帝国》（莫勒·范登布鲁克）","level":"B","type":"作品卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1923年出版","place":"德国；魏玛共和国思想文化圈","summary":"《第三帝国》把“第三帝国”塑造成反自由主义、反西方的民族主义政治想象，后来被纳粹借用为政权名称。","fields":[{"label":"标题","value":"《第三帝国》（莫勒·范登布鲁克）"},{"label":"分级","value":"B"},{"label":"类型","value":"作品卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1923年出版"},{"label":"地点","value":"德国；魏玛共和国思想文化圈"},{"label":"一句话概括","value":"《第三帝国》把“第三帝国”塑造成反自由主义、反西方的民族主义政治想象，后来被纳粹借用为政权名称。"},{"label":"作者/创作者","value":"阿图尔·莫勒·范登布鲁克。"},{"label":"媒介/体裁","value":"政治思想著作、保守革命派文本。"},{"label":"主要内容/讲了什么","value":"作品批判魏玛自由民主、西方议会政治和凡尔赛秩序，想象一个超越旧帝国和共和国的新德意志国家共同体。"},{"label":"核心主张/表达","value":"德国需要一个新的民族国家形式，既不是帝国旧贵族秩序，也不是自由主义共和国，而是带有民族复兴和权威政治色彩的“第三帝国”。"},{"label":"它出现在什么背景下","value":"1923年德国处在鲁尔占领、恶性通胀、左右翼暴力和国家危机之中，保守革命派试图为反魏玛政治提供新语言。"},{"label":"为什么重要","value":"它没有直接等同于纳粹纲领，但提供了“第三帝国”这一极具动员力的政治名称和想象。理解纳粹为何能吸收更广泛右翼思想资源，这本书很关键。"},{"label":"接受与影响","value":"纳粹后来借用了“第三帝国”称呼，但莫勒本人并不简单等同于纳粹党人。他的文本属于魏玛右翼思想光谱中的保守革命传统。"},{"label":"争议/局限","value":"作品概念宏大而含混，容易被不同右翼力量借用。把它直接说成纳粹主义蓝图会过度简化，但忽视其反民主影响也不准确。"},{"label":"创作时间","value":"一战后至1923年前后。"},{"label":"发表/出版/首演时间","value":"1923年由 Ring-Verlag 出版。"},{"label":"出处","value":"Encyclopaedia Britannica: Arthur Moeller van den Bruck；German History in Documents and Images: Arthur Moeller van den Bruck, The Third Empire；Freie Universität Berlin digital copy: Das dritte Reich。"},{"label":"资料备注","value":"本卡按作品卡处理，重点在文本和政治语言，不把它直接等同为纳粹官方纲领。"}],"relationItems":["← 前因：德国“背后一刀”传说","← 前因：魏玛恶性通货膨胀","→ 后果：纳粹元首国家","↔ 相关：反犹主义政治运动","↔ 相关：德国民族使命论"],"relations":[{"text":"← 前因：德国“背后一刀”传说","id":"extra623"},{"text":"← 前因：魏玛恶性通货膨胀","id":"card90"},{"text":"→ 后果：纳粹元首国家","id":"extra110"},{"text":"↔ 相关：反犹主义政治运动","id":"extra686"},{"text":"↔ 相关：德国民族使命论","id":"extra622"}],"source":"history","id":"extra76"},{"title":"斯宾格勒《西方的没落》","level":"B","type":"作品卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"第一卷1918年出版，第二卷1922年出版","place":"德国；一战失败后的德语思想界","summary":"《西方的没落》用文明生命周期解释欧洲危机，成为魏玛时期悲观文化批判和保守思想的重要文本。","fields":[{"label":"标题","value":"斯宾格勒《西方的没落》"},{"label":"分级","value":"B"},{"label":"类型","value":"作品卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"第一卷1918年出版，第二卷1922年出版"},{"label":"地点","value":"德国；一战失败后的德语思想界"},{"label":"一句话概括","value":"《西方的没落》用文明生命周期解释欧洲危机，成为魏玛时期悲观文化批判和保守思想的重要文本。"},{"label":"作者/创作者","value":"奥斯瓦尔德·斯宾格勒。"},{"label":"媒介/体裁","value":"历史哲学著作、文化批判。"},{"label":"主要内容/讲了什么","value":"作品把各文明视为有生命历程的文化有机体，认为西方文明已从创造性文化阶段走向理性化、都市化和权力政治主导的文明晚期。"},{"label":"核心主张/表达","value":"西方并非线性进步，而是在不可逆的历史周期中走向衰老；自由主义、议会政治和现代都市被描绘为晚期文明症状。"},{"label":"它出现在什么背景下","value":"第一卷在德国战败和革命前后出版，正好击中一战后欧洲危机感、德国失败创伤和魏玛反自由主义情绪。"},{"label":"为什么重要","value":"它不是普通历史书，而是一种时代情绪文本。它帮助塑造魏玛文化悲观主义，也影响保守革命派和反自由主义思想气候。"},{"label":"接受与影响","value":"作品在战后德国和欧洲广泛传播，引发赞同、批判和模仿；它的宏大历史图式影响很大，但学术史学界常批评其类比过度和决定论。"},{"label":"争议/局限","value":"斯宾格勒的文明有机体模型缺乏严格实证基础，容易把复杂历史压缩成宿命论叙事。不能把它直接等同纳粹思想，但它确实滋养了反自由主义文化氛围。"},{"label":"创作时间","value":"一战前后写作，第一卷完成于1918年前后。"},{"label":"发表/出版/首演时间","value":"第一卷1918年出版，第二卷1922年出版。"},{"label":"出处","value":"Encyclopaedia Britannica: Oswald Spengler；Encyclopaedia Britannica: The Decline of the West；German History in Documents and Images: Weimar cultural pessimism materials。"},{"label":"资料备注","value":"本卡按作品卡处理，重点在文本和思想影响，不把斯宾格勒简单归入纳粹思想家。"}],"relationItems":["← 前因：第一次世界大战德国战败","← 前因：德国“背后一刀”传说","→ 后果：《第三帝国》（莫勒·范登布鲁克）","↔ 相关：魏玛德国相对稳定期","↔ 相关：德国民族使命论"],"relations":[{"text":"← 前因：第一次世界大战德国战败","id":"extra926"},{"text":"← 前因：德国“背后一刀”传说","id":"extra623"},{"text":"→ 后果：《第三帝国》（莫勒·范登布鲁克）","id":"extra76"},{"text":"↔ 相关：魏玛德国相对稳定期","id":"card134"},{"text":"↔ 相关：德国民族使命论","id":"extra622"}],"source":"history","id":"extra77"},{"title":"费希特《告德意志民族书》","level":"B","type":"作品卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1807—1808年演讲；1808年出版","place":"被法军占领时期的柏林","summary":"费希特《告德意志民族书》在拿破仑占领背景下呼吁民族教育与精神更新，是德意志民族主义早期经典文本。","fields":[{"label":"标题","value":"费希特《告德意志民族书》"},{"label":"分级","value":"B"},{"label":"类型","value":"作品卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1807—1808年演讲；1808年出版"},{"label":"地点","value":"被法军占领时期的柏林"},{"label":"一句话概括","value":"费希特《告德意志民族书》在拿破仑占领背景下呼吁民族教育与精神更新，是德意志民族主义早期经典文本。"},{"label":"作者/创作者","value":"约翰·戈特利布·费希特。"},{"label":"媒介/体裁","value":"政治哲学演讲集、民族教育论述。"},{"label":"主要内容/讲了什么","value":"作品由费希特在柏林发表的一系列演讲构成，讨论德意志人的语言、教育、道德更新和民族使命，主张通过新的国民教育塑造共同体。"},{"label":"核心主张/表达","value":"民族不是单纯的王朝或领土单位，而应通过语言、教育和精神文化形成共同体；德意志复兴需要从教育和道德自我改造开始。"},{"label":"它出现在什么背景下","value":"普鲁士在耶拿-奥尔施泰特失败后受到法国支配，德意志政治破碎和军事失败刺激知识界寻找民族复兴方案。"},{"label":"为什么重要","value":"它为19世纪德意志民族主义提供了文化和教育语言，也把反拿破仑抵抗同民族共同体想象连接起来。"},{"label":"接受与影响","value":"后来常被视为德意志民族主义思想史关键文本，但不同时代对其解读差异很大。"},{"label":"争议/局限","value":"作品中的民族语言和文化优越论容易被后世民族主义者选择性利用；不能把它简单等同于后来帝国主义或纳粹思想。"},{"label":"出处","value":"German History in Documents and Images, Johann Gottlieb Fichte, Addresses to the German Nation (1807/08)；Open Library, Addresses to the German Nation。"}],"relationItems":["← 前因：普鲁士施泰因-哈登贝格改革","→ 后果：德意志民族主义","↔ 相关：德意志解放战争","↔ 相关：德国体操运动","↔ 同时期参考：法国大革命民族动员"],"relations":[{"text":"← 前因：普鲁士施泰因-哈登贝格改革","id":"extra522"},{"text":"→ 后果：德意志民族主义","id":"extra504"},{"text":"↔ 相关：德意志解放战争","id":"extra523"},{"text":"↔ 相关：德国体操运动","id":"extra517"}],"source":"history","id":"extra78"},{"title":"格林兄弟《格林童话》","level":"B","type":"作品卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1812—1815年初版两卷；1819—1857年多次修订","place":"德意志地区；卡塞尔等地","summary":"《格林童话》把民间故事整理为德语文化经典，连接浪漫主义、民族文化建构和现代儿童文学。","fields":[{"label":"标题","value":"格林兄弟《格林童话》"},{"label":"分级","value":"B"},{"label":"类型","value":"作品卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1812—1815年初版两卷；1819—1857年多次修订"},{"label":"地点","value":"德意志地区；卡塞尔等地"},{"label":"一句话概括","value":"《格林童话》把民间故事整理为德语文化经典，连接浪漫主义、民族文化建构和现代儿童文学。"},{"label":"作者/创作者","value":"雅各布·格林、威廉·格林。"},{"label":"媒介/体裁","value":"民间故事集、文学整理作品、儿童与家庭读物。"},{"label":"主要内容/讲了什么","value":"作品收录并改写大量德语地区及欧洲流传故事，包括灰姑娘、白雪公主、小红帽、汉塞尔与格蕾特等，形成后来世界熟知的童话文本。"},{"label":"核心主张/表达","value":"格林兄弟并非单纯“记录故事”，也在浪漫主义和民族语文学背景下把口头传统整理成可出版、可教育、可代表民族文化的文本。"},{"label":"它出现在什么背景下","value":"拿破仑时代和德意志民族文化觉醒使学者重视语言、民歌、传说和民间故事，认为它们能保存民族精神。"},{"label":"为什么重要","value":"《格林童话》是世界儿童文学和民俗学史上的标志性作品，也说明德国民族文化建设不只靠政治和军队，还靠语言、故事和家庭阅读。"},{"label":"接受与影响","value":"作品不断修订，逐渐从学术民俗材料变成儿童文学经典，并通过翻译进入全球文化。"},{"label":"争议/局限","value":"所谓“民间原貌”经过大量筛选和编辑，性别、暴力、道德训诫和阶级观念也随版本变化而调整。"},{"label":"出处","value":"Britannica, Grimm’s Fairy Tales；Britannica, Brothers Grimm。"}],"relationItems":["← 前因：德意志浪漫主义","→ 后果：德意志民族主义","↔ 相关：德意志“青年德意志”文学运动","↔ 相关：德语民族文化建构","↔ 同时期参考：欧洲浪漫主义民俗采集"],"relations":[{"text":"← 前因：德意志浪漫主义","id":"extra552"},{"text":"→ 后果：德意志民族主义","id":"extra504"},{"text":"↔ 相关：德意志“青年德意志”文学运动","id":"extra503"}],"source":"history","id":"extra79"},{"title":"克劳塞维茨《论战争》","level":"A","type":"作品卡","tags":["战争与外交","文化与思想"],"mainTag":"战争与外交","subTag":"文化与思想","timeText":"1816—1830年主要写作；1832—1837年陆续出版","place":"普鲁士；柏林等地","summary":"克劳塞维茨《论战争》把战争理解为政治延续，是现代战略思想中最有影响力的著作之一。","fields":[{"label":"标题","value":"克劳塞维茨《论战争》"},{"label":"分级","value":"A"},{"label":"类型","value":"作品卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1816—1830年主要写作；1832—1837年陆续出版"},{"label":"地点","value":"普鲁士；柏林等地"},{"label":"一句话概括","value":"克劳塞维茨《论战争》把战争理解为政治延续，是现代战略思想中最有影响力的著作之一。"},{"label":"作者/创作者","value":"卡尔·冯·克劳塞维茨；其妻玛丽·冯·布吕尔在作者去世后整理出版。"},{"label":"媒介/体裁","value":"军事理论著作、战略哲学文本。"},{"label":"主要内容/讲了什么","value":"作品分析战争的政治目的、暴力升级、偶然性、摩擦、军事天才、防御与进攻、人民战争和战略判断，试图建立理解战争本质的理论框架。"},{"label":"核心主张/表达","value":"战争不是孤立的军事技术问题，而是服务政治目的的暴力互动；真实战争充满不确定性、摩擦和心理因素。"},{"label":"它出现在什么背景下","value":"克劳塞维茨经历法国大革命战争、拿破仑战争和普鲁士改革，看到民族动员和大规模战争改变了欧洲战争形态。"},{"label":"为什么重要","value":"它把德国军事思想放入世界战略史核心位置，影响19—20世纪军官教育、总参谋传统和现代国际关系研究。"},{"label":"接受与影响","value":"被各国军校、战略家和政治理论家反复阅读，但不同传统常选择性引用“政治延续”等命题。"},{"label":"争议/局限","value":"作品未完成且结构复杂，后世常把它简化为战争工具理性，忽视其关于不确定性和政治判断的复杂讨论。"},{"label":"出处","value":"Britannica, On War；Britannica, Carl von Clausewitz。"}],"relationItems":["← 前因：拿破仑战争","→ 后果：普鲁士军制改革","↔ 相关：德意志解放战争","↔ 相关：德国施里芬计划","↔ 同时期参考：若米尼《战争艺术概论》"],"relations":[{"text":"← 前因：拿破仑战争","id":"extra918"},{"text":"→ 后果：普鲁士军制改革","id":"extra536"},{"text":"↔ 相关：德意志解放战争","id":"extra523"},{"text":"↔ 相关：德国施里芬计划","id":"extra643"}],"source":"history","id":"extra80"},{"title":"李斯特《德国国民经济学体系》","level":"B","type":"作品卡","tags":["经济与社会","政治与制度"],"mainTag":"经济与社会","subTag":"政治与制度","timeText":"1841年出版","place":"德意志地区；奥格斯堡等出版环境","summary":"李斯特《德国国民经济学体系》主张保护关税和民族经济建设，是理解德国工业化经济民族主义的重要文本。","fields":[{"label":"标题","value":"李斯特《德国国民经济学体系》"},{"label":"分级","value":"B"},{"label":"类型","value":"作品卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1841年出版"},{"label":"地点","value":"德意志地区；奥格斯堡等出版环境"},{"label":"一句话概括","value":"李斯特《德国国民经济学体系》主张保护关税和民族经济建设，是理解德国工业化经济民族主义的重要文本。"},{"label":"作者/创作者","value":"弗里德里希·李斯特。"},{"label":"媒介/体裁","value":"政治经济学著作。"},{"label":"主要内容/讲了什么","value":"作品批评古典自由贸易理论忽视国家发展阶段，主张落后或后发国家可通过关税、铁路、教育和国家政策培养本国生产力。"},{"label":"核心主张/表达","value":"财富不只是眼前交换利益，国家应培养“生产力”；自由贸易适合强者，后发国家需要先建立工业和市场基础。"},{"label":"它出现在什么背景下","value":"德意志邦国经济分裂、关税同盟推进、铁路建设和英国工业优势共同促成德意志经济民族主义论述。"},{"label":"为什么重要","value":"它解释德国统一前后为何重视关税同盟、铁路和国家支持工业，也为后发工业化国家提供了重要理论资源。"},{"label":"接受与影响","value":"影响德意志保护主义、发展经济学和后发国家工业政策讨论，也常被拿来与英国自由贸易思想对照。"},{"label":"争议/局限","value":"保护主义可能保护低效率利益集团，也可能把经济发展过度民族国家化，忽视工人、殖民和国际分工问题。"},{"label":"出处","value":"Britannica, Friedrich List；The Online Library of Liberty, The National System of Political Economy。"}],"relationItems":["← 前因：德意志关税同盟（Zollverein）","→ 后果：德意志帝国保护关税政策","↔ 相关：弗里德里希·李斯特","↔ 相关：德国铁路扩张","↔ 同时期参考：英国自由贸易运动"],"relations":[{"text":"← 前因：德意志关税同盟（Zollverein）","id":"extra486"},{"text":"→ 后果：德意志帝国保护关税政策","id":"extra630"},{"text":"↔ 相关：弗里德里希·李斯特","id":"extra506"}],"source":"history","id":"extra81"},{"title":"马克思恩格斯《德意志意识形态》","level":"B","type":"作品卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1845—1846年写作；1932年首次完整出版","place":"布鲁塞尔等地；德国思想界为批判对象","summary":"《德意志意识形态》集中批判青年黑格尔派，并形成历史唯物主义的重要早期表达。","fields":[{"label":"标题","value":"马克思恩格斯《德意志意识形态》"},{"label":"分级","value":"B"},{"label":"类型","value":"作品卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1845—1846年写作；1932年首次完整出版"},{"label":"地点","value":"布鲁塞尔等地；德国思想界为批判对象"},{"label":"一句话概括","value":"《德意志意识形态》集中批判青年黑格尔派，并形成历史唯物主义的重要早期表达。"},{"label":"作者/创作者","value":"卡尔·马克思、弗里德里希·恩格斯。"},{"label":"媒介/体裁","value":"哲学批判手稿、社会理论文本。"},{"label":"主要内容/讲了什么","value":"作品批评德国哲学把观念看作历史动力，强调人们的物质生产、社会关系和现实生活过程才是理解历史和意识形态的基础。"},{"label":"核心主张/表达","value":"意识不是脱离生活的独立力量，社会存在、生产方式和阶级关系塑造思想；所谓“意识形态”常掩盖现实社会关系。"},{"label":"它出现在什么背景下","value":"1840年代青年黑格尔派、社会主义运动和德国哲学争论交织，马克思与恩格斯正从哲学批判转向政治经济学和共产主义理论。"},{"label":"为什么重要","value":"它虽在作者生前未出版，却成为20世纪理解马克思主义、意识形态理论和历史唯物主义的重要文本。"},{"label":"接受与影响","value":"1932年完整出版后影响马克思主义哲学、社会学和思想史研究，也被不同学派反复重读。"},{"label":"争议/局限","value":"作品是未完成手稿，编辑史复杂；后世把其中观点系统化时，容易忽略文本的草稿性和论战语境。"},{"label":"出处","value":"Marxists Internet Archive, The German Ideology；Britannica, Communism: Marxian communism。"}],"relationItems":["← 前因：青年黑格尔派","→ 后果：马克思恩格斯《共产党宣言》","↔ 相关：卡尔·马克思","↔ 相关：弗里德里希·恩格斯","↔ 同时期参考：欧洲社会主义思想兴起"],"relations":[{"text":"→ 后果：马克思恩格斯《共产党宣言》","id":"extra61"},{"text":"↔ 相关：卡尔·马克思","id":"extra911"},{"text":"↔ 相关：弗里德里希·恩格斯","id":"extra912"}],"source":"history","id":"extra82"},{"title":"《资本论》第一卷","level":"S","type":"作品卡","tags":["经济与社会","文化与思想"],"mainTag":"经济与社会","subTag":"文化与思想","timeText":"1867年出版","place":"汉堡出版；伦敦写作环境","summary":"《资本论》第一卷系统分析资本主义生产、商品、剩余价值和资本积累，是世界思想史和经济史坐标级作品。","fields":[{"label":"标题","value":"《资本论》第一卷"},{"label":"分级","value":"S"},{"label":"类型","value":"作品卡"},{"label":"主标签","value":"经济与社会"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1867年出版"},{"label":"地点","value":"汉堡出版；伦敦写作环境"},{"label":"一句话概括","value":"《资本论》第一卷系统分析资本主义生产、商品、剩余价值和资本积累，是世界思想史和经济史坐标级作品。"},{"label":"作者/创作者","value":"卡尔·马克思。"},{"label":"媒介/体裁","value":"政治经济学批判著作。"},{"label":"主要内容/讲了什么","value":"第一卷从商品、价值、货币、资本、劳动力商品和剩余价值出发，分析资本主义生产过程、工作日、机器大工业、原始积累和资本积累机制。"},{"label":"核心主张/表达","value":"资本主义不是自然秩序，而是一套历史形成的社会关系；利润背后是劳动力被组织进生产过程后的剩余价值生产。"},{"label":"它出现在什么背景下","value":"19世纪工业资本主义扩张、英国工厂制度、工人运动和古典政治经济学争论构成作品背景。"},{"label":"为什么重要","value":"它超出德国史范围，成为全球社会主义运动、劳工政治、经济学批判和现代社会理论的基础文本之一。"},{"label":"接受与影响","value":"第一卷在马克思生前出版，后两卷由恩格斯整理出版；它深刻影响社会主义第二国际、俄国革命、中国革命和20世纪全球左翼思想。"},{"label":"争议/局限","value":"不同学派对价值理论、历史决定论和政治实践的解读分歧很大；作品影响巨大，也常被政治运动选择性使用。"},{"label":"出处","value":"Britannica, Das Kapital；Marxists Internet Archive, Capital Volume One。"}],"relationItems":["← 前因：马克思恩格斯《德意志意识形态》","→ 后果：德国社会民主党（SPD）","↔ 相关：马克思恩格斯《共产党宣言》","↔ 相关：德国社民党《爱尔福特纲领》","↔ 同时期参考：英国工业革命"],"relations":[{"text":"← 前因：马克思恩格斯《德意志意识形态》","id":"extra82"},{"text":"→ 后果：德国社会民主党（SPD）","id":"extra628"},{"text":"↔ 相关：马克思恩格斯《共产党宣言》","id":"extra61"},{"text":"↔ 相关：德国社民党《爱尔福特纲领》","id":"extra696"}],"source":"history","id":"extra83"},{"title":"瓦格纳《尼伯龙根的指环》","level":"B","type":"作品卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1848年构思；1876年完整首演","place":"巴伐利亚拜罗伊特","summary":"瓦格纳《尼伯龙根的指环》把神话、音乐戏剧和民族文化想象结合，是19世纪德国音乐与文化政治的巨型作品。","fields":[{"label":"标题","value":"瓦格纳《尼伯龙根的指环》"},{"label":"分级","value":"B"},{"label":"类型","value":"作品卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1848年构思；1876年完整首演"},{"label":"地点","value":"巴伐利亚拜罗伊特"},{"label":"一句话概括","value":"瓦格纳《尼伯龙根的指环》把神话、音乐戏剧和民族文化想象结合，是19世纪德国音乐与文化政治的巨型作品。"},{"label":"作者/创作者","value":"理查德·瓦格纳。"},{"label":"媒介/体裁","value":"四联音乐剧/歌剧循环。"},{"label":"主要内容/讲了什么","value":"作品由《莱茵的黄金》《女武神》《齐格弗里德》《诸神的黄昏》组成，以莱茵黄金、权力戒指、诸神、英雄和世界毁灭构成庞大神话叙事。"},{"label":"核心主张/表达","value":"作品通过主导动机、连续音乐和总体艺术作品理念，把音乐、诗歌、舞台和神话整合为一种现代民族文化仪式。"},{"label":"它出现在什么背景下","value":"1848革命、德意志民族主义、浪漫主义中世纪想象和瓦格纳个人艺术改革理念共同塑造了作品。"},{"label":"为什么重要","value":"它不仅是音乐史杰作，也说明德国民族文化身份如何通过神话、剧场和艺术节制度被制造和体验。"},{"label":"接受与影响","value":"1876年拜罗伊特首演后，瓦格纳和拜罗伊特成为欧洲艺术和德国文化民族主义的重要象征。"},{"label":"争议/局限","value":"瓦格纳的反犹主义和作品后来的民族主义、纳粹化接受使其文化遗产高度复杂，不能只以纯艺术理解。"},{"label":"出处","value":"Britannica, Der Ring des Nibelungen；Bayreuth Festival historical summaries。"}],"relationItems":["← 前因：德意志浪漫主义","→ 后果：拜罗伊特音乐节","↔ 相关：德意志民族主义","↔ 相关：德国青年风格（Jugendstil）","↔ 同时期参考：意大利民族歌剧传统"],"relations":[{"text":"← 前因：德意志浪漫主义","id":"extra552"},{"text":"↔ 相关：德意志民族主义","id":"extra504"},{"text":"↔ 相关：德国青年风格（Jugendstil）","id":"extra729"}],"source":"history","id":"extra84"},{"title":"托马斯·曼《布登勃洛克一家》","level":"C","type":"作品卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1901年出版","place":"德国吕贝克为主要原型；慕尼黑写作/出版环境相关","summary":"《布登勃洛克一家》通过一个商人家族衰落写出德意志市民阶层、艺术气质和现代性焦虑。","fields":[{"label":"标题","value":"托马斯·曼《布登勃洛克一家》"},{"label":"分级","value":"C"},{"label":"类型","value":"作品卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1901年出版"},{"label":"地点","value":"德国吕贝克为主要原型；慕尼黑写作/出版环境相关"},{"label":"一句话概括","value":"《布登勃洛克一家》通过一个商人家族衰落写出德意志市民阶层、艺术气质和现代性焦虑。"},{"label":"作者/创作者","value":"托马斯·曼。"},{"label":"媒介/体裁","value":"长篇小说、家族小说、现实主义/现代主义过渡作品。"},{"label":"主要内容/讲了什么","value":"小说描写北德商人布登勃洛克家族数代人的商业、婚姻、教育和精神生活，展示家族财富和生命力逐渐衰退的过程。"},{"label":"核心主张/表达","value":"作品把市民阶层的纪律、商业伦理和艺术敏感之间的冲突写成家族命运，呈现现代德国资产阶级的内在张力。"},{"label":"它出现在什么背景下","value":"德意志帝国经济繁荣、城市资产阶级稳固，但文学中已出现对市民秩序、衰落和个人精神危机的反思。"},{"label":"为什么重要","value":"它是理解帝国德国市民文化的重要文学入口，也使托马斯·曼成为德语文学核心人物。"},{"label":"接受与影响","value":"作品为托马斯·曼获得1929年诺贝尔文学奖提供了关键声誉基础。"},{"label":"争议/局限","value":"小说主要聚焦资产阶级家庭经验，对工人阶级、殖民和帝国政治的直接呈现有限。"},{"label":"出处","value":"Britannica, Buddenbrooks；NobelPrize.org, Thomas Mann Facts。"}],"relationItems":["← 前因：德意志帝国市民阶层","→ 后果：托马斯·曼《魔山》","↔ 相关：魏玛德国大众消费文化","↔ 相关：德意志帝国女性大学入学开放","↔ 同时期参考：法国自然主义小说"],"relations":[{"text":"→ 后果：托马斯·曼《魔山》","id":"extra86"},{"text":"↔ 相关：魏玛德国大众消费文化","id":"card87"},{"text":"↔ 相关：德意志帝国女性大学入学开放","id":"extra823"}],"source":"history","id":"extra85"},{"title":"托马斯·曼《魔山》","level":"B","type":"作品卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1924年出版","place":"瑞士达沃斯疗养院为故事空间；德国魏玛时期文化背景","summary":"《魔山》把疗养院写成一战前欧洲精神危机的缩影，是魏玛时期思想小说的重要作品。","fields":[{"label":"标题","value":"托马斯·曼《魔山》"},{"label":"分级","value":"B"},{"label":"类型","value":"作品卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1924年出版"},{"label":"地点","value":"瑞士达沃斯疗养院为故事空间；德国魏玛时期文化背景"},{"label":"一句话概括","value":"《魔山》把疗养院写成一战前欧洲精神危机的缩影，是魏玛时期思想小说的重要作品。"},{"label":"作者/创作者","value":"托马斯·曼。"},{"label":"媒介/体裁","value":"长篇小说、思想小说、现代主义文学。"},{"label":"主要内容/讲了什么","value":"小说讲述年轻工程师汉斯·卡斯托普到瑞士疗养院探望表兄，却长期滞留山中，在病人与知识分子争论中接触死亡、时间、自由主义、激进主义和欧洲危机。"},{"label":"核心主张/表达","value":"疗养院像一个隔离的欧洲精神实验室，人物辩论折射一战前后欧洲思想、疾病、死亡和政治选择的复杂性。"},{"label":"它出现在什么背景下","value":"作品始于一战前构想，战后完成；魏玛共和国的政治危机和托马斯·曼从保守民族主义转向共和立场影响了作品方向。"},{"label":"为什么重要","value":"它把魏玛文化的思想焦虑、病态现代性和欧洲危机压缩进文学空间，是理解战间期德语文学的重要文本。"},{"label":"接受与影响","value":"被视为20世纪德语文学经典，常与一战前欧洲文明危机和魏玛思想史一起解读。"},{"label":"争议/局限","value":"作品高度知识化、象征化，普通社会现实和具体政治行动被转化为漫长的思想辩论。"},{"label":"出处","value":"Britannica, The Magic Mountain；Britannica, Thomas Mann。"}],"relationItems":["← 前因：托马斯·曼《布登勃洛克一家》","→ 后果：魏玛共和国文化危机","↔ 相关：魏玛德国性改革运动","↔ 相关：罗伯特·科赫发现结核杆菌","↔ 同时期参考：普鲁斯特《追忆似水年华》"],"relations":[{"text":"← 前因：托马斯·曼《布登勃洛克一家》","id":"extra85"},{"text":"↔ 相关：魏玛德国性改革运动","id":"card85"},{"text":"↔ 相关：罗伯特·科赫发现结核杆菌","id":"extra811"}],"source":"history","id":"extra86"},{"title":"格罗皮乌斯《包豪斯宣言》","level":"B","type":"作品卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"1919年发布","place":"魏玛","summary":"《包豪斯宣言》提出把建筑、工艺和艺术重新结合，成为现代设计教育和魏玛文化改革的重要文本。","fields":[{"label":"标题","value":"格罗皮乌斯《包豪斯宣言》"},{"label":"分级","value":"B"},{"label":"类型","value":"作品卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"1919年发布"},{"label":"地点","value":"魏玛"},{"label":"一句话概括","value":"《包豪斯宣言》提出把建筑、工艺和艺术重新结合，成为现代设计教育和魏玛文化改革的重要文本。"},{"label":"作者/创作者","value":"瓦尔特·格罗皮乌斯；封面木刻由莱昂内尔·费宁格创作。"},{"label":"媒介/体裁","value":"艺术学校纲领、宣言、设计教育文本。"},{"label":"主要内容/讲了什么","value":"宣言呼吁艺术家和工匠共同建设未来建筑，反对学院艺术与手工艺分离，强调工作坊训练和建筑作为综合艺术目标。"},{"label":"核心主张/表达","value":"艺术不应只是博物馆和学院的孤立对象，而要回到生产、工艺、建筑和集体劳动中，形成现代生活的新形式。"},{"label":"它出现在什么背景下","value":"一战失败和魏玛革命后，德国艺术教育、工艺改革和社会重建想象交织，包豪斯在魏玛成立。"},{"label":"为什么重要","value":"它是包豪斯教育理念的起点之一，解释现代设计为何同时关心美学、工业生产、日常生活和社会改革。"},{"label":"接受与影响","value":"魏玛包豪斯迁往德绍后影响扩散，后被纳粹关闭，但其设计教育模式和现代主义风格影响全球。"},{"label":"争议/局限","value":"早期宣言带有手工艺和中世纪行会理想，后来包豪斯转向工业设计，两者之间存在张力。"},{"label":"出处","value":"Bauhaus-Archiv, 14 Years of Bauhaus；Goethe-Institut, Walter Gropius: The Bauhaus Manifesto of 1919。"}],"relationItems":["← 前因：德意志制造联盟","→ 后果：魏玛包豪斯迁往德绍","↔ 相关：新法兰克福住房项目","↔ 相关：新法兰克福“法兰克福厨房”","↔ 同时期参考：俄国构成主义"],"relations":[{"text":"← 前因：德意志制造联盟","id":"extra724"},{"text":"→ 后果：魏玛包豪斯迁往德绍","id":"card176"},{"text":"↔ 相关：新法兰克福住房项目","id":"card82"},{"text":"↔ 相关：新法兰克福“法兰克福厨房”","id":"card84"}],"source":"history","id":"extra87"},{"title":"莱妮·里芬施塔尔《意志的胜利》","level":"B","type":"作品卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1934年拍摄；1935年上映","place":"纽伦堡纳粹党大会","summary":"《意志的胜利》把1934年纳粹党大会拍成宏大政治仪式，是电影史上最臭名昭著的宣传片之一。","fields":[{"label":"标题","value":"莱妮·里芬施塔尔《意志的胜利》"},{"label":"分级","value":"B"},{"label":"类型","value":"作品卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1934年拍摄；1935年上映"},{"label":"地点","value":"纽伦堡纳粹党大会"},{"label":"一句话概括","value":"《意志的胜利》把1934年纳粹党大会拍成宏大政治仪式，是电影史上最臭名昭著的宣传片之一。"},{"label":"作者/创作者","value":"莱妮·里芬施塔尔导演、剪辑并参与制作。"},{"label":"媒介/体裁","value":"纪录/宣传电影。"},{"label":"主要内容/讲了什么","value":"影片记录并高度编排希特勒抵达纽伦堡、党卫队和冲锋队队列、群众集会、青年与军队展示、领袖演说和党大会仪式。"},{"label":"核心主张/表达","value":"影片把希特勒塑造成超越日常政治的救世领袖，把纳粹党表现为秩序、青春、团结和民族复兴的视觉整体。"},{"label":"它出现在什么背景下","value":"长刀之夜后，纳粹政权需要展示党和国家重新统一、希特勒权威稳固，纽伦堡党大会成为宣传舞台。"},{"label":"为什么重要","value":"它是理解纳粹宣传美学的关键作品，说明电影技术、群众编排和政治神话如何共同制造权力景观。"},{"label":"接受与影响","value":"影片因摄影、剪辑和场面调度在电影史上常被讨论，但其艺术成就无法与纳粹宣传功能分开评价。"},{"label":"争议/局限","value":"它不是中立纪录片，而是为独裁政权服务的政治影像；战后里芬施塔尔试图淡化责任，长期引发争议。"},{"label":"出处","value":"Britannica, Triumph of the Will；Routledge Encyclopedia of Modernism, Triumph of the Will (1935)。"}],"relationItems":["← 前因：纳粹宣传机器","→ 后果：1936年柏林奥运会","↔ 相关：约瑟夫·戈培尔","↔ 相关：纳粹德国帝国文化院","↔ 同时期参考：苏联政治宣传电影"],"relations":[{"text":"← 前因：纳粹宣传机器","id":"extra94"},{"text":"→ 后果：1936年柏林奥运会","id":"extra129"},{"text":"↔ 相关：约瑟夫·戈培尔","id":"card49"},{"text":"↔ 相关：纳粹德国帝国文化院","id":"extra125"}],"source":"history","id":"extra88"},{"title":"康德《纯粹理性批判》","level":"S","type":"作品卡","tags":["文化与思想","政治与制度"],"mainTag":"文化与思想","subTag":"政治与制度","timeText":"1781年初版；1787年第二版","place":"柯尼斯堡","summary":"康德《纯粹理性批判》重塑现代哲学对知识、经验和理性的理解，是世界思想史坐标级作品。","fields":[{"label":"标题","value":"康德《纯粹理性批判》"},{"label":"分级","value":"S"},{"label":"类型","value":"作品卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"政治与制度"},{"label":"时间","value":"1781年初版；1787年第二版"},{"label":"地点","value":"柯尼斯堡"},{"label":"一句话概括","value":"康德《纯粹理性批判》重塑现代哲学对知识、经验和理性的理解，是世界思想史坐标级作品。"},{"label":"作者/创作者","value":"伊曼努尔·康德。"},{"label":"媒介/体裁","value":"哲学著作，认识论和形而上学批判。"},{"label":"主要内容/讲了什么","value":"作品分析人类知识如何可能，区分感性、知性和理性，讨论先验条件、时间空间、范畴和传统形而上学的限度。"},{"label":"核心主张/表达","value":"人并不是被动接收世界，经验知识依赖主体的认识结构；理性有能力也有限度，不能无限制地证明灵魂、上帝和世界整体等对象。"},{"label":"它出现在什么背景下","value":"18世纪启蒙运动、牛顿科学、休谟怀疑论和德国大学哲学共同构成康德批判哲学背景。"},{"label":"为什么重要","value":"它改变欧洲哲学方向，为德国古典哲学、现代认识论、伦理学和政治哲学奠定基础。"},{"label":"接受与影响","value":"作品影响费希特、谢林、黑格尔、叔本华和后来的新康德主义、现象学和分析哲学。"},{"label":"争议/局限","value":"文本高度抽象难读，后世对其先验哲学、物自身和形而上学限度的解释分歧极大。"},{"label":"出处","value":"Britannica, Critique of Pure Reason；Stanford Encyclopedia of Philosophy, Kant’s Critique of Pure Reason。"}],"relationItems":["← 前因：德意志启蒙运动","→ 后果：德国古典哲学","↔ 相关：魏玛古典主义","↔ 相关：费希特《告德意志民族书》","↔ 同时期参考：休谟《人性论》"],"relations":[{"text":"← 前因：德意志启蒙运动","id":"extra317"},{"text":"↔ 相关：魏玛古典主义","id":"extra342"},{"text":"↔ 相关：费希特《告德意志民族书》","id":"extra78"}],"source":"history","id":"extra89"},{"title":"歌德《浮士德》","level":"S","type":"作品卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"第一部1808年出版；第二部1832年出版","place":"魏玛；德语文学世界","summary":"歌德《浮士德》以求知、欲望、交易和现代人的不满足为核心，是世界文学坐标级作品。","fields":[{"label":"标题","value":"歌德《浮士德》"},{"label":"分级","value":"S"},{"label":"类型","value":"作品卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"第一部1808年出版；第二部1832年出版"},{"label":"地点","value":"魏玛；德语文学世界"},{"label":"一句话概括","value":"歌德《浮士德》以求知、欲望、交易和现代人的不满足为核心，是世界文学坐标级作品。"},{"label":"作者/创作者","value":"约翰·沃尔夫冈·冯·歌德。"},{"label":"媒介/体裁","value":"诗剧、哲学戏剧、世界文学经典。"},{"label":"主要内容/讲了什么","value":"作品讲述学者浮士德对知识和人生感到不满足，与魔鬼梅菲斯特订约，经历爱情悲剧、政治经济幻想、古典世界和现代开发等多重场景。"},{"label":"核心主张/表达","value":"作品把现代人的无尽追求、道德风险、知识欲、资本和开发冲动写成宏大戏剧，既赞美行动，也揭示代价。"},{"label":"它出现在什么背景下","value":"德意志启蒙、狂飙突进、魏玛古典主义、法国大革命和早期现代化经验共同塑造歌德长期创作。"},{"label":"为什么重要","value":"《浮士德》超出德国文学范围，是现代性、知识欲和人类自我超越问题的世界文学经典。"},{"label":"接受与影响","value":"作品影响欧洲戏剧、歌剧、哲学、文学批评和现代性研究，浮士德形象成为现代人隐喻。"},{"label":"争议/局限","value":"作品规模宏大、象征复杂，第二部尤其难读；对女性悲剧、殖民和开发主题的现代解读存在争议。"},{"label":"出处","value":"Britannica, Faust by Goethe；Goethe-Institut / Klassik Stiftung Weimar, Goethe Faust materials。"}],"relationItems":["← 前因：魏玛古典主义","→ 后果：德意志浪漫主义","↔ 相关：德意志启蒙运动","↔ 相关：康德《纯粹理性批判》","↔ 同时期参考：弥尔顿《失乐园》"],"relations":[{"text":"← 前因：魏玛古典主义","id":"extra342"},{"text":"→ 后果：德意志浪漫主义","id":"extra552"},{"text":"↔ 相关：德意志启蒙运动","id":"extra317"},{"text":"↔ 相关：康德《纯粹理性批判》","id":"extra89"}],"source":"history","id":"extra90"},{"title":"塔西佗《日耳曼尼亚》","level":"B","type":"作品卡","tags":["文化与思想"],"mainTag":"文化与思想","subTag":"","timeText":"约公元98年","place":"罗马帝国","summary":"塔西佗描写罗马边疆外日耳曼诸部落，后来被欧洲学者和德国民族主义反复重新解释。","fields":[{"label":"标题","value":"塔西佗《日耳曼尼亚》"},{"label":"分级","value":"B"},{"label":"类型","value":"作品卡"},{"label":"主标签","value":"文化与思想"},{"label":"时间","value":"约公元98年"},{"label":"地点","value":"罗马帝国"},{"label":"一句话概括","value":"塔西佗描写罗马边疆外日耳曼诸部落，后来被欧洲学者和德国民族主义反复重新解释。"},{"label":"作者/创作者","value":"塔西佗。"},{"label":"媒介/体裁","value":"拉丁文民族志和政治道德评论作品。"},{"label":"主要内容/讲了什么","value":"作品描述罗马帝国北方边疆外日耳曼人的地理、习俗、战争、家庭和政治组织，并把这些描述与罗马社会的道德批评联系起来。"},{"label":"核心主张/表达","value":"塔西佗并非在写现代德国史，而是借边疆民族形象反照罗马社会；其文本后来却被当作“日耳曼性格”的古典来源。"},{"label":"它出现在什么背景下","value":"罗马帝国在莱茵-多瑙边疆与日耳曼诸部落长期接触，罗马精英也常用边疆民族来讨论帝国道德和政治问题。"},{"label":"为什么重要","value":"它是后世理解“日耳曼”概念的关键文本之一。文艺复兴和近代民族主义时期，德国学者重新发现并利用它建构古老民族身份。"},{"label":"接受与影响","value":"中世纪影响有限，15世纪后随着人文主义和印刷传播重新流行，19世纪德国民族主义尤其重视该文本。"},{"label":"争议/局限","value":"它带有罗马作者的修辞目的和二手信息，不能当作日耳曼社会的直接客观记录。"},{"label":"创作时间","value":"约公元98年。"},{"label":"发表/出版/首演时间","value":"古罗马时期以手抄本传播，15世纪后在欧洲人文主义语境中重新传播。"},{"label":"出处","value":"Britannica, Tacitus；Britannica, Germania；Perseus Digital Library, Tacitus Germania。"}],"relationItems":["← 前因：罗马帝国莱茵-多瑙边疆","↔ 相关：条顿堡森林战役（9年）","↔ 相关：德意志人文主义","↔ 同时期参考：罗马帝国"],"relations":[{"text":"← 前因：罗马帝国莱茵-多瑙边疆","id":"extra391"},{"text":"↔ 相关：条顿堡森林战役（9年）","id":"extra392"},{"text":"↔ 相关：德意志人文主义","id":"extra412"},{"text":"↔ 同时期参考：罗马帝国","id":"extra871"}],"source":"history","id":"extra91"}],"proverbCards":[{"title":"“Nach Canossa gehen wir nicht”","level":"B","type":"俗语卡","tags":["政治与制度","文化与思想"],"mainTag":"政治与制度","subTag":"文化与思想","timeText":"1872年5月14日后流行","place":"德国。","summary":"俾斯麦用“Nach Canossa gehen wir nicht”表达新帝国不会向教皇权威低头，成为德意志帝国文化斗争时期国家权力对抗天主教会的标志性话语。","fields":[{"label":"标题","value":"“Nach Canossa gehen wir nicht”"},{"label":"分级","value":"B"},{"label":"类型","value":"俗语卡"},{"label":"主标签","value":"政治与制度"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1872年5月14日后流行"},{"label":"主要国家","value":"德国、梵蒂冈"},{"label":"一句话概括","value":"俾斯麦用“Nach Canossa gehen wir nicht”表达新帝国不会向教皇权威低头，成为德意志帝国文化斗争时期国家权力对抗天主教会的标志性话语。"},{"label":"原文/标准说法","value":"Nach Canossa gehen wir nicht（我们不去卡诺莎）"},{"label":"出现时间","value":"1872年俾斯麦在帝国议会关于教会与国家关系的辩论中使用。"},{"label":"流行时间","value":"十九世纪七十年代德意志帝国文化斗争时期广泛流行，后成为德语政治语言中表示“不屈服”的典故。"},{"label":"地区","value":"德国。"},{"label":"它在说什么（字面+引申）","value":"字面上引用中世纪皇帝亨利四世赴卡诺莎向教皇忏悔的典故；引申为现代德国国家不会向罗马教廷作政治性屈服。"},{"label":"为什么会出现","value":"德意志帝国成立后，俾斯麦担心德国中央党和罗马教廷削弱新帝国的国家整合，因而发动限制天主教会影响力的德意志帝国文化斗争。"},{"label":"它反映了什么","value":"它反映了新帝国的国家建构焦虑：统一后的德国不仅要整合邦国，也要决定宗教权威、政治忠诚和国家主权的边界。"},{"label":"类似变体","value":"中文常译作“我们不到卡诺莎去”。"},{"label":"关联事件/概念","value":"德意志帝国文化斗争、德国中央党、德意志帝国成立、德意志帝国俾斯麦时代"},{"label":"出处","value":"Deutsches Historisches Museum/LeMO: Kulturkampf；German History Documents and Images: Bismarck and the Kulturkampf；Encyclopaedia Britannica: Kulturkampf。"},{"label":"资料备注","value":"该表达的力量来自中世纪“亨利四世卡诺莎之行”的历史典故，因此后续可单独补“亨利四世卡诺莎之行”世界史卡。"}],"relationItems":["← 前因：德意志帝国成立","→ 后果：德意志帝国文化斗争","↔ 相关：奥托·冯·俾斯麦","↔ 相关：德国中央党"],"relations":[{"text":"← 前因：德意志帝国成立","id":"extra621"},{"text":"→ 后果：德意志帝国文化斗争","id":"extra626"},{"text":"↔ 相关：奥托·冯·俾斯麦","id":"extra924"},{"text":"↔ 相关：德国中央党","id":"extra673"}],"source":"proverb","id":"proverb1"},{"title":"“Ein Platz an der Sonne”","level":"B","type":"俗语卡","tags":["战争与外交","文化与思想"],"mainTag":"战争与外交","subTag":"文化与思想","timeText":"1897年后流行","place":"德国及欧洲列强外交语境。","summary":"这句“Ein Platz an der Sonne”把德国的海外扩张包装成应得权利，成为威廉时代德意志帝国世界政策和帝国主义焦虑的经典表达。","fields":[{"label":"标题","value":"“Ein Platz an der Sonne”"},{"label":"分级","value":"B"},{"label":"类型","value":"俗语卡"},{"label":"主标签","value":"战争与外交"},{"label":"副标签","value":"文化与思想"},{"label":"时间","value":"1897年后流行"},{"label":"主要国家","value":"德国、英国、法国"},{"label":"一句话概括","value":"这句“Ein Platz an der Sonne”把德国的海外扩张包装成应得权利，成为威廉时代德意志帝国世界政策和帝国主义焦虑的经典表达。"},{"label":"原文/标准说法","value":"Ein Platz an der Sonne（阳光下的土地）"},{"label":"出现时间","value":"1897年，外交国务秘书伯恩哈德·冯·比洛在帝国议会讲话中使用。"},{"label":"流行时间","value":"十九世纪末至一战前，尤其与德国德意志帝国世界政策、海军扩张和殖民竞争联系在一起。"},{"label":"地区","value":"德国及欧洲列强外交语境。"},{"label":"它在说什么（字面+引申）","value":"字面是要求在阳光下占有一席之地；引申为德国作为新兴强国，也应获得海外殖民地、海上力量和世界政治发言权。"},{"label":"为什么会出现","value":"德意志帝国统一较晚，海外殖民和海权扩张起步落后于英国、法国等老牌帝国。威廉二世时期德国转向更积极的德意志帝国世界政策，需要一种正当化扩张的公共语言。"},{"label":"它反映了什么","value":"它反映了德国强国地位与世界资源分配之间的紧张，也反映出帝国主义时代列强把殖民扩张说成“国家应得权利”的共同逻辑。"},{"label":"类似变体","value":"常与“德意志帝国世界政策”“海军主义”“殖民政策”并置使用。"},{"label":"关联事件/概念","value":"德意志帝国世界政策、德意志帝国海军扩张、殖民帝国主义"},{"label":"出处","value":"German History Documents and Images: Bernhard von Bülow and Weltpolitik；Deutsches Historisches Museum/LeMO: Weltpolitik；Encyclopaedia Britannica: William II。"},{"label":"资料备注","value":"该表达常被概括为德国德意志帝国世界政策的口号，但它本身来自具体的1897年议会演说语境。"}],"relationItems":["← 前因：德意志帝国成立","→ 后果：德意志帝国海军扩张","→ 后果：第一次世界大战爆发","↔ 相关：威廉二世","↔ 相关：伯恩哈德·冯·比洛"],"relations":[{"text":"← 前因：德意志帝国成立","id":"extra621"},{"text":"→ 后果：德意志帝国海军扩张","id":"extra636"},{"text":"→ 后果：第一次世界大战爆发","id":"extra925"},{"text":"↔ 相关：威廉二世","id":"extra973"},{"text":"↔ 相关：伯恩哈德·冯·比洛","id":"extra778"}],"source":"proverb","id":"proverb2"},{"title":"“08/15”","level":"C","type":"俗语卡","tags":["文化与思想","战争与外交"],"mainTag":"文化与思想","subTag":"战争与外交","timeText":"一战时期从军队语境中形成；二十世纪继续流行，沿用至今","place":"德国及德语区。","summary":"“08/15”原与德军机枪型号相关，后来变成德语里表示普通、平庸、没特色的常用说法。","fields":[{"label":"标题","value":"“08/15”"},{"label":"分级","value":"C"},{"label":"类型","value":"俗语卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"一战时期从军队语境中形成；二十世纪继续流行，沿用至今"},{"label":"主要国家","value":"德国"},{"label":"一句话概括","value":"“08/15”原与德军机枪型号相关，后来变成德语里表示普通、平庸、没特色的常用说法。"},{"label":"原文/标准说法（原文+中文翻译）","value":"08/15 / nullachtfünfzehn，中文可译作“普普通通”“很一般”“没什么特别”。"},{"label":"出现时间","value":"一战时期的德国军队语境。"},{"label":"流行时间","value":"二十世纪以来长期流行，现代德语中仍常见。"},{"label":"地区","value":"德国及德语区。"},{"label":"它在说什么（字面+引申）","value":"字面上是数字“零八一五”，与MG 08/15机枪型号有关；引申为标准化、重复、乏味、没有新意或质量一般。"},{"label":"为什么会出现","value":"常见解释认为士兵长期接受与MG 08/15相关的重复训练，使“08/15”逐渐和机械化、日常化、千篇一律的军营经验联系起来。"},{"label":"它反映了什么","value":"它把现代战争中的标准化武器和重复训练，沉淀成日常口语里对“平庸无奇”的评价。"},{"label":"类似变体（可选）","value":"nullachtfünfzehn；null-acht-fünfzehn。"},{"label":"关联事件/概念（可选）","value":"第一次世界大战、德国军队、现代战争的标准化"},{"label":"出处","value":"Duden: nullachtfünfzehn；Redensarten-Index/德语俗语资料关于“08/15”的解释；DER SPIEGEL Zwiebelfisch-Abc: Nullachtfünfzehn。"},{"label":"资料备注","value":"关于“08/15”从具体武器型号转为“平庸”的过程存在不同细节解释，卡片采用较稳妥的“士兵语境与重复训练”说法。"}],"relationItems":["← 前因：第一次世界大战","↔ 相关：德国军队","↔ 相关：现代战争的标准化"],"relations":[{"text":"← 前因：第一次世界大战","id":"extra968"}],"source":"proverb","id":"proverb3"},{"title":"“blau machen”","level":"C","type":"俗语卡","tags":["文化与思想","经济与社会"],"mainTag":"文化与思想","subTag":"经济与社会","timeText":"十九世纪以来在德语口语中广泛可见，沿用至今","place":"德国及德语区。","summary":"“blau machen”字面是“做蓝”，实际指逃课、旷工或假装有事不去上班，是德语里很有生活气的口语表达。","fields":[{"label":"标题","value":"“blau machen”"},{"label":"分级","value":"C"},{"label":"类型","value":"俗语卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"经济与社会"},{"label":"时间","value":"十九世纪以来在德语口语中广泛可见，沿用至今"},{"label":"主要国家","value":"德国、奥地利、瑞士"},{"label":"一句话概括","value":"“blau machen”字面是“做蓝”，实际指逃课、旷工或假装有事不去上班，是德语里很有生活气的口语表达。"},{"label":"原文/标准说法（原文+中文翻译）","value":"blau machen，字面为“做蓝”；中文意思是“旷工”“逃课”“偷懒不去”。"},{"label":"出现时间","value":"较难精确锁定，通常与“蓝色星期一”等旧手工业和口语传统联系在一起。"},{"label":"流行时间","value":"近现代德语口语中持续流行，现代仍常用。"},{"label":"地区","value":"德国及德语区。"},{"label":"它在说什么（字面+引申）","value":"字面并不是认真“制作蓝色”，而是说某人无正当理由不去工作或上课，有时带玩笑和轻微责备语气。"},{"label":"为什么会出现","value":"常见解释把它和“蓝色星期一”、染布工艺或手工业者星期一休息传统相连，但词源并非完全无争议。"},{"label":"它反映了什么","value":"它反映了工作纪律进入日常生活后，人们也发展出一套调侃“逃避劳动/义务”的轻松说法。"},{"label":"类似变体（可选）","value":"blaumachen；einen blauen Montag machen。"},{"label":"关联事件/概念（可选）","value":"工业劳动纪律、手工业传统、德语颜色俗语"},{"label":"出处","value":"Duden: blaumachen；DWDS: blaumachen；Redensarten-Index/德语俗语资料关于“blauer Montag”的解释。"},{"label":"资料备注","value":"词源存在多种解释，卡片只写“常见解释”，不把染布来源写成确定无疑的唯一答案。"}],"relationItems":["↔ 相关：工业劳动纪律","↔ 相关：德语颜色俗语"],"relations":[],"source":"proverb","id":"proverb4"},{"title":"Ich verstehe nur Bahnhof","level":"C","type":"俗语卡","tags":["文化与思想","战争与外交"],"mainTag":"文化与思想","subTag":"战争与外交","timeText":"出现时间约为1917—1918年；流行时间为魏玛时期广泛流行，沿用至今","place":"德国及德语区。","summary":"这个说法起源于一战末期士兵的厌战情绪，后来演变成德语里表示“完全听不懂”的常用俗语。","fields":[{"label":"标题","value":"Ich verstehe nur Bahnhof"},{"label":"地区","value":"德国及德语区。"},{"label":"分级","value":"C"},{"label":"类型","value":"俗语卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"出现时间约为1917—1918年；流行时间为魏玛时期广泛流行，沿用至今"},{"label":"一句话概括","value":"这个说法起源于一战末期士兵的厌战情绪，后来演变成德语里表示“完全听不懂”的常用俗语。"},{"label":"原文/标准说法","value":"Ich verstehe nur Bahnhof"},{"label":"中文直译","value":"我只听得懂“火车站”"},{"label":"中文常用意思","value":"我完全听不懂；我一头雾水"},{"label":"它在说什么","value":"字面上是“别的话我都听不进去，只听见火车站”，实际表达的是“你说的我根本没听懂”或者“我根本不想听”。"},{"label":"为什么会出现","value":"一战末期，德国士兵普遍厌战，最想听到的就是能回家的消息，而“火车站”象征复员、返乡和脱离前线，所以这个词被拿来概括一种强烈的逃离战争心理。"},{"label":"它反映了什么","value":"一战末期和战后德国社会中很强的厌战情绪、对官方语言的疏离感，以及一种带有黑色幽默色彩的日常表达方式。"},{"label":"类似变体","value":"可联系同时期一些表达逃避、拒绝承担、厌烦动员的口头说法，但“Ich verstehe nur Bahnhof”本身后来保留下来并进入现代德语日常口语。"},{"label":"关联事件/概念","value":"一战末期德军士气崩溃、1918年十一月革命、魏玛初期的反战社会心理"},{"label":"出处","value":"常见于德语俗语词典和现代德语解释资料，具体最早书面出处还可以后续再细查"}],"relationItems":[],"relations":[],"source":"proverb","id":"proverb5"},{"title":"Das ist mir Wurst","level":"C","type":"俗语卡","tags":["文化与思想","无"],"mainTag":"文化与思想","subTag":"无","timeText":"出现时间为19世纪初；流行时间为19世纪以来一直通行于德语口语，沿用至今","place":"德国及德语区。","summary":"这是德语里很常见的口语表达，字面是“这对我来说是香肠”，实际意思是“我无所谓”“这对我来说都一样”。 DWDS","fields":[{"label":"标题","value":"Das ist mir Wurst"},{"label":"地区","value":"德国及德语区。"},{"label":"分级","value":"C"},{"label":"类型","value":"俗语卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"无"},{"label":"时间","value":"出现时间为19世纪初；流行时间为19世纪以来一直通行于德语口语，沿用至今"},{"label":"一句话概括","value":"这是德语里很常见的口语表达，字面是“这对我来说是香肠”，实际意思是“我无所谓”“这对我来说都一样”。 DWDS"},{"label":"原文/标准说法","value":"Das ist mir Wurst"},{"label":"中文直译","value":"这对我来说是香肠"},{"label":"中文常用意思","value":"这对我无所谓；我不在乎；都一样"},{"label":"它在说什么","value":"这句话不是在认真谈“香肠”，而是借“Wurst”来表达“无差别、无所谓”。在实际语境里，它通常就是“我不在乎结果”“哪个都行”“反正都一样”的意思。 DWDS"},{"label":"为什么会出现","value":"现有常见解释有两条。一条认为它和“香肠两头看起来差不多”有关，所以引申出“从哪头下手都一样”；另一条解释则认为，香肠作为一种内容混杂、不那么讲究的食物，被拿来表示“放什么进去都差不多”，也就引申为“无所谓”。而较可靠的词典线索指出，这个表达最迟在19世纪初已经出现在学生语言里。 DWDS Redensarten-Index"},{"label":"它反映了什么","value":"它反映的是一种很典型的德语日常口语风格：表达直接、带点俚俗感，也带一点轻微的不耐烦或抽离感。和“Ich verstehe nur Bahnhof”那种有明确战争语境的俗语不同，这一句更像是长期稳定存在的口语表达，不依赖某一个特定历史事件。"},{"label":"类似变体","value":"Das ist mir egal；Das ist mir gleich；Ist mir wurscht。后者尤其常见于口语和部分地区变体。 DWDS"},{"label":"关联事件/概念","value":"德语学生语言、德语口语俗语系统、日常生活中的俚俗表达传统"},{"label":"出处","value":"DWDS 词条“Wurst”；Redensarten-Index“jemandem wurst/wurscht sein” DWDS Redensarten-Index"}],"relationItems":[],"relations":[],"source":"proverb","id":"proverb6"},{"title":"Da haben wir den Salat / Jetzt haben wir den Salat","level":"C","type":"俗语卡","tags":["文化与思想","无"],"mainTag":"文化与思想","subTag":"无","timeText":"出现时间最晚可确证到1849年；流行时间为19世纪中期以来一直通行于德语口语，沿用至今","place":"德国及德语区。","summary":"这句德语俗语字面是“这下我们有沙拉了”，实际意思是“这下糟了”“现在成一团乱麻了”，通常用来抱怨某个已经发生的麻烦结果。 DWDS Redensarten-Index","fields":[{"label":"标题","value":"Da haben wir den Salat / Jetzt haben wir den Salat"},{"label":"地区","value":"德国及德语区。"},{"label":"分级","value":"C"},{"label":"类型","value":"俗语卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"无"},{"label":"时间","value":"出现时间最晚可确证到1849年；流行时间为19世纪中期以来一直通行于德语口语，沿用至今"},{"label":"一句话概括","value":"这句德语俗语字面是“这下我们有沙拉了”，实际意思是“这下糟了”“现在成一团乱麻了”，通常用来抱怨某个已经发生的麻烦结果。 DWDS Redensarten-Index"},{"label":"原文/标准说法","value":"Da haben wir den Salat；Jetzt haben wir den Salat"},{"label":"中文直译","value":"这下我们有沙拉了"},{"label":"中文常用意思","value":"这下麻烦了；这下乱套了；事情果然搞砸了"},{"label":"它在说什么","value":"这句话通常是在事情已经出了问题之后说的，不是单纯描述“乱”，而是带一点“你看吧，果然出事了”“现在只能面对这个烂摊子了”的语气。它常见于抱怨、懊恼，或者带一点讽刺的场景。 DWDS"},{"label":"为什么会出现","value":"较可靠的解释是，德语里从大约19世纪中期开始就把“Salat”拿来比喻“混乱、杂乱、搅成一团的状态”，因为沙拉本身就是多种材料混在一起的东西。Redensarten-Index还指出，这个感叹句本身最晚在1849年已经有书面记录，所以它并不是现代新造说法，而是有明确19世纪根源的口语表达。 Redensarten-Index"},{"label":"它反映了什么","value":"它反映的是德语口语里一种很典型的“用食物说混乱”的表达方式，把生活中的麻烦说得既形象又带点幽默感。和“Das ist mir Wurst”一样，这类说法并不依附于某一场单独历史事件，而是长期沉淀进了日常口语系统。"},{"label":"类似变体","value":"Da hast du den Salat；Nun haben wir den Salat。现代语境里“Da haben wir den Salat”和“Jetzt haben wir den Salat”都能见到。 DWDS"},{"label":"关联事件/概念","value":"德语口语俗语系统、以食物表达情绪或局面的语言习惯、19世纪以来的日常俚俗表达"},{"label":"出处","value":"DWDS“da haben wir den Salat”；Redensarten-Index“Da haben wir den Salat”"}],"relationItems":[],"relations":[],"source":"proverb","id":"proverb7"},{"title":"Es geht um die Wurst","level":"C","type":"俗语卡","tags":["文化与思想","无"],"mainTag":"文化与思想","subTag":"无","timeText":"出现时间至少可追到19世纪；流行时间为19世纪以来一直通行于德语口语，沿用至今","place":"德国及德语区。","summary":"这句德语俗语字面是“事情关乎香肠”，实际意思是“现在到了关键时刻”“胜负就看这一回”“事情要见分晓了”。 DWDS","fields":[{"label":"标题","value":"Es geht um die Wurst"},{"label":"地区","value":"德国及德语区。"},{"label":"分级","value":"C"},{"label":"类型","value":"俗语卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"无"},{"label":"时间","value":"出现时间至少可追到19世纪；流行时间为19世纪以来一直通行于德语口语，沿用至今"},{"label":"一句话概括","value":"这句德语俗语字面是“事情关乎香肠”，实际意思是“现在到了关键时刻”“胜负就看这一回”“事情要见分晓了”。 DWDS"},{"label":"原文/标准说法","value":"Es geht um die Wurst"},{"label":"中文直译","value":"现在关系到香肠了"},{"label":"中文常用意思","value":"到了关键时刻；到了胜负关头；成败在此一举"},{"label":"它在说什么","value":"这句话一般不是表示“无所谓”，而是恰恰相反，表示事情已经到了最要紧的时候，结果马上要出来了，不能再拖，也不能再随便应付。常见语境包括比赛、选举、谈判、考试、最后决策等。 DWDS"},{"label":"为什么会出现","value":"DWDS给出的核心义项是“es geht um die Entscheidung, kommt darauf an”，说明这个表达本身就和“决定性时刻”有关；词典还标明它属于19世纪就已经存在的说法。也就是说，它不是现代网络口语，而是一个历史较久的德语俗语。 DWDS"},{"label":"它反映了什么","value":"它反映出德语口语里很典型的一种表达方式：用具体、日常、甚至有点滑稽的食物意象，去说一种高度紧张的现实处境。正因为字面上很轻松，实际含义却很紧绷，所以这句话听起来既生活化，又很有戏剧感。"},{"label":"类似变体","value":"Jetzt geht es um die Wurst。这个形式尤其常见，语气更强，更像“现在可真到节骨眼了”。"},{"label":"关联事件/概念","value":"德语口语俗语系统、比赛与竞争语境、19世纪以来的日常表达传统"},{"label":"出处","value":"DWDS“Wurst”词条 DWDS"}],"relationItems":[],"relations":[],"source":"proverb","id":"proverb8"},{"title":"“Jeder Schuss ein Russ, jeder Stoß ein Franzos, jeder Tritt ein Brit”","level":"C","type":"俗语卡","tags":["文化与思想","战争与外交"],"mainTag":"文化与思想","subTag":"战争与外交","timeText":"第一次世界大战期间","place":"德意志帝国及德语宣传文化圈。","summary":"这句押韵敌人口号把俄、法、英变成可笑化的射击对象，体现一战早期德国大众宣传的粗粝动员语言。","fields":[{"label":"标题","value":"“Jeder Schuss ein Russ, jeder Stoß ein Franzos, jeder Tritt ein Brit”"},{"label":"分级","value":"C"},{"label":"类型","value":"俗语卡"},{"label":"主标签","value":"文化与思想"},{"label":"副标签","value":"战争与外交"},{"label":"时间","value":"第一次世界大战期间"},{"label":"一句话概括","value":"这句押韵敌人口号把俄、法、英变成可笑化的射击对象，体现一战早期德国大众宣传的粗粝动员语言。"},{"label":"原文/标准说法（原文+中文翻译）","value":"Jeder Schuss ein Russ, jeder Stoß ein Franzos, jeder Tritt ein Brit。中文：“每一枪一个俄国佬，每一刺一个法国佬，每一脚一个英国佬。”"},{"label":"出现时间","value":"一战期间，常见于宣传明信片、儿童化战争图像和战时大众文化。"},{"label":"流行时间","value":"1914年前后至一战中期，作为押韵战时口号传播。"},{"label":"地区","value":"德意志帝国及德语宣传文化圈。"},{"label":"它在说什么（字面+引申）","value":"字面是夸张地说德国士兵轻易击倒敌人；引申义是把战争简化成轻松、游戏化、可笑化的敌人消灭。"},{"label":"为什么会出现","value":"一战初期各国都用简短、押韵、儿童也能记住的口号动员情绪，淡化现代战争的残酷性。"},{"label":"它反映了什么","value":"反映早期战争狂热、敌人漫画化和大众宣传对暴力的轻佻处理，与后来的壕沟现实形成强烈反差。"},{"label":"类似变体（可选）","value":"Jeder Schuß ein Russ’! Jeder Stoß ein Franzos’! 等拼写和排序变体。"},{"label":"关联事件/概念（可选）","value":"第一次世界大战、德国战时宣传、英法俄协约。"},{"label":"出处","value":"Deutsche Digitale Bibliothek, “Jeder Schuss ein Russ' - Jeder Tritt ein Britt' - Jeder Stoß ein Franzos'”；1914-1918-Online, Propaganda at Home (Germany)。"}],"relationItems":["← 前因：1914年七月危机","→ 后果：第一次世界大战壕沟战","↔ 相关：“Gott strafe England!”","↔ 相关：英国参加第一次世界大战","↔ 同时期参考：协约国反德宣传明信片"],"relations":[{"text":"← 前因：1914年七月危机","id":"extra646"},{"text":"↔ 相关：“Gott strafe England!”","id":"proverb30"},{"text":"↔ 相关：英国参加第一次世界大战","id":"extra648"}],"source":"proverb","id":"proverb9"},{"title":"“eine Leiche im Keller haben”","level":"C","type":"俗语卡","tags":["文化与思想"],"mainTag":"文化与思想","subTag":"","timeText":"近现代德语口语；具体源头有多种说法","place":"德语区。","summary":"“地下室里有尸体”不是说真有尸体，而是说一个人或组织藏着见不得光的秘密。","fields":[{"label":"标题","value":"“eine Leiche im Keller haben”"},{"label":"分级","value":"C"},{"label":"类型","value":"俗语卡"},{"label":"主标签","value":"文化与思想"},{"label":"时间","value":"近现代德语口语；具体源头有多种说法"},{"label":"一句话概括","value":"“地下室里有尸体”不是说真有尸体，而是说一个人或组织藏着见不得光的秘密。"},{"label":"原文/标准说法（原文+中文翻译）","value":"eine Leiche im Keller haben。中文：“地下室里有一具尸体。”"},{"label":"出现时间","value":"作为现代德语俗语流行，具体起源存在不同解释。"},{"label":"流行时间","value":"20世纪以来至今。"},{"label":"地区","value":"德语区。"},{"label":"它在说什么（字面+引申）","value":"字面像犯罪故事，家里地下室藏着尸体；引申义是某人有不可告人的过去、丑闻或黑历史。"},{"label":"为什么会出现","value":"地下室、隐藏、尸体这三个意象组合起来很强，适合表达“秘密没有消失，只是被藏起来了”。它和英语“skeleton in the closet”意思接近。"},{"label":"它反映了什么","value":"这类俗语把道德秘密空间化，仿佛过去的罪行会变成藏在房子里的东西，随时可能被发现。"},{"label":"类似变体（可选）","value":"Leichen im Keller haben；eine Leiche im Keller。"},{"label":"关联事件/概念（可选）","value":"黑历史、丑闻、秘密、战后责任记忆。"},{"label":"出处","value":"radio SAW, Redewendung: eine Leiche im Keller haben；Projekt Deutsche WortSchätze, Leiche。"}],"relationItems":["↔ 相关：战后德国“零点时刻”","↔ 相关：德国去纳粹化","↔ 同时期参考：“skeleton in the closet”"],"relations":[{"text":"↔ 相关：战后德国“零点时刻”","id":"extra9"},{"text":"↔ 相关：德国去纳粹化","id":"extra5"},{"text":"↔ 同时期参考：“skeleton in the closet”","id":"proverb18"}],"source":"proverb","id":"proverb10"},{"title":"“Da liegt der Hund begraben”","level":"C","type":"俗语卡","tags":["文化与思想"],"mainTag":"文化与思想","subTag":"","timeText":"近现代德语俗语；早期源流有多种解释","place":"德语区。","summary":"“狗就埋在那里”意思是“问题关键就在这里”，也可带一点“这里真冷清”的语感。","fields":[{"label":"标题","value":"“Da liegt der Hund begraben”"},{"label":"分级","value":"C"},{"label":"类型","value":"俗语卡"},{"label":"主标签","value":"文化与思想"},{"label":"时间","value":"近现代德语俗语；早期源流有多种解释"},{"label":"一句话概括","value":"“狗就埋在那里”意思是“问题关键就在这里”，也可带一点“这里真冷清”的语感。"},{"label":"原文/标准说法（原文+中文翻译）","value":"Da liegt der Hund begraben。中文：“狗就埋在那里。”"},{"label":"出现时间","value":"较早进入德语俗语系统，具体源流有民间故事、词义转化等不同解释。"},{"label":"流行时间","value":"近现代至今。"},{"label":"地区","value":"德语区。"},{"label":"它在说什么（字面+引申）","value":"字面是在指出一只被埋的狗；引申义是“关键点、问题根子就在这里”。在某些语境中也可说一个地方很无聊、没有生气。"},{"label":"为什么会出现","value":"这句话的画面很具体：问题像被埋在地下的东西，只有挖到那里才知道真正原因。"},{"label":"它反映了什么","value":"德语俗语常用很日常甚至有点怪的画面来表达抽象判断，让“找原因”变成“找埋在哪里”。"},{"label":"类似变体（可选）","value":"Da ist der Hund begraben；Hier liegt der Hund begraben。"},{"label":"关联事件/概念（可选）","value":"问题根源、关键原因、地方冷清。"},{"label":"出处","value":"GEOlino, Redewendung: Da liegt der Hund begraben；Wiktionary, da liegt der Hund begraben；Hücker Archiv, Da liegt der Hund begraben。"}],"relationItems":["↔ 相关：Das ist mir Wurst","↔ 相关：Da haben wir den Salat / Jetzt haben wir den Salat"],"relations":[{"text":"↔ 相关：Das ist mir Wurst","id":"proverb6"},{"text":"↔ 相关：Da haben wir den Salat / Jetzt haben wir den Salat","id":"proverb7"}],"source":"proverb","id":"proverb11"},{"title":"“die Kirche im Dorf lassen”","level":"C","type":"俗语卡","tags":["文化与思想"],"mainTag":"文化与思想","subTag":"","timeText":"近现代德语俗语","place":"德语区。","summary":"“把教堂留在村里”是在劝人别夸张、别过头，保持分寸和现实感。","fields":[{"label":"标题","value":"“die Kirche im Dorf lassen”"},{"label":"分级","value":"C"},{"label":"类型","value":"俗语卡"},{"label":"主标签","value":"文化与思想"},{"label":"时间","value":"近现代德语俗语"},{"label":"一句话概括","value":"“把教堂留在村里”是在劝人别夸张、别过头，保持分寸和现实感。"},{"label":"原文/标准说法（原文+中文翻译）","value":"die Kirche im Dorf lassen。中文：“把教堂留在村里。”"},{"label":"出现时间","value":"近现代德语俗语，具体源头常与村庄、教堂和宗教仪式空间有关。"},{"label":"流行时间","value":"近现代至今。"},{"label":"地区","value":"德语区。"},{"label":"它在说什么（字面+引申）","value":"字面是别把村里的教堂搬走；引申义是别小题大做、别把事情说得太过，保持适度。"},{"label":"为什么会出现","value":"教堂在传统村庄里是中心建筑，“教堂还在村里”意味着秩序、位置和比例没有被弄乱。"},{"label":"它反映了什么","value":"这句俗语很有德语乡村秩序感：事情可以讨论，但不要把共同生活的尺度都搞乱。"},{"label":"类似变体（可选）","value":"Lass mal die Kirche im Dorf。"},{"label":"关联事件/概念（可选）","value":"地方共同体、宗教空间、分寸感。"},{"label":"出处","value":"FOCUS, Die Kirche im Dorf lassen；Phraseo, Die Kirche im Dorf lassen。"}],"relationItems":["↔ 相关：德国新教教会斗争","↔ 相关：魏玛德国宗教教育妥协"],"relations":[{"text":"↔ 相关：德国新教教会斗争","id":"extra153"},{"text":"↔ 相关：魏玛德国宗教教育妥协","id":"card178"}],"source":"proverb","id":"proverb12"},{"title":"“den inneren Schweinehund überwinden”","level":"C","type":"俗语卡","tags":["文化与思想"],"mainTag":"文化与思想","subTag":"","timeText":"20世纪以来常见；更早与“Schweinehund”骂语有关","place":"德语区。","summary":"“战胜内心猪狗”指克服懒惰、拖延和不想动的心理阻力，常用于健身、学习和自律场景。","fields":[{"label":"标题","value":"“den inneren Schweinehund überwinden”"},{"label":"分级","value":"C"},{"label":"类型","value":"俗语卡"},{"label":"主标签","value":"文化与思想"},{"label":"时间","value":"20世纪以来常见；更早与“Schweinehund”骂语有关"},{"label":"一句话概括","value":"“战胜内心猪狗”指克服懒惰、拖延和不想动的心理阻力，常用于健身、学习和自律场景。"},{"label":"原文/标准说法（原文+中文翻译）","value":"den inneren Schweinehund überwinden。中文：“战胜内心的猪狗。”"},{"label":"出现时间","value":"20世纪以来常见；“Schweinehund”本身更早是粗俗骂语。"},{"label":"流行时间","value":"20世纪至今，尤其在健身、工作、学习和自我管理语境中常见。"},{"label":"地区","value":"德语区。"},{"label":"它在说什么（字面+引申）","value":"字面像身体里住着一只不愿动的怪东西；引申义是克服惰性，硬着头皮做应该做的事。"},{"label":"为什么会出现","value":"它把意志薄弱人格化、动物化，让拖延和懒惰变成一个可以被“打败”的对象。"},{"label":"它反映了什么","value":"这句俗语很适合现代自律文化：问题不是不知道该做什么，而是要制服那个不想做的自己。"},{"label":"类似变体（可选）","value":"mein innerer Schweinehund；gegen den inneren Schweinehund kämpfen。"},{"label":"关联事件/概念（可选）","value":"身体文化、体育、自律、现代生活节奏。"},{"label":"出处","value":"Wiktionary, den inneren Schweinehund überwinden；t-online, Den inneren Schweinehund überwinden；Wiktionary/Redensarten-Index related references。"}],"relationItems":["↔ 相关：德国裸体文化运动","↔ 相关：魏玛德国大众体育文化","↔ 相关：德国体操运动"],"relations":[{"text":"↔ 相关：德国裸体文化运动","id":"extra727"},{"text":"↔ 相关：魏玛德国大众体育文化","id":"card86"},{"text":"↔ 相关：德国体操运动","id":"extra517"}],"source":"proverb","id":"proverb13"},{"title":"“Tomaten auf den Augen haben”","level":"C","type":"俗语卡","tags":["文化与思想"],"mainTag":"文化与思想","subTag":"","timeText":"近现代德语口语","place":"德语区。","summary":"“眼睛上长番茄”是在说一个人明明该看见却没看见，带有轻微吐槽意味。","fields":[{"label":"标题","value":"“Tomaten auf den Augen haben”"},{"label":"分级","value":"C"},{"label":"类型","value":"俗语卡"},{"label":"主标签","value":"文化与思想"},{"label":"时间","value":"近现代德语口语"},{"label":"一句话概括","value":"“眼睛上长番茄”是在说一个人明明该看见却没看见，带有轻微吐槽意味。"},{"label":"原文/标准说法（原文+中文翻译）","value":"Tomaten auf den Augen haben。中文：“眼睛上有番茄。”"},{"label":"出现时间","value":"近现代德语口语，具体来源有多种解释。"},{"label":"流行时间","value":"20世纪以来至今。"},{"label":"地区","value":"德语区。"},{"label":"它在说什么（字面+引申）","value":"字面是眼睛被番茄挡住；引申义是看漏了明显的东西，或对眼前事实视而不见。"},{"label":"为什么会出现","value":"番茄又红又圆，放在眼睛上的画面很荒诞，适合表达“你怎么这都看不见”。"},{"label":"它反映了什么","value":"这类俗语常把认知错误变成身体画面：不是你判断错了，而是你的眼睛被奇怪的东西糊住了。"},{"label":"类似变体（可选）","value":"Hast du Tomaten auf den Augen?"},{"label":"关联事件/概念（可选）","value":"日常吐槽、视觉隐喻、误判。"},{"label":"出处","value":"GEOlino, Redewendung: Tomaten auf den Augen haben；Wiktionary, Tomaten auf den Augen haben；DW, Das sagt man so: Tomaten auf den Augen haben。"}],"relationItems":["↔ 相关：Ich verstehe nur Bahnhof","↔ 相关：Das ist mir Wurst"],"relations":[{"text":"↔ 相关：Ich verstehe nur Bahnhof","id":"proverb5"},{"text":"↔ 相关：Das ist mir Wurst","id":"proverb6"}],"source":"proverb","id":"proverb14"},{"title":"“Butter bei die Fische”","level":"C","type":"俗语卡","tags":["文化与思想"],"mainTag":"文化与思想","subTag":"","timeText":"近现代北德口语","place":"德国北部，后来进入更广泛德语口语。","summary":"“给鱼上黄油”意思是别绕弯子、说重点、拿出实质内容，带有北德口语味道。","fields":[{"label":"标题","value":"“Butter bei die Fische”"},{"label":"分级","value":"C"},{"label":"类型","value":"俗语卡"},{"label":"主标签","value":"文化与思想"},{"label":"时间","value":"近现代北德口语"},{"label":"一句话概括","value":"“给鱼上黄油”意思是别绕弯子、说重点、拿出实质内容，带有北德口语味道。"},{"label":"原文/标准说法（原文+中文翻译）","value":"Butter bei die Fische。中文：“黄油配到鱼上。”"},{"label":"出现时间","value":"近现代北德口语，具体形成时间不易精确。"},{"label":"流行时间","value":"20世纪以来至今。"},{"label":"地区","value":"德国北部，后来进入更广泛德语口语。"},{"label":"它在说什么（字面+引申）","value":"字面是吃鱼时该把黄油加上；引申义是“说实话、来点实际的、别再空谈”。"},{"label":"为什么会出现","value":"鱼端上桌但没有黄油，就像谈话只有铺垫没有重点；黄油一上，真正的东西才到位。"},{"label":"它反映了什么","value":"这句俗语很实用，也很有地方感：不追求漂亮修辞，而是催你进入正题。"},{"label":"类似变体（可选）","value":"Jetzt mal Butter bei die Fische。"},{"label":"关联事件/概念（可选）","value":"北德口语、直接表达、谈判场景。"},{"label":"出处","value":"t-online, Butter bei die Fische；Sprichwörter & Redewendungen, Butter bei die Fische；wissen.de, Butter bei die Fische。"}],"relationItems":["↔ 相关：Das ist mir Wurst","↔ 相关：Es geht um die Wurst"],"relations":[{"text":"↔ 相关：Das ist mir Wurst","id":"proverb6"},{"text":"↔ 相关：Es geht um die Wurst","id":"proverb8"}],"source":"proverb","id":"proverb15"},{"title":"“unter aller Kanone”","level":"C","type":"俗语卡","tags":["文化与思想"],"mainTag":"文化与思想","subTag":"","timeText":"近现代德语口语；常解释为学生语误读/戏译","place":"德语区。","summary":"“低于所有大炮”听起来像军事夸张，其实是说质量差到离谱、表现糟糕透顶。","fields":[{"label":"标题","value":"“unter aller Kanone”"},{"label":"分级","value":"C"},{"label":"类型","value":"俗语卡"},{"label":"主标签","value":"文化与思想"},{"label":"时间","value":"近现代德语口语；常解释为学生语误读/戏译"},{"label":"一句话概括","value":"“低于所有大炮”听起来像军事夸张，其实是说质量差到离谱、表现糟糕透顶。"},{"label":"原文/标准说法（原文+中文翻译）","value":"unter aller Kanone。中文：“低于所有大炮。”"},{"label":"出现时间","value":"近现代德语口语，常被解释为从拉丁语 sub omni canone 讹变或戏译而来。"},{"label":"流行时间","value":"近现代至今。"},{"label":"地区","value":"德语区。"},{"label":"它在说什么（字面+引申）","value":"字面像比所有大炮还低；引申义是“糟糕到不能接受”，类似中文“烂到没边”。"},{"label":"为什么会出现","value":"常见解释认为它来自拉丁语“低于一切标准”，后来被德语学生或口语戏谑地理解成“Kanone”。这种误读反而让表达更生动。"},{"label":"它反映了什么","value":"俗语常会从误听、误读和玩笑里长出来，原本抽象的“标准”被变成了可笑的大炮画面。"},{"label":"类似变体（可选）","value":"Das ist unter aller Kanone。"},{"label":"关联事件/概念（可选）","value":"学生语、讹变、评价语言。"},{"label":"出处","value":"Sub omni canone historical explanation；Duden/Wahrig idiom references cited by wissen.de and related idiom dictionaries。"}],"relationItems":["↔ 相关：德意志学生兄弟会","↔ 相关：德国大学文化"],"relations":[{"text":"↔ 相关：德意志学生兄弟会","id":"extra499"}],"source":"proverb","id":"proverb16"},{"title":"“nicht alle Tassen im Schrank haben”","level":"C","type":"俗语卡","tags":["文化与思想"],"mainTag":"文化与思想","subTag":"","timeText":"20世纪德语口语中可见；更早源流有不同解释","place":"德语区。","summary":"“柜子里不是所有杯子都在”是在说一个人脑子不太正常、想法离谱，是一种委婉又刻薄的吐槽。","fields":[{"label":"标题","value":"“nicht alle Tassen im Schrank haben”"},{"label":"分级","value":"C"},{"label":"类型","value":"俗语卡"},{"label":"主标签","value":"文化与思想"},{"label":"时间","value":"20世纪德语口语中可见；更早源流有不同解释"},{"label":"一句话概括","value":"“柜子里不是所有杯子都在”是在说一个人脑子不太正常、想法离谱，是一种委婉又刻薄的吐槽。"},{"label":"原文/标准说法（原文+中文翻译）","value":"nicht alle Tassen im Schrank haben。中文：“柜子里不是所有杯子都在。”"},{"label":"出现时间","value":"20世纪德语口语中可见，具体源流有不同解释。"},{"label":"流行时间","value":"20世纪至今。"},{"label":"地区","value":"德语区。"},{"label":"它在说什么（字面+引申）","value":"字面是杯柜里的杯子不全；引申义是说一个人不太清醒、想法荒唐或行为离谱。"},{"label":"为什么会出现","value":"完整的柜子象征秩序和理性，少了几只杯子就像脑子里的“零件”不齐。"},{"label":"它反映了什么","value":"这类俗语把精神状态说成家居秩序问题，听起来比直接骂人温和，但其实很尖刻。"},{"label":"类似变体（可选）","value":"nicht mehr alle Tassen im Schrank haben；nicht alle Latten am Zaun haben。"},{"label":"关联事件/概念（可选）","value":"日常讽刺、委婉骂人、理性隐喻。"},{"label":"出处","value":"DW, So ein Durcheinander im Oberstübchen；Die Presse, Etwas auf dem Kasten, aber nicht alle Tassen im Schrank haben；Wiktionary/Redensarten-Index references。"}],"relationItems":["↔ 相关：Ich verstehe nur Bahnhof","↔ 相关：“Tomaten auf den Augen haben”"],"relations":[{"text":"↔ 相关：Ich verstehe nur Bahnhof","id":"proverb5"},{"text":"↔ 相关：“Tomaten auf den Augen haben”","id":"proverb14"}],"source":"proverb","id":"proverb17"},{"title":"“Gott strafe England!”","level":"C","type":"俗语卡","tags":["文化与思想"],"mainTag":"文化与思想","subTag":"","timeText":"第一次世界大战期间","place":"德国及德语战时舆论空间。","summary":"“愿上帝惩罚英国！”是一战德国流行的仇英口号，反映海上封锁和战时宣传塑造的敌意。","fields":[{"label":"标题","value":"“Gott strafe England!”"},{"label":"分级","value":"C"},{"label":"类型","value":"俗语卡"},{"label":"主标签","value":"文化与思想"},{"label":"时间","value":"第一次世界大战期间"},{"label":"一句话概括","value":"“愿上帝惩罚英国！”是一战德国流行的仇英口号，反映海上封锁和战时宣传塑造的敌意。"},{"label":"原文/标准说法（原文+中文翻译）","value":"Gott strafe England! 中文：“愿上帝惩罚英国！”"},{"label":"出现时间","value":"1914年后的一战德国宣传语境。"},{"label":"流行时间","value":"第一次世界大战期间，尤其在战争早期和仇英宣传中常见。"},{"label":"地区","value":"德国及德语战时舆论空间。"},{"label":"它在说什么（字面+引申）","value":"字面是祈求上帝惩罚英国；引申义是把英国塑造成德国苦难和战争围困的主要敌人。"},{"label":"为什么会出现","value":"英德海军竞争、英国海上封锁、德国宣传和战时民族主义共同制造了强烈仇英情绪。"},{"label":"它反映了什么","value":"这句口号把外交和军事冲突变成宗教式咒语，显示总体战中敌意如何进入日常语言。"},{"label":"类似变体（可选）","value":"Gott strafe England, er strafe es! 常见回答为 Er strafe es!"},{"label":"关联事件/概念（可选）","value":"一战海上战争、英国海上封锁、德国战时宣传。"},{"label":"出处","value":"1914-1918 Online: Propaganda；DHM/LeMO: Erster Weltkrieg Propaganda；Jeffrey Verhey, The Spirit of 1914。"}],"relationItems":["↔ 相关：一战海上战争","↔ 相关：一战反德宣传","↔ 相关：“Jeder Schuss ein Russ, jeder Stoß ein Franzos, jeder Tritt ein Brit”"],"relations":[{"text":"↔ 相关：一战海上战争","id":"extra957"},{"text":"↔ 相关：一战反德宣传","id":"extra960"},{"text":"↔ 相关：“Jeder Schuss ein Russ, jeder Stoß ein Franzos, jeder Tritt ein Brit”","id":"proverb9"}],"source":"proverb","id":"proverb30"},{"title":"“skeleton in the closet”","level":"C","type":"俗语卡","tags":["文化与思想"],"mainTag":"文化与思想","subTag":"","timeText":"近现代英语俗语","place":"英语区；美国常说 closet，英国也可说 cupboard。","summary":"“柜子里的骷髅”指一个人或家庭藏着不愿公开的秘密，通常带有丑闻或羞耻意味。","fields":[{"label":"标题","value":"“skeleton in the closet”"},{"label":"分级","value":"C"},{"label":"类型","value":"俗语卡"},{"label":"主标签","value":"文化与思想"},{"label":"时间","value":"近现代英语俗语"},{"label":"一句话概括","value":"“柜子里的骷髅”指一个人或家庭藏着不愿公开的秘密，通常带有丑闻或羞耻意味。"},{"label":"原文/标准说法（原文+中文翻译）","value":"skeleton in the closet / skeleton in the cupboard。中文：“柜子里的骷髅。”"},{"label":"出现时间","value":"19世纪以来在英语中逐渐固定为俗语。"},{"label":"流行时间","value":"19世纪至今。"},{"label":"地区","value":"英语区；美国常说 closet，英国也可说 cupboard。"},{"label":"它在说什么（字面+引申）","value":"字面是家里柜子藏着骷髅；引申义是一个人、家族或组织有不能见光的秘密。"},{"label":"为什么会出现","value":"骷髅代表死亡和罪行，柜子代表家庭内部或私人空间；两者结合成“被藏起来但仍存在的过去”。"},{"label":"它反映了什么","value":"这句俗语把秘密具象成家中物件，暗示所谓体面生活背后可能有被遮掩的历史。"},{"label":"类似变体（可选）","value":"skeleton in the cupboard；have skeletons in one's closet。"},{"label":"关联事件/概念（可选）","value":"丑闻、秘密、家庭名誉、政治黑历史。"},{"label":"出处","value":"Merriam-Webster, skeleton in the closet；Cambridge Dictionary, skeleton in the cupboard/closet。"}],"relationItems":["↔ 相关：“eine Leiche im Keller haben”","↔ 同时期参考：维多利亚时代家庭体面文化"],"relations":[{"text":"↔ 相关：“eine Leiche im Keller haben”","id":"proverb10"}],"source":"proverb","id":"proverb18"},{"title":"“the elephant in the room”","level":"C","type":"俗语卡","tags":["文化与思想"],"mainTag":"文化与思想","subTag":"","timeText":"20世纪英语中广泛流行","place":"英语区。","summary":"“房间里的大象”指所有人都知道但没人愿意说破的大问题。","fields":[{"label":"标题","value":"“the elephant in the room”"},{"label":"分级","value":"C"},{"label":"类型","value":"俗语卡"},{"label":"主标签","value":"文化与思想"},{"label":"时间","value":"20世纪英语中广泛流行"},{"label":"一句话概括","value":"“房间里的大象”指所有人都知道但没人愿意说破的大问题。"},{"label":"原文/标准说法（原文+中文翻译）","value":"the elephant in the room。中文：“房间里的大象。”"},{"label":"出现时间","value":"20世纪英语俗语中逐渐固定。"},{"label":"流行时间","value":"20世纪后期至今。"},{"label":"地区","value":"英语区。"},{"label":"它在说什么（字面+引申）","value":"字面是房间里站着一头巨大动物却没人提；引申义是明显存在但被集体回避的问题。"},{"label":"为什么会出现","value":"大象体积巨大，不可能真的被忽视；这个荒诞画面正好讽刺人们在社交、政治或组织中假装看不见问题。"},{"label":"它反映了什么","value":"这句话特别适合描述公共沉默：问题不是不知道，而是不敢说、不方便说或不想承担说破后的后果。"},{"label":"类似变体（可选）","value":"ignore the elephant in the room；address the elephant in the room。"},{"label":"关联事件/概念（可选）","value":"公共沉默、政治正确、组织危机、家庭禁忌。"},{"label":"出处","value":"Merriam-Webster, elephant in the room；Cambridge Dictionary, elephant in the room。"}],"relationItems":["↔ 相关：“skeleton in the closet”","↔ 同时期参考：英语公共辩论文化"],"relations":[{"text":"↔ 相关：“skeleton in the closet”","id":"proverb18"}],"source":"proverb","id":"proverb19"},{"title":"“when pigs fly”","level":"C","type":"俗语卡","tags":["文化与思想"],"mainTag":"文化与思想","subTag":"","timeText":"近现代英语俗语","place":"英语区。","summary":"“等猪会飞的时候”意思是某件事几乎不可能发生，语气通常幽默又带点嘲讽。","fields":[{"label":"标题","value":"“when pigs fly”"},{"label":"分级","value":"C"},{"label":"类型","value":"俗语卡"},{"label":"主标签","value":"文化与思想"},{"label":"时间","value":"近现代英语俗语"},{"label":"一句话概括","value":"“等猪会飞的时候”意思是某件事几乎不可能发生，语气通常幽默又带点嘲讽。"},{"label":"原文/标准说法（原文+中文翻译）","value":"when pigs fly。中文：“等猪会飞的时候。”"},{"label":"出现时间","value":"近现代英语口语，和更早的“不可能动物飞行”类表达有关。"},{"label":"流行时间","value":"19世纪以来至今。"},{"label":"地区","value":"英语区。"},{"label":"它在说什么（字面+引申）","value":"字面说猪飞上天时才会发生；引申义是“绝不可能”或“你想得太美”。"},{"label":"为什么会出现","value":"猪是笨重、贴地、不会飞的动物，用它飞起来表示荒诞到不可能。"},{"label":"它反映了什么","value":"这类俗语用荒谬画面表达怀疑，比直接说“不可能”更有戏谑感。"},{"label":"类似变体（可选）","value":"pigs might fly；and pigs can fly。"},{"label":"关联事件/概念（可选）","value":"夸张、讽刺、不可能愿望。"},{"label":"出处","value":"Merriam-Webster, when pigs fly；Cambridge Dictionary, pigs might fly。"}],"relationItems":["↔ 相关：“Tomaten auf den Augen haben”","↔ 同时期参考：中文“太阳从西边出来”"],"relations":[{"text":"↔ 相关：“Tomaten auf den Augen haben”","id":"proverb14"}],"source":"proverb","id":"proverb20"},{"title":"“kick the bucket”","level":"C","type":"俗语卡","tags":["文化与思想"],"mainTag":"文化与思想","subTag":"","timeText":"近现代英语俗语","place":"英语区。","summary":"“踢桶”是英语里“死了”的委婉粗俗说法，语气比正式死亡表达更口语化。","fields":[{"label":"标题","value":"“kick the bucket”"},{"label":"分级","value":"C"},{"label":"类型","value":"俗语卡"},{"label":"主标签","value":"文化与思想"},{"label":"时间","value":"近现代英语俗语"},{"label":"一句话概括","value":"“踢桶”是英语里“死了”的委婉粗俗说法，语气比正式死亡表达更口语化。"},{"label":"原文/标准说法（原文+中文翻译）","value":"kick the bucket。中文：“踢桶。”"},{"label":"出现时间","value":"18—19世纪英语中逐渐固定，具体来源有多种说法。"},{"label":"流行时间","value":"近现代至今。"},{"label":"地区","value":"英语区。"},{"label":"它在说什么（字面+引申）","value":"字面是踢到一个桶；引申义是死亡、去世，常带黑色幽默。"},{"label":"为什么会出现","value":"关于来源有屠宰、上吊等不同解释，但核心在于用一个滑稽动作替代严肃死亡，使表达更口语化。"},{"label":"它反映了什么","value":"人们常用委婉、荒诞或玩笑方式谈死亡，既缓和恐惧，也制造距离感。"},{"label":"类似变体（可选）","value":"bucket list 与此俗语有关，指死前想做的事清单。"},{"label":"关联事件/概念（可选）","value":"死亡委婉语、黑色幽默、日常口语。"},{"label":"出处","value":"Merriam-Webster, kick the bucket；Online Etymology Dictionary, kick the bucket。"}],"relationItems":["↔ 相关：“eine Leiche im Keller haben”","↔ 同时期参考：死亡委婉语文化"],"relations":[{"text":"↔ 相关：“eine Leiche im Keller haben”","id":"proverb10"}],"source":"proverb","id":"proverb21"},{"title":"“chercher midi à quatorze heures”","level":"C","type":"俗语卡","tags":["文化与思想"],"mainTag":"文化与思想","subTag":"","timeText":"近现代法语俗语","place":"法语区。","summary":"“下午两点找正午”意思是把简单问题想复杂，没事找事。","fields":[{"label":"标题","value":"“chercher midi à quatorze heures”"},{"label":"分级","value":"C"},{"label":"类型","value":"俗语卡"},{"label":"主标签","value":"文化与思想"},{"label":"时间","value":"近现代法语俗语"},{"label":"一句话概括","value":"“下午两点找正午”意思是把简单问题想复杂，没事找事。"},{"label":"原文/标准说法（原文+中文翻译）","value":"chercher midi à quatorze heures。中文：“在14点寻找正午。”"},{"label":"出现时间","value":"近现代法语俗语。"},{"label":"流行时间","value":"近现代至今。"},{"label":"地区","value":"法语区。"},{"label":"它在说什么（字面+引申）","value":"字面是在下午两点找中午十二点；引申义是绕远路、想太复杂、在简单事情里找不存在的问题。"},{"label":"为什么会出现","value":"正午明明在十二点，却偏要去十四点找，画面荒唐，适合讽刺过度解释和复杂化。"},{"label":"它反映了什么","value":"法国俗语里常有一种理性秩序感：时间、逻辑和比例错位，就变成可笑的思维错误。"},{"label":"类似变体（可选）","value":"Il ne faut pas chercher midi à quatorze heures。"},{"label":"关联事件/概念（可选）","value":"过度解释、形式主义、复杂化。"},{"label":"出处","value":"Larousse, chercher midi à quatorze heures；Expressio, Chercher midi à quatorze heures。"}],"relationItems":["↔ 相关：“die Kirche im Dorf lassen”","↔ 同时期参考：中文“舍近求远”"],"relations":[{"text":"↔ 相关：“die Kirche im Dorf lassen”","id":"proverb12"}],"source":"proverb","id":"proverb22"},{"title":"“revenons à nos moutons”","level":"C","type":"俗语卡","tags":["文化与思想"],"mainTag":"文化与思想","subTag":"","timeText":"15世纪戏剧源头；近现代法语持续使用","place":"法国及法语区。","summary":"“回到我们的羊”意思是别跑题，回到正题，源头常追溯到中世纪法国喜剧。","fields":[{"label":"标题","value":"“revenons à nos moutons”"},{"label":"分级","value":"C"},{"label":"类型","value":"俗语卡"},{"label":"主标签","value":"文化与思想"},{"label":"时间","value":"15世纪戏剧源头；近现代法语持续使用"},{"label":"一句话概括","value":"“回到我们的羊”意思是别跑题，回到正题，源头常追溯到中世纪法国喜剧。"},{"label":"原文/标准说法（原文+中文翻译）","value":"revenons à nos moutons。中文：“回到我们的羊。”"},{"label":"出现时间","value":"常追溯到15世纪法国闹剧《巴特兰律师》。"},{"label":"流行时间","value":"中世纪晚期以来，近现代法语仍常用。"},{"label":"地区","value":"法国及法语区。"},{"label":"它在说什么（字面+引申）","value":"字面是回到羊的问题；引申义是“话题跑远了，我们回到正题”。"},{"label":"为什么会出现","value":"在《巴特兰律师》中，羊的纠纷和庭审跑题制造喜剧效果，“回到羊”后来变成回到原话题的固定说法。"},{"label":"它反映了什么","value":"这句俗语很适合会议、课堂和聊天场景，说明俗语有时能从具体文学场景变成日常语言工具。"},{"label":"类似变体（可选）","value":"Revenons-en à nos moutons。"},{"label":"关联事件/概念（可选）","value":"跑题、戏剧语言、法语文学传统。"},{"label":"出处","value":"Larousse, Revenons à nos moutons；Académie française / Dire, ne pas dire references。"}],"relationItems":["↔ 相关：“Butter bei die Fische”","↔ 同时期参考：中世纪欧洲闹剧传统"],"relations":[{"text":"↔ 相关：“Butter bei die Fische”","id":"proverb15"}],"source":"proverb","id":"proverb23"},{"title":"“vendre la peau de l’ours avant de l’avoir tué”","level":"C","type":"俗语卡","tags":["文化与思想"],"mainTag":"文化与思想","subTag":"","timeText":"拉封丹寓言时代后广泛固定","place":"法语区。","summary":"“熊还没打死就卖熊皮”是在劝人别提前庆祝、别把尚未到手的东西当成已经拥有。","fields":[{"label":"标题","value":"“vendre la peau de l’ours avant de l’avoir tué”"},{"label":"分级","value":"C"},{"label":"类型","value":"俗语卡"},{"label":"主标签","value":"文化与思想"},{"label":"时间","value":"拉封丹寓言时代后广泛固定"},{"label":"一句话概括","value":"“熊还没打死就卖熊皮”是在劝人别提前庆祝、别把尚未到手的东西当成已经拥有。"},{"label":"原文/标准说法（原文+中文翻译）","value":"vendre la peau de l’ours avant de l’avoir tué。中文：“在杀死熊之前先卖熊皮。”"},{"label":"出现时间","value":"与拉封丹寓言传统密切相关，更早欧洲也有类似表达。"},{"label":"流行时间","value":"17世纪以来至今。"},{"label":"地区","value":"法语区。"},{"label":"它在说什么（字面+引申）","value":"字面是猎人还没猎到熊就卖皮；引申义是事情还没成功就提前计划收益或庆祝。"},{"label":"为什么会出现","value":"打猎风险很高，猎物还没到手就谈收益显得自信过头，适合表达“别高兴太早”。"},{"label":"它反映了什么","value":"这句俗语把经济交易和风险判断结合起来，提醒人不要把可能性当成事实。"},{"label":"类似变体（可选）","value":"Il ne faut pas vendre la peau de l’ours avant de l’avoir tué。"},{"label":"关联事件/概念（可选）","value":"过早庆祝、风险、预期落空。"},{"label":"出处","value":"Wiktionnaire, vendre la peau de l’ours avant de l’avoir tué；La Fontaine, L’Ours et les deux Compagnons tradition references。"}],"relationItems":["↔ 相关：“when pigs fly”","↔ 同时期参考：英语“don’t count your chickens before they hatch”"],"relations":[{"text":"↔ 相关：“when pigs fly”","id":"proverb20"}],"source":"proverb","id":"proverb24"},{"title":"“in bocca al lupo”","level":"C","type":"俗语卡","tags":["文化与思想"],"mainTag":"文化与思想","subTag":"","timeText":"近现代意大利语常用祝福语","place":"意大利及意大利语区。","summary":"“进狼嘴里”反而是意大利语祝好运的话，回答通常是“Crepi!”。","fields":[{"label":"标题","value":"“in bocca al lupo”"},{"label":"分级","value":"C"},{"label":"类型","value":"俗语卡"},{"label":"主标签","value":"文化与思想"},{"label":"时间","value":"近现代意大利语常用祝福语"},{"label":"一句话概括","value":"“进狼嘴里”反而是意大利语祝好运的话，回答通常是“Crepi!”。"},{"label":"原文/标准说法（原文+中文翻译）","value":"in bocca al lupo。中文：“到狼嘴里去。”常见回应：Crepi! / Crepi il lupo! “愿狼死掉！”"},{"label":"出现时间","value":"近现代意大利语常用表达，源头解释有多种。"},{"label":"流行时间","value":"20世纪以来至今，在考试、演出、比赛前尤其常见。"},{"label":"地区","value":"意大利及意大利语区。"},{"label":"它在说什么（字面+引申）","value":"字面听起来像让人进入危险；引申义却是祝好运，相当于英语 break a leg。"},{"label":"为什么会出现","value":"危险意象被反向使用，可能与猎人、剧场迷信或民间避讳有关：不直接说“祝好运”，反而用险境来避开坏运。"},{"label":"它反映了什么","value":"很多文化里都有“反着说”的祝福，尤其在舞台、考试和比赛前，人们怕直接祝福反而招来不吉。"},{"label":"类似变体（可选）","value":"Crepi il lupo；Viva il lupo 作为较新的回应也可见。"},{"label":"关联事件/概念（可选）","value":"避讳、反向祝福、剧场文化。"},{"label":"出处","value":"Treccani, in bocca al lupo；Accademia della Crusca, In bocca al lupo e viva il lupo。"}],"relationItems":["↔ 相关：“break a leg”","↔ 同时期参考：欧洲舞台迷信"],"relations":[],"source":"proverb","id":"proverb25"},{"title":"“вешать лапшу на уши”","level":"C","type":"俗语卡","tags":["文化与思想"],"mainTag":"文化与思想","subTag":"","timeText":"20世纪俄语口语中常见","place":"俄语区。","summary":"“往耳朵上挂面条”意思是骗人、忽悠、给人灌迷魂汤。","fields":[{"label":"标题","value":"“вешать лапшу на уши”"},{"label":"分级","value":"C"},{"label":"类型","value":"俗语卡"},{"label":"主标签","value":"文化与思想"},{"label":"时间","value":"20世纪俄语口语中常见"},{"label":"一句话概括","value":"“往耳朵上挂面条”意思是骗人、忽悠、给人灌迷魂汤。"},{"label":"原文/标准说法（原文+中文翻译）","value":"вешать лапшу на уши。中文：“把面条挂到耳朵上。”"},{"label":"出现时间","value":"20世纪俄语口语中常见，具体起源有多种解释。"},{"label":"流行时间","value":"20世纪至今。"},{"label":"地区","value":"俄语区。"},{"label":"它在说什么（字面+引申）","value":"字面是把面条挂在别人耳朵上；引申义是编瞎话、欺骗别人，让对方相信荒唐说法。"},{"label":"为什么会出现","value":"耳朵是听话的器官，面条是黏糊糊、乱七八糟的东西，把它挂到耳朵上就像用废话堵住人的判断。"},{"label":"它反映了什么","value":"这句俗语非常有画面感，把说谎从抽象语言行为变成“把东西挂到别人耳朵上”的滑稽动作。"},{"label":"类似变体（可选）","value":"не вешай мне лапшу на уши（别给我耳朵上挂面条）。"},{"label":"关联事件/概念（可选）","value":"欺骗、宣传、忽悠、谣言。"},{"label":"出处","value":"RussianPod101, Russian Idioms；Wiktionary, вешать лапшу на уши；Master Russian idiom references。"}],"relationItems":["↔ 相关：“the elephant in the room”","↔ 同时期参考：中文“忽悠”"],"relations":[{"text":"↔ 相关：“the elephant in the room”","id":"proverb19"}],"source":"proverb","id":"proverb26"},{"title":"“делать из мухи слона”","level":"C","type":"俗语卡","tags":["文化与思想"],"mainTag":"文化与思想","subTag":"","timeText":"俄语常用俗语；类似表达可追溯到古典修辞传统","place":"俄语区。","summary":"“把苍蝇做成大象”意思是小题大做，把很小的问题夸张成大事。","fields":[{"label":"标题","value":"“делать из мухи слона”"},{"label":"分级","value":"C"},{"label":"类型","value":"俗语卡"},{"label":"主标签","value":"文化与思想"},{"label":"时间","value":"俄语常用俗语；类似表达可追溯到古典修辞传统"},{"label":"一句话概括","value":"“把苍蝇做成大象”意思是小题大做，把很小的问题夸张成大事。"},{"label":"原文/标准说法（原文+中文翻译）","value":"делать из мухи слона。中文：“把苍蝇做成大象。”"},{"label":"出现时间","value":"俄语中长期使用，类似表达在欧洲多种语言中可见。"},{"label":"流行时间","value":"近现代至今。"},{"label":"地区","value":"俄语区。"},{"label":"它在说什么（字面+引申）","value":"字面是把一只小苍蝇变成大象；引申义是夸大问题、过度反应。"},{"label":"为什么会出现","value":"苍蝇和大象的体量差距极大，用它们对比能马上呈现“夸张得离谱”。"},{"label":"它反映了什么","value":"这类俗语说明很多语言都喜欢用大小反差表达比例失衡，俄语版本尤其画面直接。"},{"label":"类似变体（可选）","value":"сделать из мухи слона。"},{"label":"关联事件/概念（可选）","value":"夸张、小题大做、恐慌传播。"},{"label":"出处","value":"Russian Wiktionary, делать из мухи слона；Reverso Context / Russian idiom dictionaries。"}],"relationItems":["↔ 相关：“die Kirche im Dorf lassen”","↔ 同时期参考：英语“make a mountain out of a molehill”"],"relations":[{"text":"↔ 相关：“die Kirche im Dorf lassen”","id":"proverb12"}],"source":"proverb","id":"proverb27"},{"title":"“猫の手も借りたい”","level":"C","type":"俗语卡","tags":["文化与思想"],"mainTag":"文化与思想","subTag":"","timeText":"近现代日语常用俗语","place":"日本。","summary":"“连猫的手都想借”意思是忙到极点，任何帮手都想要。","fields":[{"label":"标题","value":"“猫の手も借りたい”"},{"label":"分级","value":"C"},{"label":"类型","value":"俗语卡"},{"label":"主标签","value":"文化与思想"},{"label":"时间","value":"近现代日语常用俗语"},{"label":"一句话概括","value":"“连猫的手都想借”意思是忙到极点，任何帮手都想要。"},{"label":"原文/标准说法（原文+中文翻译）","value":"猫の手も借りたい。中文：“连猫的手都想借。”"},{"label":"出现时间","value":"近现代日语俗语，具体源头不易精确。"},{"label":"流行时间","value":"近现代至今。"},{"label":"地区","value":"日本。"},{"label":"它在说什么（字面+引申）","value":"字面是忙到连猫的小爪子都想借来帮忙；引申义是人手严重不足，忙得不可开交。"},{"label":"为什么会出现","value":"猫通常不适合帮人干活，连猫都想借，说明忙到已经不挑帮手。"},{"label":"它反映了什么","value":"这句俗语很生活化，特别适合形容节前、店里、公司或家庭事务忙乱的状态。"},{"label":"类似变体（可选）","value":"猫の手でも借りたい。"},{"label":"关联事件/概念（可选）","value":"劳动、人手不足、日常忙乱。"},{"label":"出处","value":"Kotobank, 猫の手も借りたい；Jisho.org, 猫の手も借りたい。"}],"relationItems":["↔ 相关：“den inneren Schweinehund überwinden”","↔ 同时期参考：中文“忙得团团转”"],"relations":[{"text":"↔ 相关：“den inneren Schweinehund überwinden”","id":"proverb13"}],"source":"proverb","id":"proverb28"},{"title":"“井の中の蛙大海を知らず”","level":"C","type":"俗语卡","tags":["文化与思想"],"mainTag":"文化与思想","subTag":"","timeText":"源自汉文典故；日语中长期使用","place":"日本及东亚汉字文化圈。","summary":"“井里的青蛙不知道大海”指见识狭窄、只知道自己小圈子的人。","fields":[{"label":"标题","value":"“井の中の蛙大海を知らず”"},{"label":"分级","value":"C"},{"label":"类型","value":"俗语卡"},{"label":"主标签","value":"文化与思想"},{"label":"时间","value":"源自汉文典故；日语中长期使用"},{"label":"一句话概括","value":"“井里的青蛙不知道大海”指见识狭窄、只知道自己小圈子的人。"},{"label":"原文/标准说法（原文+中文翻译）","value":"井の中の蛙大海を知らず。中文：“井中之蛙，不知大海。”"},{"label":"出现时间","value":"源自中国古典典故，经汉文传统进入日语表达。"},{"label":"流行时间","value":"古典以来，近现代日语仍常用。"},{"label":"地区","value":"日本及东亚汉字文化圈。"},{"label":"它在说什么（字面+引申）","value":"字面是井底青蛙没有见过大海；引申义是人见识有限，却可能自以为了解世界。"},{"label":"为什么会出现","value":"井和大海形成极端空间对比，小井代表封闭经验，大海代表广阔世界。"},{"label":"它反映了什么","value":"这句话很适合解释知识边界：人最容易把自己见过的一点东西误认为全部世界。"},{"label":"类似变体（可选）","value":"井蛙、大海を知らず；中文“井底之蛙”。"},{"label":"关联事件/概念（可选）","value":"见识、地方主义、世界观局限。"},{"label":"出处","value":"Kotobank, 井の中の蛙大海を知らず；Jisho.org, 井の中の蛙大海を知らず。"}],"relationItems":["↔ 相关：“Tomaten auf den Augen haben”","↔ 同时期参考：中国《庄子》相关典故传统"],"relations":[{"text":"↔ 相关：“Tomaten auf den Augen haben”","id":"proverb14"}],"source":"proverb","id":"proverb29"}]};
